/** KNSL indexed statute corpus */
export const PASAL = [{"l":"KUHP","p":"1","b":"Batas Berlakunya Aturan Pidana","t":"(1) Suatu perbuatan tidak dapat dipidana, kecuali berdasarkan kekuatan ketentuan perundang-undangan pidana yang telah ada (2) Bilamana ada perubahan dalam perundang-undangan sesudah perbuatan dilakukan, maka terhadap terdakwa diterapkan ketentuan yang paling menguntungkannya."},{"l":"KUHP","p":"2","b":"Batas Berlakunya Aturan Pidana","t":"Ketentuan pidana dalam perundang-undangan dangan Indonesia diterapkan bagi setiap orang yang melakukan sesuatu tindak pidana di Indonesia."},{"l":"KUHP","p":"3","b":"Batas Berlakunya Aturan Pidana","t":"Ketentuan pidana dalam perundang-undangan Indonesia berlaku bagi setiap orang yang di luar wilayah Indonesia melakukan tindak pidana di dalam kendaraan air atau pesawat udara Indonesia."},{"l":"KUHP","p":"4","b":"Batas Berlakunya Aturan Pidana","t":"Ketentuan pidana dalam perundang-undangan Indonesia diterapkan bagi setiap orang yang melakukan di luar Indonesia: 1. salah satu kejahatan berdasarkan pasal-pasal 104, 106, 107,108,dan 131. 2. suatu kejahatan mengenai mata uang atau uang kertas yang dikeluarkan oleh negara atau bank, ataupun mengenai meterai yang dikeluarkan dan merek yang digunakan oleh Pemerintah Indonesia. 3. pemalsuan surat hutang atau sertifikat hutang atas tanggungan Indonesia, atas tanggungan suatu daerah atau bagian daerah Indonesia, termasuk pula pemalsuan talon, tanda dividen atau tanda bunga, yang mengikuti surat atau sertifikat itu, dan tanda yang dikeluarkan sebagai pengganti surat tersebut, atau menggunakan surat-surat tersebut di atas, yang palsu atau dipalsukan, seolah-olah asli dan tidak dipalsu; 4. salah satu kejahatan yang tersebut dalam pasal-pasal 438, 444 sampai dengan 446 tentang pembajakan laut dan pasal 447 tentang penyerahan kendaraan air kepada kekuasaan bajak laut dan pasal 479 huruf j tentang penguasaan pesawat udara secara melawan hukum, pasal 479 huruf I, m, n, dan o tentang kejahatan yang mengancam keselamatan penerbangan sipil."},{"l":"KUHP","p":"5","b":"Batas Berlakunya Aturan Pidana","t":"(1) Ketentuan pidana dalam perundang-undangan Indonesia diterspksn bsgi warga negara yang di luar Indonesia melakukan: 1. salah satu kejahatan tersebut dalam Bab I dan II Buku Kedua dan pasal-pasal 160, 161, 240, 279, 450, dan 451. 2. salah satu perbuatan yang oleh suatu ketentuan pidana dalam perundang-undangan Indonesia dipandang sebagai kejahatan, sedangkan menurut perundang-undangan negara dimana perbuatan dilakukan diancam dengan pidana. (2) Penuntutan perkara sebagaimana dimaksud dalam butir 2 dapat dilakukan juga jika tertuduh menjadi warga negara sesudah melakukan perbuatan."},{"l":"KUHP","p":"6","b":"Batas Berlakunya Aturan Pidana","t":"Berlakunya pasal 5 ayat 1 butir 2 dibatasi sedemikian rupa sehingga tidak dijatuhkan pidana mati, jika menurut perundang-undangan negara dimana perbuatan dilakukan, terhadapnya tidak diancamkan pidana mati."},{"l":"KUHP","p":"7","b":"Batas Berlakunya Aturan Pidana","t":"Ketentuan pidana dalam perundang-undangan Indonesia berlaku bagi setiap pejabat yang di luar Indonesia melakukan salah satu tindak pidana sebagaimana dimaksud dalam bab XXVIII Buku Kedua Pasal 8 Ketentuan pidana dalam perundang-undangan Indonesia berlaku bagi nahkoda dan penumpang perahu Indonesia, yang diluar Indonesia, sekalipun di luar perahu, melakukan salah satu tindak pidana sebagaimana dimaksud dalam Bab XXIX Buku Kedua, dan BAb IX Buku ketiga; begitu pula yang tersebut dalam peraturan mengenai surat laut dan pas kapal di Indonesia, maupun dalam Ordonansi Perkapalan."},{"l":"KUHP","p":"9","b":"Batas Berlakunya Aturan Pidana","t":"Diterapkannya pasal-pasal 2-5, 7, dan 8 dibatasi oleh pengecualian-pengecualian yang diakui dalam hukum internasional."},{"l":"KUHP","p":"10","b":"Pidana","t":"Pidana terdirl atas: a. pidana pokok: 1. pidana mati; 2. pidana penjara; 3. pidana kurungan; 4. pidana denda; 5. pidana tutupan. b. pidana tambahan 1. pencabutan hak-hak tertentu; 2. perampasan barang-barang tertentu; 3. pengumuman putusan hakim."},{"l":"KUHP","p":"11","b":"Pidana","t":"Pidana mati dijalankan oleh algojo di tempat gantungan dengan menjeratkan tali yang terikat di tiang gantungan pada leher terpidana kemudian menjatuhkan papan tempat terpidana berdiri."},{"l":"KUHP","p":"12","b":"Pidana","t":"(1) Pidana penjara ialah seumur hidup atau selama waktu tertentu. (2) Pidana penjara selama waktu tertentu paling pendek satu hari dan paling lama lima belas tahun berturut-turut. (3) Pidana penjara selama waktu tertentu boleh dijatuhkan untuk dua puluh tahun berturut-turut dalam hal kejahatan yang pidananya hakim boleh memilih antara pidana mati, pidana seumur hidup, dan pidana penjara selama waktu tertentu, atau antara pidana penjara seumur hidup dan pidana penjara selama waktu tertentu; begitu juga dalam hal batas lima belas tahun dilampaui sebab tambahanan pidana karena perbarengan, pengulangan atau karena ditentukan pasal 52. (4) Pidana penjara selama waktu tertentu sekali-kali tidak boleh melebihi dua puluh tahun."},{"l":"KUHP","p":"13","b":"Pidana","t":"Para terpidana dijatuhi pidana penjara dibagi-bagi atas beberapa golongan"},{"l":"KUHP","p":"14","b":"Pidana","t":"Terpidana yang dijatuhkan pidana penjara wajib menjalankan segala pekerjaan yang dibebankan kepadanya berdasarkan ketentuan pelaksanaan pasal 29."},{"l":"KUHP","p":"14a","b":"Pidana","t":"(1) Apabila hakim menjatuhkan pidana paling lama satu tahun atau pidana kurungan, tidak termasuk pidana kurungan pengganti maka dalam putusnya hakim dapat memerintahkan pula bahwa pidana tidak usah dijalani, kecuali jika dikemudianhari ada putusan hakim yang menentukan lain, disebabkan karena si terpidana melakukan suatu tindak pidana sebelum masa percobaan yang ditentukan dalam perintah tersebut diatas habis, atau karena si terpidana selama masa percobaan tidak memenuhi syarat khusus yang mungkin ditentukan lain dalam perintah itu. (2) Hakim juga mempunyai kewenangan seperti di atas, kecuali dalam perkara-perkara yang mangenai penghasilan dan persewaan negara apabila menjatuhkan pidana denda, tetapi harus ternyata kepadanya bahwa pidana denda atau perampasan yang mungkin diperintahkan pula akan sangat memberatkan si terpidana . Dalam menerapkan ayat ini, kejahatan dan pelanggaran candu hanya dianggap sebagai perkara mengenai penghasilan negara, jika terhadap kejahatan dan pelanggaran itu ditentukan bahwa dalam hal dijatuhkan pidana denda, tidak diterapkan ketentuan pasal 30 ayat 2. (3) Jika hakim tidak menentukan lain, maka perintah mengenai pidana pokok juga mengenai pidana pokok juga mengenai pidana tambahan. (4) Perintah tidak diberikan, kecuali hakim setelah menyelidiki dengan cermat berkeyakinan bahwa dapat diadakan pengawasan yang cukup untuk dipenuhinya syarat umum, bahwa terpidana tidak akan melakukan tindak pidana, dan syarat-syarat khusus jika sekiranya ditetapkan. (5) Perintah tersebut dalam ayat 1 harus disertai hal-hal atau keadaan-keadaan yang menjadi alasan perintah itu."},{"l":"KUHP","p":"14b","b":"Pidana","t":"(1) Masa percobaan bagi kejahatan dan pelanggaran dalam pasal-pasal 492, 504, 505, 506, dan 536 paling lama tiga tahun dan bagi pelanggaran lainnya paling lama dua tahun. (2) Masa percobaan dimulai pada saat putusan telah menjadi tetap dan telah diberitahukan kepada terpidana menurut cara yang ditentukan dalam undang-undang. (3) Masa percobaan tidak dihitung selama terpidana ditahan secara sah."},{"l":"KUHP","p":"14c","b":"Pidana","t":"(1) Dengan perintah yang dimaksud pasal 14a, kecuali jika dijatuhkan pidana denda, selain menetapkan syarat umum bahwa terpidana tidak akan melakukan tindak pidana, hakim dapat menetapkan syarat khusus bahwa terpidana tindak pidana , hakim dapat menerapkan syarat khusus bahwa terpidana dalam waktu tertentu, yang lebih pendek daripada masa percobaannya, harus mengganti segala atau sebagian kerugian yang ditimbulkan oleh tindak pidana tadi. (2) Apabila hakim menjatuhkan pidana penjara lebih dari tiga bulan atau pidana kurungan atas salah satu pelanggaran berdasarkan pasal-pasal 492, 504, 505, 506, dan 536, maka boleh diterapkan syarat-syarat khusus lainnya mengenai tingkah laku terpidana yang harus dipenuhi selama masa percobaan atau selama sebagian dari masa percobaan. (3) Syarat-syarat tersebut di atas tidak boleh mengurangi kemerdekaan beragama atau kemerdekaan berpolitik terpidana."},{"l":"KUHP","p":"14d","b":"Pidana","t":"(1) Yang diserahi mengawasi supaya syarat-syarat dipenuhi, ialah pejabat yang berwenang menyuruh menjalankan putusan, jika kemidian ada perintah untuk menjalankan putusan. (2) Jika ada alasan, hakim dapat perintah boleh mewajibkan lembaga yang berbentuk badan hukum dan berkedudukan di Indonesia, atau kepada pemimpin suatu rumah penampungan yang berkedudukan di situ, atau kepada pejabat tertentu, supaya memberi pertolongan atau bantuan kepada terpidana dalam memenuhi syarat-syarat khusus. (3) Aturan-aturan lebih lanjut mengenai pengawasan dan bantuan tadi serta mengenai penunjukan lembaga dan pemimpin rumah penampungan yang dapat diserahi dengan bantuan itu, diatur dengan undang-undang."},{"l":"KUHP","p":"14e","b":"Pidana","t":"Atas usul pejabat dalam pasal ayat 1, atau atas permintaan terpidana, hakim yang memutus perkara dalam tingkat pertama, selama masa percobaan, dapat mengubah syarat-syarat khusus dalam masa percobaan. Hakim juga boleh memerintahkan orang lain daripada orang yang diperintahkan semula, supaya memberi bantuan kepada terpidana dan juga boleh memperpanjang masa percobaan satu kali, paling banyak dengan separuh dari waktu yang paling lama dapat diterapkan untuk masa percobaan."},{"l":"KUHP","p":"14f","b":"Pidana","t":"(1) Tanpa mengurangi ketentuan pasal diatas, maka ats usul pejabat tersebut dalam pasal 14d ayat 1, hakim yang memutus perkara dalam tingkat pertama dapat memerintahkan supaya pidananya dijalankan, atau memerintahkan supaya atas namanya diberi peringatan pada terpidana, yaitu jika terpidana selama masa percobaan melakukan tindak pidana dan karenanya ada pemidanaan yang menjadi tetap, atau jika salah satu syarat lainnya tidak dipenuhi, ataupun jika terpidana sebelum masa percobaan habis dijatuhi pemidanaan yang menjadi tetap, karena melakukan tindak pidana selama masa percobaan mulai berlaku. Ketika memberi peringatan, hakim harus menentukan juga cara bagaimana memberika peringatan itu. (2) Setelah masa percobaan habis, perintah supaya pidana dijalankan tidak dapat diberikan lagi, kecuali jika sebelum masa percobaan habis, terpidana dituntut karena melakukan tindak pidana di dalam masa percobaan dan penuntutan itu kemudian berakhir dengan pemidanan yang memnjadi tetap. Dalam hal itu, dalam waktu dua bulan setelah pemidanaan menjadi tetap, hakim masih boleh memerintahkan supaya pidananya dijalankan, karena melakukan tindak pidana tadi."},{"l":"KUHP","p":"15","b":"Pidana","t":"(1) Jika terpidana telah menjalani dua pertiga dari lamanya pidana penjara yang dijatuhkan kepadanya, sekurang-kurangnya harus sembilan bulan, maka ia dapat dikenakan pelepasan bersyarat. Jika terpidana harus menjalani beberapa pidana berturut- turut, pidana itu dianggap sebagai satu pidana. (2) Ketika memberikan pelepasan bersyarat, ditentukan pula suatu masa percobaan, serta ditetapkan syarat-syarat yang harus dipenuhi selama masa percobaan. (3) Masa percobaan itu lamanya sama dengan sisa waktu pidana penjara yang belum dijalani, ditambah satu tahun. Jika terpidana ada dalam tahanan yang sah, maka waktu itu tidak termasuk masa percobaan."},{"l":"KUHP","p":"15a","b":"Pidana","t":"(1) Pelepasan bersyarat diberikan dengan syarat umum bahwa terpidana tidak akan melakukan tindak pidana dan perbuatan lain yang tidak baik.] (2) Selain itu, juga boleh ditambahkan syarat-syarat khusus mengenai kelakuan terpidana, asal saja tidak mengurangi kemerdekaan beragama dan kemerdekaan berpolitik. (3) Yang diserahi mengawasi supaya segala syarat dipenuhi ialah pejabat tersebut dalam pasal 14d ayat 1. (4) Agar supaya syarat-syarat dipenuhi, dapat diadakan pengawasan khusus yang semata- mata harus bertujuan memberi bantuan kepada terpidana. (5) Selama masa percobaan, syarat-syarat dapat diubah atau di hapus atau dapat diadakan syarat-syarat khusus baru; begitu juga dapat diadakan pengawasan khusus. Pengawasan khusus itu dapat diserahkan kepada orang lain daripada orang yang semula diserahi. (6) Orang yang mendapat pelepasan bersyarat diberi surat pas yang memuat syarat- syarat yang harus dipenuhinya. Jika hal-hal yang tersebut dalam ayat di atas dijalankan, maka orang itu diberi surat pas baru."},{"l":"KUHP","p":"15b","b":"Pidana","t":"(1) Jika orang yang diberi pelepasan bersyarat selama masa percobaan melakukan hal- hal yang melanggar syarat-syarat tersebut dalam surat pasnya, maka pelepasan bersyarat dapat dicabut. Jika ada sangkaan keras bahwa hal-hal di atas dilakukan, Menteri Kehakiman dapat menghentikan pelepasan bersyarat tersebut untuk sementara waktu. (2) Waktu selama terpidasna dilepaskan bersyarat sampai menjalani pidana lagi, tidak termasuk waktu pidananya. (3) Jika tiga bulan setelah masa percobaan habis, pelepasan bersyarat tidak dapat dicabut kembali, kecuali jika sebelum waktu tiga bulan lewat, terpidana dituntut karena melakukan tindak pidana pada masa percobaan, dan tuntutan berakhir dengan putusan pidana yang menjadi tetap. Pelepasan bersyarat masih dapat dicabut dalam waktu tiga bulan bersyarat masih dapat dicabut dalam waktu tiga bulan setelah putusan menjadi tetap berdasarkan pertimbangan bahwa terpidana melakukan tindak pidana selama masa percobaan."},{"l":"KUHP","p":"16","b":"Pidana","t":"(1) Ketentuan pelepasan bersyarat ditetapkan oleh Menteri Kehakiman atas usul atau setelah mendapat kabar dari pengurus penjara tempat terpidana, dan setelah mendapat keterangan dari jaksa tempat asal terpidana. Sebelum menentukan, harus ditanya dahulu pendapat Dewan Reklasering Pusat, yang tugasnya diatur oleh Menteri Kehakiman. (2) Ketentuan mencabut pelepasan bersyarat, begitu juga hal-hal yang tersebut dalam pasal 15a ayat 5, ditetapkan oleh Menteri Kehakiman atas usul atau setelah mendapat kabar dari jaksa tempat asal terpidana. Sebelum memutus, harus ditanya dahulu pendapat Dewan Reklasering Pusat. (3) Selama pelepasan masih dapat dicabut, maka atas perintah jaksa tempat dimana dia berada, orang yang dilapaskan bersyarat orang yang dilepaskan bersyarat dapat ditahan guna menjaga ketertiban umum, jika ada sangkaan yang beralasan bahwa orang itu selama masa percobaan telah berbuat hal-hal yang melanggar syarat-syarat tersebut dalam surat pasnya. Jaksa harus segera memberitahukan penahanan itu kepada Menteri Kehakiman. (4) Waktu penahanan paling lama enam puluh ahri. Jika penahanan disusul dengan penghentian untuk sementara waktu atau pencabutan pelepasan bersyarat, maka orang itu dianggap meneruskan menjalani pidananya mulai dari tahanan."},{"l":"KUHP","p":"17","b":"Pidana","t":"Contoh surat pas dan peraturan pelaksanaan pasal-pasal 15, 15a, dan 16 diatur dengan undang-undang."},{"l":"KUHP","p":"18","b":"Pidana","t":"(1) Pidana kurungan paling sedikit satu hari dan paling lama satu tahun. (2) Jika ada pidana yang disebabkan karena perbarengan atau pengulangan atau karena ketentuan pasal 52, pidana kurungan dapat ditambah menjadi satu tahun empat bulan. (3) Pidana kurungan sekali-kali tidak boleh lebih dari satu tahun empat bulan."},{"l":"KUHP","p":"19","b":"Pidana","t":"(1) Orang yang dijatuhi pidana kurungan wajib menjalankan pekerjaan yang dibebankan kepadanya, sesuai dengan aturan-aturan pelaksanaan pasal 29. (2) Ia diserahi pekerjaan yang lebih ringan daripada orang yang dijatuhi pidana penjara."},{"l":"KUHP","p":"20","b":"Pidana","t":"(1) Hakim yang menjatuhkan pidana penjara atau pidana kurungan paling lama satu bulan, boleh menetapkan bahwa jaksa dapat mengizinkan terpidana bergerak dengan bebas di luar penjara sehabis waktu kerja. (2) Jika terpidana yang mendapat kebebasan itu mendapat kebebasan itu tidak datang pada waktu dan tempat yang telah ditentukan untuk menjalani pekerjaan yang dibebankan kepadanya, maka ia harus menjalani pidananya seperti biasa kecuali kalau tidak datangnya itu bukan karena kehendak sendiri. (3) Ketentuan dalam ayat 1 tidak diterapkan kepada terpidana karena terpidana jika pada waktu melakukan tindak pidana belum ada dua tahun sejak ia habis menjalani pidana penjara atau pidana kurungan."},{"l":"KUHP","p":"21","b":"Pidana","t":"Pidana kurungan harus dijalani dalam daerah dimana si terpidana berdiam ketika putusan hakim dijalankan, atau jika tidak punya tempat kediaman, di dalam daerah dimana ia berada, kecuali kalau Menteri Kehakiman atas permintaannya terpidana membolehkan menjalani pidananya di daerah lain."},{"l":"KUHP","p":"22","b":"Pidana","t":"(1) Terpidana yang sedang menjalani pidana hilang kemerdekaan di suatu tempat yang digunakan untuk menjalani pidana penjara, atau pidana kurungan, atau kedua-duanya, segera sehabis pidana habis hilang kemerdekaan itu selesai, kalau diminta, boleh menjalani kurungan di tempat itu juga. (2) Pidana kurungan karena sebab di atas dijalani di tempat yang khusus untuk menjalani pidana penjara, tidak berubah sifatnya oleh karena itu."},{"l":"KUHP","p":"23","b":"Pidana","t":"Orang yang dijatuhi pidana kurungan, dengan biaya sendiri boleh sekedar meringankan nasibnya menurut aturan-aturan yang akan ditetapkan dengan undang-undang."},{"l":"KUHP","p":"24","b":"Pidana","t":"Orang yang dijatuhi pidana penjara atau pidana kurungan boleh diwajibkan bekerja di dalam atau di luar tembok tempat orang-orang terpidana."},{"l":"KUHP","p":"25","b":"Pidana","t":"Yang tidak boleh diserahi pekerjaan di luar tembok tempat tersebut ialah: 1. Orang-orang yang di jatuhi pidana penjara seumur hidup; 2. Para wanita; 3. Orang-orang yang menurut pemeriksaan dokter tidak boleh menjalankan pekerjaan demikian."},{"l":"KUHP","p":"26","b":"Pidana","t":"Jikalau mengingat keadaan diri atau masyarakat terpidana, hakim menimbang ada alasan, maka dalam putusan ditentukan bahwa terpidana tidak boleh diwajibkan bekerja di luar tembok tempat orang-orang terpidana."},{"l":"KUHP","p":"27","b":"Pidana","t":"Lamanya pidana penjara untuk waktu tertentu dan pidana kurungan dalam putusan hakim dinyatakan dengan hari, minggu, bulan, dan tahun; tidak boleh dengan pecahan."},{"l":"KUHP","p":"28","b":"Pidana","t":"Pidana penjara dan pidana kurungan dapat dilaksanakan di satu tempat asal saja terpisah."},{"l":"KUHP","p":"29","b":"Pidana","t":"(1) Hal menunjuk tempat untuk menjalani pidana penjara, pidana kurungan, atau kedua- duanya, begitu juga hal mengatur dan mengurus tempat-tempat itu, hal membedakan orang terpidana dalam golongan-golongan, hal mengatur pemberian pengajaran, penyelenggaraan ibadat, hal tata tertib, hal tempat untuk tidur, hal makanan, dan pakaian, semuanya itu diatur dengan undang-undang sesuai dengan kitab undang- undang sesuai dengan kitab undang-undang ini. (2) Jika perlu, Menteri Kehakiman menetepkan aturan rumah tangga untuk tempat- tempat orang terpidana."},{"l":"KUHP","p":"30","b":"Pidana","t":"(1) Pidana denda paling sedikit tiga rupiah tujuh puluh lima sen. (2) Jika pidana denda tidak dibayar, ia diganti dengan pidana kurungan. (3) Lamanya pidana kurungan pengganti paling sedikit satu hari dan paling lama enam bulan. (4) Dalam putusan hakim, lamanya pidana kurungan pengganti ditetapkan demikian; jika pidana dendanya tujuh rupiah lima puluh dua sen atau kurungan, di hitung satu hari; jika lebih dari lima rupiah lima puluh sen, tiap-tiap tujuh rupiah lima puluh sen di hitung paling banyak satu hari demikian pula sisanya yang tidak cukup tujuh rupiah lima puluh sen. (5) Jika ada pemberatan pidana denda disebabkan karena perbarengan atau pengulangan, atau karena ketentuan pasal 52, maka pidana kurungan pengganti paling lama delapan bulan. (6) Pidana kurungan pengganti sekali-kali tidak boleh lebih dari delapan bulan."},{"l":"KUHP","p":"31","b":"Pidana","t":"(1) Terpidana dapat menjalani pidana kurungan pengganti tanpa menunggu batas waktu pembayaran denda. (2) Ia selalu berwenang membebaskan dirinya dari pidana kurungan pengganti dengan membayar dendanya. (3) Pembayaran sebagian dari pidana denda, baik sebelum maupun sesudah mulai menjalani pidana kurungan yang seimbang dengan bagian yang dibayarnya."},{"l":"KUHP","p":"32","b":"Pidana","t":"(1) Pidana penjara dan pidana kurungan mulai berlaku bagi terpidana yang sudah di dalam tahanan sementara, pada hari ketika putusan hakim menjadi tetap, dan bagi terpidana lainnya pada hari ketika putusan hakim mulai dijalankan. (2) jika dalam putusan hakim dijatuhkan pidana penjara dan pidana kurungan atas beberapa perbuatan pidana, dan kemudian putusan itu bagi kedua pidana tadi menjadi tetap pada waktu yang sama, sedangkan terpidana sudah ada dalam tahanan sementara karena kedua atau salah satu perbuatan pidana itu, maka pidana penjara mulai berlaku pada saat ketika putusan hakim menjadi tetap, dan pidana kurungan mulai berlaku setelah pidana penjara habis."},{"l":"KUHP","p":"33","b":"Pidana","t":"(1) Hakim dalam putusannya boleh menentukan bahwa waktu terpidana ada dalam tahanan sementara sebelum putusan menjadi tetap, seluruhnya atau sebagian di potong dari pidana penjara selama waktu tertentu dari pidana kurungan atau dari pidana denda yang dijatuhkan kepadanya; dalam hal pidana denda dengan memakai ukuran menurut pasal 31 ayat 3. (2) Waktu selama seorang terdakwa dalam tahanan sementara yang tidak berdasarkan surat perintah, tidak dipotong dari pidananya, kecuali jika pemotongan itu dinyatakan khusus dalam putusan hakim. (3) Ketentuan pasal ini berlaku juga dalam hal terdakwa oleh sebab dituntut bareng karena melakukan beberapa tindak pidana, kemudian dipidana karena perbuatan lain daripada yang didakwakan kepadanya waktu ditahan sementara."},{"l":"KUHP","p":"33a","b":"Pidana","t":"Jika orang yang ditahan sementara di jatuhi pidana penjara atau pidana kurungan, dan kemudian dia sendiri atau orang lain dengan persetujuannya mengajukan permohonan ampun, waktu mulai permohonan diajukan hingga ada putusan Presiden, tidak dihitung sebagai waktu menjalani pidana, kecuali jika Presiden, dengan mengingat keadaan perkaranya, menentukan bahwa waktu itu seluruhnya atau sebagian dihitung sebagai waktu menjalani pidana."},{"l":"KUHP","p":"34","b":"Pidana","t":"Jika terpidana selama menjalani pidana melarikan diri, maka waktu selama di luar tempat menjalani pidana tidak dihitung sebagai waktu menjalani pidana."},{"l":"KUHP","p":"35","b":"Pidana","t":"(1) Hak-hak terpidana yang dengan putusan hakim dapat dicabut dalam hal-hal yang ditentukan dalam kitab undang-undang ini, atau dalam aturan umum lainnya ialah: 1. hak memegang jabatan pada umumnya atau jabatan yang tertentu; 2. hak memasuki Angkatan Bersenjata; 3. hak memilih dan dipilih dalam pemilihan yang diadakan berdasarkan aturan-aturan umum. 4. hak menjadi penasehat hukum atau pengurus atas penetapan pengadilan, hak menjadi wali, wali pengawas, pengampu atau pengampu pengawas, atas orang yang bukan anak sendiri; 5. hak menjalankan kekuasaan bapak, menjalankan perwalian atau pengampuan atas anak sendiri; 6. hak menjalankan mata pencarian tertentu. (2) Hakim tidak berwenang memecat seorang pejabat dari jabatannya, jika dalam aturan- aturan khusus di tentukan penguasa lain untuk pemecatan itu."},{"l":"KUHP","p":"36","b":"Pidana","t":"Hak memegang jabatan pada umumnya atau jabatan tertentu dan hak memasuki Angkatan Bersenjata, kecuali dalam hal yang diterangkan dalam Buku Kedua, dapat di cabut dalam hal pemidanaan karena kejahatan jabatan atau kejahatan yang melanggar kewajiban khusus sesuatu jabatan, atau karena memakai kekuasaan, kesempatan atau sarana yang diberikan pada terpidana karena jabatannya."},{"l":"KUHP","p":"37","b":"Pidana","t":"(1) Kekuasaan bapak, kekuasaan wali, wali pengawas, pengampu, dan pengampu pengawas, baik atas anak sendiri maupun atas orang lain, dapat dicabut dalam hal pemidanaan: 1. orang tua atau wali yang dengan sengaja melakukan kejahatan bersama-sama dengan anak yang belum dewasa yang ada di bawah kekuasaannya; 2. orang tua atau wali terhadap anak yang belum dewasa yang ada di bawah kekuasaannya, melakukan kejahatan, yang tersebut dalam bab XIII, XIV, XV, XVIII, XIX, dan XX Buku Kedua. (2) Pencabutan tersebut dalam ayat 1 tidak boleh dilakukan oleh hakim pidana terhadap orang-orang yang baginya diterapkan undang-undang hukum perdata tentang pencabutan kekuasaan orang tua, kekuasaan wali dan kekuasaan pengampu."},{"l":"KUHP","p":"38","b":"Pidana","t":"(1) Jika dilakukan pencabutan hak, hakim menentukan lamanya pencabutan sebagai berikut: 1. dalam hal pidana mati atau pidana penjara seumur hidup, lamanya pencabutan seumur hidup; 2. dalam hal pidana penjara untuk waktu tertentu atau pidana kurungan, lamanya pencabutan paling sedikit dua tahun dan paling banyak lima tahun lebih lama dari pidana pokoknya; 3. dalam hal pidana denda, lamanya pencabutan paling sedikit dua tahun dan paling banyak lima tahun. (2) Pencabutan hak mulai berlaku pada hari putusan hakim dapat dijalankan."},{"l":"KUHP","p":"39","b":"Pidana","t":"(1) Barang-barang kepunyaan terpidana yang diperoleh dari kejahatan atau yang sengaja dipergunakan untuk melakukan kejahatan, dapat dirampas. (2) Dalam hal pemidanaan karena kejahatan yang tidak dilakukan dengan sengaja atau karena pelanggaran, dapat juga dijatuhkan putusan perampasan berdasarkan hal-hal yang ditentukan dalam undang-undang. (3) Perampasan dapat dilakukan terhadap orang yang bersalah yang diserahkan kepada pemerintah, tetapi hanya atas barang-barang yang telah disita."},{"l":"KUHP","p":"40","b":"Pidana","t":"Jika seorang di bawah umur enam belas tahun mempunyai, memasukkan atau mengangkut barang-barang denga melanggar aturan-aturan mengenai pengawasan pelayaran di bagian-bagian Indonesia yang tertentu, atau aturan-aturan mengenai larangan memasukkan, mengeluarkan, dan meneruskan pengangkutan barang-barang, maka hakim dapat menjatuhkan pidana perampasan atas barang-barang itu, juga dalam hal yang bersalah diserahkan kembali kepada orang tuanya, walinya atau pemeliharanya tanpa pidana apapun."},{"l":"KUHP","p":"41","b":"Pidana","t":"(1) Perampasan atas barang-barang yang disita sebelumya, diganti menjadi pidana kurungan, apabila barang-barang itu tidak diserahkan, atau harganya menurut taksiran dalam putusan hakim, tidak di bayar. (2) Pidana kurungan pengganti ini paling sedikit satu hari dan paling lama enam bulan. (3) Lamanya pidana kurungan pengganti ini dalam putusan hakim ditentukan sebagai berikut: tujuh rupiah lima puluh sen atau kurang di hitung satu hari; jika lebih dari tujuh rupiah lima puluh sen, tiap-tiap tujuh rupiah lima puluh sen dihitung paling banyak satu hari, demikian pula sisanya yang tidak cukup tujuh rupiah lima puluh sen. (4) Pasal 31 diterapkan bagi pidana kurungan pengganti ini. (5) Jika barang-barang yang dirampas diserahkan, pidana kurungan pengganti ini juga di hapus."},{"l":"KUHP","p":"42","b":"Pidana","t":"Segala biaya untuk pidana penjara dan pidana kurungan dipikul oleh negara, dan segala pendapatan dari pidana denda dan perampasan menjadi milik negara."},{"l":"KUHP","p":"43","b":"Pidana","t":"Apabila hakim memerintahkan supaya putusan diumumkan berdasarkan kitab undang- undang ini atau aturan-aturan umum lainnya, maka ia harus menetapkan pula bagaimana cara melaksanakan perintah itu atas biaya terpidana."},{"l":"KUHP","p":"44","b":"Hal yang Menghapuskan/Mengurangi/Memberatkan Pidana","t":"(1) Barang siapa melakukan perbuatan yang tidak dapat dipertanggungkan kepadanya karena jiwanya cacat dalam pertumbuhan atau terganggu karena penyakit, tidak dipidana. (2) Jika ternyata perbuatan itu tidak dapat dipertanggungkan kepada pelakunya karena pertumbuhan jiwanya cacat atau terganggu karena penyakit, maka hakim dapat memerintahkan supaya orang itu dimasukkan ke rumah sakit jiwa, paling lama satu tahun sebagai waktu percobaan. (3) Ketentuan dalam ayat 2 hanya berlaku bagi Mahkamah Agung, Pengadilan Tinggi, dan Pengadilan Negeri."},{"l":"KUHP","p":"45","b":"Hal yang Menghapuskan/Mengurangi/Memberatkan Pidana","t":"Dalam hal penuntutan pidana terhadap orang yang belum dewasa karena melakukan suatu perbuatan sebelum umur enam belas tahun, hakim dapat menentukan: memerintahkan supaya yang bersalah dikembalikan kepada orang tuanya, walinya atau pemeliharanya, tanpa pidana apa pun; atau memerintahkan supaya yang bersalah diserahkan kepada pemerintah tanpa pidana apa pun, jika perbuatan merupakan kejahatan atau salah satu pelanggaran berdasar- kan pasal-pasal 489, 490, 492, 496, 497, 503 - 505, 514, 517 - 519, 526, 531, 532, 536, dan 540 serta belum lewat dua tahun sejak dinyatakan bersalah karena melakukan kejahatan atau salah satu pelanggaran tersebut di atas, dan putusannya telah menjadi tetap; atau menjatuhkan pidana kepada yang bersalah."},{"l":"KUHP","p":"46","b":"Hal yang Menghapuskan/Mengurangi/Memberatkan Pidana","t":"(1) Jika hakim memerintahkan supaya yang bersalah diserahkan kepada pemerintah, maka ia dimasukkan dalam rumah pendidikan negara supaya menerima pendidikan dari pemerintah atau di kemudian hari dengan cara lain, atau diserahkan kepada seorang tertentu yang bertempat tinggal di Indonesia atau kepada sesuatu badan hukum, yayasan atau lembaga amal yang berkedudukan di Indonesia untuk menyelenggarakan pendidikannya, atau di kemudian hari, atas tanggungan pemerintah, dengan cara lain; dalam kedua hal di atas, paling lama sampai orang yang bersalah itu mencapai umur delapan belas tahun. (2) Aturan untuk melaksanakan ayat 1 pasal ini ditetapkan dengan undang-undang."},{"l":"KUHP","p":"47","b":"Hal yang Menghapuskan/Mengurangi/Memberatkan Pidana","t":"(1) Jika hakim menjatuhkan pidana, maka maksimum pidana pokok terhadap tindak pidananya dikurangi sepertiga. (2) Jika perbuatan itu merupakan kejahatan yang diancam dengan pidana mati atau pidana penjara seumur hidup, maka dijatuhkan pidana penjara paling lama lima belas tahun. (3) Pidana tambahan dalam pasal 10 butir b, nomor 1 dan 3, tidak dapat diterapkan."},{"l":"KUHP","p":"48","b":"Hal yang Menghapuskan/Mengurangi/Memberatkan Pidana","t":"Barang siapa melakukan perbuatan karena pengaruh daya paksa, tidak dipidana."},{"l":"KUHP","p":"49","b":"Hal yang Menghapuskan/Mengurangi/Memberatkan Pidana","t":"(1) Tidak dipidana, barang siapa melakukan perbuatan pembelaan terpaksa untuk diri sendiri maupun untuk orang lain, kehormatan kesusilaan atau harta benda sendiri maupun orang lain, karena ada serangan atau ancaman serangan yang sangat dekat pada saat itu yang melawan hukum. (2) Pembelaan terpaksa yang melampaui batas, yang langsung disebabkan oleh keguncangan jiwa yang hebat karena serangan atau ancaman serangan itu, tidak dipidana."},{"l":"KUHP","p":"50","b":"Hal yang Menghapuskan/Mengurangi/Memberatkan Pidana","t":"Barang siapa melakukan perbuatan untuk melaksanakan ketentuan undang-undang, tidak dipidana."},{"l":"KUHP","p":"51","b":"Hal yang Menghapuskan/Mengurangi/Memberatkan Pidana","t":"(1) Barang siapa melakukan perbuatan untuk melaksanakan perintah jabatan yang diberikan oleh penguasa yang berwenang, tidak dipidana. (2) Perintah jabatan tanpa wewenang, tidak menyebabkan hapusnya pidana, kecuali jika yang diperintah, dengan itikad baik mengira bahwa perintah diberikan dengan wewenang dan pelaksanaannya termasuk dalam lingkungan pekerjaannya."},{"l":"KUHP","p":"52","b":"Hal yang Menghapuskan/Mengurangi/Memberatkan Pidana","t":"Bilamana seorang pejabat karena melakukan perbuatan pidana melanggar suatu kewajiban khusus dari jabatannya , atau pada waktu melakukan perbuatan pidana memakai kekuasaan, kesempatan atau sarana yang diberikan kepadanya karena jabatannya, pidananya dapat ditambah sepertiga."},{"l":"KUHP","p":"52a","b":"Hal yang Menghapuskan/Mengurangi/Memberatkan Pidana","t":"Bilamana pada waktu melakukan kejahatan digunakan bendera kebangsaan Republik Indonesia, pidana untuk kejahatan tersebut ditambah sepertiga."},{"l":"KUHP","p":"53","b":"Percobaan","t":"(1) Mencoba melakukan kejahatan dipidana, jika niat untuk itu telah ternyata dari adanya permulaan pelaksanaan, dan tidak selesainya pelaksanaan itu, bukan semata-mata disebabkan karena kehendaknya sendiri. (2) Maksimum pidana pokok terhadap kejahatan, dalam hal percobaan dikurangi sepertiga. (3) Jika kejahatan diancam dengan pidana mati atau pidana penjara seumur hidup, dijatuhkan pidana penjara paling lama lima belas tahun. (4) Pidana tambahan bagi percobaan sama dengan kejahatan selesai."},{"l":"KUHP","p":"54","b":"Percobaan","t":"Mencoba melakukan pelanggaran tidak dipidana."},{"l":"KUHP","p":"55","b":"Penyertaan dalam Tindak Pidana","t":"(1) Dipidana sebagai pelaku tindak pidana: 1. mereka yang melakukan, yang menyuruh melakukan, dan yang turut serta melakukan perbuatan; 2. mereka yang dengan memberi atau menjanjikan sesuatu dengan menyalahgunakan kekuasaan atau martabat, dengan kekerasan, ancaman atau penyesatan, atau dengan memberi kesempatan, sarana atau keterangan, sengaja menganjurkan orang lain supaya melakukan perbuatan. (2) Terhadap penganjur, hanya perbuatan yang sengaja dianjurkan sajalah yang diperhitungkan, beserta akibat-akibatnya."},{"l":"KUHP","p":"56","b":"Penyertaan dalam Tindak Pidana","t":"Dipidana sebagai pembantu kejahatan: 1. mereka yang sengaja memberi bantuan pada waktu kejahatan dilakukan; 2. mereka yang sengaja memberi kesempatan, sarana atau ke- terangan untuk melakukan kejahatan."},{"l":"KUHP","p":"57","b":"Penyertaan dalam Tindak Pidana","t":"(1) Dalam hal pembantuan, maksimum pidana pokok terhadap kejahatan, dikurangi sepertiga. (2) Jika kejahatan diancam dengan pidana mati atau pidana penjara seumur hidup, dijatuhkan pidana penjara paling lama lima belas tahun. (3) Pidana tambahan bagi pembantuan sama dengan kejahatannya sendiri. (4) Dalam menentukan pidana bagi pembantu, yang diperhitungkan hanya perbuatan yang sengaja dipermudah atau diperlancar olehnya, beserta akibat-akibatnya."},{"l":"KUHP","p":"58","b":"Penyertaan dalam Tindak Pidana","t":"Dalam menggunakan aturan-aturan pidana, keadaan-keadaan pribadi seseorang, yang menghapuskan, mengurangi atau memberatkan pengenaan pidana, hanya diperhitungkan terhadap pembuat atau pembantu yang bersangkutan itu sendiri."},{"l":"KUHP","p":"59","b":"Penyertaan dalam Tindak Pidana","t":"Dalam hal-hal di mana karena pelanggaran ditentukan pidana terhadap pengurus, anggota-anggota badan pengurus atau komisaris-komisaris, maka pengurus, anggota badan pengurus atau komisaris yang ternyata tidak ikut campur melakukan pelanggaran tidak dipidana."},{"l":"KUHP","p":"60","b":"Penyertaan dalam Tindak Pidana","t":"Membantu melakukan pelangaran tidak dipidana."},{"l":"KUHP","p":"61","b":"Penyertaan dalam Tindak Pidana","t":"(1) Mengenai kejahatan yang dilakukan dengan percetakan, penertiban selaku demikian tidak dituntut apabila dalam barang cetakkan disebut nama dan tempat tinggalnya, sedangkan pembuatnya dikenal, atau setelah dimulai penuntutan, pada waktu ditegur pertama kali lalu diberitahukan kepada penerbit. (2) Aturan ini tidak berlaku jika pelaku pada saat barang cetakkan terbit, tidak dapat dituntut atau sudah menetap di luar Indonesia."},{"l":"KUHP","p":"62","b":"Penyertaan dalam Tindak Pidana","t":"(1) Mengenai kejahatan yang dilakukan dengan percetakan, pencetaknya selaku demikian tidak dituntut apabila dalam barang cetakkan disebut nama dan tempat tinggalnya, sedangkan orang yang menyuruh mencetak dikenal, atau setelah dimulai penuntutan, pada waktu ditegur pertama kali lalu diberitahukan oleh pencetak. (2) Aturan ini tidak berlaku, jika orang yang menyuruh mencetak pada saat barang cetakkan terbit, tidak dapat dituntut sudah menetap di luar Indonesia."},{"l":"KUHP","p":"63","b":"Perbarengan Tindak Pidana","t":"(1) Jika suatu perbuatan masuk dalam lebih dari satu aturan pidana, maka yang dikenakan hanya salah satu di antara aturan-aturan itu; jika berbeda-beda, yang dikenakan yang memuat ancaman pidana pokok yang paling berat. (2) Jika suatu perbuatan masuk dalam suatu aturan pidana yang umum, diatur pula dalam aturan pidana yang khusus, maka hanya yang khusus itulah yang diterapkan."},{"l":"KUHP","p":"64","b":"Perbarengan Tindak Pidana","t":"(1) Jika antara beberapa perbuatan, meskipun masing-masing merupakan kejahatan atau pelanggaran, ada hubungannya sedemikian rupa sehingga harus dipandang sebagai satu perbuatan berlanjut, maka hanya diterapkan satu aturan pidana; jika berbeda-beda, yang diterapkan yang memuat ancaman pidana pokok yang paling berat. (2) Demikian pula hanya dikenakan satu aturan pidana, jika orang dinyatakan bersalah melakukan pemalsuan atau perusakan mata uang, dan menggunakan barang yang dipalsu atau yang dirusak itu. (3) Akan tetapi, jika orang yang melakukan kejahatan-kejahatan tersebut dalam pasal- pasal 364, 373, 379, dan 407 ayat 1, sebagai perbuatan berlanjut dan nilai kerugian yang ditimbulkan jumlahnya melebihi dari tiga ratus tujuh puluh lima rupiah, maka ia dikenakan aturan pidana tersebut dalam pasal 362, 372, 378, dan 406."},{"l":"KUHP","p":"65","b":"Perbarengan Tindak Pidana","t":"(1) Dalam hal perbarengan beberapa perbuatan yang harus dipandang sebagai perbuatan yang berdiri sendiri sehingga merupakan beberapa kejahatan, yang diancam dengan pidana pokok yang sejenis, maka dijatuhkan hanya satu pidana. (2) Maksimum pidana yang dijatuhkan ialah jumlah maksimum pidana yang diancam terhadap perbuatan itu, tetapi boleh lebih dari maksimum pidana yang trerberat ditambah sepertiga."},{"l":"KUHP","p":"66","b":"Perbarengan Tindak Pidana","t":"(1) Dalam hal perbarengan beberapa perbuatan yang masing-masing harus dipandang sebagai perbuatan yang berdiri sendiri sehingga merupakan beberapa kejahatan, yang diancam dengan pidana pokok yang tidak sejenis , maka dijatuhkan pidana atas tiap-tiap kejahatan, tetapi jumlahnya tidak boleh melebihi maksimum pidana yang terberat ditambah sepertiga. (2) Pidana denda adalah hal itu dihitung menurut lamanya maksimum pidana kurungan pengganti yang ditentukan untuk perbuatan itu."},{"l":"KUHP","p":"67","b":"Perbarengan Tindak Pidana","t":"Jika orang dijatuhi pidana mati atau pidana penjara seumur hidup, di samping itu tidak boleh dijatuhkan pidana lain lagi kecuali pencabutan hak-hak tertentu, dan pengumuman putusan hakim."},{"l":"KUHP","p":"68","b":"Perbarengan Tindak Pidana","t":"(1) Berdasarkan hal-hal dalam pasal 65 dan 66, tentang pidana tambahan berlaku aturan sebagai berikut: 1. pidana-pidana pencabutan hak yang sama dijadikan satu, yang lamanya paling sedikit dua tahun dan paling banyak lima tahun melebihi pidana pokok atau pidana-pidana pokok yang dijatuhkan. Jika pidana pokok hanya pidana denda saja, maka lamanya pencabutan hak paling sedikit dua tahun dan paling lama lima tahun; 2. pidana-pidana pencabutan hak yang berlainan dijatuhkan sendiri- sendiri tanpa dikurangi; 3. pidana-pidana perampasan barang-barang tertentu, begitu pula halnya dengan pidana kurungan pengganti karena barang-barang tidak diserahkan, dijatuhkan sendiri-sendiri tanpa dikurangi. (2) pidana kurungan-kurungan pengganti jumlahnya tidak boleh melebihi delapan bulan."},{"l":"KUHP","p":"69","b":"Perbarengan Tindak Pidana","t":"(1) Perbandingan beratnya pidana pokok yang tidak sejenis ditentukan menurut urut- urutan dalam pasal 10. (2) Jika hakim memilih antara beberapa pidana pokok, maka dalam perbandingan hanya terberatlah yang dipakai. (3) Perbandingan beratnya pidana-pidana pokok yang sejenis ditentukan menurut maksimumnya masing-masing. (4) Perbandingan lamanya pidana-pidana pokok yang sejenis ditentukan menurut maksimumnya masing-masing."},{"l":"KUHP","p":"70","b":"Perbarengan Tindak Pidana","t":"(1) Jika ada perbarengan seperti yang dimaksudkan dalam pasal 65 dan 66, baik perbarengan pelanggaran dengan kejahatan, maupun pelanggaran dengan pelanggaran, maka untuk tiap-tiap pelanggaran dijatuhkan pidana sendiri-sendiri tanpa dikurangi. (2) Mengenai pelanggaran, jumlah lamanya pidana kurungan dan pidana kurungan pengganti paling banyak satu tahun empat bulan, sedangkan jumlah lamanya pidana kurungan pengganti, paling banyak delapan bulan. Pasal 70 bis Ketika menerapkan pasal-pasal 65, 66, dan 70, kejahatan-kejahatan berdasarkan pasal- pasal 302 ayat 1, 352, 364, 373,379, dan 482 dianggap sebagai pelanggaran, dengan pengertian jika dijatuhkan pidana-pidana penjara atas kejahatan-kejahatan itu, jumlah paling banyak delapan bulan."},{"l":"KUHP","p":"71","b":"Perbarengan Tindak Pidana","t":"Jika seseorang telah dijatuhi pidana, kemudian dinyatakan bersalah lagi karena melakukan kejahatan atau pelanggaran lain sebelum ada putusan pidana itu, maka pidana yang dahulu diperhitungkan pada pidana yang akan dijatuhkan dengan menggunakan aturan-aturan dalam bab ini mengenai hal perkara-perkara diadili pada saat yang sama."},{"l":"KUHP","p":"72","b":"Pengaduan dalam Kejahatan Aduan","t":"(1) Selama orang yang terkena kejahatan yang hanya boleh dituntut atas pengaduan, dan orang itu umurnya belum cukup enam belas tahun dan lagi belum dewasa, atau selama ia berada di bawah pengampuan yang disebabkan oleh hal lain daripada keborosan, maka wakilnya yang sah dalam perkara perdata yang berhak mengadu; (2) Jika tidak ada wakil, atau wakil itu sendiri yang harus diadukan, maka penuntutan dilakukan atas pengaduan wali pengawas atau pengampu pengawas, atau majelis yang menjadi wali pengawas atau pengampu pengawas; juga mungkin atas pengaduan istrinya atau seorang keluarga sedarah dalam garis lurus, atau jika itu tidak ada, atas pengaduan seorang keluarga sedarah dalam garis menyimpang sampai derajat ketiga."},{"l":"KUHP","p":"73","b":"Pengaduan dalam Kejahatan Aduan","t":"Jika yang terkena kejahatan meninggal di dalam tenggang waktu yang ditentukan dalam pasal berikut maka tanpa memperpanjang tenggang itu, penuntutan dilakukan atas pengaduan orang tuanya, anaknya, atau suaminya (istrinya) yang masih hidup kecuali kalau ternyata bahwa yang meninggal tidak menghendaki penuntutan."},{"l":"KUHP","p":"74","b":"Pengaduan dalam Kejahatan Aduan","t":"(1) Pengaduan hanya boleh diajukan dalam waktu enam bulan sejak orang yang berhak mengadu mengetahui adanya kejahatan, jika bertempat tinggal di Indonesia, atau dalam waktu sembilan bulan jika bertempat tinggal di luar Indonesia. (2) Jika yang terkena kejahatan berhak mengadu pada saat tenggang waktu tersebut dalam ayat 1 belum habis, maka setelah saat itu, pengaduan masih boleh diajukan hanya selama sisa yang masih kurang pada tenggang waktu tersebut."},{"l":"KUHP","p":"75","b":"Pengaduan dalam Kejahatan Aduan","t":"Orang yang mengajukan pengaduan, berhak menarik kembali dalam waktu tiga bulan setelah pengaduan diajukan."},{"l":"KUHP","p":"76","b":"Hapusnya Kewenangan Menuntut & Menjalankan Pidana","t":"(1) Kecuali dalam hal putusan hakim masih mungkin diulangi, orang tidak boleh dituntut dua kali karena perbuatan yang oleh hakim Indonesia terhadap dirinya telah diadili dengan putusan yang menjadi tetap. Dalam artian hakim Indonesia, termasuk juga hakim pengadilan swapraja dan adat, di tempat-tempat yang mempunyai pengadilan-pengadilan tersebut. (2) Jika putusan yang menjadi tetap itu berasal dari hakim lain, maka terhadap orang itu dan karena tindak pidana itu pula, tidak boleh diadakan penuntutan dalam hal: 1. putusan berupa pembebasan dari tuduhan atau lepas dari tuntutan hukum; 2. putusan berupa pemidanaan dan telah dijalani seluruhnya atau telah diberi ampun atau wewenang untuk menjalankannya telah hapus karena daluwarsa."},{"l":"KUHP","p":"77","b":"Hapusnya Kewenangan Menuntut & Menjalankan Pidana","t":"Kewenangan menuntut pidana hapus, jika tertuduh meninggal dunia."},{"l":"KUHP","p":"78","b":"Hapusnya Kewenangan Menuntut & Menjalankan Pidana","t":"(1) Kewenangan menuntut pidana hapus karena daluwarsa: 1. mengenai semua pelanggaran dan kejahatan yang dilakukan dengan percetakan sesudah satu tahun; 2. mengenai kejahatan yang diancam dengan pidana denda, pidana kurungan, atau pidana penjara paling lama tiga tahun, sesudah enam tahun; 3. mengenai kejahatan yang diancam dengan pidana penjara lebih dari tiga tahun, sesudah dua belas tahun; 4. mengenai kejahatan yang diancam dengan pidana mati atau pidana penjara seumur hidup, sesudah delapan belas tahun. (2) Bagi orang yang pada saat melakukan perbuatan umurnya belum delapan belas tahun, masing-masing tenggang daluwarsa di atas dikurangi menjadi sepertiga."},{"l":"KUHP","p":"79","b":"Hapusnya Kewenangan Menuntut & Menjalankan Pidana","t":"Tenggang daluwarsa mulai berlaku pada hari sesudah perbuatan dilakukan, kecuali dalam hal-hal berikut: 1. mengenai pemalsuan atau perusakan mata uang, tenggang mulai berlaku pada hari sesudah barang yang dipalsu atau mata uang yang dirusak digunakan: 2. mengenai kejahatan dalam pasal-pasal 328, 329, 330, dan 333, tenggang dimulai pada hari sesudah orang yang langsung terkena oleh kejahatan dibebaskan atau meninggal dunia; 3. mengenai pelanggaran dalam pasal 556 sampai dengan pasal 558a, tenggang dimulai pada hari sesudah daftar-daftar yang memuat pelanggaran-pelanggaran itu, menurut aturan-aturan umum yang menentukan bahwa register-register catatan sipil harus dipindah ke kantor panitera suatu pengadilan , dipindah ke kantor tersebut."},{"l":"KUHP","p":"80","b":"Hapusnya Kewenangan Menuntut & Menjalankan Pidana","t":"(1) Tiap-tiap tindakan penuntutan menghentikan daluwarsa , asal tindakan itu diketahui oleh orang yang dituntut, atau telah diberitahukan kepadanya menurut cara yang ditentukan dalam aturan-aturan umum. (2) Sesudah dihentikan, dimulai tanggang daluwarsa baru."},{"l":"KUHP","p":"81","b":"Hapusnya Kewenangan Menuntut & Menjalankan Pidana","t":"Penundaan penuntutan pidana berhubung dengan adanya perselisihan pra-yudisial, menunda daluwarsa."},{"l":"KUHP","p":"82","b":"Hapusnya Kewenangan Menuntut & Menjalankan Pidana","t":"(1) Kewenangan menuntut pelanggaran yang diancam dengan pidana denda saja menjadi hapus, kalau dengan suka rela dibayar maksimum denda dan biaya-biaya yang telah dikeluarkan kalau penuntutan telah dimulai, atas kuasa pejabat yang ditunjuk untuk itu oleh aturan-aturan umum , dan dalam waktu yang ditetapkan olehnya. (2) Jika di samping pidana denda ditentukan perampasan, maka barang yang dikenai perampasan harus diserahkan pula, atau harganya harus dibayar menurut taksiran pejabat dalam ayat 1. (3) Dalam hal-hal pidana diperberat karena pengulangan, pemberatan itu tetap berlaku sekalipun kewenangan menuntut pidana terhadap pelanggaran yang dilakukan lebih dahulu telah hapus berdasarkan ayat 1 dan ayat 2 pasal ini. (4) Ketentuan-ketentuan dalam pasal ini tidak berlaku bagi orang yang belum dewasa, yang pada saat melakukan perbuatan belum berumur enam belas tahun."},{"l":"KUHP","p":"83","b":"Hapusnya Kewenangan Menuntut & Menjalankan Pidana","t":"Kewenangan menjalankan pidana hapus jika terpidana meninggal dunia."},{"l":"KUHP","p":"84","b":"Hapusnya Kewenangan Menuntut & Menjalankan Pidana","t":"(1) Kewenangan menjalankan pidana hapus karena daluwarsa. (2) Tenggang daluwarsa mengenai semua pelanggaran lamanya dua tahun, mengenai kejahatan yang dilakukan dengan sarana percetakan lamanya lima tahun, dan mengenai kejahatan-kejahatan lainnya lamanya sama dengan tenggang daluwarsa bagi penuntutan pidana, ditambah sepertiga. (3) Bagaimanapun juga, tenggang daluwarsa tidak boleh kurang dari lamanya pidana yang dijatuhkan. (4) Wewenang menjalankan pidana mati tidak daluwarsa."},{"l":"KUHP","p":"85","b":"Hapusnya Kewenangan Menuntut & Menjalankan Pidana","t":"(1) Tenggang daluwarsa mulai berlaku pada esak harinya setelah putusan hakim dapat dijalankan. (2) Jika seorang terpidana melarikan diri selama menjalani pidana, maka pada esok harinya setelah melarikan diri itu mulai berlaku tenggang daluwarsa baru. Jika suatu pelepasan bersyarat dicabut, maka pada esok harinya setelah pencabutan, mulai berlaku tenggang daluwarsa baru. (3) Tenggang daluwarsa tertuduh selama penjalanan pidana ditunda menurut perintah dalam suatu peraturan umum, dan juga selama terpidana dirampas kemerdekaannya, meskipun perampasan kemerdekaan itu berhubung dengan pemidanaan lain."},{"l":"KUHP","p":"86","b":"Arti Istilah dalam KUHP","t":"Apabila disebut kejahatan, baik dalam arti kejahatan pada umumnya maupun dalam arti suatu kejahatan tertentu, maka di situ termasuk pembantuan dan percobaan melakukan kejahatan, kecuali jika dinyatakan sebaliknya oleh suatu aturan."},{"l":"KUHP","p":"87","b":"Arti Istilah dalam KUHP","t":"Dikatakan ada makar untuk melakukan suatu perbuatan, apabila niat untuk itu telah ternyata dari adanya permulaan pelaksanaan, seperti dimaksud dalam pasal 53."},{"l":"KUHP","p":"88","b":"Arti Istilah dalam KUHP","t":"Dikatakan ada permufakatan jahat, apabila dua orang atau lebih telah sepakat akan melakukan kejahatan. Pasal 88 bis Dengan penggulingan pemerintahan dimaksud meniadakan atau mengubah secara tidak sah bentuk pemerintahan menurut Undang-Undang Dasar."},{"l":"KUHP","p":"89","b":"Arti Istilah dalam KUHP","t":"Membuat orang pingsan atau tidak berdaya disamakan dengan menggunakan kekerasan."},{"l":"KUHP","p":"90","b":"Arti Istilah dalam KUHP","t":"Luka berat berarti: • jatuh sakit atau mendapat luka yang tidak memberi harapan akan sembuh sama sekali, atau yang menimbulkan bahaya maut; • tidak mampu terus-menerus untuk menjalankan tugas jabatan atau pekerjaan pencarian; • kehilangan salah satu pancaindera; • mendapat cacat berat; • menderita sakit lumpuh; • terganggunya daya pikir selama empat minggu lebih; • gugur atau matinya kandungan seorang perempuan."},{"l":"KUHP","p":"91","b":"Arti Istilah dalam KUHP","t":"(1) Dalam kekuasaan bapak dicakup pula kekuasaan kepala keluarga. (2) Dengan orang tua, dimaksud pula kepala keluarga. (3) Dengan bapak, dimaksud pula orang yang menjalankan kekuasaan yang sama dengan bapak. (4) Dengan anak, dimaksud pula orang yang ada di bawah kekuasaan yang sama dengan kekuasaan bapak."},{"l":"KUHP","p":"92","b":"Arti Istilah dalam KUHP","t":"(1) Yang disebut pejabat, termasuk juga orang-orang yang dipilih dalam pemilihan yang diadakan berdasarkan aturan-aturan umum, begitu juga orang-orang yang bukan karena pemilihan, menjadi anggota badan pembentuk undang-undang, badan pemerintahan, atau badan perwakilan rakyat, yang dibentuk oleh pemerintah atau atas nama pemerintah; begitu juga semua anggota dewan subak, dan semua kepala rakyat Indonesia asli dan kepala golongan Timur Asing, yang menjalankan kekuasaan yang sah. (2) Yang disebut pejabat dan hakim termasuk juga hakim wasit; yang disebut hakim termasuk juga orang-orang yang menjalankan peradilan administratif, serta ketua-ketua dan anggota-anggota pengadilan agama. (3) Semua anggota Angkatan Perang juga dianggap sebagai pejabat. Pasal 92 bis Yang disebut pengusaha ialah tiap-tiap orang yang menjalankan perusahaan."},{"l":"KUHP","p":"93","b":"Arti Istilah dalam KUHP","t":"(1) Yang disebut nakoda ialah orang yang memegang kekuasaan di kapal atau yang mewakilinya. (2) Yang disebut penumpang ialah semua orang yang ada di kapal, kecuali nakoda. (3) Yang disebut anak buah kapal ialah semua perwira atau kelasi yang ada di dalam kapal."},{"l":"KUHP","p":"94","b":"Arti Istilah dalam KUHP","t":"Pasal ini ditiadakan berdasarkan Undang-undang No.1 Tahun 1946, pasal VIII, butir 11."},{"l":"KUHP","p":"95","b":"Arti Istilah dalam KUHP","t":"Yang disebut kapal Indonesia ialah kapal yang mempunyai surat laut atau pas kapal, atau surat izin sebagai pengganti sementara menurut aturan-aturan umum mengenai surat laut dan pas kapal di Indonesia."},{"l":"KUHP","p":"95a","b":"Arti Istilah dalam KUHP","t":"(1) Yang dimaksud dengan pesawat udara Indonesia adalah pesawat udara yang didaftarkan di Indonesia. (2) Termasuk pula pesawat udara Indonesia adalah pesawat udara asing yang disewa tanpa awak pesawat dan dioperasikan oleh perusahaan penerbangan Indonesia."},{"l":"KUHP","p":"95b","b":"Arti Istilah dalam KUHP","t":"Yang dimaksud dengan dalam penerbanagan adalah sejak saat pintu luar pesawat udara ditutup setelah naiknya penumpang (embarkasi) sampai saat pintu dibuka untuk penurunan penumpang (diembarkasi). Dalam hal terjadi pendaratan darurat penerbangan dianggap terus berlangsung sampai saat penguasa yang berwenang mengambil alih tanggung jawab atas pesawat udara dan barang yang ada di dalamnya."},{"l":"KUHP","p":"95c","b":"Arti Istilah dalam KUHP","t":"Yang diamksud dengan dalam dinas adalah jangka waktu sejak pesawat udara disiapkan oleh awak darat atau oleh awak pesawat untuk penerbangan tertentu, hingga setelah 24 jam lewat sesudah setiapendaratan."},{"l":"KUHP","p":"96","b":"Arti Istilah dalam KUHP","t":"(1) Yang disebut musuh termasuk juga pemberontak. Begitu juga termasuk di situ negara atau kekuasaan yang akan menjadi lawan perang. (2) Yang disebut perang termasuk juga permusuhan dengan daerah-daerah swapraja, begitu juga perang saudara. (3) Yang disebut masa perang termasuk juga waktu selama perang sedang mengancam. Begitu juga dikatakan masih ada masa perang, segera sesudah diperintahkan mobilisasi Angkatan Perang dan selama mobilisasi itu berlaku."},{"l":"KUHP","p":"97","b":"Arti Istilah dalam KUHP","t":"Yang disebut hari adalah waktu selama dua puluh empat jam; yang disebut bulan adalah waktu selama tiga puluh hari."},{"l":"KUHP","p":"98","b":"Arti Istilah dalam KUHP","t":"Yang disebut waktu malam yaitu waktu antara matahari terbenam dan matahari terbit."},{"l":"KUHP","p":"99","b":"Arti Istilah dalam KUHP","t":"Yang disebut memanjat termasuk juga masuk melalui lubang yang memang sudah ada, tetapi bukan untuk masuk atau masuk melalui lubang di dalam tanah yang dengan sengaja digali; begitu juga menyeberangi selokan atau parit yang digunakan sebagai batas penutup."},{"l":"KUHP","p":"100","b":"Arti Istilah dalam KUHP","t":"Yang disebut anak kunci palsu termasuk juga segala perkakas yang tidak dimaksud untuk membuka kunci."},{"l":"KUHP","p":"101","b":"Arti Istilah dalam KUHP","t":"Yang disebut ternak yaitu semua binatang yang berkuku satu, binatang memamah biak, dan babi. Pasal 101 bis (1) Yang dimaksud bangunan listrik yaitu bangunan-bangunan yang gunanya untuk membangkitkan, mengalirkan, mengubah, atau menyerahkan tenaga listrik; begitu pula alat-alat yang berhubungan dengan itu, yaitu alat-alat penjaga keselamatan, alat-alat pemasang, alat-alat pendukung, dan alat-alat peringatan. (2) Dengan bangunan-bangunan telegrap dan telepon tidak dimaksudkan bangunan listrik."},{"l":"KUHP","p":"102","b":"Arti Istilah dalam KUHP","t":"Ditiadakan dengan Staatsblad 1920 No. 382 Aturan Penutup"},{"l":"KUHP","p":"103","b":"Arti Istilah dalam KUHP","t":"Ketentuan-ketentuan dalam Bab I sampai Bab VIII buku ini juga berlaku bagi perbuatan- perbuatan yang oleh ketentuan perundang-undangan lainnya diancam dengan pidana, kecuali jika oleh undang-undang ditentukan lain. Buku Kedua – Kejahatan Daftar Isi 1. Bab - I Kejahatan Terhadap Keamanan Negara 2. Bab - II Kejahatan-kejahatan Terhadap Martabat Presiden dan Wakil Presiden 3. Bab - III Kejahatan-kejahatan Terhadap Negara Sahabat dan Terhadap Kepala Negara Sahabat Serta Wakilnya 4. Bab - IV Kejahatan Terhadap Melakukan Kewajiban dan Hak Kenegaraan 5. Bab - V Kejahatan Terhadap Ketertiban Umum 6. Bab - VI Perkelahian Tanding 7. Bab - VII Kejahatan yang Membahayakan Keamanan Umum bagi Orang atau Barang 8. Bab - VIII Kejahatan Terhadap Penguasa Umum 9. Bab - IX Sumpah Palsu dan Keterangan Palsu 10. Bab - X Pemalsuan Mata Uang dan Uang Kertas 11. Bab - XI Pemalsuan Meterai dan Merek 12. Bab - XII Pemalsuan Surat 13. Bab - XIII Kejahatan Terhadap Asal-Usul dan Perkawinan 14. Bab - XIV Kejahatan Terhadap Kesusilaan 15. Bab - XV Meninggalkan Orang yang Perlu Ditolong 16. Bab - XVI Penghinaan 17. Bab - XVII Membuka Rahasia 18. Bab - XVIII Kejahatan Terhadap Kemerdekaan Orang 19. Bab - XIX Kejahatan Terhadap Nyawa 20. Bab - XX Penganiayaan 21. Bab - XXI Menyebabkan Mati atau Luka-luka Karena Kealpaan 22. Bab - XXII Pencurian 23. Bab - XXIII Pemerasan dan Pengancaman 24. Bab - XXIV Penggelapan 25. Bab - XXV Perbuatan Curang 26. Bab - XXVI Perbuatan Merugikan Pemiutang atau Orang yang Mempunyai Hak 27. Bab - XXVII Menghancurkan atau Merusakkan Barang 28. Bab - XXVIII Kejahatan Jabatan 29. Bab - XXIX Kejahatan Pelayaran 30. Bab - XXIX A Kejahatan Penerbangan dan Kejahatan Terhadap Sarana/Prasarana Penerbangan 31. Bab - XXX Penadahan Penerbitan dan Percetakan"},{"l":"KUHP","p":"104","b":"Kejahatan Terhadap Keamanan Negara","t":"Makar dengan maksud untuk membunuh, atau merampas kemerdekaan, atau meniadakan kemampuan Presiden atau Wakil Presiden memerintah, diancam dengan pidana mati atau pidana penjara seumur hidup atau pidana penjara sementara paling lama dua puluh tahun."},{"l":"KUHP","p":"105","b":"Kejahatan Terhadap Keamanan Negara","t":"Pasal ini ditiadakan berdasarkan Undang-undang No. 1 Tahun 1946, pasal VIII, butir 13."},{"l":"KUHP","p":"106","b":"Kejahatan Terhadap Keamanan Negara","t":"Makar dengan maksud supaya seluruh atau sebagian dari wilayah negara, diancam dengan pidana penjara seumur hidup atau pidana penjara sementara paling lama dua puluh tahun."},{"l":"KUHP","p":"107","b":"Kejahatan Terhadap Keamanan Negara","t":"(1) Makar dengan maksud untuk menggulingkan pemerintah, diancam dengan pidana penjara paling lama lima belas tahun. (2) Para pemimpin dan pengatur makar tersebbut dalam ayat 1, diancam dengan pidana penjara seumur hidup atau pidana penjara sementara paling lama dua puluh tahun."},{"l":"KUHP","p":"108","b":"Kejahatan Terhadap Keamanan Negara","t":"(1) Barang siapa bersalah karena pemberontakan, diancam dengan pidana penjara paling lama lima belas tahun: 1. orang yang melawan pemerintah Indonesia dengan senjata; 2. orang yang dengan maksud melawan Pemerintah Indonesia menyerbu bersama-sama atau menggabungkan diri pada gerombolan yang melawan Pemerintah dengan senjata. (2) Para pemimpin dan para pengatur pemberontakan diancam dengan penjara seumur hidup atau pidana penjara sementara paling lama dua puluh tahun."},{"l":"KUHP","p":"109","b":"Kejahatan Terhadap Keamanan Negara","t":"Pasal iani ditiadakan berdasarkan S. 1930 No. 31."},{"l":"KUHP","p":"110","b":"Kejahatan Terhadap Keamanan Negara","t":"(1) Permufakatan jahat untuk melakukan kejahatan menurut pasal 104, 106, 107, dan 108 diancam berdasarkan ancaman pidana dalam pasal-pasal tersebut. (2) Pidana yang sama diterapkan terhadap orang-orang yang dengan maksud berdasarkan pasal 104, 106, dan 108, mempersiapkan atau memperlancar kejahatan: 1. berusaha menggerakkan orang lain untuk melakukan, menyuruh melakukan atau turut serta melakukan agar memberi bantuan pada waktu melakukan atau memberi kesempatan, sarana atau keterangan untuk melakukan kejahatan; 2. berusaha memperoleh kesempatan, sarana atau keterangan untuk melakukan kejahatan bagi diri sendiri atua orang lain; 3. memiliki persediaan barang-barang yang diketahuinya berguna untuk melakukan kejahatan; 4. mempersiapkan atau memiliki rencana untuk melaksanakan kejahatan yang bertujuan untuk memberitahukan kepada orang lain; 5. berusaha mencegah, merintangi atau menggagalkan tindakan yang diadakan pemerintah untuk mencegah atau menindas pelaksanaan kejahatan. (3). Barang-barang sebagaimana dimaksud dalam butir 3 ayat sebelumnya, dapat dirampas. (4) Tidak dipidana barang siapa yang ternyata bermaksud hanya mempersiapkan atau memperlancar perubahan ketatanegaraan dalam artian umum. (5) Jika dalam salah satu hal seperti yang dimaksud dalam ayat 1 dan 2 pasal ini, kejahatan sungguh terjadi, pidananya dapat dilipatkan dua kali."},{"l":"KUHP","p":"111","b":"Kejahatan Terhadap Keamanan Negara","t":"(1) Barang siapa mengadakan hubungan dengan negara asing dengan maksud menggerakkannya untuk melakukan perbuatan permusuhan atau perang terhadap negara, memperkuat niat mereka, menjanjikan bantuan atau membantu mempersiapkan mereka untuk melakukan perbuatann permufakatan atua perang terhadap negara, diancam dengan pidana penjara paling lama lima belas tahun. (2) Jika perbuatan permusuhan dilakukan atau terjadi perang, diancam dengan pidana mati atua pidana penjara seumur hidup atau pidana penjara sementara paling lama dua puluh tahun. Pasal 111 bis (1) Dengan pidana penjara paling lama enam tahun diancam: 1. barang siapa mengadakan hubungan dengan orang atau badan yang berkedudukan di luar Indonesia, dengan maksud untuk menggerakan orang atau badan itu supaya membantu mempersiapkan, memperlancar atau menggerakkan untuk menggulingkan pemerintah, untuk memperkuat niat orang atau badan itu atua menjanjikan atau memberi bantuan kepada orang atau badan itu atau menyiapkan, memperlancar atau menggerakkan penggulingan pemerintah; 2. barang siapa memaksudkan suatu benda yang dapat digunakan untuk memberi bantuan material dalam mempersiapkan, memperlancar atau menggerakkan penggulingan pemerintah, sedangkan diketahuinya atau ada alasan kuat untuk memnduga bahwa benda tersebut akan dipergunakan untuk perbuatan tersebut; 3. orang yang mempunyai atau mengadakan perjanjian mengenai suatu benda yang dapat dipergunakan untuk memberikan bantuan material dalam mempersiapkan, memperlancar atau menggerakkan penggulingan pemerintah, sedangkan diketahuinya atau ada alasan baginya untuk menduga bahwa benda itu akan dipergunakan untuk perbuatan tersebut atau benda itu atau barang lainsebagai penggantinya, dimaksudkan dengan tujuan tersebut atau untuk untuk diperuntukkan bagi tujuan itu oleh orang atau benda yang berkedudukan di luar Indonesia. (2) Benda-benda yang dengan mana atau yang ada hubungan dengan ayat 1 ke-2 dan ke-3 yang dipakai untuk melakukan kejahatan, dapat dirampas."},{"l":"KUHP","p":"112","b":"Kejahatan Terhadap Keamanan Negara","t":"Barang siapa dengan sengaja mengumumkan surat-surat, berita-berita atau keterangan- keterangan yang diketahuinya bahwa harus dirahasiakan untuk kepentingan negara, atau dengan sengaja memberitahukan atau memberikannya kepada negara asing, diancam dengan pidana penjara paling lama tujuh tahun."},{"l":"KUHP","p":"113","b":"Kejahatan Terhadap Keamanan Negara","t":"(1) Barang siapa dengan sengaja, untuk seluruhnya atau sebagian mengumumkan, atau memberitahukan maupun menyerahkan kepada orang yang tidak berwenang mengetahui, surat-surat, peta-peta, rencana-rencana, gambar-gambar atau benda- benda yang bersifat rahasia yang bersangkutan dengan pertahanan atau keamanan Indonesia terhadap serangan dari luar, yang ada padanya atau yang isinya, bentuknya atau susunanya benda- benda itu diketahui olehnya, diancam dengan pidana penjara paling lama empat tahun. (2) Jika surat-surat atau benda-benda ada pada yang bersalah, atau pengetahuannya tentang itu karena pencariannya, pidananya dapat ditambah sepertiga."},{"l":"KUHP","p":"114","b":"Kejahatan Terhadap Keamanan Negara","t":"Barang siapa karena kesalahannya (kealpaannya) menyebabkan surat-surat atau benda- benda rahasia sebagaimana yang dimaksudkan dalam pasal 113 harus menjadi tugasnya untuk menyimpan atau menaruhnya, bentuk atau susunannya atau seluruh atau sebagian diketahui oleh umum atau dikuasai atau diketahui oleh orang lain (atau) tidak berwenang mengetahui, diancam dengan pidana penjara paling lama satu tahun enam bulan atau pidana kurungan paling lama satu tahun atau pidana denda paling tinggi empat ribu lima ratus rupiah."},{"l":"KUHP","p":"115","b":"Kejahatan Terhadap Keamanan Negara","t":"Barang siapa melihat atua membaca surat-surat atau benda-benda rahasia sebagaimana dimaksud dalam pasal 113, untuk seluruhnya atau sebagian, sedangkan diketahui atau selayaknya harus diduganya bahwa benda-benda itu tidak dimaksud untuk diketahui olehnya, begitu pula jika membuat atau menyuruh membuat salinan atau ikhtisar dengan huruf atau dalam bahasa apa pun juga, membuat atau menyuruh buat teraan, gambaran atau jika tidak menyerahkan benda-benda itu kepada pejabat kehakiman, kepolisian atau pamongh praja, dalam hal benda-benda itu ke tangannya, diancam dengan pidana penjara palling lama tiga tahun."},{"l":"KUHP","p":"116","b":"Kejahatan Terhadap Keamanan Negara","t":"Permufakatan jahat untuk melakukan kejahatan sebagaimana diamksud dalam pasal 113 dan 115, diancam dengan pidana penjara paling lama satu atahun."},{"l":"KUHP","p":"117","b":"Kejahatan Terhadap Keamanan Negara","t":"Diancam dengan pidana penjara paling lama enam bulan atau denda paling banyak empat ribu lima ratus rupiah, barang siapa tanpa wenang. 1. dengan sengaja memasuki bangunan Angkatan Darat atau Angkatan Laut, atau memasuki kapal perang melalui jalan yang bukan jalan biasa; 2. dengan sengaja memasuki daerah, yang oleh Presiden atau atas namanya, atau oleh penguasa tentara ditentukan sebagai daerah tentara yang dilarang; 3. dengan sengaja membuat, mengumpulkan, mempunyai, menyimpan, menyembunyikan atau mangangkut gambat potret atau gambar tangan maupun keterangan-keterangan atau petunjuk-petunjuk lain mengenai daerah seperti tersebut dalam pasal ke-2, beserta segala sesuatu yang ada disitu."},{"l":"KUHP","p":"118","b":"Kejahatan Terhadap Keamanan Negara","t":"Diancam dengan pidana penjara paling lama dua tahun atau denda sembilan ribu rupiah, barang siapa tanpa wenang, sengaja membuat, mengumpulkan, mempunyai, menyimpan, menyembunyikan atau petunjuk-petunjuk lain mengenai sesuatu hal yang bersangkutan dengan kepentingan tentara."},{"l":"KUHP","p":"119","b":"Kejahatan Terhadap Keamanan Negara","t":"Diancam dengan pidana penjara paling lama satu tahun: 1. barang siapa memberi pondokan kepada orang lain, yang diketahuinya mempunyai niat atau sedang mencoba untuk mengetahui benda-benda rahasia seperti tersebut dalam pasal 113, padahal tidak wenang untuk itu, atau mempunyai niat atau sedang mencoba untuk mengetahui letak, bentuk, susunan, persenjataan, perbekalan, perlengkapan mesin, atau kekuatan orang dari bangunan pertahanan atau sesuatu hal lain yang bersangkutan dengan kepentingan tentara; 2. barang siapa menyembunyikan benda-benda yang diketahuinya behawa dengan cara apapun juga, akan diperlukan dalam melaksanakan niat seperti tersebut pada ke-1."},{"l":"KUHP","p":"120","b":"Kejahatan Terhadap Keamanan Negara","t":"Jika kejahatan tersebut pasal 113, 115, 117, 118, 119 dilakukan dengan akal curang seperti penyesatan, menyamakan, pemakaian nama atau kedudukan palsu, atau dengan menawarkan atau menerima, membayangkan atau menjanjikan hadiah, keuntungan atau upah dalam bentuk apapun juga, atau dilakukan dengan kekerasan atau ancaman kekerasan, maka pidana hilang kemerdekaan dapat diperberat lipat dua."},{"l":"KUHP","p":"121","b":"Kejahatan Terhadap Keamanan Negara","t":"Barang siapa ditugaskan pemerintah untuk berunding dengan suatu negara asing, dengan sengaja merugikan negara, diancam dengan pidana penjara paling lama dua belas tahun."},{"l":"KUHP","p":"122","b":"Kejahatan Terhadap Keamanan Negara","t":"Diancam dengan pidana penjara paling lama tujuh tahun: 1. barang siapa dalam masa perang yang tidak menyangkut Indonesia, dengan sengaja melakukan perbuatan yang membahayakan kenetralan negara, atau dengan sengaja melanggar suatu aturan yang dikeluarkan dan diumumkan oleh pemerintah, khusus untuk mempertahankan kenbetralan tersebut; 2. barang siapa dalam masa perang dengan sengaja melanggar aturan yang dikeluarkan dan diumumkan oleh pemerintah guna keselamatan negara."},{"l":"KUHP","p":"123","b":"Kejahatan Terhadap Keamanan Negara","t":"Seorang warga negara Indonesia yang dengan suka rela masuk tentara negara asing, pada hal ia mengetahui bahwa negara itu sedang perang dengan negara Indonesaia, atau akan menghadapi perang dengan Indonesia, diancam dalam hal terakhir jika pecah perang, denga pidana penjara paling lama lima belas tahun."},{"l":"KUHP","p":"124","b":"Kejahatan Terhadap Keamanan Negara","t":"(1) Barang siapa dalam masa perang dengan sengaja memberi bantuan kepada musuh atau merugikan negara terhadap musuh, diancam dengan pidana penjara lima belas tahun. (2) Diancam dengan pidana penjara seumur hidup atau selama waktu tertentu atau paling lama dua puluh tahun jika si pembuat: 1. memberitahukan atau memberikan kepada musuh peta, rencana, gambar, atau penulisan mengenai bangunan-bangunan tentara; 2. menjadi mata-mata musuh, atau memberikan pondokan kepadanya. (3) Pidana mati atau pidana seumur hidup atau selama waktu tertentu paling lama dua puluh tahun dijatuhkan jika si pembuat: 1. memberitahukan atau menyerahkan kepada musuh, menghancurkan atau merusakkan sesuatu tempat atau pos yang diperkuat atau diduduki, suatu alat perhubungan, gudang persediaan perang, atau kas perang ataupun Angkatan Laut, Angkatan Darat atau bagian daripadanya, merintangi, menghalang-halangi atau menggagalkan suatu untuk menggenangi air atau karya tentara lainya yang direncanakan atau diselenggarakan untuk menangkis tau menyerang; 2. menyebabkan atau memperlancar timbulnya huru-hara, pemberontakan atau desersi dikalangan Angkatan Perang."},{"l":"KUHP","p":"125","b":"Kejahatan Terhadap Keamanan Negara","t":"Permufakatan jahat untuk melakukan kejahatan sebagaimana dimaksudkan dalam pasal 124, diancam dengan pidana paling lama enam tahun."},{"l":"KUHP","p":"126","b":"Kejahatan Terhadap Keamanan Negara","t":"Diancam dengan pidana penjara paling lama tujuh tahun barang siapa dalam masa perang, tidak dengan maksud membantu musuh atau merugikan negara sehingga menguntungkan musuh, dnegan sengaja: 1. memberikan pondokan kepada mata-mata musuh, menyembunyikannya atau membantunya melarikan diri; 2. menggerakkan atau memperlancar pelarian (desersi) prajurit yang bertugas untuk negara."},{"l":"KUHP","p":"127","b":"Kejahatan Terhadap Keamanan Negara","t":"(1) Barang siapa dalam masa perang menjalankan tipu muslihat dalam penyerahan barang-barang keperluan Angkatan Laut atau Angkatan Darat, diancam dengan pidana penjara paling lama dua belas tahun. (2) Diancam dengan pidana yang sama barang siapa diserahi mengawasi penyerahan barang-barang, membiarkan tipu muslihat itu."},{"l":"KUHP","p":"128","b":"Kejahatan Terhadap Keamanan Negara","t":"(1) Dalam hal pemidanaan berdasarkan kejahatan pasal 104, dapat dipidana pencabutan hak-hak berdasarkan pasal 35 no. 1-5. (2) Dalam hal pemidanaan berdasarkan kejahatan pasal-pasal 106-108, 110-125, dapat dipidana pencabutan hak-hak berdasarkan pasal 35 no. 1-3. (3) Dalam hal pemidanaan berdasarkan kejahatan pasal 127, yang bersalah dapat dilarang menjalankan pencarian yang dijalankannya ketika melakukan kejahatan itu, dicabut hak- hak berdasarkan pasal 35 no. 1-4, dan dapat diperintahkan supaya putusan hakim diumumkan."},{"l":"KUHP","p":"129","b":"Kejahatan Terhadap Keamanan Negara","t":"Pidana-pidana yang berdasarkan terhadap perbuatan-perbuatan dalam pasal-pasal 124- 127, diterapkan jika salah satu perbuatan dilakukan terhadap atua bersangkutan dengan negara sekutu dalam perang bersama. Bab II Kejahatan-Kejahatan Terhadap Martabat Presiden Dan Wakil Presiden"},{"l":"KUHP","p":"130","b":"Kejahatan Terhadap Keamanan Negara","t":"Pasal ini ditiadakan berdasarkan Undang-undang No. 1 Tahun 1946, pasal VIII, butir 21."},{"l":"KUHP","p":"131","b":"Kejahatan Terhadap Keamanan Negara","t":"Tiap-tiap penyerangan terhadap diri presiden atau Wakil Presiden, yang tidak termasuk dalam ketentuan pidana lain yang lebih berat, diancam dengan pidana penjara paling lama delapan tahun."},{"l":"KUHP","p":"132","b":"Kejahatan Terhadap Keamanan Negara","t":"Pasal ini ditiadakan berdasarkan Undang-undang No. 1 Tahun 1946, pasal VIII, butir 23."},{"l":"KUHP","p":"133","b":"Kejahatan Terhadap Keamanan Negara","t":"Pasal ini ditiadakan berdasarkan Undang-undang No. 1 Tahun 1946, pasal VIII, butir 23."},{"l":"KUHP","p":"134","b":"Kejahatan Terhadap Keamanan Negara","t":"Penghinaan dengan sengaja terhadap Presiden atua Wakil Presiden diancam dengan pidana penjara paling lama enam tahun, atau pidana denda paling banyak empat ribu lima ratus ribu rupiah."},{"l":"KUHP","p":"135","b":"Kejahatan Terhadap Keamanan Negara","t":"Pasal ini ditiadakan bersarkan Undang-undang No. 1 Tahun 1946, pasal VIII, butir 25."},{"l":"KUHP","p":"136","b":"Kejahatan Terhadap Keamanan Negara","t":"Pasal ini ditiadakan berdasarkan Undang-undang No. 1 Tahun 1946, pasal VIII butir 25. Pasal 136 bis Pengertian penghinaan sebagaimana dimaksud dalam pasal 134 mencakup juga perumusan perbuatan dalam pasal 135, jika itu dilakukan diluar kehadiran yang dihina, baik dengan tingkah laku di muka umum, maupun tidak dimuka umum baik lidsan atau tulisan, namun dihadapan lebih dari empat orang, atau di hadapan orang ketiga, bertentangan dengan kehendaknya dan oleh karena itu merasa tersinggung."},{"l":"KUHP","p":"137","b":"Kejahatan Terhadap Keamanan Negara","t":"(1) Barang siapa menyiarkan, mempertunjukan, atau menempelkan di muka umum tulisan atau lukisan yang berisi penghinaan terhadap Presiden atau Wakil Presiden, dengan maksud supaya isi penghinaan diketahui atau lebih diketahui oleh umum, diancam dengan pidana penjara paling lama satu tahun empat bulan atau pidana denda paling banyak empat ribu lima ratus rupiah. (2) Jika yang bersalah melakukan kejahatan pada waktu menjalankan pencariannya, dan pada waktu itu belum lewat dua tahun sejak adanya pemidanaan menjadi tetap karena kejahatan semacam itu juga, maka terhadapnya dapat dilarang menjalankan pencarian tersebut."},{"l":"KUHP","p":"138","b":"Kejahatan Terhadap Keamanan Negara","t":"Pasal ini ditiadakan berdasarkan Undang-undang No. 1 Tahun 1946, pasal VIII, butir 28."},{"l":"KUHP","p":"139","b":"Kejahatan Terhadap Keamanan Negara","t":"(1) Ayat ini ditiadakan berdasarkan Undang-undang No. 1 Tahun 1946, pasal VIII, butir 29. (2) Dalam hal pemidanaan berdasarkan perumusan kejahatan dalam pasal 131, dapat dipidana pencabutan hak berdasarkan pasal 35 no. 1-4. (3) Dalam hal pemidanaan berdasarkan perumusan kejahatan dalam pasal 134, dapat dipidana pencabutan hak berdasarkan pasal 35 no. 1-3."},{"l":"KUHP","p":"139a","b":"Kejahatan Terhadap Negara Sahabat & Kepala Negara","t":"Makar dengan maksud melepaskan wilayah atau daerah lain dari suatu negara sahabat untuk seluruhnya atau sebagian dari kekuasaan pemerintah yang berkuasa di situ, diancam dengan pidana penjara paling lama lima tahun."},{"l":"KUHP","p":"139b","b":"Kejahatan Terhadap Negara Sahabat & Kepala Negara","t":"Makar dengan maksud meniadakan atau mengubah secara tidak sah bentuk pemerintahan negara sahabat atau daerahnya yang lain, diancam dengan pidana penjara paling lama empat tahun."},{"l":"KUHP","p":"139c","b":"Kejahatan Terhadap Negara Sahabat & Kepala Negara","t":"Permufakatan jahat untuk melakukan kejahatan sebagaimana dirumuskan dalam pasal- pasal 139a dan 139b, diancam dengan pidana penjara paling lama satu tahun enam bulan."},{"l":"KUHP","p":"140","b":"Kejahatan Terhadap Negara Sahabat & Kepala Negara","t":"(1) Makar terhadap nyawa atau kemerdekaan raja yang memerintah atau kepala negara sahabat, diancam dengan pidana penjara paling lama lima belas tahun. (2) Jika mekar terhadap nyawa mengakibatkan kematian atau dilakukan dengan rencana terlebih dahulu mengakibatkan kematian, diancam dengan pidana mati atau pidana penjara seumur hidup atau pidana penjara sementara paling lama dua puluh tahun. (3) Jika makar terhadap nyawa dilakukan dengan rencana terlebih dahulu mengakibatkan kematian, diancam dengan pidana mati atau pidana penjara seumur hidup atau pidana penjara sementara paling lama dua puluh tahun."},{"l":"KUHP","p":"141","b":"Kejahatan Terhadap Negara Sahabat & Kepala Negara","t":"Tiap-tiap perbuatan penyerangan terhadap diri raja yang memerintah atau kepala negara sahabat, yang tidak termasuk dalam ketentuan pidana yang lebih berat, diancam dengan pidana penjara paling lama tujuh tahun."},{"l":"KUHP","p":"142","b":"Kejahatan Terhadap Negara Sahabat & Kepala Negara","t":"Penghinaan dengan sengaja terhadap raja yang memerintah atau kepala negara sahabat, diancam dengan pidana penjara paling lama lima tahun atau pidana paling banyak empat ribu lima ratus ribu rupiah."},{"l":"KUHP","p":"142a","b":"Kejahatan Terhadap Negara Sahabat & Kepala Negara","t":"Barang siapa menodai bendera kebangsaan negara sahabat diancam dengan pidana penjara paling lama empat tahun atau pidana denda paling banyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"144","b":"Kejahatan Terhadap Negara Sahabat & Kepala Negara","t":"(1) Barang siapa menyiarkan, mempertunjukkan atau menempelkan dimuka umum tulisan atau lukisan yang berisi penghinaan terhadap raja yang memerintah, atau kepala negara sahabat, atau wakil negara asing di Indonesia dalam pangkatnya, dengan maksud supaya penghinaan itu diketahui atau lebih diketahui oleh umum, diancam dengan pidana penjara paling lama sembilan bulan atau pidana denda paling banyak empat ribu lima ratus rupiah. (2) Jika yang bersalah melakukan kejahatan itu pada waktu menjalankan pencarianya, dan pada saat itu belum lewat dua tahun sejak ada pemidanaan yang tetap karena kejahatan semacam itu juga, ia dapat dilarang menjalankan pencarian tersebut."},{"l":"KUHP","p":"145","b":"Kejahatan Terhadap Negara Sahabat & Kepala Negara","t":"(1) Dalam hal pemidanaan berdasarkan perumusan kejahatan dalam pasal 140, dapat dipidanan pencabutan hak berdasarkan pasal 35 no. 1-5. (2) Dalam hal pemidanaan berdasarkan perumusan kejahatan dalam pasal 141, dapat dipidana pencabutan hak berdasarkan pasal 335 no. 1-4. (3) Dalam hal pemidanaan berdasarkan perumusan kejahatan dalam pasal-pasal 139a, 139b, 139c, 142, dan 143, dapat dipidana pencabutan hak berdasarkan pasal 35 no. 1-3. Bab IV Kejahatan Terhadap Melakukan Kewajiban Dan Hak Kenegaraan"},{"l":"KUHP","p":"146","b":"Kejahatan Terhadap Negara Sahabat & Kepala Negara","t":"Barang siapa dengan kekerasan atau ancaman kekerasan membubarkan rapat badan pembentuk undang-undang, badan pemerintahan atau badan perwakilan rakyat, yang dibentuk oleh atau atas nama Pemerintah, atau memaksa badan-badan itu supaya mengambil atau tidak mengambil sesuatu putusan atau mengambil sesuatu putusan atau mengusir ketua atau anggota rapat itu, diancam dengan ancaman penjara paling lama sembilan tahun."},{"l":"KUHP","p":"147","b":"Kejahatan Terhadap Negara Sahabat & Kepala Negara","t":"Barang siapa dengan kekerasan atau ancaman kekerasan, dengan sengaja merintangi ketua atau anggota badan pembentuk undang-undang, badan pemerintahan atau badan perwakilan rakyat, yang dibentuk oleh atau atas nama Pemerintah, untuk menghadiri rapat badan-badan itu, diancam dengan pidana penjara paling lama dua tahun delapan bulan."},{"l":"KUHP","p":"148","b":"Kejahatan Terhadap Negara Sahabat & Kepala Negara","t":"Barang siapa pada waktu diadakan pemilihan berdasarkan aturan-aturan umum, dengan kekerasan atau ancaman kekerasan, dengan sengaja merintangi seseorang memakai hak pilihnya dengan bebas dan tidak terganggu, diancam dengan pidana penjara paling lama satu tahun empat bulan."},{"l":"KUHP","p":"149","b":"Kejahatan Terhadap Negara Sahabat & Kepala Negara","t":"(1) Barang siapa pada waktu diadakan pemilihan berdasarkan aturan-aturan umum, dengan memberi atau menjanjikan sesuatu, menyuap seseorang supaya tidak memakai hak pilihnya atau supaya memakai hak itu menurut cara tertentu, diancam dengan pidana penjara paling lama sembilan bulan atau pidana denda paling lama empat ribu lima ratus rupiah. (2) Pidana yang sama diterapkan kepada pemilih, yang dengan menerima pemberian atau janji, mau disuap."},{"l":"KUHP","p":"150","b":"Kejahatan Terhadap Negara Sahabat & Kepala Negara","t":"Barang suiapa pada waktu diadakan pemilihan berdasarkan aturan-aturan umum, melakukan tipu muslihat berdasarkan aturan-aturan umum, melakukan tipu muslihat sehingga suara seorang pemilih menjadi tidak berharga atau menyebabkan orang lain daripada yang dimaksud oleh pemilih yang ditunjuk, diancam dengan pidana penjara paling lama sembilan bulan."},{"l":"KUHP","p":"151","b":"Kejahatan Terhadap Negara Sahabat & Kepala Negara","t":"Barang siapa memakai nama orang lain untuk ikut dalam pemilihan berdasarkan aturan- aturan umum, diancam dengan pidana penjara paling lama satu tahun empat bulan."},{"l":"KUHP","p":"152","b":"Kejahatan Terhadap Negara Sahabat & Kepala Negara","t":"Barang siapa pada waktu diadakan pemilihan berdasarkan aturan-aturan umum dengan sengaja menggagalkan pemungutan suara yang telah diadaka atau mengadakan tipu muslihat yang menyebabkan putusan pemungutan suara itu lain dari yang seharusnya diperoleh berdasarkan kartu-kartu pemungutan suara yang masuk secara sah atau berdasarkan suara-suara yang dikeluarkan secara sah, diancam dengan pidana penjara paling lama dua tahun."},{"l":"KUHP","p":"153","b":"Kejahatan Terhadap Negara Sahabat & Kepala Negara","t":"(1) Dalam hal pemidanaan berdasarkan perumusan kejahatan dalam pasal 146, dapat dipidana pencabutan hak berdasarkan pasal 35 ke 1-3. (2) Dalam hal pemidanaan berdasarkan perumusan kejahatan dalam pasal 147-152, dapat dipidana pencabutan hak berdasarkan pasal 35 ke-3."},{"l":"KUHP","p":"154","b":"Kejahatan Terhadap Ketertiban Umum","t":"Barang siapa di muka umum menyatakan perasaan permusuhan, kebencian atau penghinaan terhadap Pemerintah Indonesia, diancam dengan pidana penjara paling lama tujuh tahun atau pidana denda paling banyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"154a","b":"Kejahatan Terhadap Ketertiban Umum","t":"Barang siapa menodai bendera kebangsaan Republik Indonesia dan lambang Negara Republik Indonesia, diancam dengan pidana penjara paling lama empat tahun atau pidana denda paling banyak empat puluh lima ribu rupiah."},{"l":"KUHP","p":"155","b":"Kejahatan Terhadap Ketertiban Umum","t":"(1) Barang siapa menyiarkan, mempertunjukkan atau menempelkan tulisan atau lukisan di muka umum yang mengandung pernyataan perasaan permusuhan, kebencian atau penghinaan terhadap Pemerintah Indonesia, dengan maksud supaya isinya diketahui atau lebih diketahui oleh umum, diancam dengan pidana penjara paling lama empat tahun enam bulan atau pidana denda paling banyak empat ribu lima ratus rupiah. (2) Jika yang bersalah melakukan kejahatan tersebut pada waktu menjalankan pencariannya dan pada saat itu belum lewat lima tahun sejak pemidanaannya menjadi tetap karena melakukan kejahatan semacam itu juga, yang bersangkutan dapat dilarang menjalankan pencarian tersebut."},{"l":"KUHP","p":"156","b":"Kejahatan Terhadap Ketertiban Umum","t":"Barang siapa di rnuka umum menyatakan perasaan permusuhan, kebencian atau penghinaan terhadap suatu atau beherapa golongan rakyat Indonesia, diancam dengan pidana penjara paling lama empat tahun atau pidana denda paling banyak empat ribu lima ratus rupiah. Perkataan golongan dalam pasal ini dan pasal berikutnya berarti tiap- tiap bagian dari rakyat Indonesia yang berbeda dengan suatu atau beberapa hagian lainnya karena ras, negeri asal, agama, tempat, asal, keturunan, kebangsaan atau kedudukan menurut hukum tata negara."},{"l":"KUHP","p":"156a","b":"Kejahatan Terhadap Ketertiban Umum","t":"Dipidana dengan pidana penjara selama-lumanya lima tahun barang siapa dengan sengaja di muka umum mengeluarkan perasaan atau melakukan perbuatan: a. yang pada pokoknya bcrsifat permusuhan, penyalahgunaan atau penodaan terhadap suatu agama yang dianut di Indonesia; b. dengan maksud agar supaya orang tidak menganut agama apa pun juga, yang bersendikan Ketuhanan Yang Maha Esa."},{"l":"KUHP","p":"157","b":"Kejahatan Terhadap Ketertiban Umum","t":"(1) Barang siapa menyiarkan, mempertunjukkan atau menempelkan tulisan atau lukisan di muka umum, yang isinya mengandung pernyataan perasaan permusuhan, kebencian atau penghinaan di antara atau terhadap golongan-golongan rakyat Indonesia, dengan maksud supaya isinya diketuhui atau lebih diketahui oleh umum, diancam dcngan pidana penjara paling lama dua tahun enam bulan atau pidana denda paling hanyak empat rupiah lima ratus rupiah. (2) Jika yang bersalah melakukan kejahatan tersebut padu waktu menjalankan pencariannya dan pada saat, itu belum lewat lima tahun sejak pemidanaannya menjadi tetap karena kejahatan semacam itu juga, yang bersangkutan dapat di- larang menjalankan pencarian tersebut."},{"l":"KUHP","p":"158","b":"Kejahatan Terhadap Ketertiban Umum","t":"Barang siapa menyelenggarakan pemilihan anggota untuk suatu lembaga kenegaraan asing di Indonesia, atau menyiapkan ataupun memudahkan pemilihan itu, baik yang diadakan di Indonesia maupun di luar negeri, diancam dengan pidana penjara paling lama dua tahun atau pidana denda paling banyak tujuh ribu lima ratus rupiah."},{"l":"KUHP","p":"159","b":"Kejahatan Terhadap Ketertiban Umum","t":"Barang siapa turut serta dalam pemilihan umum, baik yang diadakan di Indonesia maupun di luar negeri, seperti yang dimaksud- kan dalam pasal 158, diancam dengan pidana penjara paling lama enam bulan atau pidana denda paling banyak seribu lima ratus rupiah."},{"l":"KUHP","p":"160","b":"Kejahatan Terhadap Ketertiban Umum","t":"Barang siapa di muka umum dengan lisan atau tulisan menghasut supaya melakukan perbuatan pidana, melakukan kekerasan terhadap penguasa umum atau tidak menuruti baik ketentuan undang-undang maupun perintah jabatan yang diherikan berdasar ketentuan undang-undang, diancam dengan pidana penjara paling lama enam tahun utau pidana denda paling banyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"161","b":"Kejahatan Terhadap Ketertiban Umum","t":"(1) Barang siapa menyiarkan, mempertunjukkan atau menempelkan di muka umum tulisan yang menghasut supaya melakukan perbuatan pidana, menentang penguasa umum dengan kekerasan, atau menentang sesuatu hal lain seperti tersebut dalam pasal di atas, dengan maksud supaya isi yang menghasut diketahui atau lebih diketahui oleh umum, diancam dengan pidana penjara paling lama empat tahun atau pidana denda paling banyak empat ribu lima ratus rupiah. (2) Jika yang bersalah melakukan kejahatan tersebut pada waktu menjalankan pencariannya dan pada saat itu belum lewat lima tahun sejak pemidanaannya menjadi tetap karena kejahatan semacam itu juga, yang bersangkutan dapat dilarang menjalankan pencarian tersebut. Pasal 161 bis Pasal ini ditiadakan berdasarkan Undang-undang No. 1 Tahun 1946, pasal 8, butir 34."},{"l":"KUHP","p":"162","b":"Kejahatan Terhadap Ketertiban Umum","t":"Barang siapa di muka umum dengan lisan atau tulisan menawarkan untuk memberi keterangan, kesempatan atau sarana guna melakukan tindak pidana, diancam dengan pidana penjara paling lama sembilan hulan atau pidana denda paling banyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"163","b":"Kejahatan Terhadap Ketertiban Umum","t":"(1) Barang siapa menyiarkan, mempertunjukkan atau menempelkan di muka umum tulisan yang berisi penawaran untuk memberi keterangan, kesempatan atau sarana guna melakukan tindak pidana dengan maksud supaya penawaran itu diketahui atau lebih diketahui oleh umum, diancam dengan pidana penjara paling lama empat bulan dua minggu atau pidana denda paling banyak empat ribu lima ratus rupiah. (2) Jika yang bersalah melakukan kejahatan tersebut pada waktu menjalankan pencariannya dan pada saat itu belum lewat lima tahun sejak pemidanaannya menjadi tetap karena kejahatan semacam itu juga yang bersangkutan dapat dilarang menjalankan pencarian tersebut. Pasal 163 bis (1) Barang siapa dengan menggunakan salah satu sarana tersebut dalam pasal 55 ke-2 berusaha menggerakkan orang lain supaya melakukan kejahatan, dan kejahatan itu atau percobaan untuk itu dapat dipidana tidak terjadi, diancam dengan pidana penjara paling lama enam tahun atau pidana denda paling banyak tiga ratus rupiah, tetapi dengan pengertian bahwa sekali-kali tidak dapat dijatuhkan pidana yang lebih berat daripada yang dapat dijatuhkan karena percobaan kejahatan atau apahila percobaan itu tidak dapat dipidana karena kejahatan itu sendiri. (2) Aturan tersebut tidak berlaku, jika tidak mengakibatkan kejahatan atau percobaan kejahatan disebabkan karena kehendaknya sendiri."},{"l":"KUHP","p":"164","b":"Kejahatan Terhadap Ketertiban Umum","t":"Barang siapa mengetahui ada sesuatu permufakatan untuk melakukan kejahatan berdasarkan pasal-pasal 104, 106, 107, dan 108, 113, 115, 124, 187 atau 187 bis, sedang masih ada waktu untuk mencegah kejahatan itu, dan dengan sengaja tidak segera memberitahukan tentang hal itu kepada pejabat kehakiman atau kepolisian atau kepada orang yang terancam oleh kejahatan itu, dipidana jika kejahatan itu jadi dilakukan, dengan pidana penjara paling lama satu tahun empat bulan atau pidana denda paling banyak tiga ratus rupiah."},{"l":"KUHP","p":"165","b":"Kejahatan Terhadap Ketertiban Umum","t":"(1) Barang siapa mengetahui ada niat untuk melakukan salah satu kejahatan berdasarkan pasal-pasal 104, 106, 107, dan 108, 110 - 113, dan 115 - 129 dan 131 atau niat untuk lari dari tentara dalam masa perang, untuk desersi, untuk membunuh dengan rencana, untuk menculik atau memperkosa atau mengetahui adanya niat untuk melakukan kejahatan tersebut dalam bab 8 dalam kitab undang-undang ini, sepanjang kejahatan itu membahayakan nyawa orang atau untuk melakukan salah satu kejahatan berdasarkan pasal- pasal 224 228, 250 atau salah satu kejahatan berdasarkan pasal- pasal 264 dan 275 sepanjang mengenai surat kredit yang diperuntukkan bagi peredaran, sedang masih ada waktu untuk mencegah kejahatan itu, dan dengan sengaja tidak segera memberitahukan hal itu kepada pejabat kehakiman atau kepolisian atau kepada orang yang terancam oleh kejahatan itu, dipidana jika kejahatan itu jadi dilakukan, dengan pidana penjara paling lama sembilan bulan atau pidana denda paling banyak empat ribu lima ratus rupiah. (2) Pidana tersebut diterapkan terhadap orang yang mengetahui bahwa sesuatu kejahatan berdasarkan ayat 1 telah dilakukan, dan telah membahayakan nyawa orang pada saat akihat masih dapat dicegah, dengan sengaja tidak memheritahukannya kepada pihak- pihak tersebut dalam ayat l."},{"l":"KUHP","p":"166","b":"Kejahatan Terhadap Ketertiban Umum","t":"Ketentuan dalam pasal 164 dan 165 tidak berlaku bagi orang yang dengan memberitahukan itu mungkin mendatangkan bahaya penuntutan pidana bagi diri sendiri, bagi seorang keluarganya sedarah atau semenda dalam garis lurus atau garis menyimpang derajat kedua atau ketiga, bagi suami atau bekas suaminya, atau bagi orang lain yang jika dituntut, berhubung dengan jabatan atau pencariannya, dimungkinkan pembebasan menjadi saksi terhadap orang tersebut."},{"l":"KUHP","p":"167","b":"Kejahatan Terhadap Ketertiban Umum","t":"(1) Barang siapa memaksa masuk ke dalam rumah, ruangan atau pekarangan tertutup yang dipakai orang lain dengan me- lawan hukum atau berada di situ dengan melawan hukum, dan atas permintaan yang berhak atau suruhannya tidak pergi dengan segera, diancam dengan pidana penjara paling lema sembilan bulan atau pidana denda paling banyak empat ribu lima ratus rupiah. (2) Barang siapa masuk dengan merusak atau memanjat, dengan menggunakan anak kunci palsu, perintah palsu atau pakaian jahatan palsu, atau barang siapa tidak setahu yang berhak lebih dahulu serta bukan karena kekhilafan masuk dan kedapatan di situ pada waktu malam, dianggap memaksa masuk. (3) Jika mengeluarkan ancaman atau menggunakan sarana yang dapat menakutkan orang, diancam dengan pidana penjara paling lama satu tahun empat bulan. (4) Pidana tersebut dalam ayat 1 dan 3 dapat ditambah sepertiga jika yang melakukan kejahatan dua orang atau lebih dengan bersekutu."},{"l":"KUHP","p":"168","b":"Kejahatan Terhadap Ketertiban Umum","t":"(1) Barang siapa memaksa masuk ke dalam ruangan untuk dinas umum, atau berada di situ dengan melawan hukum, dan atas permintaan pejabat yang berwenang tidak pergi dengan segera, diancam dengan pidana penjara paling lama empat bulan dua minggu atau pidana denda paling banyak empat ribu lima ratus rupiah. (2) Barang siapa masuk dengan merusak atau memanjat, dengan menggunakan anak kunci palsu, perintah palsu, atau pakaian jabatan palsu, atau barang siapa tidak setahu pejabat yang berwenang lebih dahulu serta bukan karena kekhilafan masuk dan kedapatan di situ pada waktu malam, dianggap memaksa masuk. (3) Jika ia mengeluarkan ancaman atau menggunakan sarana yang dapat menakutkan orang, diancam dengan pidana penjara menjadi paling lama satu tahun empat bulan. (4) Pidana tersebut dalam ayat 1 dan 3 dapat ditambah sepertiga, jika yang melakukan kejahatan dua orang atau lebih dengan bersekutu."},{"l":"KUHP","p":"169","b":"Kejahatan Terhadap Ketertiban Umum","t":"(1) Turut serta dalam perkumpulan yang bertujuan melakukan kejahatan. atau turut serta dalam perkumpulan lainnya yang dilarang oleh aturan-aturan umum, diancam dengan pidana penjara paling lama enam tahun. (2) Turut serta dalam perkumpulan yang bertujuan melakukan pelanggaran, diancam dengan pidana penjara paling lama sembilan bulan atau pidana denda paling banyak empat ribu lima ratus rupiah. (3) Terhadap pendiri atau pengurus, pidana dapat ditambah sepertiga."},{"l":"KUHP","p":"170","b":"Kejahatan Terhadap Ketertiban Umum","t":"(1) Barang siapa dengan terang-terangan dan dengan tenaga bersama menggunakan kekerasan terhadap orang atau barang, diancam dengan pidana penjara paling lama lima tahun enam bulan. (2) Yang bersalah diancam: 1. dengan pidana penjara paling lama tujuh tahun, jika ia dengan sengaja menghancurkan barang atau jika kekerasan yang digunakan mengakibatkan luka-luka; 2. dengan pidana penjara paling lama sembilan tahun, jika kekerasan mengakibatkan luka berat; 3. dengan pidana penjara paling lama dua belas tahun, jika kekerasan mengakibatkan maut. (3) Pasal 89 tidak diterapkan."},{"l":"KUHP","p":"171","b":"Kejahatan Terhadap Ketertiban Umum","t":"Pasal ini ditiadakan berdasarkan Undang-undang no. 1 Tahun 1946, pasal 8, butir 37."},{"l":"KUHP","p":"172","b":"Kejahatan Terhadap Ketertiban Umum","t":"Barang siapa dengan sengaja mengganggu ketenangan dengan mengeluarkan teriakan- teriakan, atau tanda-tanda bahaya palsu, diancam dengan pidana penjara paling lama tiga minggu atau pidana denda paling banyak sembilan ratus rupiah."},{"l":"KUHP","p":"173","b":"Kejahatan Terhadap Ketertiban Umum","t":"Barang siapa dengan kekerasan atau ancaman kekerasan merintangi rapat, umum yang diizinkan, diancam dengan pidana penjara paling lama satu tahun."},{"l":"KUHP","p":"174","b":"Kejahatan Terhadap Ketertiban Umum","t":"Barang siapa dengan sengaja mengganggu rapat umum yang diizinkan dengan jalan menimbulkan kekacauan atau suara gaduh, diancam dengan pidana penjara paling lama tiga minggu atau pidana denda paling banyak sembilan ratus rupiah."},{"l":"KUHP","p":"175","b":"Kejahatan Terhadap Ketertiban Umum","t":"Barang siapa dengan kekerasan atau ancaman kekerasan merintangi pertemuan keagamaan yang bersifat umum dan diizinkan, atau upacara keagamaan yang diizinkan, atau upacara penguburan jenazah, diancam dengan pidana penjara paling lama satu tahun empat bulan."},{"l":"KUHP","p":"176","b":"Kejahatan Terhadap Ketertiban Umum","t":"Barang siapa dengan sengaja mengganggu pertemuan keagamaan yang bersifat, umum dan diizinkan, atau upacara keagamaan yang diizinkan atau upacara penguburan jenazah, dengan menimbulkan kekacauan atau suara gaduh, diancam dengan pidana penjara paling lama satu bulan dua minggu atau pidana denda paling banyak seribu delapan ratus rupiah."},{"l":"KUHP","p":"177","b":"Kejahatan Terhadap Ketertiban Umum","t":"Diancam dengan pidana penjara paling lama empat bulan dua minggu atau pidana denda paling banyak seribu delapan ratus rupiah: 1. barang siapa menertawakan seorang petugas agama dalam men- jalankan tugas yang diizinkan; 2. barang siapa menghina benda-benda untuk keperluan ibadat di tempat atau padu waktu ibadat dilakukan."},{"l":"KUHP","p":"178","b":"Kejahatan Terhadap Ketertiban Umum","t":"Barang siapa dengan sengaja merintangi atau menghalang-halangi jalan masuk atau pengangkutan mayat ke kuburan yang diizinkan, diancam dengan pidana penjara paling lama satu bulan dua minggu atau pidana denda paling banyak seribu delapan ratus rupiah."},{"l":"KUHP","p":"179","b":"Kejahatan Terhadap Ketertiban Umum","t":"Barang siapa dengan sengaja menodai kuburan atau dengan sengaja dan melawan hukum menghancurkan atau merusak tanda peringntan di tempat kuburan, diancam dengan pidana penjara paling lama satu tahun empat bulan."},{"l":"KUHP","p":"180","b":"Kejahatan Terhadap Ketertiban Umum","t":"Barang siapa dengan sengaja dan melawan hukum menggali atau mengambil jenazah atau memindahkan atau mengangkut jenazah yang sudah digali atau diambil, diancam dengan pidana penjara paling lama satu tahun empat bulan atau pidana denda paling banyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"181","b":"Kejahatan Terhadap Ketertiban Umum","t":"Barang siapa mengubur, menyembunyikan, membawa lari atau menghilangkan mayat dengan maksud menyembunyikan kematian atau kelahirannya, diancam dengan pidana penjara paling lama sembilan bulan atau pidana denda paling banyak empat ribu lirna ratus rupiah."},{"l":"KUHP","p":"182","b":"Perkelahian Tanding","t":"Dengan pidana penjara paling lama sembilan bulan, diancam: (1) barang siapa menantang seorang untuk perkelahian tanding atau rnenyuruh orang menerima tantangan, bilamana hal itu mengakibatkan perkelahian tanding; (2) barang siapa dengan sengaja meneruskan tantangan, bilamana hal itu mengakibatkan perkelahian tanding."},{"l":"KUHP","p":"183","b":"Perkelahian Tanding","t":"Diancam dengan pidana penjara paling lama enam bulan atau pidana denda paling tinggi tiga ratus rupiah, barang siapa di muka umum atau di hadapan pihak ketiga mencerca atau mengejek seseorang oleh karena yang bersangkutan tidak rnau menentang atau menolak tantangan untuk perkelahian tanding."},{"l":"KUHP","p":"184","b":"Perkelahian Tanding","t":"(1) Seseorang diancam dengan pidana penjara paling lama sembilan bulan, jika ia dalam perkelahian tanding itu tidak melukai tubuh pihak lawannya. (2) Diancam dengan pidana penjara paling lama satu tahun dan empat bulan, barang siapa melukai tmbuh lawannya. (3) Diancam dengan pidana penjma paling lama empat tahun, barang siapa melukai berat tubuh lawannya. (4) Barang siapa yang merampas nyawa lawannya, diancam dengan pidana penjara paling lama tujuh tahun, atau jika perkelahian tanding itu dilakukan dengan perjanjian hidup atau mati, diancam dengan pidana penjara paling lama dua belas tahun. (5) Percobaan perkelahian tanding tidak dipidana."},{"l":"KUHP","p":"185","b":"Perkelahian Tanding","t":"Barang siapa dalam perkelahian tanding merampas nyawa pihak lawan atau melukai tubuhnya, maka diterapkan ketentuan-ketentuan mengenai pembunuhan berencana, pembunuhan atau penganiayaan: 1. jika persyaratan tidak diatur terlebih dahulu; 2.jika perkelahian tanding tidak dilakukan di hadapan saksi kedua belah pihak; 3.jika pelaku dengmi sengaja dan merugikan pihak lawan, bersalah melakukan perbuatan penipuan atau yang menyimpang dari persy aratan."},{"l":"KUHP","p":"186","b":"Perkelahian Tanding","t":"(1) Para saksi dan dokter yang menghadiri perkelahian tanding, tidak dipidana. (2) Para saksi diancam: 1.dengan pidana penjara paling lama tiga tahun, jika persyaratan tidak diatur terlebih dahulu, atau jika para saksi menghasut para pihak untuk perkelahian tanding; 2. dengan pidana penjara paling lama empat tahun, jika para saksi dengan sengaja dan merugikan salah satu atau kedua belah pihak, bersalah melakukan perbuatan penipuan atau membiarkan para pihak melakukan perbuatan penipuan, atau membiarkan dilakukan penyimpangan daripada syarat-syarat; 3. ketentuan-ketentuan mengenai pembunuhan berencana, pembunuhan atau penganiayaan diterapkan terhadap saksi dalam perkelahian tanding, di mana satu pihak dirampas nyawanya atau menderita karena dilukai tubuhnya, jika ia dengan sengaja dan merugikan pihak itu bersalah melakukan perbuatan penipuan atau membiarkan penyimpangan dari persyaratan yang merugikan yang dikalahkan atau dilukai."},{"l":"KUHP","p":"187","b":"Kejahatan Membahayakan Keamanan Umum","t":"Barang siapa dengan sengaja menimbulkan kebakaran, ledakan atau banjir, diancam: 1. dengan pidana penjara paling lama dua belas tahun, jika karena perbuatan tersebut di atas timbul bahaya umum bagi barang; 2. dengan pidana penjara paling lama lima belas tahun, jika karena perbuatan tersebut di atas timbul bahaya bagi nyawa orang lain; 3. dengan pidana penjara seumur hidup atau selama waktu tertentu paling lama dua puluh tahun, jika karena perbuatan tersebut di atas timbul bahaya bagi nyawa orang lain dan meng- akibatkan orang mati. Pasal 187 bis (1) Barang siapa membuat, menerima, berusaha memperoleh, mempunyai persediaan, menyembunyikan, mengangkut otau memasukkan ke Indonesia bahan-bahan, benda- benda atau perkakas-perkakas yung diketahui atau selayaknya harus diduga bahwa diperuntukkan, atau kalau ada kesempatan akan diperuntukkan, untuk menimbulkan ledakan yang membahayakan nyawa orang atau menimbulkan bahaya umum bagi barang, diancam dengan pidana penjara paling lama delapan tahun atau pidana kurungan paling lama satu tahun, (2) Tidak mampunya bahan-bahan, benda-benda atau perkakas- perkakas untuk menirnbulkan ledakan; seperti tersebut di atas, tidak menghapuskan pengenaan pidana. Pasal 187 ter Permufakatan jahat, untuk melakukan salah satu kejahatan tersebut dalam pasal 187 dan 187 his, diancam dengan pidana penjara paling lama lima tahun. Pasal 188 ( L.N. 1960 - 1) Barang siapa karena kesalahan (kealpaan) menyebabkan kebakar- an, ledakan atau banjir, diancam dengan pidana penjara paling lama lima tahun atau pidana kurungan paling lama satu tahun atau pidnna denda paling banyak empat ribu lima ratus rupiah, jika karena perbuatan itu timbul bahaya umum bagi barang, jika karena perbuatan itu timbul bahaya bagi nyawa orang lain, atau jika karena perbuatan itu mengakibatkan orang mati."},{"l":"KUHP","p":"189","b":"Kejahatan Membahayakan Keamanan Umum","t":"Barang siapa pada waktu ada atau akan ada kebakaran, dengan sengaja dan melawan hukum menyembunyikan atau membikin tak dapat dipakai perkakas-perkakas atau alat- alat pemadam api atau dengan cara apa pun merintangi atau menghalang-halangi pekerjaan memadamkan api, diancam dengan pidana penjara paling lama tujuh tahun."},{"l":"KUHP","p":"190","b":"Kejahatan Membahayakan Keamanan Umum","t":"Barang siapa pada waktu ada, atau akan ada banjir, dengan sengaja dan melawan hukum menyembunyikan atau membikin tak dapat dipakai bahan-bahan untuk tanggul atau perkakas-perkakas atau menggagalkan usaha untuk membetulkan tanggul-tanggul atau bangunan-bangunan pengairan, atau merintangi usaha untuk mencegah atau menahan banjir, diancam dengan pidana penjara paling lama tujuh tahun."},{"l":"KUHP","p":"191","b":"Kejahatan Membahayakan Keamanan Umum","t":"Barang siapa dengan sengaja menghancurkan, membikin tak dapat dipakai atau merusak bangunan untuk menahan atau menyalurkan diani:am dengan pidana penjara paling lama tujuh tahun jika karena perbuat:en itu timbul bahaya banjir. Pasal 191 bis Barang siapa dvngan sengaja menghancurkan, merusak atau membikin tak dapat dipakai hangunan listrik, atau menyenabkan jalan atau bekerjanya hangunan itu terganggu, atau menggagalkan atau mcmpv.r.sukar usaha unt.uk menyelanmtkan atau niembetulkan bangunan itu, diancam: 1. dengan pidana penjara paling lama sembilan bulan atau pidana denda paling banyak empat, ribu lima ratus rupiah, jika karena perbuatan itu timbul rintangan atau kesukaran dalam penyerahan tenaga listrik untuk kepentingan umum; 2. dengan pidana penjara paling lama tujuh tahun, jika karena perbuatan itu tirnbul bahaya umum bagi barang; 3. dengan pidana penjara paling lama sembilan tahun, jika karena perbuatan itu timbul bahaya bagi nyawa orang lain; 4. dengan pidana penjara paling lama lima belas tahun, jika karena perbuatan itu timbul bahaya bagi nyawa orang lain dan mengakibatkan orang mati. Pasal 191 ter Barang siapa karena kesalahannya (kealpaannya) menyebabkan suatu bangunan listrik hancur, rusak atau tak dapat dipakai atau menyebahkan jalannya atau bekerjanya bangunan itu terganggu, atau usaha untuk menyelamatkan atau membetulkan bangunan itu gagal atau menjadi sukar, diancam: 1. dengan pidana penjara paling lama empat bulan dua minggu atau pidana kurungan paling lama tiga bulan atau pidana denda paling banyak empat ribu lima ratus rupiah, jika menimbulkan rintangan atau kesukaran dalam memberikan tenaga listrik untuk kepentingan umum atau menimbulkan bahaya umum bagi barang; 2. dengan pidana penjara paling lama sembilan bulan atau pidana kurungan paling lama enam bulan atau pidana denda paling banyak empat ribu lima ratus rupiah, jika membahayakan nyawa orang lain; 3. dengan pidana penjara paling lama satu tahun empat bulan atau pidana kurungan paling lama satu tahun, jika mengakibatkan orang mati."},{"l":"KUHP","p":"192","b":"Kejahatan Membahayakan Keamanan Umum","t":"Barang siapa dengan sengaja menghancurkan, membikin tak dapat dipakai atau merusak bangunan untuk lalu lintas umum, atau me- rintangi jalan umum darat atau air, atau menggagalkan usaha untuk pengamanan bangunan atau jalan itu, diancam: 1. dengan pidana penjara paling lama sembilan tahun, jika karena perbuatan itu timbul bahaya bagi keamanan lalu lintas, 2. dengan pidana penjara paling lama lima belas tahun, jika karena perbuatan itu timbul bahaya bagi keamanan lalu lintas dan mengakibatkan orang mati."},{"l":"KUHP","p":"193","b":"Kejahatan Membahayakan Keamanan Umum","t":"Barang siapa karena kesalahannya (kealpaannya) menyebabkan bangunan untuk lalu lintas umum dihancurkan, tidak dapat dipakai atau merusak, atau menyebabkan jalan umum darat atau air dirintangi, atau usaha untuk pengamanan bangunan atau jalan itu digagalkan, diancam: 1.dengan pidana penjara paling lama empat bulan dua minggu atau pidana kurungan paling lama tiga bulan atau pidana denda paling banyak empat ribu lima ratus rupiah, jika karena perbuatan itu timbul bahaya bagi keamanan lalu lintas; 2.dengan pidana penjara paling lama satu tahun empat bulan atau pidana kurungan paling lama satu tahun, jika kerena perbuatan itu mengakibatkan orang mati."},{"l":"KUHP","p":"194","b":"Kejahatan Membahayakan Keamanan Umum","t":"(1) Barang siapa dengan sengaja menimbulkan bahaya bagi lalu lintas umum yang digerakkan oleh tenaga uap atau berkekuatan mesin lain di jalan kereta api atau trem, diancam dengan pidana penjara paling lama lima belas tahun. (2) Jika perbuatan itu mengakibatkan orang mati, yang bersalah diancam dengan pidana penjara seumur hidup atau pidana penjara selama waktu tertentu paling lama dua puluh tahun."},{"l":"KUHP","p":"195","b":"Kejahatan Membahayakan Keamanan Umum","t":"(1) Barang siapa karena kesalahannya (kealpaannya) menimbulkan bahaya bagi lalu lintas umum yang digerakkan oleh tenaga uap atau kekuatan mesin lain di jalan kereta api atau trem, diancam dengan pidana penjara paling lama sembilan bulan atau pidana kurungan paling lama enam bulan atau pidana denda paling banyak empat ribu lima ratus rupiah. (2) Jika perbuatan itu mengakibatkan orang mati, yang bersalah diancam pidana penjara paling lama satu tahun empat bulan atau pidana kurungan paling lama satu tahun."},{"l":"KUHP","p":"196","b":"Kejahatan Membahayakan Keamanan Umum","t":"Barang siapa dengan sengaja menghancurkan, merusak, mengambil atau memindahkan tanda untuk keamanan pelayaran, atau menggagalkan bekerjanya atau memasang tanda yang keliru, diancam: 1. dengan pidana penjara paling lama dua belas tahun, jika karena perbuatan itu timbul bahaya bagi keamanan pelayaran; 2. dengan pidana penjara paling lama lima belas tahun, jika karena perbuatan itu timbul bahaya bagi keamanan pelayaran dan mengakibatkan tenggelam atau terdamparnya kapal; 3. dengan pidana penjara seumur hidup atau pidana penjara selama waktu tertentu paling lama dua puluh tahun, jika karena perbuatan itu timbul bahaya bagi keamanan pelayaran dan mengakibatkan orang mati."},{"l":"KUHP","p":"197","b":"Kejahatan Membahayakan Keamanan Umum","t":"Barang siapa karena kesalahan (kealpaan) menyehabkan tanda untuk keamanan dihancurkan, dirusak; diambil atau dipindahkan, atau menyebabkan dipasang anda yang keliru, diancam: 1. dengan pidana penjara paling lama empat bulan dua minggu atau pidana kurungan paling lama tiga bulan atau pidana denda paling banyak empat ribu lima ratus rupiah, jika karena per- buatan itu pelayaran tidak aman; 2. dengan pidana penjara paling lama sembilan bulan atau pidana kurungan paling lama enam bulan atau pidana denda paling banyak empat, rihu lima ratus rupiah, jika karena Ixrhuatan itu mengakibatkan tenggelam atau terdamparnya kapal, 3. dengan pidana peniara paling lama satu tahun empat bulan atau pidana kurungan paling lama satu tahun, jika karena perbuatan itu mengakibatkan orang mati."},{"l":"KUHP","p":"198","b":"Kejahatan Membahayakan Keamanan Umum","t":"Barang siapa dengan sengaja dan melawan hukum menenggelamkan atau mendamparkan, menghancurkan, membikin tidak dapat dipakai atau merusak kapal, diancam: 1. dengan pidana penjara paling lama lima belas tahun, jika karena perbuatan itu timbul bahaya bagi nyawa orang lain; 2 dengan pidana penjara seumur hidup atau pidana penjara selama waktu tertentu paling lama dua puluh tahun, jika karena perbuatan itu timbul bahaya bagi nyawa orang lain dan mengakibatkan orang mati."},{"l":"KUHP","p":"199","b":"Kejahatan Membahayakan Keamanan Umum","t":"Barang siapa karena kesalahan (kealpaannya) menyebabkan kapal tenggelam atau terdampar, dihancurkan, tidak dapat dipakai atau dirusak, diancam: 1. dengan pidana penjara paling lama sembilan hulan atau pidana kurungan paling lama enam bulan atau pidana denda paling banyak empat ribu lima ratus rupiah, jika karcna perbuatan itu timbul bahaya bagi orang lain; 2. dengan pidana penjara paling lama satu tahun empat bulan atau pidana kurungan paling lama satu tahun, jika karena perbuatan itu mengakibatkan orang mati."},{"l":"KUHP","p":"200","b":"Kejahatan Membahayakan Keamanan Umum","t":"Barang siapa dengan sengaja menghancurkan atau merusak gedung atau bangunan diancam: 1. dengan pidana penjara paling lama dua belas tahun, jika karena perbuatan itu timbul bahaya umum bagi barang; 2. dengan pidana penjara paling lama lima belas tahun, jika karena perbuatan itu timbul bahaya bagi nyawa orang lain; 3. dengan pidana penjara seumur hidup atau pidana penjara selama waktu tertentu paling lama dua puluh tahun, jika karena perbuatan itu timbul bahaya bagi nyawa orang lain dan mengakibatkan orang mati."},{"l":"KUHP","p":"201","b":"Kejahatan Membahayakan Keamanan Umum","t":"Barang siapa karena kesalahannya (kealpaannya) menyebabkan gedung atau bangunan dihancurkan atau dirusak, diancam: 1. dengan pidana penjara paling lama empat bulan dua minggu atau pidana kurungan paling lama tiga bulan atau pidana denda paling banyak empat ribu lima ratus rupiah, jika perbuatan itu menimbulkan bahaya umum bagi barang; 2. dengan pidana penjara paling lama sembilan bulan atau pidana kurungan paling lama enam bulan atau pidana denda paling banyak empat rihu lima ratus rupiah, jika petbuatan itu menimbulkan bahaya bagi nyawa orang; 3. dengan pidana penjara paling lama satu tahun empat bulan atau pidana kurungan paling lama satu tahun jika perbuatan itu mengakibatkan orang mati."},{"l":"KUHP","p":"202","b":"Kejahatan Membahayakan Keamanan Umum","t":"(1) Barang siapa memasukkan barang sesuatu ke dalam sumur, pompa, sumber atau ke dalam perlengkapan air minum untuk umum atau untuk dipakai oleh atau bersama-sama dengan orang lain, padahal diketahuinya bahwa karena perbuatan itu air lalu berbahaya bagi nyawa atau kesehatan orang, diancam dengan pidana penjara paling lama lima belas tahun. (2) Jika perbuatan itu mengakibatkan orang mati, yang ber- salah diancam dengan pidana penjara seumur hidup atau pidana penjara selama waktu tertentu paling lama dua puluh tahun."},{"l":"KUHP","p":"203","b":"Kejahatan Membahayakan Keamanan Umum","t":"(1) Barang siapa karena kesalahannya (kealpaannya) menyebabkan bahwa barang sesuatu dimasukkan ke dalam sumur, pompa, sumber atau ke dalam perlengkapan air minum untuk umum atau untuk dipakai oleh, atau bersama-sama dengan orang lain, sehingga karena perbuatan itu air lalu berbahaya bagi nyawa atau kesehatan orang, diancam dengan pidana penjara paling lama sembilan bulan atau pidana kurungan paling lama enam bulan atau pidana denda paling banyak empat ribu lima ratus rupiah. (2) Jika perbuatan itu mengakibatkan orang mati, yang bersalah diancam dengan pidana penjara paling lama satu tahun empat bulan atau pidana kurungan paling lama satu tahun."},{"l":"KUHP","p":"204","b":"Kejahatan Membahayakan Keamanan Umum","t":"(1) Barang siapa menjual, menawarkan, menyerahkan atau membagi-bagikan barang yang diketahuinya membahayakan nyawa atau kesehatan orang, padahal sifat; berhahaya itu tidak diberi tahu, diancam dengan pidana penjara paling lama lima belas tahun. (2) Jika perbuatan itu mengakihatkan orang mati, yang bersalah diancam dengan pidana penjara seumur hidup atau pidana penjara selama waktu tertentu paling lama dua puluh tahun."},{"l":"KUHP","p":"205","b":"Kejahatan Membahayakan Keamanan Umum","t":"(1) Barang siapa karena kesalahannya (kealpaannya) menyebabkan barang-barang yang berbahaya bagi nyawa atau kesehatan orang, dijual, diserahkan atau di bagi- bagikan tanpa diketahui sifat berbahayanya oleh yang membeli atau yang memperoleh, diancam dengan pidana penjara paling lama sembilan bulan atau pidana kurungan paling lama enam bulan atau pidana denda paling banyak empat ribu lima ratus rupiah. (2) Jika perbuatan itu mengakibatkan orang mati, yang bersalah diancam dengan pidana penjara paling lama satu tahun empat bulan atau pidana kurungan paling lama satu tahun. (3) Barang-barang itu dapat disita."},{"l":"KUHP","p":"206","b":"Kejahatan Membahayakan Keamanan Umum","t":"(1) Dalam hal pemidanaan karena salah satu kejahatan berdasarkan bab ini, yang bersalah dapat dilarang menjalankan pencariannya ketika melakukan kejahatan tersebut. (2) Dalam hal pemidahaan berdasarkah salah satu kejahatan dalam pasal 204 dan 205, hakim dapat memerintahkan supaya putusan diumumkan"},{"l":"KUHP","p":"207","b":"Kejahatan Terhadap Penguasa Umum","t":"Barang siapa dengan sengaja di muka umum dengan lisan atau tulisan menghina suatu penguasa atau hadan umum yang ada di Indonesia, diancam dengan pidana penjara paling lama satu tahun enam bulan atau pidana denda paling banyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"208","b":"Kejahatan Terhadap Penguasa Umum","t":"(1) Barang siapa menyiarkan, mempertunjukkan atau menempelkan di muka umum suatu tulisan atau lukisan yang memuat penghinaan terhadap penguasa atau badan umum yang ada di Indonesia dengan maksud supaya isi yang menghina itu diketahui atau lebih diketahui oleh umum, diancam dengan pidana penjara paling lama empat bulan atau pidana denda paling banyak empat ribu lima ratus rupiah. (2) Jika yang bersalah melakukan kejahatan tersebut dalam pencariannya dan ketika itu belum lewat dua tahun sejak adanya pemidanaan yang menjadi tetap karena kejahatan semacam itu juga, maka yang bersangkutan dapat dilarang menjalankan pencarian tersebut."},{"l":"KUHP","p":"209","b":"Kejahatan Terhadap Penguasa Umum","t":"(1) Diancam dengan pidana penjara paling lama dua tahun delapan bulan atau pidana denda paling banyak empat ribu lima ratus rupiah: 1. barang siapa memberi atau menjanjikan sesuatu kepada seorang pejabat dengan maksud menggerakkannya untuk berbuat atau tidak berbuat sesuatu dalam jabatannya yang bertentangan dengan kewajibannya; 2. barang siapa memberi sesuatu kepada seorang pejabat karena atau berhubung dengan sesuatu yang bertentangan dengan kewajiban, dilakukan atau tidak dilakukan dalam jabatannya. Pencabutan hak tersebut dalam pasal 35 No. 1- 4 dapat dijatuhkan."},{"l":"KUHP","p":"210","b":"Kejahatan Terhadap Penguasa Umum","t":"(1) Diancam dengan pidana penjara paling lama tujuh tahun: 1. barang siapa memberi atau menjanjikan sesuatu kepada seorang hakim dengan maksud untuk mempengaruhi putusan tentang perkara yang diserahkan kepadanya untuk diadili; 2. barang siapa memberi atau menjanjikan sesuatu kepada seorang yang menurut ketentuan undang-undang ditentukan menjadi penasihat atau adviseur untuk menghadiri sidang atau pengadilan, dengan maksud untuk mempengaruhi nasihat atau pendapat yang akan diherikan berhubung dengan perkara yang diserahkan kepada pengadilan untuk diadili. (2) Jika pemberian atau janji dilakukan dengan maksud supaya dalam perkara pidana dijatuhkan pemidanaan, maka yang bersalah diancam dengan pidana penjara paling lama sembilan tahun. (3) Pencabutan hak berdasarkan pasal 35 No. 1- 4 dapat dijatuhkan."},{"l":"KUHP","p":"211","b":"Kejahatan Terhadap Penguasa Umum","t":"Barang siapa dengan kekerasan atau ancaman kekerasan memaksa seorang pejabat untuk melakukan perbuatan jabatan atau untuk tidak melakukan perbuatan jabatan yang sah, diancam dengan pidana penjara paling lama empat tahun."},{"l":"KUHP","p":"212","b":"Kejahatan Terhadap Penguasa Umum","t":"Barang siapa dengan kekerasan atau ancaman kekerasan melawan seorang pejabat yang sedang menjalankan tugas yang sah, atau orang yang menurut kewajiban undang- undang atau atas permintaan pejabat memberi pertolongan kepadanya, diancam karena melawan pejabat, dengan pidana penjara paling lama satu tahun empat bulan atau pidana denda paling banyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"213","b":"Kejahatan Terhadap Penguasa Umum","t":"Paksaan dan perlawanan berdasarkan pasal 211 dan 212 diancam: 1. dengan pidana penjara paling lama lima tahun, jika kejahatan atau perbuatan lainnya ketika itu mengakibatkan luka-luka; 2. dengan pidana penjara paling lama delapan tahun enam bulan, jika mengakibatkan luka-luka berat; 3. dengan pidana penjara paling lama dua belas tahun jika mengakibatkan orang mati."},{"l":"KUHP","p":"214","b":"Kejahatan Terhadap Penguasa Umum","t":"(1) Paksaan dan perlawanan berdasarkan pasal 211 dan 212 jika dilakukan oleh dua orang atau lehih dengan bersekutu, diancam dengan pidana penjara paling lama tujuh tahun. (2)Yang bersalah dikenakan: 1. pidana penjara paling lama delapan tahun enam bulan, jika kejahatan atau perbuatan lainnya ketika itu mengakibatkan luka-luka; 2. pidana penjara paling lama dua belas tahun, jika mengakibatkan luka berat; 3. pidana penjara paling lama lima helas tahun, jika mengakibatkan orang mati."},{"l":"KUHP","p":"215","b":"Kejahatan Terhadap Penguasa Umum","t":"Disamakan dengan pejabat dalam pasal 211 - 214: 1. orang yang menurut ketentuan undang-undang terus-menerus atau untuk sementara waktu diserahi menjalankan sesuatu jabatan umum; 2. pengurus dan para pegawai yang disumpah serta pekerja-pekerja pada jawatan kereta api dan trem untuk lalu lintas umum, di mana pengangkutan dijalankan dengan tenaga uap atau mesin lainnya."},{"l":"KUHP","p":"216","b":"Kejahatan Terhadap Penguasa Umum","t":"(1) Barang siapa dengan sengaja tidak menuruti perintah atau permintaan yang dilakukan menurut undang-undang oleh pejabat yang tugasnya mengawasi sesuatu, atau oleh pejabat berdasarkan tugasnya, demikian pula yang diberi kuasa untuk mengusut atau memeriksa tindak pidana; demikian pula barang siapa dengan sengaja mencegah, menghalang-halangi atau menggagalkan tindakan guna menjalankan ketentuan undang- undang yang dilakukan oleh salah seorang pejabat tersebut, diancam dengan pidana penjara paling lama empat bulan dua minggu atau pidana denda puling banyak sembilan ribu rupiah. (2) Disamakan dengan pejahat tersebut di atas, setiap orang yang menurut ketentuan undang-undang terus-menerus atau untuk sementara waktu diserahi tugas menjalankan jabatan umum. (3) Jika pada waktu melakukan kejahatan belum lewat dua tahun sejak adanya pemidanaan yang menjadi tetap karena kejahatan semacam itu juga, maka pidananya dapat ditambah sepertiga."},{"l":"KUHP","p":"217","b":"Kejahatan Terhadap Penguasa Umum","t":"Barang siapa menimbulkan kegaduhan dalam sidang pengadilan atau di tempat di mana seorang pejabat sedang menjalankan tugasnya yang sah di muka umum, dan tidak pergi sesudah diperintah oleh atau atas nama penguasa yang berwenang, diancam dengan pidana penjara paling lama tiga minggu atau pidana denda paling banyak seribu delapan ratus rupiah."},{"l":"KUHP","p":"218","b":"Kejahatan Terhadap Penguasa Umum","t":"Barang siapa pada waktu rakyat datang berkerumun dengan se- ngaja tidak segera pergi setelah diperintah tiga kali oleh atau atas nama penguasa yang berwenang, diancam karena ikut serta perkelompokan dengan pidana penjara paling lama empat bulan dua minggu atau pidana denda paling banyak sembilan ribu rupiah."},{"l":"KUHP","p":"219","b":"Kejahatan Terhadap Penguasa Umum","t":"Barang siapa secara melawan hukum merobek, membikin tak dapat dihaca atau merusak maklumat yang diumumkan atas nama penguasa yang berwenang atau menurut, ketentuan undang-undang, dengan maksud untuk mencegah atau menyukarkan orang mengetahui isi maklumat itu, diancam dengan pidana penjara paling lama satu bulan dua minggu atau pidana denda paling banyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"220","b":"Kejahatan Terhadap Penguasa Umum","t":"Barang siapa memberitahukan atau mengadukan bahwa telah dilakukan suatu perbuatan pidana, padahal mengetahui bahwa itu tidak dilakukan, diancam dengan pidana penjara paling lama satu tahun empat bulan."},{"l":"KUHP","p":"221","b":"Kejahatan Terhadap Penguasa Umum","t":"(1) Diancam dengan pidana penjara paling lama sembilan bulan atau pidana denda paling banyak empat rihu lima ratus rupiah: 1.barang siapa dengan sengaja menyembunyikan orang yang melakukan kejahatan atau yang dituntut karena kejahatan, atau barang siapa memberi pertolongan kepadanya untuk menghindari penyidikan atau penahanan oleh penjahat kehakiman atau kepolisian, atau oleh orang lain yang menurut ketentuan undang-undang terus-menerus atau untuk sementara waktu diserahi menjalankan jabatan kepolisian; 2. barang siapa setelah dilakukan suatu kejahatan dan dengan maksud untuk menutupinya, atau untuk menghalang-halangi atau mempersukar penyidikan atau penuntutannya, menghancurkan, menghilangkan, menyembunyikan benda-benda terhadap mana atau dengan mana kejahatan dilakukan atau bekas-bekas kejahatan lainnya, atau menariknya dari pemeriksaan yang dilakukan oleh pejabat kehakiman atau kepolisian maupun olsh orang lain, yang menurut ketentuan undang- undang terus- menerus atau untuk sementara waktu diserahi menjalankan jabatan kepolisian. (2) Aturan di atas tidak berlaku bagi orang yang melakukan perbuatan tersebut dengan maksud untuk menghindarkan atau menghalaukan bahaya penuntutan terhadap seorang keluarga sedarah atau semenda garis lurus atau dalam garis menyimpang derajat kedua atau ketiga, atau terhadap suami/istrinya atau bekas suami/istrinya."},{"l":"KUHP","p":"222","b":"Kejahatan Terhadap Penguasa Umum","t":"Barang siapa dengan sengaja mencegah, menghalang-halangi atau menggagalkan pemeriksaan mayat forensik, diancam dengan pidana penjara paling lama sembilan bulan atau pidana denda paling banyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"223","b":"Kejahatan Terhadap Penguasa Umum","t":"Barang siapa dengan sengaja melepaskan atau memberi pertolongan ketika meloloskan diri kepada orang yang ditahan atas perintah penguasa umum, atas putusan atau ketetapan hakim, diancam dengan pidana penjara paling lama dua tahun delapan bulan."},{"l":"KUHP","p":"224","b":"Kejahatan Terhadap Penguasa Umum","t":"Barang siapa dipanggil sebagai saksi, ahli atau juru bahasa menurut undang-undang dengan sengaja tidak memenuhi kewajiban berdasarkan undang-undang yang harus dipenuhinya, diancam: 1. dalam perkara pidana, dengan pidana penjara paling lama sembilan bulan; 2. dalam perkara lain, dengan pidana penjara paling lama enam bulan."},{"l":"KUHP","p":"225","b":"Kejahatan Terhadap Penguasa Umum","t":"Barang siapa dengan sengaja tidak memenuhi perintah undang-undang untuk menyerahkan surat-surat yang dianggap palsu atau dipalsukan, atau yang harus dipakai untuk dibandingkan dengan surat lain yang dianggap palsu atau dipalsukan atau yang kebenarannya disangkal atau tidak diakui, diancam: 1. dalam perkara pidana, dengan pidana penjara paling lama sembilan bulan; 2. dalam perkara lain, dengan pidana penjara paling lama enam bulan;"},{"l":"KUHP","p":"226","b":"Kejahatan Terhadap Penguasa Umum","t":"Barang siapa dinyatakan pailit atau dalam keadaan tak mampu atau sebagai suami/istri orang yang pailit dalam perkawinan dengan persatuan harta kekayaan atau sebagai pengurus atau komisaris suatu perseroan, perkumpulan atau yayasan yang dinyatakan pailit, dan dipanggil berdasarkan ketentuan undang-undang untuk memberi keterangan, dengan sengaja tidak hadir tanpa alasan yang sah, atau enggan memberi keterangan yang diminta ataupun dengan sengaja memberi keterangan yang keliru, diancam dengan pidana penjara paling lama satu tahun empat bulan."},{"l":"KUHP","p":"227","b":"Kejahatan Terhadap Penguasa Umum","t":"Barang siapa melaksanakan suatu hak, padahal ia mengetahui bahwa dengan putusan hakim hak tadi telah dicabut, diancam dengan pidana penjara paling lama sembilan bulan atau pidana denda paling banyak sembilan ratus rupiah."},{"l":"KUHP","p":"228","b":"Kejahatan Terhadap Penguasa Umum","t":"Barang siapa dengan sengaja memakai tanda kepangkatan atau melakukan perbuatan yang termasuk jabatan yang tidak dijabatnya atau yang ia sementara dihentikan daripadanya, diancam dengan pidana penjara paling lama dua tahun atau pidana denda paling banyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"229","b":"Kejahatan Terhadap Penguasa Umum","t":"Barang siapa dengan sengaja memakai tanda kebesaran yang berhubungan dengan pangkat atau gelar yang tidak dimilikinya, diancam dengan pidana penjara paling lama empat bulan dua minggu atav pidana denda paling banyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"230","b":"Kejahatan Terhadap Penguasa Umum","t":"Pasal ini ditiadakan berdasarkan Undang-undang No.1 Tahun 1946 pasal 8, butir 41."},{"l":"KUHP","p":"231","b":"Kejahatan Terhadap Penguasa Umum","t":"(1) Barang siapa dengan sengaja menarik suatu barang yang disita berdasarkan ketentuanundang-undang atau yang dititipkan atas perintah hakim, atau dengan mengetahui bahwa barang ditarik dari situ, menyembunyikannya, diancam dengan pidana penjara paling lama empat tahun. (2) Dengan pidana yang sama, diancam barang siapa dengan sengaja menghancurkan, merusak atau membikin tak dapat dipakai barang yang disita berdasarkan ketentuan undang-undang. (3) Penyimpan barang yang dengan sengaja melakukan atau membiarkan dilakukan salah satu kejahatan itu, atau sebagai pembantu menolong perbuatan itu, diancam dengan pidana penjara paling lama lima tahun. (4) Jika salah satu perbuatan dilakukan karena kealpaan penyimpan barang, diancam dengan pidana kurungan paling lama satu bulan atau pidana denda paling banyak seribu delapan ratus rupiah."},{"l":"KUHP","p":"232","b":"Kejahatan Terhadap Penguasa Umum","t":"(1) Barang siapa dengan sengaja memutus, membuang atau merusak penyegelan suatu benda oleh atau atas nama penguasa umum yang berwenang, atau dengan cara lain menggagalkan penutupan dengan segel, diancam dengan pidana penjara paling lama dua tahun delapan bulan. (2) Penyimpan barang yang dengan sengaja melakukan atau membiarkan perbuatan tersebut, atau sebagai pembantu menolong perbuatan itu, diancam dengan pidana penjara paling lama empat tahun. (3) Jika perbuatan dilakukan karena kealpaan penyimpan barang, diancam dengan pidana kurungan paling lama satu bulan atau pidana denda paling banyak seribu delapan ratus rupiah."},{"l":"KUHP","p":"233","b":"Kejahatan Terhadap Penguasa Umum","t":"Barang siapa dengan sengaja menghancurkan, merusak, membikin tak dapat dipakai, menghilangkan barang-barang yang digunakan untuk meyakinkan atau membuktikan sesuatu di muka penguasa yang berwenang, akta-akta, surat-surat atau daftar-daftar yang atas perintah penguasa umum, terus-menerus atau untuk sementara waktu disimpan, atau diserahkan kepada seorang pejabat, ataupun kepada orang lain untuk kepentingan umum, diancam dengan pidana penjara paling lama empat tahun."},{"l":"KUHP","p":"234","b":"Kejahatan Terhadap Penguasa Umum","t":"Barang siapa dengan sengaja menarik dari alamatnya, membuka, atau merusak suzat- surat atau barang-barang lain yang diserahkan ke kantor pos atau kantor telegram, atau yang telah dimasukan dalam kotak pos atau dipercayakan kepada seorang pembawa surat, diancam dengan pidana penjara paling lama satu tahun empat bulan."},{"l":"KUHP","p":"235","b":"Kejahatan Terhadap Penguasa Umum","t":"Jika yang bersalah melakukan salah satu kejahatan berdasarkan pasal 231 - 234, masuk ke tempat kejahatan dengan membongkar, merusak atau memanjat, dengan memakai anak kunci palsu, perintah palsu atau pakaian jabatan palsu, pidananya boleh ditambah menjadi lipat dua."},{"l":"KUHP","p":"236","b":"Kejahatan Terhadap Penguasa Umum","t":"Barang siapa pada waktu damai dengan memakai salah satu cara berdasarkan pasal 55 No. 2 sengaja menganjurkan seorang anggota tentara dalam dinas negara supaya melarikan diri, atau mempermudahnya menurut salah satu cara berdasarkan pasal 56, diancam dengan pidana penjara paling lama sembilan bulan."},{"l":"KUHP","p":"237","b":"Kejahatan Terhadap Penguasa Umum","t":"Barang siapa pada waktu damai dengan memakai salah satu cara berdasarkan pasal 55 No. 2 sengaja menganjurkan supaya ada huru-hara atau pemberontakan di kalangan anggota Angkatan Bersenjata dalam dinas Negara atau mempermudahnya menurut sesuatu cara yang berdasarkan pasal 56, diancam dengan pidana penjara paling lama tujuh tahun."},{"l":"KUHP","p":"238","b":"Kejahatan Terhadap Penguasa Umum","t":"Barang siapa tanpa persetujuan Presiden mengajak masuk seorang menjadi tentara negara asing, diancam dengan pidana penjara paling lama satu tahun empat bulan atau pidana denda paling hanyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"239","b":"Kejahatan Terhadap Penguasa Umum","t":"Barang siapa tanpa persetujuan Presiden mengajak seorang warga negara Indonesia bekerja di luar Indonesia atau untuk mempertunjukkan di luar Indonesia cara sewajarnya kehidupan rakyat Indonesia. diancam dengan pidana penjara paling lama enam hulan atau pidana denda paling banyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"240","b":"Kejahatan Terhadap Penguasa Umum","t":"(1) Diancam dengan pidana penjara paling lama dua tahun delapan bulan: 1.barang siapa dengan sengaja membikin atau menyuruh membikin dirinya tak mampu untuk memenuhi kewajib an berdasarkan pasal 30 Undang-Undang Dasar Republik Indonesia: 2.barang siapa atas permintaan orang lain, dengan sengaja membikin orang itu tak mampu memenuhi kewajiban tersebut. (2) Jika perbuatan terakhir mengakibatkan kematian. diancam dengan pidana penjara paling lama tujuh tahun."},{"l":"KUHP","p":"241","b":"Kejahatan Terhadap Penguasa Umum","t":"Diancam dengan pidana penjara paling lama tiga bulan atau pidana denda paling banyak empat ribu lima ratus rupiah: 1. ditiadakan berdasarkan L.N. 1955 - 28; 2. barang siapa dalam pengangkut ternak yang diwajibkan memakai pas pengantar, pada waktu mengangkut dengan sengaja memakai pas yang diberikan untuk ternak lain, seolah-olah diberikan untuk yang diangkut."},{"l":"KUHP","p":"242","b":"Sumpah Palsu Dan Keterangan Palsu","t":"(1) Barang siapa dalam keadaan di mana undang-undang menentukan supaya memberi keterangan di atas sumpah atau mengadakan akibat hukum kepada keterangan yang demikian, dengan sengaja memberi keterangan palsu di atas sumpah, baik dengan lisan atau tulisan, secara pribadi maupun oleh kuasanya yang khusus ditunjuk untuk itu, diancam dengan pidana penjara paling lama tujuh tahun. (2) Jika keterangan palsu di atas sumpah diberikan dalam perkara pidana dan merugikan terdakwa atau tersangka, yang bersalah diancam dengan pidana penjara paling lama sembilan tahun. (3) Disamakan dengan sumpah adalah janji atau penguatan diharuskan menurut aturan- aturan umum atau yang menjadi pengganti sumpah. (4) Pidana pencabutan hak berdasarkan pasal 35 No. 1 - 4 dapat dijatuhkan."},{"l":"KUHP","p":"243","b":"Sumpah Palsu Dan Keterangan Palsu","t":"Ditiadakan berdasarkan Stbl. 1931 No. 240."},{"l":"KUHP","p":"244","b":"Pemalsuan Mata Uang Dan Uang Kertas","t":"Barang siapa meniru atau memalsu mata uang atau kertas yang dikeluarkan oleh Negara atau Bank, dengan maksud untuk mengedarkan atau menyuruh mengedarkan mata uang atau uang kertas itu sebagai asli dan tidak dipalsu, diancam dengan pidana penjara paling lama lima belas tahun."},{"l":"KUHP","p":"245","b":"Pemalsuan Mata Uang Dan Uang Kertas","t":"Barang siapa dengan sengaja mengedarkan mata uang atau uang kertas yang dikeluarkan oleh Negara atau Bank sebagai mata uang atau uang kertas asli dan tidak dipalsu, padahal ditiru atau dipalsu olehnya sendiri, atau waktu diterima diketahuinya bahwa tidak asli atau dipalsu, ataupun barang siapa menyimpan atau memasukkan ke Indonesia mata uang dan uang kertas yang demikian, dengan maksud untuk mengedarkan atau menyuruh mengedarkan sebagai uang asli dan tidak dipalsu, diancam dengan pidana penjara paling lama lima belas tahun."},{"l":"KUHP","p":"246","b":"Pemalsuan Mata Uang Dan Uang Kertas","t":"Barang siapa mengurangi nilai mata uang dengan maksud untuk mengeluarkan atau menyuruh mengedarkan uang yang dikurangi nilainya itu, diancam karena merusak uang dengan pidana penjara paling lama dua belas tahun."},{"l":"KUHP","p":"247","b":"Pemalsuan Mata Uang Dan Uang Kertas","t":"Barang siapa dengan sengaja mengedarkan mata uang yang dikurangi nilai olehnya sendiri atau yang merusaknya waktu diterima diketahui sebagai uang yang tidak rusak, ataupun barang siapa menyimpan atau memasukkan ke Indonesia uang yang demikian itu dengan maksud untuk mengedarkan atau menyuruh mengedarkannya sebagai uang yang tidak rusak, diancam dengan pidana penjara paling lama dua belas tahun."},{"l":"KUHP","p":"248","b":"Pemalsuan Mata Uang Dan Uang Kertas","t":"Ditiadakan berdasarkan Stbl. 1938 No. 593."},{"l":"KUHP","p":"249","b":"Pemalsuan Mata Uang Dan Uang Kertas","t":"Barang siapa dengan sengaja mengedarkan mata uang yang tidak asli, dipalsu atau dirusak atau uang kertas Negara atau Bank yang palsu atau dipalsu, diancam, kecuali berdasarkan pasal 245 dan 247, dengan pidana penjara paling lama empat bulan dua minggu atau pidana denda paling banyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"250","b":"Pemalsuan Mata Uang Dan Uang Kertas","t":"Barangsiapa membuat atau mempunyai persediaan bahan atau benda yang diketahuinya bahwa itu digunakan untuk meniru, memalsu atau mengurangi nilai mata uang, atau untuk meniru atau memalsu uang kertas negara atau bank, diancam dengan pidana penjara paling lama enam tahun atau pidana denda paling banyak empat ribu lima ratus rupiah. Pasal 250 bis Pemidanaan berdasarkan salah satu kejahatan yang diterangkan dalam bab ini: maka mata uang palsu, dipalsu atau dirusak, uang kertas Negara atau Bank yang palsu atau dipalsukan, bahan-bahan atau benda-benda yang menilik sifatnya digunakan untuk meniru, memalsu atau mengurangi nilai mata uang atau uang kertas, sepanjang dipakai untuk atau menjadi obyek dalam melakukan kejahatan, dirampas, juga apabila barang- barang itu bukan kepunyaan terpidana."},{"l":"KUHP","p":"251","b":"Pemalsuan Mata Uang Dan Uang Kertas","t":"Diancam dengan pidana penjara paling lama satu tahun atau pidana denda paling banyak sepuluh ribu rupiah, barang siapa dengan sengaja dan tanpa izin Pemerintah, menyimpan atau memasukkan ke Indonesia keping-keping atau lembar-lembaran perak, baik yang ada maupun yang tidak ada capnya atau dikerjakan sedikit, mungkin dianggap sebagai mata uang, padahal tidak nyata-nyata akan digunakan sebagai perhiasan atau tanda peringatan."},{"l":"KUHP","p":"252","b":"Pemalsuan Mata Uang Dan Uang Kertas","t":"Dalam hal pemidanaan berdasarkan salah satu kejahatan yang diterangkan dalam pasal 244 - 247, maka hak-hak sebagaimana dimaksud dalam pasal 35 No. 1 - 4 dapat dicabut."},{"l":"KUHP","p":"253","b":"Pemalsuan Materai Dan Merek","t":"Diancam dengan pidana penjara paling lama tujuh tahun: 1. barang siapa meniru atau memalsu meterai yang dikeluarkan oleh Pemerintah Indonesia, atau jika diperlukan tanda-tangan untuk sahnya meterai itu, barang siapa meniru atau memalsu tanda-tangan, dengan maksud untuk memakai atau menyuruh orang lain memakai meterai itu sebagai meterai yang asli dan tidak dipalsu atau yang sah; 2 barang siapa dengan maksud yang sama, membikin meterai tersebut dengan menggunakan cap yang asli secara melawan hukum."},{"l":"KUHP","p":"254","b":"Pemalsuan Materai Dan Merek","t":"Diancam dengan pidana penjara paling lama enam tahun: 1. barang siapa membubuhi barang-barang emas atau perak dengan merek Negara yang dipalsukan, atau dengan tanda keahlian menurut undang-undang yang dipalsukan atau memalsu merek atau tanda yang asli dengan maksud untuk memakai atau menyuruh orang lain memakai seolah-olah merek atau tanda itu asli dan tidak dipalsu; 2 barang siapa dengan maksud yang sama membubuhi barang-barang tersebut dengan merek atau tanda, dengan menggunakan cap yang asli secara melawan hukum; 3. barang siapa memberi, menambah atau memindah merek Negara yang asli atau tanda keahlian menurut undang-undang yang asli pada barang emas atau perak yang lain daripada yang semula dibubuhi merek atau tanda itu, dengan maksud untuk memakai atau menyuruh orang lain memakai barang itu seolah-olah merek atau tanda dari semula sudah dibubuhkan pada barang itu."},{"l":"KUHP","p":"255","b":"Pemalsuan Materai Dan Merek","t":"Diancam dengan pidana penjara paling lama empat tahun: 1. barang siapa membubuhi barang yang wajib ditera atau yang atas permintaan yang berkepentingan diizinkan untuk ditera atau ditera lagi dengan tanda tera Indonesia yang palsu, atau barang siapa memalsu tanda tera yang asli, dengan maksud untuk memakai atau menyuruh orang lain memakai barang itu seolah-olah tanda teranya asli dan tidak dipalsu; 2 barang siapa dengan maksud yang sama membubuhi merek pada barang tersebut dengan menggunakan cap yang asli secara melawan hukum; 3, barang siapa memberi, menambah atau memindahkan tera Indonesia yang asli kepada barang yang lain daripada yang semula dibubuhi tanda itu, dengan maksud untuk memakai atau menyuruh orang lain memakai barang itu seolah-olah tanda tersebut dari semula diadakan pada barang itu."},{"l":"KUHP","p":"256","b":"Pemalsuan Materai Dan Merek","t":"Diancam dengan pidana penjara paling lama tiga tahun: 1. barang siapa membubuhi merek lain daripada yang tersebut dalam pasal 254 dan 255, yang menurut ketentuan undang-undang harus atau boleh dibubuhi pada barang atau bungkusnya secara palsu pada barang atau bungkus tersebut, dengan maksud untuk memakai atau menyuruh orang lain memakai barang itu seolah-olah mereknya asli dan tidak dipalsu; 2. barang siapa yang dengan maksud yang sama membubuhi merek pada barang atau bungkusnya dengan memakai cap yang asli secara melawan hukum; 3. barang siapa memakai merek yang asli untuk barang atau bungkusnya, padahal merek itu bukan untuk barang atau bungkusnya itu, dengan maksud untuk memakai atau menyuruh orang lain memakai barang itu seolah-olah merek tersebut ditentukan untuk barang itu."},{"l":"KUHP","p":"257","b":"Pemalsuan Materai Dan Merek","t":"Barang siapa dengan sengaja memakai, menjual, menawarkan, menyerahkan, mempunyai persediaan untuk dijual, atau memasukkan ke Indonesia, meterai, tanda atau merek yang tidak asli, dipalsu atau dibikin secara melawan hukum, ataupun benda- benda di mana merek itu dibubuhkannya secara melawan hukum seolah-olah meterai, tanda atau merek itu asli, tidak dipalsu dan tidak dibikin secara melawan hukum, ataupun tidak dibubuhkan secara melawan hukum pada benda-benda itu, diancam dengan pidana penjara sama dengan yang ditentukan dalam pasal 253 - 256, menurut perbedaan yang ditentukan dalam pasal-pasal itu."},{"l":"KUHP","p":"258","b":"Pemalsuan Materai Dan Merek","t":"(1) Barang siapa memalsu ukuran atau takaran, anak timbangan atau timbangan sesudah dibubuhi tanda tera, dengan maksud untuk memakai atau menyuruh orang lain memakai barang itu seolah-olah asli dan tidak dipalsu, diancam dengan pidana penjara paling lama tiga tahun. (2) Diancam dengan pidana yang sama barang siapa dengan sengaja memakai ukuran atau takaran, anak timbangan atau timbangan yang dipalsu, seolah-olah barang itu asli dan tidak dipalsu."},{"l":"KUHP","p":"259","b":"Pemalsuan Materai Dan Merek","t":"(1) Barang siapa menghilangkan tanda apkir pada barang yang ditera dengan maksud hendak memakai atau menyuruh orang lain memakai barang itu seolah-olah tidak diapkir, diancam dengan pidana penjara paling lama satu tahun empat bulan. (2) Diancam dengan pidana yang sama barang siapa dengan sengaja memakai, menjual, menawarkan, menyerahkan atau mempunyai persediaan untuk dijual suatu benda yang dihilangkan tanda apkirnya seolah-olah benda itu tidak diapkir."},{"l":"KUHP","p":"260","b":"Pemalsuan Materai Dan Merek","t":"Diancam dengan pidana penjara paling lama empat tahun atau denda paling banyak empat ribu lima ratus rupiah: 1. barang siapa pada meterai Pemerintah Indonesia yang telah dipakai, menghilangkan cap yang gunanya untuk tidak memungkinkan dipakainya lagi, dengan maksud untuk memakai atau menyuruh orang lain memakai, seolah-olah meterai itu belum dipakai; 2. barang siapa pada meterai Pemerintah Indonesia yang telah dipakai, dengan maksud yang sama menghilangkan tanda tangan, ciri atau tanda saat dipakainya, yang menurut ketentuan undang-undang harus dihubuhkan di atas atau pada meterai-meterai tersebut. (2) Diancam dengan pidana yang sama barang siapa dengan sengaja memakai, menjual, menawarkan, menyerahkan, mempunyai persediaan untuk dijual atau memasukkan ke Indonesia meterai yang capnya, tanda tangannya, ciri atau tanda saat dipakainya dihilangkan, seolah-olah meterai belum dipakai. Pasal 260 bis (1) Ketentuan dalam pasal 253, 256, 257, dan 260 berlaku juga menurut perbedaan yang ditentukan dalam pasal-pasal itu, jika perbuatan yang diterangkan di situ dilakukan terhadap meterai atau merek yang dipakai oleh Jawatan Pos Indonesia atau suatu negara asing. (2) Jika kejahatan dilakukan terhadap meterai atau merek yang dipakai oleh jawatan pos negara asing, maksimum pidana pokok yang ditentukan bagi kejahatan itu dikurangi sepertiga."},{"l":"KUHP","p":"261","b":"Pemalsuan Materai Dan Merek","t":"(1) Barang siapa menyimpan bahan atau benda yang diketahuinya diperuntukkan untuk melakukan salah satu kejahatan yang diterangkan dalam pasal 253 atau dalam pasal 260 bis, berhubung dengan pasal 253, diancam dengan pidana penjara paling lama sembilan bulan atau pidana denda paling banyak empat ribu lima ratus rupiah. (2) Bahan-bahan dan barang-barang itu dirampas."},{"l":"KUHP","p":"262","b":"Pemalsuan Materai Dan Merek","t":"Dalam hal pemidanaan berdasarkan salah.satu kejahatan yang diterangkan dalam pasal 253 - 260 bis, maka hak-hak sebagaimana dimaksud dalam pasal 35 No. 1 - 4 dapat dicabut."},{"l":"KUHP","p":"263","b":"Pemalsuan Surat","t":"(1) Barang siapa membuat surat palsu atau memalsukan surat yang dapat menimbulkan sesuatu hak, perikatan atau pembebasan hutang, atau yang diperuntukkan sebagai bukti daripada sesuatu hal dengan maksud untuk memakai atau menyuruh orang lain memakai surat tersebut seolah-olah isinya benar dan tidak dipalsu, diancam jika pemakaian tersebut dapat menimbulkan kerugian, karena pemalsuan surat, dengan pidana penjara paling lama enam tahun. (2) Diancam dengan pidana yang sama, barang siapa dengan sengaja memakai surat palsu atau yang dipalsukan seolah-olah sejati, jika pemakaian surat itu dapat menimbulkan kerugian."},{"l":"KUHP","p":"264","b":"Pemalsuan Surat","t":"(1) Pemalsuan surat diancam dengan pidana penjara paling lama delapan tahun, jika dilakukan terhadap: l. akta-akta otentik; 2. surat hutang atau sertifikat hutang dari sesuatu negara atau bagiannya ataupun dari suatu lembaga umum; 3. surat sero atau hutang atau sertifikat sero atau hutang dari suatu perkumpulan, yayasan, perseroan atau maskapai: 4. talon, tanda bukti dividen atau bunga dari salah satu surat yang diterangkan dalam 2 dan 3, atau tanda bukti yang dikeluarkan sebagai pengganti surat-surat itu; 5. surat kredit atau surat dagang yang diperuntukkan untuk diedarkan. (2) Diancam dengan pidana yang sama barang siapa dengan sengaja memakai surat tersebut dalam ayat pertama, yang isinya tidak sejati atau yang dipalsukan seolah-olah benar dan tidak dipalsu, jika pemalsuan surat itu dapat menimbulkan kerugian."},{"l":"KUHP","p":"265","b":"Pemalsuan Surat","t":"Ditiadakan berdasarkan Stbl. 1926. No. 359 jo. No. 429."},{"l":"KUHP","p":"266","b":"Pemalsuan Surat","t":"(1) Barang siapa menyuruh memasukkan keterangan palsu ke dalam suatu akta otentik mengenai sesuatu hal yang kebenarannya harus dinyatakan oleh akta itu, dengan maksud untuk memakai atau menyuruh orang lain memakai akta itu seolah-olah keterangannya sesuai dengan kebenaran, diancam, jika pemakaian itu dapat menimbulkan kerugian, dengan pidana penjara paling lama tujuh tahun; (2) Diancam dengan pidana yang sama barang siapa dengan sengaja memakai surat tersebut dalam ayat pertama, yang isinya tidak sejati atau yang dipalsukan seolah-olah benar dan tidak dipalsu, jika pemalsuan surat itu dapat menimbulkan kerugian."},{"l":"KUHP","p":"267","b":"Pemalsuan Surat","t":"(1) Seorang dokter yang dengan sengaja memberikan surat keterangan palsu tentang ada atau tidaknya penyakit, kelemahan atau cacat, diancam dengan pidana penjara paling lama empat tahun (2) Jika keterangan diberikan dengan maksud untuk memasukkan seseorang ke dalam rumah sakit jiwa atau untuk menahannya di situ, dijatuhkan pidana penjara paling lama delapan tahun enam bulan. (3) Diancam dengan pidana yang sama, barang siapa dengan sengaja memakai surat keterangan palsu itu seolah-olah isinya sesuai dengan kebenaran."},{"l":"KUHP","p":"268","b":"Pemalsuan Surat","t":"(1) Barang siapa membuat secara palsu atau memalsu surat keterangan dokter tentang ada atau tidak adanya penyakit, kelemahan atau cacat, dengan maksud untuk menyesatkan penguasa umum atau penanggung, diancam dengan pidana penjara paling lama empat tahun. (2) Diancam dengan pidana yang sama, barang siapa dengan maksud yang sama memakai surat keterangan yang tidak benar atau yang dipalsu, seolah-olah surat itu benar dan tidak dipalsu."},{"l":"KUHP","p":"269","b":"Pemalsuan Surat","t":"(1) Barang siapa membuat surat palsu atau memalsu surat keterangan tanda kelakuan baik, kecakapan, kemiskinan, kecacatan atau keadaan lain, dengan maksud untuk memakai atau menyuruh orang lain memakai surat itu supaya diterima dalam pekerjaan atau supaya menimbulkan kemurahan hati dan pertolongan, diancam dengan pidana penjara paling lama satu tahun empat bulan. (2) Diancam dengan pidana yang sama barang siapa dengan sengaja memakai surat keterangan yang palsu atau yang dipalsukan tersebut dalam ayat pertama, seolah-olah surat itu sejati dan tidak dipalsukan."},{"l":"KUHP","p":"270","b":"Pemalsuan Surat","t":"(1) Barang siapa membuat surat palsu atau memalsukan pas jalan atau surat penggantinya, kartu keamanan, surat perintah jalan atau surat yang diberikan menurut ketentuan undang-undang tentang pemberian izin kepada orang asing untuk masuk dan menetap di Indonesia, ataupun barang siapa menyuruh beri surat serupa itu atas nama palsu atau nama kecil yang palsu atau dengan menunjuk pada keadaan palsu, dengan maksud untuk memakai atau menyuruh orang lain memakai surat itu seolah-olah sejati dan tidak dipalsukan atau seolah-olah isinya sesuai dengan kebenaran, diancam dengan pidana penjara paling lama dua tahun delapan bulan. (2) Diancam dengan pidana yang sama, barang siapa dengan sengaja memakai surat yang tidak benar atau yang dipalsu tersebut dalam ayat pertama, seolah-olah benar dan tidak dipalsu atau seolah-olah isinya sesuai dengan kebenaran."},{"l":"KUHP","p":"271","b":"Pemalsuan Surat","t":"(1) Barang siapa membuat palsu atau memalsukan surat pengantar bagi kerbau atau sapi, atau menyuruh beri surat serupa itu atas nama palsu atau dengan menunjuk pada keadaan palsu, dengan maksud untuk memakai atau menyuruh orang lain memakai surat itu seolah-olah isinya sesuai dengan kebenaran, diancam dengan pidana penjara paling lama dua tahun delapan bulan. (2) Diancam dengan pidana yang sama, barang siapa dengan sengaja memakai surat yang palsu atau yang dipalsukan tersebut dalam ayat pertama, seolah-olah sejati dan tidak dipalsu atau seolah-olah isinya sesuai dengan kebenaran."},{"l":"KUHP","p":"272","b":"Pemalsuan Surat","t":"Ditiadakan berdasarkan S. 1926 No. 359 jo. No. 429."},{"l":"KUHP","p":"273","b":"Pemalsuan Surat","t":"Ditiadakan berdasarkan S. 1926 No. 359 jo. No. 429."},{"l":"KUHP","p":"274","b":"Pemalsuan Surat","t":"(1) Barang siapa membuat palsu atau memalsukan surat keterangan seorang pejabat selaku penguasa yang sah, tentang hak milik atau hak lainnya atas sesuatu barang, dengan maksud untuk memudahkan penjualan atau penggadaiannya atau untuk menyesatkan pejabat kehakiman atau kepolisian tentang asalnya, diancam dengan pidana penjara paling lama dua tahun. (2) Diancam dengan pidana yang sama, barang siapa dengan mak- sud tersebut, memakai surat keterangan itu seolah-olah sejati dan tidak dipalsukan."},{"l":"KUHP","p":"275","b":"Pemalsuan Surat","t":"(1) Barang siapa menyimpan bahan atau benda yang diketahuinya bahwa diperuntukkan untuk melakukan salah satu kejahatan berdasarkan pasal 264 No. 2 - 5, diancam dengan pidana penjara paling lama sembilan bulan atau pidana denda paling banyak empat ribu lima ratus rupiah. (2) Bahan-bahan dan benda-benda itu dirampas."},{"l":"KUHP","p":"276","b":"Pemalsuan Surat","t":"Dalam hal pemidanaan berdasarkan salah satu kejahatan dalam pasal 263 - 268, dapat dijatuhkan pencabutan hak berdasarkan pasal 35 No. 1 - 4."},{"l":"KUHP","p":"277","b":"Kejahatan Terhadap Asal-Usul Dan Perkawinan","t":"(1) Barang siapa dengan salah satu perbuatan sengaja menggelapkan asal-usul orang, diancam karena penggelapan asal-usul, dengan pidana penjara paling lama enam tahun. (2) Pencabutan hak berdasarkan pasal 35 No. 1 - 4 dapat dinyatakan."},{"l":"KUHP","p":"278","b":"Kejahatan Terhadap Asal-Usul Dan Perkawinan","t":"Barang siapa mengakui seorang anak sebagai anaknya menurut peraturan Kitab Undang- undang Hukum Perdata, padahal diketahuinya bahwa dia bukan ayah dari anak tersebut, diancam karena melakukan pengakuan anak palsu dengan pidana penjara paling lama tiga tahun."},{"l":"KUHP","p":"279","b":"Kejahatan Terhadap Asal-Usul Dan Perkawinan","t":"(1) Diancam dengan pidana penjara paling lama lima tahun: 1. barang siapa mengadakan perkawinan padahal mengetahui bahwa perkawinan atau perkawinan-perkawinannya yang telah ada menjadi penghalang yang sah untuk itu; 2. barang siapa mengadakan perkawinan padahal mengetahui bahwa perkawinan atau perkawinan-perkawinan pihak lain menjadi penghalang untuk itu. (2) Jika yang melakukan perbuatan berdasarkan ayat 1 butir 1 menyembunyikan kepada pihak lain bahwa perkawinan yang telah ada menjadi penghalang yang sah untuk itu diancam dengan pidana penjara paling lama tujuh tahun. (3) Pencabutan hak berdasarkan pasal No. 1 – 5 dapat dinyatakan."},{"l":"KUHP","p":"280","b":"Kejahatan Terhadap Asal-Usul Dan Perkawinan","t":"Barang siapa mengadakan perkawinan, padahal sengaja tidak memberitahu kepada pihak lain bahwa ada penghalang yang sah, diancam dengan pidana penjara paling lama lima tahun, apabila kemudian berdasarkan penghalang tersebut, perkawinan lalu dinyatakan tidak sah."},{"l":"KUHP","p":"281","b":"Kejahatan Terhadap Kesusilaan","t":"Diancam dengan pidana penjara paling lama dua tahun delapan bulan atau pidana denda paling banyak empat ribu lima ratus rupiah: 1. barang siapa dengan sengaja dan terbuka melanggar kesusilaan; 2. barang siapa dengan sengaja dan di depan orang lain yang ada di situ bertentangan dengan kehendaknya, melanggar kesusilaan"},{"l":"KUHP","p":"282","b":"Kejahatan Terhadap Kesusilaan","t":"(1) Barang siapa menyiarkan, mempertunjukkan atau menempelkan di muka umum tulisan, gambaran atau benda yang telah diketahui isinya melanggar kesusilaan, atau barang siapa dengan maksud untuk disiarkan, dipertunjukkan atau ditempelkan di muka umum, membikin tulisan, gambaran atau benda tersebut, memasukkannya ke dalam negeri, meneruskannya, mengeluarkannya dari negeri, atau memiliki persediaan, ataupun barang siapa secara terang-terangan atau dengan mengedarkan surat tanpa diminta, menawarkannya atau menunjukkannya sebagai bisa diperoleh, diancam dengan pidana penjara paling lama satu tahun enam bulan atau pidana denda paling tinggi empat ribu lima ratus rupiah. (2) Barang siapa menyiarkan, mempertunjukkan atau menempelkan di muka umum tulisan, gambaran atau benda yang melanggar kesusilaan, ataupun barang siapa dengan maksud untuk disiarkan, dipertunjukkan atau ditempelkan di muka umum, membikin, memasukkan ke dalam negeri, meneruskan mengeluarkannya dari negeri, atau memiliki persediaan, ataupun barang siapa secara terang-terangan atau dengan mengedarkan surat tanpa diminta, menawarkan, atau menunjuk sebagai bisa diperoleh, diancam, jika ada alasan kuat baginya untuk menduga bahwa tulisan, gambazan atau benda itu me!anggar kesusilaan, dengan pidana paling lama sembilan bulan atau pidana denda paling banyak empat ribu lima ratus rupiah. (3) Kalau yang bersalah melakukan kejahatan tersebut dalam ayat pertama sebagai pencarian atau kebiasaan, dapat dijatuhkan pidana penjara paling lama dua tahun delapan bulan atau pidana denda paling banyak tujuh puluh lima ribu rupiah."},{"l":"KUHP","p":"283","b":"Kejahatan Terhadap Kesusilaan","t":"(1) Diancam dengan pidana penjara paling lama sembilan bulan atau pidana denda paling banyak sembilan ribu rupiah, barang siapa menawarkan, memberikan untuk terus maupun untuk sementara waktu, menyerahkan atau memperlihatkan tulisan, gambaran atau benda yang melanggar kesusilaan, maupun alat untuk mencegah atau menggugurkan kehamilan kepada seorang yang belum dewasa, dan yang diketahui atau sepatutnya harus diduga bahwa umumya belum tujuh belas tahun, jika isi tulisan, gambaran, benda atau alat itu telah diketahuinya. (2) Diancam dengan pidana yang sama, barang siapa membacakan isi tulisan yang melanggar kesusilaan di muka oranng yang belum dewasa sebagaimana dimaksud dalam ayat yang lalu, jika isi tadi telah diketahuinya. (3) Diancam dengan pidana penjara paling lama empat bulan atau pidana kurungan paling lama tiga bulan atau pidana denda paling banyak sembilan ribu rupiah, barang siapa menawarkan, memberikan untuk terus maupun untuk sementara waktu, menyerahkan atau memperlihatkan, tulis- an, gambaran atau benda yang melanggar kesusilaan, maupun alat untuk mencegah atau menggugurkan kehamilan kepada seorang yang belum dewasa sebagaimana dimaksud dalam ayat pertama, jika ada alasan kuat baginya untuk menduga, bahwa tulisan, gambaran atau benda yang melang- gar kesusilaan atau alat itu adalah alat untuk mencegah atau menggugurkan kehamilan. Pasal 283 bis Jika yang bersalah melykukan salah satu kejahatan tersebut dalam pasal 282 dan 283 dalam menjalankan pencariannya dan ketika itu belum lampau dua tahun sejak adanya pemidanaan yang menjadi pasti karena kejahatan semacam itu juga, maka dapat di cabut haknya untuk menjalankan pencarian tersebut."},{"l":"KUHP","p":"284","b":"Kejahatan Terhadap Kesusilaan","t":"(1) Diancam dengan pidana penjara paling lama sembilan bulan: l. a. seorang pria yang telah kawin yang melakukan gendak (overspel), padahal diketahui bahwa pasal 27 BW berlaku baginya, b. seorang wanita yang telah kawin yang melakukan gendak, padahal diketahui bahwa pasal 27 BW berlaku baginya; 2. a. seorang pria yang turut serta melakukan perbuatan itu, padahal diketahuinya bahwa yang turut bersalah telah kawin; b. seorang wanita yang telah kawin yang turut serta melakukan perbuatan itu, padahal diketahui olehnya bahwa yang turut bersalah telah kawin dan pasal 27 BW berlaku baginya. (2) Tidak dilakukan penuntutan melainkan atas pengaduan suami/istri yang tercemar, dan bilamana bagi mereka berlaku pasal 27 BW, dalam tenggang waktu tiga bulan diikuti dengan permintaan bercerai atau pisah-meja dan ranjang karena alasan itu juga. (3) Terhadap pengaduan ini tidak berlaku pasal 72, 73, dan 75. (4) Pengaduan dapat ditarik kembali selama pemeriksaan dalam sidang pengadilan belum dimulai. (5) Jika bagi suami-istri berlaku pasal 27 BW, pengaduan tidak diindahkan selama perkawinan belum diputuskan karena perceraian atau sebelum putusan yang menyatakan pisah meja dan tempat tidur menjadi tetap."},{"l":"KUHP","p":"285","b":"Kejahatan Terhadap Kesusilaan","t":"Barang siapa dengan kekerasan atau ancaman kekerasan memaksa seorang wanita bersetubuh dengan dia di luar perkawinan, diancam karena melakukan perkosaan dengan pidana penjara paling lama dua belas tahun."},{"l":"KUHP","p":"286","b":"Kejahatan Terhadap Kesusilaan","t":"Barang siapa bersetubuh dengan seorang wanita di luar perkawinan, padahal diketahui bahwa wanita itu dalam keadaan pingsan atau tidak berdaya, diancam dengan pidana penjara paling lama sembilan tahun."},{"l":"KUHP","p":"287","b":"Kejahatan Terhadap Kesusilaan","t":"(1) Barang siapa bersetubuh dengan seorang wanita di luar perkawinan, padahal diketahuinya atau sepatutnya harus diduganya bahwa umumya belum lima belas tahun, atau kalau umurnya tidak jelas, bawa belum waktunya untuk dikawin, diancam dengan pidana penjara paling lama sembilan tahun. (2) Penuntutan hanya dilakukan atas pengaduan, kecuali jika umur wanita belum sampai dua belas tahun atau jika ada salah satu hal berdasarkan pasal 291 dan pasal 294."},{"l":"KUHP","p":"288","b":"Kejahatan Terhadap Kesusilaan","t":"(1) Barang siapa dalam perkawinan bersetubuh dengan seormig wanita yang diketahuinya atau sepatutnya harus didugunya bahwa yang bersangkutan belum waktunya untuk dikawin, apabila perbuatan mengakibatkan luka-luka diancam dengan pidana penjara paling lama empat tahun. (2) Jika perbuatan mengakibatkan luka-luka berat, dijatuhkan pidana penjara paling lama delapan tahun. (3) Jika mengakibatkan mati, dijatuhkan pidana penjara paling lama dua belas tahun."},{"l":"KUHP","p":"289","b":"Kejahatan Terhadap Kesusilaan","t":"Barang siapa dengan kekerasan atau ancaman kekerasan memaksa seorang untuk melakukan atau membiarkan dilakukan perbuatan cabul, diancam karena melakukan perbuatan yang menyerang kehormatan kesusilaan, dengan pidana penjara paling lama sembilan tahun."},{"l":"KUHP","p":"290","b":"Kejahatan Terhadap Kesusilaan","t":"Diancam dengan pidana penjara paling lama tujuh tahun: 1. barang siapa melakukan perbuatan cabul dengan seorang, padahal diketahuinya bahwa orang itu pingsan atau tidak berdaya; 2. barang siapa melakukan perbuatan cabul dengan seorang padahal diketahuinya atau sepatutnya harus diduganya, bahwa umumya belum lima belas tahun atau kalau umumya tidak jelas, yang bersangkutan belum waktunya untuk dikawin: 3. barang siapa membujuk seseorang yang diketahuinya atau sepatutnya harus diduganya bahwa umurnya belum lima belas tahun atau kalau umumya tidak jelas yang bersangkutan atau kutan belum waktunya untuk dikawin, untuk melakukan atau membiarkan dilakukan perbuatan cabul, atau bersetubuh di luar perkawinan dengan orang lain."},{"l":"KUHP","p":"291","b":"Kejahatan Terhadap Kesusilaan","t":"(1) Jika salah satu kejahatan berdasarkan pasal 286, 2 87, 289, dan 290 mengakibatkan luka-luka berat, dijatuhkan pidana penjara paling lama dua belas tahun; (2) Jika salah satu kejahatan berdasarkan pasal 285, 2 86, 287, 289 dan 290 mengakibatkan kematisn dijatuhkan pidana penjara paling lama lima belas tahun."},{"l":"KUHP","p":"292","b":"Kejahatan Terhadap Kesusilaan","t":"Orang dewasa yang melakukan perbuatan cabul dengan orang lain sesama kelamin, yang diketahuinya atau sepatutnya harus diduganya belum dewasa, diancam dengan pidana penjara paling lama lima tahun."},{"l":"KUHP","p":"293","b":"Kejahatan Terhadap Kesusilaan","t":"(1) Barang siapa dengan memberi atau menjanjikan uang atau barang, menyalahgunakan pembawa yang timbul dari hubungan keadaan, atau dengan penyesatan sengaja menggerakkan seorang belum dewasa dan baik tingkahlakunya untuk melakukan atau membiarkan dilakukan perbuatan cabul dengan dia, padahal tentang belum kedewasaannya, diketahui atau selayaknya harus diduganya, diancam dengan pidana penjara paling lama lima tahun. (2) Penuntutan hanya dilakukan atas pengaduan orang yang terhadap dirinya dilakukan kejahatan itu. (3) Tenggang waktu tersebut dalam pasal 74 bagi pengaduan ini adalah masing-masing sembilan bulan dan dua belas bulan."},{"l":"KUHP","p":"294","b":"Kejahatan Terhadap Kesusilaan","t":"(1) Barang siapa melakukan perbuatan cabul dengm anaknya, tirinya, anak angkatnya, anak di bawah pengawannya yang belum dewasa, atau dengan orang yang belum dewasa yang pemeliharaanya, pendidikan atau penjagaannya diannya yang belum dewasa, diancam dengan pidana penjara paling lama tujuh tahun. (2) Diancam dengan pidana yang sama: 1. pejabat yang melakukan perbuatan cabul dengan orang yang karena jabatan adalah bawahannya, atau dengan orang yang penjagaannya dipercayakan atau diserahkan kepadanya, 2. pengurus, dokter, guru, pegawai, pengawas atau pesuruh dalam penjara, tempat pekerjaan negara, tempat pen- didikan, rumah piatu, rumah sakit, rumah sakit jiwa atau lembaga sosial, yang melakukan perbuatan cabul dengan orang yang dimasukkan ke dalamnya."},{"l":"KUHP","p":"295","b":"Kejahatan Terhadap Kesusilaan","t":"(1) Diancam: 1. dengan pidana penjara paling lama lima tahun barang siapa dengan sengaja menyebabkan atau memudahkan dilakukannya perbuatan cabul oleh anaknya, anak tirinya, anak angkatnya, atau anak di bawah pengawasannya yang belum dewasa, atau oleh orang yang belum dewasa yang pemeliharaannya, pendidikan atau penjagaannya diserahkan kepadanya, ataupun oleh bujangnya atau bawahannya yang belum cukup umur, dengan orang lain; 2. dengan pidana penjara paling lama empat tahun barang siapa dengan sengaja menghubungkan atau memudahkan perbuatan cabul, kecuali yang tersebut dalam butir 1 di atas., yang dilakukan oleh orang yang diketahuinya belum dewasa atau yang sepatutnya harus diduganya demikian, dengan orang lain. (2) Jika yang rs me lakukan kejahatan itu sebagai pencarian atau kebiasaan, maka pidana dapat ditam sepertiga."},{"l":"KUHP","p":"296","b":"Kejahatan Terhadap Kesusilaan","t":"Barang siapa dengan sengaja menyebabkan atau memudahkan bul oleh orang lain dengan orang lain, dan menjadikannya sebagai pencarian atau kebiasaan, diancam dengan pidana penjara paling lama satu tahun empat bulan atau pidana denda paling banyak lima belas ribu rupiah."},{"l":"KUHP","p":"297","b":"Kejahatan Terhadap Kesusilaan","t":"Perdagangan wanita dan perdagangan anak laki-laki yang belum dewasa, diancam dengan pidana penjara paling lama enam tahun."},{"l":"KUHP","p":"298","b":"Kejahatan Terhadap Kesusilaan","t":"(1) Dalam hal pemidanaan berdasarkan salah satu kejahatan dalam pasal 281, 284 - 290 dan 292 - 297, pencabutan hakhak berdasarkan pasal 35 No. 1 - 5 dapat dinyatakan. (2) Jika yang bersalah melakukan salah satu kejahatan berdasarkan pasal 292 - 297 dalam melakukan pencariannya, maka hak untuk melakukan pencarian itu dapat dicabut."},{"l":"KUHP","p":"299","b":"Kejahatan Terhadap Kesusilaan","t":"(1) Barang siapa dengan sengaja mengobati seorang wanita atau menyuruh supaya diobati, dengan diberitahukan atau ditimbulkan harapan bahwa karena pengobatan itu hamilnya dapat digugurkan, diancam dengan pidana penjara paling lama empat tahun atau pidana denda paling banyak empat puluh lima ribu rupiah. (2) Jika yang bersalah berbuat demikian untuk mencari keu tungan, atau menjadikan perbuatan tersebut sebagai pencarian atau kebiasaan, atau jika dia seorang tabib, bidan atau juruobat, pidmmya dapat ditambah sepertiga (3) Jika yang bersalah melakukan kejahatan tersebut dalam menjalankan pencariannya, dapat dicabut haknya untuk menjalakukan pencarian itu."},{"l":"KUHP","p":"300","b":"Kejahatan Terhadap Kesusilaan","t":"(1) Diancam dengan pidana penjara paling lama satu tahun atau denda paling banyak empat ribu lima ratus rupiah: 1. barang siapa dengan sengaja menjual atau memberikan minuman yang memabukkan kepada seseorang yang telah kelihatan mabuk; Perdagangan wanita dan perdagangan anak laki-laki yang belum dewasa, diancam dengan pidana penjara paling lama enam tahun. 2. barang siapa dengan sengaja membikin mabuk seorang anak yang umurnya belum cukup enam belas tahun; 3. barang siapa dengan kekerasan atau ancaman kekerasan memaksa orang untuk minum minuman yang memabukan. (2) Jika perbuatan mengakibatkan luka-luka berat, yang bersalah diancam dengan pidana penjara paling lama tujuh tahun. (3) Jika perbuatan mengakibatkan kematian, yang bersalah diancam dengan pidana penjara paling lama sembilan tahun. (4) Jika yang bersalah melakukan kejahatan tersebut dalam menjalankan pencariannya, dapat dicabut haknya untuk menjalankan pencarian itu."},{"l":"KUHP","p":"301","b":"Kejahatan Terhadap Kesusilaan","t":"Barang siapa memberi atau menyerahkan kepada orang lain seorang anak yang ada di bawah kekuasaainnya yang sah dan yang umumya kurang dari dua belas tahun, padahal diketahui bahwa anak itu akan dipakai untuk atau di waktu melakukan pengemisan atau untuk pekerjaan yang berbahaya, atau yang dapat merusak kesehatannya, diancam dengan pidana penjara paling lama empat tahun."},{"l":"KUHP","p":"302","b":"Kejahatan Terhadap Kesusilaan","t":"(1) Diancam dengan pidana penjara paling lama tiga bulan atau pidana denda paling banyak empat ribu lima ratus rupiah karena melakukan penganiayaan ringan terhadap hewan: 1. barang siapa tanpa tujuan yang patut atau secara melampaui batas, dengan sengaja menyakiti atau melukai hewan atau merugikan kesehatannya; 2. barang siapa tanpa tujuan yang patut atau dengan melampaui batas yang diperlukan untuk mencapai tujuan itu, dengan sengaja tidak memberi makanan yang diperlukan untuk hidup kepada hewan, yang seluruhnya atau sebagian menjadi kepunyaannya dan ada di bawah pengawasannya, atau kepada hewan yang wajib dipeliharanya. (2) Jika perbuatan itu mengakibatkan sakit lebih dari seminggu, atau cacat atau menderita luka-luka berat lainnya, atau mati, yang bersalah diancam dengan pidana penjara paling lama sembilan bulan, atau pidana denda paling banyak tiga ratus rupiah, karena penganiayaan hewan. (3) Jika hewan itu milik yang bersalah, maka hewan itu dapat dirampas. (4) Percobaan melakukan kejahatan tersebut tidak dipidana."},{"l":"KUHP","p":"303","b":"Kejahatan Terhadap Kesusilaan","t":"(1) Diancam dengan pidana penjara paling lama sepuluh tahun atau pidana denda paling banyak dua puluh lima juta rupiah, barang siapa tanpa mendapat izin: 1. dengan sengaja menawarkan atau memberikan kesempatan untuk permainan judi dan menjadikannya sebagai pen- carian, atau dengan sengaja turut serta dalam suatu perusahaan untuk itu; 2. dengan sengaja menawarkan atau memberi kesempatan kepada khalayak umum untuk bermain judi atau dengan sengaja turut serta dalam perusahaan untuk itu, dengan tidak peduli apakah untuk menggunakan kesempatan adanya sesuatu syarat atau dipenuhinya sesuatu tata-cara; 3. menjadikan turut serta pada permainan 'udi seb agai pen (2) Kalau yang bersalah melakukan kejahatan tersebut dalam mejalakan pencariannya, maka dapat dicabut hak nya untuk menjalankan pencarian itu. (3) Yang disebut permainan judi adalah tiap-tiap permainan, di mana pada umumnya kemungkinan mendapat untung bergantung pada peruntungan belaka, juga karena pemainnya lebih terlatih atau lebih mahir. Di situ termasuk segala pertaruhan tentang keputusan perlombaan atau permainanlain-lainnya yang tidak diadakan antara mereka yang turut berlomba atau bermain, demikian juga segala pertaruhan lainnya. Pasal 303 bis (1) Diancam dengan pidana penjara paling lama empat tahun atau pidana denda paling banyak sepuluh juta rupiah: 1. barang siapa menggunakan kesempatan main judi, yang diadakan dengan melanggar ketentuan Pasal 303; 2. barang siapa ikut serta main judi di jalan umum atau di pinggir jalan umum atau di tempat yang dapat dikunjungi umum, kecuali kalau ada izin dari penguasa yang berwenang yang telah memberi izin untuk mengadakan perjudian itu. (2) Jika ketika melakukan pelanggaran belum lewat dua tahun sejak ada pemidanaan yang menjadi tetap karena salah satu dari pelanggaran ini, dapat dikenakan pidana penjara paling lama enam tahun atau pidana denda paling banyak lima belas juta rupiah."},{"l":"KUHP","p":"304","b":"Meninggalkan Orang Yang Perlu Ditolong","t":"Barang siapa dengan sengaja menempatkan atau membiarkan seorang dalam keadaan sengsara, padahal menurut hukum yang berlaku baginya atau karena persetujuan dia wajib memberi kehidupan, perawatan atau pemeliharaan kepada orang itu, diancam dengan pidana penjara paling lama dua tahun delapan bulan atau pidana denda paling banyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"305","b":"Meninggalkan Orang Yang Perlu Ditolong","t":"Barang siapa menempatkan anak yang umurnya belum tujuh tahun untuk ditemukan atau meninggalkan anak itu dengan maksud untuk melepaskan diri daripadanya, diancam dengan pidana penjara paling lama lima tahun enam bulan."},{"l":"KUHP","p":"306","b":"Meninggalkan Orang Yang Perlu Ditolong","t":"(1) Jika salah satu perbuatan berdasarkan pasal 304 dan 305 mengakibatkan luka-luka berat, yang bersalah diancamdengan pidana penjara paling lama tujuh tahun enam bulan. (2) Jika mengakibatkan kematian pidana penjara paling lama sembilan tahun."},{"l":"KUHP","p":"307","b":"Meninggalkan Orang Yang Perlu Ditolong","t":"Jika yang melakukan kejahatan berdasarkan pasal 305 adalah bapak atau ibu dari anak itu, maka pidana yang ditentukan dalam pasal 305 dan 306 dapat ditambah dengan sepertiga."},{"l":"KUHP","p":"308","b":"Meninggalkan Orang Yang Perlu Ditolong","t":"Jika seorang ibu karena takut akan diketahui orang tentang kelahiran anaknya, tidak lama sesudah melahirkan, menempatkan anaknya untuk ditemukan atau meninggalkannya dengan maksud untuk melepaskan diri daripadanya, maka maksimum pidana tersebut dalam pasal 305 dan 306 dikurangi separuh."},{"l":"KUHP","p":"309","b":"Meninggalkan Orang Yang Perlu Ditolong","t":"Dalam hal pemidanaan berdasarkan salah satu kejahatan dalam pasal 304 - 308, maka hak-hak tersebut dalam pasal 35 No. 4 dapat dicabut."},{"l":"KUHP","p":"310","b":"Penghinaan","t":"(1) Barang siapa sengaja menyerang kehormatan atau nama baik seseorang dengan menuduhkan sesuatu hal, yang maksudnya terang supaya hal itu diketahui umum, diancam karena pencemaran dengan pidana penjara paling lama sembilan bulan atau pidana denda paling banyak empat ribu lima ratus rupiah. (2) Jika hal itu dilakukan dengan tulisan atau gambaran yang disiarkan, dipertunjukkan atau ditempelkan di muka umum, maka diancam karena pencemaran tertulis dengan pidana penjara paling lama satu tahun empat bulan atau pidana denda paling banyak empat ribu lima ratus rupiah. (3) Tidak merupakan pencemaran atau pencemaran tertulis, jika perbuatan jelas dilakukan demi kepentingan umum atau karena terpaksa untuk membela diri."},{"l":"KUHP","p":"311","b":"Penghinaan","t":"(1) Jika yang melakukan kejahatan pencemaran atau pencemaran tertulis dibolehkan untuk membuktikan apa yang dituduhkan itu benar, tidak membuktikannya, dan tuduhan dilakukan bertentangan dengan apa yang diketahui, maka dia diancam melakukan fitnah dengan pidana penjara paling lama empat tahun. (2) Pencabutan hak-hak berdasarkan pasal 35 No. 1 - 3 dapat dijatuhkan."},{"l":"KUHP","p":"312","b":"Penghinaan","t":"Pembuktian akan kebenaran tuduhan hanya dibolehkan dalam hal-hal berikut: 1. apabila hakim memandang perlu untuk memeriksa kebenaran itu guna menimbang keterangan terdakwa, bahwa perbuatan dilakukan demi kepentingan umum, atau karena terpaksa untuk membela diri; 2. apabila seorang pejabat dituduh sesuatu hal dalam menjalankan tugasnya."},{"l":"KUHP","p":"313","b":"Penghinaan","t":"Pembuktian yang dimaksud dalam pasal 312 tidak dibolehkan, jika hal yang dituduhkan hanya dapat dituntut atas pengaduan dan pengaduan tidak dimajukan."},{"l":"KUHP","p":"314","b":"Penghinaan","t":"(1) Jika yang dihina, dengan putusan hakim yang menjadi tetap, dinyatakan bersalah atas hal yang dituduhkan, maka pemidanaan karena fitnah tidak mungkin. (2) Jika dia dengan putusan hakim yang menjadi tetap dibebaskan dari hal yang dituduhkan, maka putusan itu dipandang sebagai bukti sempurna bahwa hal yang dituduhkan tidak benar. (3) Jika terhadap yang dihina telah dimulai penuntutan pidana karena hal yang dituduhkan padanya, maka penuntutan karena fitnah dihentikan sampai mendapat putusan yang menjadi tetap tentang hal yang dituduhkan."},{"l":"KUHP","p":"315","b":"Penghinaan","t":"Tiap-tiap penghinaan dengan sengaja yang tidak bersifat peneemaran atau pencemaran tertulis yang dilakuknn terhadap seseorang, baik di muka umum dengan lisan atau tulisan, maupun di muka orang itu sendiri dengan lisan atau perbuatan, atau dengan surat yang dikirimkan stau diterimakan kepadanya, diancam karena penghinaan ringan dengan pidana penjara paling lama empat bulan dua minggu atau pidana denda paling banyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"316","b":"Penghinaan","t":"Pidana yang ditentukan dalam pasal-pasal sebelumnya dalam bab ini, dspat ditambah dengan sepertiga jika yang dihina adalah seorang pejabat pada waktu atau karena menjalankan tugasnya yang sah."},{"l":"KUHP","p":"317","b":"Penghinaan","t":"(1) Barang siapa dengan sengaja mengajukan pengaduan atau pemberitahuan palsu kepada penguasa, baik secara tertulis maupun untuk dituliskan, tentang seseorang sehingga kehormatan atau nama baiknya terserang, diancam karena melakukan pengaduan fitnah, dengan pidana penjara paling lama empat tahun, (2) Pencabutan hak-hak berdasarkan pasal 35 No, 1 - 3 dapat dijatuhkan."},{"l":"KUHP","p":"318","b":"Penghinaan","t":"(1) Barang siapa dengan sesuatu perbuatan sengaja menimbulkan secara palsu persangkaan terhadap seseorang bahwa dia melakukan suatu perbuatan pidana, diancam karena menimbulkan persangkaan palsu, dengan pidana penjara paling lama empat tahun. (2) Pencabutan hak-hak berdasarkan pasal 35 No. 1 - 3 dapat dijatuhkan. Pasal 319 Penghinaan yang diancam dengan pidana menurut bab ini, tidak dituntut jika tidak ada pengaduan dari orang yang terkena kejahatan itu, kecuali berdasarkan pasal 316."},{"l":"KUHP","p":"320","b":"Penghinaan","t":"(1) Barang siapa terhadap seseorang yang sudah mati melakukan perbuatan yang kalau orang itu masih hidup akan merupakan pencemaran atau pencemaran tertulis, diancam dengan pidana penjara paling lama empat bulan dua minggu atau pidana denda paling banyak empat ribu lima ratus rupiah. (2) Kejahatan ini tidak dituntut kalau tidak ada pengaduan dari salah seorang keluarga sedarah maupun semenda dalam garis lurus atau menyimpang sampai derajat kedua dari yang mati itu, atau atas pengaduan suami (istri)nya. (3) Jika karena lembaga matriarkal kekuasaan bapak dilakukan oleh orang lain daripada bapak, maka kejahatan juga dapat dituntut atas pengaduan orang itu."},{"l":"KUHP","p":"321","b":"Penghinaan","t":"(1) Barang siapa menyiarkan, mempertunjukkan atau menempelkan di muka umum tulisan atau gambaran yang isinya menghina atau bagi orang ymg sudah mati mencemarkan namanya, dengan maksud supaya isi surat atau gambar itu ditahui atau lehih diketahui oleh umum, diancam dengan pidana penjara paling lama satu hulan dua minggu atau pidana denda paling banyak empat ribu lima ratus rupiah. (2) Jika Yang bersalah rnelakukan kejahat.an tersehut dalam menjalankan pencariannya, sedangkan ketika itu belum lampau dua tahun sejak adanya pemidanaan yang menjadi tetap karena kejahatan semacam itu juga, maka dapat. dicabut haknya untuk menjalankan pencarian tersehut. (3) Kejahatan ini tidak dituntut kalau tidak ada pengaduan dari orang yang ditunjuk dalam pasal 319 dan pasal 320, ayat kedua dan ketiga."},{"l":"KUHP","p":"322","b":"Membuka Rahasia","t":"(1) Barang siapa dengan sengaja membuka rahasia yang wajib disimpannya karena jabatan atau pencariannya, baik yang sekarang maupun yang dahulu, diancam dengan pidana penjara paling lama sembilan bulan atau pidana denda paling banyak sembilan ribu rupiah. (2) Jika kejahatan dilakukan terhadap seorang tertentu, maka perbuatan itu hanya dapat dituntut atas pengaduan orang itu."},{"l":"KUHP","p":"323","b":"Membuka Rahasia","t":"(1) Barang siapa dengan sengaja memberitahukan hal-hal khusus tentang suatu perusahaan dagang, kerajinan atau pertanian, di mana ia bekerja atau dahulu bekerja, yang harus dirahasiakannya, diancam dengan pidana penjara paling lama sembilan bulan atau pidana denda paling banyak sembilan ribu rupiah. (2) Kejahatan ini hanya dituntut atas pengaduan pengurus perusahaan itu."},{"l":"KUHP","p":"324","b":"Kejahatan Terhadap Kemerdekaan Orang","t":"Barang siapa dengan biaya sendiri atau biaya orang lain menjalankan perniagaan budak atau melakukan perbuatan perniagaan budak atau dengan sengaja turut serta secara langsung atau tidak langsung dalam salah satu perbuatan tersebut di atas, diancam dengan pidana penjara paling lama dua belas tahun."},{"l":"KUHP","p":"325","b":"Kejahatan Terhadap Kemerdekaan Orang","t":"(1) Barang siapa sebagai nakoda bekerja atau bertugas di kapal, sedang diketahuinya bahwa kapal itu dipergunakan untuk tujuan pemiagaan budak, atau dipakai kapal itu untuk perniagaan budak, diancam dengan pidana penjara paling lama dua belas tahun. (2) Bilamana pengangkutan itu mengakibatkan kematian seorang budak atau lebih, maka nakoda diancam dengan pidana penjara paling lama lima belas tahun."},{"l":"KUHP","p":"326","b":"Kejahatan Terhadap Kemerdekaan Orang","t":"Barang siapa bekerja sebagai awak kapal di sebuah kapal, sedang diketahuinya bahwa kapal itu dipergunakan untuk tujuan atsu keperluan perniagaan budak, atau dengan sukarela tetap berengas setelah mendengar bahwa kapal itu dipergunakan untuk tujuan atau keperluan perniagaan budak, diancam dengan pidana penjara paling lama sembilan tahun."},{"l":"KUHP","p":"327","b":"Kejahatan Terhadap Kemerdekaan Orang","t":"Barang siapa dengan biaya sendiri atau biaya orang lain, secara langsung atau tidak langsung bekerja sama untuk menyewakan, mengangkutkan atau mengasuransikan sebuah kapal, sedang diketahuinya bahwa kapal itu dipergunakan untuk tujuan perniagaan budak, diancam dengan pidana penjara paling lama delapan tahun."},{"l":"KUHP","p":"328","b":"Kejahatan Terhadap Kemerdekaan Orang","t":"Barang siapa membawa pergi seorang dari tempat kediamannya atau tempat tinggalnya sementara dengan maksud untuk menempatkan orang itu secara melawan hukum di bawah kekuasaannya atau kekuasaan orang lain, atau untuk menempatkan dia dalam keadaan sengsara, diancam karena penculikan dengan pidana penjara paling lama dua belas tahun."},{"l":"KUHP","p":"329","b":"Kejahatan Terhadap Kemerdekaan Orang","t":"Barang siapa dengan sengaja dan melawan hukum mengangkut orang ke daerah lain, padahal orang itu telah membuat perjanjian untuk bekerja di suatu tempat tertentu, diancam dengan pidana penjara paling lama tujuh tahun."},{"l":"KUHP","p":"330","b":"Kejahatan Terhadap Kemerdekaan Orang","t":"(1) Barang siapa dengan sengaja menarik seorang yang belum cukup umur dari kekuasaan yang menurut undang-undang ditentukan atas dirinya, atau dari pengawasan orang yang berwenang untuk itu, diancam dengan pidana penjara paling lama tujuh tahun. (2) Bilamana dalam hal ini dilakukan tipu muslihat, kekerasan atau ancaman kekerasan, atau bilamana anaknya belum berumur dua belas tahun, dijatuhkan pidana penjara paling lama sembilan tahun."},{"l":"KUHP","p":"331","b":"Kejahatan Terhadap Kemerdekaan Orang","t":"Orang siapa dengan sengaja menyemhunyikan orang yang belum dewasa yang ditarik atau menarik sendiri dari kekuasaan yang menurut undang-undang ditentukan atas dirinya. atau dari pengawasan orang yang berwenang untuk itu, atau dengan sengaja menariknya dari pengusutan pejabat kehakiman atau kepolisian diancam dengan penjara paling lama empat tahun, atau jika anak itu berumur di bawah dua belas tahun, dengan pidana penjara paling lama tujuh tahun."},{"l":"KUHP","p":"332","b":"Kejahatan Terhadap Kemerdekaan Orang","t":"(1) Bersalah melarikan wanita diancam dengan pidana penjara; 1. paling lama tujuh tahun, barang siapa membawa pergi seorang wanita yang belum dewasa, tanpa dikehendaki orang tuanya atau walinya tetapi dengan persetujuannya. dengan maksud untuk memastikan penguasaan tezhadap wanita itu, baik di dalam maupun di luar perkawinan; 2. paling lama sembilan tahun, barang siapa membawa pergi seorang wanita dengan tipu muslihat, kekerasan atau ancaman kekerasan, dengan maksud untuk memastikan penguasaannya terhadap wanita itu, baik di dalam maupun di luar perkawinan. (2) Penuntutan hanya dilakukan atas pengaduan. (3) Pengaduan dilakukan: a. jika wanita ketika dibawa pergi belum dewasa, oleh dia sendiri atau orang lain yang harus memberi izin bila dia kawin; b. jika wanita ketika dibawa pergi sudah dewasa, oleh dia sendiri atau oleh suaminya. (4) Jika yang membaiva pergi lalu kawin dengan wanita yang dibawa pergi dan terhadap perkawinan itu berlaku aturan aturan Burgerlijk Wetboek, maka tak dapat dijatuhkan pidana sebelum perkawinan itu dinyatakan batal."},{"l":"KUHP","p":"333","b":"Kejahatan Terhadap Kemerdekaan Orang","t":"(1) Barang siapa dengan sengaja dan melawan hukum merampas kemerdekaan seseorang, atau meneruskan perarnpasan kemerdekaan yang demikian, diancam dengan pidana penjara paling lama delapan tahun. (2) Jika perbuatan itu mengakibatkan luka-luka berat maka yang bersalah diancam dengan pidana penjara paling lama sembilan tahun. (3) Jika mengakibatkan mati diancam dengan pidana penjara paling lama dua belas tahun. (4) Pidana yang ditentukan dalam pasal ini diterapkan juga bagi orang yang dengan sengaja dan melawan hukum memberi tempat untuk perampasan kemerdekaan."},{"l":"KUHP","p":"334","b":"Kejahatan Terhadap Kemerdekaan Orang","t":"(1) Barang siapa karena kealpaannya menyebabkan seorang dirampas kemerdekaannya secara melawan hukum, atau diteruskannya perampasan kemerdekaan yang demikian, diancam dengan pidana kurungan paling lama tiga bulan atau pidana denda paling banyak tiga ratus rupiah. (2) Jika perbuatan itu mengakibatkan luka-luka berat, maka yang bersalah diancam dengan pidana kurungan paling lama sembilan bulan. (3) Jika mengakibatkan mati, diancam dengan pidana kurungan paling lama satu tahun."},{"l":"KUHP","p":"335","b":"Kejahatan Terhadap Kemerdekaan Orang","t":"(1) Diancam dengan pidana penjara paling lama satu tahun atau denda paling banyak empat ribu lima ratus rupiah: 1. barang siapa secara melawan hukum memaksa orang lain supaya melakukan, tidak melakukan atau membiarkan sesuatu, dengan memakai kekerasan, sesuatu perbuatan lain maupun perlakuan yang tak menyenangkan, atau dengan memakai ancaman kekerasan, sesuatu perbuatan lain maupun perlakuan yang tak menyenangkan, baik terhadap orang itu sendiri maupun orang lain; 2 barang siapa memaksa orang lain supaya melakukan, tidak melakukan atau membiarkan sesuatu dengan ancaman pencemaran atau pencemaran tertulis. (2) Dalam hal sebagaimana dirumuskan dalam butir 2, kejahatan hanya dituntut atas pengaduan orang yang terkena."},{"l":"KUHP","p":"336","b":"Kejahatan Terhadap Kemerdekaan Orang","t":"(1) Diancam dengan pidana penjara paling lama dua tahun delapan bulan, barang siapa mengancam dengan kekerasan terhadap orang atau barang secara terang-terangan dengan tenaga bersama, dengan suatu kejahatan yang menimbulkan bahaya umum bagi keamanan orang atau barang, dengan perkosaan atau perbuatan yang melanggar kehormatan kesusilaan, dengan sesuatu kejahatan terhadap nyawa, dengan penganiayaan berat atau dengan pembakaran. (2) Bilamana ancaman dilakukan secara tertulis dan dengan syarat tertentu, maka dikenakan pidana penjara paling lama lima tahun."},{"l":"KUHP","p":"337","b":"Kejahatan Terhadap Kemerdekaan Orang","t":"Dalam hal pemidanaan berdasarkan salah satu kejahatan dalam pasal 324 - 333 dan pasal 336 ayat kedua, dapat dijatuhkan pencabutan hak berdasarkan pasal 35 No. 1 - 4."},{"l":"KUHP","p":"338","b":"Kejahatan Terhadap Nyawa","t":"Barang siapa dengan sengaja merampas nyawa orang lain, diancam karena pembunuhan dengan pidana penjara paling lama lima belas tahun."},{"l":"KUHP","p":"339","b":"Kejahatan Terhadap Nyawa","t":"Pembunuhan yang diikuti, disertai atau didahului oleh suatu perbuatan pidana, yang dilakukan dengan maksud untuk mempersiapkan atau mempermudah pelaksanaannya, atau untuk melepaskan diri sendiri maupun peserta lainnya dari pidana dalam hal tertangkap tangan, ataupun untuk memastikan penguasaan barang yang diperolehnya secara melawan hukum, diancam dengan pidana penjara seumur hidup atau selama waktu tertentu, paling lama dua puluh tahun."},{"l":"KUHP","p":"340","b":"Kejahatan Terhadap Nyawa","t":"Barang siapa dengan sengaja dan dengan rencana terlebih dahulu merampas nyawa orang lain, diancam karena pembunuhan dengan rencana, dengan pidana rnati atau pidana penjara seumur hidup atau selama waktu tertentu, paling lama dua puluh tahun."},{"l":"KUHP","p":"341","b":"Kejahatan Terhadap Nyawa","t":"Seorang ibu yang karena takut akan ketahuan melahirkan anak pada saat anak dilahirkan atau tidak lama kemudian, dengan sengaja merampas nyawa anaknya, diancam karena membunuh anak sendiri, dengan pidana penjara paling lama tujuh tahun."},{"l":"KUHP","p":"342","b":"Kejahatan Terhadap Nyawa","t":"Seorang ibu yang untuk melaksanakan niat yang ditentukan karena takut akan ketahuan bahwa ia akan melahirkan anak pada saat anak dilahirkan atau tidak lama kemudian merampas nyawa anaknya, diancam karena melakukan pembunuhan anak sendiri dengan rencana, dengan pidana penjara paling lama semhi- lan tahun."},{"l":"KUHP","p":"343","b":"Kejahatan Terhadap Nyawa","t":"Kejahatan yang diterangkan dalam pasal 341 dan 342 dipandang bagi orang lain yang turut serta melakukan, sebagai pembunuhan atau pembunuhan anak dengan rencana."},{"l":"KUHP","p":"344","b":"Kejahatan Terhadap Nyawa","t":"Barang siapa merampas nyawa orang lain atas permintaan orang itu sendiri yang jelas dinyatakan dengan kesungguhan hati, diancam dengan pidana penjara paling lama dua belas tahun."},{"l":"KUHP","p":"345","b":"Kejahatan Terhadap Nyawa","t":"Barang siapa sengaja mendorong orang lain untuk bunuh diri, menolongnya dalam perbuatan itu atau memberi sarana kepadanya untuk itu, diancam dengan pidana penjara paling lama empat tahun kalau orang itu jadi bunuh diri. Pasal 346 Seorang wanita yang sengaja menggugurkan atau mematikan kandungannya atau menyuruh orang lain untuk itu, diancam dengan pidana penjara paling lama empat tahun."},{"l":"KUHP","p":"347","b":"Kejahatan Terhadap Nyawa","t":"(1) Barang siapa dengan sengaja menggugurkan atau mematikan kandungan seorang wanita tanpa persetujuannya, diancam dengan pidana penjara paling lama dua belas tahun. (2) Jika perbuatan itu mengakibatkan matinya wanita tersebut diancam dengan pidana penjara paling lama lima belas tahun."},{"l":"KUHP","p":"348","b":"Kejahatan Terhadap Nyawa","t":"(1) Barang siapa dengan sengaja menggugurkan atau mematikan kandungan seorang wanita dengan persetujuannya, diancam dengan pidana penjara paling lama lima tahun enam bulan. (2) Jika perbuatan itu mengakibatkan matinya wanita tersebut, diancam dengan pidana penjara paling lama tujuh tahun."},{"l":"KUHP","p":"349","b":"Kejahatan Terhadap Nyawa","t":"Jika seorang dokter, bidan atau juru obat membantu melakukan kejahatan berdasarkan pasal 346, ataupun melakukan atau membantu melakukan salah satu kejahatan yang diterangkan dalam pasal 347 dan 348, maka pidana yang ditentukan dalam pasal itu dapat ditambah dengan sepertiga dan dapat dicabut hak untuk menjalankan pencarian dalam mana kejahatan dilakukan."},{"l":"KUHP","p":"350","b":"Kejahatan Terhadap Nyawa","t":"Dalam hal pemidanaan karena pembunuhan, karena pembunuhan dengan rencana, atau karena salah satu kejahatan berdasarkan Pasal 344, 347 dan 348, dapat dijatuhkan pencabutan hak berdasarkan pasal 35 No. 1- 5."},{"l":"KUHP","p":"351","b":"Penganiayaan","t":"(1) Penganiayaan diancam dengan pidana penjara paling lama dua tahun delapan bulan atau pidana denda paling banyak empat ribu lima ratus rupiah, (2) Jika perbuatan mengakibatkan luka-luka berat, yang bersalah diancam dengan pidana penjara paling lama lima tahun. (3) Jika mengakibatkan mati, diancam dengan pidana penjara paling lama tujuh tahun. (4) Dengan penganiayaan disamakan sengaja merusak kesehatan. (5) Percobaan untuk melakukan kejahatan ini tidak dipidana."},{"l":"KUHP","p":"352","b":"Penganiayaan","t":"(1) Kecuali yang tersebut dalam pasal 353 dan 356, maka penganiayaan yang tidak menimbulkan penyakit atau halangan untuk menjalankan pekerjaan jabatan atau pencarian, diancam, sebagai penganiayaan ringan, dengan pidana penjara paling lama tiga bulan atau pidana denda paling banyak empat ribu lima ratus rupiah. Pidana dapat ditambah sepertiga bagi orang yang melakukan kejahatan itu terhadap orang yang bekerja padanya, atau menjadi bawahannya. (2) Percobaan untuk melakukan kejahatan ini tidak dipidana."},{"l":"KUHP","p":"353","b":"Penganiayaan","t":"(1) Penganiayaan dengan rencana lebih dahulu, diancam dengan pidana penjara paling lama empat tahun. (2) Jika perbuatan itu mengakibatka luka-luka berat, yang bersalah dikenakan pidana penjara paling lama tujuh tahun. (3) Jika perbuatan itu mengkibatkan kematian yang bersalah diancam dengan pidana penjara paling lama sembilan tahun"},{"l":"KUHP","p":"354","b":"Penganiayaan","t":"(1) Barang siapa sengaja melukai berat orang lain, diancam karena melakukan penganiayaan berat dengan pidana penjara paling lama delapan tahun. (2) Jika perbuatan itu mengakibatkan kematian, yang bersalah diancam dengan pidana penjara paling lama sepuluh tahun."},{"l":"KUHP","p":"355","b":"Penganiayaan","t":"(1) Penganiayaan berat yang dilakukan dengan rencana terlebih dahulu, diancam dengan pidana penjara paling lama dua belas tahun. (2) Jika perbuatan itu mengakibatkan kematian, yang bersalah diancam dengan pidana penjara paling lams lima belas tahun."},{"l":"KUHP","p":"356","b":"Penganiayaan","t":"Pidana yang ditentukan dalam pasal 351, 353, 354 dan 355 dapat ditambah dengan sepertiga: 1. bagi yang melakukan kejahatan itu terhadap ibunya, bapaknya yang sah, istrinya atau anaknya; 2. jika kejahatan itu dilakukan terhadap seorang pejsbat ketika atau karena menjalankan tugasnya yang sah; 3. jika kejahatan itu dilakukan dengan memberikan bahan yang herbahaya bagi nyawa atau kesehatan untuk dimakan atau diminum."},{"l":"KUHP","p":"357","b":"Penganiayaan","t":"Dalam hal pemidanaan karena salah satu kejahatan berdasarkan pasal 353 dan 355, dapat dijatuhkan pencabutan hak berdasarkan pasal 3o No. 1 - 4."},{"l":"KUHP","p":"358","b":"Penganiayaan","t":"Mereka yang sengaja turut serta dalam penyerangan atau perkelahian di mana terlibat beberapa orang, selain tanggung jawab masing-masing terhadap apa yang khusus dilakukan olehnya, diancam: 1. dengan pidana penjara paling lama dua tahun delapan bulan, jika akibat penyerangan atau perkelahian itu ada yang luka-luka berat; 2. dengan pidana penjara paling lama empat tahun, jika akibatnya ada yang mati. Bab XXI Menyebabkan Mati Atau Luka-Luka Karena Kealpaan"},{"l":"KUHP","p":"359","b":"Penganiayaan","t":"Barang siapa karena kesalahannya (kealpaannya) menyebabkan orang lain mati, diancam dengan pidana penjara paling lama lima tahun atau pidana kurungan paling lama satu tahun."},{"l":"KUHP","p":"360","b":"Penganiayaan","t":"(1) Barang siapa karena kesalahannya (kealpaannya) menyebabkan orang lain mendapat luka-luka berat, diancam dengan pidana penjara paling lama lima tahun atau pidana kurungan paling lama satu tahun. (2) Barang siapa karena kesalahannya (kealpaannya) menyebahkan orang lain luka- luka sedemikian rupa sehingga timhul penyakit atau halangan menjalankan pekerjaan jabatan atau pencarian selama waktu tertentu, diancam dengan pidana penjara paling lama sembilan bulan atau pidana kurungan paling lama enam bulan atau pidana denda paling tinggi empat ribu lima ratus rupiah."},{"l":"KUHP","p":"361","b":"Penganiayaan","t":"Jika kejahatan yang diterangkan dalam bab ini dilakukan dalam menjalankan suatu jabatan atau pencarian, maka pidana ditamhah dengan sepertiga dan yang bersalah dapat dicahut haknya untuk menjalankan pencarian dalam mana dilakukan kejahatan dan hakim dapat memerintahkan supaya putusannya diumumkan."},{"l":"KUHP","p":"362","b":"Pencurian","t":"Barang siapa mengambil barang sesuatu, yang seluruhnya atau sebagian kepunyaan orang lain, dengan maksud untuk dimiliki secara melawan hukum, diancam karena pencurian, dengan pidana penjara paling lama lima tahun atau pidana denda paling banyak sembilan ratus rupiah."},{"l":"KUHP","p":"363","b":"Pencurian","t":"(1) Diancam dengan pidana penjara paling lama tujuh tahun: 1. pencurian ternak; 2. pencurian pada waktu ada kebakaran, letusan, banjir gempa bumi, atau gempa laut, gunung meletus, kapal karam, kapal terdampar, kecelakaan kereta api, huru-hara, pemberontakan atau bahaya perang; 3. pencurian di waktu malam dalam sebuah rumah atau pekarangan tertutup yang ada rumahnya, yang dilakukan oleh orang yang ada di situ tidak diketahui atau tidak dikehendaki oleh yang berhak; 4. pencurian yang dilakukan oleh dua orang atau lebih: 5. pencurian yang untuk masuk ke tempat melakukan kejahatan, atau untuk sampai pada barang yang diambil, dilakukan dengan merusak, memotong atau memanjat, atau dengan memakai anak kunci palsu, perintah palsu atau pakaian jabatan palsu. (2) Jika pencurian yang diterangkan dalam butir 3 disertai dengan salah satu hal dalam butir 4 dan 5, maka diancam dengan pidana penjara paling lama sembilan tahun."},{"l":"KUHP","p":"364","b":"Pencurian","t":"Perbuatan yang diterangkan dalam pasal 362 dan pasal 363 butir 4, begitu pun perbuatan yang diterangkan dalam pasal 363 butir 5, apabila tidak dilakukan dalam sebuah rumah atau pekarangan tertutup yang ada rumahnya, jika harga barang yang dicuri tidak lebih dari dua puluh lima rupiah, diancam karena pencurian ringan dengan pidana penjara paling lama tiga bulan atau pidana denda paling banyak dua ratus lima puluh rupiah."},{"l":"KUHP","p":"365","b":"Pencurian","t":"(1) Diancam dengan pidana penjara paling lama sembilan tahun pencurian yang didahului, disertai atau diikuti dengan kekerasan atau ancaman kekerasan, terhadap orang dengan maksud untuk mempersiapkan atsu mempermudah pencurian, atau dalam hal tertangkap tangan, untuk memungkinkan melarikan diri sendiri atau peserta lainnya, atau untuk tetap menguasai barang yang dicuri. (2) Diancam dengan pidana penjara paling lama dua belas tahun: 1. jika perbuatan dilakukan pada waktu malam dalam sebuah rumah atau pekarangan tertutup yang ada rumahnya, di berjalan; 2. jika perbuatan dilakukan oleh dua orang atau lebih dengan bersekutu; 3. jika masuk ke tempat melakukan kejahatan dengan merusak atau memanjat atau dengan memakai anak kunci palsu, periniah palsu atau pakaian jabatan palsu. 4. jika perbuatan mengakibatkan luka-luka berat. (3) Jika perbuatan mengakibatkan kematian maka diancam dengan pidana penjara paling lama lima belas tuhun. (4) Diancam dengan pidana mati atau pidana penjara seumur hidup atau selama waktu tertentu paling lama dua puluh tahun, jika perbuatan mengakihntkan luka berat atau kematian dan dilakukan oleh dua orang atau lebih dengan bersekutu, disertai pula oleh salah satu hal yang diterangkan dalam no. 1 dan 3."},{"l":"KUHP","p":"366","b":"Pencurian","t":"Dalam hal pemidanaan berdasarkan salah satu perbuatan yang dirumuskan dalum pasal 362. 363, dan 865 dapat dijatuhkan pencabutan hak berdasarkan pasal 35 No. 1 - 4."},{"l":"KUHP","p":"367","b":"Pencurian","t":"(1) Jika pembuat atau pemhantu ciari salah satu kejahatan dalam bab ini adalah suami (istri) dari orang yang terkena kejahatan dan tidak terpisah meja dan ranjang atau terpisah harta kekayaan, maka terhadap pembuat atau pembantu itu tidak mungkin diadakan tuntutan pidana. (2) Jika dia adalah suami (istri) yang terpisah meja dan ranjang atau terpisah harta kekayaan, atau jika dia adalah keluarga sedarah atau semenda, baik dalam garis lurus maupun garis menyimpang derajat kedua maka terhadap orang itu hanya mungkin diadakan penuntutan jika ada pengaduan yang terkena kejahatan. (3) Jika menurut lembaga matriarkal kekuasaan bapak dilakukan oleh orang lain daripada bapak kandung (sendiri), maka ketentuan ayat di atas berlaku juga bagi orang itu."},{"l":"KUHP","p":"368","b":"Pemerasan Dan Pengancaman","t":"(1) Barang siapa dengan maksud untuk menguntungkan diri sendiri atau orang lain secara melawan hukum, memaksa seorang dengan kekerasan atau ancaman kekerasan untuk memberikan barang sesuatu, yang seluruhnya atau sebagian adalah kepunyaan orang itu atau orang lain, atau supaya membuat hutang maupun menghapuskan piutang, diancam karena pemerasan dengan pidana penjara paling lama sembilan bulan. (2) Ketentuan pasal 365 ayat kedua, ketiga, dan keempat berlaku bagi kejahatan ini."},{"l":"KUHP","p":"369","b":"Pemerasan Dan Pengancaman","t":"(1) Barang siapa dengan maksud untuk menguntungkan diri sendiri atau orang lain secara melawan hukum. dengan ancaman pencemaran baik dengan lisan maupun tulisan, atau dengan ancaman akan membuka rahasia, memaksa seorang supaya memberikan barang sesuatu yang seluruhnya atau sebagian kepunyaan orang itu atau orang lain. atau supaya membuat hutang atau menghapuskan piutang, diancam dengan pidana penjara paling lama empat tahun. (2) Kejahatan ini tidak dituntut kecuali atas pengaduan orang yang terkena kejahatan."},{"l":"KUHP","p":"370","b":"Pemerasan Dan Pengancaman","t":"Ketentuan pasal 367 berlaku bagi kejahatan-kejahatan yang di rumuskan dalam bab ini."},{"l":"KUHP","p":"37l","b":"Pemerasan Dan Pengancaman","t":"Dalam hal pemidanaan berdasarkan salah satu kejahatan yang dirumuskan dalam bab ini dapat dijatuhkan pencabutan hak berdasarkan pasal 35 no. 1 - 4."},{"l":"KUHP","p":"372","b":"Penggelapan","t":"Barang siapa dengan sengaja dan melawan hukum memiliki barang sesuatu yang seluruhnya atau sebagian adalah kepunyaan orang lain, tetapi yang ada dalam kekuasaannya bukan karena kejahatan diancam karena penggelapan, dengan pidana penjara paling lama empat tahun atau pidana denda paling banyak sembilan ratus rupiah."},{"l":"KUHP","p":"373","b":"Penggelapan","t":"Perbuatan yang dirumuskan dalam pasal 372 apabila yang digelapkan bukan ternak dan harganya tidak lebih dari dua puluh lima rupiah, diancam sebagai penggelapan ringan dengan pidana penjara paling lama tiga bulan atau pidana denda paling banyak dua ratus lima puluh rupiah."},{"l":"KUHP","p":"374","b":"Penggelapan","t":"Penggelapan yang dilakukan oleh orang yang penguasaannya terhadap barang disebabkan karena ada hubungan kerja atau karena pencarian atau karena mendapat upah untuk itu, diancam dengan pidana penjara paling lama lima tahun."},{"l":"KUHP","p":"375","b":"Penggelapan","t":"Penggelapan yang dilakukan oleh orang yang karena terpaksa diberi barang untuk disimpan, atau yang dilakukan oleh wali pengampu, pengurus atau pelaksana surat wasiat, pengurus lembaga sosial atau yayasan, terhadap barang sesuatu yang dikuasainya selaku demikian, diancam dengan pidana penjara paling lama enam tahun."},{"l":"KUHP","p":"376","b":"Penggelapan","t":"Ketentuan dalam pasal 367 berlaku bagi kejahatan-kejahatan yang dirumuskan dalam bab ini."},{"l":"KUHP","p":"377","b":"Penggelapan","t":"(1) Dalam hal pemidanaan berdasarkan salah satu kejahatan yang dirumuskan dalam pasal 372, 374, dan 375 hakim dapat memerintahkan supaya putusan diumumkan dan dicabutnya hak-hak berdasarkan pasal 35 No. 1 4. (2) Jika kejahatan dilakukan dalam menjalankan pencarian maka dapat dicabut haknya untuk menjalankan pencarian itu. Bab XXV Perbuatan Curang"},{"l":"KUHP","p":"378","b":"Penggelapan","t":"Barang siapa dengan maksud untuk menguntungkan diri sendiri atau orang lain secara melawan hukum, dengan memakai nama palsu atau martabat palsu, dengan tipu muslihat, ataupun rangkaian kebohongan, menggerakkan orang lain untuk menyerahkan barang sesuatu kepadanya, atau supaya memberi hutang rnaupun menghapuskan piutang diancam karena penipuan dengan pidana penjara paling lama empat tahun."},{"l":"KUHP","p":"379","b":"Penggelapan","t":"Perbuatan yang dirumuskan dalam pasal 378, jika barang yang diserahkan itu bukan ternak dan harga daripada barang, hutang atau piutang itu tidak lebih dari dua puluh lima rupiah diancam sebagai penipuan ringan dengan pidana penjara paling lama tiga bulan atau pidana denda paling banyak dua ratus lima puluh rupiah."},{"l":"KUHP","p":"379a","b":"Penggelapan","t":"Barang siapa menjadikan sebagai mata pencarian atau kebiasaan untuk membeli barang- barang, dengan maksud supaya tanpa pembayaran seluruhnya memastikan penguasaan terhadap barang- barang itu untuk diri sendiri maupun orang lain diancam dengan pidana penjara paling lama empat tahun."},{"l":"KUHP","p":"380","b":"Penggelapan","t":"(1) Diancam dengan pidana penjara paling lama dua tahun delapan bulan atau pidana denda paling banyak lima ribu rupiah: 1. barang siapa menaruh suatu nama atau tanda secara palsu di atas atau di dalam suatu hasil kesusastraan, keilmuan, kesenian atau kerajinan, atau memalsu nama atau tanda yang asli, dengan mal sud supaya orang mengira bahwa itu benar-benar buah hasil orang yang nama atau tandanya ditaruh olehnya di atas atau di dalamnya tadi; 2. barang siapa dengan sengaja menjual menawarkan menyerahkan, mempunyai persediaan untuk dijual at.au memasukkan ke Indonesia, hasil kesusastraan, keilmuan, kesenian atau kerajinan. yang di dalam atau di atasnya telah ditaruh nama at.au tanda yang palsu, atau yang nama atau tandanya yang asli telah dipalsu, seakan-akan itu benar- benar hasil orang yang nama atau tandanya telah ditaruh secara palsu tadi. (2) Jika hasil itu kepunyaan terpidana, maka boleh dirampas."},{"l":"KUHP","p":"381","b":"Penggelapan","t":"Barang siapa dengan jalan tipu muslihat menyesatkan penanggung asuransi mengenai keadaan-keadaan yang berhubungan dengan pertanggungan sehingga disetujui perjanjian, hal mana tentu tidak akan disetujuinya atau setidak-tidaknya tidak dengan syarat- syarat yang demikian, jika diketahuinya keadaan-keadaan sebenarnya diancam dengan pidana penjara paling lama satu tahun empat bulan."},{"l":"KUHP","p":"382","b":"Penggelapan","t":"Barang siapa dengan maksud untuk menguntungkan diri sendiri atau orang lain secara melawan hukum. atas kerugian penanggung asuransi atau pemegang surat bodemerij yang sah. menimbulkan kebakaran atau ledakan pada suatu barang yang dipertanggungkan terhadap bahaya kebakaran, atau mengaramkan. mendamparkan. menghancurkan, merusakkan. atau membikin tak dapat dipakai. kapal yang dipertanggungkan atau yang muatannya maupun upah yang akan diterima untuk pengangkutan muatannya yang dipertanggungkan, ataupun yang atasnya telah diterima uang bode- merij diancarn dengan pidana penjara paling lama lima tahun. Pasal 382 bis Barang siapa untuk mendapatkan, melangsungkan atau memperluas hasil perdagangan atau perusahaan milik sendiri atau orang lain, melakukan perbuatan curang untuk menyesatkan khalayak umum atau seorang tertentu, diancam, jika perbuatan itu dapat enimbulkan kerugian bagi konkuren-konkurennya atau konguren-konkuren orang lain, karena persaingan curang, dengan pidana penjara paling lama satu tahun empat bulan atau pidana denda paling banyak tiga belas ribu lima ratus rupiah."},{"l":"KUHP","p":"383","b":"Penggelapan","t":"Diancam dengan pidana penjara paling lama satu tahun empat bulan, seorang penjual yang berbuat curang terhadap pembeli: 1. karena sengaja menyerahkan barang lain daripada yang ditunjuk untuk dibeli; 2 mengenai jenis, keadaan atau jumlah barang yang diserahkan, dengan menggunakan tipu muslihat. Pasal 383 bis Seorang pemegang konosemen yang sengaja mempergunakan beberapa eksemplar dari surat tersebut dengan titel yang memberatkan, dan untuk beberapa orang penerima, diancam dengan pidana penjara paling lama dua tahun delapan bulan."},{"l":"KUHP","p":"384","b":"Penggelapan","t":"Perbuatan yang dirumuskan dalam pasal 383, diancam dengan pidana penjara paling lama tiga bulan atau denda paling banyak dua ratus lima puluh rupiah, jika jumlah keuntungan yang di peroleh tidak lebih dari dua puluh lima rupiah."},{"l":"KUHP","p":"385","b":"Penggelapan","t":"Diancam dengan pidana penjara paling lama empat tahun: 1. barang siapa dengan maksud menguntungkan diri sendiri atau orang lain secara melawan hukum, menjual, menukarkan atau membebani dengan creditverband sesuatu hak tanah yang telah bersertifikat, sesuatu gedung, bangunan, penanaman atau pembenihan di atas tanah yang belum bersertifikat, padahal diketahui bahwa yang mempunyai atau turut mempunyai hak di atasnya adalah orang lain; 2. barang siapa dengan maksud yang sama menjual, menukarkan atau membebani dengan credietverband, sesuatu hak tanah yang belum bersertifikat yang telah dibehani credietverband atau sesuatu gedung bangunan. penanaman atau pembenihan di atas tanah yang juga telah dibebani demikian, tanpa mem beritahukan tentang adanya heban itu kepada pihak yang lain; 3. barang siapa dengan maksud yang sama mengadakan credietverband mengenai sesuatu hak tanah yang belum bersertifikat. dengan menyembunyikan kepada pihak lain bahwa tanah yanr bezhubungan dengan hak tadi sudah digadaikan; 4. barang siapa dengan maksud yang sama, menggadaikan atau menyewakan tanah dengan hak tanah yang belum bersertifikat padahal diketahui bahwa orang lain yang mempunyai atau turut mempunyai hak atas tanah itu: 5. barang siapa dengan maksud yang sama, menjual atau menukarkan tanah dengan hak tanah yang belum bersertifikat yang telah digadaikan, padahal tidak diberitahukannya kepada pihak yang lain bahwa tanah itu telah digadaikan; 6. barang siapa dengan maksud yang sama menjual atau menukarkan tanah dengan hak tanah yang belum bersertifikat untuk suatu masa, padahal diketahui, bahwa tanah itu telah disewakan kepada orang lain untuk masa itu juga."},{"l":"KUHP","p":"386","b":"Penggelapan","t":"(1) Barang siapa menjual, menawarkan atau menyerahkan barang makanan, minuman atau obat-obatan yang diketahuinya bahwa itu dipalsu, dan menyembunyikan hal itu, diancan dengan pidana penjara paling lama empat tahun. (2) Bahan makanan, minuman atau obat-obatan itu dipalsu jika nilainya atau faedahnya menjadi kurang karena sudab dicampur dengan sesuatu bahan lain."},{"l":"KUHP","p":"387","b":"Penggelapan","t":"(1) Diancam dengan pidana penjara paling lama tujuh tahun seorang pemborong atau ahli bangunan atau penjual bahan-bahan bangunan, yang pada waktu membuat bangunan atau pada waktu menyerahkan bahan-bahan bangunan, melakukan sesuatu perhuatan curang yang dapat membahayakan amanan orang atau barang, atau keselamatan negara dalam keadaan perang. (2) Diancam dengan pidana yang sama, barang siapa yang bertugas mengawasi pemhangunan atau penyerahan barang-barang itu, sengaja membiarkan perbuatan yang curang itu."},{"l":"KUHP","p":"388","b":"Penggelapan","t":"(1) Barang siapa pada waktu menyerahkan barang keperluan Angkatan Laut atau Angkatan Darat melakukan perbuat.an curang yang dapat membahayakan kesempatan negara dalam keadaan perang diancam dengan pidana penjara paling lama tujuh tahun. (2) Diancam dengan pidana yang sama, barang siapa yang bertugas mengawasi penyerahan barang-barang itu, dengan sengaja membiarkan perbuatan yang curang itu."},{"l":"KUHP","p":"389","b":"Penggelapan","t":"Barang siapa dengan maksud untuk menguntungkan diri sendiri atau orang lain secara melawan hukum, menghancurkan, memindahkan, membuang atau membikin tak dapat dipakai sesuatu yang digunakan untuk menentukan batas pekarangan, diancam dengan pidana penjara paling lama dua tahun delapan bulan."},{"l":"KUHP","p":"390","b":"Penggelapan","t":"Barang siapa dengan maksud untuk menguntungkan diri sendiri atau orang lain secara melawan hukum, dengan menyiarkan kabar bohong yang menyebabkan harga barang- barang dagangan, dana-dana atau surat-surat berharga menjadi turun atau naik diancam dengan pidana penjara paling lama dua tahun delapan"},{"l":"KUHP","p":"391","b":"Penggelapan","t":"Barang siapa menerima kewajiban untuk, atau memberi pertolongan pada penempatan surat hutang sesuatu negara atau bagiannya, atau sesuatu lembaga umum sero, atau surat hutang sesuatu perkumpulan, yayasan atau perseroan, mencoba menggerakkan khalayak umum untuk pendaftaran atau penyertaannya, dengan sengaja menyembunyikan atau mengurangkan keadaan yang sebenarnya atau dengan membayang-bayangkan keadaan yang palsu, diancam dengan pidana penjara paling lama empat tahun."},{"l":"KUHP","p":"392","b":"Penggelapan","t":"Seorang pengusaha, seorang pengurus atau komisaris persero terbatas, maskapai andil Indonesia atau koperasi, yang sengaja mengumumkan daftar atau neraca yang tidak benar, diancam dengan pidana penjara paling lama satu tahun empat bulan."},{"l":"KUHP","p":"393","b":"Penggelapan","t":"(1) Barang siapa memasukkan ke Indonesia tanpa tujuan jelas untuk mengeluarkan lagi dari Indonesia, menjual, menamarkan, menyerahkan, membagikan atau mempunyai persediaan untuk dijual atau dibagi-bagikan. barang-barang yang diketahui atau sepatutnya harus diduganya bahwa padabarangnya itu sendiri atau pada bungkusnya dipakaikan secara palsu, nama firma atau merek yang menjadi hak orang lain atau untui menyatakan asalnya barang, nama sehuah tempat tertentu, dengan ditambahkan nama atau firma yang khayal, ataupun pada barangnya sendiri atau pada bungkusnya ditirukan nama, firma atau merek yang demikian sekalipun dengan sedikit perubahan, diancam dengan pidana penjara paling lama empat bulan dua minggu atau pidana denda paling banyak sembilan ribu rupiah. (2) Jika pada waktu melakukan kejahatan helurn lewat lima tahun sejak adanya pemidanaan yang menjadi tetap karena kejahatan semacam itu juga dapat dijatuhkan pidana penjara paling lama sembilan bulan. Pasal 393 bis (1) Seorang pengacara yang sengaja memasukkan atau menyuruh masukkan dalam surat permohonan cerai atau pisah meja dan ranjang, atau dalam surat permohonan pailit, keterangan- keterangan tentang tempat tinggal atau kediaman tergugat atau penghutang, padahal diketahui atau sepatutnya harus diduganya bahwa keterangan- keterangan itu tertentangan dengan yang sebenarnya, diancam dengan pidana penjara paling lama satu tahun. (2) Diancam dengan pidana yang sama ialah si suami (istri) yang mengajukan gugatan atau si pemiutang yang memasukkan permintaan pailit, yang sengaja memberi keterangan palsu kepada pengacara yang dimaksudkan dalam ayat pertama."},{"l":"KUHP","p":"394","b":"Penggelapan","t":"Ketentuan pasal 367 berlaku hagi kejahatan-kejahatan yang dirumuskan dalam bab ini kecuali yang dirumuskan dalam ayat kedua pasal 393 bis, sepanjang kejahatan dilakukan mengenai keterangan untuk mohon cerai atau pisah meja dan ranjang"},{"l":"KUHP","p":"395","b":"Penggelapan","t":"(1) Dalam hal pemidanaan berdasarkan salah satu kejahatan yang dirumuskan dalam bab ini, hakim dapat memerintahkan pengumuman putusannya dan yang bersalah dapat dicabut haknya untuk menjalankan pencarian ketika kejahatan di lakukan. (2) Dalam hal pemidanaan berdasarkan salah satu kejahatan yang dirumuskan dalam pasal 378 382, 385, 387, 388, 393 bis dapat dijatuhkan pencabutan hak-hak berdasarkan pasal No. 1 - 4."},{"l":"KUHP","p":"396","b":"Perbuatan Merugikan Pemiutang","t":"Seorang pengusaha yang dinyatakan dalam keadaan pailit atau yang diizinkan melepaskan budel oleh pengadilan, diancam karena merugikan pemiutang dengan pidana penjara paling lama satu tahun empat bulan: 1. jika pengeluarannya melewati batas; 2. jika yang bersangkutan dengan maksud untuk menangguhkan kepailitannya telah meminjam uang dengan syarat-syarat yang memberatkan sedang diketahuinya bahwa pinjaman itu tiada mencegah kepailitan; 3. jika dia tak dapat memperlihatkan dalam keadaan tak diubah buku- buku dan surat- surat untuk catatan menurut pasal 6 Kitab Undang- undang Hukum Dagang dan tulisan- tulisan yang harus disimpannya menurut pasal itu."},{"l":"KUHP","p":"397","b":"Perbuatan Merugikan Pemiutang","t":"Seorang pengusaha yang dinyatakan dalam keadaan pailit atau diizinkan melepaskan budel oleh pengadilan, diancam karena merugikan pemiutang secara curang jika yang bezsangkutan untuk mengurangi hak pemiutang secara curang: 1. membikin pengeluaran yang tak ada, maupun tidak membukukan pendapatan, atau menarik barang sesuatu dari budel; 2. telah melijerkan (uervreemden) barang sesuatu dengan cuma-cuma atau jelas di bawah harganya; 3. dengan suatu cara menguntungkan salah seorang pemiutang diwaktu pailitnya atau pada saat di mana diketahui hahwa keadaan tersebut tak dapat dicegah; 4. tidak memenuhi kewajiban untuk mengadakan pencatatan menurut pasal 6 ayat pertama Kitah Undang-undang Hukum Dagang atau untuk menyimpan dan memperlihatkan buku-buku, surat-surat, dan tulisan- tulisan yang dimaksud dalam ayat ketiga pasal tersebut."},{"l":"KUHP","p":"398","b":"Perbuatan Merugikan Pemiutang","t":"Seorang pengurus atau komisaris perseroan terbatas, maskapai andil Indonesia atau perkumpulan koperasi yang dinyatakan dalam keadaan pailit atau yang diperintahkan penyelesaian oleh pengadilan, diancam dengan pidana penjara paling lama satu tahun empat bulan: 1. jika yang bersangkutan turut membantu atau mengizinkan untuk melakukan perbuatan- perbuatan yang bertentangan dengan anggaran dasar, sehingga oleh karena itu seluruh atau sebagian besar dari kerugian diderita oleh perseroan, maskapai atau perkumpulan, 2. jika yang bersangkutan dengan maksud untuk menangguhkan kepailitan atau penyelesaian perseroan, maskapai atau perkumpulan. turut membantu atau mengizinkan peminjaman uang dengan syarat- syarat yang memberatkan, padahal diketahuinya tak dapat dicegah keadaan pailit atau penyelesaiannya; 3. jika yang bersangkutan dapat dipersalahkan tidak memenuhi kewajiban yang diterangkan dalam pasal 6 ayat pertama Kitab Unclang- undang Hukum Dagang dan pasal 27 ayat pertama ordonansi tentang maskapai andil Indonesia, atau bahiva buku- buku dan surat-surat yang memuat catatan-catatan dan tulisan-tulisan yang disimpan menurut pasal tadi, tidak dapat di perlihatkan dalam keadaan tak diubah."},{"l":"KUHP","p":"399","b":"Perbuatan Merugikan Pemiutang","t":"Seorang pengurus atau komisaris perseroan terbatas, maskapai andil Indonesia atau perkumpulan koperasi yang dinyatakan dalam keadaan pailit atau yang penyelesaiannya diperintahkan oleh pengadilan, diancam dengan pidana penjara paling lama tujuh tahun jika yang hersangkutan mengurangi secara curanp hak-hak pemiutang dari perseroan maskapai atau perkumpulai untuk: 1. membikin pengeluaran yang tak ada, maupun tidak membuku kan pendapatan atau menarik barang sesuatu dari budel; 2. telah melijerkan (uerureemden) barang sesuatu dengan cuma cuma atau jelas di bawah harganya; 3. dengan sesuatu cara menguntungkan salah seorang pemiutang di waktu kepailitan atau penyelesaian, ataupun pada saat di mana diketahuinya bahwa kepailitan atau penyelesaian tadi tak dapat dicegah; 4. tidak memenuhi kewajiban mengadakan catatan menurut Kitat Undang-undang Hukum Dagang atau pasal 27 ayat pertama ordonansi tentang maskapai andil Indonesia, dan tentang menyimpan dan memperlihatkan buku-buku, surat-surat dan tulisan-tulisan menurut pasal- pasal itu."},{"l":"KUHP","p":"400","b":"Perbuatan Merugikan Pemiutang","t":"Diancam dengan pidana penjara paling lama lima tahun enan bulan, barang siapa yang mengurangi dengan penipuan hak-hak pemiutang: 1. dalam hal pelepasan budel, kepailitan atau penyelesaian atau pada waktu diketahui akan terjadi salah satu di antaranya dan kemudian sungguh disusul dengan pelepasan budel. kepailitan atau penyelesaian menarik barang sesuatu dari budel atau menerima pembayaran baik dari hutang yang tak dapat di tagih maupun yang dapat ditagih, dalam hal terakhir dengan diketahuinya bahwa kepailitan atau penyelesaian penghutang sudah dimohonkan, atau akibat rundingan dengan penghutang; 2. di waktu verifikasi piutang-piutang dalam hal pelepasan budel, kepailitan atau penyelesaian. mengaku adanya piutang yang tak ada atau memperbesar jumlah piutang yang ada."},{"l":"KUHP","p":"401","b":"Perbuatan Merugikan Pemiutang","t":"(1) Seorang pemiutang yang menyetujui tawaran persetujuan di muka pengadilan karena telah ada persetujuan dengan penglautang maupun pihal ketiga di mana yang bersangkutan minta keuntungan istimewa, diancam dengm pidana penjara paling lama satu tahun empat bulan, jika persetujuan itu diterima. (2) Diancam dengan pidana yang sama pada penghutang dalam hal seperti di atas, atau jika penghutang adalah perseroan, maskapai, perkumpulan atau yayasan, pada pengurus atau komisaris yang mengadakan persetujuan."},{"l":"KUHP","p":"402","b":"Perbuatan Merugikan Pemiutang","t":"Barang siapa dinyatakan dalam keadaan jelas tak mampu atau jika bukan pengusaha, dinyatakan dalam keadaan pailit atau dibolehkan melepaskan budel, diancam dengan pidana penjara pa!ing lama lima tahun enam bulan. jika yang bersangkutan secara curang mengurangi hak-hak pemiutang dengan mengada-ada pengeluaran yang tak ada, maupun menyembunyikan pendapatan, atau menarik barang sesuatu dari budel ataupun telah melijerkan barang sesuatu dengan cuma-cuma atau terang di bawah harganya, atau di waktu ketidakmampuannya, pelepasan budelnya atau kepailitannya. atau pada saat di mana diketahuinya bahwa salah satu dari keadaan tadi tak dapat dicegah, menguntungkan salah seorang pemiutang dengan sesuatu cara."},{"l":"KUHP","p":"403","b":"Perbuatan Merugikan Pemiutang","t":"Seorang pengurus atau komisaris perseroan terbatas. maskapai andil Indonesia atau perkumpulan koperasi di luar ketentuan pasal 398, turut membantu atau mengizinkan dilakukan perbuatan yang bertentangan dengan anggaran dasar, dan oleh karena itu mengakibatkan perseroan, maskapai atau perkumpulan tak dapat memenuhi kewajibannya, atau harus dibubarkan, diancam dengan pidana denda paling banyak seratus lima puluh ribu rupiah."},{"l":"KUHP","p":"404","b":"Perbuatan Merugikan Pemiutang","t":"Diancam dengan pidana penjara paling lama dua tahun. 1. barang siapa dengan sengaja menarik barang milik sendiri, atau kalau bukan demikian untuk pemiliknya dari orang lain yang mempunyai hak gadai, hak menahan, pungut hasil atau pakai atasnya; 2. barang siapa dengan sengaja untuk seluruhnya atau sebagian, menarik barang milik sendiri atau kalau bukan demikian untuk pemiliknya dari ikatan hipotik 3. barang siapa dengan sengaja, untuk seluruhnya atau sebagian, menarik suatu barang yang olehnya dibebani ikatan panen atau untuk yang memheri ikatan menarik suatu barang yang oleh oruig lain itu dibehani ikatan panen. dengan merugikan pemengang ikatan; 4 barang siapa dengan sengaja, untuk seluruhnya atau sebagian, menarik suatu barang milik sendiri atau kalau tiukan demikian, untuk pemiliknya. dari ikatan kredit atasnya, dengan merugi kan pemegang ikatan."},{"l":"KUHP","p":"405","b":"Perbuatan Merugikan Pemiutang","t":"(1) Dalam hal pemidanaan berkasarkan salah satu kejahatan yang dirumuskan dalam pasal 397, 399 400, dan 402 yang bersalah dapat dicabut hak-haknya berdasarkan pasal 35. (2) Pemidanaan berlasarkan salah satu kejahatan seperti yang dirumuskan. dalam pasal 396 - 402, dapat diperintahkan supaya putus hakim diumumkan."},{"l":"KUHP","p":"413","b":"Kejahatan Jabatan","t":"Seorang komandan Angkatan Bersenjata yang menolak atau sengaia mengabaikan untuk menggunakan kekuntan di bawah perintahnya, ketika diminta oleh penguasa sipil yang berwenang menurut undang-undang, diancam dengan pidana penjara lama empat tahun."},{"l":"KUHP","p":"414","b":"Kejahatan Jabatan","t":"(1) Seorang pejabat yang sengaja minta bantuan Angkatan Bersenjata untuk melawan pelaksanaan ketentuan undang-undang, perintah penguasa umum menurut udang- undang, putusan atau surat perintah pengadilan, diancam dengan pidana penjara paling lama tujuh tahun. (2) Jika pelaksanaan dihalang-halangi oleh perbuatan demikian, yang bersalah diancam dengan pidana penjara paling lama sembilan tahun."},{"l":"KUHP","p":"415","b":"Kejahatan Jabatan","t":"Seorang pejabat atau orang lain yang ditugaskan menjalankan suatu jabatan umum terus- menerus atau untuk sementara waktu, Wang dengan sengaja menggelapkan uang atau surat berharga yang disimpan karena jabaimnya, atau membiarkan uang atau surat berharga ihu diambil atau digelapkan oleh orang lain, atau menolong sebagai pembantu dalam melakukan perbuatan tersebut, diancam dengan pidana penjsra paling 1ama tujuh tahun."},{"l":"KUHP","p":"416","b":"Kejahatan Jabatan","t":"Seorang pejabat atau orang lain yang diheri tugas menjalankan suatu jabatan umum terus- menerus atau untuk sementara waktu, yang sengaja membuat secara palsu atau memalsu buku buku-buku daftar-daftar yang khusus untuk pemeriksaan administrasi, diancam dengan pidana penjara paling lama empat tahun."},{"l":"KUHP","p":"417","b":"Kejahatan Jabatan","t":"Seorang pejabat atau orang lain yang diberi tugas menjalankan suatu jabatan umum terus- menerus atau untuk sementara waktu yang sengaja menggelapkan, menghancurkan. merusakkan atau membikin tak dapat dipakai barang-barang yang diperuntukkan guna meyakinkan atau membuktikan di muka penguasa yang berwenang, akta-akta, surat-surat atau daftar-daftar yang dikuasai nya karena jabatannya, atau memhiarkan orang lain menghilangkan, menghancurkan, merusakkan atau memhikin tak dapat di pakai barang- barang itu, atau menolong sebagai pembantu dalam melakukan perbuatan itu, diancam dengan pidana penjara paling lama lima tahun enam bulan."},{"l":"KUHP","p":"418","b":"Kejahatan Jabatan","t":"Seorang pejabat yang menerima hadiah atau janji padahal diketahui atau sepatutnya harus diduganya., hahwa hadiah atau janji itu diberikan karena kekuasaan atau kewenangan yang berhubungan dengan jabatannya, atau yang menurut pikiran orang yang memberi hadiah atau janji itu ada hubungan dengan jabatannya diancam dengan pidana penjara paling lama enam tahun atau pidana denda paling banyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"419","b":"Kejahatan Jabatan","t":"Diancam dengan pidana penjara paling lama lima tahun seorang pejabat: l. yang menerima hadiah atau janji padahal diketahuinya bahwa hadiah atau janji itu diberikan untuk menggerakkannya supaya melakukan atau tidak melakukan sesuatu dalam jabatannya yang bertentangan dengan kewajibannya; 2. yang menerinia hadiah mengetahui bahwa hadiah itu diberikan sebagai akibat. atau oleh karena si penerima telah melakukan atau tidak melakukan sesuatu dalam jabatannya yang bertentangan dengan kewajibannya."},{"l":"KUHP","p":"420","b":"Kejahatan Jabatan","t":"(1) Diancam dengan pidana penjara paling lama sembilan tahun: 1. seorang hakim yang menerima hadiah atau janji. padahal diketahui bahwa hadiah atau janji itu diberikan untuk mempengaruhi putusan perkara yang menjadi tugasnya; 2. barang siapa menurut ket.entuan undang-undang ditunjuk menjadi penasihat untuk menghadiri sidang pengadilan, menerima hadiah atau janji, padahal diketahui bahwa hadiah atau janji itu diberikan untuk mempengaruhi nasihat tentang perkara yang harus diputus oleh pengadilan itu. (2) Jika hadiah atau janji itu diterima dengan sadar bahwa hadiah atau janji itu diberikan supaya dipidana dalam suatu perkara pidana, maka yang bersalah diancam dengan pidana penjara paling lama dua belas tahun."},{"l":"KUHP","p":"421","b":"Kejahatan Jabatan","t":"Seorang pejabat yang menyalahgunakan kekuasaan memaksa seseorang untuk melakukan, tidak melakukan atau membiarkan sesuatu, diancam dengan pidana penjara paling lama dua tahun delapan bulan."},{"l":"KUHP","p":"422","b":"Kejahatan Jabatan","t":"Seorang pejabat yang dalam suatu perkara pidana menggunakan barana paksaan, baik untuk memeras pengakuan, maupun untuk mendapatkan keterangan, diancam dengan pidana penjara paling lama empat tahun."},{"l":"KUHP","p":"423","b":"Kejahatan Jabatan","t":"Seorang pejabat dengan maksud menguntungkan diri sendiri atau orang lain secara melawan hukum, dengan menyalahgunakan kekuasaannya, memaksa seseorang untuk memberikan sesuatu, untuk membayar atau menerima pembayaran dengan potongan, atau untuk mengerjakan sesuatu bagi dirinya sendiri, diancam dengan pidana penjara paling lama enam tahun."},{"l":"KUHP","p":"424","b":"Kejahatan Jabatan","t":"Seorang pejabat dengan maksud menguntungkan diri sendiri atau orang lain secara melawan hukum, dengan menyalahgunakan kekuasaannya, menggunakan tanah negara di atas mana ada hak hak pakai Indonesia, diancam dengan pidana penjara paling lama enam tahun."},{"l":"KUHP","p":"425","b":"Kejahatan Jabatan","t":"Diancam karena melakukan pemerasan dengan pidana penjara paling lama tujuh tahun: 1. seorang pejabat yang pada waktu menjalankan tugas, meminta, menerima, atau memotong pembayaran, seolah-olah berhutang kepadanya, kepada pejabat lainnya atau kepada kas umum, padahal diketahuinya bahwa tidak demikian adanya; 2. seorang pejabat yang pada waktu menjalankan tugas, meminta atau menerima pekerjaan orang atau penyerahan barang seolah olah merupakan hutang kepada dirinya, padahal diketahuinya bahwa tidak demikian halnya; 3. seorang pejabat yang pada waktu menjalankan tugas, seolaholah sesuai dengan aturan- aturan yang bersangkutan telah menggunakan tanah negara yang di atasnya ada hak-hak pakai Indonesia dengan merugikan yang berhak padahal diketahui nya bahwa itu bertentangan dengan peraturan tersebut."},{"l":"KUHP","p":"426","b":"Kejahatan Jabatan","t":"(1) Seorang pejabat yang diberi tugas menjaga orang yang dirampas kemerdekaannya atas perintah penguasa umum atau atas putusan atau ketetapan pengadilan, dengan sengaja membiarkan orang itu melarikan diri atau dengan sengaja melepaskannya, atau memberi pertolongan pada waktu dilepas atau melepaskan diri., diancam dengan pidana penjara paling lama empat tahun. (2) Jika orang itu lari, dilepaskan, atau melepaskan diri karena kesalahan (kealpaan), maka yang bersangkutan diancam dengan pidana kurungan paling lama dua bulan atau pidana denda paling banyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"427","b":"Kejahatan Jabatan","t":"(1) Diancam dengan pidana penjara paling lama empat tahun: 1. seorang pejabat dengan tugas menyidik perbuatan pidana, yang sengaja tidak memenuhi permintaan untuk menyatakan bahwa ada orang dirampas kemerdekaannya secara melawan hukum, atau yang sengaja tidak memberitahukan hal itu kepada kekuasaan yang lebih tinggi; 2. seorang pejabat yang dalam menjalankan tugasnya mengetahui bahwa ada orangdirampas kemerdekaannya secara melawan hukum, sengaja tidak memberitahukan hal itu dengan sepera kepada pejabat yang bertugas menyidik perbuatan pidana. (2) Seorang pejahat yang bersalah (alpa) menyebabkan apa yang dirumuskan dalam pasal ini terlaksana, diancam dengan pidana kurungan paling lama tiga bulan atau pidana denda paling banyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"428","b":"Kejahatan Jabatan","t":"Diancam dengan pidana penjara paling lama satu tahun empat bulan, seorang kepala lembaga pemasyarakatan tempat menutup orang terpidana, orang tahanan sementara atau orang yang disandera, atau seorang kepala lembaga pendidikan negara atau rumah sakit jiwa, yang menolak memenuhi permintaan menurut udang-undang supaya memperlihatkan orang yang dimasukkan di situ, atau supaya memperlihatkan register masuk, atau akta- akta yang menuzut aturan-aturan umum harus ada untuk memasukkan orang di situ."},{"l":"KUHP","p":"429","b":"Kejahatan Jabatan","t":"(1) Seorang pejabat yang melampaui kekuasaan atau tanpa mengindahkan cara-cara yang ditentukan dalam peraturan umum, memaksa masuk ke dalam rumah atau ruangan atau pekarangan terututup yang dipakai oleh orang lain, atau jika berada di situ secara melawan hukum, tidak segera pergi atas permintaan yang berhak atau atas nama orang itu, diancam dengan pidana penjara paling lama satu tahun empat bulan atau pidana denda paling tinggi empat ribu lima ratus rupiah. (2) Diancam dengan pidana yang sama, seorang pejabat yang pada waktu menggeledah rumah, dengan melampaui ke kuasaannya atau tanpa mengindahkan cara-cara yang ditentukan dalam peraturan umum, memeriksa atau merampas surat surat, buku-buku atau kertas-kertas lain."},{"l":"KUHP","p":"430","b":"Kejahatan Jabatan","t":"(1) Seorang pejabat yang melampaui kekuasaannya, menyuruh memperlihatkan kepadanya atau merampas surat, kartu pos, barang atau paket yang diserahkan kepada lembaga pengangkutan umum atau kabar kawat yang dalam tangan pejabat telegrap untuk keperluan umum, diancam dengan pidana penjara paling lama dua tahun delapan bulan. (2) Pidana yang sama dijatuhkan kepada pejabat yang melampaui kekuasaannya, menyuruh seorang pejabat telepon atau orang lain yang diberi tugas pekerjaan telepon untuk keperluan umum, memberi keterangan kepadanya tentang sesuatu percakapan yang dilakukan denggan perantaraaan lembaga itu."},{"l":"KUHP","p":"431","b":"Kejahatan Jabatan","t":"Seorang pejabat, suatu lembaga pengangkutan umum yang sengaja dan melaivan hukum membuka suatu surat barang tertutup atau paket yang diserahkan kepada lembaga itu. memeriksa isinya, atau memberitahukan isinya kepada orang lain, diancam dengan pidana penjara paling lama dua tahun."},{"l":"KUHP","p":"432","b":"Kejahatan Jabatan","t":"(1) Seorang pejahat suatu lembaga pengangkutan umum yang dengan sengaja memberikan kepada orang lain daripada yang berhak, surat tertutup, kartu pos atau paket yang dipercayakan kepada lembaga itu, atau menghancurkan, menghilangkan, memiliki sendiri atau mengubah isinya, atau memiliki sendiri barang sesuatu yang ada di dalamnya diancam dengan pidana penjara paling lama lima tahun. (2) Jika surat atau barang itu bernilai uang, maka pemilikan sendiri itu diancam dengan pidana penjara paling lama tujuh tahun."},{"l":"KUHP","p":"433","b":"Kejahatan Jabatan","t":"Seorang pejabat telegrap atau telepon, atau orang lain yang ditugasi mengaxvasi pekerjaan telegrap atau telepon yang digunakan untuk kepentingan umum, diancam: 1. dengan pidana penjara paling lama dua tahun. jika ia dengan sengaja dan melawan hukum memberitahukan kepada orang lain, kabar yang diserahkan kepada jawatan telegrap atau telepon atau kepada lembaga semacam itu, atau dengan sengaja dan melawan hukum membuka, membaca, atau memberitahukan kabar telegrap atau telepon kepada orang lain; 2. dengan pidana penjara paling lama lima tahun, jika ia dengan sengaja memberikan kepada orang lain daripada yang berhak atau. menghancurkan, menghilangkan, memiliki sendiri atau mengubah isi suatu berita telegrap atau telepon yang diserahkan kepada jawatan telegrap, telepon atau pada lembaga semacam itu."},{"l":"KUHP","p":"434","b":"Kejahatan Jabatan","t":"Seorang pejabat suatu lembaga pengangkutan umum, seorang pejabat telegrap atau telepon atau orang lain yang dimaksud dalam pasal 433, yang dengan sengaja membiarkan orang lain melakukan salah satu perbuatan berdasarkan pasal 431 - 433, atau membantu orang lain dalam perbuatan itu, diancam dengan pidana menurut perbedaan- perbedaan yang ditetapkan dalam pasal-pasal tersebut."},{"l":"KUHP","p":"435","b":"Kejahatan Jabatan","t":"Seorang pejabat yang dengan langsung maupun tidak langsung sengaja turut serta dalam pemborongan, penyerahan atau persewaan, yang pada saat dilakukan perbuatan, untuk seluruh atau sebagian, dia ditugaskan mengurus atau mengawasinya, diancam dengan pidana penjara paling lama sembilan bulan atau pidana denda paling banyak delapan belas ribu rupiah."},{"l":"KUHP","p":"436","b":"Kejahatan Jabatan","t":"(1) Barang siapa menurut hukum yang berlaku bagi masing- masing pihak mempunyai kewenangan melangsungkan perkawinan seseorang, padahal diketahuinya bahwa perkawinan atau perkawinan-perkawinan orang itu yang telah ada men jadi halangan untuk ltu berdasarkan undang-undang, diancam dengan pidana penjara paling lama tujuh tahun. (2) Barang siapa menurut hukum yang berlaku bagi masing-masing pihak mempunyai kewenangan melangsungkan perkawinan seseorang, padahal diketahuinya ada halangan untuk itu berdasarkan undang-undang diancam dengan pidana penjara paling lama dua tahun delapan bulan atau pidana denda paling banyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"437","b":"Kejahatan Jabatan","t":"Dalam hal pemidanaan berdasarkan pasal 415 419, 420 423 434, 425, 432 ayat penghabisan, dan pasal 436 ayat pertama. dapat dijatuhkan pencabutan hak berdasarkan pasal 35. No.3 dan 4."},{"l":"KUHP","p":"438","b":"Kejahatan Pelayaran","t":"(1) Diancam karena melakukan pembajakan di laut: 1. dengan pidana penjara paling lama lima belas tahun, barang siapa masuk bekerja menjadi nahkoda atau menjalankan pekerjaan itu di sebuah kapal, padahal diketahuinya bahwa kapal itu diperuntukkan atau digunakan untuk melakukan perbuatan-perbuatan kekerasan di lautan bebas terhadap kapal lain atau terhadap orang dan barang di atasnya, tanpa mendapat kuasa untuk itu dari sebuah negara yang berperang atau tanpa masuk angkatan laut suatu negara yang diakui; 2. dengan pidana penjara paling lama dua belas tahun, barang siapa mengetahui tentang tujuan atau penggunaan kapal itu, masuk bekerja menjadi kelasi kapal tersebut atau dengan suka rela terus menjalankan pekerjaan tersebut setelab hal itu diketahui olehnya, ataupun termasuk anak buah kapal tersebut. (2) Disamakan dengan tidak punya surat kuasa, jika melampaui apa yang dikuasakan, demikian juga jika memegang surat kuasa dari negara-negara yang berperang satu dengan yang lainnya. (3) Pasal 89 tidak diterapkan."},{"l":"KUHP","p":"439","b":"Kejahatan Pelayaran","t":"(1) Diancam karena melakukan pembajakan di tepi laut dengan pidana penjara paling lama lima belas tahun, barang siapa dengan memakai kapal melakukan perbuatan kekerasan terhadap kapal lain atau terhadap orang atau barang di atasnya, di perairan Indonesia. (2) Yang dimaksud dengan wilayah laut Indonesia yaitu wilayah \"Territoriale zee en maritieme kringen ordonantie, S. 1939 442.\""},{"l":"KUHP","p":"440","b":"Kejahatan Pelayaran","t":"Diancam karena melakukan pembajakan di pantai dengan pidana penjara paling lama lima belas tahun, barang siapa yang di darat maupun di air sekitar pantai atau muara sungai, melakukan perbuatan kekerasan terhadap orang atau barang di situ, setelah lebih dahulu menyeberangi lautan seluruhnya atau sebagiannya untuk tujuan tersebut."},{"l":"KUHP","p":"441","b":"Kejahatan Pelayaran","t":"Diancam karena melakukan pembajakan di sungai dengan pidana penjara paling lama lima belas tahun, barang siapa dengan memakai kapal melakukan perbuatan kekerasan di sungai terhadap kapal lain atau terhadap orang atau barang di atasnya, setelah datang ke tempat dan untuk tujuan tersebut dengan kapal dari tempat lain."},{"l":"KUHP","p":"442","b":"Kejahatan Pelayaran","t":"Diancam dengan pidana penjara paling lama lima belas tahun, barang siapa yang menerima atau melakukan pekerjaan sebagai komandan atau pemimpin sebuah kapal. padahal diketahuinya bahwa kapal itu diperuntukkan atau digunakan untuk melakukan salah satu perbuatan yang dirumuskan dalam pasal 439 - 441."},{"l":"KUHP","p":"443","b":"Kejahatan Pelayaran","t":"Diancam dengan pidana penjara paling lama sepuluh tahun barang siapa yang menerima atau melakukan pekerjaan sebagai kelasi di sebuah kapal, padahal diketahuinya bahwa kapal itu diperuntukkan atau digunakan untuk melakukan salah satu perbuatan yang dirumuskan dalam pasal 439 - 441 ataupun dengan sukarela tetap tinggal bekerja di kapal itu, sesudah diketahui olehnya bahwa kapal itu digunakan seperti diterangkan di atas."},{"l":"KUHP","p":"444","b":"Kejahatan Pelayaran","t":"Jika perbuatan kekerasan yang diterangkan dalam pasal 438 - 441 mengakibatkan seseorang di kapal yang diserang atau seseorang yang diserang itu mati maka nakoda. komandan atau pemimpin kapal dan mereka yang turut serta melakukan perbuatan kekerasan, diancam dengan pidana mati, pidana penjara seumur hidup, atau pidana penjara selama waktu tertentu paling lama dua puluh tahun."},{"l":"KUHP","p":"445","b":"Kejahatan Pelayaran","t":"Barang siapa melengkapi kapal atas biaya sendiri atau orang lain, dengan maksud untuk digunakan sebagai yang dirumuskan dalam pasal 438 atau dengan maksud untuk melakukan salah satu per- buatan yang dirumuskan dalam pasal 439 - 441, diancam dengan pidana penjara paling lama lima belas tahun."},{"l":"KUHP","p":"446","b":"Kejahatan Pelayaran","t":"Barang siapa atas biaya sendiri atau orang lain, secara langsung maupun tidak langsung turut melaksanakan penyewaan, pemuatan atau pertanggungan sebuah kapal, padahal diketahuinya bahwa kapal itu akan digunakan sebagai yang dirumuskan dalam pasal 438, 38, atau untuk melakukan salah satu perbuatan yang dirumuskan dalam pasal 439 - 441, diancam dengan pidana penjara paling lama dua belas tahun dalam"},{"l":"KUHP","p":"447","b":"Kejahatan Pelayaran","t":"Barang siapa dengan sengaja menyerahkan sebuah kapal Indonesia dalam kekuasaan bajak laut, bajak tepi laut, bajak pantai, dan bajak sungai, diancam: 1. dengan pidana penjara paling lama lima belas tahun. jika ia adalah nakoda kapal itu; 2. dengan pidana penjara paling lama dua belas tahun, dalam hal-hal lain."},{"l":"KUHP","p":"448","b":"Kejahatan Pelayaran","t":"Seorang penumpang kapal Indonesia yang merampas kekuasaav atas kapal secara melawan hukum, diancam dengan pidana penjara paling lama tujuh tahun."},{"l":"KUHP","p":"449","b":"Kejahatan Pelayaran","t":"Seorang nakoda sebuah hapal Indonesia yang menarik kapal dari pemiliknya atau dari pengusahanya dan memakainya untul keuntungan sendiri, diancam dengan pidana penjara paling lama delapan tahun enam bulan."},{"l":"KUHP","p":"450","b":"Kejahatan Pelayaran","t":"Seorang warga negara Indonesia yang tanpa izin Pemerintah Indonesia menerima surat, bajak, maupun menerima atau men jalankan pekerjaan sebagai nakoda sebuah kapal, padahal diketahui bahwa kapal itu diperuntukkan atau digunakan untuk pelayaran pembajakan tanpa izin Pemerintah Indonesia, diancam dengan pidana penjara paling lima tahun."},{"l":"KUHP","p":"451","b":"Kejahatan Pelayaran","t":"Seorang warga negara Indonesia yang menerima pekerjaan sebagai kelasi di sebuah kapal. padahal diketahuinya bahwa kapal itu diperuntukkan atau digunakan untuk pelayaran pembajakan tanpa izin Pemerintah Indonesia, ataupun secara suka rela tetap bekerja sebagai kelasi sesudah diketahuinya tujuan atau pengguaan kapal itu, diancam dengan pidana penjara paling lama empat tahun. Pasal 451 bis (1) Seorang nakoda sebuah kapal Indonesia yang menyuruh membikin keterangan kapal, yang diketahuinya bahwa isinya bertentangan dengan kenyataan. diancam dengan pidana penjara paling lama lima tahun. (2) Kelasi-kelasi yang turut serta menyuruh membikin keterangan kapal yang diketahuinya bahwa isinya tidak benar, diancam dengan piclana penjara paling lama dua tahun delapan bulan. Pasal 451 ter Barang siapa untuk memenuhi peraturan dalam ayat ketiga pasal 12 aturan tentang pendaftaran kapal, memperlihatkan surat keterangan yang diketahuinya bahwa isinya tidak benar, diancam dengan pidana penjara paling lama lima tahun."},{"l":"KUHP","p":"452","b":"Kejahatan Pelayaran","t":"(1) Barang siapa dalam berita acara suatu keterangan kapa1, menyuruh menulis keterangun palsu tentang suatu keudann yang kebenarannya harus dinyatakan dalam akta itu dengan maksud untuk menggunakan atau menyuruh orang lain menggunakan akta itu, seolah-olah keterangannya sesuai dengan kenyataan, dianeam, jiks karena penggunaan aktu itu dapat menimbulkan kerugian dengan pidana penjara paling lama delapan tahun. (2) Diancam dengan pidana yang sama, barang siapa dengan sengaja menggunakan akta itu seolah-olah isinya sesuai dengan kenyataan, jika karena penggunaan itu dapat timbul kerugian."},{"l":"KUHP","p":"453","b":"Kejahatan Pelayaran","t":"Diancam dengan pidana penjara paling lama dua tahun delapan bulan, seorang nakoda kapal Indonesia yang sesudah dimulai penerimaan atau penyewaan kelasi. tetapi sebelum perjanjian habis dengan sengaja dan melawan hukum menarik diri dari pimpinan kapal itu."},{"l":"KUHP","p":"454","b":"Kejahatan Pelayaran","t":"Diancam, karena melakukan desersi, dengan pidana penjara paling lama satu tahun empat bulan, seorang kelasi yang, bertentangan dengan kewajibannya menurut persetujuan kerja, menarik diri dari tugasnya di kapal Indonesia, jika menurut keadaan di waktu melakukan perbuatan, ada kekhawatiran timbul bahaya bagi kapal, penumpang atau muatan kapal itu."},{"l":"KUHP","p":"455","b":"Kejahatan Pelayaran","t":"Diancam karena melakukan desersi biasa, dengan pidana pen jara paling lama empat bulan dua minggu, seorang anak buah kapal kapal Indonesia, yang dengan sengaja dan melawan hukun tidak mengikuti atau tidak meneruskan perjalanan yang telah di setujuinya."},{"l":"KUHP","p":"456","b":"Kejahatan Pelayaran","t":"Ditiadakan berdasarkan S. 34 - 124 jo. 38 - 2."},{"l":"KUHP","p":"457","b":"Kejahatan Pelayaran","t":"Pidana yang ditentukan dalam pasal 454 dan 455 dapat dilipatkan dua, jika dua orang atau lebih dengan bersekutu melakukan kejahatan itu, atau jika kejahatan dilakukan akibat permufakatan jahat untuk berbuat demikian."},{"l":"KUHP","p":"458","b":"Kejahatan Pelayaran","t":"(1) Seorang pengusaha, pemegang buku, atau nakoda kapal Indonesia yang menerima seorang anak buah kapal untuk bekerja, padahal mengetahui bahwa anak buah kapal itu belum ada sebulan sejak menarik diri dari persetujuannya dengan kapal Indonesia seperti dirumuskan di dalam salah satu pasal 454 atau 455, diancam dengan pidana penjara paling lama empat bulan dua minggu atau pidana denda paling banyak empat ribu lima ratus rupiah. (2) Tidak dipidana, jika penerimaan kerja dilakukan di luar Indonesia dengan izin konsul Indonesia. atau kalau ini tidak ada, atas permintaan penguasa setempat."},{"l":"KUHP","p":"459","b":"Kejahatan Pelayaran","t":"(1) Seorang penumpang kapal Indonesia yang di atas kapal menyerang nakoda, melawannya dengan kekerasan atau ancaman kekerasan, dengan sengaja merampas kebebasannya untuk bergerak atau seorang anak buah kapal Indonesia yang di atas kapal dalam pekerjaan berbuat demikian terhadap orang yang lebih tinggi pangkatnya, diancam karena melakukan insubordinasi dengan pidana penjara paling lama dua tahun delapan bulan. (2) Yang bersalah diancam dengan: 1. pidana penjara paling lama empat tahun, jika kejahatan itu atau perbuatan-perbuatan lain yang menyertainya mengakibatkan luka-luka; 2. pidana penjara paling lama delapan tahun enam bulan jika mengakibatkan luka-luka berat; 3. pidana penjara paling lama dua belas tahun, jika mengakibatkan kematian."},{"l":"KUHP","p":"460","b":"Kejahatan Pelayaran","t":"(1) Insubordinasi yang dilakukan dua orang atau lebih dengan bersekutu, diancam karena melakukan pemberontakan di kapal dengan pidana penjara paling lama tujuh tahun. (2) Yang hersalah diancam dengan 1. pidana penjara paling lama delapan tahun enam bulan jika kejahatan itu atau perbuatan-perbuatan lain yang menyertainya mengakibatkan luka-luka; 2. pidana penjara paling lama dua belas tahun, jika mengakibatkan luka- luka berat; 3. pidana penjara paling lama lima belas tahun jika mengakihatkan kematian."},{"l":"KUHP","p":"461","b":"Kejahatan Pelayaran","t":"Barang siapa di atas kapal Indonesia menghasut supaya mem berontak, diancam dengan pidana penjara paling lama enam tahun"},{"l":"KUHP","p":"462","b":"Kejahatan Pelayaran","t":"Penolakan kerja oleh dua orang anak buah kapal Indonesia atau lebih yang dilakukan bersekutu atau akibat permufakatan jahat diancam dengan pidana penjara paling lama dua tahun delapan bulan."},{"l":"KUHP","p":"463","b":"Kejahatan Pelayaran","t":"Diancam dengan pidana penjara paling lama sembilan bulan. seorang anak buah kapal Indonesia yang sesudah dikenakan tiv dakan disiplin karena menolak kerja, masih tetap menolak kerja juga."},{"l":"KUHP","p":"464","b":"Kejahatan Pelayaran","t":"(1) Diancam dengan pidana penjara paling lama sembilan bulan atau denda paling banyak empat ribu lima ratus rupial seorang penumpang kapal Indonesia; 1. yang sengaja tidak menurut perintah nakoda yang diberikan untuk keamanan atau untuk meneguhkan ketertiban dan disiplin di atas kapal; 2. yang tidak memberi pertolongan menurut kemampuannya kepada nakoda, ketika diketahuinya bahwa dia dirampas kemerdekaanya untuk bergerak; 3. yang sengaja tidak memberitahukan kepada nakoda ketika diketahuinya adanya niat untuk melakukan insubordinasi. (2) Ketentuan tersebut pada no. 3 tidak berlaku jika insuhordinasi tidak terjadi."},{"l":"KUHP","p":"465","b":"Kejahatan Pelayaran","t":"Pidana yang diancam pada pasal 448 451 454 464 dapat ditambah sepertiga, jika yang melakukan salah satu kejahatan yang dirumuskan dalam pasal itu, berpangkat perwira kapal ."},{"l":"KUHP","p":"466","b":"Kejahatan Pelayaran","t":"Seorang nakoda kapal Indonesia yang dengan maksud menguntungkan diri sendiri atau orang lain dengan melawan hukum atau untuk menutupi perbuatan itu menjual kapalnya, atau meminjam uang dengan mempertanggungkan kapalnya atau perlengkapan kapal itu atau perbekalannya, atau menjual atau menggadaikan kapal itu barang muatan atau barang perbekalan kapal itu, atau mengurangi kerugian atau belanja, atau tidak menjaga supaya buku-buku harian harian di kapal dipelihara menurut undang-undang, ataupun tidak mengurus keselamatan surat-surat kapal ketika meninggalkan kapalnya, diancam dengan pidana penjara paling lama tujuh"},{"l":"KUHP","p":"467","b":"Kejahatan Pelayaran","t":"Seorang nakoda kapal Indonesia, yang dengan maksud untuk menguntungkan diri sendiri atau orang lain secara melawan hukum, atau untuk menutupi keuntungan yang demikian, mengubah haluan kapalnya, diancam dengan pidana penjara paling lama empat tahun."},{"l":"KUHP","p":"468","b":"Kejahatan Pelayaran","t":"Seorang nakoda kapal Indonesia yang di luar keharusan atau bertentangan dengan hukum yang berlaku baginya, meninggalkan kapalnya di tengah perjalanan, dan juga menyuruh atau memberi izin kepada anak buahnya untuk berbuat demikian. diancam dengan pidana penjara paling lama lima tahun enam bulan."},{"l":"KUHP","p":"469","b":"Kejahatan Pelayaran","t":"(1) Seorang nakoda kapal Indonesia yang di luar keharusan dan di luar pengetahuan lebih dahulu dari pemilik atau peng usaha kapal, melakukan atau membiarkan dilakukan perbuatan yang diketahuinya bahwa karena itu kapalnya atau muatannya kemungkinan ditangkap ditahan atau dirintangi diancam dengan pidana penjara paling lama satu tahun empat bulan atau pidana denda sebanyak-banyaknya sembilan ribu rupiah. (2) Seorang penumpang kapal yang di luar keharusan dan di luar pengetahuan lebih dulu dari nakoda melakukan perbuatan yang sama dengan pengetahuan yang sama pula, dianeair dengan pidana penjara paling lama satu tahun atau pidana denda paling banyak sembilan ribu rupiah."},{"l":"KUHP","p":"470","b":"Kejahatan Pelayaran","t":"Seorang nakoda kapal Indonesia yang di luar keharusan sengaja tidak memberi kepada penumpang kapalnya apa yang wajib di berikan padanya. diancam dengan pidana penjara paling lama dua tahun delapan bulan atau pidana denda paling banyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"471","b":"Kejahatan Pelayaran","t":"Seorang nakoda kapal Indonesia yang sengaja membuang barang muatan di luar keharusan dan bertentangan dengan hukum yang berlaku baginya, diancam dengan pidana penjara paling lama dua tahun delapan bulan atau pidana denda paling banyak empat rihu lima ratus rupiah."},{"l":"KUHP","p":"472","b":"Kejahatan Pelayaran","t":"Barang siapa dengan sengaja dan melawan hukum, menghancurkan merusakkan, atau membikin tak dapat dipakai muatan, perbekalan atau barang keperluan yang ada dalam kapal, diancam dengan pidana penjara paling lama dua tahun delapan bulan. Pasal 472 bis Barang siapa sebagai penumpang gelap turut berlayar di atas sebuah kapal, diancam dengan pidana penjara paling tiga bulan."},{"l":"KUHP","p":"473","b":"Kejahatan Pelayaran","t":"Seorang nakoda yang memakai bendera Indonesia, padahal diketahuinya bahwa dia tidak berhak untuk itu, diancam dengan pidana penjara paling lama satu tahun empat bulan atau pidana denda paling banyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"474","b":"Kejahatan Pelayaran","t":"Seorang nakoda yang dengan niemakai tanda-tanda pada kapalnya sengaja menimbulkan kesan seakan-akan kapalnya adalah kapal perang Indonesia kapal Angkatan Laut atau kapal penunjuk yang bekerja di perairan atau terusan laut Indonesia, diancam dengan pidana penjara paling lama empat bulan dua minggu atau pidana denda paling banyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"475","b":"Kejahatan Pelayaran","t":"Baran siapa yang diluar keharusan melakukan pekerjaan nakoda, juru mudi atau masinis di kapal Indonesia padahal diketahuirsya bahwa kewenangannya untuk berlayar telah dicabut oleh penguasa yang berwenang, diancam dengan pidana penjara paling lama sembilan bulan atau pidana denda paling banyak sembilan ribu rupiah."},{"l":"KUHP","p":"476","b":"Kejahatan Pelayaran","t":"Seorang nakoda kapal Indonesia yang tanpa alasan yang dapat diterima menolak untuk memenuhi permintaan berdasarkan undang-undang untuk menerima di kapalnya seorang terdakwa atau terpidana beserta benda-benda yang berhubungan dengan perkaranya, diancam dengan pidana penjara paling lama empat bulan dua minggu atau pidana denda paling banyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"477","b":"Kejahatan Pelayaran","t":"(1) Seorang nakoda kapal Indonesia yang dengan sengaja mem biarkan lari, atau melepaskan seorang terdakwa atau terpidana atau memberi bantuan ketika dilepaskan atau melepaskan diri, padahal orang itu diterima di kapalnya atas permintaan berdasarkan undang-undang. diancam dengan pidana penjara paling lama empat tahun. (2) Jika orang itu lari, dilepaskan atau melepaskan dirinya karena kealpaan nakoda itu, maka dia diancam dengan pidana kurungan paling lama dua bulan atau pidana denda paling banyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"478","b":"Kejahatan Pelayaran","t":"Seorang nakoda kapal Indonesia yang sengaja tidak memenuhi kewajibannya menurut ayat pertama pasal 358a Kitab Undang- undang Hukum Dagang untuk memberi pertolongan kalau kapal nya terlibat dalam suatu tabrakan, diancam dengan pidana penjara paling lama empat tahun."},{"l":"KUHP","p":"479","b":"Kejahatan Pelayaran","t":"Dalam hal pemidanaan berdasarkan salah satu kejahatan yang di- rumuskan dalam pasal 488 - 449,. 446, dan 467, dapat dinyatakan pencabutan hak-hak berdasarkan pasal 35 no. 1 - 4. Bab XXIX A - Kejahatan Penerbangan Dan Kejahatan Terhadap Sarana/Prasarana Penerbangan Pasal 479 a (1) Barang siapa dengan sengaja dan melawan hukum menghancurkan, membuat tidak dapat dipakai atau merusak bangunan untuk pengamanan lalu-lintas udara atau menggagalakan usaha untuk pengamanan bangun teesebut dipidana dengan pidana penjara selama-lamanya sembilam tahun, (2) Dengan pidana penjara selama-lamanya sembilan tahun jika karena perbuatan itu timbul bahaya bagi keamanan lalu-lintas udara; (3) Dengan pidana penjara selama-lamanya lima belas tahun jika karena perbuatan itu mengakibatkan matinya orang. Pasal 479 b (1) Barang siapa karena kealpaannya menyebabkan hancurnya, tidak dapat dipakainya atau rusaknya bangunan untuk pengamanan lalu-lintas udara, atau gagalnya usaha untuk pengamanan bangunan tersebut, dipidana dengan pidana penjara selama- lamanya tiga tahun. (2) Dengan pidana penjara selama-lamanya lima tahun, jika karena perbuatan itu timbul bahaya bagi keamanan lalu lintas udara. (3 ) Dengan pidana penjara selama-lamanya tujuh tahun, jika karena perbuatan itu mengakibatkan matinya orang. Pasal 479 c (1) Barang siapa dengan sengaja dan melawan hukum menghancurkan, merusak. mengambil atau memindahkan tanda atau alat untuk pengamanan penerbangan, atau menggagalkan bekerjanya tanda atau alat tersebut, atau memasang tanda atau alat yang keliru, dipidana dengan pidana penjara selama-lamanya enam tahun. (2) Dengan pidana penjara selama-lamanya sembilan tahun, jika karena perbuatan itu timbul bahaya bagi keamanan penerbangan. (3) Dengan pidana penjara selama-lamanya dua belas tahun, jika karena perbuatan itu timbul bahaya bagi keamanan penerbangan dan mengakibatkan celakanya pesawat udara. (4) Dengan pidana penjara selama-lamanya lima belas tahun, jika karena perbuatan itu timbul bahaya keamanan penerbangan dan mengakibatkan matinya orang."},{"l":"KUHP","p":"479d","b":"Kejahatan Pelayaran","t":"Barang siapa karena kealpaan menyebabkan tanda atau alat untuk pengamanan penerbangan hancur, rusak, terambil atau pindah atau menyebabkan tidak dapat bekerja atau menyebabkan terpasangnya tanda atau alat untuk pengamanan penerbangan yang keliru, dipidana: a. dengan pidana penjara selama-lamanya lima tahun, jika karena perbuatan itu menyebabkan penerbangan tidak aman; b. dengan pidana penjara selama-lamanya lima tahun, jika karena perbuatan itu mengakibatkan celakanya pesawat udara; c. dengan pidana penjara selama-lamanya tujuh tahun, jika karena perbuatan itu mengakibatkan matinya orang."},{"l":"KUHP","p":"479e","b":"Kejahatan Pelayaran","t":"Barang siapa dengar. sengaja dan melawan hukum, menghancurkan atau membuat tidak dapat dipakainya pesawat udara yang seluruhnya atau sebagian kepunyaan orang lain, dipidana dengan pidana penjara selama-lamanya sembilan tahun."},{"l":"KUHP","p":"479f","b":"Kejahatan Pelayaran","t":"Barang siapa dengan sengaja dan melawan hukum mencelakakan, menghancurkan, membuat tidak dapat dipakai atau merusak pesawat udara, dipidana: a. dengan pidana penjara selama-lamanya lima belas tahun, jika karena perbuatan itu timbul bahaya bagi nyawa orang lain; b. dengan pidana penjara seumur hidup atau pidana penjara untuk selama-lamanya dua puluh tahun, jika karena perbuatan itu mengakibatkan matinya orang."},{"l":"KUHP","p":"479g","b":"Kejahatan Pelayaran","t":"Barang siapa karena kealpaannya menyebabkan pesawat udara celaka, hancur, tidak dapat dipakai atau rusak, dipidana: a. dengan pidana penjara selama-lamanya lima tahun, jika karena perbuatan itu timbul bahaya bagi nyawa orang lain; b. dengan pidana penjara selama-lamanya tujuh tahun, jika karena perbuatan itu mengakibatkan matinya orang."},{"l":"KUHP","p":"479h","b":"Kejahatan Pelayaran","t":"(1) Barang siapa dengan maksud untuk menguntungkan diri sendiri atau orang lain dengan melawan hukum, atas kerugian penanggung asuransi menimbulkan kebakaran atau ledakan, kecelakaan, kehancuran, kerusakan atau membuat tidak dapat dipakainya pesawat udara, yang dipertanggungkan terhadap bahaya tersebut di atas atau yang dipertanggungkan muatannya maupun upah yang akan diterima untuk pengangkutan muatannya, ataupun untuk kepentingan muatan tersebut telah diterima uang tanggungan, dipidana dengan pidana penjara selama-lamanya sembilan tahun. (2) Apabila yang dimaksud pada ayat (1) pasal ini adalah pesawat udara dalam penerbangan, dipidana dengan pidana penjara selama-lamanya lima belas tahun. (3) Barang siapa dengan maksud untuk menguntungkan diri sendiri atau orang. lain dengan melawan hukum atas kerugian penanggung asuransi, menyebabkan penumpang pesawat udara yang dipertanggungkan terhadap bahaya. mendapat kecelakaan, dipidana: a. dengan pidana penjara selama-lamanya sepuluh tahun, jika karena perbuatan itu menyebabkan luka berat; b. dengan pidana penjara selama-lamanya lima belas tahun, jika karena perbuatan itu mengakibatkan matinya orang."},{"l":"KUHP","p":"479i","b":"Kejahatan Pelayaran","t":"Barang siapa di dalam pesawat udara dengan perbuatan yang melawan hukum merampas atau mempertahankan perampasan atau menguasai pesawat udara dalam penerbangan. dipidana dengan pidana penjara selama-lamanya dua belas tahun."},{"l":"KUHP","p":"479j","b":"Kejahatan Pelayaran","t":"Barang siapa dalam pesawat udara dengan kekerasan atau ancaman kekerasan atau ancaman dalam bentuk lainnya merampas atau mempertahankan perampasan atau menguasai pengendalian pesawat udara dalam penerbangan dipidana dengan pidana penjara selama-lamanya lima belas tahun. Pasai 479 k (1) Dipidana dengan pidana penjara seumur hidup atau pidana penjara selama-lamanya dua puluh tahun, apabila perbuatan dimaksud pasal 479 huruf i dan pasal 479 jitu: a. dilakukan oleh dua orang atau lebih bersama-sama; b. sebagai kelanjutan permufakatan jahat; c. dilakukan dengan direncanakan lebih dahulu; d. mengakibatkan kerusakan pada pesawat udara tersebut sehingga dapat membahayakan penerbangannya; e. mengakibatkan luka berat seseorang; f. dilakukan dengan maksud untuk merampas kemerdekaan atau meneruskan merampas kemerdekaan seseorang. (2) Jika perbuatan itu mengakibatkan matinya seseorang atau hancurnya pesawat udara itu, dipidana dengan pidana mati atau pidana penjara seumur hidup atau pidana penjara selama-lamanya dua puluh tahun."},{"l":"KUHP","p":"479l","b":"Kejahatan Pelayaran","t":"Barang siapa dengan sengaja dan melawan hukum melakukan perbuatan kekerasan terhadap seseorang di dalam pesawat udara dalam penerbangan, jika perbuatan itu dapat membahayakan keselamatan pesawat udara tersebut, dipidana dengan pidana penjara selama-lamanya lima belas tahun. Pasal 479 m Barang siapa dengan sengaja dan melawan hukum merusak pesawat udara dalam dinas atau menyebabkan kerusakan atas pesawat udara tersebut yang menyebabkan tidak dapat terbang atau membahayakan keamanan penerbangan, dipidana dengan pidana penjara selama-lamanya lima belas tahun."},{"l":"KUHP","p":"479n","b":"Kejahatan Pelayaran","t":"Barang siapa dengan sengaja dan melawan hukum menempatkan atau menyebabkan ditempatkannya di dalam pesawat udara dalam dinas, dengan cara apa pun, alat atau bahan yang dapat menghancurkan pesawat udara atau menyebabkan kerusakan pesawat udara tersebut yang membuatnya tidak dapat terbang atau menyebabkan kerusakan pesawat udara tersebut yang dapat membahayakan keamanan dalam penerbangan, dipidana dengan pidana penjara selama-lamanya lima belas tahun."},{"l":"KUHP","p":"479o","b":"Kejahatan Pelayaran","t":"(1) Dipidana dengan pidana penjara seumur hidup atau pidana penjara selama-lamanya dua puluh tahun apabila perbuatan dimaksud pasal 479 huruf l, pasal 479 huruf m, dan pasal 479 huruf n itu: a dilakukan oleh dua orang atau lebih bersama-sama; b. sebagai kelanjutan dari permufakatan jahat; c. dilakukan dengan direncanakan lebih dahulu; d. mengakibatkan luka berat bagi seseorang; (2) Jika perbuatan itu mengakibatkan matinya seseorang atau hancurnya pesawat udara itu, dipidana dengan pidana mati atau pidana penjara seumur hidup atau pidana penjara selamalamanya dua puluh tahun. Pasal 479 p Barang siapa memberikan keterangan yang diketahuinya adalah palsu dan karena perbuatan itu membahayakan keamanan pesawat udara dalam penerbangan, dipidana dengan pidana penjara selama-lamanya lima belas tahun. Pasal 479 q Barang siapa di dalam pesawat udara, melakukan perbuatan yang dapat membahayakan keamanan dalam pesawat udara dalam penerbangan, dipidana dengan pidana penjara selama-lamanya lima tahun. Pasal 479 r Barang siapa di dalam pesawat udara melakukan perbuatan-perbuatan yang dapat mengganggu ketertiban dan tata-tertib di dalam pesawat udara dalam penerbangan, dipidana penjara selama-lamanya satu tahun."},{"l":"KUHP","p":"480","b":"Penadahan Penerbitan Dan Percetakan","t":"Diancam dengan pidana penjara paling lama empat tahun atau pidana denda paling banyak sembilan ratus rupiah: 1. barang siapa membeli, menyewa, menukar, menerima gadai, menerima hadiah, atau untuk menarik keuntungan, menjual, menyewakan, menukarkan, menggadaikan, mengangkut, meyimpan atau menyembunyikan sesuatu benda, yang diketahui atau sepatutnya. harus diduga bahwa diperoleh dari kejahatan penadahan; 2. barang siapa menarik keuntungan dari hasil sesuatu benda, yang diketahuinya atau sepatutnya harus diduga bahwa diperoleh dari kejahatan."},{"l":"KUHP","p":"481","b":"Penadahan Penerbitan Dan Percetakan","t":"(1) Barang siapa menjadikan sebagai kebiasaan untuk sengaja membeli, menukar, menerima gadai, menyimpan, atau menyembunyikan barang yang diperoleh dari kejahatan, diancam dengan pidana penjara paling lama tujuh tahun. (2) Yang bersalah dapat dicabut haknya berdasarkan pasal 35 no. 1 - 4 dan haknya untuk melakukan pencarian dalam mana kejahatan dilakukan."},{"l":"KUHP","p":"482","b":"Penadahan Penerbitan Dan Percetakan","t":"Perbuatan sebagaimana dirumuskan dalam pasal 480, diancam karena penadahan ringan dengan pidana penjara paling lama tiga bulan atau pidana denda paling banyak sembilan ratus rupiah, jika kejahatan dari mana benda tersebut diperoleh adalah salah satu kejahatan yang dirumuskan dalam pasal 364, 373, dan 379."},{"l":"KUHP","p":"483","b":"Penadahan Penerbitan Dan Percetakan","t":"Barang siapa menerbitkan sesuatu tulisan atau sesuatu gambar yung karena sifatnya dapat diancam dengan pidana, diancam dengan pidana penjnra paling lama satu tahun empat bulan atau pidana kurungan paling lama satu tahun atau pidana denda paling banyak empat ribu lima ratus rupiah, jika: l. si pelaku tidak diketahui namanya dan juga tidak diberitahukan namanya oleh penerbit pada peringatan pertama sesudah penuntutan berjalan terhadapnya; 2. penerbit sudah mengetahui atau pat,ut menduga hahwa pada waktu tulisan atau gambar itu diterbitkan, si pelaku itu tak dapat dituntut atau akan menetap di luar Indonesia."},{"l":"KUHP","p":"484","b":"Penadahan Penerbitan Dan Percetakan","t":"Barang siapa mencetak tulisan atau gambar yang merupakan perbuatan pidana, diancam dengan pidana paling lama satu tahun empat bulan atau pidana kurungan paling lama satu tahun atau pidana denda paling banyak empat ribu lima ratus rupiah, jika: 1. orang yang menyuruh mencetak barang tidak diketahui, dan setelah ditentukan penuntutan, pada teguran pertama tidak diberitahukan olehnya; 2. pencetak mengetahui atau seharusnya renduga bahwa orang yang menyuruh mencetak pada saat penerbitan, tidak dapat dituntut atau menetap di luar Indonesia."},{"l":"KUHP","p":"485","b":"Penadahan Penerbitan Dan Percetakan","t":"Jika sifat tulisan atau gamhar merupakan kejahatan yang hanya dapat dituntut atas pengaduan, maka penerbit atau pencetak dalam kedua pasal di atas hanya dituntut atas pengaduan orang yang terkena kejahatan itu. Buku Ketiga - Pelanggaran Daftar Isi 1. Bab I - Tentang Pelanggaran Keamanan Umum bagi Orang atau Barang dan Kesehatan 2. Bab II - Pelanggaran Ketertiban Umum 3. Bab III - Pelanggaran Terhadap Penguasa Umum 4. Bab IV - Pelanggaran Mengenai Asal-Usul dan Perkawinan 5. Bab V - Pelanggaran Terhadap Orang yang Memerlukan Pertolongan 6. Bab VI - Pelanggaran Kesusilaan 7. Bab VII - Pelanggaran Mengenai Tanah, Tanaman dan Pekarangan 8. Bab VIII - Pelanggaran Jabatan 9. Bab IX - Pelanggaran Pelayaran"},{"l":"KUHP","p":"489","b":"Pelanggaran Keamanan Umum","t":"(1) Kenakalan terhadap orang atau barang yang dapat menimbulkan bahaya, kerugian atau kesusahan, diancam dengan pidana denda paling banyak dua ratus dua puluh lima rupiah. (2) Jika ketika melakukan pelanggaran belum lewat satu tahun sejak adanya pemidanaan yang menjadi tetap karena pelanggaran yang sama, pidana denda dapat diganti dengan pidana kurungan paling lama tiga hari."},{"l":"KUHP","p":"490","b":"Pelanggaran Keamanan Umum","t":"Diancam dengan pidana kurungan paling lama enam hari, atau pidana denda paling banyak tiga ratus rupiah: 1. barang siapa menghasut hewan terhadap orang atau terhadap hewan yang sedang ditunggangi, atau dipasang di muka kereta atau kendaraan, atau sedang memikul muatan: 2. barang siapa tidak mencegah hewan yang ada di bawah penjagaannya, bilamana hewan itu menyerang orang atau hewan yang lagi ditunggangi atau dipasang di muka kereta atau kendaraan, atau sedang memikul muatan: 3. barang siapa tidak menjaga secukupnya binatang buas yang ada di bawah penjagaannya, supaya tidak menimbulkan kerugian; 4. barang siapa memelihara binatang buas yang berbahaya tanpa melaporkan kepada polisi atau pejabat lain yang ditunjuk untuk itu, atau tidak menaati peraturan yang diberikan oleh pejabat tersebut tentang hal itu."},{"l":"KUHP","p":"491","b":"Pelanggaran Keamanan Umum","t":"Diancam dengan pidana denda paling banyak tujuh ratus lima puluh rupiah: 1. barang siapa diwajibkan menjaga orang gila yang berbahaya bagi dirinya sendiri maupun orang lain, membiarkan orang itu berkeliaran tanpa dijaga; 2. barang siapa diwajibkan menjaga seorang anak, meninggalkan anak itu tanpa dijaga sehingga oleh karenanya dapat timbul bahaya bagi anak itu atau orang lain."},{"l":"KUHP","p":"492","b":"Pelanggaran Keamanan Umum","t":"(1) Barang siapa dalam keadaan mabuk di muka umum merintangi lalu lintas, atau mengganggu ketertiban, atau mengancam keamanan orang lain, atau melakukan sesuatu yang harus dilakukan dengan hati-hati atau dengan mengadakan tindakan penjagaan tertentu lebih dahulu agar jangan membahayakan nyawa atau kesehatan orang lain, diancam dengan pidana kurungan paling lama enam hari, atau pidana denda paling banyak tiga ratus tujuh puluh lima rupiah. (2) Jika ketika melakukan pelanggaran belum lewat satu tahun sejak adanya pemidanaan yang menjadi tetap karena pelanggaran yang sama, atau karena hal yang dirumuskan dalam pasal 536, dijatuhkan pidana kurungan paling lama dua minggu."},{"l":"KUHP","p":"493","b":"Pelanggaran Keamanan Umum","t":"Barang siapa secara melawan hukum di jalan umum membahayakan kebebasan bergerak orang lain, atau terus mendesakkan dirinya bersama dengan seorang atau lebih kepada orang lain yang tidak menghendaki itu dan sudah tegas dinyatakan, atau mengikuti orang lain secara mengganggu, diancam dengan pidana denda paling banyak seribu lima ratus rupiah."},{"l":"KUHP","p":"494","b":"Pelanggaran Keamanan Umum","t":"Diancam dengan pidana denda paling banyak tiga ratus tujuh puluh lima rupiah: 1. barang siapa tidak mengadakan penerangan secukupnya dan tanda- tanda menurut kebiasaan pada penggalian atau menumpukkan tanah di jalan umum, yang dilakukan oleh atau atas perintahnya, atau pada benda yang ditaruh di situ oleh atau atas perintahnya; 2. barang siapa tidak mengadakan tindakan seperlunya pada waktu melakukan suatu pekerjaan di atas atau dipinggir jalan umum untuk memberi tanda bagi yang lalu di situ, bahwa ada kemungkinan bahaya; 3. barang siapa menaruh atau menggantungkan sesuatu di atas suatu bangunan, melempar atau menuangkan ke luar dari situ sedemikian rupa hingga oleh karena itu dapat timbul kerugian pada orang yang sedang menggunakan jalan umum; 4. barang siapa membiarkan di jalan umum, hewan untuk dinaiki, untuk menarik atau hewan muatan tanpa mengadakan tindakan penjagaan agar tidak menimbulkan kerugian; 5. barang siapa membiarkan ternak berkeliaran di jalan umum tanpa mengadakan tindakan penjagaaan, agar tidak menimbulkan kerugian; 6. barang siapa tanpa izin penguasa yang berwenang, menghalangi sesuatau jalanan untuk umum di darat maupun di air atau menimbulkan rintangan karena pemakaian kendaraan atau kapal yang tidak semestinya."},{"l":"KUHP","p":"495","b":"Pelanggaran Keamanan Umum","t":"(1) Barang siapa tanpa izin kepala polisi atau pejabat yang ditunjuk untuk itu, di tempat yang dilalui orang memasang ranjau perangkap, jerat, atau perkakas lain untuk menangkap atau membunuh binatang buas, diancam dengan pidana denda paling banyak tiga ratus tujuh puluh lima rupiah. (2) Jika ketika melakukan pelanggaran belum lewat satu tahun sesudah adanya pemidanaan yang menjadi tetap karena pelanggaran yang sama, pidana denda dapat diganti dengan pidana kurungan paling lama enam hari."},{"l":"KUHP","p":"496","b":"Pelanggaran Keamanan Umum","t":"Barang siapa tanpa izin kepala polisi atau pejabat yang ditunjuk untuk itu, membakar barang tak bergerak kepunyaan sendiri, diancam dengan pidana denda paling tinggi tujuh ratus lima puluh rupiah."},{"l":"KUHP","p":"497","b":"Pelanggaran Keamanan Umum","t":"Diancam dengan pidana denda paling tinggi tiga ratus tujuh puluh lima rupiah: 1. barang siapa di jalan umum atau di pinggirnya, ataupun di tempat yang sedemikian dekatnya dengan bangunan atau barang, hingga dapat timbul bahaya kebakaran, menyalakan api tanpa perlu menembakkan senjata api; 2. barang siapa melepaskan balon angin di mana digantungkan bahan- bahan menyala. Pasal 498 dan 499 Ditiadakan berdasarkan S. 32 - 143 jo. 33 - 9."},{"l":"KUHP","p":"500","b":"Pelanggaran Keamanan Umum","t":"Barang siapa tanpa izin kepala polisi atau pejabat yang ditunjuk untuk itu, membikin obet ledak, mata peluru atau peluru untuk senjata api, diancam dengan pidana kurungan paling lama sepuluh hari atau pidana denda paling banyak tujuh ratus lima puluh rupiah."},{"l":"KUHP","p":"501","b":"Pelanggaran Keamanan Umum","t":"(1) Diancam dengan pidana denda paling banyak tiga ratus tujuh puluh lima rupiah: 1. barang siapa menjual, menawarkan, menyerahkan, membagikan atau mempunyai persediaan untuk dijual atau dibagikan, barang makanan atau minuman yang dipalsu atau yang busuk, ataupun air susu dari ternak yang sakit atau yang dapat mengganggu kesehatan; 2. barang siapa tanpa izin kepala polisi atau pejabat yang ditunjuk untuk itu, menjual, menawarkan, menyerahkan, membagikan daging ternak yang dipotong karena sakit atau mati dengan sendirinya. (2) Jika ketika melakukan pelanggaran belum lewat dua tahun setelah ada pemidanaan yang menjadi tetap karena pelanggaran yang sama, pidana denda dapat diganti dengan pidana kurungan paling lama enam hari."},{"l":"KUHP","p":"502","b":"Pelanggaran Keamanan Umum","t":"(1) Barang siapa tanpa izin penguasa yang berwenang untuk itu, memburu atau membawa senjata api ke dalam hutan negara di mana dilarang untuk itu tanpa izin, diancam dengan pidana kurungan paling lama satu bulan atau pidana denda paling banyak tiga ribu rupiah; (2) Binatang yang ditangkap atau ditembak serta perkakas dan senjata yang digunakan dalam pelanggaran, dapat dirampas."},{"l":"KUHP","p":"503","b":"Pelanggaran Ketertiban Umum","t":"Diancam dengan pidana kurungan paling lama tiga hari atau pidana denda paling banyak dua ratus dua puluh lima rupiah: 1. barang siapa membikin ingar atau riuh, sehingga ketentraman malam hari dapat terganggu; 2. barang siapa membikin gaduh di dekat bangunan untuk menjalankan ibadat yang dibolehkan atau untuk sidang pengadilan, di waktu ada ibadat atau sidang."},{"l":"KUHP","p":"504","b":"Pelanggaran Ketertiban Umum","t":"(1) Barang siapa mengemis di muka umum, diancam karena melakukan pengemisan dengan pidana kurungan paling lama enam minggu. (2) Pengemisan yang dilakukan oleh tiga orang atau lebih, yang berumur di atas enam belas tahun, diancam dengan pidana kurungan paling lama tiga bulan. Pasal 505 (1) Barang siapa bergelandangan tanpa pencarian, diancam karena melakukan pergelandangan dengan pidana kurungan paling lama tiga bulan. (2) Pergelandangan yang dilakukan oleh tiga orang atau lebih, yang berumur di atas enam belas tahun diancam dengan pidana kurungan paling lama enam bulan."},{"l":"KUHP","p":"506","b":"Pelanggaran Ketertiban Umum","t":"Barang siapa menarik keuntungan dari perbuatan cabul seorang wanita dan menjadikannya sebagai pencarian, diancam dengan pidana kurungan paling lama satu tahun."},{"l":"KUHP","p":"507","b":"Pelanggaran Ketertiban Umum","t":"Diancam dengan pidana denda paling banyak dua ribu dua ratus lima puluh rupiah: 1. barang siapa tanpa wenang memakai suatu gelar ningrat, atau suatu tanda kehormatan Indonesia; 2. barang siapa tanpa izin Presiden, manakala itu diperlukan, menerima suatu tanda kehormatan, gelar, pangkat atau derajat asing; 3. barang siapa ketika ditanya oleh penguasa yang berwenang tentang namanya, memberi nama yang palsu."},{"l":"KUHP","p":"508","b":"Pelanggaran Ketertiban Umum","t":"Barang siapa tanpa wenang memakai dengan sedikit penyimpangan suatu nama atau tanda jasa yang pemakaiannya menurut ketentuan undang-undang, semata-mata untuk suatu perkumpulan atau personal perkumpulan, atau personal dinas kesehatan tentara, diancam dengan pidana kurungan paling lama satu bulan atau pidana denda paling banyak empat ribu lima ratus rupiah. Pasal 508 bis Barang siapa di muka umum tanpa wenang memakai pakaian yang menyamai pakaian jabatan yang ditetapkan untuk pegawai negeri atau pejabat yang bekerja pada negara, pada suatu provinsi, pada suatu daerah yang berdiri sendiri yang diakui atau yang diatur dengan undang-undang sehingga patut ia dapat dipandang orang sebagai pegawai atau pejabat itu, diancam dengan pidana kurungan paling lama satu bulan atau pidana denda paling banyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"509","b":"Pelanggaran Ketertiban Umum","t":"Barang siapa tanpa izin meminjamkan uang atau barang dengan gadai, atau dalam bentuk jual-beli dengan boleh dibeli kembali ataupun dalam bentuk kontrak komisi, yang nilainya tidak lebih dari seratus rupiah, diancam dengan pidana kurungan paling lama tiga bulan, atau pidana denda paling banyak lima belas ribu rupiah."},{"l":"KUHP","p":"510","b":"Pelanggaran Ketertiban Umum","t":"(1) Diancam dengan pidana denda paling banyak tiga ratus tujuh puluh lima rupiah, barang siapa tanpa izin kepala polisi atau pejabat lain yang ditunjuk untuk itu: 1. mengadakan pesta lain yang ditunjuk untuk itu: 2. mengadakan arak-arakan di jalan umum. (2) Jika arak-arakan diadakan untuk menyatakan keinginan-keinginan secara menakjubkan, yang bersalah diancam dengan pidana kurungan paling lama dua minggu atau pidana denda dua ribu dua ratus lima puluh rupiah."},{"l":"KUHP","p":"511","b":"Pelanggaran Ketertiban Umum","t":"Barang siapa di waktu ada pesta arak-arakan, dan sebagainya, tidak menaati perintah dan petunjuk yang diadakan oleh polisi untuk mencegah kecelakaan oleh kemacetan lalu lintas di jalan umum, diancam dengan pidana denda paling banyak tiga ratus tujuh puluh lima rupiah."},{"l":"KUHP","p":"512","b":"Pelanggaran Ketertiban Umum","t":"(1) Barang siapa tidak diwenangkan melakukan pencarian yang menurut aturan-aturan umum harus diberi kewenangan untuk itu, melakukannya tanpa keharusan, diancam dengan pidana denda paling banyak empat ribu lima ratus rupiah. (2) Barang siapa diwenangkan melakukan pencarian yang menurut aturan-aturan umum harus diberi kewenangan untuk itu, dalam melakukan pencarian tersebut tanpa keharusan melampaui batas kewenangannya, diancam dengan pidana denda paling banyak tujuh ratus lima puluh rupiah. (3) Jika ketika melakukan pelanggaran belum lewat dua tahun sejak adanya pemidanaan yang menjadi tetap karena pelanggaran yang sama, maka dalam hal ayat pertama, pidana denda dapat diganti dengan pidana kurungan paling lama dua bulan, dan dalam hal ayat kedua, paling lama satu bulan."},{"l":"KUHP","p":"512a","b":"Pelanggaran Ketertiban Umum","t":"Barang siapa sebagai mata pencarian, baik khusus maupun sebagai sambilan menjalankan pekerjaan dokter atau dokter gigi dengan tidak mempunyai surat izin, di dalam keadaan yang tidak memaksa, diancam dengan pidana kurungan paling lama dua bulan atau pidana denda setinggi-tingginya seratus lima puluh ribu rupiah."},{"l":"KUHP","p":"513","b":"Pelanggaran Ketertiban Umum","t":"Barang siapa menggunakan atau membolehkan digunakan barang orang lain yang ada padanya karena ada hubungan kerja atau karena pencariannya, untuk pemakaian yang tidak diizinkan oleh pemiliknya, diancam dengan pidana kurungan paling lama enam hari atau pidana denda paling banyak tiga ratus tujuh puluh lima rupiah."},{"l":"KUHP","p":"514","b":"Pelanggaran Ketertiban Umum","t":"Seorang pekerja harian, pembawa bungkusan, pesuruh, pemikul atau kuli, yang dalam menjalankan pencariannya melakukan kelalaian atau kekurangan dalam pengembalian perkakas yang diterima untuk dipakai, atau dalam penyampaian barang yang diterima untuk diangkut, diancam dengan pidana kurungan paling lama enam hari, atau pidana denda paling banyak tiga ratus tujuh puluh lima rupiah."},{"l":"KUHP","p":"515","b":"Pelanggaran Ketertiban Umum","t":"(1) Diamcam denga pidana kurungan paling lama enam hari, atau pidana denda paling banyak tujuh ratus lima puluh rupiah; 1. barang siapa pindah kediaman dari bagian kota, desa atau kampung di mana dia menetap, tanpa memberitahukan sebelumnya kepada penguasa yang berwenang dengan menyebut tempat menetap yang baru; 2. barang siapa setelah menetap di bagian kota, desa atau kampung, tidak memberitahukan hal itu kepada penguasa yang berwenang dalam tenggang waktu empat belas hari, dengan menyebut nama, pencarian dan tempat asalnya. (2) Ketentuan dalam ayat pertama tidak berlaku bagi orang yang pindah tempat kediaman dan menetap, yang masih di dalam satu kota."},{"l":"KUHP","p":"516","b":"Pelanggaran Ketertiban Umum","t":"(1) Barang siapa menjadikan sebagai pencarian untuk memberi tempat bermalam kepada orang lain, dan tidak mempunyai register terus-menerus, atau tidak mencatat atau menyuruh catat nama, pencarian atau pekerjaan, tempat kediaman, hari datang dan perginya orang yang bermalam di situ, atau atas permintaan kepala polisi atau pejabat yang ditunjuk untuk itu, tidak memperlihatkan register itu, diancam dengan pidana denda paling banyak tiga ratus tujuh puluh lima rupiah. (2) Jika ketika melakukan pelanggaran belum lewat dua tahun sejak adanya pemidanaan yang menjadi tetap karena pelanggaran yang sama, pidana denda dapat diganti dengan pidana kurungan paling lama enam hari."},{"l":"KUHP","p":"517","b":"Pelanggaran Ketertiban Umum","t":"(1) Diancam dengan pidana kurungan paling lama satu bulan atau pidana denda paling banyak dua ribu dua ratus lima puluh rupiah: 1. barang siapa membeli, menukar, menerima untuk ibadah, gadai, pakai atau simpan dari seorang tentara di bawah pangkat perwira; atau menjualkan, menggadaikan, meminjamkan atau menyimpankan barang tersebut untuk seorang tentara di bawah pangkat perwira, yang diberikan tanpa izin dari atau nama perwira. 2. barang siapa menjadikan kebiasaan atau pencarian untuk membeli barang-barang yang demikian, tidak menaati peraturan mengenai pencatatan dalam register yang ditentukan dalam aturan-aturan umum. (2) Jika ketika melakukan pelanggaran belum lewat dua tahun sejak adanya pemidanaan yang menjadi tetap karena pelanggaran yang sama, pidananya dapat dilipatkan dua kali."},{"l":"KUHP","p":"518","b":"Pelanggaran Ketertiban Umum","t":"Barang siapa tanpa wenang memberi pada atau menerima dari seorang terpidana sesuatu barang, diancam dengan pidana kurungan paling lama enam hari atau pidana denda paling banyak tiga ratus tujuh puluh lima rupiah."},{"l":"KUHP","p":"519","b":"Pelanggaran Ketertiban Umum","t":"(1) Barang siapa membikin, menjual, menyiarkan atau mempunyai persediaan untuk dijual atau disiarkan, ataupun memasukannya ke Indonesia, barang cetakan, potongan logam atau benda-benda lain yang bentuknya menyerupai uang kertas, mata uang, benda- benda emas atau perak dengan merek negara, atau perangko pos, diancam dengan pidana denda paling banyak empat ribu lima ratus rupiah. (2) Benda-benda yang merupakan pelanggaran dapt dirampas. Pasal 519 bis Diancam dengan pidana kurungan paling lama tiga bulan, atau pidana denda paling banyak lima belas ribu rupiah: 1. barang siapa mengumumkan isi apa yang ditangkap lewat pesawat penerima radio yang dipakai olehnya atau yang ada di bawah pengurusannya, yang sepatutnya harus diduganya bahwa itu tidak untuk dia atau untuk diumumkan, maupun memberitahukannya kepada orang lain, jika sepatutnya harus diduganya bahwa itu akan diumumkan dan memang lalu disusul dengan pengumuman; 2. barang siapa mengumumkan berita yang ditangkap lewat pesawat penerima radio, jika ia sendiri, maupun orang dari mana berita itu diterimanya, tidak berwenang untuk itu."},{"l":"KUHP","p":"520","b":"Pelanggaran Ketertiban Umum","t":"Diancam dengan pidana kurungan paling lama tiga bulan: 1. barang siapa yang setelah mendapat pengunduran pembayaran hutang dengan kehendak sendiri melakukan perbuatan-perbuatan, untuk mana menurut aturan-aturan umum, diharuskan adanya kerjasama dengan pengurua; 2. seorang pengurus atau komisaris perseroan, maskapai, perkumpulan atau yayasan, yang setelah mendapat pengunduran bayar hutang, dengan kehendak sendiri melakukan perbuatan-perbuatan untuk mana menurut aturan-aturan umum, diharuskan adanya kerjasama dengan pengurus."},{"l":"KUHP","p":"521","b":"Pelanggaran Terhadap Penguasa Umum","t":"Barang siapa melanggar ketentuan peraturan penguasa umum yang telah diumumkan mengenai pemakaian dan pembagian air dari perlengkapan air atau bangunan pengairan guna keperluan umum, diancam dengan pidana kurungan paling lama dua belas hari, atau pidana denda paling banyak sembilan ratus rupiah."},{"l":"KUHP","p":"522","b":"Pelanggaran Terhadap Penguasa Umum","t":"Barang siapa menurut undang-undang dipanggil sebagai saksi, ahli atau juru bahasa, tidak datang secara melawan hukum, diancam dengan pidana denda paling banyak sembilan ratus rupiah."},{"l":"KUHP","p":"523","b":"Pelanggaran Terhadap Penguasa Umum","t":"Barang siapa tanpa alasan yang sah membiarkan tidak dikerjakannya pekerjaan rodi, pekerjaan desa atau pekerjaan perusahaan kebun negara, diancam dengan pidana kurungan paling tinggi tiga hari atau pidana denda paling tinggi sepuluh rupiah. Jika ketika melakukan pelanggaran belum lewat enam bulan sejak adanya pemidanaan yang menjadi tetap karena pelanggaran yang sama, dapat diancam dengan pidana kurungan paling tinggi tiga bulan."},{"l":"KUHP","p":"524","b":"Pelanggaran Terhadap Penguasa Umum","t":"Diancam dengan pidana paling banyak sembilan ratus rupiah: 1. barangsiapa dalam perkara mengenai orang yang belum dewasa, atau orang yang sudah tahu akan di bawah pengampuan, atau orang yang akan atau sudah dimasukkan dalam rumah sakit jiwa, dipanggil untuk didengar selaku keluarga sedarah atau semenda, selaku suami/istri, wali atau wali pengawas oleh hakim atau atas perintahnya oleh kepala polisi, tidak datang sendiri maupun dengan perantaraan kuasanya jika itu dibolehkan, tanpa alasan yang dapat diterima; 2. barang siapa dalam perkara mengenai orang yang belum dewasa atau orang yang sudah atau akan di bawah pengampuan, dipanggil untuk didengar oleh kantor peninggalan harta atau atas permintaannya oleh kepala polisi, tidak datang sendiri maupun dengan perantaraan kuasanya jika itu dibolehkan, tanpa alasan yang dapat diterima; 3. barang siapa dalam perkara mengenai orang yang belum dewasa dipanggil untuk didengar oleh majelis perwalian atau atas permintaannya oleh kepala polisi, tidak datang sendiri atau dengan perantaraan kuasanya, tanpa alasan yang dapat diterima."},{"l":"KUHP","p":"525","b":"Pelanggaran Terhadap Penguasa Umum","t":"(1) Barang siapa ketika ada bahaya umum bagi orang atau barang, atau ketika ada kejahatan tertangkap tangan diminta pertolongannya oleh penguasa umum tetapi menolaknya, padahal mampu untuk memberi pertolongan tersebut tanpa menempatkan diri langsung dalam keadaan yang membahayakan, diancam dengan pidana denda paling banyak tiga ratus tujuh puluh lima rupiah; (2) Ketentuan ini tidak berlaku bagi mereka yang menolak memberi pertolongan karena ingin menghindari atau menghalaukan bahaya penuntutan bagi salah seorang keluarganya sedarah atau semenda dalam garis lurus atau menyimpang, sampai derajat kedua atau ketiga, atau bagi suami (istri) atau bekas suaminya (istrinya)."},{"l":"KUHP","p":"526","b":"Pelanggaran Terhadap Penguasa Umum","t":"Barang siapa menyobek, membikin tak terbaca atau merusak suatu pemberitahuan di muka umum dari pihak penguasa yang wenang atau karena ketentuan undang-undang, diancam dengan pidana denda paling banyak dua ratus dua puluh lima rupiah."},{"l":"KUHP","p":"527","b":"Pelanggaran Terhadap Penguasa Umum","t":"Ditiadakan berdasarkan L.N. 1955 - 28."},{"l":"KUHP","p":"528","b":"Pelanggaran Terhadap Penguasa Umum","t":"(1) Diancam dengan pidana kurungan paling lama dua bulan atau pidana denda paling banyak empat ribu lima ratus rupiah, barang siapa tanpa izin penguasa yang berwenang: 1. membikin salinan atau petikan dari surat-surat jabatan negara dan alat- alatnya, yang dengan perintah penguasa umum harus dirahasiakan; 2. mengumumkan seluruh atau sebagaian surat-surat tersebut dalam butir 1; 3. mengumumkan hal-hal yang termakstub dalam surat-surat tersebut dalam butir 1, padahal sewajarnya dapat diduga bahwa hal-hal itu harus dirahasiakan. (2) Perbuatan itu tidak dipidana, jika perintah merahasiakan jelas diberikan karena alasan lain daripada kepentingan dinas atau umum."},{"l":"KUHP","p":"529","b":"Pelanggaran Mengenai Asal-Usul Dan Perkawinan","t":"Barang siapa tidak memenuhi kewajibannya menurut undang-undang untuk melaporkan pada pejabat Catatan Sipil atau perantaranya tentang kelahiran dan kematian, diancam dengan pidana denda paling banyak seribu lima ratus rupiah."},{"l":"KUHP","p":"530","b":"Pelanggaran Mengenai Asal-Usul Dan Perkawinan","t":"(1) Seorang petugas agama yang melakukan upacara perkawinan, yang hanya dapat dilangsungkan di hadapan pejabat Catatan Sipil, sebelum dinyatakan padanya bahwa pelangsungan di muka pejabat itu sudah dilakukan, diancam dengan pidana denda paling banyak empat ribu lima ratus rupiah. (2) Jika ketika melakukan pelanggaran belum lewat dua tahun sejak adanya pemidanaan yang menjadi tetap karena pelanggaran sama, pidana denda dapat diganti dengan pidana kurungan paling lama dua bulan. Bab V Pelanggaran Terhadap Orang Yang Memerlukan Pertolongan"},{"l":"KUHP","p":"531","b":"Pelanggaran Mengenai Asal-Usul Dan Perkawinan","t":"Barang siapa ketika menyaksikan bahwa ada orang yang sedang menghadapi maut tidak memberi pertolongan yang dapat diberikan padanya tanpa selayaknya menimbulkan bahaya bagi dirinya atau orang lain, diancam, jika kemudian orang itu meninggal, dengan pidana kurungan paling lama tiga bulan atau pidana denda paling banyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"532","b":"Pelanggaran Kesusilaan","t":"Diancam dengan pidana kurungan paling lama tiga hari atau pidana denda paling banyak dua ratus dua puluh lima rupiah: 1. barang siapa di muka umum menyanyikan lagu-lagu yang melanggar kesusilaan; 2. barang siapa di muka umum mengadakan pidato yang melanggar kesusilaan; 3. barang siapa di tempat yang terlihat dari jalan umum mengadakan tulisan atau gambaran yang melanggar kesusilaan."},{"l":"KUHP","p":"533","b":"Pelanggaran Kesusilaan","t":"Diancam dengan pidana kurungan paling lama dua bulan atau pidana denda paling banyak tiga ribu rupiah: 1. barang siapa di tempat untuk lalu lintas umum dengan terang-terangan mempertunjukkan atau menempelkan tulisan dengan judul, kulit, atau isi yang dibikin terbaca, maupun gambar atau benda, yang mampu membangkitkan nafsu birahi para remaja; 2. barang siapa di tempat untuk lalu lintas umum dengan terang-terangan memperdengarkan isi tulisan yang mampu membangkitkan nafsu birahi para remaja; 3. barang siapa secara terang-terangan atau tanpa diminta menawarkan suatu tulisan, gambar atau barang yang dapat merangsang nafsu berahi para remaja maupun secara terang-terangan atau dengan menyiarkan tulisan tanpa diminta, menunjuk sebagai bisa didapat, tulisan atau gambar yang dapat membangkitkan nafsu berahi para remaja; 4. barang siapa menawarkan, memberikan untuk terus atau sementara waktu, menyerahkan atau memperlihatkan gambar atau benda yang demikian, pada seorang belum dewasa dan di bawah umur tujuh belas tahun; 5. barang siapa memperdengarkan isi tulisan yang demikian di muka seorang yang belum dewasa dan dibawah umur tujuh belas tahun."},{"l":"KUHP","p":"534","b":"Pelanggaran Kesusilaan","t":"Barang siapa secara terang-terangan mempertunjukkan sesuatu sarana untuk mencegah kehamilan maupun secara terang-terangan atau tanpa diminta menawarkan, ataupun secara terang-terangan atau dengan menyiarkan tulisan tanpa diminta, menunjuk sebagai bisa didapat, sarana atau perantaraan (diensten) yang demikian itu, diancam dengan pidana kurungan paling lama dua bulan atau pidana denda paling banyak tiga ribu rupiah."},{"l":"KUHP","p":"536","b":"Pelanggaran Kesusilaan","t":"(1) Barang siapa terang dalam keadaan mabuk berada di jalan umum, diancam dengan pidana denda paling banyak dua ratus dua puluh lima rupiah. (2) Jika ketika melakukan pelanggaran belum lewat satu tahun sejak adanya pemidanaan yang menjadi tetap karena pelanggaran yang sama atau yang dirumuskan dalam pasal 492, pidana denda dapat diganti dengan pidana kurungan paling lama tiga hari. (3) Jika terjadi pengulangan kedua dalam satu tahun setelah pemidanaan pertama berakhir dan menjadi tetap, dikenakan pidana kurungan paling lama dua minggu. (4) Pada pengulangan ketiga kalinya atau lebih dalam satu tahun, setelah pemidanaan yang kemudian sekali karena pengulangan kedua kalinya atau lebih menjadi tetap, dikenakan pidana kurungan paling lama tiga bulan."},{"l":"KUHP","p":"537","b":"Pelanggaran Kesusilaan","t":"Barang siapa di luar kantin tentara menjual atau memberikan minuman keras atau arak kepada anggota Angkatan Bersenjata di bawah pangkat letnan atau kepada istrinya, anak atau pelayan, diancam dengan pidana kurungan paling lama tiga minggu atau pidana denda paling tinggi seribu lima ratus rupiah."},{"l":"KUHP","p":"538","b":"Pelanggaran Kesusilaan","t":"Penjual atau wakilnya yang menjual minuman keras yang dalam menjalankan pekerjaan memberikan atau menjual minuman keras atau arak kepada seorang anak di bawah umur enam belas tahun, diancam dengan pidana kurungan paling lama tiga minggu atau pidana denda paling tinggi empat ribu lima ratus rupiah."},{"l":"KUHP","p":"539","b":"Pelanggaran Kesusilaan","t":"Barang siapa pada kesempatan diadakan pesta keramaian untuk umum atau pertunjukkan rakyat atau diselenggarakan arak-arakan untuk umum, menyediakan secara cuma-cuma minuman keras atau arak dan atau menjanjikan sebagai hadiah, diancam dengan pidana kurungan paling lama dua belas hari atau pidana denda paling tinggi tiga ratus tujuh puluh lima rupiah."},{"l":"KUHP","p":"540","b":"Pelanggaran Kesusilaan","t":"(1) Diancam dengan pidana kurungan paling lama delapan hari atau pidana denda paling banyak dua ribu dua ratus lima puluh rupiah: 1. barang siapa menggunakan hewan untuk pekerjaan yang terang melebihi kekuatannya; 2. barang siapa tanpa perlu menggunakan hewan untuk pekerjaan dengan cara yang menyakitkan atau yang merupakan siksaan bagi hewan tersebut; 3. barang siapa menggunakan hewan yang pincang atau yang mempunyai cacat lainnya, yang kudisan, luka-luka atau yang jelas sedang hamil maupun sedang menyusui untuk pekerjaan yang karena keadaannya itu tidak sesuai atau yang menyakitkan maupun yang merupakan siksaan bagi hewan tersebut; 4. barang siapa mengangkut atau menyuruh mengangkut hewan tanpa perlu dengan cara yang menyakitkan atau yang merupakan siksaan bagi hewan tersebut; 5. barang siapa mengangkut atau menyuruh mengangkut hewan tanpa diberi atau disuruh beri makan atau minum. (2) Jika ketika melakukan pelanggaran belum lewat satu tahun setelah ada pemidanaan yang menjadi tetap karena pelanggaran yang sama karena salah satu pelanggaran pada pasal 302, dapat dikenakan pidana kurungan paling lama empat belas hari."},{"l":"KUHP","p":"541","b":"Pelanggaran Kesusilaan","t":"(1) Diancam dengan pidana denda paling banyak dua ratus dua puluh lima rupiah; 1. barang siap menggunakan sebagai kuda beban, tunggangan atau kuda penarik kereta padahal kuda tersebut belum tukar gigi atau kedua gigi dalamnya di rahang atas belum menganggit kedua gigi dalamnya di rahang bawah; 2. barang siapa memasangkan pakaian kuda pada kuda tersebut dalam butir 1 atau mengikat maupun memasang kuda itu pada kendaraan atau kuda tarikan; 3. barang siapa menggunakan sebagai kuda beban, tunggangan atau penarik kereta seekor kuda induk, dengan membiarkan anaknya yang belum tumbuh keenam gigi mukanya, mengikutinya. (2) Jika ketika melakukan pelanggaran belum lewat satu tahun setelah ada pemidanaan yang menjadi tetap karena pelanggaran yang sama atau yang berdasarkan pasal 540, ataupun karena kejahatan berdasarkan pasal 302, pidana denda dapat diganti dengan pidana kurungan paling lama tiga hari."},{"l":"KUHP","p":"542","b":"Pelanggaran Kesusilaan","t":"Ditiadakan berdasarkan Undang-undang No. 7 Tahun 1974."},{"l":"KUHP","p":"543","b":"Pelanggaran Kesusilaan","t":"Ditiadakan berdasarkan S.23 - 277, 352."},{"l":"KUHP","p":"544","b":"Pelanggaran Kesusilaan","t":"(1) Barang siapa tanpa izin kepala polisi atau pejabat yang ditunjuk untuk itu mengadakan sabungan ayam atau jangkrik di jalan umum atau di pinggirnya, maupun di tempat yang dapat dimasuki oleh khalayak umum, diancam dengan pidana kurungan paling lama enam hari atau pidana denda paling banyak tiga ratus tujuh puluh lima rupiah. (2) Jika ketika melakukan pelanggaran belum lewat satu tahun sejak adanya pemidanaan yang menjadi tetap karena pelanggaran yang sama, pidananya dapat dilipatduakan."},{"l":"KUHP","p":"545","b":"Pelanggaran Kesusilaan","t":"(1) Barang siapa menjadikan sebagai pencariannya untuk menyatakan peruntungan seseorang, untuk mengadakan peramalan atau penafsiran impian, diancam dengan pidana kurungan paling lama enam hari atau pidana denda paling banyak tiga ratus rupiah. (2) Jika ketika melakukan pelanggaran belum lewat satu tahun sejak adanya pemidanaan yang menjadi tetap karena pelanggaran yang sama, pidananya dapat dilipatduakan."},{"l":"KUHP","p":"546","b":"Pelanggaran Kesusilaan","t":"Diancam dengan pidana kurungan paling lama tiga bulan atau pidana denda paling banyak empat ribu lima ratus rupiah: 1. Diancam dengan pidana kurungan paling lama tiga bulan atau pidana denda paling banyak empat ribu lima ratus rupiah: 2. barang siapa menjual, menawarkan, menyerahkan, membagikan atau mempunyai persediaan untuk dijual atau dibagikan jimat-jimat atau benda-benda yang dikatakan olehnya mempunyai kekuatan gaib; 3. barang siapa mengajar ilmu-ilmu atau kesaktian-kesaktian yang bertujuan menimbulkan kepercayaan bahwa melakukan perbuatan pidana tanpa kemungkinan bahaya bagi diri sendiri."},{"l":"KUHP","p":"547","b":"Pelanggaran Kesusilaan","t":"Seorang saksi, yang ketika diminta untuk memberi keterangan di bawah sumpah menurut ketentuan undang-undang, dalam sidang pengadilan memakai jimat-jimat atau benda- benda sakti, diancam dengan pidana kurungan paling lama sepuluh hari atau pidana denda paling banyak tujuh ratus lima puluh rupiah. Bab VII Pelanggaran Mengenai Tanah, Tanaman Dan Pekarangan"},{"l":"KUHP","p":"548","b":"Pelanggaran Kesusilaan","t":"Barang siapa tanpa wenang membiarkan unggas ternaknya berjalan di kebun, di tanah yang sudah ditaburi, ditugali atau ditanami, diancam dengan pidana denda paling banyak dua ratus dua puluh lima rupiah."},{"l":"KUHP","p":"549","b":"Pelanggaran Kesusilaan","t":"(1) Barang siapa tanpa wenang membiarkan ternaknya berjalan di kebun, di padang rumput atau di ladang rumput atau di padang rumput kering, baik di tanah yang telah ditaburi, ditugali atau ditanami atau yang hasilnya belum diambil, ataupun di tanah kepunyaan orang lain oleh yang berhak dilarang dimasuki dan sudah diberi tanda larangan yang nyata bagi pelanggar, diancam dengan pidana denda paling banyak tiga ratus tujuh puluh lima rupiah. (2) Ternak yang menyebabkan pelanggaran, dapat dirampas. (3) Jika ketika melakukan pelanggaran belum lewat satu tahun sejak adanya pemidanaan yang menjadi tetap karena pelanggaran yang sama, pidana denda dapat diganti dengan pidana kurungan paling lama empat belas hari."},{"l":"KUHP","p":"550","b":"Pelanggaran Kesusilaan","t":"Barang siapa tanpa wenang berjalan atau berkendaraan di tanah yang sudah ditaburi, ditugali atau ditanami, diancam dengan pidana denda paling banyak dua ratus dua puluh lima rupiah."},{"l":"KUHP","p":"551","b":"Pelanggaran Kesusilaan","t":"Barang siapa tanpa wenang, berjalan atau berkendaraan di atas tanah yang oleh pemiliknya dengan cara jelas dilarang memasukinya, diancam dengan pidana denda paling banyak dua ratus dua puluh lima rupiah."},{"l":"KUHP","p":"552","b":"Pelanggaran Jabatan","t":"Seorang pejabat yang berwenang mengeluarkan salinan atau petikan putusan pengadilan, jika mengeluarkan salinan atau petikan demikian itu sebelum putusan ditandatangani sebagaimana mestinya, diancam dengan pidana denda paling banyak tujuh ratus lima puluh rupiah."},{"l":"KUHP","p":"553","b":"Pelanggaran Jabatan","t":"Ditiadakan berdasarkan S. 35 - 576; lihat pasal 528."},{"l":"KUHP","p":"554","b":"Pelanggaran Jabatan","t":"Diancam dengan pidana kurungan paling lama dua bulan atau pidana denda paling banyak empat ribu lima ratus rupiah, seorang bekas pejabat yang tanpa izin penguasa yang berwenang menahan surat-surat jabatan."},{"l":"KUHP","p":"555","b":"Pelanggaran Jabatan","t":"Diancam dengan pidana kurungan paling lama satu bulan atau pidana denda paling banyak dua ribu dua ratus lima puluh rupiah kepala lembaga pemasyarakatan, tempat menahan orang tahanan sementara atau orang yang disandera, atau kepala rumah pendidikan negara atau rumah sakit jiwa, yang menerima atau menahan orang dalam tempat itu dengan tidak meminta diperlihatkan kepadanya lebih dahulu surat perintah penguasa yang berwenang, atau putusan pengadilan, atau yang alpa menuliskan menurut aturan dalam daftar hal penerimaan itu dan perintah atau keputusan yang menjadi alasan orang itu diterima."},{"l":"KUHP","p":"556","b":"Pelanggaran Jabatan","t":"Seorang pejabat catatan sipil yang sebelum melangsungkan perkawinan tidak minta diberikan padanya bukti-bukti atau keterangan-keterangan yang diharuskan menurut aturan-aturan umum, diancam dengan pidana denda paling banyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"557","b":"Pelanggaran Jabatan","t":"Diancam dengan pidana denda paling banyak seribu lima ratus rupiah: 1. seorang pejabat catatan sipil yang bertindak berlawanan dengan ketentuan aturan- aturan umum mengenai register atau akta catatan sipil, mengenai tata cara sebelumnya perkawinan atau pelaksanaan perkawinan; 2. setiap orang lain penyimpan register itu yang bertindak berlawanan dengan ketentuan aturan-aturan umum mengenai regiter dan akta catatan sipil."},{"l":"KUHP","p":"557a","b":"Pelanggaran Jabatan","t":"Seorang perantara catatan sipil yang bertindak berlawanan dengan ketentuan reglemen pemeliharaan register catatan sipil orang-orang Cina diancam dengan denda paling banyak tujuh ratus lima puluh rupiah."},{"l":"KUHP","p":"558","b":"Pelanggaran Jabatan","t":"Seorang pejabat catatan sipil yang tidak memasukkan suatu akta dalam register atau menuliskan suatu akta di atas kertas lepas, diancam dengan pidana denda paling banyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"558a","b":"Pelanggaran Jabatan","t":"Seorang perantara catatan sipil yang tidak membikin akta daripada suatu pemberitahuan kepadanya menurut ketentuan tentang pemeliharaan register catatan sipil bagi orang- orang Cina, atau menuliskan suatu akta di kertas lepas, diancam dengan pidana denda paling banyak dua ribu dua ratus lima puluh rupiah."},{"l":"KUHP","p":"559","b":"Pelanggaran Jabatan","t":"Diancam dengan pidana denda paling banyak seribu lima ratus rupiah: 1. seorang pejabat catatan sipil yang tidak melaporkan kepada penguasa yang berwenang sebagaimana diharuskan oleh ketentuan undang- undang; 2. seorang pejabat yang tidak melaporkan kepada pejabat catatan sipil, sebagaimana diharuskan oleh ketentuan undang-undang."},{"l":"KUHP","p":"560","b":"Pelanggaran Pelayaran","t":"Seorang nakoda kapal Indonesia yang berangkat sebelum dibikin dan ditandatangani daftar anak buah yang diharuskan oleh ketentuan undang-undang, diancam dengan pidana denda paling banyak seribu lima ratus rupiah."},{"l":"KUHP","p":"561","b":"Pelanggaran Pelayaran","t":"Seorang nakoda kapal Indonesia yang tidak mempunyai di kapalnya kertas-kertas kapal, buku-buku dan surat-surat yang diharuskan oleh ketentuan undang-undang, diancam dengan pidana denda paling banyak seribu lima ratus rupiah."},{"l":"KUHP","p":"562","b":"Pelanggaran Pelayaran","t":"Diancam dengan pidana denda paling banyak empat ribu lima ratus rupiah: 1. seorang nakoda kapal Indonesia yang tidak menjaga supaya buku- buku harian di kapal dipelihara menurut aturan-aturan umum, atau tidak memperlihatkan buku-buku harian itu di mana dan apabila menurut ketentuan undang-undang itu diharuskan padanya; 2. seorang nakoda kapal Indonesia yang tidak memelihara register pidana yang diharuskan oleh aturan-aturan umum menurut ketentuan undang-undang, atau tidak memperlihatkannya di mana dan apabila menurut ketentuan undang-undang itu diharuskan padanya; 3. seorang nakoda kapal Indonesia yang jika register pidana tidak ada, tidak memberi keterangan kepada hakim sebagaimana diharuskan menurut ketentuan undang-undang; 4. seorang pengusaha pelayaran, pemegang buku atau nakoda kapal Indonesia yang menolak permintaan untuk memperlihatkan kepada yang berkepentingan buku-buku harian yang dipelihara di kapalnya, atau menolak untuk memberi salinan dari buku-buku itu, dengan membayar biayanya."},{"l":"KUHP","p":"563","b":"Pelanggaran Pelayaran","t":"Seorang nakoda kapal Indonesia yang tidak mencukupi kewajibannya menurut undang- undang mengenai pencatatan dan pemberitahuan kelahiran dan kematian selama perjalanannya, diancam dengan pidana denda paling banyak seribu lima ratus rupiah."},{"l":"KUHP","p":"564","b":"Pelanggaran Pelayaran","t":"Seorang nakoda atau anak buah yang tidak memperhatikan ketentuan undang-undang untuk mencegah tabrakan disebabkan karena kapalnya melanggar atau terdampar, diancam dengan pidana denda paling banyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"565","b":"Pelanggaran Pelayaran","t":"Barang siapa tanpa wewenang menggunakan suatu tanda pengenal walaupun dengan sedikit perubahan, menurut ketentuan undang-undang yang hanya boleh dipakai oleh kapal-kapal rumah sakit, sekoci-sekoci kapal-kapal yang demikian, maupun perahu- perahu yang digunakan untuk pekerjaan merawat orang sakit, diancam dengan pidana kurungan paling lama satu bulan atau pidana denda paling banyak empat ribu lima ratus rupiah."},{"l":"KUHP","p":"566","b":"Pelanggaran Pelayaran","t":"Seorang nakoda kapal Indonesia yang tidak memenuhi kewajiban yang dibebankan padanya menurut pasal 358a Kitab Undang-undang Hukum Dagang, diancam dengan pidana kurungan paling lama tiga bulan atau pidana denda paling banyak emapt ribu lima ratus rupiah."},{"l":"KUHP","p":"567","b":"Pelanggaran Pelayaran","t":"Seorang penguasa pelabuhan atau nakoda kapal Indonesia yang menggunakan untuk pekerjaan anak buah orang-orang yang tidak mengadakan perjanjian kerja ebagaimana dimaksud pasal 395 Kitab Undang-undang Hukum Dagang atau yang tidak menjalankan perusahaan di kapal atas biaya sendiri, ataupun menggunakan orang-orang yang namanya tidak ada dalam daftar anak buah, dalam hal ini diharuskan oleh aturan-aturan umum, diancam dengan pidana denda paling banyak sembilan ratus rupiah untuk tiap- tiap orang yang bekerja demikian."},{"l":"KUHP","p":"568","b":"Pelanggaran Pelayaran","t":"Barang siapa menandatangani konosemen yang dikeluarkan dengan melanggar ketentuan pasal 517b Kitab Undang-undang Hukum Dagang, begitu pula orang untuk siapa dibutuhkan tanda tangan sesuai dengan kewenangannya, diancam jika konosemen lalu dikeluarkan, dengan pidana denda paling banyak tujuh puluh lima ribu rupiah."},{"l":"KUHP","p":"569","b":"Pelanggaran Pelayaran","t":"(1) Barang siapa menandatangani surat jalan yang dikeluarkan dengan melanggar ketentuan pasal 533b Kitab Undang-undang Hukum Dagang, begitu pula orang untuk siapa dibutuhkan tandatangan sesuai dengan kewenangannya, diancam, jika surat lalu dikeluarkan, dengan pidana denda paling banyak tujuh puluh lima ribu rupiah. (2) Diancam dengan pidana yang sama, barang siapa bertentangan dengan pasal 533b Kitab Undang-undang Hukum dagang, memberikan surat jalan yang tidak ditandatangani, begitu pula orang untuk siapa surat diberikan menurut kewenangannya."},{"l":"UU PT No.40/2007","p":"1","b":"","t":"Dalam undang-undang ini yang dimaksud dengan: 1. Perseroan Terbatas, yang selanjutnya disebut perseroan, adalah badan hukum yang merupakan persekutuan modal, didirikan berdasarkan perjanjian, melakukan kegiatan usaha dengan modal dasar yang seluruhnya terbagi dalam saham dan memenuhi persyaratan yang ditetapkan dalam undang-undang ini serta peraturan pelaksanaannya. 2. Organ Perseroan adalah Rapat Umum Pemegang Saham, Direksi, dan Dewan Komisaris. 3. Tanggung Jawab Sosial dan Lingkungan adalah komitmen Perseroan untuk berperan serta dalam pembangunan ekonomi berkelanjutan guna meningkatkan kualitas kehidupan dan lingkungan yang bermanfaat, baik bagi Perseroan sendiri, komunitas setempat, maupun masyarakat pada umumnya. 4. Rapat Umum Pemegang Saham, yang selanjutnya disebut RUPS, adalah Organ Perseroan yang mempunyai wewenang yang tidak diberikan kepada Direksi atau Dewan Komisaris dalam batas yang ditentukan dalam undang-undang ini dan/atau anggaran dasar. 5. Direksi adalah Organ Perseroan yang berwenang dan bertanggung jawab penuh atas pengurusan Perseroan untuk kepentingan Perseroan, sesuai dengan maksud dan tujuan Perseroan serta mewakili Perseroan, baik di dalam maupun di luar pengadilan sesuai dengan ketentuan anggaran dasar. 6. Dewan Komisaris adalah Organ Perseroan yang bertugas melakukan pengawasan secara umum dan/atau khusus sesuai dengan anggaran dasar serta memberi nasihat kepada Direksi. - 2- 7. Perseroan Terbuka adalah Perseroan Publik atau Perseroan yang melakukan penawaran umum saham, sesuai dengan ketentuan peraturan perundang- undangan di bidang pasar modal. 8. Perseroan Publik adalah Perseroan yang memenuhi kriteria jumlah pemegang saham dan modal disetor sesuai dengan ketentuan peraturan perundang-undangan di bidang pasar modal. 9. Penggabungan adalah perbuatan hukum yang dilakukan oleh satu Perseroan atau lebih untuk menggabungkan diri dengan Perseroan lain yang telah ada yang mengakibatkan aktiva dan pasiva dari Perseroan yang menggabungkan diri beralih karena hukum kepada Perseroan yang menerima penggabungan dan selanjutnya status badan hukum Perseroan yang menggabungkan diri berakhir karena hukum. 10. Peleburan adalah perbuatan hukum yang dilakukan oleh dua Perseroan atau lebih untuk meleburkan diri dengan cara mendirikan satu Perseroan baru yang karena hukum memperoleh aktiva dan pasiva dari Perseroan yang meleburkan diri dan status badan hukum Perseroan yang meleburkan diri berakhir karena hukum. 11. Pengambilalihan adalah perbuatan hukum yang dilakukan oleh badan hukum atau orang perseorangan untuk mengambil alih saham Perseroan yang mengakibatkan beralihnya pengendalian atas Perseroan tersebut. 12. Pemisahan adalah perbuatan hukum yang dilakukan oleh Perseroan untuk memisahkan usaha yang mengakibatkan seluruh aktiva dan pasiva Perseroan beralih karena hukum kepada 2 (dua) Perseroan atau lebih atau sebagian aktiva dan pasiva Perseroan beralih karena hukum kepada 1 (satu) Perseroan atau lebih. 13. Surat Tercatat adalah surat yang dialamatkan kepada penerima dan dapat dibuktikan dengan tanda terima dari penerima yang ditandatangani dengan menyebutkan tanggal penerimaan. 14. Surat Kabar adalah surat kabar harian berbahasa Indonesia yang beredar secara nasional. 15. Hari adalah hari kalender. 16. Menteri adalah Menteri yang tugas dan tanggung jawabnya di bidang hukum dan hak asasi manusia."},{"l":"UU PT No.40/2007","p":"2","b":"","t":"Perseroan harus mempunyai maksud dan tujuan serta kegiatan usaha yang tidak bertentangan dengan ketentuan peraturan perundang- undangan, ketertiban umum, dan/atau kesusilaan."},{"l":"UU PT No.40/2007","p":"3","b":"","t":"(1) Pemegang saha m Perseroan tidak bertanggung jawab secara pribadi atas perikatan yang dibuat atas nama Perseroan dan tidak bertanggung jawab atas kerugian Perseroan melebihi saham yang dimiliki. (2) Ketentuan sebagaimana dimaksud pada ayat (1) tidak berlaku apabila: a. persyaratan Perseroan sebagai badan hukum belum atau tidak terpenuhi; b. pemegang saham yang bersangkutan baik langsung maupun tidak langsung dengan itikad buruk memanfaatkan Perseroan untuk kepentingan pribadi; c. pemegang saham yang bersangkutan terlibat dalam perbuatan melawan hukum yang dilakukan oleh Perseroan; atau d. pemegang saham yang bersangkutan baik langsung maupun tidak langsung secara melawan hukum menggunakan kekayaan Perseroan, yang mengakibatkan kekayaan Perseroan menjadi tidak cukup untuk melunasi utang Perseroan."},{"l":"UU PT No.40/2007","p":"4","b":"","t":"Terhadap Perseroan berlaku undang-undang ini, anggaran dasar Perseroan, dan ketentuan peraturan perundang-undangan lainnya."},{"l":"UU PT No.40/2007","p":"5","b":"","t":"(1) Perseroan mempunyai nama dan tempat kedudukan dalam wilayah negara Republik Indonesia yang ditentukan dalam anggaran dasar. (2) Perseroan mempunyai alamat lengkap sesuai dengan tempat kedudukannya. - 3- (3) Dalam surat- menyurat, pengumuman yang diterbitkan oleh Perseroan, barang cetakan, dan akta dalam hal Perseroan menjadi pihak harus menyebutkan nama dan alamat lengkap Perseroan."},{"l":"UU PT No.40/2007","p":"6","b":"","t":"Perseroan didirikan untuk jangka waktu terbatas atau tidak terbatas sebagaimana ditentukan dalam anggaran dasar. BAB II PENDIRIAN, ANGGARAN DASAR DAN PERUBAHAN ANGGARAN DASAR, DAFTAR PERSEROAN DAN PENGUMUMAN Bagian Kesatu Pendirian"},{"l":"UU PT No.40/2007","p":"7","b":"","t":"(1) Perseroan didirikan oleh 2 (dua) orang atau lebih dengan akta notaris yang dibuat dalam bahasa Indonesia. (2) Setiap pendiri Perseroan wajib mengambil bagian saham pada saat Perseroan didirikan. (3) Ketentuan sebagaimana dimaksud pada ayat (2) tidak berlaku dalam rangka Peleburan. (4) Perseroan memperoleh status badan hukum pada tanggal diterbitkannya keputusan menteri mengenai pengesahan badan hukum Perseroan. (5) Setelah Perseroan memperoleh status badan hukum dan pemegang saham menjadi kurang dari 2 (dua) orang, dalam jangka waktu paling lama 6 (enam) bulan terhitung sejak keadaan tersebut pemegang saham yang bersangkutan wajib mengalihkan sebagian sahamnya kepada orang lain atau Perseroan mengeluarkan saham baru kepada orang lain. (6) Dalam hal jangka waktu sebagaimana dimaksud pada ayat (5) telah dilampaui, pemegang saham tetap kurang dari 2 (dua) orang, pemegang saham bertanggung jawab secara pribadi atas segala perikatan dan kerugian Perseroan, dan atas permohonan pihak yang berkepentingan, pengadilan negeri dapat membubarkan Perseroan tersebut. (7) Ketentuan yang mewajibkan Perseroan didirikan oleh 2 (dua) orang atau lebih sebagaimana dimaksud pada ayat (1), dan ketentuan pada ayat (5), serta ayat (6) tidak berlaku bagi: a. Persero yang seluruh sahamnya dimiliki oleh negara; atau b. Perseroan yang mengelola bursa efek, lembaga kliring dan penjaminan, lembaga penyimpanan dan penyelesaian, dan lembaga lain sebagaimana diatur dalam undang- undang tentang Pasar Modal."},{"l":"UU PT No.40/2007","p":"8","b":"","t":"(1) Akta pendirian memuat anggaran dasar dan keterangan la in berkaitan dengan pendirian Perseroan. (2) Keterangan lain sebagaimana dimaksud pada ayat (1) memuat sekurang-kurangnya: a. nama lengkap, tempat dan tanggal lahir, pekerjaan, tempat tinggal, dan kewarganegaraan pendiri perseorangan, atau nama, tempat kedudukan dan alamat lengkap serta nomor dan tanggal keputusan menteri mengenai pengesahan badan hukum dari pendiri Perseroan; b. nama lengkap, tempat dan tanggal lahir, pekerjaan, tempat tinggal, kewarganegaraan anggota Direksi dan Dewan Komisaris yang pertama kali diangkat; c. nama pemegang saham yang telah mengambil bagian saham, rincian jumlah saham, dan nilai nominal saham yang telah ditempatkan dan disetor. (3) Dalam pembuatan akta pendirian, pendiri dapat diwakili oleh orang lain berdasarkan surat kuasa."},{"l":"UU PT No.40/2007","p":"9","b":"","t":"(1) Untuk memperoleh keputusan menteri mengenai pengesahan badan hukum Perseroan sebagaimana dimaksud dalam Pasal 7 ayat (4), pendiri bersama-sama mengajukan permohonan melalui jasa teknologi informasi sistem administrasi badan hukum secara elektronik kepada Menteri dengan mengisi format isian yang memuat sekurang-kurangnya: a. nama dan tempat kedudukan Perseroan; - 4- b. jangka waktu berdirinya Perseroan; c. maksud dan tujuan serta kegiatan usaha Perseroan; d. jumlah modal dasar, modal ditempatkan, dan modal disetor; e. alamat lengkap Perseroan. (2) Pengisian format isian sebagaimana dimaksud pada ayat (1) harus didahului dengan pengajuan nama Perseroan. (3) Dalam hal pendiri tidak mengajukan sendiri permohonan sebagaimana dimaksud pada ayat (1) dan ayat (2), pendiri hanya dapat memberi kuasa kepada notaris. (4) Ketentuan lebih lanjut mengenai tata cara pengajuan dan pemakaian nama Perseroan diatur dengan peraturan pemerintah."},{"l":"UU PT No.40/2007","p":"10","b":"","t":"(1) Permohonan untuk memperoleh keputusan menteri sebagaimana dimaksud dalam Pasal 9 ayat (1) harus diajukan kepada Menteri paling lambat 60 (enam puluh) hari terhitung sejak tanggal akta pendirian ditandatangani, dilengkapi keterangan mengenai dokumen pendukung. (2) Ketentuan mengenai dokumen pendukung sebagaimana dimaksud pada ayat (1) diatur dengan peraturan menteri. (3) Apabila format isian sebagaimana dimaksud dalam Pasal 9 ayat (1) dan keterangan mengenai dokumen pendukung sebagaimana dimaksud pada ayat (1) telah sesuai dengan ketentuan peraturan perundang-undangan, Menteri langsung menyatakan tidak berkeberatan atas permoho nan yang bersangkutan secara elektronik. (4) Apabila format isian sebagaimana dimaksud dalam Pasal 9 ayat (1) dan keterangan mengenai dokumen pendukung sebagaimana dimaksud pada ayat (1) tidak sesuai dengan ketentuan peraturan perundang- undangan, Menteri langsung memberitahukan penolakan beserta alasannya kepada pemohon secara elektronik. (5) Dalam jangka waktu paling lambat 30 (tiga puluh) hari terhitung sejak tanggal pernyataan tidak berkeberatan sebagaimana dimaksud pada ayat (3), pemohon yang bersangkutan wajib menyampaikan secara fisik surat permohonan yang dilampiri dokumen pendukung. (6) Apabila semua persyaratan sebagaimana dimaksud pada ayat (5) telah dipenuhi secara lengkap, paling lambat 14 (empat belas) hari, Menteri menerbitkan keputusan tentang pengesahan badan hukum Perseroan yang ditandatangani secara elektronik. (7) Apabila persyaratan tentang jangka waktu dan kelengkapan dokumen pendukung sebagaimana dimaksud pada ayat (5) tidak dipenuhi, Menteri langsung memberitahukan hal tersebut kepada pemohon secara elektronik, dan pernyataan tidak berkeberatan sebagaimana dimaksud pada ayat (3) menjadi gugur. (8) Dalam hal pernyataan tidak berkeberatan gugur, pemohon sebagaimana dimaksud pada ayat (5) dapat mengajukan kembali permohonan untuk memperoleh keputusan menteri sebagaimana dimaksud dalam Pasal 9 ayat (1). (9) Dalam hal permohonan untuk memperoleh keputusan menteri tidak diajukan dalam jangka waktu sebagaimana dimaksud pada ayat (1), akta pendirian menjadi batal sejak lewatnya jangka waktu tersebut dan Perseroan yang belum memperoleh status badan hukum bubar karena hukum dan pemberesannya dilakukan oleh pendiri. (10) Ketentuan jangka waktu sebagaimana dimaksud pada ayat (1) berlaku juga bagi permohonan pengajuan kembali."},{"l":"UU PT No.40/2007","p":"11","b":"","t":"Ketentuan lebih lanjut mengenai pengajuan permohonan untuk memperoleh keputusan menteri sebagaimana dimaksud dalam Pasal 7 ayat (4) bagi daerah tertentu yang belum mempunyai atau tidak dapat digunakan jaringan elektronik diatur dengan peraturan menteri."},{"l":"UU PT No.40/2007","p":"12","b":"","t":"(1) Perbuatan hukum yang berkaitan denga n kepemilikan saham dan penyetorannya yang dilakukan oleh calon pendiri sebelum Perseroan didirikan, harus dicantumkan dalam akta pendirian. (2) Dalam hal perbuatan hukum sebagaimana dimaksud pada ayat (1), dinyatakan dengan akta yang bukan akta otentik, akta tersebut dilekatkan pada akta pendirian. - 5- (3) Dalam hal perbuatan hukum sebagaimana dimaksud pada ayat (1), dinyatakan dengan akta otentik, nomor, tanggal dan nama serta tempat kedudukan notaris yang membuat akta otentik tersebut disebutkan dalam akta pendirian Perseroan. (4) Dalam hal ketentuan sebagaimana dimaksud pada ayat (1), ayat (2), dan ayat (3) tidak dipenuhi, perbuatan hukum tersebut tidak menimbulkan hak dan kewajiban serta tidak mengikat Perseroan."},{"l":"UU PT No.40/2007","p":"13","b":"","t":"(1) Perbuatan hukum yang dilakukan calon pendiri untuk kepentingan Perseroan yang belum didirikan, mengikat Perseroan setelah Perseroan menjadi badan hukum apabila RUPS pertama Perseroan secara tegas menyatakan menerima atau mengambil alih semua hak dan kewajiban yang timbul dari perbuatan hukum yang dilakukan oleh calon pendiri atau kuasanya. (2) RUPS pertama sebagaimana dimaksud pada ayat (1) harus diselenggarakan dalam jangka waktu paling lambat 60 (enam puluh) hari setelah Perseroan memperoleh status badan hukum. (3) Keputusan RUPS sebagaimana dimaksud pada ayat (2) sah apabila RUPS dihadiri oleh pemegang saham yang mewakili semua saham dengan hak suara dan keputusan disetujui dengan suara bulat. (4) Dalam hal RUPS tidak diselenggarakan dalam jangka waktu sebagaimana dimaksud pada ayat (2) atau RUPS tidak berhasil mengambil keputusan sebagaimana dimaksud pada ayat (3), setiap calon pendiri yang melakukan perbuatan hukum tersebut bertanggung jawab secara pribadi atas segala akibat yang timbul. (5) Persetujuan RUPS sebagaimana dimaksud pada ayat (2) tidak diperlukan apabila perbuatan hukum tersebut dilakukan atau disetujui secara tertulis oleh semua calon pendiri sebelum pendirian Perseroan."},{"l":"UU PT No.40/2007","p":"14","b":"","t":"(1) Perbuatan hukum atas nama Perseroan yang belum memperoleh status badan hukum, hanya boleh dilakukan oleh semua anggota Direksi bersama-sama semua pendiri serta semua anggota Dewan Komisaris Perseroan dan mereka semua bertanggung jawab secara tanggung renteng atas perbuatan hukum tersebut. (2) Dalam hal perbuatan hukum sebagaimana dimaksud pada ayat (1) dilakukan oleh pendiri atas nama Perseroan yang belum memperoleh status badan hukum, perbuatan hukum tersebut menjadi tanggung jawab pendiri yang bersangkutan dan tidak mengikat Perseroan. (3) Perbuatan hukum sebagaimana dimaksud pada ayat (1), karena hukum menjadi tanggung jawab Perseroan setelah Perseroan menjadi badan hukum. (4) Perbuatan hukum sebagaimana dimaksud pada ayat (2) hanya mengikat dan menjadi tanggung jawab Perseroan setelah perbuatan hukum tersebut disetujui oleh semua pemegang saham dalam RUPS yang dihadiri oleh semua pemega ng saham Perseroan. (5) RUPS sebagaimana dimaksud pada ayat (4) adalah RUPS pertama yang harus diselenggarakan paling lambat 60 (enam puluh) hari setelah Perseroan memperoleh status badan hukum. Bagian Kedua Anggaran Dasar dan Perubahan Anggaran Dasar Paragraf 1 Anggaran Dasar"},{"l":"UU PT No.40/2007","p":"15","b":"","t":"(1) Anggaran dasar sebagaimana dimaksud dalam Pasal 8 ayat (1) memuat sekurang-kurangnya: a. nama dan tempat kedudukan Perseroan; b. maksud dan tujuan serta kegiatan usaha Perseroan; c. jangka waktu berdirinya Perseroan; d. besarnya jumlah modal dasar, modal ditempatkan, dan modal disetor; e. jumlah saham, klasifikasi saham apabila ada berikut jumlah saham untuk tiap klasifikasi, hak-hak yang melekat pada setiap saham, dan nilai nominal setiap saham; - 6- f. nama jabatan dan jumlah anggota Direksi dan Dewan Komisaris; g. penetapan tempat dan tata cara penyelenggaraan RUPS; h. tata cara pengangkatan, penggantian, pemberhentian anggota Direksi dan Dewan Komisaris; i. tata cara penggunaan laba dan pembagian dividen. (2) Selain ketentuan sebagaimana dimaksud pada ayat (1) anggaran dasar dapat juga memuat ketentuan lain yang tidak bertentangan dengan undang- undang ini. (3) Anggaran dasar tidak boleh memuat: a. ketentuan tentang penerimaan bunga tetap atas saham; dan b. ketentuan tentang pemberian manfaat pribadi kepada pendiri atau pihak lain."},{"l":"UU PT No.40/2007","p":"16","b":"","t":"(1) Perseroan tidak boleh memakai nama yang: a. telah dipakai secara sah oleh Perseroan lain atau sama pada pokoknya dengan nama Perseroan lain; b. bertentangan dengan ketertiban umum dan/atau kesusilaan; c. sama atau mirip dengan nama lembaga ne gara, lembaga pemerintah, atau lembaga internasional, kecuali mendapat izin dari yang bersangkutan; d. tidak sesuai dengan maksud dan tujuan, serta kegiatan usaha, atau menunjukkan maksud dan tujuan Perseroan saja tanpa nama diri; e. terdiri atas angka atau rangkaian angka, huruf atau rangkaian huruf yang tidak membentuk kata; atau f. mempunyai arti sebagai Perseroan, badan hukum, atau persekutuan perdata. (2) Nama Perseroan harus didahului dengan frase “Perseroan Terbatas” atau disingkat “PT”. (3) Dalam hal Perseroan Terbuka selain berlaku ketentuan sebagaimana dimaksud pada ayat (2), pada akhir nama Perseroan ditambah kata singkatan “Tbk”. (4) Ketentuan lebih lanjut mengenai tata cara pemakaian nama Perseroan diatur dengan peraturan pemerintah."},{"l":"UU PT No.40/2007","p":"17","b":"","t":"(1) Perseroan mempunyai tempat kedudukan di daerah kota atau kabupaten dalam wilayah negara Republik Indonesia yang ditentukan dalam anggaran dasar. (2) Tempat kedudukan sebagaimana dimaksud pada ayat (1) sekaligus merupakan kantor pusat Perseroan."},{"l":"UU PT No.40/2007","p":"18","b":"","t":"Perseroan harus mempunyai maksud dan tujuan serta kegiatan usaha yang dicantumkan dalam anggaran dasar Perseroan sesuai dengan ketentuan peraturan perundang-undangan. Paragraf 2 Perubahan Anggaran Dasar"},{"l":"UU PT No.40/2007","p":"19","b":"","t":"(1) Perubahan anggaran dasar ditetapkan oleh RUPS. (2) Acara mengenai perubahan anggaran dasar wajib dicantumkan dengan jelas dalam panggilan RUPS."},{"l":"UU PT No.40/2007","p":"20","b":"","t":"(1) Perubahan anggaran dasar Perseroan yang telah dinyatakan pailit tidak dapat dilakukan, kecuali dengan pesetujuan kurator. (2) Persetujuan kurator sebagaimana dimaksud pada ayat (1) dilampirkan dalam permohonan persetujuan atau pemberitahuan perubahan anggaran dasar kepada Menteri."},{"l":"UU PT No.40/2007","p":"21","b":"","t":"(1) Perubahan anggaran dasar tertentu harus mendapat persetujuan Menteri. (2) Perubahan anggaran dasar tertentu sebagaimana dimaksud pada ayat (1) meliputi: - 7- a. nama Perseroan dan/atau tempat kedudukan Perseroan; b. maksud dan tujuan serta kegiatan usaha Perseroan; c. jangka waktu berdirinya Perseroan; d. besarnya modal dasar; e. pengurangan modal f. ditempatkan dan disetor; dan/atau g. status Perseroan yang tertutup menjadi Perseroan Terbuka atau sebaliknya. (3) Perubahan anggaran dasar selain sebagaimana dimaksud pada ayat (2) cukup diberitahukan kepada Menteri. (4) Perubahan anggaran dasar sebagaimana dimaksud pada ayat (2) dan ayat (3) dimuat atau dinyatakan dalam akta notaris dalam bahasa Indonesia. (5) Perubahan anggaran dasar yang tidak dimuat dalam akta berita acara rapat yang dibuat notaris harus dinyatakan dalam akta notaris paling lambat 30 (tiga puluh) hari terhitung sejak tanggal keputusan RUPS. (6) Perubahan anggaran dasar tidak boleh dinyatakan dalam akta notaris setelah lewat batas waktu 30 (tiga puluh) hari sebagaimana dimaksud pada ayat (5). (7) Permohonan persetujuan perubahan anggaran dasar sebagaimana dimaksud pada ayat (2) diajukan kepada Menteri, paling lambat 30 (tiga puluh) hari terhitung sejak tanggal akta notaris yang memuat perubahan anggaran dasar. (8) Ketentuan sebagaimana dimaksud pada ayat (7) mutatis mutandis berlaku bagi pemberitahuan perubahan anggaran dasar kepada Menteri. (9) Setelah lewat batas waktu 30 (tiga puluh) hari sebagaimana dimaksud pada ayat (6) permohonan persetujuan atau pemberitahuan perubahan anggaran dasar tidak dapat diajukan atau disampaikan kepada Menteri."},{"l":"UU PT No.40/2007","p":"22","b":"","t":"(1) Permohonan persetujuan perubahan anggaran dasar mengenai perpanjangan jangka waktu berdirinya Perseroan sebagaimana ditetapkan dalam anggaran dasar harus diajukan kepada Menteri paling lambat 60 (enam puluh) hari sebelum jangka waktu berdirinya Perseroan berakhir. (2) Menteri memberikan persetujuan atas permohonan perpanjangan jangka waktu sebagaimana dimaksud pada ayat (1) paling lambat pada tanggal terakhir berdirinya Perseroan."},{"l":"UU PT No.40/2007","p":"23","b":"","t":"(1) Perubahan anggaran dasar sebagaimana dimaksud dalam Pasal 21 ayat (2) mulai berlaku sejak tanggal diterbitkannya keputusan menteri mengenai persetujuan perubahan anggaran dasar. (2) Perubahan anggaran dasar sebagaimana dimaksud dalam Pasal 21 ayat (3) mulai berlaku sejak tanggal diterbitkannya surat penerimaan pemberitahuan perubahan anggaran dasar oleh Menteri. (3) Ketentuan sebagaimana dimaksud pada ayat (1) dan ayat (2) tidak berlaku dalam hal undang- undang ini menentukan lain."},{"l":"UU PT No.40/2007","p":"24","b":"","t":"(1) Perseroan yang modal dan jumlah pemegang sahamnya telah memenuhi kriteria sebagai Perseroan Publik sesuai dengan ketentuan peraturan perundang-undangan di bidang pasar modal, wajib mengubah anggaran dasarnya sebagaimana dimaksud dalam Pasal 21 ayat (2) huruf f dalam jangka waktu 30 (tiga puluh) hari terhitung sejak terpenuhi kriteria tersebut. (2) Direksi Perseroan sebagaimana dimaksud pada ayat (1) wajib mengajukan pernyataan pendaftaran sesuai dengan ketentuan peraturan perundang-undangan di bidang pasar modal."},{"l":"UU PT No.40/2007","p":"25","b":"","t":"(1) Perubahan anggaran dasar mengenai status Perseroan yang tertutup menjadi Perseroan Terbuka mulai berlaku sejak tanggal: a. efektif pernyataan pendaftaran yang diajukan kepada lembaga pengawas di bidang pasar modal bagi Perseroan Publik; atau - 8- b. dilaksanakan penawaran umum, bagi Perseroan yang mengajukan pernyataan pendaftaran kepada lembaga pengawas di bidang pasar modal untuk melakukan penawaran umum saham sesuai dengan ketent uan peraturan perundang- undangan di bidang pasar modal. (2) Dalam hal pernyataan pendaftaran Perseroan sebagaimana dimaksud pada ayat (1) huruf a tidak menjadi efektif atau Perseroan yang telah mengajukan pernyataan pendaftaran sebagaimana dimaksud pada ayat (1) huruf b tidak melaksanakan penawaran umum saham, Perseroan harus mengubah kembali anggaran dasarnya dalam jangka waktu 6 (enam) bulan setelah tanggal persetujuan Menteri."},{"l":"UU PT No.40/2007","p":"26","b":"","t":"Perubahan anggaran dasar yang dilakukan dalam rangka Penggabungan atau Pengambilalihan berlaku sejak tanggal: a. persetujuan Menteri; b. kemudian yang ditetapkan dalam persetujuan Menteri; atau c. pemberitahuan perubahan anggaran dasar diterima Menteri, atau tanggal kemudian yang ditetapkan dalam akta Penggabungan atau akta Pengambilalihan."},{"l":"UU PT No.40/2007","p":"27","b":"","t":"Permohonan persetujuan atas perubahan anggaran dasar sebagaimana dimaksud dalam Pasal 21 ayat (2) ditolak apabila: a. bertentangan dengan ketentuan mengenai tata cara perubahan anggaran dasar; b. isi perubahan bertentangan dengan ketentuan peraturan perundang-undangan, ketertiban umum, dan/atau kesusilaan; atau c. terdapat keberatan dari kreditor atas keputusan RUPS mengenai pengurangan modal."},{"l":"UU PT No.40/2007","p":"28","b":"","t":"Ketentuan mengenai tata cara pengajuan permohonan untuk memperoleh keputusan menteri mengenai pengesahan badan hukum Perseroan, dan keberatannya sebagaimana dimaksud dalam Pasal 9, Pasal 10, dan Pasal 11 mutatis mutandis berlaku bagi pengajuan permohonan persetujuan perubahan anggaran dasar dan keberatannya. Bagian Ketiga Daftar Perseroan dan Pengumuman Paragraf 1 Daftar Perseroan"},{"l":"UU PT No.40/2007","p":"29","b":"","t":"(1) Daftar Perseroan diselenggarakan oleh Menteri. (2) Daftar Perseroan sebagaimana dimaksud pada ayat (1) memuat data tentang (3) Perseroan yang meliputi: a. nama dan tempat kedudukan, maksud dan tujuan serta kegiatan usaha, jangka waktu pendirian, dan permodalan; b. alamat lengkap Perseroan sebagaimana dimaksud dalam Pasal 5; c. nomor dan tanggal akta pendirian dan keputusan menteri mengenai pengesahan badan hukum Perseroan sebagaimana dimaksud dalam Pasal 7 ayat (4); d. nomor dan tangga l akta perubahan anggaran dasar dan persetujuan Menteri sebagaimana dimaksud dalam Pasal 23 ayat (1); e. nomor dan tanggal akta perubahan anggaran dasar dan tanggal penerimaan pemberitahuan oleh Menteri sebagaimana dimaksud dalam Pasal 23 ayat (2); f. nama dan tempat kedudukan notaris yang membuat akta pendirian dan akta perubahan anggaran dasar; g. nama lengkap dan alamat pemegang saham, anggota Direksi, dan anggota Dewan Komisaris Perseroan; h. nomor dan tanggal akta pembubaran atau nomor dan tanggal penetapan pengadilan tentang pembubaran Perseroan yang telah diberitahukan kepada Menteri; - 9- i. berakhirnya status badan hukum Perseroan; j. neraca dan laporan laba rugi dari tahun buku yang bersangkutan bagi Perseroan yang wajib diaudit. (4) Data Perseroan sebagaimana dimaksud pada ayat (2) dimasukkan dalam daftar Perseroan pada tanggal yang bersamaan dengan tanggal: a. Keputusan menteri mengenai pengesahan badan hukum Perseroan, persetujuan atas perubahan anggaran dasar yang memerlukan persetujuan; b. Penerimaan pemberitahuan perubahan anggaran dasar yang tidak memerlukan persetujuan; atau c. Penerimaan pemberitahuan perubahan data Perseroan yang bukan merupakan perubahan anggaran dasar. (5) Ketentuan sebagaimana dimaksud pada ayat (2) huruf g mengenai nama lengkap dan alamat pemegang saham Perseroan Terbuka sesuai dengan ketentuan peraturan perundang-undangan di bidang pasar modal. (6) Daftar Perseroan sebagaimana dimaksud pada ayat (1) terbuka untuk umum. (7) Ketentuan lebih lanjut mengenai daftar Perseroan diatur dengan peraturan menteri. Paragraf 2 Pengumuman"},{"l":"UU PT No.40/2007","p":"30","b":"","t":"(1) Menteri mengumumkan dalam Tambahan Berita Negara Republik Indonesia: a. akta pendirian Perseroan beserta keputusan menteri sebagaimana dimaksud dalam Pasal 7 ayat (4); b. akta perubahan anggaran dasar Perseroan beserta keputusan menteri sebagaimana dimaksud dalam Pasal 21 ayat (1); c. akta perubahan anggaran dasar yang telah diterima pemberitahuannya oleh Menteri. (2) Pengumuman sebagaimana dimaksud pada ayat (1) dilakukan oleh Menteri dalam waktu paling lambat 14 (empat belas) hari terhitung sejak tanggal diterbitkannya keputusan Menteri sebagaimana dimaksud pada ayat (1) huruf a dan huruf b atau sejak diterimanya pemberitahuan sebagaimana dimaksud pada ayat (1) huruf c. (3) Ketentuan lebih lanjut mengenai tata cara pengumuman dilaksanakan sesuai dengan ketentuan peraturan perundang- undangan. BAB III MODAL DAN SAHAM Bagian Kesatu Modal"},{"l":"UU PT No.40/2007","p":"31","b":"","t":"(1) Modal dasar Perseroan terdiri atas seluruh nilai nominal saham. (2) Ketentuan sebagaimana dimaksud pada ayat (1) tidak menutup kemungkinan peraturan perundang-undangan di bidang pasar modal mengatur modal Perseroan terdiri atas saham tanpa nilai nominal."},{"l":"UU PT No.40/2007","p":"32","b":"","t":"(1) Modal dasar Perseroan paling sedikit Rp50.000.000,00 (lima puluh juta rupiah). (2) Undang-undang yang mengatur kegiatan usaha tertentu dapat menentukan jumlah minimum modal Perseroan yang lebih besar daripada ketentuan modal dasar sebagaimana dimaksud pada ayat (1). (3) Perubahan besarnya modal dasar sebagaimana dimaksud pada ayat (1), ditetapkan dengan peraturan pemerintah."},{"l":"UU PT No.40/2007","p":"33","b":"","t":"(1) Paling sedikit 25% (dua puluh lima persen) dari modal dasar sebagaimana dimaksud dalam Pasal 32 harus ditempatkan dan disetor penuh. - 10 - (2) Modal ditempatkan dan disetor penuh sebagaimana dimaksud pada ayat (1) dibuktikan dengan bukti penyetoran yang sah. (3) Pengeluaran saham lebih lanjut yang dilakukan setiap kali untuk menambah modal yang ditempatkan harus disetor penuh."},{"l":"UU PT No.40/2007","p":"34","b":"","t":"(1) Penyetoran atas modal saham dapat dilakukan dalam bentuk uang dan/atau dalam bentuk lainnya. (2) Dalam hal penyetoran modal saham dilakukan dalam bentuk lain sebagaimana dimaksud pada ayat (1), penilaian setoran modal saham ditentukan berdasarkan nilai wajar yang ditetapkan sesuai dengan harga pasar atau oleh ahli yang tidak terafiliasi dengan Perseroan. (3) Penyetoran saham dalam bentuk benda tidak bergerak harus diumumkan dalam 1 (satu) Surat Kabar atau lebih, dalam jangka waktu 14 (empat belas) hari setelah akta pendirian ditandatangani atau setelah RUPS memutuskan penyetoran saham tersebut."},{"l":"UU PT No.40/2007","p":"35","b":"","t":"(1) Pemegang saham dan kreditor lainnya yang mempunyai tagihan terhadap Perseroan tidak dapat menggunakan hak tagihnya sebagai kompensasi kewajiban penyetoran atas harga saham yang telah diambilnya, kecuali disetujui oleh RUPS. (2) Hak tagih terhadap Perseroan sebagaimana dimaksud pada ayat (1) yang dapat dikompensasi dengan setoran saha m adalah hak tagih atas tagihan terhadap Perseroan yang timbul karena: a. Perseroan telah menerima uang atau penyerahan benda berwujud atau benda tidak berwujud yang dapat dinilai dengan uang; b. pihak yang menjadi penanggung atau penjamin utang Perseroan telah membayar lunas utang Perseroan sebesar yang ditanggung atau dijamin; atau c. Perseroan menjadi penanggung atau penjamin utang dari pihak ketiga dan Perseroan telah menerima manfaat berupa uang atau barang yang dapat dinilai dengan uang yang langsung atau tidak langsung secara nyata telah diterima Perseroan. (3) Keputusan RUPS sebagaimana dimaksud pada ayat (1) sah apabila dilakukan sesuai dengan ketentuan mengenai panggilan rapat, kuorum, dan jumlah suara untuk perubahan anggaran dasar sebagaimana diatur dalam undang-undang ini dan/atau anggaran dasar."},{"l":"UU PT No.40/2007","p":"36","b":"","t":"(1) Perseroan dilarang mengeluarkan saham baik untuk dimiliki sendiri maupun dimiliki oleh Perseroan lain, yang sahamnya secara langsung atau tidak langsung telah dimiliki oleh Perseroan. (2) Ketentuan larangan kepemilikan saham sebagaimana dimaksud pada ayat (1) tidak berlaku terhadap kepemilikan saham yang diperoleh berdasarkan peralihan karena hukum, hibah, atau hibah wasiat. (3) Saham yang diperoleh berdasarkan ketentuan sebagaimana dimaksud pada ayat (2), dalam jangka waktu 1 (satu) tahun setelah tanggal perolehan harus dialihkan kepada pihak lain yang tidak di larang memiliki saham dalam Perseroan. (4) Dalam hal Perseroan lain sebagaimana dimaksud pada ayat (1) merupakan perusahaan efek, berlaku ketentuan peraturan perundang- undangan di bidang pasar modal. Bagian Kedua Perlindungan Modal dan Kekayaan Perseroan"},{"l":"UU PT No.40/2007","p":"37","b":"","t":"(1) Perseroan dapat membeli kembali saham yang telah dikeluarkan dengan ketentuan: a. pembelian kembali saham tersebut tidak menyebabkan kekayaan bersih Perseroan menjadi lebih kecil dari jumlah modal yang ditempatkan ditambah cadangan wajib yang telah disisihkan; dan b. jumlah nilai nominal seluruh saham yang dibeli kembali oleh Perseroan dan gadai saham atau jaminan fidusia atas saham yang dipegang oleh Perseroan sendiri dan/atau Perseroan lain yang sahamnya secara langsung atau tidak langsung dimiliki oleh Perseroan, tidak - 11 - melebihi 10% (sepuluh persen) dari jumlah modal yang ditempatkan dalam Perseroan, kecuali diatur lain dalam peraturan perundang-undangan di bidang pasar modal. (2) Pembelian kembali saham, baik secara langsung maupun tidak langsung, yang bertentangan dengan ayat (1) batal karena hukum. (3) Direksi secara tanggung renteng bertanggung jawab atas kerugian yang diderita pemegang saham yang beritikad baik, yang timbul akibat pembelian kembali yang batal karena hukum sebagaimana dimaksud pada ayat (2). (4) Saham yang dibeli kembali Perseroan sebagaimana dimaksud pada ayat (1) hanya boleh dikuasai Perseroan paling lama 3 (tiga) tahun."},{"l":"UU PT No.40/2007","p":"38","b":"","t":"(1) Pembelian kembali saham sebagaimana dimaksud dalam Pasal 37 ayat (1) atau pengalihannya lebih lanjut hanya boleh dilakukan berdasarkan persetujuan RUPS, kecuali ditentukan lain dalam peraturan perundang-undangan di bidang pasar modal. (2) Keputusan RUPS yang memuat persetujuan sebagaimana dimaksud pada ayat (1) sah apabila dilakukan sesuai dengan ketentuan mengenai panggilan rapat, kuorum, dan persetujuan jumlah suara untuk perubahan anggaran dasar sebagaimana diatur dalam undang-undang ini dan/atau anggaran dasar."},{"l":"UU PT No.40/2007","p":"39","b":"","t":"(1) RUPS dapat menyerahkan kewenangan kepada Dewan Komisaris guna menyetujui pelaksanaan keputusan RUPS sebagaimana dimaksud dalam Pasal 38 untuk jangka waktu paling lama 1 (satu) tahun. (2) Penyerahan kewenangan sebagaimana dimaksud pada ayat (1) setiap kali dapat diperpanjang untuk jangka waktu yang sama. (3) Penyerahan kewenangan sebagaimana dimaksud pada ayat (1) sewaktu-waktu dapat ditarik kembali oleh RUPS."},{"l":"UU PT No.40/2007","p":"40","b":"","t":"(1) Saham yang dikuasai Perseroan karena pembelian kembali, peralihan karena hukum, hibah atau hibah wasiat, tidak dapat digunakan untuk mengeluarkan suara dalam RUPS dan tidak diperhitungkan dalam menentukan jumlah kuorum yang harus dicapai sesuai dengan ketentuan undang- undang ini dan/atau anggaran dasar. (2) Saham sebagaimana dimaksud pada ayat (1) tidak berhak mendapat pembagian dividen. Bagian Ketiga Penambahan Modal"},{"l":"UU PT No.40/2007","p":"41","b":"","t":"(1) Penambahan modal Perseroan dilakukan berdasarkan persetujuan RUPS. (2) RUPS dapat menyerahkan kewenangan kepada Dewan Komisaris guna menyetujui pelaksanaan keputusan RUPS sebagaimana dimaksud pada ayat (1) untuk jangka waktu paling lama1 (satu) tahun. (3) Penyerahan kewenangan sebagaimana dimaksud pada ayat (2) sewaktu-waktu dapat ditarik kembali oleh RUPS."},{"l":"UU PT No.40/2007","p":"42","b":"","t":"(1) Keputusan RUPS untuk penambahan modal dasar adalah sah apabila dilakukan denga n memperhatikan persyaratan kuorum dan jumlah suara setuju untuk perubahan anggaran dasar sesuai dengan ketentuan dalam undang-undang ini dan/atau anggaran dasar. (2) Keputusan RUPS untuk penambahan modal ditempatkan dan disetor dalam batas modal dasar adalah sah apabila dilakukan dengan kuorum kehadiran lebih dari 1/2 (satu perdua) bagian dari seluruh jumlah saham dengan hak suara dan disetujui oleh lebih dari 1/2 (satu perdua) bagian dari jumlah seluruh suara yang dikeluarkan, kecuali ditentukan lebih besar dalam anggaran dasar. (3) Penambahan modal sebagaimana dimaksud pada ayat wajib diberitahukan kepada Menteri untuk dicatat dalam daftar Perseroan. - 12 -"},{"l":"UU PT No.40/2007","p":"43","b":"","t":"(1) Seluruh saham yang dikeluarkan untuk penambahan modal harus terlebih dahulu ditawarkan kepada setiap peme gang saham seimbang dengan pemilikan saham untuk klasifikasi saham yang sama. (2) Dalam hal saham yang akan dikeluarkan untuk penambahan modal merupakan saham yang klasifikasinya belum pernah dikeluarkan, yang berhak membeli terlebih dahulu adalah seluruh pemegang saham sesuai dengan perimbangan jumlah saham yang dimilikinya. (3) Penawaran sebagaimana dimaksud pada ayat (1) tidak berlaku dalam hal pengeluaran saham: a. ditujukan kepada karyawan Perseroan; b. ditujukan kepada pemegang obligasi atau efek lain yang dapat dikonversikan menjadi saham, yang telah dikeluarkan dengan persetujuan RUPS; atau c. dilakukan dalam rangka reorganisasi dan/atau restrukturisasi yang telah disetujui oleh RUPS. (4) Dalam hal pemegang saham sebagaimana dimaksud pada ayat (1) tidak menggunakan hak untuk membeli dan membayar lunas saham yang dibeli dalam jangka waktu 14 (empat belas) hari terhitung sejak tanggal penawaran, Perseroan dapat menawarkan sisa saham yang tidak diambil bagian tersebut kepada pihak ketiga. Bagian Keempat Pengurangan Modal"},{"l":"UU PT No.40/2007","p":"44","b":"","t":"(1) Keputusan RUPS untuk pengurangan modal Perseroan adalah sah apabila dilakukan dengan memperhatikan persyaratan ketentuan kuorum dan jumlah suara setuju untuk perubahan anggaran dasar sesuai ketentuan dalam undang-undang ini dan/atau anggaran dasar. (2) Direksi wajib memberitahukan keputusan sebagaimana dimaksud pada ayat (1) kepada semua kreditor dengan mengumumkan dalam 1 (satu) atau lebih surat kabar dalam jangka waktu paling lambat 7 (tujuh) hari terhitung sejak tanggal keputusan RUPS."},{"l":"UU PT No.40/2007","p":"45","b":"","t":"(1) Dalam jangka waktu 60 (enam puluh) hari terhitung sejak tanggal pengumuman sebagaimana dimaksud dalam Pasal 44 ayat (2), kreditor dapat mengajukan keberatan secara tertulis disertai alasannya kepada Perseroan atas keputusan pengurangan modal dengan tembusan kepada Menteri. (2) Dalam jangka waktu 30 (tiga puluh) hari terhitung sejak keberatan sebagaimana dimaksud pada ayat (1) diterima, Perseroan wajib memberikan jawaban secara tertulis atas keberatan yang diajukan. (3) Dalam hal Perseroan: a. menolak keberatan atau tidak memberikan penyelesaian yang disepakati kreditor dalam jangka waktu 30 (tiga puluh) hari terhitung sejak tanggal jawaban Perseroan diterima; atau b. tidak memberikan tanggapan dalam jangka waktu 60 (enam puluh) hari terhitung sejak tanggal keberatan diajukan kepada Perseroan, kreditor dapat mengajukan gugatan ke pengadilan negeri yang daerah hukumnya meliputi tempat kedudukan Perseroan."},{"l":"UU PT No.40/2007","p":"46","b":"","t":"(1) Pengurangan modal Perseroan merupakan perubahan anggaran dasar yang harus mendapat persetujuan Menteri. (2) Persetujuan Menteri sebagaimana dimaksud pada ayat (1) diberikan apabila: a. tidak terdapat keberatan tertulis dari kreditor dalam jangka waktu sebagaimana dimaksud dalam Pasal 45 ayat (1); b. telah dicapai penyelesaian atas keberatan yang diajukan kreditor; atau c. gugatan kreditor ditolak oleh pengadilan berdasarkan putusan yang telah memperoleh kekuatan hukum tetap. - 13 -"},{"l":"UU PT No.40/2007","p":"47","b":"","t":"(1) Keputusan RUPS tentang pengurangan modal ditempatkan dan disetor dilakukan dengan cara penarikan kembali saham atau penurunan nilai nominal saham. (2) Penarikan kembali saham sebagaimana dimaksud pada ayat (1) dilakukan terhadap saham yang telah dibeli kembali oleh Perseroan atau terhadap saham dengan klasifikasi yang dapat ditarik kembali. (3) Penurunan nilai nominal saham tanpa pembayaran kembali harus dilakukan secara seimbang terhadap seluruh saham dari setiap klasifikasi saham. (4) Keseimbangan sebagaimana dimaksud pada ayat (3) dapat dikecualikan dengan persetujuan semua pemegang saham yang nilai nominal sahamnya dikurangi. (5) Dalam hal terdapat lebih dari 1 (satu) klasifikasi saham, keputusan RUPS tentang pengurangan modal hanya boleh diambil setelah mendapat persetujuan terlebih dahulu dari semua pemegang saham dari setiap klasifikasi saham yang haknya dirugikan oleh keputusan RUPS tentang pengurangan modal tersebut. Bagian Kelima Saham"},{"l":"UU PT No.40/2007","p":"48","b":"","t":"(1) Saham Perseroan dikeluarkan atas nama pemiliknya. (2) Persyaratan kepemilikan saham dapat ditetapkan dalam anggaran dasar dengan memperhatikan persyaratan yang ditetapkan oleh instansi yang berwenang sesuai dengan ketentuan peraturan perundang- undangan. (3) Dalam hal persyaratan kepemilikan saham sebagaimana dimaksud pada ayat (2) telah ditetapkan dan tidak dipenuhi, pihak yang memperoleh kepemilikan saham tersebut tidak dapat menjalankan hak selaku pemegang saham dan saham tersebut tidak diperhitungkan dalam kuorum yang harus dicapai sesuai dengan ketentuan undang- undang ini dan/atau anggaran dasar."},{"l":"UU PT No.40/2007","p":"49","b":"","t":"(1) Nilai saham harus dicantumkan dalam mata uang rupiah. (2) Saham tanpa nilai nominal tidak dapat dikeluarkan. (3) Ketentuan sebagaimana dimaksud pada ayat (2) tidak menutup kemungkinan diaturnya pengeluaran saham tanpa nilai nominal dalam peraturan perundang-undangan di bidang pasar modal."},{"l":"UU PT No.40/2007","p":"50","b":"","t":"(1) Direksi Perseroan wajib mengadakan dan menyimpan daftar pemegang saham, yang memuat sekurang-kurangnya: a. nama dan alamat pemegang saham; b. jumlah, nomor, tanggal perolehan saham yang dimiliki pemegang saham, dan klasifikasinya dalam hal dikeluarkan lebih dari satu klasifikasi saham; c. jumlah yang disetor atas setiap saham; d. nama dan alamat dari orang perseorangan atau badan hukum yang mempunyai hak gadai atas saham atau sebagai penerima jaminan fidusia saham dan tanggal perolehan hak gadai atau tanggal pendaftaran jaminan fidusia tersebut; e. keterangan penyetoran saham dalam bentuk lain sebagaimana dimaksud dalam Pasal 34 ayat (2). (2) Selain daftar pemegang saham sebagaimana dimaksud pada ayat (1), Direksi Perseroan wajib mengadakan dan menyimpan daftar khusus yang memuat keterangan mengenai saham anggota Direksi dan Dewan Komisaris beserta keluarganya dalam Perseroan dan/atau pada Perseroan lain serta tanggal saham itu diperoleh. (3) Dalam daftar pemegang saham dan daftar khusus sebagaimana dimaksud pada ayat (1) dan ayat (2) dicatat juga setiap perubahan kepemilikan saham. (4) Daftar pemegang saham dan daftar khusus sebagaimana dimaksud pada ayat (1) dan ayat (2) disediakan di tempat kedudukan Perseroan agar dapat dilihat oleh para pemegang saham. - 14 - (5) Dalam hal peraturan perundang-undangan di bidang pasar modal tidak mengatur lain, ketentuan sebagaimana dimaksud pada ayat (1), ayat (3), dan ayat (4) berlaku juga bagi Perseroan Terbuka."},{"l":"UU PT No.40/2007","p":"51","b":"","t":"Pemegang saham diberi bukti pemilikan saham untuk saham yang dimilikinya."},{"l":"UU PT No.40/2007","p":"52","b":"","t":"(1) Saham memberikan hak kepada pemiliknya untuk: a. menghadiri dan mengeluarkan suara dalam RUPS; b. menerima pembayaran dividen dan sisa kekayaan hasil likuidasi; c. menjalankan hak lainnya berdasarkan undang- undang ini. (2) Ketentuan sebagaimana dimaksud pada ayat (1) berlaku setelah saham dicatat dalam daftar pemegang saham atas nama pemiliknya. (3) Ketentuan sebagaimana dimaksud pada ayat (1) huruf a dan huruf c tidak berlaku bagi klasifikasi saham tertentu sebagaimana ditetapkan dalam undang- undang ini. (4) Setiap saham memberikan kepada pemiliknya hak yang tidak dapat dibagi. (5) Dalam hal 1 (satu) saham dimiliki oleh lebih dari 1 (satu) orang, hak yang timbul dari saham tersebut digunakan dengan cara menunjuk 1 (satu) orang sebagai wakil bersama."},{"l":"UU PT No.40/2007","p":"53","b":"","t":"(1) Anggaran dasar menetapkan 1 (satu) klasifikasi saham atau lebih. (2) Setiap saham dalam klasifikasi yang sama me mberikan kepada pemegangnya hak yang sama. (3) Dalam hal terdapat lebih dari 1 (satu) klasifikasi saham, anggaran dasar menetapkan salah satu di antaranya sebagai saham biasa. (4) Klasifikasi saham sebagaimana dimaksud pada ayat (3), antara lain: a. saham dengan hak suara atau tanpa hak suara; b. saham dengan hak khusus untuk mencalonkan anggota Direksi dan/atau anggota Dewan Komisaris; c. saham yang setelah jangka waktu tertentu ditarik kembali atau ditukar dengan klasifikasi saham lain; d. saham yang memberikan hak kepada pemegangnya untuk menerima dividen lebih dahulu dari pemegang saham klasifikasi lain atas pembagian dividen secara kumulatif atau nonkumulatif; e. saham yang memberikan hak kepada pemegangnya untuk menerima lebih dahulu dari pemegang saham klasifikasi lain atas pembagian sisa kekayaan Perseroan dalam likuidasi."},{"l":"UU PT No.40/2007","p":"54","b":"","t":"(1) Anggaran dasar dapat menentukan pecahan nilai nominal saham. (2) Pemegang pecahan nilai nominal saham tidak diberikan hak suara perseorangan, kecuali pemegang pecahan nilai nominal saham, baik sendiri atau bersama pemegang pecahan nilai nominal saham lainnya yang klasifikasi sahamnya sama memiliki nilai nominal sebesar 1 (satu) nominal saham dari klasifikasi tersebut. (3) Ketentuan sebagaimana dimaksud dalam Pasal 52 ayat (4) dan ayat (5) mutatis mutandis berlaku bagi pemegang pecahan nilai nominal saham."},{"l":"UU PT No.40/2007","p":"55","b":"","t":"Dalam anggaran dasar Perseroan ditentukan cara pemindahan hak atas saham sesuai dengan ketentuan peraturan perundang- undangan."},{"l":"UU PT No.40/2007","p":"56","b":"","t":"(1) Pemindahan hak atas saham dilakukan dengan akta pemindahan hak. (2) Akta pemindahan hak sebagaimana dimaksud pada ayat (1) atau salinannya disampaikan secara tertulis kepada Perseroan. (3) Direksi wajib mencatat pemindahan hak atas saham, tanggal, dan hari pemindahan hak tersebut dalam daftar pemegang saham atau daftar khusus sebagaimana dimaksud dalam - 15 - Pasal 50 ayat (1) dan ayat (2) dan memberitahukan perubahan susunan pemegang saham kepada Menteri untuk dicatat dalam daftar Perseroan paling lambat 30 (tiga puluh) hari terhitung sejak tanggal pencatatan pemindahan hak. (4) Dalam hal pemberitahuan sebagaimana dimaksud pada ayat (3) belum dilakukan, Menteri menolak permohonan persetujuan atau pemberitahuan yang dilaksanakan berdasarkan susunan dan nama pemegang saham yang belum diberitahukan tersebut. (5) Ketentuan mengenai tata cara pemindahan hak atas saham yang diperdagangkan di pasar modal diatur dalam peraturan perundang- undangan di bidang pasar modal."},{"l":"UU PT No.40/2007","p":"57","b":"","t":"(1) Dalam anggaran dasar dapat diatur persyaratan mengenai pemindahan hak atas saham, yaitu: a. keharusan menawarkan terlebih dahulu kepada pemegang saham dengan klasifikasi tertentu atau pemegang saham lainnya; b. keharusan mendapatkan persetujuan terlebih dahulu dari Organ Perseroan; dan/atau c. keharusan mendapatkan persetujuan terlebih dahulu dari instansi yang berwenang sesuai dengan ketentuan peraturan perundang- undangan. (2) Persyaratan sebagaimana dimaksud pada ayat (1) tidak berlaku dalam hal pemindahan hak atas saham disebabkan peralihan hak karena hukum, kecuali keharusan sebagaimana dimaksud pada ayat (1) huruf c berkenaan dengan kewarisan."},{"l":"UU PT No.40/2007","p":"58","b":"","t":"(1) Dalam hal anggaran dasar mengharuskan pemegang saham penjual menawarkan terlebih dahulu sahamnya kepada pemegang saham klasifikasi tertentu atau pemegang saham lain, dan dalam jangka waktu 30 (tiga puluh hari) terhitung sejak tanggal penawaran dilakukan ternyata pemegang saham tersebut tidak membeli, pemegang saham penjual dapat menawarkan dan menjual sahamnya kepada pihak ketiga. (2) Setiap pemegang saham penjual yang diharuskan menawarkan sahamnya sebagaimana dimaksud pada ayat (1) berhak menarik kembali penawaran tersebut, setelah lewatnya jangka waktu 30 (tiga puluh) hari sebagaimana dimaksud pada ayat (1). (3) Kewajiban menawarkan kepada pemegang saham klasifikasi tertentu atau pemegang saham lain sebagaimana dimaksud pada ayat (1) hanya berlaku 1 (satu) kali."},{"l":"UU PT No.40/2007","p":"59","b":"","t":"(1) Pemberian persetujuan pemindahan hak atas saham yang memerlukan persetujuan Organ Perseroan atau penolakannya harus diberikan secara tertulis dalam jangka waktu paling lama 90 (sembilan puluh) hari terhitung sejak tangga l Organ Perseroan menerima permintaan persetujuan pemindahan hak tersebut. (2) Dalam hal jangka waktu sebagaimana dimaksud pada ayat (1) telah lewat dan Organ Perseroan tidak memberikan pernyataan tertulis, Organ Perseroan dianggap menyetujui pemindahan hak atas saham tersebut. (3) Dalam hal pemindahan hak atas saham disetujui oleh Organ Perseroan, pemindahan hak harus dilakukan sesuai dengan ketentuan sebagaimana dimaksud dalam Pasal 56 dan dilakukan dalam jangka waktu paling lama 90 (sembilan puluh) hari terhitung sejak tanggal persetujuan diberikan."},{"l":"UU PT No.40/2007","p":"60","b":"","t":"(1) Saham merupakan benda bergerak dan memberikan hak sebagaimana dimaksud dalam Pasal 52 kepada pemiliknya. (2) Saham dapat diagunkan dengan gadai atau jaminan fidusia sepanjang tidak ditentukan lain dalam anggaran dasar. (3) Gadai saham atau jaminan fidusia atas saham yang telah didaftarkan sesuai dengan ketentuan peraturan perundang- undangan wajib dicatat dalam daftar pemegang saham dan daftar khusus sebagaimana dimaksud dalam Pasal 50. (4) Hak suara atas saham yang diagunkan dengan gadai atau jaminan fidusia tetap berada pada pemegang saham. - 16 -"},{"l":"UU PT No.40/2007","p":"61","b":"","t":"(1) Setiap pemegang saham berhak mengajukan gugatan terhadap Perseroan ke pengadilan negeri apabila dirugikan karena tindakan Perseroan yang dianggap tidak adil dan tanpa alasan wajar sebagai akibat keputusan RUPS, Direksi, dan/atau Dewan Komisaris. (2) Gugatan sebagaimana dimaksud pada ayat (1) diajukan ke pengadilan negeri yang daerah hukumnya meliputi tempat kedudukan Perseroan."},{"l":"UU PT No.40/2007","p":"62","b":"","t":"(1) Setiap pemegang saham berhak meminta kepada Perseroan agar sahamnya dibeli dengan harga yang wajar apabila yang bersangkutan tidak menyetujui tindakan Perseroan yang merugikan pemegang saham atau Perseroan, berupa: a. perubahan anggaran dasar; b. pengalihan atau penjaminan kekayaan Perseroan yang mempunyai nilai lebih dari 50% (lima puluh persen) kekayaan bersih Perseroan; atau c. penggabungan, peleburan, pengambilalihan, atau pemisahan. (3) Dalam hal saham yang diminta untuk dibeli sebagaimana dimaksud pada ayat (1) melebihi batas ketentuan pembelian kembali saham oleh Perseroan sebagaimana dimaksud dalam Pasal 37 ayat (1) huruf b, Perseroan wajib mengusahakan agar sisa saham dibeli oleh pihak ketiga. BAB IV RENCANA KERJA, LAPORAN TAHUNAN, DAN PENGGUNAAN LABA Bagian Kesatu Rencana Kerja"},{"l":"UU PT No.40/2007","p":"63","b":"","t":"(1) Direksi menyusun rencana kerja tahunan sebelum dimulainya tahun buku yang akan datang. (2) Rencana kerja sebagaimana dimaksud pada ayat (1) memuat juga anggaran tahunan Perseroan untuk tahun buku yang akan datang."},{"l":"UU PT No.40/2007","p":"64","b":"","t":"(1) Rencana kerja sebagaimana dimaksud dalam Pasal 63 disampaikan kepada Dewan Komisaris atau RUPS sebagaimana ditentukan dalam anggaran dasar. (2) Anggaran dasar dapat menentukan rencana kerja yang disampaikan oleh Direksi sebagaimana dimaksud pada ayat (1) harus mendapat persetujuan Dewan Komisaris atau RUPS, kecuali ditentukan lain dalam peraturan perundang-undangan. (3) Dalam hal anggaran dasar menentukan rencana kerja harus mendapat persetujuan RUPS, rencana kerja tersebut terlebih dahulu harus ditelaah Dewan Komisaris."},{"l":"UU PT No.40/2007","p":"65","b":"","t":"(1) Dalam hal Direksi tidak menyampaikan rencana kerja sebagaimana dimaksud dalam Pasal 64, rencana kerja tahun yang lampau diberlakukan. (2) Rencana kerja tahun yang lampau berlaku juga bagi Perseroan yang rencana kerjanya belum memperoleh persetujuan sebagaimana ditentukan dalam anggaran dasar atau peraturan perundang-undangan. Bagian Kedua Laporan Tahunan"},{"l":"UU PT No.40/2007","p":"66","b":"","t":"(1) Direksi menyampaikan laporan tahunan kepada RUPS setelah ditelaah oleh Dewan Komisaris dalam jangka waktu paling lambat 6 (enam) bulan setelah tahun buku Perseroan berakhir. (2) Laporan tahunan sebagaimana dimaksud pada ayat (1) harus memuat sekurang-kurangnya: - 17 - a. laporan keuangan yang terdiri atas sekurang-kurangnya neraca akhir tahun buku yang baru lampau dalam perbandingan dengan tahun buku sebelumnya, laporan laba rugi dari tahun buk u yang bersangkutan, laporan arus kas, dan laporan perubahan ekuitas, serta catatan atas laporan keuangan tersebut; b. laporan mengenai kegiatan Perseroan; c. laporan pelaksanaan Tanggung Jawab Sosial dan Lingkungan; d. rincian masalah yang timbul selama tahun buku yang mempengaruhi kegiatan usaha Perseroan; e. laporan mengenai tugas pengawasan yang telah dilaksanakan oleh Dewan Komisaris selama tahun buku yang baru lampau; f. nama anggota Direksi dan anggota Dewan Komisaris; g. gaji dan tunjangan bagi anggota Direksi dan gaji atau honorarium dan tunjangan bagi anggota Dewan Komisaris Perseroan untuk tahun yang baru lampau. (3) Laporan keuangan sebagaimana dimaksud pada ayat (2) huruf a disusun berdasarkan standar akuntansi keuangan. (4) Neraca dan laporan laba rugi dari tahun buku yang bersangkutan sebagaimana dimaksud pada ayat (2) huruf a bagi Perseroan yang wajib diaudit, harus disampaikan kepada Menteri sesuai dengan ketentuan peraturan perundang-undangan."},{"l":"UU PT No.40/2007","p":"67","b":"","t":"(1) Laporan tahunan sebagaimana dimaksud dalam Pasal 66 ayat (1) ditandatangani oleh semua anggota Direksi dan semua anggota Dewan Komisaris yang menjabat pada tahun buku yang bersangkutan dan disediakan di kantor Perseroan sejak tanggal panggilan RUPS untuk dapat diperiksa oleh pemegang saham. (2) Dalam hal terdapat anggota Direksi atau anggota Dewan Komisaris yang tidak menandatangani laporan tahunan sebagaimana dimaksud pada ayat (1), yang bersangkutan harus menyebutkan alasannya secara tertulis, atau alasan tersebut dinyatakan oleh Direksi dalam surat tersendiri yang dilekatkan dalam laporan tahunan. (3) Dalam hal terdapat anggota Direksi atau anggota Dewan Komisaris yang tidak menandatangani laporan tahunan sebagaimana dimaksud pada ayat (1) dan tidak memberi alasan secara tertulis, yang bersangkutan dianggap telah menyetujui isi laporan tahunan."},{"l":"UU PT No.40/2007","p":"68","b":"","t":"(1) Direksi wajib menyerahkan laporan keuangan Perseroan kepada akuntan publik untuk diaudit apabila: a. kegiatan usaha Perseroan adalah menghimpun dan/atau mengelola dana masyarakat; b. Perseroan menerbitkan surat pengakuan utang kepada masyarakat; c. Perseroan merupakan Perseroan Terbuka; d. Perseroan merupakan persero; e. Perseroan mempunyai aset dan/atau jumlah peredaran usaha dengan jumlah nilai paling sedikit Rp50.000.000.000,00 (lima puluh miliar rupiah); atau f. diwajibkan oleh peraturan perundang-undangan. (2) Dalam hal kewajiban sebagaimana dimaksud pada ayat (1) tidak dipenuhi, laporan keuangan tidak disahkan oleh RUPS. (3) Laporan atas hasil audit akuntan publik sebagaimana dimaksud pada ayat (1) disampaikan secara tertulis kepada RUPS melalui Direksi. (4) Neraca dan laporan laba rugi dari laporan keuangan sebagaimana dimaksud pada ayat (1) huruf a, huruf b, dan huruf c setelah mendapat pengesahan RUPS diumumkan dalam 1 (satu) surat kabar. (5) Pengumuman neraca dan laporan laba rugi sebagaimana dimaksud pada ayat (4) dilakukan paling lambat 7 (tujuh) hari setelah mendapat pengesahan RUPS. (6) Pengurangan besarnya jumlah nilai sebagaimana dimaksud pada ayat (1) huruf e ditetapkan dengan peraturan pemerintah."},{"l":"UU PT No.40/2007","p":"69","b":"","t":"(1) Persetujuan laporan tahunan termasuk pengesahan laporan keuangan serta laporan tugas pengawasan Dewan Komisaris dilakukan oleh RUPS. - 18 - (2) Keputusan atas pengesahan laporan keuangan dan persetujuan laporan tahunan sebagaimana dimaksud pada ayat (1) ditetapkan berdasarkan ketentuan dalam undang- undang ini dan/atau anggaran dasar. (3) Dalam hal laporan keuangan yang disediakan ternyata tidak benar dan/atau menyesatkan, anggota Direksi dan anggota Dewan Komisaris secara tanggung renteng bertanggung jawab terhadap pihak yang dirugikan. (4) Anggota Direksi dan anggota Dewan Komisaris dibebaskan dari tanggung jawab sebagaimana dimaksud pada ayat (3) apabila terbukti bahwa keadaan tersebut bukan karena kesalahannya. Bagian Ketiga Penggunaan Laba"},{"l":"UU PT No.40/2007","p":"70","b":"","t":"(1) Perseroan wajib menyisihkan jumlah tertentu dari laba bersih setiap tahun buku untuk cadangan. (2) Kewajiban penyisihan untuk cadangan sebagaimana dimaksud pada ayat (1) berlaku apabila Perseroan mempunyai saldo laba yang positif. (3) Penyisihan laba bersih sebagaimana dimaksud pada ayat (1) dilakukan sampai cadangan mencapai paling sedikit 20% (dua puluh persen) dari jumlah modal yang ditempatkan dan disetor. (4) Cadangan sebagaimana dimaksud pada ayat (1) yang belum mencapai jumlah sebagaimana dimaksud pada ayat (3) hanya boleh dipergunakan untuk menutup kerugian yang tidak dapat dipenuhi oleh cadangan lain."},{"l":"UU PT No.40/2007","p":"71","b":"","t":"(1) Penggunaan laba bersih termasuk penentuan jumlah penyisihan untuk cadangan sebagaimana dimaksud dalam Pasal 70 ayat (1) diputuskan oleh RUPS. (2) Seluruh laba bersih setelah dikurangi penyisihan untuk cadangan sebagaimana dimaksud dalam Pasal 70 ayat (1) dibagikan kepada pemegang saham sebagai dividen, kecuali ditentukan lain dalam RUPS. (3) Dividen sebagaimana dimaksud pada ayat (2) hanya boleh dibagikan apabila Perseroan mempunyai saldo laba yang positif."},{"l":"UU PT No.40/2007","p":"72","b":"","t":"(1) Perseroan dapat membagikan dividen interim sebelum tahun buku Perseroan berakhir sepanjang diatur dalam anggaran dasar Perseroan. (2) Pembagian dividen interim sebagaimana dimaksud pada ayat (1) dapat dilakukan apabila jumlah kekayaan bersih Perseroan tidak menjadi lebih kecil daripada jumlah modal ditempatkan dan disetor ditambah cadangan wajib. (3) Pembagian dividen interim sebagaimana dimaksud pada ayat (2) tidak boleh mengganggu atau menyebabkan Perseroan tidak dapat memenuhi kewajibannya pada kreditor atau mengganggu kegiatan Perseroan. (4) Pembagian dividen interim ditetapkan berdasarkan keputusan Direksi setelah memperoleh persetujuan Dewan Komisaris, dengan memperhatikan ketentuan pada ayat (2) dan ayat (3). (5) Dalam hal setelah tahun buku berakhir ternyata Perseroan menderita kerugian, dividen interim yang telah dibagikan harus dikembalikan oleh pemegang saham kepada Perseroan. (6) Direksi dan Dewan Komisaris bertanggung jawab secara tanggung renteng atas kerugian Perseroan, dalam hal pemegang saham tidak dapat mengembalikan dividen interim sebagaimana dimaksud pada ayat (5)."},{"l":"UU PT No.40/2007","p":"73","b":"","t":"(1) Dividen yang tidak diambil setelah 5 (lima) tahun terhitung sejak tanggal yang ditetapkan untuk pembayaran dividen lampau, dimasukkan ke dalam cadangan khusus. (2) RUPS mengatur tata cara pengambilan dividen yang telah dimasukkan ke dalam cadangan khusus sebagaimana dimaksud pada ayat (1). - 19 - (3) Dividen yang telah dimasukkan dalam cadangan khusus sebagaimana dimaksud pada ayat (1) dan tidak diambil dalam jangka waktu 10 (sepuluh) tahun akan menjadi hak Perseroan. BAB V TANGGUNG JAWAB SOSIAL DAN LINGKUNGAN"},{"l":"UU PT No.40/2007","p":"74","b":"","t":"(1) Perseroan yang menjalankan kegiatan usahanya di bidang dan/atau berkaitan dengan sumber daya alam wajib melaksanakan Tanggung Jawab Sosial dan Lingkungan. (2) Tanggung Jawab Sosial dan Lingkungan sebagaimana dimaksud pada ayat (1) merupakan kewajiban Perseroan yang dianggarkan dan diperhitungkan sebagai biaya Perseroan yang pelaksanaannya dilakukan dengan memperhatikan kepatutan dan kewajaran. (3) Perseroan yang tidak melaksanakan kewajiban sebagaimana dimaksud pada ayat (1) dikenai sanksi sesuai dengan ketentuan peraturan perundang-undangan. (4) Ketentuan lebih lanjut mengenai Tanggung Jawab Sosial dan Lingkungan diatur dengan peraturan pemerintah. BAB VI RAPAT UMUM PEMEGANG SAHAM"},{"l":"UU PT No.40/2007","p":"75","b":"","t":"(1) RUPS mempunyai wewenang yang tidak diberikan kepada Direksi atau Dewan Komisaris, dalam batas yang ditentukan dalam undang-undang ini dan/atau anggaran dasar. (2) Dalam forum RUPS, pemegang saham berhak memperoleh keterangan yang berkaitan dengan Perseroan dari Direksi dan/atau Dewan Komisaris, sepanjang berhubungan dengan mata acara rapat dan tidak bertentangan dengan kepentingan Perseroan. (3) RUPS dalam mata acara lain- lain tidak berhak mengambil keputusan, kecuali semua pemegang saham hadir dan/atau diwakili dalam RUPS dan me nyetujui penambahan mata acara rapat. (4) Keputusan atas mata acara rapat yang ditambahkan harus disetujui dengan suara bulat."},{"l":"UU PT No.40/2007","p":"76","b":"","t":"(1) RUPS diadakan di tempat kedudukan Perseroan atau di tempat Perseroan melakukan kegiatan usahanya yang utama sebagaimana ditentukan dalam anggaran dasar. (2) RUPS Perseroan Terbuka dapat diadakan di tempat kedudukan bursa di mana saham Perseroan dicatatkan. (3) Tempat RUPS sebagaimana dimaksud pada ayat (1) dan ayat (2) harus terletak di wilayah negara Republik Indonesia. (4) Jika dalam RUPS hadir dan/atau diwakili semua pemegang saham dan semua pemegang saham menyetujui diadakannya RUPS dengan agenda tertentu, RUPS dapat diadakan di manapun dengan memperhatikan ketentuan sebagaimana dimaksud pada ayat (3). (5) RUPS sebagaimana dimaksud pada ayat (4) dapat mengambil keputusan jika keputusan tersebut disetujui dengan suara bulat."},{"l":"UU PT No.40/2007","p":"77","b":"","t":"(1) Selain penyelenggaraan RUPS sebagaimana dimaksud dalam Pasal 76, RUPS dapat juga dilakukan melalui media telekonferensi, video konferensi, atau sarana media elektronik lainnya yang memungkinkan semua peserta RUPS saling melihat dan mendengar secara langsung serta berpartisipasi dalam rapat. (2) Persyaratan kuorum dan persyaratan pengambilan keputusan adalah persyaratan sebagaimana diatur dalam undang-undang ini dan/atau sebagaimana diatur dalam anggaran dasar Perseroan. (3) Persyaratan sebagaimana dimaksud pada ayat (2) dihitung berdasarkan keikutsertaan peserta RUPS sebagaimana dimaksud pada ayat (1). (4) Setiap penyelenggaraan RUPS sebagaimana dimaksud pada ayat (1) harus dibuatkan risalah rapat yang disetujui dan ditandatangani oleh semua peserta RUPS. - 20 -"},{"l":"UU PT No.40/2007","p":"78","b":"","t":"(1) RUPS terdiri atas RUPS tahunan dan RUPS lainnya. (2) RUPS tahunan wajib diadakan dalam jangka waktu paling lambat 6 (enam) bulan setelah tahun buku berakhir. (3) Dalam RUPS tahunan, harus diajukan semua dokumen dari laporan tahunan Perseroan sebagaimana dimaksud dalam Pasal 66 ayat (2). (4) RUPS lainnya dapat diadakan setiap waktu berdasarkan kebutuhan untuk kepentingan Perseroan."},{"l":"UU PT No.40/2007","p":"79","b":"","t":"(1) Direksi menyelenggarakan RUPS tahunan sebagaimana dimaksud dalam Pasal 78 ayat (2) dan RUPS lainnya sebagaimana dimaksud dalam Pasal 78 ayat (4) dengan didahului pemanggilan RUPS. (2) Penyelenggaraan RUPS sebagaimana dimaksud pada ayat (1) dapat dilakukan atas permintaan: a. 1 (satu) orang atau lebih pemegang saham yang bersama-sama mewakili 1/10 (satu persepuluh) atau lebih dari jumlah seluruh saham dengan hak suara, kecuali anggaran dasar menentukan suatu jumlah yang lebih kecil; atau b. Dewan Komisaris. (3) Permintaan sebagaimana dimaksud pada ayat (2) diajukan kepada Direksi dengan Surat Tercatat disertai alasannya. (4) Surat Tercatat sebagaimana dimaksud pada ayat (3) yang disampaikan oleh pemegang saham tembusannya disampaikan kepada Dewan Komisaris. (5) Direksi wajib melakukan pemanggilan RUPS dalam jangka waktu paling lambat 15 (lima belas) hari terhitung sejak tanggal permintaan penyelenggaraan RUPS diterima. (6) Dalam hal Direksi tidak melakukan pemanggilan RUPS sebagaimana dimaksud pada ayat (5): a. Permintaan penyelenggaraan RUPS sebagaimana dimaksud pada ayat (2) huruf a diajukan kembali kepada Dewan Komisaris; atau b. Dewan Komisaris melakukan pemanggilan sendiri RUPS, sebagaimana dimaksud pada ayat (2) huruf b. (7) Dewan Komisaris wajib melakukan pemanggilan RUPS sebagaimana dimaksud pada ayat huruf a dalam jangka waktu paling lambat 15 (lima belas) hari terhitung sejak tanggal permintaan penyelenggaraan RUPS diterima. (8) RUPS yang diselenggarakan Direksi berdasarkan panggilan RUPS sebagaimana dimaksud pada ayat (5) membicarakan masalah yang berkaitan dengan alasan sebaga imana dimaksud pada ayat (3) dan mata acara rapat lainnya yang dipandang perlu oleh Direksi. (9) RUPS yang diselenggarakan Dewan Komisaris berdasarkan panggilan RUPS sebagaimana dimaksud pada ayat (6) huruf b dan ayat (7) hanya membicarakan masalah yang berkaitan dengan alasan sebagaimana dimaksud pada ayat (3). (10) Penyelenggaraan RUPS Perseroan Terbuka tunduk pada ketentuan undang-undang ini sepanjang ketentuan peraturan perundang-undangan di bidang pasar modal tidak menentukan lain."},{"l":"UU PT No.40/2007","p":"80","b":"","t":"(1) Dalam hal Direksi atau Dewan Komisaris tidak melakukan pemanggilan RUPS dalam jangka waktu sebagaimana dimaksud dalam Pasal 79 ayat (5) dan ayat (7), pemegang saham yang meminta penyelenggaraan RUPS dapat mengajukan permohonan kepada ketua pengadilan negeri yang daerah hukumnya meliputi tempat kedudukan Perseroan untuk menetapkan pemberian izin kepada pemohon melakukan sendiri pemanggilan RUPS tersebut. (2) Ketua pengadilan negeri setelah memanggil dan mendengar pemohon, Direksi dan/atau Dewan Komisaris, menetapkan pemberian izin untuk menyelenggarakan RUPS apabila pemohon secara sumir telah membuktikan bahwa persyaratan telah dipenuhi dan pemohon mempunyai kepentingan yang wajar untuk diselenggarakannya RUPS. (3) Penetapan ketua pengadilan negeri sebagaimana dimaksud pada ayat (2) memuat juga ketentuan mengenai: - 21 - a. bentuk RUPS, mata acara RUPS sesuai dengan permohonan pemegang saham, jangka waktu pemanggilan RUPS, kuorum kehadiran, dan/atau ketentuan tentang persyaratan pengambilan keputusan RUPS, serta penunjukan ketua rapat, sesuai dengan atau tanpa terikat pada ketentuan undang- undang ini atau anggaran dasar; dan/atau b. perintah yang mewajibkan Direksi dan/atau Dewan Komisaris untuk hadir dalam RUPS. (4) Ketua pengadilan negeri menolak permohonan dalam hal pemohon tidak dapat membuktikan secara sumir bahwa persyaratan telah dipenuhi dan pemohon mempunyai kepentingan yang wajar untuk diselenggarakannya RUPS. (5) RUPS sebagaimana dimaksud pada ayat (1) hanya boleh membicarakan mata acara rapat sebagaimana ditetapkan oleh ketua pengadilan negeri. (6) Penetapan ketua pengadilan negeri mengenai pemberian izin sebagaimana dimaksud pada ayat (3) bersifat final dan mempunyai kekuatan hukum tetap. (7) Dalam hal penetapan ketua pengadilan negeri menolak permohonan sebagaimana dimaksud pada ayat (4), upaya hukum yang dapat diajukan hanya kasasi. (8) Ketentuan sebagaimana dimaksud pada ayat (1) berlaku juga bagi Perseroan Terbuka dengan memperhatikan persyaratan pengumuman akan diadakannya RUPS dan persyaratan lainnya untuk penyelenggaraan RUPS sebagaimana diatur dalam peraturan perundang- undangan di bidang pasar modal."},{"l":"UU PT No.40/2007","p":"81","b":"","t":"(1) Direksi melakukan pemanggilan kepada pemegang saham sebelum menyelenggarakan RUPS. (2) Dalam hal tertentu, pemanggilan RUPS sebagaimana dimaksud pada ayat (1) dapat dilakukan oleh Dewan Komisaris atau pemegang saham berdasarkan penetapan ketua pengadilan negeri."},{"l":"UU PT No.40/2007","p":"82","b":"","t":"(1) Pemanggilan RUPS dilakukan dalam jangka waktu paling lambat 14 (empat belas) hari sebelum tanggal RUPS diadakan, dengan tidak memperhitungkan tanggal pemanggilan dan tanggal RUPS. (2) Pemanggilan RUPS dilakukan dengan Surat Tercatat dan/atau dengan iklan dalam Surat Kabar. (3) Dalam panggilan RUPS dicantumkan tanggal, waktu, tempat, dan mata acara rapat disertai pemberitahuan bahwa bahan yang akan dibicarakan dalam RUPS tersedia di kantor Perseroan sejak tanggal dilakukan pemanggilan RUPS sampai dengan tanggal RUPS diadakan. (4) Perseroan wajib memberikan salinan bahan sebagaimana dimaksud pada ayat (3) kepada pemegang saham secara cuma-cuma jika diminta. (5) Dalam hal pemanggilan tidak sesuai dengan ketentuan sebagaimana dimaksud pada ayat (1) dan ayat (2), dan panggilan tidak sesuai dengan ketentuan ayat (3), keputusan RUPS tetap sah jika semua pemegang saham dengan hak suara hadir atau diwakili dalam RUPS dan keputusan tersebut disetujui dengan suara bulat."},{"l":"UU PT No.40/2007","p":"83","b":"","t":"(1) Bagi Perseroan Terbuka, sebelum pemanggilan RUPS dilakukan wajib didahului dengan pengumuman mengenai akan diadakan pemanggilan RUPS dengan memperhatikan peraturan perundang-undangan di bidang pasar modal. (2) Pengumuman sebagaimana dimaksud pada ayat (1) dilakukan dalam jangka waktu paling lambat 14 (empat belas) hari sebelum pemanggilan RUPS."},{"l":"UU PT No.40/2007","p":"84","b":"","t":"(1) Setiap saham yang dikeluarkan mempunyai satu hak suara, kecuali anggaran dasar menentukan lain. (2) Hak suara sebagaimana dimaksud pada ayat (1) tidak berlaku untuk: a. saham Perseroan yang dikuasai sendiri oleh Perseroan; b. saham induk Perseroan yang dikuasai oleh anak perusahaannya secara langsung atau tidak langsung; atau - 22 - c. saham Perseroan yang dikuasai oleh Perseroan lain yang sahamnya secara langsung atau tidak langsung telah dimiliki oleh Perseroan."},{"l":"UU PT No.40/2007","p":"85","b":"","t":"(1) Pemegang saham, baik sendiri maupun diwakili berdasarkan surat kuasa berhak menghadiri RUPS dan menggunakan hak suaranya sesuai dengan jumlah saham yang dimilikinya. (2) Ketentuan sebagaimana dimaksud pada ayat (1) tidak berlaku bagi pemegang saham dari saham tanpa hak suara. (3) Dalam pemungutan suara, suara yang dikeluarkan oleh pemegang saham berlaku untuk seluruh saham yang dimilikinya dan pemegang saham tidak berhak memberikan kuasa kepada lebih dari seorang kuasa untuk sebagian dari jumlah saham yang dimilikinya dengan suara yang berbeda. (4) Dalam pemungutan suara, anggota Direksi, anggota Dewan Komisaris, dan karyawan Perseroan yang bersangkutan dilarang bertindak sebagai kuasa dari pemegang saham sebagaimana dimaksud pada ayat (1). (5) Dalam hal pemegang saham hadir sendiri dalam RUPS, surat kuasa yang telah diberikan tidak berlaku untuk rapat tersebut. (6) Ketua rapat berhak menentukan siapa yang berhak hadir dalam RUPS dengan memperhatikan ketentuan undang-undang ini dan anggaran dasar Perseroan. (7) Terhadap Perseroan Terbuka selain berlaku ketentuan sebagaimana dimaksud pada ayat (3) dan ayat (6) berlaku juga ketentuan peraturan perundang- undangan di bidang pasar modal."},{"l":"UU PT No.40/2007","p":"86","b":"","t":"(1) RUPS dapat dilangsungkan jika dalam RUPS lebih dari 1/2 (satu perdua) bagian dari jumlah seluruh saham dengan hak suara hadir atau diwakili, kecuali undang-undang dan/atau anggaran dasar menentukan jumlah kuorum yang lebih besar. (2) Dalam hal kuorum sebagaimana dimaksud pada ayat (1) tidak tercapai, dapat diadakan pemanggilan RUPS kedua. (3) Dalam pemanggilan RUPS kedua harus disebutkan bahwa RUPS pertama telah dilangsungkan dan tidak mencapai kuorum. (4) RUPS kedua sebagaimana dimaksud pada ayat (2) sah dan berhak mengambil keputusan jika dalam RUPS paling sedikit 1/3 (satu pertiga) bagian dari jumlah seluruh saham dengan hak suara hadir atau diwakili, kecuali anggaran dasar menentukan jumlah kuorum yang lebih besar. (5) Dalam hal kuorum RUPS kedua sebagaimana dimaksud pada ayat (4) tidak tercapai, Perseroan dapat memohon kepada ketua pengadilan negeri yang daerah hukumnya meliputi tempat kedudukan Perseroan atas permohonan Perseroan agar ditetapkan kuorum untuk RUPS ketiga. (6) Pemanggilan RUPS ketiga harus menyebutkan bahwa RUPS kedua telah dilangsungkan dan tidak mencapai kuorum dan RUPS ketiga akan dilangsungkan dengan kuorum yang telah ditetapkan oleh ketua pengadilan negeri. (7) Penetapan ketua pengadilan negeri mengenai kuorum RUPS sebagaimana dimaksud pada ayat (5) bersifat final dan mempunyai kekuatan hukum tetap. (8) Pemanggilan RUPS kedua dan ketiga dilakukan dalam jangka waktu paling lambat 7 (tujuh) hari sebelum RUPS kedua atau ketiga dilangsungkan. (9) RUPS kedua dan ketiga dilangsungkan dalam jangka waktu paling cepat 10 (sepuluh) hari dan paling lambat 21 (dua puluh satu) hari setelah RUPS yang mendahuluinya dilangsungkan."},{"l":"UU PT No.40/2007","p":"87","b":"","t":"(1) Keputusan RUPS diambil berdasarkan musyawarah untuk mufakat. (2) Dalam hal keputusan berdasarkan musyawarah untuk mufakat sebagaimana dimaksud pada ayat (1) tidak tercapai, keputusan adalah sah jika disetujui lebih dari 1/2 (satu per dua) bagian dari jumlah suara yang dikeluarkan kecuali undang- undang dan/atau anggaran dasar menentukan bahwa keputusan adalah sah jika disetujui oleh jumlah suara setuju yang lebih besar. - 23 -"},{"l":"UU PT No.40/2007","p":"88","b":"","t":"(1) RUPS untuk mengubah anggaran dasar dapat dilangsungkan jika dalam rapat paling sedikit 2/3 (dua pertiga) bagian dari jumlah seluruh saham dengan hak suara hadir atau diwakili dalam RUPS dan keputusan adalah sah jika disetujui paling sedikit 2/3 (dua pertiga) bagian dari jumlah suara yang dikeluarkan, kecuali anggaran dasar menentukan kuorum kehadiran dan/atau ketentuan tentang pengambilan keputusan RUPS yang lebih besar. (2) Dalam hal kuorum kehadiran sebagaimana dimaksud pada ayat (1) tidak tercapai, dapat diselenggarakan RUPS kedua. (3) RUPS kedua sebagaimana dimaksud pada ayat (2) sah dan berhak mengambil keputusan jika dalam rapat paling sedikit 3/5 (tiga perlima) bagian dari jumlah seluruh saham dengan hak suara hadir atau diwakili dalam RUPS dan keputusan adala h sah jika disetujui paling sedikit 2/3 (dua pertiga) bagian dari jumlah suara yang dikeluarkan, kecuali anggaran dasar menentukan kuorum kehadiran dan/atau ketentuan tentang pengambilan keputusan RUPS yang lebih besar. (4) Ketentuan sebagaimana dimaksud dalam Pasal 86 ayat (5), ayat (6), ayat (7), ayat (8), dan ayat (9) mutatis mutandis berlaku bagi RUPS sebagaimana dimaksud pada ayat (1). (5) Ketentuan sebagaimana dimaksud pada ayat (1), ayat (2), dan ayat (3) mengenai kuorum kehadiran dan ketentuan tentang persyaratan pengambilan keputusan RUPS berlaku juga bagi Perseroan Terbuka sepanjang tidak diatur lain dalam peraturan perundang- undangan di bidang pasar modal."},{"l":"UU PT No.40/2007","p":"89","b":"","t":"(1) RUPS untuk menyetujui Penggabungan, Peleburan, Pengambilalihan, atau Pemisahan, pengajuan permohonan agar Perseroan dinyatakan pailit, perpanjangan jangka waktu berdirinya, dan pembubaran Perseroan dapat dilangsungkan jika dalam rapat paling sedikit 3/4 (tiga perempat) bagian dari jumlah seluruh saham dengan hak suara hadir atau diwakili dalam RUPS dan keputusan adalah sah jika disetujui paling sedikit 3/4 (tiga perempat) bagian dari jumlah suara yang dikeluarkan, kecuali anggaran dasar menentukan kuorum kehadiran dan/atau ketentuan tentang persyaratan pengambilan keputusan RUPS yang lebih besar. (2) Dalam hal kuorum kehadiran sebagaimana dimaksud pada ayat (1) tidak tercapai, dapat diadakan RUPS kedua. (3) RUPS kedua sebagaimana dimaksud pada ayat (2) sah dan berhak mengambil keputusan jika dalam rapat paling sedikit 2/3 (dua pertiga) bagian dari jumlah seluruh saham dengan hak suara hadir atau diwakili dalam RUPS dan keputusan adalah sah jika disetujui oleh paling sedikit 3/4 (tiga perempat) bagian dari jumlah suara yang dikeluarkan, kecuali anggaran dasar menentukan kuorum kehadiran dan/atau ketentuan tentang persyaratan pengambilan keputusan RUPS yang lebih besar. (4) Ketentuan sebagaimana dimaksud dalam Pasal 86 ayat (5), ayat (6), ayat (7), ayat (8), dan ayat (9) mutatis mutandis berlaku bagi RUPS sebagaimana dimaksud pada ayat (1). (5) Ketentuan sebagaimana dimaksud pada ayat (1), ayat (2), dan ayat (3) mengenai kuorum kehadiran dan/atau ketentuan tentang persyaratan pengambilan keputusan RUPS berlaku juga bagi Perseroan Terbuka sepanjang tidak diatur lain dalam peraturan perundang-undangan di bidang pasar modal."},{"l":"UU PT No.40/2007","p":"90","b":"","t":"(1) Setiap penyelenggaraan RUPS, risalah RUPS wajib dibuat dan ditandatangani oleh ketua rapat dan paling sedikit 1 (satu) orang pemegang saham yang ditunjuk dari dan oleh peserta RUPS. (2) Tanda tangan sebagaimana dimaksud pada ayat (1) tidak disya ratkan apabila risalah RUPS tersebut dibuat dengan akta notaris."},{"l":"UU PT No.40/2007","p":"91","b":"","t":"Pemegang saham dapat juga mengambil keputusan yang mengikat di luar RUPS dengan syarat semua pemegang saham dengan hak suara menyetujui secara tertulis dengan menandatangani usul yang bersangkutan. - 24 - BAB VII DIREKSI DAN DEWAN KOMISARIS Bagian Kesatu Direksi"},{"l":"UU PT No.40/2007","p":"92","b":"","t":"(1) Direksi menjalankan pengurusan Perseroan untuk kepentingan Perseroan dan sesuai dengan maksud dan tujuan Perseroan. (2) Direksi berwenang menjalankan pengurusan sebagaimana dimaksud pada ayat (1) sesuai dengan kebijakan yang dipandang tepat, dalam batas yang ditentukan dalam undang-undang ini dan/ atau anggaran dasar. (3) Direksi Perseroan terdiri atas 1 (satu) orang anggota Direksi atau lebih. (4) Perseroan yang kegiatan usahanya berkaitan dengan menghimpun dan/atau mengelola dana masyarakat, Perseroan yang menerbitkan surat pengakuan utang kepada masyarakat, atau Perseroan Terbuka wajib mempunyai paling sedikit 2 (dua) orang anggota Direksi. (5) Dalam hal Direksi terdiri atas 2 (dua) anggota Direksi atau lebih, pembagian tugas dan wewenang pengurusan di antara anggota Direksi ditetapkan berdasarkan keputusan RUPS. (6) Dalam hal RUPS sebagaimana dimaksud pada ayat (5) tidak menetapkan, pembagian tugas dan wewenang anggota Direksi ditetapkan berdasarkan keputusan Direksi."},{"l":"UU PT No.40/2007","p":"93","b":"","t":"(1) Yang dapat diangkat menjadi anggota Direksi adalah orang perseorangan yang cakap melakukan perbuatan hukum, kecuali dalam waktu 5 (lima) tahun sebelum pengangkatannya pernah: a. dinyatakan pailit; b. menjadi anggota Direksi atau anggota Dewan Komisaris yang dinyatakan bersalah menyebabkan suatu Perseroan dinyatakan pailit; atau c. dihukum karena melakukan tindak pidana yang merugikan keuangan negara dan/atau yang berkaitan dengan sektor keuangan. (2) Ketentuan persyaratan sebagaimana dimaksud pada ayat (1) tidak mengurangi kemungkinan instansi teknis yang berwenang menetapkan persyaratan tambahan berdasarkan peraturan perundang-undangan. (3) Pemenuhan persyaratan sebagaimana dimaksud pada ayat (1) dan ayat (2) dibuktikan dengan surat yang disimpan oleh Perseroan."},{"l":"UU PT No.40/2007","p":"94","b":"","t":"(1) Anggota Direksi diangkat oleh RUPS. (2) Untuk pertama kali pengangkatan anggota Direksi dilakukan oleh pendiri dalam akta pendirian sebagaimana dimaksud dalam Pasal 8 ayat (2) huruf b. (3) Anggota Direksi diangkat untuk jangka waktu tertentu dan dapat diangkat kembali. (4) Anggaran dasar mengatur tata cara pengangkatan, penggantian, dan pemberhentian anggota Direksi dan dapat juga mengatur tentang tata cara pencalonan anggota Direksi. (5) Keputusan RUPS mengenai pengangkatan, penggantian, dan pemberhentian anggota Direksi juga menetapkan saat mulai berlakunya pengangkatan, penggantian, dan pemberhentian tersebut. (6) Dalam hal RUPS tidak menetapkan saat mulai berlakunya pengangkatan, penggantian, dan pemberhentian anggota Direksi, pengangkatan, penggantian, dan pemberhentian anggota Direksi tersebut mulai berlaku sejak ditutupnya RUPS. (7) Dalam hal terjadi pengangkatan, penggantian, dan pemberhentian anggota Direksi, Direksi wajib memberitahukan perubahan anggota Direksi kepada Menteri untuk dicatat dalam daftar Perseroan dalam jangka waktu paling lambat 30 (tiga puluh) hari terhitung sejak tanggal keputusan RUPS tersebut. (8) Dalam hal pemberitahuan sebagaimana dimaksud pada ayat (7) belum dilakukan, Menteri menolak setiap permohonan yang diajukan atau pemberitahuan yang disampaikan kepada Menteri oleh Direksi yang belum tercatat dalam daftar Perseroan. - 25 - (9) Pemberitahuan sebagaimana dimaksud pada ayat (8) tidak termasuk pemberitahuan yang disampaikan oleh Direksi baru atas pengangkatan dirinya sendiri."},{"l":"UU PT No.40/2007","p":"95","b":"","t":"(1) Pengangkatan anggota Direksi yang tidak memenuhi persyaratan sebagaimana dimaksud dalam Pasal 93 batal karena hukum sejak saat anggota Direksi lainnya atau Dewan Komisaris mengetahui tidak terpenuhinya persyaratan tersebut. (2) Dalam jangka waktu paling lambat 7 (tujuh) hari terhitung sejak diketahui, anggota Direksi lainnya atau Dewan Komisaris harus mengumumkan batalnya pengangkatan anggota Direksi yang bersangkutan dalam surat kabar dan memberitahukannya kepada Menteri untuk dicatat dalam daftar Perseroan. (3) Perbuatan hukum yang telah dilakukan untuk dan atas nama Perseroan oleh anggota Direksi sebagaimana dimaksud pada ayat (1) sebelum pengangkatannya batal, tetap mengikat dan menjadi tanggung jawab Perseroan. (4) Perbuatan hukum yang dilakukan untuk dan atas nama Perseroan oleh anggota Direksi sebagaimana dimaksud pada ayat (1) setelah pengangkatannya batal, adalah tidak sah dan menjadi tanggung jawab pribadi anggota Direksi yang bersangkutan. (5) Ketentuan sebagaimana dimaksud pada ayat (3) tidak mengurangi tanggung jawab anggota Direksi yang bersangkutan terhadap kerugian Perseroan sebagaimana dimaksud dalam Pasal 97 dan Pasal 104."},{"l":"UU PT No.40/2007","p":"96","b":"","t":"(1) Ketentuan tentang besarnya gaji dan tunjangan anggota Direksi ditetapkan berdasarkan keputusan RUPS. (2) Kewenangan RUPS sebagaimana dimaksud pada ayat (1), dapat dilimpahkan kepada Dewan Komisaris. (3) Dalam hal kewenangan RUPS dilimpahkan kepada Dewan Komisaris sebagaimana dimaksud pada ayat (2), besarnya gaji dan tunjangan sebagaimana dimaksud pada ayat (1) ditetapkan berdasarkan keputusan rapat Dewan Komisaris."},{"l":"UU PT No.40/2007","p":"97","b":"","t":"(1) Direksi bertanggung jawab atas pengurusan Perseroan sebagaimana dimaksud dalam Pasal 92 ayat (1). (2) Pengurusan sebagaimana dimaksud pada ayat (1), wajib dilaksanakan setiap anggota Direksi dengan itikad baik dan penuh tanggung jawab. (3) Setiap anggota Direksi bertanggung jawab penuh secara pribadi atas kerugian Perseroan apabila yang bersangkutan bersalah atau lalai menjalankan tugasnya sesuai dengan ketentuan sebagaimana dimaksud pada ayat (2). (4) Dalam hal Direksi terdiri atas 2 (dua) anggota Direksi atau lebih, tanggung jawab sebagaimana dimaksud pada ayat (3) berlaku secara tanggung renteng bagi setiap anggota Direksi. (5) Anggota Direksi tidak dapat dipertanggungjawabkan atas kerugian sebagaimana dimaksud pada ayat (3) apabila dapat membuktikan: a. kerugian tersebut bukan karena kesalahan atau kelalaiannya; b. telah melakukan pengurusan dengan itikad baik dan kehati-hatian untuk kepentingan dan sesuai dengan maksud dan tujuan Perseroan; c. tidak mempunyai benturan kepentingan baik langsung maupun tidak langsung atas tindakan pengurusan yang mengakibatkan kerugian; dan d. telah mengambil tindakan untuk mencegah timbul atau berlanjutnya kerugian tersebut. (6) Atas nama Perseroan, pemegang saham yang mewakili paling sedikit 1/10 (satu persepuluh) bagian dari jumlah seluruh saham dengan hak suara dapat mengajukan gugatan melalui pengadilan negeri terhadap anggota Direksi yang karena kesalahan atau kelalaiannya menimbulkan kerugian pada Perseroan. (7) Ketentuan sebagaimana dimaksud pada ayat (5) tidak mengurangi hak anggota Direksi lain dan/atau anggota Dewan Komisaris untuk mengajukan gugatan atas nama Perseroan. - 26 -"},{"l":"UU PT No.40/2007","p":"98","b":"","t":"(1) Direksi mewakili Perseroan baik di dalam maupun di luar pengadilan. (2) Dalam hal anggota Direksi terdiri lebih dari 1 (satu) orang, yang berwenang mewakili Perseroan adalah setiap anggota Direksi, kecuali ditentukan lain dalam anggaran dasar. (2) Kewenangan Direksi untuk mewakili Perseroan sebagaimana dimaksud pada ayat (1) adalah tidak terbatas dan tidak bersyarat, kecuali ditentukan lain dalam undang-undang ini, anggaran dasar, atau keputusan RUPS. (3) Keputusan RUPS sebagaimana dimaksud pada ayat (3) tidak boleh bertentangan dengan ketentuan Undang-Undang ini dan/atau anggaran dasar Perseroan."},{"l":"UU PT No.40/2007","p":"99","b":"","t":"(1) Anggota Direksi tidak berwenang mewakili Perseroan apabila: a. terjadi perkara di pengadilan antara Perseroan dengan anggota Direksi yang bersangkutan; atau b. anggota Direksi yang bersangkutan mempunyai benturan kepentingan dengan Perseroan. (2) Dalam hal terdapat keadaan sebagaimana dimaksud pada ayat (1), yang berhak mewakili Perseroan adalah: a. anggota Direksi lainnya yang tidak mempunyai benturan kepentingan dengan Perseroan; b. Dewan Komisaris dalam hal seluruh anggota Direksi mempunyai benturan kepentingan dengan Perseroan; atau c. pihak lain yang ditunjuk oleh RUPS dalam hal seluruh anggota Direksi atau Dewan Komisaris mempunyai benturan kepentingan dengan Perseroan."},{"l":"UU PT No.40/2007","p":"100","b":"","t":"(1) Direksi Wajib: a. membuat daftar pemegang saham, daftar khusus, risalah RUPS, dan b. risalah rapat Direksi; c. membuat laporan tahunan sebagaimana dimaksud dalam Pasal 66 dan dokumen keuangan Perseroan sebagaimana dimaksud dalam undang- undang tentang Dokumen Perusahaan; dan d. memelihara seluruh daftar, risalah, dan dokumen keuangan Perseroan sebagaimana dimaksud pada huruf a dan huruf b dan dokumen Perseroan lainnya. (2) Seluruh daftar, risalah, dokumen keuangan Perseroan, dan dokumen Perseroan lainnya sebagaimana dimaksud pada ayat (1) disimpan di tempat kedudukan Perseroan. (3) Atas permohonan tertulis dari pemegang saham, Direksi memberi izin kepada pemegang saham untuk memeriksa daftar pemegang saham, daftar khusus, risalah RUPS sebagaimana dimaksud pada ayat (1) dan laporan tahunan, serta mendapatkan salinan risalah RUPS dan salinan laporan tahunan. (4) Ketentuan sebagaimana dimaksud pada ayat (3) tidak menutup kemungkinan peraturan perundang-undangan di bidang pasar modal menentukan lain."},{"l":"UU PT No.40/2007","p":"101","b":"","t":"(1) Anggota Direksi wajib melaporkan kepada Perseroan mengenai saham yang dimiliki anggota Direksi yang bersangkutan dan/atau keluarganya dalam Perseroan dan Perseroan lain untuk selanjutnya dicatat dalam daftar khusus. (2) Anggota Direksi yang tidak melaksanakan kewajiban sebagaimana dimaksud pada ayat (1) dan menimbulkan kerugian bagi Perseroan, bertanggung jawab secara pribadi atas kerugian Perseroan tersebut."},{"l":"UU PT No.40/2007","p":"102","b":"","t":"(1) Direksi wajib meminta persetujuan RUPS untuk: a. mengalihkan kekayaan Perseroan; atau b. menjadikan jaminan utang kekayaan Perseroan; yang merupakan lebih dari 50% (lima puluh persen) jumlah kekayaan bersih Perseroan dalam 1 (satu) transaksi atau lebih, baik yang berkaitan satu sama lain maupun tidak. - 27 - (2) Transaksi sebagaimana dimaksud pada ayat (1) huruf a adalah transaksi pengalihan kekayaan bersih Perseroan yang terjadi dalam jangka waktu 1 (satu) tahun buku atau jangka waktu yang lebih lama sebagaimana diatur dalam anggaran dasar Perseroan. (3) Ketentuan sebagaimana dimaksud pada ayat (1), tidak berlaku terhadap tindakan pengalihan atau penjaminan kekayaan Perseroan yang dilakukan oleh Direksi sebagai pelaksanaan kegiatan usaha Perseroan sesuai dengan anggaran dasarnya. (4) Perbuatan hukum sebagaimana dimaksud pada ayat (1) tanpa persetujuan RUPS, tetap mengikat Perseroan sepanjang pihak lain dalam perbuatan hukum tersebut beritikad baik. (5) Ketentuan kuorum kehadiran dan/atau ketentuan tentang pengambilan keputusan RUPS sebagaimana dimaksud dalam Pasal 89 mutatis mutandis berlaku bagi keputusan RUPS untuk menyetujui tindakan Direksi sebagaimana dimaksud pada ayat (1)."},{"l":"UU PT No.40/2007","p":"103","b":"","t":"Direksi dapat memberi kuasa tertulis kepada 1 (satu) orang karyawan Perseroan atau lebih atau kepada orang lain untuk dan atas nama Perseroan melakukan perbuatan hukum tertentu sebagaimana yang diuraikan dalam surat kuasa."},{"l":"UU PT No.40/2007","p":"104","b":"","t":"(1) Direksi tidak berwenang mengajukan permohonan pailit atas Perseroan sendiri kepada Pengadilan Niaga sebelum memperoleh persetujuan RUPS, dengan tidak mengurangi ketentuan sebagaimana diatur dalam undang-undang tentang Kepailitan dan Penundaan Kewajiban Pembayaran Utang. (2) Dalam hal kepailitan sebagaimana dimaksud pada ayat terjadi karena kesalahan atau kelalaian Direksi dan harta pailit tidak cukup untuk membayar seluruh kewajiban Perseroan dalam kepailitan tersebut, setiap anggota Direksi secara tanggung renteng bertanggung jawab atas seluruh kewajiban yang tidak terlunasi dari harta pailit tersebut. (3) Tanggung jawab sebagaimana dimaksud pada ayat (2) berlaku juga bagi anggota Direksi yang salah atau lalai yang pernah menjabat sebagai anggota Direksi dalam jangka waktu 5 (lima) tahun sebelum putusan pernyataan pailit diucapkan. (4) Anggota Direksi tidak bertanggungjawab atas kepailitan Perseroan sebagaimana dimaksud pada ayat (2) apabila dapat membuktikan: a. kepailitan tersebut bukan karena kesalahan atau kelalaiannya; b. telah melakukan pengurusan dengan itikad baik, kehati- hatian, dan penuh tanggung jawab untuk kepentingan Perseroan dan sesuai dengan maksud dan tujuan Perseroan; c. tidak mempunyai benturan kepentingan baik langsung maupun tidak langsung atas tindakan pengurusan yang dilakukan; dan d. telah mengambil tindakan untuk mencegah terjadinya kepailitan. (5) Ketentuan sebagaimana dimaksud pada ayat (2), ayat (3), dan ayat (4) berlaku juga bagi Direksi dari Perseroan yang dinyatakan pailit berdasarkan gugatan pihak ketiga."},{"l":"UU PT No.40/2007","p":"105","b":"","t":"(1) Anggota Direksi dapat diberhentikan sewaktu-waktu berdasarkan keputusan RUPS dengan menyebutkan alasannya. (2) Keputusan untuk memberhentikan anggota Direksi sebagaimana dimaksud pada ayat (1) diambil setelah yang bersangkutan diberi kesempatan untuk membela diri dalam RUPS. (3) Dalam hal keputusan untuk memberhentikan anggota Direksi sebagaimana dimaksud pada ayat (2) dilakukan dengan keputusan di luar RUPS sesuai dengan ketentuan sebagaimana dimaksud dalam Pasal 91, anggota Direksi yang bersangkutan diberi tahu terlebih dahulu tentang rencana pemberhentian dan diberikan kesempatan untuk membela diri sebelum diambil keputusan pemberhentian. (4) Pemberian kesempatan untuk membela diri sebagaimana dimaksud pada ayat (2) tidak diperlukan dalam hal yang bersangkutan tidak berkeberatan atas pemberhentian tersebut. (5) Pemberhentian anggota Direksi berlaku sejak: a. ditutupnya RUPS sebagaimana dimaksud pada ayat (1); b. tanggal keputusan sebagaimana dimaksud pada ayat (3); c. tanggal lain yang ditetapkan dalam keputusan RUPS sebagaimana dimaksud pada ayat (1); atau - 28 - d. tanggal lain yang ditetapkan dalam keputusan sebagaimana dimaksud pada ayat (3)."},{"l":"UU PT No.40/2007","p":"106","b":"","t":"(1) Anggota Direksi dapat diberhentikan untuk sementara oleh Dewan Komisaris dengan menyebutkan alasannya. (2) Pemberhentian sementara sebagaimana dimaksud pada ayat (1) diberitahukan secara tertulis kepada anggota Direksi yang bersangkutan. (3) Anggota Direksi yang diberhentikan sementara sebagaimana dimaksud pada ayat (1) tidak berwenang melakukan tugas sebagaimana dimaksud dalam Pasal 92 ayat (1) dan Pasal 98 ayat (1). (4) Dalam jangka waktu paling lambat 30 (tiga puluh) hari setelah tanggal pemberhentian sementara harus diselenggarakan RUPS. (5) Dalam RUPS sebagaimana dimaksud pada ayat (4) anggota Direksi yang bersangkutan diberi kesempatan untuk membela diri. (6) RUPS mencabut atau menguatkan keputusan pemberhentian sementara tersebut. (7) Dalam hal RUPS menguatkan keputusan pemberhentian sementara, anggota Direksi yang bersangkutan diberhentikan untuk seterusnya. (8) Dalam hal jangka waktu 30 (tiga puluh) hari telah lewat RUPS sebagaimana dimaksud pada ayat (4) tidak diselenggarakan, atau RUPS tidak dapat mengambil keputusan, pemberhentian sementara tersebut menjadi batal. (9) Bagi Perseroan Terbuka penyelenggaraan RUPS sebagaimana dimaksud pada ayat (4) dan ayat (8) berlaku ketentuan peraturan perundang-undangan di bidang pasar modal."},{"l":"UU PT No.40/2007","p":"107","b":"","t":"Dalam anggaran dasar diatur ketentuan mengenai: a. tata cara pengunduran diri anggota Direksi; b. tata cara pengisian jabatan anggota Direksi yang lowong; dan c. pihak yang berwenang menjalankan pengurusan dan mewakili Perseroan dalam hal seluruh anggota Direksi berhalangan atau diberhentikan untuk sementara. Bagian Kedua Dewan Komisaris"},{"l":"UU PT No.40/2007","p":"108","b":"","t":"(1) Dewan Komisaris melakukan pengawasan atas kebijakan pengurusan, jalannya pengurusan pada umumnya, baik mengenai Perseroan maupun usaha Perseroan, dan memberi nasihat kepada Direksi. (2) Pengawasan dan pemberian nasihat sebagaimana dimaksud pada ayat (1) dilakukan untuk kepentingan Perseroan dan sesuai dengan maksud dan tujuan Perseroan. (3) Dewan Komisaris terdiri atas 1 (satu) orang anggota atau lebih. (4) Dewan Komisaris yang terdiri atas lebih dari 1 (satu) orang anggota merupakan majelis dan setiap anggota Dewan Komisaris tidak dapat bertindak sendiri-sendiri, melainkan berdasarkan keputusan Dewan Komisaris. (5) Perseroan yang kegiatan usahanya berkaitan dengan menghimpun dan/atau mengelola dana masyarakat, Perseroan yang menerbitkan surat pengakuan utang kepada masyarakat atau Perseroan Terbuka wajib mempunyai paling sedikit 2 (dua) orang anggota Dewan Komisaris."},{"l":"UU PT No.40/2007","p":"109","b":"","t":"(1) Perseroan yang menjalankan kegiatan usaha berdasarkan prinsip syariah selain mempunyai Dewan Komisaris wajib mempunyai Dewan Pengawas Syariah. (2) Dewan Pengawas Syariah sebagaimana dimaksud pada ayat (1) terdiri atas seorang ahli syariah atau lebih yang diangkat oleh RUPS atas rekomendasi Majelis Ulama Indonesia. (3) Dewan Pengawas Syariah sebagaimana dimaksud pada ayat (1) bertugas memberikan nasihat dan saran kepada Direksi serta mengawasi kegiatan Perseroan agar sesuai dengan prinsip syariah. - 29 -"},{"l":"UU PT No.40/2007","p":"110","b":"","t":"(1) Yang dapat diangkat menjadi anggota Dewan Komisaris adalah orang perseoranga n yang cakap melakukan perbuatan hukum, kecuali dalam waktu 5 (lima) tahun sebelum pengangkatannya pernah: a. dinyatakan pailit; b. menjadi anggota Direksi atau anggota Dewan Komisaris yang dinyatakan bersalah menyebabkan suatu Perseroan dinyatakan pailit; atau c. dihukum karena melakukan tindak pidana yang merugikan keuangan negara dan/atau yang berkaitan dengan sektor keuangan. (2) Ketentuan persyaratan sebagaimana dimaksud pada ayat (1) tidak mengurangi kemungkinan instansi teknis yang berwenang menetapkan persyaratan tambahan berdasarkan peraturan perundang-undangan. (3) Pemenuhan persyaratan sebagaimana dimaksud pada ayat (1) dan ayat (2) dibuktikan dengan surat yang disimpan oleh Perseroan."},{"l":"UU PT No.40/2007","p":"111","b":"","t":"(1) Anggota Dewan Komisaris diangkat oleh RUPS. (2) Untuk pertama kali pengangkatan anggota Dewan Komisaris dilakukan oleh pendiri dalam akta pendirian sebagaimana dimaksud dalam Pasal 8 ayat (2) huruf b. (3) Anggota Dewan Komisaris diangkat untuk jangka waktu tertentu dan dapat diangkat kembali. (4) Anggaran dasar mengatur tata cara pengangkatan, penggantian, dan pemberhentian anggota Dewan Komisaris serta dapat juga mengatur tentang pencalonan anggota Dewan Komisaris. (5) Keputusan RUPS mengenai pengangkatan, penggantian, dan pemberhentian anggota Dewan Komisaris juga menetapkan saat mulai berlakunya pengangkatan, penggantian, dan pemberhentian tersebut. (6) Dalam hal RUPS tidak menentukan saat mulai berlakunya pengangkatan, penggantian, dan pemberhentian anggota Dewan Komisaris, pengangkatan, penggantian, dan pemberhentian mulai berlaku sejak ditutupnya RUPS. (7) Dalam hal terjadi pengangkatan, penggantian, dan pemberhentian anggota Dewan Komisaris, Direksi wajib memberitahukan perubahan tersebut kepada Menteri untuk dicatat dalam daftar Perseroan dalam jangka waktu paling lambat 30 (tiga puluh) hari terhitung sejak tanggal keputusan RUPS tersebut. (8) Dalam hal pemberitahuan sebagaimana dimaksud pada ayat (7) belum dilakukan, Menteri menolak setiap pemberitahuan tentang perubahan susunan Dewan Komisaris selanjutnya yang disampaikan kepada Menteri oleh Direksi."},{"l":"UU PT No.40/2007","p":"112","b":"","t":"(1) Pengangkatan anggota Dewan Komisaris yang tidak memenuhi persyaratan sebagaimana dimaksud dalam Pasal 110 ayat (1) dan ayat (2) batal karena hukum sejak saat anggota Dewan Komisaris lainnya atau Direksi mengetahui tidak terpenuhinya persyaratan tersebut. (2) Dalam jangka waktu paling lambat 7 (tujuh) hari terhitung sejak diketahui, Direksi harus mengumumkan batalnya pengangkatan anggota Dewan Komisaris yang bersangkutan dalam surat kabar dan memberitahukannya kepada Menteri untuk dicatat dala m daftar Perseroan. (3) Perbuatan hukum yang telah dilakukan oleh anggota Dewan Komisaris sebagaimana dimaksud pada ayat (1) untuk dan atas nama Dewan Komisaris sebelum pengangkatannya batal, tetap mengikat dan menjadi tanggung jawab Perseroan. (4) Ketentuan sebagaimana dimaksud pada ayat (2) tidak mengurangi tanggung jawab anggota Dewan Komisaris yang bersangkutan terhadap kerugian Perseroan sebagaimana dimaksud dalam Pasal 114 dan Pasal 115."},{"l":"UU PT No.40/2007","p":"113","b":"","t":"Ketentuan tentang besarnya gaji atau honorarium dan tunjangan bagi anggota Dewan Komisaris ditetapkan oleh RUPS. - 30 -"},{"l":"UU PT No.40/2007","p":"114","b":"","t":"(1) Dewan Komisaris bertanggung jawab atas pengawasan Perseroan sebagaimana dimaksud dalam Pasal 108 ayat (1). (2) Setiap anggota Dewan Komisaris wajib dengan itikad baik, kehati-hatian, dan bertanggung jawab dalam menjalankan tugas pengawasan dan pemberian nasihat kepada Direksi sebagaimana dimaksud dalam Pasal 108 ayat (1) untuk kepentingan Perseroan dan sesuai dengan maksud dan tujuan Perseroan. (3) Setiap anggota Dewan Komisaris ikut bertanggung jawab secara pribadi atas kerugian Perseroan apabila yang bersangkutan bersalah atau lalai menjalankan tugasnya sebagaimana dimaksud pada ayat (2). (4) Dalam hal Dewan Komisaris terdiri atas 2 (dua) anggota Dewan Komisaris atau lebih, tanggung jawab sebagaimana dimaksud pada ayat (3) berlaku secara tanggung renteng bagi setiap anggota Dewan Komisaris. (5) Anggota Dewan Komisaris tidak dapat dipertanggungjawabkan atas kerugian sebagaimana dimaksud pada ayat (3) apabila dapat membuktikan: a. telah melakukan pengawasan dengan itikad baik dan kehati- hatian untuk kepentingan Perseroan dan sesuai dengan maksud dan tujuan Perseroan; b. tidak mempunyai kepentingan pribadi baik langsung maupun tidak langsung atas tindakan pengurusan Direksi yang mengakibatkan kerugian; dan c. telah memberikan nasihat kepada Direksi untuk mencegah timbul atau berlanjutnya kerugian tersebut. (6) Atas nama Perseroan, pemegang saham yang mewakili paling sedikit 1/10 (satu persepuluh) bagian dari jumlah seluruh saham dengan hak suara dapat menggugat anggota Dewan Komisaris yang karena kesalahan atau kelalaiannya menimbulkan kerugian pada Perseroan ke pengadilan negeri."},{"l":"UU PT No.40/2007","p":"115","b":"","t":"(1) Dalam hal terjadi kepailitan karena kesalahan atau kelalaian Dewan Komisaris dalam melakukan pengawasan terhadap pengurusan yang dilaksanakan oleh Direksi dan kekayaan Perseroan tidak cukup untuk membayar seluruh kewajiban Perseroan akibat kepailitan tersebut, setiap anggota Dewan Komisaris secara tanggung renteng ikut bertanggung jawab dengan anggota Direksi atas kewajiban yang belum dilunasi. (2) Tanggung jawab sebagaimana dimaksud pada ayat (1) berlaku juga bagi anggota Dewan Komisaris yang sudah tidak menjabat 5 (lima) tahun sebelum putusan pernyataan pailit diucapkan. (3) Anggota Dewan Komisaris tidak dapat dimintai pertanggungjawaban atas kepailitan Perseroan sebagaimana dimaksud pada ayat (1) apabila dapat membuktikan: a. kepailitan tersebut bukan karena kesalahan atau kelalaiannya; b. telah melakukan tugas pengawasan dengan itikad baik dan kehati- hatian untuk kepentingan Perseroan dan sesuai dengan maksud dan tujuan Perseroan; c. tidak mempunyai kepentingan pribadi, baik langsung maupun tidak langsung atas tindakan pengurusan oleh Direksi yang mengakibatkan kepailitan; dan d. telah memberikan nasihat kepada Direksi untuk mencegah terjadinya kepailitan."},{"l":"UU PT No.40/2007","p":"116","b":"","t":"Dewan Komisaris wajib: a. membuat risalah rapat Dewan Komisaris dan menyimpan salinannya; b. melaporkan kepada Perseroan mengenai kepemilikan sahamnya dan/atau keluarganya pada Perseroan tersebut dan Perseroan lain; dan c. memberikan laporan tentang tugas pengawasan yang telah dilakukan selama tahun buku yang baru lampau kepada RUPS."},{"l":"UU PT No.40/2007","p":"117","b":"","t":"(1) Dalam anggaran dasar dapat ditetapkan pemberian wewenang kepada Dewan Komisaris untuk memberikan persetujuan atau bantuan kepada Direksi dalam melakukan perbuatan hukum tertentu. - 31 - (2) Dalam hal anggaran dasar menetapkan persyaratan pemberian persetujuan atau bantuan sebagaimana dimaksud pada ayat (1), tanpa persetujuan atau bantuan Dewan Komisaris, perbuatan hukum tetap mengikat Perseroan sepanjang pihak lainnya dalam perbuatan hukum tersebut beritikad baik."},{"l":"UU PT No.40/2007","p":"118","b":"","t":"(1) Berdasarkan anggaran dasar atau keputusan RUPS, Dewan Komisaris dapat melakukan tindakan pengurusan Perseroan dalam keadaan tertentu untuk jangka waktu tertentu. (2) Dewan Komisaris yang dalam keadaan tertentu unt uk jangka waktu tertentu melakukan tindakan pengurusan sebagaimana dimaksud pada ayat (1) berlaku semua ketentuan mengenai hak, wewenang, dan kewajiban Direksi terhadap Perseroan dan pihak ketiga."},{"l":"UU PT No.40/2007","p":"119","b":"","t":"Ketentuan mengenai pemberhentian anggota Direksi sebagaimana dimaksud dalam Pasal 105 mutatis mutandis berlaku bagi pemberhentian anggota Dewan Komisaris."},{"l":"UU PT No.40/2007","p":"120","b":"","t":"(1) Anggaran dasar Perseroan dapat mengatur adanya 1 (satu) orang atau lebih Komisaris Independen dan 1 (satu) orang Komisaris Utusan. (2) Komisaris independen sebagaimana dimaksud pada ayat (1) diangkat berdasarkan keputusan RUPS dari pihak yang tidak terafiliasi dengan pemegang saham utama, anggota Direksi dan/atau anggota Dewan Komisaris lainnya. (3) Komisaris utusan sebagaimana dimaksud pada ayat (1) merupakan anggota Dewan Komisaris yang ditunjuk berdasarkan keputusan rapat Dewan Komisaris. (4) Tugas dan wewenang Komisaris utusan ditetapkan dalam anggaran dasar Perseroan dengan ketentuan tidak bertentangan dengan tugas dan wewenang Dewan Komisaris dan tidak mengurangi tugas pengurusan yang dilakukan Direksi."},{"l":"UU PT No.40/2007","p":"121","b":"","t":"(1) Dalam menjalankan tugas pengawasan sebagaimana dimaksud dalam Pasal 108, Dewan Komisaris dapat membentuk komite, yang anggotanya seorang atau lebih adalah anggota Dewan Komisaris. (2) Komite sebagaimana dimaksud pada ayat (1) bertanggung jawab kepada Dewan Komisaris. BAB VIII PENGGABUNGAN, PELEBURAN, PENGAMBILALIHAN, DAN PEMISAHAN"},{"l":"UU PT No.40/2007","p":"122","b":"","t":"(1) Penggabungan dan Peleburan mengakibatkan Perseroan yang menggabungkan atau meleburkan diri berakhir karena hukum. (2) Berakhirnya Perseroan sebagaimana dimaksud pada ayat (1) terjadi tanpa dilakukan likuidasi terlebih dahulu. (3) Dalam hal berakhirnya Perseroan sebagaimana dimaksud pada ayat (2), a. aktiva dan pasiva Perseroan yang menggabungkan atau meleburkan diri beralih karena hukum kepada Perseroan yang menerima Penggabungan atau Perseroan hasil Peleburan; b. pemegang saham Perseroan yang menggabungkan atau meleburkan diri karena hukum menjadi pemegang saham Perseroan yang menerima Penggabungan atau Perseroan hasil Peleburan; dan c. Perseroan yang menggabungkan atau meleburkan diri berakhir karena hukum terhitung sejak tanggal Penggabungan atau Peleburan mulai berlaku."},{"l":"UU PT No.40/2007","p":"123","b":"","t":"(1) Direksi Perseroan yang akan menggabungkan diri dan menerima Penggabungan menyusun rancangan Penggabungan. (2) Rancangan Penggabungan sebagaimana dimaksud pada ayat (1) memuat sekurang- kurangnya: - 32 - a. nama dan tempat kedudukan dari setiap Perseroan yang akan melakukan Penggabungan; b. alasan serta penjelasan Direksi Perseroan yang akan melakukan Penggabungan dan persyaratan Penggabungan; c. tata cara penilaian dan konversi saham Perseroan yang menggabungkan diri terhadap saham Perseroan yang menerima Penggabungan; d. rancangan perubahan anggaran dasar Perseroan yang menerima Penggabungan apabila ada; e. laporan keuangan sebagaimana dimaksud dalam Pasal 66 ayat (2) huruf a yang meliputi 3 (tiga) tahun buku terakhir dari setiap Perseroan yang akan melakukan Penggabungan; f. rencana kelanjutan atau pengakhiran kegiatan usaha dari Perseroan yang akan melakukan Penggabungan; g. neraca proforma Perseroan yang menerima Penggabungan sesuai dengan prinsip akuntansi yang berlaku umum di Indonesia; h. cara penyelesaian status, hak dan kewajiban anggota Direksi, Dewan Komisaris, dan karyawan Perseroan yang akan melakukan Penggabungan diri; i. cara penyelesaian hak dan kewajiban Perseroan yang akan menggabungkan diri terhadap pihak ketiga. j. cara penyelesaian hak pemegang saham yang tidak setuju terhadap Penggabungan Perseroan; k. nama anggota Direksi dan Dewan Komisaris serta gaji, honorarium dan tunjangan bagi anggota Direksi dan Dewan Komisaris Perseroan yang menerima Penggabungan; l. perkiraan jangka waktu pelaksanaan Penggabungan; m. laporan mengenai keadaan, perkembangan, dan hasil yang dicapai dari setiap Perseroan yang akan melakukan Penggabungan; n. kegiatan utama setiap Perseroan yang melakukan Penggabungan dan perubahan yang terjadi selama tahun buku yang sedang berjalan; dan o. rincian masalah yang timbul selama tahun buku yang sedang berjalan yang mempengaruhi kegiatan Perseroan yang akan melakukan Penggabungan. (3) Rancangan Penggabungan sebagaimana dimaksud pada ayat (2) setelah mendapat persetujuan Dewan Komisaris dari setiap Perseroan diajukan kepada RUPS masing- masing untuk mendapat persetujuan. (3) Bagi Perseroan tertentu yang akan melakukan Penggabungan selain berlaku ketentuan dalam undang-undang ini, perlu mendapat persetujuan terlebih dahulu dari instansi terkait sesuai dengan ketentuan peraturan perundang- undangan. (4) Ketentuan sebagaimana dimaksud pada ayat (1) sampai dengan ayat (4) berlaku juga bagi Perseroan Terbuka sepanjang tidak diatur lain dalam peraturan perundang- undangan di bidang pasar modal."},{"l":"UU PT No.40/2007","p":"124","b":"","t":"Ketentuan sebagaimana dimaksud dalam Pasal 123 mutatis mutandis berlaku bagi Perseroan yang akan meleburkan diri."},{"l":"UU PT No.40/2007","p":"125","b":"","t":"(1) Pengambilalihan dilakukan dengan cara pengambilalihan saham yang telah dikeluarkan dan/atau akan dikeluarkan oleh Perseroan melalui Direksi Perseroan atau langsung dari pemegang saham. (2) Pengambilalihan dapat dilakukan oleh badan hukum atau orang perseorangan. (3) Pengambilalihan sebagaimana dimaksud pada ayat (1) adalah pengambilalihan saham yang mengakibatkan beralihnya pengendalian terhadap Perseroan tersebut. (4) Dalam hal Pengambilalihan yang dilakukan oleh badan hukum berbentuk Perseroan, Direksi sebelum melakukan perbuatan hukum pengambilalihan harus berdasarkan keputusan RUPS yang memenuhi kuorum kehadiran dan ketentuan tentang persyaratan pengambilan keputusan RUPS sebagaimana dimaksud dalam Pasal 89. (5) Dalam hal Pengambilalihan dilakukan melalui Direksi, pihak yang akan mengambil alih menyampaikan maksudnya untuk melakukan Pengambilalihan kepada Direksi Perseroan yang akan diambil alih. - 33 - (6) Direksi Perseroan yang akan diambil alih dan Perseroan yang akan mengambil alih dengan persetujuan Dewan Komisaris masing- masing menyusun rancangan Pengambilalihan yang memuat sekurang-kurangnya: a. nama dan tempat kedudukan dari Perseroan yang akan mengambil alih dan Perseroan yang akan diambil alih; b. alasan serta penjelasan Direksi Perseroan yang akan mengambil alih dan Direksi Perseroan yang akan diambil alih; c. laporan keuangan sebagaimana dimaksud dalam Pasal 66 ayat (2) huruf a untuk tahun buku terakhir dari Perseroan yang akan mengambil alih dan Perseroan yang akan diambil alih; d. tata cara penilaian dan konversi saham dari Perseroan yang akan diambil alih terhadap saham penukarnya apabila pembayaran pengambilalihan dilakukan dengan saham; e. jumlah saham yang akan diambil alih; f. kesiapan pendanaan; g. neraca konsolidasi proforma Perseroan yang akan mengambil alih setelah Pengambilalihan yang disusun sesuai dengan prinsip akuntansi yang berlaku umum di Indonesia; h. cara penyelesaian hak pemegang saham yang tidak setuju terhadap Pengambilalihan; i. cara penyelesaian status, hak dan kewajiban anggota Direksi, Dewan Komisaris, dan karyawan dari Perseroan yang akan diambil alih; j. perkiraan jangka waktu pelaksanaan Pengambilalihan, termasuk jangka waktu pemberian kuasa pengalihan saham dari pemegang saham kepada Direksi Perseroan; k. rancangan perubahan anggaran dasar Perseroan hasil Pengambilalihan apabila ada. (7) Dalam hal pengambilalihan saham dilakukan langsung dari pemegang saham, ketentuan sebagaimana dimaksud pada ayat (5) dan ayat (6) tidak berlaku. (8) Pengambilalihan saham sebagaimana dimaksud pada ayat (7) wajib memperhatikan ketentuan anggaran dasar Perseroan yang diambil alih tentang pemindahan hak atas saham dan perjanjian yang telah dibuat oleh Perseroan dengan pihak lain."},{"l":"UU PT No.40/2007","p":"126","b":"","t":"(1) Perbuatan hukum Penggabungan, Peleburan, Pengambilalihan, atau Pemisahan wajib memperhatikan kepentingan: a. Perseroan, pemegang saham minoritas, karyawan Perseroan; b. kreditor dan mitra usaha lainnya dari Perseroan; dan c. masyarakat dan persaingan sehat dalam melakukan usaha. (2) Pemegang saham yang tidak setuju terhadap keputusan RUPS mengenai Penggabungan, Peleburan, Pengambilalihan, atau Pemisahan sebagaimana dimaksud pada ayat (1) hanya boleh menggunakan haknya sebagaimana dimaksud dalam Pasal 62. (3) Pelaksanaan hak sebagaimana dimaksud pada ayat (2) tidak menghentikan proses pelaksanaan Penggabungan, Peleburan, Pengambilalihan, atau Pemisaha n."},{"l":"UU PT No.40/2007","p":"127","b":"","t":"(1) Keputusan RUPS mengenai Penggabungan, Peleburan, Pengambilalihan, atau Pemisahan sah apabila diambil sesuai dengan ketentuan Pasal 87 ayat (1) dan Pasal 89. (2) Direksi Perseroan yang akan melakukan Penggabungan, Peleburan, Pengambilalihan, atau Pemisahan wajib mengumumkan ringkasan rancangan paling sedikit dalam 1 (satu) surat kabar dan mengumumkan secara tertulis kepada karyawan dari Perseroan yang akan melakukan Penggabungan, Peleburan, Pengambilalihan, atau Pemisahan dalam jangka waktu paling lambat 30 (tiga puluh) hari sebelum pemanggilan RUPS. (3) Pengumuman sebagaimana dimaksud pada ayat (2) memuat juga pemberitahuan bahwa pihak yang berkepentingan dapat memperoleh rancangan Penggabungan, Peleburan, Pengambilalihan, atau Pemisahan di kantor Perseroan terhitung sejak tanggal pengumuman sampai tanggal RUPS diselenggarakan. (4) Kreditor dapat mengajukan keberatan kepada Perseroan dalam jangka waktu paling lambat 14 (empat belas) hari setelah pengumuman sebagaimana dimaksud pada ayat (2) mengenai Penggabungan, Peleburan, Pengambilalihan, atau Pemisahan sesuai dengan rancangan tersebut. - 34 - (5) Apabila dalam jangka waktu sebagaimana dimaksud pada ayat (4) kreditor tidak mengajukan keberatan, kreditor dianggap menyetujui Penggabungan, Peleburan, Pengambilalihan, atau Pemisahan. (6) Dalam hal keberatan kreditor sebagaimana dimaksud pada ayat (4) sampai dengan tanggal diselenggarakan RUPS tidak dapat diselesaikan oleh Direksi, keberatan tersebut harus disampaikan dalam RUPS guna mendapat penyelesaian. (7) Selama penyelesaian sebagaimana dimaksud pada ayat (6) belum tercapai, Penggabungan, Peleburan, Pengambilalihan, atau Pemisahan tidak dapat dilaksanakan. (8) Ketentuan sebagaimana dimaksud pada ayat (2), ayat (4), ayat (5), ayat (6), dan ayat (7) mutatis mutandis berlaku bagi pengumuman dalam rangka Pengambilalihan saham yang dilakukan langsung dari pemegang saham dalam Perseroan sebagaimana dimaksud dalam Pasal 125."},{"l":"UU PT No.40/2007","p":"128","b":"","t":"(1) Rancangan Penggabungan, Peleburan, Pengambilalihan, atau Pemisahan yang telah disetujui RUPS dituangkan ke dalam akta Penggabungan, Peleburan, Pengambilalihan, atau Pemisahan yang dibuat di hadapan notaris dalam bahasa Indonesia. (2) Akta pengambilalihan saham yang dilakukan langsung dari pemegang saham wajib dinyatakan dengan akta notaris dalam bahasa Indonesia. (3) Akta peleburan sebagaimana dimaksud pada ayat (1) menjadi dasar pembuatan akta pendirian Perseroan hasil Peleburan."},{"l":"UU PT No.40/2007","p":"129","b":"","t":"(1) Salinan akta Penggabungan Perseroan dilampirkan pada: a. pengajuan permohonan untuk mendapatkan persetujuan Menteri sebagaimana dimaksud dalam Pasal 21 ayat (1); atau b. penyampaian pemberitahuan kepada Menteri tentang perubahan anggaran dasar sebagaimana dimaksud dalam Pasal 21 ayat (3). (2) Dalam hal Penggabungan Perseroan tidak disertai perubahan anggaran dasar, salinan akta Penggabungan harus disampaikan kepada Menteri untuk dicatat dalam daftar Perseroan."},{"l":"UU PT No.40/2007","p":"130","b":"","t":"Salinan akta Peleburan dilampirkan pada pengajuan permohonan untuk mendapatkan keputusan menteri mengenai pengesahan badan hukum Perseroan hasil Peleburan sebagaimana dimaksud dalam Pasal 7 ayat (4)."},{"l":"UU PT No.40/2007","p":"131","b":"","t":"(1) Salinan akta Pengambilalihan Perseroan wajib dilampirkan pada penyampaian pemberitahuan kepada Menteri tentang perubahan anggaran dasar sebagaimana dimaksud dalam Pasal 21 ayat (3). (2) Dalam hal Pengambilalihan saham dilakukan secara langsung dari pemegang saham, salinan akta pemindahan hak atas saham wajib dilampirkan pada penyampaian pemberitahuan kepada Menteri tentang perubahan susunan pemegang saham."},{"l":"UU PT No.40/2007","p":"132","b":"","t":"Ketentuan sebagaimana dimaksud dalam Pasal 29 dan Pasal 30 berlaku juga bagi Penggabungan, Peleburan, Pengambilalihan, atau Pemisahan."},{"l":"UU PT No.40/2007","p":"133","b":"","t":"(1) Direksi Perseroan yang menerima Penggabungan atau Direksi Perseroan hasil Peleburan wajib mengumumkan hasil Penggabungan atau Peleburan dalam 1 (satu) surat kabar atau lebih dalam jangka waktu paling lambat 30 (tiga puluh) hari terhitung sejak tanggal berlakunya Penggabungan atau Peleburan. (2) Ketentuan sebagaimana dimaksud pada ayat (1) berlaku juga terhadap Direksi dari Perseroan yang sahamnya diambil alih. - 35 -"},{"l":"UU PT No.40/2007","p":"134","b":"","t":"Ketentuan lebih lanjut mengenai Penggabungan, Peleburan, atau Pengambilalihan Perseroan diatur dengan peraturan pemerintah."},{"l":"UU PT No.40/2007","p":"135","b":"","t":"(1) Pemisahan dapat dilakukan dengan cara: a. Pemisahan murni; atau b. Pemisahan tidak murni. (2) Pemisahan murni sebagaimana dimaksud pada ayat (1) huruf a mengakibatkan seluruh aktiva dan pasiva Perseroan beralih karena hukum kepada 2 (dua) Perseroan lain atau lebih yang menerima peralihan dan Perseroan yang melakukan pemisahan usaha tersebut berakhir karena hukum. (3) Pemisahan tidak murni sebagaimana dimaksud pada ayat (1) huruf b mengakibatkan sebagian aktiva dan pasiva Perseroan beralih karena hukum kepada 1 (satu) Perseroan lain atau lebih yang menerima peralihan, dan Perseroan yang melakukan Pemisahan tersebut tetap ada."},{"l":"UU PT No.40/2007","p":"136","b":"","t":"Ketentuan lebih lanjut mengenai Pemisahan diatur dengan peraturan pemerintah."},{"l":"UU PT No.40/2007","p":"137","b":"","t":"Dalam hal peraturan perundang-undangan di bidang pasar modal tidak mengatur lain, ketentuan sebagaimana dimaksud dalam Bab VIII berlaku juga bagi Perseroan Terbuka. BAB IX PEMERIKSAAN TERHADAP PERSEROAN"},{"l":"UU PT No.40/2007","p":"138","b":"","t":"(1) Pemeriksaan terhadap Perseroan dapat dilakukan dengan tujuan untuk mendapatkan data atau keterangan dalam hal terdapat dugaan bahwa: a. Perseroan melakukan perbuatan melawan hukum yang merugikan pemegang saham atau pihak ketiga; atau b. anggota Direksi atau Dewan Komisaris melakukan perbuatan melawan hukum yang merugikan Perseroan atau pemegang saham atau pihak ketiga. (2) Pemeriksaan sebagaimana dimaksud pada ayat (1) dilakukan dengan mengajukan permohonan secara tertulis beserta alasannya ke pengadilan negeri yang daerah hukumnya meliputi tempat kedudukan Perseroan. (3) Permohonan sebagaimana dimaksud pada ayat (2) dapat diajukan oleh: a. 1 (satu) pemegang saham atau lebih yang mewakili paling sedikit 1/10 (satu persepuluh) bagian dari jumlah seluruh saham dengan hak suara; b. pihak lain yang berdasarkan peraturan perundang- undangan, anggaran dasar Perseroan atau perjanjian dengan Perseroan diberi wewenang untuk mengajukan permohonan pemeriksaan; atau c. kejaksaan untuk kepentingan umum. (4) Permohonan sebagaimana dimaksud pada ayat (3) huruf a diajukan setelah pemohon terlebih dahulu meminta data atau keterangan kepada Perseroan dalam RUPS dan Perseroan tidak memberikan data atau keterangan tersebut. (5) Permohonan untuk mendapatkan data atau keterangan tentang Perseroan atau permohonan pemeriksaan untuk mendapatkan data atau keterangan tersebut harus didasarkan atas alasan yang wajar dan itikad baik. (6) Ketentuan sebagaimana dimaksud pada ayat (2), ayat (3) huruf a, dan ayat (4) tidak menutup kemungkinan peraturan perundang-undangan di bidang pasar modal menentukan lain."},{"l":"UU PT No.40/2007","p":"139","b":"","t":"(1) Ketua pengadilan negeri dapat menolak atau mengabulkan permohonan sebagaimana dimaksud dalam Pasal 138. - 36 - (2) Ketua pengadilan negeri sebagaimana dimaksud pada ayat (1) menolak permohonan apabila permohonan tersebut tidak didasarkan atas alasan yang wajar dan/atau tidak dilakukan dengan itikad baik. (3) Dalam hal permohonan dikabulkan, ketua pengadilan negeri mengeluarkan penetapan pemeriksaan dan mengangkat paling banyak 3 (tiga) orang ahli untuk melakukan pemeriksaan dengan tujuan untuk mendapatkan data atau keterangan yang diperlukan. (4) Setiap anggota Direksi, anggota Dewan Komisaris, karyawan Perseroan, konsultan, dan akuntan publik yang telah ditunjuk oleh Perseroan tidak dapat diangkat sebagai ahli sebagaimana dimaksud pada ayat (3). (5) Ahli sebagaimana dimaksud pada ayat (3) berhak memeriksa semua dokumen dan kekayaan Perseroan yang dianggap perlu oleh ahli tersebut untuk diketahui. (6) Setiap anggota Direksi, anggota Dewan Komisaris, dan semua karyawan Perseroan wajib memberikan segala keterangan yang diperlukan untuk pelaksanaan pemeriksaan. (7) Ahli sebagaimana dimaksud pada ayat (3) wajib merahasiakan hasil pemeriksaan yang telah dilakukan."},{"l":"UU PT No.40/2007","p":"140","b":"","t":"(1) Laporan hasil pemeriksaan disampaikan oleh ahli sebagaimana dimaksud dalam Pasal 139 kepada ketua pengadilan negeri dalam jangka waktu sebagaimana ditentukan dalam penetapan pengadilan untuk pemeriksaan paling lambat 90 (sembilan puluh) hari terhitung sejak tanggal pengangkatan ahli tersebut. (2) Ketua pengadilan negeri memberikan salinan laporan hasil pemeriksaan kepada pemohon dan Perseroan yang bersangkutan dalam jangka waktu paling lambat 14 (empat belas) hari terhitung sejak tanggal laporan hasil pemeriksaan diterima."},{"l":"UU PT No.40/2007","p":"141","b":"","t":"(1) Dalam hal permohonan untuk melakukan pemeriksaan dikabulkan, ketua pengadilan negeri menentukan jumlah maksimum biaya pemeriksaan. (2) Biaya pemeriksaan sebagaimana dimaksud pada ayat (1) dibayar oleh Perseroan. (3) Ketua pengadilan negeri atas permohonan Perseroan dapat membebankan penggantian seluruh atau sebagian biaya pemeriksaan sebagaimana dimaksud pada ayat (2) kepada pemohon, anggota Direksi, dan/atau anggota Dewan Komisaris. BAB X PEMBUBARAN, LIKUIDASI, DAN BERAKHIRNYA STATUS BADAN HUKUM PERSEROAN"},{"l":"UU PT No.40/2007","p":"142","b":"","t":"(1) Pembubaran Perseroan terjadi: a. berdasarkan keputusan RUPS; b. karena jangka waktu berdirinya yang ditetapkan dalam anggaran dasar telah berakhir; c. berdasarkan penetapan pengadilan; d. dengan dicabutnya kepailitan berdasarkan putusan pengadilan niaga yang telah mempunyai kekuatan hukum tetap, harta pailit Perseroan tidak cukup untuk membayar biaya kepailitan; e. karena harta pailit Perseroan yang telah dinyatakan pailit berada dalam keadaan insolvensi sebagaimana diatur dalam undang-undang tentang Kepailitan dan Penundaan Kewajiban Pembayaran Utang; atau f. karena dicabutnya izin usaha Perseroan sehingga mewajibkan Perseroan melakukan likuidasi sesuai dengan ketentuan peraturan perundang-undangan. (2) Dalam hal terjadi pembubaran Perseroan sebagaimana dimaksud pada ayat (1): a. wajib diikuti dengan likuidasi yang dilakukan oleh likuidator atau kurator; dan b. Perseroan tidak dapat melakukan perbuatan hukum, kecuali diperlukan untuk membereskan semua urusan Perseroan dalam rangka likuidasi. (3) Dalam hal pembubaran terjadi berdasarkan keputusan RUPS, jangka waktu berdirinya yang ditetapkan dalam anggaran dasar telah berakhir atau dengan dicabutnya kepailitan - 37 - berdasarkan keputusan pengadilan niaga dan RUPS tidak menunjuk likuidator, Direksi bertindak selaku likuidator. (4) Dalam hal pembubaran Perseroan terjadi dengan dicabutnya kepailitan sebagaimana dimaksud pada ayat (1) huruf d, pengadilan niaga sekaligus memutuskan pemberhentian kurator dengan memperhatikan ketentuan dalam undang-undang tentang Kepailitan dan Penundaan Kewajiban Pembayaran Utang. (5) Dalam hal ketentuan sebagaimana dimaksud pada ayat (2) huruf b dilanggar, anggota Direksi, anggota Dewan Komisaris, dan Perseroan bertanggung jawab secara tanggung renteng. (6) Ketentuan mengenai pengangkatan, pemberhentian sementara, pemberhentian, wewenang, kewajiban, tanggung jawab, dan pengawasan terhadap Direksi mutatis mutandis berlaku bagi likuidator."},{"l":"UU PT No.40/2007","p":"143","b":"","t":"(1) Pembubaran Perseroan tidak mengakibatkan Perseroan kehilangan status badan hukum sampai dengan selesainya likuidasi dan pertanggungjawaban likuidator diterima oleh RUPS atau pengadilan. (2) Sejak saat pembubaran pada setiap surat keluar Perseroan dicantumkan kata “dalam likuidasi” di belakang nama Perseroan."},{"l":"UU PT No.40/2007","p":"144","b":"","t":"(1) Direksi, Dewan Komisaris atau 1 (satu) pemegang saham atau lebih yang mewakili paling sedikit 1/10 (satu persepuluh) bagian dari jumlah seluruh saham dengan hak suara, dapat mengajukan usul pembubaran Perseroan kepada RUPS. (2) Keputusan RUPS tentang pembubaran Perseroan sah apabila diambil sesuai dengan ketentuan sebagaimana dimaksud dalam Pasal 87 ayat (1) dan Pasal 89. (3) Pembubaran Perseroan dimulai sejak saat yang ditetapkan dalam keputusan RUPS."},{"l":"UU PT No.40/2007","p":"145","b":"","t":"(1) Pembubaran Perseroan terjadi karena hukum apabila jangka waktu berdirinya Perseroan yang ditetapkan dalam anggaran dasar berakhir. (2) Dalam jangka waktu paling lambat 30 (tiga puluh) hari setelah jangka waktu berdirinya Perseroan berakhir RUPS menetapkan penunjukan likuidator. (3) Direksi tidak boleh melakukan perbuatan hukum baru atas nama Perseroan setelah jangka waktu berdirinya Perseroan yang ditetapkan dalam anggaran dasar berakhir."},{"l":"UU PT No.40/2007","p":"146","b":"","t":"(1) Pengadilan negeri dapat membubarkan Perseroan atas: a. permohonan kejaksaan berdasarkan alasan Perseroan melanggar kepentingan umum atau Perseroan melakukan perbuatan yang melanggar peraturan perundang-undangan; b. permohonan pihak yang berkepentingan berdasarkan alasan adanya cacat hukum dalam akta pendirian; c. permohonan pemegang saham, Direksi atau Dewan Komisaris berdasarkan alasan Perseroan tidak mungkin untuk dilanjutkan. (2) Dalam penetapan pengadilan ditetapkan juga penunjukan likuidator."},{"l":"UU PT No.40/2007","p":"147","b":"","t":"(1) Dalam jangka waktu paling lambat 30 (tiga puluh) hari terhitung sejak tanggal pembubaran Perseroan, likuidator wajib memberitahukan: a. kepada semua kreditor mengenai pembubaran Perseroan dengan cara mengumumkan pembubaran Perseroan dalam surat kabar dan Berita Negara Republik Indonesia; dan b. pembubaran Perseroan kepada Menteri untuk dicatat dalam daftar Perseroan bahwa Perseroan dalam likuidasi. (2) Pemberitahuan kepada kreditor dalam surat kabar dan Berita Negara Republik Indonesia sebagaimana dimaksud pada ayat (1) huruf a memuat: a. pembubaran Perseroan dan dasar hukumnya; b. nama dan alamat likuidator; - 38 - c. tata cara pengajuan tagihan; dan d. jangka waktu pengajuan tagihan. (3) Jangka waktu pengajuan tagihan sebagaimana dimaksud pada ayat (2) huruf d adalah 60 (enam puluh) hari terhitung sejak tanggal pengumuman sebagaimana dimaksud pada ayat (1). (4) Pemberitahuan kepada Menteri sebagaimana dimaksud pada ayat (1) huruf b wajib dilengkapi dengan bukti: a. dasar hukum pembubaran Perseroan; dan b. pemberitahuan kepada kreditor dalam surat kabar sebagaimana dimaksud pada ayat (1) huruf a."},{"l":"UU PT No.40/2007","p":"148","b":"","t":"(1) Dalam hal pemberitahuan kepada kreditor dan Menteri sebagaimana dimaksud dalam Pasal 147 belum dilakukan, pembubaran Perseroan tidak berlaku bagi pihak ketiga. (2) Dalam hal likuidator lalai melakukan pemberitahuan sebagaimana dimaksud pada ayat (1), likuidator secara tanggung renteng dengan Perseroan bertanggung jawab atas kerugian yang diderita pihak ketiga."},{"l":"UU PT No.40/2007","p":"149","b":"","t":"(1) Kewajiban likuidator dalam melakukan pemberesan harta kekayaan Perseroan dalam proses likuidasi meliputi pelaksanaan: a. pencatatan dan pengumpulan kekayaan dan utang Perseroan; b. pengumuman dalam surat kabar dan Berita Negara Republik Indonesia mengenai rencana pembagian kekayaan hasil likuidasi; c. pembayaran kepada para kreditor; d. pembayaran sisa kekayaan hasil likuidasi kepada pemegang saham; dan e. tindakan lain yang perlu dilakukan dalam pelaksanaan pemberesan kekayaan. (2) Dalam hal likuidator memperkirakan bahwa utang Perseroan lebih besar daripada kekayaan Perseroan, likuidator wajib mengajukan permohonan pailit Perseroan, kecuali peraturan perundang-undangan menentukan lain, dan semua kreditor yang diketahui identitas dan alamatnya, menyetujui pemberesan dilakukan di luar kepailitan. (3) Kreditor dapat mengajukan keberatan atas rencana pembagian kekayaan hasil likuidasi dalam jangka waktu paling lambat 60 (enam) puluh hari terhitung sejak tanggal pengumuman sebagaimana dimaksud pada ayat (1) huruf b. (4) Dalam hal pengajuan keberatan sebagaimana dimaksud pada ayat (3) ditolak oleh likuidator, kreditor dapat mengajukan gugatan ke pengadilan negeri dalam jangka waktu paling lambat 60 (enam puluh) hari terhitung sejak tanggal penolakan."},{"l":"UU PT No.40/2007","p":"150","b":"","t":"(1) Kreditor yang mengajukan tagihan sesuai dengan jangka waktu sebaga imana dimaksud dalam Pasal 147 ayat (3), dan kemudian ditolak oleh likuidator dapat mengajukan gugatan ke pengadilan negeri dalam jangka waktu paling lambat 60 (enam puluh) hari terhitung sejak tanggal penolakan. (2) Kreditor yang belum mengajukan tagihannya dapat mengajukan melalui pengadilan negeri dalam jangka waktu 2 (dua) tahun terhitung sejak pembubaran Perseroan diumumkan sebagaimana dimaksud dalam Pasal 147 ayat (1). (3) Tagihan yang diajukan kreditor sebagaimana dimaksud pada ayat (2) dapat dilakukan dalam hal terdapat sisa kekayaan hasil likuidasi yang diperuntukkan bagi pemegang saham. (4) Dalam hal sisa kekayaan hasil likuidasi telah dibagikan kepada pemegang saham dan terdapat tagihan kreditor sebagaimana dimaksud pada ayat (2), pengadilan negeri memerintahkan likuidator untuk menarik kembali sisa kekayaan hasil likuidasi yang telah dibagikan kepada pemegang saham. (5) Pemegang saham wajib mengembalikan sisa kekayaan hasil likuidasi sebagaimana dimaksud pada ayat (4) secara proporsional dengan jumlah yang diterima terhadap jumlah tagihan. - 39 -"},{"l":"UU PT No.40/2007","p":"151","b":"","t":"(1) Dalam hal likuidator tidak dapat melaksanakan kewajibannya sebagaimana dimaksud dalam Pasal 149, atas permohonan pihak yang berkepentingan atau atas permohonan kejaksaan, ketua pengadilan negeri dapat mengangkat likuidator baru dan memberhentikan likuidator lama. (2) Pemberhentian likuidator sebagaimana dimaksud pada ayat (1), dilakukan setelah yang bersangkutan dipanggil untuk didengar keterangannya."},{"l":"UU PT No.40/2007","p":"152","b":"","t":"(1) Likuidator bertanggung jawab kepada RUPS atau pengadilan yang mengangkatnya atas likuidasi Perseroan yang dilakukan. (2) Kurator bertanggung jawab kepada hakim pengawas atas likuidasi Perseroan yang dilakukan. (3) Likuidator wajib memberitahukan kepada Menteri dan mengumumkan hasil akhir proses likuidasi dalam surat kabar setelah RUPS memberikan pelunasan dan pembebasan kepada likuidator atau setelah pengadilan menerima pertanggungjawaban likuidator yang ditunjuknya. (4) Ketentuan sebagaimana dimaksud pada ayat (3) berlaku juga bagi kurator yang pertanggungjawabannya telah diterima oleh hakim pengawas. (5) Menteri mencatat berakhirnya status badan hukum Perseroan dan menghapus nama Perseroan dari daftar Perseroan, setelah ketentuan sebagaimana dimaksud pada ayat (3) dan ayat (4) dipenuhi. (6) Ketentuan sebagaimana dimaksud pada ayat (5) berlaku juga bagi berakhirnya status badan hukum Perseroan karena Penggabungan, Peleburan, atau Pemisahan. (7) Pemberitahuan dan pengumuman sebagaimana dimaksud pada ayat (3) dan ayat (4) dilakukan dalam jangka waktu paling lambat 30 (tiga puluh) hari terhitung sejak tanggal pertanggungjawaban likuidator atau kurator diterima oleh RUPS, pengadilan atau hakim pengawas. (8) Menteri mengumumkan berakhirnya status badan hukum Perseroan dalam Berita Negara Republik Indonesia. BAB XI BIAYA"},{"l":"UU PT No.40/2007","p":"153","b":"","t":"Ketentuan mengenai biaya untuk: a. memperoleh persetujuan pemakaian nama Perseroan; b. memperoleh keputusan pengesahan badan hukum Perseroan; c. memperoleh keputusan persetujuan perubahan anggaran dasar; d. memperoleh informasi tentang data Perseroan dalam daftar Perseroan; e. pengumuman yang diwajibkan dalam undang-undang ini dalam Berita Negara Republik Indonesia dan Tambahan Berita Negara Republik Indonesia; dan f. memperoleh salinan keputusan menteri mengenai pengesahan badan hukum Perseroan atau persetujuan perubahan anggaran dasar Perseroan diatur dengan peraturan pemerintah. BAB XII KETENTUAN LAIN-LAIN"},{"l":"UU PT No.40/2007","p":"154","b":"","t":"(1) Bagi Perseroan Terbuka berlaku ketentuan undang-undang ini jika tidak diatur lain dalam peraturan perundang-undangan di bidang pasar modal. (2) Peraturan perundang- undangan di bidang pasar modal yang mengecualikan ketentuan undang-undang ini tidak boleh bertentangan dengan asas hukum Perseroan dalam undang- undang ini. - 40 -"},{"l":"UU PT No.40/2007","p":"155","b":"","t":"Ketentuan mengenai tanggung jawab Direksi dan/atau Dewan Komisaris atas kesalahan dan kelalaiannya yang diatur dalam undang-undang ini tidak mengurangi ketentuan yang diatur dalam undang- undang tentang Hukum Pidana."},{"l":"UU PT No.40/2007","p":"156","b":"","t":"(1) Dalam rangka pelaksanaan dan perkembangan undang-undang ini dibentuk tim ahli pemantauan hukum Perseroan. (2) Keanggotaan tim sebaga imana dimaksud pada ayat (1) terdiri atas unsur: a. pemerintah; b. pakar/akademisi; c. profesi; dan d. dunia usaha. (3) Tim ahli berwenang mengkaji akta pendirian dan perubahan anggaran dasar yang diperoleh atas inisiatif sendiri dari tim atau atas permintaan pihak yang berkepentingan, serta memberikan pendapat atas hasil kajian tersebut kepada Menteri. (4) Ketentuan lebih lanjut mengenai kewenangan, susunan organisasi dan tata kerja tim ahli diatur dengan peraturan menteri. BAB XIII KETENTUAN PERALIHAN"},{"l":"UU PT No.40/2007","p":"157","b":"","t":"(1) Anggaran dasar dari Perseroan yang telah memperoleh status badan hukum dan perubahan anggaran dasar yang telah disetujui atau dilaporkan kepada Menteri dan didaftarkan dalam daftar perusahaan sebelum undang- undang ini berlaku tetap berlaku jika tidak bertentangan dengan undang- undang ini. (2) Anggaran dasar dari Perseroan yang belum memperoleh status badan hukum atau anggaran dasar yang perubahannya belum disetujui atau dilaporkan kepada Menteri pada saat undang- undang ini mulai berlaku, wajib disesuaikan dengan undang-undang ini. (3) Perseroan yang telah memperoleh status badan hukum berdasarkan peraturan perundang- undangan, dalam jangka waktu 1 (satu) tahun setelah berlakunya undang- undang ini wajib menyesuaikan anggaran dasarnya dengan ketentuan undang-undang ini. (4) Perseroan yang tidak menyesuaikan anggaran dasarnya dalam jangka waktu sebagaimana dimaksud pada ayat (3) dapat dibubarkan berdasarkan putusan pengadilan negeri atas permohonan kejaksaan atau pihak yang berkepentingan."},{"l":"UU PT No.40/2007","p":"158","b":"","t":"Pada saat undang-undang ini mulai berlaku, Perseroan yang tidak memenuhi ketentuan sebagaimana dimaksud dalam Pasal 36, dalam jangka waktu 1 (satu) tahun harus menyesuaikan dengan ketentuan undang-undang ini. BAB XIV KETENTUAN PENUTUP"},{"l":"UU PT No.40/2007","p":"159","b":"","t":"Peraturan pelaksanaan dari Undang-Undang Nomor 1 Tahun 1995 tentang Perseroan Terbatas dinyatakan tetap berlaku sepanjang tidak bertentangan atau belum diganti dengan yang baru berdasarkan undang- undang ini."},{"l":"UU PT No.40/2007","p":"160","b":"","t":"Pada saat undang- undang ini mulai berlaku, Undang-Undang Nomor 1 Tahun 1995 tentang Perseroan Terbatas (Lembaran Negara Republik Indonesia Tahun 1995 Nomor 13, Tambahan Lembaran Negara Republik Indonesia Nomor 3587), dicabut dan dinyatakan tidak berlaku. - 41 -"},{"l":"UU PT No.40/2007","p":"161","b":"","t":"Undang-undang ini mulai berlaku pada tanggal diundangkan. Agar setiap orang mengetahuinya, memerintahkan pengundangan undang- undang ini dengan penempatannya dalam Lembaran Negara Republik Indonesia. Disahkan di Jakarta pada tanggal 16 Agustus 2007 PRESIDEN REPUBLIK INDONESIA, ttd DR. H. SUSILO BAMBANG YUDHOYONO Diundangkan di Jakarta pada tanggal 16 Agustus 2007 MENTERI HUKUM DAN HAK ASASI MANUSIA REPUBLIK INDONESIA, ttd ANDI MATTALATTA LEMBARAN NEGARA REPUBLIK INDONESIA TAHUN 2007 NOMOR 106 - 42 -"},{"l":"UUD 1945","p":"1","b":"","t":"Panitia Persiapan Kemerdekaan Indonesia mengatur dan menyelenggarakan kepindahan pemerintahan kepada Pemerintah Indonesia . Pasal II Segala badan negara dan peraturan yang ada masih langsung berlaku, selama belum diadakan yang baru menurut Undang-Undang Dasar ini. Pasal III Untuk pertama kali Presiden dan Wakil Presiden dipilih oleh Panitia Persiapan Kemerdekaan Indonesia. Pasal IV Sebelum Majelis Permusyawaratan Rakyat, Dewan Perwakilan Rakyat, dan Dewan Pertimbangan Agung dibentuk menurut Undang-Undang Dasar ini, segala kekuasaannya dijalankan oleh Presiden dengan bantuan sebuah komite nasional. ATURAN PERTAMBAHAN (1) Dalam enam bulan sesudah akhirnya peperangan Asia Timur Raya, Presiden Indonesia mengatur dan menyelenggarakan segala hal yang ditetapkan dalam Undang-Undang Dasar ini. (2) Dalam enam bulan sesudah Majelis Permusyawaratan Rakyat dibentuk, Majelis itu bersidang untuk menetapkan Undang-Undang Dasar."},{"l":"UUD 1945","p":"2","b":"","t":"(1) Majelis Permusyawaratan Rakyat terdiri atas anggota-anggota Dewan Perwakilan Rakyat, ditambah dengan utusan-utusan dari daerah-daerah dan golongan-golongan, menurut aturan yang ditetapkan dengan undang-undang. (2) Majelis Permusyawaratan Rakyat bersidang sedikitnya sekali dalam lima tahun di ibukota negara. (3) Segala putusan Majelis Permusyawaratan Rakyat ditetapkan dengan suara yang terbanyak."},{"l":"UUD 1945","p":"3","b":"","t":"Majelis Permusyawaratan Rakyat menetapkan Undang-Undang Dasar dan garis-garis besar dari ada haluan negara. BAB III KEKUASAAN PEMERINTAH NEGARA"},{"l":"UUD 1945","p":"4","b":"","t":"(1) Presiden Republik Indonesia memegang kekuasaan pemerintahan menurut Undang- Undang Dasar. (2) Dalam melakukan kewajibannya Presiden dibantu oleh satu orang Wakil Presiden."},{"l":"UUD 1945","p":"5","b":"","t":"(1) Presiden memegang kekuasaan membentuk undang- undang dengan persetujuan Dewan Perwakilan Rakyat. (2) Presiden menetapkan peraturan pemerintah untuk menjalankan undang-undang sebagaimana mestinya."},{"l":"UUD 1945","p":"6","b":"","t":"(1) Presiden ialah orang Indonesia asli. (2) Presiden dan Wakil Presiden dipilih oleh Majelis Permusyawaratan Rakyat dengan suara yang terbanyak."},{"l":"UUD 1945","p":"7","b":"","t":"Presiden dan Wakil Presiden memegang jabatannya selama masa lima tahun, dan sesudahnya dapat dipilih kembali."},{"l":"UUD 1945","p":"8","b":"","t":"Jika Presiden mangkat, berhenti, atau tidak dapat melakukan kewajibannya dalam masa jabatannya, ia diganti oleh Wakil Presiden sampai habis waktunya."},{"l":"UUD 1945","p":"9","b":"","t":"Sebelum memangku jabatannya, Presiden dan Wakil Presiden bersumpah menurut agama, atau berjanji dengan sungguh-sungguh di hadapan Majelis Permusyawaratan Rakyat atau Dewan Perwakilan Rakyat sebagai berikut: Sumpah Presiden (Wakil Presiden): \"Demi Allah, saya bersumpah akan memenuhi kewajiban Presiden Republik Indonesia (Wakil Presiden Republik Indonesia) dengan sebaik-baiknya dan seadil-adilnya, memegang teguh Undang- Undang Dasar dan menjalankan segala undang-undang dan peraturannya dengan selurus-lurusnya serta berbakti kepada Nusa dan Bangsa. \"Janji Presiden (WakilPresiden): \"Saya berjanji dengan sungguh-sungguh akan memenuhi kewajiban Presiden Republik Indonesia (Wakil Presiden Republik Indonesia) dengan sebaik-baiknya dan seadil- adilnya, memegang teguh Undang-Undang Dasar dan menjalankan segala undang- undang dan peraturannya dengan seluruslurusnya serta berbakti kepada Nusa dan Bangsa.\""},{"l":"UUD 1945","p":"10","b":"","t":"Presiden memegang kekuasaan yang tertinggi atas Angkatan Darat, Angkatan Laut, dan Angkatan Udara."},{"l":"UUD 1945","p":"11","b":"","t":"Presiden dengan persetujuan Dewan Perwakilan Rakyat menyatakan perang, membuat perdamaian dan perjanjian dengan negara lain."},{"l":"UUD 1945","p":"12","b":"","t":"Presiden menyatakan keadaan bahaya. Syarat-syarat dan akibatnya keadaan bahaya ditetapkan dengan undang-undang."},{"l":"UUD 1945","p":"13","b":"","t":"(1) Presiden mengangkat duta dan konsul. (2) Presiden menerima duta negara lain."},{"l":"UUD 1945","p":"14","b":"","t":"Presiden memberi grasi, amnesti, abolisi, dan rehabilitasi."},{"l":"UUD 1945","p":"15","b":"","t":"Presiden memberi gelaran, tanda jasa ,dan lain-lain tanda kehormatan. BAB IV DEWAN PERTIMBANGAN AGUNG"},{"l":"UUD 1945","p":"16","b":"","t":"(1) Susunan Dewan Pertimbangan Agung ditetapkan dengan undang-undang. (2) Dewan ini berkewajiban memberi jawab atas pertanyaan Presiden dan berhak memajukan usul kepada pemerintah. BAB V KEMENTERIAN NEGARA"},{"l":"UUD 1945","p":"17","b":"","t":"(1) Presiden dibantu oleh menteri-menteri negara. (2) Menteri-menteri itu diangkat dan diperhentikan oleh Presiden. (3) Menteri-menteri itu memimpin departemen pemerintahan. BAB VI PEMERINTAHAN DAERAH"},{"l":"UUD 1945","p":"18","b":"","t":"Pembagian daerah Indonesia atas daerah besar dan kecil, dengan bentuk susunan pemerintahannya ditetapkan dengan undang-undang, dengan memandang dan mengingati dasar permusyawaratan dalam sistem pemerintahan negara, dan hak-hak asal-usul dalam daerah-daerah yang bersifat istimewa. BAB VII DEWAN PERWAKILAN RAKYAT"},{"l":"UUD 1945","p":"19","b":"","t":"(1) Susunan Dewan Perwakilan Rakyat ditetapkan dengan undang-undang. (2) Dewan Perwakilan Rakyat bersidang sedikitnya sekali dalam setahun."},{"l":"UUD 1945","p":"20","b":"","t":"(1) Tiap-tiap undang-undang menghendaki persetujuan Dewan Perwakilan Rakyat. (2) Jika sesuatu rancangan undang-undang tidak mendapat persetujuan Dewan Perwakilan Rakyat, maka rancangan tadi tidak boleh dimajukan lagi dalam persidangan Dewan Perwakilan Rakyat masa itu."},{"l":"UUD 1945","p":"21","b":"","t":"(1) Anggota-anggota Dewan Perwakilan Rakyat berhak memajukan rancangan undang- undang. (2) Jika rancangan itu, meskipun disetujui oleh Dewan Perwakilan Rakyat, tidak disyahkan oleh Presiden, maka rancangan tadi tidak boleh dimajukan lagi dalam persidangan Dewan Perwakilan Rakyat masa itu."},{"l":"UUD 1945","p":"22","b":"","t":"(1) Dalam hal ihwal kegentingan yang memaksa, Presiden berhak menetapkan peraturan pemerintah pengganti undang-undang. (2) Peraturan pemerintah itu harus mendapat persetujuan Dewan Perwakilan Rakyat dalam persidangan yang berikut. (3) Jika tidak mendapat persetujuan, maka peraturan pemerintah itu harus dicabut. BAB VIII HAL KEUANGAN"},{"l":"UUD 1945","p":"23","b":"","t":"(1) Anggaran pendapatan dan belanja ditetapkan tiap-tiap tahun dengan undang-undang. Apabila Dewan Perwakilan Rakyat tidak menyetujui anggaran yang diusulkan pemerintah, maka pemerintah menjalankan anggaran tahun yang lalu. (2) Segala pajak untuk keperluan negara berdasarkan undang-undang. (3) Macam dan harga mata uang ditetapkan dengan undang-undang. (4) Hal keuangan negara selanjutnya diatur dengan undang-undang. (5) Untuk memeriksa tanggung jawab tentang keuangan negara diadakan suatu Badan Pemeriksa Keuangan, yang peraturannya ditetapkan dengan undang-undang. Hasil pemeriksaan itu diberitahukan kepada Dewan Perwakilan Rakyat. BAB IX KEKUASAAN KEHAKIMAN"},{"l":"UUD 1945","p":"24","b":"","t":"(1) Kekuasaan Kehakiman dilakukan oleh sebuah Mahkamah Agung dan lain-lain badan kehakiman menurut undang-undang. (2) Susunan dan kekuasaan badan kehakiman itu diatur dengan undang-undang."},{"l":"UUD 1945","p":"25","b":"","t":"Syarat-syarat untuk menjadi dan diperhentikan sebagai hakim ditetapkan dengan undang- undang. BAB X WARGA NEGARA"},{"l":"UUD 1945","p":"26","b":"","t":"(1) Yang menjadi warga negara ialah orang-orang bangsa Indonesia asli dan orang-orang bangsa lain yang disahkan dengan undang-undang sebagai warga negara. (2) Syarat-syarat yang mengenai kewarganegaraan ditetapkan dengan undang-undang."},{"l":"UUD 1945","p":"27","b":"","t":"(1) Segala warga negara bersamaan kedudukannya dalam hukum dan pemerintahan dan wajib menjunjung hukum dan pemerintahan itu dengan tidak ada kecualinya. (2) Tiap-tiap warga negara berhak atas pekerjaan dan penghidupan yang layak bagi kemanusiaan."},{"l":"UUD 1945","p":"28","b":"","t":"Kemerdekaan berserikat dan berkumpul, mengeluarkan pikiran dengan lisan dan tulisan dan sebagainya ditetapkan dengan undang-undang. BAB XI AGAMA"},{"l":"UUD 1945","p":"29","b":"","t":"(1) Negara berdasar atas Ketuhanan Yang Maha Esa. (2) Negara menjamin kemerdekaan tiap-tiap penduduk untuk memeluk agamanya masing-masing dan untuk beribadat menurut agamanya dan kepercayaannya itu. BAB XII PERTAHANAN NEGARA"},{"l":"UUD 1945","p":"30","b":"","t":"(1) Tiap-tiap warga negara berhak dan wajib ikut serta dalam usaha pembelaan negara. (2) Syarat-syarat tentang pembelaan diatur dengan undang-undang. BAB XIII PENDIDIKAN"},{"l":"UUD 1945","p":"31","b":"","t":"(1) Tiap-tiap warga negara berhak mendapat pengajaran. (2) Pemerintah mengusahakan dan menyelenggarakan satu sistem pengajaran nasional, yang diatur dengan undang-undang."},{"l":"UUD 1945","p":"32","b":"","t":"Pemerintah memajukan kebudayaan nasional Indonesia. BAB XIV KESEJAHTERAAN SOSIAL"},{"l":"UUD 1945","p":"33","b":"","t":"(1) Perekonomian disusun sebagai usaha bersama berdasar atas asas kekeluargaan. (2) Cabang-cabang produksi yang penting bagi negara dan yang menguasai hajat hidup orang banyak dikuasai oleh negara. (3) Bumi dan air dan kekayaan alam yang terkandung didalamnya dikuasai oleh negara dan dipergunakan untuk sebesar-besar kemakmuran rakyat."},{"l":"UUD 1945","p":"34","b":"","t":"Fakir miskin dan anak-anakyang terlantar dipelihara oleh negara. BAB XV BENDERA DAN BAHASA"},{"l":"UUD 1945","p":"35","b":"","t":"Bendera Negara Indonesia ialah Sang Merah Putih."},{"l":"UUD 1945","p":"36","b":"","t":"Bahasa negara ialah Bahasa Indonesia. BAB XVI PERUBAHAN UNDANG-UNDANG DASAR"},{"l":"UUD 1945","p":"37","b":"","t":"(1) Untuk mengubah Undang-Undang Dasar sekurang-kurangnya 2/3 dari pada jumlah anggota Majelis Permusyawaratan Rakyat harus hadir. (2) Putusan diambil dengan persetujuan sekurang-kurangnya 2/3 dari pada jumlah anggota Majelis Permusyawaratan Rakyat yang hadir. ATURAN PERALIHAN"},{"l": "UU 37/2004", "p": "1", "b": "BAB I KETENTUAN UMUM", "t": "Dalam Undang-Undang ini yang dimaksud dengan : 1. Kepailitan adalah sita umum atas semua kekayaan Debitor Pailit yang pengurusan dan pemberesannya dilakukan oleh Kurator di bawah pengawasan Hakim Pengawas sebagaimana diatur dalam Undang-Undang ini. 2. Kreditor adalah orang yang mempunyai piutang karena per-janjian atau Undang-Undang yang dapat ditagih di muka pengadilan. 3. Debitor adalah orang yang mempunyai utang karena perjanjian atau undang-undang yang pelunasannya dapat ditagih di muka pengadilan. 4. Debitor pailit adalah debitor yang sudah dinyatakan pailit dengan putusan Pengadilan. 5. Kurator adalah Balai Harta Peninggalan atau orang perseorangan yang diangkat oleh Pengadilan untuk mengurus dan memberes-kan harta Debitor Pailit di bawah pengawasan Hakim Pengawas sesuai dengan Undang-Undang ini. 6. Utang … 6. Utang adalah kewajiban yang dinyatakan atau dapat dinyatakan dalam jumlah uang baik dalam mata uang Indonesia maupun mata uang asing, baik secara langsung maupun yang akan timbul di kemudian hari atau kontinjen, yang timbul karena perjanjian atau undang-undang dan yang wajib dipenuhi oleh Debitor dan bila tidak dipenuhi memberi hak kepada Kreditor untuk mendapat …"}, {"l": "UU 37/2004", "p": "2", "b": "Bagian Kesatu", "t": "(1) Debitor yang mempunyai dua atau lebih Kreditor dan tidak membayar lunas sedikitnya satu utang yang telah jatuh waktu dan dapat ditagih, dinyatakan pailit dengan putusan Pengadilan, baik atas permohonannya sendiri maupun atas permohonan satu atau lebih kreditornya. (2) Permohonan … (2) Permohonan sebagaimana dimaksud pada ayat (1) dapat juga diajukan oleh kejaksaan untuk kepentingan umum. (3) Dalam hal Debitor adalah bank, permohonan pernyataan pailit hanya dapat diajukan oleh Bank Indonesia. (4) Dalam hal Debitor adalah Perusahaan Efek, Bursa Efek, Lembaga Kliring dan Penjaminan, Lembaga Penyimpanan dan Penyelesaian, permohonan pernyataan pailit hanya dapat diajukan oleh Badan Pengawas Pasar Modal. (5) Dalam hal Debitor adalah Perusahaan Asuransi, Perusahaan Reasuransi, Dana Pensiun, atau Badan Usaha Milik Negara yang bergerak di bidang kepentingan publik, permohonan pernyataan pailit hanya dapat diajukan oleh Menteri Keuangan."}, {"l": "UU 37/2004", "p": "3", "b": "Bagian Kesatu", "t": "(1) Putusan atas permohonan pernyataan pailit dan hal-hal lain yang berkaitan dan/atau diatur dalam Undang-Undang ini, diputuskan oleh Pengadilan yang daerah hukumnya meliputi daerah tempat kedudukan hukum Debitor. (2) Dalam hal Debitor telah meninggalkan wilayah Negara Republik Indonesia, Pengadilan yang berwenang menjatuhkan putusan atas permohonan pernyataan pailit adalah Pengadilan yang daerah hukumnya meliputi tempat kedudukan hukum terakhir Debitor. (3) Dalam hal Debitor adalah pesero suatu firma, Pengadilan yang daerah hukumnya meliputi tempat kedudukan hukum firma tersebut juga berwenang memutuskan. (4) Dalam hal debitur tidak berkedudukan di wilayah negara Republik Indonesia tetapi menjalankan profesi atau usahanya di wilayah negara Pengadilan yang daerah hukumnya meliputi tempat kedudukan atau kantor pusat Debitor menjalankan profesi atau usahanya di wilayah negara (5) Dalam … (5) Dalam hal Debitor merupakan badan hukum, tempat kedudukan hukumnya adalah sebagaimana dimaksud dalam anggaran dasarnya."}, {"l": "UU 37/2004", "p": "4", "b": "Bagian Kesatu", "t": "(1) Dalam hal permohonan pernyataan pailit diajukan oleh Debitor yang masih terikat dalam pernikahan yang sah, permohonan hanya dapat diajukan atas persetujuan suami atau istrinya. (2) Ketentuan sebagaimana dimaksud pada ayat (1) tidak berlaku apabila tidak ada persatuan harta."}, {"l": "UU 37/2004", "p": "5", "b": "Bagian Kesatu", "t": "Permohonan pernyataan pailit terhadap suatu firma harus memuat nama dan tempat tinggal masing-masing pesero yang secara tanggung renteng terikat untuk seluruh utang firma."}, {"l": "UU 37/2004", "p": "6", "b": "Bagian Kesatu", "t": "(1) Permohonan pernyataan pailit diajukan kepada Ketua Pengadilan. (2) Panitera mendaftarkan permohonan pernyataan pailit pada tanggal permohonan yang bersangkutan diajukan, dan kepada pemohon diberikan tanda terima tertulis yang ditandatangani oleh pejabat yang berwenang dengan tanggal yang sama dengan tanggal pendaftaran. (3) Panitera wajib menolak pendaftaran permohonan pernyataan pailit bagi institusi sebagaimana dimaksud dalam Pasal 2 ayat (3), ayat (4), dan ayat (5) jika dilakukan tidak sesuai dengan ketentuan dalam ayat-ayat tersebut. (4) Panitera menyampaikan permohonan pernyataan pailit kepada Ketua Pengadilan paling lambat 2 (dua) hari setelah tanggal permohonan didaftarkan. (5) Dalam … (5) Dalam jangka waktu paling lambat 3 (tiga) hari setelah tanggal permohonan pernyataan pailit didaftarkan, Pengadilan mempelajari permohonan dan menetapkan hari sidang. (6) Sidang pemeriksaan atas permohonan pernyataan pailit diselenggarakan dalam jangka waktu paling lambat 20 (dua puluh) hari setelah tanggal permohonan didaftarkan. (7) Atas permohonan Debitor dan berdasarkan alasan yang cukup, Pengadilan dapat menunda penyelenggaraan sidang sebagaimana dimaksud pada ayat (5) sampai …"}, {"l": "UU 37/2004", "p": "7", "b": "Bagian Kesatu", "t": "(1) Permohonan sebagaimana dimaksud dalam Pasal 6, Pasal 10, Pasal 11, Pasal 12, Pasal 43, Pasal 56, Pasal 57, Pasal 58, Pasal 68, Pasal 161, Pasal 171, Pasal 207, dan Pasal 212 harus diajukan oleh seorang advokat. (2) Ketentuan sebagaimana dimaksud pada ayat (1) tidak berlaku dalam hal permohonan diajukan oleh kejaksaan, Bank Indonesia, Badan Pengawas Pasar Modal, dan Menteri Keuangan."}, {"l": "UU 37/2004", "p": "8", "b": "Bagian Kesatu", "t": "(1) Pengadilan : a. wajib memanggil Debitor, dalam hal permohonan pernyataan pailit diajukan oleh Kreditor, kejaksaan, Bank Indonesia, Badan Pengawas Pasar Modal, atau Menteri Keuangan; b. dapat memanggil Kreditor, dalam hal permohonan pernyataan pailit diajukan oleh Debitor dan terdapat keraguan bahwa persyaratan untuk dinyatakan pailit sebagaimana dimaksud dalam Pasal 2 ayat (1) telah terpenuhi. (2) Pemanggilan … (2) Pemanggilan sebagaimana dimaksud pada ayat (1) dilakukan oleh juru sita dengan surat kilat tercatat paling lambat 7 (tujuh) hari sebelum sidang pemeriksaan pertama diselenggarakan. (3) Pemanggilan adalah sah dan dianggap telah diterima oleh Debitor, jika dilakukan oleh juru sita sesuai dengan ketentuan sebagaimana dimaksud pada ayat (2). (4) Permohonan pernyataan pailit harus dikabulkan apabila terdapat fakta atau keadaan yang terbukti secara sederhana bahwa persyaratan untuk dinyatakan pailit sebagaimana dimaksud dalam Pasal 2 ayat (1) telah dipenuhi. (5) Putusan Pengadilan atas permohonan pernyataan pailit harus diucapkan paling lambat 60 (enam puluh) hari setelah tanggal permohonan pernyataan pailit didaftarkan. (6) Putusan Pengadilan sebagaimana dimaksud pada …"}, {"l": "UU 37/2004", "p": "9", "b": "Bagian Kesatu", "t": "wajib disampaikan oleh juru sita dengan surat kilat tercatat kepada Debitor, pihak yang mengajukan permohonan pernyataan pailit, Kurator, dan Hakim Pengawas paling lambat 3 (tiga) hari setelah tanggal putusan atas permohonan pernyataan pailit diucapkan."}, {"l": "UU 37/2004", "p": "10", "b": "Bagian Kesatu", "t": "(1) Selama putusan atas permohonan pernyataan pailit belum diucapkan, setiap Kreditor, kejaksaan, Bank Indonesia, Badan Pengawas Pasar Modal, atau Menteri Keuangan dapat mengajukan permohonan kepada Pengadilan untuk: a. meletakkan sita jaminan terhadap sebagian atau seluruh kekayaan Debitor; atau b. menunjuk Kurator sementara untuk mengawasi: 1) pengelolaan usaha Debitor; dan 2) pembayaran kepada Kreditor, pengalihan, atau pengagunan kekayaan Debitor yang dalam kepailitan merupakan wewenang Kurator. (2) Permohonan sebagaimana dimaksud pada ayat (1) hanya dapat dikabulkan, apabila hal tersebut diperlukan guna melindungi kepentingan Kreditor. (3) Dalam hal permohonan sebagaimana dimaksud pada ayat (1) huruf a dikabulkan, Pengadilan dapat menetapkan syarat agar Kreditor pemohon memberikan jaminan yang dianggap wajar oleh Pengadilan."}, {"l": "UU 37/2004", "p": "11", "b": "Bagian Kesatu", "t": "(1) Upaya hukum yang dapat diajukan terhadap putusan atas permohonan pernyataan pailit adalah kasasi ke Mahkamah Agung. (2) Permohonan … (2) Permohonan kasasi sebagaimana dimaksud pada ayat (1) diajukan paling lambat 8 (delapan) hari setelah tanggal putusan yang dimohonkan kasasi diucapkan, dengan mendaftarkan kepada Panitera Pengadilan yang telah memutus permohonan pernyataan pailit. (3) Permohonan kasasi sebagaimana dimaksud pada ayat (2), selain dapat diajukan oleh Debitor dan Kreditor yang merupakan pihak pada persidangan tingkat pertama, juga dapat diajukan oleh Kreditor lain yang bukan merupakan pihak pada persidangan tingkat pertama yang tidak puas terhadap putusan atas permohonan pernyataan pailit. (4) Panitera mendaftar permohonan kasasi pada tanggal permohonan yang bersangkutan diajukan dan kepada pemohon diberikan tanda terima tertulis yang ditandatangani panitera dengan tanggal yang sama dengan tanggal penerimaan pendaftaran."}, {"l": "UU 37/2004", "p": "12", "b": "Bagian Kesatu", "t": "(1) Pemohon kasasi wajib menyampaikan kepada Panitera Pengadilan memori kasasi pada tanggal permohonan kasasi didaftarkan. (2) Panitera wajib mengirimkan permohonan kasasi dan memori kasasi sebagaimana dimaksud pada ayat (1) kepada pihak termohon kasasi paling lambat 2 (dua) hari setelah permohonan kasasi didaftarkan. (3) Termohon kasasi dapat mengajukan kontra memori kasasi kepada panitera Pengadilan paling lambat 7 (tujuh) hari setelah tanggal termohon kasasi menerima memori kasasi sebagaimana dimaksud pada ayat (2), dan panitera Pengadilan wajib menyampaikan kontra memori kasasi kepada pemohon kasasi paling lambat 2 (dua) hari setelah kontra memori kasasi diterima. (4) Panitera … (4) Panitera wajib menyampaikan permohonan kasasi, memori kasasi, dan kontra memori kasasi beserta berkas perkara yang bersangkutan kepada Mahkamah Agung paling lambat 14 (empat belas) hari setelah tanggal permohonan kasasi didaftarkan."}, {"l": "UU 37/2004", "p": "13", "b": "Bagian Kesatu", "t": "(1) Mahkamah Agung wajib mempelajari permohonan kasasi dan menetapkan hari sidang paling lambat 2 (dua) hari setelah tanggal permohonan kasasi diterima oleh Mahkamah Agung. (2) Sidang pemeriksaan atas permohonan kasasi dilakukan paling lambat 20 (dua puluh) hari setelah tanggal permohonan kasasi diterima oleh Mahkamah Agung. (3) Putusan atas permohonan kasasi harus diucapkan paling lambat 60 (enam puluh) hari setelah tanggal permohonan kasasi diterima oleh Mahkamah Agung. (4) Putusan atas permohonan kasasi sebagaimana dimaksud pada ayat (3) yang memuat secara lengkap pertimbangan hukum yang mendasari putusan tersebut harus diucapkan dalam sidang terbuka untuk umum. (5) Dalam hal terdapat perbedaan pendapat antara anggota dengan ketua majelis maka perbedaan pendapat tersebut wajib dimuat dalam putusan kasasi. (6) Panitera pada Mahkamah Agung wajib menyampaikan salinan putusan kasasi kepada Panitera pada Pengadilan Niaga paling lambat 3 (tiga) hari setelah tanggal putusan atas permohonan kasasi diucapkan. (7) Jurusita Pengadilan wajib menyampaikan salinan putusan kasasi sebagaimana dimaksud pada ayat (5) kepada pemohon kasasi, termohon kasasi, Kurator, dan Hakim Pengawas paling …"}, {"l": "UU 37/2004", "p": "14", "b": "Bagian Kesatu", "t": "(1) Terhadap putusan atas permohonan pernyataan pailit yang telah memperoleh kekuatan hukum tetap, dapat diajukan peninjauan kembali ke Mahkamah Agung. (2) Ketentuan sebagaimana dimaksud dalam Pasal 12 dan Pasal 13 berlaku mutatis mutandis bagi peninjauan kembali."}, {"l": "UU 37/2004", "p": "15", "b": "Bagian Kesatu", "t": "(1) Dalam putusan pernyataan pailit, harus diangkat Kurator dan seorang Hakim Pengawas yang ditunjuk dari hakim Pengadilan. (2) Dalam hal Debitor, Kreditor, atau pihak yang berwenang mengajukan permohonan pernyataan pailit sebagaimana dimaksud dalam Pasal 2 ayat (2), ayat (3), ayat (4), atau ayat (5) tidak mengajukan usul pengangkatan Kurator kepada Pengadilan maka Balai Harta Peninggalan diangkat selaku Kurator. (3) Kurator yang diangkat sebagaimana dimaksud pada ayat (1) harus independen, tidak mempunyai benturan kepentingan dengan Debitor atau Kreditor, dan tidak sedang menangani perkara kepailitan dan penundaan kewajiban pembayaran utang lebih dari 3 (tiga) perkara. (4) Dalam jangka waktu paling lambat 5 (lima) hari setelah tanggal putusan pernyataan pailit diterima oleh Kurator dan Hakim Pengawas, Kurator mengumumkan dalam Berita Negara Republik Indonesia dan paling sedikit 2 (dua) surat kabar harian yang ditetapkan oleh Hakim Pengawas, mengenai ikhtisar putusan pernyataan pailit yang memuat hal-hal sebagai berikut: a. nama, alamat, dan pekerjaan Debitor; b. nama Hakim Pengawas; c. nama, alamat, dan pekerjaan Kurator; d. nama, … d. nama, alamat, dan pekerjaan anggota panitia …"}, {"l": "UU 37/2004", "p": "16", "b": "Bagian Kesatu", "t": "(1) Kurator berwenang melaksanakan tugas pengurusan dan/atau pemberesan atas harta pailit sejak tanggal putusan pailit diucapkan meskipun terhadap putusan tersebut diajukan kasasi atau peninjauan kembali. (2) Dalam hal putusan pernyataan pailit dibatalkan sebagai akibat adanya kasasi atau peninjauan kembali, segala perbuatan yang telah dilakukan oleh Kurator sebelum atau pada tanggal Kurator menerima pemberitahuan tentang putusan pembatalan sebagaimana dimaksud dalam Pasal 17 tetap sah dan mengikat Debitor."}, {"l": "UU 37/2004", "p": "17", "b": "Bagian Kesatu", "t": "(1) Kurator wajib mengumumkan putusan kasasi atau peninjauan kembali yang membatalkan putusan pailit dalam Berita Negara Republik Indonesia dan paling sedikit 2 (dua) surat kabar harian sebagaimana dimaksud dalam Pasal 15 ayat (4). (2) Majelis hakim yang membatalkan putusan pernyataan pailit juga menetapkan biaya kepailitan dan imbalan jasa Kurator. (3) Biaya sebagaimana dimaksud pada ayat (2) dibebankan kepada pemohon pernyataan pailit atau kepada pemohon dan Debitor dalam perbandingan yang ditetapkan oleh majelis hakim tersebut. (4) Untuk pelaksanaan pembayaran biaya kepailitan dan imbalan jasa Kurator sebagaimana dimaksud pada ayat (2), Ketua Pengadilan mengeluarkan penetapan eksekusi atas permohonan Kurator. (5) Dalam hal putusan pernyataan pailit dibatalkan, perdamaian yang mungkin terjadi gugur demi hukum. Pasal 18 …"}, {"l": "UU 37/2004", "p": "18", "b": "Bagian Kesatu", "t": "(1) Dalam hal harta pailit tidak cukup untuk membayar biaya kepailitan maka Pengadilan atas usul Hakim Pengawas dan setelah mendengar panitia kreditor sementara jika ada, serta setelah memanggil dengan sah atau mendengar Debitor, dapat memutuskan pencabutan putusan pernyataan pailit. (2) Putusan sebagaimana dimaksud pada ayat (1) diucapkan dalam sidang terbuka untuk umum. (3) Majelis hakim yang memerintahkan pencabutan pailit menetapkan jumlah biaya kepailitan dan imbalan jasa Kurator. (4) Jumlah biaya kepailitan dan imbalan jasa Kurator sebagaimana dimaksud pada ayat (3) dibebankan kepada Debitor. (5) Biaya dan imbalan jasa sebagaimana dimaksud pada ayat (3) harus didahulukan atas semua utang yang tidak dijamin dengan agunan. (6) Terhadap penetapan majelis hakim mengenai biaya kepailitan dan imbalan jasa Kurator sebagaimana dimaksud pada ayat (3), tidak dapat diajukan upaya hukum. (7) Untuk pelaksanaan pembayaran biaya kepailitan dan imbalan jasa Kurator sebagaimana dimaksud pada ayat (3), Ketua Pengadilan mengeluarkan penetapan eksekusi atas permohonan Kurator yang diketahui Hakim Pengawas."}, {"l": "UU 37/2004", "p": "19", "b": "Bagian Kesatu", "t": "(1) Putusan yang memerintahkan pencabutan pernyataan pailit, diumumkan oleh Panitera Pengadilan dalam Berita Negara Republik Indonesia dan paling sedikit 2 (dua) surat kabar harian sebagaimana dimaksud dalam Pasal 15 ayat (4). (2) Terhadap putusan pencabutan pernyataan pailit sebagaimana dimaksud pada ayat (1) dapat diajukan kasasi dan/atau peninjauan kembali. (3) Dalam … (3) Dalam hal setelah putusan pencabutan pernyataaan pailit diucapkan diajukan lagi permohonan pernyataan pailit maka Debitor atau pemohon wajib membuktikan bahwa ada cukup harta untuk membayar biaya kepailitan."}, {"l": "UU 37/2004", "p": "20", "b": "Bagian Kesatu", "t": "(1) Panitera Pengadilan wajib menyelenggarakan suatu daftar umum untuk mencatat setiap perkara kepailitan secara tersendiri. (2) Daftar umum sebagaimana dimaksud pada ayat (1) harus memuat secara berurutan : a. ikhtisar putusan pailit atau putusan pembatalan pernyataaan pailit; b. isi singkat perdamaian dan putusan pengesahannya; c. pembatalan perdamaian; d. jumlah pembagian dalam pemberesan; e. pencabutan kepailitan sebagaimana dimaksud dalam Pasal 18; dan f. rehabilitasi; dengan menyebutkan tanggal masing-masing. (3) Ketentuan lebih lanjut mengenai bentuk dan isi daftar umum sebagaimana dimaksud pada ayat (1) ditetapkan dengan Keputusan Ketua Mahkamah Agung. (4) Daftar umum sebagaimana dimaksud pada ayat (1) terbuka untuk umum dan dapat dilihat oleh setiap orang dengan cuma-cuma."}, {"l": "UU 37/2004", "p": "21", "b": "Bagian Kedua", "t": "Kepailitan meliputi seluruh kekayaan Debitor pada saat putusan pernyataan pailit diucapkan serta segala sesuatu yang diperoleh selama kepailitan. Pasal 22 …"}, {"l": "UU 37/2004", "p": "22", "b": "Bagian Kedua", "t": "Ketentuan sebagaimana dimaksud dalam Pasal 21 tidak berlaku terhadap : a. benda, termasuk hewan yang benar-benar dibutuhkan oleh Debitor sehubungan dengan pekerjaannya, perlengkapannya, alat-alat medis yang dipergunakan untuk kesehatan, tempat tidur dan perlengkapannya yang dipergunakan oleh Debitor dan keluarganya, dan bahan makanan untuk 30 (tiga puluh) hari bagi Debitor dan keluarganya, yang terdapat di tempat itu; b. segala sesuatu yang diperoleh Debitor dari pekerjaannya sendiri sebagai penggajian dari suatu jabatan atau jasa, sebagai upah, pensiun, uang tunggu atau uang tunjangan, sejauh yang ditentukan oleh Hakim Pengawas; atau c. uang yang diberikan kepada Debitor untuk memenuhi suatu kewajiban memberi nafkah menurut undang-undang."}, {"l": "UU 37/2004", "p": "23", "b": "Bagian Kedua", "t": "Debitor Pailit sebagaimana dimaksud dalam Pasal 21 dan Pasal 22 meliputi istri atau suami dari Debitor Pailit yang menikah dalam persatuan harta."}, {"l": "UU 37/2004", "p": "24", "b": "Bagian Kedua", "t": "(1) Debitor demi hukum kehilangan haknya untuk menguasai dan mengurus kekayaannya yang termasuk dalam harta pailit, sejak tanggal putusan pernyataan pailit diucapkan. (2) Tanggal putusan sebagaimana dimaksud pada ayat (1) dihitung sejak pukul 00.00 waktu setempat. (3) Dalam hal sebelum putusan pernyataan pailit diucapkan telah dilaksanakan transfer dana melalui bank atau lembaga selain bank pada tanggal putusan sebagaimana dimaksud pada ayat (1), transfer tersebut wajib diteruskan. (4) Dalam … (4) Dalam hal sebelum putusan pernyataan pailit diucapkan telah dilaksanakan Transaksi Efek di Bursa Efek maka transaksi tersebut wajib diselesaikan."}, {"l": "UU 37/2004", "p": "25", "b": "Bagian Kedua", "t": "Semua perikatan Debitor yang terbit sesudah putusan pernyataan pailit tidak lagi dapat dibayar dari harta pailit, kecuali perikatan tersebut menguntungkan harta pailit."}, {"l": "UU 37/2004", "p": "26", "b": "Bagian Kedua", "t": "(1) Tuntutan mengenai hak atau kewajiban yang menyangkut harta pailit harus diajukan oleh atau terhadap Kurator. (2) Dalam hal tuntutan sebagaimana dimaksud pada ayat (1) diajukan atau diteruskan oleh atau terhadap Debitor Pailit maka apabila tuntutan tersebut mengakibatkan suatu penghukuman terhadap Debitor Pailit, penghukuman tersebut tidak mempunyai akibat hukum terhadap harta pailit."}, {"l": "UU 37/2004", "p": "27", "b": "Bagian Kedua", "t": "Selama berlangsungnya kepailitan tuntutan untuk memperoleh pemenuhan perikatan dari harta pailit yang ditujukan terhadap Debitor Pailit, hanya dapat diajukan dengan mendaftarkannya untuk dicocokkan."}, {"l": "UU 37/2004", "p": "28", "b": "Bagian Kedua", "t": "(1) Suatu tuntutan hukum yang diajukan oleh Debitor dan yang sedang berjalan selama kepailitan berlangsung, atas permohonan tergugat, perkara harus ditangguhkan untuk memberikan kesempatan kepada tergugat memanggil Kurator untuk mengambil alih perkara dalam jangka waktu yang ditentukan oleh hakim. (2) Dalam … (2) Dalam hal Kurator tidak mengindahkan panggilan tersebut maka tergugat berhak memohon supaya perkara digugurkan, dan jika hal ini tidak dimohonkan maka perkara dapat diteruskan antara Debitor dan tergugat, di luar tanggungan harta pailit. (3) Ketentuan sebagaimana dimaksud pada ayat (2) berlaku juga dalam hal Kurator menolak mengambil alih perkara tersebut. (4) Tanpa mendapat panggilan, setiap waktu Kurator berwenang mengambil alih perkara dan mohon agar Debitor dikeluarkan dari perkara."}, {"l": "UU 37/2004", "p": "29", "b": "Bagian Kedua", "t": "Suatu tuntutan hukum di Pengadilan yang diajukan terhadap Debitor sejauh bertujuan untuk memperoleh pemenuhan kewajiban dari harta pailit dan perkaranya sedang berjalan, gugur demi hukum dengan diucapkan putusan pernyataan pailit terhadap Debitor."}, {"l": "UU 37/2004", "p": "30", "b": "Bagian Kedua", "t": "Dalam hal suatu perkara dilanjutkan oleh Kurator terhadap pihak lawan maka Kurator dapat mengajukan pembatalan atas segala perbuatan yang dilakukan oleh Debitor sebelum yang bersangkutan dinyatakan pailit, apabila dapat dibuktikan bahwa perbuatan Debitor tersebut dilakukan dengan maksud untuk merugikan Kreditor dan hal ini diketahui oleh pihak lawannya."}, {"l": "UU 37/2004", "p": "31", "b": "Bagian Kedua", "t": "(1) Putusan pernyataan pailit berakibat bahwa segala penetapan pelaksanaan Pengadilan terhadap setiap bagian dari kekayaan Debitor yang telah dimulai sebelum kepailitan, harus dihentikan seketika dan sejak itu tidak ada suatu putusan yang dapat dilaksanakan termasuk atau juga dengan menyandera Debitor. (2) Semua … (2) Semua penyitaan yang telah dilakukan menjadi hapus dan jika diperlukan Hakim Pengawas harus memerintahkan pencoretannya. (3) Dengan tidak mengurangi berlakunya ketentuan sebagaimana dimaksud dalam Pasal 93, Debitor yang sedang dalam penahanan harus dilepaskan seketika setelah putusan pernyataan pailit diucapkan."}, {"l": "UU 37/2004", "p": "32", "b": "Bagian Kedua", "t": "Selama kepailitan Debitor tidak dikenakan uang paksa."}, {"l": "UU 37/2004", "p": "33", "b": "Bagian Kedua", "t": "Dalam hal sebelum putusan pernyataan pailit diucapkan, penjualan benda milik Debitor baik bergerak maupun tidak bergerak dalam rangka eksekusi sudah sedemikian jauhnya hingga hari penjualan benda itu sudah ditetapkan maka dengan izin Hakim Pengawas, Kurator dapat meneruskan penjualan itu atas tanggungan harta pailit."}, {"l": "UU 37/2004", "p": "34", "b": "Bagian Kedua", "t": "Kecuali ditentukan lain dalam Undang-Undang ini, perjanjian yang bermaksud memindahtangankan hak atas tanah, balik nama kapal, pembebanan hak tanggungan, hipotek, atau jaminan fidusia yang telah diperjanjikan terlebih dahulu, tidak dapat dilaksanakan setelah putusan pernyataan pailit diucapkan."}, {"l": "UU 37/2004", "p": "35", "b": "Bagian Kedua", "t": "Dalam hal suatu tagihan diajukan untuk dicocokkan maka hal tersebut mencegah berlakunya daluwarsa. Pasal 36 …"}, {"l": "UU 37/2004", "p": "36", "b": "Bagian Kedua", "t": "(1) Dalam hal pada saat putusan pernyataan pailit diucapkan, terdapat perjanjian timbal balik yang belum atau baru sebagian dipenuhi, pihak yang mengadakan perjanjian dengan Debitor dapat meminta kepada Kurator untuk memberikan kepastian tentang kelanjutan pelaksanaan perjanjian tersebut dalam jangka waktu yang disepakati oleh Kurator dan pihak tersebut. (2) Dalam hal kesepakatan mengenai jangka waktu sebagaimana dimaksud pada ayat (1) tidak tercapai, Hakim Pengawas menetapkan jangka waktu tersebut. (3) Apabila dalam jangka waktu sebagaimana dimaksud pada ayat (1) dan ayat (2) Kurator tidak memberikan jawaban atau tidak bersedia melanjutkan pelaksanaan perjanjian tersebut maka perjanjian berakhir dan pihak sebagaimana dimaksud pada ayat (1) dapat menuntut ganti rugi dan akan diperlakukan sebagai kreditor konkuren. (4) Apabila Kurator menyatakan kesanggupannya maka Kurator wajib memberi jaminan atas kesanggupan untuk melaksanakan perjanjian tersebut. (5) Ketentuan sebagaimana dimaksud pada ayat (1), ayat (2), ayat (3), dan ayat (4) tidak berlaku terhadap perjanjian yang mewajibkan Debitor melakukan sendiri perbuatan yang diperjanjikan."}, {"l": "UU 37/2004", "p": "37", "b": "Bagian Kedua", "t": "(1) Apabila dalam perjanjian sebagaimana dimaksud dalam Pasal 36 telah diperjanjikan penyerahan benda dagangan yang biasa diperdagangkan dengan suatu jangka waktu dan pihak yang harus menyerahkan benda tersebut sebelum penyerahan dilaksanakan dinyatakan pailit maka perjanjian menjadi hapus dengan diucapkannya putusan pernyataan pailit, dan dalam hal pihak lawan … lawan dirugikan karena penghapusan maka yang bersangkutan dapat mengajukan diri sebagai kreditor konkuren untuk mendapatkan ganti rugi. (2) Dalam hal harta pailit dirugikan karena penghapusan sebagaimana dimaksud pada ayat (1) maka pihak lawan wajib membayar ganti kerugian tersebut."}, {"l": "UU 37/2004", "p": "38", "b": "Bagian Kedua", "t": "(1) Dalam hal Debitor telah menyewa suatu benda maka baik Kurator maupun pihak yang menyewakan benda, dapat menghentikan perjanjian sewa, dengan syarat pemberitahuan penghentian dilakukan sebelum berakhirnya perjanjian sesuai dengan adat kebiasaan setempat. (2) Dalam hal melakukan penghentian sebagaimana dimaksud pada ayat (1), harus pula diindahkan pemberitahuan penghentian menurut perjanjian atau menurut kelaziman dalam jangka waktu paling singkat 90 (sembilan puluh) hari. (3) Dalam hal uang sewa telah dibayar di muka maka perjanjian sewa tidak dapat dihentikan lebih awal sebelum berakhirnya jangka waktu yang telah dibayar uang sewa tersebut. (4) Sejak tanggal putusan pernyataan pailit diucapkan, uang sewa merupakan utang harta pailit."}, {"l": "UU 37/2004", "p": "39", "b": "Bagian Kedua", "t": "(1) Pekerja yang bekerja pada Debitor dapat memutuskan hubungan kerja, dan sebaliknya Kurator dapat memberhentikannya dengan mengindahkan jangka waktu menurut persetujuan atau ketentuan perundang-undangan yang berlaku, dengan pengertian bahwa hubungan kerja tersebut dapat diputuskan dengan pemberitahuan paling singkat 45 (empat lima) hari sebelumnya. (2) Sejak … (2) Sejak tanggal putusan pernyataan pailit diucapkan, upah yang terutang sebelum maupun sesudah putusan pernyataan pailit diucapkan merupakan utang harta pailit."}, {"l": "UU 37/2004", "p": "40", "b": "Bagian Kedua", "t": "(1) Warisan yang selama kepailitan jatuh kepada Debitor Pailit, oleh Kurator tidak boleh diterima, kecuali apabila menguntungkan harta pailit. (2) Untuk tidak menerima suatu warisan, Kurator memerlukan izin dari Hakim Pengawas."}, {"l": "UU 37/2004", "p": "41", "b": "Bagian Kedua", "t": "(1) Untuk kepentingan harta pailit, kepada Pengadilan dapat dimintakan pembatalan segala perbuatan hukum Debitor yang telah dinyatakan pailit yang merugikan kepentingan Kreditor, yang dilakukan sebelum putusan pernyataan pailit diucapkan. (2) Pembatalan sebagaimana dimaksud pada ayat (1) hanya dapat dilakukan apabila dapat dibuktikan bahwa pada saat perbuatan hukum dilakukan, Debitor dan pihak dengan siapa perbuatan hukum tersebut dilakukan mengetahui atau sepatutnya mengetahui bahwa perbuatan hukum tersebut akan mengakibatkan kerugian bagi Kreditor. (3) Dikecualikan dari ketentuan sebagaimana dimaksud pada ayat (1) adalah perbuatan hukum Debitor yang wajib dilakukannya berdasarkan perjanjian dan/atau karena undang-undang."}, {"l": "UU 37/2004", "p": "42", "b": "Bagian Kedua", "t": "Apabila perbuatan hukum yang merugikan Kreditor dilakukan dalam jangka waktu 1 (satu) tahun sebelum putusan pernyataan pailit diucapkan, sedangkan perbuatan tersebut tidak wajib dilakukan Debitor, … Debitor, kecuali dapat dibuktikan sebaliknya, Debitor dan pihak dengan siapa perbuatan tersebut dilakukan dianggap mengetahui atau sepatutnya mengetahui bahwa perbuatan tersebut akan mengakibatkan kerugian bagi Kreditor sebagaimana dimaksud dalam Pasal 41 ayat (2), dalam hal perbuatan tersebut: a. merupakan perjanjian dimana kewajiban Debitor jauh melebihi kewajiban pihak dengan siapa perjanjian tersebut dibuat; b. merupakan pembayaran atas, atau pemberian jaminan untuk utang yang belum jatuh tempo dan/atau belum atau tidak dapat ditagih; c. dilakukan oleh Debitor perorangan, dengan atau untuk kepentingan: 1) suami atau istrinya, anak angkat, atau keluarganya sampai derajat ketiga; 2) suatu badan hukum dimana Debitor atau pihak sebagaimana dimaksud pada angka 1) adalah anggota direksi atau pengurus atau apabila pihak tersebut, baik sendiri-sendiri maupun bersama-sama, ikut serta secara langsung atau tidak langsung dalam kepemilikan badan hukum tersebut lebih dari 50% (lima puluh …"}, {"l": "UU 37/2004", "p": "43", "b": "Bagian Kedua", "t": "Hibah yang dilakukan Debitor dapat dimintakan pembatalan kepada Pengadilan, apabila Kurator dapat membuktikan bahwa pada saat hibah tersebut dilakukan Debitor mengetahui atau patut mengetahui bahwa tindakan tersebut akan mengakibatkan kerugian bagi Kreditor."}, {"l": "UU 37/2004", "p": "44", "b": "Bagian Kedua", "t": "Kecuali dapat dibuktikan sebaliknya, Debitor dianggap mengetahui atau patut mengetahui bahwa hibah tersebut merugikan Kreditor, apabila hibah tersebut dilakukan dalam jangka waktu 1 (satu) tahun sebelum putusan pernyataan pailit diucapkan."}, {"l": "UU 37/2004", "p": "45", "b": "Bagian Kedua", "t": "Pembayaran suatu utang yang sudah dapat ditagih hanya dapat dibatalkan apabila dibuktikan bahwa penerima pembayaran mengetahui bahwa permohonan pernyataan pailit Debitor sudah didaftarkan, atau dalam hal pembayaran tersebut merupakan akibat dari persekongkolan antara Debitor dan Kreditor dengan maksud menguntungkan Kreditor tersebut melebihi Kreditor lainnya. Pasal 46 …"}, {"l": "UU 37/2004", "p": "46", "b": "Bagian Kedua", "t": "(1) Berdasarkan ketentuan sebagaimana dimaksud dalam Pasal 45, pembayaran yang telah diterima oleh pemegang surat pengganti atau surat atas tunjuk yang karena hubungan hukum dengan pemegang terdahulu wajib menerima pembayaran, pembayaran tersebut tidak dapat diminta kembali. (2) Dalam hal pembayaran tidak dapat diminta kembali sebagaimana dimaksud pada ayat (1), orang yang mendapat keuntungan sebagai akibat diterbitkannya surat pengganti atau surat atas tunjuk, wajib mengembalikan kepada harta pailit jumlah uang yang telah dibayar oleh Debitor apabila: a. dapat dibuktikan bahwa pada waktu penerbitan surat sebagaimana dimaksud pada ayat (1) yang bersangkutan mengetahui bahwa permohonan pernyataan pailit Debitor sudah didaftarkan; atau b. penerbitan surat tersebut merupakan akibat dari persekongkolan antara Debitor dan pemegang pertama."}, {"l": "UU 37/2004", "p": "47", "b": "Bagian Kedua", "t": "(1) Tuntutan hak berdasarkan ketentuan sebagaimana dimaksud dalam Pasal 41, Pasal 42, Pasal 43, Pasal 44, Pasal 45, dan Pasal 46 diajukan oleh Kurator ke Pengadilan. (2) Kreditor berdasarkan alasan sebagaimana dimaksud dalam Pasal 41, Pasal 42, Pasal 43, Pasal 44, Pasal 45, dan Pasal 46 dapat mengajukan bantahan terhadap tuntutan Kurator."}, {"l": "UU 37/2004", "p": "48", "b": "Bagian Kedua", "t": "(1) Dalam hal kepailitan berakhir dengan disahkannya perdamaian maka tuntutan sebagaimana dimaksud dalam Pasal 47 gugur. (2) Tuntutan … (2) Tuntutan sebagaimana dimaksud dalam Pasal 47 tidak gugur, jika perdamaian tersebut berisi pelepasan atas harta pailit, untuk itu tuntutan dapat dilanjutkan atau diajukan oleh para pemberes harta untuk kepentingan Kreditor."}, {"l": "UU 37/2004", "p": "49", "b": "Bagian Kedua", "t": "(1) Setiap orang yang telah menerima benda yang merupakan bagian dari harta Debitor yang tercakup dalam perbuatan hukum yang dibatalkan, harus mengembalikan benda tersebut kepada Kurator dan dilaporkan kepada Hakim Pengawas. (2) Dalam hal orang sebagaimana dimaksud pada ayat (1) tidak dapat mengembalikan benda yang telah diterima dalam keadaan semula, wajib membayar ganti rugi kepada harta pailit. (3) Hak pihak ketiga atas benda sebagaimana dimaksud pada ayat (1) yang diperoleh dengan itikad baik dan tidak dengan cuma-cuma, harus dilindungi. (4) Benda yang diterima oleh Debitor atau nilai penggantinya wajib dikembalikan oleh Kurator, sejauh harta pailit diuntungkan, sedangkan untuk kekurangannya, orang terhadap siapa pembatalan tersebut dituntut dapat tampil sebagai kreditor konkuren."}, {"l": "UU 37/2004", "p": "50", "b": "Bagian Kedua", "t": "(1) Setiap orang yang sesudah putusan pernyataan pailit diucapkan tetapi belum diumumkan, membayar kepada Debitor Pailit untuk memenuhi perikatan yang terbit sebelum putusan pernyataan pailit diucapkan, dibebaskan terhadap harta pailit sejauh tidak dibuktikan bahwa yang bersangkutan mengetahui adanya putusan pernyataan pailit tersebut. (2) Pembayaran … (2) Pembayaran sebagaimana dimaksud pada ayat (1) yang dilakukan sesudah putusan pernyataan pailit diumumkan, tidak membebaskan terhadap harta pailit kecuali apabila yang melakukan dapat membuktikan bahwa pengumuman putusan pernyataan pailit yang dilakukan menurut undang- undang tidak mungkin diketahui di tempat tinggalnya. (3) Pembayaran yang dilakukan kepada Debitor Pailit, membebaskan Debitornya terhadap harta pailit, jika pembayaran itu menguntungkan harta pailit."}, {"l": "UU 37/2004", "p": "51", "b": "Bagian Kedua", "t": "(1) Setiap orang yang mempunyai utang atau piutang terhadap Debitor Pailit, dapat memohon diadakan perjumpaan utang, apabila utang atau piutang tersebut diterbitkan sebelum putusan pernyataan pailit diucapkan, atau akibat perbuatan yang dilakukannya dengan Debitor Pailit sebelum putusan pernyataan pailit diucapkan. (2) Dalam hal diperlukan, piutang terhadap Debitor Pailit dihitung menurut ketentuan sebagaimana dimaksud dalam Pasal 136 dan Pasal 137."}, {"l": "UU 37/2004", "p": "52", "b": "Bagian Kedua", "t": "(1) Setiap orang yang telah mengambil alih suatu utang atau piutang dari pihak ketiga sebelum putusan pernyataan pailit diucapkan, tidak dapat memohon diadakan perjumpaan utang, apabila sewaktu pengambilalihan utang atau piutang tersebut, yang bersangkutan tidak beritikad baik. (2) Semua utang piutang yang diambil alih setelah putusan pernyataan pailit diucapkan, tidak dapat diperjumpakan. Pasal 53 …"}, {"l": "UU 37/2004", "p": "53", "b": "Bagian Kedua", "t": "Setiap orang yang mempunyai utang kepada Debitor Pailit, yang hendak menjumpakan utangnya dengan suatu piutang atas tunjuk atau piutang atas pengganti, wajib membuktikan bahwa pada saat putusan pernyataan pailit diucapkan, orang tersebut dengan itikad baik sudah menjadi pemilik surat atas tunjuk atau surat atas pengganti tersebut."}, {"l": "UU 37/2004", "p": "54", "b": "Bagian Kedua", "t": "Setiap orang yang dengan Debitor Pailit berada dalam suatu persekutuan yang karena atau selama kepailitan dibubarkan, berhak untuk mengurangi bagian dari keuntungannya yang pada waktu pembagian diadakan jatuh kepada Debitor Pailit, dengan kewajiban Debitor Pailit untuk membayar utang persekutuan."}, {"l": "UU 37/2004", "p": "55", "b": "Bagian Kedua", "t": "(1) Dengan tetap memperhatikan ketentuan sebagaimana dimaksud dalam Pasal 56, Pasal 57, dan Pasal 58, setiap Kreditor pemegang gadai, jaminan fidusia, hak tanggungan, hipotek, atau hak agunan atas kebendaan lainnya, dapat mengeksekusi haknya seolah-olah tidak terjadi kepailitan. (2) Dalam hal penagihan suatu piutang sebagaimana dimaksud dalam Pasal 136 dan Pasal 137 maka mereka hanya dapat berbuat demikian setelah dicocokkan penagihannya dan hanya untuk mengambil pelunasan dari jumlah yang diakui dari penagihan tersebut. Pasal 56 …"}, {"l": "UU 37/2004", "p": "56", "b": "Bagian Kedua", "t": "(1) Hak eksekusi Kreditor sebagaimana dimaksud dalam Pasal 55 ayat (1) dan hak pihak ketiga untuk menuntut hartanya yang berada dalam penguasaan Debitor Pailit atau Kurator, ditangguhkan untuk jangka waktu paling lama 90 (sembilan puluh) hari sejak tanggal putusan pernyataan pailit diucapkan. (2) Penangguhan sebagaimana dimaksud pada ayat (1) tidak berlaku terhadap tagihan Kreditor yang dijamin dengan uang tunai dan hak Kreditor untuk memperjumpakan utang. (3) Selama jangka waktu penangguhan sebagaimana dimaksud pada ayat (1), Kurator dapat menggunakan harta pailit berupa benda tidak bergerak maupun benda bergerak atau menjual harta pailit yang berupa benda bergerak yang berada dalam penguasaan Kurator dalam rangka kelangsungan usaha Debitor, dalam hal telah diberikan perlindungan yang wajar bagi kepentingan Kreditor atau pihak ketiga sebagaimana dimaksud pada ayat (1)."}, {"l": "UU 37/2004", "p": "57", "b": "Bagian Kedua", "t": "(1) Jangka waktu sebagaimana dimaksud dalam Pasal 56 ayat (1) berakhir demi hukum pada saat kepailitan diakhiri lebih cepat atau pada saat dimulainya keadaan insolvensi sebagaimana dimaksud dalam Pasal 178 ayat (1). (2) Kreditor atau pihak ketiga yang haknya ditangguhkan dapat mengajukan permohonan kepada Kurator untuk mengangkat penangguhan atau mengubah syarat penangguhan tersebut. (3) Apabila Kurator menolak permohonan sebagaimana dimaksud pada ayat (1), Kreditor atau pihak ketiga dapat mengajukan permohonan tersebut kepada Hakim Pengawas. (4) Hakim … (4) Hakim Pengawas dalam waktu paling lambat 1 (satu) hari setelah permohonan sebagaimana dimaksud dalam ayat (2) diterima, wajib memerintahkan Kurator untuk segera memanggil dengan surat tercatat atau melalui kurir, Kreditor dan pihak ketiga sebagaimana dimaksud pada ayat (2) untuk didengar pada sidang pemeriksaan atas permohonan tersebut. (5) Hakim Pengawas wajib memberikan penetapan atas permohonan dalam waktu paling lambat 10 (sepuluh) hari setelah permohonan sebagaimana dimaksud pada ayat (2) diajukan kepada Hakim Pengawas. (6) Dalam memutuskan permohonan sebagaimana dimaksud pada ayat (2), Hakim Pengawas mempertimbangkan: a. …"}, {"l": "UU 37/2004", "p": "58", "b": "Bagian Kedua", "t": "(1) Penetapan Hakim Pengawas atas permohonan sebagaimana dimaksud dalam Pasal 57 ayat (2) dapat berupa diangkatnya penangguhan untuk satu atau lebih Kreditor, dan/atau menetapkan persyaratan tentang lamanya waktu penangguhan, dan/atau tentang satu atau beberapa agunan yang dapat dieksekusi oleh Kreditor. (2) Apabila Hakim Pengawas menolak untuk mengangkat atau mengubah persyaratan penangguhan tersebut, Hakim Pengawas wajib memerintahkan agar Kurator memberikan perlindungan yang dianggap wajar untuk melindungi kepentingan pemohon. (3) Terhadap … (3) Terhadap penetapan Hakim Pengawas, Kreditor atau pihak ketiga yang mengajukan permohonan sebagaimana dimaksud dalam Pasal 57 ayat (2) atau Kurator dapat mengajukan perlawanan kepada Pengadilan dalam jangka waktu paling lambat 5 (lima) hari setelah putusan diucapkan, dan Pengadilan wajib memutuskan perlawanan tersebut dalam jangka waktu paling lambat 10 (sepuluh) hari setelah perlawanan tersebut diterima. (4) Terhadap putusan Pengadilan sebagaimana dimaksud pada ayat (2) tidak dapat diajukan upaya hukum apapun termasuk peninjauan kembali."}, {"l": "UU 37/2004", "p": "59", "b": "Bagian Kedua", "t": "(1) Dengan tetap memperhatikan ketentuan Pasal 56, Pasal 57, dan Pasal 58, Kreditor pemegang hak sebagaimana dimaksud dalam Pasal 55 ayat (1) harus melaksanakan haknya tersebut dalam jangka waktu paling lambat 2 (dua) bulan setelah dimulainya keadaan insolvensi sebagaimana dimaksud dalam Pasal 178 ayat (1). (2) Setelah lewat jangka waktu sebagaimana dimaksud pada ayat (1), Kurator harus menuntut diserahkannya benda yang menjadi agunan untuk selanjutnya dijual sesuai dengan cara sebagaimana dimaksud dalam Pasal 185, tanpa mengurangi hak Kreditor pemegang hak tersebut atas hasil penjualan agunan tersebut. (3) Setiap waktu Kurator dapat membebaskan benda yang menjadi agunan dengan membayar jumlah terkecil antara harga pasar benda agunan dan jumlah utang yang dijamin dengan benda agunan tersebut kepada Kreditor yang bersangkutan. Pasal 60 …"}, {"l": "UU 37/2004", "p": "60", "b": "Bagian Kedua", "t": "(1) Kreditor pemegang hak sebagaimana dimaksud dalam Pasal 55 ayat (1) yang melaksanakan haknya, wajib memberikan pertanggungjawaban kepada Kurator tentang hasil penjualan benda yang menjadi agunan dan menyerahkan sisa hasil penjualan setelah dikurangi jumlah utang, bunga, dan biaya kepada Kurator. (2) Atas tuntutan Kurator atau Kreditor yang diistimewakan yang kedudukannya lebih tinggi daripada Kreditor pemegang hak sebagaimana dimaksud pada ayat (1) maka Kreditor pemegang hak tersebut wajib menyerahkan bagian dari hasil penjualan tersebut untuk jumlah yang sama dengan jumlah tagihan yang diistimewakan. (3) Dalam hal hasil penjualan sebagaimana dimaksud pada ayat (1) tidak cukup untuk melunasi piutang yang bersangkutan, Kreditor pemegang hak tersebut dapat mengajukan tagihan pelunasan atas kekurangan tersebut dari harta pailit sebagai kreditor konkuren, setelah mengajukan permintaan pencocokan piutang."}, {"l": "UU 37/2004", "p": "61", "b": "Bagian Kedua", "t": "Kreditor yang mempunyai hak untuk menahan benda milik Debitor, tidak kehilangan hak karena ada putusan pernyataan pailit."}, {"l": "UU 37/2004", "p": "62", "b": "Bagian Kedua", "t": "(1) Dalam hal suami atau istri dinyatakan pailit maka istri atau suaminya berhak mengambil kembali semua benda bergerak dan tidak bergerak yang merupakan harta bawaan dari istri atau suami dan harta yang diperoleh masing-masing sebagai hadiah atau warisan. (2) Jika benda milik istri atau suami telah dijual oleh suami atau istri dan harganya belum dibayar atau uang hasil penjualan belum tercampur dalam harta pailit maka istri atau suami berhak mengambil kembali uang hasil penjualan tersebut. (3) Untuk … (3) Untuk tagihan yang bersifat pribadi terhadap istri atau suami maka Kreditor terhadap harta pailit adalah suami atau istri."}, {"l": "UU 37/2004", "p": "63", "b": "Bagian Kedua", "t": "Istri atau suami tidak berhak menuntut atas keuntungan yang diperjanjikan dalam perjanjian perkawinan kepada harta pailit suami atau istri yang dinyatakan pailit, demikian juga Kreditor suami atau istri yang dinyatakan pailit tidak berhak menuntut keuntungan yang diperjanjikan dalam perjanjian perkawinan kepada istri atau suami yang dinyatakan pailit."}, {"l": "UU 37/2004", "p": "64", "b": "Bagian Kedua", "t": "(1) Kepailitan suami atau istri yang kawin dalam suatu persatuan harta, diperlakukan sebagai kepailitan persatuan harta tersebut. (2) Dengan tidak mengurangi pengecualian sebagaimana dimaksud dalam Pasal 25 maka kepailitan tersebut meliputi semua benda yang termasuk dalam persatuan, sedangkan kepailitan tersebut adalah untuk kepentingan semua Kreditor, yang berhak meminta pembayaran dari harta persatuan. (3) Dalam hal suami atau istri yang dinyatakan pailit mempunyai benda yang tidak termasuk persatuan harta maka benda tersebut termasuk harta pailit, akan tetapi hanya dapat digunakan untuk membayar utang pribadi suami atau istri yang dinyatakan pailit."}, {"l": "UU 37/2004", "p": "65", "b": "Bagian Ketiga", "t": "Hakim Pengawas mengawasi pengurusan dan pemberesan harta pailit. Pasal 66 …"}, {"l": "UU 37/2004", "p": "66", "b": "Bagian Ketiga", "t": "Pengadilan wajib mendengar pendapat Hakim Pengawas, sebelum mengambil suatu putusan mengenai pengurusan atau pemberesan harta pailit."}, {"l": "UU 37/2004", "p": "67", "b": "Bagian Ketiga", "t": "(1) Hakim Pengawas berwenang untuk mendengar keterangan saksi atau memerintahkan penyelidikan oleh para ahli untuk memperoleh kejelasan tentang segala hal mengenai kepailitan. (2) Saksi dipanggil atas nama Hakim Pengawas. (3) Dalam hal saksi tidak datang menghadap atau menolak memberi kesaksian maka berlaku ketentuan Hukum Acara Perdata. (4) Dalam hal saksi bertempat tinggal di luar daerah hukum Pengadilan yang memutus pailit, Hakim Pengawas dapat melimpahkan pemeriksaan saksi tersebut kepada pengadilan yang daerah hukumnya meliputi tempat tinggal saksi. (5) Istri atau suami, bekas istri atau suami, dan keluarga sedarah menurut keturunan lurus ke atas dan ke bawah dari Debitor Pailit mempunyai hak undur diri sebagai saksi."}, {"l": "UU 37/2004", "p": "68", "b": "Bagian Ketiga", "t": "(1) Terhadap semua penetapan Hakim Pengawas, dalam waktu 5 (lima) hari setelah penetapan tersebut dibuat, dapat diajukan permohonan banding ke Pengadilan. (2) Permohonan banding tidak dapat diajukan terhadap penetapan sebagaimana dimaksud dalam Pasal 22 huruf b, Pasal 33, Pasal 84 ayat (3), Pasal 104 ayat (2), Pasal 106, Pasal 125 ayat (1), Pasal 127 ayat (1), Pasal 183 ayat (1), Pasal 184 ayat (3), Pasal 185 ayat (1), ayat (2), dan ayat (3), Pasal 186, Pasal 188, dan Pasal 189. Paragraf 2 … Paragraf 2 Kurator"}, {"l": "UU 37/2004", "p": "69", "b": "Bagian Ketiga", "t": "(1) Tugas Kurator adalah melakukan pengurusan dan/atau pemberesan harta pailit. (2) Dalam melaksanakan tugasnya, Kurator: a. tidak diharuskan memperoleh persetujuan dari atau menyampaikan pemberitahuan terlebih dahulu kepada Debitor atau salah satu organ Debitor, meskipun dalam keadaan di luar kepailitan persetujuan atau pemberitahuan demikian dipersyaratkan; b. dapat melakukan pinjaman dari pihak ketiga, hanya dalam rangka meningkatkan nilai harta pailit. (3) Apabila dalam melakukan pinjaman dari pihak ketiga Kurator perlu membebani harta pailit dengan gadai, jaminan fidusia, hak tanggungan, hipotek, atau hak agunan atas kebendaan lainnya maka pinjaman tersebut harus terlebih dahulu memperoleh persetujuan Hakim Pengawas. (4) Pembebanan harta pailit dengan gadai, jaminan fidusia, hak tanggungan, hipotek, atau hak agunan atas kebendaan lainnya sebagaimana dimaksud pada ayat (3), hanya dapat dilakukan terhadap bagian harta pailit yang belum dijadikan jaminan utang. (5) Untuk menghadap di sidang Pengadilan, Kurator harus terlebih dahulu mendapat izin dari Hakim Pengawas, kecuali menyangkut sengketa pencocokan piutang atau dalam hal sebagaimana dimaksud dalam Pasal 36, Pasal 38, Pasal …"}, {"l": "UU 37/2004", "p": "70", "b": "Bagian Ketiga", "t": "(1) Kurator sebagaimana dimaksud dalam Pasal 69 adalah : a. Balai Harta Peninggalan; atau b. Kurator … b. Kurator lainnya. (2) Yang dapat menjadi Kurator sebagaimana dimaksud pada ayat (1) huruf b, adalah: a. orang perseorangan yang berdomisili di Indonesia, yang memiliki keahlian khusus yang dibutuhkan dalam rangka mengurus dan/atau membereskan harta pailit; dan b. terdaftar pada kementerian yang lingkup tugas dan tanggung jawabnya di bidang hukum dan peraturan perundang-undangan."}, {"l": "UU 37/2004", "p": "71", "b": "Bagian Ketiga", "t": "(1) Pengadilan setiap waktu dapat mengabulkan usul penggantian Kurator, setelah memanggil dan mendengar Kurator, dan mengangkat Kurator lain dan/atau mengangkat Kurator tambahan atas: a. permohonan Kurator sendiri; b. permohonan Kurator lainnya, jika ada; c. usul Hakim Pengawas; atau d. permintaan Debitor Pailit. (2) Pengadilan harus memberhentikan atau mengangkat Kurator atas permohonan atau atas usul kreditor konkuren berdasarkan putusan rapat Kreditor yang diselenggarakan sebagaimana dimaksud dalam Pasal 90, dengan persyaratan putusan tersebut diambil berdasarkan suara setuju lebih dari 1/2 (satu perdua) jumlah kreditor konkuren atau kuasanya yang hadir dalam rapat dan yang mewakili lebih dari 1/2 (satu perdua) jumlah piutang kreditor konkuren atau kuasanya yang hadir dalam rapat tersebut."}, {"l": "UU 37/2004", "p": "72", "b": "Bagian Ketiga", "t": "Kurator bertanggung jawab terhadap kesalahan atau kelalaiannya dalam melaksanakan tugas pengurusan dan/atau pemberesan yang menyebabkan kerugian terhadap harta pailit. Pasal 73 …"}, {"l": "UU 37/2004", "p": "73", "b": "Bagian Ketiga", "t": "(1) Apabila diangkat lebih dari satu Kurator maka untuk melakukan tindakan yang sah dan mengikat, para Kurator memerlukan persetujuan lebih dari 1/2 (satu perdua) jumlah para Kurator. (2) Apabila suara setuju dan tidak setuju sama banyaknya, tindakan sebagaimana dimaksud pada ayat (1) harus memperoleh persetujuan Hakim Pengawas. (3) Kurator yang ditunjuk untuk tugas khusus berdasarkan putusan pernyataan pailit, berwenang untuk bertindak sendiri sebatas tugasnya."}, {"l": "UU 37/2004", "p": "74", "b": "Bagian Ketiga", "t": "(1) Kurator harus menyampaikan laporan kepada Hakim Pengawas mengenai keadaan harta pailit dan pelaksanaan tugasnya setiap 3 (tiga) bulan. (2) Laporan sebagaimana dimaksud pada ayat (1) bersifat terbuka untuk umum dan dapat dilihat oleh setiap orang dengan cuma-cuma. (3) Hakim Pengawas dapat memperpanjang jangka waktu sebagaimana dimaksud pada ayat (1)."}, {"l": "UU 37/2004", "p": "75", "b": "Bagian Ketiga", "t": "Besarnya imbalan jasa Kurator ditentukan setelah kepailitan berakhir."}, {"l": "UU 37/2004", "p": "76", "b": "Bagian Ketiga", "t": "Besarnya imbalan jasa yang harus dibayarkan kepada Kurator sebagaimana dimaksud dalam Pasal 75 ditetapkan berdasarkan pedoman yang ditetapkan dengan Keputusan Menteri yang lingkup tugas dan tanggung jawabnya di bidang hukum dan perundang-undangan. Pasal 77 …"}, {"l": "UU 37/2004", "p": "77", "b": "Bagian Ketiga", "t": "(1) Setiap Kreditor, panitia kreditor, dan Debitor Pailit dapat mengajukan surat keberatan kepada Hakim Pengawas terhadap perbuatan yang dilakukan oleh Kurator atau memohon kepada Hakim Pengawas untuk mengeluarkan surat perintah agar Kurator melakukan perbuatan tertentu atau tidak melakukan perbuatan yang sudah direncanakan. (2) Hakim Pengawas harus menyampaikan surat keberatan kepada Kurator paling lambat 3 (tiga) hari setelah surat keberatan diterima. (3) Kurator harus memberikan tanggapan kepada Hakim Pengawas paling lambat 3 (tiga) hari setelah menerima surat keberatan. (4) Hakim Pengawas harus memberikan penetapan paling lambat 3 (tiga) hari setelah tanggapan dari Kurator diterima."}, {"l": "UU 37/2004", "p": "78", "b": "Bagian Ketiga", "t": "(1) Tidak adanya kuasa atau izin dari Hakim Pengawas, dalam hal kuasa atau izin diperlukan, atau tidak diindahkannya ketentuan sebagaimana dimaksud dalam Pasal 83 dan Pasal 84, tidak mempengaruhi sahnya perbuatan yang dilakukan oleh Kurator terhadap pihak ketiga. (2) Sehubungan dengan perbuatan tersebut, Kurator sendiri bertanggung jawab terhadap Debitor Pailit dan Kreditor. Paragraf 3 Panitia Kreditor"}, {"l": "UU 37/2004", "p": "79", "b": "Bagian Ketiga", "t": "(1) Dalam putusan pailit atau dengan penetapan kemudian, Pengadilan dapat membentuk panitia kreditor sementara terdiri atas 3 (tiga) orang yang dipilih dari Kreditor yang dikenal dengan maksud memberikan nasihat kepada Kurator. (2) Kreditor … (2) Kreditor yang diangkat dapat mewakilkan kepada orang lain semua pekerjaan yang berhubungan dengan tugas-tugasnya dalam panitia. (3) Dalam hal seorang Kreditor yang ditunjuk menolak pengangkatannya, berhenti, atau meninggal, Pengadilan harus mengganti Kreditor tersebut dengan mengangkat seorang di antara 2 (dua) calon yang diusulkan oleh Hakim Pengawas."}, {"l": "UU 37/2004", "p": "80", "b": "Bagian Ketiga", "t": "(1) Setelah pencocokan utang selesai dilakukan, Hakim Pengawas wajib menawarkan kepada Kreditor untuk membentuk panitia kreditor tetap. (2) Atas permintaan kreditor konkuren berdasarkan putusan kreditor konkuren dengan suara terbanyak biasa dalam rapat Kreditor, Hakim Pengawas: a. mengganti panitia kreditor sementara, apabila dalam putusan pailit telah ditunjuk panitia kreditor sementara; atau b. membentuk panitia kreditor, apabila dalam putusan pailit belum diangkat panitia kreditor."}, {"l": "UU 37/2004", "p": "81", "b": "Bagian Ketiga", "t": "(1) Panitia kreditor setiap waktu berhak meminta diperlihatkan semua buku, dokumen, dan surat mengenai kepailitan. (2) Kurator wajib memberikan kepada panitia kreditor semua keterangan yang dimintanya."}, {"l": "UU 37/2004", "p": "82", "b": "Bagian Ketiga", "t": "Dalam hal diperlukan, Kurator dapat mengadakan rapat dengan panitia kreditor, untuk meminta nasihat. Pasal 83 …"}, {"l": "UU 37/2004", "p": "83", "b": "Bagian Ketiga", "t": "(1) Sebelum mengajukan gugatan atau meneruskan perkara yang sedang berlangsung, ataupun menyanggah gugatan yang diajukan atau yang sedang berlangsung, Kurator wajib meminta pendapat panitia kreditor. (2) Ketentuan sebagaimana dimaksud pada ayat (1) tidak berlaku terhadap sengketa tentang pencocokan piutang, tentang meneruskan atau tidak meneruskan perusahaan dalam pailit, dalam hal-hal sebagaimana dimaksud dalam Pasal 36, Pasal 38, Pasal 39, Pasal 59 ayat (3), Pasal 106, Pasal 107, Pasal 184 ayat (3), dan Pasal 186, tentang cara pemberesan dan penjualan harta pailit, dan tentang waktu maupun jumlah pembagian yang harus dilakukan. (3) Pendapat panitia kreditor sebagaimana dimaksud pada ayat (1) tidak diperlukan, apabila Kurator telah memanggil panitia kreditor untuk mengadakan rapat guna memberikan pendapat, namun dalam jangka waktu 7 (tujuh) hari setelah pemanggilan, panitia kreditor tidak memberikan pendapat tersebut."}, {"l": "UU 37/2004", "p": "84", "b": "Bagian Ketiga", "t": "(1) Kurator tidak terikat oleh pendapat panitia kreditor. (2) Dalam hal Kurator tidak menyetujui pendapat panitia kreditor maka Kurator dalam waktu 3 (tiga) hari wajib memberitahukan hal itu kepada panitia kreditor. (3) Dalam hal panitia kreditor tidak menyetujui pendapat Kurator, panitia kreditor dalam waktu 3 (tiga) hari setelah pemberitahuan sebagaimana dimaksud pada ayat (2) dapat meminta penetapan Hakim Pengawas. (4) Dalam hal panitia kreditor meminta penetapan Hakim Pengawas maka Kurator wajib menangguhkan pelaksanaan perbuatan yang direncanakan selama 3 (tiga) hari. Paragraf 4 … Paragraf 4 Rapat Kreditor"}, {"l": "UU 37/2004", "p": "85", "b": "Bagian Ketiga", "t": "(1) Dalam rapat Kreditor, Hakim Pengawas bertindak sebagai ketua. (2) Kurator wajib hadir dalam rapat Kreditor."}, {"l": "UU 37/2004", "p": "86", "b": "Bagian Ketiga", "t": "(1) Hakim Pengawas menentukan hari, tanggal, waktu, dan tempat rapat Kreditor pertama, yang harus diselenggarakan dalam jangka waktu paling lambat 30 (tiga puluh) hari setelah tanggal putusan pailit diucapkan. (2) Dalam jangka waktu 3 (tiga) hari setelah putusan pernyataan pailit diterima oleh Hakim Pengawas dan Kurator, Hakim Pengawas wajib menyampaikan kepada Kurator rencana penyelenggaraan rapat Kreditor pertama sebagaimana dimaksud pada ayat (1). (3) Dalam jangka waktu paling lambat 5 (lima) hari setelah putusan pernyataan pailit diterima oleh Kurator dan Hakim Pengawas, Kurator wajib memberitahukan penyelenggaraan rapat Kreditor sebagaimana dimaksud pada ayat (2) kepada Kreditor yang dikenal dengan surat tercatat atau melalui kurir, dan dengan iklan paling sedikit dalam 2 (dua) surat kabar harian, dengan memperhatikan ketentuan sebagaimana dimaksud dalam Pasal 15 ayat (4)."}, {"l": "UU 37/2004", "p": "87", "b": "Bagian Ketiga", "t": "(1) Kecuali ditentukan dalam Undang-Undang ini, segala putusan rapat Kreditor ditetapkan berdasarkan suara setuju sebesar lebih dari 1/2 (satu perdua) jumlah suara yang dikeluarkan oleh Kreditor dan/atau kuasa Kreditor yang hadir pada rapat yang bersangkutan. (2) Dalam … (2) Dalam hal Kreditor menghadiri rapat Kreditor dan tidak menggunakan hak suara, hak suaranya dihitung sebagai suara tidak setuju. (3) Ketentuan lebih lanjut mengenai penghitungan jumlah hak suara Kreditor sebagaimana dimaksud pada ayat (1) diatur dengan Peraturan Pemerintah. (4) Pengalihan piutang yang dilakukan dengan cara pemecahan piutang setelah putusan pernyataan pailit diucapkan, tidak melahirkan hak suara bagi kreditor baru. (5) Dalam hal pengalihan dilakukan secara keseluruhan setelah putusan pernyataan pailit diucapkan, Kreditor penerima pengalihan memperoleh hak suara Kreditor yang mengalihkan."}, {"l": "UU 37/2004", "p": "88", "b": "Bagian Ketiga", "t": "Kreditor yang mempunyai hak suara adalah Kreditor yang diakui, Kreditor yang diterima dengan syarat, dan pembawa suatu piutang atas tunjuk yang telah dicocokkan."}, {"l": "UU 37/2004", "p": "89", "b": "Bagian Ketiga", "t": "Kreditor yang telah memberitahukan kepada Kurator, bahwa untuk kepailitan tersebut telah mengangkat seorang kuasa atau yang pada suatu rapat telah mewakilkan kepada orang lain maka semua panggilan dan pemberitahuan wajib ditujukan kepada kuasa tersebut, kecuali apabila Kreditor meminta kepada Kurator untuk mengirimkan panggilan dan pemberitahuan itu kepada Kreditor sendiri atau seorang kuasa lain."}, {"l": "UU 37/2004", "p": "90", "b": "Bagian Ketiga", "t": "(1) Rapat Kreditor wajib diadakan sesuai dengan ketentuan dalam Undang- Undang ini. (2) Selain … (2) Selain rapat sebagaimana dimaksud pada ayat (1), Hakim Pengawas dapat mengadakan rapat apabila dianggap perlu atau atas permintaan: a. panitia kreditor; atau b. paling sedikit 5 (lima) Kreditor yang mewakili 1/5 (satu perlima) bagian dari semua piutang yang diakui atau diterima dengan syarat. (3) Hakim Pengawas wajib menentukan hari, tanggal, waktu, dan tempat rapat. (4) Kurator memanggil semua Kreditor yang mempunyai hak suara dengan surat tercatat atau melalui kurir, dan dengan iklan paling sedikit 2 (dua) surat kabar harian sebagaimana dimaksud Pasal 15 ayat (4). (5) Panggilan dengan surat tercatat atau melalui kurir, dan dengan iklan dalam surat kabar harian sebagaimana dimaksud pada ayat (4) memuat acara yang akan dibicarakan dalam rapat. (6) Hakim Pengawas harus menetapkan tenggang waktu antara hari pemanggilan dan hari rapat. Paragraf 5 Penetapan Hakim"}, {"l": "UU 37/2004", "p": "91", "b": "Bagian Ketiga", "t": "Semua penetapan mengenai pengurusan dan/atau pemberesan harta pailit ditetapkan oleh Pengadilan dalam tingkat terakhir, kecuali Undang-Undang ini menentukan lain."}, {"l": "UU 37/2004", "p": "92", "b": "Bagian Ketiga", "t": "Semua penetapan mengenai pengurusan dan/atau pemberesan harta pailit juga yang ditetapkan oleh hakim dapat dilaksanakan terlebih dahulu, kecuali Undang-Undang ini menentukan lain."}, {"l": "UU 37/2004", "p": "93", "b": "Bagian Keempat", "t": "(1) Pengadilan dengan putusan pernyataan pailit atau setiap waktu setelah itu, atas usul Hakim Pengawas, permintaan Kurator, atau atas permintaan seorang Kreditor atau lebih dan setelah mendengar Hakim Pengawas, dapat memerintahkan supaya Debitor Pailit ditahan, baik ditempatkan di Rumah Tahanan Negara maupun di rumahnya sendiri, di bawah pengawasan jaksa yang ditunjuk oleh Hakim Pengawas. (2) Perintah penahanan sebagaimana dimaksud pada ayat (1) dilaksanakan oleh jaksa yang ditunjuk oleh Hakim Pengawas. (3) Masa penahanan sebagaimana dimaksud pada ayat (2) berlaku paling lama 30 (tiga puluh) hari terhitung sejak penahanan dilaksanakan. (4) Pada akhir tenggang waktu sebagaimana dimaksud pada ayat (3), atas usul Hakim Pengawas atau atas permintaan Kurator atau seorang Kreditor atau lebih dan setelah mendengar Hakim Pengawas, Pengadilan dapat memperpanjang masa penahanan setiap kali untuk jangka waktu paling lama 30 (tiga puluh) hari. (5) Biaya penahanan dibebankan kepada harta pailit sebagai utang harta pailit."}, {"l": "UU 37/2004", "p": "94", "b": "Bagian Keempat", "t": "(1) Pengadilan berwenang melepas Debitor Pailit dari tahanan atas usul Hakim Pengawas atau atas permohonan Debitor Pailit, dengan jaminan uang dari pihak ketiga, bahwa Debitor Pailit setiap waktu akan menghadap atas panggilan pertama. (2) Jumlah … (2) Jumlah uang jaminan sebagaimana dimaksud pada ayat (1) ditetapkan oleh Pengadilan dan apabila Debitor pailit tidak datang menghadap, uang jaminan tersebut menjadi keuntungan harta pailit."}, {"l": "UU 37/2004", "p": "95", "b": "Bagian Keempat", "t": "Permintaan untuk menahan Debitor Pailit harus dikabulkan, apabila permintaan tersebut didasarkan atas alasan bahwa Debitor Pailit dengan sengaja tidak memenuhi kewajiban sebagaimana dimaksud dalam Pasal 98, Pasal 110, atau Pasal 121 ayat (1) dan ayat (2)."}, {"l": "UU 37/2004", "p": "96", "b": "Bagian Keempat", "t": "(1) Dalam hal diperlukan kehadiran Debitor Pailit pada sesuatu perbuatan yang berkaitan dengan harta pailit maka apabila Debitor Pailit berada dalam tahanan, Debitor Pailit dapat diambil dari tempat tahanan tersebut atas perintah Hakim Pengawas. (2) Perintah sebagaimana dimaksud pada ayat (1) dilaksanakan oleh kejaksaan."}, {"l": "UU 37/2004", "p": "97", "b": "Bagian Keempat", "t": "Selama kepailitan, Debitor Pailit tidak boleh meninggalkan domisilinya tanpa izin dari Hakim Pengawas."}, {"l": "UU 37/2004", "p": "98", "b": "Bagian Keempat", "t": "Sejak mulai pengangkatannya, Kurator harus melaksanakan semua upaya untuk mengamankan harta pailit dan menyimpan semua surat, dokumen, uang, perhiasan, efek, dan surat berharga lainnya dengan memberikan tanda terima."}, {"l": "UU 37/2004", "p": "99", "b": "Bagian Keempat", "t": "(1) Kurator dapat meminta penyegelan harta pailit kepada Pengadilan, berdasarkan alasan untuk mengamankan harta pailit, melalui Hakim Pengawas. (2) Penyegelan … (2) Penyegelan sebagaimana dimaksud pada ayat (1) dilakukan oleh juru sita di tempat harta tersebut berada dengan dihadiri oleh 2 (dua) saksi yang salah satu di antaranya adalah wakil dari Pemerintah Daerah setempat."}, {"l": "UU 37/2004", "p": "100", "b": "Bagian Keempat", "t": "(1) Kurator harus membuat pencatatan harta pailit paling lambat 2 (dua) hari setelah menerima surat putusan pengangkatannya sebagai Kurator. (2) Pencatatan harta pailit dapat dilakukan di bawah tangan oleh Kurator dengan persetujuan Hakim Pengawas. (3) Anggota panitia kreditor sementara berhak menghadiri pembuatan pencatatan tersebut."}, {"l": "UU 37/2004", "p": "101", "b": "Bagian Keempat", "t": "(1) Benda sebagaimana dimaksud dalam Pasal 98, harus dimasukkan dalam pencatatan harta pailit. (2) Benda sebagaimana dimaksud dalam Pasal 22 huruf a, harus dimuat dalam daftar pertelaan yang dilampirkan pada pencatatan sebagaimana dimaksud dalam Pasal 100."}, {"l": "UU 37/2004", "p": "102", "b": "Bagian Keempat", "t": "Segera setelah dibuat pencatatan harta pailit, Kurator harus membuat daftar yang menyatakan sifat, jumlah piutang dan utang harta pailit, nama dan tempat tinggal Kreditor beserta jumlah piutang masing-masing Kreditor."}, {"l": "UU 37/2004", "p": "103", "b": "Bagian Keempat", "t": "Pencatatan harta pailit sebagaimana dimaksud dalam Pasal 100, daftar sebagaimana dimaksud dalam Pasal 102, oleh Kurator diletakkan di Kepaniteraan Pengadilan untuk dapat dilihat oleh setiap orang dengan cuma- cuma. Pasal 104 …"}, {"l": "UU 37/2004", "p": "104", "b": "Bagian Keempat", "t": "(1) Berdasarkan persetujuan panitia kreditor sementara, Kurator dapat melanjutkan usaha Debitor yang dinyatakan pailit walaupun terhadap putusan pernyataan pailit tersebut diajukan kasasi atau peninjauan kembali. (2) Apabila dalam kepailitan tidak diangkat panitia kreditor, Kurator memerlukan izin Hakim Pengawas untuk melanjutkan usaha sebagaimana dimaksud pada ayat (1)."}, {"l": "UU 37/2004", "p": "105", "b": "Bagian Keempat", "t": "(1) Kurator berwenang membuka surat dan telegram yang dialamatkan kepada Debitor Pailit. (2) Surat dan telegram yang tidak berkaitan dengan harta pailit, harus segera diserahkan kepada Debitor Pailit. (3) Perusahaan pengiriman surat dan telegram memberikan kepada Kurator, surat dan telegram yang dialamatkan kepada Debitor Pailit. (4) Semua surat pengaduan dan keberatan yang berkaitan dengan harta pailit ditujukan kepada Kurator."}, {"l": "UU 37/2004", "p": "106", "b": "Bagian Keempat", "t": "Kurator berwenang menurut keadaan memberikan suatu jumlah uang yang ditetapkan oleh Hakim Pengawas untuk biaya hidup Debitor Pailit dan keluarganya."}, {"l": "UU 37/2004", "p": "107", "b": "Bagian Keempat", "t": "(1) Atas persetujuan Hakim Pengawas, Kurator dapat mengalihkan harta pailit sejauh diperlukan untuk menutup biaya kepailitan atau apabila penahanannya akan mengakibatkan kerugian pada harta pailit, meskipun terhadap putusan pailit diajukan kasasi atau peninjauan kembali. (2) Ketentuan … (2) Ketentuan sebagaimana dimaksud dalam Pasal 185 ayat (1) berlaku terhadap ayat (1)."}, {"l": "UU 37/2004", "p": "108", "b": "Bagian Keempat", "t": "(1) Uang, perhiasan, efek, dan surat berharga lainnya wajib disimpan oleh Kurator sendiri kecuali apabila oleh Hakim Pengawas ditentukan lain. (2) Uang tunai yang tidak diperlukan untuk pengurusan harta pailit, wajib disimpan oleh Kurator di bank untuk kepentingan harta pailit setelah mendapat izin Hakim Pengawas."}, {"l": "UU 37/2004", "p": "109", "b": "Bagian Keempat", "t": "Kurator setelah meminta saran dari panitia kreditor sementara, bila ada, dan dengan izin Hakim Pengawas berwenang untuk mengadakan perdamaian guna mengakhiri suatu perkara yang sedang berjalan atau mencegah timbulnya suatu perkara."}, {"l": "UU 37/2004", "p": "110", "b": "Bagian Keempat", "t": "(1) Debitor Pailit wajib menghadap Hakim Pengawas, Kurator, atau panitia kreditor apabila dipanggil untuk memberikan keterangan. (2) Dalam hal suami atau istri dinyatakan pailit, istri atau suami yang dinyatakan pailit wajib memberikan keterangan mengenai semua perbuatan yang dilakukan oleh masing-masing terhadap harta bersama."}, {"l": "UU 37/2004", "p": "111", "b": "Bagian Keempat", "t": "Dalam hal kepailitan suatu badan hukum, ketentuan sebagaimana dimaksud dalam Pasal 93, Pasal 94, Pasal 95, Pasal 96, dan Pasal 97 hanya berlaku terhadap pengurus badan hukum tersebut, dan ketentuan Pasal 110 ayat (1) berlaku terhadap pengurus dan komisaris. Pasal 112 …"}, {"l": "UU 37/2004", "p": "112", "b": "Bagian Keempat", "t": "Atas permintaan dan biaya setiap Kreditor, Panitera wajib memberikan salinan dari surat yang disediakan di Kepaniteraan untuk dilihat oleh yang berkepentingan."}, {"l": "UU 37/2004", "p": "113", "b": "Bagian Kelima", "t": "(1) Paling lambat 14 (empat belas) hari setelah putusan pernyataan pailit diucapkan, Hakim Pengawas harus menetapkan: a. batas akhir pengajuan tagihan; b. batas akhir verifikasi pajak untuk menentukan besarnya kewajiban pajak sesuai dengan peraturan perundang-undangan di bidang perpajakan; c. hari, tanggal, waktu, dan tempat rapat Kreditor untuk mengadakan pencocokan piutang. (2) Tenggang waktu antara tanggal sebagaimana dimaksud pada ayat (1) huruf a dan huruf b paling singkat 14 (empat belas) hari."}, {"l": "UU 37/2004", "p": "114", "b": "Bagian Kelima", "t": "Kurator paling lambat 5 (lima) hari setelah penetapan sebagaimana dimaksud dalam Pasal 113 wajib memberitahukan penetapan tersebut kepada semua Kreditor yang alamatnya diketahui dengan surat dan mengumumkannya paling sedikit dalam 2 (dua) surat kabar harian sebagaimana dimaksud dalam Pasal 15 ayat (4). Pasal 115 …"}, {"l": "UU 37/2004", "p": "115", "b": "Bagian Kelima", "t": "(1) Semua Kreditor wajib menyerahkan piutangnya masing-masing kepada Kurator disertai perhitungan atau keterangan tertulis lainnya yang menunjukkan sifat dan jumlah piutang, disertai dengan surat bukti atau suatu hak istimewa, hak gadai, jaminan fidusia, hak tanggungan, hipotek, hak agunan atas kebendaan lainnya, atau hak untuk menahan benda. (2) Atas penyerahan piutang sebagaimana dimaksud pada ayat (1), Kreditor berhak meminta suatu tanda terima dari Kurator."}, {"l": "UU 37/2004", "p": "116", "b": "Bagian Kelima", "t": "(1) Kurator wajib : a. mencocokkan perhitungan piutang yang diserahkan oleh Kreditor dengan catatan yang telah dibuat sebelumnya dan keterangan Debitor Pailit; atau b. berunding dengan Kreditor jika terdapat keberatan terhadap penagihan yang diterima. (2) Kurator sebagaimana dimaksud pada ayat (1) berhak meminta kepada Kreditor agar memasukkan surat yang belum diserahkan, termasuk memperlihatkan catatan dan surat bukti asli."}, {"l": "UU 37/2004", "p": "117", "b": "Bagian Kelima", "t": "Kurator wajib memasukkan piutang yang disetujuinya ke dalam suatu daftar piutang yang sementara diakui, sedangkan piutang yang dibantah termasuk alasannya dimasukkan ke dalam daftar tersendiri. Pasal 118 …"}, {"l": "UU 37/2004", "p": "118", "b": "Bagian Kelima", "t": "(1) Dalam daftar sebagaimana dimaksud dalam Pasal 117, dibubuhkan pula catatan terhadap setiap piutang apakah menurut pendapat Kurator piutang yang bersangkutan diistimewakan atau dijamin dengan gadai, jaminan fidusia, hak tanggungan, hipotek, hak agunan atas kebendaan lainnya, atau hak untuk menahan benda bagi tagihan yang bersangkutan dapat dilaksanakan. (2) Apabila Kurator hanya membantah adanya hak untuk didahulukan atau adanya hak untuk menahan benda, piutang yang bersangkutan harus dimasukkan dalam daftar piutang yang untuk sementara diakui berikut catatan Kurator tentang bantahan serta alasannya."}, {"l": "UU 37/2004", "p": "119", "b": "Bagian Kelima", "t": "Kurator wajib menyediakan di Kepaniteraan Pengadilan salinan dari masing- masing daftar sebagaimana dimaksud dalam Pasal 117, selama 7 (tujuh) hari sebelum hari pencocokan piutang, dan setiap orang dapat melihatnya secara cuma-cuma."}, {"l": "UU 37/2004", "p": "120", "b": "Bagian Kelima", "t": "Kurator wajib memberitahukan dengan surat tentang adanya daftar sebagaimana dimaksud dalam Pasal 119 kepada Kreditor yang dikenal, disertai panggilan untuk menghadiri rapat pencocokan piutang dengan menyebutkan rencana perdamaian jika telah diserahkan oleh Debitor Pailit."}, {"l": "UU 37/2004", "p": "121", "b": "Bagian Kelima", "t": "(1) Debitor Pailit wajib hadir sendiri dalam rapat pencocokan piutang, agar dapat memberikan keterangan yang diminta oleh Hakim Pengawas mengenai sebab musabab kepailitan dan keadaan harta pailit. (2) Kreditor … (2) Kreditor dapat meminta keterangan dari Debitor Pailit mengenai hal-hal yang dikemukakan melalui Hakim Pengawas. (3) Pertanyaan yang diajukan kepada Debitor Pailit dan jawaban yang diberikan olehnya, wajib dicatat dalam berita acara."}, {"l": "UU 37/2004", "p": "122", "b": "Bagian Kelima", "t": "Dalam hal yang dinyatakan pailit suatu badan hukum, semua kewajiban sebagaimana dimaksud dalam Pasal 121 ayat (1) dan ayat (2) menjadi tanggung jawab pengurus badan hukum tersebut."}, {"l": "UU 37/2004", "p": "123", "b": "Bagian Kelima", "t": "Dalam rapat sebagaimana dimaksud dalam Pasal 121, Kreditor dapat menghadap sendiri atau mewakilkan kepada kuasanya."}, {"l": "UU 37/2004", "p": "124", "b": "Bagian Kelima", "t": "(1) Dalam rapat sebagaimana dimaksud dalam Pasal 121, Hakim Pengawas membacakan daftar piutang yang diakui sementara dan daftar piutang yang dibantah oleh Kurator. (2) Setiap Kreditor yang namanya tercantum dalam daftar piutang sebagaimana dimaksud pada ayat (1) dapat meminta agar Kurator memberikan keterangan mengenai tiap piutang dan penempatannya dalam daftar, atau dapat membantah kebenaran piutang, adanya hak untuk didahulukan, hak untuk menahan suatu benda, atau dapat menyetujui bantahan Kurator. (3) Kurator berhak menarik kembali pengakuan sementara atau bantahannya, atau menuntut supaya Kreditor menguatkan dengan sumpah kebenaran piutangnya yang tidak dibantah oleh Kurator atau oleh salah seorang Kreditor. (4) Dalam hal Kreditor asal telah meninggal dunia, para pengganti haknya wajib menerangkan di bawah sumpah bahwa mereka dengan itikad baik percaya piutang itu ada dan belum dilunasi. (5) Dalam … (5) Dalam hal dianggap perlu untuk menunda rapat maka Hakim Pengawas menentukan rapat berikutnya yang diadakan dalam waktu 8 (delapan) hari setelah rapat ditunda, tanpa suatu panggilan."}, {"l": "UU 37/2004", "p": "125", "b": "Bagian Kelima", "t": "(1) Pengucapan sumpah sebagaimana dimaksud dalam Pasal 124 ayat (3) dan ayat (4) wajib dilakukan oleh Kreditor sendiri atau wakilnya yang khusus dikuasakan untuk itu, baik pada rapat termaksud, maupun pada hari lain yang telah ditentukan oleh Hakim Pengawas. (2) Dalam hal Kreditor yang diperintahkan mengucapkan sumpah tidak hadir atau tidak diwakili dalam rapat maka panitera wajib memberitahukan kepada Kreditor adanya perintah mengucapkan sumpah dan hari yang ditentukan untuk pengucapan sumpah tersebut. (3) Hakim Pengawas wajib memberikan surat keterangan kepada Kreditor mengenai sumpah yang telah diucapkannya, kecuali apabila sumpah tersebut diucapkan dalam rapat Kreditor maka harus dicatat dalam berita acara rapat yang bersangkutan."}, {"l": "UU 37/2004", "p": "126", "b": "Bagian Kelima", "t": "(1) Piutang yang tidak dibantah wajib dipindahkan ke dalam daftar piutang yang diakui, yang dimasukkan dalam berita acara rapat. (2) Dalam hal piutang berupa surat atas tunjuk dan surat atas pengganti maka Kurator mencatat pengakuan pada surat yang bersangkutan. (3) Piutang yang oleh Kurator diperintahkan agar dikuatkan dengan sumpah, diterima dengan syarat, sampai saat diterima secara pasti setelah sumpah diucapkan pada waktu sebagaimana dimaksud dalam Pasal 125 ayat (1). (4) Berita … (4) Berita acara rapat ditandatangani oleh Hakim Pengawas dan panitera pengganti. (5) Pengakuan suatu piutang yang dicatat dalam berita acara rapat mempunyai kekuatan hukum yang tetap dalam kepailitan dan pembatalannya tidak dapat dituntut oleh Kurator, kecuali berdasarkan alasan adanya penipuan."}, {"l": "UU 37/2004", "p": "127", "b": "Bagian Kelima", "t": "(1) Dalam hal ada bantahan sedangkan Hakim Pengawas tidak dapat mendamaikan kedua belah pihak, sekalipun perselisihan tersebut telah diajukan ke pengadilan, Hakim Pengawas memerintahkan kepada kedua belah pihak untuk menyelesaikan perselisihan tersebut di pengadilan. (2) Advokat yang mewakili para pihak harus advokat sebagaimana dimaksud dalam Pasal 7. (3) Perkara sebagaimana dimaksud pada ayat (1) diperiksa secara sederhana. (4) Dalam hal Kreditor yang meminta pencocokan piutangnya tidak menghadap pada sidang yang telah ditentukan maka yang bersangkutan dianggap telah menarik kembali permintaannya dan dalam hal pihak yang melakukan bantahan tidak datang menghadap maka yang bersangkutan dianggap telah melepaskan bantahannya, dan hakim harus mengakui piutang yang bersangkutan. (5) Kreditor yang pada rapat pencocokan piutang tidak mengajukan bantahan, tidak diperbolehkan menggabungkan diri atau melakukan intervensi dalam perkara yang bersangkutan. Pasal 128 …"}, {"l": "UU 37/2004", "p": "128", "b": "Bagian Kelima", "t": "(1) Pemeriksaan terhadap bantahan yang diajukan oleh Kurator ditangguhkan demi hukum dengan disahkannya perdamaian dalam kepailitan, kecuali apabila surat-surat perkara telah diserahkan kepada hakim untuk diputuskan dengan ketentuan bahwa: a. dalam hal piutang diterima maka piutang dianggap diakui dalam kepailitan; b. biaya perkara menjadi tanggungan Debitor Pailit. (2) Debitor dapat mengambil alih perkara yang ditangguhkan sebagaimana dimaksud pada ayat (1) sebagai pengganti Kurator berdasarkan surat-surat perkara sebagaimana dimaksud pada ayat (1), dengan diwakili oleh seorang advokat. (3) Selama pengambilalihan sebagaimana dimaksud pada ayat (2) tidak terjadi maka pihak lawan berhak memanggil Debitor untuk mengambil alih perkara. (4) Dalam hal Debitor tidak menghadap, putusan tidak hadir dapat dijatuhkan menurut Hukum Acara Perdata. (5) Dalam hal bantahan itu diajukan oleh Kreditor peserta, setelah putusan pengesahan perdamaian dalam kepailitan memperoleh kekuatan hukum tetap, perkara dapat dilanjutkan oleh para pihak hanya untuk memohon hakim memutus mengenai biaya perkara."}, {"l": "UU 37/2004", "p": "129", "b": "Bagian Kelima", "t": "Kreditor yang piutangnya dibantah tidak wajib mengajukan bukti yang lebih untuk menguatkan piutang tersebut daripada bukti yang seharusnya diajukan kepada Debitor Pailit. Pasal 130 …"}, {"l": "UU 37/2004", "p": "130", "b": "Bagian Kelima", "t": "(1) Dalam hal Kreditor yang piutangnya dibantah tidak hadir dalam rapat, jurusita dalam jangka waktu 7 (tujuh) hari setelah ketidakhadiran Kreditor harus memberitahukan dengan surat dinas mengenai bantahan yang telah diajukan. (2) Dalam hal Kreditor memperkarakan bantahan sebagaimana dimaksud pada ayat (1), Kreditor tidak dapat menggunakan sebagai alasan tidak adanya pemberitahuan dalam perkara dimaksud."}, {"l": "UU 37/2004", "p": "131", "b": "Bagian Kelima", "t": "(1) Hakim Pengawas dapat menerima secara bersyarat piutang yang dibantah sampai dengan suatu jumlah yang ditetapkan olehnya. (2) Dalam hal yang dibantah adalah peringkat piutang, Hakim Pengawas dapat mengakui peringkat tersebut dengan bersyarat."}, {"l": "UU 37/2004", "p": "132", "b": "Bagian Kelima", "t": "(1) Debitor Pailit berhak membantah atas diterimanya suatu piutang baik seluruhnya maupun sebagian atau membantah adanya peringkat piutang dengan mengemukakan alasan secara sederhana. (2) Bantahan sebagaimana dimaksud pada ayat (1) dicatat dalam berita acara rapat beserta alasannya. (3) Bantahan sebagaimana dimaksud pada ayat (2) tidak menghalangi pengakuan piutang dalam kepailitan. (4) Bantahan yang tidak menyebutkan alasan atau bantahan yang tidak ditujukan terhadap seluruh piutang tetapi tidak menyatakan dengan tegas bagian yang diakui atau bagian yang dibantah, tidak dianggap sebagai suatu bantahan. Pasal 133 …"}, {"l": "UU 37/2004", "p": "133", "b": "Bagian Kelima", "t": "(1) Piutang yang dimasukkan pada Kurator setelah lewat jangka waktu sebagaimana dimaksud dalam Pasal 113 ayat (1), dengan syarat dimasukkan paling lambat 2 (dua) hari sebelum hari diadakannya rapat pencocokan piutang, wajib dicocokkan apabila ada permintaan yang diajukan dalam rapat dan tidak ada keberatan, baik yang diajukan oleh Kurator maupun oleh salah seorang Kreditor yang hadir dalam rapat. (2) Piutang yang diajukan setelah lewat jangka waktu yang ditentukan sebagai- mana dimaksud pada ayat (1), tidak dicocokkan. (3) Ketentuan jangka waktu sebagaimana dimaksud pada ayat (1) dan ayat (2) tidak berlaku, apabila Kreditor berdomisili di luar wilayah Negara Republik Indonesia yang merupakan halangan untuk melaporkan diri lebih dahulu. (4) Dalam hal diajukannya keberatan sebagaimana dimaksud pada ayat (1) atau dalam hal timbulnya perselisihan mengenai ada atau tidak adanya halangan sebagaimana dimaksud pada ayat (3), Hakim Pengawas wajib mengambil keputusan setelah meminta nasihat dari rapat."}, {"l": "UU 37/2004", "p": "134", "b": "Bagian Kelima", "t": "(1) Terhadap bunga atas utang yang timbul setelah putusan pernyataan pailit diucapkan tidak dapat dilakukan pencocokan piutang, kecuali dan hanya sejauh dijamin dengan gadai, jaminan fidusia, hak tanggungan, hipotek, atau hak agunan atas kebendaan lainnya. (2) Terhadap bunga yang dijamin dengan hak agunan sebagaimana dimaksud pada ayat (1) harus dilakukan pencocokan piutang secara pro memori. (3) Apabila … (3) Apabila bunga yang bersangkutan tidak dapat dilunasi dengan hasil penjualan benda yang menjadi agunan, Kreditor yang bersangkutan tidak dapat melaksanakan haknya yang timbul dari pencocokan piutang."}, {"l": "UU 37/2004", "p": "135", "b": "Bagian Kelima", "t": "Suatu piutang dengan syarat batal wajib dicocokkan untuk seluruh jumlahnya dengan tidak mengurangi akibat syarat batal apabila syarat tersebut terpenuhi."}, {"l": "UU 37/2004", "p": "136", "b": "Bagian Kelima", "t": "(1) Piutang dengan syarat tunda dapat dicocokkan untuk nilainya pada saat putusan pernyataan pailit diucapkan. (2) Dalam hal Kurator dan Kreditor tidak ada kata sepakat mengenai cara pencocokan, piutangnya wajib diterima dengan syarat untuk seluruh jumlahnya."}, {"l": "UU 37/2004", "p": "137", "b": "Bagian Kelima", "t": "(1) Piutang yang saat penagihannya belum jelas atau yang memberikan hak untuk memperoleh pembayaran secara berkala, wajib dicocokkan nilainya pada tanggal putusan pernyataan pailit diucapkan. (2) Semua piutang yang dapat ditagih dalam waktu 1 (satu) tahun setelah tanggal putusan pernyataan pailit diucapkan, wajib diperlakukan sebagai piutang yang dapat ditagih pada tanggal tersebut. (3) Semua piutang yang dapat ditagih setelah lewat 1 (satu) tahun setelah tanggal putusan pernyataan pailit diucapkan, wajib dicocokkan untuk nilai yang berlaku 1 (satu) tahun setelah tanggal putusan pernyataan pailit diucapkan. (4) Dalam … (4) Dalam melakukan perhitungan nilai piutang sebagaimana dimaksud pada ayat (2) dan ayat (3), wajib diperhatikan : a. waktu dan cara pembayaran angsuran; b. keuntungan yang mungkin diperoleh; dan c. besarnya bunga apabila diperjanjikan."}, {"l": "UU 37/2004", "p": "138", "b": "Bagian Kelima", "t": "Kreditor yang piutangnya dijamin dengan gadai, jaminan fidusia, hak tanggungan, hipotek, hak agunan atas kebendaan lainnya, atau yang mempunyai hak yang diistimewakan atas suatu benda tertentu dalam harta pailit dan dapat membuktikan bahwa sebagian piutang tersebut kemungkinan tidak akan dapat dilunasi dari hasil penjualan benda yang menjadi agunan, dapat meminta diberikan hak-hak yang dimiliki kreditor konkuren atas bagian piutang tersebut, tanpa mengurangi hak untuk didahulukan atas benda yang menjadi agunan atas piutangnya."}, {"l": "UU 37/2004", "p": "139", "b": "Bagian Kelima", "t": "(1) Piutang yang nilainya tidak ditetapkan, tidak pasti, tidak dinyatakan dalam mata uang Republik Indonesia atau sama sekali tidak ditetapkan dalam uang, wajib dicocokkan sesuai dengan nilai taksirannya dalam mata uang (2) Penetapan nilai piutang ke dalam mata uang Republik Indonesia sebagaimana dimaksud pada ayat (1), dilakukan pada tanggal putusan pernyataan pailit diucapkan. (3) Penetapan nilai piutang ke dalam mata uang Republik Indonesia bagi piutang milik Kreditor sebagaimana dimaksud dalam Pasal 55 ayat (1) dilakukan pada tanggal eksekusi benda agunan dengan menggunakan Kurs Tengah Bank Indonesia."}, {"l": "UU 37/2004", "p": "140", "b": "Bagian Kelima", "t": "(1) Piutang atas tunjuk dapat dicocokkan dengan mencatatkan surat tersebut tanpa menyebutkan nama pembawa atau dengan mencatatkannya atas nama pembawa. (2) Masing- … (2) Masing-masing piutang atas tunjuk yang dicocokkan tanpa menyebutkan nama pembawa sebagaimana dimaksud pada ayat (1) dianggap sebagai piutang Kreditor tersendiri."}, {"l": "UU 37/2004", "p": "141", "b": "Bagian Kelima", "t": "(1) Kreditor yang piutangnya dijamin oleh seorang penanggung dapat mengajukan pencocokan piutang setelah dikurangi dengan pembayaran yang telah diterima dari penanggung. (2) Penanggung berhak mengajukan pencocokan sebesar bayaran yang telah dilakukan kepada Kreditor. (3) Selain hak sebagaimana dimaksud pada ayat (2), penanggung dapat diterima secara bersyarat dalam pencocokan atas suatu jumlah yang belum dibayar oleh penanggung dan tidak dicocokkan oleh Kreditor."}, {"l": "UU 37/2004", "p": "142", "b": "Bagian Kelima", "t": "(1) Dalam hal terdapat Debitor tanggung-menanggung dan satu atau lebih Debitor dinyatakan pailit, Kreditor dapat mengajukan piutangnya kepada Debitor yang dinyatakan pailit atau kepada masing-masing Debitor yang dinyatakan pailit sampai seluruh piutangnya dibayar lunas. (2) Setiap Debitor tanggung-menanggung yang mempunyai hak untuk menuntut penggantian dari harta pailit Debitor lainnya yang dinyatakan pailit dapat diterima secara bersyarat dalam pencocokan apabila Kreditor tidak melakukan pencocokan sendiri. (3) Dalam hal harta pailit seluruh Debitor tanggung-menanggung melebihi 100% (seratus persen) dari tagihan, kelebihannya dibagikan di antara Debitor tanggung-menanggung menurut hubungan hukum di antara mereka. Pasal 143 …"}, {"l": "UU 37/2004", "p": "143", "b": "Bagian Kelima", "t": "(1) Setelah berakhirnya pencocokan piutang, Kurator wajib memberikan laporan mengenai keadaan harta pailit, dan selanjutnya kepada Kreditor wajib diberikan semua keterangan yang diminta oleh mereka. (2) Setelah berakhirnya rapat maka laporan sebagaimana dimaksud pada ayat (1) beserta berita acara rapat pencocokan piutang wajib disediakan di Kepaniteraan dan kantor Kurator. (3) Untuk mendapatkan salinan surat sebagaimana dimaksud pada ayat (2) dikenakan biaya. (4) Setelah berita acara rapat sebagaimana dimaksud pada ayat (2) tersedia, Kurator, Kreditor, atau Debitor Pailit dapat meminta kepada Pengadilan supaya berita acara rapat tersebut diperbaiki, apabila dari dokumen mengenai kepailitan terdapat kekeliruan dalam berita acara rapat."}, {"l": "UU 37/2004", "p": "144", "b": "Bagian Keenam", "t": "Debitor Pailit berhak untuk menawarkan suatu perdamaian kepada semua Kreditor."}, {"l": "UU 37/2004", "p": "145", "b": "Bagian Keenam", "t": "(1) Apabila Debitor Pailit mengajukan rencana perdamaian dan paling lambat 8 (delapan) hari sebelum rapat pencocokan piutang menyediakannya di Kepaniteraan Pengadilan agar dapat dilihat dengan cuma-cuma oleh setiap orang yang berkepentingan, rencana perdamaian tersebut wajib dibicarakan dan diambil keputusan segera setelah selesainya pencocokan piutang, kecuali dalam hal yang ditentukan sebagaimana dimaksud dalam Pasal 147. (2) Bersamaan … (2) Bersamaan dengan penyediaan rencana perdamaian sebagaimana dimaksud pada ayat (1) di Kepaniteraan Pengadilan maka salinannya wajib dikirimkan kepada masing-masing anggota panitia kreditor sementara."}, {"l": "UU 37/2004", "p": "146", "b": "Bagian Keenam", "t": "Kurator dan panitia kreditor sementara masing-masing wajib memberikan pendapat tertulis tentang rencana perdamaian dalam rapat sebagaimana dimaksud dalam Pasal 145."}, {"l": "UU 37/2004", "p": "147", "b": "Bagian Keenam", "t": "Pembicaraan dan keputusan mengenai rencana perdamaian sebagaimana dimaksud dalam Pasal 145, ditunda sampai rapat berikut yang tanggalnya ditetapkan oleh Hakim Pengawas paling lambat 21 (dua puluh satu) hari kemudian, dalam hal : a. apabila dalam rapat diangkat panitia kreditor tetap yang tidak terdiri atas orang-orang yang sama seperti panitia kreditor sementara, sedangkan jumlah terbanyak Kreditor menghendaki dari panitia kreditor tetap pendapat tertulis tentang perdamaian yang diusulkan tersebut; atau b. rencana perdamaian tidak disediakan di Kepaniteraan Pengadilan dalam waktu yang ditentukan, sedangkan jumlah terbanyak Kreditor yang hadir menghendaki pengunduran rapat."}, {"l": "UU 37/2004", "p": "148", "b": "Bagian Keenam", "t": "Dalam hal pembicaraan dan pemungutan suara mengenai rencana perdamaian sebagaimana dimaksud dalam Pasal 147 ditunda sampai rapat berikutnya, Kurator dalam jangka waktu 7 (tujuh) hari setelah tanggal rapat terakhir harus memberitahukan kepada Kreditor yang diakui atau Kreditor yang untuk sementara diakui yang tidak hadir pada rapat pencocokan piutang dengan surat yang memuat secara ringkas isi rencana perdamaian tersebut. Pasal 149 …"}, {"l": "UU 37/2004", "p": "149", "b": "Bagian Keenam", "t": "(1) Pemegang gadai, jaminan fidusia, hak tanggungan, hipotek, atau hak agunan atas kebendaaan lainnya dan Kreditor yang diistimewakan, termasuk Kreditor yang mempunyai hak didahulukan yang dibantah, tidak boleh mengeluarkan suara berkenaan dengan rencana perdamaian, kecuali apabila mereka telah melepaskan haknya untuk didahulukan demi kepentingan harta pailit sebelum diadakannya pemungutan suara tentang rencana perdamaian tersebut. (2) Dengan pelepasan hak sebagaimana dimaksud pada ayat (1), mereka menjadi Kreditor konkuren, juga dalam hal perdamaian tersebut tidak diterima."}, {"l": "UU 37/2004", "p": "150", "b": "Bagian Keenam", "t": "Debitor Pailit berhak memberikan keterangan mengenai rencana perdamaian dan membelanya serta berhak mengubah rencana perdamaian tersebut selama berlangsungnya perundingan."}, {"l": "UU 37/2004", "p": "151", "b": "Bagian Keenam", "t": "Rencana perdamaian diterima apabila disetujui dalam rapat Kreditor oleh lebih dari 1/2 (satu perdua) jumlah kreditor konkuren yang hadir dalam rapat dan yang haknya diakui atau yang untuk sementara diakui, yang mewakili paling sedikit 2/3 (dua pertiga) dari jumlah seluruh piutang konkuren yang diakui atau yang untuk sementara diakui dari kreditor konkuren atau kuasanya yang hadir dalam rapat tersebut. Pasal 152 …"}, {"l": "UU 37/2004", "p": "152", "b": "Bagian Keenam", "t": "(1) Apabila lebih dari 1/2 (satu perdua) jumlah Kreditor yang hadir pada rapat Kreditor dan mewakili paling sedikit 1/2 (satu perdua) dari jumlah piutang Kreditor yang mempunyai hak suara menyetujui untuk menerima rencana perdamaian maka dalam jangka waktu paling lambat 8 (delapan) hari setelah pemungutan suara pertama diadakan, diselenggarakan pemungutan suara kedua, tanpa diperlukan pemanggilan. (2) Pada pemungutan suara kedua, Kreditor tidak terikat pada suara yang dikeluarkan pada pemungutan suara pertama."}, {"l": "UU 37/2004", "p": "153", "b": "Bagian Keenam", "t": "Perubahan yang terjadi kemudian, baik mengenai jumlah Kreditor maupun jumlah piutang, tidak mempengaruhi sahnya penerimaan atau penolakan perdamaian."}, {"l": "UU 37/2004", "p": "154", "b": "Bagian Keenam", "t": "(1) Berita acara rapat wajib memuat: a. isi perdamaian; b. nama Kreditor yang hadir dan berhak mengeluarkan suara dan menghadap; c. suara yang dikeluarkan; d. hasil pemungutan suara; dan e. segala sesuatu yang terjadi dalam rapat. (2) Berita acara rapat ditandatangani oleh Hakim Pengawas dan panitera pengganti. (3) Setiap orang yang berkepentingan dapat melihat dengan cuma-cuma berita acara rapat sebagaimana dimaksud pada ayat (1) yang disediakan paling lambat 7 (tujuh) hari setelah tanggal berakhirnya rapat di Kepaniteraan Pengadilan. (4) Untuk … (4) Untuk memperoleh salinan berita acara rapat sebagaimana dimaksud pada ayat (3) dikenakan biaya."}, {"l": "UU 37/2004", "p": "155", "b": "Bagian Keenam", "t": "Kreditor yang telah mengeluarkan suara menyetujui rencana perdamaian atau Debitor Pailit, dapat meminta kepada Pengadilan pembetulan berita acara rapat dalam jangka waktu 8 (delapan) hari setelah tersedianya berita acara rapat sebagaimana dimaksud dalam Pasal 154 ayat (3), apabila dari dokumen mengenai rapat rencana perdamaian ternyata Hakim Pengawas secara keliru telah menganggap rencana perdamaian tersebut ditolak."}, {"l": "UU 37/2004", "p": "156", "b": "Bagian Keenam", "t": "(1) Dalam hal rencana perdamaian diterima sebelum rapat ditutup, Hakim Pengawas menetapkan hari sidang Pengadilan yang akan memutuskan mengenai disahkan atau tidaknya rencana perdamaian tersebut. (2) Dalam hal terdapat kekeliruan sebagaimana dimaksud dalam Pasal 155, penetapan hari sidang akan dilakukan oleh Pengadilan dan Kurator wajib memberitahukan kepada Kreditor dengan surat mengenai penetapan hari sidang tersebut. (3) Sidang Pengadilan harus diadakan paling singkat 8 (delapan) hari dan paling lambat 14 (empat belas) hari setelah diterimanya rencana perdamaian dalam rapat pemungutan suara atau setelah dikeluarkannya penetapan Pengadilan dalam hal terdapat kekeliruan sebagaimana dimaksud dalam Pasal 155."}, {"l": "UU 37/2004", "p": "157", "b": "Bagian Keenam", "t": "Selama sidang, Kreditor dapat menyampaikan kepada Hakim Pengawas alasan- alasan yang menyebabkan mereka menghendaki ditolaknya pengesahan rencana perdamaian. Pasal 158 …"}, {"l": "UU 37/2004", "p": "158", "b": "Bagian Keenam", "t": "(1) Pada hari yang ditetapkan Hakim Pengawas dalam sidang terbuka memberikan laporan tertulis, sedangkan tiap-tiap Kreditor baik sendiri maupun kuasanya, dapat menjelaskan alasan-alasan yang menyebabkan ia menghendaki pengesahan atau penolakan perdamaian. (2) Debitor Pailit juga berhak mengemukakan alasan guna membela kepentingannya."}, {"l": "UU 37/2004", "p": "159", "b": "Bagian Keenam", "t": "(1) Pada sidang sebagaimana dimaksud dalam Pasal 158 atau paling lambat 7 (tujuh) hari setelah tanggal sidang tersebut, Pengadilan wajib memberikan penetapan disertai alasannya. (2) Pengadilan wajib menolak pengesahan perdamaian apabila : a. harta Debitor, termasuk benda untuk mana dilaksanakan hak untuk menahan suatu benda, jauh lebih besar daripada jumlah yang disetujui dalam perdamaian; b. pelaksanaan perdamaian tidak cukup terjamin; dan/atau c. perdamaian itu dicapai karena penipuan, atau persekongkolan dengan satu atau lebih Kreditor, atau karena pemakaian upaya lain yang tidak jujur dan tanpa menghiraukan apakah Debitor atau pihak lain bekerjasama untuk mencapai hal ini."}, {"l": "UU 37/2004", "p": "160", "b": "Bagian Keenam", "t": "(1) Dalam hal pengesahan perdamaian ditolak, baik Kreditor yang menyetujui rencana perdamaian maupun Debitor Pailit, dalam waktu 8 (delapan) hari setelah tanggal putusan Pengadilan diucapkan, dapat mengajukan kasasi. (2) Dalam hal pengesahan perdamaian dikabulkan, dalam waktu 8 (delapan) hari setelah tanggal pengesahan tersebut diucapkan, dapat diajukan kasasi oleh: a. Kreditor … a. Kreditor yang menolak perdamaian atau yang tidak hadir pada saat diadakan pemungutan suara; b. Kreditor yang menyetujui perdamaian setelah mengetahui bahwa perdamaian tersebut dicapai berdasarkan alasan sebagaimana dimaksud dalam Pasal 159 ayat (2) huruf c."}, {"l": "UU 37/2004", "p": "161", "b": "Bagian Keenam", "t": "(1) Kasasi atas putusan Pengadilan sebagaimana dimaksud dalam Pasal 160 diselenggarakan sesuai dengan ketentuan sebagaimana dimaksud dalam Pasal 11, Pasal 12, dan Pasal 13. (2) Ketentuan sebagaimana dimaksud dalam Pasal 158 kecuali ketentuan yang menyangkut Hakim Pengawas dan Pasal 159 ayat (1), juga berlaku dalam pemeriksaan kasasi sebagaimana dimaksud pada ayat (1)."}, {"l": "UU 37/2004", "p": "162", "b": "Bagian Keenam", "t": "Perdamaian yang disahkan berlaku bagi semua Kreditor yang tidak mempunyai hak untuk didahulukan, dengan tidak ada pengecualian, baik yang telah mengajukan diri dalam kepailitan maupun tidak."}, {"l": "UU 37/2004", "p": "163", "b": "Bagian Keenam", "t": "Dalam hal perdamaian atau pengesahan ditolak, Debitor Pailit tidak dapat lagi menawarkan perdamaian dalam kepailitan tersebut."}, {"l": "UU 37/2004", "p": "164", "b": "Bagian Keenam", "t": "Putusan pengesahan perdamaian yang telah memperoleh kekuatan hukum tetap merupakan alas hak yang dapat dijalankan terhadap Debitor dan semua orang yang menanggung pelaksanaan perdamaian sehubungan dengan piutang yang telah diakui, sejauh tidak dibantah oleh Debitor Pailit sesuai ketentuan Pasal 132 sebagaimana termuat dalam berita acara rapat pencocokan piutang. Pasal 165 …"}, {"l": "UU 37/2004", "p": "165", "b": "Bagian Keenam", "t": "(1) Meskipun sudah ada perdamaian, Kreditor tetap memiliki hak terhadap para penanggung dan sesama Debitor . (2) Hak Kreditor terhadap benda pihak ketiga tetap dimilikinya seolah-olah tidak ada suatu perdamaian."}, {"l": "UU 37/2004", "p": "166", "b": "Bagian Keenam", "t": "(1) Dalam hal pengesahan perdamaian telah memperoleh kekuatan hukum tetap, kepailitan berakhir. (2) Kurator wajib mengumumkan perdamaian sebagaimana dimaksud pada ayat (1) dalam Berita Negara Republik Indonesia dan paling sedikit 2 (dua) surat kabar harian sebagaimana dimaksud dalam Pasal 15 ayat (4)."}, {"l": "UU 37/2004", "p": "167", "b": "Bagian Keenam", "t": "(1) Setelah pengesahan perdamaian memperoleh kekuatan hukum tetap, Kurator wajib melakukan pertanggungjawaban kepada Debitor di hadapan Hakim Pengawas. (2) Dalam hal perdamaian tidak menetapkan ketentuan lain, Kurator wajib mengembalikan kepada Debitor semua benda, uang, buku, dan dokumen yang termasuk harta pailit dengan menerima tanda terima yang sah."}, {"l": "UU 37/2004", "p": "168", "b": "Bagian Keenam", "t": "(1) Jumlah uang yang menjadi hak Kreditor yang telah dicocokan berdasarkan hak istimewa yang diakui serta biaya kepailitan wajib diserahkan langsung kepada Kurator, kecuali apabila Debitor telah memberikan jaminan untuk itu. (2) Selama kewajiban sebagaimana dimaksud pada ayat (1) belum terpenuhi, Kurator wajib menahan semua benda dan uang yang termasuk harta pailit. (3) Dalam … (3) Dalam hal setelah lewat jangka waktu 30 (tiga puluh) hari setelah tanggal putusan pengesahan perdamaian memperoleh kekuatan hukum tetap dan Debitor tidak memenuhi kewajiban sebagaimana dimaksud pada ayat (1), Kurator wajib melunasinya dari harta pailit yang tersedia. (4) Jumlah utang sebagaimana dimaksud pada ayat (1) dan bagian yang wajib diserahkan kepada masing-masing Kreditor berdasarkan hak istimewa, jika perlu ditetapkan oleh Hakim Pengawas."}, {"l": "UU 37/2004", "p": "169", "b": "Bagian Keenam", "t": "Apabila piutang yang hak istimewanya diakui dengan syarat, kewajiban sebagaimana dimaksud dalam Pasal 168 terbatas pada pemberian jaminan, dan apabila pemberian jaminan tersebut tidak dipenuhi, Kurator hanya wajib menyediakan suatu jumlah cadangan dari harta pailit sebesar hak istimewa tersebut."}, {"l": "UU 37/2004", "p": "170", "b": "Bagian Keenam", "t": "(1) Kreditor dapat menuntut pembatalan suatu perdamaian yang telah disahkan apabila Debitor lalai memenuhi isi perdamaian tersebut. (2) Debitor wajib membuktikan bahwa perdamaian telah dipenuhi. (3) Pengadilan berwenang memberikan kelonggaran kepada Debitor untuk memenuhi kewajibannya paling lama 30 (tiga puluh) hari setelah putusan pemberian kelonggaran tersebut diucapkan."}, {"l": "UU 37/2004", "p": "171", "b": "Bagian Keenam", "t": "Tuntutan pembatalan perdamaian wajib diajukan dan ditetapkan dengan cara yang sama, sebagaimana dimaksud dalam Pasal 7, Pasal 8, Pasal 9, Pasal 11, Pasal 12, dan Pasal 13 untuk permohonan pernyataan pailit. Pasal 172 …"}, {"l": "UU 37/2004", "p": "172", "b": "Bagian Keenam", "t": "(1) Dalam putusan pembatalan perdamaian diperintahkan supaya kepailitan dibuka kembali, dengan pengangkatan seorang Hakim Pengawas, Kurator, dan anggota panitia kreditor, apabila dalam kepailitan terdahulu ada suatu panitia seperti itu. (2) Hakim Pengawas, Kurator, dan anggota panitia sebagaimana dimaksud pada ayat (1) sedapat mungkin diangkat dari mereka yang dahulu dalam kepailitan tersebut telah memangku jabatannya. (3) Kurator wajib memberitahukan dan mengumumkan putusan sebagaimana dimaksud pada ayat (1) dengan cara sebagaimana dimaksud dalam Pasal 15 ayat (4)."}, {"l": "UU 37/2004", "p": "173", "b": "Bagian Keenam", "t": "(1) Dalam hal kepailitan dibuka kembali maka berlaku Pasal 17 ayat (1), Pasal 19, Pasal 20, Pasal 21, Pasal 22, dan pasal-pasal dalam Bagian Kedua,"}, {"l": "UU 37/2004", "p": "174", "b": "Bagian Ketiga, dan Bagian Keempat dalam Bab II Undang-Undang ini.", "t": "Dengan tidak mengurangi berlakunya Pasal 41, Pasal 42, Pasal 43, dan Pasal 44, apabila ada alasan untuk itu, semua perbuatan yang dilakukan oleh Debitor dalam waktu antara pengesahan perdamaian dan pembukaan kembali kepailitan mengikat bagi harta pailit. Pasal 175 …"}, {"l": "UU 37/2004", "p": "175", "b": "Bagian Ketiga, dan Bagian Keempat dalam Bab II Undang-Undang ini.", "t": "(1) Setelah kepailitan dibuka kembali maka tidak dapat lagi ditawarkan perdamaian. (2) Kurator wajib seketika memulai dengan pemberesan harta pailit."}, {"l": "UU 37/2004", "p": "176", "b": "Bagian Ketiga, dan Bagian Keempat dalam Bab II Undang-Undang ini.", "t": "Dalam hal kepailitan dibuka kembali, harta pailit dibagi di antara para Kreditor dengan cara: a. jika Kreditor lama maupun Kreditor baru belum mendapat pembayaran, hasil penguangan harta pailit dibagi di antara mereka secara pro rata; b. jika telah dilakukan pembayaran sebagian kepada Kreditor lama, Kreditor lama dan Kreditor baru berhak menerima pembayaran sesuai dengan prosentase yang telah disepakati dalam perdamaian; c. Kreditor lama dan Kreditor baru berhak memperoleh pembayaran secara pro rata atas sisa harta pailit setelah dikurangi pembayaran sebagaimana dimaksud pada huruf b sampai dipenuhinya seluruh piutang yang diakui; d. Kreditor lama yang telah memperoleh pembayaran tidak diwajibkan untuk mengembalikan pembayaran yang telah diterimanya."}, {"l": "UU 37/2004", "p": "177", "b": "Bagian Ketiga, dan Bagian Keempat dalam Bab II Undang-Undang ini.", "t": "Ketentuan sebagaimana dimaksud dalam Pasal 176 berlaku mutatis mutandis dalam hal Debitor sekali lagi dinyatakan pailit sedangkan pada saat itu yang bersangkutan belum memenuhi seluruh kewajiban dalam perdamaian."}, {"l": "UU 37/2004", "p": "178", "b": "Bagian Ketujuh", "t": "(1) Jika dalam rapat pencocokan piutang tidak ditawarkan rencana perdamaian, rencana perdamaian yang ditawarkan tidak diterima, atau pengesahan perdamaian ditolak berdasarkan putusan yang telah memperoleh kekuatan hukum tetap, demi hukum harta pailit berada dalam keadaan insolvensi. (2) Ketentuan sebagaimana dimaksud dalam Pasal 104 dan Pasal 106 tidak berlaku, apabila sudah ada kepastian bahwa perusahaan Debitor pailit tidak akan dilanjutkan menurut pasal-pasal di bawah ini atau apabila kelanjutan usaha itu dihentikan."}, {"l": "UU 37/2004", "p": "179", "b": "Bagian Ketujuh", "t": "(1) Jika dalam rapat pencocokan piutang tidak ditawarkan rencana perdamaian atau jika rencana perdamaian yang ditawarkan tidak diterima, Kurator atau Kreditor yang hadir dalam rapat dapat mengusulkan supaya perusahaan Debitor Pailit dilanjutkan. (2) Jika ada panitia kreditor dan usul diajukan oleh Kreditor, panitia kreditor dan Kurator wajib memberikan pendapat mengenai usul tersebut. (3) Atas permintaan Kurator atau salah seorang dari Kreditor yang hadir, Hakim Pengawas menunda pembicaraan dan pengambilan keputusan atas usul tersebut, sampai suatu rapat yang ditetapkan paling lambat 14 (empat belas) hari sesudahnya. (4) Kurator wajib segera memberitahu Kreditor yang tidak hadir dalam rapat mengenai akan diadakannya rapat dengan surat yang memuat usul tersebut dan diingatkan tentang adanya ketentuan sebagaimana dimaksud dalam"}, {"l": "UU 37/2004", "p": "180", "b": "Bagian Ketujuh", "t": "(1) Usul untuk melanjutkan perusahaan sebagaimana dimaksud dalam Pasal 179 ayat (1), wajib diterima apabila usul tersebut disetujui oleh Kreditor yang mewakili lebih dari 1/2 (satu perdua) dari semua piutang yang diakui dan diterima dengan sementara, yang tidak dijamin dengan hak gadai, jaminan fidusia, hak tanggungan, hipotek, atau hak agunan atas kebendaan lainnya. (2) Dalam hal tidak ada panitia kreditor, berlaku ketentuan sebagaimana dimaksud dalam Pasal 80. (3) Berita acara rapat harus memuat nama Kreditor yang hadir, suara yang dikeluarkan oleh masing-masing Kreditor, hasil pemungutan suara, dan segala sesuatu yang terjadi pada rapat tersebut. (4) Setiap orang yang berkepentingan dapat melihat dengan cuma-cuma berita acara rapat sebagaimana dimaksud pada ayat (3) yang disediakan paling lambat 7 (tujuh) hari setelah tanggal berakhirnya rapat di Kepaniteraan Pengadilan. Pasal 181 …"}, {"l": "UU 37/2004", "p": "181", "b": "Bagian Ketujuh", "t": "(1) Apabila dalam jangka waktu 8 (delapan) hari setelah putusan penolakan pengesahan perdamaian memperoleh kekuatan hukum tetap, Kurator atau Kreditor mengajukan usul kepada Hakim Pengawas untuk melanjutkan perusahaan Debitor Pailit, Hakim Pengawas wajib mengadakan suatu rapat paling lambat 14 (empat belas) hari setelah usul disampaikan kepada Hakim Pengawas. (2) Kurator wajib mengundang Kreditor paling lambat 10 (sepuluh) hari sebelum rapat diadakan, dengan surat yang menyebutkan usul yang diajukan tersebut dan dalam surat tersebut Kreditor wajib diingatkan ketentuan sebagaimana dimaksud dalam Pasal 119. (3) Kurator harus mengiklankan panggilan yang sama paling sedikit dalam 2 (dua) surat kabar sebagaimana dimaksud dalam Pasal 15 ayat (4). (4) Ketentuan sebagaimana dimaksud dalam Pasal 179 ayat (2), ayat (5), ayat (6) dan Pasal 180 berlaku juga."}, {"l": "UU 37/2004", "p": "182", "b": "Bagian Ketujuh", "t": "Selama 8 (delapan) hari setelah selesainya rapat, apabila dari dokumen ternyata Hakim Pengawas telah keliru menganggap usul tersebut ditolak atau diterima, Kurator atau Kreditor dapat meminta kepada Pengadilan untuk sekali lagi menyatakan bahwa usul tersebut telah diterima atau ditolak."}, {"l": "UU 37/2004", "p": "183", "b": "Bagian Ketujuh", "t": "(1) Atas permintaan Kreditor atau Kurator, Hakim Pengawas dapat memerintahkan supaya kelanjutan perusahaan dihentikan. (2) Dalam hal terdapat permintaan sebagaimana dimaksud dalam ayat (1), panitia Kreditor, apabila ada, wajib didengar dan Kurator wajib pula didengar apabila usul tersebut tidak diajukan oleh Kurator. (3) Hakim … (3) Hakim Pengawas juga dapat mendengar Kreditor dan Debitor Pailit."}, {"l": "UU 37/2004", "p": "184", "b": "Bagian Ketujuh", "t": "(1) Dengan tetap memperhatikan ketentuan Pasal 15 ayat (1), Kurator harus memulai pemberesan dan menjual semua harta pailit tanpa perlu memperoleh persetujuan atau bantuan Debitor apabila: a. usul untuk mengurus perusahaan Debitor tidak diajukan dalam jangka waktu sebagaimana diatur dalam Undang-Undang ini, atau usul tersebut telah diajukan tetapi ditolak; atau b. pengurusan terhadap perusahaan Debitor dihentikan. (2) Dalam hal perusahaan dilanjutkan dapat dilakukan penjualan benda yang termasuk harta pailit, yang tidak diperlukan untuk meneruskan perusahaan. (3) Debitor Pailit dapat diberikan sekadar perabot rumah dan perlengkapannya, alat-alat medis yang dipergunakan untuk kesehatan, atau perabot kantor yang ditentukan oleh Hakim Pengawas."}, {"l": "UU 37/2004", "p": "185", "b": "Bagian Ketujuh", "t": "(1) Semua benda harus dijual di muka umum sesuai dengan tata cara yang ditentukan dalam peraturan perundang-undangan. (2) Dalam hal penjualan di muka umum sebagaimana dimaksud pada ayat (1) tidak tercapai maka penjualan di bawah tangan dapat dilakukan dengan izin Hakim Pengawas. (3) Semua benda yang tidak segera atau sama sekali tidak dapat dibereskan maka Kurator yang memutuskan tindakan yang harus dilakukan terhadap benda tersebut dengan izin Hakim Pengawas. (4) Kurator berkewajiban membayar piutang Kreditor yang mempunyai hak untuk menahan suatu benda, sehingga benda itu masuk kembali dan menguntungkan harta pailit. Pasal 186 …"}, {"l": "UU 37/2004", "p": "186", "b": "Bagian Ketujuh", "t": "Untuk keperluan pemberesan harta pailit, Kurator dapat menggunakan jasa Debitor Pailit dengan pemberian upah yang ditentukan oleh Hakim Pengawas."}, {"l": "UU 37/2004", "p": "187", "b": "Bagian Ketujuh", "t": "(1) Setelah harta pailit berada dalam keadaan insolvensi maka Hakim Pengawas dapat mengadakan suatu rapat Kreditor pada hari, jam, dan tempat yang ditentukan untuk mendengar mereka seperlunya mengenai cara pemberesan harta pailit dan jika perlu mengadakan pencocokan piutang, yang dimasukkan setelah berakhirnya tenggang waktu sebagaimana dimaksud dalam Pasal 113 ayat (1), dan belum juga dicocokkan sebagaimana dimaksud dalam Pasal 133. (2) Terhadap piutang sebagaimana dimaksud pada ayat (1) Kurator wajib bertindak sebagaimana dimaksud dalam Pasal 116, Pasal 117, Pasal 118, Pasal 119, dan Pasal 120. (3) Kurator wajib mengumumkan panggilan yang sama dalam surat kabar sebagaimana dimaksud dalam Pasal 15 ayat (4). (4) Hakim Pengawas wajib menetapkan tenggang waktu paling singkat 14 (empat belas) hari antara hari pemanggilan dan hari rapat."}, {"l": "UU 37/2004", "p": "188", "b": "Bagian Ketujuh", "t": "Apabila Hakim Pengawas berpendapat terdapat cukup uang tunai, Kurator diperintahkan untuk melakukan pembagian kepada Kreditor yang piutangnya telah dicocokkan."}, {"l": "UU 37/2004", "p": "189", "b": "Bagian Ketujuh", "t": "(1) Kurator wajib menyusun suatu daftar pembagian untuk dimintakan persetujuan kepada Hakim Pengawas . (2) Daftar … (2) Daftar pembagian sebagaimana dimaksud pada ayat (1) memuat rincian penerimaan dan pengeluaran termasuk didalamnya upah Kurator, nama Kreditor, jumlah yang dicocokkan dari tiap-tiap piutang, dan bagian yang wajib diterimakan kepada Kreditor. (3) Kreditor konkuren harus diberikan bagian yang ditentukan oleh Hakim Pengawas. (4) Pembayaran kepada Kreditor: a. yang mempunyai hak yang diistimewakan, termasuk di dalamnya yang hak istimewanya dibantah; dan b. pemegang gadai, jaminan fidusia, hak tanggungan, hipotek, atau hak agunan atas kebendaan lainnya, sejauh mereka tidak dibayar menurut ketentuan sebagaimana dimaksud dalam Pasal 55, dapat dilakukan dari hasil penjualan benda terhadap mana mereka mempunyai hak istimewa atau yang diagunkan kepada mereka. (5) Dalam hal hasil penjualan benda sebagaimana dimaksud pada ayat (4) tidak mencukupi untuk membayar seluruh piutang Kreditor yang didahulukan maka untuk kekurangannya mereka berkedudukan sebagai kreditor konkuren."}, {"l": "UU 37/2004", "p": "190", "b": "Bagian Ketujuh", "t": "Kreditor yang piutangnya diterima dengan bersyarat maka besarnya jumlah bagian Kreditor tersebut dalam daftar pembagian dihitung berdasarkan prosentase dari seluruh jumlah piutang."}, {"l": "UU 37/2004", "p": "191", "b": "Bagian Ketujuh", "t": "Semua biaya kepailitan dibebankan kepada setiap benda yang merupakan bagian harta pailit, kecuali benda yang menurut ketentuan sebagaimana dimaksud dalam Pasal 55 telah dijual sendiri oleh Kreditor pemegang gadai, jaminan fidusia, hak tanggungan, hipotek atau hak agunan atas kebendaan lainnya. Pasal 192 …"}, {"l": "UU 37/2004", "p": "192", "b": "Bagian Ketujuh", "t": "(1) Daftar pembagian yang telah disetujui oleh Hakim Pengawas wajib disediakan di Kepaniteraan Pengadilan agar dapat dilihat oleh Kreditor selama tenggang waktu yang ditetapkan oleh Hakim Pengawas pada waktu daftar tersebut disetujui. (2) Penyediaan daftar pembagian dan tenggang waktu sebagaimana dimaksud pada ayat (1) diumumkan oleh Kurator dalam surat kabar sebagaimana dimaksud dalam Pasal 15 ayat (4). (3) Tenggang waktu sebagaimana dimaksud pada ayat (1) mulai berlaku pada hari dan tanggal penyediaan daftar pembagian tersebut diumumkan dalam surat kabar sebagaimana dimaksud pada ayat (2)."}, {"l": "UU 37/2004", "p": "193", "b": "Bagian Ketujuh", "t": "(1) Selama tenggang waktu sebagaimana dimaksud dalam Pasal 192 ayat (1) Kreditor dapat melawan daftar pembagian tersebut dengan mengajukan surat keberatan disertai alasan kepada Panitera Pengadilan, dengan menerima tanda bukti penerimaan. (2) Surat keberatan sebagaimana dimaksud pada ayat (1) dilampirkan pada daftar pembagian."}, {"l": "UU 37/2004", "p": "194", "b": "Bagian Ketujuh", "t": "(1) Dalam hal diajukan perlawanan maka segera setelah berakhirnya tenggang waktu sebagaimana dimaksud dalam Pasal 192, Hakim Pengawas menetapkan hari untuk memeriksa perlawanan tersebut di sidang Pengadilan terbuka untuk umum. (2) Surat penetapan hari sidang yang dibuat oleh Hakim Pengawas, disediakan di Kepaniteraan Pengadilan agar dapat dilihat oleh setiap orang dengan cuma-cuma. (3) Juru … (3) Juru sita harus memberitahukan secara tertulis mengenai penyediaan tersebut kepada pelawan dan Kurator. (4) Sidang wajib ditetapkan paling lama 7 (tujuh) hari setelah berakhirnya tenggang waktu yang ditetapkan menurut Pasal 192 ayat (3). (5) Dalam sidang terbuka untuk umum sebagaimana dimaksud pada ayat (4), Hakim Pengawas memberi laporan tertulis, sedangkan Kurator dan setiap Kreditor atau kuasanya dapat mendukung atau membantah daftar pembagian tersebut dengan mengemukakan alasannya. (6) Pada hari sidang pertama atau paling lama 7 (tujuh) hari kemudian, Pengadilan wajib memberikan putusan yang disertai dengan pertimbangan hukum yang cukup."}, {"l": "UU 37/2004", "p": "195", "b": "Bagian Ketujuh", "t": "(1) Kreditor yang piutangnya belum dicocokkan dan Kreditor yang piutangnya telah dicocokkan untuk suatu jumlah yang sangat rendah menurut pelaporannya sendiri, dapat mengajukan perlawanan dengan syarat paling lama 2 (dua) hari sebelum pemeriksaan perlawanan di sidang Pengadilan dengan ketentuan: a. piutang atau bagian piutang yang belum dicocokkan itu diajukan kepada Kurator; b. salinan surat piutang dan bukti penerimaan dari Kurator dilampirkan pada surat perlawanan; c. dalam perlawanan tersebut diajukan pula permohonan untuk mencocokkan piutang atau bagian piutang tersebut. (2) Pencocokan sebagaimana dimaksud pada ayat (1) dilakukan dalam sidang tersebut dengan cara yang ditetapkan sebagaimana dimaksud dalam Pasal 124 dan pasal-pasal selanjutnya, dilakukan sebelum pemeriksaan perlawanan dimulai. (3) Dalam … (3) Dalam hal perlawanan hanya bermaksud agar piutang pelawan dicocokkan, dan tidak ada perlawanan yang diajukan oleh orang lain, biaya perlawanan harus dibebankan kepada Kreditor pelawan tersebut."}, {"l": "UU 37/2004", "p": "196", "b": "Bagian Ketujuh", "t": "(1) Terhadap putusan Pengadilan sebagaimana dimaksud dalam Pasal 194 ayat (6), Kurator atau setiap Kreditor dapat mengajukan permohonan kasasi. (2) Kasasi atas putusan Pengadilan sebagaimana dimaksud pada ayat (1) diselenggarakan sesuai dengan ketentuan sebagaimana dimaksud dalam Pasal 11, Pasal 12, dan Pasal 13. (3) Untuk kepentingan pemeriksaan atas permohonan kasasi, Mahkamah Agung dapat memanggil Kurator atau Kreditor untuk didengar. (4) Karena lampaunya tenggang waktu sebagaimana dimaksud dalam Pasal 192, tanpa ada yang mengajukan perlawanan atau perlawanan telah diputus oleh Pengadilan maka daftar pembagian menjadi mengikat."}, {"l": "UU 37/2004", "p": "197", "b": "Bagian Ketujuh", "t": "Hakim Pengawas wajib memerintahkan pencoretan pendaftaran hipotek, hak tanggungan, atau jaminan fidusia yang membebani benda yang termasuk harta pailit, segera setelah daftar pembagian yang memuat pertanggungjawaban hasil penjualan benda yang dibebani, menjadi mengikat."}, {"l": "UU 37/2004", "p": "198", "b": "Bagian Ketujuh", "t": "(1) Pembagian yang diperuntukkan bagi Kreditor yang piutangnya diakui sementara, tidak diberikan selama belum ada putusan mengenai piutangnya yang telah memperoleh kekuatan hukum tetap. (2) Dalam … (2) Dalam hal Kreditor terbukti tidak mempunyai piutang atau piutangnya kurang dari uang yang diperuntukkan baginya, uang yang semula diperuntukkan baginya, baik seluruh atau sebagian, menjadi keuntungan Kreditor lainnya. (3) Jika bagian yang diperuntukkan bagi Kreditor yang hak untuk didahulukan dibantah, melebihi prosentase bagian yang wajib dibayarkan kepada kreditor konkuren, bagian tersebut untuk sementara wajib dicadangkan sampai ada putusan mengenai hak untuk didahulukan."}, {"l": "UU 37/2004", "p": "199", "b": "Bagian Ketujuh", "t": "Dalam hal suatu benda yang di atasnya terletak hak istimewa tertentu, gadai, jaminan fidusia, hak tanggungan, hipotek, atau hak agunan atas kebendaan lainnya dijual, setelah kepada Kreditor yang didahulukan tersebut diberikan pembagian menurut Pasal 189 pada waktu diadakan pembagian lagi, hasil penjualan benda tersebut akan dibayarkan kepada mereka sebesar paling tinggi nilai hak yang didahulukan setelah dikurangi jumlah yang telah diterima sebelumnya."}, {"l": "UU 37/2004", "p": "200", "b": "Bagian Ketujuh", "t": "(1) Kreditor yang karena kelalaiannya baru mencocokkan setelah dilakukan pembagian, dapat diberikan pembayaran suatu jumlah yang diambil lebih dahulu dari uang yang masih ada, seimbang dengan apa yang telah diterima oleh Kreditor lain yang diakui. (2) Dalam hal Kreditor mempunyai hak untuk didahulukan, mereka kehilangan hak tersebut terhadap hasil penjualan benda yang bersangkutan, apabila hasil tersebut dalam suatu daftar pembagian yang lebih dahulu telah diperuntukkan bagi Kreditor lainnya secara mendahulukan. Pasal 201 …"}, {"l": "UU 37/2004", "p": "201", "b": "Bagian Ketujuh", "t": "Setelah berakhirnya tenggang waktu untuk melihat daftar pembagian sebagaimana dimaksud dalam Pasal 192, atau dalam hal telah diajukan perlawanan setelah putusan perkara perlawanan tersebut diucapkan, Kurator wajib segera membayar pembagian yang sudah ditetapkan."}, {"l": "UU 37/2004", "p": "202", "b": "Bagian Ketujuh", "t": "(1) Segera setelah kepada Kreditor yang telah dicocokkan, dibayarkan jumlah penuh piutang mereka, atau segera setelah daftar pembagian penutup menjadi mengikat maka berakhirlah kepailitan, dengan tidak mengurangi berlakunya ketentuan sebagaimana dimaksud dalam Pasal 203. (2) Kurator melakukan pengumuman mengenai berakhirnya kepailitan dalam Berita Negara Republik Indonesia dan surat kabar sebagaimana dimaksud dalam Pasal 15 ayat (4). (3) Kurator wajib memberikan pertanggungjawaban mengenai pengurusan dan pemberesan yang telah dilakukannya kepada Hakim Pengawas paling lama 30 (tiga puluh) hari setelah berakhirnya kepailitan. (4) Semua buku dan dokumen mengenai harta pailit yang ada pada Kurator wajib diserahkan kepada Debitor dengan tanda bukti penerimaan yang sah."}, {"l": "UU 37/2004", "p": "203", "b": "Bagian Ketujuh", "t": "Dalam hal sesudah diadakan pembagian penutup, ada pembagian yang tadinya dicadangkan sebagaimana dimaksud dalam Pasal 198 ayat (3), jatuh kembali dalam harta pailit, atau apabila ternyata masih terdapat bagian harta pailit, yang sewaktu diadakan pemberesan tidak diketahui maka atas perintah Pengadilan, Kurator membereskan dan membaginya berdasarkan daftar pembagian yang dahulu."}, {"l": "UU 37/2004", "p": "204", "b": "Bagian Kedelapan", "t": "Setelah daftar pembagian penutup menjadi mengikat maka Kreditor memperoleh kembali hak eksekusi terhadap harta Debitor mengenai piutang mereka yang belum dibayar."}, {"l": "UU 37/2004", "p": "205", "b": "Bagian Kedelapan", "t": "(1) Pengakuan suatu piutang sebagaimana dimaksud dalam Pasal 126 ayat (5) mempunyai kekuatan hukum tetap terhadap Debitor seperti suatu putusan pengadilan yang telah memperoleh kekuatan hukum tetap. (2) Ikhtisar berita acara rapat pencocokan piutang yang dibuat dalam bentuk putusan yang dapat dilaksanakan, merupakan alas hak yang dapat dilaksanakan terhadap Debitor mengenai piutang yang diakui."}, {"l": "UU 37/2004", "p": "206", "b": "Bagian Kedelapan", "t": "Ketentuan sebagaimana dimaksud dalam Pasal 205 tidak berlaku, sejauh piutang yang bersangkutan dibantah oleh Debitor Pailit sebagaimana dimaksud dalam Pasal 131."}, {"l": "UU 37/2004", "p": "207", "b": "Bagian Kesembilan", "t": "Harta kekayaan orang yang meninggal harus dinyatakan dalam keadaan pailit, apabila dua atau lebih Kreditor mengajukan permohonan untuk itu dan secara singkat dapat membuktikan bahwa: a.utang … a. utang orang yang meninggal, semasa hidupnya tidak dibayar lunas; atau b. pada saat meninggalnya orang tersebut, harta peninggalannya tidak cukup untuk membayar utangnya."}, {"l": "UU 37/2004", "p": "208", "b": "Bagian Kesembilan", "t": "(1) Permohonan sebagaimana dimaksud dalam Pasal 207 harus diajukan kepada Pengadilan yang daerah hukumnya meliputi tempat tinggal terakhir Debitor yang meninggal. (2) Ahli waris harus dipanggil untuk didengar mengenai permohonan tersebut dengan surat juru sita. (3) Surat panggilan sebagaimana dimaksud pada ayat (2), harus disampaikan di tempat tinggal terakhir Debitor yang meninggal, tanpa keharusan menyebutkan nama masing-masing ahli waris, kecuali nama mereka itu dikenal."}, {"l": "UU 37/2004", "p": "209", "b": "Bagian Kesembilan", "t": "Putusan pernyataan pailit berakibat demi hukum dipisahkannya harta kekayaan orang yang meninggal dari harta kekayaan ahli warisnya."}, {"l": "UU 37/2004", "p": "210", "b": "Bagian Kesembilan", "t": "Permohonan pernyataan pailit harus diajukan kepada Pengadilan paling lambat 90 (sembilan puluh) hari setelah Debitor meninggal."}, {"l": "UU 37/2004", "p": "211", "b": "Bagian Kesembilan", "t": "Ketentuan mengenai perdamaian sebagaimana dimaksud dalam Pasal 144 sampai dengan Pasal 177, tidak berlaku terhadap kepailitan harta peninggalan, kecuali apabila warisannya telah diterima oleh ahli waris secara murni."}, {"l": "UU 37/2004", "p": "212", "b": "Bagian Kesepuluh", "t": "Kreditor yang setelah putusan pernyataan pailit diucapkan, mengambil pelunasan seluruh atau sebagian piutangnya dari benda yang termasuk harta pailit yang terletak di luar wilayah Negara Republik Indonesia, yang tidak diperikatkan kepadanya dengan hak untuk didahulukan wajib mengganti kepada harta pailit segala apa yang diperolehnya."}, {"l": "UU 37/2004", "p": "213", "b": "Bagian Kesepuluh", "t": "(1) Kreditor yang memindahkan seluruh atau sebagian piutangnya terhadap Debitor Pailit kepada pihak ketiga, dengan maksud supaya pihak ketiga mengambil pelunasan secara didahulukan daripada orang lain atas seluruh atau sebagian piutangnya dari benda yang termasuk harta pailit yang terletak di luar wilayah Negara Republik Indonesia, wajib mengganti kepada harta pailit apa yang diperolehnya. (2) Kecuali apabila dibuktikan sebaliknya maka setiap pemindahan piutang wajib dianggap telah dilakukan sesuai dengan ketentuan sebagaimana dimaksud pada ayat (1), apabila pemindahan tersebut dilakukan oleh Kreditor dan Kreditor tersebut mengetahui bahwa pernyataan pailit sudah atau akan diajukan."}, {"l": "UU 37/2004", "p": "214", "b": "Bagian Kesepuluh", "t": "(1) Setiap orang yang memindahkan seluruh atau sebagian piutang atau utangnya kepada pihak ketiga, yang karena itu mendapat kesempatan untuk melakukan perjumpaan utang di luar wilayah Negara Republik Indonesia yang tidak diperbolehkan oleh Undang-Undang ini, wajib mengganti kepada harta pailit. (2) Ketentuan Pasal 213 ayat (2) berlaku juga terhadap hal sebagaimana dimaksud pada ayat (1)."}, {"l": "UU 37/2004", "p": "215", "b": "Bagian Kesebelas", "t": "Setelah berakhirnya kepailitan sebagaimana dimaksud dalam Pasal 166, Pasal 202, dan Pasal 207 maka Debitor atau ahli warisnya berhak mengajukan permohonan rehabilitasi kepada Pengadilan yang telah mengucapkan putusan pernyataan pailit."}, {"l": "UU 37/2004", "p": "216", "b": "Bagian Kesebelas", "t": "Permohonan rehabilitasi baik Debitor maupun ahli warisnya tidak akan dikabulkan, kecuali apabila pada surat permohonan tersebut dilampirkan bukti yang menyatakan bahwa semua Kreditor yang diakui sudah memperoleh pembayaran secara memuaskan."}, {"l": "UU 37/2004", "p": "217", "b": "Bagian Kesebelas", "t": "Permohonan rehabilitasi sebagaimana dimaksud dalam Pasal 216 harus diumumkan paling sedikit dalam 2 (dua) surat kabar harian yang ditunjuk oleh Pengadilan."}, {"l": "UU 37/2004", "p": "218", "b": "Bagian Kesebelas", "t": "(1) Dalam jangka waktu 60 (enam puluh) hari setelah permohonan rehabilitasi diumumkan paling sedikit dalam 2 (dua) surat kabar harian, setiap Kreditor yang diakui dapat mengajukan keberatan terhadap permohonan tersebut, dengan memasukkan surat keberatan disertai alasan di Kepaniteraan Pengadilan dan Panitera harus memberi tanda penerimaan. (2) Keberatan sebagaimana dimaksud pada ayat (1) hanya dapat diajukan apabila persyaratan sebagaimana dimaksud dalam Pasal 216 tidak dipenuhi. Pasal 219 …"}, {"l": "UU 37/2004", "p": "219", "b": "Bagian Kesebelas", "t": "Setelah berakhirnya jangka waktu 60 (enam puluh) hari sebagaimana dimaksud dalam Pasal 218, terlepas diajukan atau tidak diajukannya keberatan, Pengadilan harus mengabulkan atau menolak permohonan tersebut."}, {"l": "UU 37/2004", "p": "220", "b": "Bagian Kesebelas", "t": "Terhadap putusan Pengadilan sebagaimana dimaksud dalam Pasal 219 tidak terbuka upaya hukum apapun."}, {"l": "UU 37/2004", "p": "221", "b": "Bagian Kesebelas", "t": "Putusan yang mengabulkan rehabilitasi wajib diucapkan dalam sidang terbuka untuk umum dan harus dicatat dalam daftar umum sebagaimana dimaksud dalam Pasal 20."}, {"l": "UU 37/2004", "p": "222", "b": "Bagian Kesatu", "t": "(1) Penundaan Kewajiban Pembayaran Utang diajukan oleh Debitor yang mempunyai lebih dari 1 (satu) Kreditor atau oleh Kreditor. (2) Debitor yang tidak dapat atau memperkirakan tidak akan dapat melanjutkan membayar utang-utangnya yang sudah jatuh waktu dan dapat ditagih, dapat memohon penundaan kewajiban pembayaran utang, dengan maksud untuk mengajukan rencana perdamaian yang meliputi tawaran pembayaran sebagian atau seluruh utang kepada Kreditor. (3) Kreditor … (3) Kreditor yang memperkirakan bahwa Debitor tidak dapat melanjutkan membayar utangnya yang sudah jatuh waktu dan dapat ditagih, dapat memohon agar kepada Debitor diberi penundaan kewajiban pembayaran utang, untuk memungkinkan Debitor mengajukan rencana perdamaian yang meliputi tawaran pembayaran sebagian atau seluruh utang kepada Kreditornya."}, {"l": "UU 37/2004", "p": "223", "b": "Bagian Kesatu", "t": "Dalam hal Debitor adalah Bank, Perusahaan Efek, Bursa Efek, Lembaga Kliring dan Penjaminan, Lembaga Penyimpanan dan Penyelesaian, Perusahaan Asuransi, Perusahaan Reasuransi, Dana Pensiun, dan Badan Usaha Milik Negara yang bergerak di bidang kepentingan publik maka yang dapat mengajukan permohonan penundaan kewajiban pembayaran utang adalah lembaga sebagaimana dimaksud dalam Pasal 2 ayat (3), ayat (4), dan ayat (5)."}, {"l": "UU 37/2004", "p": "224", "b": "Bagian Kesatu", "t": "(1) Permohonan penundaan kewajiban pembayaran utang sebagaimana dimaksud dalam Pasal 222 harus diajukan kepada Pengadilan sebagaimana dimaksud dalam Pasal 3, dengan ditandatangani oleh pemohon dan oleh advokatnya. (2) Dalam hal pemohon adalah Debitor, permohonan penundaan kewajiban pembayaran utang harus disertai daftar yang memuat sifat, jumlah piutang, dan utang Debitor beserta surat bukti secukupnya. (3) Dalam hal pemohon adalah Kreditor, Pengadilan wajib memanggil Debitor melalui juru sita dengan surat kilat tercatat paling lambat 7 (tujuh) hari sebelum sidang. (4) Pada sidang sebagaimana dimaksud pada ayat (3), Debitor mengajukan daftar yang memuat sifat, jumlah piutang, dan utang Debitor beserta surat bukti secukupnya dan, bila ada, rencana perdamaian. (5) Pada … (5) Pada surat permohonan sebagaimana dimaksud pada ayat (2) dapat dilampirkan rencana perdamaian sebagaimana dimaksud dalam Pasal 222. (6) Ketentuan sebagaimana dimaksud dalam Pasal 6 ayat (1), ayat (2), ayat (3), ayat (4), dan ayat (5) berlaku mutatis mutandis sebagai tata cara pengajuan permohonan penundaan kewajiban pembayaran utang sebagaimana dimaksud pada ayat (1)."}, {"l": "UU 37/2004", "p": "225", "b": "Bagian Kesatu", "t": "(1) Surat permohonan sebagaimana dimaksud dalam Pasal 224 ayat (1) berikut lampirannya, bila ada, harus disediakan di Kepaniteraan Pengadilan, agar dapat dilihat oleh setiap orang dengan cuma-cuma. (2) Dalam hal permohonan diajukan oleh Debitor, Pengadilan dalam waktu paling lambat 3 (tiga) hari sejak tanggal didaftarkannya surat permohonan sebagaimana dimaksud dalam Pasal 224 ayat (1) harus mengabulkan penundaan kewajiban pembayaran utang sementara dan harus menunjuk seorang Hakim Pengawas dari hakim pengadilan serta mengangkat 1 (satu) atau lebih pengurus yang bersama dengan Debitor mengurus harta Debitor. (3) Dalam hal permohonan diajukan oleh Kreditor, Pengadilan dalam waktu paling lambat 20 (dua puluh) hari sejak tanggal didaftarkannya surat permohonan, harus mengabulkan permohonan penundaan kewajiban pembayaran utang sementara dan harus menunjuk Hakim Pengawas dari hakim pengadilan serta mengangkat 1 (satu) atau lebih pengurus yang bersama dengan Debitor mengurus harta Debitor. (4) Segera … (4) Segera setelah putusan penundaan kewajiban pembayaran utang sementara diucapkan, Pengadilan melalui pengurus wajib memanggil Debitor dan Kreditor yang dikenal dengan surat tercatat …"}, {"l": "UU 37/2004", "p": "226", "b": "Bagian Kesatu", "t": "(1) Pengurus wajib segera mengumumkan putusan penundaan kewajiban pembayaran utang sementara dalam Berita Negara Republik Indonesia dan paling sedikit dalam 2 (dua) surat kabar harian yang ditunjuk oleh Hakim Pengawas dan pengumuman tersebut juga harus memuat undangan untuk hadir pada persidangan yang merupakan rapat permusyawaratan hakim berikut tanggal, tempat, dan waktu sidang tersebut, nama Hakim Pengawas dan nama serta alamat pengurus. (2) Apabila pada waktu penundaan kewajiban pembayaran utang sementara diucapkan sudah diajukan rencana perdamaian oleh Debitor, hal ini harus disebutkan dalam pengumuman tersebut, dan pengumuman tersebut harus dilakukan dalam jangka waktu paling lama 21 (dua puluh satu) hari sebelum tanggal sidang yang direncanakan."}, {"l": "UU 37/2004", "p": "227", "b": "Bagian Kesatu", "t": "Penundaan kewajiban pembayaran utang sementara berlaku sejak tanggal putusan penundaan kewajiban pembayaran utang tersebut diucapkan dan berlangsung sampai dengan tanggal sidang sebagaimana dimaksud dalam Pasal 226 ayat (1) diselenggarakan. Pasal 228 …"}, {"l": "UU 37/2004", "p": "228", "b": "Bagian Kesatu", "t": "(1) Pada hari sidang sebagaimana dimaksud dalam Pasal 226 ayat (1), Pengadilan harus mendengar Debitor, Hakim Pengawas, pengurus dan Kreditor yang hadir, wakilnya, atau kuasanya yang ditunjuk berdasarkan surat kuasa. (2) Dalam sidang sebagaimana dimaksud pada ayat (1), setiap Kreditor berhak untuk hadir walaupun yang bersangkutan tidak menerima panggilan untuk itu. (3) Apabila rencana perdamaian dilampirkan pada permohonan penundaan kewajiban pembayaran utang sementara sebagaimana dimaksud dalam Pasal 224 ayat (2) atau telah disampaikan oleh Debitor sebelum sidang maka pemungutan suara tentang rencana perdamaian dapat dilakukan, jika ketentuan sebagaimana dimaksud dalam Pasal 267 telah dipenuhi. (4) Dalam hal ketentuan sebagaimana dimaksud pada ayat (3) tidak dipenuhi, atau jika Kreditor belum dapat memberikan suara mereka mengenai rencana perdamaian, atas permintaan Debitor, Kreditor harus menentukan pemberian atau penolakan penundaan kewajiban pembayaran utang tetap dengan maksud untuk memungkinkan Debitor, pengurus, dan Kreditor untuk mempertimbangkan dan menyetujui rencana perdamaian pada rapat atau sidang yang diadakan selanjutnya. (5) Dalam hal penundaan kewajiban pembayaran …"}, {"l": "UU 37/2004", "p": "229", "b": "Bagian Kesatu", "t": "(1) Pemberian penundaan kewajiban pembayaran utang tetap berikut perpanjangannya ditetapkan oleh Pengadilan berdasarkan: a. persetujuan lebih dari 1/2 (satu perdua) jumlah kreditor konkuren yang haknya diakui atau sementara diakui yang hadir dan mewakili paling sedikit 2/3 (dua pertiga) bagian dari seluruh tagihan yang diakui atau yang sementara diakui dari kreditor konkuren atau kuasanya yang hadir dalam sidang tersebut; dan b. persetujuan lebih dari 1/2 (satu perdua) jumlah Kreditor yang piutangnya dijamin dengan gadai, jaminan fidusia, hak tanggungan, hipotik, atau hak agunan atas kebendaan lainnya yang hadir dan mewakili paling sedikit 2/3 (dua pertiga) bagian dari seluruh tagihan Kreditor atau kuasanya yang hadir dalam sidang tersebut. (2) Perselisihan yang timbul antara pengurus dan kreditor konkuren tentang hak suara Kreditor sebagaimana dimaksud pada ayat (1) huruf a diputus oleh Hakim Pengawas. (3) Apabila permohonan pernyataan pailit dan permohonan penundaan kewajiban pembayaran utang diperiksa pada saat yang bersamaan, permohonan penundaan kewajiban pembayaran utang harus diputuskan terlebih dahulu. (4) Permohonan penundaan kewajiban pembayaran utang yang diajukan …"}, {"l": "UU 37/2004", "p": "230", "b": "Bagian Kesatu", "t": "(1) Apabila jangka waktu penundaan kewajiban pembayaran utang sementara berakhir, karena Kreditor tidak menyetujui pemberian penundaan kewajiban pembayaran utang tetap atau perpanjangannya sudah diberikan, tetapi sampai dengan batas waktu sebagaimana dimaksud dalam Pasal 228 ayat (6) belum tercapai persetujuan terhadap rencana perdamaian, pengurus pada hari berakhirnya waktu tersebut wajib memberitahukan hal itu melalui Hakim Pengawas kepada Pengadilan yang harus menyatakan Debitor Pailit paling lambat pada hari berikutnya. (2) Pengurus wajib mengumumkan hal sebagaimana dimaksud pada ayat (1) dalam surat kabar harian di mana permohonan penundaan kewajiban pembayaran utang sementara diumumkan berdasarkan Pasal 226."}, {"l": "UU 37/2004", "p": "231", "b": "Bagian Kesatu", "t": "(1) Pengadilan harus mengangkat panitia kreditor apabila: a. permohonan penundaan kewajiban pembayaran utang meliputi utang yang bersifat rumit atau banyak Kreditor; atau b. pengangkatan tersebut dikehendaki oleh Kreditor yang mewakili paling sedikit 1/2 (satu perdua) bagian dari seluruh tagihan yang diakui. (2) Pengurus dalam menjalankan tugasnya wajib meminta dan mempertimbangkan saran panitia kreditor."}, {"l": "UU 37/2004", "p": "232", "b": "Bagian Kesatu", "t": "(1) Panitera Pengadilan wajib mengadakan daftar umum perkara penundaan kewajiban pembayaran utang dengan mencantumkan untuk setiap penundaan kewajiban pembayaran utang: a. tanggal putusan penundaan kewajiban pembayaran utang sementara dan tanggal putusan penundaan kewajiban pembayaran utang tetap berikut perpanjangannya; b. kutipan … b. kutipan putusan Pengadilan yang menetapkan penundaan kewajiban pembayaran utang sementara maupun yang tetap dan perpanjangannya; c. nama Hakim Pengawas dan Pengurus yang diangkat; d. ringkasan isi perdamaian dan pengesahan perdamaian tersebut oleh Pengadilan; dan e. pengakhiran perdamaian. (2) Ketentuan lebih lanjut mengenai bentuk dan isi daftar umum perkara penundaan kewajiban pembayaran utang tersebut ditetapkan oleh Mahkamah Agung. (3) Panitera Pengadilan wajib menyediakan daftar umum perkara penundaan kewajiban pembayaran utang sebagaimana dimaksud pada ayat (1) untuk dapat dilihat oleh setiap orang dengan cuma-cuma."}, {"l": "UU 37/2004", "p": "233", "b": "Bagian Kesatu", "t": "(1) Apabila diminta oleh pengurus, Hakim Pengawas dapat mendengar saksi atau memerintahkan pemeriksaan oleh ahli untuk menjelaskan keadaan yang menyangkut penundaan kewajiban pembayaran utang, dan saksi tersebut dipanggil sesuai dengan ketentuan dalam Hukum Acara Perdata. (2) Dalam hal saksi tidak hadir atau menolak untuk mengangkat sumpah atau memberi keterangan, berlaku ketentuan Hukum Acara Perdata. (3) Istri atau suami, bekas istri atau suami, dan keluarga sedarah menurut keturunan lurus ke atas dan ke bawah dari Debitor dapat menggunakan hak mereka untuk dibebaskan dari kewajiban memberi kesaksian. Pasal 234 …"}, {"l": "UU 37/2004", "p": "234", "b": "Bagian Kesatu", "t": "(1) Pengurus yang diangkat sebagaimana dimaksud dalam Pasal 225 ayat (2) harus independen dan tidak memiliki benturan kepentingan dengan Debitor atau Kreditor. (2) Pengurus sebagaimana dimaksud pada ayat (1) yang terbukti tidak independen dikenakan sanksi pidana dan/atau perdata sesuai dengan peraturan perundang-undangan. (3) Yang dapat menjadi pengurus sebagaimana dimaksud pada ayat (1), adalah: a. orang perseorangan yang berdomisili di wilayah Negara Republik Indonesia, yang memiliki keahlian khusus yang dibutuhkan dalam rangka mengurus harta Debitor; dan b. terdaftar pada kementerian yang lingkup tugas dan tanggung jawabnya di bidang hukum dan peraturan perundang-undangan. (4) Pengurus bertanggung jawab terhadap kesalahan atau kelalaiannya dalam melaksanakan tugas pengurusan yang menyebabkan kerugian terhadap harta Debitor. (5) Besarnya imbalan jasa pengurus ditetapkan oleh Pengadilan berdasarkan pedoman yang ditetapkan oleh Menteri yang lingkup tugas dan tanggung jawabnya di bidang hukum dan peraturan perundang-undangan setelah penundaan kewajiban pembayaran utang berakhir dan harus dibayar lebih dahulu dari harta Debitor."}, {"l": "UU 37/2004", "p": "235", "b": "Bagian Kesatu", "t": "(1) Terhadap putusan penundaan kewajiban pembayaran utang tidak dapat diajukan upaya hukum apapun. (2) Putusan sebagaimana dimaksud pada ayat (1) harus diumumkan dengan cara sebagaimana dimaksud dalam Pasal 226. Pasal 236 …"}, {"l": "UU 37/2004", "p": "236", "b": "Bagian Kesatu", "t": "(1) Apabila diangkat lebih dari satu pengurus, untuk melakukan tindakan yang sah dan mengikat, pengurus memerlukan persetujuan lebih dari 1/2 (satu perdua) jumlah pengurus. (2) Apabila suara setuju dan tidak setuju sama banyaknya, tindakan sebagaimana dimaksud pada ayat (1) harus memperoleh persetujuan Hakim Pengawas. (3) Pengadilan setiap waktu dapat mengabulkan usul penggantian pengurus, setelah memanggil dan mendengar pengurus, dan mengangkat pengurus lain dan atau mengangkat pengurus tambahan berdasarkan : a. usul Hakim Pengawas; b. permohonan Kreditor dan permohonan tersebut hanya dapat diajukan apabila didasarkan atas persetujuan lebih dari 1/2 (satu perdua) jumlah Kreditor yang hadir dalam rapat Kreditor; c. permohonan pengurus sendiri; atau d. permohonan pengurus lainnya, jika ada."}, {"l": "UU 37/2004", "p": "237", "b": "Bagian Kesatu", "t": "(1) Dalam putusan yang mengabulkan penundaan kewajiban pembayaran utang sementara Pengadilan dapat memasukkan ketentuan yang dianggap perlu untuk kepentingan Kreditor. (2) Hakim Pengawas dapat juga melakukan hal sebagaimana dimaksud pada ayat (1) setiap waktu selama berlangsungnya penundaan kewajiban pembayaran utang tetap, berdasarkan: a. prakarsa Hakim Pengawas; b. permintaan pengurus; atau c. permintaan satu atau lebih Kreditor. Pasal 238 …"}, {"l": "UU 37/2004", "p": "238", "b": "Bagian Kesatu", "t": "(1) Jika penundaan kewajiban pembayaran utang telah dikabulkan, Hakim Pengawas dapat mengangkat satu atau lebih ahli untuk melakukan pemeriksaan dan menyusun laporan tentang keadaan harta Debitor dalam jangka waktu tertentu berikut perpanjangannya yang ditetapkan oleh Hakim Pengawas. (2) Laporan ahli sebagaimana dimaksud pada ayat (1) harus memuat pendapat yang disertai dengan alasan lengkap tentang keadaan harta Debitor dan dokumen yang telah diserahkan oleh Debitor serta tingkat kesanggupan atau kemampuan Debitor untuk memenuhi kewajibannya kepada Kreditor, dan laporan tersebut harus sedapat mungkin menunjukkan tindakan yang harus diambil untuk dapat memenuhi tuntutan Kreditor. (3) Laporan ahli sebagaimana dimaksud pada ayat (2), harus disediakan oleh ahli tersebut di Kepaniteraan Pengadilan agar dapat dilihat oleh setiap orang dengan cuma-cuma dan penyediaan laporan tersebut tanpa dipungut biaya. (4) Ketentuan sebagaimana dimaksud dalam Pasal 236 ayat (3) berlaku mutatis mutandis bagi para ahli."}, {"l": "UU 37/2004", "p": "239", "b": "Bagian Kesatu", "t": "(1) Setiap 3 (tiga) bulan sejak putusan penundaan kewajiban pembayaran utang diucapkan pengurus wajib melaporkan keadaan harta Debitor, dan laporan tersebut harus disediakan pula di Kepaniteraan Pengadilan sebagaimana dimaksud dalam Pasal 238 ayat (3). (2) Jangka waktu pelaporan sebagaimana dimaksud pada ayat (1) dapat diperpanjang oleh Hakim Pengawas. Pasal 240 …"}, {"l": "UU 37/2004", "p": "240", "b": "Bagian Kesatu", "t": "(1) Selama penundaan kewajiban pembayaran utang, Debitor tanpa persetujuan pengurus tidak dapat melakukan tindakan kepengurusan atau kepemilikan atas seluruh atau sebagian hartanya. (2) Jika Debitor melanggar ketentuan sebagaimana dimaksud pada ayat (1), pengurus berhak untuk melakukan segala sesuatu yang diperlukan untuk memastikan bahwa harta Debitor tidak dirugikan karena tindakan Debitor tersebut. (3) Kewajiban Debitor yang dilakukan tanpa mendapatkan persetujuan dari pengurus yang timbul setelah dimulainya penundaan kewajiban pembayaran utang, hanya dapat dibebankan kepada harta Debitor sejauh hal itu menguntungkan harta Debitor. (4) Atas dasar persetujuan yang diberikan oleh pengurus, Debitor dapat melakukan pinjaman dari pihak ketiga hanya dalam rangka meningkatkan nilai harta Debitor. (5) Apabila dalam melakukan pinjaman sebagaimana dimaksud pada ayat (4) perlu diberikan agunan, Debitor dapat membebani hartanya dengan gadai, jaminan fidusia, hak tanggungan, hipotek, atau hak agunan atas kebendaan lainnya, sejauh pinjaman tersebut telah memperoleh persetujuan Hakim Pengawas. (6) Pembebanan harta Debitor dengan gadai, jaminan fidusia, hak tanggungan, hipotek, atau hak agunan …"}, {"l": "UU 37/2004", "p": "241", "b": "Bagian Kesatu", "t": "Apabila Debitor telah menikah dalam persatuan harta, harta Debitor mencakup semua aktiva dan pasiva persatuan. Pasal 242 …"}, {"l": "UU 37/2004", "p": "242", "b": "Bagian Kesatu", "t": "(1) Selama berlangsungnya penundaan kewajiban pembayaran utang, Debitor tidak dapat dipaksa membayar utang sebagaimana dimaksud dalam Pasal 245 dan semua tindakan eksekusi yang telah dimulai untuk memperoleh pelunasan utang, harus ditangguhkan. (2) Kecuali telah ditetapkan tanggal yang lebih awal oleh Pengadilan berdasarkan permintaan pengurus, semua sita yang telah diletakkan gugur dan dalam hal Debitor disandera, Debitor harus dilepaskan segera setelah diucapkan putusan penundaan kewajiban pembayaran utang tetap atau setelah putusan pengesahan perdamaian memperoleh kekuatan hukum tetap, dan atas permintaan pengurus atau Hakim Pengawas, jika masih diperlukan, Pengadilan wajib mengangkat sita yang telah diletakkan atas benda yang termasuk harta Debitor. (3) Ketentuan sebagaimana dimaksud pada ayat (1) dan ayat (2) berlaku pula terhadap eksekusi dan sita yang telah dimulai atas benda yang tidak dibebani, sekalipun eksekusi dan sita tersebut berkenaan dengan tagihan Kreditor yang dijamin dengan gadai, jaminan fidusia, hak tanggungan, hipotek, hak agunan atas kebendaan lainnya, atau dengan hak yang harus diistimewakan berkaitan dengan kekayaan tertentu berdasarkan undang- undang."}, {"l": "UU 37/2004", "p": "243", "b": "Bagian Kesatu", "t": "(1) Penundaan kewajiban pembayaran utang tidak menghentikan berjalannya perkara yang sudah dimulai oleh Pengadilan atau menghalangi diajukannya perkara baru. (2) Dalam hal perkara sebagaimana dimaksud pada ayat (1) mengenai gugatan pembayaran suatu piutang yang sudah diakui Debitor, sedangkan penggugat tidak mempunyai kepentingan untuk memperoleh … memperoleh suatu putusan untuk melaksanakan hak terhadap pihak ketiga, setelah dicatatnya pengakuan tersebut, hakim dapat menangguhkan putusan sampai berakhirnya penundaan kewajiban pembayaran utang. (3) Debitor tidak dapat menjadi penggugat atau tergugat dalam perkara mengenai hak atau kewajiban yang menyangkut harta kekayaannya tanpa persetujuan pengurus."}, {"l": "UU 37/2004", "p": "244", "b": "Bagian Kesatu", "t": "Dengan tetap memperhatikan ketentuan Pasal 246, penundaan kewajiban pembayaran utang tidak berlaku terhadap: a. tagihan yang dijamin dengan gadai, jaminan fidusia, hak tanggungan, hipotek, atau hak agunan atas kebendaan lainnya; b. tagihan biaya pemeliharaan, pengawasan, atau pendidikan yang sudah harus dibayar dan Hakim Pengawas harus menentukan jumlah tagihan yang sudah ada dan belum dibayar sebelum penundaan kewajiban pembayaran utang yang bukan merupakan tagihan dengan hak untuk diistimewakan; dan c. tagihan yang diistimewakan terhadap benda tertentu milik Debitor maupun terhadap seluruh harta Debitor yang tidak tercakup pada ayat (1) huruf b."}, {"l": "UU 37/2004", "p": "245", "b": "Bagian Kesatu", "t": "Pembayaran semua utang, selain yang sebagaimana dimaksud dalam Pasal 244 yang sudah ada sebelum diberikannya penundaan kewajiban pembayaran utang selama berlangsungnya penundaan kewajiban pembayaran utang, tidak boleh dilakukan, kecuali pembayaran utang tersebut dilakukan kepada semua Kreditor, menurut perimbangan piutang masing-masing, tanpa mengurangi berlakunya juga ketentuan sebagaimana dimaksud dalam Pasal 185 ayat (3). Pasal 246 …"}, {"l": "UU 37/2004", "p": "246", "b": "Bagian Kesatu", "t": "Ketentuan sebagaimana dimaksud dalam Pasal 56, Pasal 57, dan Pasal 58 berlaku mutatis mutandis terhadap pelaksanaan hak Kreditor sebagaimana dimaksud dalam Pasal 55 ayat (1) dan Kreditor yang diistimewakan, dengan ketentuan bahwa penangguhan berlaku selama berlangsungnya penundaan kewajiban pembayaran utang."}, {"l": "UU 37/2004", "p": "247", "b": "Bagian Kesatu", "t": "(1) Orang yang mempunyai utang kepada Debitor atau piutang terhadap Debitor tersebut, dapat memperjumpakan utang piutang dimaksud, dengan syarat utang piutang tersebut atau perbuatan hukum yang menimbulkan utang piutang dimaksud telah terjadi sebelum penundaan kewajiban pembayaran utang. (2) Piutang terhadap Debitor sebagaimana dimaksud pada ayat (1) dihitung menurut ketentuan sebagaimana dimaksud dalam Pasal 274 dan Pasal 275."}, {"l": "UU 37/2004", "p": "248", "b": "Bagian Kesatu", "t": "(1) Orang yang mengambil alih dari pihak ketiga utang kepada Debitor atau piutang terhadap Debitor dari pihak ketiga sebelum penundaan kewajiban pembayaran utang, tidak dapat melakukan perjumpaan utang apabila dalam pengambilalihan utang piutang tersebut ia tidak beritikad baik. (2) Piutang atau utang yang diambil alih setelah dimulainya penundaan kewajiban pembayaran utang, tidak dapat diperjumpakan. (3) Ketentuan sebagaimana dimaksud dalam Pasal 53 dan Pasal 54 berlaku bagi perjumpaan utang yang diatur dalam Pasal ini. Pasal 249 …"}, {"l": "UU 37/2004", "p": "249", "b": "Bagian Kesatu", "t": "(1) Dalam hal pada saat putusan penundaan kewajiban pembayaran utang diucapkan terdapat perjanjian timbal balik yang belum atau baru sebagian dipenuhi, pihak yang mengadakan perjanjian dengan Debitor dapat meminta kepada pengurus untuk memberikan kepastian tentang kelanjutan pelaksanaan perjanjian tersebut dalam jangka waktu yang disepakati oleh pengurus dan pihak tersebut. (2) Dalam hal tidak tercapai kesepakatan mengenai jangka waktu sebagaimana dimaksud pada ayat (1), Hakim Pengawas menetapkan jangka waktu tersebut. (3) Apabila dalam jangka waktu sebagaimana dimaksud pada ayat (1) dan ayat (2) pengurus tidak memberikan jawaban atau tidak bersedia melanjutkan pelaksanaan perjanjian tersebut, perjanjian berakhir dan pihak sebagaimana dimaksud pada ayat (1) dapat menuntut ganti rugi sebagai Kreditor konkuren. (4) Apabila pengurus menyatakan kesanggupannya, pengurus memberikan jaminan atas kesanggupannya untuk melaksanakan perjanjian tersebut. (5) Ketentuan sebagaimana dimaksud pada ayat (1), ayat (2), ayat (3), dan ayat (4) tidak berlaku terhadap perjanjian yang mewajibkan Debitor melakukan sendiri perbuatan yang diperjanjikan."}, {"l": "UU 37/2004", "p": "250", "b": "Bagian Kesatu", "t": "(1) Dalam hal perjanjian sebagaimana dimaksud dalam Pasal 249 telah diperjanjikan penyerahan benda yang biasa diperdagangkan dengan suatu jangka waktu dan sebelum penyerahan dilakukan telah diucapkan putusan penundaan kewajiban pembayaran utang sementara, perjanjian menjadi hapus, dan dalam hal pihak lawan dirugikan karena penghapusan, ia boleh mengajukan diri sebagai Kreditor konkuren untuk mendapatkan ganti rugi. (2) Dalam … (2) Dalam hal harta dirugikan karena penghapusan sebagaimana dimaksud pada ayat (1) maka pihak lawan wajib membayar kerugian tersebut."}, {"l": "UU 37/2004", "p": "251", "b": "Bagian Kesatu", "t": "(1) Dalam hal Debitor telah menyewa suatu benda, Debitor dengan persetujuan pengurus, dapat menghentikan perjanjian sewa, dengan syarat pemberitahuan penghentian dilakukan sebelum berakhirnya perjanjian sesuai dengan adat kebiasaan setempat. (2) Dalam hal melakukan penghentian sebagaimana dimaksud pada ayat (1), harus pula diindahkan jangka waktu menurut perjanjian atau menurut kelaziman, dengan ketentuan bahwa jangka waktu 90 (sembilan puluh) hari adalah cukup. (3) Dalam hal telah dibayar uang sewa di muka, perjanjian sewa tidak dapat dihentikan lebih awal sebelum berakhirnya jangka waktu sewa yang telah dibayar uang muka. (4) Sejak hari putusan penundaan kewajiban pembayaran utang sementara diucapkan maka uang sewa merupakan utang harta Debitor."}, {"l": "UU 37/2004", "p": "252", "b": "Bagian Kesatu", "t": "(1) Segera setelah diucapkannya putusan penundaan kewajiban pembayaran utang sementara maka Debitor berhak untuk memutuskan hubungan kerja dengan karyawannya, dengan mengindahkan ketentuan sebagaimana dimaksud dalam Pasal 240 dan dengan mengindahkan jangka waktu menurut persetujuan atau ketentuan perundang-undangan yang berlaku dengan pengertian bahwa hubungan kerja tersebut dapat diputuskan dengan pemberitahuan paling singkat 45 (empat puluh lima) hari sebelumnya. (2) Sejak … (2) Sejak mulai berlakunya penundaan kewajiban pembayaran utang sementara maka gaji dan biaya lain yang timbul dalam hubungan kerja tersebut menjadi utang harta Debitor."}, {"l": "UU 37/2004", "p": "253", "b": "Bagian Kesatu", "t": "(1) Pembayaran yang dilakukan kepada Debitor, setelah diucapkannya putusan penundaan kewajiban pembayaran utang sementara yang belum diumumkan, untuk memenuhi perikatan yang terbit sebelum putusan penundaan kewajiban pembayaran utang sementara, membebaskan pihak yang telah melakukan pembayaran terhadap harta Debitor, kecuali dapat dibuktikan bahwa pihak tersebut telah mengetahui adanya putusan penundaan kewajiban pembayaran utang sementara. (2) Pembayaran sebagaimana dimaksud pada ayat (1) yang dilakukan sesudah pengumuman, hanya membebaskan orang yang melakukan pembayaran dimaksud apabila ia dapat membuktikan bahwa meskipun telah dilakukan pengumuman menurut undang-undang akan tetapi ia tidak mungkin dapat mengetahui pengumuman dimaksud di tempat kediamannya, dengan tidak mengurangi hak pengurus untuk membuktikan sebaliknya."}, {"l": "UU 37/2004", "p": "254", "b": "Bagian Kesatu", "t": "Penundaan kewajiban pembayaran utang tidak berlaku bagi keuntungan sesama Debitor dan penanggung."}, {"l": "UU 37/2004", "p": "255", "b": "Bagian Kesatu", "t": "(1) Penundaan kewajiban pembayaran utang dapat diakhiri, atas permintaan Hakim Pengawas, satu atau lebih Kreditor, atau atas prakarsa Pengadilan dalam hal: a. Debitor, selama waktu penundaan kewajiban pembayaran utang, bertindak dengan itikad buruk dalam melakukan pengurusan terhadap hartanya; b. Debitor … b. Debitor telah merugikan atau telah mencoba merugikan kreditornya; c. Debitor melakukan pelanggaran ketentuan Pasal 240 ayat (1); d. Debitor lalai melaksanakan tindakan-tindakan yang diwajibkan kepadanya oleh Pengadilan pada saat atau setelah penundaan kewajiban pembayaran utang diberikan, atau lalai melaksanakan tindakan- tindakan yang disyaratkan oleh pengurus demi kepentingan harta Debitor; e. selama waktu penundaan kewajiban pembayaran utang, keadaan harta Debitor ternyata tidak lagi memungkinkan dilanjutkannya penundaan kewajiban pembayaran utang; atau f. keadaan Debitor tidak dapat diharapkan untuk memenuhi kewajibannya terhadap Kreditor pada waktunya. (2) Dalam hal keadaan sebagaimana dimaksud pada ayat (1) huruf a dan huruf e pengurus wajib mengajukan permohonan pengakhiran penundaan kewajiban pembayaran utang. (3) Pemohon, Debitor, dan pengurus harus didengar pada …"}, {"l": "UU 37/2004", "p": "256", "b": "Bagian Kesatu", "t": "Ketentuan sebagaimana dimaksud dalam Pasal 11, Pasal 12, Pasal 13, dan Pasal 14 berlaku mutatis mutandis terhadap putusan pernyataan pailit sebagai akibat putusan pengakhiran penundaan kewajiban pembayaran utang."}, {"l": "UU 37/2004", "p": "257", "b": "Bagian Kesatu", "t": "Putusan pernyataan pailit sebagai akibat putusan pengakhiran penundaan kewajiban pembayaran utang harus diumumkan sesuai dengan ketentuan sebagaimana dimaksud dalam Pasal 15 ayat (4)."}, {"l": "UU 37/2004", "p": "258", "b": "Bagian Kesatu", "t": "(1) Jika Pengadilan menganggap bahwa sidang permohonan pengakhiran penundaan kewajiban pembayaran utang tidak dapat diselesaikan sebelum tanggal Kreditor didengar sesuai dengan ketentuan sebagaimana dimaksud dalam Pasal 225 ayat (3), Pengadilan wajib memerintahkan agar Kreditor diberitahu secara tertulis bahwa mereka tidak dapat didengar pada tanggal tersebut. (2) Jika diperlukan, Pengadilan segera menetapkan tanggal lain untuk sidang dan dalam hal demikian Kreditor dipanggil oleh pengurus."}, {"l": "UU 37/2004", "p": "259", "b": "Bagian Kesatu", "t": "(1) Debitor setiap waktu dapat memohon kepada Pengadilan agar penundaan kewajiban pembayaran utang dicabut, dengan alasan bahwa harta Debitor memungkinkan dimulainya pembayaran kembali dengan ketentuan bahwa pengurus dan Kreditor harus dipanggil dan didengar sepatutnya sebelum putusan diucapkan. (2) Pemanggilan sebagaimana dimaksud pada ayat (1) wajib dilakukan oleh jurusita dengan surat dinas tercatat, paling lambat 7 (tujuh) hari sebelum sidang Pengadilan. Pasal 260 …"}, {"l": "UU 37/2004", "p": "260", "b": "Bagian Kesatu", "t": "Selama penundaan kewajiban pembayaran utang berlangsung, terhadap Debitor tidak dapat diajukan permohonan pailit."}, {"l": "UU 37/2004", "p": "261", "b": "Bagian Kesatu", "t": "Apabila berdasarkan salah satu ketentuan dalam Bab ini, putusan pernyataan pailit diucapkan maka berlaku ketentuan sebagaimana dimaksud dalam Pasal 15."}, {"l": "UU 37/2004", "p": "262", "b": "Bagian Kesatu", "t": "(1) Dalam hal Debitor dinyatakan pailit berdasarkan ketentuan dalam Bab ini maka berlaku ketentuan sebagai berikut: a. jangka waktu sebagaimana dimaksud dalam Pasal 42 dan Pasal 44 harus dihitung sejak putusan penundaan kewajiban pembayaran utang sementara diucapkan; b. perbuatan hukum yang dilakukan oleh Debitor setelah diberi persetujuan oleh pengurus untuk melakukannya harus dianggap sebagai perbuatan hukum yang dilakukan oleh Kurator, dan utang harta Debitor yang terjadi selama berlangsungnya penundaan kewajiban pembayaran utang merupakan utang harta pailit; c. kewajiban Debitor yang timbul selama jangka waktu penundaan kewajiban pembayaran utang tanpa persetujuan oleh pengurus tidak dapat dibebankan terhadap harta Debitor, kecuali hal tersebut membawa akibat yang menguntungkan bagi harta Debitor. (2) Apabila permohonan penundaan kewajiban pembayaran utang diajukan dalam waktu 2 (dua) bulan setelah berakhirnya penundaan kewajiban pembayaran utang sebelumnya maka ketentuan ayat (1) berlaku pula bagi jangka waktu penundaan kewajiban pembayaran utang berikutnya. Pasal 263 …"}, {"l": "UU 37/2004", "p": "263", "b": "Bagian Kesatu", "t": "Imbalan jasa bagi ahli yang diangkat berdasarkan ketentuan sebagaimana dimaksud dalam Pasal 238, ditentukan oleh Hakim Pengawas dan harus dibayar lebih dahulu dari harta Debitor."}, {"l": "UU 37/2004", "p": "264", "b": "Bagian Kesatu", "t": "Ketentuan hukum internasional sebagaimana dimaksud dalam Pasal 212, Pasal 213, dan Pasal 214 berlaku mutatis mutandis dalam hal penundaan kewajiban pembayaran utang."}, {"l": "UU 37/2004", "p": "265", "b": "Bagian Kedua", "t": "Debitor berhak pada waktu mengajukan permohonan penundaan kewajiban pembayaran utang atau setelah itu menawarkan suatu perdamaian kepada Kreditor."}, {"l": "UU 37/2004", "p": "266", "b": "Bagian Kedua", "t": "(1) Apabila rencana perdamaian tersebut tidak disediakan di Kepaniteraan Pengadilan sebagaimana dimaksud dalam Pasal 225 maka rencana tersebut diajukan sebelum hari sidang sebagaimana dimaksud dalam Pasal 226 atau pada tanggal kemudian dengan tetap memperhatikan ketentuan sebagaimana dimaksud dalam Pasal 228 ayat (4). (2) Salinan rencana perdamaian harus segera disampaikan kepada Hakim Pengawas, pengurus, dan ahli, bila ada. Pasal 267 …"}, {"l": "UU 37/2004", "p": "267", "b": "Bagian Kedua", "t": "Dalam hal sebelum putusan pengesahan perdamaian memperoleh kekuatan hukum tetap, ada putusan Pengadilan yang menyatakan bahwa penundaan kewajiban pembayaran utang berakhir, gugurlah rencana perdamaian tersebut."}, {"l": "UU 37/2004", "p": "268", "b": "Bagian Kedua", "t": "(1) Apabila rencana perdamaian telah diajukan kepada panitera, Hakim Pengawas harus menentukan: a. hari terakhir tagihan harus disampaikan kepada pengurus; b. tanggal dan waktu rencana perdamaian yang diusulkan itu akan dibicarakan dan diputuskan dalam rapat Kreditor yang dipimpin oleh Hakim Pengawas. (2) Tenggang waktu antara hari sebagaimana dimaksud pada ayat (1) huruf a dan huruf b paling singkat 14 (empat belas) hari."}, {"l": "UU 37/2004", "p": "269", "b": "Bagian Kedua", "t": "(1) Pengurus wajib mengumumkan penentuan waktu sebagaimana dimaksud dalam Pasal 268 ayat (1) bersama-sama dengan dimasukkannya rencana perdamaian, kecuali jika hal ini sudah diumumkan sesuai dengan ketentuan sebagaimana dimaksud dalam Pasal 226. (2) Pengurus juga wajib memberitahukan hal-hal sebagaimana dimaksud pada ayat (1) dengan surat tercatat atau melalui kurir kepada semua Kreditor yang dikenal, dan pemberitahuan ini harus menyebutkan ketentuan sebagaimana dimaksud dalam Pasal 270 ayat (2). (3) Kreditor dapat menghadap sendiri atau diwakili oleh seorang kuasa berdasarkan surat kuasa. (4) Pengurus … (4) Pengurus dapat mensyaratkan agar Debitor memberikan kepada mereka uang muka dalam jumlah yang ditetapkan oleh pengurus guna menutup biaya untuk pengumuman dan pemberitahuan tersebut."}, {"l": "UU 37/2004", "p": "270", "b": "Bagian Kedua", "t": "(1) Tagihan harus diajukan kepada pengurus dengan cara menyerahkan surat tagihan atau bukti tertulis lainnya yang menyebutkan sifat dan jumlah tagihan disertai bukti yang mendukung atau salinan bukti tersebut. (2) Terhadap tagihan yang diajukan kepada pengurus sebagaimana dimaksud pada ayat (1), Kreditor dapat meminta tanda terima dari pengurus."}, {"l": "UU 37/2004", "p": "271", "b": "Bagian Kedua", "t": "Semua perhitungan yang telah dimasukkan oleh pengurus harus dicocokkan dengan catatan dan laporan dari Debitor."}, {"l": "UU 37/2004", "p": "272", "b": "Bagian Kedua", "t": "Pengurus harus membuat daftar piutang yang memuat nama, tempat tinggal Kreditor, jumlah piutang masing-masing, penjelasan piutang, dan apakah piutang tersebut diakui atau dibantah oleh pengurus."}, {"l": "UU 37/2004", "p": "273", "b": "Bagian Kedua", "t": "(1) Piutang yang berbunga harus dimasukkan dalam daftar sebagaimana dimaksud dalam Pasal 272 disertai perhitungan bunga sampai dengan hari diucapkannya putusan penundaan kewajiban pembayaran utang. (2) Ketentuan sebagaimana dimaksud dalam Pasal 135, Pasal 139, Pasal 140, Pasal 141, dan Pasal 142 ayat (1) dan ayat (2) berlaku mutatis mutandis dalam hal penundaan kewajiban pembayaran utang. Pasal 274 …"}, {"l": "UU 37/2004", "p": "274", "b": "Bagian Kedua", "t": "(1) Suatu tagihan dengan syarat tangguh dapat dimasukkan dalam daftar sebagaimana dimaksud dalam Pasal 272 untuk nilai yang berlaku pada saat dimulainya penundaan kewajiban pembayaran utang. (2) Jika pengurus dan Kreditor tidak mencapai kesepakatan tentang penetapan nilai tagihan tersebut, seluruh nilai tagihan Kreditor harus diterima secara bersyarat."}, {"l": "UU 37/2004", "p": "275", "b": "Bagian Kedua", "t": "(1) Piutang yang saat penagihannya belum jelas atau yang memberikan hak untuk memperoleh pembayaran secara berkala, wajib dimasukkan dalam daftar untuk nilai yang berlaku pada tanggal diucapkannya putusan penundaan kewajiban pembayaran utang sementara. (2) Semua piutang yang dapat ditagih dalam jangka waktu 1 (satu) tahun sejak putusan penundaan kewajiban pembayaran utang diucapkan, wajib diperlakukan sebagai piutang yang dapat ditagih pada tanggal tersebut. (3) Semua piutang yang dapat ditagih setelah lewat 1 (satu) tahun sejak putusan penundaan kewajiban pembayaran utang diucapkan, wajib dimasukkan dalam daftar untuk nilai yang berlaku 1 (satu) tahun setelah putusan penundaan kewajiban pembayaran utang tersebut diucapkan. (4) Dalam melakukan perhitungan nilai piutang sebagaimana dimaksud pada ayat (2) dan ayat (3), wajib diperhatikan: a. waktu dan cara pembayaran angsuran; b. keuntungan yang mungkin diperoleh; dan c. besarnya bunga apabila diperjanjikan. Pasal 276 …"}, {"l": "UU 37/2004", "p": "276", "b": "Bagian Kedua", "t": "(1) Pengurus wajib menyediakan salinan daftar sebagaimana dimaksud dalam Pasal 272 di Kepaniteraan Pengadilan, agar dalam waktu 7 (tujuh) hari sebelum diadakannya rapat sebagaimana dimaksud dalam Pasal 268 dapat dilihat oleh setiap orang dengan cuma-cuma. (2) Penyediaan salinan sebagaimana dimaksud pada ayat (1) dilakukan dengan cuma-cuma."}, {"l": "UU 37/2004", "p": "277", "b": "Bagian Kedua", "t": "(1) Dengan tetap memperhatikan ketentuan mengenai jangka waktu penundaan kewajiban pembayaran utang sebagaimana dimaksud dalam Pasal 228 ayat (4), atas permintaan pengurus atau karena jabatannya, Hakim Pengawas dapat menunda pembicaraan dan pemungutan suara tentang rencana perdamaian tersebut. (2) Dalam hal terjadi penundaan pembicaraan dan pemungutan suara sebagaimana dimaksud pada ayat (1) berlaku ketentuan sebagaimana dimaksud dalam Pasal 269."}, {"l": "UU 37/2004", "p": "278", "b": "Bagian Kedua", "t": "(1) Dalam rapat rencana perdamaian, baik pengurus maupun ahli, apabila telah diangkat, harus secara tertulis memberikan laporan tentang rencana perdamaian yang ditawarkan itu. (2) Ketentuan sebagaimana dimaksud dalam Pasal 150 berlaku mutatis mutandis dalam hal penundaan kewajiban pembayaran utang. (3) Piutang yang dimasukkan kepada pengurus sesudah lewat tenggang waktu sebagaimana dimaksud dalam Pasal 268 ayat (1) huruf a, dengan syarat dimasukkan paling lama 2 (dua) hari sebelum diadakan rapat, harus dimuat dalam daftar piutang atas permintaan yang diajukan pada rapat tersebut, jika pengurus maupun Kreditor yang hadir, tidak mengajukan keberatan. (4) Piutang … (4) Piutang yang dimasukkan sesudah tenggang waktu sebagaimana dimaksud pada ayat (3), tidak dimasukkan dalam daftar tersebut. (5) Ketentuan jangka waktu sebagaimana dimaksud pada ayat (2) dan ayat (3) tidak berlaku, apabila Kreditor berdomisili di luar wilayah Negara Republik Indonesia yang merupakan halangan untuk melaporkan diri lebih dahulu. (6) Dalam hal diajukan keberatan sebagaimana dimaksud pada ayat (2) dan ayat (3), atau dalam hal adanya perselisihan tentang ada atau tidak adanya halangan sebagaimana dimaksud …"}, {"l": "UU 37/2004", "p": "279", "b": "Bagian Kedua", "t": "(1) Pengurus berhak dalam rapat tersebut menarik kembali setiap pengakuan atau bantahan yang pernah dilakukan. (2) Kreditor yang hadir dapat membantah piutang yang oleh pengurus seluruhnya atau sebagian diakuinya. (3) Pengakuan atau bantahan yang dilakukan dalam rapat, harus dicatat dalam daftar piutang."}, {"l": "UU 37/2004", "p": "280", "b": "Bagian Kedua", "t": "Hakim Pengawas menentukan Kreditor yang tagihannya dibantah, untuk dapat ikut serta dalam pemungutan suara dan menentukan batasan jumlah suara yang dapat dikeluarkan oleh Kreditor tersebut."}, {"l": "UU 37/2004", "p": "281", "b": "Bagian Kedua", "t": "(1) Rencana perdamaian dapat diterima berdasarkan: a. persetujuan lebih dari 1/2 (satu perdua) jumlah kreditor konkuren yang haknya diakui atau sementara diakui yang hadir pada rapat Kreditor sebagaimana dimaksud dalam Pasal … Pasal 268 termasuk Kreditor sebagaimana dimaksud dalam Pasal 280, yang bersama-sama mewakili paling sedikit 2/3 (dua pertiga) bagian dari seluruh tagihan yang diakui atau sementara diakui dari kreditor konkuren atau kuasanya yang hadir dalam rapat tersebut; dan b. persetujuan lebih dari 1/2 (satu perdua) jumlah Kreditor yang piutangnya dijamin dengan gadai, jaminan fidusia, hak tanggungan, hipotek, atau hak agunan atas kebendaan lainnya yang hadir dan mewakili paling sedikit 2/3 (dua per tiga) bagian dari seluruh tagihan dari Kreditor tersebut atau kuasanya yang hadir dalam rapat tersebut. (2) Kreditor sebagaimana dimaksud pada ayat (1) huruf b yang tidak menyetujui rencana perdamaian diberikan kompensasi sebesar nilai terendah di antara nilai jaminan atau nilai aktual pinjaman yang secara langsung dijamin dengan hak agunan atas kebendaan. (3) Ketentuan sebagaimana dimaksud dalam Pasal 152 dan Pasal 153 berlaku juga dalam pemungutan suara untuk menerima …"}, {"l": "UU 37/2004", "p": "282", "b": "Bagian Kedua", "t": "(1) Berita acara rapat yang dipimpin oleh Hakim Pengawas harus mencantumkan isi rencana perdamaian, nama Kreditor yang hadir dan berhak mengeluarkan suara, catatan tentang suara yang dikeluarkan Kreditor, hasil pemungutan suara, dan catatan tentang semua kejadian lain dalam rapat. (2) Daftar Kreditor yang dibuat oleh pengurus yang telah ditambah atau diubah dalam rapat, harus ditandatangani oleh Hakim Pengawas dan panitera pengganti serta harus dilampirkan pada berita acara rapat yang bersangkutan. (3) Salinan … (3) Salinan berita acara rapat sebagaimana dimaksud pada ayat (1) harus disediakan di Kepaniteraan Pengadilan paling lambat 3 (tiga) hari setelah putusan rapat. (4) Salinan berita acara rapat dapat dilihat oleh setiap orang dengan cuma- cuma selama 8 (delapan) hari setelah tanggal disediakan."}, {"l": "UU 37/2004", "p": "283", "b": "Bagian Kedua", "t": "(1) Debitor dan Kreditor yang memberi suara mendukung rencana perdamaian dalam waktu 8 (delapan) hari setelah tanggal pemungutan suara dalam rapat, dapat meminta kepada Pengadilan agar berita acara rapat diperbaiki apabila berdasarkan dokumen yang ada ternyata bahwa perdamaian oleh Hakim Pengawas keliru telah dianggap sebagai ditolak. (2) Jika Pengadilan membuat perbaikan berita acara rapat maka dalam putusan yang sama Pengadilan harus menentukan tanggal pengesahan perdamaian yang harus dilaksanakan paling singkat 8 (delapan) hari dan paling lambat 14 (empat belas) hari setelah putusan Pengadilan yang memperbaiki berita acara rapat tersebut diucapkan. (3) Pengurus wajib memberitahukan secara tertulis kepada Kreditor putusan Pengadilan sebagaimana dimaksud pada ayat (2), dan putusan tersebut mengakibatkan putusan pernyataan pailit berdasarkan Pasal 289 menjadi batal demi hukum."}, {"l": "UU 37/2004", "p": "284", "b": "Bagian Kedua", "t": "(1) Apabila rencana perdamaian diterima, Hakim Pengawas wajib menyampaikan laporan tertulis kepada Pengadilan pada tanggal yang telah ditentukan untuk keperluan pengesahan perdamaian, dan pada tanggal yang ditentukan tersebut pengurus serta Kreditor dapat menyampaikan alasan yang menyebabkan ia menghendaki pengesahan atau penolakan perdamaian. (2) Ketentuan … (2) Ketentuan sebagaimana dimaksud dalam Pasal 158 ayat (2) berlaku mutatis mutandis terhadap pelaksanaan ketentuan ayat (1). (3) Pengadilan dapat mengundurkan dan menetapkan tanggal sidang untuk pengesahan perdamaian yang harus diselenggarakan paling lambat 14 (empat belas) hari setelah tanggal sidang sebagaimana dimaksud pada ayat (1)."}, {"l": "UU 37/2004", "p": "285", "b": "Bagian Kedua", "t": "(1) Pengadilan wajib memberikan putusan mengenai pengesahan perdamaian disertai alasan-alasannya pada sidang sebagaimana dimaksud dalam Pasal 284 ayat (3). (2) Pengadilan wajib menolak untuk mengesahkan perdamaian, apabila: a. harta Debitor, termasuk benda untuk mana dilaksanakan hak untuk menahan benda, jauh lebih besar daripada jumlah yang disetujui dalam perdamaian; b. pelaksanaan perdamaian tidak cukup terjamin; c. perdamaian itu dicapai karena penipuan, atau persekongkolan dengan satu atau lebih Kreditor, atau karena pemakaian upaya lain yang tidak jujur dan tanpa menghiraukan apakah Debitor atau pihak lain bekerja sama untuk mencapai hal ini; dan/atau d. imbalan jasa dan biaya yang dikeluarkan oleh ahli dan pengurus belum dibayar atau tidak diberikan jaminan untuk pembayarannya. (3) Apabila Pengadilan menolak mengesahkan perdamaian maka dalam putusan yang sama Pengadilan wajib menyatakan Debitor Pailit dan putusan tersebut harus diumumkan dalam Berita Negara Republik Indonesia dan paling sedikit 2 (dua) surat kabar harian sebagaimana dimaksud dalam Pasal 226 dengan jangka waktu paling lambat 5 (lima) hari setelah putusan diterima oleh Hakim Pengawas dan Kurator. (4) …"}, {"l": "UU 37/2004", "p": "286", "b": "Bagian Kedua", "t": "Perdamaian yang telah disahkan mengikat semua Kreditor, kecuali Kreditor yang tidak menyetujui rencana perdamaian sebagaimana dimaksud dalam Pasal 281 ayat (2)."}, {"l": "UU 37/2004", "p": "287", "b": "Bagian Kedua", "t": "Putusan pengesahan perdamaian yang telah memperoleh kekuatan hukum tetap dalam hubungannya dengan berita acara sebagaimana dimaksud dalam Pasal 282, bagi semua Kreditor yang tidak dibantah oleh Debitor, merupakan alas hak yang dapat dijalankan terhadap Debitor dan semua orang yang telah mengikatkan diri sebagai penanggung untuk perdamaian tersebut."}, {"l": "UU 37/2004", "p": "288", "b": "Bagian Kedua", "t": "Penundaan kewajiban pembayaran utang berakhir pada saat putusan pengesahan perdamaian memperoleh kekuatan hukum tetap dan pengurus wajib mengumumkan pengakhiran ini dalam Berita Negara Republik Indonesia dan paling sedikit 2 (dua) surat kabar harian sebagaimana dimaksud dalam"}, {"l": "UU 37/2004", "p": "289", "b": "Bagian Kedua", "t": "Apabila rencana perdamaian ditolak maka Hakim Pengawas wajib segera memberitahukan penolakan itu kepada Pengadilan dengan cara menyerahkan kepada Pengadilan tersebut salinan rencana perdamaian serta berita acara rapat sebagaimana dimaksud dalam Pasal 282, dan dalam hal demikian Pengadilan harus menyatakan Debitor Pailit setelah Pengadilan menerima pemberitahuan penolakan dari Hakim Pengawas, dengan memperhatikan ketentuan sebagaimana dimaksud dalam Pasal 283 ayat (1). Pasal 290 …"}, {"l": "UU 37/2004", "p": "290", "b": "Bagian Kedua", "t": "Apabila Pengadilan telah menyatakan Debitor Pailit maka terhadap putusan pernyataan pailit tersebut berlaku ketentuan tentang kepailitan sebagaimana dimaksud dalam Bab II, kecuali Pasal 11, Pasal 12, Pasal 13, dan Pasal 14."}, {"l": "UU 37/2004", "p": "291", "b": "Bagian Kedua", "t": "(1) Ketentuan sebagaimana dimaksud dalam Pasal 170 dan Pasal 171 berlaku mutatis mutandis terhadap pembatalan perdamaian. (2) Dalam putusan Pengadilan yang membatalkan perdamaian, Debitor juga harus dinyatakan pailit."}, {"l": "UU 37/2004", "p": "292", "b": "Bagian Kedua", "t": "Dalam suatu putusan pernyataan pailit yang diputuskan berdasarkan ketentuan sebagaimana dimaksud dalam Pasal 285, Pasal 286, atau Pasal 291, tidak dapat ditawarkan suatu perdamaian."}, {"l": "UU 37/2004", "p": "293", "b": "Bagian Kedua", "t": "(1) Terhadap putusan Pengadilan berdasarkan ketentuan dalam Bab III ini tidak terbuka upaya hukum, kecuali ditentukan lain dalam Undang-Undang ini. (2) Upaya hukum kasasi dapat diajukan oleh Jaksa Agung demi kepentingan hukum."}, {"l": "UU 37/2004", "p": "294", "b": "Bagian Kedua", "t": "Permohonan yang diajukan berdasarkan ketentuan sebagaimana dimaksud dalam Pasal 237, Pasal 255, Pasal 256, Pasal 259, Pasal 283, Pasal 285, Pasal 290, dan Pasal 291 harus ditandatangani oleh advokat yang bertindak berdasarkan surat kuasa khusus, kecuali apabila diajukan oleh pengurus."}, {"l": "UU 37/2004", "p": "295", "b": "BAB IV PERMOHONAN PENINJAUAN KEMBALI", "t": "(1) Terhadap putusan hakim yang telah memperoleh kekuatan hukum tetap, dapat diajukan permohonan peninjauan kembali kepada Mahkamah Agung, kecuali ditentukan lain dalam Undang-Undang ini. (2) Permohonan peninjauan kembali dapat diajukan, apabila: a. setelah perkara diputus ditemukan bukti baru yang bersifat menentukan yang pada waktu perkara diperiksa di Pengadilan sudah ada, tetapi belum ditemukan; atau b. dalam putusan hakim yang bersangkutan terdapat kekeliruan yang nyata."}, {"l": "UU 37/2004", "p": "296", "b": "BAB IV PERMOHONAN PENINJAUAN KEMBALI", "t": "(1) Pengajuan permohonan peninjauan kembali berdasarkan alasan sebagaimana dimaksud dalam Pasal 295 ayat (2) huruf a, dilakukan dalam jangka waktu paling lambat 180 (seratus delapan puluh) hari setelah tanggal putusan yang dimohonkan peninjauan kembali memperoleh kekuatan hukum tetap. (2) Pengajuan permohonan peninjauan kembali berdasarkan alasan sebagaimana dimaksud dalam Pasal 295 ayat (2) huruf b, dilakukan dalam jangka waktu paling lambat 30 (tiga puluh) hari setelah tanggal putusan yang dimohonkan peninjauan kembali memperoleh kekuatan hukum tetap. (3) Permohonan peninjauan kembali disampaikan kepada Panitera Pengadilan. (4) Panitera … (4) Panitera Pengadilan mendaftar permohonan peninjauan kembali pada tanggal permohonan diajukan, dan kepada pemohon diberikan tanda terima tertulis yang ditandatangani Panitera Pengadilan dengan tanggal yang sama dengan tanggal permohonan didaftarkan. (5) Panitera Pengadilan menyampaikan permohonan peninjauan kembali kepada Panitera Mahkamah Agung dalam jangka waktu 2 (dua) hari setelah tanggal permohonan didaftarkan."}, {"l": "UU 37/2004", "p": "297", "b": "BAB IV PERMOHONAN PENINJAUAN KEMBALI", "t": "(1) Pemohon peninjauan kembali wajib menyampaikan kepada Panitera Pengadilan bukti pendukung yang menjadi dasar pengajuan permohonan peninjauan kembali dan untuk termohon salinan permohonan peninjauan kembali berikut salinan bukti pendukung yang bersangkutan, pada tanggal permohonan didaftarkan sebagaimana dimaksud dalam Pasal 296 ayat (4). (2) Tanpa mengenyampingkan ketentuan sebagaimana dimaksud pada ayat (1), Panitera Pengadilan menyampaikan salinan permohonan peninjauan kembali berikut salinan bukti pendukung kepada termohon dalam jangka waktu paling lambat 2 (dua) hari setelah tanggal permohonan didaftarkan. (3) Pihak termohon dapat mengajukan jawaban terhadap permohonan peninjauan kembali yang diajukan, dalam jangka waktu 10 (sepuluh) hari setelah tanggal permohonan peninjauan kembali didaftarkan. (4) Panitera Pengadilan wajib menyampaikan jawaban sebagaimana dimaksud pada ayat (3) kepada Panitera Mahkamah Agung, dalam jangka waktu paling lambat 12 (dua belas) hari setelah tanggal permohonan didaftarkan. Pasal 298 …"}, {"l": "UU 37/2004", "p": "298", "b": "BAB IV PERMOHONAN PENINJAUAN KEMBALI", "t": "(1) Mahkamah Agung segera memeriksa dan memberikan putusan atas permohonan peninjauan kembali dalam jangka waktu paling lambat 30 (tiga puluh) hari setelah tanggal permohonan diterima Panitera Mahkamah Agung. (2) Putusan atas permohonan peninjauan kembali harus diucapkan dalam sidang terbuka untuk umum. (3) Dalam jangka waktu paling lambat 32 (tiga puluh dua) hari setelah tanggal permohonan diterima Panitera Mahkamah Agung, Mahkamah Agung wajib menyampaikan kepada para pihak salinan putusan peninjauan kembali yang memuat secara lengkap pertimbangan hukum yang mendasari putusan tersebut."}, {"l": "UU 37/2004", "p": "299", "b": "BAB V KETENTUAN LAIN-LAIN", "t": "Kecuali ditentukan lain dalam Undang-Undang ini maka hukum acara yang berlaku adalah Hukum Acara Perdata."}, {"l": "UU 37/2004", "p": "300", "b": "BAB V KETENTUAN LAIN-LAIN", "t": "(1) Pengadilan sebagaimana dimaksud dalam Undang-Undang ini, selain memeriksa dan memutus permohonan pernyataan pailit dan Penundaan Kewajiban Pembayaran Utang, berwenang pula memeriksa dan memutus perkara lain di bidang perniagaan yang penetapannya dilakukan dengan undang-undang. (2) Pembentukan Pengadilan sebagaimana dimaksud pada ayat (1) dilakukan secara bertahap dengan Keputusan Presiden, dengan memperhatikan kebutuhan dan kesiapan sumber daya yang diperlukan. Pasal 301 …"}, {"l": "UU 37/2004", "p": "301", "b": "BAB V KETENTUAN LAIN-LAIN", "t": "(1) Pengadilan memeriksa dan memutus perkara pada tingkat pertama dengan hakim majelis. (2) Dalam hal menyangkut perkara lain di bidang perniagaan sebagaimana dimaksud dalam Pasal 300 ayat (1), Ketua Mahkamah Agung dapat menetapkan jenis dan nilai perkara yang pada tingkat pertama diperiksa dan diputus oleh hakim tunggal. (3) Dalam menjalankan tugasnya, hakim Pengadilan dibantu oleh seorang panitera atau seorang panitera pengganti dan juru sita."}, {"l": "UU 37/2004", "p": "302", "b": "BAB V KETENTUAN LAIN-LAIN", "t": "(1) Hakim Pengadilan diangkat berdasarkan Keputusan Ketua Mahkamah Agung. (2) Syarat-syarat untuk dapat diangkat sebagai hakim sebagaimana dimaksud pada ayat (1), adalah: a. telah berpengalaman sebagai hakim dalam lingkungan Peradilan Umum; b. mempunyai dedikasi dan menguasai pengetahuan di bidang masalah- masalah yang menjadi lingkup kewenangan Pengadilan; c. berwibawa, jujur, adil, dan berkelakuan tidak tercela; dan d. telah berhasil menyelesaikan program pelatihan khusus sebagai hakim pada Pengadilan. (3) Dengan tetap memperhatikan syarat-syarat sebagaimana dimaksud pada ayat (2) huruf b, huruf c, dan huruf d, dengan Keputusan Presiden atas usul Ketua Mahkamah Agung dapat diangkat seseorang yang ahli, sebagai hakim ad hoc, baik pada pengadilan tingkat pertama, kasasi, maupun pada peninjauan kembali. Pasal 303 …"}, {"l": "UU 37/2004", "p": "303", "b": "BAB V KETENTUAN LAIN-LAIN", "t": "Pengadilan tetap berwenang memeriksa dan menyelesaikan permohonan pernyataan pailit dari para pihak yang terikat perjanjian yang memuat klausula arbitrase, sepanjang utang yang menjadi dasar permohonan pernyataan pailit telah memenuhi ketentuan sebagaimana dimaksud dalam Pasal 2 ayat (1) Undang-Undang ini."}, {"l": "UU 37/2004", "p": "304", "b": "BAB VI KETENTUAN PERALIHAN", "t": "Perkara yang pada waktu Undang-Undang ini berlaku: a. sudah diperiksa dan diputus tetapi belum dilaksanakan atau sudah diperiksa tetapi belum diputus maka diselesaikan berdasarkan peraturan perundang-undangan di bidang kepailitan sebelum berlakunya Undang- Undang ini; b. sudah diajukan tetapi belum diperiksa, diselesaikan berdasarkan ketentuan dalam Undang-Undang ini."}, {"l": "UU 37/2004", "p": "305", "b": "BAB VI KETENTUAN PERALIHAN", "t": "Semua peraturan perundang-undangan yang merupakan pelaksanaan dari Undang-Undang tentang Kepailitan (Faillissements-verordening Staatsblad 1905:217 juncto Staatsblad 1906:348) yang diubah dengan Peraturan Pemerintah Pengganti Undang-Undang Nomor 1 Tahun 1998 tentang Perubahan Atas Undang-Undang tentang Kepailitan yang ditetapkan menjadi Undang-Undang berdasarkan Undang-Undang Nomor 4 Tahun 1998 pada saat Undang-Undang ini diundangkan, masih tetap berlaku sejauh tidak bertentangan dan/atau belum diganti dengan peraturan baru berdasarkan Undang-Undang ini."}, {"l": "UU 37/2004", "p": "306", "b": "BAB VII KETENTUAN PENUTUP", "t": "Pengadilan Niaga pada Pengadilan Negeri Jakarta Pusat yang dibentuk berdasarkan ketentuan Pasal 281 ayat (1) Peraturan Pemerintah Pengganti Undang-Undang Nomor 1 Tahun 1998 tentang Perubahan Atas Undang- Undang tentang Kepailitan sebagaimana telah ditetapkan menjadi Undang- Undang Nomor 4 Tahun 1998, dinyatakan tetap berwenang memeriksa dan memutus perkara yang menjadi lingkup tugas Pengadilan Niaga."}, {"l": "UU 37/2004", "p": "307", "b": "BAB VII KETENTUAN PENUTUP", "t": "Pada saat Undang-Undang ini mulai berlaku, Undang-Undang tentang Kepailitan (Faillissements-verordening Staatsblad 1905:217 juncto Staatsblad 1906:348) dan Undang-Undang Nomor 4 Tahun 1998 tentang Penetapan Peraturan Pemerintah Pengganti Undang-Undang Nomor 1 Tahun 1998 tentang Perubahan Atas Undang-Undang tentang Kepailitan menjadi Undang- Undang (Lembaran Negara Republik Indonesia Tahun 1998 Nomor 135, dinyatakan tidak berlaku."}, {"l": "UU 37/2004", "p": "308", "b": "BAB VII KETENTUAN PENUTUP", "t": "Undang-Undang ini mulai berlaku pada tanggal diundangkan. Agar … Undang ini dengan penempatannya dalam Lembaran Negara Republik Indonesia. pada tanggal 18 Oktober 2004 MEGAWATI SOEKARNOPUTRI pada tanggal 18 Oktober 2004 SEKRETARIS NEGARA REPUBLIK INDONESIA, BAMBANG KESOWO Bidang Hukum dan Perundang-undangan Lambock V. Nahattands"}, {"l": "UU ITE 11/2008", "p": "1", "b": "BAB I KETENTUAN UMUM", "t": "Dalam Undang-Undang ini yang dimaksud dengan: 1. Informasi Elektronik adalah satu atau sekumpulan data elektronik, termasuk tetapi tidak terbatas pada tulisan, suara, gambar, peta, rancangan, foto, electronic data interchange (EDI), surat elektronik (electronic mail), telegram, teleks, telecopy atau sejenisnya, huruf, tanda, angka, Kode Akses, simbol, atau perforasi yang telah diolah yang memiliki arti atau dapat dipahami oleh orang yang mampu memahaminya. 2. Transaksi Elektronik adalah perbuatan hukum yang dilakukan dengan menggunakan Komputer, jaringan Komputer, dan/atau media elektronik lainnya. 3. Teknologi Informasi adalah suatu teknik untuk mengumpulkan, menyiapkan, menyimpan, memproses, mengumumkan, menganalisis, dan/atau menyebarkan informasi. 4. Dokumen Elektronik adalah setiap Informasi Elektronik yang dibuat, diteruskan, dikirimkan, diterima, atau disimpan dalam bentuk analog, digital, elektromagnetik, optikal, atau sejenisnya, yang dapat dilihat, ditampilkan, dan/atau didengar melalui Komputer atau Sistem Elektronik, termasuk tetapi tidak terbatas pada tulisan, suara, gambar, peta, rancangan, foto atau sejenisnya, huruf, tanda, angka, Kode Akses, simbol atau perforasi …"}, {"l": "UU ITE 11/2008", "p": "2", "b": "BAB I KETENTUAN UMUM", "t": "Undang-Undang ini berlaku untuk setiap Orang yang melakukan perbuatan hukum sebagaimana diatur dalam Undang-Undang ini, baik yang berada di wilayah hukum Indonesia maupun di luar wilayah hukum Indonesia, yang memiliki akibat hukum di wilayah hukum Indonesia dan/atau di luar wilayah hukum Indonesia dan merugikan kepentingan Indonesia."}, {"l": "UU ITE 11/2008", "p": "3", "b": "BAB II ASAS DAN TUJUAN", "t": "Pemanfaatan Teknologi Informasi dan Transaksi Elektronik dilaksanakan berdasarkan asas kepastian hukum, manfaat, kehati-hatian, iktikad baik, dan kebebasan memilih teknologi atau netral teknologi."}, {"l": "UU ITE 11/2008", "p": "4", "b": "BAB II ASAS DAN TUJUAN", "t": "Pemanfaatan Teknologi Informasi dan Transaksi Elektronik dilaksanakan dengan tujuan untuk: a. mencerdaskan kehidupan bangsa sebagai bagian dari masyarakat informasi dunia; b. mengembangkan perdagangan dan perekonomian nasional dalam rangka meningkatkan kesejahteraan masyarakat; c. meningkatkan efektivitas dan efisiensi pelayanan publik; d. membuka kesempatan seluas-luasnya kepada setiap Orang untuk memajukan pemikiran dan kemampuan di bidang penggunaan dan pemanfaatan Teknologi Informasi seoptimal mungkin dan bertanggung jawab; dan e. memberikan rasa aman, keadilan, dan kepastian hukum bagi pengguna dan penyelenggara Teknologi Informasi."}, {"l": "UU ITE 11/2008", "p": "5", "b": "BAB III INFORMASI, DOKUMEN, DAN TANDA TANGAN ELEKTRONIK", "t": "(1) Informasi Elektronik dan/atau Dokumen Elektronik dan/atau hasil cetaknya merupakan alat bukti hukum yang sah. (2) Informasi Elektronik dan/atau Dokumen Elektronik dan/atau hasil cetaknya sebagaimana dimaksud pada ayat (1) merupakan perluasan dari alat bukti yang sah sesuai dengan Hukum Acara yang berlaku di Indonesia. (3) Informasi Elektronik dan/atau Dokumen Elektronik dinyatakan sah apabila menggunakan Sistem Elektronik sesuai dengan ketentuan yang diatur dalam Undang- Undang ini. (4) Ketentuan mengenai Informasi Elektronik dan/atau Dokumen Elektronik sebagaimana dimaksud pada ayat (1) tidak berlaku untuk: a. surat yang menurut Undang-Undang harus dibuat dalam bentuk tertulis; dan b. surat beserta dokumennya yang menurut Undang-Undang harus dibuat dalam bentuk akta notaril atau akta yang dibuat oleh pejabat pembuat akta."}, {"l": "UU ITE 11/2008", "p": "6", "b": "BAB III INFORMASI, DOKUMEN, DAN TANDA TANGAN ELEKTRONIK", "t": "Dalam hal terdapat ketentuan lain selain yang diatur dalam Pasal 5 ayat (4) yang mensyaratkan bahwa suatu informasi harus berbentuk tertulis atau asli, Informasi Elektronik dan/atau Dokumen Elektronik dianggap sah sepanjang informasi yang tercantum di dalamnya dapat diakses, ditampilkan, dijamin keutuhannya, dan dapat dipertanggungjawabkan sehingga menerangkan suatu keadaan."}, {"l": "UU ITE 11/2008", "p": "7", "b": "BAB III INFORMASI, DOKUMEN, DAN TANDA TANGAN ELEKTRONIK", "t": "Setiap Orang yang menyatakan hak, memperkuat hak yang telah ada, atau menolak hak Orang lain berdasarkan adanya Informasi Elektronik dan/atau Dokumen Elektronik harus memastikan bahwa Informasi Elektronik dan/atau Dokumen Elektronik yang ada padanya berasal dari Sistem Elektronik yang memenuhi syarat berdasarkan Peraturan Perundang- undangan."}, {"l": "UU ITE 11/2008", "p": "8", "b": "BAB III INFORMASI, DOKUMEN, DAN TANDA TANGAN ELEKTRONIK", "t": "(1) Kecuali diperjanjikan lain, waktu pengiriman suatu Informasi Elektronik dan/atau Dokumen Elektronik ditentukan pada saat Informasi Elektronik dan/atau Dokumen Elektronik telah dikirim dengan alamat yang benar oleh Pengirim ke suatu Sistem Elektronik yang ditunjuk atau dipergunakan Penerima dan telah memasuki Sistem Elektronik yang berada di luar kendali Pengirim. (2) Kecuali diperjanjikan lain, waktu penerimaan suatu Informasi Elektronik dan/atau Dokumen Elektronik ditentukan pada saat Informasi Elektronik dan/atau Dokumen Elektronik memasuki Sistem Elektronik di bawah kendali Penerima yang berhak. (3) Dalam hal Penerima telah menunjuk suatu Sistem Elektronik tertentu untuk menerima Informasi Elektronik, penerimaan terjadi pada saat Informasi Elektronik dan/atau Dokumen Elektronik memasuki Sistem Elektronik yang ditunjuk. (4) Dalam hal terdapat dua atau lebih sistem informasi yang digunakan dalam pengiriman atau penerimaan Informasi Elektronik dan/atau Dokumen Elektronik, maka: a. waktu pengiriman adalah ketika Informasi Elektronik dan/atau Dokumen Elektronik memasuki sistem informasi pertama yang berada di luar kendali Pengirim; b. waktu penerimaan adalah ketika Informasi …"}, {"l": "UU ITE 11/2008", "p": "9", "b": "BAB III INFORMASI, DOKUMEN, DAN TANDA TANGAN ELEKTRONIK", "t": "Pelaku usaha yang menawarkan produk melalui Sistem Elektronik harus menyediakan informasi yang lengkap dan benar berkaitan dengan syarat kontrak, produsen, dan produk yang ditawarkan."}, {"l": "UU ITE 11/2008", "p": "10", "b": "BAB III INFORMASI, DOKUMEN, DAN TANDA TANGAN ELEKTRONIK", "t": "(1) Setiap pelaku usaha yang menyelenggarakan Transaksi Elektronik dapat disertifikasi oleh Lembaga Sertifikasi Keandalan. (2) Ketentuan mengenai pembentukan Lembaga Sertifikasi Keandalan sebagaimana dimaksud pada ayat (1) diatur dengan Peraturan Pemerintah."}, {"l": "UU ITE 11/2008", "p": "11", "b": "BAB III INFORMASI, DOKUMEN, DAN TANDA TANGAN ELEKTRONIK", "t": "(1) Tanda Tangan Elektronik memiliki kekuatan hukum dan akibat hukum yang sah selama memenuhi persyaratan sebagai berikut: a. data pembuatan Tanda Tangan Elektronik terkait hanya kepada Penanda Tangan; b. data pembuatan Tanda Tangan Elektronik pada saat proses penandatanganan elektronik hanya berada dalam kuasa Penanda Tangan; c. segala perubahan terhadap Tanda Tangan Elektronik yang terjadi setelah waktu penandatanganan dapat diketahui; d. segala perubahan terhadap Informasi Elektronik yang terkait dengan Tanda Tangan Elektronik tersebut setelah waktu penandatanganan dapat diketahui; e. terdapat cara tertentu yang dipakai untuk mengidentifikasi siapa Penandatangannya; dan f. terdapat cara tertentu untuk menunjukkan bahwa Penanda Tangan telah memberikan persetujuan terhadap Informasi Elektronik yang terkait. (2) Ketentuan lebih lanjut tentang Tanda Tangan Elektronik sebagaimana dimaksud pada ayat (1) diatur dengan Peraturan Pemerintah."}, {"l": "UU ITE 11/2008", "p": "12", "b": "BAB III INFORMASI, DOKUMEN, DAN TANDA TANGAN ELEKTRONIK", "t": "(1) Setiap Orang yang terlibat dalam Tanda Tangan Elektronik berkewajiban memberikan pengamanan atas Tanda Tangan Elektronik yang digunakannya. (2) Pengamanan Tanda Tangan Elektronik sebagaimana dimaksud pada ayat (1) sekurang- kurangnya meliputi: a. sistem tidak dapat diakses oleh Orang lain yang tidak berhak; b. Penanda Tangan harus menerapkan prinsip kehati-hatian untuk menghindari penggunaan secara tidak sah terhadap data terkait pembuatan Tanda Tangan Elektronik; c. Penanda Tangan harus tanpa menunda-nunda, menggunakan cara yang dianjurkan oleh penyelenggara Tanda Tangan Elektronik ataupun cara lain yang layak dan sepatutnya harus segera memberitahukan kepada seseorang yang oleh Penanda Tangan dianggap memercayai Tanda Tangan Elektronik atau kepada pihak pendukung layanan Tanda Tangan Elektronik jika: 1. Penanda Tangan mengetahui bahwa data pembuatan Tanda Tangan Elektronik telah dibobol; atau 2. keadaan yang diketahui oleh Penanda Tangan dapat menimbulkan risiko yang berarti, kemungkinan akibat bobolnya data pembuatan Tanda Tangan Elektronik; dan d. dalam hal Sertifikat Elektronik digunakan untuk mendukung Tanda Tangan Elektronik, Penanda Tangan harus memastikan kebenaran …"}, {"l": "UU ITE 11/2008", "p": "13", "b": "Bagian Kesatu", "t": "(1) Setiap Orang berhak menggunakan jasa Penyelenggara Sertifikasi Elektronik untuk pembuatan Tanda Tangan Elektronik. (2) Penyelenggara Sertifikasi Elektronik harus memastikan keterkaitan suatu Tanda Tangan Elektronik dengan pemiliknya. (3) Penyelenggara Sertifikasi Elektronik terdiri atas: a. Penyelenggara Sertifikasi Elektronik Indonesia; dan b. Penyelenggara Sertifikasi Elektronik asing. (4) Penyelenggara Sertifikasi Elektronik Indonesia berbadan hukum Indonesia dan berdomisili di Indonesia. (5) Penyelenggara Sertifikasi Elektronik asing yang beroperasi di Indonesia harus terdaftar di Indonesia. (6) Ketentuan lebih lanjut mengenai Penyelenggara Sertifikasi Elektronik sebagaimana dimaksud pada ayat (3) diatur dengan Peraturan Pemerintah."}, {"l": "UU ITE 11/2008", "p": "14", "b": "Bagian Kesatu", "t": "Penyelenggara Sertifikasi Elektronik sebagaimana dimaksud dalam Pasal 13 ayat (1) sampai dengan ayat (5) harus menyediakan informasi yang akurat, jelas, dan pasti kepada setiap pengguna jasa, yang meliputi: a. metode yang digunakan untuk mengidentifikasi Penanda Tangan; b. hal yang dapat digunakan untuk mengetahui data diri pembuat Tanda Tangan Elektronik; dan c. hal yang dapat digunakan untuk menunjukkan keberlakuan dan keamanan Tanda Tangan Elektronik."}, {"l": "UU ITE 11/2008", "p": "15", "b": "Bagian Kedua", "t": "(1) Setiap Penyelenggara Sistem Elektronik harus menyelenggarakan Sistem Elektronik secara andal dan aman serta bertanggung jawab terhadap beroperasinya Sistem Elektronik sebagaimana mestinya. (2) Penyelenggara Sistem Elektronik bertanggung jawab terhadap Penyelenggaraan Sistem Elektroniknya. (3) Ketentuan sebagaimana dimaksud pada ayat (2) tidak berlaku dalam hal dapat dibuktikan terjadinya keadaan memaksa, kesalahan, dan/atau kelalaian pihak pengguna Sistem Elektronik."}, {"l": "UU ITE 11/2008", "p": "16", "b": "Bagian Kedua", "t": "(1) Sepanjang tidak ditentukan lain oleh undang-undang tersendiri, setiap Penyelenggara Sistem Elektronik wajib mengoperasikan Sistem Elektronik yang memenuhi persyaratan minimum sebagai berikut: a. dapat menampilkan kembali Informasi Elektronik dan/atau Dokumen Elektronik secara utuh sesuai dengan masa retensi yang ditetapkan dengan Peraturan Perundang-undangan; b. dapat melindungi ketersediaan, keutuhan, keotentikan, kerahasiaan, dan keteraksesan Informasi Elektronik dalam Penyelenggaraan Sistem Elektronik tersebut; c. dapat beroperasi sesuai dengan prosedur atau petunjuk dalam Penyelenggaraan Sistem Elektronik tersebut; d. dilengkapi dengan prosedur atau petunjuk yang diumumkan dengan bahasa, informasi, atau simbol yang dapat dipahami oleh pihak yang bersangkutan dengan Penyelenggaraan Sistem Elektronik tersebut; dan e. memiliki mekanisme yang berkelanjutan untuk menjaga kebaruan, kejelasan, dan kebertanggungjawaban prosedur atau petunjuk. (2) Ketentuan lebih lanjut tentang Penyelenggaraan Sistem Elektronik sebagaimana dimaksud pada ayat (1) diatur dengan Peraturan Pemerintah."}, {"l": "UU ITE 11/2008", "p": "17", "b": "BAB V", "t": "(1) Penyelenggaraan Transaksi Elektronik dapat dilakukan dalam lingkup publik ataupun privat. (2) Para pihak yang melakukan Transaksi Elektronik sebagaimana dimaksud pada ayat (1) wajib beriktikad baik dalam melakukan interaksi dan/atau pertukaran Informasi Elektronik dan/atau Dokumen Elektronik selama transaksi berlangsung. (3) Ketentuan lebih lanjut mengenai penyelenggaraan Transaksi Elektronik sebagaimana dimaksud pada ayat (1) diatur dengan Peraturan Pemerintah."}, {"l": "UU ITE 11/2008", "p": "18", "b": "BAB V", "t": "(1) Transaksi Elektronik yang dituangkan ke dalam Kontrak Elektronik mengikat para pihak. (2) Para pihak memiliki kewenangan untuk memilih hukum yang berlaku bagi Transaksi Elektronik internasional yang dibuatnya. (3) Jika para pihak tidak melakukan pilihan hukum dalam Transaksi Elektronik internasional, hukum yang berlaku didasarkan pada asas Hukum Perdata Internasional. (4) Para pihak memiliki kewenangan untuk menetapkan forum pengadilan, arbitrase, atau lembaga penyelesaian sengketa alternatif lainnya yang berwenang menangani sengketa yang mungkin timbul dari Transaksi Elektronik internasional yang dibuatnya. (5) Jika para pihak tidak melakukan pilihan forum sebagaimana dimaksud pada ayat (4), penetapan kewenangan pengadilan, arbitrase, atau lembaga penyelesaian sengketa alternatif lainnya yang berwenang menangani sengketa yang mungkin timbul dari transaksi tersebut, didasarkan pada asas Hukum Perdata Internasional."}, {"l": "UU ITE 11/2008", "p": "19", "b": "BAB V", "t": "Para pihak yang melakukan Transaksi Elektronik harus menggunakan Sistem Elektronik yang disepakati."}, {"l": "UU ITE 11/2008", "p": "20", "b": "BAB V", "t": "(1) Kecuali ditentukan lain oleh para pihak, Transaksi Elektronik terjadi pada saat penawaran transaksi yang dikirim Pengirim telah diterima dan disetujui Penerima. (2) Persetujuan atas penawaran Transaksi Elektronik sebagaimana dimaksud pada ayat (1) harus dilakukan dengan pernyataan penerimaan secara elektronik."}, {"l": "UU ITE 11/2008", "p": "21", "b": "BAB V", "t": "(1) Pengirim atau Penerima dapat melakukan Transaksi Elektronik sendiri, melalui pihak yang dikuasakan olehnya, atau melalui Agen Elektronik. (2) Pihak yang bertanggung jawab atas segala akibat hukum dalam pelaksanaan Transaksi Elektronik sebagaimana dimaksud pada ayat (1) diatur sebagai berikut: a. jika dilakukan sendiri, segala akibat hukum dalam pelaksanaan Transaksi Elektronik menjadi tanggung jawab para pihak yang bertransaksi; b. jika dilakukan melalui pemberian kuasa, segala akibat hukum dalam pelaksanaan Transaksi Elektronik menjadi tanggung jawab pemberi kuasa; atau c. jika dilakukan melalui Agen Elektronik, segala akibat hukum dalam pelaksanaan Transaksi Elektronik menjadi tanggung jawab penyelenggara Agen Elektronik. (3) Jika kerugian Transaksi Elektronik disebabkan gagal beroperasinya Agen Elektronik akibat tindakan pihak ketiga secara langsung terhadap Sistem Elektronik, segala akibat hukum menjadi tanggung jawab penyelenggara Agen Elektronik. (4) Jika kerugian Transaksi Elektronik disebabkan gagal beroperasinya Agen Elektronik akibat kelalaian pihak pengguna jasa layanan, segala akibat hukum menjadi tanggung jawab pengguna jasa layanan. (5) Ketentuan sebagaimana …"}, {"l": "UU ITE 11/2008", "p": "22", "b": "BAB V", "t": "(1) Penyelenggara Agen Elektronik tertentu harus menyediakan fitur pada Agen Elektronik yang dioperasikannya yang memungkinkan penggunanya melakukan perubahan informasi yang masih dalam proses transaksi. (2) Ketentuan lebih lanjut mengenai penyelenggara Agen Elektronik tertentu sebagaimana dimaksud pada ayat (1) diatur dengan Peraturan Pemerintah."}, {"l": "UU ITE 11/2008", "p": "23", "b": "BAB VI NAMA DOMAIN, HAK KEKAYAAN INTELEKTUAL, DAN PERLINDUNGAN HAK PRIBADI", "t": "(1) Setiap penyelenggara negara, Orang, Badan Usaha, dan/atau masyarakat berhak memiliki Nama Domain berdasarkan prinsip pendaftar pertama. (2) Pemilikan dan penggunaan Nama Domain sebagaimana dimaksud pada ayat (1) harus didasarkan pada iktikad baik, tidak melanggar prinsip persaingan usaha secara sehat, dan tidak melanggar hak Orang lain. (3) Setiap penyelenggara negara, Orang, Badan Usaha, atau masyarakat yang dirugikan karena penggunaan Nama Domain secara tanpa hak oleh Orang lain, berhak mengajukan gugatan pembatalan Nama Domain dimaksud."}, {"l": "UU ITE 11/2008", "p": "24", "b": "BAB VI NAMA DOMAIN, HAK KEKAYAAN INTELEKTUAL, DAN PERLINDUNGAN HAK PRIBADI", "t": "(1) Pengelola Nama Domain adalah Pemerintah dan/atau masyarakat. (2) Dalam hal terjadi perselisihan pengelolaan Nama Domain oleh masyarakat, Pemerintah berhak mengambil alih sementara pengelolaan Nama Domain yang diperselisihkan. (3) Pengelola Nama Domain yang berada di luar wilayah Indonesia dan Nama Domain yang diregistrasinya diakui keberadaannya sepanjang tidak bertentangan dengan Peraturan Perundang-undangan. (4) Ketentuan lebih lanjut mengenai pengelolaan Nama Domain sebagaimana dimaksud pada ayat (1), ayat (2), dan ayat (3) diatur dengan Peraturan Pemerintah."}, {"l": "UU ITE 11/2008", "p": "25", "b": "BAB VI NAMA DOMAIN, HAK KEKAYAAN INTELEKTUAL, DAN PERLINDUNGAN HAK PRIBADI", "t": "Informasi Elektronik dan/atau Dokumen Elektronik yang disusun menjadi karya intelektual, situs internet, dan karya intelektual yang ada di dalamnya dilindungi sebagai Hak Kekayaan Intelektual berdasarkan ketentuan Peraturan Perundang-undangan."}, {"l": "UU ITE 11/2008", "p": "26", "b": "BAB VI NAMA DOMAIN, HAK KEKAYAAN INTELEKTUAL, DAN PERLINDUNGAN HAK PRIBADI", "t": "(1) Kecuali ditentukan lain oleh Peraturan Perundang-undangan, penggunaan setiap informasi melalui media elektronik yang menyangkut data pribadi seseorang harus dilakukan atas persetujuan Orang yang bersangkutan. (2) Setiap Orang yang dilanggar haknya sebagaimana dimaksud pada ayat (1) dapat mengajukan gugatan atas kerugian yang ditimbulkan berdasarkan Undang-Undang ini."}, {"l": "UU ITE 11/2008", "p": "27", "b": "BAB VII PERBUATAN YANG DILARANG", "t": "(1) Setiap Orang dengan sengaja dan tanpa hak mendistribusikan dan/atau mentransmisikan dan/atau membuat dapat diaksesnya Informasi Elektronik dan/atau Dokumen Elektronik yang memiliki muatan yang melanggar kesusilaan. (2) Setiap Orang dengan sengaja dan tanpa hak mendistribusikan dan/atau mentransmisikan dan/atau membuat dapat diaksesnya Informasi Elektronik dan/atau Dokumen Elektronik yang memiliki muatan perjudian. (3) Setiap Orang dengan sengaja dan tanpa hak mendistribusikan dan/atau mentransmisikan dan/atau membuat dapat diaksesnya Informasi Elektronik dan/atau Dokumen Elektronik yang memiliki muatan penghinaan dan/atau pencemaran nama baik. (4) Setiap Orang dengan sengaja dan tanpa hak mendistribusikan dan/atau mentransmisikan dan/atau membuat dapat diaksesnya Informasi Elektronik dan/atau Dokumen Elektronik yang memiliki muatan pemerasan dan/atau pengancaman."}, {"l": "UU ITE 11/2008", "p": "28", "b": "BAB VII PERBUATAN YANG DILARANG", "t": "(1) Setiap Orang dengan sengaja dan tanpa hak menyebarkan berita bohong dan menyesatkan yang mengakibatkan kerugian konsumen dalam Transaksi Elektronik. (2) Setiap Orang dengan sengaja dan tanpa hak menyebarkan informasi yang ditujukan untuk menimbulkan rasa kebencian atau permusuhan individu dan/atau kelompok masyarakat tertentu berdasarkan atas suku, agama, ras, dan antargolongan (SARA)."}, {"l": "UU ITE 11/2008", "p": "29", "b": "BAB VII PERBUATAN YANG DILARANG", "t": "Setiap Orang dengan sengaja dan tanpa hak mengirimkan Informasi Elektronik dan/atau Dokumen Elektronik yang berisi ancaman kekerasan atau menakut-nakuti yang ditujukan secara pribadi."}, {"l": "UU ITE 11/2008", "p": "30", "b": "BAB VII PERBUATAN YANG DILARANG", "t": "(1) Setiap Orang dengan sengaja dan tanpa hak atau melawan hukum mengakses Komputer dan/atau Sistem Elektronik milik Orang lain dengan cara apa pun. (2) Setiap Orang dengan sengaja dan tanpa hak atau melawan hukum mengakses Komputer dan/atau Sistem Elektronik dengan cara apa pun dengan tujuan untuk memperoleh Informasi Elektronik dan/atau Dokumen Elektronik. (3) Setiap Orang dengan sengaja dan tanpa hak atau melawan hukum mengakses Komputer dan/atau Sistem Elektronik dengan cara apa pun dengan melanggar, menerobos, melampaui, atau menjebol sistem pengamanan."}, {"l": "UU ITE 11/2008", "p": "31", "b": "BAB VII PERBUATAN YANG DILARANG", "t": "(1) Setiap Orang dengan sengaja dan tanpa hak atau melawan hukum melakukan intersepsi atau penyadapan atas Informasi Elektronik dan/atau Dokumen Elektronik dalam suatu Komputer dan/atau Sistem Elektronik tertentu milik Orang lain. (2) Setiap Orang dengan sengaja dan tanpa hak atau melawan hukum melakukan intersepsi atas transmisi Informasi Elektronik dan/atau Dokumen Elektronik yang tidak bersifat publik dari, ke, dan di dalam suatu Komputer dan/atau Sistem Elektronik tertentu milik Orang lain, baik yang tidak menyebabkan perubahan apa pun maupun yang menyebabkan adanya perubahan, penghilangan, dan/atau penghentian Informasi Elektronik dan/atau Dokumen Elektronik yang sedang ditransmisikan. (3) Kecuali intersepsi sebagaimana dimaksud pada ayat (1) dan ayat (2), intersepsi yang dilakukan dalam rangka penegakan hukum atas permintaan kepolisian, kejaksaan, dan/atau institusi penegak hukum lainnya yang ditetapkan berdasarkan undang-undang. (4) Ketentuan lebih lanjut mengenai tata cara intersepsi sebagaimana dimaksud pada ayat (3) diatur dengan Peraturan Pemerintah."}, {"l": "UU ITE 11/2008", "p": "32", "b": "BAB VII PERBUATAN YANG DILARANG", "t": "(1) Setiap Orang dengan sengaja dan tanpa hak atau melawan hukum dengan cara apa pun mengubah, menambah, mengurangi, melakukan transmisi, merusak, menghilangkan, memindahkan, menyembunyikan suatu Informasi Elektronik dan/atau Dokumen Elektronik milik Orang lain atau milik publik. (2) Setiap Orang dengan sengaja dan tanpa hak atau melawan hukum dengan cara apa pun memindahkan atau mentransfer Informasi Elektronik dan/atau Dokumen Elektronik kepada Sistem Elektronik Orang lain yang tidak berhak. (3) Terhadap perbuatan sebagaimana dimaksud pada ayat (1) yang mengakibatkan terbukanya suatu Informasi Elektronik dan/atau Dokumen Elektronik yang bersifat rahasia menjadi dapat diakses oleh publik dengan keutuhan data yang tidak sebagaimana mestinya."}, {"l": "UU ITE 11/2008", "p": "33", "b": "BAB VII PERBUATAN YANG DILARANG", "t": "Setiap Orang dengan sengaja dan tanpa hak atau melawan hukum melakukan tindakan apa pun yang berakibat terganggunya Sistem Elektronik dan/atau mengakibatkan Sistem Elektronik menjadi tidak bekerja sebagaimana mestinya."}, {"l": "UU ITE 11/2008", "p": "34", "b": "BAB VII PERBUATAN YANG DILARANG", "t": "(1) Setiap Orang dengan sengaja dan tanpa hak atau melawan hukum memproduksi, menjual, mengadakan untuk digunakan, mengimpor, mendistribusikan, menyediakan, atau memiliki: a. perangkat keras atau perangkat lunak Komputer yang dirancang atau secara khusus dikembangkan untuk memfasilitasi perbuatan sebagaimana dimaksud dalam Pasal 27 sampai dengan Pasal 33; b. sandi lewat Komputer, Kode Akses, atau hal yang sejenis dengan itu yang ditujukan agar Sistem Elektronik menjadi dapat diakses dengan tujuan memfasilitasi perbuatan sebagaimana dimaksud dalam Pasal 27 sampai dengan Pasal 33. (2) Tindakan sebagaimana dimaksud pada ayat (1) bukan tindak pidana jika ditujukan untuk melakukan kegiatan penelitian, pengujian Sistem Elektronik, untuk perlindungan Sistem Elektronik itu sendiri secara sah dan tidak melawan hukum."}, {"l": "UU ITE 11/2008", "p": "35", "b": "BAB VII PERBUATAN YANG DILARANG", "t": "Setiap Orang dengan sengaja dan tanpa hak atau melawan hukum melakukan manipulasi, penciptaan, perubahan, penghilangan, pengrusakan Informasi Elektronik dan/atau Dokumen Elektronik dengan tujuan agar Informasi Elektronik dan/atau Dokumen Elektronik tersebut dianggap seolah-olah data yang otentik."}, {"l": "UU ITE 11/2008", "p": "36", "b": "BAB VII PERBUATAN YANG DILARANG", "t": "Setiap Orang dengan sengaja dan tanpa hak atau melawan hukum melakukan perbuatan sebagaimana dimaksud dalam Pasal 27 sampai dengan Pasal 34 yang mengakibatkan kerugian bagi Orang lain."}, {"l": "UU ITE 11/2008", "p": "37", "b": "BAB VII PERBUATAN YANG DILARANG", "t": "Setiap Orang dengan sengaja melakukan perbuatan yang dilarang sebagaimana dimaksud dalam Pasal 27 sampai dengan Pasal 36 di luar wilayah Indonesia terhadap Sistem Elektronik yang berada di wilayah yurisdiksi Indonesia."}, {"l": "UU ITE 11/2008", "p": "38", "b": "BAB VIII PENYELESAIAN SENGKETA", "t": "(1) Setiap Orang dapat mengajukan gugatan terhadap pihak yang menyelenggarakan Sistem Elektronik dan/atau menggunakan Teknologi Informasi yang menimbulkan kerugian. (2) Masyarakat dapat mengajukan gugatan secara perwakilan terhadap pihak yang menyelenggarakan Sistem Elektronik dan/atau menggunakan Teknologi Informasi yang berakibat merugikan masyarakat, sesuai dengan ketentuan Peraturan Perundang- undangan."}, {"l": "UU ITE 11/2008", "p": "39", "b": "BAB VIII PENYELESAIAN SENGKETA", "t": "(1) Gugatan perdata dilakukan sesuai dengan ketentuan Peraturan Perundang-undangan. (2) Selain penyelesaian gugatan perdata sebagaimana dimaksud pada ayat (1), para pihak dapat menyelesaikan sengketa melalui arbitrase, atau lembaga penyelesaian sengketa alternatif lainnya sesuai dengan ketentuan Peraturan Perundang-undangan."}, {"l": "UU ITE 11/2008", "p": "40", "b": "BAB IX PERAN PEMERINTAH DAN PERAN MASYARAKAT", "t": "(1) Pemerintah memfasilitasi pemanfaatan Teknologi Informasi dan Transaksi Elektronik sesuai dengan ketentuan Peraturan Perundang-undangan. (2) Pemerintah melindungi kepentingan umum dari segala jenis gangguan sebagai akibat penyalahgunaan Informasi Elektronik dan Transaksi Elektronik yang mengganggu ketertiban umum, sesuai dengan ketentuan Peraturan Perundang-undangan. (3) Pemerintah menetapkan instansi atau institusi yang memiliki data elektronik strategis yang wajib dilindungi. (4) Instansi atau institusi sebagaimana dimaksud pada ayat (3) harus membuat Dokumen Elektronik dan rekam cadang elektroniknya serta menghubungkannya ke pusat data tertentu untuk kepentingan pengamanan data. (5) Instansi atau institusi lain selain diatur pada ayat (3) membuat Dokumen Elektronik dan rekam cadang elektroniknya sesuai dengan keperluan perlindungan data yang dimilikinya. (6) Ketentuan lebih lanjut mengenai peran Pemerintah sebagaimana dimaksud pada ayat (1), ayat (2), dan ayat (3) diatur dengan Peraturan Pemerintah."}, {"l": "UU ITE 11/2008", "p": "41", "b": "BAB IX PERAN PEMERINTAH DAN PERAN MASYARAKAT", "t": "(1) Masyarakat dapat berperan meningkatkan pemanfaatan Teknologi Informasi melalui penggunaan dan Penyelenggaraan Sistem Elektronik dan Transaksi Elektronik sesuai dengan ketentuan Undang-Undang ini. (2) Peran masyarakat sebagaimana dimaksud pada ayat (1) dapat diselenggarakan melalui lembaga yang dibentuk oleh masyarakat. (3) Lembaga sebagaimana dimaksud pada ayat (2) dapat memiliki fungsi konsultasi dan mediasi."}, {"l": "UU ITE 11/2008", "p": "42", "b": "BAB X", "t": "Penyidikan terhadap tindak pidana sebagaimana dimaksud dalam Undang-Undang ini, dilakukan berdasarkan ketentuan dalam Hukum Acara Pidana dan ketentuan dalam Undang- Undang ini."}, {"l": "UU ITE 11/2008", "p": "43", "b": "BAB X", "t": "(1) Selain Penyidik Pejabat Polisi Negara Republik Indonesia, Pejabat Pegawai Negeri Sipil tertentu di lingkungan Pemerintah yang lingkup tugas dan tanggung jawabnya di bidang Teknologi Informasi dan Transaksi Elektronik diberi wewenang khusus sebagai penyidik sebagaimana dimaksud dalam Undang-Undang tentang Hukum Acara Pidana untuk melakukan penyidikan tindak pidana di bidang Teknologi Informasi dan Transaksi Elektronik. (2) Penyidikan di bidang Teknologi Informasi dan Transaksi Elektronik sebagaimana dimaksud pada ayat (1) dilakukan dengan memperhatikan perlindungan terhadap privasi, kerahasiaan, kelancaran layanan publik, integritas data, atau keutuhan data sesuai dengan ketentuan Peraturan Perundang-undangan. (3) Penggeledahan dan/atau penyitaan terhadap sistem elektronik yang terkait dengan dugaan tindak pidana harus dilakukan atas izin ketua pengadilan negeri setempat. (4) Dalam melakukan penggeledahan dan/atau penyitaan sebagaimana dimaksud pada ayat (3), penyidik wajib menjaga terpeliharanya kepentingan pelayanan umum. (5) Penyidik Pegawai Negeri Sipil sebagaimana dimaksud pada ayat (1) berwenang: a. menerima laporan atau pengaduan dari seseorang tentang adanya tindak …"}, {"l": "UU ITE 11/2008", "p": "44", "b": "BAB X", "t": "Alat bukti penyidikan, penuntutan dan pemeriksaan di sidang pengadilan menurut ketentuan Undang-Undang ini adalah sebagai berikut: a. alat bukti sebagaimana dimaksud dalam ketentuan Perundang-undangan; dan b. alat bukti lain berupa Informasi Elektronik dan/atau Dokumen Elektronik sebagaimana dimaksud dalam Pasal 1 angka 1 dan angka 4 serta Pasal 5 ayat (1), ayat (2), dan ayat (3)."}, {"l": "UU ITE 11/2008", "p": "45", "b": "BAB XI KETENTUAN PIDANA", "t": "(1) Setiap Orang yang memenuhi unsur sebagaimana dimaksud dalam Pasal 27 ayat (1), ayat (2), ayat (3), atau ayat (4) dipidana dengan pidana penjara paling lama 6 (enam) tahun dan/atau denda paling banyak Rp1.000.000.000,00 (satu miliar rupiah). (2) Setiap Orang yang memenuhi unsur sebagaimana dimaksud dalam Pasal 28 ayat (1) atau ayat (2) dipidana dengan pidana penjara paling lama 6 (enam) tahun dan/atau denda paling banyak Rp1.000.000.000,00 (satu miliar rupiah). (3) Setiap Orang yang memenuhi unsur sebagaimana dimaksud dalam Pasal 29 dipidana dengan pidana penjara paling lama 12 (dua belas) tahun dan/atau denda paling banyak Rp2.000.000.000,00 (dua miliar rupiah)."}, {"l": "UU ITE 11/2008", "p": "46", "b": "BAB XI KETENTUAN PIDANA", "t": "(1) Setiap Orang yang memenuhi unsur sebagaimana dimaksud dalam Pasal 30 ayat (1) dipidana dengan pidana penjara paling lama 6 (enam) tahun dan/atau denda paling banyak Rp600.000.000,00 (enam ratus juta rupiah). (2) Setiap Orang yang memenuhi unsur sebagaimana dimaksud dalam Pasal 30 ayat (2) dipidana dengan pidana penjara paling lama 7 (tujuh) tahun dan/atau denda paling banyak Rp700.000.000,00 (tujuh ratus juta rupiah). (3) Setiap Orang yang memenuhi unsur sebagaimana dimaksud dalam Pasal 30 ayat (3) dipidana dengan pidana penjara paling lama 8 (delapan) tahun dan/atau denda paling banyak Rp800.000.000,00 (delapan ratus juta rupiah)."}, {"l": "UU ITE 11/2008", "p": "47", "b": "BAB XI KETENTUAN PIDANA", "t": "Setiap Orang yang memenuhi unsur sebagaimana dimaksud dalam Pasal 31 ayat (1) atau ayat (2) dipidana dengan pidana penjara paling lama 10 (sepuluh) tahun dan/atau denda paling banyak Rp800.000.000,00 (delapan ratus juta rupiah)."}, {"l": "UU ITE 11/2008", "p": "48", "b": "BAB XI KETENTUAN PIDANA", "t": "(1) Setiap Orang yang memenuhi unsur sebagaimana dimaksud dalam Pasal 32 ayat (1) dipidana dengan pidana penjara paling lama 8 (delapan) tahun dan/atau denda paling banyak Rp2.000.000.000,00 (dua miliar rupiah). (2) Setiap Orang yang memenuhi unsur sebagaimana dimaksud dalam Pasal 32 ayat (2) dipidana dengan pidana penjara paling lama 9 (sembilan) tahun dan/atau denda paling banyak Rp3.000.000.000,00 (tiga miliar rupiah). (3) Setiap Orang yang memenuhi unsur sebagaimana dimaksud dalam Pasal 32 ayat (3) dipidana dengan pidana penjara paling lama 10 (sepuluh) tahun dan/atau denda paling banyak Rp5.000.000.000,00 (lima miliar rupiah)."}, {"l": "UU ITE 11/2008", "p": "49", "b": "BAB XI KETENTUAN PIDANA", "t": "Setiap Orang yang memenuhi unsur sebagaimana dimaksud dalam Pasal 33, dipidana dengan pidana penjara paling lama 10 (sepuluh) tahun dan/atau denda paling banyak Rp10.000.000.000,00 (sepuluh miliar rupiah)."}, {"l": "UU ITE 11/2008", "p": "50", "b": "BAB XI KETENTUAN PIDANA", "t": "Setiap Orang yang memenuhi unsur sebagaimana dimaksud dalam Pasal 34 ayat (1) dipidana dengan pidana penjara paling lama 10 (sepuluh) tahun dan/atau denda paling banyak Rp10.000.000.000,00 (sepuluh miliar rupiah)."}, {"l": "UU ITE 11/2008", "p": "51", "b": "BAB XI KETENTUAN PIDANA", "t": "(1) Setiap Orang yang memenuhi unsur sebagaimana dimaksud dalam Pasal 35 dipidana dengan pidana penjara paling lama 12 (dua belas) tahun dan/atau denda paling banyak Rp12.000.000.000,00 (dua belas miliar rupiah). (2) Setiap Orang yang memenuhi unsur sebagaimana dimaksud dalam Pasal 36 dipidana dengan pidana penjara paling lama 12 (dua belas) tahun dan/atau denda paling banyak Rp12.000.000.000,00 (dua belas miliar rupiah)."}, {"l": "UU ITE 11/2008", "p": "52", "b": "BAB XI KETENTUAN PIDANA", "t": "(1) Dalam hal tindak pidana sebagaimana dimaksud dalam Pasal 27 ayat (1) menyangkut kesusilaan atau eksploitasi seksual terhadap anak dikenakan pemberatan sepertiga dari pidana pokok. (2) Dalam hal perbuatan sebagaimana dimaksud dalam Pasal 30 sampai dengan Pasal 37 ditujukan terhadap Komputer dan/atau Sistem Elektronik serta Informasi Elektronik dan/atau Dokumen Elektronik milik Pemerintah dan/atau yang digunakan untuk layanan publik dipidana dengan pidana pokok ditambah sepertiga. (3) Dalam hal perbuatan sebagaimana dimaksud dalam Pasal 30 sampai dengan Pasal 37 ditujukan terhadap Komputer dan/atau Sistem Elektronik serta Informasi Elektronik dan/atau Dokumen Elektronik milik Pemerintah dan/atau badan strategis termasuk dan tidak terbatas pada lembaga pertahanan, bank sentral, perbankan, keuangan, lembaga internasional, otoritas penerbangan diancam dengan pidana maksimal ancaman pidana pokok masing-masing Pasal ditambah dua pertiga. (4) Dalam hal tindak pidana sebagaimana dimaksud dalam Pasal 27 sampai dengan Pasal 37 dilakukan oleh korporasi dipidana dengan pidana pokok ditambah dua pertiga."}, {"l": "UU ITE 11/2008", "p": "53", "b": "BAB XII KETENTUAN PERALIHAN", "t": "Pada saat berlakunya Undang-Undang ini, semua Peraturan Perundang-undangan dan kelembagaan yang berhubungan dengan pemanfaatan Teknologi Informasi yang tidak bertentangan dengan Undang-Undang ini dinyatakan tetap berlaku."}, {"l": "UU ITE 11/2008", "p": "54", "b": "BAB XIII KETENTUAN PENUTUP", "t": "(1) Undang-Undang ini mulai berlaku pada tanggal diundangkan. (2) Peraturan Pemerintah harus sudah ditetapkan paling lama 2 (dua) tahun setelah diundangkannya Undang-Undang ini. penempatannya dalam Lembaran Negara Republik Indonesia. pada tanggal 21 April 2008 DR. H. SUSILO BAMBANG YUDHOYONO pada tanggal 21 April 2008 ANDI MATTALATA BIDANG PERUNDANG-UNDANGAN, MUHAMMAD SAPTA MURTI"}, {"l": "UU ITE 1/2024", "p": "1", "b": "UU ITE 1/2024", "t": "Beberapa ketentuan dalam Undang-Undang Nomor 11 Tahun 20O8 tentang Informasi dan Transaksi Elektronik (Lembaran Negara Republik Indonesia Tahun 2008 Nomor 58, Tambahan kmbaran Negara Republik Indonesia Nomor 4843) sebagaimana telah diubah dengan Undang- Undang Nomor 19 Tahun 2016 tentang Perubahan atas Undang-Undang Nomor 11 Tahun 2008 tentang Informasi dan Transaksi Elektronik (Lembarein Negara Republik Indonesia Tahun 2016 Nomor 251, Tambahan Lembaran Negara Republik Indonesia Nomor 5952) diubah sebagai berikut: 1. Ketentuan. . . J REPITBLIK INDONESI.A 1 Ketentuan ayat (41 Pasal 5 serta penjelasan ayat (1) dan ayat (4) Pasal 5 diubah sehingga Pasal 5 berbunyi sebagai berikut:"}, {"l": "UU ITE 1/2024", "p": "5", "b": "UU ITE 1/2024", "t": "(1) Informasi Elektronik dan/ atau Dokumen Elektronik dan/ atau hasil cetaknya merupakan alat bukti hukum yang sah. (2) Informasi Elektronik dan/ atau Dokumen Elektronik dan/ atau hasil cetaknya sebagaimana dimaksud pada ayat (1) merupakan perluasan dari alat bukti yang sah sesuai dengan Hukum Acara yang berlaku di Indonesia. (3) Informasi Elektronik dan/ atau Dokumen Elektronik dinyatakan sah apabila menggunakan Sistem Elektronik sesuai dengan ketentuan yang diatur dalam Undang-Undang ini. (4) Ketentuan mengenai Informasi Elektronik dan/atau Dokumen Elektronik sebagaimana dimaksud pada ayat (l) tidak berlaku dalam hal diatur lain dalam Undang-Undang. 2 Ketentuan ayat (3), ayat (41, ayat (5), dan ayat (6) Pasal 13 serta penjelasan ayat (5) Pasal 13 diubah sehingga Pasal 13 berbunyi sebagai berikut:"}, {"l": "UU ITE 1/2024", "p": "13", "b": "UU ITE 1/2024", "t": "(1) Setiap Orang berhak menggunakan Jasa Penyelenggara Sertifikasi Elektronik untuk pembuatan Tanda Tangan Elektronik. (21 Penyelenggara Sertilikasi Elektronik harus memastikan keterkaitan suatu Tanda Tangan Elektronik dengan pemiliknya. (3) Penyelenggara Sertifikasi Elektronik yang beroperasi di Indonesia harus berbadan hukum Indonesia dan berdomisili di Indonesia. (4) Ketentuan . . . i IHirEftXTIf.T.TIfdfA (4) Ketentuan sebagaimana dimaksud pada ayat (3) dikecualikan dalam hal penyelenggaraan layanan yang menggunakan Sertifikat Elektronik belum tersedia di Indonesia. (5) Pengakuan timbal balik (mutual recognition) untuk mengenali Sertifikat Elektronik antarnegara didasarkan pada perjanjian kerja sEuna. (6) Ketentuan lebih lanjut mengenai Penyelenggara Sertifikasi Elektronik sebagaimana dimaksud pada ayat (3), ayat (4), dan ayat (5) diatur dalam Peraturan Pemerintah. 3 Di antara Pasal 13 dan Pasal 14 disisipkan I (satu) pasal, yakni Pasal 13A sehingga berbunyi sebagai berikut:"}, {"l": "UU ITE 1/2024", "p": "13A", "b": "UU ITE 1/2024", "t": "(1) Penyelenggara Sertifikasi Elektronik dapat menyelenggarakan layanan berupa: a. Tanda Tangan Elektronik; b. segel elektronik; c. penanda waktu elektronik; d. layanan pengiriman elektronik tercatat; e. autentikasi situs web; f. preservasi Tanda Tangan Elektronik dan/ atau segel elektronik; g. identitas digital; dan/atau h. layanan lain yang menggunakan Sertifikat Elektronik. (21 Ketentuan lebih lanjut mengenai penyelenggaraan layanan sebagaimana dimaksqd pada ayat (1) diatur dalam Peraturan Pemerintah. 4. Penjelasan . . . .,( NEPLTBLIK INDONESIA 4. Penjelasan ayat (1) dan ayat (2) Pasal 15 diubah sebagaimana tercantum dalam penjelasan. 5. Di antara Pasal 16 dan Pasal 17 disisipkan 2 (dua) pasal, yakni Pasal 16A dan Pasal 168 sehingga berbunyi sebagai berikut:"}, {"l": "UU ITE 1/2024", "p": "16A", "b": "UU ITE 1/2024", "t": "(1) Penyelenggara Sistem Elektronik wajib memberikan pelindungan bagi anak yang menggunakan atau mengakses Sistem Elektronik. (21 Pelindungan sebagaimana dimaksud pada ayat (1) meliputi pelindungan terhadap hak anak sebagaimana dimaksud dalam peraturan perundang-undangan mengenai penggunaan produk, layanan, dan fitur yang dikembangkan dan diselenggarakan oleh Penyelenggara Sistem Elektronik. (3) Dalam memberikan produk, layanan, dan fitur bagr anak, Penyelenggara Sistem Elektronik wajib menerapkan teknologi dan langkah teknis operasional untuk memberikan pelindungan sebagaimana dimaksud pada ayat (1) dari tahap pengembangan sampai dengan tahap Penyelenggaraan Sistem Elektronik. (4) Dalam memberikan pelindungan sebagaimana dimaksud pada ayat (1), Penyelenggara Sistem Elektronik wajib menyediakan : a. informasi mengenai batasan minimum usia anak yang dapat menggunakan produk atau layanannya; b. mekanisme verifikasi pengguna anak; dan c. mekanisme pelaporan penyalahgunaan produk, layanan, dan fitur yang melanggar atau berpotensi melanggar hak anak. (5) Ketentuan . . . ihtrEILtriIi REPI'BUK INDONESIA (5) Ketentuan lebih lanjut mengenai pelindungan sebagaimana dimaksud pada ayat (1) …"}, {"l": "UU ITE 1/2024", "p": "168", "b": "UU ITE 1/2024", "t": "(1) Pelanggaran terhadap ketentuan sebagaimana dimaksud dalam Pasal 16A dikenai sanksi administratif. (21 Sanksi administratif sebagaimana dimaksud pada ayat (1) dapat berupa: a. teguran tertulis; b. dendaadministratif; c. penghentian sementara; dan/atau d. pemutusan Akses. (3) Ketentuan lebih lanjut mengenai pengenaan sanksi administratif sebagaimana dimaksud pada ayat (1) dan ayat (21 diatur dalam Peraturan Pemerintah. 6 Ketentuan ayat (1) Pasal 17 diubah, dan di antara ayal l2l dan ayat (3) Pasal 17 disisipkan 1 (satu) ayat, yakni ayat (2a1, dar ketentuan ayat (3) Pasal 17 diubah sehingga Pasal 17 berbunyi sebagai berikut:"}, {"l": "UU ITE 1/2024", "p": "17", "b": "UU ITE 1/2024", "t": "(1) Penyelenggaraan Transaksi Elektronik dapat dilakukan dalam lingkup publik atau privat. (2) Para pihak yang melakukan Transaksi Elektronik sebagaimana dimaksud pada ayat (1) wajib beriktikad baik dalam melakukan interaksi dan/ atau pertukaran Informasi Elektronik dan/ atau Dokumen Elektronik selama transaksi berlangsung. (2a) Transaksi . . . :Ili iirl. IIIilNIinIiiEIA (2a) Transaksi Elektronik yang memiliki risiko tinggi bagi para pihak menggunakan Tanda Tangan Elektronik yang diamankan dengan Sertilikat Elektronik. (3) Ketentuan lebih lanjut mengenai irenyelenggaraan Transaksi Elektronik sebagaimana dimaksud pada ayat (ll, ayat (21, dan ayat (2al diatur dalam Peraturan Pemerintah. 7 Di antara Pasal 18 dan Pasal 19 disisipkan I (satu) pasal, yakni Pasal 18A sehingga berbunyi sebagai berikut:"}, {"l": "UU ITE 1/2024", "p": "18A", "b": "UU ITE 1/2024", "t": "(1) Kontrak Elektronik internasional yang menggunakan klausula baku yang dibuat oleh Penyelenggara Sistem Elektronik diatur dengan hukum Indonesia dalam hal: a. pengguna layanan Penyelenggara Sistem Elektronik sebagai salah satu pihak dalam Transaksi Elektronik berasal dari Indonesia dan memberikan persetqjuannya dari atau dalam yurisdiksi Indonesia; b. tempat pelaksanaan kontrak ada di wilayah Indonesia; dan/ atau c. Penyelenggara Sistem Elektronik memiliki tempat usaha atau melakukan kegiatan usaha di wilayah Indonesia. (21 Kontrak Elektronik sebagaimana dimaksud pada ayat (1) menggunakan bahasa yang sederhana, jelas, dan mudah dipahami, serta menjunjung prinsip iktikad baik dan transparansi. 8 Ketentuan Pasal 27 diubah sehingga berbunyi sebagai berikut: PasaJ2T ... -l LIK iNf.ftIf+TA"}, {"l": "UU ITE 1/2024", "p": "27", "b": "UU ITE 1/2024", "t": "(1) Setiap Orang dengan sengaja dan tanpa hak menyiarkan, mempertunjukkan, mendistribusikan, mentransmisikan, dan/atau membuat dapat diaksesnya Informasi Elektronik dan/ atau Dokumen Elektronik yang memiliki muatan yang melanggar kesusilaan untuk diketahui umum. (21 Setiap Orang dengan sengaja dan tanpa hak mendistribusikan, mentransmisikan, dan/atau membuat dapat diaksesnya Informasi Elektronik dan/atau Dokumen Elektronik yang memiliki muatan perjudian. 9 Di antara Pasal 27 dan Pasal 28 disisipkan 2 (dua) pasal, yakni Pasil 27A dan Pasal 27B sehingga berbunyi sebagai berikut: Pasal2TA Setiap Orang dengan sengaja menyerang kehormatan atau nama baik orang lain dengan cara menuduhkan suatu hal, dengan maksud supaya hal tersebut diketahui umum dalam bentuk Informasi Elektronik dan/ atau Dokumen Elektronik yang dilakukan melalui Sistem Elektronik."}, {"l": "UU ITE 1/2024", "p": "278", "b": "UU ITE 1/2024", "t": "(1) Setiap Orang dengan sengaja dan tanpa hak mendistribusikan dan/atau mentransmisikan Informasi Elektronik dan/atau Dokumen Elektronik, dengan maksud untuk menguntungkan diri sendiri atau orang lain secara melawan hukum, memaksa orang dengan ancaman kekerasan untuk: a. memberikan suatu barang, yang sebagian atau seluruhnya milik orang tersebut atau milik orang lain; atau b. memberi . . . NEPUELIK INDONESTA b memberi utang, membuat pengakuan utang, atau menghapuskan piutang. (21 Setiap Orang dengan sengaja dan tanpa hak mendistribusikan dan/atau mentransmisikan Informasi Elektronik dan/atau Dokumen Elektronik, dengan maksud untuk menguntungkan diri sendiri atau orang lain secara melawan hukum, dengan ancarnan pencemaran atau dengan ancaman akan membuka rahasia, memaksa orang supaya: a. memberikan suatu barang yang sebagial atau seluruhnya milik orang tersebut atau milik orang lain; atau b. memberi utang, membuat pengakuan utang, atau menghapuskan piutang. 10. Ketentuan Pasal 28 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU ITE 1/2024", "p": "28", "b": "UU ITE 1/2024", "t": "(1) Setiap Orang dengan sengaja dan/atau mentransmisikan Informasi Elektronik dan/ atau Dokumen Elektronik yang berisi pemberitahuan bohong atau informasi menyesatkan yang mengakibatkan kerugian materiel bagi konsumen dalam Transaksi Elektronik. (21 Setiap Orang dengan sengaja dan tanpa hak mendistribusikan dan/atau mentransmisikan Informasi Elektronik dan/atau Dokumen Elektronik yang sifatnya menghasut, mengajak, atau memengaruhi orang lain sehingga menimbulkan rasa kebencian atau permusuhan terhadap individu dan/atau kelompok masyarakat tertentu berdasarkan ras, kebangsaan, etnis, warna kulit, agama, kepercayaan, jenis kelamin, disabilitas mental, atau disabilitas fisik. (3) Setiap. . . tr{irEtfirrrrd{n{{n (3) Setiap Orang dengan sengaja menyebarkan Informasi Elektronik dan/atau Dokumen Elektronik yang diketahuinya memuat pemberitahuan bohong yang menimbulkan kerusuhan di masyarakat. 11. Ketentuan Pasal 29 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU ITE 1/2024", "p": "29", "b": "UU ITE 1/2024", "t": "Setiap Orang dengan sengaja dan tanpa hak Informasi Elektronik dan/atau Dokumen Elektronik secara langsung kepada korban yang berisi ancam.rn kekerasan dan/ atau menakut- nakuti. 12. Ketentuan Pasal 36 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU ITE 1/2024", "p": "36", "b": "UU ITE 1/2024", "t": "Setiap Orang dengan sengaja dan tanpa hak melakukan perbuatan sebagaimana dimaksud dalam Pasal 30 sampai dengan Pasal 34 yang mengakibatkan kerugian materiel bagi Orang lain. 13. Di antara ayat (2b) dan ayat (3) Pasal 40 disisipkan 2 (dua) ayat, yakni ayat l2cl dan ayat (2d), ketentuan ayat (2b), ayat (5), dan ayat (6) Pasal 4O diubah, serta penjelasan ayat (2b) Pasal 40 diubah sehingga Pasal 40 berbunyi sebagai berikut:"}, {"l": "UU ITE 1/2024", "p": "40", "b": "UU ITE 1/2024", "t": "(l) Pemerintah memfasilitasi pemanfaatan Teknologi Informasi dan Transaksi Elektronik sesuai dengan ketentuan peraturan perundang- undangan. (2) Pemerintah . . . ;i'l LIK (21 Pemerintah melindungi kepentingan umum dari segala jenis gangguan sebagai akibat penyalahgunaan Informasi Elektronik dan Transaksi Elektronik yang mengganggu ketertiban umum, sesuai dengan ketentuan peraturan perundang-undangan. (2a) Pemerintah wajib melakukan pencegahan penyebarluasan dan penggunaan Informasi Elektronik dan/ atau Dokumen Elektronik yang memiliki muatan yang dilarang sesuai dengan ketentuan peraturan perundang-undangan. (2b) Dalam melakukan pencegahan sebagaimana dimaksud pada ayat (2a), Pemerintah berwenang melakukan pemutusan Akses dan/atau memerintahkan kepada Penyeleprggara Sistem Elektronik untuk melakukan pemutusan Akses terhadap Informasi Elektronik dan/atau Dokumen Elektronik yang memiliki muatan yang melanggar hukum. l2cl Perintah kepada Penyelenggara Sistem Elektronik sebagaimana dimaksud pada ayat (2b) berupa pemutusan Akses dan/ atau moderasi konten secara mandiri terhadap Informasi Elektronik dan/ atau Dokumen Elektronik yang memiliki muatan pornografi, perjudian, atau muatan …"}, {"l": "UU ITE 1/2024", "p": "40A", "b": "UU ITE 1/2024", "t": "(U Pemerintah bertanggung jawab dalam mendorong terciptanya ekosistem digital yang adil, akuntabel, aman, dan inovatif. (21 Dalam rangka melaksanakan tanggung Jawab sebagaimana dimaksud pada ayat (1), Pemerintah berwenang memerintahkan Penyelenggara Sistem Elektronik untuk melakukan penyesuaian pada Sistem Elektronik dan/atau melakukan tindakan tertentu. (3) Penyelenggara Sistem Elektronik wajib melaksanakan perintah sebagaimana dimaksud pada ayat (2). (41 Dalam hal Penyelenggara Sistem Elektronik melanggar kewajiban sebagaimana dimaksud pada ayat (3), Penyelenggara Sistem Elektronik dikenai sanksi administratif. (5) Sanksi... NEPUBLIK INDONESTA (5) Sanksi administratif sebagaimana dimalsud pada ayat (4) dapat berupa: a. teguran tertulis; b. dendaadministratif; c. penghentian sementara; dan/atau d. pemutusan Akses. (6) Ketentuan lebih lanjut mengenai tanggung jawab Pemerintah sebagaimana dimaksud pada ayat (l ), wewenang Pemerintah sebagaimana dimaksud pada ayat (21, kewajiban Penyelepggara Sistem Elektronik sebagaimana dimaksud pada ayat (3), dan pengenaan sanksi administratif sebagaimana dimaksud pada ayat (4) dan ayat (5) diatur dalam Peraturan Pemerintah. 15. Ketentuan ayat …"}, {"l": "UU ITE 1/2024", "p": "43", "b": "UU ITE 1/2024", "t": "(1) Selain Penyidik Pejabat Polisi Negara Republik Indonesia, Pejabat Pegawai Negeri Sipil tertentu di lingkungan Pemerintah yang lingkup tugas dan tanggung jawabnya di bidang Teknologi Informasi dan Transaksi Elektronik diberi wewenang khusus sebagai penyidik sebagaimana dimaksud dalam Undang-Undang tentang Hukum Acara Pidana untuk melakukan penyidikan tindak pidana di bidang Teknologi Informasi dan Transaksi Elektronik. (2) Penyidikan. . . REPUBLIK INDONEISIA -t4- l2l Penyidikan tindak pidana di bidang Teknologi Informasi dan Transaksi Elektronik sebagaimana dimaksud pada ayat (1) dilakukan dengan memperhatikan pelindungan terhadap privasi, kerahasiaan, kelancaran layanan publik, dan integritas atau keutuhan data sesuai dengan ketentuan peraturan perundang-undangan. (3) Penggeledahan dan/atau penyitaan terhadap Sistem Elektronik yang terkait dengan dugaan tindak pidana di bidang Teknologi Informasi dan Transaksi Elektronik dilakukan sesuai dengan ketentuan hukum acara pidana. (41 Dalam melakukan penggeledahan dan/ atau penyitaan sebagaimana dimaksud pada ayat (3), penyidik wajib menjaga terpeliharanya kepentingan pelayanan umum. (5) Penyidik Pejabat Pegawai Negeri Sipil …"}, {"l": "UU ITE 1/2024", "p": "45", "b": "UU ITE 1/2024", "t": "(1) Setiap Orang yang dengan sengaja dan tanpa hak menyiarkan, mempertunjukkan, mendistribusikan, mentransmisikan, dan/atau membuat dapat diaksesnya Informasi Elektronik dan/ atau Dokumen Elektronik yang memiliki muatan yang melanggar kesusilaan untuk diketahui umum sebagaimana dimaksud dalam Pasal 27 ayat (1) dipidana dengan pidana penjara paling lama 6 (enam) tahun dan/atau denda paling banyak Rpl.000.000.000,00 (satu miliar rupiah). (2) Perbuatan . . . f,r{rr:rftxlTrffif{Tff, -L7- (21 Perbuatan sebagaimana dimaksud pada ayat (1) tidak dipidana dalam hal: a. dilakukan demi kepentingan umum; b. dilakukan untuk pembelaan atas dirinya sendiri; atau c. Informasi Elektronik dan/ atau Dokumen Elektronik tersebut merupakan karya seni, budaya, olahraga, kesehatan, dan/ atau ilmu pengetahuan. (3) Setiap Orang yang dengan sengaja dan tanpa hak mendistribusikan, mentransmisikan, dan/ atau membuat dapat diaksesnya Informasi Elektronik dan/ atau Dokumen Elektronik yang memiliki muatan perjudian sebagaimana dimaksud dalam Pasal 27 ayat (2) dipidana dengan pidana penjara paling lama 10 (sepuluh) tahun dan/atau denda paling banyak Rp 1 0. 000.000.000,00 (sepuluh miliar rupiah). (4) Setiap Orang …"}, {"l": "UU ITE 1/2024", "p": "45A", "b": "UU ITE 1/2024", "t": "(1) Setiap Orang yang dengan sengaja mendistribusikan dan/atau mentransmisikan Informasi Elektronik dan/atau Dokumen Elektronik yang berisi pemberitahuan bohong atau informasi menyesatkan yang mengakibatkan kerugian materiel bagi konsumen dalam Transaksi Elektronik sebagaimana dimaksud dalam Pasal 28 ayat (1) dipidana dengan pidana penjara paling lama 6 (enam) tahun dan/ atau denda paling banyak Rp1.0O0.0O0.000,00 (satu miliar rupiah). (2) Setiap Orang yang dengan sengaja dan tanpa hak mendistribusikan dan/atau mentransmisikan Informasi Elektronik dan/atau Dokumen Elektronik yang sifatnya menghasut, mengajak, atau orang lain sehingga menimbulkan rasa kebencian atau permusuhan terhadap individu dan/atau kelompok masyarakat tertentu berdasarkan ras, kebangsaan, etnis, warna kulit, agama, kepercayaan, jenis kelamin, disabilitas mental, atau disabilitas frsik sebagaimana dimaksud dalam Pasal 28 ayat (2) dipidana dengan pidana penjara paling lama 6 (enam) tahun dan/ atau denda paling banyak Rp1.0OO.0O0.000,0O (satu miliar rupiah). (3) Setiap. . . NEPUELIK INDONEISIA (3) Setiap Orang yang dengan sengaja menyebarkan Informasi Elektronik dan/atau Dokumen Elektronik yang diketahuinya …"}, {"l": "UU ITE 1/2024", "p": "45B", "b": "UU ITE 1/2024", "t": "Setiap Orang yang dengan sengaja dan tanpa hak mengirimkan Informasi Elektronik dan/atau Dokumen Elektronik secara langsung kepada korban yang berisi ancaman kekerasan dan/ atau menakut- nakuti sebagaimana dimaksud dalam Pasal 29 dipidana dengan pidana penjara paling lama 4 (empat) tahun dan/ atau denda paling banyak Rp750.000.000,00 (tqjuh ratus lima puluh juta rupiah)."}, {"l": "UU ITE 1/2024", "p": "11", "b": "UU ITE 1/2024", "t": "1 Pada saat Undang-Undang ini mulai berlaku, ketentuan dalam Pasal 27 ayat (1), Pasal 27A, Pasal. 28 ayat (2), Pasal 28 ayal (3), Pasal 36, Pasal 45 ayat (1), Pasal 45 ayat (2), Pasal 45 ayat (4), Pasal 45 ayat (5), Pasal 45 ayat (6), Pasal 45 ayat (7), Pasal 45A ayat (2), dan Pasal 45A ayat (3) berlaku sampai dengan diberlakukannya Undang-Undang Nomor 1 Tahun 2O23 tentang Kitab Undang-Undang Hukum Pidana (Lembaran Negara Republik Indonesia Tahun 2O23 Nomor 1, Tambahan Lembaran Negara Republik Indonesia Nomor 6842). 2 Undang-Undang ini mulai berlaku pada tanggal diundangkan. Agar . . . FRESIDEN REPUBUK INDONESIA -2t- pengundangan Undang-Undang ini dengan penempatannya dalam l,embaran Negara Republik Indonesia. pada tanggal 2 Januari2024 JOKO WIDODO pada tanggal 2 Jarruari 2024 PRATIKNO KEMENTERIAN SEKRETARIAT NEGARA Perundang-undangan dan trasi Hukum, Djaman TI.I JTFIIIilNFIEFI;FIA"}, {"l": "UU 30/1999", "p": "1", "b": "BAB I KETENTUAN UMUM", "t": "Dalam Undang-undang ini yang dimaksud dengan : 1. Arbitrase adalah cara penyelesaian suatu sengketa perdata di luar peradilan umum yang didasarkan pada perjanjian arbitrase yang dibuat secara tertulis oleh para pihak yang bersengketa. 2. Para pihak adalah subyek hukum, baik menurut hukum perdata maupun hukum publik. 3. Perjanjian arbitrase adalah suatu kesepakatan berupa klausula arbitrase yang tercantum dalam suatu perjanjian tertulis yang dibuat para pihak sebelum timbul sengketa, atau suatu perjanjian arbitrase tersendiri yang dibuat para pihak setelah timbul sengketa. 4. Pengadilan Negeri adalah Pengadilan Negeri yang daerah hukumnya meliputi tempat tinggal termohon. 5. Pemohon adalah pihak yang mengajukan permohonan penyelesaian sengketa melalui arbitrase. 6. Termohon adalah pihak lawan dari Pemohon dalam penyelesaian sengketa melalui arbitrase. 7. Arbiter adalah seorang atau lebih yang dipilih oleh para pihak yang bersengketa atau yang ditunjuk oleh Pengadilan Negeri atau oleh lembaga arbitrase, untuk memberikan putusan mengenai sengketa tertentu yang diserahkan penyelesaiannya melalui arbitrase. 8. Lembaga Arbitrase adalah badan yang dipilih oleh para pihak yang bersengketa …"}, {"l": "UU 30/1999", "p": "2", "b": "BAB I KETENTUAN UMUM", "t": "Undang-undang ini mengatur penyelesaian sengketa atau beda pendapat antar para pihak dalam suatu hubungan hukum tertentu yang telah mengadakan perjanjian arbitrase yang secara tegas menyatakan bahwa semua sengketa atau beda pendapat yang timbul atau yang mungkin timbul dari hubungan hukum tersebut akan diselesaikan dengan cara arbitrase atau melalui alternatif penyelesaian sengketa."}, {"l": "UU 30/1999", "p": "3", "b": "BAB I KETENTUAN UMUM", "t": "Pengadilan Negeri tidak berwenang untuk mengadili sengketa para pihak yang telah terikat dalam perjanjian arbitrase."}, {"l": "UU 30/1999", "p": "4", "b": "BAB I KETENTUAN UMUM", "t": "(1) Dalam hal para pihak telah menyetujui bahwa sengketa di antara mereka akan diselesaikan melalui arbitrase dan para pihak telah memberikan wewenang, maka arbiter berwenang menentukan dalam putusannya mengenai hak dan kewajiban para pihak jika hal ini tidak diatur dalam perjanjian mereka. (2) Persetujuan untuk menyelesaikan sengketa melalui arbitrase sebagaimana dimaksud dalam ayat (1) dimuat dalam suatu dokumen yang ditandatangani oleh para pihak. (3) Dalam hal disepakati penyelesaian sengketa melalui arbitrase terjadi dalam bentuk pertukaran surat, maka pengiriman teleks, telegram, faksimili, e-mail atau dalam bentuk sarana komunikasi lainnya, wajib disertai dengan suatu catatan penerimaan oleh para pihak."}, {"l": "UU 30/1999", "p": "5", "b": "BAB I KETENTUAN UMUM", "t": "(1) Sengketa yang dapat diselesaikan melalui arbitrase hanya sengketa di bidang perdagangan dan mengenai hak yang menurut hukum dan peraturan perundang-undangan dikuasai sepenuhnya oleh pihak yang bersengketa. (2) Sengketa yang tidak dapat diselesaikan melalui arbitrase adalah sengketa yang menurut peraturan perundang-undangan tidak dapat diadakan perdamaian."}, {"l": "UU 30/1999", "p": "6", "b": "BAB II ALTERNATIF PENYELESAIAN SENGKETA", "t": "(1) Sengketa atau beda pendapat perdata dapat diselesaikan oleh para pihak melalui alternatif penyelesaian sengketa yang didasarkan pada itikad baik dengan mengesampingkan penyelesaian secara litigasi di Pengadilan Negeri. (2) Penyelesaian sengketa atau beda pendapat melalui alternatif penyelesaian sengketa sebagaimana dimaksud dalam ayat (1) diselesaikan dalam pertemuan langsung oleh para pihak dalam waktu paling lama 14 (empat belas) hari dan hasilnya dituangkan dalam suatu kesepakatan tertulis. (3) Dalam hal sengketa atau beda pendapat sebagaimana dimaksud dalam ayat (2) tidak dapat diselesaikan, maka atas kesepakatan tertulis para pihak, sengketa atau beda pendapat diselesaikan melalui bantuan seorang atau lebih penasehat ahli maupun melalui seorang mediator. (4) Apabila para pihak tersebut dalam waktu paling lama 14 (empat belas) hari dengan bantuan seorang atau lebih penasehat ahli maupun melalui seorang mediator tidak berhasil mencapai kata sepakat, atau mediator tidak berhasil mempertemukan kedua belah pihak, maka para pihak dapat menghubungi sebuah lembaga arbitrase atau lembaga alternatif penyelesaian sengketa untuk menunjuk seorang mediator. (5) Setelah penunjukan …"}, {"l": "UU 30/1999", "p": "7", "b": "Bagian Pertama", "t": "Para pihak dapat menyetujui suatu sengketa yang terjadi atau yang akan terjadi antara mereka untuk diselesaikan melalui arbitrase."}, {"l": "UU 30/1999", "p": "8", "b": "Bagian Pertama", "t": "(1) Dalam hal timbul sengketa, pemohon harus memberitahukan dengan surat tercatat, telegram, teleks, faksimili, e-mail atau dengan buku ekspedisi kepada termohon bahwa syarat arbitrase yang diadakan oleh pemohon atau termohon berlaku. (2) Surat pemberitahuan untuk mengadakan arbitrase sebagaimana dimaksud dalam ayat (1) memuat dengan jelas : a. nama dan alamat para pihak; b. penunjukan kepada klausula atau perjanjian arbitrase yang berlaku; c. perjanjian atau masalah yang menjadi sengketa; d. dasar tuntutan dan jumlah yang dituntut, apabila ada; e. cara penyelesaian yang dikehendaki; dan f. perjanjian yang diadakan oleh para pihak tentang jumlah arbiter atau apabila tidak pernah diadakan perjanjian semacam itu, pemohon dapat mengajukan usul tentang jumlah arbiter yang dikehendaki dalam jumlah ganjil."}, {"l": "UU 30/1999", "p": "9", "b": "Bagian Pertama", "t": "(1) Dalam hal para pihak memilih penyelesaian sengketa melalui arbitrase setelah sengketa terjadi, persetujuan mengenai hal tersebut harus dibuat dalam suatu perjanjian tertulis yang ditandatangani oleh para pihak. (2) Dalam hal para pihak tidak dapat menandatangani perjanjian tertulis sebagaimana dimaksud dalam ayat (1), perjanjian tertulis tersebut harus dibuat dalam bentuk akta notaris. (3) Perjanjian tertulis sebagaimana dimaksud dalam ayat (1) harus memuat : a. masalah yang dipersengketakan; b. nama lengkap dan tempat tinggal para pihak; c. nama lengkap dan tempat tinggal arbiter atau majelis arbitrase; d. tempat arbiter atau majelis arbitrase akan mengambil keputusan; e. nama lengkap sekretaris; f. jangka waktu penyelesaian sengketa; g. pernyataan kesediaan dari arbiter; dan h. pernyataan kesediaan dari pihak yang bersengketa untuk menanggung segala biaya yang diperlukan untuk penyelesaian sengketa melalui arbitrase. (4) Perjanjian tertulis yang tidak memuat hal sebagaimana dimaksud dalam ayat (3) batal demi hukum."}, {"l": "UU 30/1999", "p": "10", "b": "Bagian Pertama", "t": "Suatu perjanjian arbitrase tidak menjadi batal disebabkan oleh keadaan tersebut di bawah ini : a. meninggalnya salah satu pihak; b. bangkrutnya salah satu pihak; c. novasi; d. insolvensi salah satu pihak; e. pewarisan; f. berlakunya syarat-syarat hapusnya perikatan pokok; g. bilamana pelaksanaan perjanjian tersebut dialihtugaskan pada pihak ketiga dengan persetujuan pihak yang melakukan perjanjian arbitrase tersebut; atau h. berakhirnya atau batalnya perjanjian pokok."}, {"l": "UU 30/1999", "p": "11", "b": "Bagian Pertama", "t": "(1) Adanya suatu perjanjian arbitrase tertulis meniadakan hak para pihak untuk mengajukan penyelesaian sengketa atau beda pendapat yang termuat dalam perjanjiannya ke Pengadilan Negeri. (2) Pengadilan Negeri wajib menolak dan tidak akan campur tangan di dalam suatu penyelesaian sengketa yang telah ditetapkan melalui arbitase, kecuali dalam hal-hal tertentu yang ditetapkan dalam Undang-undang ini."}, {"l": "UU 30/1999", "p": "12", "b": "Bagian Kedua", "t": "(1) Yang dapat ditunjuk atau diangkat sebagai arbiter harus memenuhi syarat : a. cakap melakukan tindakan hukum; b. berumur paling rendah 35 tahun; c. tidak mempunyai hubungan keluarga sedarah atau semenda sampai dengan derajat kedua dengan salah satu pihak bersengketa; d. tidak mempunyai kepentingan finansial atau kepentingan lain atas putusan arbitrase; dan e. memiliki pengalaman serta menguasai secara aktif di bidangnya paling sedikit 15 tahun. (2) Hakim, jaksa, panitera dan pejabat peradilan lainnya tidak dapat ditunjuk atau diangkat sebagai arbiter."}, {"l": "UU 30/1999", "p": "13", "b": "Bagian Kedua", "t": "(1) Dalam hal para pihak tidak dapat mencapai kesepakatan mengenai pemilihan arbiter atau tidak ada ketentuan yang dibuat mengenai pengangkatan arbiter, Ketua Pengadilan Negeri menunjuk arbiter atau majelis arbitrase. (2) Dalam suatu arbitrase ad–hoc bagi setiap ketidaksepakatan dalam penunjukan seorang atau beberapa arbiter, para pihak dapat mengajukan permohonan kepada Ketua Pengadilan Negeri untuk menunjuk seorang arbiter atau lebih dalam rangka penyelesaian sengketa para pihak."}, {"l": "UU 30/1999", "p": "14", "b": "Bagian Kedua", "t": "(1) Dalam hal para pihak telah bersepakat bahwa sengketa yang timbul akan diperiksa dan diputus oleh arbiter tunggal, para pihak wajib untuk mencapai suatu kesepakatan tentang pengangkatan arbiter tunggal. (2) Pemohon dengan surat tercatat, telegram, teleks, faksimili, e-mail atau dengan buku ekspedisi harus mengusulkan kepada pihak termohon nama orang yang dapat diangkat sebagai arbiter tunggal. (3) Apabila dalam waktu paling lama 14 (empat belas) hari setelah termohon menerima usul pemohon sebagaimana dimaksud dalam ayat (2) para pihak tidak berhasil menentukan arbiter tunggal, atas permohonan dari salah satu pihak, Ketua Pengadilan Negeri dapat mengangkat arbiter tunggal. (4) Ketua Pengadilan Negeri akan mengangkat arbiter tunggal berdasarkan daftar nama yang disampaikan oleh para pihak, atau yang diperoleh dari organisasi atau lembaga arbitrase sebagaimana dimaksud dalam Pasal 34, dengan memperhatikan baik rekomendasi maupun keberatan yang diajukan oleh para pihak terhadap orang yang bersangkutan."}, {"l": "UU 30/1999", "p": "15", "b": "Bagian Kedua", "t": "(1) Penunjukan dua orang arbiter oleh para pihak memberi wewenang kepada dua arbiter tersebut untuk memilih dan menunjuk arbiter yang ketiga. (2) Arbiter ketiga sebagaimana dimaksud dalam ayat (1) diangkat sebagai ketua majelis arbitrase. (3) Apabila dalam waktu paling lama 30 (tiga puluh) hari setelah pemberitahuan diterima oleh termohon sebagaimana dimaksud dalam Pasal 8 ayat (1), dan salah satu pihak ternyata tidak menunjuk seseorang yang akan menjadi anggota majelis arbitrase, arbiter yang ditunjuk oleh pihak lainnya akan bertindak sebagai arbiter tunggal dan putusannya mengikat kedua belah pihak. (4) Dalam hal kedua arbiter yang telah ditunjuk masing-masing pihak sebagaimana dimaksud dalam ayat (1) tidak berhasil menunjuk arbiter ketiga dalam waktu paling lama 14 (empat belas) hari setelah arbiter yang terakhir ditunjuk, atas permohonan salah satu pihak, Ketua Pengadilan Negeri dapat mengangkat arbiter ketiga. (5) Terhadap pengangkatan arbiter yang dilakukan oleh Ketua Pengadilan Negeri sebagaimana dimaksud dalam ayat (4), tidak dapat diajukan upaya pembatalan."}, {"l": "UU 30/1999", "p": "16", "b": "Bagian Kedua", "t": "(1) Arbiter yang ditunjuk atau diangkat dapat menerima atau menolak penunjukan atau pengangkatan tersebut. (2) Penerimaan atau penolakan sebagaimana dimaksud dalam ayat (1), wajib diberitahukan secara tertulis kepada para pihak dalam waktu paling lama 14 (empat belas) hari terhitung sejak tanggal penunjukan atau pengangkatan."}, {"l": "UU 30/1999", "p": "17", "b": "Bagian Kedua", "t": "(1) Dengan ditunjuknya seorang arbiter atau beberapa arbiter oleh para pihak secara tertulis dan diterimanya penunjukan tersebut oleh seorang arbiter atau beberapa arbiter secara tertulis, maka antara pihak yang menunjuk dan arbiter yang menerima penunjukan terjadi suatu perjanjian perdata. (2) Penunjukan sebagaimana dimaksud dalam ayat (1), mengakibatkan bahwa arbiter atau para arbiter akan memberikan putusannya secara jujur, adil, dan sesuai dengan ketentuan yang berlaku dan para pihak akan menerima putusannya secara final dan mengikat seperti yang telah diperjanjikan bersama."}, {"l": "UU 30/1999", "p": "18", "b": "Bagian Kedua", "t": "(1) Seorang calon arbiter yang diminta oleh salah satu pihak untuk duduk dalam majelis arbitrase, wajib memberitahukan kepada para pihak tentang hal yang mungkin akan mempengaruhi kebebasannya atau menimbulkan keberpihakan putusan yang akan diberikan. (2) Seseorang yang menerima penunjukan sebagai arbiter sebagaimana dimaksud dalam ayat (1), harus memberitahukan kepada para pihak mengenai penunjukannya."}, {"l": "UU 30/1999", "p": "19", "b": "Bagian Kedua", "t": "(1) Dalam hal arbiter telah menyatakan menerima penunjukan atau pengangkatan sebagaimana dimaksud dalam Pasal 16, maka yang bersangkutan tidak dapat menarik diri, kecuali atas persetujuan para pihak. (2) Dalam hal arbiter sebagaimana dimaksud dalam ayat (1) yang telah menerima penunjukan atau pengangkatan, menyatakan menarik diri, maka yang bersangkutan wajib mengajukan permohonan secara tertulis kepada para pihak. (3) Dalam hal para pihak dapat menyetujui permohonan penarikan diri sebagaimana dimaksud dalam ayat (2), maka yang bersangkutan, dapat dibebaskan dari tugas sebagai arbiter. (4) Dalam hal permohonan penarikan diri tidak mendapat persetujuan para pihak, pembebasan tugas arbiter ditetapkan oleh Ketua Pengadilan Negeri."}, {"l": "UU 30/1999", "p": "20", "b": "Bagian Kedua", "t": "Dalam hal arbiter atau majelis arbitrase tanpa alasan yang sah tidak memberikan putusan dalam jangka waktu yang telah ditentukan, arbiter dapat dihukum untuk mengganti biaya dan kerugian yang diakibatkan karena kelambatan tersebut kepada para pihak."}, {"l": "UU 30/1999", "p": "21", "b": "Bagian Kedua", "t": "Arbiter atau majelis arbitrase tidak dapat dikenakan tanggung jawab hukum apapun atas segala tindakan yang diambil selama proses persidangan berlangsung untuk menjalankan fungsinya sebagai arbiter atau majelis arbitrase, kecuali dapat dibuktikan adanya itikad tidak baik dari tindakan tersebut."}, {"l": "UU 30/1999", "p": "22", "b": "Bagian Ketiga", "t": "(1) Terhadap arbiter dapat diajukan tuntutan ingkar apabila terdapat cukup alasan dan cukup bukti otentik yang menimbulkan keraguan bahwa arbiter akan melakukan tugasnya tidak secara bebas dan akan berpihak dalam mengambil putusan. (2) Tuntutan ingkar terhadap seorang arbiter dapat pula dilaksanakan apabila terbukti adanya hubungan kekeluargaan, keuangan atau pekerjaan dengan salah satu pihak atau kuasanya."}, {"l": "UU 30/1999", "p": "23", "b": "Bagian Ketiga", "t": "(1) Hak ingkar terhadap arbiter yang diangkat oleh Ketua Pengadilan Negeri diajukan kepada Pengadilan Negeri yang bersangkutan. (2) Hak ingkar terhadap arbiter tunggal diajukan kepada arbiter yang bersangkutan. (3) Hak ingkar terhadap anggota majelis arbitrase diajukan kepada majelis arbitrase yang bersangkutan."}, {"l": "UU 30/1999", "p": "24", "b": "Bagian Ketiga", "t": "(1) Arbiter yang diangkat tidak dengan penetapan pengadilan, hanya dapat diingkari berdasarkan alasan yang baru diketahui pihak yang mempergunakan hak ingkarnya setelah pengangkatan arbiter yang bersangkutan. (2) Arbiter yang diangkat dengan penetapan pengadilan, hanya dapat diingkari berdasarkan alasan yang diketahuinya setelah adanya penerimaan penetapan pengadilan tersebut. (3) Pihak yang berkeberatan terhadap penunjukan seorang arbiter yang dilakukan oleh pihak lain, harus mengajukan tuntutan ingkar dalam waktu paling lama 14 (empat belas) hari sejak pengangkatan. (4) Dalam hal alasan sebagaimana dimaksud dalam Pasal 22 ayat (1) dan (2) diketahui kemudian, tuntutan ingkar harus diajukan dalam waktu paling lama 14 (empat belas) hari sejak diketahuinya hal tersebut. (5) Tuntutan ingkar harus diajukan secara tertulis, baik kepada pihak lain maupun kepada pihak arbiter yang bersangkutan dengan menyebutkan alasan tuntutannya. (6) Dalam hal tuntutan ingkar yang diajukan oleh salah satu pihak disetujui oleh pihak lain, arbiter yang bersangkutan harus mengundurkan diri dan seorang arbiter pengganti akan ditunjuk sesuai dengan cara yang ditentukan dalam Undang-undang ini."}, {"l": "UU 30/1999", "p": "25", "b": "Bagian Ketiga", "t": "(1) Dalam hal tuntutan ingkar yang diajukan oleh salah satu pihak tidak disetujui oleh pihak lain dan arbiter yang bersangkutan tidak bersedia mengundurkan diri, pihak yang berkepentingan dapat mengajukan tuntutan kepada Ketua Pengadilan Negeri yang putusannya mengikat kedua pihak, dan tidak dapat diajukan perlawanan. (2) Dalam hal Ketua Pengadilan Negeri memutuskan bahwa tuntutan sebagaimana dimaksud dalam ayat (1) beralasan, seorang arbiter pengganti harus diangkat dengan cara sebagaimana yang berlaku untuk pengangkatan arbiter yang digantikan. (3) Dalam hal Ketua Pengadilan Negeri menolak tuntutan ingkar, arbiter melanjutkan tugasnya."}, {"l": "UU 30/1999", "p": "26", "b": "Bagian Ketiga", "t": "(1) Wewenang arbiter tidak dapat dibatalkan dengan meninggalnya arbiter dan wewenang tersebut selanjutnya dilanjutkan oleh penggantinya yang kemudian diangkat sesuai dengan Undang-undang ini. (2) Arbiter dapat dibebastugaskan bilamana terbukti berpihak atau menunjukkan sikap tercela yang harus dibuktikan melalui jalur hukum. (3) Dalam hal selama pemeriksaan sengketa berlangsung, arbiter meninggal dunia, tidak mampu, atau mengundurkan diri, sehingga tidak dapat melaksanakan kewajibannya, seorang arbiter pengganti akan diangkat dengan cara sebagaimana yang berlaku bagi pengangkatan arbiter yang bersangkutan. (4) Dalam hal seorang arbiter tunggal atau ketua majelis arbitrase diganti, semua pemeriksaan yang telah diadakan harus diulang kembali. (5) Dalam hal anggota majelis yang diganti, pemeriksaan sengketa hanya diulang kembali secara tertib antar arbiter."}, {"l": "UU 30/1999", "p": "27", "b": "Bagian Pertama", "t": "Semua pemeriksaan sengketa oleh arbiter atau majelis arbitrase dilakukan secara tertutup."}, {"l": "UU 30/1999", "p": "28", "b": "Bagian Pertama", "t": "Bahasa yang digunakan dalam semua proses arbitrase adalah bahasa Indonesia, kecuali atas persetujuan arbiter atau majelis arbitrase para pihak dapat memilih bahasa lain yang akan digunakan."}, {"l": "UU 30/1999", "p": "29", "b": "Bagian Pertama", "t": "(1) Para pihak yang bersengketa mempunyai hak dan kesempatan yang sama dalam mengemukakan pendapat masing-masing. (2) Para pihak yang bersengketa dapat diwakili oleh kuasanya dengan surat kuasa khusus."}, {"l": "UU 30/1999", "p": "30", "b": "Bagian Pertama", "t": "Pihak ketiga di luar perjanjian arbitrase dapat turut serta dan menggabungkan diri dalam proses penyelesaian sengketa melalui arbitrase, apabila terdapat unsur kepentingan yang terkait dan keturutsertaannya disepakati oleh para pihak yang bersengketa serta disetujui oleh arbiter atau majelis arbitrase yang memeriksa sengketa yang bersangkutan."}, {"l": "UU 30/1999", "p": "31", "b": "Bagian Pertama", "t": "(1) Para pihak dalam suatu perjanjian yang tegas dan tertulis, bebas untuk menentukan acara arbitrase yang digunakan dalam pemeriksaan sengketa sepanjang tidak bertentangan dengan ketentuan dalam Undang-undang ini. (2) Dalam hal para pihak tidak menentukan sendiri ketentuan mengenai acara arbitrase yang akan digunakan dalam pemeriksaan, dan arbiter atau majelis arbitrase telah terbentuk sesuai dengan Pasal 12, Pasal 13, dan Pasal 14, semua sengketa yang penyelesaiannya diserahkan kepada arbiter atau majelis arbitrase akan diperiksa dan diputus menurut ketentuan dalam Undang-undang ini. (3) Dalam hal para pihak telah memilih acara arbitrase sebagaimana dimaksud dalam ayat (1), harus ada kesepakatan mengenai ketentuan jangka waktu dan tempat diselenggarakan arbitrase dan apabila jangka waktu dan tempat arbitrase tidak ditentukan, arbiter atau majelis arbitrase yang akan menentukan."}, {"l": "UU 30/1999", "p": "32", "b": "Bagian Pertama", "t": "(1) Atas permohonan salah satu pihak, arbiter atau majelis arbitrase dapat mengambil putusan provisionil atau putusan sela lainnya untuk mengatur ketertiban jalannya pemeriksaan sengketa termasuk penetapan sita jaminan, memerintahkan penitipan barang kepada pihak ketiga, atau menjual barang yang mudah rusak. (2) Jangka waktu pelaksanaan putusan provisionil atau putusan sela lainnya sebagaimana dimaksud dalam ayat (1) tidak dihitung dalam jangka waktu sebagaimana dimaksud dalam Pasal 48."}, {"l": "UU 30/1999", "p": "33", "b": "Bagian Pertama", "t": "Arbiter atau majelis arbitrase berwenang untuk memperpanjang jangka waktu tugasnya apabila : a. diajukan permohonan oleh salah satu pihak mengenai hal khusus tertentu; b. sebagai akibat ditetapkan putusan provisionil atau putusan sela lainnya; atau c. dianggap perlu oleh arbiter atau majelis arbitrase untuk kepentingan pemeriksaan."}, {"l": "UU 30/1999", "p": "34", "b": "Bagian Pertama", "t": "(1) Penyelesaian sengketa melalui arbitrase dapat dilakukan dengan menggunakan lembaga arbitrase nasional atau internasional berdasarkan kesepakatan para pihak. (2) Penyelesaian sengketa melalui lembaga arbitrase sebagaimana dimaksud dalam ayat (1) dilakukan menurut peraturan dan acara dari lembaga yang dipilih, kecuali ditetapkan lain oleh para pihak."}, {"l": "UU 30/1999", "p": "35", "b": "Bagian Pertama", "t": "Arbiter atau majelis arbitrase dapat memerintahkan agar setiap dokumen atau bukti disertai dengan terjemahan ke dalam bahasa yang ditetapkan oleh arbiter atau majelis arbitrase."}, {"l": "UU 30/1999", "p": "36", "b": "Bagian Pertama", "t": "(1) Pemeriksaan sengketa dalam arbitrase harus dilakukan secara tertulis. (2) Pemeriksaan secara lisan dapat dilakukan apabila disetujui para pihak atau dianggap perlu oleh arbiter atau majelis arbitrase."}, {"l": "UU 30/1999", "p": "37", "b": "Bagian Pertama", "t": "(1) Tempat arbitrase ditentukan oleh arbiter atau majelis arbitrase, kecuali ditentukan sendiri oleh para pihak. (2) Arbiter atau majelis arbitrase dapat mendengar keterangan saksi atau mengadakan pertemuan yang dianggap perlu pada tempat tertentu diluar tempat arbitrase diadakan. (3) Pemeriksaan saksi dan saksi ahli dihadapan arbiter atau majelis arbitrase, diselenggarakan menurut ketentuan dalam hukum acara perdata. (4) Arbiter atau majelis arbitrase dapat mengadakan pemeriksaan setempat atas barang yang dipersengketakan atau hal lain yang berhubungan dengan sengketa yang sedang diperiksa, dan dalam hal dianggap perlu, para pihak akan dipanggil secara sah agar dapat juga hadir dalam pemeriksaan tersebut."}, {"l": "UU 30/1999", "p": "38", "b": "Bagian Pertama", "t": "(1) Dalam jangka waktu yang ditentukan oleh arbiter atau majelis arbitrase, pemohon harus menyampaikan surat tuntutannya kepada arbiter atau majelis arbitrase. (2) Surat tuntutan tersebut harus memuat sekurang-kurangnya : a. nama lengkap dan tempat tinggal atau tempat kedudukan para pihak; b. uraian singkat tentang sengketa disertai dengan lampiran bukti-bukti; dan isi tuntutan yang jelas."}, {"l": "UU 30/1999", "p": "39", "b": "Bagian Pertama", "t": "Setelah menerima surat tuntutan dari pemohon, arbiter atau ketua majelis arbitrase menyampaikan satu salinan tuntutan tersebut kepada termohon dengan disertai perintah bahwa termohon harus menanggapi dan memberikan jawabannya secara tertulis dalam waktu paling lama 14 ( empat belas ) hari sejak diterimanya salinan tuntutan tersebut oleh termohon."}, {"l": "UU 30/1999", "p": "40", "b": "Bagian Pertama", "t": "(1) Segera setelah diterimanya jawaban dari termohon atas perintah arbiter atau ketua majelis arbitrase, salinan jawaban tersebut diserahkan kepada pemohon. (2) Bersamaan dengan itu, arbiter atau ketua majelis arbitrase memerintahkan agar para pihak atau kuasa mereka menghadap di muka sidang arbitrase yang ditetapkan paling lama 14 (empat belas) hari terhitung mulai hari dikeluarkannya perintah itu."}, {"l": "UU 30/1999", "p": "41", "b": "Bagian Pertama", "t": "Dalam hal termohon setelah lewat 14 (empat belas) hari sebagaimana dimaksud dalam Pasal 39 tidak menyampaikan jawabannya, termohon akan dipanggil dengan ketentuan sebagaimana dimaksud dalam Pasal 40 ayat (2)."}, {"l": "UU 30/1999", "p": "42", "b": "Bagian Pertama", "t": "(1) Dalam jawabannya atau selambat-lambatnya pada sidang pertama, termohon dapat mengajukan tuntutan balasan dan terhadap tuntutan balasan tersebut pemohon diberi kesempatan untuk menanggapi. (2) Tuntutan balasan sebagaimana dimaksud dalam ayat (1), diperiksa dan diputus oleh arbiter atau majelis arbitrase bersama-sama dengan pokok sengketa."}, {"l": "UU 30/1999", "p": "43", "b": "Bagian Pertama", "t": "Apabila pada hari yang ditentukan sebagaimana dimaksud dalam Pasal 40 ayat (2) pemohon tanpa suatu alasan yang sah tidak datang menghadap, sedangkan telah dipanggil secara patut, surat tuntutannya dinyatakan gugur dan tugas arbiter atau majelis arbitrase dianggap selesai."}, {"l": "UU 30/1999", "p": "44", "b": "Bagian Pertama", "t": "(1) Apabila pada hari yang telah ditentukan sebagaimana dimaksud dalam Pasal 40 ayat (2), termohon tanpa suatu alasan sah tidak datang menghadap, sedangkan termohon telah dipanggil secara patut, arbiter atau majelis arbitrase segera melakukan pemanggilan sekali lagi. (2) Paling lama 10 (sepuluh) hari setelah pemanggilan kedua diterima termohon dan tanpa alasan sah termohon juga tidak datang menghadap di muka persidangan, pemeriksaan akan diteruskan tanpa hadirnya termohon dan tuntutan pemohon dikabulkan seluruhnya, kecuali jika tuntutan tidak beralasan atau tidak berdasarkan hukum."}, {"l": "UU 30/1999", "p": "45", "b": "Bagian Pertama", "t": "(1) Dalam hal para pihak datang menghadap pada hari yang telah ditetapkan, arbiter atau majelis arbitrase terlebih dahulu mengusahakan perdamaian antara para pihak yang bersengketa. (2) Dalam hal usaha perdamaian sebagaimana dimaksud dalam ayat (1) tercapai, maka arbiter atau majelis arbitrase membuat suatu akta perdamaian yang final dan mengikat para pihak dan memerintahkan para pihak untuk memenuhi ketentuan perdamaian tersebut."}, {"l": "UU 30/1999", "p": "46", "b": "Bagian Pertama", "t": "(1) Pemeriksaan terhadap pokok sengketa dilanjutkan apabila usaha perdamaian sebagaimana dimaksud dalam Pasal 45 ayat (1) tidak berhasil. (2) Para pihak diberi kesempatan terakhir kali untuk menjelaskan secara tertulis pendirian masing-masing serta mengajukan bukti yang dianggap perlu untuk menguatkan pendiriannya dalam jangka waktu yang ditetapkan oleh arbiter atau majelis arbitrase. (3) Arbiter atau majelis arbitrase berhak meminta kepada para pihak untuk mengajukan penjelasan tambahan secara tertulis, dokumen atau bukti lainnya yang dianggap perlu dalam jangka waktu yang ditentukan oleh arbiter atau majelis arbitrase."}, {"l": "UU 30/1999", "p": "47", "b": "Bagian Pertama", "t": "(1) Sebelum ada jawaban dari termohon, pemohon dapat mencabut surat permohonan untuk menyelesaikan sengketa melalui arbitrase. (2) Dalam hal sudah ada jawaban dari termohon, perubahan atau penambahan surat tuntutan hanya diperbolehkan dengan persetujuan termohon dan sepanjang perubahan atau penambahan itu menyangkut hal-hal yang bersifat fakta saja dan tidak menyangkut dasar-dasar hukum yang menjadi dasar permohonan."}, {"l": "UU 30/1999", "p": "48", "b": "Bagian Pertama", "t": "(1) Pemeriksaan atas sengketa harus diselesaikan dalam waktu paling lama 180 (seratus delapan puluh) hari sejak arbiter atau majelis arbitrase terbentuk. (2) Dengan persetujuan para pihak dan apabila diperlukan sesuai ketentuan Pasal 33, jangka waktu sebagaimana dimaksud dalam ayat (1) dapat diperpanjang."}, {"l": "UU 30/1999", "p": "49", "b": "Bagian Kedua", "t": "(1) Atas perintah arbiter atau majelis arbitrase atau atas permintaan para pihak dapat dipanggil seorang saksi atau lebih atau seorang saksi ahli atau lebih, untuk didengar keterangannya. (2) Biaya pemanggilan dan perjalanan saksi atau saksi ahli dibebankan kepada pihak yang meminta. (3) Sebelum memberikan keterangan, para saksi atau saksi ahli wajib mengucapkan sumpah."}, {"l": "UU 30/1999", "p": "50", "b": "Bagian Kedua", "t": "(1) Arbiter atau majelis arbitrase dapat meminta bantuan seorang atau lebih saksi ahli untuk memberikan keterangan tertulis mengenai suatu persoalan khusus yang berhubungan dengan pokok sengketa. (2) Para pihak wajib memberikan segala keterangan yang diperlukan oleh para saksi ahli. (3) Arbiter atau majelis arbitrase meneruskan salinan keterangan saksi ahli tersebut kepada para pihak agar dapat ditanggapi secara tertulis oleh para pihak yang bersengketa. (4) Apabila terdapat hal yang kurang jelas, atas permintaan para pihak yang berkepentingan, saksi ahli yang bersangkutan dapat didengar keterangannya di muka sidang arbitrase dengan dihadiri oleh para pihak atau kuasanya."}, {"l": "UU 30/1999", "p": "51", "b": "Bagian Kedua", "t": "Terhadap kegiatan dalam pemeriksaan dan sidang arbitrase dibuat berita acara pemeriksaan oleh sekretaris."}, {"l": "UU 30/1999", "p": "52", "b": "BAB V PENDAPAT DAN PUTUSAN ARBITRASE", "t": "Para pihak dalam suatu perjanjian berhak untuk memohon pendapat yang mengikat dari lembaga arbitrase atas hubungan hukum tertentu dari suatu perjanjian."}, {"l": "UU 30/1999", "p": "53", "b": "BAB V PENDAPAT DAN PUTUSAN ARBITRASE", "t": "Terhadap pendapat yang mengikat sebagaimana dimaksud dalam Pasal 52 tidak dapat dilakukan perlawanan melalui upaya hukum apapun."}, {"l": "UU 30/1999", "p": "54", "b": "BAB V PENDAPAT DAN PUTUSAN ARBITRASE", "t": "(1) Putusan arbitrase harus memuat : a. kepala putusan yang berbunyi \"DEMI KEADILAN BERDASARKAN KETUHANAN YANG MAHA ESA\"; b. nama lengkap dan alamat para pihak; c. uraian singkat sengketa; d. pendirian para pihak; e. nama lengkap dan alamat arbiter; f. pertimbangan dan kesimpulan arbiter atau majelis arbitrase mengenai keseluruhan sengketa; g. pendapat tiap-tiap arbiter dalam hal terdapat perbedaan pendapat dalam majelis arbitrase; h. amar putusan; i. tempat dan tanggal putusan; dan j. tanda tangan arbiter atau majelis arbitrase. (2) Tidak ditandatanganinya putusan arbitrase oleh salah seorang arbiter dengan alasan sakit atau meninggal dunia tidak mempengaruhi kekuatan berlakunya putusan. (3) Alasan tentang tidak adanya tanda tangan sebagaimana dimaksud dalam ayat (2) harus dicantumkan dalam putusan. (4) Dalam putusan ditetapkan suatu jangka waktu putusan tersebut harus dilaksanakan."}, {"l": "UU 30/1999", "p": "55", "b": "BAB V PENDAPAT DAN PUTUSAN ARBITRASE", "t": "Apabila pemeriksaan sengketa telah selesai, pemeriksaan segera ditutup dan ditetapkan hari sidang untuk mengucapkan putusan arbitrase."}, {"l": "UU 30/1999", "p": "56", "b": "BAB V PENDAPAT DAN PUTUSAN ARBITRASE", "t": "(1) Arbiter atau majelis arbitrase mengambil putusan berdasarkan ketentuan hukum, atau berdasarkan keadilan dan kepatutan. (2) Para pihak berhak menentukan pilihan hukum yang akan berlaku terhadap penyelesaian sengketa yang mungkin atau telah timbul antara para pihak."}, {"l": "UU 30/1999", "p": "57", "b": "BAB V PENDAPAT DAN PUTUSAN ARBITRASE", "t": "Putusan diucapkan dalam waktu paling lama 30 (tiga puluh) hari setelah pemeriksaan ditutup."}, {"l": "UU 30/1999", "p": "58", "b": "BAB V PENDAPAT DAN PUTUSAN ARBITRASE", "t": "Dalam waktu paling lama 14 (empat belas) hari setelah putusan diterima, para pihak dapat mengajukan permohonan kepada arbiter atau majelis arbitrase untuk melakukan koreksi terhadap kekeliruan administratif dan atau menambah atau mengurangi sesuatu tuntutan putusan."}, {"l": "UU 30/1999", "p": "59", "b": "Bagian Pertama", "t": "(1) Dalam waktu paling lama 30 (tiga puluh) hari terhitung sejak tanggal putusan diucapkan, lembar asli atau salinan otentik putusan arbitrase diserahkan dan didaftarkan oleh arbiter atau kuasanya kepada Panitera Pengadilan Negeri. (2) Penyerahan dan pendaftaran sebagaimana dimaksud dalam ayat (1), dilakukan dengan pencatatan dan penandatanganan pada bagian akhir atau di pinggir putusan oleh Panitera Pengadilan Negeri dan arbiter atau kuasanya yang menyerahkan, dan catatan tersebut merupakan akta pendaftaran. (3) Arbiter atau kuasanya wajib menyerahkan putusan dan lembar asli pengangkatan sebagai arbiter atau salinan otentiknya kepada Panitera Pengadilan Negeri. (4) Tidak dipenuhinya ketentuan sebagaimana dimaksud dalam ayat (1), berakibat putusan arbitrase tidak dapat dilaksanakan. (5) Semua biaya yang berhubungan dengan pembuatan akta pendaftaran dibebankan kepada para pihak."}, {"l": "UU 30/1999", "p": "60", "b": "Bagian Pertama", "t": "Putusan arbitrase bersifat final dan mempunyai kekuatan hukum tetap dan mengikat para pihak."}, {"l": "UU 30/1999", "p": "61", "b": "Bagian Pertama", "t": "Dalam hal para pihak tidak melaksanakan putusan arbitrase secara sukarela, putusan dilaksanakan berdasarkan perintah Ketua Pengadilan Negeri atas permohonan salah satu pihak yang bersengketa."}, {"l": "UU 30/1999", "p": "62", "b": "Bagian Pertama", "t": "(1) Perintah sebagaimana dimaksud dalam Pasal 61 diberikan dalam waktu paling lama 30 (tiga puluh) hari setelah permohonan eksekusi didaftarkan kepada Panitera Pengadilan Negeri. (2) Ketua Pengadilan Negeri sebagaimana dimaksud dalam ayat (1) sebelum memberikan perintah pelaksanaan, memeriksa terlebih dahulu apakah putusan arbitrase memenuhi ketentuan Pasal 4 dan Pasal 5, serta tidak bertentangan dengan kesusilaan dan ketertiban umum. (3) Dalam hal putusan arbitrase tidak memenuhi ketentuan sebagaimana dimaksud dalam ayat (2), Ketua Pengadilan Negeri menolak permohonan pelaksanaan eksekusi dan terhadap putusan Ketua Pengadilan Negeri tersebut tidak terbuka upaya hukum apapun. (4) Ketua Pengadilan Negeri tidak memeriksa alasan atau pertimbangan dari putusan arbitrase."}, {"l": "UU 30/1999", "p": "63", "b": "Bagian Pertama", "t": "Perintah Ketua Pengadilan Negeri ditulis pada lembar asli dan salinan otentik putusan arbitrase yang dikeluarkan."}, {"l": "UU 30/1999", "p": "64", "b": "Bagian Pertama", "t": "Putusan arbitrase yang telah dibubuhi perintah Ketua Pengadilan Negeri, dilaksanakan sesuai ketentuan pelaksanaan putusan dalam perkara perdata yang putusannya telah mempunyai kekuatan hukum tetap."}, {"l": "UU 30/1999", "p": "65", "b": "Bagian Kedua", "t": "Yang berwenang menangani masalah pengakuan dan pelaksanaan Putusan Arbitrase Internasional adalah Pengadilan Negeri Jakarta Pusat."}, {"l": "UU 30/1999", "p": "66", "b": "Bagian Kedua", "t": "Putusan Arbitrase Internasional hanya diakui serta dapat dilaksanakan di wilayah hukum a. Putusan Arbitrase Internasional dijatuhkan oleh arbiter atau majelis arbitrase di suatu negara yang dengan negara Indonesia terikat pada perjanjian, baik secara bilateral maupun multilateral, mengenai pengakuan dan pelaksanaan Putusan Arbitrase Internasional; b. Putusan Arbitrase Internasional sebagaimana dimaksud dalam huruf a terbatas pada putusan yang menurut ketentuan hukum Indonesia termasuk dalam ruang lingkup hukum perdagangan; c. Putusan Arbitrase Internasional sebagaimana dimaksud dalam huruf a hanya dapat dilaksanakan di Indonesia terbatas pada putusan yang tidak bertentangan dengan ketertiban umum; d. Putusan Arbitrase Internasional dapat dilaksanakan di Indonesia setelah memperoleh eksekuatur dari Ketua Pengadilan Negeri Jakarta Pusat; dan e. Putusan Arbitrase Internasional sebagaimana dimaksud dalam huruf a yang menyangkut Negara Republik Indonesia sebagai salah satu pihak dalam sengketa, hanya dapat dilaksanakan setelah memperoleh eksekuatur dari Mahkamah Agung Republik Indonesia yang selanjutnya dilimpahkan kepada Pengadilan Negeri Jakarta Pusat."}, {"l": "UU 30/1999", "p": "67", "b": "Bagian Kedua", "t": "(1) Permohonan pelaksanaan Putusan Arbitrase Internasional dilakukan setelah putusan tersebut diserahkan dan didaftarkan oleh arbiter atau kuasanya kepada Panitera Pengadilan Negeri Jakarta Pusat. (2) Penyampaian berkas permohonan pelaksanaan sebagaimana dimaksud dalam ayat (1) harus disertai dengan : a. lembar asli atau salinan otentik Putusan Arbitrase Internasional, sesuai ketentuan perihal otentifikasi dokumen asing, dan naskah terjemahan resminya dalam Bahasa Indonesia; b. lembar asli atau salinan otentik perjanjian yang menjadi dasar Putusan Arbitrase Internasional sesuai ketentuan perihal otentifikasi dokumen asing, dan naskah terjemahan resminya dalam bahasa Indonesia; dan c. keterangan dari perwakilan diplomatik Republik Indonesia di negara tempat Putusan Arbitrase Internasional tersebut ditetapkan, yang menyatakan bahwa negara pemohon terikat pada perjanjian, baik secara bilateral maupun multilateral dengan negara Republik Indonesia perihal pengakuan dan pelaksanaan Putusan Arbitrase Internasional."}, {"l": "UU 30/1999", "p": "68", "b": "Bagian Kedua", "t": "(1) Terhadap putusan Ketua Pengadilan Negeri Jakarta Pusat sebagaimana dimaksud dalam Pasal 66 huruf d yang mengakui dan melaksanakan Putusan Arbitrase Internasional, tidak dapat diajukan banding atau kasasi. (2) Terhadap putusan Ketua Pengadilan Negeri Jakarta Pusat sebagaimana dimaksud dalam Pasal 66 huruf d yang menolak untuk mengakui dan melaksanakan suatu Putusan Arbitrase Internasional, dapat diajukan kasasi. (3) Mahkamah Agung mempertimbangkan serta memutuskan setiap pengajuan kasasi sebagaimana dimaksud dalam ayat (2), dalam jangka waktu paling lama 90 (sembilan puluh) hari setelah permohonan kasasi tersebut diterima oleh Mahkamah Agung. (4) Terhadap putusan Mahkamah Agung sebagaimana dimaksud dalam Pasal 66 huruf e, tidak dapat diajukan upaya perlawanan."}, {"l": "UU 30/1999", "p": "69", "b": "Bagian Kedua", "t": "(1) Setelah Ketua Pengadilan Negeri Jakarta Pusat memberikan perintah eksekusi sebagaimana dimaksud dalam Pasal 64, maka pelaksanaan selanjutnya dilimpahkan kepada Ketua Pengadilan Negeri yang secara relatif berwenang melaksanakannya. (2) Sita eksekusi dapat dilakukan atas harta kekayaan serta barang milik termohon eksekusi. (3) Tata cara penyitaan serta pelaksanaan putusan mengikuti tata cara sebagaimana ditentukan dalam Hukum Acara Perdata."}, {"l": "UU 30/1999", "p": "70", "b": "BAB VII PEMBATALAN PUTUSAN ARBITRASE", "t": "Terhadap putusan arbitrase para pihak dapat mengajukan permohonan pembatalan apabila putusan tersebut diduga mengandung unsur-unsur sebagai berikut : a. surat atau dokumen yang diajukan dalam pemeriksaan, setelah putusan dijatuhkan, diakui palsu atau dinyatakan palsu; b. setelah putusan diambil ditemukan dokumen yang bersifat menentukan, yang disembunyikan oleh pihak lawan ; atau c. putusan diambil dari hasil tipu muslihat yang dilakukan oleh salah satu pihak dalam pemeriksaan sengketa."}, {"l": "UU 30/1999", "p": "71", "b": "BAB VII PEMBATALAN PUTUSAN ARBITRASE", "t": "Permohonan pembatalan putusan arbitrase harus diajukan secara tertulis dalam waktu paling lama 30 (tiga puluh) hari terhitung sejak hari penyerahan dan pendaftaran putusan arbitrase kepada Panitera Pengadilan Negeri."}, {"l": "UU 30/1999", "p": "72", "b": "BAB VII PEMBATALAN PUTUSAN ARBITRASE", "t": "(1) Permohonan pembatalan putusan arbitrase harus diajukan kepada Ketua Pengadilan Negeri. (2) Apabila permohonan sebagaimana dimaksud dalam ayat (1) dikabulkan, Ketua Pengadilan Negeri menentukan lebih lanjut akibat pembatalan seluruhnya atau sebagian putusan arbitrase. (3) Putusan atas permohonan pembatalan ditetapkan oleh Ketua Pengadilan Negeri dalam waktu paling lama 30 (tiga puluh) hari sejak permohonan sebagaimana dimaksud dalam ayat (1) diterima. (4) Terhadap putusan Pengadilan Negeri dapat diajukan permohonan banding ke Mahkamah Agung yang memutus dalam tingkat pertama dan terakhir. (5) Mahkamah Agung mempertimbangkan serta memutuskan permohonan banding sebagaimana dimaksud dalam ayat (4) dalam waktu paling lama 30 (tiga puluh) hari setelah permohonan banding tersebut diterima oleh Mahkamah Agung."}, {"l": "UU 30/1999", "p": "73", "b": "BAB VIII BERAKHIRNYA TUGAS ARBITER", "t": "Tugas arbiter berakhir karena : a. putusan mengenai sengketa telah diambil; b. jangka waktu yang telah ditentukan dalam perjanjian arbitrase atau sesudah diperpanjang oleh para pihak telah lampau; atau c. para pihak sepakat untuk menarik kembali penunjukan arbiter."}, {"l": "UU 30/1999", "p": "74", "b": "BAB VIII BERAKHIRNYA TUGAS ARBITER", "t": "(1) Meninggalnya salah satu pihak tidak mengakibatkan tugas yang telah diberikan kepada arbiter berakhir. (2) Jangka waktu tugas arbiter sebagaimana dimaksud dalam Pasal 48 ditunda paling lama 60 (enam puluh) hari sejak meninggalnya salah satu pihak."}, {"l": "UU 30/1999", "p": "75", "b": "BAB VIII BERAKHIRNYA TUGAS ARBITER", "t": "(1) Dalam hal arbiter meninggal dunia, dikabulkannya tuntutan ingkar atau pemberhentian seorang atau lebih arbiter, para pihak harus mengangkat arbiter pengganti. (2) Apabila para pihak dalam waktu paling lama 30 (tiga puluh) hari tidak mencapai kesepakatan mengenai pengangkatan arbiter pengganti sebagaimana dimaksud dalam ayat (1), maka Ketua Pengadilan Negeri atas permintaan dari pihak yang berkepentingan, mengangkat seorang atau lebih arbiter pengganti. (3) Arbiter pengganti bertugas melanjutkan penyelesaian sengketa yang bersangkutan berdasarkan kesimpulan terakhir yang telah diadakan."}, {"l": "UU 30/1999", "p": "76", "b": "BAB IX BIAYA ARBITRASE", "t": "(1) Arbiter menentukan biaya arbitrase. (2) Biaya sebagaimana dimaksud dalam ayat (1) meliputi : a. honorarium arbiter; b. biaya perjalanan dan biaya lainnya yang dikeluarkan oleh arbiter; c. biaya saksi dan atau saksi ahli yang diperlukan dalam pemeriksaan sengketa; dan d. biaya administrasi."}, {"l": "UU 30/1999", "p": "77", "b": "BAB IX BIAYA ARBITRASE", "t": "(1) Biaya arbitrase dibebankan kepada pihak yang kalah. (2) Dalam hal tuntutan hanya dikabulkan sebagian, biaya arbitrase dibebankan kepada para pihak secara seimbang."}, {"l": "UU 30/1999", "p": "78", "b": "BAB X KETENTUAN PERALIHAN", "t": "Sengketa yang pada saat Undang-undang ini mulai berlaku sudah diajukan kepada arbiter atau lembaga arbitrase tetapi belum dilakukan pemeriksaan, proses penyelesaiannya dilakukan berdasarkan Undang-undang ini."}, {"l": "UU 30/1999", "p": "79", "b": "BAB X KETENTUAN PERALIHAN", "t": "Sengketa yang pada saat Undang-undang ini mulai berlaku sudah diperiksa tetapi belum diputus, tetap diperiksa dan diputus berdasarkan ketentuan peraturan perundang-undangan yang lama."}, {"l": "UU 30/1999", "p": "80", "b": "BAB X KETENTUAN PERALIHAN", "t": "Sengketa yang pada saat Undang-undang ini mulai berlaku sudah diputus dan putusannya telah memperoleh kekuatan hukum tetap, pelaksanaannya dilakukan berdasarkan Undang-undang ini."}, {"l": "UU 30/1999", "p": "81", "b": "BAB XI KETENTUAN PENUTUP", "t": "Pada saat Undang-undang ini mulai berlaku, ketentuan mengenai arbitrase sebagaimana dimaksud dalam Pasal 615 sampai dengan Pasal 651 Reglemen Acara Perdata (Reglement op de Rechtsvordering, Staatsblad 1847:52) dan Pasal 377 Reglemen Indonesia Yang Diperbaharui (Het Herziene Indonesisch Reglement, Staatsblad 1941:44) dan Pasal 705 Reglemen Acara Untuk Daerah Luar Jawa dan Madura (Rechtsreglement Buitengewesten, Staatsblad 1927:227), dinyatakan tidak berlaku."}, {"l": "UU 30/1999", "p": "82", "b": "BAB XI KETENTUAN PENUTUP", "t": "Undang-undang ini mulai berlaku pada tanggal diundangkan. penempatannya dalam Lembaran Negara Republik Indonesia. pada tanggal 12 Agustus 1999 BACHARUDDIN JUSUF HABIBIE pada tanggal 12 Agustus 1999 MUL ADI"}, {"l": "UU 20/2025", "p": "1", "b": "BAB I KETENTUAN UMUM", "t": "Dalam Undang-Undang ini yang dimaksud dengan: 1. Penyidik adalah penyidik Kepolisian Negara Republik Indonesia, penyidik pegawai negeri sipil, atau penyidik tertentu yang diberi kewenangan oleh Undang-Undang untuk melakukan penyidikan. 2. Penyidik Kepolisian Negara Republik Indonesia yang selanjutnya disebut Penyidik Polri adalah pejabat Kepolisian Negara Republik Indonesia yang diberi kewenangan oleh Undang-Undang untuk melakukan penyidikan. 3. Penyidik NEPUELIK INDONESIA 3. Penyidik Pegawai Negeri Sipil yang selanjutnya disingkat PPNS adalah pejabat pegawai negeri sipil yang diberi kewenangan untuk melakukan penyidikan berdasarkan Undang-Undang yang menjadi dasar hukumnya. 4. Penyidik Tertentu adalah pejabat suatu lembaga selain Penyidik Polri dan PPNS yang diberi kewenangan untuk melakukan penyidikan berdasarkan Undang-Undang yang menjadi dasar hukumnya. 5. Penyidikan adalah serangkaian tindakan Penyidik untuk mencari dan mengumpulkan alat bukti guna membuat terang tindak pidana, serta menemukan tersangka. 6. Penyidik Pembantu adalah pejabat Kepolisian Negara untuk melakukan Penyidikan. 7. Penyelidik adalah pejabat Kepolisian Negara Republik Indonesia atau pejabat lain yang …"}, {"l": "UU 20/2025", "p": "2", "b": "BAB I KETENTUAN UMUM", "t": "(1) Acara pidana dilaksanakan hanya berdasarkan tata cara yang diatur dalam Undang-Undang. (2) Acara pidana dilaksanakan dengan sistem peradilan pidana terpadu atas dasar prinsip diferensiasi fungsional yang menekankan fungsi Penyidikan pada Kepolisian Negara Republik Indonesia, Penuntutan pada Jaksa, pemeriksaan pengadilan pada Hakim, Advokat yang memberikan Jasa Hukum dan Bantuan Hukum dalam rangka mendudukkan peristiwa pidana secara profesional dan proporsional serta Pembimbing Kemasyarakatan yang melaksanakan fungsi pembinaan terhadap narapidana dan Terpidana."}, {"l": "UU 20/2025", "p": "3", "b": "BAB I KETENTUAN UMUM", "t": "(1) Ruang lingkup berlakunya Undang-Undang ini dimaksudkan untuk melaksanakan tata cara peradilan pidana dalam lingkungan peradilan umum pada semua tahap peradilan. (2) Ketentuan dalam Undang-Undang ini dimaksudkan untuk melaksanakan tata cara peradilan pidana terhadap seluruh tindak pidana, kecuali diatur lain dalam Undang-Undang. Pasal 4. . . REPUBUK INDONESIA"}, {"l": "UU 20/2025", "p": "4", "b": "BAB I KETENTUAN UMUM", "t": "Acara pidana yang diatur dalam Undang-Undang ini dilaksanakan dengan perpaduan antara sistem Hakim aktif dengan para pihak berlawanan secara berimbang dalam pemeriksaan di sidang pengadilan."}, {"l": "UU 20/2025", "p": "5", "b": "Bagian Kesatu", "t": "(l) Penyelidik karena kewajibannya mempunyai wewenang: a. menerima Laporan atau Pengaduan dari seseor€rng mengenai adanya tindak pidana baik secara tertulis maupun melalui media telekomunikasi dan/ atau media elektronik; b. mencari, mengumpulkan, dan keterangan dan barang bukti; c. menyuruh berhenti seseorang yang dicurigai dan menanyakan serta memeriksa tanda pengenal diri; d. melakukan asesmen dan mengupayakan fasilitas dan/ atau rujukan bagi kebutuhan khusus perempuzrn dan kelompok rentan; dan e. mengadakan tindakan lain menurut hukum yang bertanggung jawab. l2l Penyelidik atas perintah Penyidik dapat melakukan tindakan berupa: a. Penangkapan, larangan meninggalkan tempat, Penggeledahan, dan Penahanan; b. pemeriksaan dan Penyitaan surat; c. mengambil sidik jari, melakukan identifikasi, memotret seseorang, dan mengambil data forensik seseorang; dan d. membawa dan menghadapkan seseorang pada Penyidik. (3) Penyelidik. . . FRESIDEN ]IEFUBUK INOONESIA (3) Penyelidik membuat dan menyampaikan laporan hasil pelaksanaan wewenang sebagaimana dimaksud pada ayat (1) dan tindakan sebagaimana dimaksud pada ayat {21 kepada Penyidik. (41 Penyelidik mempunyai wewenang melaksanakan tugas di …"}, {"l": "UU 20/2025", "p": "7", "b": "Bagian Kedua", "t": "(1) Penyidik mempunyai tugas dan wewenang: a- menerima Laporan atau Pengaduan dari seseorang mengenai adanya tindak pidana; b. mencari dan mengumpulkan serta alat bukti; c melakukan tindakan pertama di tempat kejadian; d. menyuruh . . . REPUEUK INDONESIA d. men5ruruh berhenti seseorang dan memeriksa surat atau tanda pengenal diri yang bersangkutan; e. mencari orang yang diduga melakukan tindak pidana untuk menetapkan Tersangka; f. melakukan Upaya Paksa; g. mengambil sidik jari, melakukan identifikasi, memotret seseorang, dan mengambil data forensik seseorang; h. mendatangi orang yang berhubungan dengan tindak pidana untuk diperiksa dan didengar keterangannya; i. memanggil orang untuk diperiksa dan didengar keterangannya sebagai Saksi, Ahli, atau Tersangka; j. melakukan penghentian Penyidikan dengan memberitahukan kepada Penuntut Umum; k. melakukan penyelesaian perkara melalui mekanisme Keadilan Restoratif; L menetapkan Tersangka sebagai saksi mahkota; m. menerima pengakuan bersalah; n. melakukan asesmen dan mengupayakan fasilitas dan/atau rujukan bagi kebutuhan khusus perempuan dan kelompok rentan; dan o. melakukan tindakan lain sesuai dengan ketentuan peraturan pemndang-undangan. …"}, {"l": "UU 20/2025", "p": "8", "b": "Bagian Kedua", "t": "(l) Penyidik membuat berita acara pelalsanaan tindakan yang sesuai dengan kewenangannya. (21 Penyidik menyerahkan berkas perkara kepada Penuntut Umum. (3) Penyerahan berkas perkara yang dilakukan oleh PPNS atau Penyidik Tertentu dilakukan melalui Penyidik Polri untuk kemudian secara bersama-sama menyerahkan berkas perkara kepada Penuntut Umum. (41 Dalam hal berkas perkara dinilai lengkap oleh Penuntut Umum, Penyidik menyerahkan Tersangka dan barang bukti kepada Penuntut Umum."}, {"l": "UU 20/2025", "p": "9", "b": "Bagian Kedua", "t": "Penyidik berwenang melaksanakan tugas di seluruh wilayah Negara Kesatuan Republik Indonesia sesuai dengan ketentuan Undang-Undang. Paragraf 2 Penyidik Pembantu"}, {"l": "UU 20/2025", "p": "10", "b": "Bagian Kedua", "t": "Penyidik Pembantu mempunyai wewenang seperti Penyidik sebagaimana dimaksud dalam Pasal 7 ayat (l), kecuali mengenai Penahanan yang wajib diberikan dengan pelimpahan wewenang dari Penyidik."}, {"l": "UU 20/2025", "p": "11", "b": "Bagian Kedua", "t": "Penyidik Pembantu membuat berita acara dan menyerahkan berkas perkara kepada Penyidik, kecuali perkara dengan acara pemeriksaan singkat yang dapat langsung diserahkan kepada Penuntut Umum. Pasal 12. . . FRESIDEN REPUEUK INDONESIA"}, {"l": "UU 20/2025", "p": "12", "b": "Bagian Kedua", "t": "Ketentuan mengenai syarat dan tata cara pengangkatan dan pemberhentian Penyidik Pembantu sebagaimana dimaksud dalam Pasal l0 dan Pasal 11 diatur dalam Peraturan Pemerintah."}, {"l": "UU 20/2025", "p": "13", "b": "Bagian Ketiga", "t": "(1) Penyelidik yang mengetahui atau menerima Laporan atau Pengaduan terjadinya suatu peristiwa yang patut diduga merupalan tindak pidana wajib segera melakukan tindakan Penyelidikan yang diperlukan. (2) Penyelidikan sebagaimana dimaksud pada ayat (1) wajib dilengkapi surat perintah Penyelidikan. (3) Dalam hal Tertangkap Tangan tanpa menunggu perintah Penyidik, Penyelidik wajib segera melakukan tindakan sebagaimana dimaksud dalam Pasal 5 ayat (1) dan ayat (2). (4) Penyelidik wajib membuat berita acara mengenai tindakan sebagaimana dimaksud pada ayat (1) dan ayat (3), serta melaporkan tindakan tersebut kepada Penyidik."}, {"l": "UU 20/2025", "p": "14", "b": "Bagian Ketiga", "t": "(l) Laporan atau Pengaduan yang diajukan secara tertulis harus ditandatangani oleh pelapor atau pengadu. (21 Laporan atau Pengaduan yang diajukan secara lisan harus dicatat oleh Penyelidik dan ditandatangani oleh pelapor atau pengadu dan Penyelidik. (3) Dalam hal pelapor atau pengadu tidak dapat menulis, hal itu harus disebutkan sebagai catatan dalam Laporan atau Pengaduan tersebut. Pasal 15. . . REPUBUK INDONESIA"}, {"l": "UU 20/2025", "p": "15", "b": "Bagian Ketiga", "t": "Dalam melaksanakan tugas Penyelidikan, Penyelidik wajib menunjukkan tanda pengenalnya."}, {"l": "UU 20/2025", "p": "16", "b": "Bagian Ketiga", "t": "(1) Penyelidikan dapat dilakukan dengan cara: a. pengolahan tempat kejadian perkara; b. pengamatan; c. wawancara; d. pembuntutan; e. penyamaran; f. pembelianterselubung; g. penyerahan di bawah pengawasan; h. pelacakan; i. penelitian dan analisis dokumen; j. mendatangi atau mengundang seseorang untuk memperoleh keterangan; dan/atau k. kegiatan lain yang tidak bertentangan dengan ketentuan peraturan perundang-undangan. l2l Sasaran Penyelidikan meliputi: a. orang; b. benda atau barang; c. tempat; d. peristiwa/kejadian; dan/atau e. kegiatan."}, {"l": "UU 20/2025", "p": "17", "b": "Bagian Ketiga", "t": "(1) Sebelum melakukan Penyelidikan, Penyelidik wajib membuat rencana Penyelidikan. (21 Rencana Penyelidikan sebagaimana dimaksud pada ayat (l) diajukan oleh Penyelidik kepada Penyidik. (3) Rencana . . . REPIJBLIK INDONESIA -t7- (3) Rencana Penyelidikan sebagaimana dimaksud pada ayat (1) minimal memuat: a. surat perintah Penyelidikan; b. jumlah dan identitas Penyelidik yang akan melaksanakan Penyelidikan ; c. objek, sasaran, dan target hasil Penyelidikan; d. kegiatan dan metode yang akan dilakukan dalam Penyelidikan; e. peralatan dan perlengkapan yang diperlukan dalam pelaksanaan Penyelidikan; f. waktu yang diperlukan dalam pelaksanaan Penyelidikan; dan g. kebutuhananggaran Penyelidikan."}, {"l": "UU 20/2025", "p": "18", "b": "Bagian Ketiga", "t": "(1) Penyelidik wajib membuat laporan hasil Penyelidikan secara tertulis kepada Penyidik. (2) Laporan sebagaimana dimaksud pada ayat (1) minimal memuat: a. tempat dan waktu; b. kegiatan Penyelidikan; c. hasil Penyelidikan; d. hambatan; dan e. pendapat/saran."}, {"l": "UU 20/2025", "p": "19", "b": "Bagian Ketiga", "t": "(l) Gelar perkara terhadap hasil Penyelidikan sebagaimana dimaksud dalam Pasal 18 ayat (1) dilaksanakan oleh Penyidik untuk memutuskan status peristiwa yang dimuat dalam hasil Penyelidikan merupakan tindak pidana atau bukan tindak pidana. (21 Dalam hal Penyidik memutuskan status peristiwa sebagaimana dimaksud pada ayat (l) merupakan tindak pidana, Penyidik menindaklanjuti peristiwa tersebut ke tahap Penyidikan. (3) Dalam . . . FRESIDEN (3) Dalam hal Penyidik memutuskan status peristiwa sebagaimana dimaksud pada ayat (1) bukan merupakan tindak pidana, Penyidik menghentikan Penyelidikan. (4) Dalam hal Penyidik memutuskan status peristiwa sebagaimana dimaksud pada ayat (1) merupakan tindak pidana, namun bukan kewenangan Penyidik yang bersangkutan, Penyidik yang bersangkutan melimpahkan berkas perkara hasil Penyelidikan kepada instansi yang berwenang."}, {"l": "UU 20/2025", "p": "20", "b": "Bagian Ketiga", "t": "(1) Dalam melaksanakan tugas Penyelidikan, Penyelidik dikoordinasikan, diawasi, dan diberi petunjuk oleh Penyidik Polri. (21 Ketentuan sebagaimana dimaksud pada ayat (1) dikecualikan untuk Penyelidikan di Kejaksaan Pidana Korupsi, dan Tentara Nasional Indonesia Angkatan Laut sesuai dengan ketentuan Undang- Undang."}, {"l": "UU 20/2025", "p": "21", "b": "Bagian Ketiga", "t": "Ketentuan lebih lanjut mengenai Penyelidikan sebagaimana dimaksud dalam Pasal 13 sampai dengan Pasal 20 diatur dalam Peraturan Pemerintah."}, {"l": "UU 20/2025", "p": "22", "b": "Bagian Keempat", "t": "(l) Untuk kepentingan Penyidikan, Penyidik dapat memanggil atau mendatangi seseorang untuk memperoleh keterangan tanpa sebelumnya memberi status orang tersebut sebagai Tersangka atau Saksi. (2) Untuk. . . REPIJBLIK INDONESIA (21 Untuk kepentingan Penyidikan, Penyidik dapat menetapkan Tersangka sebagai saksi mahkota untuk membantu mengungkapkan keterlibatan Tersangka lain yang patut dipidana dalam perkara yang sama. (3) Dalam menetapkan saksi mahkota sebagaimana dimaksud pada ayat (2), Penyidik berkoordinasi dengan Penuntut Umum dan dituangkan dalam berita acara. (4) Untuk kepentingan Penyidikan, Penyidik dapat menerima pengakuan bersalah dari Tersangka dengan dituangkan dalam berita acara. (5) Dalam menerima pengaluan bersalah sebagaimana dimaksud pada ayat (4), Penyidik berkoordinasi dengan Penuntut Umum."}, {"l": "UU 20/2025", "p": "23", "b": "Bagian Keempat", "t": "(l ) Setiap orang yang mengetahui permufakatan jahat untuk melakukan tindak pidana wajib seketika itu juga melaporkan hal tersebut kepada Penyelidik atau Penyidik. (21 Laporan atau Pengaduan yang diajukan secara tertulis kepada Penyelidik atau Penyidik harus ditandatangani oleh pelapor atau pengadu. (3) Laporan atau Pengaduan yang diajukan secara lisan harus dicatat oleh Penyelidik atau Penyidik dan ditandatangani oleh pelapor atau pengadu dan Penyelidik atau Penyidik. (4) Dalam hal pelapor atau pengadu tidak bisa baca tulis, hal itu harus disebutkan sebagai catatan dalam Laporan atau Pengaduan tersebut. (5) Setelah menerima Laporan atau Pengaduan, Penyelidik atau Penyidik harus memberikan surat tanda penerimaan Laporan atau Pengaduan kepada yang bersangkutan. (6) Dalam . . . K INDONESIA (6) Dalam hal Penyelidik atau Penyidik tidak menanggapi Laporan atau Pengaduan, dalam jangka waktu paling lama 14 (empat belas) Hari terhitung sejak Laporan atau Pengaduan diterima, pelapor atau pengadu dapat melaporkan Penyelidik atau Penyidik yang tidak menindaklanjuti Laporan atau Pengaduan kepada atasan Penyidik atau pejabat pengemban fungsi pengawasan dalam Penyidikan. (7) Penyelidik atau …"}, {"l": "UU 20/2025", "p": "24", "b": "Bagian Keempat", "t": "(1) Dalam hal Penyidik menghentikan Penyidikan, Penyidik memberitahukan penghentian Penyidikan kepada Penuntut Umum, Korban, Tersangka, atau Keluarga Tersangka. (21 Penghentian Penyidikan sebagaimana dimaksud pada ayat (1) dilakukan karena: a. tidak terdapat cukup alat bukti; b. peristiwa tersebut bukan merupakan tindak pidana; c. Penyidikan dihentikan demi hukum; d. terdapat Putusan Pengadilan yang telah memperoleh kekuatan hukum tetap terhadap Tersangka atas perkara yang sama; e. kedaluwarsa; f. Tersangka meninggal dunia; g. ditariknya Pengaduan pada tindak pidana aduan; h. tercapainya penyelesaian perkara melalui mekanisme Keadilan Restoratif; i. Tersangka membayar maksimum pidana denda atas tindak pidana yang hanya diancam dengan pidana denda paling banyak kategori II; atau j. Tersangka . . . PNESIDEN REPUBUK INDONESIA -2L- j. Tersangka membayar maksimum pidana denda kategori IV atas tindak pidana yang diancam dengan pidana penjara paling lama I (satu) tahun atau pidana denda paling banyak kategori III. (3) Dalam hal PPNS atau Penyidik Tertentu menghentikan Penyidikan, PPNS atau Penyidik Tertentu wajib melibatkan Penyidik Polri. (4) Dalam hal Penyidik menghentikan Penyidikan, …"}, {"l": "UU 20/2025", "p": "25", "b": "Bagian Keempat", "t": "Penyidik dapat menggabungkan atau memisahkan perkara untuk memudahkan Penyidikan."}, {"l": "UU 20/2025", "p": "26", "b": "Bagian Keempat", "t": "(l) Penyidik berwenang memanggil Tersangka dan/ atau Saksi untuk dilakukan pemeriksaan. (2) Pemanggilan sebagaimana dimaksud pada ayat (1) dilakukan dengan surat panggilan yang sah dengan memperhatikan jangka waktu yang wajar dan menyebutkan alasan pemanggilan secara jelas."}, {"l": "UU 20/2025", "p": "27", "b": "Bagian Keempat", "t": "Dalam hal terhadap penghentian Penyidikan yang dilakukan untuk menindaklanjuti keputusan gelar perkara diajukan permohonan ke pengadilan negeri untuk memeriksa sah atau tidalnya penghentian Penyidikan dan pengadilan negeri memutuskan penghentian Penyidikan tidak sah, Penuntut Umum wajib melakukan Penuntutan. Pasal 28..."}, {"l": "UU 20/2025", "p": "28", "b": "Bagian Keempat", "t": "(l) Tersangka dan/ atau Saksi yang dipanggil wajib datang di hadapan Penyidik. (2) Dalam hal Tersangka dan/atau Saksi tidak datang, Penyidik memanggil sekali lagi dengan meminta bantuan kepada pejabat yang berwenang untuk membawa Tersangka dan/atau Saksi kepada Penyidik."}, {"l": "UU 20/2025", "p": "29", "b": "Bagian Keempat", "t": "(1) Dalam hal Tersangka dan/atau Saksi yang dipanggil tidak datang dengan memberi alasan yang sah dan patut kepada Penyidik yang melakukan pemeriksaan, Penyidik tersebut datang ke tempat kediamannya untuk melakukan pemeriksaan. (2) Dalam hal Tersangka dan/atau Saksi menghindar dari pemeriksaan, Penyidik dapat langsung mendatangi kediaman Tersangka dan/ atau Saksi tanpa terlebih dahulu dilakukan pemanggilan untuk melakukan pemeriksaan."}, {"l": "UU 20/2025", "p": "30", "b": "Bagian Keempat", "t": "(U Pemeriksaan terhadap seseor€rng yang disangka melakukan tindak pidana direkam dengan menggunakan kamera pengawas selama pemeriksaan berlangsung. (21 Rekaman kamera pengawas sebagaimana dimaksud pada ayat (1) dilakukan untuk kepentingan Penyidikan, Penuntutan, pembelaan terhadap Tersangka atau Terdakwa dan dalam pemeriksaan di sidang pengadilan atas permintaan Hakim. (3) Ketentuan lebih lanjut mengenai penguasaan dan penggunaan rekaman kamera pengawas sebagaimana dimaksud pada ayat (l) dan ayat (21 diatur dalam Peraturan Pemerintah."}, {"l": "UU 20/2025", "p": "31", "b": "Bagian Keempat", "t": "Sebelum dimulainya pemeriksaan sebagaimana Pasal 3O, Penyidik wajib memberitahukan kepada Tersangka mengenai haknya untuk mendapatkan Bantuan Hukum atau pendampingan oleh Advokat atau Pemberi Bantuan Hukum. Pasal 32... REPUELIK INDONESIA"}, {"l": "UU 20/2025", "p": "32", "b": "Bagian Keempat", "t": "(1) Dalam hal Penyidik sedang melakukan pemeriksaan terhadap Tersangka, Advokat atau Pemberi Bantuan Hukum mendampingi selama jalannya pemeriksaan. (21 Dalam hal Penyidik melakukan intimidasi dan/ atau mengajukan pertanyaan yang bersifat menjerat terhadap Tersangka, Advokat atau Pemberi Bantuan Hukum dapat menyatakan keberatan. (3) Keberatan sebagaimana dimaksud pada ayat (2) dicatat dalam berita acara."}, {"l": "UU 20/2025", "p": "33", "b": "Bagian Keempat", "t": "(1) Penyidik memeriksa Saksi dengan tidak disumpah, kecuali jika terdapat cukup alasan untuk diduga bahwa Saksi tidak akan dapat hadir dalam pemeriksaan di pengadilan. (21 Penyidik memeriksa Saksi secara tersendiri, tetapi dapat dipertemukan yang satu dengan yang lain dan wajib memberikan keterangan yang sebenamya. (3) Keterangan Saksi kepada Penyidik diberikan tanpa tekanan dari siapapun atau dalam bentuk apapun."}, {"l": "UU 20/2025", "p": "34", "b": "Bagian Keempat", "t": "(l) Dalam memberikan penjelasan atau keterangan pada tingkat Penyidikan, Tersangka diberitahukan haknya. (21 Penyidik mencatat keterangan Tersangka secara teliti sesuai dengan yang dikatakannya dalam pemeriksaan dan dimuat dalam berita acara pemeriksaan. (3) Dalam hal keterangan Tersangka tidak menggunakan bahasa Indonesia, Penyidik wajib menunjuk Penerjemah untuk menerjemahkan keterangan Tersangka. (4) Keterangan Tersangka sebagaimana dimaksud pada ayat (3) harus ditandatangani oleh Penerjemah dan dilampirkan pada berkas perkara. (5) Dalam . . . (5) Dalam hal Tersangka merupakan Penyandang Disabilitas, Penyidik memfasilitasi akses dukungan kebutuhan khusus, diantaranya namun tidak terbatas pada juru bahasa dan pendamping sesuai ragam disabilitasnya."}, {"l": "UU 20/2025", "p": "35", "b": "Bagian Keempat", "t": "(l) Penyidik wajib memeriksa Saksi yang dihadirkan oleh Tersangka untuk diambil keterangannya. (21 Da1am pemeriksaan Saksi sebagaimana dimaksud pada ayat (1) Keterangan Saksi dicatat dalam berita acara pemeriksaan."}, {"l": "UU 20/2025", "p": "36", "b": "Bagian Keempat", "t": "(1) Keterangan Tersangka dan/atau Saksi dicatat dalam berita acara pemeriksaan yang ditandatangani oleh Penyidik, Tersangka, dan/ atau Saksi setelah membaca dan mengerti isinya. (21 Dalam hal Tersangka dan/atau Saksi tidak bisa baca tulis, Tersangka dan/atau Saksi membubuhkan cap jempol pada berita acara pemeriksaan setelah Penyidik membacakan keterangan Tersangka dan/atau Saksi tersebut. (3) Dalam hal Tersangka dan/atau Saksi tidak bersedia membubuhkan tanda tangan atau cap jempol, Penyidik mencatat hal tersebut dalam berita acara pemeriksaan dengan menyebut alasannya."}, {"l": "UU 20/2025", "p": "37", "b": "Bagian Keempat", "t": "(1) Dalam hal Tersangka dan/ atau Saksi yang harus didengar keterangannya berdiam atau bertempat tinggal di luar daerah hukum Penyidik yang melakukan Penyidikan, pemeriksaan terhadap Tersangka dan/atau Saksi dapat dilimpahkan kepada Penyidik di tempat kejadian atau tempat tinggal Tersangka dan/ atau Saksi tersebut. (2) Berita... PIIESIDEN NEPUELIK INDONESIA l2l Berita acara pemeriksaan terhadap Tersangka dan/ atau Saksi sebagaimana dimaksud pada ayat (1) harus diserahkan kepada Penyidik yang melakukan Penyidikan dalam jangka waktu paling lama 1O (sepuluh) Hari terhitung sejak pemeriksaan selesai dilaksanakan."}, {"l": "UU 20/2025", "p": "38", "b": "Bagian Keempat", "t": "(1) Dalam hal Penyidik menganggap perlu, Penyidik dapat meminta Keterangan Ahli. l2l Sebelum memberikan Keterangan Ahli sebagaimana dimaksud pada ayat (l), Ahli mengangkat sumpah atau mengucapkan janji di muka Penyidik untuk memberikan keterangan menurut dengan sebaik-baiknya. (3) Jika Ahli yang karena harkat dan martabat, pekerjaan, atau jabatan diwajibkan menyimpan rahasia, Ahli dapat menolak untuk memberikan keterangan yang diminta."}, {"l": "UU 20/2025", "p": "39", "b": "Bagian Keempat", "t": "Penyidik atas kekuatan sumpah jabatannya dalam jangka waktu paling lama 3 (tiga) Hari membuat berita acara yang diberi tanggal dan memuat: a. tindak pidana yang dipersangkakan dengan menyebut waltu, tempat, dan keadaan pada waktu tindak pidana dilakukan; b. nama dan tempat tinggal dari Tersangka dan/atau Saksi;. c. keterangan Tersangka, Saksi, dan/atau Ahli; d. catatan mengenai akta dan/atau benda; dan e. segala sesuatu yang dianggap perlu untuk kepentingan penyelesaian perkara."}, {"l": "UU 20/2025", "p": "40", "b": "Bagian Keempat", "t": "Dalam hal Tersangka ditahan, dalam waktu 1 (satu) Hari setelah perintah Penahanan tersebut dijalankan, Tersangka harus mulai diperiksa oleh Penyidik. Pasal 41 ... REFUBLIK INDONESIA"}, {"l": "UU 20/2025", "p": "41", "b": "Bagian Keempat", "t": "Dalam hal Penyidik melakukan Penggeledahan, penyidik terlebih dahulu menunjukkan tanda pengenalnya dan surat izin Penggeledahan dari ketua pengadilan negeri kepada Tersangka atau Keluarganya."}, {"l": "UU 20/2025", "p": "42", "b": "Bagian Keempat", "t": "(l) Penyidik membuat berita acara Penggeledahan. (2) Penyidik lebih dahulu membacal<an berita acara Penggeledahan kepada Tersangka, kemudian diberi tanggal dan ditandatangani oleh Penyidik, Tersangka atau Keluarganya, dan kepala desa/lurah atau nama lainnya atau ketua rukun tetangga dengan 2 (dua) orang saksi. (3) Dalam hal Tersangka atau Keluarganya tidak bersedia membubuhkan tanda tangan, hal tersebut dicatat dalam berita acara dengan menyebut alasannya."}, {"l": "UU 20/2025", "p": "43", "b": "Bagian Keempat", "t": "(l) Untuk keamanan dan ketertiban Penggeledahan, Penyidik dapat mengadalan penjagaan atau penutupan tempat yang bersangkutan. (21 Penyidik berhak memerintahkan setiap orang yang dianggap perlu untuk tidak meninggalkan tempat tersebut selama Penggeledahan sebagaimana dimaksud pada ayat (1) berlangsung."}, {"l": "UU 20/2025", "p": "44", "b": "Bagian Keempat", "t": "Dalam hal Penyidik melakukan Penyitaan, Penyidik terlebih dahulu menunjukkan tanda pengenalnya dan surat izin Penyitaan dari ketua pengadilan negeri kepada pemilik atau pihak yang menguasai benda tersebut. Pasal 45... BLIK INDONESIA"}, {"l": "UU 20/2025", "p": "45", "b": "Bagian Keempat", "t": "(l) Penyidik menjelaskan benda yang akan disita kepada pemilik atau pihak yang menguasai benda tersebut atau Keluarganya dan dapat meminta keterangan mengenai benda yang akan disita tersebut dengan disaksikan oleh kepala desa/lurah atau nama lainnya atau ketua rukun tetangga dengan 2 (dua) orang saksi. (21 Penyidik membuat berita acara Penyitaan yang kemudian dibacakan kepada pemilik atau pihak yang menguasai benda atau Keluarganya dengan diberi tanggal dan ditandatangani oleh Penyidik, pemilik atau pihak yang menguasai benda, atau Keluarganya dan kepala desa/lurah atau nama lainnya atau ketua rukun tetangga dengan 2 (dua) orang saksi. (3) Dalam hal pemilik atau pihak yang menguasai benda atau Keluarganya tidak bisa baca tulis, berita acara Penyitaan sebagaimana dimaksud pada ayat (2) dibacakan oleh Penyidik, serta diberi tanggal dan ditandatangani oleh Penyidik, dibubuhkan cap jempol oleh pemilik atau pihak yang menguasai benda atau Keluarganya, dan ditandatangani oleh kepala desa/lurah atau nama lainnya atau ketua rukun tetangga dengan 2 (dua) orang saksi. (4) Dalam hal pemilik atau pihak yang menguasai benda tidak bersedia membubuhkan tandatangannya atau cap jempol, hal …"}, {"l": "UU 20/2025", "p": "46", "b": "Bagian Keempat", "t": "(l) Benda sitaan sebelum dibungkus, dicatat mengenai berat dan/ atau jumlah menurut jenis masing-masing, ciri atau sifat khas, tempat, hari dan tanggal Penyitaan, dan identitas pemilik atau pihak yang menguasai benda yang disita atau Keluarganya, yang kemudian diberi lak dan cap jabatan yang ditandatangani oleh Penyidik. (2) Dalam . . . R,EPUBUK INDONESIA (21 Dalam hal benda sitaan tidak mungkin dibungkus, Penyidik memberi catatan sebagaimana dimaksud pada ayat (1) yang ditulis di atas label dan ditempelkan atau dikaitkan pada benda sitaan."}, {"l": "UU 20/2025", "p": "47", "b": "Bagian Keempat", "t": "Untuk pengungkapan suatu tindak pidana, Penyidik dapat melakukan Penggeledahan terhadap surat, buku, kitab, daftar, atau data tertulis lain yang belum disita dan jika diperlukan Penyidik dapat melakukan Penyitaan terhadap surat, buku, kitab, daftar, atau data tertulis lain tersebut."}, {"l": "UU 20/2025", "p": "48", "b": "Bagian Keempat", "t": "(1) Dalam hal Pengaduan yang diterima terdapat surat atau tulisan palsu, dipalsukan, atau diduga palsu oleh Penyidik, untuk kepentingan Penyidikan, Penyidik dapat meminta keterangan mengenai hal itu kepada Ahli. l2l Dalam hal timbul dugaan kuat terdapat surat atau tulisan palsu atau dipalsukan, Penyidik dengan surat izin ketua pengadilan negeri dapat datang atau dapat meminta pejabat penyimpan umum untuk mengirimkan surat asli yang disimpannya sebagai bahan perbandingan. (3) Pejabat penyimpan umum sebagaimana dimaksud pada ayat (2) wajib memenuhi permintaan Penyidik. (41 Dalam hal suatu surat yang dipandang perlu untuk pemeriksaan menjadi bagian dan tidak dapat dipisahkan dari daftar sebagaimana dimaksud dalam Pasal 47, Penyidik dapat meminta daftar tersebut seluruhnya selama waktu yang ditentukan dalam surat permintaan dikirimkan kepadanya untuk diperiksa, dengan menyerahkan tanda penerimaan. (5) Dalam hal surat sebagaimana dimaksud pada ayat (21 tidak menjadi bagian dari suatu daftar, penyimpan membuat salinan sebagai penggantinya sampai surat asli diterima kembali dan di bagian bawah dari salinan tersebut diberi catatan salinan tersebut dibuat. (6) Dalam . . . Er-fSJftIaIl …"}, {"l": "UU 20/2025", "p": "49", "b": "Bagian Keempat", "t": "(1) Dalam hal Penyidik untuk kepentingan peradilan menangani korban luka, keracunan, atau mati yang diduga akibat peristiwa tindak pidana, Penyidik berwenang mengajukan permintaan keterangan kepada Ahli kedokteran forensik atau dokter dan/ atau Ahli lainnya. (21 Permintaan Keterangan Ahli sebagaimana dimaksud pada ayat (1) dilakukan secara tertulis dengan menyebutkan secara tegas untuk pemeriksaan luka, keracunan, mayat, dan/atau bedah mayat. (3) Dalam hal korban mati, mayat dikirim kepada Ahli kedokteran forensik dan/atau dokter pada rumah sakit dengan memperlakukan mayat tersebut secara baik dengan penuh penghormatan dan diberi label yang dilak dan diberi cap jabatan yang memuat identitas mayat dan dilekatkan pada ibu jari kaki atau bagian lain badan mayat."}, {"l": "UU 20/2025", "p": "50", "b": "Bagian Keempat", "t": "(l) Dalam hal untuk keperluan pembuktian diperlukan pembedahan mayat yang tidak mungkin lagi dihindari, Penyidik wajib terlebih dahulu memberitahukan pembedahan mayat tersebut kepada Keluarga Korban. (21 Dalam hal Keluarga Korban keberatan, Penyidik wajib menerangkan dengan jelas maksud dan tqluan pembedahan mayat kepada Keluarga Korban. (3) Dalam hal Keluarga Korban keberatan sebagaimana dimaksud pada ayat (2) atau Keluarga Korban atau pihak yang perlu diberitahukan tidak ditemukan, Penyidik dapat meminta penetapan dari pengadilan negeri setelah dilakukan pembedahan mayat. Pasal 5l ... FRESIDEN"}, {"l": "UU 20/2025", "p": "51", "b": "Bagian Keempat", "t": "Dalam hal untuk kepentingan peradilan Penyidik perlu melakukan penggalian mayat, kepentingan tersebut dilaksanakan sesuai dengan ketentuan sebagaimana dimaksud dalam Pasal 49 ayat (2) dan Pasal 5O ayat (1)."}, {"l": "UU 20/2025", "p": "52", "b": "Bagian Keempat", "t": "Semua biaya yang dikeluarkan untuk kepentingan Penyidikan dibebankan kepada negara."}, {"l": "UU 20/2025", "p": "53", "b": "Bagian Kelima", "t": "(1) Setiap pelapor, pengadu, Saksi, dan/ atau Korban berhak memperoleh pelindungan. (21 Pelindungan sebagaimana dimaksud pada ayat (1) berlaku pada setiap tahap pemeriksaan. (3) Dalam hal diperlukan, pelindungan dapat dilakukan secara khusus dan tanpa batas waktu. (41 Pelindungan sebagaimana dimaksud pada ayat (1) dilaksanakan oleh lembaga yang melaksanakan tugas dan fungsi di bidang pelindungan Saksi dan Korban. (5) Penyidik, Penuntut Umum, dan Hakim berkoordinasi dengan lembaga yang melaksanakan tugas dan fungsi di bidang pelindungan Saksi dan Korban sebagaimana dimaksud pada ayat (4). (6) Tata cara pemberian pelindungan dilaksanakan sesuai dengan ketentuan peraturan perundang-undangan."}, {"l": "UU 20/2025", "p": "54", "b": "Bagian Kelima", "t": "Semua biaya yang dikeluarkan untuk kepentingan pelindungan pelapor, pengadu, Saksi, dan/atau Korban dibebankan kepada negara. Brgian REPUBUK INDONESIA"}, {"l": "UU 20/2025", "p": "55", "b": "Bagian Keenam", "t": "Penyidik dalam melaksanakan Penyidikan tindak pidana didukung dengan bantuan teknis Penyidikan untuk pembuktian secara ilmiah."}, {"l": "UU 20/2025", "p": "56", "b": "Bagian Keenam", "t": "(1) Bantuan teknis Penyidikan sebagaimana dimaksud dalam Pasal 55, meliputi: a. laboratorium forensik, digunakan dalam hal Penyidik memerlukan pemeriksaan dan pengujian barang bukti yang harus mendapat penanganan dan/ atau perlakuan khusus; b. identifikasi, digunakan dalam hal Penyidik memerlukan kepastian identitas Tersangka, Saksi, atau Korban tindak pidana dan sebagai alat bukti; c. kedokteran forensik, digunakan dalam hal Penyidik memerlukan pemeriksaan Tersangka, Saksi, atau Korban yang harus mendapatkan penanganan atau perlakuan fisik secara khusus; d. psikologi forensik, digunakan dalam hal Penyidik memerlukan pemeriksaan Tersangka, Saksi, atau Korban yang harus mendapatkan penanganan atau perlakuan psikis secara khusus; e. digital forensik, digunakan dalam hal Penyidik memerlukan pemeriksaan dan pengujian barang bukti digital yang harus mendapat penanganan atau perlakuan secara khusus; dan f. bantuan teknis lain yang dibutuhkan. (21 Bantuan teknis sebagaimana dimaksud pada ayat (1) dilaksanakan oleh Kepolisian Negara Republik Indonesia. (3) Dalam melaksanakan bantuan teknis sebagaimana dimaksud pada ayat (l), Kepolisian Negara Republik Indonesia dapat meminta bantuan …"}, {"l": "UU 20/2025", "p": "57", "b": "Bagian Keenam", "t": "Ketentuan lebih lanjut mengenai bantuan teknis Penyidikan sebagaimana dimaksud dalam Pasal 55 dan Pasal 56 diatur dalam Peraturan Pemerintah."}, {"l": "UU 20/2025", "p": "58", "b": "Bagian Ketujuh", "t": "Penanganan setiap tindak pidana dilaksanakan oleh Penyidik dengan melibatkan Penuntut Umum dengan cara berkoordinasi sesuai dengan kewenangan masing-masing dalam kerangka sistem peradilan pidana terpadu."}, {"l": "UU 20/2025", "p": "59", "b": "Bagian Ketujuh", "t": "(1) Koordinasi antara Penyidik dan Penuntut Umum dalam penanganan setiap tindak pidana sebagaimana dimaksud dalam Pasal 58 dilakukan secara setara, saling melengkapi, dan saling mendukung. (21 Koordinasi antara Penyidik dan Penuntut Umum dimulai dari pengiriman surat pemberitahuan dimulainya Penyidikan yang dikirim oleh Penyidik kepada Penuntut Umum. (3) Koordinasi antara Penyidik dan Penuntut Umum dapat dilakukan dengan menggunakan sarana teknologi informasi. (41 Koordinasi sebagaimana dimaksud pada ayat (2) dilakukan sebelum dan setelah hasil Penyidikan dikirimkan Penyidik kepada Penuntut Umum serta wajib dituangkan dalam berita acara. (5) Koordinasi yang dilakukan setelah hasil Penyidikan dikirimkan Penyidik kepada Penuntut Umum, hanya dapat dilakukan 1 (satu) kali dalam setiap perkara. (6) Pendapat Penuntut Umum dalam penelitian berkas perkara meliputi aspek formal dan aspek materiel. (7) Pemberitahuan . . . K INDONESIA (71 Pemberitahuan lengkapnya berkas perkara yang diajukan Penyidik, dituangkan dalam surat pemberitahuan yang ditandatangani oleh kepala kejaksaan negeri selaku penanggung jawab Penuntutan di wilayah hukum yang bersangkutan. (8) Dalam hal berkas perkara …"}, {"l": "UU 20/2025", "p": "60", "b": "Bagian Ketujuh", "t": "(1) Pemberitahuan dimulainya Penyidikan oleh Penyidik kepada Penuntut Umum dikirimkan dalam jangka waktu paling lama 7 (tujuh) Hari setelah Penyidikan dimulai. (21 Dalam waktu paling lama 3 (tiga) Hari sejak surat pemberitahuan dimulainya Penyidikan diterima kejaksaan sebagaimana dimaksud pada ayat (l), Penyidik berkoordinasi dengan Penuntut Umum yang ditunjuk untuk mengikuti perkembangan Penyidikan. (3) Dalam berjalannya Penyidikan, Penyidik dapat berkoordinasi dengan Penuntut Umum dalam melengkapi berkas perkara, perpanjangan Penahanan, dan/atau pemberitahuan penghentian Penyidikan."}, {"l": "UU 20/2025", "p": "61", "b": "Bagian Ketujuh", "t": "(1) Setelah Penyidikan selesai, Penyidik menyampaikan hasil Penyidikan beserta berkas perkara kepada Penuntut Umum untuk dilakukan penelitian berkas perkara dalam jangka waktu paling lama 7 (tujuh) Hari terhitung sejak tanggal diterimanya berkas perkara dari Penyidik. (21 Dalam hal Penuntut Umum menilai berkas perkara yang diterima dari Penyidik belum lengkap, Penuntut Umum mengembalikan berkas perkara kepada Penyidik disertai dengan petunjuk mengenai hal yang harus dilengkapi berdasarkan hasil koordinasi. (3) Penyidik wajib melengkapi berkas perkara melalui Penyidikan tambahan sesuai hasil koordinasi dengan Penuntut Umum dalam jangka waktu paling lama 14 (empat belas) Hari terhitung sejak tanggal diterimanya pengembalian berkas perkara dari Penuntut Umum. (4) Dalam . . . REPUELIK INDONESIA (4) Dalam hal berkas perkara dinyatakan lengkap oleh Penuntut Umum, Penyidik menyerahkan Tersangka dan barang bukti kepada Penuntut Umum untuk dilakukan Penuntutan."}, {"l": "UU 20/2025", "p": "62", "b": "Bagian Ketujuh", "t": "(1) Dalam hal Penuntut Umum berpendapat bahwa hasil Penyidikan tambahan masih belum lengkap, Penuntut Umum mengembalikan berkas perkara kepada Penyidik. (21 Penyidik melengkapi berkas perkara dalam jangka waktu paling lama 14 (empat belas) Hari untuk menindaklanjuti berkas perkara sebagaimana dimaksud pada ayat (l) dan mengundang Penuntut Umum untuk melakukan gelar perkara yang dihadiri oleh Penyidik, pengawas Penyidik, Penuntut Umum, pengawas Penuntut Umum, dan Ahli. (3) Dalam hal hasil gelar perkara memutuskan status perkara dihentikan, Penyidik wajib mengeluarkan surat ketetapan penghentian Penyidikan dengan memberitahukan surat penghentian Penyidikan kepada Penuntut Umum. l4l Dalam hal hasil gelar perkara memutuskan status berkas perkara lengkap, Penyidik mengirim kembali berkas perkara kepada Penuntut Umum untuk dinyatakan sebagai berkas perkara yang lengkap dan selanjutnya dilakukan Penuntutan. (5) Dalam keadaan Penyidik berkesimpulan bahwa Penyidikan telah cukup bukti, sedangkan Penuntut Umum berpendapat bahwa Penyidikan belum maksimal, Penyidik dapat menyerahkan Tersangka disertai dengan hasil Penyidikan dan bukti kepada Penuntut Umum. (6) Dalam jangka waktu paling lama 14 …"}, {"l": "UU 20/2025", "p": "63", "b": "Bagian Ketujuh", "t": "Ketentuan lebih lanjut mengenai tata cara koordinasi antara Penyidik dan Penuntut Umum sebagaimana dimaksud dalam Pasal 58 sampai dengan Pasal 62 diatur dalam Peraturan Pemerintah."}, {"l": "UU 20/2025", "p": "64", "b": "Bagian Kesatu", "t": "Penuntut Umum terdiri atas: a. pejabat Kejaksaan Republik Indonesia; dan b. pejabat suatu lembaga yang diberi kewenangan untuk melakukan Penuntutan berdasarkan ketentuan Undang-Undang."}, {"l": "UU 20/2025", "p": "65", "b": "Bagian Kesatu", "t": "Penuntut Umum mempunyai wewenang: a. menerima dan memeriksa berkas perkara Penyidikan dari Penyidik; b. melakukan koordinasi antara Penyidik dan Penuntut Umum untuk kepentingan melengkapi hasil Penyidikan; c. memberikan perpanjangan Penahanan, melal<ukan Penahanan atau Penahanan lanjutan, dan/atau mengubah status tahanan setelah perkaranya dilimpahkan oleh Penyidik; d. membuat surat dakwaan; e. melimpahkan perkara dan melakukan Penuntutan ke pengadilan; f. melakukan penghentian Penuntutan dengan memberitahukan kepada Penyidik; g. menyampaikan . . . T:]TI-iFITII=N K INDONESIA g. menyampaikan pemberitahuan kepada Terdakwa mengenai ketentuan waktu dan tempat perkara disidangkan dan disertai surat panggilan kepada Terdakwa dan Saksi, untuk datang pada sidang yang telah ditentukan; h. melaksanakan penetapan dan/ atau putusan Hakim pengadilan negeri, Hakim pengadilan tinggi, atau Halim Mahkamah Agung; i. melakukan penyelesaian denda damai; j. melakukan penyelesaian perkara melalui mekanisme Keadilan Restoratif; k. melakukan Perjanjian Penundaan Penuntutan; l. menerima Pengakuan Bersalah; dan m. menutup perkara demi kepentingan hukum."}, {"l": "UU 20/2025", "p": "66", "b": "Bagian Kesatu", "t": "(l) Denda damai sebagaimana dimaksud dalam Pasal 65 huruf i merupakan mekanisme penghentian perkara di luar pengadilan dengan membayar denda yang disetujui oleh Jaksa Agung sesuai dengan ketentuan peraturan perundang-undangan. (21 Ketentuan lebih lanjut mengenai tata cara pelaksanaan denda damai diatur dalam Peraturan Pemerintah."}, {"l": "UU 20/2025", "p": "67", "b": "Bagian Kesatu", "t": "(1) Penuntut Umum menuntut perkara tindak pidana yang terjadi dalam daerah hukumnya sesuai dengan ketentuan Undang-Undang. (21 Dalam hal tertentu, Penuntut Umum dapat menuntut perkara tindak pidana di luar daerah hukum sebagaimana dimaksud pada ayat (l). (3) Untuk melaksanakan Penuntutan perkara di luar daerah hukum sebagaimana dimaksud pada ayat (21, Penuntut Umum harus mendapatkan surat pengangkatan sementara dari Jaksa Agung sebagai Jaksa di daerah hukum Penuntutan dilaksanakan. Pasal 68... REFIJELIK INDONESIA"}, {"l": "UU 20/2025", "p": "68", "b": "Bagian Kesatu", "t": "Penuntut Umum dalam melaksanakan tugas, fungsi, dan kewenangannya melampaui atau melanggar ketentuan peraturan perundang-undangan atau kode etik dikenai sanksi administratif, sanksi etik, atau sanksi pidana sesuai dengan ketentuan peraturan perundang-undangan."}, {"l": "UU 20/2025", "p": "69", "b": "Bagian Kedua", "t": "Penuntut Umum berwenang melakukan Penuntutan terhadap Terdakwa dalam daerah hukumnya dan melimpahkan perkara ke pengadilan negeri yang berwenang Mengadili."}, {"l": "UU 20/2025", "p": "70", "b": "Bagian Kedua", "t": "Dalam hal Penuntut Umum berpendapat bahwa dari hasil Penyidikan dapat dilakukan Penuntutan, Penuntut Umum membuat surat dakwaan dalam jangka waktu paling lama 7 (tujuh) Hari."}, {"l": "UU 20/2025", "p": "71", "b": "Bagian Kedua", "t": "(1) Dalam hal Penuntut Umum menghentikan Penuntutan karena gugurnya kewenangan menuntut, Penuntut Umum menuangkan penghentian Penuntutan dalam surat ketetapan. l2l Gugurnya kewenangan Penuntutan sebagaimana dimaksud pada ayat (l)jika: a. terdapat Putusan Pengadilan yang telah memperoleh kekuatan hukum tetap terhadap Terdakwa atas perkara yang sama; b. kedaluwarsa; c. Terdakwa meninggal dunia; d. ditariknya Pengaduan bagi tindak pidana aduan; e. Terdakwa membayar maksimum pidana denda atas tindak pidana yang hanya diancam dengan pidana denda paling banyak kategori II; f. Terdakwa . . . REPUBUK INDONESIA f. Terdakwa membayar maksimum pidana denda kategori IV atas tindak pidana yang diancam dengan pidana penjara paling lama 1 (satu) tahun atau pidana denda paling banyak kategori III; g. tercapainya penyelesaian perkara melalui mekanisme Keadilan Restoratif; atau h. diberikannya amnesti atau abolisi. (3) Isi surat ketetapan sebagaimana dimaksud pada ayat (1) diberitahukan kepada Tersangka dan jika Tersangka ditahan, wajib segera dibebaskan. (41 Salinan surat ketetapan sebagaimana dimaksud pada ayat (l) wajib disampaikan kepada Tersangka, Keluarganya, atau Advokat, pejabat rumah …"}, {"l": "UU 20/2025", "p": "72", "b": "Bagian Kedua", "t": "(l) Apabila pada waktu yang sama atau hampir bersamaan Penuntut Umum menerima beberapa perkara, Penuntut Umum dapat melakukan penggabungan perkara dan membuatnya dalam 1 (satu) surat dakwaan, dalam hal: a. beberapa tindak pidana dilakukan oleh seseorang yang sama dan kepentingan pemeriksaan tidak menjadikan halangan terhadap penggabungannya; b. beberapa tindak pidana bersangkut paut satu dengan yang lain; atau c. beberapa tindak pidana ada hubungannya satu dengan yang lain dan penggabungan tersebut diperlukan untuk kepentingan pemeriksaan. (21 Beberapa tindak pidana dapat dituntut dalam I (satu) surat dakwaan tanpa memperhatikan gabungan dari pidana umum atau khusus atau ditetapkan oleh Undang-Undang khusus sepanjang memenuhi ketentuan sebagaimana dimaksud pada ayat (1), kecuali dalam kompetensi pengadilan khusus. (3) Penuntut Umum dapat menuntut 2 (dua) atau lebih Terdakwa dalam I (satu) surat dakwaan, jika Terdakwa melakukan tindak pidana penyertaan. Pasal 73... REPUBUK INDONESIA"}, {"l": "UU 20/2025", "p": "73", "b": "Bagian Kedua", "t": "(1) Pentrntut Umum menetapkan saksi mahkota sebagqiman. dimaksud dalam Pasal 22 ayat (2) dan ayat (3). (21 Saksi mahkota sebagaimana dimaksud pada ayat (1) dapat diberikan keringanan dari tuntutan pidana, jika saksi mahkota membantu mengungkapkan keterlibatan Tersangka atau Terdakwa lain yang patut dipidana dalam perkara yang sama. Pasal T4 (1) Dalam hal Tersangka yang akan dijadikan sebagai saksi mahkota menerima untuk melakukan negosiasi kesepakatan saksi mahkota, Penuntut Umum memanggil Tersangka yang akan dijadikan sebagai saksi mahkota beserta Advokatnya untuk membahas isi kesepakatan dari perjanjian saksi mahkota. (2) Kesepakatan perjanjian salsi mahkota dibuat secara tertulis yang ditandatangani oleh Penuntut Umum, calon saksi mahkota, dan Advokatnya, yang memuat isi kesepakatan sebagai berikut: a. keterangan yang akan diungkapkan dalam persidangan Terdakwa pada persidangan lain; b. syarat pemberian keterangan yang wajib dipatuhi oleh saksi mahkota; c. pasal tindak pidana yang akan dituntut oleh Penuntut Umum kepada saksi mahkota; dan d. imbalan serta jaminan yang wajib diberikan oleh Penuntut Umum. (3) Imbalan serta jaminan yang diberikan oleh Penuntut Umum sebagaimana …"}, {"l": "UU 20/2025", "p": "75", "b": "Bagian Kedua", "t": "(1) Penuntut Umum melimpahkan perkara ke pengadilan negeri dengan permintaan agar Mengadili perkara tersebut disertai dengan surat dakwaan dalam jangka waktu paling lama 14 (empat belas) Hari. l2l Penuntut Umum membuat surat dakwaan yang berisi: a. tanggal penandatanganan, nama lengkap, tempat lahir, umur dan tanggal lahir, jenis kelamin, kebangsaan, tempat tinggal, agama, dan pekerjaan Tersangka; b. uraian secara cermat, jelas, dan lengkap mengenai tindak pidana yang didakwakan dengan menyebutkan waktu dan tempat tindak pidana dilakukan; c. pasal Undang-Undang yang dilanggar; dan d. tanda tangan Penuntut Umum. (3) Surat dakwaan yang tidak memenuhi ketentuan sebagaimana dimaksud pada ayat (2) huruf b batal demi hukum. (41 Dalam hal surat dakwaan batal demi hukum sebagaimana dimaksud pada ayat (3), Hakim memberikan kesempatan I (satu) kali kepada Penuntut Umum untuk memperbaiki dan menqajukan kembali surat dakwaan kepada pengadilan negeri. (5) Dalam hal surat dakwaan sebagaimana dimaksud pada ayat (4) masih diajukan keberatan oleh Terdakwa atau Advokatnya, Hakim memeriksa dan memutus keberatan tersebut bersama dengan pokok perkara dalam putusan akhir. (6) Salinan . . . ;TTT{I'IJII …"}, {"l": "UU 20/2025", "p": "76", "b": "Bagian Kedua", "t": "(1) Penuntut Umum dapat menyempurnakan surat dakwaan atau tidak melanjutkan Penuntutan sebelum pengadilan menetapkan hari sidang. (21 Penyempurnaan surat dakwaan sebagaimana dimaksud pada ayat (1) dapat dilakukan 1 (satu) kali paling lambat 7 (tujuh) Hari sebelum tanggal sidang dimulai. (3) Dalam hal Penuntut Umum menyempurnakan surat dakwaan, Penuntut Umum menyampaikan salinan surat dakwaan kepada Penyidik, Terdakwa, dan Advokat. Pasal TT Semua biaya yang dikeluarkan untuk kepentingan Penuntutan dibebankan kepada negara."}, {"l": "UU 20/2025", "p": "78", "b": "Bagian Ketiga", "t": "(1) Pengakuan Bersalah hanya dapat diterapkan dengan persyaratan: a. baru pertama kali melakukan tindak pidana; b. terhadap tindak pidana yang diancam dengan pidana penjara paling lama 5 (lima) tahun atau pidana denda paling banyak kategori V; dan/atau c. bersedia membayar Ganti Rugi atau Restitusi. l2l Penuntut Umum menanyakan kepada Terdakwa yang didampingi kuasa hukumnya apakah Terdakwa bersalah atau tidak. (3) Dalam . . . (3) Dalam hal Terdakwa mengalu bersalah, Terdakwa wajib didampingi oleh Advokat dan pengakuan tersebut dinyatakan dalam berita acara. (4) Pengakuan Bersalah diajukan dalam sidang tertentu sebelum persidangan pokok perkara dimulai. (5) Persidangan sebagaimana dimaksud pada ayat (4) dilakukan oleh Hakim tunggal. (6) Dalam hal Pengakuan Bersalah disepakati, pedanjian tertulis dibuat antara Penuntut Umum dan Terdakwa dengan persetujuan Hakim. (71 Kesepakatan sebagaimana dimaksud pada ayat (6) memuat sebagai berikut: a. Terdakwa mengetahui konsekuensi dari Pengakuan Bersalahnya, termasuk pengabaian hak diam dan hak untuk diadili dengan acara pemeriksaan biasa; b. pengakuan dilakukan secara sukarela; c. pasal yang didakwa dan ancaman hukuman yang akan dituntut …"}, {"l": "UU 20/2025", "p": "79", "b": "Bagian Kesatu", "t": "(l) Mekanisme Keadilan Restoratif dilakukan untuk memulihkan keadaan semula yang berupa: a. pemaafan dari Korban dan/atau Keluarganya; b. pengembalian barang yang diperoleh dari tindak pidana kepada Korban; c. penggantian biaya perawatan medis dan/atau psikologis; d. ganti rugi atas kerugian lain yang diderita Korban sebagai akibat tindak pidana yang dialami Korban; e. memperbaiki kerusakan yang ditimbulkan dari akibat tindak pidana yang dialami Korban; atau f. membayar ganti rugi yang ditimbulkan dari akibat tindak pidana. (2) Pemulihan keadaan semula sebagaimana dimaksud pada ayat (l) harus dituangkan dalam kesepakatan. (3) Kesepakatan sebagaimana dimaksud pada ayat (2) wajib dilaksanakan dalam jangka waktu paling lama 7 (tujuh) Hari. (4) Pencabutan Laporan atau Pengaduan hanya dapat dilalukan setelah pelaku memenuhi seluruh kesepakatan sebagaimana dimaksud pada ayat (2). (5) Setelah seluruh kesepakatan terlaksana, perkara wajib dihentikan dan dimintakan penetapan pengadilan. (6) Apabila. . . REP]JBLIK INDONESIA (6) Apabila kesepakatan tidak dilaksanakan oleh pelaku sampai dengan berakhirnya jangka waktu sebagaimana dimaksud pada ayat (3), Penyidik wajib membuat berita acara …"}, {"l": "UU 20/2025", "p": "80", "b": "Bagian Kesatu", "t": "(1) Mekanisme Keadilan Restoratif dapat dikenakan terhadap tindak pidana yang memenuhi syarat sebagai berikut: a. tindak pidana diancam hanya dengan pidana denda paling banyak kategori III atau diancam dengan pidana penjara paling lama 5 (lima) tahun; b. tindak pidana yang pertama kali dilakukan; dan/atau c. bukan merupakan pengulangan tindak pidana, kecuali terhadap tindak pidana yang putusannya berupa pidana denda atau tindak pidana yang dilakukan karena kealpaan. (2) Dalam . . . (21 Dalam hal belum terdapat tindak pidana sebagaimana dimaksud pada ayat (1), berdasarkan laporan Korban dilakukan mekanisme Keadilan Restoratif pada tahap Penyelidikan berupa kesepakatan damai antara pelaku dan Korban."}, {"l": "UU 20/2025", "p": "81", "b": "Bagian Kesatu", "t": "(1) Mekanisme Keadilan Restoratif dilakukan melalui: a. permohonan yang diajukan oleh pelaku tindak pidana, Tersangka, Terdakwa, atau Keluarganya, dan/atau Korban tindak pidana atau Keluarganya; atau b. penawaran dari Penyelidik, Penyidik, Penuntut Umum, atau Hakim kepada Korban, pelaku tindak pidana, Tersangka, atau Terdakwa. (21 Mekanisme Keadilan Restoratif sebagaimana dimaksud pada ayat (l) dilakukan tanpa tekanan, paksaan, intimidasi, tipu daya, ancaman kekerasan, kekerasan, penyiksaan, dan tindakan yang merendahkan kemanusian terhadap Tersangka, Terdakwa, Korban, dan/ atau Keluarganya."}, {"l": "UU 20/2025", "p": "82", "b": "Bagian Kesatu", "t": "Mekanisme Keadilan Restoratif dikecualikan untuk: a. tindak pidana terhadap keamanan negara, tindak pidana terhadap negara sahabat, kepala negara sahabat serta wakilnya, tindak pidana ketertiban umum, dan tindak pidana kesusilaan; b. tindak pidana terorisme; c. tindak pidana korupsi; d. tindak pidana kekerasan seksual; e. tindak pidana yang diancam dengan pidana penjara 5 (lima) tahun atau lebih, kecuali karena kealpaannya; f. tindak pidana terhadap nyawa orang; g. tindak pidana yang diancam dengan pidana minimum khusus; h. tindak pidana tertentu yang sangat membahayakan atau merugikan masyarakat; dan/ atau i. tindak pidana narkotika kecuali yang berstatus sebagai pengguna atau penyalahguna."}, {"l": "UU 20/2025", "p": "83", "b": "Bagian Kedua", "t": "(1) Mekanisme Keadilan Restoratif pada tahap Penyelidikan dan Penyidikan dilakukan melalui kesepakatan untuk menyelesaikan perkara di hadapan Penyelidik atau Penyidik. (21 Kesepakatan sebagaimana dimaksud pada ayat (1) dibuktikan dengan surat kesepakatan penyelesaian perkara dan ditandatangani oleh pelaku, Korban, dan Penyelidik atau Penyidik. (3) Berdasarkan surat kesepakatan penyelesaian perkara sebagaimana dimaksud pada ayat (2), Penyelidik menerbitkan surat penghentian Penyelidikan. (41 Berdasarkan surat kesepakatan penyelesaian perkara sebagaimana dimaksud pada ayat (21, Penyidik menerbitkan surat penghentian Penyidikan."}, {"l": "UU 20/2025", "p": "84", "b": "Bagian Kedua", "t": "Surat penghentian Penyidikan sebagaimana dimaksud dalam Pasal 83 ayat (4) diberitahukan oleh Penyidik kepada Penuntut Umum dan dimintakan penetapan kepada ketua pengadilan negeri dalam jangka waktu paling lama 3 (tiga) Hari."}, {"l": "UU 20/2025", "p": "85", "b": "Bagian Ketiga", "t": "(l ) Mekanisme Keadilan Restoratif pada tahap Penuntutan dilakukan melalui kesepakatan untuk menyelesaikan perkara di hadapan Penuntut Umum. (2) Kesepakatan . . . PRESIOEN (21 Kesepakatan sebagaimana dimaksud pada ayat (1) dibuktikan dengan surat kesepakatan penyelesaian perkara dan ditandatangani oleh Tersangka, Korban, dan Penuntut Umum. (3) Berdasarkan surat kesepakatan penyelesaian perkara sebagaimana dimaksud pada ayat (21, Penuntut Umum menerbitkan surat ketetapan penghentian Penuntutan."}, {"l": "UU 20/2025", "p": "86", "b": "Bagian Ketiga", "t": "(l) Surat ketetapan penghentian Penuntutan sebagaimana dimaksud dalam Pasal 85 ayat (3) dalam jangka waktu paling lama 3 (tiga) Hari dimintakan penetapan kepada ketua pengadilan negeri. (21 Penetapan ketua pengadilan negeri sebagaimana dimaksud pada ayat (1) wajib disampaikan oleh Penuntut Umum kepada Penyidik."}, {"l": "UU 20/2025", "p": "87", "b": "Bagian Keempat", "t": "Dalam hal mekanisme Keadilan Restoratif sebagaimana dimaksud dalam Pasal 79 sampai dengan Pasal 86 tidak dapat dilakukan, penerapan mekanisme Keadilan Restoratif dilakukan pada tahap pemeriksaan di sidang pengadilan melalui Putusan Pengadilan dan pelaksanaan Putusan Pengadilan."}, {"l": "UU 20/2025", "p": "88", "b": "Bagian Keempat", "t": "Ketentuan lebih lanjut mengenai pelaksanaan mekanisme Keadilan Restoratif dalam Pasal 79 sampai dengan Pasal 87 diatur dalam Peraturan Pemerintah. BABV... PRES!DEN PEPIIBLIK INDONESIA"}, {"l": "UU 20/2025", "p": "89", "b": "Bagian Kesatu", "t": "Bentuk Upaya Paksa meliputi: a. PenetapanTersangka; b. Penangkapan; c. Penahanan; d. Penggeledahan; e. Penyitaan; f. Penyadapan; g. pemeriksaan surat; h. Pemblokiran; dan i. larangan bagi Tersangka atau Terdakwa untuk keluar wilayah Indonesia."}, {"l": "UU 20/2025", "p": "90", "b": "Bagian Kedua", "t": "(l) Penetapan Tersangka dilakukan Penyidik terhadap seseorang yang diduga melakukan tindak pidana berdasarkan minimal 2 (dua) alat bukti. (21 Penetapan Tersangka sebagaimana dimaksud pada ayat (l) dituangkan dalam surat Penetapan Tersangka yang ditandatangani oleh Penyidik dan diberitahukan kepada Tersangka paling lama I (satu) Hari terhitung sejak surat Penetapan Tersangka dikeluarkan. (3) Surat... PTIES IDEN REPUBUK INDONESIA (3) Surat Penetapan Tersangka sebagaimana dimaksud pada ayat (2) memuat: a. identitasTersangka; b. uraian singkat perkara; dan c. hak Tersangka. (41 Dalam hal Tertangkap Tangan, Penyidik segera menerbitkan surat Penetapan Tersangka sebagaimana dimaksud pada ayat (2) dan ayat (3). (5) Dalam hal Tersangka merupakan warga negara asing, surat Penetapan Tersangka sebagaimana dimaksud pada ayat (2) dan ayat (3) diberitahukan kepada perwakilan negaranya. Pasal 9 I Dalam melakukan Penetapan Tersangka, Penyidik dilarang melakukan perbuatan yang menimbulkan praduga bersalah."}, {"l": "UU 20/2025", "p": "92", "b": "Bagian Kedua", "t": "Dalam melakukan pencarian Tersangka, Penyidik dapat meminta bantuan media dan masyarakat untuk memberikan informasi mengenai keberadaan Tersangka tersebut."}, {"l": "UU 20/2025", "p": "93", "b": "Bagian Ketiga", "t": "(1) Untuk kepentingan Penyidikan, Penyelidik atas perintah Penyidik berwenang melakukan Penangkapan. (21 Untuk kepentingan Penyidikan, Penyidik dan Penyidik Pembantu berwenang melakukan Penangkapan. (3) PPNS dan Penyidik Tertentu tidak dapat melakukan Penangkapan kecuali atas perintah Penyidik Polri. (4) Penangkapan... ELIK INDONESIA (4) Penangkapan sebagaimana dimaksud pada ayat (3) dikecualikan bagi Penyidik di Kejaksaan Republik Indonesia, Komisi Pemberantasan Tindak Pidana Korupsi, dan Tentara Nasional Indonesia Angkatan Laut sesuai dengan ketentuan Undang-Undang."}, {"l": "UU 20/2025", "p": "94", "b": "Bagian Ketiga", "t": "Penangkapan dilakukan terhadap seseorang yang diduga melakukan tindak pidana berdasarkan minimal 2 (dua) alat bukti."}, {"l": "UU 20/2025", "p": "95", "b": "Bagian Ketiga", "t": "(1) Penangkapan dilakukan oleh Penyidik dengan memperlihatkan surat tugas kepada Tersangka. (21 Selain surat tugas sebagaimana dimaksud pada ayat (1), Penyidik harus memberikan surat perintah Penangkapan kepada Tersangka yang berisi: a. identitasTersangka; b. alasan Penangkapan; c. uraian singkat perkara tindak pidana yang dipersangkakan; dan d. tempat Tersangka diperiksa. (3) Tembusan surat perintah Penangkapan sebagaimana dimaksud pada ayat (2) harus diberikan kepada Keluarga Tersangka atau orang yang ditunjuk Tersangka atau ketua rukun warga/rukun tetangga tempat Tersangka tinggal dalam waktu paling lama 1 (satu) Hari terhitung sejak Penangkapan dilakukan. (4) Dalam hal Tertangkap Tangan, Penangkapan dilakukan tanpa surat perintah Penangkapan. (5) Pihak yang melakukan Penangkapan sebagaimana dimaksud pada ayat (4) harus segera menyerahkan tertangkap beserta barang bukti kepada Penyidik atau Penyidik Pembantu."}, {"l": "UU 20/2025", "p": "96", "b": "Bagian Ketiga", "t": "Penangkapan dilakukan paling lama 1x24 (satu kali dua puluh empat) jam, kecuali ditentukan lain oleh Undang-Undang. Pasal 97. . . .litiElEtrN"}, {"l": "UU 20/2025", "p": "97", "b": "Bagian Ketiga", "t": "(1) Penangkapan tidak dapat dilakukan terhadap Tersangka yang disangka melakukan tindak pidana yang ancaman pidananya hanya pidana denda paling banyak kategori II. (2) Dalam hal Tersangka sebagaimana dimaksud pada ayat (1) tidak memenuhi panggilan Penyidik secara sah 2 (dua) kali berturut-turut tanpa alasan yang sah, Penangkapan dapat dilakukan."}, {"l": "UU 20/2025", "p": "98", "b": "Bagian Ketiga", "t": "Dalam hal Penangkapan dilakukan terhadap seorang Hakim, Penangkapan harus berdasarkan izin Ketua Mahkamah Agung."}, {"l": "UU 20/2025", "p": "99", "b": "Bagian Keempat", "t": "(1) Untuk kepentingan Penyidikan, Penyidik berwenang melakukan Penahanan. (21 Penyidik Pembantu berwenang melakukan Penahanan atas perintah Penyidik. (3) PPNS dan Penyidik Tertentu tidak dapat melakukan Penahanan kecuali atas perintah Penyidik Polri. (41 Penahanan sebagaimana dimaksud pada ayat (3) dikecualikan bagi Penyidik di Kejaksaan Republik Indonesia, Komisi Pemberantasan Tindak Pidana Korupsi, dan Tentara Nasional Indonesia Angkatan Laut sesuai dengan ketentuan Undang-Undang. (5) Untuk kepentingan Penuntutan, Penuntut Umum berwenang melakukan Penahanan atau Penahanan lanjutan. (6) Untuk kepentingan pemeriksaan di sidang pengadilan, Hakim dengan penetapannya berwenang melakukan Penahanan. Pasal 1OO . . . REPIIELIK INDONESIA"}, {"l": "UU 20/2025", "p": "100", "b": "Bagian Keempat", "t": "(1) Penahanan sebagaimana dimaksud dalam Pasal 99 hanya dapat dilakukan berdasarkan surat perintah Penahanan atau penetapan Hakim terhadap Tersangka atau Terdakwa yang melakukan tindak pidana atau melakukan percobaan atau pembantuan melakukan tindak pidana yang diancam dengan pidana penjara 5 (lima) tahun atau lebih. (21 Penahanan juga dapat dilakukan terhadap tindak pidana yang diatur dalam Pasal 213, Pasal 24O ayat (21, Pasal 241 ayat (21, Pasal 242, Pasal 243 ayat (1), Pasal 244, Pasal 247, Pasal 250 ayat (1), Pasal 252, Pasal 263 ayat (21, Pasal 264, Pasal 300, Pasal 302, Pasal 3O3 ayat (21, Pasal 3O4, Pasal 305 ayat (l), Pasal 347, Pasal 420, Pasal 421, Pasal 425, Pasal 448 ayat (1) dar: (21, Pasal 462, Pasal 466 ayat (1), Pasal 467 ayat (1), Pasal 472, Pasal 483, Pasal 486, Pasal 492, Pasal 496, Pasal 527, Pasal 553 ayat (1) huruf a dan huruf b, Pasal 569 ayat (1), dan Pasal 591 Kitab Undang-Undang Hukum Pidana. (3) Surat perintah Penahanan atau penetapan Hakim sebagaimana dimaksud pada ayat (1) dan ayat (21 harus mencantumkan: a. identitas Tersangka atau Terdakwa; b. alasan Penahanan; c. uraian singkat perkara tindak pidana yang dipersangkakan atau didakwakan; dan d. tempat …"}, {"l": "UU 20/2025", "p": "101", "b": "Bagian Keempat", "t": "Dalam hal Penahanan dilakukan terhadap seorang Hakim, Penahanan harus berdasarkan izin Ketua Mahkamah Agung."}, {"l": "UU 20/2025", "p": "102", "b": "Bagian Keempat", "t": "(l) Penyidik dapat melakukan Penahanan untuk kepentingan pemeriksaan pada tahap Penyidikan sebagaimana dimaksud dalam Pasal 99 ayal (1) dan ayat (21 untuk jangka waktu paling I ama 20 (dua puluh) Hari. (2) Apabila jangka waktu Penahanan sebagaimana dimaksud pada ayat (l) telah terlampaui, Penyidik dapat mengajukan permohonan perpanjangan Penahanan kepada Penuntut Umum untuk jangka waktu paling lama 40 (empat puluh) Hari. (3) Apabila jangka waktu 40 (empat puluh) Hari sebagaimana dimaksud pada ayat (2) terlampaui, Penyidik wajib mengeluarkan Tersangka dari tahanan. Pasal 1O3. . . REPTIELIK INDONESIA"}, {"l": "UU 20/2025", "p": "103", "b": "Bagian Keempat", "t": "(l) Penuntut Umum dapat melakukan Penahanan untuk kepentingan pemeriksaan pada tahap Penuntutan sebagaimana dimaksud dalam Pasal 99 ayat (5) untuk jangka waktu paling lama 20 (dua puluh) Hari. (2) Apabila jangka waktu Penahanan sebagaimana dimaksud pada ayat (1) telah terlampaui, Penuntut Umum dapat mengajukan permohonan perpanjangan Penahanan kepada ketua pengadilan negeri untuk jangka waktu paling lama 30 (tiga puluh) Hari. (3) Apabila jangka waktu 30 (tiga puluh) Hari sebagaimana dimaksud pada ayat (2) terlampaui, Penuntut Umum wajib mengeluarkan Tersangka dari tahanan."}, {"l": "UU 20/2025", "p": "104", "b": "Bagian Keempat", "t": "(1) Halim pengadilan negeri yang Mengadili perkara dengan penetapannya dapat melakukan Penahanan untuk kepentingan pemeriksaan di sidang pengadilan sebagaimana dimaksud dalam Pasal 99 ayat (6) untuk jangka waktu paling lama 30 (tiga puluh) Hari. (21 Apabila jangka waktu Penahanan sebagaimana dimaksud pada ayat (1) telah terlampaui, Hakim pengadilan negeri mengajukan permohonan perpanjangan Penahanan kepada ketua pengadilan negeri untuk jangka waktu paling lama 60 (enam puluh) Hari. (3) Apabila jangka waktu 60 (enam puluh) Hari sebagaimana dimaksud pada ayat (2) terlampaui, Hakim pengadilan negeri wajib mengeluarkan Tersangka dari tahanan."}, {"l": "UU 20/2025", "p": "105", "b": "Bagian Keempat", "t": "(1) Hakim pengadilan tinggi yang Mengadili perkara untuk kepentingan pemeriksaan perkara banding berwenang mengeluarkan penetapan Penahanan untuk jangka waktu paling lama 30 (tiga puluh) Hari. (2) Apabila. . . !NDONESIA (21 Apabila jangka waktu Penahanan sebagaimana dimaksud pada ayat (1) telah terlampaui, Hakim pengadilan tinggi mengajukan permohonan perpanjangan Penahanan kepada ketua pengadilan tinggi untuk jangka waktu paling lama 6O (enam puluh) Hari. (3) Apabila jangka waktu 60 (enam puluh) Hari sebagaimana dimaksud pada ayat (2) terlampaui, Hakim pengadilan tinggr wajib mengeluarkan Tersangka dari tahanan."}, {"l": "UU 20/2025", "p": "106", "b": "Bagian Keempat", "t": "(l) Untuk kepentingan pemeriksaan kasasi, Hakim agung berwenang mengeluarkan penetapan Penahanan untuk jangka waktu paling lama 30 (tiga puluh) Hari. (21 Apabila jangka waktu Penahanan sebagaimana dimaksud pada ayat (1) telah terlampaui, Penahanan dapat diperpanjang oleh Ketua Mahkamah Agung untuk jangka waktu paling lama 60 (enam puluh) Hari. (3) Apabila jangka waktu 60 (enam puluh) Hari sebagaimana dimaksud pada ayat (2) terlampaui, Hakim agung wajib mengeluarkan Tersangka dari tahanan."}, {"l": "UU 20/2025", "p": "107", "b": "Bagian Keempat", "t": "(l) Jangka waktu Penahanan sebagaimana dimaksud dalam Pasal 102 sampai dengan Pasal 106 dapat diperpanjang kembali berdasarkan alasan yang patut untuk kepentingan pemeriksaan Tersangka atau Terdakwa karena: a. Tersangka atau Terdakwa menderita gangguan fisik atau mental yang berat, yang dibuktikan dengan surat keterangan dokter; atau b. perkara yang sedang diperiksa diancam dengan pidana penjara 9 (sembilan) tahun atau lebih. (2) Perpanjangan sebagaimana dimaksud pada ayat (1) diberikan untuk jangka waktu paling lama 3O (tiga puluh) Hari dan dalam hal Penahanan tersebut masih diperlukan, dapat diperpanjang kembali untuk jangka waktu paling lama 3O (tiga puluh) Hari. (3) Perpanjangan . . . (3) Perpanjangan Penahanan sebagaimana dimaksud pada ayat (2) dilakukan berdasarkan permintaan dan laporan pemeriksaan pada tahap: a. Penyidikan dan Penuntutan diberikan oleh ketua pengadilan negeri; b. pemeriksaan di pengadilan negeri diberikan oleh ketua pengadilan tinggi; c. pemeriksaan banding diberikan oleh Ketua Mahkamah Agung; atau d. pemeriksaan kasasi diberikan oleh Ketua Mahkamah Agung. (4) Penggunaan kewenangan perpanjangan Penahanan oleh pejabat sebagaimana dimaksud pada ayat (3) …"}, {"l": "UU 20/2025", "p": "108", "b": "Bagian Keempat", "t": "(1) Jenis Penahanan terdiri atas: a. penahanan rumah tahanan negara; b. penahanan rumah; dan c. penahanan kota. l2l Penahanan rumah tahanan negara sebagaimana dimaksud pada ayat (1) huruf a dilaksanakan di rumah tahanan negara. (3) Rumah tahanan negara sebagaimana dimaksud pada ayat (2) dikelola oleh menteri yang menyelenggarakan urusan pemerintahan di bidang pemasyarakatan yang ada di kabupaten/kota di wilayah hukum pengadilan negeri yang menetapkan Penahanan atau pengadilan negeri yang Mengadili perkara. (4) Dalam hal tidak terdapat rumah tahanan negara pada kabupaten/kota sebagaimana dimaksud ayat (1), Penahanan dilaksanakan di rumah tahanan lain yang dikelola oleh: a. menteri yang urusan pemerintahan di bidang pemasyarakatan; atau b. institusi penegak hukum yang memiliki kewenangan melakukan Penahanan berkoordinasi dengan menteri yang menyelenggarakan urusan pemerintahan di bidang pemasyarakatan, yang ada pada kabupaten/kota terdekat. (5) Penahanan rumah sebagaimana dimaksud pada ayat (1) huruf b, dilalsanakan di rumah tempat tinggal atau rumah kediaman Tersangka atau Terdakwa dengan mengadakan pengawasan terhadapnya untuk menghindarkan segala sesuatu yang dapat menimbulkan …"}, {"l": "UU 20/2025", "p": "109", "b": "Bagian Keempat", "t": "(1) Dalam hal Penahanan sebagaimana dimaksud dalam Pasal 1O2 sampai dengan Pasal 106 atau perpanjangan Penahanan sebagaimana dimaksud dalam Pasal 107 tidak sah, Tersangka atau Terdakwa berhak mengajukan permohonan Ganti Rugr kepada pengadilan negeri. (21 l,amanya Tersangka atau Terdakwa dalam tahanan tidak boleh melebihi ancaman pidana maksimum."}, {"l": "UU 20/2025", "p": "110", "b": "Bagian Keempat", "t": "(l) Atas permintaan Tersangka atau Terdakwa, penangguhan Penahanan dapat diberikan oleh Penyidik, Penuntut Umum, atau Hakim sesuai dengan kewenangan masing-masing. (21 Penangguhan Penahanan sebagaimana dimaksud pada ayat (1) dapat dilakukan dengan atau tanpa jaminan uang atau jaminan orang berdasarkan syarat yang ditentukan. (3) Jaminan... REPUBUK INDONESIA (3) Jaminan orang sebagaimana dimalsud pada ayat (21 dapat diberikan oleh Keluarga Tersangka atau Terdakwa, Advokat, atau orang lain yang tidak mempunyai hubungan apapun dengan Tersangka atau Terdakwa sepanjang bersedia dan bertanggung jawab memikul segala risiko dan akibat yang timbul jika tahanan melarikan diri. (4) Penyidik, Penuntut Umum, atau Hakim karena jabatannya sewaktu-waktu dapat mencabut penangguhan Penahanan dalam hal Tersangka atau Terdakwa melanggar syarat sebagaimana dimaksud pada ayat (21. (5) Dalam hal Penuntut Umum mengajukan perlawanan terhadap penangguhan penahanan, Terdakwa tetap dalam tahanan sampai dengan diterimanya penetapan ketua pengadilan negeri. (6) Dalam hal ketua pengadilan negeri menerima perlawanan Penuntut Umum, Halim pengadilan negeri wajib mengeluarkan surat perintah Penahanan kembali dalam …"}, {"l": "UU 20/2025", "p": "111", "b": "Bagian Keempat", "t": "(l) Apabila pada masa Penahanan Tersangka atau Terdakwa di tahap Penyidikan, Penuntutan, dan/atau pemeriksaan di sidang pengadilan menderita sakit dan dirawat di rumah sakit, Tersangka atau Terdakwa dilakukan pembantaran. (21 Masa pembantaran sebagaimana dimaksud pada ayat (1) tidak dihitung sebagai masa Penahanan. (3) Selama pembantaran sebagaimana dimaksud pada ayat (1), Tersangka atau Terdakwa berada dalam pengawasan Penyidik, Penuntut Umum, atau Hakim sesuai dengan tahap pemeriksaan. l4l Ketentuan lebih lanjut mengenai syarat, tata cara, dan pengawasan pembantaran Tersangka atau Terdakwa diatur dalam Peraturan Pemerintah."}, {"l": "UU 20/2025", "p": "112", "b": "Bagian Kelima", "t": "Untuk kepentingan Penyidikan, Penyidik dapat melakukan Penggeledahan terhadap: a. rumah atau bangunan; b. pakaian; c. badan; d. alat transportasi; e. Informasi Elektronik; f. Dokumen Elektronik; dan/atau g. benda lainnya."}, {"l": "UU 20/2025", "p": "113", "b": "Bagian Kelima", "t": "(1) Sebelum melalukan Penggeledahan sebagaimana dimaksud dalam Pasal 112, Penyidik mengajukan permohonan izin kepada ketua pengadilan negeri. (21 Permohonan izin sebagaimana dimaksud pada ayat (1) harus disertai uraian mengenai: a. lokasi yang akan digeledah; dan b. dasar atau fakta yang dipercaya bahwa dalam lokasi tersebut terdapat barang bukti yang terkait dengan tindak pidana. (3) Dalam melakukan Penggeledahan, Penyidik hanya dapat melakukan pemeriksaan dan/ atau Penyitaan barang bukti yang terkait dengan tindak pidana. (41 Dalam keadaan mendesak, Penyidik dapat melakukan Penggeledahan tanpa izin dari ketua pengadilan negeri. (5) Keadaan mendesak sebagaimana dimaksud pada ayat (4) meliputi: a. letak geografis yang susah dijangkau; b. Tertangkap Tangan; c. berpotensi berupaya merusak dan menghilangkan barang bukti; dan/ atau d. situasi berdasarkan penilaian Penyidik. (6) Dalam . . . PRES!DEN IIEPUBUK INDONESIA (6) Dalam keadaan sebagaimana dimaksud pada ayat (4), Penyidik paling lama 2x24 (dua kali dua puluh empat) jam meminta persetqjuan kepada ketua pengadilan negeri setelah dilakukan Penggeledahan. (71 Ketua pengadilan negeri dalam waktu paling lama 2x24 (dua kali dua puluh …"}, {"l": "UU 20/2025", "p": "114", "b": "Bagian Kelima", "t": "(1) Penyidik wajib menunjukkan surat tugas dan surat izin Penggeledahan dari ketua pengadilan negeri kepada Tersangka atau pemilik/penghuni rumah atau bangunan. (21 Penyidik melakukan Penggeledahan rumah atau bangunan sebagaimana dimaksud dalam Pasal 112 huruf a dengan disaksikan oleh 2 (dua) orang saksi. (3) Dalam hal Tersangka atau pemilik/penghuni menolak untuk dilakukan Penggeledahan atau tidak berada di tempat, Penggeledahan harus disaksikan oleh kepala desa/lurah atau nama lainnya atau ketua rukun warga/ rukun tetangga dan 2 (dua) orang saksi. (41 Setelah melakukan Penggeledahan sebagaimana dimaksud pada ayat (2), Penyidik membuat berita acara Penggeledahan rumah atau bangunan yang ditandatangani oleh Penyidik, Tersangka atau pemilik/penghuni rumah atau bangunan, dan saksi. (5) Setelah melakukan Penggeledahan sebagaimana dimaksud pada ayat (3), Penyidik membuat berita acara Penggeledahan rumah atau bangunan yang ditandatangani oleh Penyidik, kepala desa/lurah atau nama lainnya atau ketua rukun warga/ rukun tetangga, dan saksi. Pasal 115... PR,ESIDEH REPUBUK INDONESIA"}, {"l": "UU 20/2025", "p": "115", "b": "Bagian Kelima", "t": "Penyidik dilarang melakukan Penggeledahan pada: a. ruang yang di dalamnya sedang berlangsung sidang Majelis Permusyawaratan Ralryat, Dewan Perwakilan Ralryat, Dewan Perwakilan Daerah, atau Dewan Perwakilan Rakyat Daerah; b. ruang yang di dalamnya sedang berlangsung ibadah dan/ atau upacara keagamaan; atau c. ruang yang di dalamnya sedang berlangsung sidang pengadilan."}, {"l": "UU 20/2025", "p": "116", "b": "Bagian Kelima", "t": "Dalam hal Penyidik harus melakukan Penggeledahan rumah atau bangunan di luar daerah hukumnya, Penggeledahan tersebut harus diketahui oleh ketua pengadilan negeri dan didampingi oleh Penyidik dari daerah hukum tempat Penggeledahan tersebut dilakukan."}, {"l": "UU 20/2025", "p": "117", "b": "Bagian Kelima", "t": "(1) Pada waktu menangkap Tersangka, Penyelidik hanya berwenang menggeledah pakaian termasuk benda yang dibawanya serta apabila terdapat dugaan dengan alasan yang cukup bahwa pada Tersangka terdapat benda yang dapat disita. 12) Pada waktu menangkap Tersangka atau dalam hal Tersangka sebagaimana dimal<sud pada ayat (1) dibawa kepada Penyidik, Penyidik berwenang menggeledah pakaian dan/atau menggeledah badan Tersangka."}, {"l": "UU 20/2025", "p": "118", "b": "Bagian Keenam", "t": "Untuk kepentingan Penyidikan, Penyidik dapat melakukan Penyitaan. Pasal 119... FRESIDEN K INDONESIA"}, {"l": "UU 20/2025", "p": "119", "b": "Bagian Keenam", "t": "(1) Sebelum melakukan Penyitaan, Penyidik mengajukan permohonan izin kepada ketua pengadilan negeri tempat keberadaan benda tersebut. (21 Permohonan izin sebagaimana dimaksud pada ayat (1) harus memuat informasi lengkap mengenai benda yang akan disita minimal meliputi: a. jenis; b. jumlah dan nilai barang; c. lokasi; dan d. alasan Penyitaan. (3) Ketua pengadilan negeri wajib meneliti secara cermat permohonan izin sebagaimana dimaksud pada ayat (21 dalam jangka waktu paling lama 2 (dua) Hari terhitung sejak permohonan izin diajukan. l4l Ketua pengadilan negeri dapat meminta informasi tambahan dari Penyidik mengenai benda yang akan disita sebagaimana dimaksud pada ayat (21. (5) Ketua pengadilan negeri dalam jangka waktu paling lama 2 (dua) Hari terhitung sejak penelitian sebagaimana dimaksud pada ayat (3) wajib mengeluarkan penetapan persetujuan atau penolakan."}, {"l": "UU 20/2025", "p": "120", "b": "Bagian Keenam", "t": "(1) Dalam keadaan mendesak, Penyidik dapat melakukan Penyitaan lanpa izin ketua pengadilan negeri hanya atas benda bergerak dan untuk itu dalam jangka waktu paling lama 5 (lima) hari kerja wajib meminta persetujuan kepada ketua pengadilan negeri. l2l Keadaan mendesak sebagaimana dimaksud pada ayat (1) meliputi: a. letak geografis yang susah dijangkau; b. Tertangkap Tangan; c. Tersangka berpotensi berupaya merusak dan menghilangkan barang bukti secara nyata; d. benda atau aset tersebut mudah dipindahkan; e. adanya ancaman serius terhadap keamanan nasional atau nyawa seseorang yang memerlukan tindakan segera; dan/ atau f. situasi berdasarkan penilaian Penyidik. (3) Ketua . . . ETI:FITitjN REPI,JBUK INDONESIA (3) Ketua pengadilan negeri dalam jangka waktu paling lama 2 (dua) hari kerja terhitung sejak Penyidik meminta persetujuan Penyitaan sebagaimana dimaksud pada ayat (l) wajib mengeluarkan penetapan persetujuan atau penolakan."}, {"l": "UU 20/2025", "p": "121", "b": "Bagian Keenam", "t": "(l) Dalam hal ketua pengadilan negeri menolak untuk memberikan izin sebagaimana dimaksud dalam Pasal 119 ayat (5) atau persetujuan Penyitaan sebagaimana dimaksud dalam Pasal 120 ayat (3), penetapan penolakan harus disertai dengan alasan. l2l Terhadap penetapan penolakan sebagaimana dimaksud pada ayat (1), Penyidik dapat mengajukan kembali permohonan Penyitaan terhadap benda yang sama kepada ketua pengadilan negeri hanya 1 (satu) kali. (3) Penetapan penolakan sebagaimana dimaksud pada ayat (1) mengakibatkan hasil Penyitaan tidak dapat dijadikan alat bukti. (41 Setelah memperoleh penetapan penolakan sebagaimana dimaksud pada ayat (l), Penyidik wajib segera mengembalikan benda yang disita kepada pemilik atau pihak yang menguasai benda pada saat dilakukan Penyitaan dalam jangka waktu paling lama 3 (tiga) Hari terhitung sejak penetapan penolakan diterima."}, {"l": "UU 20/2025", "p": "122", "b": "Bagian Keenam", "t": "(l) Penyidik wajib menunjukkan surat perintah Penyitaan dan surat izin Penyitaan dari ketua pengadilan negeri kepada pemilik atau pihak yang menguasai benda tersebut ketika melakukan Penyitaan. (21 Penyitaan sebagaimana dimaksud pada ayat (1) wajib dihadiri oleh 2 (dua) orang saksi. (3) Setelah Penyidik melakukan Penyitaan sebagaimana dimaksud pada ayat (1), Penyidik wajib membuat berita acara Penyitaan yang ditandatangani oleh Penyidik, pemilik atau pihak yang menguasai benda yang disita, dan saksi. (4) Dalam . . . (4) Dalam jangka waktu paling lama 2 (dua) Hari terhitung sejak Penyitaan selesai dilakukan, Penyidik memberikan salinan surat perintah Penyitaan atau surat izin Penyitaan sebagaimana dimaksud pada ayat (1) dan berita acara sebagaimana dimaksud pada ayat (3) kepada pemilik atau pihak yang menguasai benda dan kepada ketua pengadilan negeri. (5) Dalam hal pemilik atau pihak yang menguasai benda yang disita tidak berada di tempat, Penyitaan wajib disaksikan oleh kepala desa/lurah atau nama lainnya atau ketua rukun warga/rukun tetangga dengan 2 (dua) orang saksi. (6) Setelah Penyidik melakukan Penyitaan sebagaimana dimaksud pada ayat (5), Penyidik wajib membuat berita …"}, {"l": "UU 20/2025", "p": "123", "b": "Bagian Keenam", "t": "(1) Benda yang dapat disita adalah: a. benda atau tagihan Tersangka atau Terdakwa yang seluruh atau sebagian diduga diperoleh dari tindak pidana atau sebagai hasil dari tindak pidana; b. benda yang telah dipergunakan untuk melakukan tindak pidana atau untuk mempersiapkannya; c. benda yang dipergunakan untuk menghalang- halangi Penyidikan tindak pidana; d. benda yang khusus dibuat atau diperuntukkan melakukan tindak pidana; e. benda yang tercipta dari suatu tindak pidana; dan/ atau f. benda yang diduga merupakan hasil tindak pidana namun pemiliknya tidak diketahui. (2) Benda. . . EJ-.FITil:N REPUBUK INDONESIA l2l Benda yang berada dalam sitaan karena perkara perdata atau karena pailit dapat juga disita untuk kepentingan Penyidikan, Penuntutan, dan pemeriksaan di sidang pengadilan sepanjang memenuhi ketentuan sebagaimana dimaksud pada ayat (1). (3) Nilai keseluruhan dari benda yang disita tidak melebihi nilai kerugian akibat tindak pidana. (4) Dalam hal benda sitaan tidak sesuai dengan ketentuan sebagaimana dimaksud pada ayat (1), ketua pengadilan negeri memerintahkan Penyidik untuk mengembalikan benda yang disita kepada pemilik dalam jangka waktu paling lama 3O (tiga puluh) Hari. …"}, {"l": "UU 20/2025", "p": "124", "b": "Bagian Keenam", "t": "(1) Penyidik dapat melakukan Penyitaan terhadap benda sebagaimana dimaksud dalam Pasal 123 dengan mengajukan izin kepada ketua pengadilan negeri yang daerah hukumnya meliputi tempat keberadaan benda tersebut. (21 Dalam hal benda yang dimohonkan untuk disita terdapat di beberapa daerah hukum pengadilan negeri, Penyidik dapat memilih salah satu dari pengadilan negeri tersebut sebagaimana dimaksud pada ayat (1). (3) Dalam hal keadaan daerah tidak suatu Pengadilan Negeri untuk memeriksa permohonan Penyitaan, Mahkamah Agung menetapkan atau menunjuk pengadilan negeri lain yang layak untuk memeriksa permohonan dimaksud. (4) Dalam hal benda yang dimohonkan untuk disita berada di luar negeri, Pengadilan Negeri Jakarta Pusat berwenang memeriksa, Mengadili, dan memutus permohonan Penyitaan tersebut. Pasal 125 . . . PR,ESIDEN"}, {"l": "UU 20/2025", "p": "125", "b": "Bagian Keenam", "t": "(1) Penyitaan terhadap benda yang pemiliknya tidak diketahui sebagaimana dimaksud dalam Pasal 123 ayat (1) huruf f, diajukan permohonan Penyitaan oleh Penyidik kepada ketua pengadilan negeri. (21 Ketua pengadilan negeri dalam waktu paling lama 3 (tiga) Hari memerintahkan panitera untuk mengumumkan permohonan Penyitaan pada papan pengumuman Pengadilan Negeri dan/atau media lain guna memberikan kesempatan kepada pihak yang merasa berhak atas benda untuk mengajukan keberatan. (3) Dalam hal tidak terdapat keberatan terhadap permohonan Penyitaan, ketua pengadilan negeri menunjuk Hakim tunggal untuk memeriksa, Mengadili, dan memutus permohonan Penyitaan. l4l Berdasarkan permohonan Penyitaan yang diajukan oleh Penyidik, Hakim memutus benda tersebut sebagai aset negara atau dikembalikan kepada yang berhak. (5) Hakim harus memutus permohonan Penyitaan sebagaimana dimaksud pada ayat (1) dalam waktu paling lama 7 (tuluh) hari kerja terhitung sejak Hari sidang pertama."}, {"l": "UU 20/2025", "p": "126", "b": "Bagian Keenam", "t": "Dalam hal Tertangkap Tangan, Penyidik dapat menyita: a. benda yang telah digunakan untuk melakukan tindak pidana; b. benda yang patut diduga telah digunakan untuk melakukan tindak pidana; dan/ atau c. benda lain yang dapat dipakai sebagai barang bukti."}, {"l": "UU 20/2025", "p": "127", "b": "Bagian Keenam", "t": "(l) Dalam hal Tertangkap Tangan, Penyidik berwenang menyita paket, surat, atau benda yang pengangkutannya atau pengirimannya dilakukan oleh kantor pos dan telekomunikasi, perusahaan komunikasi, atau perusahaan jasa pengangkutan sepanjang paket, surat, atau benda tersebut diperuntukkan bagi Tersangka atau yang berasal dari Tersangka. (2) Setelah... EJIFIIEIiN REFUBLIK INDONESIA (21 Setelah melakukan Penyitaan sebagaimana dimaksud pada ayat (1), Penyidik memberikan surat tanda penerimaan kepada Tersangka dan pejabat kantor pos dan telekomunikasi, perusahaan komunikasi, atau perusahaan jasa pengangkutan."}, {"l": "UU 20/2025", "p": "128", "b": "Bagian Keenam", "t": "(1) Penyidik berwenang memerintahkan orang yang memiliki atau menguasai benda yang dapat disita untuk menyerahkan benda tersebut kepadanya untuk kepentingan pemeriksaan. (21 Penyidik harus memberikan tanda terima kepada orang yang menyerahkan benda tersebut."}, {"l": "UU 20/2025", "p": "129", "b": "Bagian Keenam", "t": "(l) Surat atau tulisan lain hanya dapat diperintahkan untuk diserahkan kepada Penyidik, jika surat atau tulisan tersebut berkaitan dengan tindak pidana. (2) Penyitaan surat atau tulisan lain dari pejabat atau seseorang yang mempunyai kewajiban menurut Undang-Undang untuk merahasiakannya, sepanjang tidak menyangkut rahasia negara, hanya dapat dilakukan atas persetujuan pejabat atau seseorang tersebut atau atas izin khusus ketua pengadilan negeri setempat, kecuali Undang-Undang menentukan lain."}, {"l": "UU 20/2025", "p": "130", "b": "Bagian Keenam", "t": "(l) Pejabat yang berwenang melakukan Penyitaan wajib bertanggung jawab atas benda sitaan. (2) Benda sitaan dapat disimpan pada: a. rumah penyimpanan benda sitaan negara; b. tempat yang disediakan oleh Penyidik untuk kepentingan Penyidikan; atau c. tempat yang disediakan oleh Jaksa untuk kepentingan Penuntutan. (3) Pengelolaan benda sitaan dilakukan dengan sebaik- baiknya dan sedapat mungkin menjaga nilai ekonomis dari benda sitaan. (4) Benda . . . (4) Benda sitaan dilarang untuk dipergunakan oleh siapa pun dan untuk tujuan apapun, kecuali untuk kepentingan pemeriksaan perkara. (5) Ketentuan lebih lanjut mengenai pengelolaan dan penyimpanan benda sitaan diatur dalam Peraturan Pemerintah."}, {"l": "UU 20/2025", "p": "131", "b": "Bagian Keenam", "t": "(1) Dalam hal benda sitaan sebagaimana dimaksud dalam Pasal 123 terdiri atas benda yang dapat lekas rusak atau membahayakan, sehingga tidak mungkin disimpan sampai Putusan Pengadilan terhadap perkara yang bersangkutan memperoleh kekuatan hukum tetap, benda tersebut dapat diamankan, dimusnahkan, atau dilelang oleh Penyidik atau Penuntut Umum dengan persetujuan Tersangka atau Terdakwa dan/atau Advokatnya dan disaksikan oleh Penyidik, Penuntut Umum, Tersangka, atau Terdakwa dan/ atau Advokatnya. l2l Jika Tersangka atau Terdakwa tidak memberikan persetujuan sebagaimana dimaksud pada ayat (l), Penyidik atau Penuntut Umum membuat berita acara penolakan paling lama 3 (tiga) Hari dan lelang tetap dilaksanakan. (3) Benda sitaan yang dilelang sebagaimana dimaksud pada ayat (1) tidak dapat dibeli oleh Tersangka atau Terdakwa dan/atau pihak yang mempunyai hubungan keluarga sedarah sampai derajat kedua, hubungan semenda, dan hubungan kerja atau keuangan. (4) Dalam hal benda sitaaan sebagaimana dimaksud pada ayat (1) telah dilelang, namun berdasarkan putusan berkekuatan hukum tetap tidak dirampas untuk negara, maka uang hasil penjualan lelang barang sitaan tersebut harus dikembalikan kepada …"}, {"l": "UU 20/2025", "p": "132", "b": "Bagian Keenam", "t": "(1) Dalam hal benda sitaan merupakan benda berbahaya, bersifat terlarang atau dilarang untuk diedarkan, benda tersebut dirampas untuk kepentingan negara atau dimusnahkan dengan izin ketua pengadilan negeri, dengan atau tanpa disaksikan oleh Tersangka, Terdakwa, atau Advokatnya dengan mengundang Tersangka, Terdakwa, atau Advokatnya. l2l Benda sitaan yang bersifat terlarang atau dilarang untuk diedarkan sebagaimana dimaksud pada ayat (1) disisihkan sebagian untuk kepentingan pembuktian di pengadilan."}, {"l": "UU 20/2025", "p": "133", "b": "Bagian Keenam", "t": "Benda yang dikenakan Penyitaan dikembalikan kepada orang yang memiliki atau menguasai benda yang disita, atau kepada orang yang paling berhak dalam hal: a. tidak diperlukan lagi untuk kepentingan Penyidikan dan Penuntutan; b. perkara tersebut tidak jadi dituntut karena tidak cukup bukti atau ternyata bukan merupakan tindak pidana; atau c. perkara tersebut dikesampingkan untuk kepentingan umum atau perkara tersebut ditutup demi hukum, kecuali apabila benda itu diperoleh dari suatu tindak pidana atau yang dipergunakan untuk melakukan suatu tindak pidana."}, {"l": "UU 20/2025", "p": "134", "b": "Bagian Keenam", "t": "Pengembalian benda sitaan sebagaimana dimaksud dalam Pasal 133 dilakukan paling lama 7 (tujuh) Hari terhitung sejak benda sitaan tidak lagi diperlukan untuk kepentingan Penyidikan, penghentian Penyidikan, Penuntutan, penghentian Penuntutan, perkara tersebut dikesampingkan untuk kepentingan umum, atau perkara ditutup demi hukum. Pasal 135 . . . FRESIDEN REFUBLIK INDONESIA -7t-"}, {"l": "UU 20/2025", "p": "135", "b": "Bagian Keenam", "t": "Apabila perkara sudah diputus maka benda yang disita sebagaimana dimaksud dalam Pasal 134 dikembalikan kepada orang yang berhak, kecuali jika menurut putusan Hakim benda tersebut dirampas untuk negara atau dimusnahkan atau jika benda tersebut masih diperlukan sebagai bukti dalam perkara lain. Brgian Ketujuh Penyadapan"}, {"l": "UU 20/2025", "p": "136", "b": "Bagian Keenam", "t": "(1) Penyidik dapat melakukan Penyadapan untuk kepentingan Penyidikan. (21 Ketentuan mengenai Penyadapan sebagaimana dimaksud pada ayat (1) diatur dengan Undang-Undang mengenai penyadapan."}, {"l": "UU 20/2025", "p": "137", "b": "Bagian Kedelapan", "t": "(1) Penyidik berhak membuka, memeriksa, dan menyita surat yang dikirim melalui kantor pos, perusahaan telekomunikasi, atau perusahaan pengangkutan, jika surat tersebut dicurigai dengan alasan yang kuat mempunyai hubungan dengan perkara pidana yang sedang diperiksa. l2l Untuk kepentingan Penyidikan, Penyidik dapat meminta kepada kepala kantor pos, kepala perusahaan telekomunikasi, atau kepala perusahaan pengangkutan sebagaimana dimaksud pada ayat (l) untuk menyerahkan surat yang dimalsud dan harus memberikan tanda terima. (3) Ketentuan sebagaimana dimaksud pada ayat (1) dan ayat (2l., dapat dilakukan pada setiap tahap pemeriksaan dalam proses peradilan. Pasal 138. . . _72_"}, {"l": "UU 20/2025", "p": "138", "b": "Bagian Kedelapan", "t": "(l) Jika sesudah dibuka dan diperiksa, ternyata surat tersebut ada hubungannya dengan perkara yang sedang diperiksa, surat tersebut dilampirkan pada berkas perkara. (21 Apabila surat tersebut tidak ada hubungannya dengan perkara, surat tersebut ditutup kembali dan dalam jangka waktu paling larrra 2 (dua) Hari terhitung sejak pemeriksaan selesai, harus diserahkan kembali kepada kantor pos, pemsahaan telekomunikasi, atau perusahaan pengangkutan, setelah dibubuhi cap yang berbunyi \"telah dibuka oleh Penyidik\" dengan dibubuhi tanggal, tanda tangan, dan identitas Penyidik. (3) Penyidik dan pejabat pada setiap tahap pemeriksaan dalam proses peradilan wajib merahasiakan isi surat yang dikembalikan."}, {"l": "UU 20/2025", "p": "139", "b": "Bagian Kedelapan", "t": "(1) Penyidik membuat berita acara mengenai tindakan yang dilakukan sebagaimana dimaksud dalam Pasal 137 dan Pasal 138. (21 Penyidik harus memberikan tembusan berita acara sebagaimana dimaksud pada ayat (1) kepada kepala kantor pos, kepala perusahaan telekomunikasi, atau kepala perusahaan pengangkutan yang bersangkutan, dan kepada ketua pengadilan negeri."}, {"l": "UU 20/2025", "p": "140", "b": "Bagian Kesembilan", "t": "(1) Pemblokiran dapat dilakukan oleh Penyidik, Penuntut Umum, atau Hakim. l2l Pemblokiran sebagaimana dimaksud pada ayat (1) harus mendapat izin ketua pengadilan negeri. (3) Permohonan . . . REFI.JELIK INDONESIA (3) Permohonan izin sebagaimana dimaksud pada ayat (21 harus memuat informasi lengkap mengenai alasan perlunya dilakukan Pemblokiran minimal meliputi: a. uraian tindak pidana yang sedang diproses; b. dasar atau fakta yang menunjukkan objek yang akan diblokir memiliki relevansi dengan tindak pidana yang sedang diproses dan sumber perolehan dasar atau fakta tersebut; dan c. bentuk dan tujuan Pemblokiran yang akan dilakukan terhadap masing-masing objek yang akan diblokir. (41 Ketua pengadilan negeri wajib meneliti secara cermat permohonan izin sebagaimana dimaksud pada ayat (3) dalam jangka waktu paling larrra 2 (dua) Hari terhitung sejak permohonan izin diajukan. (5) Ketua pengadilan negeri dapat meminta informasi tambahan dari Penyidik mengenai hal sebagaimana dimaksud pada ayat (3). (6) Pemblokiran hanya dapat dilakukan untuk jangka waktu 1 (satu) tahun dan dapat diperpanjang 2 (dua) kali untuk jangka waktu 6 (enam) Bulan. (71 Dalam keadaan mendesak, Pemblokiran dapat …"}, {"l": "UU 20/2025", "p": "141", "b": "Bagian Kesepuluh", "t": "(1) Untuk kepentingan Penyidikan, Penuntutan, atau pemeriksaan di sidang pengadilan, Penyidik, Penuntut Umum, atau Hakim berwenang melakukan pencegahan yang dilaksanakan dalam bentuk pelarangan sementara terhadap Tersangka atau Terdakwa untuk keluar wilayah Indonesia berdasarkan alasan yang sesuai dengan hukum. (21 Dalam rangka pelarangan sebagaimana dimaksud pada ayat (1), Penyidik, Penuntut Umum, atau Hakim berkoordinasi dan meminta kementerian yang menyelenggarakan urusan pemerintahan di bidang keimigrasian untuk melakukan upaya pelarangan Tersangka atau Terdakwa keluar wilayah Indonesia. (3) Pencegahan . . . BLIK INDONESIA (3) Pencegahan keluar wilayah Indonesia sebagaimana dimaksud pada ayat (1) untuk jangka waktu paling lama 6 (enam) Bulan dan dapat diperpanjang 1 (satu) kali untuk jangka waktu paling lama 6 (enam) Bulan. (41 Ketentuan lebih lanjut mengenai tata cara pencegahan keluar wilayah Indonesia diatur dalam Peraturan Pemerintah."}, {"l": "UU 20/2025", "p": "142", "b": "BAB VI HAK TERSANGKA DAN TERDAKWA", "t": "Tersangka atau Terdakwa berhak: a. segera menjalankan pemeriksaan; b. memilih, menghubungi, dan mendapat pendampingan Advokat dalam setiap pemeriksaan; c. diberitahu dengan jelas dalam bahasa yang dimengerti olehnya mengenai apa yang disangkakan atau didakwakan kepadanya; d. diberitahu mengenai haknya; e. memberikan atau menolak untuk memberikan keterangan berkaitan dengan sangkaan atau dakwaan yang dikenakan kepadanya; f. setiap waktu mendapat bantuan Penerjemah atau juru bahasa; g. mendapat Jasa Hukum dan/atau Bantuan Hukum; h. menghubungi, berkomunikasi, dan menerima kunjungan perwakilan negaranya bagi Tersangka atau Terdakwa yang berkewarganegaraan asing; i. menunjuk perwakilan suatu negara untuk dihubungi; j. menghubungi, berkomunikasi, dan menerima kunjungan dokter untuk kepentingan pemeriksaan kesehatan atas dirinya; k. menghubungi, berkomunikasi, dan menerima kunjungan rohaniwan; l. menghubungi . . . REPUBUK INDONESIA l. menghubungi, berkomunikasi, dan menerima kunjungan Keluarga, kerabat, atau hubungan lain secara langsung atau melalui perantaraan Advokat; m. mengirim dan menerima surat dari dan kepada Advokat dan Keluarga Tersangka atau Terdakwa; n. mengajukan permohonan …"}, {"l": "UU 20/2025", "p": "143", "b": "Bagian Kesatu", "t": "Saksi berhak: a. tidak dapat dituntut secara hukum, baik pidana maupun perdata atas kesaksian dan/ atau Laporan yang akan, sedang, atau telah diberikannya, kecuali kesaksian atau Laporan tersebut diberikan tidak dengan iktikad baik; b. memilih, menghubungi, dan mendapat pendampingan Advokat dalam setiap pemeriksaan; c. mendapat Bantuan Hukum; d. memberikan keterangan tanpa tekanan; e. mendapat Penerjemah atau juru bahasa; f. bebas. . . REPTJBLIK INDONESIA f. bebas dari pertanyaan yang menjerat; g. menolak memberikan keterangan yang dapat memberatkan dirinya sendiri walaupun Saksi telah mengambil sumpah atau janji; h. memperoleh pelindungan atas keamanan pribadi, Keluarga, dan harta bendanya, serta bebas dari ancaman yang berkaitan dengan kesaksian yang akan, sedang, atau telah diberikannya; i. dirahasiakan identitasnya; j. memperoleh penggantian biaya transportasi selama proses penanganan perkara; k. ikut serta dalam proses memilih dan menentukan bentuk pelindungan dan dukungan keamanan; l. memperoleh penggantian biaya transportasi selama proses pemenuhan layanan; dan/ atau m. bebas dari penyiksaan, intimidasi, perbuatan tidak manusiawi atau merendahkan harkat dan martabat manusia …"}, {"l": "UU 20/2025", "p": "144", "b": "Bagian Kedua", "t": "Korban berhak: a. tidak dapat dituntut secara hukum, baik pidana maupun perdata atas kesaksian, Laporan, dan/ atau Pengaduan yang akan, sedang, atau telah diberikannya, kecuali kesaksian, Laporan, dan/atau Pengaduan tersebut diberikan tidak dengan iktikad baik; b. memilih, menghubungi, dan mendapat pendampingan Advokat dalam setiap pemeriksaan; c. memberikan keterangan tanpa tekanan; d. mendapat Penerjemah atau juru bahasa; e. bebas dari pertanyaan yang menjerat; f. mendapat informasi mengenai perkembangan perkara; g.mendapat... REFUBUK INDONESIA g. mendapat informasi mengenai Putusan Pengadilan; h. mendapat informasi dalam hal Terpidana dibebaskan; i. memperoleh pelindungan atas keamanan pribadi, Keluarga, dan harta bendanya, serta bebas dari ancaman yang berkaitan dengan kesaksian yang akan, sedang, atau telah diberikannya; j. dirahasiakan identitasnya; k. memperoleh penggantian biaya transportasi selama proses penanganan perkara; l. mengajukan Restitusi melalui tuntutan; m. melakukan mekanisme Keadilan Restoratif; n. ikut serta dalam proses memilih dan menentukan bentuk pelindungan dan dukungan keamanan; o. mendapat bantuan medis dan Rehabilitasi psikososial dan psikologis; p. …"}, {"l": "UU 20/2025", "p": "145", "b": "Bagian Ketiga", "t": "(l) Penyandang Disabilitas berhak atas pelayanan dan sarana prasarana berdasarkan ragam Penyandang Disabilitas dalam setiap tahap pemeriksaan. (21 Ketentuan lebih lanjut mengenai pelayanan dan sarana prasarana sebagaimana dimaksud pada ayat (f ) diatur dalam Peraturan Pemerintah."}, {"l": "UU 20/2025", "p": "146", "b": "Bagian Ketiga", "t": "(1) Terhadap pelaku tindak pidana yang tidak dapat dimintai pertanggungiawaban karena Penyandang Disabilitas mental dan/ atau intelektual berat sebagaimana dimaksud dalam Kitab Undang-Undang Hukum Pidana, pengadilan dapat menetapkan tindakan berupa Rehabilitasi atau perawatan. (21 Tindakan sebagaimana dimaksud pada ayat (l) ditetapkan dengan penetapan Hakim dalam sidang terbuka untuk umum. (3) Penetapan tindakan sebagaimana dimaksud pada ayat (21 bukan merupakan putusan pemidanaan. (41 Ketentuan lebih lanjut mengenai tata cara pengajuan, pemeriksaan, dan pelaksanaan tindakan diatur dalam Peraturan Pemerintah."}, {"l": "UU 20/2025", "p": "147", "b": "Bagian Keempat", "t": "(1) Perempuan yang berhadapan dengan hukum dapat berstatus sebagai Tersangka, Terdakwa, Terpidana, Saksi, atau Korban. (2) Perempuan . . . REPUEUK INDONESIA (21 Perempuan yang berhadapan dengan hukum sebagaimana dimaksud pada ayat (l), selain memiliki hak sebagai Tersangka, Terdakwa, Terpidana, Saksi, Korban, atau Penyandang Disabilitas sebagaimana dimaksud dalam Pasal 142 sampai dengan Pasal 146, juga memiliki hak: a. mendapatkan perlakuan yang bebas dari sikap dan pernyataan yang merendahkan, menyalahkan, dan/atau mengintimidasi dalam setiap tahap pemeriksaan; b. mendapatkan pertimbangan situasi dan kepentingan dari kerugian yang tidak proporsional akibat ketidaksetaraan gender; c. mendapatkan Pendamping dalam setiap tahap pemeriksaan; d. didengar keterangannya melalui komunikasi audio visual jarak jauh di pengadilan setempat atau di tempat lain, jika kondisi kejiwaannya tidak sehat diakibatkan oleh rasa takut/trauma psikis berdasarkan penilaian dokter atau psikolog; dan/atau e. mendapatkan pertimbangan spesilik berbasis kerentanan dan kebutuhan gender dalam setiap keputusan Penyidik, Penuntut Umum, atau Hakim dalam melaksanakan seluruh kewenangan dalam Undang-Undang ini."}, {"l": "UU 20/2025", "p": "148", "b": "Bagian Kelima", "t": "(1) Orang lanjut usia dapat berstatus sebagai Tersangka, Terdakwa, Terpidana, Saksi, atau Korban. (21 Orang lanjut usia sebagaimana dimaksud pada ayat (1), selain memiliki hak sebagai Tersangka, Terdakwa, Terpidana, Saksi, Korban, atau Penyandang Disabilitas sebagaimana dimaksud dalam Pasal 142 sampai dengan Pasal 146, juga memiliki hak: a. pelayanan, sarana, dan prasarana khusus yang sesuai dengan kondisi fisik dan psikis pada setiap tahap pemeriksaan; b. mendapatkan . . . PEESIDEN b. mendapatkan pelayanan kesehatan lanjut usia; dan/ atau c. sedapat mungkin tidak dijatuhkan pidana penjara bagi Terdakwa yang berusia di atas 75 (tujuh puluh lima) tahun berdasarkan pertimbangan Hakim sesuai dengan ketentuan Undang-Undang yang mengatur mengenai kitab undang-undang hukum pidana."}, {"l": "UU 20/2025", "p": "149", "b": "Bagian Kesatu", "t": "(1) Advokat berstatus sebagai penegak hukum menjalankan tugas dan fungsi Jasa Hukum sesuai dengan etika profesi serta dijamin oleh hukum dan peraturan perundang-undangan. (21 Advokat tidak dapat dituntut baik secara perdata maupun pidana dalam menjalankan tugas profesinya dengan iktikad baik untuk kepentingan pembelaan klien di dalam atau di luar pengadilan."}, {"l": "UU 20/2025", "p": "150", "b": "Bagian Kesatu", "t": "Advokat berhak: a. memberikan Jasa Hukum dan/ atau Bantuan Hukum atas permintaan Tersangka, Terdakwa, Saksi, atau Korban; b menghubungi, dan mengunjungi Tersangka, Terdakwa, Saksi, atau Korban sejak saat ditangkap atau ditahan pada semua tahap pemeriksaan dan setiap waktu untuk kepentingan pembelaan perkaranya; c memberikan nasihat hukum kepada Tersangka, Terdakwa, Saksi, atau Korban mengenai hak dan kewajibannya dalam proses peradilan pidana; d. mendampingi . . . EEtrEIEtrN UELIK IN d. mendampingi Tersangka, Terdakwa, Saksi, dan Korban pada semua tahap pemeriksaan; e. meminta pejabat yang bersangkutan memberikan kepentingan pembelaan Tersangka sesaat setelah selesainya pemeriksaan; f. mengirim dan menerima surat dari Tersangka atau Terdakwa setiap kali dikehendaki olehnya; g. menghadiri sidang pengadilan dan mengajukan pembelaan terhadap Terdakwa; h. bebas mengeluarkan pendapat atau pernyataan di setiap tahap pemeriksaan pengadilan untuk memberikan pembelaan kepada Terdakwa; i. meminta keterangan dari Saksi dan Ahli dalam sidang pengadilan; j. meminta dokumen dan bukti yang relevan untuk membantu pembelaan; dan/ atau k. mengajukan bukti yang meringankan Terdakwa dalam proses …"}, {"l": "UU 20/2025", "p": "151", "b": "Bagian Kesatu", "t": "(1) Advokat wajib: a. memberikan Bantuan Hukum; b. mematuhi kode etik profesi; dan c. mematuhi ketentuan peraturan perundang- undangan. (21 Dalam memberikan Jasa Hukum dan/atau Bantuan Hukum, setiap Advokat wajib menunjukkan kepada Penyidik, Penuntut Umum, dan/atau Hakim di persidangan sesuai dengan tahap pemeriksaan: a. surat kuasa yang menunjukkan secarajelas perihal tindakan hukum yang dikuasakan oleh pemberi kuasa; dan b. berita acara sumpah pengangkatan sebagai Advokat dan/atau identitas keanggotaannya di dalam suatu lembaga Bantuan Hukum. Pasal 152 . . . Irl${ltrell REPUBUK INDONESIA"}, {"l": "UU 20/2025", "p": "152", "b": "Bagian Kesatu", "t": "(l) Advokat dalam berhubungan dengan Tersangka, Terdakwa, atau Terpidana diawasi oleh Penyidik, Penuntut Umum, atau petugas lembaga pemasyarakatan tanpa mendengar isi pembicaraan. (21 Dalam hal kejahatan terhadap keamanan negara, pejabat yang bersangkutan sebagaimana dimaksud pada ayat (1) dapat mendengar isi pembicaraan."}, {"l": "UU 20/2025", "p": "153", "b": "Bagian Kesatu", "t": "Penyidik, Penuntut Umum, atau petugas lembaga pemasyarakatan wajib memberikan salinan berita acara pemeriksaan kepada Tersangka, Terdakwa, atau Advokatnya untuk kepentingan pembelaannya dalam waktu paling lama 1 (satu) Hari terhitung sejak penandatanganan berita acara pemeriksaan."}, {"l": "UU 20/2025", "p": "154", "b": "Bagian Kedua", "t": "(l) Bantuan Hukum diberikan terhadap: a. Tersangka atau Terdakwa; dan b. pelapor, pengadu, Saksi, atau Korban, yang tidak mampu pada setiap tahap pemeriksaan. (21 Pejabat yang bersangkutan pada setiap tahap pemeriksaan wajib memberitahukan hak mendapatkan Bantuan Hukum dan menunjuk Advokat atau Pemberi Bantuan Hukum bagi Tersangka, Terdakwa, pelapor, pengadu, Saksi, atau Korban sebagaimana dimaksud pada ayat (1). (3) Advokat atau Pemberi Bantuan Hukum sebagaimana dimaksud pada ayat (1) dan ayat (21wajib memberikan Bantuan Hukum. (4) Kewajiban . . . REPUEUK INDONESIA (41 Kewajiban menujuk Advokat atau Pemberi Bantuan Hukum sebagaimana dimaksud pada ayat (2) tidak berlaku jika Tersangka, Terdakwa, pelapor, pengadu, Saksi, atau Korban menyatakan menolak untuk didampingi Advokat atau Pemberi Bantuan Hukum yang dibuktikan dengan berita acara. (5) Berita acara sebagaimana dimaksud pada ayat (4) dibuat oleh: a. Penyidik yang ditandatangani oleh Penyidik dan Tersangka, pelapor, pengadu, Saksi, atau Korban; b. Penuntut Umum yang ditandatangani oleh Penuntut Umum dan Tersangka, pelapor, pengadu, Saksi, atau Korban; atau c. Penuntut Umum yang ditandatangani oleh Penuntut Umum dan Terdakwa, …"}, {"l": "UU 20/2025", "p": "155", "b": "Bagian Kedua", "t": "(1) Dalam hal Tersangka atau Terdakwa disangka atau didakwa melakukan tindak pidana yang diancam dengan pidana mati, pidana penjara seumur hidup, pidana penjara 15 (lima belas) tahun atau lebih, pejabat yang bersangkutan pada semua tahap pemeriksaan wajib menunjuk Advokat bagi Tersangka atau Terdakwa. (21 Tersangka atau Terdakwa yang disangka atau didakwa melakukan tindak pidana yang diancam dengan pidana 5 (lima) tahun atau lebih, tetapi tidak mampu dan tidak mempunyai Advokat sendiri, pejabat yang bersangkutan pada semua tahap pemeriksaan wajib menunjuk Advokat bagi Tersangka atau Terdakwa. (3) Advokat atau Pemberi Bantuan Hukum sebagaimana dimaksud pada ayat (1) dan ayat (2) wajib memberikan Bantuan Hukum."}, {"l": "UU 20/2025", "p": "156", "b": "BAB IX BERITA ACARA", "t": "(1) Berita acara dibuat untuk setiap tindakan yang diperlukan dalam penyelesaian perkara mengenai: a. pemeriksaan Tersangka; b. Penangkapan; c. Penahanan; d. Penggeledahan; e. Penyitaan benda; f. Penyadapan; g. pemeriksaan surat; h. Pemblokiran; i. pengambilan keterangan Saksi; j. pemeriksaan di tempat kejadian; k. pengambilan Keterangan Ahli; l. pelaksanaan penetapan Hakim dan Putusan Pengadilan; m. pelelangan bukti; n. penyisihan bukti; dan o. pelaksanaan tindakan hukum lain sesuai dengan ketentuan dalam Undang-Undang ini. (2) Berita acara dibuat oleh pejabat yang bersangkutan dalam melakukan tindakan sebagaimana dimaksud pada ayat (1) dan dibuat atas kekuatan sumpah jabatan. (3) Selain ditandatangani oleh pejabat sebagaimana dimaksud pada ayat (2), berita acara ditandatangani oleh semua pihak yang terlibat dalam tindakan sebagaimana dimaksud pada ayat (1). (41 Tersangka atau Terdakwa berhak meminta konfirmasi kebenaran dari isi berita acara pemeriksaan. (slJika. . . (5) Jika isi berita acara pemeriksaan sebagaimana dimaksud pada ayat (a) tidak sesuai, Tersangka atau Terdakwa berhak menolak menandatangani berita acara pemeriksaan. (6) Pejabat yang berwenang wajib memberikan …"}, {"l": "UU 20/2025", "p": "157", "b": "BAB X SUMPAH ATAU JANJI", "t": "(l) Dalam hal diharuskan adanya pengambilan sumpah atau janji berdasarkan ketentuan dalam Undang- Undang ini, mekanisme pengambilan sumpah atau janji dilaksanalan sesuai dengan ketentuan peraturan perundang-undangan. (21 Jika ketentuan sebagaimana dimaksud pada ayat (1) tidak dipenuhi, sumpah atau janji tersebut batal demi hukum."}, {"l": "UU 20/2025", "p": "158", "b": "Bagian Kesatu", "t": "Pengadilan negeri berwenang untuk memeriksa dan memutus, sesuai dengan ketentuan dalam Undang-Undang ini mengenai: a. sah atau tidaknya pelaksanaan Upaya Paksa; b. sah atau tidaknya penghentian Penyidikan atau penghentian Penuntutan ; c. permintaan . . . IIEFUBUK INDONESIA c. permintaan Ganti Rugi dan/ atau Rehabilitasi bagi seseorang yang perkara pidananya dihentikan pada tahap Penyidikan atau Penuntutan; d. Penyitaan benda atau barang yang tidak ada kaitannya dengan tindak pidana; e. penundaan terhadap pen€rnganan perkara tanpa alasan yang sah; dan f. penangguhan pembantaran Penahanan."}, {"l": "UU 20/2025", "p": "159", "b": "Bagian Kesatu", "t": "(1) Wewenang pengadilan negeri sebagaimana dimaksud dalam Pasal 158 dilaksanakan oleh Praperadilan. (2) Praperadilan dipimpin oleh Hakim tunggal yang ditunjuk oleh ketua pengadilan negeri dan dibantu oleh seorang panitera."}, {"l": "UU 20/2025", "p": "160", "b": "Bagian Kesatu", "t": "(1) Permohonan pemeriksaan mengenai sah atau tidaknya pelaksanaan Upaya Paksa sebagaimana dimaksud dalam Pasal 158 huruf a diajukan oleh Tersangka, Keluarga Tersangka, atau Advokatnya kepada ketua pengadilan negeri dengan menyebutkan alasannya. (21 Permohonan pemeriksaan mengenai Penyitaan benda atau barang sebagaimana dimaksud dalam Pasal 158 huruf d diajukan oleh pihak ketiga. (3) Permohonan pemeriksaan sah atau tidaknya pelaksanaan Upaya Paksa yang diajukan oleh Tersangka, Keluarga Tersangka, atau Advokatnya sebagaimana dimaksud pada ayat (l) hanya dapat diajukan 1 (satu) kali untuk hal yang sama. (4) Permohonan Praperadilan sebagaimana dimaksud dalam Pasal 158 huruf a dan huruf c tidak dapat diajukan jika Tersangka melarikan diri atau dalam status daftar pencarian orang. Pasal 161 . .. FRES!DEN"}, {"l": "UU 20/2025", "p": "161", "b": "Bagian Kesatu", "t": "Permohonan untuk memeriksa sah atau tidaknya penghentian Penyidikan atau penghentian Penuntutan sebagaimana dimaksud dalam Pasal 158 huruf b dapat diajukan oleh Korban, pelapor, atau kuasa hukumnya kepada ketua pengadilan negeri dengan menyebutkan alasannya."}, {"l": "UU 20/2025", "p": "162", "b": "Bagian Kesatu", "t": "Permohonan Ganti Rugi dan/atau Rehabilitasi akibat tidak sahnya penghentian Penyidikan atau penghentian Penuntutan sebagaimana dimaksud dalam Pasal 158 huruf c diajukan oleh Korban atau pelapor kepada ketua pengadilan negeri dengan menyebutkan alasannya."}, {"l": "UU 20/2025", "p": "163", "b": "Bagian Kesatu", "t": "(1) Acara pemeriksaan Praperadilan ditentukan sebagai berikut: a. dalam jangka waktu 3 (tiga) Hari terhitung sejak permintaan diterima, Hakim yang ditunjuk menetapkan hari sidang; b. dalam memeriksa dan memutus permohonan sebagaimana dimaksud dalam Pasal 16O sampai dengan Pasal 162, Hakim mendengar keterangan baik dari Tersangka atau Advokatnya, Keluarga Tersangka, pihak yang berkepentingan, Penyidik, atau Penuntut Umum; c. pemeriksaan sebagaimana dimaksud dalam huruf b dilakukan secara cepat dan dalam jangka waktu paling lama 7 (tqiuh) Hari terhitung sejak permohonan dibacakan, Hakim harus sudah menjatuhkan putusannya; d. dalam keadaan termohon tidak hadir sebanyak 2 (dua) kali persidangan, pemeriksaan Praperadilan tetap dilanjutkan dan termohon dianggap melepaskan haknya; e.selama.-. REF].IBUK INDONESIA e. selama pemeriksaan sebagaimana dimaksud dalam huruf c belum selesai, pemeriksaan pokok perkara di pengadilan tidak dapat diselenggarakan; f. dalam hal putusan Praperadilan menetapkan Upaya Paksa yang dilakukan oleh Penyidik dan/atau Penuntut Umum dinyatakan tidak sah, hal lain yang terkait dengan Upaya Paksa tersebut agar dilakukan pemulihan dalam jangka waktu paling lama 3 …"}, {"l": "UU 20/2025", "p": "164", "b": "Bagian Kesatu", "t": "(1) Putusan Praperadilan terhadap permohonan sebagaimana dimaksud dalam Pasal 16O sampai dengan Pasal 162 tidak dapat dimintakan banding. (21 Ketentuan sebagaimana dimaksud pada ayat (1) dikecualikan terhadap putusan Praperadilan yang menetapkan tidak sahnya penghentian Penyidikan atau Penuntutan sehingga dapat dimintakan putusan akhir ke pengadilan tinggi dalam daerah hukum yang bersangkutan."}, {"l": "UU 20/2025", "p": "165", "b": "Bagian Kedua", "t": "(1) Pengadilan negeri berwenang memeriksa, Mengadili, dan memutus perkara tindak pidana yang dilakukan di daerah hukumnya. (21 Pengadilan negeri yang daerah hukumnya meliputi tempat tinggal Terdakwa, kediaman terakhir, atau tempat Terdakwa ditemukan atau ditahan, hanya berwenang Mengadili perkara Terdakwa tersebut, atau tempat kediaman sebagian besar Saksi yang dipanggil lebih dekat pada tempat pengadilan negeri itu daripada tempat kedudukan pengadilan negeri yang daerah hukumnya tindak pidana tersebut dilakukan. (3) Dalam . . . P]IESIDEN (3) Dalam hal seorzrng Terdakwa melakukan beberapa tindak pidana dalam daerah hukum beberapa pengadilan negeri, tiap pengadilan negeri tersebut masing-masing berwenang Mengadili perkara pidana itu. (4) Terhadap beberapa perkara pidana yang satu sama lain ada sangkut pautnya dan dilakukan oleh Terdakwa dalam daerah hukum beberapa pengadilan negeri, diadili oleh salah satu pengadilan negeri yang daerah hukumnya meliputi tempat tinggal Terdakwa dengan melakukan penggabungan perkara pidana tersebut. (5) Dalam hal seorang Terdakwa melakukan satu tindak pidana dalam daerah hukum beberapa pengadilan negeri, yang berwenang memeriksa, Mengadili, dan …"}, {"l": "UU 20/2025", "p": "166", "b": "Bagian Kedua", "t": "Dalam hal keadaan daerah tidak memungkinkan suatu pengadilan negeri untuk Mengadili suatu perkara, atas usul ketua pengadilan negeri atau kepala kejaksaan negeri yang bersangkutan, Mahkamah Agung menetapkan atau menunjuk pengadilan negeri lain untuk Mengadili perkara yang dimaksud dalam Pasal 165 ayat (21 untuk Mengadili perkara yang dimaksud."}, {"l": "UU 20/2025", "p": "167", "b": "Bagian Kedua", "t": "(1) Dalam hal seseorang melakukan tindak pidana di luar negeri yang dapat diadili menurut hukum Negara Kesatuan Republik Indonesia, Pengadilan Negeri di Ibu Kota Negara berwenang Mengadili. l2l Ketentuan sebagaimana dimaksud pada ayat (1) tidak berlaku jika perbuatan dilakukan di luar negeri bukan merupalan tindak pidana menurut hukum negara tempat perbuatan itu dilakukan, meskipun menurut hukum Indonesia perbuatan tersebut merupakan tindak pidana."}, {"l": "UU 20/2025", "p": "168", "b": "Bagian Ketiga", "t": "Pengadilan tinggi berwenang Mengadili perkara pidana yang diputus oleh pengadilan negeri dalam daerah hukumnya yang dimintakan banding."}, {"l": "UU 20/2025", "p": "169", "b": "Bagian Keempat", "t": "Mahkamah Agung berwenang Mengadili semua perkara pidana yang dimintakan kasasi dan peninjauan kembali."}, {"l": "UU 20/2025", "p": "170", "b": "BAB XII KONEKSITAS", "t": "(1) Tindak pidana yang dilakukan bersama-sama oleh mereka yang termasuk lingkungan peradilan umum dan lingkungan peradilan militer, diperiksa dan diadili oleh pengadilan dalam lingkungan peradilan umum. (21 Dalam hal tindak pidana sebagaimana dimalsud pada ayat (1) terdapat titik berat kerugian terletak pada kepentingan militer, perkara tersebut harus diperiksa dan diadili oleh pengadilan dalam lingkungan peradilan militer. (3) Penyidikan perkara pidana sebagaimana dimaksud pada ayat (1) dilakukan bersama-sama Penyidik dan polisi militer Tentara Nasional Indonesia di bawah koordinasi Penuntut Umum dan oditur militer. (4) Penyidik. . . REPUEUK INDONESIA (4) Penyidik dan polisi militer Tentara Nasional Indonesia dalam jangka waktu paling lama 7 (tujuh) Hari terhitung sejak Penyidikan selesai dilakukan harus melaporkan Penyidikan perkara koneksitas kepada Penuntut Umum dan oditur militer. (5) Penyidikan sebagaimana dimaksud pada ayat (3) dilakukan menurut hukum yang berlaku untuk Penyidikan perkara pidana."}, {"l": "UU 20/2025", "p": "171", "b": "BAB XII KONEKSITAS", "t": "(l) Penuntut Umum berkoordinasi dengan oditur militer untuk menetapkan pengadilan yang berwenang Mengadili tindak pidana atas dasar hasil Penyidikan sebagaimana dimaksud dalam Pasal l7O ayat (2). (21 Penetapan pengadilan yang berwenang sebagaimana dimaksud pada ayat (1) dituangkan dalam berita acara yang ditandatangani oleh Penuntut Umum dan oditur militer. (3) Salinan berita acara sebagaimana dimaksud pada ayal (21 disampaikan kepada jaksa tinggi bidang pidana militer dan oditur militer tinggi."}, {"l": "UU 20/2025", "p": "172", "b": "BAB XII KONEKSITAS", "t": "(1) Dalam ha1 tindak pidana sebagaimana dimaksud dalam Pasal 170 ayat (2) diadili oleh pengadilan dalam lingkungan peradilan militer, tindak pidana tersebut diadili oleh majelis hakim yang terdiri atas minimal 3 (tiga) orang Hakim dengan komposisi 2 (dua) Hakim peradilan militer yang salah satu diantaranya menjadi ketua majelis dan 1 (satu) Hakim peradilan umum. l2l Dalam hal pengadilan dalam lingkungan peradilan umum yang Mengadili tindak pidana sebagaimana dimaksud dalam Pasal L7O ayat (1), majelis Hakim terdiri atas Hakim ketua dari lingkungan peradilan umum dan Hakim anggota masing-masing ditetapkan dari peradilan umum dan peradilan militer secara berimbang. (3) Ketentuan . . . REPUELIK INDONESIA (3) Ketentuan sebagaimana dimaksud pada ayat (21 berlaku juga bagi pengadilan tingkat banding. l4l Mahkamah Agung dan menteri yang menyelenggarakan urusan pemerintahan di bidang pertahanan secara timbal balik mengusulkan pengangkatan Hakim anggota sebagaimana dimaksud pada ayat (2)."}, {"l": "UU 20/2025", "p": "173", "b": "Bagian Kesatu", "t": "(1) Tersangka, Terdakwa, atau Terpidana berhak menuntut Ganti Rugi karena ditangkap, ditahan, dituntut, diadili, atau dikenakan tindakan lain tanpa alasan yang sah berdasarkan Undang-Undang atau karena kekeliruan mengenai orangnya atau hukum yang diterapkan. (2) Tuntutan Ganti Rugi oleh Tersangka atau ahli warisnya atas Penangkapan atau Penahanan serta tindakan lain tanpa alasan yang sah berdasarkan Undang-Undang atau karena kekeliruan mengenai orang atau hukum yang diterapkan sebagaimana dimaksud pada ayat (1) diputus di sidang Praperadilan. (3) Tuntutan Ganti Rugi sebagaimana dimaksud pada ayat (1) diajukan oleh Tersangka, Terdakwa, Terpidana, atau ahli warisnya kepada pengadilan yang berwenang Mengadili perkara yang bersangkutan. (41 Untuk memeriksa dan memutus perkara tuntutan Ganti Rugi sebagaimana dimaksud pada ayat (1), ketua pengadilan negeri menunjuk Hakim yang sama yang telah Mengadili perkara pidana yang bersangkutan. (5) Pemeriksaan terhadap Ganti Rugi sebagaimana dimaksud pada ayat (4) mengikuti acara Praperadilan. Pasal 174 . . . K INDONESIA"}, {"l": "UU 20/2025", "p": "174", "b": "Bagian Kesatu", "t": "(1) Putusan pemberian Ganti Rugi berbentuk penetapan. (2t Penetapan sebagaimana dimaksud pada ayat (l) memuat dengan lengkap semua hal yang dipertimbangkan sebagai alasan bagi putusan tersebut."}, {"l": "UU 20/2025", "p": "175", "b": "Bagian Kesatu", "t": "(l) Pembayaran Ganti Rugi yang telah ditetapkan pengadilan bersumber dari dana abadi untuk pembayaran Ganti Rugi, Rehabilitasi, Restitusi, dan Kompensasi. (21 Pembayaran Ganti Rugi diberikan dalam jangka waktu paling lama 14 (empat belas) hari kerja terhitung sejak tanggal permohonan Ganti Rugi diterima oleh lembaga yang mengelola dana abadi untuk pembayaran Ganti Rugi, Rehabilitasi, Restitusi, dan Kompensasi sebagaimana dimaksud pada ayat (1). (3) Salinan penetapan pemberian Ganti Rugi sebagaimana dimaksud dalam Pasal 174 ayat (2) disampaikan kepada: a. Tersangka, Terdakwa, atau Terpidana; b. Penyidik; c. Penuntut Umum; dan d. lembaga yang mengelola dana abadi untuk pembayaran Ganti Rugi, Rehabilitasi, Restitusi, dan Kompensasi. (41 Penuntut Umum menyampaikan salinan penetapan Ganti Rugi sebagaimana dimaksud pada ayat (3) dalam jangka waktu paling lama 3 (tiga) hari terhitung sejak penetapan ditetapkan. (5) Ketentuan lebih lanjut mengenai pembayaran Ganti Rugi diatur dalam Peraturan Pemerintah."}, {"l": "UU 20/2025", "p": "176", "b": "Bagian Kedua", "t": "(1) Seorang berhak memperoleh Rehabilitasi apabila oleh pengadilan diputus bebas atau diputus lepas dari segala tuntutan hukum yang putusannya telah memperoleh kekuatan hukum tetap. (2) Rehabilitasi sebagaimana yang dimaksud pada ayat (1) meliputi: a. Rehabilitasisosial; b. Rehabilitasi medis; c. pemberdayaan sosial; dan d. reintegrasi sosial. (3) Rehabilitasi tersebut diberikan dan dicantumkan sekaligus dalam Putusan Pengadilan sebagaimana dimaksud pada ayat (l). (4) Permintaan Rehabilitasi oleh Tersangka atas Penangkapan atau Penahanan tanpa alasan yang berdasarkan Undang-Undang atau kekeliruan mengenai orang atau hukum yang diterapkan dan perkaranya tidak diajukan ke pengadilan negeri diputus oleh Halim Praperadilan."}, {"l": "UU 20/2025", "p": "177", "b": "Bagian Kedua", "t": "(l) Pendanaan Rehabilitasi bersumber dari dana abadi untuk pembayaran Ganti Rugi, Rehabilitasi, Restitusi, dan Kompensasi sebagaimana dimaksud dalam"}, {"l": "UU 20/2025", "p": "178", "b": "Bagian Ketiga", "t": "(1) Korban berhak mendapatkan Restitusi. (21 Restitusi sebagaimana dimaksud pada ayat (1) berupa: a. ganti rugi atas kehilangan kekayaan atau penghasilan; b. ganti rugi yang ditimbulkan akibat penderitaan yang berkaitan langsung sebagai akibat tindak pidana; dan/ atau c. penggantian biaya perawatan medis dan/atau psikologis."}, {"l": "UU 20/2025", "p": "179", "b": "Bagian Ketiga", "t": "(1) Penyidik, Penuntut Umum, dan Hakim wajib memberitahukan hak atas Restitusi kepada Korban dan lembaga yang melaksanakan tugas dan fungsi di bidang pelindungan saksi dan korban sesuai dengan ketentuan peraturan perundang-undangan. (21 Penyidik dan Penuntut Umum sebagaimana dimaksud pada ayat (1) wajib memfasilitasi penghitungan Restitusi. (3) Restitusi dapat dititipkan terlebih dahulu di kepaniteraan pengadilan negeri tempat perkara diperiksa. (41 Penyidik dapat melakukan Penyitaan terhadap harta kekayaan pelaku tindak pidana sebagai jaminan Restitusi dengan izin ketua pengadilan negeri. (5) Penyitaan sebagaimana dimaksud pada ayat (4) dilakukan dengan memperhatikan hak pihak ketiga yang beriktikad baik."}, {"l": "UU 20/2025", "p": "180", "b": "Bagian Ketiga", "t": "Restitusi dikembalikan kepada pelaku dalam hal Terdakwa diputus bebas atau lepas dari segala tuntutan hukum. Pasal 181.. . REPUBUK INDONESIA"}, {"l": "UU 20/2025", "p": "181", "b": "Bagian Ketiga", "t": "(1) Restitusi diberikan dalam jangka waktu paling lama 30 (tiga puluh) Hari terhitung sejak salinan Putusan Pengadilan diterima. (21 Jaksa menyampaikan salinan Putusan Pengadilan yang memuat pemberian Restitusi sebagaimana dimaksud pada ayat (1) kepada Terpidana, Korban, dan lembaga yang melaksanakan tugas dan fungsi di bidang pelindungan saksi dan korban sesuai dengan ketentuan peraturan perundang-undangan dalam jangka waktu paling lama 7 (tqiuh) Hari terhitung sejak (3) Dalam hal pelaksanaan pemberian Restitusi kepada pihak Korban tidak dipenuhi sampai jangka waktu sebagaimana dimaksud pada ayat (1), Korban atau ahli warisnya memberitahukan hal tersebut kepada pengadilan. (41 Pengadilan sebagaimana dimaksud pada ayat (3) memberikan surat peringatan secara tertulis kepada pemberi Restitusi untuk segera memenuhi kewajiban memberikan Restitusi kepada Korban atau ahli warisnya. (5) Hakim dalam putusan memerintahkan Jaksa untuk melelang sita jaminan Restitusi sepanjang tidak dilakukan pembayaran Restitusi dalam jangka waktu paling lama 30 (tiga puluh) Hari setelah Putusan Pengadilan yang telah memperoleh kekuatan hukum tetap. (6) Dalam hal Restitusi yang dititipkan dan harta kekayaan …"}, {"l": "UU 20/2025", "p": "182", "b": "Bagian Ketiga", "t": "(1) Jaksa membuat berita acara pelaksanaan Restitusi dan disampaikan kepada Korban. (2) Salinan berita acara sebagaimana dimaksud ayat (1) disampaikan kepada: a. Keluarga Korban; b. Penyidik; dan c. pengadilan."}, {"l": "UU 20/2025", "p": "183", "b": "Bagian Keempat", "t": "(1) Korban berhak mendapatkan Kompensasi. t2l Kompensasi sebagaimana dimaksud pada ayat (1) berupa: a. ganti rugi atas kehilangan kekayaan atau penghasilan; b. ganti rugi yang ditimbulkan akibat penderitaan yang berkaitan langsung sebagai akibat tindak pidana; dan/ atau c. penggantian biaya perawatan medis dan/atau psikologis. (3) Kompensasi sebagaimana dimaksud pada ayat (l) diberikan oleh negara dalam hal pelaku tindak pidana tidak dapat membayar Restitusi. Pasal 184. . . EtFEIEtrN REPUBUK INDONESIA"}, {"l": "UU 20/2025", "p": "184", "b": "Bagian Keempat", "t": "(l) Penyidik, Penuntut Umum, dan Hakim wajib memberitahukan hak atas Kompensasi kepada Korban dan lembaga yang melalsanakan tugas dan fungsi di bidang pelindungan saksi dan korban sesuai dengan ketentuan peraturan pemndang-undangan. l2l Kompensasi dapat dititipkan terlebih dahulu di kepaniteraan pengadilan negeri tempat perkara diperiksa."}, {"l": "UU 20/2025", "p": "185", "b": "Bagian Keempat", "t": "( 1) Kompensasi diberikan dalam jangka waktu paling lama 30 (tiga puluh) Hari terhitung sejak salinan Putusan Pengadilan diterima. (2) Jaksa menyampaikan salinan Putusan Pengadilan yang memuat pemberian Kompensasi sebagaimana dimaksud pada ayat (1) kepada Terpidana, Korban, dan lembega yang melaksanakan tugas dan fungsi di bidang pelindungan saksi dan korban sesuai dengan ketentuan peraturan pemndang-undangan dalam jangka waktu paling lama 7 (tqiuh) Hari terhitung sejak (3) Apabila pelaksanaan pemberian Kompensasi kepada pihak Korban tidak dipenuhi sampai jangka waktu sebagaimana dimaksud pada ayat (1), Korban atau ahli warisnya memberitahukan hal tersebut kepada pengadilan."}, {"l": "UU 20/2025", "p": "186", "b": "Bagian Keempat", "t": "(1) Jaksa membuat berita acara pelaksanaan Kompensasi dan disampaikan kepada Korban. (2) Salinan berita acara sebagaimana dimaksud pada ayat (1) disampaikan kepada: a. Keluarga Korban; b. Penyidik; dan c. pengadilan."}, {"l": "UU 20/2025", "p": "187", "b": "Bagian Kelima", "t": "(1) Dana abadi untuk pembayaran Ganti Rugi, Rehabilitasi, Restitusi, dan Kompensasi bersumber dari: a. Anggaran Pendapatan dan Belanja Negara; b. pendapatan investasi; c. bagi hasil dari Pendapatan Negara Bukan Pajak penegakan hukum; d. hasil pengelolaan barang rampasan; dan/ atau e. sumber lain yang sah dan tidak mengikat sesuai dengan ketentuan peraturan perundang-undangan. (2) Pendapatan investasi sebagaimana dimaksud pada ayat (1) huruf b merupakan hasil pengelolaan dana abadi untuk pembayaran Ganti Rugi, Rehabilitasi, Restitusi, dan Kompensasi. (3) Dana abadi sebagaimana dimaksud pada ayat (1) dibayarkan oleh lembaga yang mengelola dana abadi untuk pembayaran Ganti Rugi, Rehabilitasi, Restitusi, dan Kompensasi."}, {"l": "UU 20/2025", "p": "188", "b": "Bagian Kelima", "t": "Ketentuan lebih lanjut mengenai dana abadi untuk Ganti Rugi, Rehabilitasi, Restitusi, dan Kompensasi sebagaimana dimaksud dalam Pasal 187 diatur dalam Peraturan Pemerintah."}, {"l": "UU 20/2025", "p": "189", "b": "BAB XIV PENGGABUNGAN PERKARA GANTI RUGI", "t": "(1) Jika suatu perbuatan yang menjadi dasar dakwaan di dalam suatu pemeriksaan perkara pidana oleh pengadilan negeri menimbulkan kerugian bagi orang lain, Halim ketua sidang atas permintaan orang itu dapat menetapkan untuk menggabungkan perkara gugatan ganti rugi kepada perkara pidana itu. (2) Permintaan . . . REPUBUK INDONESIA -to2- (2) Permintaan sebagaimana dimaksud pada ayat (1) hanya dapat diajukan dalam waktu paling lambat sebelum Penuntut Umum mengajukan tuntutan pidana. (3) Dalam hal Penuntut Umum tidak hadir, permintaan diajukan dalam waktu paling lambat sebelum Hakim menjatuhkan putusan."}, {"l": "UU 20/2025", "p": "190", "b": "BAB XIV PENGGABUNGAN PERKARA GANTI RUGI", "t": "(1) Jika pihak yang dirugikan minta penggabungan perkara gugatannya pada perkara pidana sebagaimana dimaksud dalam Pasal 189 ayat (l), pengadilan negeri menimbang mengenai kewenangannya untuk Mengadili gugatan tersebut, kebenaran dasar gugatan, dan hukuman penggantian biaya yang telah dikeluarkan oleh pihak yang dirugikan. (2) Dalam hal pengadilan negeri menyatakan tidak berwenang Mengadili gugatan sebagaimana dimaksud pada ayat (1) atau gugatan dinyatakan tidak dapat diterima, putusan Hakim hanya memuat mengenai penetapan hukuman penggantian biaya yang telah dikeluarkan oleh pihak yang dirugikan. (3) Putusan mengenai ganti rugi dengan sendirinya mendapat kekuatan tetap, jika putusan pidananya juga mendapat kekuatan hukum tetap. Pasal 19 I (1) Dalam hal terjadi penggabungan antara perkara perdata dan perkara pidana, penggabungan itu dengan sendirinya berlangsung dalam pemeriksaan tingkat banding. (2) Permohonan banding terhadap putusan ganti rugi tidak dapat diajukan dalam hal terhadap perkara pidana tidak diajukan permohonan banding."}, {"l": "UU 20/2025", "p": "192", "b": "BAB XIV PENGGABUNGAN PERKARA GANTI RUGI", "t": "Ketentuan mengenai hukum acara perdata berlaku bagi gugatan ganti rugi sepanjang tidak diatur lain dalam Undang-Undang ini."}, {"l": "UU 20/2025", "p": "193", "b": "Bagian Kesatu", "t": "(1) Penuntut Umum memanggil secara sah kepada Terdakwa untuk datang ke sidang pengadilan melalui alamat tempat tinggalnya. (2) Dalam hal alamat atau tempat tinggal Terdakwa tidak diketahui, panggilan disampaikan di tempat kediaman terakhir Terdakwa. (3) Apabila Terdakwa tidak ada di tempat tinggalnya atau di tempat kediaman terakhir, surat panggilan disampaikan melalui kepala desa/lurah atau nama lainnya dalam daerah hukum tempat tinggal Terdakwa atau tempat kediaman terakhir. (4) Dalam hal Terdakwa ditahan dalam rumah tahanan negara, surat panggilan disampaikan kepada Terdakwa melalui pejabat rumah tahanan negara. (5) Surat panggilan yang diterima oleh Terdakwa sendiri atau oleh orang lain dilakukan dengan tanda penerimaan. (6) Dalam hal tempat tinggal atau tempat kediaman terakhir tidak diketahui, surat panggilan ditempelkan pada papan pengumuman di gedung pengadilan tempat Terdakwa diadili atau diperiksa. (7) Datam hal Terdakwa merupakan Korporasi, panggilan disampaikan kepada pengurus di tempat kedudukan Korporasi sebagaimana tercantum dalam anggaran dasar Korporasi tersebut. (8) Salah seorang pengurus Korporasi wajib menghadap di sidang pengadilan mewakili Korporasi. Pasal …"}, {"l": "UU 20/2025", "p": "194", "b": "Bagian Kesatu", "t": "(l) Penuntut Umum menyampaikan surat panggilan kepada Terdakwa yang memuat tanggal, hari, dan jam sidang, serta jenis perkara. (2) Panggilan sebagaimana dimaksud pada ayat (l) harus sudah diterima oleh yang bersangkutan dalam waktu paling lambat 7 (tujuh) Hari sebelum sidang dimulai. (3) Dalam hal Penuntut Umum memanggil Saksi, surat panggilan memuat hal sebagaimana dimaksud pada ayat (1) yang harus diterima oleh yang bersangkutan dalam waktu paling lambat 7 (tujuh) Hari sebelum sidang dimulai."}, {"l": "UU 20/2025", "p": "195", "b": "Bagian Kedua", "t": "Setelah pengadilan negeri menerima surat pelimpahan perkara dari Penuntut Umum, ketua pengadilan negeri mempelajari apakah perkara yang disampaikan tersebut termasuk wewenang pengadilan yang dipimpinnya."}, {"l": "UU 20/2025", "p": "196", "b": "Bagian Kedua", "t": "(l) Dalam hal ketua pengadilan negeri berpendapat bahwa perkara pidana tersebut tidak termasuk wewenang pengadilan yang dipimpinnya, tetapi termasuk wewenang pengadilan negeri lain, ketua pengadilan negeri menyerahkan surat pelimpahan perkara tersebut kepada pengadilan negeri lain yang dianggap berwenang Mengadilinya dengan surat penetapan yang memuat alasan pelimpahan perkara. (21 Surat pelimpahan perkara sebagaimana dimaksud pada ayat (l) diserahkan kembali kepada Penuntut Umum, selanjutnya kejaksaan negeri yang bersangkutan menyampaikan kepada kejaksaan negeri di tempat pengadilan negeri yang tercantum dalam surat penetapan. (3) T[runan surat penetapan sebagaimana dimaksud pada ayat (1) disampaikan kepada Terdakwa, Advokat, dan Penyidik. Pasal 197. . . REPUBUK INDONESIA"}, {"l": "UU 20/2025", "p": "197", "b": "Bagian Kedua", "t": "(1) Dalam ha1 Penuntut Umum melakukan perlawanan terhadap surat penetapan pengadilan negeri sebagaimana dimaksud dalam Pasal 196 ayat (1), Penuntut Umum mengajukan perlawanan kepada pengadilan tinggi yang wilayah hukumnya meliputi tempat pengadilan negeri yang bersangkutan dalam jangka waktu paling lama 7 (tujuh) Hari terhitung sejak surat penetapan tersebut diterima. (2) Apabila jangka waktu sebagaimana dimalsud pada ayat (U terlampaui, perlawanan yang diajukan Penuntut Umum menjadi batal. (3) Perlawanan sebagaimana dimaksud pada ayat (l) disampaikan kepada ketua pengadilan negeri dan dicatat dalam buku daftar panitera. (4) Dalam jangka waktu 7 (tujuh) Hari terhitung sejak menerima perlawanan sebagaimana dimaksud pada ayat (3), pengadilan negeri wajib meneruskan perlawanan tersebut kepada pengadilan tinggi yang wilayah hukumnya meliputi tempat pengadilan negeri yang bersangkutan. (5) Pengadilan tinggi dalam jangka waktu paling lama 14 (empat belas) Hari terhitung sejak menerima perlawanan, dapat menguatkan atau menolak perlawanan tersebut dengan surat penetapan. (6) Dalam hal pengadilan tinggi menguatkan perlawanan Penuntut Umum, dengan surat penetapan pengadilan tinggi …"}, {"l": "UU 20/2025", "p": "198", "b": "Bagian Kedua", "t": "Sengketa mengenai wewenang Mengadili terjadi jika: a. 2 (dua) pengadilan atau lebih menyatakan dirinya berwenang Mengadili atas perkara yang sama; atau b. 2 (dua) pengadilan atau lebih menyatakan dirinya tidak berwenang Mengadili perkara yang sama."}, {"l": "UU 20/2025", "p": "199", "b": "Bagian Kedua", "t": "(1) Pengadilan tinggi memutus sengketa wewenang Mengadili antara 2 (dua) pengadilan negeri atau lebih yang berkedudukan dalam daerah hukumnya. (21 Mahkamah Agung memutus pada tingkat pertama dan terakhir semua sengketa mengenai wewenang Mengadili antara: a. pengadilan dari satu lingkungan peradilan dengan pengadilan dari lingkungan peradilan yang lain; b. 2 (dua) pengadilan negeri atau lebih yang berkedudukan dalam daerah hukum pengadilan tinggi yang berlainan; atau c. 2 (dua) pengadilan tinggi atau lebih."}, {"l": "UU 20/2025", "p": "200", "b": "Bagian Ketiga", "t": "(1) Jika pengadilan negeri menerima surat pelimpahan perkara dan berpendapat bahwa perkara itu termasuk wewenangnya, ketua pengadilan menunjuk Hakim yang akan menyidangkan perkara tersebut. (21 Hakim yang ditunjuk sebagaimana dimaksud pada ayat (l) menetapkan hari sidang. (3) Halim dalam menetapkan hari sidang sebagaimana dimaksud pada ayat (2) memerintahkan kepada Penuntut Umum untuk memanggil Terdakwa dan Saksi untuk datang di sidang pengadilan. Pasal 201 ... PRES!DEN REPUELIK INOONESIA -to7-"}, {"l": "UU 20/2025", "p": "201", "b": "Bagian Ketiga", "t": "(l) Pada hari dan tanggal sidang pemeriksaan: a. Penuntut Umum, Terdakwa dan/atau Advokat Terdakwa menghadirkan Saksi dan/atau Ahli untuk didengar keterangannya; dan/ atau b. Penuntut Umum dan/atau Terdakwa hadir sendiri untuk didengar keterangannya, kecuali jika terdapat alasan yang kuat untuk tidak menghadirkan Terdakwa. (21 Dalam hal Terdakwa ditahan, Penuntut Umum wajib menghadirkan Terdakwa. (3) Dalam hal Saksi dan/atau Ahli tidak dapat hadir dengan alasan yang sah, pemeriksaan terhadap Saksi dan/ atau Ahli dimaksud dapat ditunda untuk I (satu) kali. (4) Jika dalam sidang berikutnya Saksi dan/ atau Ahli tersebut tetap tidak hadir, pemeriksaan perkara dilanjutkan tanpa mendengar Keterangan Saksi dan/atau Ahli tersebut. (5) Jika pihak yang memohon untuk mendengar Keterangan Saksi dan/ atau Ahli tidak hadir pada tanggal yang telah ditentukan, permohonan menjadi batal. (6) Sidang pemeriksaan Saksi dan/atau Ahli dilakukan secara terbuka, kecuali untuk perkara tempat persidangan dilakukan secara tertutup sesuai dengan ketentuan Undang-Undang."}, {"l": "UU 20/2025", "p": "202", "b": "Bagian Ketiga", "t": "(1) Pada hari sidang yang telah ditetapkan, pengadilan wajib membuka persidangan. (21 Untuk keperluan pemeriksaan, Hakim ketua sidang membuka sidang dan menyatakan terbuka untuk umum, kecuali dalam perkara mengenai kesusilaan atau terdakwanya anak. (3) Dalam hal tidak dipenuhinya ketentuan sebagaimana dimaksud pada ayat (l), putusan batal demi hukum. (4) Hakim. . . (4) Hakim ketua sidang memimpin pemeriksaan di sidang pengadilan yang dilakukan secara lisan dalam bahasa Indonesia yang dimengerti oleh Terdakwa dan Saksi. (5) Hakim sebagaimana dimaksud pada ayat (2) wajib menjaga agar tidak dilakukan hal atau diajukan pertanyaan yang mengakibatkan Terdakwa atau Saksi memberikan jawaban secara tidak bebas. (6) Hakim ketua sidang dapat menentukan bahwa anak yang belum mencapai umur 17 (tujuh belas) tahun tidak dibolehkan menghadiri sidang."}, {"l": "UU 20/2025", "p": "203", "b": "Bagian Ketiga", "t": "(1) Jika Terdakwa ternyata telah dipanggil secara sah tetapi tidak datang di sidang tanpa alasan yang sah, pemeriksaan perkara tersebut tidak dapat dilangsungkan dan Hakim ketua sidang memerintahkan agar Terdakwa dipanggil sekali lagi. (2) Dalam hal pemeriksaan perkara Terdakwa yang tidak ditahan tidak hadir pada hari sidang yang telah ditetapkan, Hakim ketua sidang meneliti apakah Terdakwa sudah dipanggil secara sah. (3) Hakim ketua sidang memerintahkan agar Terdakwa yang tidak hadir tanpa alasan yang sah setelah dipanggil secara sah untuk kedua kalinya dihadirkan dengan paksa pada sidang berikutnya. (4) Dalam hal suatu perkara terdapat lebih dari seorang Terdakwa dan tidak semua Terdakwa hadir pada hari sidang, pemeriksaan terhadap Terdakwa yang hadir tetap dapat dilaksanakan."}, {"l": "UU 20/2025", "p": "204", "b": "Bagian Ketiga", "t": "(1) Pada permulaan sidang, Hakim ketua sidang menanyakan kepada Terdakwa mengenai nama lengkap, tempat lahir, umur atau tanggal lahir, jenis kelamin, kebangsaan, tempat tinggal, agama dan pekerjaannya serta mengingatkan Terdakwa supaya memperhatikan segala sesuatu yang didengar dan dilihatnya di sidang. (2) Dalam . . . REPUBUK INDONESIA (21 Dalam keadaan tertentu, baik sejak awal persidangan perkara maupun pada saat persidangan perkara sedang berlangsung, Hakim/majelis hakim karena jabatannya atau atas permintaan dari Penuntut Umum dan/ atau Terdakwa atau Advokat dapat menetapkan persidangan yang dilakukan sebagaimana dimaksud pada ayat (1) secara elektronik. (3) Hakim ketua sidang meminta Penuntut Umum untuk membacakan surat dakwaan dan menanyakan kepada Terdakwa apakah Terdakwa sudah mengerti isi surat dakwaan. (41 Jika Terdakwa tidak mengerti isi surat dakwaan, Penuntut Umum atas permintaan Hakim ketua sidang wajib memberi penjelasan yang diperlukan. (5) Dalam hal tindak pidana yang didakwakan bukan merupakan: a. tindak pidana yang diancam dengan pidana penjara 5 (lima) tahun atau lebih; b. tindak pidana terhadap keamanan negara, negara sahabat, kepala negara sahabat serta …"}, {"l": "UU 20/2025", "p": "205", "b": "Bagian Ketiga", "t": "(1) Dalam hal Terdakwa dan Korban tidak bersepakat untuk melakukan perdamaian, Hakim menanyakan kepada Terdakwa apakah Terdakwa bersedia mengakui dakwaan yang dibacakan oleh Penuntut Umum. (21 Dalam hal Terdakwa bersedia mengakui dakwaan yang dibacakan oleh Penuntut Umum, Hakim wajib memeriksa pengakuan Terdakwa dengan mempertimbangkan hal: a. Terdakwa telah diperiksa pada tahap Penyidikan; b. Terdakwa didampingi oleh Advokat selama pemeriksaan pada tahap Penyidikan; c. pemeriksaan pada tahap Penyidikan dilakukan dengan cara dan dalam waktu yang patut; d. Terdakwa telah diberitahu dan dapat menggunakan haknya selama Penyidikan dan Penuntutan; e. pengakuan Terdakwa tidak disebabkan oleh adanya tekanan, paksaan, dan/atau penyiksaan, baik secara fisik maupun psikis, selama proses Penyidikan dan Penuntutan; dan f. hal lain yang dipandang perlu oleh Hakim. (3) Dalam . . . REPIIELIK INDONESIA (3) Dalam hal Hakim memperoleh keyakinan bahwa seluruh hal sebagaimana dimaksud pada ayat (2) telah terpenuhi, Hakim menentukan perkara akan diperiksa dengan acara pemeriksaan singkat. (41 Dalam hal Terdakwa tidak mengakui perbuatan yang didakwakan kepadanya atau Hakim tidak memperoleh keyakinan …"}, {"l": "UU 20/2025", "p": "206", "b": "Bagian Ketiga", "t": "(l) Dalam hal Terdakwa atau Advokat mengajukan perlawanan bahwa pengadilan tidak berwenang Mengadili perkaranya atau dakwaan tidak dapat diterima atau surat dakwaan harus dibatalkan, setelah diberi kesempatan kepada Penuntut Umum untuk menyatakan pendapatnya, Hakim mempertimbangkan perlawanan tersebut untuk selanjutnya mengambil keputusan. (21 Dalam hal Hakim menyatakan perlawanan tersebut diterima, perkara tersebut tidak diperiksa lebih lanjut. (3) Dalam hal Hakim menyatakan perlawanan tidak diterima atau Hakim berpendapat hal tersebut baru dapat diputus setelah selesai pemeriksaan, sidang dilanjutkan. (4) Penuntut Umum dapat mengajukan perlawanan terhadap putusan sebagaimana dimaksud pada ayat (21 kepada pengadilan tinggi melalui pengadilan negeri yang bersangkutan. (5) Dalam hal terjadi keadaan sebagaimana dimaksud pada ayat (3) dan perlawanan yang diajukan oleh Terdakwa atau Advokatnya diterima oleh pengadilan tinggi, dalam jangka waktu 14 (empat belas) Hari, pengadilan tinggi dengan surat penetapannya membatalkan putusan pengadilan negeri dan memerintahkan pengadilan negeri yang berwenang untuk memeriksa perkara tersebut. (6) Dalam . . . REPUEUK INOONESIA -lt2- (6) Dalam hal …"}, {"l": "UU 20/2025", "p": "207", "b": "Bagian Ketiga", "t": "(1) Hakim wajib mengundurkan diri untuk Mengadili perkara apabila terikat hubungan keluarga sedarah atau semenda sampai derajat ketiga, hubungan suami atau istri meskipun sudah bercerai dengan Hakim ketua sidang, salah seorang Hakim anggota, Penuntut Umum, atau panitera. (2) Hakim ketua sidang, Hakim anggota, Penuntut Umum, atau panitera wajib mengundurkan diri dari menangani perkara apabila terikat hubungan keluarga sedarah atau semenda sampai derajat ketiga atau hubungan suami atau istri meskipun sudah bercerai dengan Terdakwa atau dengan Advokat. (3) Dalam . . . REPUEUK INDONESIA (3) Dalam hal ketentuan sebagaimana dimalsud pada ayat (1) dan ayat (2) dipenuhi, Halim ketua sidang, Hakim anggota, Penuntut Umum, dan panitera yang mengundurkan diri harus diganti. (41 Apabila ketentuan sebagaimana dimaksud pada ayat (3) tidak dipenuhi atau tidak diganti sedangkan perkara telah diputus, perkara dalam waktu paling lambat 2 (dua) Hari sejak tanggal putusan wajib diadili ulang dengan susunan yang lain."}, {"l": "UU 20/2025", "p": "208", "b": "Bagian Ketiga", "t": "Sebelum majelis memutuskan, Hakim dilarang menunjukkan sikap atau mengeluarkan pernyataan di sidang mengenai keyakinan mengenai salah atau tidaknya Terdakwa."}, {"l": "UU 20/2025", "p": "209", "b": "Bagian Ketiga", "t": "(1) Hakim ketua sidang meneliti apakah semua Saksi atau Ahli yang dipanggil telah hadir dan memberi perintah untuk mencegah jangan sampai Saksi atau Ahli berhubungan satu dengan yang lain sebelum memberi keterangan di sidang. (21 Dalam hal Saksi atau Ahli tidak hadir meskipun telah dipanggil dengan sah dan Hakim ketua sidang mempunyai cukup alasan untuk menyangka bahwa Saksi itu tidak akan hadir, Hakim ketua sidang dapat memerintahkan agar Saksi tersebut dihadapkan ke persidangan."}, {"l": "UU 20/2025", "p": "210", "b": "Bagian Ketiga", "t": "(1) Penuntut Umum dan Terdakwa atau Advokat Terdakwa diberi kesempatan menyampaikan penjelasan singkat untuk menguraikan bukti dan Saksi yang akan diajukan pada persidangan. (21 Sesudah pernyataan pembuka, Saksi dan Ahli memberikan keterangan. (3) Urutan Saksi dan AhIi ditentukan oleh pihak yang memanggil. (4) Penuntut Umum mengajukan Sal<si, Ahli, dan buktinya terlebih dahulu. (5) Dalam . . . -tt4- (5) Dalam hal Hakim menyetujui Saksi dan Ahli yang diminta oleh Advokat untuk dihadirkan, Hakim memerintahkan kepada Penuntut Umum untuk memanggil Saksi dan Ahli yang diajukan oleh Advokat tersebut. (6) Hakim ketua sidang menanyakan kepada Saksi dan/atau Ahli mengenai nama lengkap, umur atau tanggal lahir, jenis kelamin, kebangsaan, tempat tinggal, agama, dan pekerjaan Saksi dan/ atau Ahli. (71 Selain menanyakan keterangan sebagaimana dimaksud pada ayat (6), Hakim juga menanyakan apakah Saksi mengenal Terdakwa sebelum Terdakwa melakukan perbuatan yang menjadi dasar dakwaan atau apakah Saksi mempunyai hubungan keluarga sedarah atau semenda sampai derajat ketiga dengan Terdakwa, atau suami atau istri dari Terdakwa, atau pernah menjadi suami atau istri dari Terdakwa, atau terikat hubungan …"}, {"l": "UU 20/2025", "p": "212", "b": "Bagian Ketiga", "t": "(l) Jika Saksi setelah memberi keterangan dalam Penyidikan tidak hadir di sidang karena: a. meninggal dunia atau karena halangan yang sah; b. jauh tempat kediaman atau tempat tinggalnya; atau c. karena sebab lain yang berhubungan dengan kepentingan negara, keterangan yang telah diberikan tersebut dibacakan. l2l Jika keterangan sebagaimana dimaksud pada ayat (l) diberikan di bawah sumpah atau janji, keterangan tersebut oleh Hakim dapat dipertimbangkan sebagai Keterangan Saksi di bawah sumpah atau janji yang diucapkan di sidang. Pasal 2 13 Jika Keterangan Saksi di sidang berbeda dengan keterangan yang terdapat dalam berita acara, Hakim ketua sidang mengingatkan Saksi mengenai hal tersebut dan meminta keterangan mengenai perbedaan yang ada dan dicatat dalam berita acara pemeriksaan sidang. Pasal2l4 (1) Penuntut Umum terlebih dahulu mengajukan pertanyaan kepada Saksi atau Ahli yang dihadirkan oleh Penuntut Umum. (21 Setelah Penuntut Umum selesai mengajukan pertanyaan, Advokat dapat mengajukan pertanyaan kepada Saksi atau Ahli. (3) Penuntut. . . FRES!DEN REFUBUK INDONESIA (3) Penuntut Umum dapat mengajukan pertanyaan kembali kepada Saksi atau Ahli untuk memperjelas setiap jawaban yang …"}, {"l": "UU 20/2025", "p": "215", "b": "Bagian Ketiga", "t": "Pertanyaan yang bersifat menjerat dilarang diajukan kepada Saksi Ahli, atau Terdakwa. Pasal 2 16 (1) Penuntut Umum dengan izin Hakim ketua sidang memperlihatkan kepada Terdakwa semua alat bukti dan menanyakan kepada Terdakwa apakah mengenal alat bukti tersebut dengan memperhatikan ketentuan sebagaimana dimaksud dalam Pasal 214. (2)Jika... REPUEUK INDONESIA -tL7- (2) Jika izin Hakim ketua sidang diperlukan, alat bukti diperlihatkan juga oleh Penuntut Umum kepada Saksi. (3) Untuk kepentingan pembuktian, Hakim ketua sidang dapat membacakan atau memperlihatkan surat atau berita acara kepada Terdgkwa atau Saksi dan selanjutnya meminta keterangan yang diperlukan mengenai hal tersebut kepada Terdakwa atau Saksi."}, {"l": "UU 20/2025", "p": "217", "b": "Bagian Ketiga", "t": "(l) Setelah Saksi memberi keterangan, Saksi diharuskan tetap hadir di sidang, kecuali Hakim ketua sidang memberi izin untuk meninggalkannya. (21 Izin sebagaimana dimaksud pada ayat (1) tidak diberikan, jika Penuntut Umum, Terdakwa, atau Advokat mengajukan permintaan agar Saksi tersebut tetap menghadiri sidang. (3) Para Saksi selama sidang berlangsung dilarang saling bercakap-cakap."}, {"l": "UU 20/2025", "p": "218", "b": "Bagian Ketiga", "t": "Saksi tidak dapat didengar keterangannya dan dapat mengundurkan diri sebagai Saksi, kecuali ditentukan lain dalam Undang-Undang ini, dalam hal: a. mempunyai hubungan keluarga sedarah atau semenda dalam garis lurus ke atas atau ke bawah sampai derajat ketiga dari Terdakwa; b. bersama-sama sebagai Tersangka atau Terdakwa walaupun perkaranya dipisah; c. mempunyai hubungan saudara dari Terdakwa atau saudara ibu atau saudara bapak, juga mereka yang mempunyai hubungan karena perkawinan dan anak- anak saudara Terdakwa sampai dera-iat ketiga; dan/atau d. berstatus sebagai suami atau istri Terdakwa atau pernah sebagai suami atau istri Terdakwa. Pasal 219. . . R,EPUBUK INDONESIA"}, {"l": "UU 20/2025", "p": "219", "b": "Bagian Ketiga", "t": "(1) Dalam hal Salsi menghendakinya dan penuntut Umum serta Terdakwa secara tegas menyetqiuinya, Saksi dapat memberi keterangan di bawah sumpah atau janji. (21 Dalam hal persetujuan sebagaimana dimaksud pada ayat (1) tidak dikehendaki, Saksi dapat memberikan keterangan tanpa sumpah atau janji."}, {"l": "UU 20/2025", "p": "220", "b": "Bagian Ketiga", "t": "(1) Orang yang karena harkat martabat, pekerjaan, atau jabatannya diwajibkan menyimpan rahasia dapat meminta dibebaskan dari kewajiban untuk memberi keterangan sebagai Saksi mengenai hal yang dipercayakan kepada mereka. (21 Hakim menentukan sah atau tidaknya segala alasan permintaan sebagaimana dimaksud pada ayat (1)."}, {"l": "UU 20/2025", "p": "221", "b": "Bagian Ketiga", "t": "Seseorang yang dapat diminta memberikan keterangan tanpa sumpah atau janji adalah: a. anak yang belum berumur 14 (empat belas) tahun; atau b. Penyandang Disabilitas mental dan/atau disabilitas intelektual. PasaT 222 (l) Setelah Saksi memberi keterangan, Terdakwa atau Advokatnya dapat mengajukan permintaan kepada Hakim ketua sidang agar di antara Saksi tersebut yang tidak dikehendaki kehadirannya dikeluarkan dari ruang sidang, dan Saksi yang lain dipanggil masuk oleh Hakim ketua sidang untuk didengar keterangannya, baik seorang demi seorang maupun bersama-sama tanpa hadirnya Saksi yang dikeluarkan tersebut. (2) Dalam . . . REFUEUK INDONESIA (21 Dalam hal dipandang perlu, Hakim karena jabatannya dapat meminta agar Saksi yang telah didengar keterangannya keluar dari ruang sidang untuk selanjutnya mendengar Keterangan Saksi yang lain."}, {"l": "UU 20/2025", "p": "223", "b": "Bagian Ketiga", "t": "(l) Hakim ketua sidang dapat mendengar Keterangan Saksi mengenai hal tertentu tanpa hadirnya Terdakwa. (21 Dalam hal Hakim mendengar Keterangan Saksi sebagaimana dimaksud pada ayat (l), Hakim meminta Terdakwa keluar ruang sidang dan pemeriksaan perkara tidak boleh diteruskan sebelum kepada Terdakwa diberitahukan semua hal pada waktu Terdakwa tidak hadir."}, {"l": "UU 20/2025", "p": "224", "b": "Bagian Ketiga", "t": "(1) Dalam hal Keterangan Saksi di sidang diduga palsu, Hakim ketua sidang memperingatkan dengan sungguh-sungguh kepada Saksi agar memberikan keterangan yang sebenar-benarnya dan mengemukakan ancaman pidana yang dapat dikenakan kepada Saksi apabila tetap memberikan keterangan palsu. (21 Dalam hal Saksi tetap memberikan keterangan yang diduga palsu, Hakim ketua sidang karena jabatannya atau atas permintaan Penuntut Umum atau Terdakwa dapat memberi perintah agar Saksi ditahan dan dituntut dengan dakwaan sumpah palsu. (3) Panitera dalam waktu paling lambat 2 (dua) Hari membuat berita acara pemeriksaan sidang yang memuat Keterangan Saksi dengan menyebutkan alasan persangkaan bahwa Keterangan Saksi tersebut palsu dan berita acara tersebut ditandatangani oleh Hakim ketua sidang serta panitera dan segera diserahkan kepada Penuntut Umum untuk diselesaikan sesuai ketentuan dalam Undang-Undang ini. (4) Dalam hal diperlukan, Hakim ketua sidang menangguhkan sidang dalam perkara semula sampai pemeriksaan perkara pidana terhadap dugaan keterangan palsu sebagaimana dimaksud pada ayat (1) selesai. Pasal 225... -t20-"}, {"l": "UU 20/2025", "p": "225", "b": "Bagian Ketiga", "t": "Dalam hal Terdakwa tidak menjawab atau menolak untuk menjawab pertanyaan yang diajukan kepadanya, Hakim ketua sidang menganjurkan untuk menjawab dan setelah itu pemeriksaan dilanjutkan."}, {"l": "UU 20/2025", "p": "226", "b": "Bagian Ketiga", "t": "(1) Dalam hal Terdakwa bertingkah laku yang tidak patut sehingga mengganggu ketertiban sidang, Hakim ketua sidang berwenang menegur Terdakwa dan meminta untuk bertingkah laku tertib dan patut. (2) Dalam hal teguran sebagaimana dimaksud pada ayat (1) tidak ditaati atau Terdakwa secara terus menerus bertingkah laku tidak patut, Hakim memerintahkan agar Terdakwa dikeluarkan dari ruang sidang dan pemeriksaan perkara tersebut dilanjutkan tanpa hadirnya Terdakwa. (3) Dalam hal tindakan Terdakwa sebagaimana dimaksud pada ayat (2) tetap dilakukan, Hakim ketua sidang mengusahakan upaya sedemikian rupa sehingga putusan tetap dapat dijatuhkan dengan tanpa hadirnya Terdakwa."}, {"l": "UU 20/2025", "p": "227", "b": "Bagian Ketiga", "t": "(l) Dalam hal Terdakwa atau Saksi tidak memahami atau tidak bisa berbahasa Indonesia, Hakim ketua sidang menunjuk seorang Penerjemah yang bersumpah atau berjanji akan menerjemahkan dengan benar semua yang harus diterjemahkan. (2) Dalam hal seseorang tidak diperbolehkan menjadi Saksi dalam suatu perkara, yang bersangkutan dilarang menjadi Penerjemah dalam perkara itu."}, {"l": "UU 20/2025", "p": "228", "b": "Bagian Ketiga", "t": "(l) Dalam hal Terdakwa atau Saksi disabilitas dan/ atau tidak dapat menulis, Hakim ketua sidang mengangkat pendamping disabilitas atau petugas lain yang terkait dengan ragam disabilitas Terdakwa atau Saksi tersebut sebagai juru bahasa. (2) Dalam . . . -t2t- (21 Dalam hal Terdakwa atau Saksi bisu atau tuli tetapi dapat menulis, Hakim ketua sidang menyampaikan semua pertanyaan atau teguran secara tertulis kepada Terdakwa atau Saksi tersebut untuk diperintahkan menulis jawabannya dan selanjutnya semua pertanyaan serta jawaban harus dibacakan."}, {"l": "UU 20/2025", "p": "229", "b": "Bagian Ketiga", "t": "(1) Setiap orang yang diminta pendapatnya sebagai Ahli kedokteran kehakiman, dokter, atau Ahli lainnya wajib memberikan Keterangan Ahli demi keadilan. (21 Semua ketentuan mengenai Saksi berlaku juga bagi Ahli yang memberikan keterangan, dengan ketentuan bahwa Ahli yang mengucapkan sumpah atau janji tersebut akan memberikan keterangan yang sebenar- benarnya dan sejujur-jujurnya menurut pengetahuan dalam bidang keahliannya."}, {"l": "UU 20/2025", "p": "230", "b": "Bagian Ketiga", "t": "(1) Dalam hal diperlukan untuk menjernihkan duduk persoalan yang timbul di sidang pengadilan, Hakim ketua sidang dapat meminta Keterangan Ahli dan dapat pula meminta agar diajukan bahan baru oleh yang berkepentingan. (21 Dalam hal timbul perlawanan yang beralasan dari Terdakwa atau Advokatnya terhadap hasil Keterangan Ahli sebagaimana dimaksud pada ayat (1), Hakim memerintahkan agar hal tersebut dilakukan penelitian ulang, termasuk penelitian ulang atas Keterangan Ahli tersebut. (3) Penelitian ulang sebagaimana dimaksud pada ayat (2) dilakukan oleh instansi semula dengan komposisi personal yang berbeda dan instansi lain yang mempunyai wewenang untuk itu. Pasal 231 ... PNESIDEN REPUEUK INDONESIA -L22-"}, {"l": "UU 20/2025", "p": "231", "b": "Bagian Ketiga", "t": "(1) Setelah kesaksian dan bukti disampaikan oleh kedua belah pihak, Penuntut Umum dan Advokat diberi kesempatan untuk menyampaikan keterangan lisan yang menjelaskan mengenai bukti yang diajukan di persidangan mendukung pendapat mereka mengenai perkara tersebut. (21 Dalam hal pemeriksaan dinyatakan selesai, Penuntut Umum mengajukan tuntutan pidana kepada Terdakwa setelah menguraikan hal yang memberatkan dan meringankan Terdakwa. (3) Setelah Penuntut Umum mengajukan tuntutan pidana, Terdakwa dan/ atau Advokat mengajukan pembelaannya yang dapat dijawab oleh Penuntut Umum dengan ketentuan bahwa Terdakwa atau Advokatnya selalu mendapat giliran terakhir. (4) Tuntutan atau jawaban atas pembelaan dilakukan secara tertulis dan setelah dibacakan dalam waktu paling lambat I (satu) Hari diserahkan kepada Hakim ketua sidang dan salinannya kepada pihak yang berkepentingan. (5) Jika ketentuan sebagaimana dimaksud pada ayat (1) sampai dengan ayat (3) selesai dilaksanakan, Hakim ketua sidang menyatakan bahwa pemeriksaan dinyatakan ditutup."}, {"l": "UU 20/2025", "p": "232", "b": "Bagian Ketiga", "t": "(1) Dalam hal tertentu, baik atas kewenangan Hakim ketua sidang karena jabatannya maupun atas permintaan Penuntut Umum atau Terdakwa atau Advokatnya dengan memberikan alasan yang dapat diterima, sidang sebagaimana dimaksud dalam Pasal 231 ayat (5) dapat dibuka kembali. (21 Setelah ketentuan sebagaimana dimaksud pada ayat (1) dilakukan, Hakim mengadakan musyawarah terakhir untuk mengambil keputusan dan apabila perlu musyawarah tersebut diadakan setelah Terdakwa, Saksi, Advokat, Penuntut Umum, dan hadirin meninggalkan ruang sidang. (3) Musyawarah . . . REFUBU( INDONESIA (3) Musyawarah sebagaimana dimaksud pada ayat (2) harus didasarkan atas surat dakwaan dan segala sesuatu yang terbukti dalam pemeriksaan di sidang pengadilan. (41 Dalam musyawarah sebagaimana dimaksud pada ayat (3), Hakim ketua majelis mengajukan pertanyaan kepada setiap Hakim anggota dan setelah itu ketua majelis Hakim mengemukakan pendapatnya. (5) Pendapat sebagaimana dimaksud pada ayat (4) harus disertai dengan pertimbangan beserta alasannya."}, {"l": "UU 20/2025", "p": "233", "b": "Bagian Ketiga", "t": "(l) Putusan dalam musyawarah majelis merupakan hasil permufakatan bulat. (21 Dalam hal permufakatan sebagaimana dimaksud pada ayat (1) tidak dapat dicapai setelah diusahakan dengan sungguh-sungguh, putusan diambil dengan suara terbanyak. (3) Dalam hal ketentuan sebagaimana dimaksud pada ayat (21 tidak juga dapat dipenuhi, putusan diambil berdasarkan pendapat Hakim yang paling menguntungkan bagi Terdakwa. (41 Pelaksanaan pengambilan putusan sebagaimana dimaksud pada ayat (3) dicatat dalam buku himpunan putusan yang sifatnya rahasia yang disediakan khusus untuk keperluan tersebut. (5) Putusan Pengadilan negeri dapat dijatuhkan dan diumumkan pada hari itu juga. (6) Dalam hal putusan dijatuhkan dan diumumkan pada hari lain, putusan tersebut sebelumnya harus diberitahukan kepada Penuntut Umum, Terdakwa, atau Advokat."}, {"l": "UU 20/2025", "p": "234", "b": "Bagian Ketiga", "t": "(1) Pada saat Penuntut Umum membacakan surat dakwaan, Terdakwa mengakui semua perbuatan yang didakwakan dan mengaku bersalah melakukan tindak pidana yang anc:rman pidana yang didakwakan tidak lebih dari 7 (tujuh) tahun, Penuntut Umum dapat melimpahkan perkara ke sidang acara pemeriksaan singkat. (2) Pengakuan . . . REPUELIK INDONESIA -t24- l2l Pengaluan Terdakwa dituangkan dalam berita acara yang ditandatangani oleh Terdakwa dan Penuntut Umum. (3) Hakim wajib: a. memberitahukan kepada Terdakwa mengenai hak yang dilepaskannya dengan memberikan pengakuan sebagaimana dimaksud pada ayat (21; b. memberitahukan kepada Terdakwa mengenai lamanya pidana yang kemungkinan dikenakan; dan c. menanyakan apalah pengakuan sebagaimana dimaksud pada ayat (2) diberikan secara sukarela. (41 Hakim dapat menolak pengakuan sebagaimana dimaksud pada ayat (2) jika Hakim ragu terhadap kebenaran pengakuan Terdakwa. (5) Penjatuhan pidana terhadap Terdakwa sebagaimana dimaksud pada ayat (1) tidak boleh melebihi 2/3 (dua per tiga) dari maksimum pidana tindak pidana yang didakwakan. (6) Hakim atas kehendaknya sendiri atau atas permintaan Terdakwa atau Advokatnya dapat memberi penjelasan mengenai ketentuan …"}, {"l": "UU 20/2025", "p": "235", "b": "Bagian Keempat", "t": "(1) Alat bukti terdiri atas: a. Keterangan Saksi; b. Keterangan Ahli; c. surat; d. keterangan Terdakwa; e. barang bukti; f. bukti elektronik; g. pengamatan Hakim; dan h. segala sesuatu yang dapat digunakan untuk kepentingan pembuktian pada pemeriksaan di sidang pengadilan sepanjang diperoleh secara tidak melawan hukum. (2) Hal. . . tf,Trrr:ilrilTilililrt+ra -L25- (21 Hal yang secara umum sudah diketahui tidak perlu dibuktikan. (3) Alat bukti sebagaimana dimaksud pada ayat (1) harus dapat dibuktikan autentikasinya dan diperoleh secara tidak melawan hukum. (4) Hakim berwenang menilai autentikasi dan sah atau tidaknya perolehan alat bukti yang diajukan. (5) Alat bukti yang oleh Hakim dinyatakan tidak autentik dan/atau diperoleh secara melawan hukum tidak dapat digunakan sebagai alat bukti pada pemeriksaan di sidang pengadilan dan tidak memiliki kekuatan pembuktian."}, {"l": "UU 20/2025", "p": "236", "b": "Bagian Keempat", "t": "(1) Keterangan Salsi sebagaimana dimaksud dalam Pasal 235 ayat (1) huruf a disampaikan secara langsung di sidang pengadilan. (21 Dalam hal Keterangan Salsi tidak dapat disampaikan secara langsung di sidang pengadilan, Keterangan Saksi dapat disampaikan melalui alat komunikasi audio visual. (3) Dalam hal Saksi dan/ atau Korban merupakan Penyandang Disabilitas, Keterangan Saksi dan/atau Korban yang diberikan mempunyai kekuatan hukum yang sama dengan Keterangan Saksi dan/atau Korban yang bukan Penyandang Disabilitas. (41 Ketentuan lebih lanjut mengenai persyaratan dan tata cara penyzrmpaian Keterangan Saksi melalui alat komunikasi audiovisual sebagaimana dimaksud pada ayat (21 diatur dalam Peraturan Pemerintah."}, {"l": "UU 20/2025", "p": "237", "b": "Bagian Keempat", "t": "(l) Keterangan I (satu) orang Saksi tidak cukup untuk membuktikan bahwa Terdakwa bersalah terhadap perbuatan yang didakwakan kepadanya. (21 Ketentuan sebagaimana dimaksud pada ayat (1) tidak berlaku jika keterangan seorang Saksi diperkuat dengan alat bukti lain. (3) Keterangan . . . REPTJELIK INDONESIA (3) Keterangan beberapa Saksi mengenai suatu kejadian atau keadaan dapat digunakan sebagai alat bukti dalam hal keterangan beberapa Saksi tersebut saling berhubungan satu sama lain sehingga dapat membenarkan adanya suatu kejadian atau keadaan tertentu. (4) Pendapat atau rekaan yang diperoleh dari hasil pemikiran belaka bukan merupakan Keterangan Saksi. (5) Dalam menilai kebenaran Keterangan Saksi, Hakim wajib memperhatikan: a. kesesuaian antara Keterangan Saksi satu dengan yang lain; b. kesesuaian antara Keterangan Saksi dengan alat bukti yang lain; c. alasan yang mungkin dipergunakan oleh Saksi untuk memberi keterangan tertentu; d. cara hidup dan kesusilaan Saksi serta segala sesuatu yang pada umumnya dapat mempengaruhi dipercayanya keterangan tersebut; dan/atau e. konsistensi keterangan dari Saksi sebelum dan Keterangan Saksi pada waktu sidang. (6) Keterangan Saksi yang tidak …"}, {"l": "UU 20/2025", "p": "238", "b": "Bagian Keempat", "t": "(1) Keterangan Ahli sebagaimana dimaksud dalam Pasal 235 ayat (1) huruf b disampaikan secara langsung di sidang pengadilan di bawah sumpah atau janji mengenai apa yang diketahui sesuai dengan keahliannya. (21 Dalam memberikan keterangan di depan sidang pengadilan Ahli tidak wajib menyampaikan surat tugas atau izin dari institusi atau lembaga dimana Ahli bekerja. (3) Ketentuan. . . ilITiEIEtrN ]IEPUBUK INDONESIA (3) Ketentuan sebagaimana dimaksud pada ayat (21 dikecualikan terhadap Ahli yang sebelum memberikan keterangan di depan sidang pengadilan perlu melakukan pemeriksaan, penelitian, atau pengamatan terlebih dahulu terkait perkara tersebut."}, {"l": "UU 20/2025", "p": "239", "b": "Bagian Keempat", "t": "Surat sebagaimana dimaksud dalam Pasal 235 ayat (1) huruf c, dibuat berdasarkan sumpah jabatan atau dikuatkan dengan sumpah, yakni: a. berita acara dan surat lain dalam bentuk resmi yang dibuat oleh pejabat umum yang berwenang atau yang dibuat di hadapannya, yang memuat keterangan mengenai kejadian atau keadaan yang didengar, dilihat, atau dialami sendiri disertai dengan alasan yang tegas dan jelas mengenai keterangannya; b. surat yang dibuat menurut ketentuan peraturan perundang-undangan atau surat yang dibuat oleh pejabat mengenai hal yang termasuk dalam ketatalaksanaan yang menjadi tanggung jawabnya dan yang diperuntukkan bagi pembuktian suatu hal atau suatu keadaan; c. surat Keterangan Ahli yang memuat pendapat berdasarkan keahliannya mengenai suatu hal atau suatu keadaan yang diminta secara resmi darinya; dan d. surat lain yang hanya dapat berlaku, jika ada hubungannya dengan isi dari alat pembuktian yang lain."}, {"l": "UU 20/2025", "p": "240", "b": "Bagian Keempat", "t": "(1) Keterangan Terdakwa sebagaimana dimaksud dalam Pasal 235 ayat (l) huruf d merupakan segala hal yang dinyatakan oleh Terdakwa dalam pemeriksaan di sidang pengadilan mengenai perbuatan yang dilakukan atau diketahui sendiri atau dialami sendiri. (21 Keterangan Terdakwa yang diberikan di luar pemeriksaan di sidang pengadilan dapat digunakan untuk membantu menemukan bukti dalam pemeriksaan di sidang pengadilan, dengan ketentuan ba-hwa keterangan tersebut didukung oleh suatu alat bukti yang sah sepanjang mengenai hal yang didakwakan kepadanya. (3) Keterangan . . . PTIESIDEN REPUBUK INDONESIA -l2a- (3) Keterangan Terdakwa hanya dapat digunakan terhadap dirinya sendiri. (41 Keterangan Terdakwa saja tidak cukup untuk membuktikan bahwa Terdakwa bersalah melalukan perbuatan yang didakwakan kepadanya, melainkan harus disertai dengan alat bukti yang sah lainnya."}, {"l": "UU 20/2025", "p": "241", "b": "Bagian Keempat", "t": "Barang bukti sebagaimana dimaksud dalam pasal 235 ayat (l) huruf e mencakup: a. alat atau sarana untuk melakukan tindak pidana; b. alat atau sarana yang menjadi objek tindak pidana; dan/ atau c. aset yang merupakan hasil tindak pidana."}, {"l": "UU 20/2025", "p": "242", "b": "Bagian Keempat", "t": "Bukti elektronik sebagaimana dimaksud dalam pasal 235 ayat (1) huruf f mencakup segala bentuk Informasi Elektronik, Dokumen Elektronik, dan/atau sistem elektronik yang berkaitan dengan tindak pidana."}, {"l": "UU 20/2025", "p": "243", "b": "Bagian Kelima", "t": "(1) Selama pemeriksaan di sidang pengadilan, jika Terdakwa tidak ditahan, pengadilan dapat memerintahkan dengan surat penetapan untuk menahan Terdakwa jika dipenuhi ketentuan sebagaimana dimaksud dalam Pasal 100 dan terdapat alasan yang cukup untuk itu. (21 Dalam hal Terdakwa ditahan, pengadilan dapat memerintahkan dengan surat penetapan untuk menangguhkan Penahanan Terdakwa, jika terdapat alasan yang cukup untuk itu sesuai dengan ketentuan sebagaimana dimaksud dalam Pasal 110 ayat (1). Pasal 244 .. . REPUBUK INDONESIA"}, {"l": "UU 20/2025", "p": "244", "b": "Bagian Kelima", "t": "(l) Dalam hal Hakim berpendapat bahwa hasil pemeriksaan di sidang pengadilan, tindak pidana yang didakwakan terbukti secara sah dan meyalinkan, Terdakwa dikenai sanksi berupa pidana atau tindakan. l2l Dalam hal Hakim berpendapat bahwa hasil pemeriksaan di sidang pengadilan, tindak pidana yang didakwakan tidak terbukti secara sah dan meyakinkan, Terdakwa diputus bebas. (3) Dalam hal Hakim berpendapat bahwa perbuatan yang didakwakan kepada Terdakwa terbukti, tetapi ada dasar peniadaan pidana, Terdakwa diputus lepas dari segala tuntutan hukum. (41 Dalam hal Terdakwa diputus bebas sebagaimana dimaksud pada ayat (2), Terdakwa yang ada dalam tahanan dilepaskan dari tahanan sejak putusan diucapkan. (5) Dalam hal Terdakwa diputus lepas dari segala tuntutan hukum sebagaimana dimaksud pada ayat (3) dan Penuntut Umum tidak melakukan upaya banding, Terdakwa yang ada dalam tahanan dilepaskan dari tahanan sejak putusan diucapkan. (6) Dalam hal Terdakwa dipidana sebagaimana dimaksud pada ayat (1), Hakim dapat memerintahkan Terdakwa ditahan jika memenuhi syarat Penahanan sebagaimana dimaksud dalam Pasal 1O0 ayat (5)."}, {"l": "UU 20/2025", "p": "245", "b": "Bagian Kelima", "t": "(l) Perintah untuk melepaskan Terdakwa dari tahanan sebagaimana dimaksud dalam Pasal 244 ayat (4) dan ayat (5) dilaksanakan oleh Penuntut Umum dalam waktu paling lama 1 (satu) Hari setelah putusan diucapkan. (2) Dalam waktu paling lama 3 (tiga) Hari setelah putusan diucapkan, Penuntut Umum harus membuat dan laporan tertulis kepada ketua pengadilan yang bersangkutan mengenai pelaksanaan perintah tersebut dengan melampirkan surat pelepasan. Pasal 246. . ."}, {"l": "UU 20/2025", "p": "246", "b": "Bagian Kelima", "t": "(l) Hakim dapat menjatuhkan putusan yang menyatakan Terdakwa terbukti bersalah, namun tidak menjatuhkan pidana atau tindakan, dengan mempertimbangkan: a. ringannya perbuatan; b. keadaan pribadi pelaku; dan/atau c. keadaan pada saat dan setelah terjadinya tindak pidana. (21 Putusan sebagaimana dimaksud pada ayat (l) dikategorikan sebagai jenis putusan tersendiri, yaitu Putusan Pemaafan Hakim. (3) Terhadap putusan sebagaimana dimaksud pada ayat (l), para pihak dapat mengajukan Upaya Hukum sesuai ketentuan dalam Undang-Undang ini. (41 Ketentuan lebih lanjut mengenai bentuk, format, dan syarat Putusan Pemaafan Hakim diatur dalam Peraturan Mahkamah Agung."}, {"l": "UU 20/2025", "p": "247", "b": "Bagian Kelima", "t": "(1) Dalam hal putusan berupa Putusan Pemaafan Hakim, pemidanaan bebas atau lepas dari segala tuntutan hukum, pengadilan menetapkan supaya barang bukti yang disita diserahkan kepada pihak yang paling berhak menerima kembali yang namanya tercantum dalam putusan tersebut, kecuali jika menurut ketentuan peraturan perundang-undangan barang bukti tersebut harus dirampas untuk kepentingan negara atau dimusnahkan atau dirusak sehingga tidak dapat dipergunakan lagi. (21 Dalam hal barang bukti yang disita diserahkan kepada pihak yang paling berhak, pengadilan menetapkan supaya barang bukti diserahkan segera sesudah sidang selesai. (3) Perintah penyerahan barang bukti dilakukan tanpa disertai suatu syarat apapun, kecuali dalam hal Putusan Pengadilan belum mempunyai kekuatan hukum tetap. Pasal 248... REFUBUK INDONESIA"}, {"l": "UU 20/2025", "p": "248", "b": "Bagian Kelima", "t": "Semua Putusan Pengadilan hanya sah dan mempunyai kekuatan hukum jika diucapkan dalam sidang terbuka untuk umum."}, {"l": "UU 20/2025", "p": "249", "b": "Bagian Kelima", "t": "(1) Pengadilan memutus perkara dengan hadirnya Terdakwa, kecuali Undang-Undang menentukan lain. (2) Dalam hal terdapat lebih dari seorang Terdakwa dalam satu perkara, putusan dapat diucapkan dengan hadirnya Terdakwa yang ada. (3) Segera sesudah putusan pemidanaan diucapkan, Hakim ketua sidang wajib memberitahukan kepada Terdakwa yang menjadi haknya, yaitu: a. hak segera menerima atau segera menolak putusan; b. hak mempelajari putusan sebelum menyatakan menerima atau menolak putusan dalam jangka waktu yang ditentukan oleh Undang-Undang ini; c. hak untuk dapat mengajukan grasi, dalam hal Terdakwa menerima putusan; d. hak meminta diperiksa perkaranya di tingkat banding dalam jangka waktu yang ditentukan oleh Undang-Undang ini, dalam hal Terdakwa menolak putusan; dan e. hak untuk mencabut pernyataan sebageimana dimaksud dalam huruf a dalam jangka waktu yang ditentukan oleh Undang-Undang ini."}, {"l": "UU 20/2025", "p": "250", "b": "Bagian Kelima", "t": "(l) Putusan pemidanaan di pengadilan tingkat pertama memuat: a. kepala putusan yang dituliskan berbunyi: \"DEMI KEADILAN BERDASARKAN KETUHANAN YANG MAHA ESA\"; b. nama lengkap, tempat lahir, umur atau tanggal, jenis kelamin, kebangsaan, tempat tinggal, agama, dan pekerjaan Terdakwa; c. dakwaan . . . REPUBUK INDONESIA -t32- c. dakwaan sebagaimana terdapat dalam surat dakwaan; d. pertimbangan yang disusun secara jelas dan lengkap mengenai fakta dan keadaan beserta alat pembuktian yang diperoleh dari pemeriksaan di sidang pengadilan yang menjadi dasar penentuan kesalahan Terdakwa; e. tuntutan pidana sebagaimana terdapat dalam surat tuntutan; f. pasal peraturan perundang-undangan yang menjadi dasar pemidanaan dan pasal peraturan perundang-undangan yang menjadi dasar hukum dari putusan, disertai keadaan yang memberatkan dan yang meringankan Terdakwa; g. hari dan tanggal diadakannya musyawarah majelis Hakim, kecuali perkara diperiksa oleh Hakim tunggal; h. pernyataan kesalahan Terdakwa, pernyataan telah terpenuhi semua unsur dalam rumusan tindak pidana disertai dengan kualifikasinya dan pidana dan/atau tindakan yang dijatuhkan; i. ketentuan kepada siapa biaya perkara dibebankan dengan …"}, {"l": "UU 20/2025", "p": "251", "b": "Bagian Kelima", "t": "(1) Hakim wajib mempertimbangkan pedoman pemidanaan sebagaimana tercantum dalam Kitab Undang-Undang Hukum Pidana dan Undang-Undang lain dalam setiap putusan pemidanaan. (21 Format Putusan Pengadilan harus mencantumkan bagian khusus yang menjelaskan pertimbangan Hakim terhadap pedoman pemidanaan. (3) Mahkamah Agung menyusun dan memutakhirkan format baku putusan yang memuat bagian sebagaimana dimaksud pada ayat (2)."}, {"l": "UU 20/2025", "p": "252", "b": "Bagian Kelima", "t": "(1) Apabila Hakim atau Penuntut Umum berhalangan, ketua pengadilan atau pejabat kejaksaan yang berwenang wajib menunjuk pengganti pejabat yang berhalangan tersebut dalam wal,rhr paling lama 1 (sahr) Hari. l2l Dalam hal Advokat berhalangan, Terdakwa atau asosiasi Advokat menunjuk penggantinya. (3) Dalam hal pengganti sebagaimana dimaksud pada ayat (21ternyata tidak ada atau juga berhalangan maka sidang dapat dilanjutkan."}, {"l": "UU 20/2025", "p": "253", "b": "Bagian Kelima", "t": "(1) Putusan yang bukan merupakan pemidanaan memuat: a. ketentuan sebagaimana dimaksud dalam Pasal 250 ayat (1) kecuali huruf e, huruf f, dan huruf h; b. pernyataan bahwa Terdakwa diputus bebas atau lepas dari segala tuntutan hukum, dengan menyebutkan alasan dan pasal peraturan perundang-undangan yang menjadi dasar putusan; dan c. perintah supaya Terdakwa yang ditahan dibebaskan sejak putusan diucapkan. (21 Ketentuan sebagaimana dimaksud dalam Pasal 250 ayat (21 dan ayat (3) berlaku juga terhadap pasal ini. Pasal 254... REFUBLIK INDONESIA"}, {"l": "UU 20/2025", "p": "254", "b": "Bagian Kelima", "t": "Petikan putusan ditandatangani oleh Hakim dan panitera segera setelah putusEm diucapkan."}, {"l": "UU 20/2025", "p": "255", "b": "Bagian Kelima", "t": "(1) Dalam hal terdapat surat palsu atau dipalsukan, panitera melekatkan petikan putusan yang ditandatanganinya pada surat tersebut yang memuat keterangan sebagaimana dimaksud dalam Pasal 250 ayat (1) hurufj dan surat palsu atau yang dipalsukan tersebut diberi catatan dengan menunjuk pada petikan putusan tersebut. (21 Salinan pertama dari surat palsu atau yang dipalsukan tidak diberikan, kecuali panitera sudah membubuhi catatan pada catatan sebagaimana dimaksud pada ayat (1) disertai dengan salinan petikan putusan."}, {"l": "UU 20/2025", "p": "256", "b": "Bagian Kelima", "t": "(1) Panitera membuat berita acara sidang dengan memperhatikan persyaratan yang diperlukan dan memuat segala kejadian di sidang yang berhubungan dengan pemeriksaan. (21 Berita acara sidang sebagaimana dimaksud pada ayat (1) memuat juga hal yang penting dari Keterangan Saksi, Terdakwa, dan Ahli, kecuali jika Hakim ketua sidang menyatakan cukup menunjuk keterangan dalam berita acara pemeriksaan dengan menyebut perbedaan yang terdapat antara yang satu dengan yang lain. (3) Atas permintaan Penuntut Umum, Terdakwa, atau Advokat, Hakim ketua sidang wajib memerintahkan kepada panitera supaya dibuat catatan sec€rra khusus mengenai suatu keadaan atau keterangan. (4) Berita acara sidang ditandatangani oleh Hakim ketua sidang dan panitera, kecualijika salah satu dari Hakim ketua sidang dan panitera berhalangan, hal tersebut dinyatakan dalam berita acara."}, {"l": "UU 20/2025", "p": "257", "b": "Bagian Keenam", "t": "(1) Perkara yang diperiksa menurut acara pemeriksaan singkat merupakan perkara yang menurLlt Penuntut Umum pembuktian serta penerapan hukumnya mudah dan sifatnya sederhana. (21 Dalam pemeriksaan perkara sebagaimana dimaksud pada ayat (1), Penuntut Umum menghadapkan Terdakwa beserta Saksi, barang bukti, Ahli, dan juru bahasa jika diperlukan. (3) Dalam acara pemeriksaan singkat berlaku ketentuan: a. Penuntut Umum dengan segera setelah Terdakwa di sidang menjawab segala pertanyaan sebagaimana dimaksud dalam Pasal 2O4 ayat (l) memberitahukan dengan lisan dari catatannya kepada Terdakwa mengenai tindak pidana yang didakwakan kepadanya dengan menerangkan waktu, tempat, dan keadaan pada waktu tindak pidana dilakukan, yang dicatat dalam berita acara sidang dan merupakan pengganti surat dakwaan; b. dalam hal Hakim memandang perlu pemeriksaan tambahan maka diadakan pemeriksaan tambahan dalam jangka waktu paling lama 14 (empat belas) Hari dan apabila dalam jangka waktu tersebut Penuntut Umum belum juga dapat menyelesaikan pemeriksaan tambahan, Hakim memerintahkan perkara tersebut diajukan ke sidang pengadilan dengan acara pemeriksaan biasa; c. guna kepentingan pembelaan, atas permintaan …"}, {"l": "UU 20/2025", "p": "258", "b": "Bagian Ketujuh", "t": "(l ) Pemeriksaan terhadap tindak pidana ringan sebagaimana dimaksud dalam Kitab Undang-Undang Hukum Pidana dilakukan melalui acara pemeriksaan cepat. (21 Perkara yang diperiksa menurut acara pemeriksaan cepat sebagaimana dimaksud pada ayat (1) merupakan perkara yang diancam dengan pidana penjara paling lama 6 (enam) bulan dan/atau pidana denda paling banyak kategori II. (3) Dalam perkara sebagaimana dimaksud pada ayat (21, Penyidik atas kuasa Penuntut Umum dalam jangka waktu 3 (tiga) Hari sejak berita acara pemeriksaan cepat selesai dibuat, menghadapkan Terdakwa beserta barang bukti, Saksi, Ahli, Penerjemah, atau juru bahasa ke sidang pengadilan. (41 Dalam acara pemeriksaan cepat sebagaimana dimaksud pada ayat (1), pengadilan Mengadili dengan Hakim tunggal pada tingkat pertama dan terakhir. (5) Dalam hal dijatuhkan pidana perampasan kemerdekaan, Terdakwa dapat meminta banding."}, {"l": "UU 20/2025", "p": "259", "b": "Bagian Ketujuh", "t": "Pengadilan menetapkan hari tertentu dalam jangka waktu paling lama 7 (tujuh) Hari untuk Mengadili perkara dengan acara pemeriksaan cepat. Pasal 26O... ilitiEItrtrN REPUBUK INDONESIA -r37-"}, {"l": "UU 20/2025", "p": "260", "b": "Bagian Ketujuh", "t": "(1) Penyidik memberitahukan secara tertulis kepada Terdakwa mengenai hari, tanggal, jam, dan tempat Terdakwa harus menghadap sidang pengadilan dan hal tersebut dicatat dengan baik oleh Penyidik yang selanjutnya catatan dan bersama berkas dikirim ke pengadilan. (21 Perkara dengan acara pemeriksaan cepat yang diterima oleh pengadilan harus segera disidangkan pada hari sidang itu juga. (3) Hakim yang bersangkutan memerintahkan panitera mencatat dalam buku register semua perkara yang diterimanya. (4) Dalam buku register dimuat nama lengkap, tempat lahir, umur atau tanggal lahir, jenis kelamin, kebangsaan, tempat tinggal, agama, dan pekerjaan Terdakwa serta apa yang didakwakan kepadanya."}, {"l": "UU 20/2025", "p": "261", "b": "Bagian Ketujuh", "t": "Untuk perkara lalu lintas jalan, tidak diperlukan berita acara pemeriksaan, narnun catatan sebagaimana dimaksud dalam Pasal 260 ayat (1) segera diserahkan kepada pengadilan paling lambat pada kesempatan hari sidang pertama berikutnya."}, {"l": "UU 20/2025", "p": "262", "b": "Bagian Ketujuh", "t": "Dalam acara pemeriksaan cepat Saksi tidak wajib mengucapkan sumpah atau janji, kecuali Hakim menganggap perlu."}, {"l": "UU 20/2025", "p": "263", "b": "Bagian Ketujuh", "t": "(1) Putusan dicatat oleh Hakim dalam daftar catatan perkara dan selanjutnya oleh panitera dicatat dalam register serta ditandatangani oleh Hakim yang bersangkutan dan panitera. (2) Berita acara pemeriksaan sidang tidak dibuat, kecuali jika dalam pemeriksaan tersebut ternyata terdapat hal yang tidak sesuai dengan berita acara pemeriksaan yang dibuat oleh Penyidik. PasaJ264... REFUBUK INDONESIA"}, {"l": "UU 20/2025", "p": "264", "b": "Bagian Ketujuh", "t": "Ketentuan dalam Bagian Kesatu, Bagian Kedua, dan Bagian Ketiga Bab XV tetap berlaku sepanjang tidak bertentangan dengan ketentuan sebagaimana dimaksud dalam Bagian Ketujuh Bab XV."}, {"l": "UU 20/2025", "p": "265", "b": "Bagian Ketujuh", "t": "Terdakwa dapat menunjuk seseorang dengan surat untuk mewakilinya dalam pemeriksaan di sidang pengadilan."}, {"l": "UU 20/2025", "p": "266", "b": "Bagian Ketujuh", "t": "(1) Jika Terdakwa atau wakilnya tidak hadir di sidang, pemeriksaan perkara tetap dilanjutkan. (2) Dalam hal putusan diucapkan di luar hadirnya Terdakwa, surat amar putusan paling lama 1 (satu) Hari terhitung sejak tanggal diputuskan disampaikan kepada Terpidana. (3) Bukti bahwa surat amar putusan telah disampaikan oleh penyidik kepada Terpidana, diserahkan kepada panitera untuk dicatat dalam buku register. (4) Dalam hal putusan dijatuhkan di luar hadirnya Terdakwa dan putusan itu berupa pidana perampasan kemerdekaan, Terdakwa dapat mengajukan perlawanan. (5) Dalam waktu paling lama 7 (tujuh) Hari terhitung sejak tanggal putusan diberitahukan secara sah kepada Terdakwa, Terdakwa dapat mengajukan perlawanan kepada pengadilan yang menjatuhkan putusan itu. (6) Dengan perlawanan sebagaimana dimaksud pada ayat (5), putusan di luar hadirnya Terdakwa menjadi gugur. (71 Setelah panitera memberitahukan kepada Penyidik mengenai perlawanan sebagaimana dimaksud pada ayat (5), Hakim menetapkan hari sidang untuk memeriksa kembali perkara tersebut. (8) Jika putusan setelah diajukannya perlawanan tetap berupa pidana sebagaimana dimaksud pada ayat (4), terhadap putusan tersebut Terdakwa tidak dapat …"}, {"l": "UU 20/2025", "p": "267", "b": "Bagian Ketujuh", "t": "Pengembalian benda sitaan dilakukan tanpa syarat kepada yang paling berhak dalam waktu paling lama 1 (satu) Hari terhitung sejak tanggal putusan dijatuhkan, jika Terpidana telah memenuhi isi amar putusan."}, {"l": "UU 20/2025", "p": "268", "b": "Bagian Kedelapan", "t": "(l) Hakim ketua sidang memimpin dan memelihara tata tertib persidangan. (21 Segala sesuatu yang diperintahkan oleh Hakim ketua sidang untuk memelihara tata tertib di persidaagan wajib dilaksanakan dengan segera dan cermat."}, {"l": "UU 20/2025", "p": "269", "b": "Bagian Kedelapan", "t": "(1) Dalam ruang sidang, setiap orang wajib menunjukkan sikap hormat kepada pengadilan dan mematuhi perintah pengadilan yang dikeluarkan untuk kepentingan proses peradilan. (21 Setiap orang yang berada di sidang pengadilan bersikap tidak sesuai dengan martabat pengadilan, menyerang integritas aparat penegak hukum, petugas pengadilan, atau persidangan dalam sidang pengadilan dan tidak menaati tata tertib setelah mendapat peringatan dari Hakim ketua sidang, atas perintah Halim ketua sidang, yang bersangkutan dikeluarkan dari ruang sidang. Pasal2TO (1) Setiap orang dilarang membawa senjata api, senjata tajam, bahan peledak, alat atau benda yang dapat membahayakan keamanan sidang. (2) Tanpa . . . FR,ESIDEN REPUEUK INDONESIA -t40- (21 Tanpa surat perintah, petugas keamanan pengadilan karena tugas jabatannya dapat mengadakan Penggeledahan badan untuk menjamin bahwa kehadiran seseorang di ruang sidang tidak membawa senjata, bahan, alat, atau benda yang dapat membahayakan keamanan sidang. (3) Dalam hal pada seseorang yang digeledah ditemukan membawa senjata api, senjata tajam, bahan peledak, alat, atau benda yang dapat membahayakan keamanan sidang, petugas meminta yang bersangkutan untuk …"}, {"l": "UU 20/2025", "p": "271", "b": "Bagian Kedelapan", "t": "(1) Hakim dilarang Mengadili suatu perkara yang berkaitan dengan kepentingannya, baik langsung maupun tidak langsung. (21 Dalam hal Hakim mempunyai kepentingan dengan perkara sebagaimana dimaksud pada ayat (l), Hakim yang bersangkutan wajib mengundurkan diri baik atas kehendak sendiri maupun atas permintaan: a. Penuntut Umum; atau b. Terdakwa atau Advokatnya. (3) Dalam hal terdapat keraguan atau perbedaan pendapat mengenai kepentingan sebagaimana dimaksud pada ayat (1), ketua pengadilan tinggi yang menetapkan Hakim yang akan Mengadili. (41 Ketentuan sebagaimana dimaksud pada ayat (1) dan ayat l2l berlaku secara mutatis mutandis bagi Penuntut Umum. Pasal 272... PRESTDEN REPUELIK INDONESIA -t4t-"}, {"l": "UU 20/2025", "p": "272", "b": "Bagian Kedelapan", "t": "(1) Dalam hal terdapat alasan yang kuat mengenai objektivitas, kebebasan, dan keberpihakan Hakim atau majelis Hakim yang menyidangkan perkara, Penuntut Umum, Terdakwa, atau Advokat dapat mengajukan permohonan pergantian Hakim atau majelis Hakim yang menyidangkan perkara tersebut. (2) Permohonan pergantian Hakim atau majelis Hakim sebagaimana dimaksud pada ayat (1) diajukan sebelum pemeriksaan perkara pokok kepada ketua pengadilan negeri. (3) Dalam hal ketua pengadilan negeri tidak mengabulkan permohonan pergantian Hakim atau majelis Hakim sebagaimana dimaksud pada ayat (2), permohonan diajukan kepada ketua pengadilan tinggi. (4) Apabila permohonan pergantian Hakim atau majelis Hakim sebagaimana dimaksud pada ayat (1) dikabulkan, dalam waktu paling lama 3 (tiga) Hari ketua pengadilan negeri membuat penetapan mengenai penggantian Hakim atau majelis Hakim. Pasal273 (1) Setiap Terdakwa yang diputus pidana wajib membayar biaya perkara. (21 Dalam hal Terdakwa diputus bebas atau lepas dari segala tuntutan hukum, biaya perkara dibebankan kepada negara. (3) Dalam hal Terdakwa sebelumnya telah mengajukan permohonan pembebasan dari pembayaran biaya perkara berdasarkan syarat tertentu dengan …"}, {"l": "UU 20/2025", "p": "274", "b": "Bagian Kedelapan", "t": "(1) Jika Hakim memberi perintah kepada seseorang untuk mengucapkan sumpah atau janji di luar sidang, Hakim dapat menunda pemeriksaan perkara sampai pada hari sidang yang lain. (2) Dalam . . . REPUBUK INDONESIA -t42- l2l Dalam hal sumpah atau janji dilakukan sebagaimana dimaksud pada ayat (1), Hakim menunjuk panitera untuk menghadiri pengucapan sumpah atau janji dan membuat berita acaranya."}, {"l": "UU 20/2025", "p": "275", "b": "Bagian Kedelapan", "t": "Semua Putusan Pengadilan disimpan dalam arsip oleh pengadilan yang Mengadili perkara pada tingkat pertama dan dilarang dipindahkan, kecuali Undang-Undang menentukan lain."}, {"l": "UU 20/2025", "p": "276", "b": "Bagian Kedelapan", "t": "(1) Panitera membuat dan menyediakan buku daftar untuk semua perkara. (21 Buku daftar sebagaimana dimaksud pada ayat (1) memuat: a. nama dan identitas Terdakwa; b. tindak pidana yang didakwakan; c. tanggal penerimaan perkara; d. tanggal Terdakwa mulai ditahan jika Terdakwa berada dalam tahanan; e. tanggal dan isi putusan secara singkat; f. tanggal penerimaan permintaan dan putusan banding atau kasasi; g. tanggal permohonan serta pemberian grasi, amnesti, abolisi, atau Rehabilitasi; dan h. hal lain yang berkaitan dengan proses perkara."}, {"l": "UU 20/2025", "p": "277", "b": "Bagian Kedelapan", "t": "(l) Petikan Putusan Pengadilan diberikan kepada Terdakwa, Advokat, Penyidik, dan Penuntut Umum, sesaat setelah putusan diucapkan. l2l Salinan Putusan Pengadilan diberikan kepada Penuntut Umum dan Penyidik, sedangkan kepada Terdakwa atau Advokatnya diberikan atas permintaan. (3) Salinan . . . PRESIDEH REPUELIK INDONESIA -r43- (3) Salinan Putusan Pengadilan hanya dapat diberikan kepada orang lain dengan seizin ketua pengadilan setelah mempertimbangkan kepentingan dari permintaan tersebut."}, {"l": "UU 20/2025", "p": "278", "b": "Bagian Kedelapan", "t": "(1) Semua jenis pemberitahuan atau panggilan oleh pihak yang berwenang pada semua tahap pemeriksaan kepada Terdakwa, Saksi, atau Ahli disampaikan paling lambat 3 (tiga) Hari sebelum tanggal kehadiran yang ditentukan, di tempat tinggal atau di tempat kediaman Terdakwa, Saksi, atau Ahli terakhir. (21 Petugas yang melaksanakan panggilan tersebut harus bertemu sendiri dan berbicara langsung dengan orang yang dipanggil dan membuat catatan bahwa panggilan telah diterima oleh yang bersangkutan dengan membubuhkan tanggal dan tanda tangan, baik oleh petugas maupun orang yang dipanggil dan jika yang dipanggil tidak menandatangani maka petugas harus mencatat alasannya. (3) Dalam hal orang yang dipanggil tidak terdapat di salah satu tempat sebagaimana dimaksud pada ayat (1), surat panggilan disampaikan melalui kepala desa/lurah atau nama lainnya dan jika di luar negeri melalui Perwakilan Negara Kesatuan Republik Indonesia di tempat orang yang dipanggil berdiam. (41 Dalam hal tidak diketahui tempat tinggal atau kediamannya dan surat belum berhasil disampaikan, surat panggilan ditempelkan di tempat pengumuman kantor pejabat yang mengeluarkan panggilan tersebut."}, {"l": "UU 20/2025", "p": "279", "b": "Bagian Kedelapan", "t": "Jangka waktu menurut Undang-Undang ini mulai diperhitungkan pada hari berikutnya. Pasal 280... PRESIOEN -t44-"}, {"l": "UU 20/2025", "p": "280", "b": "Bagian Kedelapan", "t": "(1) Saksi atau Ahli, yang telah hadir memenuhi panggilan untuk memberikan keterangan di semua tahap pemeriksaan, berhak mendapat penggantian biaya sesuai dengan ketentuan peraturan perundang- undangan. (21 Pejabat yang melakukan pemanggilan wajib memberitahukan kepada Saksi atau Ahli mengenai haknya sebagaimana dimaksud pada ayat (l)."}, {"l": "UU 20/2025", "p": "281", "b": "Bagian Kedelapan", "t": "(1) Sidang pengadilan dilaksanal<an dalam ruang sidang di gedung pengadilan. (21 Dalam nrang sidang, Hakim, Penuntut Umum, Advokat, dan panitera mengenakan pakaian sidang dan atribut masing-masing sesuai dengan ketentuan peraturan perundang-undangan. (3) Ruang sidang sebagaimana dimaksud pada ayat (1) ditata menurut ketentuan sebagai berikut: a. tempat meja dan kursi Hakim terletak lebih tinggi dari tempat Penuntut Umum, Terdakwa, Advokat, dan pengunjung; b. tempat panitera terletak di sisi kanan belakang tempat Hakim ketua sidang; c. tempat Penuntut Umum terletak di sisi kanan depan tempat Hakim; d. tempat Terdakwa dan Advokat terletak di sisi kiri depan dari tempat Hakim dan tempat Terdakwa di sebelah kanan tempat Advokat; e. tempat kursi pemeriksaan Terdakwa dan Saksi terletak di depan tempat Hakim; f. tempat Saksi atau Ahli yang telah didengar terletak di belakang kursi pemeriksaan; g. tempat pengunjung terletak di belakang tempat Saksi yang telah didengar; h. bendera . . . PRESIOEN R,EPUBLIK !NDONESIA h. bendera Negara Kesatuan Republik Indonesia ditempatkan di sebelah kanan meja Hakim dan bendera pengadilan ditempatkan di sebelah kiri meja Hakim sedangkan lambang negara …"}, {"l": "UU 20/2025", "p": "282", "b": "Bagian Kedelapan", "t": "(1) Sebelum sidang dimulai, panitera, Penuntut Umum, Advokat, dan pengunjung menduduki tempatnya masing-masing dalam ruang sidang. (21 Pada saat Hakim memasuki dan meninggalkan ruang sidang, semua yang hadir wajib berdiri untuk memberi penghormatan. (3) Selama sidang berlangsung, setiap orang yang keluar masuk ruang sidang wajib memberi hormat."}, {"l": "UU 20/2025", "p": "283", "b": "Bagian Kedelapan", "t": "Ketentuan lebih lanjut mengenai jenis, bentuk, dan warna pakaian sidang serta atribut dan hal yang berhubungan dengan perangkat kelengkapan sebagaimana dimaksud dalam Pasal 2al ayat (21 diatur dalam Peraturan Pemerintah. Pasal 284... FRESIDEN"}, {"l": "UU 20/2025", "p": "284", "b": "Bagian Kedelapan", "t": "Semua biaya yang dikeluarkan untuk kepentingan pemeriksaan di sidang pengadilan dibebankan kepada negara."}, {"l": "UU 20/2025", "p": "285", "b": "Bagian Kesatu", "t": "(1) Permohonan banding dapat diajukan ke pengadilan tinggi oleh Terdal<wa atau Advokatnya atau Penuntut Umum. (21 Permohonan banding 5slagaim€ura dimaksud pada ayat (l) diterima oleh panitera pengadilan negeri dalam jangka waktu paling lama 7 (tujuh) Hari setelah putusan dijatuhkan atau setelah putusan diberitahukan kepada Terdakwa yang tidak hadir dalam sidang sebagaimana dimaksud dalam Pasal 266 ayat (21. (3) Terhadap permohonan banding sebagaimana dimaksud pada ayat (21, pailtera membuat surat keterangan yang ditandatangani oleh panitera dan pemohon, serta tembusannya diberikan kepada pemohon yang bersangkutan. (41 Dalam hal pemohon tidak dapat menghadap, panitera harus mencatatnya disertai dengan alasan dan catatan harus dilampirkan dalam berkas perkara dan ditulis dalam daftar perkara pidana. (5) Dalam hal pengadilan negeri menerima permohonan banding yang diajukan oleh: a. Penuntut Umum atau Terdakwa atau Advokatnya; atau b. Penuntut Umum dan Terdakwa atau Advokatnya sekaligus, panitera wajib memberitahukan permohonan dari pihak yang satu kepada pihak yang lain. Pasal 286. . ."}, {"l": "UU 20/2025", "p": "286", "b": "Bagian Kesatu", "t": "(1) Apabila jangka waktu sebagaimana dimaksud dalam Pasal 285 ayat (21 telah lewat tanpa diajukan permohonan banding maka Terdakwa atau Advokatnya dan/atau Penuntut Umum dianggap menerima putusan. (21 Dalam hal telah lewat waktu dan Terdakwa atau Advokatnya, atau Penuntut Umum dianggap menerima putusan sebagaimana dimaksud pada ayat (1), panitera mencatat dan membuat akta mengenai hal tersebut serta dilekatkan pada berkas perkara."}, {"l": "UU 20/2025", "p": "287", "b": "Bagian Kesatu", "t": "(1) Dalam hal perkara banding belum diputus oleh pengadilan tinggi, permohonan banding dapat dicabut sewaktu-waktu. (2) Dalam hal perkara sebagaimana dimaksud pada ayat (1) sudah dicabut, permohonan banding untuk perkara tersebut tidak dapat diajukan lagi. (3) Dalam hal perkara telah mulai diperiksa, namun belum diputus sedangkan pemohon mencabut permohonan bandingnya, pemohon dibebankan kewajiban membayar biaya perkara yang telah dikeluarkan oleh pengadilan tinggi hingga saat pencabutannya."}, {"l": "UU 20/2025", "p": "288", "b": "Bagian Kesatu", "t": "(1) Dalam jangka waktu paling lama 14 (empat belas) Hari terhitung sejak permohonan banding diajukan, panitera mengirimkan salinan putusan pengadilan negeri, berkas perkara, dan surat bukti kepada pengadilan tinggi. (2) Pemohon banding wajib diberi kesempatan untuk mempelajari berkas perkara tersebut di pengadilan negeri dalam waktu paling lambat 7 (tujuh) Hari sebelum pengiriman berkas perkara kepada pengadilan tinggi. (3) Dalam . . . -t48- (3) Dalam hal pemohon banding menyatakan secara tertulis akan mempelajari berkas perkara tersebut di pengadilan tinggi, pemohon wajib diberi kesempatan dalam jangka waktu paling lama 7 (tujuh) Hari terhitung sejak tanggal berkas perkara diterima oleh pengadilan tinggi. (41 Pemohon banding wajib diberi kesempatan untuk sewaktu-waktu meneliti keaslian berkas perkaranya."}, {"l": "UU 20/2025", "p": "289", "b": "Bagian Kesatu", "t": "(1) Dalam hal Penuntut Umum mengajukan permohonan banding, Penuntut Umum wajib menyertakan memori banding. (21 Dalam hal Terdakwa mengajukan permohonan banding, Terdakwa dapat menyertakan memori banding. (3) Memori banding diajukan dalam jangka waktu paling lama 7 (tujuh) Hari setelah permohonan diajukan. (4) Apabila jangka waktu sebagaimana dimaksud pada ayat (3) terlampaui dan Penuntut Umum sebagai pemohon banding tidak mengajukan memori banding, permohonan banding gugur."}, {"l": "UU 20/2025", "p": "290", "b": "Bagian Kesatu", "t": "(1) Penuntut Umum dan/atau Terdakwa dalam memori bandingnya dapat meminta agar Saksi dan/atau Ahli yang telah didengar keterangannya pada tingkat pertama untuk diperiksa kembali oleh pengadilan tinggi. (21 Permintaan sebagaimana dimaksud pada ayat (l) wajib disertai alasan mengapa Saksi dan/atau Ahli tersebut perlu didengar kembali oleh pengadilan tinggi. (3) Permintaan sebagaimana dimaksud pada ayat (1)juga dapat diajukan terhadap Saksi dan/atau Ahli yang pada tingkat pertama tidak hadir. Pasal 291 ... FRESIDEN"}, {"l": "UU 20/2025", "p": "291", "b": "Bagian Kesatu", "t": "(1) Pemeriksaan dalam tingkat banding dilakukan. oleh pengadilan tinggi dengan minimal 3 (tiga) orang Hakim atas dasar berkas perkara yang diterima dari pengadilan negeri yang terdiri dari berita acara pemeriksaan dari Penyidik, berita acara pemeriksaan di sidang pengadilan negeri, beserta semua surat yang timbul di sidang yang berhubungan dengan perkara itu, dan putusan pengadilan negeri. (21 Wewenang untuk menentukan Penahanan beralih ke pengadilan tinggi sejak saat diajukannya permohonan banding. (3) Dalam jangka waktu paling lama 3 (tiga) Hari terhitung sejak tanggal menerima berkas perkara banding dari pengadilan negeri, ketua pengadilan tinggi menunjuk Hakim/majelis Hakim yang akan memeriksa permohonan banding. (41 Dalam jangka waktu paling lama 3 (tiga) Hari terhitung sejak ditunjuknya Hakim sebagaimana dimaksud pada ayat (3), Hakim/majelis Hakim pengadilan tinggi wajib mempelajari berkas perkara untuk menetapkan: a. perlu atau tidaknya Terdakwa tetap ditahan atau tidak, baik karena jabatannya maupun atas permintaan Terdakwa; dan/ atau b. perlu atau tidalnya Saksi dan/atau Ahli untuk dipanggil dan diperiksa untuk didengar kembali keterangannya dalam hal sebagaimana dimaksud …"}, {"l": "UU 20/2025", "p": "292", "b": "Bagian Kesatu", "t": "(l) Ketua majelis Hakim pengadilan tinggi menetapkan tanggal sidang pemeriksaan dalam hal: a. memandang perlu untuk mendengar kembali Keterangan Saksi dan/atau Ahli berdasarkan permintaan Penuntut Umum dan/atau Terdakwa sebagaimana dimaksud dalam Pasal 29O ayat (l); dan /atau b. memandang perlu untuk mendengar kembali keterangan Terdakwa, Penuntut Umum, Saksi dan/atau Ahli yang tidak dimintakan untuk didengar kembali. (2) Panitera pengadilan tinggi mengirimkan penetapan tanegal sidang pemeriksaan beserta nama Terdakwa, Penuntut Umum, Saksi, dan/atau Ahli kepada Terdakwa dan Penuntut Umum melalui pengadilan negeri."}, {"l": "UU 20/2025", "p": "293", "b": "Bagian Kesatu", "t": "Tata cara pemeriksaan Saksi dan/ atau Ahli pada tingkat pertama sebagaimana dimaksud dalam Pasal 214 berlaku secara mutatis mutandis terhadap sidang pemeriksaan Saksi dan/atau Ahli di tingkat banding."}, {"l": "UU 20/2025", "p": "294", "b": "Bagian Kesatu", "t": "(1) Ketentuan mengenai larangan bagr Hakim menunjukkan sikap atau pernyataan mengenai salah atau tidaknya Terdakwa sebagaimana dimaksud dalam Pasal 208 dan ketentuan mengenai larangan Mengadili suatu perkara yang berkaitan dengan kepentingannya sebagaimana dimaksud dalam Pasal 271 berlaku secara mutatis mutandis bagi pemeriksaan perkara dalam tingkat banding. (21 Ketentuan mengenai Hakim wajib mengundurkan diri untuk Mengadili perkara yang terikat hubungan keluarga sebagaimana dimaksud dalam Pasal 207 berlaku secara mutatis mutandis bagi Hakim dan/atau panitera tingkat banding dan Hakim dan/atau panitera tingkat pertama yang telah Mengadili perkara yang sama. (3) Dalam . . . .IItrEIEtrN REFUBLIK TNDONESIA (3) Dalam hal Hakim yang memutus perkara dalam tingkat pertama diangkat menjadi Hakim pada pengadilan tinggi, Hakim tersebut dilarang memeriksa perkara yang sama dalam tingkat banding."}, {"l": "UU 20/2025", "p": "295", "b": "Bagian Kesatu", "t": "(l) Jika pengadilan tinggi berpendapat bahwa dalam pemeriksaan tingkat pertama ternyata terdapat kelalaian dalam penerapan hukum acara, kekeliruan, atau kurang lengkap, pengadilan tinggi dapat memerintahkan pengadilan negeri untuk memperbaiki hal tersebut atau pengadilan tinggi melakukannya sendiri melalui putusan. (21 Dalam hal diperlukan, pengadilan tinggi dapat membatalkan penetapan dari pengadilan negeri sebelum putusan pengadilan tinggi dijatuhkan."}, {"l": "UU 20/2025", "p": "296", "b": "Bagian Kesatu", "t": "(l) Setelah semua hal sebagaimana dimaksud dalam Pasal 295 dipertimbangkan dan dilaksanakan, pengadilan tinggi memutuskan, menguatkan, mengubah, atau dalam hal membatalkan putusan pengadilan negeri, pengadilan tinggi Mengadili sendiri atas perkara tersebut. (21 Dalam hal pembatalan tersebut terjadi atas putusan pengadilan negeri karena pengadilan tidak berwenang memeriksa perkara tersebut maka berlaku ketentuan mengenai surat pelimpahan perkara kepada pengadilan negeri lain yang dianggap berwenang Mengadili sebagaimana dimaksud dalam Pasal 295 ayat (21. Pasal297 Jika dalam pemeriksaan tingkat banding, Terdakwa yang dipidana ditahan dalam tahanan, pengadilan tinggi dalam putusannya memerintahkan agar Terdakwa tetap ditahan atau dibebaskan. Pasal 298... t-rkGEIEtrN :ITITT:If TETTEI'ITI+f 'I -t52-"}, {"l": "UU 20/2025", "p": "298", "b": "Bagian Kesatu", "t": "(1) Pengadilan tinggi memberitahukan kepada Terdakwa dan Penuntut Umum tanggal sidang pembacaan putusan. (21 Putusan pengadilan tinggi wajib dibacakan dalam sidang terbuka untuk umum. (3) Dalam hal terdapat perubahan tanggal pembacaan putusan, pengadilan tinggi memberitahukan hal tersebut kepada Terdakwa dan Penuntut Umum. (4) Pemberitahuan kepada Terdakwa sebagaimana dimaksud pada ayat (l) dan ayat (3) dilakukan oleh Penuntut Umum yang untuk itu Penuntut Umum membuatkan tanda terima pemberitahuan. (5) Sidang pembacaan putusan dapat dihadiri oleh Terdakwa dan/ atau Penuntut Umum, baik secara langsung maupun secara elektronik. (6) Isi petikan putusan diumumkan melalui laman sistem informasi pengadilan pada hari putusan diumumkan. (71 Salinan putusan pengadilan tinggi beserta berkas perkara dalam waktu 7 (tujuh) Hari setelah putusan tersebut dijatuhkan, disampaikan kepada pengadilan negeri yang memutus pada tingkat pertama. (8) Isi putusan setelah dicatat dalam buku register segera diberitahukan kepada Terdakwa dan Penuntut Umum oleh panitera pengadilan negeri dan selanjutnya pemberitahuan tersebut dicatat dalam salinan putusan pengadilan tinggi. (9) Ketentuan mengenai putusan …"}, {"l": "UU 20/2025", "p": "299", "b": "Bagian Kedua", "t": "(l) Terhadap putusan perkara pidana yang diberikan pada tingkat terakhir oleh pengadilan lain selain Mahkamah Agung, Terdakwa, atau Penuntut Umum dapat mengajukan permohonan pemeriksaan kasasi kepada Mahkamah Agung. (21 Pengajuan pemeriksaan kasasi sebagaimana dimaksud pada ayat (1) tidak dapat diajukan terhadap: a. putusan bebas; b. putusan berupa pemaafan Hakim; c. putusan berupa tindakan; d. putusan terhadap tindak pidana yang diancam dengan pidana penjara tidak lebih dari 5 (lima) tahun atau pidana denda kategori V; dan e. putusan yang telah diperiksa dengan acara pemeriksaan singkat."}, {"l": "UU 20/2025", "p": "300", "b": "Bagian Kedua", "t": "(l) Permohonan kasasi disampaikan oleh pemohon dalam jangka waktu paling lama 14 (empat belas) Hari terhitung sejak Putusan Pengadilan yang dimintakan kasasi itu dibacakan dalam sidang yang terbuka untuk umum, l2l Permintaan sebagaimana dimaksud pada ayat (1) oleh panitera ditulis dalam sebuah surat keterangan yang ditandatangani oleh panitera serta pemohon, dan dicatat dalam daftar yang dilampirkan pada berkas perkara. (3) Dalam . . . R,EPUBLIK INDONESIA (3) Dalam hal pengadilan negeri menerima permohonan kasasi yang diajukan oleh: a. Penuntut Umum atau Terdakwa; atau b. Penuntut Umum dan Terdakwa sekaligus, panitera wajib memberitahukan permintaan dari pihak yang satu kepada pihak yang lain. Pasal 3O 1 (1) Apabila jangka waltu sebagaimana dimaksud dalam Pasal 300 ayat (l) telah lewat tanpa diajukan permohonan kasasi oleh yang bersangkutan maka Terdakwa atau Advokatnya, atau Penuntut Umum dianggap menerima putusan. (21 Apabila dalam jangka waktu sebagaimana dimaksud pada ayat (l), pemohon terlambat mengajukan permohonan kasasi maka hak untuk mengajukan kasasi gugur. (3) Apabila jangka waktu sebagaimana dimaksud pada ayat (l) telah lewat dan keterlambatan waktu mengajukan …"}, {"l": "UU 20/2025", "p": "302", "b": "Bagian Kedua", "t": "(l) Selama perkara permohonan kasasi belum diputus oleh Mahkamah Agung, permohonan kasasi dapat dicabut sewaktu-waktu. (2) Dalam hal permohonan sebagaimana dimaksud pada ayat (1) sudah dicabut, permohonan kasasi tidak dapat diajukan lagi. (3) Da1am hal pencabutan dilakukan sebelum berkas perkara dikirim ke Mahkamah Agung, berkas tersebut tidak perlu dikirimkan. l4l Dalam hal perkara telah mulai diperiksa dan belum diputus, namun pemohon mencabut permohonan kasasinya, pemohon dibebani membayar biaya perkara hingga saat pencabutannya. (5) Permohonan kasasi hanya dapat diajukan I (satu) kali. Pasal 303... ilrl-d{fr{X"}, {"l": "UU 20/2025", "p": "303", "b": "Bagian Kedua", "t": "(1) Pemohon kasasi wajib mengajukan memori kasasi yang memuat alasan permohonan kasasinya dan dalam jangka waktu 14 (empat belas) Hari setelah mengajukan permohonan tersebut, harus sudah menyerahkannya kepada panitera yang untuk itu ia memberikan surat tanda terima. (21 Dalam hal pemohon kasasi merupakan Terdakwa yang kurang memahami hukum, panitera pada waktu menerima permohonan kasasi wajib menanyakan alasan mengajukan permohonan tersebut dan untuk itu panitera membuatkan memori kasasinya. (3) Apabila dalam jangka waktu sebagaimana dimaksud pada ayat (l), pemohon terlambat menyerahkan memori kasasi maka hak untuk mengajukan permohonan kasasi gugur. (41 Ketentuan sebagaimana diatur dalam Pasal 3O2 ayat (3) berlaku juga untuk ayat (3) pasal ini. (5) Tembusan memori kasasi yang diajukan oleh salah satu pihak, oleh panitera disampaikan kepada pihak lainnya dan pihak lain itu berhak mengajukan kontra memori kasasi. (6) Dalam jangka waktu s6legaimana dimaksud pada ayat (l), panitera menyampaikan tembusan kontra memori kasasi kepada pihak yang semula mengajukan memori kasasi."}, {"l": "UU 20/2025", "p": "304", "b": "Bagian Kedua", "t": "(1) Dalam hal salah satu pihak berpendapat masih ada sesuatu yang perlu ditambahkan dalam memori kasasi atau kontra memori kasasi, pihak yang bersangkutan diberikan kesempatan untuk mengajukan tambahan tersebut dalam jangka waktu paling lama 14 (empat belas) Hari sebagaimana dimaksud dalam Pasal 303 ayat (1). l2l Tambahan sebagaimana dimaksud pada ayat (l) diserahkan kepada panitera pengadilan. (3) Dalam jangka waktu paling lama 14 (empat belas) Hari setelah jangka waktu sebagaimana dimaksud pada ayat (l), panitera pengadilan segera permohonan kasasi secara lengkap kepada Mahkamah Agung. Pasal 305... FRESIDEN REFUBLIK INDONESIA"}, {"l": "UU 20/2025", "p": "305", "b": "Bagian Kedua", "t": "(l) Setelah panitera pengadilan negeri menerima memori kasasi dan/atau kontra memori kasasi, panitera dalam waktu paling lama 1 (satu) Hari wajib mengirim berkas perkara kepada Mahkamah Agung. (21 Pada saat panitera Mahkamah Agung menerima berkas perkara sebagaimana dimalsud pada ayat (1), panitera langsung mencatat dalam buku agenda surat, buku register perkara, dan pada kartu petunjuk. (3) Buku register perkara sebagaimana dimaksud pada ayat (21 wajib dikerjakan secara tertutup dan ditandatangani oleh panitera pada setiap hari kerja yang harus diketahui dan ditandatangani oleh Ketua Mahkamah Agung. (4) Dalam hal Ketua Mahkamah Agung berhalangan, penandatanganan dilakukan oleh wakil Ketua Mahkamah Agung. (5) Dalam hal wakil Ketua Mahkamah Agung berhalangan, Ketua Mahkamah Agung menunjuk salah sahr Hakim anggotanya dengan keputusan Ketua Mahkamah Agung. (6) Panitera Mahkamah Agung mengeluarkan bukti penerimaan yang aslinya dikirimkan kepada panitera pengadilan negeri yang bersangkutan, sedangkan kepada para pihak dikirimkan tembusannya."}, {"l": "UU 20/2025", "p": "306", "b": "Bagian Kedua", "t": "(l) Ketentuan mengenai larangan bagi Hakim yang menunjukkan sikap atau pernyataan mengenai salah atau tidaknya Terdakwa sebagaimana dimaksud dalam Pasal 208 dan ketentuan mengenai larangan Mengadili suatu perkara yang berkaitan dengan kepentingannya sebagaimana dimalsud dalam Pasal 2O7 berlaku secara mutatis mutandis bagi pemeriksaan perkara dalam tingkat kasasi. (21 Ketentuan mengenai Halim wajib mengundurkan diri untuk Mengadili perkara yang terikat hubungan keluarga sebagaimana dimaksud dalam Pasal 207 ayat (l) berlaku secara mutatis mutandis bagi Hakim dan/atau panitera tingkat kasasi dan Hakim dan/ atau panitera tingkat banding yang telah Mengadili perkara yang sama. (3) Dalam . . . -r57- (3) Dalam hal seorang Hakim yang Mengadili perkara dalam tingkat pertama atau tingkat banding, kemudian telah menjadi Hakim atau panitera pada Mahkamah Agung, Hakim tersebut dilarang bertindak sebagai Hakim atau panitera untuk perkara yang sama dalam tingkat kasasi."}, {"l": "UU 20/2025", "p": "307", "b": "Bagian Kedua", "t": "(1) Ketentuan sebagaimana dimaksud dalam Pasal 271 ayat (1) berlaku juga bagi pemeriksaan perkara dalam tingkat kasasi. (2) Dalam hal terdapat keraguan atau perbedaan pendapat mengenai ketentuan sebagaimana dimaksud pada ayat (1), dalam tingkat kasasi: a. Ketua Mahkamah Agung karena jabatannya bertindak sebagai pejabat yang berwenang menetapkan Hakim yang akan Mengadili; atau b. dalam hal menyangkut Ketua Mahkamah Agung sendiri, pihak yang berwenang menetapkan Hakim yang akan Mengadili merupakan majelis yang terdiri atas 3 (tiga) orang Hakim yang dipilih oleh dan antar Hakim anggota."}, {"l": "UU 20/2025", "p": "308", "b": "Bagian Kedua", "t": "(1) Pemeriksaan dalam tingkat kasasi dilakukan oleh Mahkamah Agung atas permintaan para pihak guna menentukan apakah benar: a. suatu ketentuan peraturan perundang-undangan tidak diterapkan atau diterapkan tidak sebagaimana mestinya; b. cara Mengadili tidak dilaksanakan sesuai dengan ketentuan peraturan perundang-undangan; dan/ atau c. pengadilan telah melampaui batas wewenangnya. (21 Dalam pemeriksaan sebagaimana dimaksud pada ayat (1), Mahkamah Agung tidak lagi melakukan penilaian atas terbukti atau tidaknya perbuatan yang didakwakan. (3) Pemeriksaan . . . R,EPUBIJK INDONESIA (3) Pemeriksaan sebagaimana dimaksud pada ayat (1) dilakukan dengan paling sedikit 3 (tiga) orang Hakim atas dasar berkas perkara yang diterima dari pengadilan lain oleh Mahkamah Agung. (41 Pemeriksaan sebagaimana dimaksud pada ayat (3) terdiri atas: a. berita acara pemeriksaan dari Penyidik; b. berita acara pemeriksaan di sidang pengadilan; c. semua surat yang timbul dalam pemeriksaan di sidang pengadilan yang berhubungan dengan perkara itu; dan d. Putusan Pengadilan tingkat pertama dan/atau tingkat terakhir. (5) Jika dipandang perlu untuk kepentingan pemeriksaan sebagaimana dimaksud pada ayat (1), Mahkamah …"}, {"l": "UU 20/2025", "p": "309", "b": "Bagian Kedua", "t": "(1) Dalam hal Mahkamah Agung memeriksa permohonan kasasi karena telah memenuhi ketentuan sebagaimana dimaksud dalam Pasal 308 ayat (1) dan ayat (41 mengenai hukumnya, Mahkamah Agung dapat memutus untuk menolak atau mengabulkan permohonan kasasi. (21 Dalam hal Mahkamah Agung menerima permohonan kasasi, Mahkamah Agung memutus mengenai penerapan hukum dan tidak mengenai fakta atau pembuktian."}, {"l": "UU 20/2025", "p": "310", "b": "Bagian Kedua", "t": "(1) Dalam hal suatu putusan dibatalkan karena ketentuan peraturan perundang-undangan tidak diterapkan atau diterapkan tidak sebagaimana mestinya, Mahkamah Agung Mengadili perkara. (21 Dalam hal suatu putusan dibatalkan karena cara Mengadili tidak dilaksanakan sesuai dengan ketentuan peraturan perundang-undangan, Mahkamah Agung menetapkan disertai petunjuk agar pengadilan yang memutus perkara memeriksanya kembali mengenai bagian yang dibatalkan atau berdasarkan alasan tertentu Mahkamah Agung dapat menetapkan perkara tersebut diperiksa oleh pengadilan setingkat yang lain. (3) Dalam hal suatu putusan dibatalkan karena pengadilan atau Hakim yang bersangkutan tidak berwenang Mengadili perkara, Mahkamah Agung menetapkan pengadilan atau Hakim lain Mengadili perkara tersebut. Pasal 31 1 (l) Dalam hal Mahkamah Agung mengabulkan permohonan kasasi, Mahkamah Agung membatalkan Putusan Pengadilan yang dimintakan kasasi. (21 Ketentuan mengenai pembatalan Putusan Pengadilan sebagaimana dimaksud dalam Pasal 310 berlaku secara mutatis mutandis terhadap pembatalan Putusan Pengadilan yang dimintakan kasasi sebagaimana dimaksud pada ayat (1). Pasal 312... REFUBLIK INDONESIA"}, {"l": "UU 20/2025", "p": "312", "b": "Bagian Kedua", "t": "Ketentuan mengenai pemberian petikan atau salinan surat putusan sebagaimana dimaksud dalam Pasal 254 dan Pasal 277 ayat (l) berlaku juga bagr putusan kasasi Mahkamah Agung, kecuali mengenai pengiriman salinan putusan beserta berkas perkaranya kepada pengadilan yang memutus pada tingkat pertama yaitu dalam waktu paling lama 14 (empat belas) Hari."}, {"l": "UU 20/2025", "p": "313", "b": "Bagian Kedua", "t": "Ketentuan mengenai pemeriksaan tingkat kasasi sebagaimana dimaksud dalam Pasal 299 sampai dengan Pasal 3 12 berlaku secara mutatis mutandis terhadap pemeriksaan tingkat kasasi terhadap Putusan Pengadilan dalam lingkungan peradilan militer."}, {"l": "UU 20/2025", "p": "314", "b": "Bagian kesatu", "t": "(1) Putusan yang telah memperoleh kekuatan hukum tetap dari pengadilan lain selain Mahkamah Agung dapat diajukan I (satu) kali permohonan kasasi demi kepentingan hukum oleh Jaksa Agung. (2) Putusan kasasi demi kepentingan hukum sebagaimana dimaksud pada ayat (l) tidak boleh merugikan pihak yang berkepentingan. Pasal 3 15 (1) Permohonan kasasi demi kepentingan hukum sebagaimana dimaksud dalam Pasal 314 ayat (1) disampaikan secara tertulis oleh Jaksa Agung kepada Mahkamah Agung melalui panitera pengadilan yang telah memutus perkara pada tingkat pertama, disertai risalah yang memuat alasan permintaan tersebut. (2) Salinan . . . l2l Salinan risalah sebagaimana dimaksud pada ayat (1) dalam jangka waktu paling lama 2 (dua) Hari oleh panitera disampaikan kepada pihak yang berkepentingan. (3) Ketua pengadilan sebagaimana dimaksud pada ayat (1) dalam jangka waktu paling lama 2 (dua) Hari meneruskan permintaan tersebut kepada Mahkamah Agung."}, {"l": "UU 20/2025", "p": "316", "b": "Bagian kesatu", "t": "(1) Salinan putusan kasasi demi kepentingan hukum oleh Mahkamah Agung disampaikan kepada Jaksa Agung dan kepada pengadilan yang bersangkutan dengan disertai berkas perkara. (21 Ketentuan mengenai penyampaian salinan putusan pengadilan tinggi sebagaimana dimaksud dalam Pasal 298 ayat (71 berlaku secara mutatis mutandis terhadap penyampaian salinan putusan kasasi sebagaimana dimaksud pada ayat (l ). Pasal 3 l7 Ketentuan mengenai pemeriksaan tingkat kasasi demi kepentingan hukum sebagaimana dimaksud dalam Pasal 314 sampai dengan Pasal 316 berlaku bagi pemeriksaan tingkat kasasi demi kepentingan hukum terhadap Putusan Pengadilan dalam lingkungan peradilan militer. BagiaP 1L6\" Peninjauan Kembali Putusan Pengadilan Yang Telah Memperoleh Kekuatan Hukum Tetap"}, {"l": "UU 20/2025", "p": "318", "b": "Bagian kesatu", "t": "(1) Terhadap Putusan Pengadilan yang telah memperoleh kekuatan hukum tetap, Terpidana dapat mengajukan permintaan peninjauan kembali kepada Mahkamah Agung. (2) Permintaan . . . E{TFITEtrN -t62- (2) Permintaan peninjauan kembali sebagaimana dimaksud pada ayat (1) hanya dapat diajukan oleh pihak Terpidana atau ahli warisnya. (3) Dalam hal Terpidana telah meninggal dunia permintaan dapat diajukan oleh istri atau suami yang ditinggalkan, orang tua, anak, atau saudara kandung. (41 Permintaan oleh Terpidana atau pihak sebagaimana dimaksud pada ayat (3) dapat dikuasakan kepada Advokat yang dikuasakan khusus untuk itu. (5) Permintaan peninjauan kembali dilakukan atas dasar: a. jika terdapat keadaan baru atau bukti baru yang menimbulkan dugaan kuat, bahwa keadaan atau bukti tersebut jika diketahui pada waktu sidang masih berlangsung, hasilnya dapat berupa putusan bebas, putusan lepas dari segala tuntutan hukum, tuntutan Penuntut Umum tidak dapat diterima, atau terhadap perkara itu diterapkan ketentuan pidana yang lebih ringan; b. salah seorang atau lebih Hakim yang menjatuhkan pemidanaan tersebut terbukti bersalah berdasarkan putusan yang berkekuatan hukum tetap menerima hadiah atau janji …"}, {"l": "UU 20/2025", "p": "319", "b": "Bagian kesatu", "t": "(1) Permintaan peninjauan kembali oleh pemohon sebagaimana dimaksud dalam Pasal 318 ayat (1) diajukan kepada panitera pengadilan yang telah memutus perkaranya dalam tingkat pertama dengan menyebutkan alasannya. (21 Permintaan peninjauan kembali sebagaimana dimaksud dalam Pasal 318 ayat (5) huruf a dan huruf c tidak dibatasi dengan suatu jangka waktu pengajuannya. (3) Permintaan peninjauan kembali sebagaimana dimaksud dalam Pasal 318 ayat (5) huruf b diajukan dalam jangka waktu paling lama 6 (enam) bulan terhitung sejak putusan berkekuatan hukum tetap. (41 Ketua pengadilan segera mengirimkan surat permintaan peninjauan kembali beserta berkas perkaranya kepada Mahkamah Agung, disertai dengan berita acara hasil pemeriksaan alasan peninjauan kembali."}, {"l": "UU 20/2025", "p": "320", "b": "Bagian kesatu", "t": "(1) Ketua pengadilan negeri setelah menerima permohonan peninjauan kembali menunjuk Hakim yang tidak memeriksa perkara semula yang dimohonkan peninjauan kembali untuk memeriksa permohonan peninjauan kembali tersebut memenuhi alasan sebagaimana dimaksud dalam pasal 318 ayat (5). (2) Dalam pemeriksaan sebagaimana dimaksud pada ayat (1), pemohon dan perwakilan dari Jaksa Agung hadir dan dapat menyampaikan pendapatnya. (3) Terhadap pemeriksaan sebagaimana dimaksud pada ayat (1) dibuat berita acara pemeriksaan yang ditandatangani oleh Hakim, Jaksa, pemohon, dan panitera dan berdasarkan berita acara itu dibuat berita acara pendapat yang ditandatangani oleh Hakim dan panitera. (4) Ketua . . . (41 Ketua pengadilan negeri dalam waktu paling lama 1 (satu) Hari setelah permohonan peninjauan kembali diterima melanjutkan permohonan peninjauan kembali yang dilampiri berkas perkara semula, berita acara pemeriksaan, dan berita acara pendapat kepada Mahkamah Agung yang tembusan surat pengantarnya disampaikan kepada pemohon dan Jaksa. (5) Dalam hal suatu perkara yang dimohonkan peninjauan kembali merupakan putusan pengadilan banding, tembusan surat pengantar tersebut harus dilampiri tembusan berita …"}, {"l": "UU 20/2025", "p": "322", "b": "Bagian kesatu", "t": "(1) Setelah berkas permohonan peninjauan kembali diterima, Ketua Mahkamah Agung atau Hakim agu.ng yang ditunjuk memeriksa permohonan tersebut dan menetapkan bahwa permohonan peninjauan kembali telah memenuhi ketentuan sebagaimana dimaksud dalam Pasal 320 ayat (3). (21 Dalam hal Mahkamah Agung berpendapat bahwa permohonan peninjauan kembali dapat diterima untuk diperiksa, berlaku ketentuan sebagai berikut: a. jika Mahkamah Agung tidak membenarkan alasan pemohon, Mahkamah Agung menolak permohonan peninjauan kembali dengan menetapkan bahwa putusan yang dimohonkan peninjauan kembali tersebut tetap berlaku disertai dasar pertimbangannya; dan b. dalam . . . FRESIDEN b. dalam hal Mahkamah Agung membenarkan alasan pemohon, Mahkamah Agung membatalkan putusan yang dimohonkan peninjauan kembali dan menjatuhkan putusan yang dapat berupa: 1. putusan bebas; 2. putusan lepas dari segala tuntutan hukum; 3. putusan yang menyatakan tuntutan Penuntut Umum tidak dapat diterima; atau 4. putusan dengan menerapkan ketentuan pidana yang lebih ringan. (3) Dalam hal Terpidana telah menjalani putusan yang diajukan peninjauan kembali dan ternyata putusan peninjauan kembali membebaskan, melepaskan dari segala …"}, {"l": "UU 20/2025", "p": "323", "b": "Bagian kesatu", "t": "(l) Kecuali untuk pelaksanaan pidana mati, pemusnahan, perusakan barang bukti, permohonan peninjauan kembali atas suatu putusan tidak menangguhkan atau menghentikan pelaksanaan dari putusan tersebut. (21 Dalam hal permohonan peninjauan kembali sudah diterima oleh Mahkamah Agung dan pemohon meninggal dunia, mengenai diteruskan atau tidaknya peninjauan kembali tersebut diserahkan kepada ahli warisnya."}, {"l": "UU 20/2025", "p": "324", "b": "Bagian kesatu", "t": "(1) Permintaan peninjauan kembali atas suatu putusan tidak menangguhkan dan menghentikan pelaksanaan dari putusan tersebut. (2) Dalam . . . REPI.JBUK INDONESIA (21 Dalam hal suatu permintaan peninjauan kembali sudah diterima oleh Mahkamah Agung dan sementara itu pemohon meninggal dunia, mengenai diteruskan atau tidalnya peninjauan kembali tersebut diserahkan kepada ahli warisnya."}, {"l": "UU 20/2025", "p": "325", "b": "Bagian kesatu", "t": "Ketentuan mengenai peninjauan kembali Putusan Pengadilan yang telah memperoleh kekuatan hukum tetap sebagaimana dimaksud dalam Pasal 318 sampai dengan Pasal 324 berlaku secara mutatis mutandis terhadap peninjauan kembali Putusan Pengadilan dalam lingkungan peradilan militer."}, {"l": "UU 20/2025", "p": "326", "b": "Bagian Kesatu", "t": "(1) Pertanggungiawaban atas tindak pidana oleh Korporasi dikenakan terhadap Korporasi dan penanggung jawab Korporasi. (2) Penanggung jawab Korporasi sebagaimana dimaksud pada ayat (l) terdiri atas: a. pengurus yang memiliki jabatan fungsional dalam struktur organisasi Korporasi; b. pemberi perintah; c. pemegang kendali; atau d. pemilik manfaat."}, {"l": "UU 20/2025", "p": "327", "b": "Bagian Kedua", "t": "(1) Pemanggilan terhadap Korporasi pada tahap Penyelidikan dapat diwakili oleh penanggung jawab Korporasi. (21 Penyidik yang melakukan pemeriksaan terhadap Korporasi memanggil Korporasi yang diwakili oleh penanggung jawab Korporasi sebagaimana dimaksud dalam Pasal 326 ayat (2) dengan surat panggilan yang sah. (3) Penanggung jawab Korporasi dalam pemeriksaan sebagaimana dimaksud pada ayat (2) wajib hadir dalam pemeriksaan Korporasi. (41 Dalam hal Korporasi telah dipanggil secara sah namun tidak hadir, menolak hadir, atau tidak menunjuk penanggung jawab Korporasi sebagaimana dimaksud dalam Pasal 326 ayat (2) untuk mewakili Korporasi dalam pemeriksaan, Penyidik menentukan salah seorang penanggung jawab Korporasi untuk mewakili Korporasi dan memanggil sekali lagi dengan perintah kepada petugas untuk membawa penanggung jawab Korporasi secara paksa. (5) Ketentuan mengenai Upaya Paksa terhadap orang pada tahap Penyidikan sebagaimana dimaksud dalam Pasal 90 sampai dengan Pasal 141 berlaku secara mutatis mutandis terhadap Upaya Paksa bagi penanggung jawab Korporasi. (6) Ketentuan mengenai mekanisme Keadilan Restoratif terhadap Korporasi berlaku dengan ketentuan: a. tindak pidana pertama …"}, {"l": "UU 20/2025", "p": "328", "b": "Bagian Ketiga", "t": "(l) Perjanjian Penundaan Penuntutan bertujuan untuk kepatuhan hukum, pemulihan kerugian akibat tindak pidana, serta efisiensi dalam peradilan pidana. (21 Perjanjian Penundaan Penuntutan hanya dapat diterapkan pada tindak pidana oleh Korporasi. (3) Permohonan Perjanjian Penundaan Penuntutan dapat diajukan oleh Tersangka, Terdakwa, atau Advokat kepada Penuntut Umum sebelum perkara dilimpahkan ke pengadilan. l4l Penuntut Umum dapat menerima atau menolak permohonan sebagaimana dimaksud pada ayat (3) berdasarkan pertimbangan keadilan, Korban, dan kepatuhan Terdakwa terhadap ketentuan peraturan perundang-undangan. (5) Dalam hal Penuntut Umum menerima permohonan, Penuntut Umum wajib memberitahukan kepada pengadilan terkait akan dilaksanakan proses Perjanjian Penundaan Penuntutan dan dicatat dalam berita acara. (6) Hasil kesepakatan Perjanjian Penundaan Penuntutan wajib disampaikan oleh Penuntut Umum kepada pengadilan dalam jangka waktu paling larl:a 7 (tujuh) Hari setelah kesepakatan ditandatangani oleh para pihak. (7) Pengadilan wajib mengadakan sidang pemeriksaan untuk menilai kelayakan dan keabsahan Perjanjian Penundaan Penuntutan sebelum disahkan. (8) Dalam sidang pemeriksaan …"}, {"l": "UU 20/2025", "p": "329", "b": "Bagian Keempat", "t": "(l) Surat dakwaan terhadap Korporasi dibuat sesuai dengan ketentuan dalam Undang-Undang ini. l2l Surat dakwaan sebagaimana dimaksud pada ayat (l) memuat sebagai berikut: a. identitas Korporasi terdiri atas: 1. nama Korporasi; 2. tempat dan tanggal pendirian dan/atau nomor anggaran dasar/akta pendirian/peraturan/ dokumen/perjanjian serta perubahan terakhir; 3. tempat kedudukan; 4. kebangsaan Korporasi; 5. jenis Korporasi; 6. bentuk kegiatan/ usaha; dan 7. identitas penanggung jawab Korporasi yang mewakili; dan b. uraian secara cermat, jelas, dan lengkap mengenai tindak pidana yang didakwakan dengan menyebutkan waktu dan tempat tindak pidana itu dilakukan."}, {"l": "UU 20/2025", "p": "330", "b": "Bagian Kelima", "t": "(1) Korporasi dapat dikenai pertanggungiawaban dalam hal terjadi penggabungan, peleburan, pemisahan atau pembubaran Korporasi. (21 Ketentuan lebih lanjut mengenai tata cara pertanggungjawaban Korporasi dalam penggabungan, peleburan, pemisahan, atau pembubaran Korporasi sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Pemerintah."}, {"l": "UU 20/2025", "p": "331", "b": "Bagian Keenam", "t": "(1) Hakim dapat menjatuhkan pidana dan/atau tindakan terhadap Korporasi. (2) Hakim menjatuhkan pidana dan/ atau tindakan sebagaimana dimaksud pada ayat (l) didasarkan pada setiap Undang-Undang yang mengatur ancaman pidana terhadap Korporasi. (3) Penjatuhan pidana dan/atau tindakan terhadap Korporasi sebagaimana dimaksud ayat (1) tidak menutup penjatuhan pidana terhadap pelaku lain yang berdasarkan ketentuan peraturan perundang-undangan terbukti terlibat dalam tindak pidana tersebut."}, {"l": "UU 20/2025", "p": "332", "b": "Bagian Keenam", "t": "Korporasi dan penanggung jawab Korporasi dapat diajukan bersama-sama sebagai Terdakwa."}, {"l": "UU 20/2025", "p": "333", "b": "Bagian Ketujuh", "t": "(l) Hakim menjatuhkan pidana terhadap Korporasi berupa pidana pokok dan/atau pidana tambahan. (21 Pidana pokok yang dapat dijatuhkan terhadap Korporasi sebagaimana dimaksud pada ayat (1) adalah pidana denda. (3) Pidana tambahan dijatuhkan terhadap Korporasi sesuai dengan ketentuan peraturan perundang- undangan."}, {"l": "UU 20/2025", "p": "334", "b": "Bagian Kedelapan", "t": "(1) Pelaksanaan putusan dilakukan berdasarkan Rrtusan Pengadilan yang memperoleh kekuatan hukum tetap. l2l Petikan putusan dapat digunakan sebagai dasar dalam pelaksanaan putusan sebagaimana dimaksud pada ayat (1)."}, {"l": "UU 20/2025", "p": "335", "b": "Bagian Kedelapan", "t": "(1) Dalam hal Korporasi dikenai pidana denda, pembayaran denda dilakukan dalam jangka waktu 1 (satu) bulan sejak putusan berkekuatan hukum tetap. (21 Dalam hal terdapat alasan kuat, jangka waktu sebagaimana dimaksud pada ayat (1) dapat diperpanjang paling lama I (satu) bulan. (3) Dalam hal Terpidana Korporasi tidak membayar denda sebagaimana dimaksud pada ayat (l) dan ayat (21, harta benda Korporasi disita oleh Jaksa atas izin ketua pengadilan negeri dan dilelang dengan bantuan kantor lelang negara untuk membayar denda. Pasal 336. . . REPIJBLIK INDONESIA -L73-"}, {"l": "UU 20/2025", "p": "336", "b": "Bagian Kedelapan", "t": "Pelaksanaan putusan harus dihadiri oleh hakim pengawas dan jaksa yang menangani perkara."}, {"l": "UU 20/2025", "p": "337", "b": "Bagian Kedelapan", "t": "(1) Dalam hal penanggungjawab Korporasi dikenai pidana denda, pembayaran denda dilakukan dalam jangka waktu I (satu) bulan sejak putusan berkekuatan hukum tetap. (21 Dalam hal terdapat alasan kuat, jangka waktu sebagaimana dimaksud pada ayat (1) dapat diperpanjang paling lama 1 (satu) bulan. (3) Dalam hal penanggung jawab Korporasi tidak membayar denda sebagian atau seluruhnya, harta benda Korporasi disita oleh Jaksa atas izin ketua pengadilan negeri dan dilelang dengan bantuan kantor lelang negara untuk melunasi pidana denda yang tidak dibayar."}, {"l": "UU 20/2025", "p": "338", "b": "Bagian Kesembilan", "t": "Pidana tambahan terhadap Korporasi dilaksanakan berdasarkan Putusan Pengadilan."}, {"l": "UU 20/2025", "p": "339", "b": "Bagian Kesembilan", "t": "(1) Dalam hal Korporasi dikenai pidana tambahan berupa perampasan barang yang diperoleh dari tindak pidana, perampasan barang dilakukan paling lama I (satu) bulan sejak putusan berkekuatan hukum tetap. (2) Dalam hal terdapat alasan kuat, jangka waktu sebagaimana dimaksud pada ayat (1) dapat diperpanjang paling lama 1 (satu) bulan. (3) Dalam hal terdapat keuntungan berupa harta benda Korporasi yang timbul dari hasil tindak pidana maka seluruh keuntungan tersebut disita untuk negara. Pasal 34O... REPUBUK INDONESIA"}, {"l": "UU 20/2025", "p": "340", "b": "Bagian Kesembilan", "t": "(1) Korporasi yang dikenai pidana tambahan berupa ganti rugi atau Restitusi, tata cara pelaksanaannya dilakukan sesuai dengan ketentuan peraturan perundang-undangan. (21 Dalam hal Korporasi dikenai pidana tambahan berupa ganti rugi atau Restitusi, pembayaran ganti rugi atau Restitusi dibayarkan dalam jangka waktu paling lama 1 (satu) bulan sejak putusan berkekuatan hukum tetap (3) Dalam hal terdapat alasan kuat, jangka waktu sebagaimana tersebut pada ayat (21 dapat diperpanjang untuk paling lama 1 (satu) bulan. (4) Dalam hal Korporasi tidak membayar ganti rugi atau Restitusi sebagaimana dimaksud pada ayat (2) dan ayat (3), harta benda Korporasi disita oleh Jaksa atas bin ketua pengadilan negeri dan dilelang dengan bantuan kantor lelang negara untuk membayar ganti rugi atau Restitusi."}, {"l": "UU 20/2025", "p": "341", "b": "Bagian Kesembilan", "t": "Ketentuan lebih lanjut mengenai tata cara pengenaan pidana tambahan terhadap Korporasi sebagaimana dimaksud dalam Pasal 338 sampai dengan Pasal 340 diatur dalam Peraturan Pemerintah."}, {"l": "UU 20/2025", "p": "342", "b": "BAB XIX PELAKSANAAN PUTUSAN PENGADILAN", "t": "(1) Pelalsanaan Putusan Pengadilan yang telah memperoleh kekuatan hukum tetap dilakukan oleh Penuntut Umum. (21 Salinan putusan sebagaimana dimaksud pada ayat (1) dikirim panitera kepada Penuntut Umum, Penyidik, pelapor/Korban/Keluarga Korban/Advokat Korban, secara elektronik dan/atau secara langsung. Pasal 343... REPUEUK INDONESIA"}, {"l": "UU 20/2025", "p": "343", "b": "BAB XIX PELAKSANAAN PUTUSAN PENGADILAN", "t": "Penjatuhan pidana pokok, pidana tambahan, dan pidana yang bersifat khusus terhadap Terpidana orang- perseorangan dan Korporasi, dilaksanakan sesuai dengan ketentuan peraturan perundang-undangan."}, {"l": "UU 20/2025", "p": "344", "b": "BAB XIX PELAKSANAAN PUTUSAN PENGADILAN", "t": "(1) Jika Terpidana dipidana penjara dan kemudian dijatuhi pidana yang sejenis sebelum Terpidana menjalani pidana yang dijatuhkan terdahulu, pidana tersebut dijalankan berturut-turut dimulai dengan pidana yang dijatuhkan lebih dahulu. l2l Pelaksanaan Pidana Penjara dilakukan di lembaga pemasyarakatan yang menyelenggarakan sistem dan fungsi pemasyarakatan. (3) Pembimbing Kemasyarakatan melakukan pembinaan terhadap narapidana."}, {"l": "UU 20/2025", "p": "345", "b": "BAB XIX PELAKSANAAN PUTUSAN PENGADILAN", "t": "(1) Jika Putusan Pengadilan menjatuhkan putusan pidana denda, Terpidana diberikan jangka waktu 1 (satu) bulan untuk membayar denda tersebut, kecuali dalam putusan acara pemeriksaan cepat yang harus seketika dilunasi. (21 Dalam hal terdapat alasan yang kuat, jangka waktu sebagaimana dimakud pada ayat (1) dapat diperpanjang untuk paling lama I (satu) bulan. (3) Jika Putusan Pengadilan menetapkan barang bukti dirampas untuk negzrra, selain pengecualian sebagaimana dimaksud dalam Pasal 130, Penuntut Umum menguasakan benda tersebut kepada kantor lelang negara dan dalam waktu 3 (tiga) bulan dilelang yang hasilnya dimasukkan ke kas negara sebagai hasil penegakan hukum. (41 Dalam hal pengadilan menetapkan putusan mengenai pemulihan aset kepada Korban atau yang berhak, Penuntut Umum harus segera melakukan pengembalian aset yang telah dirampas sesuai dengan ketentuan peraturan perundang-undangan dalam jangka waltu 3 (tiga) bulan. (5) Jangka. . . -t76- (5) Jangka waktu sebagaimana dimaksud pada ayat (3) dan ayat (4) dapat diperpanjang untuk paling lama I (satu) bulan."}, {"l": "UU 20/2025", "p": "346", "b": "BAB XIX PELAKSANAAN PUTUSAN PENGADILAN", "t": "(1) Terpidana dapat mengajukan permohonan angsur€rn pidana denda paling lama 6 (enam) bulan sejak putusan memperoleh kekuatan hukum tetap. (21 Dalam hal denda tidak dibayar dalam jangka waktu sebagaimana dimaksud pada ayat (1), jaksa melakukan: a. Penyitaan harta benda atau pendapatan Terpidana atas izin ketua pengadilan negeri; b. pelelangan barang sitaan dengan bantuan kantor lelang negara; dan/ atau c. pengajuan pidana pengganti sesuai ketentuan Kitab Undang-Undang Hukum Pidana. (3) Harta benda milik Terpidana yang tidak dapat disita meliputi barang yang diperlukan untuk hidup layak dan bekerja, sebagaimana diatur dalam ketentuan peraturan perundang-undangan. (4) Ketentuan lebih lanjut mengenai tata cara eksekusi pidana denda diatur dengan Peraturan Pemerintah."}, {"l": "UU 20/2025", "p": "347", "b": "BAB XIX PELAKSANAAN PUTUSAN PENGADILAN", "t": "(1) Dalam hal pengadilan menjatuhkan juga putusan ganti rugi, pelaksanaannya dilakukan sesuai dengan ketentuan mengenai pelalsanaan pidana denda secara mutatis mutandis. (21 Penuntut Umum wajib menyerahkan ganti rrgi sebagaimana dimaksud pada ayat (1) kepada Korban paling lama 1 (satu) Hari setelah ganti rugi diterima."}, {"l": "UU 20/2025", "p": "348", "b": "BAB XIX PELAKSANAAN PUTUSAN PENGADILAN", "t": "Jika dalam satu perkara Terpidana lebih dari 1 (satu) orang, biaya perkara dan/ atau Ganti Rugi dibebankan kepada Terpidana bersama-sama secara berimbang. Pasal 349... REPUELIK INDONESIA"}, {"l": "UU 20/2025", "p": "349", "b": "BAB XIX PELAKSANAAN PUTUSAN PENGADILAN", "t": "(1) Dalam hal pengadilan menjatuhkan putusan pidana pengawasan, pelaksanaan putusan pidana pengawasan dilakukan oleh Jaksa dan pembimbingan terhadap Terpidana dilakukan oleh Pembimbing Kemasyarakatan sesuai dengan ketentuan peraturan perundang-undangan. (21 Dalam hal pengadilan menjatuhkan putusan pidana kerja sosial, pelaksanaan putusan pidana kerja sosial dilakukan oleh Jaksa dan pembimbingan terhadap Terpidana dilakukan oleh Pembimbing Kemasyarakatan sesuai dengan ketentuan peraturan perundang-undangan. (3) Dalam hal pengadilan menjatuhkan putusan tindakan, pelaksanaan putusan tindakan dilakukan oleh Jaksa dan pembimbingan terhadap Terpidana dilakukan oleh Pembimbing Kemasyarakatan atau lembaga lain sesuai dengan ketentuan peraturan perundang-undangan."}, {"l": "UU 20/2025", "p": "350", "b": "BAB XIX PELAKSANAAN PUTUSAN PENGADILAN", "t": "(1) Dalam hal pengadilan menjatuhkan putusan pencabutan hak tertentu terhadap Terpidana, lembaga terkait wajib melaksanakan putusan tersebut tanpa terkecuali sesuai dengan ketentuan peraturan perundang-undangan. l2l Salinan putusan sebagaimana dimaksud pada ayat (l) dikirim panitera kepada lembaga terkait secara elektronik dan/ atau secara langsung."}, {"l": "UU 20/2025", "p": "351", "b": "BAB XIX PELAKSANAAN PUTUSAN PENGADILAN", "t": "(1) Dalam hal pengadilan menjatuhkan putusan pidana tambahan berupa pemenuhan kewajiban adat, pelalsanaan pemenuhan kewajiban adat dilakukan sesuai dengan ketentuan peraturan perundang- undangan. (2) Dalam hal pemenuhan kewajiban adat tidak terpenuhi, Terpidana wajib membayar ganti rugi. (3) Ganti rugi dalam rangka tidak terpenuhinya ketentuan sebagaimana dimaksud pada ayat (2) wajib dibayarkan dalam jangka waktu 3 (tiga) bulan. (4) Pembayaran . . . REPUBUK INDONESIA -t7a- (4) Pembayaran ganti rugi tersebut harus dibuat secara tertulis dalam bentuk berita acara serah terima ditandatangani oleh Terpidana dan perwakilan adat serta disaksikan minimal oleh 2 (dua) orang saksi."}, {"l": "UU 20/2025", "p": "352", "b": "BAB XIX PELAKSANAAN PUTUSAN PENGADILAN", "t": "(l) Dalam hal pengadilan menjatuhkan putusan pidana tambahan kepada Korporasi, pelaksanaan pidana tambahan dilaksanakan sesuai dengan ketentuan peraturan perundang-undangan. (21 Dalam hal pelaksanaan pidana tambahan oleh Korporasi tidak terpenuhi, Penuntut Umum dapat menyita kekayaan atau pendapatan Korporasi dan melakukan pelelangan atas izin ketua pengadilan dengan bantuan kantor lelang negara dalam waktu 3 (tiga) bulan. (3) Hasil pelelangan sebagaimana dimaksud pada ayat (2) dimasukkan ke kas negara. (41 Jangka waktu sebagaimana dimaksud pada ayat (21 dapat diperpanjang untuk paling lama I (satu) bulan."}, {"l": "UU 20/2025", "p": "353", "b": "BAB XX PENGAWASAN DAN PENGAMATAN PELAKSANAAN PUTUSAN PENGADILAN", "t": "(1) Setiap pengadilan harus ada paling sedikit 3 (tiga) Hakim yang diberi tugas khusus untuk membantu ketua dalam melakukan pengawasan dan pengamatan terhadap Putusan Pengadilan yang menjatuhkan pidana berupa pidana pokok, pidana tambahan, pidana yang bersifat khusus, dan tindakan yang ditentukan dalam Undang-Undang. (21 Hakim sebagaimana dimaksud pada ayat (1) disebut Hakim pengawas dan pengamat. (3) Hakim sebagaimana dimaksud pada ayat (2) ditunjuk oleh ketua pengadilan untuk jangka waktu paling lama 2 (dua) tahun. (4) Hakim. . . R,EPUBUK INOONESIA -t79- (41 Hakim sebagaimana dimaksud pada ayat (1) melibatkan pihak lain yang ada kaitannya dengan proses penegakan hukum meliputi: a Penyidik; b Advokat, selaku yang mewakili kepentingan Terpidana dan Keluarga Terpidana; c. Pembimbing Kemasyarakatan ; d. Korban tindak pidana; dan e. kementerian yang urusan pemerintahan di bidang keuangan, sebagai bendahara negara, kuasa pelalsana penilai, dan pelelang, dalam hal Putusan Pengadilan menetapkan perampasan barang sitaan diserahkan pada negara."}, {"l": "UU 20/2025", "p": "354", "b": "BAB XX PENGAWASAN DAN PENGAMATAN PELAKSANAAN PUTUSAN PENGADILAN", "t": "(l) Berita acara pelaksanaan Putusan Pengadilan ditandatangani oleh: a. Jaksa yang menangani perkara; b. kepala lembaga pemasyarakatan; dan c. Terpidana. l2l Jaksa tembusan berita acara sebagaimana dimaksud pada ayat (l) kepada: a. pengadilan yang memutus perkara pada tingkat pertama; b. Penyidik; c. Advokat selaku yang mewakili kepentingan Terpidana atau Keluarga Terpidana; dan d. Korban tindak pidana. (3) Panitera mencatat berita acara sebagaimana dimaksud pada ayat l2l dalam register pengawasan dan pengamatan."}, {"l": "UU 20/2025", "p": "355", "b": "BAB XX PENGAWASAN DAN PENGAMATAN PELAKSANAAN PUTUSAN PENGADILAN", "t": "Register pengawasan dan pengamatan sebagaimana dimaksud dalam Pasal 354 wajib dikerjakan, ditutup, dan ditandatangani oleh panitera pada setiap Hari kerja dan ditandatangani juga oleh Hakim sebagaimana dimaksud dalam Pasal 353. Pasal 356 . . . REPU3UK INDOHESIA"}, {"l": "UU 20/2025", "p": "356", "b": "BAB XX PENGAWASAN DAN PENGAMATAN PELAKSANAAN PUTUSAN PENGADILAN", "t": "(l) Hakim pengawas dan pengamat mengadakan pengawasan guna memperoleh kepastian bahwa Putusan Pengadilan dilaksanakan sebagaimana mestinya. (21 Hakim pengawas dan pengamat mengadakan pengamatan untuk bahan penelitian demi ketetapan yang bermanfaat bagi pemidanaan, yang diperoleh dari perilaku narapidana atau pembinaan lembaga pemasyarakatan, serta pengaruh timbal balik terhadap narapidana selama menjalani pidananya. (3) Pengamatan sebagaimana dimaksud pada ayat (2) tetap dilaksanakan setelah Terpidana selesai menjalani pidana. (4) Pengawasan dan pengamatan sebagaimana dimalsud dalam Pasal 353 berlaku bagi pemidanaan bersyarat."}, {"l": "UU 20/2025", "p": "357", "b": "BAB XX PENGAWASAN DAN PENGAMATAN PELAKSANAAN PUTUSAN PENGADILAN", "t": "Kepala lembaga pemasyarakatan menyampaikan kepada Hakim pengawas dan pengamat mengenai informasi secara berkala mengenai perilaku narapidana tertentu yang ada dalam pengamatan Hakim pengawas dan pengamat tersebut."}, {"l": "UU 20/2025", "p": "358", "b": "BAB XX PENGAWASAN DAN PENGAMATAN PELAKSANAAN PUTUSAN PENGADILAN", "t": "Jika dipandang perlu demi pendayagunaan pengamatan, Hakim pengawas dan pengamat dapat membicarakan dengan kepala lembaga pemasyarakatan mengenai cara pembinaan narapidana tertentu."}, {"l": "UU 20/2025", "p": "359", "b": "BAB XX PENGAWASAN DAN PENGAMATAN PELAKSANAAN PUTUSAN PENGADILAN", "t": "Hasil pengawasan dan pengamatan dilaporkan oleh Hakim pengawas dan pengamat kepada ketua pengadilan setiap 3 (tiga) bulan sekali. BABXXI ..."}, {"l": "UU 20/2025", "p": "360", "b": "BAB XXI SISTEM PERADILAN PIDANA BERBASIS TEKNOLOGI INFORMASI", "t": "(1) Penyelenggaraan peradilan pidana dilakukan melalui sistem peradilan pidana berbasis teknologi informasi. l2l Sistem peradilan pidana berbasis teknologi informasi sebagaimana dimaksud pada ayat (1) digunakan dalam Penyelidikan, Penyidikan, Penuntutan, peradilan, dan pemasyarakatan. (3) Sistem peradilan pidana berbasis teknologi informasi sebagaimana dimaksud pada ayat (l) digunakan dalam rangka memberikan informasi terkait dengan: a. penyelenggaraan peradilan pidana; b. penanganan Tersangka, Terdakwa, dan Terpidana; c. pelaksanaan Upaya Paksa; d. pemenuhan hak Korban; e. pelaksanaan penyelesaian perkara melalui mekanisme Keadilan Restoratif; f. statistik kriminal; g. Putusan Pengadilan; h. pelaksanaan Putusan Pengadilan; dan i. data lainnya berkaitan dengan penyelenggaraan sistem peradilan pidana terpadu. (4) Pemberian informasi sebagaimana dimaksud pada ayat (3) diberikan kepada Penyidik, Jaksa, Hakim, Advokat, dan Pembimbing Kemasyarakatan sesuai dengan peruntukannya. (5) Pemberian informasi sebagaimana dimalsud pada ayat (3) dan ayat (4) dilakukan dengan menjamin kerahasiaan identitas Saksi dan Korban. (6) Ketentuan lebih lanjut mengenai tata, cara penyelenggaraan sistem …"}, {"l": "UU 20/2025", "p": "361", "b": "BAB XXII KETENTUAN PERALIHAN", "t": "Pada saat Undang-Undang ini mulai berlaku: a. perkara tindak pidana yang sedang dalam proses Penyidikan atau Penuntutan, Penyidikan atau Penuntutannya diselesaikan berdasarkan ketentuan dalam Undang-Undang Nomor 8 Tahun 1981 tentang Hukum Acara Pidana (Lembaran Negara Republik Indonesia Tahun 1981 Nomor 76, Tambahan lrmbaran Negara Republik Indonesia Nomor 3209); b. perkara tindak pidana yang sudah terjadi sebelum berlakunya Undang-Undang ini tetapi proses Penyidikan atau Penuntutan belum dimulai, Penyidikan atau Penuntutannya dilakukan berdasarkan ketentuan dalam Undang-Undang ini; c. perkara tindak pidana yang sudah dilimpahkan ke pengadilan dan sudah dimulai proses pemeriksaannya tetap diperiksa, diadili, dan diputus berdasarkan ketentuan dalam Undang-Undang Nomor 8 Tahun l98l tentang Hukum Acara Pidana (Lembaran Negara kecuali untuk proses peninjauan kembali berlaku ketentuan dalam Undang-Undang ini; dan d. dalam hal perkara tindak pidana yang sudah dilimpahkan ke pengadilan tetapi proses pemeriksaan Terdakwa belum dimulai, perkara diperiksa, diadili, dan diputus berdasarkan ketentuan dalam Undang-Undang ini."}, {"l": "UU 20/2025", "p": "362", "b": "BAB XXIII KETENTUAN PENUTUP", "t": "Pada saat Undang-Undang ini mulai berlaku Undang- Undang Nomor 8 Tahun 1981 tentang Hukum Acara Pidana (Lembaran Negara Republik Indonesia Tahun 1981 Nomor 76, Tambahan Lembaran Negara Republik Indonesia Nomor 3209) dicabut dan dinyatakan tidak berlaku. Pasal 363... iITIiFITEtrN REFUBLIK INDONESIA"}, {"l": "UU 20/2025", "p": "363", "b": "BAB XXIII KETENTUAN PENUTUP", "t": "Pada saat Undang-Undang ini mulai berlaku semua ketentuan peraturan perundang-undangan yang mengatur mengenai kewenangan PPNS dan Penyidik Tertentu dinyatakan tetap berlaku sepanjang tidak bertentangan dengan ketentuan dalam Undang-Undang ini."}, {"l": "UU 20/2025", "p": "364", "b": "BAB XXIII KETENTUAN PENUTUP", "t": "Pada saat Undang-Undang ini mulai berlaku semua ketentuan peraturan perundang-undangan yang mengatur mengenai Upaya Paksa dinyatakan tetap berlaku sepanjang tidak bertentangan dengan ketentuan dalam Undang- Undang ini."}, {"l": "UU 20/2025", "p": "365", "b": "BAB XXIII KETENTUAN PENUTUP", "t": "Pada saat Undang-Undang ini mulai berlaku semua ketentuan peraturan perundang-undangan yang merupakan peraturan pelaksanaan dari Undang-Undang Nomor 8 Tahun 1981 tentang Hukum Acara Pidana (Lembaran Negara dinyatakan masih tetap berlaku sepanjang tidak bertentangan dengan ketentuan dalam Undang-Undang ini."}, {"l": "UU 20/2025", "p": "366", "b": "BAB XXIII KETENTUAN PENUTUP", "t": "Peraturan pelaksanaan dari Undang-Undang ini harus ditetapkan paling lama 1 (satu) tahun terhitung sejak Undang-Undang ini diundangkan."}, {"l": "UU 20/2025", "p": "367", "b": "BAB XXIII KETENTUAN PENUTUP", "t": "Seluruh ketentuan peraturan perundang-undangan terkait acara pidana yang bertentangan dengan Undang-Undang ini dinyatakan tidak berlaku, kecuali diatur dalam Undang-Undang."}, {"l": "UU 20/2025", "p": "368", "b": "BAB XXIII KETENTUAN PENUTUP", "t": "Undang-Undang ini dapat disebut dengan KUHAP."}, {"l": "UU 20/2025", "p": "369", "b": "BAB XXIII KETENTUAN PENUTUP", "t": "Undang-Undang ini muLai berlaku pada tanegal 2 Jarvari,2O26. Agar ELIK INDONESIA pengundangan Undang-Undang ini dengan penempatannya dalam Lembaran Negara Republik Indonesia. pada tanggal 17 Desember 2025 PRABOWO SUBIANTO pada tanggal 17 Desember 2025 PRASETYO HADI KEMENTERIAN SEKRETARIAT NEGARA Pemndang-undangan dan Hukum, vanna Djaman FRESIDEN"}, {"l": "UU 4/2023", "p": "1", "b": "BAB I KETENTUAN UMUM", "t": "Dalam Undang-Undang ini yang dimaksud dengan: 1. Sistem Keuangan adalah suatu kesatuan yang terdiri atas lembaga jasa keuangan, pasar keuangan, dan infrastruktur keuangan, termasuk sistem pembayaran, yang berinteraksi dalam memfasilitasi pengumpulan dana masyarakat dan pengalokasiannya untuk mendukung aktivitas perekonomian nasional, serta korporasi dan rumah tangga yang terhubung dengan lembaga jasa keuangan. 2. Stabilitas Sistem Keuangan adalah stabilitas Sistem Keuangan sebagaimana dimaksud dalam undang-undang mengenai pencegahan dan penanganan krisis sistem keuangan. 3. Dewan Perwakilan Rakyat yang selanjutnya disingkat DPR adalah Dewan Perwakilan Rakyat sebagaimana dimaksud dalam Undang-Undang Dasar Negara Republik Indonesia Tahun 1945. 4. Pemerintah Pusat yang selanjutnya disebut Pemerintah adalah Presiden Republik Indonesia yang memegang kekuasaan pemerintahan Negara Republik Indonesia yang dibantu oleh Wakil Presiden dan menteri sebagaimana dimaksud dalam Undang-Undang Dasar Negara Republik Indonesia Tahun 1945. 5. Menteri ... jdih.kemenkeu.go.id REPUBUK INDONESIA 5. Menteri adalah menteri yang menyelenggarakan urusan pemerintahan di bidang keuangan. 6. Otoritas Jasa …"}, {"l": "UU 4/2023", "p": "2", "b": "Bagian Kesatu", "t": "Undang-Undang ini dilaksanakan berdasarkan asas: a. kepentingan nasional; b. kemanfaatan; c. kepastian hukum; d. keterbukaan; e. akuntabilitas; ... jdih.kemenkeu.go.id REPUBUK INDONESIA . e. akuntabilitas; f. keadilan; g. Pelindungan Konsumen; h. edukasi; dan 1. keterpaduan."}, {"l": "UU 4/2023", "p": "3", "b": "Bagian Kedua", "t": "(1) Undang-Undang ini dibentuk dengan maksud mendorong kontribusi sektor keuangan bagi pertumbuhan ekonomi yang inklusif, berkelanjutan, dan berkeadilan guna meningkatkan taraf hidup masyarakat, mengurangi ketimpangan ekonomi, dan mewujudkan Indonesia yang sejahtera, maju, dan bermartabat. (2) Undang-Undang ini dibentuk dengan tujuan untuk: a. mengoptimalkan fungsi intermediasi sektor keuangan kepada usaha sektor produktif; b. meningkatkan portofolio pendanaan terhadap sektor usaha yang produktif; c. meningkatkan kemudahan akses dan literasi terkait jasa keuangan; d. meningkatkan dan memperluas inklusi sektor keuangan; e. memperluas sumber pembiayaan jangka panjang; f. meningkatkan daya saing dan efisiensi sektor keuangan; g. mengembangkan instrumen di pasar keuangan dan memperkuat mitigasi risiko; h. meningkatkan pembinaan, pengawasan, dan Pelindungan Konsumen; 1. memperkuat pelindungan atas data pribadi nasabah sektor keuangan; j. memperkuat ... jdih.kemenkeu.go.id PR.ESIDEN REPUBUK INDONESIA J. memperkuat kelembagaan dan ketahanan Stabilitas Sistem Keuangan; k. mengembangkan dan memperkuat ekosistem sektor keuangan; 1. memperkuat wewenang, tanggung jawab, tugas, dan fungsi …"}, {"l": "UU 4/2023", "p": "5", "b": "Bagian Kesatu", "t": "Dalam rangka pengembangan dan penguatan sektor keuangan melalui penataan kelembagaan otoritas sektor keuangan, Undang-Undang m1 mengubah, menghapus, dan/ atau menetapkan pengaturan baru beberapa ketentuan yang diatur dalam: a. Undang-Undang Nomor 9 Tahun 2016 tentang Pencegahan dan Penanganan Krisis Sistem Keuangan (Lembaran Negara Republik Indonesia Tahun 2016 Nomor 70, Tambahan Lembaran Negara Republik Indonesia Nomor 5872); b. Undang-Undang Nomor 24 Tahun 2004 tentang Lembaga Penjamin Simpanan (Lembaran Negara Republik Indonesia Tahun 2004 Nomor 96, Tambahan Lembaran Negara Republik Indonesia Nomor 4420) sebagaimana telah diubah dengan Undang-Undang Nomor 7 Tahun 2009 tentang Penetapan Peraturan Pemerintah Pengganti Undang-Undang Nomor 3 Tahun 2008 tentang Perubahan atas Undang-Undang Nomor 24 Tahun 2004 tentang Lembaga Penjamin Simpanan Menjadi Undang­ Undang (Lembaran Negara Republik Indonesia Tahun 2009 Nomor 8, Tambahan Lembaran Negara c. Undang-Undang Nomor 21 Tahun 2011 tentang Otoritas Jasa Keuangan (Lembaran Negara Republik Indonesia Tahun 2011 Nomor 111, Tambahan Lembaran Negara d. Undang-Undang ... jdih.kemenkeu.go.id REPUBUK INDONESIA d. Undang-Undang Nomor 23 Tahun …"}, {"l": "UU 4/2023", "p": "4", "b": "Bagian Kedua", "t": "(1) Berdasarkan undang-undang mengenai pencegahan dan penanganan krisis sistem keuangan dibentuk Komite Stabilitas Sistem Keuangan. (2) Komite Stabilitas Sistem Keuangan sebagaimana dimaksud pada ayat (1) menyelenggarakan pencegahan dan penanganan Krisis Sistem Keuangan untuk melaksanakan kepentingan dan ketahanan negara di bidang perekonomian. (3) Komite Stabilitas Sistem Keuangan beranggotakan: a. Menteri Keuangan sebagai koordinator merangkap anggota dengan hak suara; b. Gubernur Bank Indonesia sebagai anggota dengan hak suara; c. Ketua Dewan Komisioner Otoritas Jasa Keuangan sebagai anggota dengan hak suara; dan d. Ketua ... jdih.kemenkeu.go.id REPUBUK INDONESIA d. Ketua Dewan Komisioner Lembaga Penjamin Simpanan sebagai anggota dengan hak suara. (4) Setiap anggota Komite Stabilitas Sistem Keuangan sebagaimana dimaksud pada ayat (3) bertindak untuk dan atas nama lembaga yang dipimpinnya sesuai dengan ketentuan peraturan perundang­ undangan. 3. Ketentuan Pasal 5 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "6", "b": "Bagian Kedua", "t": "Komite Stabilitas Sistem Keuangan berwenang: a. menetapkan keputusan mengenai tata kelola Komite Stabilitas Sistem Keuangan dan sekretariat Komite Stabilitas Sistem Keuangan; b. membentuk gugus tugas atau kelompok kerja untuk membantu pelaksanaan tugas Komite Stabilitas Sistem Keuangan; c. menetapkan kriteria dan indikator untuk penilaian kondisi Stabilitas Sistem Keuangan; d. melakukan penilaian terhadap kondisi Stabilitas Sistem Keuangan berdasarkan masukan dari setiap anggota Komite Stabilitas Sistem Keuangan, beserta data dan informasi pendukungnya; e. menetapkan langkah koordinasi untuk mencegah Krisis Sistem Keuangan dengan mempertimbangkan rekomendasi dan/ a tau kesepakatan dari anggota Komite Stabilitas Sistem Keuangan; f. merekomendasikan ... jdih.kemenkeu.go.id REPUBUK INDONESIA f. merekomendasikan kepada Presiden untuk memutuskan perubahan status Stabilitas Sistem Keuangan, dari kondisi normal menjadi kondisi Krisis Sistem Keuangan atau dari kondisi Krisis Sistem Keuangan menjadi kondisi normal; g. merekomendasikan kepada Presiden untuk memutuskan langkah penanganan Krisis Sistem Keuangan; h. mengoordinasikan langkah yang harus dilakukan oleh anggota Komite Stabilitas …"}, {"l": "UU 4/2023", "p": "7", "b": "Bagian Kedua", "t": "(1) Dalam menjalankan tugas sebagaimana dimaksud dalam Pasal 5 dan wewenang sebagaimana dimaksud dalam Pasal 6, Komite Stabilitas Sistem Keuangan dibantu oleh sekretariat Komite Stabilitas Sistem Keuangan yang dipimpin oleh sekretaris Komite Stabilitas Sistem Keuangan. (2) Sekretaris Komite Stabilitas Sistem Keuangan sebagaimana dimaksud pada ayat (1) merupakan pejabat eselon I Kementerian Keuangan. (3) Organisasi dan tata kerja sekretariat Komite Stabilitas Sistem Keuangan ditetapkan oleh Menteri Keuangan sesuai dengan ketentuan peraturan perundang-undangan. (4) Dalam rangka mendukung pelaksanaan tugas dan wewenang Komite Stabilitas Sistem Keuangan, sekretariat Komite Stabilitas Sistem Keuangan melakukan analisis, riset, dan/ a tau asesmen Stabilitas Sistem Keuangan. (5) Dalam ... jdih.kemenkeu.go.id PRESIOEN REPUBUK INDONESIA . (5) Dalam melakukan analisis, riset, dan/atau asesmen Stabilitas Sistem Keuangan sebagaimana dimaksud pada ayat (4), sekretariat Komite Stabilitas Sistem Keuangan: a. menggunakan data dan informasi dari sarana pertukaran informasi secara terintegrasi sebagaimana dimaksud dalam undang-undang mengenai Otoritas Jasa Keuangan; dan b. mendapatkan akses atas …"}, {"l": "UU 4/2023", "p": "8A", "b": "Bagian Kedua", "t": "Selain rapat secara berkala atau sewaktu-waktu sebagaimana dimaksud dalam Pasal 8, Komite Stabilitas Sistem Keuangan dapat menyelenggarakan rapat koordinasi dalam rangka pemantauan dan pemeliharaan Stabilitas Sistem Keuangan. 7. Ketentuan Pasal 9 diubah sehingga berbunyi sebagai berikut: Pasal9 (1) Rapat Komite Stabilitas Sistem Keuangan harus dihadiri oleh seluruh anggota Komite Stabilitas Sistem Keuangan secara fisik dan/ atau secara virtual. (2) Rapat ... jdih.kemenkeu.go.id . REPUBUK INDONESIA . (2) Rapat Komite Stabilitas Sistem Keuangan dipimpin oleh koordinator Komite Stabilitas Sistem Keuangan. (3) Pengambilan keputusan Komite Stabilitas Sistem Keuangan dilakukan dalam rapat Komite Stabilitas Sistem Keuangan secara musyawarah untuk mufakat. (4) Dalam hal musyawarah untuk mufakat sebagaimana dimaksud pada ayat (3) tidak tercapai, pengambilan keputusan dilakukan berdasarkan suara terbanyak. (5) Dalam hal pengambilan keputusan berdasarkan suara terbanyak sebagaimana dimaksud pada ayat (4) tidak tercapai, Menteri Keuangan sebagai koordinator Komite Stabilitas Sistem Keuangan mengambil keputusan atas nama Komite Stabilitas Sistem Keuangan. (6) Keputusan Komite Stabilitas Sistem …"}, {"l": "UU 4/2023", "p": "34A", "b": "Bagian Kedua", "t": "Dalam hal Presiden memutuskan kondisi Krisis Sistem Keuangan sebagaimana dimaksud dalam Pasal 34, Dewan Komisioner Otoritas Jasa Keuangan, dan Ketua Dewan Komisioner Lembaga Penjamin Simpanan bersama-sama melaksanakan langkah penanganan Krisis Sistem Keuangan."}, {"l": "UU 4/2023", "p": "3A", "b": "Bagian Ketiga", "t": "Lembaga Penjamin Simpanan bertujuan menjamin dan melindungi dana masyarakat yang ditempatkan pada Bank serta Perusahaan Asuransi dan Perusahaan Asuransi Syariah. 4. Ketentuan Pasal 4 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "10A", "b": "Bagian Ketiga", "t": "(1) Dalam rangka melaksanakan kebijakan Penjaminan, Lembaga Penjamin Simpanan dapat menjamin Simpanan untuk kelompok nasabah. (2) Ketentuan mengenai Penjaminan kelompok nasabah sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Pemerintah setelah dikonsultasikan dengan DPR. 9. Ketentuan ... jdih.kemenkeu.go.id REPUBUK INDONESIA 9. Ketentuan Pasal 14 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "14", "b": "Bagian Ketiga", "t": "(1) Penghitungan premi Penjaminan dilakukan sendiri oleh Bank. (2) Perhitungan premi oleh Bank sebagaimana dimaksud pada ayat (1) menjadi final setelah melewati jangka waktu 10 (sepuluh) tahun. (3) Lembaga Penjamin Simpanan dapat melakukan verifikasi atas perhitungan premi oleh Bank sebelum jangka waktu 10 (sepuluh) tahun sebagaimana dimaksud pada ayat (2). (4) Verifikasi yang dilakukan oleh Lembaga Penjamin Simpanan atas perhitungan premi sebagaimana dimaksud pada ayat (3) dapat dilakukan melalui pemeriksaan dokumen, pemanggilan pejabat Bank yang bersangkutan, dan/atau pemeriksaan langsung pada Bank. (5) Dalam hal dilakukan verifikasi oleh Lembaga Penjamin Simpanan, hasil verifikasi premi dimaksud merupakan perhitungan premi final. (6) Dalam hal terdapat perbedaan hasil perhitungan premi oleh Bank sebagaimana dimaksud pada ayat (2) dengan hasil verifikasi Lembaga Penjamin Simpanan sebagaimana dimaksud pada ayat (5), Bank wajib melakukan penyesuaian jumlah premi pada saat pembayaran premi periode berikutnya. 10. Di antara Pasal 14 dan Pasal 15 disisipkan 1 (satu) pasal, yakni Pasal 14A sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "14A", "b": "Bagian Ketiga", "t": "Dalam melakukan penghitungan premi Penjaminan, Lembaga Penjamin Simpanan memperhitungkan dana yang ditempatkan oleh Pemerintah pada Bank dalam rangka kebijakan penanganan permasalahan perekonomian nasional dalam kondisi krisis. 11. Penjelasan Pasal 16 diubah sebagaimana tercantum dalam penjelasan. 12. Ketentuan . . . jdih.kemenkeu.go.id REPUBUK INOONESIA . 12. Ketentuan Pasal 17 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "17", "b": "Bagian Ketiga", "t": "(1) Pembayaran klaim Penjaminan dapat dilakukan secara tunai dan/ a tau dengan alat pembayaran lain yang setara dengan itu. (2) Setiap pembayaran klaim Penjaminan sebagaimana dimaksud pada ayat (1) dilakukan dalam mata uang Rupiah. (3) Klaim Penjaminan dari Simpanan dalam mata uang asing dibayarkan dalam bentuk ekuivalen Rupiah berdasarkan kurs yang diterbitkan Bank Indonesia. (4) Ketentuan lebih lanjut mengenai alat pembayaran lain sebagaimana dimaksud pada ayat (1) dan kurs sebagaimana dimaksud pada ayat (3) diatur dalam Peraturan Lembaga Penjamin Simpanan. 13. Ketentuan Pasal 18 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "18", "b": "Bagian Ketiga", "t": "(1) Dalam hal Nasabah Penyimpan pada saat yang bersamaan mempunyai kewajiban kepada Bank, pembayaran klaim Penjaminan dilakukan setelah Lembaga Penjamin Simpanan melakukan perjumpaan utang antara kewajiban Nasabah Penyimpan kepada Bank dan Simpanan nasabah yang bersangkutan sesuai dengan persyaratan yang ditetapkan oleh Lembaga Penjamin Simpanan. (2) Ketentuan mengenai perjumpaan utang sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Lembaga Penjamin Simpanan. 14. Penjelasan Pasal 19 diubah sebagaimana tercantum dalam penjelasan. 15. Ketentuan ... jdih.kemenkeu.go.id REPUBUK INDONESIA 15. Ketentuan Pasal 20 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "20", "b": "Bagian Ketiga", "t": "(1) Dalam hal Nasabah Penyimpan sebagaimana dimaksud dalam Pasal 19 ayat (1) keberatan terhadap keputusan penetapan Simpanan tidak layak dibayar, Nasabah Penyimpan dapat mengajukan keberatan kepada Lembaga Penjamin Simpanan yang didukung dengan bukti nyata danjelas paling lama 180 (seratus delapan puluh) hari kalender terhitung sejak keputusan diumumkan. (2) Dalam hal keberatan tidak diajukan sesuai jangka waktu sebagaimana dimaksud pada ayat (1), Nasabah Penyimpan dianggap telah menerima keputusan penetapan Simpanan tidak layak dibayar. (3) Dalam hal Nasabah Penyimpan mengajukan keberatan sebagaimana dimaksud pada ayat (1), Lembaga Penjamin Simpanan memberikan keputusan atas keberatan yang diajukan oleh Nasabah Penyimpan dalam jangka waktu 180 (seratus delapan puluh) hari kalender. (4) Nasabah Penyimpan dapat mengajukan upaya hukum melalui pengadilan terhadap keputusan atas keberatan sebagaimana dimaksud pada ayat (3) paling lama 180 (seratus delapan puluh) hari kalender terhitung sejak tanggal pemberitahuan surat keputusan atas penanganan keberatan. (5) Dalam hal Lembaga Penjamin Simpanan menerima keberatan sebagaimana dimaksud pada ayat (1) atau putusan pengadilan mengabulkan …"}, {"l": "UU 4/2023", "p": "22", "b": "Bagian Ketiga", "t": "(1) Penyelesaian a tau penanganan Bank Dalam Resolusi dilakukan oleh Lembaga Penjamin Simpanan dengan cara sebagai berikut: a. penyelesaian Bank selain Bank Sistemik yang ditetapkan sebagai Bank Dalam Resolusi dilakukan dengan melakukan penyelamatan atau tidak melakukan penyelamatan terhadap Bank Dalam Resolusi; atau b. penanganan Bank Sistemik yang ditetapkan sebagai Bank Dalam Resolusi dilakukan dengan melakukan penyelamatan yang mengikutsertakan pemegang saham lama atau tanpa mengikutsertakan pemegang saham lama. (2) Pemilihan penyelesaian atau penanganan Bank Dalam Resolusi sebagaimana dimaksud pada ayat (1) dilakukan berdasarkan pertimbangan: a. perkiraan biaya resolusi; dan b. faktor lain yang meliputi: 1. kondisi perekonomian; 2. kompleksitas kondisi permasalahan Bank; 3. pangsa pasar Bank terhadap sistem perbankan; 4. kebutuhan waktu penanganan; 5. ketersediaan investor; 6. efektivitas penanganan permasalahan Bank; dan/ atau 7. kondisi lainnya. (3) Ketentuan lebih lanjut mengenai penyelesaian atau penanganan Bank Dalam Resolusi sebagaimana dimaksud pada ayat (1) dan ayat (2) diatur dalam Peraturan Lembaga Penjamin Simpanan. 18. Ketentuan . . . jdih.kemenkeu.go.id REPUBUK …"}, {"l": "UU 4/2023", "p": "24", "b": "Bagian Ketiga", "t": "(1) Lembaga Penjamin Simpanan melakukan penyelamatan Bank selain Bank Sistemik yang ditetapkan sebagai Bank Dalam Resolusi dalam hal pertimbangan sebagaimana dimaksud dalam Pasal 22 ayat (2) telah terpenuhi. (2) Pemegang saham, anggota direksi, dan anggota dewan komisaris serta pegawai dan mantan pegawai Bank selain Bank Sistemik yang ditetapkan sebagai Bank Dalam Resolusi wajib untuk setiap saat memberikan segala data dan informasi yang diperlukan oleh Lembaga Penjamin Simpanan. 19. Ketentuan Pasal 25 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "25", "b": "Bagian Ketiga", "t": "Terhitung sejak Lembaga Penjamin Simpanan menerima pemberitahuan tertulis atas penetapan Bank selain Bank Sistemik sebagai Bank Dalam Resolusi dari Otoritas Jasa Keuangan, Lembaga Penjamin Simpanan mengambil alih hak dan wewenang RUPS, kepemilikan, kepengurusan, dan kepentingan lain pada Bank. 20. Ketentuan Pasal 26 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "26", "b": "Bagian Ketiga", "t": "(1) Setelah Lembaga Penjamin Simpanan mengambil alih hak dan wewenang RUPS, kepemilikan, kepengurusan, dan kepentingan lain pada Bank sebagaimana dimaksud dalam Pasal 25, Lembaga Penjamin Simpanan dapat melakukan tindakan: a. menguasai, mengelola, dan melakukan tindakan kepemilikan atas aset milik atau yang menjadi hak Bank dan/ atau kewajiban Bank; b. melakukan penyertaan modal sementara; c. menjual ... jdih.kemenkeu.go.id c. menjual atau mengalihkan aset Bank tanpa persetujuan Nasabah Debitur dart/ atau kewajiban Bank tanpa persetujuan nasabah kreditur; d. mengalihkan manajemen Bank kepada pihak lain; e. melakukan penggabungan atau peleburan dengan Bank lain; f. melakukan pengalihan kepemilikan Bank; dan/atau g. meninjau ulang, membatalkan, mengakhiri, dan/ a tau mengubah kontrak Bank yang mengikat Bank dengan pihak ketiga, yang menurut Lembaga Penjamin Simpanan merugikan Bank. (2) Ketentuan lebih lanjut mengenai tindakan Lembaga Penjamin Simpanan sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Lembaga Penjamin Simpanan. 21. Ketentuan Pasal 28 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "28", "b": "Bagian Ketiga", "t": "(1) Dalam hal ekuitas Bank bernilai positif pada saat Lembaga Penjamin Simpanan menerima pemberitahuan tertulis atas penetapan Bank selain Bank Sistemik sebagai Bank Dalam Resolusi dari Otoritas Jasa Keuangan sebagaimana dimaksud dalam Pasal 25, PSP lama mendapatkan bagian dari hasil penjualan saham Bank yang telah diselamatkan sebesar proporsional kepemilikan PSP terhadap ekuitas Bank pada saat Lembaga Penjamin Simpanan menerima pemberitahuan tertulis. (2) Dalam hal ekuitas bank bemilai nol atau negatif pada saat Lembaga Penjamin Simpanan menerima pemberitahuan tertulis atas penetapan Bank selain Bank Sistemik sebagai Bank Dalam Resolusi dari Otoritas Jasa Keuangan sebagaimana dimaksud dalam Pasal 25, PSP lama tidak memiliki hak atas hasil penjualan saham Bank setelah penyelamatan. 22. Ketentuan ... jdih.kemenkeu.go.id . REPUBUK INDONESIA 22. Ketentuan Pasal 29 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "29", "b": "Bagian Ketiga", "t": "(1) Penggunaan hasil penjualan saham Bank sebagaimana dimaksud dalam Pasal 28 ayat (1) dilakukan dengan urutan: a. pengembalian seluruh biaya penyelamatan yang telah dikeluarkan oleh Lembaga Penjamin Simpanan; dan b. pengembalian kepada PSP lama sebesar proporsional kepemilikan PSP lama terhadap ekuitas Bank pada saat Lembaga Penjamin Simpanan menerima pemberitahuan tertulis atas penetapan Bank selain Bank Sistemik sebagai Bank Dalam Resolusi dari Otoritas Jasa Keuangan sebagaimana dimaksud dalam"}, {"l": "UU 4/2023", "p": "30", "b": "Bagian Ketiga", "t": "(1) Lembaga Penjamin Simpanan wajib menjual seluruh saham yang dimiliki oleh Lembaga Penjamin Simpanan dan PSP lama Bank selain Bank Sistemik yang ditetapkan sebagai Bank Dalam Resolusi dalam jangka waktu paling lama 3 (tiga) tahun terhitung sejak Lembaga Penjamin Simpanan menetapkan untuk menyelamatkan Bank Dalam Resolusi. (2) Penjualan saham sebagaimana dimaksud pada ayat (1) dilakukan secara terbuka dan transparan, dengan tetap mempertimbangkan tingkat (3) Tingkat ... jdih.kemenkeu.go.id REPUBUK INOONESIA (3) Tingkat pengembalian yang optimal sebagaimana dimaksud pada ayat (2) paling sedikit sebesar seluruh penempatan modal sementara yang dikeluarkan oleh Lembaga Penjamin Simpanan. (4) Dalam hal tingkat pengembalian yang optimal sebagaimana dimaksud pada ayat (2) dan ayat (3) tidak dapat diwujudkan dalam jangka waktu paling lama 3 (tiga) tahun, jangka waktu sebagaimana dimaksud pada ayat (1) dapat diperpanjang paling banyak 2 (dua) kali dengan masing-masing perpanjangan selama 1 (satu) tahun. (5) Dalam hal tingkat pengembalian yang optimal sebagaimana dimaksud pada ayat (2) dan ayat (3) tidak dapat diwujudkan dalam jangka waktu perpanjangan sebagaimana dimaksud pada ayat (4), …"}, {"l": "UU 4/2023", "p": "31", "b": "Bagian Ketiga", "t": "(1) Dalam hal Lembaga Penjamin Simpanan memutuskan untuk tidak melakukan penyelamatan atau tidak melanjutkan proses penyelamatan, Lembaga Penjamin Simpanan meminta pencabutan izin usaha Bank selain Bank Sistemik yang ditetapkan sebagai Bank Dalam Resolusi kepada Otoritas Jasa Keuangan sesuai dengan ketentuan peraturan perundang-undangan. (2) Lembaga Penjamin Simpanan melaksanakan pembayaran klaim Penjaminan kepada Nasabah Penyimpan Bank yang dicabut izin usahanya sebagaimana dimaksud pada ayat (1) sesuai dengan ketentuan dalam Undang-Undang ini. 2 5. Ketentuan . . . jdih.kemenkeu.go.id REPUBUK INDONESIA 25. Ketentuan Pasal 33 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "33", "b": "Bagian Ketiga", "t": "(1) Penanganan Bank Dalam Resolusi sebagaimana dimaksud dalam Pasal 32 hanya dapat dilakukan apabila pemegang saham Bank Dalam Resolusi telah menyetor modal paling sedikit 20% (dua puluh persen) dari perkiraan biaya penanganan. (2) Ketentuan lebih lanjut mengenai persyaratan penanganan Bank Dalam Resolusi sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Lembaga Penjamin Simpanan. 26. Ketentuan Pasal 34 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "34", "b": "Bagian Ketiga", "t": "Terhitung sejak Lembaga Penjamin Simpanan menerima pemberitahuan tertulis atas penetapan Bank Sistemik sebagai Bank Dalam Resolusi dari Otoritas Jasa Keuangan, berdasarkan Undang-Undang ini: a. segala hak dan wewenang RUPS, kepemilikan, kepengurusan, dan kepentingan lain pada Bank dimaksud beralih kepada Lembaga Penjamin Simpanan; dan b. pemegang saham dan pengurus Bank lama tidak dapat menuntut Lembaga Penjamin Simpanan atau pihak yang ditunjuk oleh Lembaga Penjamin Simpanan dalam rangka penanganan Bank Dalam Resolusi, sepanjang Lembaga Penjamin Simpanan dan/atau pihak yang ditunjuk Lembaga Penjamin Simpanan melakukan tugasnya dengan iktikad baik, sesuai dengan ketentuan peraturan perundang­ undangan dan tata kelola yang baik. 27. Ketentuan Pasal 35 diubah sehingga berbunyi sebagai berikut: Pasal35 (1) Dalam hal ekuitas Bank bernilai positif setelah PSP lama melakukan penyetoran modal sementara, Lembaga Penjamin Simpanan dan PSP lama menandatangani perjanjian yang mengatur penggunaan hasil penjualan saham Bank. (2) Dalam ... jdih.kemenkeu.go.id REPUBUK INDONESIA (2) Dalam bal ekuitas Bank bernilai nol atau negatif setelab PSP lama melakukan penyetoran modal, PSP lama tidak …"}, {"l": "UU 4/2023", "p": "37", "b": "Bagian Ketiga", "t": "(1) Lembaga Penjamin Simpanan bertanggung jawab atas kekurangan biaya penanganan Bank Dalam Resolusi setelab pemegang sabam lama melakukan penyetoran modal sebagaimana dimaksud dalam Pasal 33 ayat (1). (2) Biaya ... jdih.kemenkeu.go.id PRESIOEN REPUBUK INDONESIA (2) Biaya penanganan Bank Dalam Resolusi yang dikeluarkan oleh Lembaga Penjamin Simpanan menjadi penyertaan modal sementara Lembaga Penjamin Simpanan pada Bank. 30. Ketentuan Pasal 38 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "38", "b": "Bagian Ketiga", "t": "(1) Lembaga Penjamin Simpanan wajib menjual seluruh saham Bank yang dimiliki oleh Lembaga Penjamin Simpanan dan PSP lama Bank Sistemik yang ditetapkan sebagai Bank Dalam Resolusi paling lama 3 (tiga) tahun terhitung sejak Lembaga Penjamin Simpanan menetapkan untuk melakukan penanganan. (2) Penjualan saham sebagaimana dimaksud pada ayat (1) dilakukan secara terbuka dan transparan dengan tetap mempertimbangkan tingkat pengembalian yang optimal bagi Lembaga Penjamin Simpanan. (3) Tingkat pengembalian yang optimal sebagaimana dimaksud pada ayat (2) paling sedikit sebesar seluruh penempatan modal sementara yang dikeluarkan oleh Lembaga Penjamin Simpanan. (4) Dalam hal tingkat pengembalian yang optimal sebagaimana dimaksud pada ayat (2) dan ayat (3) tidak dapat diwujudkan dalam jangka waktu paling lama 3 (tiga) tahun, jangka waktu sebagaimana dimaksud pada ayat (1) dapat diperpanjang paling banyak 2 (dua) kali dengan masing-masing perpanjangan selama 1 (satu) tahun. (5) Dalam hal tingkat pengembalian yang optimal sebagaimana dimaksud pada ayat (2) dan ayat (3) tidak dapat diwujudkan dalam jangka waktu perpanjangan sebagaimana dimaksud pada ayat (4), Lembaga Penjamin Simpanan menjual …"}, {"l": "UU 4/2023", "p": "50A", "b": "Bagian Ketiga", "t": "(1) Dalam hal terdapat sengketa dalam proses likuidasi sebagaimana dimaksud dalam Pasal 50, gugatan diajukan kepada ketua pengadilan niaga dalam wilayah hukum tempat tinggal atau domisili tergugat. (2) Dalam hal salah satu pihak bertempat tinggal di luar wilayah Negara Kesatuan Republik Indonesia, gugatan diajukan kepada Ketua Pengadilan Niaga Jakarta Pusat. (3) Panitera ... jdih.kemenkeu.go.id REPUBUK INDONESIA (3) Panitera mendaftarkan gugatan pada tanggal gugatan diajukan dan kepada penggugat diberikan tanda terima yang ditandatangani oleh panitera pada tanggal yang sama dengan tanggal pendaftaran gugatan. (4) Panitera sebagaimana dimaksud pada ayat (3) menyampaikan gugatan kepada ketua pengadilan niaga sebagaimana dimaksud pada ayat (1) paling lama 2 (dua) hari kerja terhitung sejak tanggal gugatan didaftarkan. (5) Dalam jangka waktu paling lama 3 (tiga) hari kerja terhitung sejak tanggal gugatan disampaikan sebagaimana dimaksud pada ayat (4), ketua pengadilan niaga mempelajari gugatan dan menunjuk majelis hakim untuk menetapkan hari sidang. (6) Pemanggilan para pihak dilakukan oleh juru sita paling lama 7 (tujuh) hari kerja terhitung sejak gugatan didaftarkan. (7) Sidang …"}, {"l": "UU 4/2023", "p": "53", "b": "Bagian Ketiga", "t": "(1) Likuidasi Bank dilakukan dengan cara: a. pencairan aset dan/ atau penagihan piutang kepada para debitur diikuti dengan pembayaran kewajiban Bank kepada para kreditur dari hasil pencairan dan/ atau penagihan; dan/ atau b. pengalihan aset dan kewajiban Bank kepada pihak lain berdasarkan persetujuan Lembaga Penjamin Simpanan. (2) Ketentuan lebih lanjut mengenai pelaksanaan likuidasi Bank sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Lembaga Penjamin Simpanan. 35. Ketentuan Pasal 54 diubah sehingga berbunyi sebagai berikut: Pasal 54 ... jdih.kemenkeu.go.id REPUBUK INDONESIA"}, {"l": "UU 4/2023", "p": "54", "b": "Bagian Ketiga", "t": "(1) Pembayaran kewajiban Bank kepada para kreditur dari basil pencairan dan/ a tau penagiban sebagaimana dimaksud dalam Pasal 53 dilakukan dengan urutan sebagai berikut: a. penggantian atas talangan pembayaran gaji pegawai yang terutang; b. penggantian atas pembayaran talangan pesangon pegawai; c. biaya perkara di pengadilan, biaya lelang yang terutang, dan biaya operasional kantor; d. biaya penyelamatan yang dikeluarkan oleb Lembaga Penjamin Simpanan dan/ atau pembayaran atas klaim Penjaminan yang barus dibayarkan oleb Lembaga Penjamin Simpanan; e. pajak yang terutang; f. kewajiban kepada Bank Indonesia dalam rangka pinjaman likuiditas jangka pendek atau pembiayaan likuiditas jangka pendek berdasarkan Prinsip Syariah dan operasi moneter serta kewajiban kepada Lembaga Penjamin Simpanan dalam rangka penempatan dana Lembaga Penjamin Simpanan pada Bank; g. bagian Simpanan dari Nasabab Penyimpan yang tidak dibayarkan penjaminannya dan Simpanan dari Nasabab Penyimpan yang tidak dijamin; dan b. bak dari kreditur lainnya. (2) Segala biaya yang berkaitan dengan likuidasi dan tercantum dalam daftar biaya likuidasi menjadi beban aset Bank dalam likuidasi dan dikeluarkan terlebib dabulu dari …"}, {"l": "UU 4/2023", "p": "65", "b": "Bagian Ketiga", "t": "(1) Anggota Dewan Komisioner berjumlah 7 (tujuh) orang terdiri atas: a. 1 (satu) orang pejabat setingkat eselon I Kementerian Keuangan yang ditunjuk oleh b. 1 (satu) orang anggota Dewan Komisioner Otoritas Jasa Keuangan yang ditunjuk oleh Ketua Dewan Komisioner Otoritas Jasa Keuangan; c. 1 (satu) orang anggota Dewan Gubernur Bank Indonesia yang ditunjuk oleh Gubernur Bank Indonesia; dan d. 4 (empat) orang anggota yang berasal dari dalam dan/atau dari luar Lembaga Penjamin Simpanan. (2) Anggota Dewan Komisioner sebagaimana dimaksud pada ayat (1) huruf d terdiri atas: a. Ketua Dewan Komisioner merangkap anggota; b. Wakil Ketua Dewan Komisioner merangkap anggota; c. anggota Dewan Komisioner yang membidangi program Penjaminan dan resolusi Bank; dan d. anggota Dewan Komisioner yang membidangi program penjaminan polis. (3) Anggota Dewan Komisioner sebagaimana dimaksud pada ayat (1) huruf d dipilih oleh DPR berdasarkan calon anggota yang diusulkan oleh Presiden. (4) Untuk setiap jabatan sebagaimana dimaksud pada ayat (3), Presiden mengusulkan kepada DPR paling sedikit 2 (dua) calon. (5) Dalam rangka pengajuan calon anggota Dewan Komisioner Lembaga Penjamin Simpanan sebagaimana dimaksud …"}, {"l": "UU 4/2023", "p": "66", "b": "Bagian Ketiga", "t": "(1) Anggota Dewan Komisioner sebagaimana dimaksud dalam Pasal 65 ayat (1) diangkat untuk masajabatan 5 (lima) tahun dan hanya dapat diangkat kembali untuk 1 (satu) kali untuk masa jabatan berikutnya. (2) Anggota Dewan Komisioner sebagaimana dimaksud dalam Pasal 65 ayat (1) huruf d melakukan tugas secara penuh waktu dan tidak diperbolehkan menduduki jabatan eksekutif di tempat lain, kecuali merupakan penugasan sehubungan dengan jabatan yang dipegang atau merupakan bagian dari kegiatan sosial. 42. Ketentuan Pasal 67 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "67", "b": "Bagian Ketiga", "t": "Calon anggota Dewan Komisioner harus memenuhi persyaratan sebagai berikut: a. warga negara Indonesia; b. memiliki akhlak, moral, dan integritas yang baik; c. cakap melakukan perbuatan hukum; d. tidak pernah dinyatakan pailit atau tidak pernah menjadi pengurus perusahaan yang menyebabkan perusahaan tersebut pailit; e. sehat jasmani; f. berusia ... jdih.kemenkeu.go.id f. berusia paling tinggi 65 (enam puluh lima) tahun pada saat ditetapkan; g. mempunyai pengalaman atau keahlian di sektor jasa keuangan; h. tidak pernah dijatuhi pidana penjara berdasarkan putusan pengadilan yang telah memperoleh kekuatan hukum tetap karena melakukan tindak pidana yang diancam dengan hukuman 5 (lima) tahun atau lebih; 1. bukan sebagai konsultan, pegawai, pengurus, dan/ atau pemilik Bank atau Perusahaan Asuransi dan Perusahaan Asuransi Syariah baik langsung maupun tidak langsung; j. bukan pengurus dan/atau anggota partai politik saat pencalonan; dan k. tidak dinyatakan sebagai orang perseorangan yang tercela di bidang perbankan dan jasa keuangan lainnya berdasarkan ketentuan peraturan perundang-undangan. 43. Ketentuan Pasal 69 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "69", "b": "Bagian Ketiga", "t": "(1) Anggota Dewan Komisioner hanya dapat diberhentikan oleh Presiden apabila: a. berhalangan tetap; b. masa jabatannya berakhir; c. mengundurkan diri; d. tidak hadir dalam rapat Dewan Komisioner sebanyak 4 (empat) kali berturut-turut tanpa alasan; e. tidak menjalankan tugasnya sebagai anggota Dewan Komisioner lebih dari 6 (enam) bulan meskipun dengan alasan yang dapat dipertimbangkan; f. memiliki hubungan keluarga sampai dengan derajat kedua atau besan dengan anggota Dewan Komisioner yang lain, dan tidak ada satupun yang mengundurkan diri; atau g. tidak ... jdih.kemenkeu.go.id g. tidak lagi memenuhi syarat sebagaimana dimaksud dalam Pasal 67. (2) Anggota Dewan Komisioner sebagaimana dimaksud dalam Pasal 65 ayat (1) huruf a, huruf b, dan huruf c diberhentikan dari jabatannya karena alasan sebagaimana dimaksud pada ayat (1) atau tidak lagi menjadi pejabat setingkat eselon I di Kementerian Keuangan, anggota Dewan Komisioner Otoritas Jasa Keuangan, atau anggota Dewan Gubernur Bank Indonesia. (3) Pemberhentian sebagaimana dimaksud pada ayat (1) dan ayat (2) ditetapkan dengan Keputusan Presiden. (4) Pemberhentian anggota Dewan Komisioner dan pengusulan anggota yang baru harus dilakukan …"}, {"l": "UU 4/2023", "p": "71", "b": "Bagian Ketiga", "t": "(1) Dewan Komisioner wajib mengadakan rapat secara berkala paling sedikit 1 (satu) bulan sekali dengan agenda yang memuat: a. menetapkan kebijakan Penjaminan dan penjaminan polis berdasarkan Undang-Undang ini; b. menetapkan ... jdih.kemenkeu.go.id . REPUDLIK INDONESIA b. menetapkan kebijakan Lembaga Penjamin Simpanan dalam rangka turut aktif memelihara Stabilitas Sistem Keuangan sesuai dengan kewenangannya; c. menetapkan kebijakan resolusi Bank dan penyelesaian permasalahan Perusahaan Asuransi dan Perusahaan Asuransi Syariah yang dicabut izin usahanya oleh Otoritas Jasa Keuangan; d. mengevaluasi pelaksanaan Penjaminan, penjaminan polis, penempatan dana, resolusi Bank, dan likuidasi Perusahaan Asuransi dan Perusahaan Asuransi Syariah, serta pelaksanaan peran Lembaga Penjamin Simpanan dalam rangka turut aktif memelihara Stabilitas Sistem Keuangan; e. menerima dan mengevaluasi hal lain yang dilaporkan anggota Dewan Komisioner; dan f. hal lain yang berhubungan dengan tugas Lembaga Penjamin Simpanan. (2) Ketua Dewan Komisioner memimpin rapat Dewan Komisioner. (3) Dalam hal Ketua Dewan Komisioner berhalangan sehingga yang bersangkutan tidak dapat memimpin rapat, Ketua Dewan Komisioner …"}, {"l": "UU 4/2023", "p": "72", "b": "Bagian Ketiga", "t": "(1) Pengambilan keputusan Dewan Komisioner dilakukan secara musyawarah untuk mufakat. (2) Dalam hal musyawarah untuk mufakat sebagaimana dimaksud pada ayat (1) tidak tercapai, Ketua Dewan Komisioner menetapkan keputusan akhir. (3) Dalam hal anggota Dewan Komisioner mempunyai kepentingan pribadi, baik langsung maupun tidak langsung, yang dapat menimbulkan benturan kepentingan dengan objek yang akan diputuskan, yang bersangkutan tidak ikut dalam pengambilan keputusan. (4) Keputusan Dewan Komisioner sebagaimana dimaksud pada ayat (1) dan ayat (2) sah apabila diputuskan dalam rapat Dewan Komisioner. (5) Rapat Dewan Komisioner dinyatakan sah jika dihadiri lebih dari 1/2 (satu perdua) dari jumlah anggota Dewan Komisioner. (6) Keputusan Dewan Komisioner mengikat seluruh anggota Dewan Komisioner. (7) Semua catatan dan data termasuk argumentasi yang dikemukakan oleh anggota Dewan Komisioner dalam pengambilan keputusan Dewan Komisioner dimuat dalam risalah rapat dan ditandatangani oleh semua anggota Dewan Komisioner yang hadir. (8) Ketentuan lebih lanjut mengenai tata cara pengambilan keputusan Dewan Komisioner sebagaimana dimaksud pada ayat (1) sampai dengan ayat (7) diatur dalam Peraturan …"}, {"l": "UU 4/2023", "p": "74A", "b": "Bagian Ketiga", "t": "(1) Dewan Komisioner menetapkan dan menegakkan kode etik Lembaga Penjamin Simpanan. (2) Ketentuan ... jdih.kemenkeu.go.id REPUBUK INDONESIA . (2) Ketentuan lebih lanjut mengenai kode etik sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Dewan Komisioner. 49. Bagian Ketiga dalam Bab VII dihapus. 50. Pasal 77 dihapus. 51. Ketentuan Pasal 78 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "78", "b": "Bagian Ketiga", "t": "(1) Dewan Komisioner menetapkan sistem kepegawaian, sistem penggajian, penghargaan, program pensiun dan tunjangan hari tua, serta penghasilan lainnya bagi pegawai Lembaga Penjamin Simpanan. (2) Ketentuan lebih lanjut mengenai sistem kepegawaian, sistem penggajian, penghargaan, program pensiun dan tunjangan hari tua, serta penghasilan lainnya bagi pegawai Lembaga Penjamin Simpanan sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Dewan Komisioner. 52. Ketentuan Pasal 79 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "79", "b": "Bagian Ketiga", "t": "(1) Dalam hal berdasarkan putusan pengadilan yang telah memperoleh kekuatan hukum tetap: a. anggota Dewan Komisioner atau mantan anggota Dewan Komisioner; b. mantan Kepala Eksekutif; dan/atau c. pegawai Lembaga Penjamin Simpanan atau mantan pegawai Lembaga Penjamin Simpanan, diwajibkan untuk membayar ganti rugi kepada pihak lain, sepanjang yang bersangkutan melaksanakan tugas, wewenang, dan/atau fungsi sesuai dengan ketentuan peraturan perundang-undangan, Lembaga Penjamin Simpanan membayar ganti rugi dimaksud. (2) Biaya ... jdih.kemenkeu.go.id (2) Biaya penyelesaian perkara terhadap putusan pengadilan sebagaimana dimaksud pada ayat (1) ditanggung oleh Lembaga Penjamin Simpanan. · 53. Ketentuan Pasal 82 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "82", "b": "Bagian Ketiga", "t": "(1) Dana yang digunakan Lembaga Penjamin Simpanan untuk menjalankan tugas sebagaimana dimaksud dalam Pasal 5 dan wewenang sebagaimana dimaksud dalam Pasal 6 bersumber dari kekayaan Lembaga Penjamin Simpanan. (2) Kekayaan Lembaga Penjamin Simpanan sebagaimana dimaksud pada ayat (1) berbentuk investasi dan bukan investasi. (3) Kekayaan yang berbentuk investasi sebagaimana dimaksud pada ayat (2) hanya dapat ditempatkan pada surat berharga yang diterbitkan oleh Pemerintah Indonesia, Bank Indonesia, dan/atau pemerintah negara asing. (4) Investasi pada surat berharga yang diterbitkan oleh pemerintah negara asing sebagaimana dimaksud pada ayat (3) paling banyak 10% (sepuluh persen) dari total kekayaan Lembaga Penjamin Simpanan. (5) Lembaga Penjamin Simpanan tidak dapat menempatkan kekayaannya pada Bank atau perusahaan lainnya, kecuali dalam bentuk penyertaan modal sementara dalam rangka penyelamatan atau penanganan Bank Dalam Resolusi, penyertaan modal pada bank perantara, penempatan dana Lembaga Penjamin Simpanan pada Bank, dan penyertaan modal pada perusahaan pengelola aset. (6) Lembaga Penjamin Simpanan dapat menempatkan kekayaan bukan investasi sebagaimana dimaksud pada ayat (2) …"}, {"l": "UU 4/2023", "p": "82A", "b": "Bagian Ketiga", "t": "(1) Dalam rangka mengoptimalkan pengelolaan aset yang diperoleh dari: a. penempatan dana oleh Lembaga Penjamin Simpanan pada Bank; b. penyelesaian dan/ atau penanganan Bank Dalam Resolusi; c. penanganan Bank dalam program restrukturisasi perbankan; dan/atau d. Perusahaan Asuransi dan Perusahaan Asuransi Syariah yang dilikuidasi, Lembaga Penjamin Simpanan dapat melakukan kerja sama dengan perusahaan pengelola aset, melakukan penyertaan modal pada perusahaan pengelola aset, dan/ a tau mendirikan perusahaan pengelola aset. (2) Badan hukum perusahaan pengelola aset yang didirikan oleh Lembaga Penjamin Simpanan sebagaimana dimaksud pada ayat (1) berbentuk perseroan terbatas dan seluruh sahamnya dimiliki oleh Lembaga Penjamin Simpanan. (3) Terhadap perusahaan pengelola aset sebagaimana dimaksud pada ayat (2) tidak berlaku ketentuan yang mewajibkan perseroan terbatas didirikan atau dimiliki oleh 2 (dua) orang atau lebih sebagaimana dimaksud dalam undang-undang mengenai perseroan terbatas. 55. Di antara Pasal 83 dan Pasal 84 disisipkan 1 (satu) pasal, yakni Pasal 83A sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "83A", "b": "Bagian Ketiga", "t": "Ketentuan mengenai perpajakan Lembaga Penjamin Simpanan diatur dalam Peraturan Pemerintah setelah mendapatkan persetujuan dari DPR. 56. Ketentuan ... jdih.kemenkeu.go.id REPUBUK INDONESIA 56. Ketentuan Pasal 85 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "85", "b": "Bagian Ketiga", "t": "(1) Dalam hal modal Lembaga Penjamin Simpanan kurang dari modal awal sebagaimana dimaksud dalam Pasal 81 ayat (1), Pemerintah dengan persetujuan DPR menutup kekurangan. (2) Lembaga Penjamin Simpanan dapat memberikan pmJaman antarprogram dalam hal salah satu program yang diselenggarakan oleh Lembaga Penjamin Simpanan mengalami kekurangan dana. (3) Dalam hal Lembaga Penjamin Simpanan memperkirakan Lembaga Penjamin Simpanan akan atau telah mengalami kesulitan likuiditas karena menjalankan tugas sebagaimana dimaksud dalam Pasal 5, Lembaga Penjamin Simpanan berwenang: a. menjual dan/atau repo (repurchase agreement) surat berharga negara yang dimiliki kepada Bank Indonesia dan/ atau pihak lain; b. menerbitkan surat utang; c. meminjam kepada pihak lain; dan/ a tau d. meminjam kepada Pemerintah. (4) Dalam hal penerbitan surat utang sebagaimana dimaksud pada ayat (3) huruf b dan/ atau pelaksanaan pmJaman kepada pihak lain sebagaimana dimaksud pada ayat (3) huruf c tidak dapat dilakukan karena kondisi pasar keuangan yang tidak memungkinkan, Lembaga Penjamin Simpanan dapat mengajukan permohonan pinjaman kepada Pemerintah. (5) Dalam hal Lembaga Penjamin Simpanan mengajukan pinjaman kepada …"}, {"l": "UU 4/2023", "p": "86", "b": "Bagian Ketiga", "t": "(1) Dalam jangka waktu paling lambat 3 (tiga) bulan sebelum tahun buku mulai berlaku, Wakil Ketua Dewan Komisioner menyampaikan rencana kerja dan anggaran tahunan kepada Dewan Komisioner. (2) Rencana kerja dan anggaran tahunan sebagaimana dimaksud pada ayat (1) memuat: a. rencana kerja dan anggaran tahunan untuk kegiatan operasional; dan b. rencana kerja dan anggaran tahunan untuk kebijakan Penjaminan, penjaminan polis, penempatan dana, resolusi Bank, dan likuidasi Perusahaan Asuransi dan Perusahaan Asuransi Syariah. (3) Bersamaan dengan penyampaian rencana kerja dan anggaran tahunan, Wakil Ketua Dewan Komisioner sebagaimana dimaksud pada ayat (1) menyampaikan evaluasi pelaksanaan anggaran tahun berjalan kepada Dewan Komisioner. (4) Ketua Dewan Komisioner menyampaikan rencana kerja dan anggaran tahunan untuk kegiatan operasional sebagaimana dimaksud pada ayat (2) huruf a kepada Menteri Keuangan untuk mendapat persetujuan. (5) Penyampaian kepada Menteri Keuangan sebagaimana dimaksud pada ayat (4) disampaikan paling lambat 2 (dua) bulan sebelum tahun buku mulai berlaku. (6) Menteri Keuangan memberikan persetujuan atas rencana kerja dan anggaran tahunan untuk kegiatan operasional …"}, {"l": "UU 4/2023", "p": "89A", "b": "Bagian Ketiga", "t": "(1) Dengan Undang-Undang m1 dibentuk Badan Supervisi Lembaga Penjamin Simpanan. (2) Badan Supervisi Lembaga Penjamin Simpanan sebagaimana dimaksud pada ayat (1) berfungsi membantu DPR dalam melaksanakan fungsi pengawasan di bidang tertentu terhadap Lembaga Penjamin Simpanan untuk meningkatkan kinerja, akuntabilitas, independensi, transparansi, dan kredibilitas kelembagaan Lembaga Penjamin Simpanan. (3) Untuk menjalankan fungsi pengawasan sebagaimana dimaksud pada ayat (2), Badan Supervisi Lembaga Penjamin Simpanan bertugas membantu DPR dalam: a. membuat laporan evaluasi kinerja kelembagaan Lembaga Penjamin Simpanan; b. melakukan pemantauan untuk meningkatkan akuntabilitas, independensi, transparansi, dan kredibilitas kelembagaan Lembaga Penjamin Simpanan; dan c. menyusun laporan kinerja. (4) Untuk melaksanakan tugas sebagaimana dimaksud pada ayat (3), Badan Supervisi Lembaga Penjamin Simpanan berwenang: a. meminta penjelasan mengenai hal yang berkaitan dengan tata kelola pelaksanaan tugas dan wewenang kelembagaan Lembaga Penjamin Simpanan; b. menerima ... jdih.kemenkeu.go.id REPUBUK INDONESIA . b. menerima tembusan laporan kinerja kelembagaan secara triwulanan dan tahunan dari …"}, {"l": "UU 4/2023", "p": "89B", "b": "Bagian Ketiga", "t": "(1) Keanggotaan Badan Supervisi Lembaga Penjamin Simpanan berjumlah paling sedikit 5 (lima) orang yang dipimpin oleh 1 (satu) orang ketua yang dipilih dari dan oleh anggotanya. (2) Anggota Badan Supervisi Lembaga Penjamin Simpanan sebagaimana dimaksud pada ayat (1) terdiri atas unsur Pemerintah, akademisi, dan masyarakat. (3) Anggota Badan Supervisi Lembaga Penjamin Simpanan menjabat selama 5 (lima) tahun dan dapat dipilih kembali untuk 1 (satu) kali masa jabatan berikutnya. (4) Untuk dapat diangkat menjadi anggota Badan Supervisi Lembaga Penjamin Simpanan sebagaimana dimaksud pada ayat (1), calon anggota harus memenuhi persyaratan sebagai berikut: a. warga negara Indonesia; b. sehat jasmani dan rohani; c. mempunyai integritas dan moralitas yang tinggi; d. bukan pengurus partai politik saat pencalonan; e. memiliki keahlian dan pengalaman di bidang perbankan, Pasar Modal, perasuransian, Sistem Keuangan, organisasi dan manajemen, sistem informasi, dan/ atau hukum; f. tidak memiliki hubungan keluarga sampai derajat ketiga dan/ atau semenda dengan anggota Dewan Komisioner Lembaga Penjamin Simpanan; g. tidak pernah dijatuhi pidana penjara berdasarkan putusan pengadilan yang memperoleh …"}, {"l": "UU 4/2023", "p": "89C", "b": "Bagian Ketiga", "t": "(1) Anggota Badan Supervisi Lembaga Penjamin Simpanan sebagaimana dimaksud dalam Pasal 89B ayat (1) diseleksi dan dipilih oleh DPR. (2) Badan Supervisi Lembaga Penjamin Simpanan memberitahukan kepada DPR dengan tembusan kepada Presiden tentang akan berakhirnya masa jabatan anggota Badan Supervisi Lembaga Penjamin Simpanan paling lambat 6 (enam) bulan sebelum berakhirnya masa jabatan anggota tersebut. (3) DPR memulai proses pemilihan anggota Badan Supervisi Lembaga Penjamin Simpanan terhitung sejak tanggal diterimanya surat pemberitahuan dari Badan Supervisi Lembaga Penjamin Simpanan sebagaimana dimaksud pada ayat (2) dan harus menyelesaikan pemilihan anggota yang baru, paling lama 1 (satu) bulan sebelum berakhirnya masa jabatan anggota Badan Supervisi Lembaga Penjamin Simpanan yang lama. (4) Pemilihan dan penetapan calon anggota Badan Supervisi Lembaga Penjamin Simpanan sebagaimana dimaksud pada ayat (1) dilaksanakan oleh panitia seleksi yang dibentuk DPR. (5) Anggota Badan Supervisi Lembaga Penjamin Simpanan yang dipilih sebagaimana dimaksud pada ayat (1) ditetapkan dengan Keputusan Presiden. (6) Anggota Badan Supervisi Lembaga Penjamin Simpanan dilarang memiliki benturan …"}, {"l": "UU 4/2023", "p": "91", "b": "Bagian Ketiga", "t": "(1) Dewan Komisioner, anggota Dewan Komisioner, pegawai Lembaga Penjamin Simpanan, atau setiap pihak yang bertugas untuk dan atas nama Lembaga Penjamin Simpanan wajib merahasiakan semua dokumen, informasi, dan catatan yang diperoleh atau dihasilkan dalam pelaksanaan tugasnya yang harus dirahasiakan berdasarkan ketentuan peraturan perundang-undangan. (2) Perbuatan hukum Dewan Komisioner, anggota Dewan Komisioner, pegawai Lembaga Penjamin Simpanan, atau setiap pihak yang bertugas untuk dan atas nama Lembaga Penjamin Simpanan yang dilakukan berdasarkan ketentuan peraturan perundang-undangan dikecualikan dari ketentuan sebagaimana dimaksud pada ayat (1). 63. Ketentuan Pasal 92 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "92", "b": "Bagian Ketiga", "t": "(1) Bank yang melanggar ketentuan kewajiban: a. pembayaran premi Penjaminan; b. penyampaian laporan berkala dalam format yang ditentukan; c. pemberian data, informasi, dan dokumen yang dibutuhkan dalam rangka penyelenggaraan Penjaminan; dan/ atau d. penempatan bukti kepesertaan atau salinannya di dalam kantor Bank atau tempat lainnya sehingga dapat diketahui dengan mudah oleh masyarakat, dikenai sanksi administratif oleh Lembaga Penjamin Simpanan berupa denda paling banyak Rpl.000.000,00 (satu juta rupiah) per hari keterlambatan penyamp aian kewajiban dan/ atau laporan. (2) Pengenaan ... jdih.kemenkeu.go.id (2) Pengenaan sanksi administratif kepada Bank yang melanggar ketentuan kewajiban pembayaran premi Penjaminan sebagaimana dimaksud pada ayat (1) huruf a ditetapkan paling banyak 150% (seratus lima puluh persen) dari jumlah premi yang seharusnya dibayar untuk setiap periode dan dikenakan untuk jangka waktu paling lama 12 (dua belas) bulan. (3) Pengenaan sanksi administratif sebagaimana dimaksud pada ayat (1) sesuai dengan tingkat pelanggara:n yang dilakukan. (4) Ketentuan lebih lanjut mengenai besaran dan jangka waktu pengenaan serta tata cara pengenaan sanksi administratif …"}, {"l": "UU 4/2023", "p": "95", "b": "Bagian Ketiga", "t": "(1) Pemegang saham, anggota direksi, anggota dewan komisaris, pegawai, dan/ atau pihak lain yang terkait dengan Bank yang dicabut izin usahanya atau Bank dalam likuidasi yang melanggar ketentuan mengenai: a. kewajiban membantu memberikan segala data dan informasi yang diperlukan oleh Lembaga Penjamin Simpanan sebagaimana dimaksud dalam Pasal 16 ayat (5); b. kewajiban untuk membantu memberikan segala ·data dan informasi yang diperlukan oleh tim likuidasi sebagaimana dimaksud dalam Pasal 4 7 ayat (2); dan/atau c. larangan menghambat proses likuidasi sebagaimana dimaksud dalam Pasal 47 ayat (3), dipidana dengan pidana penjara paling singkat 1 (satu) tahun dan paling lama 3 (tiga) tahun dan pidana denda paling sedikit Rp2.000.000.000,00 (dua miliar rupiah) dan paling banyak Rp3.000.000.000,00 (tiga miliar rupiah). (2) Anggota ... jdih.kemenkeu.go.id REPUBUK INDONESIA . (2) Anggota Dewan Komisioner dan pegawai Lembaga Penjamin Simpanan, atau pihak lain yang ditunjuk atau disetujui oleh Lembaga Penjamin Simpanan untuk melakukan tugas tertentu, yang melanggar ketentuan kewajiban untuk menjaga kerahasiaan sebagaimana dimaksud dalam Pasal 91 ayat (1) dipidana dengan pidana penjara paling …"}, {"l": "UU 4/2023", "p": "8", "b": "Bagian Keempat", "t": "Beberapa ketentuan dalam Undang-Undang Nomor 21 Tahun 2011 tentang Otoritas Jasa Keuangan (Lembaran Negara sebagai berikut: 1. Ketentuan Pasal 1 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "8B", "b": "Bagian Keempat", "t": "Otoritas Jasa Keuangan merupakan satu-satunya pihak yang berwenang mengajukan permohonan pemyataan pailit dan/ atau permohonan penundaan kewajiban pembayaran utang terhadap debitur yang merupakan Bank, perusahaan efek, bursa efek, penyelenggara pasar altematif, lembaga kliring dan penjaminan, lembaga penyimpanan dan penyelesaian, penyelenggara dana perlindungan pemodal, lembaga pendanaan efek, lembaga penilaian harga efek, Perusahaan Asuransi, Perusahaan Asuransi Syariah, perusahaan reasuransi, a tau perusahaan reasuransi syariah, Dana Pensiun, lembaga penjamin, Lembaga Pembiayaan, lembaga keuangan mikro, penyelenggara sistem elektronik yang memfasilitasi penghimpunan dana masyarakat melalui penawaran Efek, Penyelenggara Layanan Pendanaan Bersama Berbasis Teknologi Informasi, atau WK Lainnya yang terdaftar dan diawasi oleh Otoritas Jasa Keuangan sepanjang pembubaran dan/ atau kepailitannya tidak diatur berbeda dengan Undang-Undang lainnya. 6. Penjelasan ... jdih.kemenkeu.go.id 6. Penjelasan Pasal 9 diubah sebagaimana tercantum dalam penjelasan. 7. Ketentuan Pasal 10 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "10", "b": "Bagian Keempat", "t": "{1) Otoritas Jasa Keuangan dipimpin oleh Dewan Komisioner. (2) Ketua Dewan Komisioner bertindak sebagai pimpinan Dewan Komisioner. (3) Dewan Komisioner beranggotakan 11 (sebelas) orang anggota yang ditetapkan dengan Keputusan Presiden. (4) Susunan Dewan Komisioner sebagaimana dimaksud pada ayat (3) terdiri atas: a. seorang Ketua merangkap anggota; b. seorang Wakil Ketua sebagai Ketua Komite Etik merangkap anggota; c. seorang Kepala Eksekutif Pengawas Perbankan merangkap anggota; d. seorang Kepala Eksekutif Pengawas Pasar Modal, Keuangan Derivatif, dan Bursa Karbon merangkap anggota; e. seorang Kepala Eksekutif Pengawas Perasuransian, Penjaminan, dan Dana Pensiun merangkap anggota; f. seorang Kepala Eksekutif Pengawas Lembaga Pembiayaan, Perusahaan Modal Ventura, Lembaga Keuangan Mikro, dan Lembaga Jasa Keuangan Lainnya merangkap anggota; g. seorang Kepala Eksekutif Pengawas lnovasi Teknologi Sektor Keuangan, Aset Keuangan Digital dan Aset Kripto merangkap anggota; h. seorang Kepala Eksekutif Pengawas Perilaku Pelaku Usaha Jasa Keuangan, Edukasi, dan Pelindungan Konsumen merangkap anggota; 1. seorang Ketua Dewan Audit merangkap anggota; j. seorang ... jdih.kemenkeu.go.id j. seorang …"}, {"l": "UU 4/2023", "p": "15", "b": "Bagian Keempat", "t": "Syarat calon anggota Dewan Komisioner sebagaimana dimaksud dalam Pasal 10 ayat (4) huruf a sampai dengan huruf i adalah sebagai berikut: a. warga negara Indonesia; b. memiliki akhlak, moral, dan integritas yang baik; c. cakap melakukan perbuatan hukum; d. tidak pernah dinyatakan pailit atau tidak pernah menjadi pengurus perusahaan yang menyebabkan perusahaan tersebut pailit; e. sehat jasmani; f. berusia paling tinggi 65 (enam puluh lima) tahun pada saat ditetapkan; g. mempunyai pengalaman atau keahlian di sektor jasa keuangan; h. tidak ... jdih.kemenkeu.go.id REPUBUK INDONESIA h. tidak pemah dijatuhi pidana penjara berdasarkan putusan pengadilan yang telah memperoleh kekuatan hukum tetap karena melakukan tindak pidana yang diancam dengan hukuman 5 (lima) tahun atau lebih; dan 1. bukan pengurus dan/ a tau anggota partai politik pada saat pencalonan. 9. Ketentuan Pasal 17 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "35", "b": "Bagian Keempat", "t": "(1) Anggaran Otoritas Jasa Keuangan sebagaimana dimaksud dalam Pasal 34 ayat (2) digunakan untuk membiayai kegiatan operasional, administrasi, pengadaan aset, dan kegiatan pendukung lainnya. (2) Anggaran dan penggunaan anggaran sebagaimana dimaksud pada ayat (1) ditetapkan berdasarkan standar yang wajar di sektor jasa keuangan. (3) Standar yang wajar di sektor jasa keuangan sebagaimana dimaksud pada ayat (2) termasuk perlakuan khusus terhadap standar biaya, proses pengadaan barang dan jasa, pengelolaan sumber daya manusia, organisasi, dan remunerasi. (4) Ketentuan mengenai standar biaya, proses pengadaan barang dan jasa, pengelolaan sumber daya manusia, organisasi, dan remunerasi sebagaimana dimaksud pada ayat (3) diatur dalam Peraturan Pemerintah setelah mendapatkan persetujuan dari DPR. 14. Di antara Pasal 36 dan Pasal 37 disisipkan 2 (dua) pasal, yakni Pasal 36A dan Pasal 36B sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "36A", "b": "Bagian Keempat", "t": "Ketentuan mengenai rencana kerja dan anggaran Otoritas Jasa Keuangan sebagaimana dimaksud dalam Pasal 34 dan Pasal 35 mulai berlaku untuk tahun anggaran 2025."}, {"l": "UU 4/2023", "p": "36B", "b": "Bagian Keempat", "t": "Ketentuan lebih lanjut mengenai rencana kerja dan anggaran Otoritas Jasa Keuangan sebagaimana dimaksud dalam Pasal 34, Pasal 35, dan Pasal 36A diatur dalam Peraturan Pemerintah. 15. Ketentuan Pasal 37 diubah sehingga berbunyi sebagai berikut: Pasal 37 ... jdih.kemenkeu.go.id REPUBUK INDONESIA"}, {"l": "UU 4/2023", "p": "37A", "b": "Bagian Keempat", "t": "{1) Pungutan yang dilakukan oleh Otoritas Jasa Keuangan sebelum berlakunya Undang-Undang ini, tetap berlaku sampai dengan akhir tahun 2024. (2) Penggunaan hasil pungutan berdasarkan undang­ undang mengenai Otoritas Jasa Keuangan tetap dapat dilakukan sampai dengan akhir tahun 2024. (3) Ketentuan mengenai pungutan sebagaimana dimaksud dalam Pasal 37 mulai berlaku tahun 2025. 17. Ketentuan Pasal 38 diubah sehingga berbunyi sebagai berikut: Pasal 38 ... jdih.kemenkeu.go.id . REPUBUK INDONESIA"}, {"l": "UU 4/2023", "p": "38A", "b": "Bagian Keempat", "t": "(1) Dengan Undang-Undang m1 dibentuk Badan Supervisi Otoritas Jasa Keuangan. (2) Badan Supervisi Otoritas Jasa Keuangan sebagaimana dimaksud pada ayat (1) berfungsi membantu DPR dalam melaksanakan fungsi pengawasan di bidang tertentu terhadap Otoritas Jasa Keuangan untuk meningkatkan kinerja, akuntabilitas, independensi, transparansi, dan kredibilitas kelembagaan Otoritas Jasa Keuangan. (3) Untuk ... jdih.kemenkeu.go.id (3) Untuk menjalankan fungsi pengawasan sebagaimana dimaksud pada ayat (2), Badan Supervisi Otoritas Jasa Keuangan bertugas membantu DPR dalam: a. membuat laporan evaluasi kinerja kelembagaan Otoritas Jasa Keuangan; b. melakukan pemantauan untuk meningkatkan akuntabilitas, independensi, transparansi, dan kredibilitas kelembagaan Otoritas Jasa Keuangan;dan c. menyusun laporan kinerja. (4) Untuk melaksanakan tugas sebagaimana dimaksud pada ayat (3), Badan Supervisi Otoritas Jasa Keuangan berwenang: a. meminta penjelasan mengenai hal yang berkaitan dengan tata kelola pelaksanaan tugas dan wewenang kelembagaan Otoritas Jasa Keuangan; b. menerima tembusan laporan kinerja kelembagaan secara triwulanan dan tahunan dari Otoritas Jasa Keuangan; c. melakukan telaahan atas …"}, {"l": "UU 4/2023", "p": "38B", "b": "Bagian Keempat", "t": "(1) Keanggotaan Badan Supervisi Otoritas Jasa Keuangan berjumlah paling sedikit 5 (lima) orang yang dipimpin oleh 1 (satu) orang ketua yang dipilih dari dan oleh anggotanya. (2) Anggota Badan Supervisi Otoritas Jasa Keuangan sebagaimana dimaksud pada ayat ( 1) terdiri atas unsur Pemerintah, akademisi, dan masyarakat. (3) Anggota Badan Supervisi Otoritas Jasa Keuangan menjabat selama 5 (lima) tahun dan dapat dipilih kembali untuk 1 (satu) kali masa jabatan berikutnya. (4) Untuk dapat diangkat menjadi anggota Badan Supervisi Otoritas Jasa Keuangan sebagaimana dimaksud pada ayat (1), calon anggota harus memenuhi persyaratan sebagai berikut: a. warga negara Indonesia; b. sehat jasmani dan rohani; c. mempunyai ... jdih.kemenkeu.go.id . R£PUBUK INDONESIA c. mempunyai integritas dan moralitas yang tinggi; d. bukan pengurus partai politik saat pencalonan; e. memiliki keahlian dan pengalaman di bidang Perbankan, Pasar Modal, Perasuransian, industri keuangan non-Bank, Sistem Keuangan, organisasi dan manajemen, sistem informasi, dan/ a tau hukum; f. tidak memiliki hubungan keluarga sampai derajat ketiga dan/ atau semenda dengan anggota Dewan Komisioner Otoritas Jasa Keuangan; g. tidak pemah …"}, {"l": "UU 4/2023", "p": "38C", "b": "Bagian Keempat", "t": "(1) Anggota Badan Supervisi Otoritas Jasa Keuangan sebagaimana dimaksud dalam Pasal 38B ayat (1) diseleksi dan dipilih oleh DPR. (2) Badan Supervisi Otoritas Jasa Keuangan memberitahukan kepada DPR dengan tembusan kepada Presiden tentang akan berakhirnya masa jabatan anggota Badan Supervisi Otoritas Jasa Keuangan paling lambat 6 (enam) bulan sebelum berakhimya masa jabatan anggota tersebut. (3) DPR memulai proses pemilihan anggota Badan Supervisi Otoritas Jasa Keuangan terhitung sejak tanggal diterimanya surat pemberitahuan dari Badan Supervisi Otoritas Jasa Keuangan sebagaimana dimaksud pada ayat (2) dan harus menyelesaikan pemilihan anggota yang baru, paling lama 1 (satu) bulan sebelum berakhirnya masa jabatan anggota Badan Supervisi Otoritas Jasa Keuangan yang lama. (4) Pemilihan . . . jdih.kemenkeu.go.id . REPUBUK INDONESIA (4) · Pemilihan dan penetapan calon anggota Badan Supervisi Otoritas Jasa Keuangan sebagaimana dimaksud pada ayat (1) dilaksanakan oleh Panitia Seleksi yang dibentuk oleh DPR. (5) Anggota Badan Supervisi Otoritas Jasa Keuangan yang dipilih sebagaimana dimaksud pada ayat (1) ditetapkan dengan Keputusan Presiden. (6) Anggota Badan Supervisi Otoritas Jasa …"}, {"l": "UU 4/2023", "p": "48B", "b": "Bagian Keempat", "t": "(1) Otoritas Jasa Keuangan berwenang menetapkan dimulainya, tidak dilakukannya, atau dihentikannya penyidikan terhadap tindak pidana sektor jasa keuangan. (2) Sebelum menetapkan dimulainya penyidikan sebagaimana dimaksud pada ayat (1), Otoritas Jasa Keuangan melakukan penyelidikan terhadap dugaan tindak pidana sektor jasa keuangan. (3) Pada ... jdih.kemenkeu.go.id REPUBUK INDONESIA (3) Pada tahap penyelidikan sebagaimana dimaksud pada ayat (2), pihak yang diduga melakukan tindak pidana sektor jasa keuangan dapat mengajukan permohonan kepada Otoritas Jasa Keuangan untuk penyelesaian pelanggaran atas peraturan perundang­ undangan di sektor jasa keuangan. (4) Otoritas Jasa Keuangan melakukan penilaian terhadap permohonan penyelesaian pelanggaran sebagaimana dimaksud pada ayat (3) dan menghitung nilai kerugian atas pelanggaran. (5) Dalam melakukan penilaian terhadap permohonan penyelesaian pelanggaran dan perhitungan nilai kerugian atas pelanggaran sebagaimana dimaksud pada ayat (4), Otoritas Jasa Keuangan mempertimbangkan minimal: a. ada atau tidaknya penyelesaian atas kerugian yang timbul akibat tindak pidana; b. nilai transaksi dan/ atau nilai kerugian atas pelanggaran; dan c. …"}, {"l": "UU 4/2023", "p": "49", "b": "Bagian Keempat", "t": "(1) Penyidik Otoritas Jasa Keuangan terdiri atas: a. pejabat penyidik Kepolisian Negara Republik Indonesia; b. pejabat ... jdih.kemenkeu.go.id REPUBUK INDONESIA . b. pejabat pegawai negeri sipil tertentu; d~ c. pegawai tertentu, yang diberi wewenang khusus sebagai penyidik sebagaimana dimaksud dalam Kitab Undang-Undang Hukum Acara Pidana, untuk melakukan penyidikan tindak pidana di sektor jasa keuangan. (2) Penyidik sebagaimana dimaksud pada ayat (1) huruf b diangkat oleh menteri yang menyelenggarakan urusan pemerintahan di bidang hukum. (3) Pegawai tertentu yang diberi wewenang khusus sebagai penyidik sebagaimana dimaksud pada ayat (1) huruf c ditetapkan setelah memenuhi kualifikasi oleh Kepolisian Negara Republik Indonesia. (4) Administrasi pengangkatan, pemindahan, pemberhentian, dan pelantikan penyidik sebagaimana dimaksud pada ayat (3) dilaksanakan oleh menteri yang menyelenggarakan urusan pemerintahan di bidang hukum. (5) Penyidikan atas tindak pidana di sektor jasa keuangan hanya dapat dilakukan oleh penyidik Otoritas Jasa Keuangan. (6) Dalam melaksanakan penyidikan sebagaimana dimaksud pada ayat (5), Otoritas Jasa Keuangan berkoordinasi dengan Kepolisian Negara Republik …"}, {"l": "UU 4/2023", "p": "9", "b": "Bagian Kelima", "t": "(1) Pihak lain dilarang melakukan segala bentuk campur tangan terhadap pelaksanaan tugas Bank Indonesia sebagaimana dimaksud dalam Pasal 8, kecuali untuk hal-hal tertentu yang secara tegas diatur dengan Undang-Undang ini. (2) Bank Indonesia wajib menolak dan/ atau mengabaikan segala bentuk campur tangan dari pihak mana pun dalam rangka pelaksanaan tugas sebagaimana dimaksud dalam Pasal 8. 5. Ketentuan Pasal 10 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "10B", "b": "Bagian Kelima", "t": "(1) Pengaturan, pengawasan, dan pengembangan Pasar Uang dan Pasar Valuta Asing oleh Bank Indonesia sebagaimana dimaksud dalam Pasal 10 ayat (2) huruf f meliputi: a. penerbitan produk dan mekanisme transaksi di Pasar Uang dan Pasar Valuta Asing; b. perizinan dan perilaku pasar pelaku Pasar Uang dan Pasar Valuta Asing; c. mekanisme pembentukan harga acuan di Pasar Uang dan Pasar Valuta Asing; d. infrastruktur Pasar Uang dan Pasar Valuta Asing; dan e. perizinan dan kegiatan usaha penukaran valuta asing yang diselenggarakan oleh bukan Bank. (2) Pengaturan, ... jdih.kemenkeu.go.id REPUBUK INDONESIA . (2) Pengaturan, pengawasan, dan pengembangan Pasar Uang dan Pasar Valuta Asing sebagaimana dimaksud pada ayat (1) dapat juga dilakukan berdasarkan Prinsip Syariah. (3) Dalam melakukan pengaturan, pengawasan, dan pengembangan Pasar Uang dan Pasar Valuta Asing sebagaimana dimaksud pada ayat (1), Bank Indonesia berkoordinasi dengan otoritas dan/ a tau kementerian/lembaga terkait. (4) Ketentuan lebih lanjut mengenai pengaturan, pengawasan, dan pengembangan Pasar Uang dan Pasar Valuta Asing sebagaimana dimaksud pada ayat (1) dan ayat (2) diatur dalam Peraturan Bank Indonesia. 7. Ketentuan Pasal …"}, {"l": "UU 4/2023", "p": "11", "b": "Bagian Kelima", "t": "(1) Selain pengelolaan likuiditas dalam rangka menetapkan dan melaksanakan kebijakan moneter sebagaimana dimaksud dalam Pasal 10 ayat (6), Bank Indonesia mengelola likuiditas untuk mendukung pertumbuhan ekonomi. (2) Pengelolaan likuiditas oleh Bank Indonesia sebagaimana dimaksud pada ayat (1) dapat dilakukan melalui pembelian atau penjualan surat berharga negara dan/ atau surat berharga berkualitas lainnya di pasar sekunder, penempatan dana pada lembaga keuangan dalam rangka pengembangan Pasar Uang, kebijakan giro wajib minimum, bauran kebijakan moneter, dan/atau instrumen kebijakan lainnya. (3) Dalam melakukan pengelolaan likuiditas sebagaimana dimaksud pada ayat (1), Bank Indonesia mengutamakan pencapaian tujuan untuk mencapai kestabilan nilai Rupiah dalam rangka kebijakan moneter sebagaimana dimaksud dalam Pasal 8 dengan memperhatikan kondisi makroekonomi. (4) Dalam melakukan pengelolaan likuiditas sebagaimana dimaksud pada ayat (2), Bank Indonesia menerapkan tata kelola yang baik. 8. Ketentuan ... jdih.kemenkeu.go.id . REPUBUK INDONESIA 8. Ketentuan Pasal 14 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "35A", "b": "BAB VIA TUGAS MENETAPKAN DAN MELAKSANAKAN KEBIJAKAN MAKROPRUDENSIAL", "t": "Bank Indonesia menetapkan dan melaksanakan kebijakan makroprudensial dalam rangka turut menjaga Stabilitas Sistem Keuangan melalui upaya mendorong intermediasi yang seimbang, berkualitas, dan berkelanjutan; memitigasi dan mengelola risiko sistemik; serta meningkatkan inklusi ekonomi, Inklusi Keuangan, dan Keuangan Berkelanjutan."}, {"l": "UU 4/2023", "p": "35B", "b": "BAB VIA TUGAS MENETAPKAN DAN MELAKSANAKAN KEBIJAKAN MAKROPRUDENSIAL", "t": "(1) Dalam rangka menetapkan dan melaksanakan kebijakan makroprudensial sebagaimana dimaksud dalam Pasal 8 huruf c, Bank Indonesia berwenang melakukan: a. pengaturan makroprudensial; b. pengawasan makroprudensial, termasuk pemeriksaan dan pengenaan sanksi; c. pengaturan ... jdih.kemenkeu.go.id . REPUBUK INDONESIA c. pengaturan dan pengembangan pembiayaan inklusif dan Keuangan Berkelanjutan; d. penyediaan dana untuk Bank dalam rangka menjalankan fungsi lender of the last resort; e. reverse repo (repurchase agreement) dan/atau pembelian surat berharga negara yang dimiliki oleh Lembaga Penjamin Simpanan pada saat Lembaga Penjamin Simpanan memerlukan likuiditas; dan f. koordinasi dengan otoritas terkait. (2) Kebijakan makroprudensial sebagaimana dimaksud pada ayat (1) huruf a sampai dengan huruf d dan huruf f ditetapkan dan diterapkan terhadap Perbankan, baik yang melakukan kegiatan usaha secara konvensional maupun yang berdasarkan Prinsip Syariah, dengan mempertimbangkan asesmen terhadap Sistem Keuangan secara keseluruhan dan keterkaitannya dengan kondisi perekonomian. (3) Ketentuan lebih lanjut mengenai kewenangan Bank Indonesia dalam menetapkan dan melaksanakan kebijakan …"}, {"l": "UU 4/2023", "p": "35C", "b": "BAB VIB KETENTUAN TERKAIT KEPAILITAN", "t": "Bank Indonesia merupakan satu-satunya pihak yang berwenang mengajukan permohonan pernyataan pailit dan/ a tau permohonan penundaan kewajiban pembayaran utang dari debitur yang merupakan penyedia jasa pembayaran dan penyelenggara infrastruktur Sistem Pembayaran, penyelenggara jasa pengolahan uang rupiah, perusahaan pialang Pasar Uang, penyedia sarana perdagangan, sarana kliring untuk transaksi derivatif suku bunga dan nilai tukar over-the-counter, atau lembaga lainnya yang diberikan izin dan/ atau penetapan oleh Bank Indonesia sepanjang pembubaran dan/ atau kepailitannya tidak diatur berbeda dengan ketentuan peraturan perundang-undangan lainnya."}, {"l": "UU 4/2023", "p": "35D", "b": "BAB VIB KETENTUAN TERKAIT KEPAILITAN", "t": "(1) Terhadap debitur yang merupakan penerbit uang elektronik, kepailitan tidak meliputi dana yang telah dipisahkan oleh penerbit guna memenuhi kewajiban penerbit kepada pengguna dan/ atau penyedia barang dan/ a tau Jasa dalam penyelenggaraan uang elektronik. (2) Dana sebagaimana dimaksud pada ayat (1) wajib digunakan sepenuhnya untuk memenuhi kewajiban penerbit kepada pengguna dan/atau penyedia barang dan/ atau jasa dalam penyelenggaraan uang elektronik. 25. Di antara Pasal 38 dan Pasal 39 disisipkan 1 (satu) pasal, yakni Pasal 38A sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "41", "b": "BAB VIB KETENTUAN TERKAIT KEPAILITAN", "t": "(1) Gubernur, Deputi Gubernur Senior, dan Deputi Gubernur diusulkan dan diangkat oleh Presiden dengan persetujuan DPR. (2) Calon Deputi Gubernur diusulkan oleh Presiden berdasarkan rekomendasi dari Gubernur. (3) Untuk setiap jabatan Gubernur dan Deputi Gubernur Senior sebagaimana dimaksud pada ayat (1), Presiden mengusulkan kepada DPR paling banyak 3 (tiga) orang calon. (4) Untuk setiap jabatan Deputi Gubernur sebagaimana dimaksud pada ayat (1), Presiden mengusulkan kepada DPR paling sedikit 2 (dua) orang calon. (5) Usulan Presiden kepada DPR sebagaimana dimaksud pada ayat (2) dan ayat (3) disampaikan paling lambat 3 (tiga) bulan sebelum berakhirnya masa jabatan Gubernur, Deputi Gubernur Senior, dan Deputi Gubernur. (6) DPR menyetujui atau menolak calon Gubernur, lambat 1 (satu) bulan terhitung sejak usul diterima. (7) Dalam hal calon Gubernur, Deputi Gubernur Senior, atau Deputi Gubernur sebagaimana dimaksud pada ayat (3) dan ayat (4) tidak disetujui oleh DPR, Presiden wajib mengajukan calon baru. (8) Dalam ... jdih.kemenkeu.go.id . REPUBUK INDONESIA (8) Dalam hal calon yang diajukan oleh Presiden sebagaimana dimaksud pada ayat (3) dan ayat (4) untuk kedua kalinya tidak disetujui …"}, {"l": "UU 4/2023", "p": "47", "b": "BAB VIB KETENTUAN TERKAIT KEPAILITAN", "t": "(1) Anggota Dewan Gubernur baik sendiri maupun bersama-sama dilarang: a. mempunyai kepentingan langsung atau tidak langsung pada perusahaan mana pun juga; b. merangkap jabatan pada lembaga lain kecuali karena kedudukannya wajib memangku jabatan tersebut; dan c. menjadi pengurus dan/ atau anggota partai politik. (2) Dalam hal anggota Dewan Gubernur melakukan 1 (satu) atau lebih larangan sebagaimana dimaksud pada ayat (1), anggota Dewan Gubemur tersebut wajib mengundurkan diri dari jabatannya. 29. Ketentuan ... jdih.kemenkeu.go.id . REPUBUK INDONESIA 29. Ketentuan Pasal 58 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "58", "b": "BAB VIB KETENTUAN TERKAIT KEPAILITAN", "t": "(1) Bank Indonesia dalam menjalankan Undang-Undang m1 wajib mengutamakan prinsip tata kelola kelembagaan yang baik dan profesional. (2) Bank Indonesia wajib menyampaikan laporan kinerja kelembagaan dalam menjalankan Undang-Undang ini, secara tertulis kepada Presiden dan DPR. (3) Laporan yang disampaikan kepada Presiden dan DPR sebagaimana dimaksud pada ayat (2) terdiri atas laporan triwulanan dan laporan tahunan. (4) Laporan triwulanan dan laporan tahunan yang disampaikan oleh Bank Indonesia sebagaimana dimaksud pada ayat (3) dievaluasi oleh DPR dan digunakan sebagai bahan penilaian tahunan terhadap kinerja Dewan Gubernur, anggota Dewan Gubemur, dan Bank Indonesia. (5) Dalam hal DPR memerlukan penjelasan mengenai hal-hal yang berkaitan dengan laporan sebagaimana dimaksud pada ayat (2), Bank Indonesia wajib menyampaikan penjelasan secara lisan dan/ atau tertulis. (6) Bagian dari laporan triwulanan dan laporan tahunan sebagaimana dimaksud pada ayat (3) disampaikan kepada masyarakat secara terbuka melalui media massa dengan mencantumkan ringkasannya dalam Berita Negara. (7) Setiap awal tahun anggaran, Bank Indonesia wajib menyampaikan informasi kepada masyarakat secara terbuka …"}, {"l": "UU 4/2023", "p": "58A", "b": "BAB VIB KETENTUAN TERKAIT KEPAILITAN", "t": "(1) Dengan Undang-Undang ini dibentuk Badan Supervisi Bank Indonesia. (2) Badan Supervisi Bank Indonesia sebagaimana dimaksud pada ayat (1) berfungsi membantu DPR dalam melaksanakan fungsi pengawasan di bidang tertentu terhadap Bank Indonesia untuk meningkatkan kinerja, akuntabilitas, independensi, transparansi, dan kredibilitas kelembagaan Bank Indonesia. (3) Dalam menjalankan fungsi sebagaimana dimaksud pada ayat (2), Badan Supervisi Bank Indonesia bertugas membantu DPR dalam: a. membuat laporan evaluasi kinerja kelembagaan Bank Indonesia; b. melakukan pemantauan untuk meningkatkan akuntabilitas, independensi, transparansi, dan kredibilitas kelembagaan Bank Indonesia; dan c. menyusun ... jdih.kemenkeu.go.id REPUBUK INDONESIA c. menyusun laporan kinerja. (4) Untuk melaksanakan tugas sebagaimana dimaksud pada ayat (3), Badan Supervisi Bank Indonesia berwenang: a. meminta penjelasan mengenai hal yang berkaitan dengan tata kelola pelaksanaan tugas dan wewenang kelembagaan Bank Indonesia; b. menerima tembusan laporan kinerja kelembagaan secara triwulanan dan tahunan dari Bank Indonesia; c. melakukan telaahan atas tata kelola pelaksanaan tugas dan wewenang kelembagaan Bank Indonesia; …"}, {"l": "UU 4/2023", "p": "58B", "b": "BAB VIB KETENTUAN TERKAIT KEPAILITAN", "t": "(1) Keanggotaan Badan Supervisi Bank Indonesia berjumlah paling sedikit 5 (lima) orang yang dipimpin oleh 1 (satu) orang ketua yang dipilih dari dan oleh anggotanya. (2) Anggota Badan Supervisi Bank Indonesia sebagaimana dimaksud pada ayat (1) terdiri atas unsur Pemerintah, akademisi, dan masyarakat. (3) Anggota Badan Supervisi Bank Indonesia menjabat selama 5 (lima) tahun dan dapat dipilih kembali untuk 1 (satu) kali masa jabatan berikutnya. (4) Untuk dapat diangkat menjadi anggota Badan Supervisi Bank Indonesia sebagaimana dimaksud pada ayat (1), calon anggota harus memenuhi persyaratan sebagai berikut: a. warga negara Indonesia; b. sehat jasmani dan rohani; c. mempunyai integritas dan moralitas yang tinggi; d. bukan pengurus partai politik saat pencalonan; e. memiliki keahlian dan pengalaman di bidang moneter, Sistem Pembayaran, makroprudensial, perbankan, Sistem Keuangan, organisasi dan manajemen, sistem informasi, dan/atau hukum; f. tidak ... jdih.kemenkeu.go.id f. tidak memiliki hubungan keluarga sampai derajat ketiga dan/ atau semenda dengan anggota Dewan Gubernur Bank Indonesia; g. tidak pernah dijatuhi pidana penJara berdasarkan putusan pengadilan yang memperoleh kekuatan …"}, {"l": "UU 4/2023", "p": "58C", "b": "BAB VIB KETENTUAN TERKAIT KEPAILITAN", "t": "(1) Anggota Badan Supervisi Bank Indonesia sebagaimana dimaksud dalam Pasal 58B ayat (1) diseleksi dan dipilih oleh DPR. (2) Badan Supervisi Bank Indonesia memberitahukan kepada DPR dengan tembusan kepada Presiden tentang akan berakhimya masa jabatan anggota Badan Supervisi Bank Indonesia paling lambat 6 (enam) bulan sebelum berakhimya masa jabatan anggota tersebut. (3) DPR memulai proses pemilihan anggota Badan Supervisi Bank Indonesia terhitung sejak tanggal diterimanya surat pemberitahuan dari Badan Supervisi Bank Indonesia sebagaimana dimaksud pada ayat (2) dan harus menyelesaikan pemilihan anggota yang baru, paling lama 1 (satu) bulan sebelum berakhirnya masa jabatan anggota Badan Supervisi Bank Indonesia yang lama. (4) Pemilihan dan penetapan calon anggota Badan Supervisi Bank Indonesia sebagaimana dimaksud pada ayat (1) dilaksanakan oleh panitia seleksi yang dibentuk DPR. (5) Anggota Badan Supervisi Bank Indonesia yang dipilih sebagaimana dimaksud pada ayat (1) ditetapkan dengan Keputusan Presiden. (6) Anggota ... jdih.kemenkeu.go.id . REPUBUK INDONESIA (6) Anggota Badan Supervisi Bank Indonesia dilarang memiliki benturan kepentingan baik secara langsung maupun tidak …"}, {"l": "UU 4/2023", "p": "60", "b": "BAB VIB KETENTUAN TERKAIT KEPAILITAN", "t": "(1) Tahun anggaran Bank Indonesia adalah tahun kalender. (2) Paling lambat 30 (tiga puluh) hari sebelum dimulai tahun anggaran, Dewan Gubernur menetapkan anggaran tahunan Bank Indonesia. (3) Anggaran tahunan sebagaimana dimaksud pada ayat (1) meliputi: a. anggaran untuk kegiatan operasional; dan b. anggaran untuk kebijakan moneter, Sistem Pembayaran, dan makroprudensial. (4) Anggaran untuk kegiatan operasional sebagaimana dimaksud pada ayat (3) huruf a, serta evaluasi pelaksanaan anggaran tahun berjalan disampaikan kepada DPR untuk mendapat persetujuan. (5) Proses persetujuan DPR sebagaimana dimaksud pada ayat (4) dilakukan oleh alat kelengkapan DPR yang membidangi keuangan, perbankan, dan perencanaan pembangunan. (6) Anggaran untuk kebijakan moneter, Sistem Pembayaran, dan makroprudensial sebagaimana dimaksud pada ayat (3) huruf b wajib dilaporkan secara khusus kepada DPR. 33. Pasal 61 dihapus. 34. Penjelasan Pasal 62 diubah sebagaimana tercantum dalam penjelasan. 35. Di antara ... jdih.kemenkeu.go.id PRESIOEN REPUBUK INDONESIA 35. Di antara Pasal 64 dan Pasal 65 disisipkan 1 (satu) pasal, yakni Pasal 64A sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "64A", "b": "BAB VIB KETENTUAN TERKAIT KEPAILITAN", "t": "(1) Bank Indonesia berwenang melakukan pengelolaan kekayaan Bank Indonesia termasuk melakukan hapus buku dan hapus tagih terhadap aset berupa piutang dan aset lainnya. (2) Pelaksanaan hapus buku dan hapus tagih terhadap aset berupa piutang dan aset lainnya dilaksanakan sesuai dengan tata kelola yang baik. (3) Ketentuan lebih lanjut mengenai pengelolaan kekayaan Bank Indonesia sebagaimana dimaksud pada ayat (1) diatur dengan Peraturan Dewan Gubemur setelah dikonsultasikan dengan DPR. 36. Di antara Bab X dan Bab XI disisipkan 1 (satu) bab, yakni Bab XA sehingga berbunyi sebagai berikut: BABXA KERAHASIAAN INFORMASI 37. Di antara Pasal 64A dan Pasal 65 disisipkan 1 (satu) pasal, yakni Pasal 64B sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "64B", "b": "BAB VIB KETENTUAN TERKAIT KEPAILITAN", "t": "(1) Setiap orang perseorangan yang menjabat atau pernah menjabat sebagai: a. anggota Dewan Gubernur; atau b. pejabat atau pegawai Bank Indonesia, dilarang menggunakan atau mengungkapkan informasi apa pun yang bersifat rahasia kepada pihak lain, kecuali dalam rangka pelaksanaan fungsi, tugas, dan wewenangnya berdasarkan keputusan Bank Indonesia atau diwajibkan oleh Undang-Undang. (2) Setiap ... jdih.kemenkeu.go.id (2) Setiap Orang yang bertindak untuk dan atas nama Bank Indonesia atau yang dipekerjakan di Bank Indonesia, dilarang menggunakan a tau mengungkapkan informasi apa pun yang bersifat rahasia kepada pihak lain, kecuali dalam rangka pelaksanaan fungsi, tugas, dan wewenangnya berdasarkan keputusan Bank Indonesia atau diwajibkan oleh Undang-Undang. (3) Setiap Orang yang mengetahui informasi yang bersifat rahasia, baik karena kedudukannya, profesinya, sebagai pihak yang diawasi, maupun hubungan apa pun dengan Bank Indonesia, dilarang menggunakan atau mengungkapkan informasi tersebut kepada pihak lain, kecuali dalam rangka pelaksanaan fungsi, tugas, dan wewenangnya berdasarkan keputusan Bank Indonesia atau diwajibkan oleh Undang-Undang. (4) Pelanggaran terhadap ketentuan …"}, {"l": "UU 4/2023", "p": "19", "b": "Bagian Keenam", "t": "Bank Indonesia wajib melaporkan Pengelolaan Rupiah sebagaimana dimaksud dalam Pasal 11 dan Pasal 14A secara periodik setiap 3 (tiga) bulan kepada DPR."}, {"l": "UU 4/2023", "p": "12", "b": "Bagian Kedelapan", "t": "(1) PUSK wajib mengidentifikasi, menilai, dan memahami risiko tindak pidana pencucian uang dan/ atau tindak pidana pendanaan terorisme terkait dengan nasabah, negara atau area geografis, produk, jasa, transaksi, dan/ a tau jaringan distribusi. (2) PUSK wajib memiliki kebijakan, pengawasan, dan prosedur pengelolaan dan mitigasi risiko pencucian uang dan pendanaan terorisme. (3) Ketentuan lebih lanjut mengenai kebijakan, pengawasan, dan prosedur pengelolaan dan mitigasi risiko sebagaimana dimaksud pada ayat (2) diatur oleh Otoritas Jasa Keuangan atau Bank Indonesia sesuai dengan kewenangannya, dengan mengacu pada undang-undang mengenai pencegahan dan pemberantasan tindak pidana pencucian uang."}, {"l": "UU 4/2023", "p": "13", "b": "Bagian Kesatu", "t": "Dalam rangka pengembangan dan penguatan sektor keuangan melalui penataan di sektor perbankan dan perbankan syariah, Undang-Undang 1n1 mengubah, menghapus, dan/ atau menetapkan pengaturan baru beberapa ketentuan yang diatur dalam: a. Undang-Undang Nomor 7 Tahun 1992 tentang Perbankan (Lembaran Negara Republik Indonesia Tahun 1992 Nomor 31, Tambahan Lembaran Negara Republik Indonesia Nomor 3472) sebagaimana telah beberapa kali diubah terakhir dengan Peraturan Pemerintah Pengganti Undang-Undang Nomor 2 Tahun 2022 tentang Cipta Kerja (Lembaran Negara Republik Indonesia Tahun 2022 Nomor 238, Tambahan Lembaran Negara Republik Indonesia Nomor 6841); dan b. Undang-Undang Nomor 21 Tahun 2008 tentang Perbankan Syariah (Lembaran Negara Republik Indonesia Tahun 2008 Nomor 94, Tambahan Lembaran Negara diubah dengan Peraturan Pemerintah Pengganti Undang­ Undang Nomor 2 Tahun 2022 tentang Cipta Kerja (Lembaran Negara Republik Indonesia Tahun 2022 Nomor 238, Tambahan Lembaran Negara Republik Indonesia Nomor 6841)."}, {"l": "UU 4/2023", "p": "7A", "b": "Bagian Kedua", "t": "(1) Dalam melaksanakan kegiatan usaha sebagaimana dimaksud dalam Pasal 6 dan Pasal 7, Bank Umum dapat memanfaatkan teknologi informasi. (2) Dalam rangka mendorong pemanfaatan teknologi informasi sebagaimana dimaksud pada ayat (1), Bank Umum dapat membuka akses data dan informasi Nasabah kepada penyelenggara keuangan lainnya termasuk penyelenggara ITSK berdasarkan persetujuan dan untuk kepentingan Nasabah melalui sistem atau aplikasi tertentu. (3) Pelaksanaan ... jdih.kemenkeu.go.id . REPUBUK INDONESIA (3) Pelaksanaan pembukaan akses data dan informasi Nasabah sebagaimana dimaksud pada ayat (2) dilakukan sesuai dengan ketentuan peraturan perundang-undangan. (4) Ketentuan lebih lanjut mengenai pemanfaatan teknologi informasi sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "7B", "b": "Bagian Kedua", "t": "(1) Dalam melakukan kegiatan usaha sebagaimana dimaksud dalam Pasal 6 dan Pasal 7, Bank Umum dapat beroperasi sebagai Bank digital. (2) Bank Umum sebagaimana dimaksud pada ayat (1) wajib memiliki 1 (satu) kantor fisik sebagai kantor pusat. (3) Ketentuan lebih lanjut mengenai Bank digital sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Otoritas Jasa Keuangan setelah dikonsultasikan dengan DPR. 5. Di antara Pasal 8 dan Pasal 9 disisipkan 1 (satu) pasal, yakni Pasal 8A sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "12A", "b": "Bagian Kedua", "t": "(1) Bank Umum dapat membeli sebagian atau seluruh Agunan, baik melalui pelelangan maupun di luar pelelangan berdasarkan penyerahan secara sukarela oleh pemilik Agunan atau berdasarkan kuasa untuk menjual di luar pelelangan dari pemilik Agunan dalam hal Nasabah Debitur tidak memenuhi kewajiban kepada Bank, dengan ketentuan Agunan yang dibeli wajib dicairkan secepatnya. (2) Dalam hal Nasabah Debitur tidak memenuhi kewajibannya sebagaimana dimaksud pada ayat (1) dalam jangka waktu tertentu, dan tidak terdapat permasalahan terhadap kepemilikan Agunan, Bank Umum dapat membeli sebagian atau seluruh Agunan, baik melalui pelelangan maupun di luar pelelangan. (3) Bank Umum harus memperhitungkan harga pembelian Agunan sebagaimana dimaksud pada ayat (1) dan ayat (2) dengan kewajiban Nasabah Bank Umum yang bersangkutan. (4) Dalam hal harga pembelian Agunan sebagaimana dimaksud pada ayat (3) melebihi jumlah kewajiban Nasabah kepada Bank Umum, selisih kelebihan jumlah tersebut harus dikembalikan kepada Nasabah setelah dikurangi dengan biaya lelang dan biaya lain yang langsung terkait dengan proses pembelian Agunan. (5) Ketentuan ... jdih.kemenkeu.go.id REPUBUK INDONESIA . (5) Ketentuan lebih …"}, {"l": "UU 4/2023", "p": "12B", "b": "Bagian Kedua", "t": "(1) Bank Umum wajib menyalurkan Kredit atau Pembiayaan Berdasarkan Prinsip Syariah untuk sektor tertentu, Usaha Mikro, Kecil, dan Menengah, pembiayaan inklusif, dan/ atau pembiayaan berkelanjutan. (2) Otoritas Jasa Keuangan dan Bank Indonesia berkoordinasi untuk mengatur kewajiban penyaluran Kredit atau Pembiayaan Berdasarkan Prinsip Syariah sebagaimana dimaksud pada ayat (1). 9. Ketentuan Pasal 13 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "13A", "b": "Bagian Kedua", "t": "Dalam melaksanakan kegiatan usaha sebagaimana dimaksud dalam Pasal 13, BPR dapat memanfaatkan teknologi informasi. 11. Ketentuan Pasal 14 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "15A", "b": "Bagian Kedua", "t": "(1) Bank Umum dapat bekerja sama dengan BPR dalam penyaluran Kredit atau Pembiayaan Berdasarkan Prinsip Syariah bagi Usaha Mikro, Kecil, dan Menengah. (2) Ketentuan lebih lanjut mengenai kerja sama Bank Umum dan BPR sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Otoritas Jasa Keuangan. 14. Ketentuan Pasal 16 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "16", "b": "Bagian Kedua", "t": "(1) Setiap Orang yang melakukan kegiatan menghimpun dana dari masyarakat dalam bentuk Simpanan wajib terlebih dahulu memperoleh izin usaha sebagai Bank Umum atau BPR dari Otoritas Jasa Keuangan, kecuali kegiatan menghimpun dana dari masyarakat dimaksud diatur dengan undang-undang tersendiri. (2) Untuk memperoleh izin usaha sebagai Bank Umum atau BPR sebagaimana dimaksud pada ayat (1), wajib dipenuhi persyaratan minimal: a. susunan organisasi dan kepengurusan; b. permodalan; c. kepemilikan; d. keahlian di bidang Perbankan; dan e. kelayakan rencana kerja. (3) Ketentuan lebih lanjut mengenai persyaratan dan tata cara penzman Bank Umum atau BPR sebagaimana dimaksud pada ayat (1) dan ayat (2) diatur dalam Peraturan Otoritas Jasa Keuangan. 15. Ketentuan . . . jdih.kemenkeu.go.id . REPUBUK INDONESIA . 15. Ketentuan Pasal 18 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "19A", "b": "Bagian Kedua", "t": "(1) BPR memiliki jaringan kantor dalam wilayah yang terbatas. (2) Ketentuan mengenai batasan wilayah jaringan kantor BPR sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Otoritas Jasa Keuangan. 18. Ketentuan Pasal 20 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "20A", "b": "Bagian Kedua", "t": "(1) Bank wajib menerapkan prinsip kehati-hatian termasuk manajemen risiko dalam melakukan kegiatan usaha. (2) Bank wajib menyusun prosedur internal mengenai pelaksanaan prinsip kehati-hatian sebagaimana dimaksud pada ayat (1)."}, {"l": "UU 4/2023", "p": "20B", "b": "Bagian Kedua", "t": "(1) Bank wajib menerapkan prinsip tata kelola yang baik dalam melakukan kegiatan usaha. (2) Bank wajib menyusun prosedur internal mengenai pelaksanaan prinsip tata kelola yang baik sebagaimana dimaksud pada ayat (1). (3) Ketentuan lebih lanjut mengenai prinsip tata kelola yang baik sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Otoritas Jasa Keuangan. 20. Ketentuan Pasal 21 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "21", "b": "Bagian Kedua", "t": "(1) Bank Umum berbentuk badan hukum perseroan terbatas. (2) BPR berbentuk badan hukum perseroan terbatas atau koperasi. (3) Bentuk badan hukum dari kantor perwakilan dan Kantor Cabang Bank yang berkedudukan di luar negeri mengikuti bentuk badan hukum kantor pusatnya. 21. Ketentuan Pasal 23 diubah sehingga berbunyi sebagai berikut: Pasal23 (1) BPR didirikan oleh: a. warga ... jdih.kemenkeu.go.id REPUBUK INDONESIA a. warga negara Indonesia; dan / a tau b. badan hukum Indonesia. (2) BPR dapat melakukan penawaran umum di bursa efek dengan syarat dan ketentuan yang diatur oleh Otoritas Jasa Keuangan. (3) Ketentuan lebih lanjut mengenai pendirian BPR sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Otoritas Jasa Keuangan. 22. Ketentuan Pasal 28 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "28A", "b": "Bagian Kedua", "t": "(1) BPR dapat melakukan Penggabungan dengan lembaga keuangan mikro. (2) Dalam hal terjadi Penggabungan antara BPR dengan lembaga keuangan mikro, entitas hasil Penggabungan wajib menjadi BPR. (3) Ketentuan ... jdih.kemenkeu.go.id REPUBUK INDONESIA (3) Ketentuan lebih lanjut mengenai Penggabungan BPR dengan lembaga keuangan mikro sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Otoritas Jasa Keuangan. 24. Ketentuan Pasal 29 diubah sehingga berbunyi sebagai berikut: Pasal29 {1) Bank wajib mematuhi peraturan yang ditetapkan oleh Otoritas Jasa Keuangan. (2) Bank wajib memelihara tingkat kesehatan Bank serta aspek terkait tingkat kesehatan sesuai dengan peraturan yang ditetapkan oleh Otoritas Jasa Keuangan. (3) Pengawasan yang dilakukan oleh Otoritas Jasa Keuangan terhadap Bank dilakukan baik secara langsung maupun tidak langsung. (4) Pengawasan secara langsung terhadap Bank oleh Otoritas Jasa Keuangan dilakukan melalui pemeriksaan, baik secara berkala maupun sewaktu­ waktu apabila diperlukan. (5) Otoritas Jasa Keuangan berwenang melakukan pengawasan secara langsung terhadap pihak terelasi dalam kelompok usaha Bank dan pihak lain yang menerima fasilitas penyediaan dana dari …"}, {"l": "UU 4/2023", "p": "31A", "b": "Bagian Kedua", "t": "Otoritas Jasa Keuangan dapat menugaskan pihak lain untuk dan atas nama Otoritas Jasa Keuangan dalam melaksanakan tugas tertentu. 29. Ketentuan ... jdih.kemenkeu.go.id REPUBUK INDONESIA . 29. Ketentuan Pasal 33 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "37C", "b": "Bagian Kedua", "t": "(1) Otoritas Jasa Keuangan berwenang mengatur dan mengembangkan penyelenggaraan sistem layanan informasi keuangan. (2) Informasi pada sistem layanan informasi keuangan sebagaimana dimaksud pada ayat (1) dikelola oleh Otoritas Jasa Keuangan, dan dapat diberikan dan/atau dipertukarkan kepada pihak lain dalam rangka pelaksanaan ketentuan peraturan perundang-undangan. (3) Setiap ... jdih.kemenkeu.go.id . REPUBUK INDONESIA (3) Setiap pihak yang memperoleh informasi sebagaimana dimaksud pada ayat (2) wajib menjaga keamanan dan kerahasiaan data sesuai dengan ketentuan peraturan perundang-undangan. (4) Otoritas Jasa Keuangan berwenang mengatur dan mengawasi lembaga pengelola informasi perkreditan."}, {"l": "UU 4/2023", "p": "37D", "b": "Bagian Kedua", "t": "(1) Otoritas Jasa Keuangan berwenang menetapkan dimulainya, tidak dilakukannya, atau dihentikannya penyidikan terhadap tindak pidana Perbankan. (2) Sebelum menetapkan dimulainya penyidikan sebagaimana dimaksud pada ayat (1), Otoritas Jasa Keuangan melakukan penyelidikan terhadap dugaan tindak pidana Perbankan. (3) Pada tahap penyelidikan sebagaimana dimaksud pada ayat (2), pihak yang diduga melakukan tindak pidana Perbankan dapat mengajukan permohonan kepada Otoritas Jasa Keuangan untuk penyelesaian pelanggaran atas peraturan perundang-undangan di sektor Perbankan. (4) Otoritas Jasa Keuangan melakukan penilaian terhadap permohonan penyelesaian pelanggaran sebagaimana dimaksud pada ayat (3) dan menghitung nilai kerugian atas pelanggaran. (5) Dalam melakukan penilaian terhadap permohonan penyelesaian pelanggaran dan perhitungan nilai kerugian atas pelanggaran sebagaimana dimaksud pada ayat (4), Otoritas Jasa Keuangan mempertimbangkan minimal: a. ada atau tidaknya penyelesaian atas kerugian yang timbul akibat tindak pidana; b. nilai transaksi dan/atau nilai kerugian atas pelanggaran; dan c. dampak terhadap sektor Perbankan, Bank, dan/atau kepentingan Nasabah dan/atau masyarakat. (6) …"}, {"l": "UU 4/2023", "p": "37E", "b": "Bagian Kedua", "t": "(1) Setiap Orang dilarang: a. membuat atau menyebabkan adanya pencatatan palsu dalam pembukuan atau dalam laporan, dokumen atau laporan kegiatan usaha, dan/atau laporan transaksi atau rekening suatu Bank; b. menghilangkan, tidak memasukkan, atau menyebabkan tidak dilakukannya pencatatan dalam pembukuan atau dalam laporan, dokumen atau laporan kegiatan usaha, dan/ a tau laporan transaksi atau rekening suatu Bank;dan c. mengubah, ... jdih.kemenkeu.go.id . REPUBUK INDONESIA e. mengubah, mengaburkan, menyembunyikan, menghapus, atau menghilangkan adanya suatu peneatatan dalam pembukuan atau dalam laporan, dokumen atau laporan kegiatan usaha, dan/ atau laporan transaksi atau rekening suatu Bank, atau mengubah, mengaburkan, menghilangkan, menyembunyikan, a tau merusak eatatan pembukuan. (2) Pemegang saham atau yang setara, anggota dewan komisaris atau yang setara, anggota direksi atau yang setara, atau pegawai Bank dilarang meminta atau menerima, mengizinkan atau menyetujui untuk menerima suatu imbalan, komisi, uang tambahan, pelayanan, uang, dan/ atau barang berharga, untuk keuntungan pribadi atau untuk keuntungan keluarganya, dalam rangka mendapatkan atau berusaha mendapatkan bagi …"}, {"l": "UU 4/2023", "p": "40B", "b": "Bagian Kedua", "t": "Otoritas Jasa Keuangan berwenang memberikan izin membuka Rahasia Bank: a. untuk kepentingan peradilan dalam perkara pidana sebagaimana dimaksud dalam Pasal 40A ayat (1) hurufb;dan b. untuk memenuhi bantuan timbal balik dalam masalah pidana sebagaimana dimaksud dalam Pasal 40A ayat (1) huruf g. Pasal 40C ... jdih.kemenkeu.go.id . REPUBUK INDONESIA"}, {"l": "UU 4/2023", "p": "40C", "b": "Bagian Kedua", "t": "Setiap Orang yang mendapatkan informasi mengenai Nasabah Penyimpan dan simpanannya sebagaimana dimaksud dalam Pasal 40A wajib menjaga kerahasiaan informasi mengenai Nasabah Penyimpan dan simpanannya. 39. Pasal 41 dihapus. 40. Ketentuan Pasal 41A diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "41A", "b": "Bagian Kedua", "t": "(1) Untuk penyelesaian piutang yang sudah diserahkan kepada panitia urusan piutang negara, Otoritas Jasa Keuangan memberikan izin kepada panitia urusan piutang negara untuk memperoleh keterangan dari Bank mengenai Simpanan Nasabah Debitur. (2) Izin sebagaimana dimaksud pada ayat (1) diberikan secara tertulis oleh Otoritas Jasa Keuangan atas permintaan tertulis dari ketua panitia urusan piutang negara. (3) Permintaan sebagaimana dimaksud pada ayat (2) harus menyebutkan nama dan jabatan panitia urusan piutang negara serta nama Nasabah Debitur yang bersangkutan. 41. Ketentuan Pasal 42 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "42", "b": "Bagian Kedua", "t": "(1) Untuk kepentingan peradilan dalam perkara pidana sebagaimana dimaksud dalam Pasal 40A ayat (1) huruf b, Otoritas Jasa Keuangan berwenang memberikan izin kepada polisi, jaksa, hakim, atau penyidik lain yang diberi wewenang berdasarkan Undang-Undang untuk memperoleh informasi dari Bank mengenai Simpanan tersangka, terdakwa, terpidana, atau pihak lain yang terkait dengan tersangka, terdakwa, atau terpidana. (2) Izin sebagaimana dimaksud pada ayat (1) diberikan secara tertulis atas permintaan tertulis dari: a. Kepala ... jdih.kemenkeu.go.id . REPUBUK INDONESIA a. Kepala Kepolisian Negara Republik Indonesia, Kepala Badan Reserse Kriminal Kepolisian Negara Republik Indonesia, atau kepala kepolisian daerah dalam hal permintaan diajukan oleh penyidik dari Kepolisian Negara b. Jaksa Agung, Jaksa Agung Muda, atau kepala kejaksaan tinggi dalam hal permintaan diajukan oleh jaksa penyidik dan/ a tau penuntut umurn; c. Ketua Mahkamah Agung, ketua pengadilan tinggi, atau ketua pengadilan negeri; atau d. pimpinan instansi yang diberi wewenang untuk melakukan penyidikan atau jabatan satu tingkat di bawah pimpinan instansi yang diberi wewenang untuk melakukan penyidikan. (3) Untuk memenuhi …"}, {"l": "UU 4/2023", "p": "43", "b": "Bagian Kedua", "t": "Dalam perkara perdata sebagaimana dimaksud dalam Pasal 40A ayat (1) huruf a, berlaku: a. untuk perkara perdata antara Bank dan Nasabah, direksi Bank atau yang setara yang bersangkutan dapat menginformasikan kepada pengadilan tentang keadaan keuangan Nasabah yang bersangkutan dan memberikan keterangan lain yang relevan dengan perkara tersebut; atau b. untuk perkara perdata antara Nasabah dan Nasabah, dan terkait dengan Nasabah, direksi Bank atau yang setara harus menginformasikan kepada pengadilan tentang keadaan keuangan Nasabah dan informasi lain yang relevan dengan perkara berdasarkan permintaan ketua pengadilan negeri, ketua pengadilan tinggi, atau Ketua Mahkamah Agung. 44. Di antara Pasal 43 dan Pasal 44 disisipkan 1 (satu) pasal, yakni Pasal 43A sehingga berbunyi sebagai berikut: Pasal43A Atas permintaan kurator yang ditetapkan berdasarkan putusan pengadilan niaga mengenai kepailitan atau likuidator yang ditetapkan berdasarkan penetapan pengadilan dalam rangka pemberesan harta sebagaimana dimaksud dalam Pasal 40A ayat (1) huruf c, Bank wajib memberikan informasi mengenai Simpanan Nasabah Penyimpan pada Bank yang terkait dengan pelaksanaan kepailitan atau likuidasi. 45. …"}, {"l": "UU 4/2023", "p": "44A", "b": "Bagian Kedua", "t": "(1) Atas permintaan, persetujuan, atau kuasa dari Nasabah Penyimpan yang dibuat secara tertulis sebagaimana dimaksud dalam Pasal 40A ayat (1) huruf d, Bank wajib memberikan Rahasia Bank kepada pihak yang ditunjuk oleh Nasabah Penyimpan. (2) Dalam hal Nasabah Penyimpan telah meninggal dunia, ahli waris yang sah dari Nasabah Penyimpan sebagaimana dimaksud dalam Pasal 40A ayat (1) huruf e berhak memperoleh keterangan mengenai Simpanan Nasabah Penyimpan. 47. Di antara Pasal 44A dan Pasal 45 disisipkan 2 (dua) pasal, yakni Pasal 44B dan 44C sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "44B", "b": "Bagian Kedua", "t": "Dalam rangka pemenuhan pembukaan Rahasia Bank untuk tujuan penyelenggaraan negara di tingkat pusat dan kepentingan umum sebagaimana dimaksud dalam Pasal 40A ayat (1) huruf i, instansi terkait harus berkoordinasi dengan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "44C", "b": "Bagian Kedua", "t": "(1) Untuk pelaksanaan perjanjian kerja sama otoritas antarnegara yang telah ditandatangani secara resiprokal sebagaimana dimaksud dalam Pasal 40A ayat (1) huruf 1, mitra perjanjian mengajukan permintaan informasi kepada Otoritas Jasa Keuangan untuk mendapatkan informasi mengenai Nasabah Penyimpan dan simpanannya. (2) Otoritas Jasa Keuangan dapat memberikan informasi sebagaimana dimaksud pada ayat (1) dengan mempertimbangkan asas resiprokal. (3) Dalam ... jdih.kemenkeu.go.id . REPUBUK INDONESIA . (3) Dalam hal Otoritas Jasa Keuangan memberikan informasi sebagaimana dimaksud pada ayat (1), informasi tersebut dapat digunakan oleh mitra perjanjian yang meminta informasi baik untuk kepentingan pidana, perdata, maupun administratif sesuai dengan ketentuan peraturan perundang- undangan. 48. Ketentuan Pasal 45 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "45", "b": "Bagian Kedua", "t": "(1) Pihak yang merasa dirugikan akibat keterangan yang diberikan oleh Bank sebagaimana dimaksud dalam Pasal 4 lA, Pasal 42, Pasal 43, Pasal 43A, Pasal 44, Pasal 44A, dan Pasal 44B, berhak untuk mengetahui isi keterangan tersebut dan meminta pembetulan jika terdapat kesalahan dalam keterangan yang diberikan. (2) Dalam hal permintaan pembetulan oleh pihak yang merasa dirugikan akibat keterangan yang diberikan oleh Bank sebagaimana dimaksud pada ayat (1) tidak dipenuhi oleh Bank, pihak yang merasa dirugikan dapat mengajukan gugatan ke pengadilan yang berwenang. 49. Di antara Pasal 45 dan Pasal 46, disisipkan 1 (satu) pasal yakni Pasal 45A sehingga berbunyi sebagai berikut: Pasal45A (1) Ketua Dewan Komisioner Otoritas Jasa Keuangan, Wakil Ketua Dewan Komisioner Otoritas Jasa Keuangan, anggota Dewan Komisioner Otoritas Jasa Keuangan, serta pejabat dan pegawai Otoritas Jasa Keuangan yang berkaitan dengan pelaksanaan Undang-Undang ini tidak dapat dituntut baik secara perdata maupun pidana jika dalam melaksanakan tugas didasarkan pada iktikad baik dan sesuai dengan ketentuan peraturan perundang-undangan. (2) Segala tindakan termasuk keputusan yang diambil berdasarkan Undang-Undang ini …"}, {"l": "UU 4/2023", "p": "47A", "b": "Bagian Kedua", "t": "Anggota dewan komisaris atau yang setara, anggota direksi atau yang setara, atau pegawai Bank yang dengan sengaja tidak memberikan keterangan sebagaimana dimaksud dalam Pasal 42A dan Pasal 44A dipidana dengan pidana penjara paling singkat 2 (dua) tahun dan paling lama 7 (tujuh) tahun dan pidana denda paling sedikit Rp4.000.000.000,00 (empat miliar rupiah) dan paling banyak Rpl5.000.000.000,00 (lima belas miliar rupiah). 53. Ketentuan Pasal 48 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "48", "b": "Bagian Kedua", "t": "Anggota dewan komisaris atau yang setara, anggota direksi atau yang setara, atau pegawai Bank yang dengan sengaja tidak memberikan keterangan dan/atau tidak melaksanakan perintah sebagaimana dimaksud dalam Pasal 30 ayat (1), Pasal 30 ayat (3), Pasal 34 ayat (1), Pasal 34 ayat (2) dan/atau Pasal 36A ayat (1) huruf c dipidana dengan pidana penjara paling singkat 2 (dua) tahun dan paling lama 10 (sepuluh) tahun dan pidana denda paling sedikit Rp5.000.000.000,00 (lima miliar rupiah) dan paling banyak Rpl00.000.000.000,00 (seratus miliar rupiah). 54. Ketentuan ... jdih.kemenkeu.go.id REPUBUK INDONESIA 54. Ketentuan Pasal 49 diubah sehingga berbunyi sebagai berikut: Pasal49 (1) Anggota dewan komisaris a tau yang setara, anggota direksi atau yang setara, atau pegawai Bank yang dengan sengaja: a. membuat atau menyebabkan adanya pencatatan palsu dalam pembukuan atau dalam laporan, dokumen atau laporan kegiatan usaha, dan/ a tau laporan transaksi a tau rekening suatu Bank sebagaimana dimaksud dalam Pasal 37E ayat (1) huruf a; b. menghilangkan, tidak memasukkan, atau menyebabkan tidak dilakukannya pencatatan dalam pembukuan atau dalam laporan, dokumen atau laporan kegiatan usaha, dan/ atau …"}, {"l": "UU 4/2023", "p": "50", "b": "Bagian Kedua", "t": "Pihak Terafiliasi yang dengan sengaja tidak melaksanakan langkah yang diperlukan untuk memastikan ketaatan Bank terhadap ketentuan dalam Undang-Undang ini dan peraturan perundang-undangan lainnya sebagaimana dimaksud dalam Pasal 37E ayat (4) dipidana dengan pidana penjara paling singkat 3 (tiga) tahun dan paling lama 8 (delapan) tahun dan pidana denda paling sedikit Rp5.000.000.000,00 (lima miliar rupiah) dan paling banyak Rpl00.000.000.000,00 (seratus miliar rupiah). 56. Ketentuan ... jdih.kemenkeu.go.id REPUBUK INDONESIA 56. Ketentuan Pasal 50A diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "50D", "b": "Bagian Kedua", "t": "(1) Selain dijatuhi pidana penjara dan pidana denda sebagaimana dimaksud dalam Pasal 46, Pasal 4 7, Pasal 47A, Pasal 48, Pasal 49, Pasal 50, Pasal 50A, Pasal 50B, dan Pasal SOC terpidana dapat dijatuhi pidana tambahan berupa penggantian kerugian apabila tindak pidana mengakibatkan kerugian. (2) Pidana tambahan berupa penggantian kerugian sebagaimana dimaksud pada ayat (1) dikembalikan kepada pihak yang dirugikan sejumlah kerugian yang diderita atau secara proporsional dalam hal jumlah penggantian kerugian tidak mencukupi jumlah total. kerugian yang ditimbulkan. (3) Dalam melaksanakan putusan pidana sebagaimana dimaksud pada ayat (1), terpidana diberikan jangka waktu selama 1 (satu) bulan sejak putusan telah memperoleh kekuatan hukum tetap. (4) Dalam hal terdapat alasan kuat, jangka waktu sebagaimana dimaksud pada ayat (3) dapat diperpanjang untuk jangka waktu paling lama 1 (satu) bulan. (5) Dalam hal terpidana tidak membayar pidana denda dan pidana tambahan berupa penggantian kerugian sebagaimana dimaksud pada ayat (1), harta benda terpidana disita dan dilelang oleh jaksa untuk melunasi denda dan ganti kerugian tersebut. (6) Dalam ... jdih.kemenkeu.go.id REPUBUK INDONESIA (6) …"}, {"l": "UU 4/2023", "p": "2A", "b": "Bagian Ketiga", "t": "(1) Penggunaan aset dalam transaksi atau sebagai bagian struktur produk dan/atau jasa Perbankan Syariah dapat dilakukan dengan cara menjual dan/ atau menyewakan Hak Manfaat atas aset atau barang. (2) Penjualan dan/ a tau penyewaan Hak Manfaat atas aset atau barang sebagaimana dimaksud pada ayat (1) dikecualikan dari peraturan perundang­ undangan yang mewajibkan pendaftaran atas kepemilikan suatu aset atau barang sebagai dasar legalitas kepemilikan. 3. Ketentuan Pasal 4 diubah sehingga berbunyi sebagai berikut: Pasal4 (1) Bank Syariah dan UUS wajib menjalankan fungsi menghimpun dan menyalurkan dana masyarakat. (2) Bank Syariah dan UUS dapat menjalankan fungsi sosial dalam bentuk lembaga baitulmal, yaitu menerima dana yang berasal dari zakat, infak, sedekah, hibah, atau dana sosial lainnya dan menyalurkannya kepada organisasi pengelola zakat. (3) Bank Syariah dan UUS dapat menghimpun dana sosial yang berasal dari wakaf uang dan menjadi pengelola wakaf/nazir dan/atau menyalurkannya melalui pengelola wakaf/nazir sesuai dengan kehendak pemberi wakaf/wakif. (4) Ketentuan . . . jdih.kemenkeu.go.id . REPUBLIK INDONESIA (4) Ketentuan pelaksanaan fungsi sosial sebagaimana dimaksud pada ayat …"}, {"l": "UU 4/2023", "p": "6A", "b": "Bagian Ketiga", "t": "(1) BPR Syariah memiliki jaringan kantor dalam wilayah yang terbatas. (2) Ketentuan mengenai batasan wilayah jaringan kantor BPR Syariah sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Otoritas Jasa Keuangan. 7. Ketentuan Pasal 7 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "17A", "b": "Bagian Ketiga", "t": "(1) BPR Syariah dapat melakukan Penggabungan dengan lembaga keuangan mikro. (2) Dalam hal terjadi Penggabungan antara BPR Syariah dan lembaga keuangan mikro, Bank hasil Penggabungan wajib menjadi BPR Syariah. (3) Ketentuan ... jdih.kemenkeu.go.id REPUBUK INDONESIA (3) Ketentuan lebih lanjut mengenai Penggabungan antara BPR Syariah dan lembaga keuangan mikro sebagaimana dimaksud pada ayat (1) dan ayat (2) diatur dalam Peraturan Otoritas Jasa Keuangan. 11. Ketentuan Pasal 19 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "21A", "b": "Bagian Ketiga", "t": "Selain melakukan kegiatan usaha sebagaimana dimaksud dalam Pasal 21, BPR Syariah dapat: a. melakukan kerja sama dengan WK lain serta kerja sama dengan selain WK dalam pemberian layanan jasa keuangan kepada Nasabah; b. melakukan kegiatan usaha penukaran valuta asing; dan c. melakukan penyertaan modal pada lembaga penunjang BPR Syariah sesuai dengan pembatasan yang diatur dalam ketentuan peraturan perundang­ undangan."}, {"l": "UU 4/2023", "p": "21B", "b": "Bagian Ketiga", "t": "(1) Dalam melaksanakan kegiatan usaha sebagaimana dimaksud dalam Pasal 19 sampai dengan Pasal 2 lA, Bank Syariah dan UUS dapat memanfaatkan teknologi informasi. (2) Dalam rangka mendorong pemanfaatan teknologi informasi sebagaimana dimaksud pada ayat (1), Bank Syariah dan UUS dapat membuka akses data dan informasi Nasabah kepada penyelenggara keuangan lainnya termasuk penyelenggara ITSK berdasarkan persetujuan dan untuk kepentingan Nasabah melalui sistem atau aplikasi tertentu. (3) Pelaksanaan pembukaan akses data dan informasi Nasabah sebagaimana dimaksud pada ayat (2) dilakukan sesuai dengan ketentuan peraturan perundang-undangan. (4) Ketentuan . . . jdih.kemenkeu.go.id . REPUBUK INDONESIA (4) Ketentuan lebih lanjut mengenai pemanfaatan teknologi informasi sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "21C", "b": "Bagian Ketiga", "t": "(1) Bank Umum Syariah dan UUS wajib menyalurkan Pembiayaan untuk sektor tertentu, Usaha Mikro, Kecil, dan Menengah, pembiayaan inklusif, dan/ a tau pembiayaan berkelanjutan. (2) Otoritas Jasa Keuangan dan Bank Indonesia berkoordinasi untuk mengatur kewajiban penyaluran Pembiayaan sebagaimana dimaksud pada ayat (1). 16. Ketentuan Pasal 24 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "27", "b": "Bagian Ketiga", "t": "(1) Pihak utama wajib mendapat persetujuan Otoritas Jasa Keuangan. (2) Dalam rangka pemberian persetujuan sebagaimana dimaksud pada ayat (1), Otoritas Jasa Keuangan melakukan penilaian kemampuan dan kepatutan. (3) Ketentuan lebih lanjut mengenai pemberian persetujuan Otoritas Jasa Keuangan sebagaimana dimaksud pada ayat (1) dan penilaian kemampuan serta kepatutan sebagaimana dimaksud pada ayat (2) diatur dalam Peraturan Otoritas Jasa Keuangan. 20. Pasal 28 dihapus. 21. Pasal 29 dihapus. 22. Pasal 30 ... jdih.kemenkeu.go.id REPUBUK INDONESIA 22. Pasal 30 dihapus. 23. Pasal 31 dihapus. 24. Ketentuan Pasal 34 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "40", "b": "Bagian Ketiga", "t": "(1) Bank Syariah dan UUS dapat membeli sebagian atau seluruh Agunan, baik melalui pelelangan maupun di luar pelelangan berdasarkan penyerahan secara sukarela oleh pemilik Agunan atau berdasarkan kuasa untuk menjual di luar pelelangan dari pemilik Agunan dalam hal Nasabah Penerima Fasilitas tidak memenuhi kewajiban kepada Bank, dengan ketentuan Agunan yang dibeli wajib dicairkan secepatnya. (2) Dalam hal Nasabah Penerima Fasilitas tidak memenuhi kewajiban sebagaimana dimaksud pada ayat (1) dalam jangka waktu tertentu, dan tidak terdapat permasalahan terhadap kepemilikan Agunan, Bank Syariah dan UUS dapat membeli sebagian atau seluruh Agunan, baik melalui pelelangan maupun di luar pelelangan. (3) Bank Syariah dan UUS harus memperhitungkan harga pembelian Agunan sebagaimana dimaksud pada ayat (1) dan ayat (2) dengan kewajiban Nasabah Bank Syariah dan UUS yang bersangkutan. (4) Dalam hal harga pembelian Agunan sebagaimana dimaksud pada ayat (3) melebihi jumlah kewajiban Nasabah kepada Bank Syariah dan UUS, selisih kelebihan jumlah tersebut harus dikembalikan kepada Nasabah setelah dikurangi dengan biaya lelang dan biaya lain yang langsung terkait dengan proses pembelian Agunan. (5) …"}, {"l": "UU 4/2023", "p": "41B", "b": "Bagian Ketiga", "t": "Otoritas Jasa Keuangan berwenang memberikan izin membuka Rahasia Bank: a. untuk kepentingan peradilan dalam perkara pidana sebagaimana dimaksud dalam Pasal 41A ayat (1) huruf b; dan b. untuk memenuhi bantuan timbal balik dalam masalah pidana sebagaimana dimaksud dalam Pasal 4 lA ayat (1) huruf g."}, {"l": "UU 4/2023", "p": "41C", "b": "Bagian Ketiga", "t": "Setiap Orang yang mendapatkan informasi mengenai Nasabah Penyimpan dan Simpanannya serta Nasabah Investor dan lnvestasinya sebagaimana dimaksud dalam Pasal 4 lA wajib menjaga kerahasiaan informasi mengenai Nasabah Penyimpan dan Simpanannya serta informasi mengenai Nasabah Investor dan Investasinya. 30. Pasal 42 ... jdih.kemenkeu.go.id 30. Pasal 42 dihapus. 31. Ketentuan Pasal 43 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "44", "b": "Bagian Ketiga", "t": "Bank Syariah dan Bank Umum Konvensional yang memiliki UUS wajib memberikan informasi yang diminta oleh pihak sebagaimana dimaksud dalam Pasal 43. 33. Ketentuan Pasal 45 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "45A", "b": "Bagian Ketiga", "t": "Atas permintaan kurator yang ditetapkan berdasarkan putusan pengadilan niaga mengenai kepailitan atau likuidator yang ditetapkan berdasarkan penetapan pengadilan dalam rangka pemberesan harta sebagaimana dimaksud dalam Pasal 41A ayat (1) huruf c, Bank Syariah dan Bank Umum Konvensional yang memiliki UUS wajib memberikan informasi mengenai Simpanan Nasabah Penyimpan dan Investasi Nasabah Investor pada Bank Syariah dan Bank Umum Konvensional yang memiliki UUS yang terkait dengan pelaksanaan kepailitan atau likuidasi. 35. Ketentuan Pasal 46 diubah sehingga berbunyi sebagai berikut: Pasal46 Dalam rangka tukar menukar informasi antar-Bank sebagaimana dimaksud dalam Pasal 41A ayat (1) huruf f, direksi Bank Syariah dan Bank Umum Konvensional yang memiliki UUS dapat memberitahukan Rahasia Bank kepada Bank lain. 36. Ketentuan ... jdih.kemenkeu.go.id . REPUBLIK INDONESIA 36. Ketentuan Pasal 47 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "48A", "b": "Bagian Ketiga", "t": "Dalam rangka pemenuhan pembukaan Rahasia Bank untuk tujuan penyelenggaraan negara dan kepentingan umum sebagaimana dimaksud dalam Pasal 41A ayat (1) huruf i, instansi terkait harus berkoordinasi dengan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "48C", "b": "Bagian Ketiga", "t": "(1) Ketua Dewan Komisioner Otoritas Jasa Keuangan, Wakil Ketua Dewan Komisioner Otoritas Jasa Keuangan, anggota Dewan Komisioner Otoritas Jasa Keuangan, serta pejabat dan pegawai Otoritas Jasa Keuangan yang berkaitan dengan pelaksanaan Undang-Undang ini tidak dapat dituntut baik secara perdata maupun pidana jika dalam melaksanakan tugas didasarkan pada iktikad baik dan sesuai dengan ketentuan peraturan perundang-undangan. (2) Segala tindakan termasuk keputusan yang diambil berdasarkan Undang-Undang ini bukan merupakan objek gugatan yang dapat diajukan kepada peradilan tata usaha negara. (3) Dalam hal Ketua Dewan Komisioner Otoritas Jasa Keuangan, Wakil Ketua Dewan Komisioner Otoritas Jasa Keuangan, anggota Dewan Komisioner Otoritas Jasa Keuangan, serta pejabat dan pegawai Otoritas Jasa Keuangan yang melaksanakan tugas berdasarkan Undang-Undang m1 menghadapi tuntutan hukum yang berkaitan dengan pelaksanaan tugas dan wewenang, yang bersangkutan mendapat bantuan hukum dari lembaga yang diwakili atau yang menugaskan. 39. Ketentuan Pasal 49 diubah sehingga berbunyi sebagai berikut: Pasal 49 ... jdih.kemenkeu.go.id REPUBUK INDONESIA Pasal49 (1) Pihak yang merasa dirugikan akibat …"}, {"l": "UU 4/2023", "p": "51", "b": "Bagian Ketiga", "t": "Bank Syariah dan UUS wajib memelihara tingkat kesehatan serta aspek terkait tingkat kesehatan dan kepatuhan terhadap Prinsip Syariah sesuai dengan ketentuan yang diatur oleh Otoritas Jasa Keuangan. 42. Ketentuan Pasal 52 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "52", "b": "Bagian Ketiga", "t": "(1) Bank Syariah dan UUS wajib menyampaikan data, informasi, keterangan, atau penjelasan mengenai usaha Bank Syariah dan UUS, dan hal lain yang terkait dengan kegiatan usahanya kepada Otoritas Jasa Keuangan. (2) Pengawasan ... jdih.kemenkeu.go.id REPUBUK INDONESIA (2) Pengawasan secara langsung terhadap Bank Syariah dan UUS oleh Otoritas Jasa Keuangan dilakukan melalui pemeriksaan, baik secara berkala maupun sewaktu-waktu apabila diperlukan. (3) Otoritas Jasa Keuangan dapat memeriksa data, informasi, keterangan, atau penjelasan mengenai usaha Bank Syariah dan UUS, dan hal lain yang terkait dengan kegiatan usaha sebagaimana dimaksud pada ayat (1). (4) Dalam rangka pelaksanaan tugas pengawasan, Otoritas Jasa Keuangan berwenang: a. meminta Bank Syariah dan UUS untuk mengambil dan menyerahkan data/ dokumen dari setiap tempat yang terkait Bank Syariah dan UUS; b. meminta Bank Syariah dan UUS untuk mengambil dan menyerahkan data/ dokumen dan keterangan dari setiap pihak yang menurut penilaian Otoritas Jasa Keuangan memiliki pengaruh terhadap Bank Syariah dan UUS; dan c. memerintahkan Bank Syariah dan UUS untuk melakukan pemblokiran rekening tertentu. (5) Otoritas Jasa Keuangan berwenang …"}, {"l": "UU 4/2023", "p": "54A", "b": "Bagian Ketiga", "t": "(1) Otoritas Jasa Keuangan berwen~ng mengatur dan mengembangkan penyelenggaraan sistem layanan informasi keuangan. (2) Informasi pada sistem layanan informasi keuangan sebagaimana dimaksud pada ayat (1) dikelola oleh Otoritas Jasa Keuangan serta dapat diberikan dan/atau dipertukarkan kepada pihak lain dalam rangka pelaksanaan ketentuan peraturan perundang-undangan. (3) Setiap pihak yang memperoleh informasi sebagaimana dimaksud pada ayat (2) wajib menjaga keamanan dan kerahasiaan data sesuai dengan ketentuan peraturan perundang-undangan. (4) Otoritas Jasa Keuangan berwenang mengatur dan mengawasi lembaga pengelola informasi perkreditan."}, {"l": "UU 4/2023", "p": "54B", "b": "Bagian Ketiga", "t": "(1) Setiap Orang dilarang: a. membuat ... jdih.kemenkeu.go.id REPUBUK INDONESIA a. membuat atau menyebabkan adanya pencatatan palsu dalam pembukuan atau dalam laporan, dokumen atau laporan kegiatan usaha, dan/ a tau laporan transaksi a tau rekening suatu Bank Syariah atau UUS; b. menghilangkan, tidak memasukkan, atau menyebabkan tidak dilakukannya pencatatan dalam pembukuan atau dalam laporan, dokumen atau laporan kegiatan usaha, dan/ atau laporan transaksi a tau rekening suatu Bank Syariah atau UUS; dan c. mengubah, mengaburkan, menyembunyikan, menghapus, atau menghilangkan adanya suatu pencatatan dalam pembukuan atau dalam laporan, dokumen atau laporan kegiatan usaha, dan/ a tau laporan transaksi atau rekening suatu Bank Syariah atau UUS, atau mengubah, mengaburkan, menghilangkan, menyembunyikan, atau merusak catatan pembukuan. (2) Pemegang saham atau yang setara, anggota dewan komisaris atau yang setara, anggota direksi atau yang setara, atau pegawai Bank Syariah atau Bank Umum Konvensional yang memiliki UUS dilarang meminta atau menerima, mengizinkan atau menyetujui untuk menerima suatu imbalan, komisi, uang tambahan, pelayanan, uang, dan/ atau barang berharga untuk keuntungan …"}, {"l": "UU 4/2023", "p": "59", "b": "Bagian Ketiga", "t": "Setiap Orang yang menghimpun dana dari masyarakat dalam bentuk Simpanan atau Investasi berdasarkan Prinsip Syariah tanpa izin usaha dari Otoritas Jasa Keuangan sebagaimana dimaksud dalam Pasal 22 dipidana dengan pidana penjara paling singkat 5 (lima) tahun dan paling lama 15 (lima belas) tahun dan pidana denda paling sedikit Rp50.000.000.000,00 (lima puluh miliar rupiah) dan paling banyak Rp600.000.000.000,00 (enam ratus miliar rupiah). 47. Ketentuan . . . jdih.kemenkeu.go.id . REPUBUK INDONESIA 4 7. Ketentuan Pasal 60 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "61", "b": "Bagian Ketiga", "t": "Anggota dewan komisaris atau yang setara, anggota direksi atau yang setara, atau pegawai Bank Syariah atau Bank Umum Konvensional yang memiliki UUS yang dengan sengaja tidak memberikan informasi, Rahasia Bank, dan keterangan sebagaimana dimaksud dalam Pasal 44, Pasal 47, dan Pasal 48 dipidana dengan pidana penjara paling singkat 2 (dua) tahun dan paling lama 7 (tujuh) tahun dan pidana denda paling sedikit Rp4.000.000.000,00 (empat miliar rupiah) dan paling banyak Rpl5.000.000.000,00 (lima belas miliar rupiah). 49. Ketentuan ... jdih.kemenkeu.go.id PRESIOEN REPUBUK INDONESIA 49. Ketentuan Pasal 62 diubah sehingga berbunyi sebagai berikut: Pasal62 Anggota dewan komisaris atau yang setara, anggota direksi atau yang setara, atau pegawai Bank Syariah atau Bank Umum Konvensional yang memiliki UUS yang dengan sengaja: a. tidak menyampaikan laporan keuangan sebagaimana dimaksud dalam Pasal 35 ayat (2); dan/atau b. tidak memberikan data, informasi, keterangan, penjelasan, atau tidak melaksanakan perintah yang wajib dipenuhi sebagaimana dimaksud dalam Pasal 52, dipidana dengan pidana penjara paling singkat 2 (dua) tahun dan paling lama 10 (sepuluh) tahun dan pidana denda paling sedikit …"}, {"l": "UU 4/2023", "p": "63", "b": "Bagian Ketiga", "t": "(1) Anggota dewan komisaris atau yang setara, anggota direksi atau yang setara, atau pegawai Bank Syariah atau Bank Umum Konvensional yang memiliki UUS yang dengan sengaja: a. membuat atau menyebabkan adanya pencatatan palsu dalam pembukuan atau dalam laporan, dokumen atau laporan kegiatan usaha, dan/ atau laporan transaksi atau rekening suatu Bank Syariah atau UUS sebagaimana dimaksud dalam Pasal 54B ayat (1) huruf a; b. menghilangkan, tidak memasukkan, atau menyebabkan tidak dilakukannya pencatatan dalam pembukuan atau dalam laporan, dokumen atau laporan kegiatan usaha, dan/ atau laporan transaksi atau rekening suatu Bank Syariah atau UUS sebagaimana dimaksud dalam Pasal 54B ayat (1) huruf b; dan/atau c. mengubah, ... jdih.kemenkeu.go.id . REPUBLIK INDONESIA . c. mengubah, mengaburkan, menyembunyikan, menghapus, atau menghilangkan adanya suatu pencatatan dalam pembukuan atau dalam laporan, dokumen atau laporan kegiatan usaha, dan/ a tau laporan transaksi a tau rekening suatu Bank Syariah atau UUS, atau mengubah, mengaburkan, menghilangkan, menyembunyikan, atau merusak catatan pembukuan sebagaimana dimaksud dalam Pasal 54 ayat (1) huruf c, dipidana dengan pidana penjara paling …"}, {"l": "UU 4/2023", "p": "66B", "b": "Bagian Ketiga", "t": "(1) Pidana pokok yang dijatuhkan terhadap korporasi atau badan usaha baik yang berbentuk badan hukum maupun yang tidak berbentuk badan hukum, atau badan lainnya merupakan pidana denda dengan ketentuan untuk: a. Bank ... jdih.kemenkeu.go.id a. Bank Umum Syariah atau Bank Umum Konvensional yang memiliki UUS paling sedikit sebesar Rp50.000.000.000,00 (lima puluh miliar rupiah) dan paling banyak Rp600.000.000.000,00 (enam ratus miliar rupiah); b. BPR Syariah paling sedikit sebesar Rp5.000.000.000,00 (lima miliar rupiah) dan paling banyak Rp60.000.000.000,00 (enam puluh miliar rupiah); a tau c. korporasi atau badan usaha baik yang berbentuk badan hukum maupun yang tidak berbentuk badan hukum, atau badan lain selain yang dimaksud dalam huruf a dan huruf b paling sedikit sebesar Rp50.000.000.000,00 (lima puluh miliar rupiah) dan paling banyak Rp600.000.000.000,00 (enam ratus miliar rupiah). (2) Selain pidana denda sebagaimana dimaksud pada ayat ( 1), terhadap korporasi atau badan usaha baik yang berbentuk badan hukum maupun yang tidak berbentuk badan hukum, atau badan lainnya juga dapat dijatuhkan pidana tambahan berupa: a. pengumuman putusan hakim; dan/ atau b. pembekuan sebagian atau …"}, {"l": "UU 4/2023", "p": "66C", "b": "Bagian Ketiga", "t": "(1) Selain dijatuhi pidana penjara dan pidana denda sebagaimana dimaksud dalam Pasal 59, Pasal 60, Pasal 61, Pasal 62, Pasal 63, Pasal 64, Pasal 65, Pasal 66, Pasal 66A, dan Pasal 66B terpidana dapat dijatuhi pidana tambahan berupa penggantian kerugian apabila tindak pidana mengakibatkan kerugian. (2) Pidana ... jdih.kemenkeu.go.id REPUBUK INDONESIA (2) Pidana tambahan berupa penggantian kerugian sebagaimana dimaksud pada ayat (1) dikembalikan kepada pihak yang dirugikan sejumlah kerugian yang diderita, atau secara proporsional dalam hal jumlah penggantian kerugian tidak mencukupi jumlah total kerugian yang ditimbulkan. (3) Dalam melaksanakan putusan pidana sebagaimana dimaksud pada ayat (1), terpidana diberikan jangka waktu selama 1 (satu) bulan sejak putusan telah memperoleh kekuatan hukum tetap. (4) Dalam hal terdapat alasan kuat, jangka waktu sebagaimana dimaksud pada ayat (3) dapat diperpanjang untuk jangka waktu paling lama 1 (satu) bulan. (5) Dalam hal terpidana tidak membayar pidana denda dan pidana tambahan berupa penggantian kerugian sebagaimana dimaksud pada ayat (1), harta benda terpidana disita dan dilelang oleh jaksa untuk melunasi denda dan ganti kerugian tersebut. …"}, {"l": "UU 4/2023", "p": "67A", "b": "Bagian Ketiga", "t": "(1) Otoritas Jasa Keuangan berwenang menetapkan dimulainya, tidak dilakukannya, atau dihentikannya penyidikan terhadap tindak pidana Perbankan Syariah. (2) Sebelum ... jdih.kemenkeu.go.id . REPUBUK INDONESIA (2) Sebelum menetapkan dimulainya penyidikan sebagaimana dimaksud pada ayat (1), Otoritas Jasa Keuangan melakukan penyelidikan terhadap dugaan tindak pidana Perbankan Syariah. (3) Pada tahap penyelidikan sebagaimana dimaksud pada ayat (2), pihak yang diduga melakukan tindak pidana Perbankan Syariah dapat mengajukan permohonan kepada Otoritas Jasa Keuangan untuk penyelesaian pelanggaran atas peraturan perundang­ undangan di sektor Perbankan Syariah. (4) Otoritas Jasa Keuangan melakukan penilaian terhadap permohonan penyelesaian pelanggaran sebagaimana dimaksud pada ayat (3) dan menghitung nilai kerugian atas pelanggaran. (5) Dalam melakukan penilaian terhadap permohonan penyelesaian pelanggaran dan perhitungan nilai kerugian atas pelanggaran sebagaimana dimaksud pada ayat (4), Otoritas Jasa Keuangan mempertimbangkan minimal: a. ada atau tidaknya penyelesaian atas kerugian yang timbul akibat tindak pidana; b. nilai transaksi dan/ atau nilai kerugian atas pelanggaran; dan c. …"}, {"l": "UU 4/2023", "p": "68", "b": "Bagian Ketiga", "t": "(1) Dalam hal Bank Umum Konvensional memiliki UUS, setelah memenuhi persyaratan tertentu yang ditetapkan oleh Otoritas Jasa Keuangan, Bank Umum Konvensional dimaksud wajib melakukan Pemisahan UUS tersebut menjadi Bank Umum Syariah. (2) Selain persyaratan sebagaimana dimaksud pada ayat (1), Otoritas Jasa Keuangan dapat meminta Pemisahan UUS menjadi Bank Umum Syariah dalam rangka konsolidasi Perbankan Syariah. (3) Ketentuan lebih lanjut mengenai Pemisahan dan konsolidasi, serta sanksi bagi Bank Umum Konvensional yang tidak melakukan Pemisahan sebagaimana dimaksud pada ayat (1) dan ayat (2) diatur dalam Peraturan Otoritas Jasa Keuangan setelah dikonsultasikan dengan DPR. (4) Peraturan Otoritas Jasa Keuangan sebagaimana dimaksud pada ayat (3) harus ditetapkan dalam jangka waktu paling lambat 6 (enam) bulan terhitung sejak Undang-Undang ini diundangkan. BABV ... jdih.kemenkeu.go.id PRESIOEN REPUBUK INDONESIA BABV PASAR MODAL, PASAR UANG, DAN PASAR VALUTA ASING"}, {"l": "UU 4/2023", "p": "29A", "b": "Bagian Ketiga", "t": "(1) Manajer Investasi dapat melakukan pengelolaan produk investasi kolektif selain Reksa Dana dan pengelolaan investasi nasabah secara individual. (2) Pengelolaan produk investasi kolektif selain Reksa Dana sebagaimana dimaksud pada ayat (1) dapat berbentuk: a. Perseroan; b. Kontrak Investasi Kolektif; atau c. bentuk lain yang ditetapkan oleh Otoritas Jasa Keuangan. (3) Pengelolaan ... jdih.kemenkeu.go.id REPUBUK INDONESIA (3) Pengelolaan produk investasi kolektif sebagaimana dimaksud pada ayat (2) dapat bersifat terbuka atau tertutup. (4) Pengelolaan produk investasi kolektif dilakukan berdasarkan Kontrak Investasi Kolektif sebagaimana dimaksud pada ayat (2) huruf b antara Manajer Investasi dan bank Kustodian. (5) Ketentuan mengenai pengelolaan produk investasi kolektif selain Reksa Dana sebagaimana dimaksud pada ayat (2) dan pengelolaan investasi nasabah secara individual diatur dalam Peraturan Otoritas J asa Keuangan."}, {"l": "UU 4/2023", "p": "29B", "b": "Bagian Ketiga", "t": "(1) Manajer lnvestasi sebagai pengelola produk investasi kolektif selain Reksa Dana dapat menjual dan membeli kembali Unit Penyertaan atau tanda bukti investasi lain secara terus-menerus atau secara terbatas sampai dengan jumlah Unit Penyertaan atau tanda bukti investasi lain yang ditetapkan dalam Kontrak lnvestasi Kolektif. (2) Dalam hal pemegang Unit Penyertaan atau tanda bukti investasi lainnya melakukan penjualan kembali, Manajer Investasi wajib membeli kembali Unit Penyertaan atau tanda bukti investasi lainnya. (3) Pengecualian ketentuan sebagaimana dimaksud pada ayat (2) hanya dapat dilakukan apabila: a. Bursa Efek yang memperdagangkan sebagian besar Portofolio Efek produk investasi kolektif selain Reksa Dana, ditutup; b. perdagangan Efek atas sebagian besar Portofolio Efek produk investasi kolektif selain Reksa Dana di Bursa Efek, dihentikan; c. keadaan darurat; d. Unit Penyertaan produk investasi kolektif selain Reksa Dana tersebut merupakan Unit Penyertaan yang dapat diperdagangkan di Bursa Efek; dan/ atau e. terdapat ... jdih.kemenkeu.go.id e. terdapat hal lain yang ditetapkan dalam kontrak pengelolaan investasi setelah mendapat persetujuan Otoritas Jasa Keuangan. (4) …"}, {"l": "UU 4/2023", "p": "42A", "b": "Bagian Kesatu", "t": "Dalam pengelolaan investasi, Manajer Investasi dilarang memiliki hubungan Afiliasi dengan bank Kustodian, kecuali hubungan Afiliasi yang terjadi karena kepemilikan atau penyertaan modal Pemerintah. Pasal 42B ... jdih.kemenkeu.go.id REPUBUK INDONESIA"}, {"l": "UU 4/2023", "p": "42B", "b": "Bagian Kesatu", "t": "Setiap Pihak dilarang memiliki saham dan/ atau melakukan tindakan pengendalian pada lebih dari 1 (satu) Perusahaan Efek baik secara langsung maupun tidak langsung, kecuali karena kepemilikan saham atau penyertaan modal Pemerintah. 13. Ketentuan BAB VIII diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "55", "b": "Bagian Kesatu", "t": "(1) Penyelesaian Transaksi Efek dilaksanakan dengan penyelesaian pembukuan, penyelesaian fisik, atau cara lain yang diatur dalam Peraturan Otoritas Jasa Keuangan. (2) Lembaga Kliring dan Penjaminan wajib menjamin penyelesaian Transaksi Efek yang diatur dalam Peraturan Otoritas Jasa Keuangan. (3) Penyelesaian Transaksi Efek oleh Lembaga Kliring dan Penjaminan dapat berupa serah terima Efek, dana pengganti, atau aset pengganti lainnya yang diatur dalam Peraturan Otoritas Jasa Keuangan. (4) Tata cara dan penjaminan penyelesaian Transaksi Efek didasarkan pada kontrak antara Penyelenggara Pasar di Pasar Modal, Lembaga Kliring dan Penjaminan, serta Lembaga Penyimpanan dan Penyelesaian. (5) Untuk ... jdih.kemenkeu.go.id REPUBUK INDONESIA (5) Untuk menjamin penyelesaian Transaksi Efek sebagaimana dimaksud pada ayat (2), Lembaga Kliring dan Penjaminan dapat menetapkan dana jaminan yang wajib dipenuhi oleh pemakai jasa Lembaga Kliring dan Penjaminan. (6) Kontrak sebagaimana dimaksud pada ayat (4) dan penetapan dana jaminan sebagaimana dimaksud pada ayat (5) mulai berlaku setelah mendapat persetujuan Otoritas Jasa Keuangan. (7) Ketentuan lebih lanjut mengenai penyelesaian Transaksi Efek …"}, {"l": "UU 4/2023", "p": "64", "b": "Bagian Kesatu", "t": "(1) Profesi penunjang Pasar Modal terdiri atas: a. akuntan publik; b. konsultan hukum; c. penilai; d. notaris; dan e. profesi lain yang ditetapkan dengan Peraturan Otoritas Jasa Keuangan. (2) Untuk dapat melakukan kegiatan di bidang Pasar Modal, profesi penunjang Pasar Modal sebagaimana dimaksud pada ayat (1) wajib terlebih dahulu memperoleh surat tanda terdaftar dari Otoritas Jasa Keuangan. (3) Dalam hal tidak terdapat instansi atau lembaga yang berwenang atau memberikan izin pada profesi lain sebagaimana dimaksud pada ayat (1) huruf e, profesi lain tersebut wajib terlebih dahulu memperoleh izin dari Otoritas Jasa Keuangan. (4) Dalam kondisi tertentu, Otoritas Jasa Keuangan dapat menetapkan pengecualian penggunaan jasa profesi penunjang Pasar Modal yang telah memperoleh surat tanda terdaftar dari Otoritas Jasa Keuangan. (5) Ketentuan lebih lanjut mengenai persyaratan dan tata cara pemberian izin dan surat tanda terdaftar profesi penunjang Pasar Modal sebagaimana dimaksud pada ayat (2) dan ayat (3) serta pengecualian sebagaimana dimaksud pada ayat (4) diatur dalam Peraturan Otoritas Jasa Keuangan. 19. Ketentuan Pasal 66 diubah sehingga berbunyi sebagai berikut: Pasal66 (1) Setiap …"}, {"l": "UU 4/2023", "p": "69A", "b": "Bagian Kesatu", "t": "(1) Dalam rangka memperluas akses Usaha Mikro, Kecil, dan Menengah untuk mendapatkan pendanaan dari Pasar Modal, Otoritas Jasa Keuangan mengatur penghimpunan dana masyarakat melalui penawaran Efek dengan menggunakan jasa penyelenggara sistem elektronik (securities crowdfunding) sebagaimana dimaksud dalam Pasal 5 huruf a angka 7. (2) Persyaratan ... jdih.kemenkeu.go.id REPUBUK INDONESIA (2) Persyaratan maksimum jumlah penghimpunan dana dan persyaratan pemodal atau investor yang dapat menggunakan mekanisme penawaran Efek dengan menggunakan jasa penyelenggara sistem elektronik (securities crowd.funding) sebagaimana dimaksud pada ayat (1) diatur oleh Otoritas Jasa Keuangan. (3) Penyelenggara sistem elektronik sebagaimana dimaksud pada ayat (2) wajib memperoleh izin usaha dari Otoritas Jasa Keuangan. (4) Dalam hal penyelenggara sistem elektronik yang memfasilitasi penghimpunan dana masyarakat melalui penawaran Efek sebagaimana dimaksud pada ayat (1) merupakan LJK yang telah memiliki izin dari Otoritas Jasa Keuangan, penyelenggara tersebut wajib memperoleh pendaftaran atau persetujuan dari Otoritas Jasa Keuangan. (5) LJK sebagai penyelenggara sistem elektronik yang memfasilitasi …"}, {"l": "UU 4/2023", "p": "69B", "b": "Bagian Kesatu", "t": "(1) Dalam rangka memberikan pelindungan kepada pemodal atau investor yang memanfaatkan layanan penyelenggara sistem elektronik yang memfasilitasi penghimpunan dana masyarakat melalui penawaran Efek, penyelenggara dana perlindungan pemodal dapat memberikan pelindungan dana pemodal berdasarkan ketentuan yang ditetapkan oleh Otoritas Jasa Keuangan. (2) Dalam ... jdih.kemenkeu.go.id REPUBUK INDONESIA (2) Dalam rangka pengawasan, penyelenggara sistem elektronik yang memfasilitasi penghimpunan dana masyarakat melalui penawaran Efek wajib memperhatikan kelengkapan, kecukupan, objektivitas, kemudahan untuk dimengerti, dan kejelasan dokumen penerbit, untuk memastikan bahwa dokumen penerbit telah memenuhi Prinsip Keterbukaan. (3) Dalam rangka pengawasan, penyelenggara sistem elektronik yang memfasilitasi penghimpunan dana masyarakat melalui penawaran Efek melaporkan informasi terkait pemodal atau investor dan penerbit yang difasilitasi dalam penawaran Efek sesuai permintaan Otoritas Jasa Keuangan. (4) Penerbit dilarang melakukan penerbitan Efek melalui lebih dari satu penyelenggara, kecuali ditentukan lain oleh Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "69C", "b": "Bagian Kesatu", "t": "(1) Dalam rangka pengembangan Pasar Modal, Penawaran Umum perusahaan berinovasi tinggi dengan pertumbuhan cepat dengan karakteristik tertentu, dapat diatur khusus oleh Otoritas Jasa Keuangan. (2) Pengaturan khusus sebagaimana dimaksud pada ayat (1) di antaranya mengenai: a. klasifikasi saham yang dapat diterbitkan; b. tata cara penambahan modal; c. transaksi tertentu; dan d. pencatatan Efek di Penyelenggara Pasar di Pasar Modal."}, {"l": "UU 4/2023", "p": "69D", "b": "Bagian Kesatu", "t": "(1) Bagi Perseroan yang melakukan kegiatan di Pasar Modal berlaku ketentuan peraturan perundang­ undangan mengenai perseroan terbatas, sepanjang tidak bertentangan dengan ketentuan peraturan perundang-undangan di bidang pasar modal. (2) Ketentuan ... jdih.kemenkeu.go.id REPUBUK INDONESIA . (2) Ketentuan sebagairnana dirnaksud pada ayat (1), ditujukan untuk rnewujudkan Pasar Modal yang teratur, wajar, efisien, dan rnelindungi kepentingan pernodal. 23. Ketentuan Pasal 70 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "70", "b": "Bagian Kesatu", "t": "(1) Penawaran Urnurn hanya dapat dilakukan dengan ketentuan: a. Erniten telah rnenyarnpaikan Pernyataan Pendaftaran kepada Otoritas Jasa Keuangan untuk rnenawarkan Efek dengan tujuan rnenjual Efek kepada rnasyarakat; dan b. Pernyataan Pendaftaran sebagairnana dirnaksud dalarn huruf a telah efektif. (2) Ketentuan sebagairnana dirnaksud pada ayat (1) tidak berlaku bagi Pihak yang rnelakukan: a. penawaran Efek yang bersifat utang dan/atau sukuk yang jatuh ternponya tidak lebih dari 1 (satu) tahun; b. penawaran Efek yang diterbitkan dan/ atau dijarnin Pemerintah Indonesia; c. penawaran Efek bersifat utang dan/atau sukuk yang diterbitkan oleh Lembaga Penjamin Simpanan khusus kepada investor profesional dalam rangka menjalankan tugas dan fungsinya; d. penawaran atas Efek atau surat berharga yang secara khusus diatur dalam Undang-Undang; atau e. penawaran Efek lain yang ditetapkan oleh Otoritas Jasa Keuangan. (3) Pengaturan dan pengawasan terhadap kegiatan perdagangan Efek bersifat utang Lembaga Penjamin Sirnpanan dilakukan oleh Otoritas Jasa Keuangan. 24. Di antara ... jdih.kemenkeu.go.id R£PUBUK INOONESIA . 24. Di antara Pasal 70 dan Pasal 71 disisipkan 1 (satu) pasal, yakni Pasal 70A …"}, {"l": "UU 4/2023", "p": "70A", "b": "Bagian Kesatu", "t": "Kegiatan terkait dengan Efek bersifat utang dalam Pasal 30, Pasal 51, Pasal 53, Pasal 54, dan Pasal 70, berlaku mutatis mutandis untuk sukuk. 25. Ketentuan Pasal 74 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "74", "b": "Bagian Kesatu", "t": "(1) Pernyataan Pendaftaran menjadi efektif pada hari kerja ke-20 (kedua puluh) sejak diterimanya Pernyataan Pendaftaran secara lengkap atau pada tanggal yang lebih awal jika dinyatakan efektif oleh Otoritas J asa Keuangan. (2) Dalam jangka waktu sebagaimana dimaksud pada ayat (1), Otoritas Jasa Keuangan dapat meminta perubahan dan/atau tambahan informasi dari Emiten atau Perusahaan Publik. (3) Dalam hal Emiten atau Perusahaan Publik menyampaikan perubahan dan/ a tau tambahan informasi sebagaimana dimaksud pada ayat (2), Pernyataan Pendaftaran tersebut dianggap telah disampaikan kembali pada tanggal diterimanya perubahan atau tambahan informasi tersebut. (4) Dalam hal Otoritas Jasa Keuangan meminta perubahan dan/atau tambahan informasi dari Emiten atau Perusahaan Publik sebagaimana dimaksud pada ayat (2), penghitungan waktu untuk efektifnya Pernyataan Pendaftaran dihitung sejak tanggal diterimanya perubahan dan/ a tau tambahan informasi dimaksud. (5) Pernyataan Pendaftaran tidak dapat menjadi efektif sampai saat perubahan dan/ a tau tambahan informasi sebagaimana dimaksud pada ayat (3) diterima dan telah memenuhi syarat yang ditetapkan oleh Otoritas Jasa Keuangan. (6) Jangka waktu …"}, {"l": "UU 4/2023", "p": "84A", "b": "Bagian Kesatu", "t": "(1) Perusahaan terbuka yang dibatalkan pencatatan sahamnya pada Bursa Efek wajib mengubah status menjadi Perseroan yang tertutup dalam jangka waktu tertentu yang ditetapkan dalam Peraturan Otoritas Jasa Keuangan. (2) Perusahaan terbuka dapat secara sukarela mengubah statusnya menjadi Perseroan yang tertutup setelah memenuhi persyaratan yang diatur oleh Otoritas Jasa Keuangan. 28. Ketentuan Pasal 86 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "87", "b": "Bagian Kesatu", "t": "(1) Direktur, komisaris Emiten, atau Perusahaan Publik wajib melaporkan kepada Otoritas Jasa Keuangan mengenai kepemilikan hak suara atas saham Emiten atau Perusahaan Publik, baik langsung maupun tidak langsung dan setiap perubahan kepemilikannya pada Emiten atau Perusahaan Publik dimaksud. (2) Setiap Pihak yang secara langsung atau tidak langsung memiliki paling sedikit 5% (lima persen) hak suara atas saham Emiten atau Perusahaan Publik wajib melaporkan kepada Otoritas Jasa Keuangan atas kepemilikan dan setiap perubahan kepemilikannya atas saham Emiten atau Perusahaan Publik dimaksud. (3) Laporan sebagaimana dimaksud pada ayat (1) dan ayat (2) wajib disampaikan sesegera mungkin, tetapi tidak lebih dari 5 (lima) hari kerja terhitung sejak terjadinya kepemilikan hak suara atas saham Emiten atau Perusahaan Publik atau perubahan kepemilikan hak suara atas saham Emiten atau Perusahaan Publik. (4) Otoritas Jasa Keuangan dapat menentukan persyaratan jangka waktu penyampaian laporan sebagaimana dimaksud pada ayat (3) lebih cepat dari 5 (lima) hari kerja terhitung sejak terjadinya: a. kepemilikan hak suara atas saham Emiten atau Perusahaan Publik; atau b. perubahan kepemilikan hak suara …"}, {"l": "UU 4/2023", "p": "87A", "b": "Bagian Kesatu", "t": "(1) Dalam hal terjadi likuidasi atas Emiten atau Perusahaan Publik, kedudukan pemegang saham publik adalah satu tingkat di bawah kreditur konkuren dan dalam hal terdapat pembagian sisa harta likuidasi, pemegang saham dimaksud berhak didahulukan dari pemegang saham yang bukan merupakan pemegang saham publik. (2) Ketentuan lebih lanjut mengenai batasan pemegang saham publik sebagaimana dimaksud pada ayat (1) diatur lebih lanjut oleh Peraturan Otoritas Jasa Keuangan. 31. Di antara Bab X dan Bab XI disisipkan 1 (satu) bab, yakni"}, {"l": "UU 4/2023", "p": "93", "b": "BAB XA sehingga berbunyi sebagai berikut:", "t": "Setiap Pihak dilarang, dengan cara apa pun, membuat pemyataan atau memberikan keterangan yang tidak benar atau menyesatkan sehingga memengaruhi harga Efek apabila pada saat pernyataan dibuat atau keterangan diberikan: a. Pihak yang bersangkutan mengetahui atau sepatutnya mengetahui bahwa pernyataan atau keterangan tersebut tidak benar atau menyesatkan; dan/atau b. Pihak yang bersangkutan tidak cukup berhati-hati dalam menentukan kebenaran dari pernyataan atau keterangan tersebut. 37. Ketentuan Pasal 94 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "94", "b": "BAB XA sehingga berbunyi sebagai berikut:", "t": "Otoritas Jasa Keuangan dapat menetapkan tindakan tertentu yang dapat dilakukan oleh Perusahaan Efek dan/ atau Pihak lain yang bukan merupakan tindakan yang dilarang sebagaimana dimaksud dalam Pasal 91 dan"}, {"l": "UU 4/2023", "p": "100A", "b": "BAB XIIA PRINSIP UNA VIA DAN PERINTAH TERTULIS", "t": "(1) Otoritas Jasa Keuangan dapat menetapkan: a. tidak melanjutkan ke tahap penyidikan; atau b. dimulainya tindakan penyidikan, terhadap dugaan terjadinya tindak pidana sebagaimana diatur dalam Undang-Undang ini. (2) Dalam menetapkan ketentuan sebagaimana dimaksud pada ayat (1), Otoritas Jasa Keuangan melakukan penilaian dengan mempertimbangkan: a. nilai transaksi dari pelanggaran atau dampak pelanggaran; b. ada atau tidak adanya penyelesaian atas kerugian yang timbul akibat tindak pidana; c. akibat tindak pidana terhadap kegiatan penawaran dan/atau perdagangan Efek secara keseluruhan; dan d. dampak kerugian terhadap sistem Pasar Modal atau kepentingan pemodal atau investor dan/ atau masyarakat. (3) Dalam hal Otoritas Jasa Keuangan menetapkan tidak melanjutkan ke tahap penyidikan sebagaimana dimaksud pada ayat (1) huruf a, Otoritas Jasa Keuangan berwenang menetapkan tindakan administratif berupa sanksi administratif dan/ atau perintah tertulis terhadap Pihak yang melakukan tindak pidana. Pasal l00B ... jdih.kemenkeu.go.id REPUBUK INDONESIA"}, {"l": "UU 4/2023", "p": "100B", "b": "BAB XIIA PRINSIP UNA VIA DAN PERINTAH TERTULIS", "t": "Dalam hal Otoritas Jasa Keuangan menetapkan tindakan administratif berupa sanksi administratif sebagaimana dimaksud dalam Pasal 1OOA ayat (3) terhadap tindak pidana sebagaimana dimaksud dalam Pasal 1OOA ayat ( 1), Otoritas Jasa Keuangan dapat memberikan perintah tertulis kepada Pihak yang melakukan tindak pidana dimaksud untuk mengembalikan keuntungan yang diperoleh dan/ atau kerugian yang dapat dihindari secara tidak sah dari pelanggaran administratif atau tindak pidana."}, {"l": "UU 4/2023", "p": "100C", "b": "BAB XIIA PRINSIP UNA VIA DAN PERINTAH TERTULIS", "t": "Otoritas Jasa Keuangan dapat mengenakan sanksi administratif berupa denda dengan disertai perintah tertulis sebagaimana dimaksud dalam Pasal 100B."}, {"l": "UU 4/2023", "p": "1000", "b": "BAB XIIA PRINSIP UNA VIA DAN PERINTAH TERTULIS", "t": "(1) Dalam rangka pelaksanaan perintah tertulis sebagaimana dimaksud dalam Pasal 100B, Otoritas Jasa Keuangan dapat memberikan perintah kepada WK dan/atau Pihak tertentu untuk: a. memblokir rekening atau membekukan aset Pihak sebagaimana dimaksud dalam Pasal 100B; b. memindahbukukan dana dan/ atau Efek dalam rekening Pihak sebagaimana dimaksud dalam huruf a ke rekening yang ditetapkan oleh Otoritas Jasa Keuangan; c. mengalihkan aset Pihak sebagaimana dimaksud dalam huruf a kepada Pihak yang ditetapkan oleh Otoritas Jasa Keuangan; dan/ a tau d. mencairkan aset Pihak dalam rekening Efek atau aset Pihak sebagaimana dimaksud dalam huruf a sebagai pemenuhan kewajiban pihak tersebut terhadap perintah Otoritas Jasa Keuangan untuk mengembalikan keuntungan yang diperoleh dan/ atau kerugian yang dapat dihindari dari tindak pidana. (2) Dana ... jdih.kemenkeu.go.id . REPUBUK INDONESIA (2) Dana yang berasal dari pengembalian keuntungan yang diperoleh atau kerugian yang dihindari secara tidak sah sebagaimana dimaksud pada ayat (1) huruf d bukan merupakan penerimaan Otoritas Jasa Keuangan dan digunakan untuk memberikan kompensasi kerugian pemodal atau investor dan/ atau pengembangan industri …"}, {"l": "UU 4/2023", "p": "101", "b": "BAB XIIA PRINSIP UNA VIA DAN PERINTAH TERTULIS", "t": "(1) Penyidikan atas tindak pidana di bidang Pasar Modal hanya dapat dilakukan oleh penyidik Otoritas Jasa Keuangan. (2) Penyidik Otoritas Jasa Keuangan sebagaimana dimaksud pada ayat (I) berwenang: a. menerima laporan, pemberitahuan, a tau pengaduan dari seseorang tentang adanya tindak pidana di bidang Pasar Modal; b. melakukan penelitian atas kebenaran laporan atau keterangan berkenaan dengan tindak pidana di bidang Pasar Modal; c. melakukan penelitian terhadap Pihak yang diduga melakukan atau terlibat dalam tindak pidana di bidang Pasar Modal; d. memanggil, ... jdih.kemenkeu.go.id REPUBUK INDONESIA d. memanggil, memeriksa, dan meminta keterangan dan barang bukti dari setiap Pihak yang disangka melakukan, atau sebagai saksi dalam tindak pidana di bidang Pasar Modal; e. meminta kepada instansi yang berwenang untuk melakukan penangkalan terhadap orang asing yang diduga akan mengganggu keamanan dan ketertiban umum melalui kegiatan di Pasar Modal; f. melakukan pemeriksaan atas pembukuan, catatan, dan dokumen lain berkenaan dengan tindak pidana di bidang Pasar Modal; g. melakukan penggeledahan di setiap tempat tertentu yang diduga terdapat setiap barang bukti pembukuan, pencatatan, …"}, {"l": "UU 4/2023", "p": "103", "b": "BAB XIIA PRINSIP UNA VIA DAN PERINTAH TERTULIS", "t": "(1) Setiap Pihak yang melakukan kegiatan di Pasar Modal tanpa memperoleh izin sebagaimana dimaksud dalam Pasal SD, Pasal 6, atau Pasal 13 dipidana dengan pidana penjara paling singkat 4 (empat) tahun dan paling lama 12 (dua belas) tahun dan pidana denda paling sedikit Rpl0.000.000.000,00 (sepuluh miliar rupiah) dan paling banyak Rp400.000.000.000,00 (empat ratus miliar rupiah). (2) Setiap ... jdih.kemenkeu.go.id (2) Setiap Pihak yang melalrukan kegiatan di Pasar Modal tanpa memperoleh 1zm a tau persetujuan sebagaimana dimaksud dalam Pasal 18 ayat (3), Pasal 30 ayat (1), Pasal 43 ayat (1) dipidana dengan pidana penjara paling singkat 3 (tiga) tahun dan paling lama 10 (sepuluh) tahun dan pidana denda paling sedikit Rp3.000.000.000,00 (tiga miliar rupiah) dan paling banyak Rpl00.000.000.000,00 (seratus miliar rupiah). (3) Setiap Pihak yang melakukan kegiatan di Pasar Modal tanpa memperoleh izin, persetujuan, atau surat tanda terdaftar sebagaimana dimaksud dalam Pasal 34 ayat (1), Pasal 48 ayat (1), Pasal 50 ayat (2), atau Pasal 64 ayat (2) dipidana dengan pidana penjara paling singkat 2 (dua) tahun dan paling lama 8 (delapan) tahun dan pidana denda paling sedikit Rp2.500.000.000,00 …"}, {"l": "UU 4/2023", "p": "104", "b": "BAB XIIA PRINSIP UNA VIA DAN PERINTAH TERTULIS", "t": "Setiap Pihak yang melanggar ketentuan sebagaimana dimaksud dalam Pasal 90, Pasal 91, Pasal 92, Pasal 93, Pasal 95, Pasal 96, Pasal 97, atau Pasal 98 dipidana dengan pidana penjara paling singkat 5 (lima) tahun dan paling lama 15 (lima belas) tahun dan pidana denda paling sedikit Rp5.000.000.000,00 (lima miliar rupiah) dan paling banyak Rp150.000.000.000,00 (seratus lima puluh miliar rupiah). 44. Di antara ... jdih.kemenkeu.go.id REPUBUK INDONESIA 44. Di antara Pasal 104 dan Pasal 105 disisipkan 1 (satu) pasal, yakni Pasal 104A sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "104A", "b": "BAB XIIA PRINSIP UNA VIA DAN PERINTAH TERTULIS", "t": "Perusahaan Efek, Penasihat Investasi, atau Pihak terafiliasinya yang melanggar ketentuan sebagaimana dimaksud dalam Pasal 35 huruf b dipidana dengan pidana penjara paling singkat 1 (satu) tahun dan paling lama 5 (lima) tahun dan pidana denda paling sedikit Rpl.500.000.000,00 (satu miliar lima ratus juta rupiah) dan paling banyak Rp50.000.000.000,00 (lima puluh miliar rupiah). 45. Ketentuan Pasal 105 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "105", "b": "BAB XIIA PRINSIP UNA VIA DAN PERINTAH TERTULIS", "t": "Manajer Investasi dan/ atau Pihak terafiliasinya yang melanggar ketentuan sebagaimana dimaksud dalam Pasal 42 dipidana dengan pidana penjara paling singkat 1 (satu) tahun dan paling lama 2 (dua) tahun dan pidana denda paling sedikit Rp600.000.000,00 (enam ratus juta rupiah) dan paling banyak Rp20.000.000.000,00 (dua puluh miliar rupiah). 46. Ketentuan Pasal 106 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "106", "b": "BAB XIIA PRINSIP UNA VIA DAN PERINTAH TERTULIS", "t": "(1) Setiap Pihak yang melakukan pelanggaran atas ketentuan sebagaimana dimaksud dalam Pasal 70 ayat (1) dipidana dengan pidana penjara paling singkat 5 (lima) tahun dan paling lama 15 (lima belas) tahun dan pidana denda paling sedikit Rp5.000.000.000,00 (lima miliar rupiah) dan paling banyak Rp150.000.000.000,00 (seratus lima puluh miliar rupiah). (2) Setiap ... jdih.kemenkeu.go.id PRESIOEN . REPUBUK INOONESIA (2) Setiap Pihak yang melakukan pelanggaran ketentuan sebagaimana dimaksud dalam Pasal 73 dipidana dengan pidana penjara paling singkat 1 (satu) tahun dan paling lama 5 (lima) tahun dan pidana denda paling sedikit Rpl.500.000.000,00 (satu miliar lima ratus juta rupiah) dan paling banyak RpS0.000.000.000,00 (lima puluh miliar rupiah). 47. Di antara Pasal 106 dan Pasal 107 disisipkan 3 (tiga) pasal, yakni Pasal 106A, Pasal 106B, dan Pasal 106C sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "106A", "b": "BAB XIIA PRINSIP UNA VIA DAN PERINTAH TERTULIS", "t": "(1) Kustodian atau Pihak terafiliasinya yang memberikan keterangan mengenai rekening Efek pada Kustodian dimaksud kepada Pihak lain selain kepada Pihak sebagaimana dimaksud dalam Pasal 47 ayat (1) dipidana dengan pidana penjara paling singkat 1 (satu) tahun dan paling lama 5 (lima) tahun dan pidana denda paling sedikit Rpl.500.000.000,00 (satu miliar lima ratus juta rupiah) dan paling banyak RpS0.000.000.000,00 (lima puluh miliar rupiah). (2) Pihak yang karena kedudukan atau profesinya atau hubungan usahanya dengan Kustodian memperoleh keterangan mengenai rekening Efek dari Kustodian a tau Pihak terafiliasinya sebagaimana dimaksud dalam Pasal 47 ayat (2), yang memberikan keterangan mengenai rekening Efek kepada Pihak lain secara melawan hukum dipidana dengan pidana penjara paling singkat 1 (satu) tahun dan paling lama 5 (lima) tahun dan pidana denda paling sedikit Rpl.500.000.000,00 (satu miliar lima ratus juta rupiah) dan paling banyak RpS0.000.000.000,00 (lima puluh miliar rupiah)."}, {"l": "UU 4/2023", "p": "106B", "b": "BAB XIIA PRINSIP UNA VIA DAN PERINTAH TERTULIS", "t": "Kustodian yang melanggar ketentuan sebagaimana dimaksud dalam Pasal 44 dipidana dengan pidana penjara paling singkat 3 (tiga) tahun dan paling lama 10 (sepuluh) tahun dan pidana denda paling sedikit Rp3.000.000.000,00 (tiga miliar rupiah) dan paling banyak Rpl00.000.000.000,00 (seratus miliar rupiah). Pasal 106C ... jdih.kemenkeu.go.id"}, {"l": "UU 4/2023", "p": "106C", "b": "BAB XIIA PRINSIP UNA VIA DAN PERINTAH TERTULIS", "t": "Setiap Pihak yang dengan sengaja mencegah, merintangi, atau menggagalkan secara langsung atau tidak langsung pemeriksaan, penyidikan, penuntutan, dan pemeriksaan di sidang pengadilan terhadap tersangka dan terdakwa ataupun para saksi dalam perkara tindak pidana yang diatur dalam Undang-Undang ini dipidana dengan pidana penjara 1 (satu) tahun dan paling lama 5 (lima) tahun dan pidana denda paling sedikit Rpl.500.000.000,00 (satu miliar lima ratus juta rupiah) dan paling banyak Rp50.000.000.000,00 (lima puluh miliar rupiah). 48. Ketentuan Pasal 107 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "107", "b": "BAB XIIA PRINSIP UNA VIA DAN PERINTAH TERTULIS", "t": "Setiap Pihak yang dengan sengaja bertujuan menipu atau merugikan Pihak lain atau menyesatkan Otoritas Jasa Keuangan, menghilangkan, memusnahkan, menghapuskan, mengubah, mengaburkan, menyembunyikan, atau memalsukan catatan dari Pihak yang memperoleh izin, persetujuan, atau pendaftaran termasuk Emiten dan Perusahaan Publik dipidana dengan pidana penjara paling sedikit 1 (satu) tahun dan paling lama 5 (lima) tahun dan pidana denda paling sedikit Rpl.500.000.000,00 (satu miliar lima ratus juta rupiah) dan paling banyak Rp50.000.000.000,00 (lima puluh miliar rupiah). 49. Ketentuan Pasal 108 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "108", "b": "BAB XIIA PRINSIP UNA VIA DAN PERINTAH TERTULIS", "t": "Ancaman pidana penjara dan pidana denda sebagaimana dimaksud dalam Pasal 103, Pasal 104, Pasal 104A, Pasal 105,Pasal 106,Pasal 106A,Pasal 106B,Pasal 106C, dan Pasal 107, berlaku pula bagi Pihak baik yang secara langsung maupun tidak langsung memengaruhi Pihak lain untuk melakukan pelanggaran pasal-pasal dimaksud. 50. Ketentuan ... jdih.kemenkeu.go.id R£PUBUK INDONESIA 50. Ketentuan Pasal 109 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "109", "b": "BAB XIIA PRINSIP UNA VIA DAN PERINTAH TERTULIS", "t": "Setiap Pihak yang tidak mematuhi atau menghambat pelaksanaan ketentuan sebagaimana dimaksud dalam Pasal 100 dipidana dengan pidana penjara paling singkat 2 (dua) tahun dan paling lama 15 (lima belas) tahun dan pidana denda paling sedikit Rp5.000.000.000,00 (lima miliar rupiah) dan paling banyak Rp200.000.000.000,00 dua ratus miliar rupiah). 51. Di antara Pasal 109 dan Pasal 110 disisipkan 1 (satu) pasal, yakni Pasal 109A sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "109A", "b": "BAB XIIA PRINSIP UNA VIA DAN PERINTAH TERTULIS", "t": "(1) Dalam hal tindak pidana sebagaimana dimaksud dalam Pasal 103 ayat (1), Pasal 103 ayat (2), Pasal 103 ayat (3), Pasal 104, Pasal 104A, Pasal 105, Pasal 106, Pasal 106A, Pasal 106B, Pasal 106C, Pasal 107, Pasal 108, dan Pasal 109 dilakukan oleh korporasi atau badan usaha yang berbentuk badan hukum maupun yang tidak berbentuk badan hukum, atau badan lainnya, pidana dijatuhkan terhadap korporasi atau badan usaha yang berbentuk badan hukum maupun yang tidak berbentuk badan hukum, atau badan lainnya dan/atau anggota direksi atau yang dipersamakan, anggota dewan komisaris atau yang dipersamakan, pemegang saham pengendali atau yang dipersamakan, dan/atau Pihak lain. (2) Pidana dijatuhkan terhadap korporasi atau badan usaha yang berbentuk badan hukum maupun yang tidak berbentuk badan hukum, atau badan lainnya sebagaimana dimaksud pada ayat (1) apabila tindak pidana: a. dilakukan atau diperintahkan oleh anggota direksi atau yang dipersamakan, anggota dewan komisaris atau yang dipersamakan, pemegang saham pengendali atau yang dipersamakan, dan/ a tau Pihak lain; b. dilakukan ... jdih.kemenkeu.go.id REPUBUK INDONESIA b. dilakukan dalam rangka pemenuhan maksud dan tujuan atau badan usaha …"}, {"l": "UU 4/2023", "p": "36", "b": "Bagian Kelima", "t": "(1) Permohonan pailit badan pengelola instrumen keuangan (special purpose vehicle) dan/ atau pengelola dana perwalian (trustee) hanya dapat diajukan oleh Otoritas Jasa Keuangan. (2) Aset yang dialihkan hak, manfaat dan risikonya badan pengelola instrumen keuangan (special purpose vehicle) dan/atau pengelola dana perwalian (trustee) bukan merupakan bagian dari aset kreditur/ pemilik aset asal (originator) dan dicatat terpisah dari aset badan pengelola instrumen keuangan (special purpose vehicle) dan/ a tau pengelola dana perwalian (trustee). (3) Dalam hal kreditur/ pemilik aset asal (originator) dipailitkan, semua aset yang hak, manfaat dan risikonya telah dialihkan sepenuhnya kepada badan pengelola instrumen keuangan (special purpose vehicle) dan/ a tau pengelola dana perwalian (trustee) tidak termasuk dalam harta pailit (boedel pailit) kreditur/pemilik aset asal (originator). Pasal 37 ... jdih.kemenkeu.go.id REPUBUK INDONESIA"}, {"l": "UU 4/2023", "p": "39", "b": "Bagian Kelima", "t": "Ketentuan lebih lanjut mengenai badan pengelola instrumen keuangan (special purpose vehicle) dan/atau pengelola dana perwalian (trustee) sebagaimana dimaksud dalam Pasal 34 sampai dengan Pasal 38 dan perlakuan perpajakannya diatur dalam Peraturan Pemerintah. Paragraf 2 ... jdih.kemenkeu.go.id REPUBUK INDONESIA Paragraf 2 Penyelesaian Transaksi"}, {"l": "UU 4/2023", "p": "46", "b": "Bagian Keenam", "t": "Dalam rangka pengembangan dan penguatan sektor keuangan melalui penataan instrumen keuangan surat utang negara, Undang-Undang 1m mengubah, menghapus, dan/ atau menetapkan pengaturan baru beberapa ketentuan yang diatur dalam Undang- Undang Nomor 24 Tahun 2002 tentang Surat Utang Negara (Lembaran Negara Republik Indonesia Tahun 2002 Nomor 110, Tambahan Lembaran Negara Republik Indonesia Nomor 4236)."}, {"l": "UU 4/2023", "p": "23", "b": "BAB VI PERASURANSIAN", "t": "(1) Laporan tertentu dan hasil analisis atas laporan sebagaimana dimaksud dalam Pasal 22 ayat (1) tidak dapat dibuka oleh Otoritas Jasa Keuangan kepada pihak lain, kecuali kepada: a. polisi ... jdih.kemenkeu.go.id PRESIOEN R£PUBUK INDONESIA a. polisi dan jaksa untuk kepentingan penyidikan; b. hakim untuk kepentingan peradilan; c. pejabat pajak untuk kepentingan perpajakan; d. Bank Indonesia untuk pelaksanaan tugasnya; e. Lembaga Penjamin Simpanan untuk pelaksanaan tugas penyelenggaraan program penjaminan polis; dan f. pihak lain berdasarkan peraturan perundang­ undangan. (2) Ketentuan lebih lanjut mengenai syarat dan tata cara memperoleh laporan tertentu dan hasil analisis atas laporan sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Otoritas Jasa Keuangan. 12. Ketentuan Pasal 27 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "39A", "b": "BAB VI PERASURANSIAN", "t": "(1) Pemerintah dapat membentuk Program Asuransi Wajib sesuai dengan kebutuhan. (2) Pemerintah dapat mewajibkan kepada kelompok tertentu dalam masyarakat untuk ikut serta dalam Program Asuransi Wajib sebagaimana dimaksud pada ayat (1). (3) Pemerintah dapat mewajibkan kepada kelompok tertentu dalam masyarakat untuk membayar Premi atau Kontribusi keikutsertaan sebagai salah satu sumber pendanaan Program Asuransi Wajib sebagaimana dimaksud pada ayat (2). (4) Ketentuan lebih lanjut mengenai penyelenggaraan Program Asuransi Wajib sebagaimana dimaksud pada ayat (1) diatur dengan Peraturan Pemerintah setelah mendapatkan persetujuan dari DPR. 16. Ketentuan Pasal 50 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "72A", "b": "BAB VI PERASURANSIAN", "t": "(1) Otoritas Jasa Keuangan berwenang menetapkan dimulainya, tidak dilakukannya, atau dihentikannya penyidikan terhadap tindak pidana perasuransian. (2) Sebelum menetapkan dimulainya penyidikan sebagaimana dimaksud pada ayat (1), Otoritas Jasa Keuangan melakukan penyelidikan terhadap dugaan tindak pidana perasuransian. (3) Pada tahap penyelidikan sebagaimana dimaksud pada ayat (2), pihak yang diduga melakukan tindak pidana perasuransian dapat mengajukan permohonan kepada Otoritas Jasa Keuangan untuk penyelesaian pelanggaran atas peraturan perundang­ undangan di sektor perasuransian. (4) Otoritas Jasa Keuangan melakukan penilaian terhadap permohonan penyelesaian pelanggaran sebagaimana dimaksud pada ayat (3) dan menghitung nilai kerugian atas pelanggaran. (5) Dalam melakukan penilaian terhadap permohonan penyelesaian pelanggaran dan perhitungan nilai kerugian atas pelanggaran sebagaimana dimaksud pada ayat (4), Otoritas Jasa Keuangan mempertimbangkan minimal: a. ada atau tidaknya penyelesaian atas kerugian yang timbul akibat tindak pidana; b. nilai transaksi dan/ atau nilai kerugian atas pelanggaran; dan c. dampak ... jdih.kemenkeu.go.id . REPUBUK INDONESIA . c. dampak terhadap …"}, {"l": "UU 4/2023", "p": "73A", "b": "BAB VI PERASURANSIAN", "t": "Pengendali yang tidak melaksanakan tanggung jawabnya sebagaimana dimaksud dalam Pasal 15 dipidana dengan pidana penjara paling singkat 7 (tujuh) tahun dan paling lama 15 (lima belas) tahun dan pidana denda paling sedikit Rpl0.000.000.000,00 (sepuluh miliar rupiah) dan paling banyak Rp200.000.000.000,00 (dua ratus miliar rupiah)."}, {"l": "UU 4/2023", "p": "73B", "b": "BAB VI PERASURANSIAN", "t": "Pengendali, pemegang saham, anggota direksi, anggota dewan komisaris, atau yang setara dengan pemegang saham, anggota direksi, dan anggota dewan komisaris pada badan hukum berbentuk koperasi atau usaha bersama sebagaimana dimaksud dalam Pasal 6 ayat (1) huruf c, pegawai, dan/ atau pihak lain yang dengan sengaja meminta atau menerima, mengizinkan atau menyetujui untuk menerima tanpa hak suatu imbalan, komisi, uang tambahan, pelayanan, uang, atau barang berharga, untuk keuntungan pribadinya atau untuk keuntungan keluarganya, dalam rangka memperoleh jasa, layanan, perolehan bisnis, penempatan investasi, dan/atau pencairan klaim dari Perusahaan Perasuransian sebagaimana dimaksud dalam Pasal 15A dipidana dengan pidana penjara paling singkat 3 (tiga) tahun dan paling lama 8 (delapan) tahun dan pidana denda paling sedikit Rp5.000.000.000,00 (lima miliar rupiah) dan paling banyak Rpl00.000.000.000,00 (seratus miliar rupiah)."}, {"l": "UU 4/2023", "p": "73C", "b": "BAB VI PERASURANSIAN", "t": "Setiap Orang yang menggelapkan kekayaan yang dimiliki dan/ atau dikelola oleh Perusahaan Asuransi, Perusahaan Asuransi Syariah, perusahaan reasuransi, atau perusahaan reasuransi syariah dengan cara mengalihkan, menjaminkan, mengagunkan, menggunakan kekayaan, atau melakukan tindakan lain yang merugikan Perusahaan Asuransi, Perusahaan Asuransi Syariah, perusahaan reasuransi, atau perusahaan reasuransi syariah sebagaimana dimaksud dalam Pasal 21B dipidana dengan pidana penjara paling lama 8 (delapan) tahun dan pidana denda paling banyak Rp50.000.000.000,00 (lima puluh miliar rupiah). 2 5. Ketentuan . . . jdih.kemenkeu.go.id REPUBUK INDONESIA 25. Ketentuan Pasal 74 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "75", "b": "BAB VI PERASURANSIAN", "t": "Setiap Orang yang dengan sengaja tidak memberikan informasi atau memberikan informasi yang tidak benar, palsu, dan/ a tau menyesatkan kepada calon Pemegang Polis, calon Tertanggung, calon Peserta, Pemegang Polis, Tertanggung, atau Peserta mengenai risiko, manfaat, kewajiban, dan pembebanan biaya terkait dengan produk asuransi atau produk asuransi syariah yang ditawarkan kepada calon Pemegang Polis, calon Tertanggung, calon Peserta, Pemegang Polis, Tertanggung, atau Peserta sebagaimana dimaksud dalam Pasal 27 ayat (7), Pasal 28 ayat (6), dan Pasal 31 ayat (2) dipidana dengan pidana penjara paling lama 5 (lima) tahun dan pidana denda paling banyak Rp5.000.000.000,00 (lima miliar rupiah). 27. Di antara Pasal 82 dan Pasal 83 disisipkan 1 (satu) pasal, yakni Pasal 82A sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "56", "b": "Bagian Ketiga", "t": "(1) Anggota Usaha Bersama terdiri atas: a. pemegang polis perorangan berkewarganegaraan Indonesia; dan b. pemegang polis badan hukum, lembaga, kelompok, atau perkumpulan yang tunduk pada hukum Indonesia. (2) Dalam hal pemegang polis merupakan badan hukum, lembaga, kelompok, atau perkumpulan yang tunduk pada hukum Indonesia sebagaimana dimaksud pada ayat (1) huruf b, keanggotaan dalam Usaha Bersama diwakili oleh pengurus atau pihak yang ditunjuk oleh pemegang polis. (3) Keanggotaan pada Usaha Bersama sebagaimana dimaksud pada ayat (1) berakhir apabila: a. anggota meninggal dunia; b. anggota tidak lagi memiliki polis asuransi pada Usaha Bersama selama 6 (enam) bulan secara berturut­ turut; atau c. keanggotaannya harus berakhir sesuai dengan ketentuan peraturan perundang-undangan. (4) Anggota Usaha Bersama berhak: a. dipilih menjadi peserta RUA sesuai dengan persyaratan dan mekanisme sebagaimana diatur dalam ketentuan peraturan perundang-undangan; dan b. mendapatkan ... jdih.kemenkeu.go.id b. mendapatkan seluruh keuntungan dari kegiatan usaha sesuai dengan ketentuan peraturan perundang-undangan. (5) Anggota Usaha Bersama wajib: a. mematuhi anggaran dasar dan keputusan yang telah …"}, {"l": "UU 4/2023", "p": "57", "b": "Bagian Keempat", "t": "Organ Usaha Bersama terdiri atas RUA, Direksi Usaha Bersama, dan Dewan Komisaris Usaha Bersama. Paragraf 1 RUA Subparagraf 1 Wewenang RUA"}, {"l": "UU 4/2023", "p": "62", "b": "Bagian Keempat", "t": "(1) Peserta RUA berjumlah ganjil paling sedikit 11 (sebelas) orang dan paling banyak 15 (lima belas) orang. (2) Peserta RUA sebagaimana dimaksud pada ayat (1) merupakan perwakilan anggota dari setiap wilayah pemilihan. (3) Jumlah wilayah pemilihan disesuaikan dengan jumlah peserta RUA sebagaimana dimaksud pada ayat (1). (4) Jumlah peserta RUA sebagaimana dimaksud pada ayat (1) dan pembagian wilayah pemilihan sebagaimana dimaksud pada ayat (2) ditetapkan dalam anggaran dasar. Subparagraf 4 ... jdih.kemenkeu.go.id REPUBUK INDONESIA Subparagraf 4 Pemilihan Peserta RUA"}, {"l": "UU 4/2023", "p": "73", "b": "Bagian Keempat", "t": "(1) Anggota Dewan Komisaris Usaha Bersama diangkat dan diberhentikan oleh RUA. (2) Anggota ... jdih.kemenkeu.go.id . REPUBUK INDONESIA . (2) Anggota Dewan Komisaris Usaha Bersama sebagaimana dimaksud pada ayat (1) harus memenuhi persyaratan sebagai berikut: a. warga negara Indonesia; b. cakap melakukan perbuatan hukum; c. mampu untuk bertindak dengan iktikad baik, jujur, dan profesional; d. tidak terafiliasi dengan Direksi Usaha Bersama, anggota Dewan Komisaris Usaha Bersama lain, dan/ atau peserta RUA; e. bebas dari hubungan keuangan atau hubungan lainnya yang dapat memengaruhi kemampuannya untuk bertindak independen atau bertindak semata- mata demi kepentingan Usaha Bersama, kecuali yang berkaitan dengan kedudukannya sebagai anggota; f. memiliki pengetahuan yang relevan dengan jabatannya; g. mampu bertindak untuk kepentingan Usaha Bersama, tertanggung, dan/atau pihak yang berhak memperoleh manfaat; h. bersedia mendahulukan kepentingan Usaha Bersama, tertanggung, dan/ atau pihak yang berhak memperoleh manfaat dari pada kepentingan pribadi; i. mampu mengambil keputusan berdasarkan penilaian independen dan objektif untuk kepentingan Usaha Bersama, tertanggung, dan/atau pihak yang …"}, {"l": "UU 4/2023", "p": "76", "b": "Bagian Keempat", "t": "(1) Anggota Dewan Komisaris Usaha Bersama wajib mengungkapkan: a. kepemilikan sahamnya pada perusahaan lain yang berkedudukan di dalam dan/ atau di luar negeri; dan b. hubungan keuangan dan/ atau hubungan keluarga dengan anggota Dewan Komisaris Usaha Bersama lain, anggota Direksi Usaha Bersama, dan/atau peserta RUA, kepada Usaha Bersama, peserta RUA, dan Otoritas Jasa Keuangan. (2) Pengungkapan ... jdih.kemenkeu.go.id REPUBUK INDONESIA (2) Pengungkapan kepemilikan oleh anggota Dewan Komisaris Usaha Bersama kepada Otoritas Jasa Keuangan disampaikan dalam laporan penerapan tata kelola perusahaan yang baik bagi perusahaan perasuransian sesuai dengan ketentuan peraturan perundang-undangan di bidang perasuransian."}, {"l": "UU 4/2023", "p": "77", "b": "Bagian Kelima", "t": "(1) Usaha Bersama dapat melakukan perubahan bentuk badan hukum menjadi perseroan terbatas. (2) Perubahan bentuk badan hukum sebagaimana dimaksud pada ayat ( 1) dilaksanakan dengan prinsip: a. wajar dan adil; b. transparan; dan c. memperhatikan hak dan kewajiban anggota. (3) Perubahan bentuk badan hukum sebagaimana dimaksud pada ayat (2) hanya dapat diusulkan oleh: a. lebih dari 1/2 (satu per dua) dari seluruh peserta RUA; b. Dewan Komisaris Usaha Bersama; atau c. Direksi Usaha Bersama. (4) Dewan Komisaris Usaha Bersama wajib melakukan pengawasan proses perubahan bentuk badan hukum Usaha Bersama. (5) Rencana perubahan bentuk badan hukum sebagaimana dimaksud pada ayat (1) dituangkan dalam Proposal dan harus mendapatkan persetujuan Otoritas Jasa Keuangan. (6) Proposal sebagaimana dimaksud pada ayat (5) harus mendapatkan persetujuan RUA terlebih dahulu sebelum disampaikan kepada Otoritas Jasa Keuangan. (7) Perubahan bentuk badan hukum Usaha Bersama mengakibatkan: a. seluruh ... jdih.kemenkeu.go.id REPUBUK INDONESIA a. seluruh aset dan liabilitas, serta hak dan kewajiban hukum Usaha Bersama menjadi aset dan liabilitas, serta hak dan kewajiban hukum badan hukum baru; dan b. semua …"}, {"l": "UU 4/2023", "p": "81", "b": "Bagian Kedua", "t": "(1) Perusahaan Asuransi dan Perusahaan Asuransi Syariah yang menjadi peserta program penjaminan polis wajib: a. menyerahkan dokumen sebagai berikut: 1. salinan anggaran dasar dan/ atau akta pendirian Perusahaan Asuransi dan Perusahaan Asuransi Syariah dan perubahannya; 2. salinan dokumen penzman Perusahaan Asuransi dan Perusahaan Asuransi Syariah; dan 3. surat pernyataan dari masing-masing Pengendali dan anggota direksi, anggota dewan komisaris atau yang setara dengan anggota direksi, anggota dewan komisaris pada badan hukum berbentuk koperasi atau Usaha Bersama, yang memuat: a) komitmen dan kesediaan masing-masing anggota direksi, anggota dewan komisaris, dan Pengendali atau yang setara dengan anggota direksi, anggota dewan komisaris, dan Pengendali pada badan hukum berbentuk koperasi atau Usaha Bersama, untuk mematuhi seluruh ketentuan sebagaimana diatur dalam Peraturan Lembaga Penjamin Simpanan; b) kesediaan untuk bertanggung jawab secara pribadi atas kelalaian dan/ atau perbuatan yang melanggar hukum yang mengakibatkan kerugian a tau membahayakan kelangsungan usaha Perusahaan Asuransi dan Perusahaan Asuransi Syariah; dan c) kesediaan ... jdih.kemenkeu.go.id REPUBUK INDONESIA …"}, {"l": "UU 4/2023", "p": "83", "b": "Bagian Ketiga", "t": "(1) Program penjaminan polis hanya menjamin unsur proteksi dari produk asuransi pada lini usaha tertentu. (2) Program asuransi sosial dan program asuransi wajib dikecualikan dari program penjaminan polis. (3) Perusahaan Asuransi dan Perusahaan Asuransi Syariah yang tidak memenuhi persyaratan untuk menjadi peserta program penjaminan polis sebagaimana dimaksud dalam Pasal 80 ayat (2) wajib membentuk dana jaminan. (4) Ketentuan lebih lanjut mengenai lini usaha tertentu sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Pemerintah setelah mendapatkan persetujuan dari DPR. (5) Ketentuan lebih lanjut mengenai pengecualian program asuransi sosial dan program asuransi wajib sebagaimana dimaksud pada ayat (2) diatur dalam Peraturan Pemerintah. (6) Ketentuan . . . jdih.kemenkeu.go.id REPUBUK INDONESIA (6) Ketentuan lebih lanjut mengenai pembentukan dana jaminan sebagaimana dimaksud pada ayat (3) diatur dalam Peraturan Otoritas Jasa Keuangan. Pasal84 ( 1) Program penjaminan polis dilaksanakan atas polis asuransi yang masih aktif atau belum berakhir dan klaim polis asuransi dari Perusahaan Asuransi dan Perusahaan Asuransi Syariah yang dicabut izin usahanya. (2) Pelaksanaan program …"}, {"l": "UU 4/2023", "p": "88", "b": "Bagian Keempat", "t": "(1) Perusahaan Asuransi dan Perusahaan Asuransi Syariah wajib menyampaikan data polis berbasis pemegang polis, tertanggung, dan/atau peserta kepada Lembaga Penjamin Simpanan untuk menentukan polis yang layak dibayar. (2) Dalam rangka menjalankan tugas untuk melaksanakan program penjaminan polis, Lembaga Penjamin Simpanan dapat melakukan pemeriksaan terhadap data polis berbasis pemegang polis, tertanggung, dan/ atau peserta. (3) Perusahaan ... jdih.kemenkeu.go.id REPUBUK INDONESIA (3) Perusahaan Asuransi dan Perusahaan Asuransi Syariah bertanggung jawab atas kebenaran dan kelengkapan data polis berbasis pemegang polis, tertanggung, dan/ atau peserta yang disampaikan kepada Lembaga Penjamin Simpanan sebagaimana dimaksud pada ayat (1). (4) Penyampaian data polis berbasis pemegang polis, tertanggung, dan/ atau peserta sebagaimana dimaksud pada ayat (1) dikecualikan dari ketentuan kerahasiaan perasuransian. (5) Ketentuan lebih lanjut mengenai penyampaian data polis berbasis pemegang polis, tertanggung, dan/ atau peserta sebagaimana dimaksud pada ayat (1) dan pemeriksaan sebagaimana dimaksud pada ayat (2) diatur dalam Peraturan Lembaga Penjamin Simpanan."}, {"l": "UU 4/2023", "p": "89", "b": "Bagian Keempat", "t": "(1) Dalam menjalankan tugas dan wewenangnya, Lembaga Penjamin Simpanan dapat meminta data, informasi, dan/ atau dokumen kepada pihak lain. (2) Setiap pihak yang dimintai data, informasi, dan/ a tau dokumen sebagaimana dimaksud pada ayat (1) wajib menyampaikan kepada Lembaga Penjamin Simpanan."}, {"l": "UU 4/2023", "p": "96", "b": "Bagian Kelima", "t": "(1) Untuk kepentingan aset atau kewajiban Perusahaan Asuransi dan Perusahaan Asuransi Syariah dalam likuidasi, tim likuidasi dapat meminta pembatalan kepada pengadilan niaga atas segala perbuatan hukum Perusahaan Asuransi dan Perusahaan Asuransi Syariah yang mengakibatkan berkurangnya aset a tau bertambahnya kewajiban Perusahaan Asuransi dan Perusahaan Asuransi Syariah, yang dilakukan dalam jangka waktu 1 (satu) tahun sebelum pencabutan izin usaha. (2) Perbuatan hukum Perusahaan Asuransi dan Perusahaan Asuransi Syariah yang wajib dilakukan berdasarkan Undang-Undang dikecualikan dari ketentuan sebagaimana dimaksud pada ayat (1). Pasal 97 ... jdih.kemenkeu.go.id"}, {"l": "UU 4/2023", "p": "97", "b": "Bagian Kelima", "t": "(1) Pengendali, pemegang saham, anggota direksi, dan anggota dewan komisaris, atau yang setara dengan pemegang saham, anggota direksi, dan anggota dewan komisaris pada badan hukum berbentuk koperasi atau Usaha Bersama, serta pegawai dan mantan pegawai Perusahaan Asuransi dan Perusahaan Asuransi Syariah dalam likuidasi wajib memberikan data dan informasi yang diperlukan oleh tim likuidasi. (2) Pengendali, pemegang saham, anggota direksi, dan anggota dewan komisaris, atau yang setara dengan pemegang saham, anggota direksi, dan anggota dewan komisaris pada badan hukum berbentuk koperasi atau Usaha Bersama, serta pegawai Perusahaan Asuransi dan Perusahaan Asuransi Syariah dalam likuidasi dilarang secara langsung atau tidak langsung menghambat proses likuidasi."}, {"l": "UU 4/2023", "p": "98", "b": "Bagian Kelima", "t": "(1) Pembayaran kewajiban Perusahaan Asuransi dan Perusahaan Asuransi Syariah kepada para kreditur dilakukan dengan urutan sebagai berikut: a. penggantian atas talangan pembayaran gaji pegawai yang terutang; b. penggantian atas pembayaran talangan pesangon pegawai; c. biaya perkara di pengadilan, biaya lelang yang terutang, dan biaya operasional kantor; d. pembayaran atas pelaksanaan program penjaminan polis yang harus dibayarkan oleh Lembaga Penjamin Simpanan sebagaimana dimaksud dalam Pasal 84 ayat (2); e. pajak yang terutang; f. bagian hak pemegang polis yang tidak dibayarkan penjaminannya dan hak pemegang polis yang tidak dijamin; dan g. hak dari kreditur lainnya. (2) Segala biaya yang berkaitan dengan likuidasi dan tercantum dalam daftar biaya likuidasi menjadi beban aset Perusahaan Asuransi dan Perusahaan Asuransi Syariah dalam likuidasi dan dikeluarkan terlebih dahulu dari setiap hasil pencairannya. (3) Honorarium ... jdih.kemenkeu.go.id REPUBUK INDONESIA (3) Honorarium tim likuidasi yang termasuk salah satu komponen dalam biaya sebagaimana dimaksud pada ayat (2) ditetapkan oleh Lembaga Penjamin Simpanan. (4) Dalam hal seluruh kewajiban Perusahaan Asuransi dan Perusahaan …"}, {"l": "UU 4/2023", "p": "99", "b": "Bagian Kelima", "t": "Setelah menerima pertanggungjawaban tim likuidasi, Lembaga Penjamin Simpanan: a. meminta tim likuidasi: 1. mengumumkan berakhirnya likuidasi dengan menempatkan dalam Berita Negara Republik Indonesia dan dalam 2 (dua) surat kabar harian yang mempunyai peredaran luas; dan 2. memberitahukan kepada instansi yang berwenang agar nama badan hukum Perusahaan Asuransi dan Perusahaan Asuransi Syariah tersebut dicoret dari daftar perusahaan; dan b. membubarkan tim likuidasi."}, {"l": "UU 4/2023", "p": "100", "b": "Bagian Kelima", "t": "Status badan hukum Perusahaan Asuransi dan Perusahaan Asuransi Syariah yang dilikuidasi hapus terhitung sejak tanggal pengumuman berakhirnya likuidasi dalam Berita Negara Republik Indonesia sebagaimana dimaksud dalam Pasal 99 huruf a angka 1. Pasal 101 ... jdih.kemenkeu.go.id REPUBUK INDONESIA"}, {"l": "UU 4/2023", "p": "102", "b": "Bagian Keenam", "t": "(1) Lembaga Penjamin Simpanan bertanggung jawab atas pengelolaan dan penatausahaan aset dan kewajiban penyelenggaraan program penjaminan polis. (2) Lembaga Penjamin Simpanan memisahkan pencatatan aset dan kewajiban penyelenggaraan program penjaminan polis sebagaimana dimaksud pada ayat (1} dari pencatatan aset dan kewajiban penyelenggaraan penjaminan s1mpanan. (3) Ketentuan lebih lanjut mengenai pengelolaan dan penatausahaan aset dan kewajiban sebagaimana dimaksud pada ayat ( 1) diatur dalam Peraturan Pemerintah."}, {"l": "UU 4/2023", "p": "110", "b": "Bagian Kedua", "t": "(1) Anggota direksi, anggota dewan komisaris, Dewan Pengawas Syariah, PSP, anggota pengurus, anggota pengawas, atau pengelola dari penyelenggara Usaha Jasa Pembiayaan wajib memenuhi persyaratan yang ditetapkan oleh Otoritas Jasa Keuangan. (2) Penyelenggara Usaha Jasa Pembiayaan yang melaksanakan kegiatan Usaha Jasa Pembiayaan berdasarkan Prinsip Syariah wajib memiliki Dewan Pengawas Syariah yang diangkat dalam rapat umum pemegang saham atau rapat anggota atas rekomendasi dari lembaga yang memiliki kewenangan dalam penetapan fatwa di bidang syariah. Pasal 111 ... jdih.kemenkeu.go.id"}, {"l": "UU 4/2023", "p": "111", "b": "Bagian Kedua", "t": "(1) Anggota direksi, anggota dewan komisaris, Dewan Pengawas Syariah, PSP, anggota pengurus, anggota pengawas, dan pengelola dari penyelenggara Usaha Jasa Pembiayaan wajib terlebih dahulu memenuhi persyaratan penilaian kemampuan dan kepatutan yang ditetapkan oleh Otoritas Jasa Keuangan. (2) Ketentuan lebih lanjut mengenai persyaratan penilaian kemampuan dan kepatutan sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Otoritas Jasa Keuangan. Paragraf 4 Sumber Dana Penyertaan"}, {"l": "UU 4/2023", "p": "112", "b": "Bagian Kedua", "t": "(1) Sumber dana penyertaan bagi penyelenggara Usaha Jasa Pembiayaan ditetapkan berdasarkan ruang lingkup Usaha Jasa Pembiayaan yang dilakukan sebagaimana dimaksud dalam Pasal 106. (2) Sumber dana penyertaan sebagaimana dimaksud pada ayat (1) dilarang: a. berasal dari pinjaman; dan b. berasal dari dan untuk tujuan kegiatan pencucian uang, pendanaan terorisme, dan kejahatan keuangan lain. (3) Ketentuan lebih lanjut mengenai persyaratan sumber dana penyertaan bagi penyelenggara Usaha Jasa Pembiayaan sebagaimana dimaksud pada ayat (1) dan ayat (2) diatur dalam Peraturan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "113", "b": "Bagian Ketiga", "t": "(1) Setiap Orang yang melakukan kegiatan usaha sebagaimana dimaksud dalam Pasal 106 wajib memperoleh izin usaha sebagai penyelenggara Usaha Jasa Pembiayaan dari Otoritas Jasa Keuangan, kecuali apabila diatur dengan undang-undang tersendiri. (2) Untuk memperoleh izin usaha sebagaimana dimaksud pada ayat (1), pemohon harus menyampaikan permohonan kepada Otoritas Jasa Keuangan dengan memenuhi persyaratan minimal: a. anggaran dasar; b. susunan organisasi; c. modal disetor; d. data anggota direksi, anggota dewan komisaris, Dewan Pengawas Syariah, anggota pengurus, anggota pengawas, dan/ atau pengelola; e. data pemegang saham atau anggota; f. kelayakan rencana kerja termasuk sistem dan prosedur kerja Usaha Jasa Pembiayaan; g. kelayakan sistem manajemen risiko; h. kesiapan infrastruktur; i. konfirmasi dari otoritas pengawas pihak asing yang bersangkutan, untuk penyelenggara Usaha Jasa Pembiayaan yang di dalamnya terdapat penyertaan langsung pihak asing; dan J. persyaratan lain yang diperlukan untuk mendukung pertumbuhan usaha yang sehat. (3) Persyaratan izin usaha sebagaimana dimaksud pada ayat (2) diberlakukan sesuai dengan lingkup usaha yang akan dijalankan sebagaimana dimaksud dalam …"}, {"l": "UU 4/2023", "p": "114", "b": "Bagian Ketiga", "t": "(1) Penyelenggara Usaha Jasa Pembiayaan dapat melakukan pembukaan kantor cabang. (2) Pembukaan kantor cabang sebagaimana dimaksud pada ayat (1) wajib dilaporkan kepada Otoritas Jasa Keuangan. (3) Ketentuan lebih lanjut mengenai pembukaan kantor cabang sebagaimana dimaksud pada ayat (1) dan kewajiban pelaporan sebagaimana dimaksud pada ayat (2) diatur dalam Peraturan Otoritas Jasa Keuangan. Paragraf 2 Konversi dan Pembentukan Unit Usaha Syariah"}, {"l": "UU 4/2023", "p": "115", "b": "Bagian Ketiga", "t": "(1) Penyelenggara Usaha Jasa Pembiayaan yang menyelenggarakan kegiatan usaha secara konvensional dapat melakukan konversi menjadi penyelenggara Usaha Jasa Pembiayaan yang menyelenggarakan kegiatan usaha sesuai dengan Prinsip Syariah. (2) Penyelenggara Usaha Jasa Pembiayaan dapat mendirikan unit usaha syariah. (3) Konversi dan pendirian unit usaha syariah sebagaimana dimaksud pada ayat (1) dan ayat (2) wajib memperoleh izin dari Otoritas Jasa Keuangan. (4) Penyelenggara Usaha Jasa Pembiayaan yang memiliki unit usaha syariah wajib melakukan pemisahan unit usaha syariah apabila memenuhi kriteria tertentu. (5) Ketentuan lebih lanjut mengenai konversi dan unit usaha syariah sebagaimana dimaksud pada ayat (1) sampai dengan ayat (4) diatur dalam Peraturan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "116", "b": "Bagian Keempat", "t": "(1) Perjanjian Usaha Jasa Pembiayaan wajib dituangkan dalam perjanjian tertulis. (2) Perjanjian Usaha Jasa Pembiayaan sebagaimana dimaksud pada ayat (1) wajib memenuhi ketentuan penyusunan perjanjian sesuai dengan ketentuan peraturan perundang-undangan. (3) Ketentuan lebih lanjut mengenai perjanjian Usaha Jasa Pembiayaan sebagaimana dimaksud pada ayat (1) dan ayat (2) diatur dalam Peraturan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "117", "b": "Bagian Keempat", "t": "Penyelenggara Usaha Jasa Pembiayaan dilarang: a. menghimpun dana secara langsung dari masyarakat berbentuk giro, tabungan, deposito, dan/ atau bentuk lainnya yang dipersamakan dengan penghimpunan dana masyarakat; b. memberikan jaminan dalam segala bentuknya atas pemenuhan kewajiban pihak lain; dan c. menerbitkan surat sanggup bayar (promissory note), kecuali sebagai jaminan atas utang kepada krediturnya."}, {"l": "UU 4/2023", "p": "118", "b": "Bagian Keempat", "t": "(1) Anggota dewan komisaris, anggota pengawas, anggota direksi, anggota pengurus, pengelola, pegawai, dan/ atau pihak terafiliasi penyelenggara Usaha Jasa Pembiayaan dilarang: a. membuat pencatatan palsu dalam pembukuan atau laporan keuangan dan/ a tau tanpa didukung dengan dokumen yang sah; b. menghilangkan atau tidak memasukkan informasi yang benar dalam laporan kegiatan usaha dan laporan keuangan; dan c. mengubah, ... jdih.kemenkeu.go.id REPUBUK INDONESIA c. mengubah, mengaburkan, menyembunyikan, menghapus, dan/ atau menghilangkan suatu pencatatan dalam pembukuan atau dalam laporan keuangan, dan dalam dokumen atau laporan kegiatan usaha. (2) Anggota dewan komisaris, anggota pengawas, anggota direksi, anggota pengurus, pengelola, pegawai, dan/ atau pihak terafiliasi penyelenggara Usaha Jasa Pembiayaan dilarang: a. meminta atau menerima suatu imbalan di luar biaya resmi, berupa uang atau barang untuk keuntungan pribadi atau keluarganya; b. menjadikan orang lain mendapatkan uang muka atau fasilitas Pembiayaan dari Usaha Jasa Pembiayaan; c. memberikan atau menyebabkan persetujuan bagi orang lain untuk melaksanakan penarikan dana yang melebihi batas Pembiayaan pada Usaha Jasa …"}, {"l": "UU 4/2023", "p": "119", "b": "Bagian Keempat", "t": "Sertifikat jaminan fidusia yang diterima oleh penyelenggara Usaha Jasa Pembiayaan sebagai jaminan dalam rangka pemenuhan kewajiban konsumen sebagaimana dimaksud dalam undang-undang mengenai jaminan fidusia memiliki kekuatan eksekutorial."}, {"l": "UU 4/2023", "p": "120", "b": "Bagian Keempat", "t": "(1) Setiap pihak yang menyerahkan barang bergerak sebagai jaminan atau barang titipan kepada penyelenggara Usaha Jasa Pembiayaan dianggap sebagai pemilik. (2) Dalam hal di kemudian hari diduga atau terbukti bahwa kepemilikan atau penguasaan barangjaminan berasal dari kejahatan atau perbuatan melanggar hukum lainnya, penyelenggara Usaha Jasa Pembiayaan tidak dapat dituntut atas tindak pidana yang berhubungan dengan penerimaan barang jaminan atau barang titipan sebagaimana dimaksud pada ayat (1). (3) Pembebasan dari tuntutan sebagaimana dimaksud pada ayat (2) hanya dapat diberikan dalam hal penyelenggara Usaha Jasa Pembiayaan telah melakukan penerapan prinsip mengenal pengguna jasa berdasarkan ketentuan peraturan perundang-undangan."}, {"l": "UU 4/2023", "p": "121", "b": "Bagian Keempat", "t": "(1) Penyelenggara Usaha Jasa Pembiayaan wajib melaksanakan prinsip tata kelola perusahaan yang baik. (2) Ketentuan lebih lanjut mengenai tata kelola perusahaan yang baik sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "122", "b": "Bagian Keempat", "t": "(1) Penyelenggara Usaha Jasa Pembiayaan wajib menerapkan manajemen risiko secara efektif yang minimal mencakup: a. pengawasan aktif direksi, dewan komisaris, Dewan Pengawas Syariah, pengurus, pengawas, dan pengelola; b. kecukupan ... jdih.kemenkeu.go.id REPUBUK INDONESIA b. kecukupan kebijakan, prosedur, dan penetapan limit risiko; c. kecukupan proses identifikasi, pengukuran, pemantauan, dan pengendalian risiko serta sistem informasi manajemen risiko; dan d. sistem pengendalian internal yang menyeluruh. (2) Dalam menerapkan manajemen risiko sebagaimana dimaksud pada ayat (1) penyelenggara Usaha Jasa Pembiayaan wajib memiliki pedoman penerapan manajemen risiko. (3) Ketentuan lebih lanjut mengenai penerapan prinsip manajemen risiko pada Usaha Jasa Pembiayaan sebagaimana dimaksud pada ayat (1) dan ayat (2) diatur dalam Peraturan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "123", "b": "Bagian Keempat", "t": "(1) Penyelenggara Usaha Jasa Pembiayaan wajib memenuhi persyaratan tingkat kesehatan. (2) Ketentuan lebih lanjut mengenai pemenuhan persyaratan tingkat kesehatan sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "124", "b": "Bagian Kelima", "t": "(1) Penyelenggara Usaha Jasa Pembiayaan dapat melakukan penggabungan, peleburan, pengambilalihan, dan pemisahan usaha berdasarkan persetujuan Otoritas Jasa Keuangan. (2) Ketentuan lebih lanjut mengenai persyaratan penggabungan, peleburan, pengambilalihan, dan pemisahan usaha sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "125", "b": "Bagian Keenam", "t": "(1) Pencabutan izm usaha penyelenggara Usaha Jasa Pembiayaan dilakukan oleh Otoritas Jasa Keuangan. (2) Pencabutan izin usaha sebagaimana dimaksud pada ayat (1) dilakukan dalam hal penyelenggara Usaha Jasa Pembiayaan: a. bubar sebagai tindak lanjut atas: 1. keputusan rapat umum pemegang saham atau rapat anggota; 2. putusan pengadilan; 3. keputusan pemerintah; atau 4. tindak lanjut proses kepailitan sebagaimana diatur dalam undang-undang mengenai kepailitan dan penundaan kewajiban pembayaran utang; b. dikenai sanksi administratif berupa pencabutan izin usaha; c. bubar karena melakukan penggabungan, peleburan, atau pemisahan; d. belum melakukan kegiatan usaha selama jangka waktu yang ditentukan oleh Otoritas Jasa Keuangan sejak tanggal izin usaha ditetapkan; atau e. mengajukan permohonan pencabutan izin usaha berdasarkan permintaan sendiri. (3) Penyelenggara Usaha Jasa Pembiayaan yang dicabut izin usahanya sebagaimana dimaksud pada ayat (2) wajib melakukan likuidasi atau penyelesaian sesuai dengan ketentuan peraturan perundang-undangan. (4) Ketentuan lebih lanjut mengenai pencabutan izin usaha dan pembubaran atas penyelenggara Usaha Jasa Pembiayaan sebagaimana dimaksud pada ayat (1) …"}, {"l": "UU 4/2023", "p": "126", "b": "Bagian Ketujuh", "t": "(1) Setiap penyelenggara Usaha Jasa Pembiayaan wajib menjadi anggota salah satu asosiasi yang sesuai dengan jenis usahanya. (2) Asosiasi penyelenggara Usaha Jasa Pembiayaan sebagaimana dimaksud pada ayat (1) harus mendapatkan persetujuan tertulis dari Otoritas Jasa Keuangan. (3) Otoritas Jasa Keuangan mendorong peran asosiasi Usaha Jasa Pembiayaan sebagaimana dimaksud pada ayat (2) untuk membangun pengawasan berbasis disiplin pasar dalam rangka penguatan dan/atau penyehatan industri Usaha Jasa Pembiayaan."}, {"l": "UU 4/2023", "p": "127", "b": "Bagian Kedelapan", "t": "(1) Profesi penunjang pada Usaha Jasa Pembiayaan terdiri atas: a. akuntan publik; b. penilai publik; dan c. profesi lain yang ditetapkan oleh Otoritas Jasa Keuangan. (2) Untuk dapat menyediakan jasa bagi penyelenggara Usaha Jasa Pembiayaan, profesi penunjang sebagaimana dimaksud pada ayat (1) wajib terdaftar di Otoritas Jasa Keuangan. (3) Penyelenggara Usaha Jasa Pembiayaan wajib menggunakan jasa dari profesi penunjang yang telah terdaftar di Otoritas Jasa Keuangan. (4) Ketentuan lebih lanjut mengenai persyaratan dan tata cara pendaftaran profesi penunjang sebagaimana dimaksud pada ayat (1) sampai dengan ayat (3) diatur dalam Peraturan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "128", "b": "Bagian Kesembilan", "t": "(1) Pengawasan terhadap penyelenggara Usaha Jasa Pembiayaan dilakukan oleh Otoritas Jasa Keuangan. (2) Dalam rangka pengawasan sebagaimana dimaksud pada ayat (1), penyelenggara Usaha Jasa Pembiayaan wajib menyampaikan laporan bulanan, laporan keuangan tahunan dan/ a tau laporan lain secara benar kepada Otoritas Jasa Keuangan. (3) Dalam melakukan pengawasan sebagaimana dimaksud pada ayat (1), Otoritas Jasa Keuangan berwenang: a. menyetujui atau menolak untuk memberikan izin usaha, izin pembukaan kantor cabang, izin konversi, dan izin pendirian unit usaha syariah; b. mencabut izin usaha penyelenggara Usaha Jasa Pembiayaan termasuk izin atas unit usaha syariah; c. melakukan pemeriksaan terhadap penyelenggara Usaha Jasa Pembiayaan dan/atau pihak terafiliasi; d. melakukan penilaian kemampuan dan kepatutan terhadap anggota direksi, anggota dewan komisaris, Dewan Pengawas Syariah, PSP, anggota pengurus, anggota pengawas, dan pengelola; e. meminta rapat anggota untuk melakukan evaluasi kinerja pengurus, pengawas, dan pengelola; f. menetapkan PSP dari penyelenggara Usaha Jasa Pembiayaan; g. menyetujui atau mencabut persetujuan suatu pihak menjadi PSP dari penyelenggara Usaha Jasa …"}, {"l": "UU 4/2023", "p": "129", "b": "Bagian Kesembilan", "t": "(1) Dalam hal penyelenggara Usaha Jasa Pembiayaan berbadan hukum perseroan terbatas mengalami kesulitan yang membahayakan kelangsungan usahanya, Otoritas Jasa Keuangan berwenang meminta: a. pemegang saham menambah modal; b. pemegang saham mengganti anggota dewan komisaris dan/ atau anggota direksi; c. penyelenggara Usaha Jasa Pembiayaan menghapusbukukan pembiayaan yang macet, dan memperhitungkan kerugian dengan modalnya; d. melakukan penggabungan, peleburan, atau konsolidasi dengan penyelenggara Usaha Jasa Pembiayaan lainnya; e. penyelenggara Usaha Jasa Pembiayaan menjual saham kepada pembeli yang bersedia mengambil alih seluruh kewajiban; dan f. mengambil tindakan lain sesuai dengan ketentuan peraturan perundang-undangan. (2) Dalam hal penyelenggara Usaha Jasa Pembiayaan berbadan hukum koperasi mengalami kesulitan yang membahayakan kelangsungan usahanya, Otoritas Jasa Keuangan berwenang meminta: a. pengurus dan/ a tau anggota meningkatkan modal; b. anggota mengganti anggota pengurus, anggota pengawas, dan/ atau pengelola; c. penyelenggara ... jdih.kemenkeu.go.id REPUBUK INDONESIA c. penyelenggara Usaha Jasa Pembiayaan menghapusbukukan pembiayaan yang macet, dan memperhitungkan …"}, {"l": "UU 4/2023", "p": "130", "b": "BAB XI KEGIATAN USAHA BULION (BULLION)", "t": "Kegiatan usaha bulion (bullion) merupakan kegiatan usaha yang berkaitan dengan emas dalam bentuk simpanan, pembiayaan, perdagangan, penitipan emas, dan/ a tau kegiatan lainnya yang dilakukan oleh WK."}, {"l": "UU 4/2023", "p": "131", "b": "BAB XI KEGIATAN USAHA BULION (BULLION)", "t": "WK yang melakukan kegiatan usaha bulion (bullion) sebagaimana dimaksud dalam Pasal 130 wajib memperoleh izin dari Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "132", "b": "BAB XI KEGIATAN USAHA BULION (BULLION)", "t": "Ketentuan mengenai penyelenggaraan kegiatan usaha bulion (bullion) sebagaimana dimaksud dalam Pasal 130 diatur dalam Peraturan Otoritas Jasa Keuangan yang paling sedikit memuat: a. pentahapan ... jdih.kemenkeu.go.id REPUBUK INDONESIA a. pentahapan pelaksanaan kegiatan usaha bulion (bullion}; b. tata kelola; c. manajemen risiko; d. prinsip kehati-hatian; dan e. sanksi administratif."}, {"l": "UU 4/2023", "p": "133", "b": "BAB XII", "t": "Dalam rangka memperbaiki sistem pensiun di Indonesia guna meningkatkan pelindungan dan kesejahteraan masyarakat di hari tua, meningkatkan produktivitas dunia usaha, meningkatkan kepercayaan masyarakat atas penyelenggaraan program pensiun, dan mempercepat akumulasi dana jangka panjang, perlu dilakukan penyempumaan pengaturan mengenai penyelenggaraan program pensiun."}, {"l": "UU 4/2023", "p": "134", "b": "Bagian Kesatu", "t": "Dalam Undang-Undang ini yang dimaksud dengan: 1. Dana Pensiun adalah badan hukum yang mengelola dan menjalankan program yang menjanjikan manfaat pensiun. 2. Dana Pensiun Pemberi Kerja adalah Dana Pensiun yang dibentuk oleh pendiri bagi kepentingan sebagian atau seluruh karyawannya sebagai peserta, dan yang menimbulkan kewajiban terhadap pemberi kerja. 3. Dana Pensiun Lembaga Keuangan adalah Dana Pensiun yang dibentuk oleh WK tertentu, selaku pendiri, yang ditujukan bagi karyawan yang diikutsertakan oleh pemberi kerjanya dan/atau perorangan secara mandiri. 4. Manfaat ... jdih.kemenkeu.go.id . REPUBUK INDONESIA . 4. Manfaat Pensiun adalah manfaat yang diterima oleh peserta baik secara berkala dan/ atau sekaligus sebagai penghasilan hari tua yang dikaitkan dengan usia pensiun, masa kerja, dan/ atau masa mengiur. 5. Peraturan Dana Pensiun adalah peraturan yang berisi ketentuan yang menjadi dasar penyelenggaraan program pensiun bagi suatu Dana Pensiun. 6. Program Pensiun adalah setiap program yang mengupayakan Manfaat Pensiun bagi peserta. 7. Program Pensiun Iuran Pasti adalah Program Pensiun yang iurannya ditetapkan dalam Peraturan Dana Pensiun dan seluruh iuran serta hasil …"}, {"l": "UU 4/2023", "p": "135", "b": "Bagian Kedua", "t": "Dana Pensiun memiliki status sebagai badan hukum dengan syarat dan tata cara yang diatur dalam Undang-Undang ini."}, {"l": "UU 4/2023", "p": "136", "b": "Bagian Kedua", "t": "Setiap Orang yang menjalankan Program Pensiun wajib memperoleh pengesahan sebagai Dana Pensiun dari Otoritas Jasa Keuangan, kecuali Program Pensiun yang didasarkan pada undang-undang tersendiri. Paragraf 2 Ruang Lingkup Usaha Dana Pensiun"}, {"l": "UU 4/2023", "p": "137", "b": "Bagian Kedua", "t": "(1) Jenis Dana Pensiun terdiri atas: a. Dana Pensiun Pemberi Kerja; dan b. Dana Pensiun Lembaga Keuangan. (2) Dana Pensiun Pemberi Kerja sebagaimana dimaksud pada ayat (1) huruf a hanya dapat dibentuk oleh Pemberi Kerja dan atas persetujuan Otoritas Jasa Keuangan. (3) Dana Pensiun Lembaga Keuangan sebagaimana dimaksud pada ayat (1) huruf b hanya dapat dibentuk oleh badan hukum yang telah memiliki izin usaha dari Otoritas Jasa Keuangan sebagai: a. bank umum; b. bank ... jdih.kemenkeu.go.id . REPUBUK INDONESIA b. bank umum syariah; c. perusahaan asuransi jiwa; d. perusahaan asuransi jiwa syariah; e. manajer investasi; f. manajer investasi syariah; atau g. lembaga lain yang diatur lebih lanjut dalam Peraturan Otoritas Jasa Keuangan setelah dikoordinasikan dengan Menteri, dan atas persetujuan Otoritas Jasa Keuangan. (4) Ketentuan lebih lanjut mengenai persyaratan pembentukan Dana Pensiun Pemberi Kerja dan Dana Pensiun Lembaga Keuangan sebagaimana dimaksud pada ayat (2) dan ayat (3) diatur dalam Peraturan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "138", "b": "Bagian Kedua", "t": "(1) Dana Pensiun Pemberi Kerja dapat menyelenggarakan Program Pensiun Manfaat Pasti dan/ atau Program Pensiun Juran Pasti. (2) Dana Pensiun Lembaga Keuangan hanya dapat menyelenggarakan Program Pensiun Juran Pasti. (3) Dana Pensiun dapat menyelenggarakan Program Pensiun berdasarkan Prinsip Syariah dalam bentuk: a. Dana Pensiun yang seluruh kegiatannya berdasarkan Prinsip Syariah; b. unit syariah di Dana Pensiun Pemberi Kerja; atau c. penjualan paket investasi syariah di Dana Pensiun Lembaga Keuangan. (4) Dalam hal tertentu, Dana Pensiun dapat memberikan manfaat lain sebagai tambahan dari Program Pensiun. (5) Dana Pensiun tidak dapat menyelenggarakan program yang hanya memberikan manfaat lain, tanpa menyelenggarakan Program Pensiun. (6) Dalam hal Dana Pensiun menyelenggarakan manfaat lain sebagaimana dimaksud pada ayat (4), berlaku ketentuan: a. aset dan kewajiban Program Pensiun dengan aset dan kewajiban manfaat lain wajib dicatat secara terpisah; b. porsi ... jdih.kemenkeu.go.id b. porsi iuran pada Program Pensiun wajib lebih besar dibanding iuran untuk manfaat lain; dan c. penyelenggaraan manfaat lain menggunakan sistem pendanaan. (7) Ketentuan lebih lanjut mengenai Program …"}, {"l": "UU 4/2023", "p": "139", "b": "Bagian Kedua", "t": "(1) Pembentukan Dana Pensiun harus didasarkan pada: a. pernyataan tertulis Pendiri; b. Peraturan Dana Pensiun; c. penunjukan Pengurus dan Dewan Pengawas; dan d. penunjukan Dewan Pengawas Syariah bagi Dana Pensiun yang menyelenggarakan Program Pensiun berdasarkan Prinsip Syariah sebagaimana dimaksud dalam Pasal 138 ayat (3). (2) Pernyataan tertulis Pendiri sebagaimana dimaksud pada ayat (1) huruf a bagi Dana Pensiun Pemberi Kerja, wajib memuat keputusan untuk membiayai penyelenggaraan Dana Pensiun sesuai dengan Undang-Undang ini dan peraturan pelaksanaannya serta Peraturan Dana Pensiun. (3) Dana Pensiun Pemberi Kerja dapat didirikan untuk lebih dari 1 (satu) Pemberi Kerja. (4) Peraturan Dana Pensiun sebagaimana dimaksud pada ayat (1) huruf b dan setiap perubahannya harus sesuai dengan ketentuan peraturan perundang-undangan. (5) Dana Pensiun memiliki status sebagai badan hukum dan dapat memulai kegiatannya sebagai suatu Dana Pensiun sejak tanggal pengesahan pembentukan Dana Pensiun oleh Otoritas Jasa Keuangan. (6) Pengurus ... jdih.kemenkeu.go.id . REPUBUK INDONESIA (6) Pengurus wajib mengumumkan pembentukan Dana Pensiun dengan menempatkan pengesahan Otoritas Jasa Keuangan atas …"}, {"l": "UU 4/2023", "p": "140", "b": "Bagian Kedua", "t": "(1) Pendiri mengajukan permohonan pengesahan pembentukan Dana Pensiun kepada Otoritas Jasa Keuangan. (2) Otoritas Jasa Keuangan memiliki kewenangan untuk menyetujui atau menolak permohonan pengesahan pembentukan Dana Pensiun sebagaimana dimaksud pada ayat (1). (3) Dalam hal Otoritas Jasa Keuangan menolak permohonan pengesahan pembentukan Dana Pensiun sebagaimana dimaksud pada ayat (2), penolakan harus dilakukan secara tertulis dengan disertai alasannya. (4) Ketentuan lebih lanjut mengenai pengajuan pengesahan pembentukan Dana Pensiun sebagaimana dimaksud pada ayat (1) sampai dengan ayat (3) diatur dalam Peraturan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "141", "b": "Bagian Kedua", "t": "(1) Pemberi Kerja dapat menjadi Mitra Pendiri pada Dana Pensiun Pemberi Kerja yang telah berdiri. (2) Dana Pensiun yang telah berdiri dapat menggabungkan diri dengan Dana Pensiun lain atau memisahkan diri menjadi 2 (dua) atau lebih Dana Pensiun. (3) Ketentuan lebih lanjut mengenai Mitra Pendiri, penggabungan, a tau pemisahan Dana Pensiun sebagaimana dimaksud pada ayat (1) dan ayat (2) diatur dalam Peraturan Otoritas Jasa Keuangan. Pasal 142 ... jdih.kemenkeu.go.id"}, {"l": "UU 4/2023", "p": "142", "b": "Bagian Kedua", "t": "(1) Pendiri mengajukan permohonan pengesahan perubahan atas Peraturan Dana Pensiun kepada Otoritas Jasa Keuangan. (2) Otoritas Jasa Keuangan menyetujui atau menolak permohonan pengesahan perubahan atas Peraturan Dana Pensiun sebagaimana dimaksud pada ayat (1) paling lama 3 (tiga) bulan terhitung sejak permohonan pengesahan diterima secara lengkap. (3) Dalam hal Otoritas Jasa Keuangan menolak permohonan pengesahan perubahan atas Peraturan Dana Pensiun sebagaimana dimaksud pada ayat (2), penolakan dilakukan secara tertulis dengan disertai alasannya. (4) Perubahan atas Peraturan Dana Pensiun sebagaimana dimaksud pada ayat (1) tidak mengurangi Manfaat Pensiun yang sudah menjadi hak Peserta yang diperoleh selama kepesertaannya sampai pada saat pengesahan Otoritas Jasa Keuangan. (5) Hak Peserta sebelum perubahan atas Peraturan Dana Pensiun sebagaimana dimaksud pada ayat (4) wajib dipenuhi sampai saat pengesahan perubahan atas Peraturan Dana Pensiun oleh Otoritas Jasa Keuangan. (6) Seluruh perubahan atas Peraturan Dana Pensiun sebagaimana dimaksud pada ayat (4) hanya dapat dilaksanakan apabila telah mendapat pengesahan Otoritas Jasa Keuangan. (7) Ketentuan lebih lanjut mengenai tata cara …"}, {"l": "UU 4/2023", "p": "143", "b": "Bagian Kedua", "t": "(1) Dana Pensiun wajib menerapkan: a. prinsip tata kelola Dana Pensiun yang baik; dan b. manajemen ... jdih.kemenkeu.go.id . REPUBLIK INDONESIA b. manajemen risiko yang efektif, dalam setiap kegiatan usahanya pada seluruh tingkatan a tau jenjang organisasi. (2) Dana Pensiun wajib dikelola dengan mengutamakan kepentingan Peserta serta Pihak yang Berhak atas Manfaat Pensiun sebagaimana ditetapkan dalam Peraturan Dana Pensiun. (3) Dana Pensiun wajib memenuhi ketentuan dalam Undang­ Undang ini dan peraturan pelaksanaannya. (4) Ketentuan lebih lanjut mengenai tata kelola Dana Pensiun yang baik dan manajemen risiko yang efektif sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "144", "b": "Bagian Kedua", "t": "(1) Pengurus dan Dewan Pengawas ditunjuk oleh dan bertanggung jawab kepada Pendiri. (2) Pendiri dapat memberhentikan dan mengubah susunan Pengurus dan Dewan Pengawas. (3) Pengurus dilarang merangkap jabatan sebagai Pengurus Dana Pensiun lain, direksi, atau jabatan eksekutif pada badan usaha lain. (4) Pengurus dan Dewan Pengawas yang ditunjuk harus memiliki kompetensi dan pengalaman yang memadai terkait bidang yang menjadi tanggung jawabnya. (5) Pendiri Dana Pensiun yang menyelenggarakan Program Pensiun berdasarkan Prinsip Syariah sebagaimana dimaksud dalam Pasal 138 ayat (3) wajib menunjuk Dewan Pengawas Syariah atas rekomendasi lembaga yang memiliki kewenangan dalam penetapan fatwa di bidang syariah. (6) Pendiri dapat memberhentikan dan mengubah susunan Dewan Pengawas Syariah. (7) Pengurus, Dewan Pengawas, dan Dewan Pengawas Syariah wajib memenuhi ketentuan dan persyaratan kemampuan dan kepatutan serta ketentuan dan persyaratan lain yang ditetapkan oleh Otoritas Jasa Keuangan. (8) Ketentuan ... jdih.kemenkeu.go.id . REPUBLIK INDONESIA (8) Ketentuan lebih lanjut mengenai Pengurus, Dewan Pengawas, dan Dewan Pengawas Syariah Dana Pensiun sebagaimana dimaksud pada ayat (1) sampai …"}, {"l": "UU 4/2023", "p": "145", "b": "Bagian Kedua", "t": "(1) Setiap karyawan pada Pemberi Kerja berhak menjadi Peserta Dana Pensiun Pemberi Kerja apabila telah memenuhi syarat kepesertaan dalam Peraturan Dana Pensiun. (2) Dalam hal Dana Pensiun Pemberi Kerja menetapkan adanya iuran Peserta, karyawan berhak untuk tidak menjadi Peserta. (3) Dalam hal karyawan sebagaimana dimaksud pada ayat (2) memutuskan menjadi Peserta, karyawan harus menyatakan kesediaannya untuk dipotong upah atau gajinya setiap bulan. (4) Kepesertaan dalam Dana Pensiun Lembaga Keuangan terbuka bagi: a. peserta mandiri; atau b. sebagian atau seluruh karyawan yang diikutsertakan oleh Pemberi Kerja. (5) Pemberi Kerja yang mengikutsertakan sebagian atau seluruh karyawan pada Dana Pensiun Lembaga Keuangan sebagaimana dimaksud pada ayat (4) huruf b membuat perjanjian tertulis dengan Dana Pensiun Lembaga Keuangan."}, {"l": "UU 4/2023", "p": "146", "b": "Bagian Kedua", "t": "(1) Usia Pensiun Normal untuk pertama kali ditetapkan paling rendah 55 (Hrna puluh lima) tahun. (2) Usia Pensiun Normal sebagaimana dimaksud pada ayat (1) direviu dan ditetapkan secara berkala paling lama setiap 3 (tiga) tahun sekali dengan mempertimbangkan angka harapan hidup dan kondisi makroekonomi. (3) Penetapan ... jdih.kemenkeu.go.id . REPUBUK INDONESIA (3) Penetapan Usia Pensiun Normal dalam Peraturan Dana Pensiun mengikuti ketentuan sebagaimana dimaksud pada ayat (1) dan ayat (2). (4) Ketentuan lebih lanjut mengenai tata cara reviu dan penetapan Usia Pensiun Normal secara berkala sebagaimana dimaksud pada ayat (1) sampai dengan ayat (3) diatur dalam Peraturan Pemerintah."}, {"l": "UU 4/2023", "p": "147", "b": "Bagian Kedua", "t": "(1) Dana Pensiun wajib merahasiakan data pribadi Peserta. (2) Kewajiban merahasiakan sebagaimana dimaksud pada ayat (1) tunduk pada ketentuan peraturan perundang­ undangan. Paragraf 6 Iuran dan Manfaat Pensiun"}, {"l": "UU 4/2023", "p": "148", "b": "Bagian Kedua", "t": "(1) luran Program Pensiun pada Dana Pensiun berupa: a. iuran Pemberi Kerja; dan/ atau b. iuran Peserta. (2) Iuran Program Pensiun pada Dana Pensiun Pemberi Kerja tidak boleh hanya berupa iuran Peserta sebagaimana dimaksud pada ayat (1) huruf b. (3) Ketentuan lebih lanjut mengenai iuran Program Pensiun pada Dana Pensiun sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "149", "b": "Bagian Kedua", "t": "(1) Bagi Dana Pensiun Pemberi Kerja yang menyelenggarakan Program Pensiun Manfaat Pasti, iuran Pemberi Kerja sebagaimana dimaksud dalam Pasal 148 ayat (1) huruf a wajib ditetapkan dalam laporan aktuaris yang disampaikan kepada Otoritas Jasa Keuangan. (2) luran Pemberi Kerja sebagaimana dimaksud pada ayat (1) wajib dihitung berdasarkan standar praktik aktuaria Dana Pensiun yang berlaku di Indonesia. (3) Bagi ... jdih.kemenkeu.go.id REPUBUK INDONESIA (3) Bagi Dana Pensiun Pemberi Kerja yang menyelenggarakan Program Pensiun Iuran Pasti, besaran iuran Pemberi Kerja sebagaimana dimaksud dalam Pasal 148 ayat (1) huruf a wajib ditetapkan dalam Peraturan Dana Pensiun. (4) Dalam hal terdapat iuran Peserta sebagaimana dimaksud dalam Pasal 148 ayat (1) huruf b pada Dana Pensiun Pemberi Kerja, besaran iuran Peserta ditetapkan dalam Peraturan Dana Pensiun. (5) Ketentuan lebih lanjut mengenai penetapan iuran Program Pensiun pada Dana Pensiun Pemberi Kerja sebagaimana dimaksud pada ayat (1) sampai dengan ayat (4) diatur dalam Peraturan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "150", "b": "Bagian Kedua", "t": "(1) Bagi Dana Pensiun Pemberi Kerja, iuran Pemberi Kerja sebagaimana dimaksud dalam Pasal 148 ayat (1) huruf a wajib dibayarkan secara berkala dengan angsuran paling sedikit 1 (satu) kali setiap bulan. (2) Dalam hal terdapat iuran Peserta sebagaimana dimaksud dalam Pasal 148 ayat (1) huruf b, berlaku ketentuan: a. bagi Dana Pensiun Pemberi Kerja, Pemberi Kerja merupakan wajib pungut iuran Peserta berdasarkan Peraturan Dana Pensiun yang dipungut paling sedikit 1 (satu) kali setiap bulan. b. bagi Dana Pensiun Lembaga Keuangan, Pemberi Kerja wajib menyetor iuran Peserta berdasarkan perjanjian kerja sama antara Pemberi Kerja dan Dana Pensiun Lembaga Keuangan. (3) Bagi peserta mandiri pada Dana Pensiun Lembaga Keuangan sebagaimana dimaksud dalam Pasal 145 ayat (4) huruf a, iuran Peserta disetorkan langsung kepada Dana Pensiun Lembaga Keuangan berdasarkan perjanjian antara Peserta dan Dana Pensiun Lembaga Keuangan. (4) Dalam hal Pendiri pada Dana Pensiun Pemberi Kerja tidak mampu memenuhi kewajiban sebagaimana dimaksud pada ayat (1), dalam jangka waktu 3 (tiga) bulan secara berturut-turut, Pengurus wajib memberitahukan hal tersebut kepada Otoritas Jasa Keuangan. (5) Dalam ... …"}, {"l": "UU 4/2023", "p": "151", "b": "Bagian Kedua", "t": "(1) Dalam hal berdasarkan laporan aktuaris yang disampaikan kepada Otoritas Jasa Keuangan diketahui Dana Pensiun Pemberi Kerja yang menyelenggarakan Program Pensiun Manfaat Pasti memiliki aset melebihi kewajibannya, kelebihan aset atas kewajiban yang melampaui batas tertentu diperhitungkan sebagai iuran Pemberi Kerja. (2) Ketentuan mengenai batas tertentu sebagaimana dimaksud pada ayat (1) ditetapkan dalam Peraturan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "152", "b": "Bagian Kedua", "t": "(1) Kewajiban Dana Pensiun Pemberi Kerja yang menyelenggarakan Program Pensiun Manfaat Pasti sebagaimana dimaksud dalam Pasal 151 dihitung dengan menggunakan metode dan asumsi aktuaria yang wajar dan dapat dipertanggungjawabkan. (2) Ketentuan lebih lanjut mengenai metode dan asumsi aktuaria yang wajar dan dapat dipertanggungjawabkan sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Otoritas Jasa Keuangan. Pasal 153 ... jdih.kemenkeu.go.id REPUBUK INDONESIA"}, {"l": "UU 4/2023", "p": "153", "b": "Bagian Kedua", "t": "(1) Dalam hal iuran Dana Pensiun Pemberi Kerja terdiri atas iuran Peserta dan iuran Pemberi Kerja, Pemberi Kerja wajib menyetor seluruh iuran kepada Dana Pensiun. (2) Bagi Dana Pensiun Pemberi Kerja, Pemberi Kerja wajib menyetor seluruh iuran Peserta dan iuran Pemberi Kerja sebagaimana dimaksud pada ayat (1) paling lambat tanggal 15 (lima belas) bulan berikutnya. (3) Bagi Dana Pensiun Pemberi Kerja, iuran Peserta dan iuran Pemberi Kerja yang belum disetor setelah melewati 1 (satu) bulan sejak jatuh tempo, dinyatakan: a. sebagai utang Pemberi Kerja yang dapat segera ditagih dan dikenakan imbal hasil tertentu yang dihitung sejak hari pertama dari bulan sebagaimana dimaksud pada ayat (2); dan b. sebagai piutang Dana Pensiun Pemberi Kerja yang memiliki hak utama, apabila Pemberi Kerja dilikuidasi atau dipailitkan. (4) Bagi Dana Pensiun yang menyelenggarakan Program Pensiun berdasarkan Prinsip Syariah, iuran Peserta dan iuran Pemberi Kerja yang belum disetor setelah melewati 1 (satu) bulan sejak jatuh tempo, dinyatakan sebagai utang Pemberi Kerja dan dikenai sanksi (ta'ziry berupa denda yang dihitung sejak hari pertama dari bulan jatuh tempo penyetoran iuran. (5) Dana yang berasal dari …"}, {"l": "UU 4/2023", "p": "154", "b": "Bagian Kedua", "t": "(1) Dana Pensiun harus menjaga kondisi pendanaan agar berada dalam keadaan dana terpenuhi (fully funded). (2) Dana ... jdih.kemenkeu.go.id REPUBUK INDONESIA (2) Dana Pensiun yang menyelenggarakan Program Pensiun Manfaat Pasti dinyatakan dalam keadaan dana terpenuhi sebagaimana dimaksud pada ayat (1) apabila aset yang diperhitungkan untuk mendanai seluruh Manfaat Pensiun tidak kurang dari kewajiban atas pembayaran seluruh Manfaat Pensiun kepada Peserta. (3) Dana Pensiun yang menyelenggarakan Program Pensiun Iuran Pasti dinyatakan dalam keadaan dana terpenuhi sebagaimana dimaksud pada ayat (1) apabila iuran bulanan yangjatuh tempo telah disetorkan. (4) Dalam hal Dana Pensiun Pemberi Kerja dalam keadaan dana tidak terpenuhi, Pemberi Kerja bertanggung jawab agar Dana Pensiun Pemberi Kerja baik secara langsung maupun bertahap mencapai keadaan dana terpenuhi. (5) Ketentuan lebih lanjut mengenai keadaan dana terpenuhi pada Dana Pensiun sebagaimana dimaksud pada ayat (1) sampai dengan ayat (4) diatur dalam Peraturan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "155", "b": "Bagian Kedua", "t": "(1) Peserta berhak atas Manfaat Pensiun Normal, Manfaat Pensiun Disabilitas, Manfaat Pensiun Dipercepat, atau Pensiun Ditunda. (2) Dalam hal Peserta meninggal dunia, baik pada saat sedang mendapatkan Manfaat Pensiun maupun masih aktif bekerja, Manfaat Pensiun dibayarkan kepada Janda/Duda. (3) Dalam hal Janda/Duda sebagaimana dimaksud pada ayat (2) tidak ada, meninggal dunia, atau kawin lagi, Manfaat Pensiun dibayarkan kepada anak. (4) Dalam hal anak sebagaimana dimaksud pada ayat (3) tidak ada, Manfaat Pensiun dibayarkan kepada pihak yang telah ditunjuk oleh Peserta. (5) Ketentuan lebih lanjut mengenai tata cara pembayaran Manfaat Pensiun Normal, Manfaat Pensiun Disabilitas, Manfaat Pensiun Dipercepat, dan Pensiun Ditunda kepada Janda/Duda, anak, atau pihak yang ditunjuk sebagaimana dimaksud pada ayat (1) sampai dengan ayat (4) diatur dalam Peraturan Otoritas Jasa Keuangan. Pasal 156 ... jdih.kemenkeu.go.id REPUBUK INDONESIA"}, {"l": "UU 4/2023", "p": "156", "b": "Bagian Kedua", "t": "(1) Hak terhadap setiap Manfaat Pensiun yang dibayarkan oleh Dana Pensiun dilarang untuk digunakan sebagai jaminan pinjaman, dialihkan, dan/ a tau disita. (2) Penyerahan, pembebanan, pengikatan, pembayaran Manfaat Pensiun sebelum jatuh tempo, atau tindakan menjaminkan Manfaat Pensiun yang diperoleh dari Dana Pensiun akibat dilakukannya larangan sebagaimana dimaksud pada ayat (1) dinyatakan batal demi hukum. (3) Pembayaran Manfaat Pensiun kepada Peserta atau Pihak yang Berhak yang dilakukan oleh Dana Pensiun membebaskan Dana Pensiun dari tanggung jawab atas pembayaran Manfaat Pensiun dimaksud. (4) Pembayaran sebagaimana dimaksud pada ayat (3) berdasarkan pada iktikad baik dan sesuai dengan ketentuan peraturan perundang-undangan."}, {"l": "UU 4/2023", "p": "157", "b": "Bagian Kedua", "t": "(1) Besamya hak atas Manfaat Pensiun bagi Peserta Program Pensiun Manfaat Pasti dihitung berdasarkan rumus yang ditetapkan dalam Peraturan Dana Pensiun. (2) Besarnya hak atas Manfaat Pensiun bagi Peserta Program Pensiun Iuran Pasti merupakan himpunan: a. iuran Peserta dan/atau iuran Pemberi Kerja; b. dana awal Pemberi Kerja; c. pengalihan dana dari Dana Pensiun lain; dan d. hasil pengembangan dari himpunan iuran Peserta dan/ atau iuran Pemberi Kerja sebagaimana dimaksud dalam huruf a, dana awal Pemberi Kerja sebagaimana dimaksud dalam huruf b, dan pengalihan dana dari Dana Pensiun lain sebagaimana dimaksud dalam huruf c terhitung sejak tanggal kepesertaan pada Dana Pensiun. (3) Ketentuan lebih lanjut mengenai besaran hak atas Manfaat Pensiun bagi Peserta Program Pensiun Manfaat Pasti sebagaimana dimaksud pada ayat (1) dan Manfaat Pensiun bagi Peserta Program Pensiun Iuran Pasti sebagaimana dimaksud pada ayat (2) diatur dalam Peraturan Otoritas Jasa Keuangan. Pasal 158 ... jdih.kemenkeu.go.id REPUBUK INDONESIA"}, {"l": "UU 4/2023", "p": "158", "b": "Bagian Kedua", "t": "(1) Peserta yang berhenti bekerja pada Usia Pensiun Normal atau setelahnya berhak atas Manfaat Pensiun Normal. (2) Peserta yang berhenti bekerja paling cepat 5 (lima) tahun sebelum Usia Pensiun Normal berhak atas Manfaat Pensiun Dipercepat. (3) Peserta yang berhenti bekerja dan memiliki masa kepesertaan kurang dari 3 (tiga) tahun berhak atas himpunan iuran Peserta yang bersangkutan ditambah hasil pengembangannya. (4) Nilai hasil pengembangan sebagaimana dimaksud pada ayat (3) bagi Peserta yang mengikuti Program Pensiun Manfaat Pasti setiap tahunnya wajib paling sedikit sebesar imbal hasil deposito bank umum milik pemerintah dengan jangka waktu 1 (satu) tahun. (5) Peserta yang mengikuti Program Pensiun Manfaat Pasti apabila berhenti bekerja setelah memiliki masa kepesertaan paling singkat 3 (tiga) tahun, tetapi belum berhak atas Manfaat Pensiun Dipercepat sebagaimana dimaksud pada ayat (2), berhak atas Pensiun Ditunda yang besamya sama dengan jumlah yang dihitung berdasarkan rumus Manfaat Pensiun bagi kepesertaannya sampai pada saat berhenti bekerja. (6) Peserta yang mengikuti Program Pensiun luran Pasti apabila berhenti bekerja setelah memiliki masa kepesertaan paling singkat 3 …"}, {"l": "UU 4/2023", "p": "159", "b": "Bagian Kedua", "t": "Dalam hal terdapat pengalihan dana awal Pemberi Kerja atau pengalihan dana dari Dana Pensiun lain kepada Dana Pensiun Lembaga Keuangan, ketentuan sebagaimana dimaksud dalam Pasal 158 ayat (3) tidak berlaku dan hak Peserta diperhitungkan berdasarkan ketentuan dalam Pasal 157 ayat (2). Pasal 160 ... jdih.kemenkeu.go.id REPUBUK INDONESIA"}, {"l": "UU 4/2023", "p": "160", "b": "Bagian Kedua", "t": "(1) Peserta mandiri sebagaimana dimaksud dalam Pasal 145 ayat (4) huruf a dapat mengalihkan haknya sebagaimana dimaksud dalam Pasal 157 ayat (2) huruf c kepada Dana Pensiun Lembaga Keuangan lainnya atau Dana Pensiun Pemberi Kerja. (2) Dalam hal Peserta berhak atas Pensiun Ditunda sebagaimana dimaksud dalam Pasal 158 ayat (5) dan ayat (6), hak atas Pensiun Ditunda dapat dibayarkan oleh Dana Pensiun Lembaga Keuangan dan/atau Dana Pensiun Pemberi Kerja yang bersangkutan atau dapat dialihkan kepada Dana Pensiun Lembaga Keuangan lainnya dan/ atau Dana Pensiun Pemberi Kerja lainnya, dengan ketentuan yang bersangkutan masih hidup dalam waktu 30 (tiga puluh) hari setelah berhenti bekerja. (3) Pemberi Kerja yang menanggung sebagian atau seluruh iuran Program Pensiun bagi karyawannya dapat mengalihkan kepesertaan. karyawannya kepada Dana Pensiun Lembaga Keuangan lain atau Dana Pensiun Pemberi Kerja lain. (4) Dalam hal Peserta turut menanggung sebagian iuran Program Pensiun, pengalihan kepesertaan sebagaimana dimaksud pada ayat (3) wajib dilakukan dengan terlebih dahulu memperhatikan pendapat dari Peserta. (5) Ketentuan lebih lanjut mengenai pengalihan hak dan kepesertaan sebagaimana …"}, {"l": "UU 4/2023", "p": "161", "b": "Bagian Kedua", "t": "(1) Dana Pensiun dilarang melakukan pembayaran apa pun, kecuali pembayaran yang ditetapkan dalam Peraturan Dana Pensiun. (2) Pembayaran Manfaat Pensiun bagi Peserta, Janda/Duda, atau anak harus dilakukan secara berkala."}, {"l": "UU 4/2023", "p": "162", "b": "Bagian Kedua", "t": "(1) Dana Pensiun dilarang melakukan pembayaran Manfaat Pensiun kepada Peserta yang belum mencapai usia paling rendah 5 (lima) tahun sebelum Usia Pensiun Normal kecuali untuk: a. pembayaran ... jdih.kemenkeu.go.id REPUBUK INDONESIA a. pembayaran Manfaat Pensiun kepada Janda/Duda atau anak; b. pembayaran Manfaat Pensiun Disabilitas; c. kondisi mendesak tertentu yang ditetapkan oleh Otoritas Jasa Keuangan; dan d. kondisi tertentu bagi Peserta yang bukan pekerja penerima upah pada badan usaha. (2) Dana Pensiun yang menyelenggarakan Program Pensiun Manfaat Pasti, Manfaat Pensiun bagi Peserta atau bagi Janda/Duda harus dibayarkan secara berkala dengan nilai tetap atau meningkat yang pembayarannya dilakukan untuk seumur hidup. (3) Dana Pensiun yang menyelenggarakan Program Pensiun Manfaat Pasti, Manfaat Pensiun bagi anak dibayarkan secara berkala sampai dengan anak mencapai batas usia tertentu. (4) Dana Pensiun yang menyelenggarakan Program Pensiun Iuran Pasti, Manfaat Pensiun bagi Peserta, Janda/Duda, atau anak dibayarkan secara berkala untuk periode tertentu. (5) Ketentuan lebih lanjut mengenai pembayaran Manfaat Pensiun sebagaimana dimaksud pada ayat (1) sampai dengan ayat (4) diatur …"}, {"l": "UU 4/2023", "p": "163", "b": "Bagian Kedua", "t": "(1) Pembayaran Manfaat Pensiun secara berkala sebagaimana dimaksud dalam Pasal 161 ayat (2) dapat dilakukan dengan cara: a. dibayarkan oleh Dana Pensiun; atau b. Peserta, Janda/Duda, atau anak memilih untuk membeli anuitas atau anuitas syariah dari perusahaan asuransi jiwa atau perusahaan asuransi jiwa syariah. (2) Tata cara pembayaran Manfaat Pensiun bagi Peserta atau Pihak yang Berhak sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Dana Pensiun. (3) Ketentuan ... jdih.kemenkeu.go.id . REPUBUK INDONESIA (3) Ketentuan lebih lanjut mengenai cakupan pengaturan terkait tata cara pembayaran Manfaat Pensiun dalam Peraturan Dana Pensiun sebagaimana dimaksud pada ayat (1) dan ayat (2) diatur dalam Peraturan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "164", "b": "Bagian Kedua", "t": "(1) Manfaat Pensiun bagi Peserta atau Pihak yang Berhak dapat dibayarkan secara sekaligus dengan ketentuan: a. Peserta meninggal dunia lebih dari 5 (lima) tahun sebelum mencapai Usia Pensiun Normal; b. besarnya Manfaat Pensiun lebih kecil dari suatu jumlah tertentu yang ditetapkan oleh Otoritas Jasa Keuangan; c. pembayaran Manfaat Pensiun kepada pihak yang ditunjuk sebagaimana dimaksud dalam Pasal 155 ayat (4); dan/ atau d. adanya kondisi tertentu yang ditetapkan oleh Otoritas Jasa Keuangan. (2) Peraturan Dana Pensiun dapat memuat ketentuan yang mengatur pilihan pembayaran Manfaat Pensiun pertama kali secara sekaligus paling banyak 20% (dua puluh persen) dari Manfaat Pensiun. (3) Ketentuan lebih lanjut mengenai tata cara pembayaran Manfaat Pensiun secara sekaligus sebagaimana dimaksud pada ayat (1) dan ayat (2) diatur dalam Peraturan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "165", "b": "Bagian Kedua", "t": "Peserta tidak dapat mengundurkan diri atau menuntut haknya dari Dana Pensiun dalam hal masih memenuhi syarat kepesertaan sebagaimana diatur dalam Peraturan Dana Pensiun."}, {"l": "UU 4/2023", "p": "166", "b": "Bagian Kedua", "t": "(1) Dana Pensiun wajib melakukan pencatatan tersendiri atas dana yang dikategorikan sebagai dana tidak aktif. (2) Sampai ... jdih.kemenkeu.go.id R£PUBUK INDONESIA (2) Sampai dengan jangka waktu tertentu, dana tidak aktif sebagaimana dimaksud pada ayat (1) dialihkan kepada balai harta peninggalan. (3) Dalam jangka waktu tertentu setelah dialihkan kepada balai harta peninggalan, dana tidak aktif sebagaimana dimaksud pada ayat (2) dialihkan kepada Negara. (4) Ketentuan lebih lanjut mengenai pencatatan tersendiri dana tidak aktif sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Otoritas Jasa Keuangan. (5) Ketentuan lebih lanjut mengenai tata cara pengalihan dana tidak aktif dan jangka waktu tertentu sebagaimana dimaksud pada ayat (2) dan ayat (3) diatur dalam Peraturan Pemerintah. Paragraf 7 Aset Dana Pensiun dan Pengelolaannya"}, {"l": "UU 4/2023", "p": "167", "b": "Bagian Kedua", "t": "(1) Aset Dana Pensiun dihimpun dari: a. iuran Pemberi Kerja; b. iuran Peserta; c. hasil pengelolaan aset; d. pengalihan aset dari Dana Pensiun lain; dan/atau e. pengalihan dana awal Pemberi Kerja. (2) Aset Dana Pensiun sebagaimana dimaksud pada ayat (1) harus dikecualikan dari setiap tuntutan hukum atas aset Pendiri."}, {"l": "UU 4/2023", "p": "168", "b": "Bagian Kedua", "t": "(1) Pengurus Dana Pensiun wajib melakukan pengelolaan aset Dana Pensiun sesuai dengan ketentuan mengenai investasi yang diatur oleh Otoritas Jasa Keuangan. (2) Dengan persetujuan Pendiri dan Dewan Pengawas, pengelolaan aset Dana Pensiun Pemberi Kerja sebagaimana dimaksud pada ayat (1) dapat dialihkan oleh Pengurus Dana Pensiun Pemberi Kerja kepada lembaga keuangan yang memenuhi ketentuan yang diatur oleh Otoritas Jasa Keuangan. (3) Bagi ... jdih.kemenkeu.go.id REPUBUK INDONESIA (3) Bagi Dana Pensiun yang menyelenggarakan Program Pensiun berdasarkan Prinsip Syariah, pengalihan pengelolaan aset sebagaimana dimaksud pada ayat (2) harus mendapat persetujuan Dewan Pengawas Syariah. (4) Dalam hal pengelolaan aset Dana Pensiun Pemberi Kerja dialihkan kepada lembaga keuangan sebagaimana dimaksud pada ayat (2) dan ayat (3), Pengurus Dana Pensiun Pemberi Kerja wajib bertanggung jawab atas kepatuhan lembaga keuangan terhadap ketentuan mengenai pengelolaan aset dalam Undang-Undang ini dan peraturan pelaksanaannya. (5) Otoritas Jasa Keuangan dapat mewajibkan Dana Pensiun menyimpan dan/ atau menatausahakan sebagian atau seluruh aset Dana Pensiun pada Bank Kustodian. (6) Aset Dana Pensiun yang …"}, {"l": "UU 4/2023", "p": "169", "b": "Bagian Kedua", "t": "(1) Dana Pensiun Pemberi Kerja dilarang mengembalikan asetnya kepada Pemberi Kerja. (2) Dana Pensiun dilarang: a. meminjamkan atau mengagunkan asetnya kepada pihak manapun, kecuali yang dikategorikan sebagai pengelolaan portofolio investasi; b. menginvestasikan asetnya, baik secara langsung maupun tidak langsung, pada surat berharga yang diterbitkan, atau pada tanah dan/ atau bangunan yang dimiliki atau yang dipergunakan oleh: 1. Pengurus, Pendiri, Mitra Pendiri, pengendali Pendiri, atau Bank Kustodian; 2. badan usaha yang lebih dari 25% (dua puluh lima persen) sahamnya dimiliki oleh orang atau badan yang terdiri dari Pendiri, Mitra Pendiri, pengendali Pendiri, Pengurus, Bank Kustodian, atau serikat pekerja yang anggotanya adalah Peserta Dana Pensiun yang bersangkutan; 3. perusahaan ... jdih.kemenkeu.go.id REPUBUK INDONESIA 3. perusahaan anak; dan/atau 4. pejabat eksekutif dari badan sebagaimana dimaksud pada angka 1 dan angka 2, serta keluarganya sampai derajat kedua menurut garis lurus maupun garis ke samping, termasuk menantu dan ipar; c. melakukan transaksi derivatif kecuali transaksi derivatif dalam rangka lindung nilai yang diatur oleh Otoritas Jasa Keuangan; atau d. …"}, {"l": "UU 4/2023", "p": "170", "b": "Bagian Kedua", "t": "(1) Penyewaan atau jual beli tanah, bangunan, a tau harta tetap lainnya milik Dana Pensiun kepada pihak sebagaimana dimaksud dalam Pasal 169 ayat (2) huruf b, hanya dapat dilakukan sepanjang menggunakan harga pasar wajar. (2) Harga pasar wajar atas: a. jual beli; dan b. penyewaan dengan nilai tertentu, untuk ... jdih.kemenkeu.go.id untuk tanah, bangunan, atau harta tetap lainnya milik Dana Pensiun sebagaimana dimaksud pada ayat (1) ditetapkan oleh penilai independen. (3) Ketentuan sebagaimana dimaksud dalam Pasal 169 ayat (2) huruf b tidak berlaku bagi investasi Dana Pensiun pada instrumen keuangan yang tercatat atau diperdagangkan di Pasar Modal dan Pasar Uang, dengan memenuhi ketentuan perundang-undangan mengenai arahan investasi atau pengelolaan aset Dana Pensiun. (4) Ketentuan lebih lanjut mengenai penerapan harga pasar wajar dalam aktivitas penyewaan tanah, bangunan, atau harta tetap lainnya oleh Dana Pensiun sebagaimana dimaksud pada ayat (2) huruf b dan pengecualian investasi sebagaimana dimaksud pada ayat (3) diatur dalam Peraturan Otoritas Jasa Keuangan. Paragraf 8 Perlakuan/Insentif Perpajakan"}, {"l": "UU 4/2023", "p": "171", "b": "Bagian Kedua", "t": "Penyelenggaraan Program Pensiun dan manfaat lain oleh Dana Pensiun dapat diberikan perlakuan/insentif perpajakan sesuai dengan ketentuan peraturan perundang-undangan di bidang perpajakan. Paragraf 9 Pengaturan, Pengawasan, dan Pelaporan Dana Pensiun"}, {"l": "UU 4/2023", "p": "172", "b": "Bagian Kedua", "t": "(1) Pengaturan dan pengawasan atas Dana Pensiun dilakukan oleh Otoritas Jasa Keuangan. (2) Pengaturan dan pengawasan sebagaimana dimaksud pada ayat (1) meliputi penyelenggaraan Program Pensiun, termasuk penyelenggaraan atas manfaat lain sebagaimana dimaksud dalam Pasal 138 ayat (4), dan pengelolaan aset Dana Pensiun. (3) Ketentuan lebih lanjut mengenai cakupan pengaturan dan pengawasan oleh Otoritas Jasa Keuangan sebagaimana dimaksud pada ayat (1) dan ayat (2) diatur dalam Peraturan Otoritas Jasa Keuangan. Pasal 173 ... jdih.kemenkeu.go.id REPUBUK INDONESIA"}, {"l": "UU 4/2023", "p": "173", "b": "Bagian Kedua", "t": "(1) Dalam rangka pelaksanaan fungsi pengaturan sebagaimana dimaksud dalam Pasal 172 ayat (1), Otoritas Jasa Keuangan menetapkan Peraturan Otoritas Jasa Keuangan. (2) Dalam rangka pelaksanaan fungsi pengawasan sebagaimana dimaksud dalam Pasal 172 ayat (1), Otoritas Jasa Keuangan berwenang: a. menyetujui atau menolak pengesahan pembentukan Dana Pensiun; b. menyetujui atau menolak pengesahan perubahan atas Peraturan Dana Pensiun; c. membubarkan Dana Pensiun; d. mewajibkan Dana Pensiun menyampaikan laporan secara berkala; e. melakukan pemeriksaan terhadap Dana Pensiun dan pihak lain yang sedang atau pernah menjadi pihak terafiliasi atau memberikan jasa kepada Dana Pensiun; f. melakukan penilaian kemampuan dan kepatutan terhadap anggota Pengurus, anggota Dewan Pengawas, dan anggota Dewan Pengawas Syariah; g. menonaktifkan anggota Pengurus, anggota Dewan Pengawas, anggota Dewan Pengawas Syariah, dan menetapkan pengelola statuter; h. memberi perintah tertulis kepada: 1. pihak tertentu untuk membuat laporan mengenai hal tertentu, atas biaya Dana Pensiun dan disampaikan kepada Otoritas Jasa Keuangan; 2. Dana Pensiun dan/ atau pihak tertentu untuk melakukan atau tidak melakukan hal tertentu …"}, {"l": "UU 4/2023", "p": "174", "b": "Bagian Kedua", "t": "(1) Pemeriksaan sebagaimana dimaksud dalam Pasal 173 ayat (2) huruf e dilakukan secara berkala dan/atau sewaktu-waktu. (2) Setiap Pendiri, Mitra Pendiri, Pengurus, Dewan Pengawas, Dewan Pengawas Syariah, dan lembaga atau profesi penunjang Dana Pensiun, serta pihak lain terkait dengan kegiatan Dana Pensiun wajib memberikan keterangan dan/ a tau data, kesempatan untuk melihat semua pembukuan, catatan, dokumen, dan sarana fisik yang berkaitan dengan kegiatan Dana Pensiun yang diperlukan dalam rangka pemeriksaan sebagaimana dimaksud pada ayat (1). (3) Setiap Orang yang pernah menjadi Pengurus, Dewan Pengawas, Dewan Pengawas Syariah, dan lembaga atau profesi penunjang Dana Pensiun, serta pihak lain terkait dengan kegiatan Dana Pensiun, wajib memberikan keterangan dan/atau data, kesempatan untuk melihat semua pembukuan, catatan, dokumen, dan sarana fisik yang berkaitan dengan kegiatan Dana Pensiun yang diperlukan dalam rangka pemeriksaan sebagaimana dimaksud pada ayat (1). Pasal 175 ... jdih.kemenkeu.go.id REPUBUK INDONESIA"}, {"l": "UU 4/2023", "p": "175", "b": "Bagian Kedua", "t": "Setiap Orang dilarang: a. membuat atau menyebabkan adanya laporan, informasi, data atau dokumen Dana Pensiun yang tidak benar, palsu, atau menyesatkan; b. menghilangkan, tidak memasukkan atau menyebabkan dihapuskannya suatu informasi atau data dalam buku catatan, laporan, atau dokumen Dana Pensiun; dan c. mengubah, mengaburkan, menyembunyikan, menghapus atau menghilangkan suatu informasi atau data dalam buku catatan, laporan, atau dokumen Dana Pensiun."}, {"l": "UU 4/2023", "p": "176", "b": "Bagian Kedua", "t": "(1) Perintah tertulis sebagaimana dimaksud dalam Pasal 173 ayat (2) huruf h diberikan dalam hal Otoritas Jasa Keuangan berkesimpulan bahwa Dana Pensiun: a. menjalankan kegiatan usahanya dengan cara tidak hati-hati dan tidak wajar, atau tidak sehat secara finansial; b. diperkirakan akan gagal memenuhi kewajibannya; c. melanggar ketentuan peraturan perundang- undangan di bidang Dana Pensiun; dan/ atau d. terlibat kejahatan keuangan. (2) Dana Pensiun dan/ a tau pihak tertentu wajib mematuhi perintah tertulis sebagaimana dimaksud pada ayat (1). (3) Perintah tertulis sebagaimana dimaksud pada ayat (1) tidak dapat dijadikan alasan oleh pihak yang melakukan perjanjian dengan Dana Pensiun untuk membatalkan atau menolak perjanjian, menghindari kewajiban yang ditentukan di dalam perjanjian, atau melakukan hal yang dapat mengakibatkan kerugian bagi Dana Pensiun. (4) Pihak sebagaimana dimaksud pada ayat (3) berhak mendapatkan ganti kerugian dari Dana Pensiun dalam hal menderita kerugian yang disebabkan oleh perintah tertulis yang diberikan kepada Dana Pensiun. (5) Ketentuan ... jdih.kemenkeu.go.id REPUBUK INDONESIA (5) Ketentuan ganti kerugian sebagaimana dimaksud pada ayat (4) tidak berlaku …"}, {"l": "UU 4/2023", "p": "177", "b": "Bagian Kedua", "t": "(1) Otoritas Jasa Keuangan dapat menonaktifkan anggota Pengurus, anggota Dewan Pengawas, dan/ a tau anggota Dewan Pengawas Syariah, dalam hal: a. berdasarkan informasi dari Dana Pensiun, diperkirakan Dana Pensiun tidak mampu memenuhi kewajiban; b. menurut pertimbangan Otoritas Jasa Keuangan, Dana Pensiun diperkirakan tidak mampu memenuhi kewajiban; c. menurut pertimbangan Otoritas Jasa Keuangan, Dana Pensiun secara keuangan dinilai tidak sehat; d. menurut pertimbangan Otoritas Jasa Keuangan, Dana Pensiun dimanfaatkan untuk memfasilitasi dan/ a tau melakukan tindakan kejahatan keuangan; atau e. menurut pertimbangan Otoritas Jasa Keuangan, Dana Pensiun melakukan kegiatan usaha yang tidak sesuai dengan ketentuan peraturan perundang­ undangan di bidang Dana Pensiun. (2) Pengelola statuter yang telah ditetapkan oleh Otoritas Jasa Keuangan sebagaimana dimaksud dalam Pasal 173 ayat (2) huruf g mempunyai tugas: a. menyelamatkan aset Dana Pensiun; b. mengendalikan dan mengelola kegiatan usaha dari Dana Pensiun sesuai dengan Undang-Undang ini; c. menyusun langkah-langkah apabila Dana Pensiun tersebut masih dapat diselamatkan; d. mengajukan usulan agar Otoritas Jasa Keuangan membubarkan Dana …"}, {"l": "UU 4/2023", "p": "178", "b": "Bagian Kedua", "t": "(1) Pengelola statuter dalam melaksanakan tugasnya wajib mematuhi ketentuan peraturan perundang-undangan di bidang Dana Pensiun. (2) Pengelola statuter sebagaimana dimaksud pada ayat (1) wajib mematuhi setiap perintah tertulis dari Otoritas Jasa Keuangan mengenai pengendalian dan pengelolaan kegiatan usaha dari Dana Pensiun. (3) Pengelola statuter mengambil alih pengendalian dan pengelolaan Dana Pensiun terhitung sejak tanggal penetapan sebagai pengelola statuter. (4) Pengelola statuter memiliki seluruh wewenang dan fungsi Pengurus, Dewan Pengawas, dan/atau Dewan Pengawas Syariah dari Dana Pensiun. (5) Selain ... jdih.kemenkeu.go.id REPUBUK INDONESIA (5) Selain kewenangan sebagaimana dimaksud pada ayat (4), pengelola statuter juga memiliki kewenangan untuk membatalkan atau mengakhiri perjanjian yang dibuat oleh Dana Pensiun dengan pihak ketiga, yang menurut pengelola statuter dapat merugikan kepentingan Dana Pensiun, Peserta, dan Pihak yang Berhak. (6) Pengelola statuter bertanggung jawab atas kerugian Dana Pensiun dan/atau pihak ketiga jika kerugian disebabkan oleh kecurangan, ketidakjujuran, atau kesengajaannya untuk tidak mematuhi ketentuan peraturan perundang­ undangan di …"}, {"l": "UU 4/2023", "p": "179", "b": "Bagian Kedua", "t": "Dalam menetapkan pengelola statuter, sebagaimana dimaksud dalam Pasal 173 ayat (2) huruf g, Otoritas Jasa Keuangan: a. mempertimbangkan ketersediaan tenaga individu yang akan ditunjuk sebagai pengelola statuter; b. melakukan penunjukan pengelola statuter melalui uji kelayakan dan kepatutan; dan/ a tau c. mempertimbangkan ketentuan peraturan perundang­ undangan."}, {"l": "UU 4/2023", "p": "180", "b": "Bagian Kedua", "t": "Dalam hal terjadi kerugian yang tidak disebabkan oleh kecurangan, ketidakjujuran, atau kesengajaan pengelola statuter untuk tidak mematuhi ketentuan perundang­ undangan di bidang Dana Pensiun sebagaimana dimaksud dalam Pasal 178 ayat (6), Pendiri wajib bertanggung jawab atas hak keuangan Peserta. Pasal 181 ... jdih.kemenkeu.go.id REPUBUK INDONESIA ."}, {"l": "UU 4/2023", "p": "181", "b": "Bagian Kedua", "t": "(1) Dana Pensiun wajib menyampaikan laporan berkala mengenai kegiatannya kepada Otoritas Jasa Keuangan sesuai dengan ketentuan yang diatur oleh Otoritas Jasa Keuangan. (2) Dana Pensiun yang menyelenggarakan Program Pensiun Manfaat Pasti wajib memiliki laporan aktuaris dan menyampaikan kepada Otoritas Jasa Keuangan paling sedikit 1 (satu) kali dalam 3 (tiga) tahun atau sewaktu­ waktu dalam hal dilakukan perubahan terhadap Peraturan Dana Pensiun yang mengakibatkan perubahan dalam pendanaan dan Manfaat Pensiun. (3) Ketentuan lebih lanjut mengenai kewajiban penyampaian laporan berkala dan laporan aktuaris oleh Dana Pensiun sebagaimana dimaksud pada ayat (1) dan ayat (2) diatur dalam Peraturan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "182", "b": "Bagian Kedua", "t": "( 1) Dana Pensiun wajib mengumumkan kondisi keuangan dan perhitungan hasil usaha secara transparan kepada Peserta. (2) Dana Pensiun wajib menyampaikan keterangan kepada Peserta mengenai hal yang timbul terkait kepesertaannya. (3) Keterangan sebagaimana dimaksud pada ayat (2) minimal memuat informasi mengenai jumlah dana yang telah terkumpul dan/ a tau proyeksi besaran manfaat yang akan diterima. (4) Dana Pensiun wajib menyampaikan informasi setiap perubahan Peraturan Dana Pensiun secara transparan kepada Peserta. (5) Ketentuan lebih lanjut mengenai pengumuman kondisi keuangan dan perhitungan hasil usaha sebagaimana dimaksud pada ayat (1), penyampaian keterangan sebagaimana dimaksud pada ayat (2), dan penyampaian informasi sebagaimana dimaksud pada ayat (4) diatur dalam Peraturan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "183", "b": "Bagian Kedua", "t": "(1) Pembubaran Dana Pensiun terjadi dalam hal: a. terdapat . . . jdih.kemenkeu.go.id REPUBUK INDONESIA a. terdapat permintaan Pendiri kepada Otoritas Jasa Keuangan; b. Pendiri bubar; atau c. berdasarkan penilaian Otoritas Jasa Keuangan: 1. Dana Pensiun tidak dapat memenuhi kewajibannya kepada Peserta dan Pihak yang Berhak; 2. terhentinya iuran pada Dana Pensiun yang dapat membahayakan kondisi keuangan Dana Pensiun dimaksud; atau 3. Dana Pensiun tidak beroperasi dalam jangka waktu 1 (satu) tahun sejak didirikan. (2) Dalam rangka pembubaran Dana Pensiun, Otoritas Jasa Keuangan menetapkan: a. pembubaran Dana Pensiun; dan b. likuidator yang diajukan oleh Pendiri atau yang diajukan oleh likuidator Pendiri. (3) Dalam hal pembubaran Dana Pensiun terjadi karena kondisi sebagaimana dimaksud pada ayat (1) huruf c, Otoritas Jasa Keuangan menunjuk dan menetapkan likuidator. (4) Pengurus, likuidator Pendiri, dan/ atau pihak lain dapat ditunjuk sebagai likuidator. (5) Dewan Pengawas tidak dapat ditunjuk sebagai likuidator. (6) Biaya yang timbul dalam rangka pembubaran Dana Pensiun dibebankan pada Dana Pensiun, Pendiri, dan/ atau Mitra Pendiri. (7) Ketentuan lebih lanjut mengenai pembubaran Dana …"}, {"l": "UU 4/2023", "p": "184", "b": "Bagian Kedua", "t": "(1) Sebelum proses likuidasi Dana Pensiun selesai, Pemberi Kerja tetap bertanggung jawab atas iuran yang terutang sampai pada saat Dana Pensiun dibubarkan sesuai dengan ketentuan mengenai pendanaan yang diatur oleh Otoritas Jasa Keuangan. (2) Dalam ... jdih.kemenkeu.go.id . REPUBUK INDONESIA . (2) Dalam hal iuran yang terutang sebagaimana dimaksud pada ayat (1) tidak dapat dilunasi oleh Pemberi Kerja kepada Dana Pensiun sampai dengan jangka waktu tertentu, iuran yang terutang dimaksud dialihkan hak tagihnya dari hak tagih Dana Pensiun menjadi hak tagih Peserta kepada Pemberi Kerja. (3) Pada saat proses likuidasi, Dana Pensiun dilarang mengembalikan aset Dana Pensiun kepada Pemberi Kerja. (4) Setiap kelebihan kekayaan atas kewajiban pada saat pembubaran harus dipergunakan untuk meningkatkan Manfaat Pensiun bagi Peserta sampai jumlah maksimum yang ditetapkan oleh Otoritas Jasa Keuangan. (5) Dalam hal masih terdapat kelebihan dana sesudah peningkatan manfaat sampai jumlah maksimum sebagaimana dimaksud pada ayat (4), sisa dana tersebut harus dibagikan kepada Peserta dan Pihak yang Berhak atas Manfaat Pensiun. (6) Dalam pembagian aset Dana Pensiun yang dilikuidasi, hak Peserta dan/ a …"}, {"l": "UU 4/2023", "p": "185", "b": "Bagian Kedua", "t": "(1) Likuidator wajib melaporkan pelaksanaan dan penyelesaian likuidasi Dana Pensiun kepada Otoritas Jasa Keuangan. (2) Likuidator wajib mengumumkan hasil penyelesaian likuidasi Dana Pensiun yang telah disetujui oleh Otoritas Jasa Keuangan dalam Berita Negara Republik Indonesia. (3) Status ... jdih.kemenkeu.go.id . REPUBUK INDONESIA (3) Status badan hukum Dana Pensiun berakhir terhitung sejak tanggal pengumuman hasil penyelesaian likuidasi sebagaimana dimaksud pada ayat (2). (4) Ketentuan lebih lanjut mengenai pelaporan pelaksanaan dan penyelesaian likuidasi sebagaimana dimaksud pada ayat (1) dan pengumuman hasil penyelesaian likuidasi sebagaimana dimaksud pada ayat (2) diatur dalam Peraturan Otoritas Jasa Keuangan. Paragraf 10 Asosiasi Dana Pensiun"}, {"l": "UU 4/2023", "p": "186", "b": "Bagian Kedua", "t": "(1) Setiap Dana Pensiun wajib menjadi anggota salah satu asosiasi Dana Pensiun yang sesuai dengan ruang lingkup usahanya. (2) Asosiasi Dana Pensiun sebagaimana dimaksud pada ayat (1) harus mendapat persetujuan tertulis dari Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "187", "b": "Bagian Ketiga", "t": "Dalam rangka peningkatan perlindungan hari tua, serta pengembangan dan penguatan sektor keuangan melalui penataan sistem jaminan sosial nasional, Undang-Undang ini mengubah, menghapus, dan/ a tau menetapkan pengaturan baru beberapa ketentuan yang diatur dalam Undang-Undang Nomor 40 Tahun 2004 tentang Sistem Jaminan Sosial Nasional (Lembaran Negara Republik Indonesia Tahun 2004 Nomor 150, sebagaimana telah diubah dengan Peraturan Pemerintah Pengganti Undang-Undang Nomor 2 Tahun 2022 tentang Cipta Kerja (Lembaran Negara Republik Indonesia Tahun 2022 Nomor 238, Tambahan Lembaran Negara Republik Indonesia Nomor 6841). Pasal 188 ... jdih.kemenkeu.go.id REPUBUK INDONESIA"}, {"l": "UU 4/2023", "p": "188", "b": "Bagian Ketiga", "t": "Beberapa ketentuan dalam Undang-Undang Nomor 40 Tahun 2004 tentang Sistem Jaminan Sosial Nasional (Lembaran Negara Republik Indonesia Tahun 2004 Nomor 150, sebagaimana telah diubah dengan Peraturan Pemerintah Pengganti Undang-Undang Nomor 2 Tahun 2022 tentang Cipta Kerja (Lembaran Negara Republik Indonesia Tahun 2022 Nomor 238, Tambahan Lembaran Negara Republik Indonesia Nomor 6841) diubah sebagai berikut: 1. Ketentuan Pasal 36 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "189", "b": "Bagian Keempat", "t": "(1) Pemerintah mengharmonisasikan seluruh Program Pensiun sebagai upaya peningkatan perlindungan hari tua dan memajukan kesejahteraan umum. (2) Harmonisasi sebagaimana dimaksud pada ayat (1) termasuk pengaturan Program Pensiun yang bersifat wajib. (3) Program Pensiun yang bersifat wajib sebagaimana dimaksud pada ayat (2) mencakup program jaminan hari tua dan program jaminan pensiun yang merupakan bagian dari sistem jaminan sosial nasional. (4) Selain program jaminan hari tua dan jaminan pensiun sebagaimana dimaksud pada ayat (3), Pemerintah dapat melaksanakan Program Pensiun tambahan yang bersifat wajib yang diselenggarakan secara kompetitif bagi pekerja dengan penghasilan tertentu dalam rangka mengharmonisasikan seluruh Program Pensiun sebagai upaya peningkatan perlindungan hari tua dan memajukan kesejahteraan umum sebagaimana dimaksud pada ayat (1). (5) Dalam rangka harmonisasi Program Pensiun sebagaimana dimaksud pada ayat (1), dilakukan koordinasi antara kementerian/lembaga dan otoritas terkait. (6) Ketentuan ... jdih.kemenkeu.go.id (6) Ketentuan lebih lanjut mengenai harmonisasi seluruh Program Pensiun sebagaimana dimaksud pada ayat (1) sampai dengan ayat (5) diatur dalam …"}, {"l": "UU 4/2023", "p": "190", "b": "Bagian Keempat", "t": "(1) Pengelola Program Pensiun merupakan profesional yang wajib memiliki kompetensi dan pengalaman yang memadai. (2) Aset dan liabilitas Program Pensiun wajib dikelola dengan menerapkan prinsip tata kelola yang baik dengan minimal menerapkan prinsip transparansi, akuntabilitas, pertanggungjawaban, independensi, dan kewajaran. (3) Pengelolaan aset dan liabilitas Program Pensiun bertujuan untuk memberikan manfaat yang optimal bagi pemangku kepentingan khususnya Peserta dan/ atau Pihak yang Berhak memperoleh Manfaat Pensiun. (4) Setiap keputusan dan tindakan terkait pengembangan aset yang dilakukan oleh pengelola Program Pensiun wajib didasarkan pada analisis pengembangan aset yang objektif, independen, dan rasional. (5) Analisis pengembangan aset sebagaimana dimaksud pada ayat (4) wajib didokumentasikan dan tertuang dalam kertas kerja analisis yang memadai. (6) Pengelola Program Pensiun yang menyelenggarakan Program Pensiun luran Pasti wajib memberikan penjelasan kepada Peserta dan/ a tau Pemberi Kerja mengenai pilihan alokasi aset secara lengkap dan transparan. (7) Peserta dan/ atau Pemberi Kerja berhak menentukan pilihan alokasi aset pada Program Pensiun Iuran Pasti sebagaimana …"}, {"l": "UU 4/2023", "p": "191", "b": "Bagian Keempat", "t": "(1) Untuk memberikan kemungkinan imbal hasil yang lebih optimal dan mencegah kerugian yang lebih besar, anggota direksi atau yang setara pada pengelola Program Pensiun yang terkait dengan keuangan negara dapat melakukan cut loss atas aset yang dikelola dengan ketentuan: a. penurunan nilai atau kerugian atas aset investasi yang dilakukan cut loss bukan karena kesalahan atau kelalaian anggota direksi atau yang setara pada pengelola Program Pensiun yang melakukan cut loss; b. telah melakukan analisis yang memadai yang dibuktikan dengan kertas kerja analisis dengan hasil menunjukkan terdapat potensi imbal hasil yang lebih optimal jika cut loss dilakukan; dan c. tidak mempunyai benturan kepentingan baik langsung maupun tidak langsung dalam melakukan tindakan cut loss. (2) Kerugian atas aset investasi yang dilakukan cut loss sebagaimana dimaksud pada ayat (1) bukan merupakan kerugian negara atau kerugian lainnya sesuai dengan ketentuan peraturan perundang-undangan. (3) Tindakan cut loss yang dilakukan oleh pengelola Program Pensiun sebagaimana dimaksud pada ayat (1) tidak dapat dipermasalahkan secara hukum. (4) Dalam hal terdapat penurunan nilai aset yang dikelola, anggota direksi atau …"}, {"l": "UU 4/2023", "p": "192", "b": "Bagian Keempat", "t": "(1) Otoritas Jasa Keuangan dan kementerian yang menyelenggarakan urusan pemerintahan di bidang keuangan membentuk unit aktuaria yang mendukung tugas dan fungsi yang memerlukan analisis aktuaria paling lambat 3 (tiga) tahun terhitung sejak Undang- Undang ini diundangkan. (2) Unit aktuaria sebagaimana dimaksud pada ayat (1) mempunyai fungsi untuk melakukan analisis aktuaria minimal mengenai: a. demografi; b. ekonomi; C. keuangan; d. investasi; dan e. pemodelan. (3) Pembentukan unit aktuaria sebagaimana dimaksud pada ayat (1) pada: a. Otoritas Jasa Keuangan ditetapkan oleh Dewan Komisioner Otoritas Jasa Keuangan; dan b. kementerian ... jdih.kemenkeu.go.id REPUBUK INDONESIA b. kementerian yang menyelenggarakan urusan pemerintahan di bidang keuangan ditetapkan oleh"}, {"l": "UU 4/2023", "p": "193", "b": "Bagian Kelima", "t": "(1) Otoritas Jasa Keuangan berwenang mengenakan sanksi administratif kepada Setiap Orang yang melanggar ketentuan sebagaimana dimaksud dalam Pasal 138 ayat (6) huruf a dan huruf b, Pasal 139 ayat (6), Pasal 142 ayat (5), Pasal 143 ayat (1), ayat (2), dan ayat (3), Pasal 144 ayat (3), ayat (5), dan ayat (7), Pasal 147 ayat (1), Pasal 149 ayat (1), ayat (2), dan ayat (3), Pasal 150 ayat (1), ayat (2), ayat (4), dan ayat (5), Pasal 153 ayat (1), ayat (2), dan ayat (5), Pasal 158 ayat (4), Pasal 160 ayat (4), Pasal 166 ayat (1), Pasal 168 ayat (1) dan ayat (4), Pasal 169 ayat (1), ayat (2) huruf c dan huruf d, ayat (3), dan ayat (4), Pasal 174 ayat (2) dan ayat (3), Pasal 176 ayat (2), Pasal 177 ayat (3) huruf b dan ayat (4), Pasal 178 ayat (1), ayat (2), dan ayat (8), Pasal 180, Pasal 181 ayat (1) dan ayat (2), Pasal 182 ayat (1), ayat (2), dan ayat (4), Pasal 184 ayat (3), ayat (7), dan ayat (8), Pasal 185 ayat (1) dan ayat (2), Pasal 186 ayat (1), serta Pasal 190 ayat (1), ayat (2), ayat (4), ayat (5), ayat (6), dan ayat (8). (2) Sanksi administratif sebagaimana dimaksud pada ayat (1) berupa: a. peringatan tertulis; b. larangan untuk menyelenggarakan program tertentu; c. penurunan …"}, {"l": "UU 4/2023", "p": "194", "b": "Bagian Keenam", "t": "Setiap Orang yang menjalankan Program Pensiun, tidak memperoleh pengesahan sebagai Dana Pensiun dari Otoritas Jasa Keuangan sebagaimana dimaksud dalam Pasal 136, dipidana dengan pidana penjara paling singkat 3 (tiga) tahun dan paling lama 5 (lima) tahun dan pidana denda paling sedikit Rpl0.000.000.000,00 (sepuluh miliar rupiah) dan paling banyak Rpl00.000.000.000,00 (seratus miliar rupiah)."}, {"l": "UU 4/2023", "p": "195", "b": "Bagian Keenam", "t": "Anggota Dewan Pengawas, anggota Dewan Pengawas Syariah, anggota Pengurus, dan pegawai Dana Pensiun yang dengan sengaja melakukan pembayaran selain yang ditetapkan dalam Peraturan Dana Pensiun dan peraturan perundang-undangan sebagaimana dimaksud dalam Pasal 161 ayat (1) dipidana dengan pidana penjara paling singkat 3 (tiga) tahun dan paling lama 5 (lima) tahun dan pidana denda paling sedikit Rpl0.000.000.000,00 (sepuluh miliar rupiah) dan paling banyak Rpl00.000.000.000,00 (seratus miliar rupiah). Pasal 196 ... jdih.kemenkeu.go.id REPUBUK INDONESIA"}, {"l": "UU 4/2023", "p": "196", "b": "Bagian Keenam", "t": "Anggota Dewan Pengawas, anggota Dewan Pengawas Syariah, anggota Pengurus, dan pegawai Dana Pensiun yang dengan sengaja meminjamkan atau mengagunkan aset Dana Pensiun kepada pihak manapun sebagaimana dimaksud dalam Pasal 169 ayat (2) huruf a dipidana dengan pidana penjara paling singkat 1 (satu) tahun dan paling lama 5 (lima) tahun dan pidana denda paling sedikit Rpl0.000.000.000,00 (sepuluh miliar rupiah) dan paling banyak Rpl00.000.000.000,00 (seratus miliar rupiah)."}, {"l": "UU 4/2023", "p": "197", "b": "Bagian Keenam", "t": "Anggota Dewan Pengawas, anggota Dewan Pengawas Syariah, anggota Pengurus, dan pegawai Dana Pensiun yang dengan sengaja menginvestasikan aset Dana Pensiun baik secara langsung maupun tidak langsung, pada surat berharga yang diterbitkan, atau pada tanah dan/ atau bangunan yang dimiliki atau yang dipergunakan oleh pihak sebagaimana dimaksud dalam Pasal 169 ayat (2) huruf b dan dilakukan tidak sesuai dengan ketentuan Pasal 170 dipidana dengan pidana penjara paling singkat 1 (satu) tahun dan paling lama 5 (lima) tahun dan pidana denda paling sedikit Rpl0.000.000.000,00 (sepuluh miliar rupiah) dan paling banyak Rpl00.000.000.000,00 (seratus miliar rupiah)."}, {"l": "UU 4/2023", "p": "198", "b": "Bagian Keenam", "t": "Setiap Orang yang dengan sengaja: a. membuat atau menyebabkan adanya laporan, informasi, data atau dokumen Dana Pensiun yang tidak benar, palsu, atau menyesatkan sebagaimana dimaksud dalam Pasal 175 huruf a; b. menghilangkan, tidak memasukkan atau menyebabkan dihapuskannya suatu informasi atau data dalam buku catatan, laporan, atau dokumen Dana Pensiun sebagaimana dimaksud dalam Pasal 175 huruf b; dan/atau c. mengubah, mengaburkan, menyembunyikan, menghapus atau menghilangkan suatu informasi atau data dalam buku catatan, laporan, atau dokumen Dana Pensiun sebagaimana dimaksud dalam Pasal 175 huruf c, dipidana ... jdih.kemenkeu.go.id REPUBUK INDONESIA dipidana dengan pidana penjara paling singkat 5 (lima) tahun dan paling lama 15 (lima belas) tahun dan pidana denda paling sedikit Rpl0.000.000.000,00 (sepuluh miliar rupiah) dan paling banyak Rp200.000.000.000,00 (dua ratus miliar rupiah)."}, {"l": "UU 4/2023", "p": "199", "b": "Bagian Keenam", "t": "Dalam hal anggota direksi atau yang setara pada pengelola Program Pensiun yang terkait dengan keuangan negara melakukan cut loss tidak sesuai dengan ketentuan sebagaimana dimaksud dalam Pasal 191 ayat (1) dan/atau menyebabkan penurunan nilai aset tidak sesuai dengan ketentuan sebagaimana dimaksud dalam Pasal 191 ayat (4) dikenai sanksi sesuai dengan ketentuan peraturan perundang­ undangan."}, {"l": "UU 4/2023", "p": "200", "b": "Bagian Keenam", "t": "(1) Dalam hal tindak pidana sebagaimana dimaksud dalam Pasal 194 dan Pasal 199 dilakukan oleh badan usaha baik yang berbentuk badan hukum maupun tidak berbentuk badan hukum, asosiasi, atau kelompok terorganisasi, tuntutan dan sanksi pidana dijatuhkan terhadap: a. badan usaha baik yang berbentuk badan hukum maupun tidak berbentuk badan hukum, asosiasi, atau kelompok terorganisasi; dan/ a tau b. orang perseorangan yang memberi perintah untuk melakukan dan/atau yang bertindak sebagai pemimpin dalam tindak pidana dimaksud. (2) Terhadap badan usaha baik yang berbentuk badan hukum maupun tidak berbentuk badan hukum, asosiasi, atau kelompok terorganisasi sebagaimana dimaksud pada ayat (1) huruf a, dipidana dengan pidana denda paling sedikit Rp20.000.000.000,00 (dua puluh miliar rupiah) dan paling banyak Rp300.000.000.000,00 (tiga ratus miliar rupiah). (3) Terhadap orang perseorangan yang memberi perintah untuk melakukan dan/ atau yang bertindak sebagai pemimpin sebagaimana dimaksud pada ayat (1) huruf b, dipidana dengan pidana penjara paling singkat 5 (lima) tahun dan paling lama 15 (lima belas) tahun dan pidana denda paling sedikit Rpl0.000.000.000,00 (sepuluh miliar rupiah) dan paling …"}, {"l": "UU 4/2023", "p": "201", "b": "BAB XIII KOPERASI DI SEKTOR JASA KEUANGAN", "t": "Dalam rangka pengembangan dan penguatan sektor keuangan melalui penataan Kegiatan Usaha Simpan Pinjam oleh Koperasi, Undang-Undang m1 mengubah dan/atau menetapkan pengaturan baru beberapa ketentuan yang diatur dalam Undang-Undang Nomor 25 Tahun 1992 tentang Perkoperasian (Lembaran Negara Republik Indonesia Tahun 1992 Nomor 116, Tambahan Lembaran Negara Republik Indonesia Nomor 3502) sebagaimana telah diubah dengan Peraturan Pemerintah Pengganti Undang-Undang Nomor 2 Tahun 2022 tentang Cipta Kerja (Lembaran Negara Republik Indonesia Tahun 2022 Nomor 238, Tambahan Lembaran Negara Republik Indonesia Nomor 6841)."}, {"l": "UU 4/2023", "p": "202", "b": "BAB XIII KOPERASI DI SEKTOR JASA KEUANGAN", "t": "Di antara Pasal 44A dan Pasal 45 dalam Undang-Undang Nomor 25 Tahun 1992 tentang Perkoperasian (Lembaran Negara Republik Indonesia Tahun 1992 Nomor 116, Tambahan 1 (satu) pasal, yakni Pasal 44B sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "203", "b": "BAB XIV LEMBAGA KEUANGAN MIKRO", "t": "Dalam rangka pengembangan dan penguatan sektor keuangan melalui penataan lembaga keuangan mikro, Undang-Undang ini mengubah, menghapus, dan/ a tau menetapkan pengaturan baru beberapa ketentuan yang diatur dalam Undang-Undang Nomor 1 Tahun 2013 tentang Lembaga Keuangan Mikro (Lembaran Negara Republik Indonesia Tahun 2013 Nomor 12,"}, {"l": "UU 4/2023", "p": "204", "b": "BAB XIV LEMBAGA KEUANGAN MIKRO", "t": "Beberapa ketentuan dalam Undang-Undang Nomor 1 Tahun 2013 tentang Lembaga Keuangan Mikro (Lembaran Negara Republik Indonesia Tahun 2013 Nomor 12, Tambahan sebagai berikut: 1. Ketentuan . . . jdih.kemenkeu.go.id REPUBUK INDONESIA 1. Ketentuan Pasal 5 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "30B", "b": "BAB XIV LEMBAGA KEUANGAN MIKRO", "t": "Pemegang saham atau pemilik dan/ atau pihak terafiliasi LKM dilarang menyuruh anggota dewan komisaris, anggota pengawas, anggota direksi, anggota pengurus, pengelola, pegawai, dan/ a tau pihak terafiliasi LKM untuk melakukan atau tidak melakukan tindakan yang mengakibatkan LKM tidak melaksanakan langkah yang diperlukan untuk memastikan ketaatan LKM terhadap ketentuan dalam Undang-Undang ini dan ketentuan peraturan perundang-undangan yang berlaku bagi LKM. Pasal 30C ... jdih.kemenkeu.go.id REPUBUK INDONESIA ."}, {"l": "UU 4/2023", "p": "30C", "b": "BAB XIV LEMBAGA KEUANGAN MIKRO", "t": "Anggota dewan komisaris, anggota pengawas, anggota direksi, anggota pengurus, pengelola, pegawai, dan/ atau pihak terafiliasi LKM dilarang memberikan laporan, informasi, data, dan dokumen kepada Otoritas Jasa Keuangan secara tidak benar, palsu, dan/ atau menyesatkan. 11. Ketentuan Pasal 31 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "207", "b": "BAB XV KONGLOMERASIKEUANGAN", "t": "(1) Kegiatan usaha PIKK meliputi: a. WK; dan b. kegiatan usaha lainnya yang ditetapkan oleh Otoritas Jasa Keuangan. (2) Ketentuan lebih lanjut mengenai kegiatan usaha PIKK sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Otoritas Jasa Keuangan. Pasal 208 ... jdih.kemenkeu.go.id REPUBUK INDONESIA"}, {"l": "UU 4/2023", "p": "208", "b": "BAB XV KONGLOMERASIKEUANGAN", "t": "(1) Dalam melaksanakan kegiatan usaha, PIKK wajib memperhatikan prinsip kehati-hatian. (2) Ketentuan mengenai prinsip kehati-hatian sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "209", "b": "BAB XV KONGLOMERASIKEUANGAN", "t": "(1) Direksi dan dewan komisaris PIKK wajib memenuhi persyaratan kemampuan dan kepatutan yang ditetapkan oleh Otoritas Jasa Keuangan. (2) Ketentuan lebih lanjut mengenai persyaratan kemampuan dan kepatutan sebagaimana dimaksud pada ayat ( 1) diatur dalam Peraturan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "210", "b": "BAB XV KONGLOMERASIKEUANGAN", "t": "(1) Dalam rangka pelaksanaan tugas pengawasan, Otoritas Jasa Keuangan berwenang untuk meminta data dan informasi termasuk melakukan pemeriksaan terhadap pihak terelasi dalam Konglomerasi Keuangan dan/atau pihak lain yang terkait dengan Konglomerasi Keuangan. (2) Pihak terelasi dan/atau pihak lain sebagaimana dimaksud pada ayat (1) wajib memenuhi permintaan data dan informasi serta hal lain yang diperlukan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "211", "b": "BAB XV KONGLOMERASIKEUANGAN", "t": "Pembentukan PIKK, termasuk juga proses pengalihan aset dalam pembentukan PIKK, dapat diberikan fasilitas perpajakan sesuai dengan ketentuan peraturan perundang-undangan mengenai perpajakan."}, {"l": "UU 4/2023", "p": "212", "b": "BAB XV KONGLOMERASIKEUANGAN", "t": "Dalam rangka pelaksanaan tugas dan/ a tau wewenang sebagaimana dimaksud dalam Pasal 205 sampai dengan Pasal 211, Otoritas Jasa Keuangan berkoordinasi dengan Bank Indonesia dan/ atau kementerian/lembaga terkait."}, {"l": "UU 4/2023", "p": "213", "b": "BAB XVI INOVASI TEKNOLOGI SEKTOR KEUANGAN", "t": "Ruang lingkup ITSK meliputi: a. sistem pembayaran; b. penyelesaian transaksi surat berharga; c. penghimpunan modal; d. pengelolaan investasi; e. pengelolaan risiko; f. penghimpunan dan/atau penyaluran dana; g. pendukung pasar; h. aktivitas terkait aset keuangan digital, termasuk aset kripto; dan 1. aktivitas jasa keuangan digital lainnya."}, {"l": "UU 4/2023", "p": "214", "b": "BAB XVI INOVASI TEKNOLOGI SEKTOR KEUANGAN", "t": "(1) ITSK dapat dimanfaatkan untuk mendukung kegiatan ekonomi dan keuangan termasuk yang dilakukan berdasarkan Prinsip Syariah. (2) Kegiatan ekonomi dan keuangan yang menggunakan ITSK berdasarkan Prinsip Syariah sebagaimana dimaksud pada ayat (1) harus mengikuti Prinsip Syariah yang dikeluarkan oleh lembaga yang memiliki kewenangan dalam penetapan fatwa di bidang syariah."}, {"l": "UU 4/2023", "p": "215", "b": "BAB XVI INOVASI TEKNOLOGI SEKTOR KEUANGAN", "t": "(1) Pihak yang menyelenggarakan ITSK terdiri atas: a. WK; dan/ atau b. pihak lain yang melakukan kegiatan di sektor keuangan sesuai dengan k etentuan pe raturan perundang-undangan. (2) Penyelenggara ITSK berbentuk: a. badan hukum perseroan terbatas; atau b. badan ... jdih.kemenkeu.go.id . REPUBUK INDONESIA b. badan hukum lain sesuai dengan ketentuan peraturan perundang-undangan. (3) Penyelenggara sebagaimana dimaksud pada ayat (1) harus menerapkan prinsip: a. tata kelola; b. manajemen risiko; c. keamanan dan keandalan sistem informasi, termasuk ketahanan siber; d. Pelindungan Konsumen dan pelindungan data pribadi; dan e. pemenuhan ketentuan peraturan perundang­ undangan."}, {"l": "UU 4/2023", "p": "216", "b": "BAB XVI INOVASI TEKNOLOGI SEKTOR KEUANGAN", "t": "(1) Bank Indonesia dan Otoritas Jasa Keuangan melakukan pengaturan dan pengawasan terhadap penyelenggaraan ITSK sesuai dengan ruang lingkup kewenangan masing­ masing. (2) Pengaturan dan pengawasan terhadap penyelenggaraan ITSK sebagaimana dimaksud pada ayat (1) dilakukan dengan prinsip: a. keseimbangan antara upaya dalam mendorong inovasi dengan mitigasi risiko; b. integrasi ekonomi dan keuangan digital; c. efisiensi dan praktik bisnis yang sehat; d. Pelindungan Konsumen; dan e. koordinasi pengaturan dan pengawasan antarotoritas. (3) Ruang lingkup pengaturan dan pengawasan terhadap penyelenggaraan ITSK sebagaimana dimaksud pada ayat (1) mencakup: a. penyediaan ruang dan/ atau fasilitasi uji coba/pengembangan inovasi (sandbox); b. perizinan; c. pemantauan dan evaluasi; d. edukasikeuangan; e. Pelindungan ... jdih.kemenkeu.go.id REPUBUK INDONESIA e. Pelindungan Konsumen; f. pelindungan data pribadi Konsumen; g. aspek kelembagaan; dan h. penyelenggaraan ITSK, termasuk aktivitas yang dilakukan oleh pihak ketiga yang menu njang penyelenggaraan ITSK."}, {"l": "UU 4/2023", "p": "217", "b": "BAB XVI INOVASI TEKNOLOGI SEKTOR KEUANGAN", "t": "(1) Bank Indonesia dan Otoritas Jasa Keuangan dapat berkoordinasi dalam rangka pengaturan, pengawasan, dan penyelenggaraan ITSK. (2) Koordinasi sebagaimana dimaksud pada ayat (1) mencakup: a. uji coba/pengembangan inovasi (sandbox); b. pengembangan ekosistem pengaturan berbasis teknologi (regulatory technology) dan pengawasan berbasis teknologi (supervisory technology) untuk pengembangan ITSK; c. pertukaran data dan/atau informasi; d. pembahasan mengenai isu yang sedang berkembang terkait dengan ITSK; e. peningkatan kapasitas sumber daya manusia; dan/atau f. aspek lain yang dipandang perlu. (3) Dalam rangka pengaturan, pengawasan, dan pengembangan ITSK, Bank Indonesia dan Otoritas Jasa Keuangan dapat berkoordinasi dengan kementerian, lembaga, dan pihak lain. (4) Mekanisme dan tata cara penyelenggaraan ruang uji coba/pengembangan inovasi (sandbox) ITSK diatur oleh Bank Indonesia dan Otoritas Jasa Keuangan sesuai dengan kewenangan masing-masing."}, {"l": "UU 4/2023", "p": "218", "b": "BAB XVI INOVASI TEKNOLOGI SEKTOR KEUANGAN", "t": "Penyelenggara ITSK wajib memenuhi ketentuan perizinan yang diatur oleh Bank Indonesia atau Otoritas Jasa Keuangan sesuai dengan kewenangan masing-masing. Pasal 219 ... jdih.kemenkeu.go.id"}, {"l": "UU 4/2023", "p": "219", "b": "BAB XVI INOVASI TEKNOLOGI SEKTOR KEUANGAN", "t": "(1) Otoritas berwenang melakukan evaluasi dan/atau tindak lanjut hasil uji coba/pengembangan inovasi (sandbox) terhadap penyelenggara ITSK. (2) Terhadap suatu produk, aktivitas, layanan, atau model bisnis dari penyelenggara ITSK yang telah lulus proses uji coba/pengembangan inovasi (sandbox) dan mendapatkan penzman dari otoritas sektor keuangan terkait, pengaturan, pengawasan, dan pengenaan sanksi tunduk pada ketentuan industri yang bersangkutan."}, {"l": "UU 4/2023", "p": "220", "b": "BAB XVI INOVASI TEKNOLOGI SEKTOR KEUANGAN", "t": "(1) Setiap penyelenggara ITSK wajib memenuhi ketentuan kepesertaan dalam asosiasi penyelenggara ITSK yang disetujui dan diatur oleh Bank Indonesia dan Otoritas Jasa Keuangan sesuai dengan kewenangan masing­ masing. (2) Dalam menjalankan pengaturan bagi anggotanya, asosiasi penyelenggara ITSK harus mengacu pada ketentuan yang telah ditetapkan oleh Bank Indonesia dan Otoritas Jasa Keuangan sesuai dengan kewenangan masing-masing. (3) Asosiasi penyelenggara ITSK sebagaimana dimaksud pada ayat (1) wajib melakukan pembinaan dan pemantauan terhadap setiap penyelenggara ITSK yang terdaftar sebagai anggota asosiasi sejalan dengan fungsi dan tugas yang diamanatkan oleh otoritas sektor keuangan. (4) Pengaturan terkait koordinasi antara Bank Indonesia dan Otoritas Jasa Keuangan dengan asosiasi penyelenggara ITSK diatur oleh Bank Indonesia dan Otoritas Jasa Keuangan sesuai dengan kewenangan masing-masing."}, {"l": "UU 4/2023", "p": "221", "b": "BAB XVI INOVASI TEKNOLOGI SEKTOR KEUANGAN", "t": "(1) Penyelenggara ITSK wajib menyampaikan data, informasi, dan/ a tau laporan berkala a tau sewaktu-waktu kepada Bank Indonesia atau Otoritas Jasa Keuangan sesuai dengan fungsi dan/atau kewenangan masing-masing. (2) Terhadap ... jdih.kemenkeu.go.id REPUBUK INDONESIA (2) Terhadap data, informasi, dan/ a tau laporan berkala atau sewaktu-waktu yang diterima, Bank Indonesia dan/ atau Otoritas Jasa Keuangan dapat melakukan pemrosesan, pertukaran, dan diseminasi, melalui sistem informasi digital dan/atau mekanisme lainnya sesuai dengan ketentuan peraturan perundang-undangan. (3) Ketentuan lebih lanjut mengenai penyampaian data, informasi, dan/ atau laporan sebagaimana dimaksud pada ayat (1) diatur dengan Peraturan Bank Indonesia dan Peraturan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "222", "b": "Bagian Kesatu", "t": "(1) PUSK, emiten, dan perusahaan publik menerapkan Keuangan Berkelanjutan dalam kegiatan usahanya. (2) PUSK, emiten, dan perusahaan publik dalam rangka menerapkan Keuangan Berkelanjutan sebagaimana dimaksud pada ayat (1) melakukan: a. praktik bisnis dan strategi investasi yang mengintegrasikan aspek lingkungan hidup, sosial, dan tata kelola; dan b. pengembangan produk, transaksi, dan jasa pembiayaan kegiatan berkelanjutan dan pembiayaan transisi. (3) PUSK, emiten, dan perusahaan publik harus membangun kapasitas dalam rangka menerapkan Keuangan Berkelanjutan sebagaimana dimaksud pada ayat (1). (4) PUSK, emiten, dan perusahaan publik menyusun laporan keberlanjutan sebagai bagian dari akuntabilitas kinerja penerapan Keuangan Berkelanjutan. (5) Ketentuan ... jdih.kemenkeu.go.id (5) Ketentuan lebih lanjut mengenai penerapan Keuangan Berkelanjutan sebagaimana dimaksud pada ayat (1) sampai dengan ayat (4) diatur oleh otoritas sektor keuangan dan Menteri sesuai dengan tugas dan kewenangan masing-masing."}, {"l": "UU 4/2023", "p": "224", "b": "Bagian Kedua", "t": "(1) Untuk mendukung pengembangan Keuangan Berkelanjutan sebagaimana dimaksud dalam Pasal 223 ayat (1), Kementerian Keuangan, Otoritas Jasa Keuangan, dan Bank Indonesia membentuk komite Keuangan Berkelanjutan. (2) Menteri bertindak sebagai koordinator dalam komite Keuangan Berkelanjutan sebagaimana dimaksud pada ayat (1). (3) Ketentuan ... jdih.kemenkeu.go.id REPUBUK INDONESIA (3) Ketentuan lebih lanjut mengenai komite Keuangan Berkelanjutan sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Pemerintah."}, {"l": "UU 4/2023", "p": "226", "b": "Bagian Kesatu", "t": "(1) PUSK wajib melaksanakan kegiatan dalam rangka meningkatkan Literasi Keuangan dan Inklusi Keuangan kepada Konsumen dan masyarakat. (2) Dalam rangka peningkatan Literasi Keuangan dan lnklusi Keuangan, Pemerintah membentuk komite nasional yang mengoordinasikan peningkatan Literasi Keuangan dan Inklusi Keuangan. (3) Ketentuan lebih lanjut mengenai kegiatan dalam rangka peningkatan Literasi Keuangan dan Inklusi Keuangan sebagaimana dimaksud pada ayat (1) diatur dalam peraturan otoritas sektor keuangan serta komite nasional sebagaimana dimaksud pada ayat (2) diatur dalam Peraturan Pemerintah."}, {"l": "UU 4/2023", "p": "227", "b": "Bagian Kedua", "t": "PUSK dalam menyelenggarakan kegiatan usahanya wajib menerapkan prinsip Pelindungan Konsumen. Pasal228 Pelindungan Konsumen di sektor keuangan menerapkan prinsip: a. edukasi yang memadai; b. keterbukaan dan transparansi informasi produk dan/atau layanan; c. perlakuan yang adil dan perilaku bisnis yang bertanggung jawab; d. pelindungan aset, privasi, dan data Konsumen; e. penanganan pengaduan dan penyelesaian sengketa yang efektif dan efisien; f. penegakan kepatuhan; dan g. persaingan yang sehat."}, {"l": "UU 4/2023", "p": "229", "b": "Bagian Kedua", "t": "Pelindungan Konsumen di sektor keuangan diselenggarakan dengan tujuan: a. menciptakan ekosistem Pelindungan Konsumen yang mewujudkan kepastian hukum serta penanganan pengaduan dan penyelesaian sengketa yang efektif dan efisien; b. menumbuhkan kesadaran PUSK mengenai perilaku bisnis yang bertanggung jawab, perlakuan yang adil; memberikan pelindungan aset, privasi, dan data Konsumen; serta meningkatkan kualitas produk dan/atau layanan PUSK; dan c. meningkatkan kesadaran, kemampuan, dan kemandirian Konsumen mengenai produk dan/atau layanan PUSK serta meningkatkan pemberdayaan Konsumen."}, {"l": "UU 4/2023", "p": "230", "b": "Bagian Ketiga", "t": "PUSK merupakan pihak yang menyelenggarakan Pelindungan Konsumen di sektor keuangan yang menyelenggarakan usaha baik di luar jaringan maupun dalam jaringan."}, {"l": "UU 4/2023", "p": "231", "b": "Bagian Ketiga", "t": "Objek dalam penyelenggaraan Pelindungan Konsumen di sektor keuangan meliputi perilaku PUSK dalam: a. melakukan perancangan, menyusun dan menya mpaikan informasi, dan melakukan penawaran atas produk dan/atau layanan di sektor keuangan; b. membuat perjanjian dan memberikan pelayanan atas penggunaan produk dan/ atau layanan di sektor keuangan;dan c. melakukan penanganan pengaduan."}, {"l": "UU 4/2023", "p": "232", "b": "Bagian Ketiga", "t": "Ruang lingkup pengaturan Pelindungan Konsumen sektor keuangan meliputi: a. wewenang pengaturan dan pengawasan dalam rangka Pelindungan Konsumen di sektor keuang!ln; b. hak dan kewajiban Konsumen serta hak, kewajiban, dan larangan bagi PUSK; c. ketentuan Perjanjian Baku; d. pelindungan data Konsumen; e. Literasi Keuangan; f. pembinaan dan pengawasan; g. penanganan pengaduan; h. penyelesaian sengketa sektor keuangan; i. LAPS-SK; j. sanksi administratif; dan k. ketentuan pidana."}, {"l": "UU 4/2023", "p": "233", "b": "Bagian Keempat", "t": "(1) Otoritas sektor keuangan berwenang melakukan pengaturan dalam rangka Pelindungan Konsumen dan masyarakat di sektor keuangan. (2) Otoritas sektor keuangan sebagaimana dimaksud pada ayat (1) berwenang mengatur mengenai: a. mekanisme penanganan pengaduan Konsumen; b. layanan Konsumen sektor keuangan; c. Pengawasan Perilaku Pasar (Market Conduct); d. penyelesaian sengketa sektor keuangan di luar pengadilan melalui badan atau lembaga penyelesaian sengketa; dan e. ketentuan lain dalam rangka Pelindungan Konsumen dan masyarakat di sektor keuangan. (3) Pelindungan Konsumen di sektor keuangan tunduk pada Undang-Undang ini."}, {"l": "UU 4/2023", "p": "234", "b": "Bagian Keempat", "t": "(1) Otoritas sektor keuangan melakukan Pengawasan Perilaku Pasar (Market Conduct) untuk memastikan kepatuhan PUSK dalam menerapkan ketentuan Pelindungan Konsumen dan masyarakat secara langsung dan/ atau tidak langsung sesuai dengan fungsi, tugas, dan wewenang otoritas sektor keuangan yang diberikan berdasarkan Undang-Undang. (2) Ketentuan lebih lanjut mengenai pengawasan sebagaimana dimaksud pada ayat (1) diatur dalam peraturan otoritas sektor keuangan sesuai dengan kewenangan masing-masing."}, {"l": "UU 4/2023", "p": "238", "b": "Bagian Keenam", "t": "(1) PUSK memenuhi keseimbangan, keadilan, dan kewajaran dalam pembuatan perjanjian dengan Konsumen. (2) Perjanjian sebagaimana dimaksud pada ayat (1) berbentuk perjanjian tertulis. (3) Perjanjian ... jdih.kemenkeu.go.id REPUBUK INDONESIA (3) Perjanjian tertulis sebagaimana dimaksud pada ayat (2) dapat berbentuk Perjanjian Baku yang memuat klausul baku, kecuali yang dilarang berdasarkan Undang-Undang 1n1. (4) PUSK dilarang membuat dan menggunakan Perjanjian Baku yang memuat klausul baku yang berisi: a. menyatakan pengalihan tanggung jawab atau kewajiban PUSK kepada Konsumen; b. menyatakan pemberian kuasa dari Konsumen kepada PUSK, baik secara langsung maupun tidak langsung, untuk melakukan segala tindakan sepihak atas barang yang diagunkan oleh Konsumen, kecuali tindakan sepihak tersebut dilakukan berdasarkan ketentuan peraturan perundang-undangan; c. mengatur tentang kewajiban pembuktian oleh Konsumen, jika PUSK menyatakan bahwa hilangnya kegunaan produk dan/ a tau layanan yang dibeli oleh Konsumen, bukan merupakan tanggungjawab PUSK; d. memberi hak kepada PUSK untuk mengurangi kegunaan produk dan/ atau layanan atau mengurangi harta kekayaan Konsumen yang menjadi objek perjanjian …"}, {"l": "UU 4/2023", "p": "239", "b": "Bagian Ketujuh", "t": "(1) PUSK wajib menjaga kerahasiaan dan keamanan data dan/ atau informasi Konsumen. (2) Kewajiban PUSK sebagaimana dimaksud pada ayat (1) dilaksanakan dengan menerapkan prinsip dasar pemrosesan pelindungan data pribadi sebagaimana diatur dalam ketentuan peraturan perundang-undangan mengenai pelindungan data pribadi. (3) Dalam hal PUSK bekerja sama dengan pihak lain untuk mengelola data dan/ a tau informasi Konsumen, PUSK wajib memastikan pihak lain tersebut menjaga kerahasiaan dan keamanan data dan/atau informasi Konsumen sebagaimana dimaksud pada ayat (1). Pasal240 (1) Dalam penggunaan data dan/atau informasi Konsumen, PUSK dapat melakukan pertukaran data dan/ atau informasi Konsumen dengan pihak lain dengan memperhatikan ketentuan peraturan perundang- undangan mengenai pelindungan data pribadi dan peraturan perundang-undangan lain yang ditetapkan oleh otoritas sektor keuangan. (2) Pertukaran ... jdih.kemenkeu.go.id REPUBUK INDONESIA (2) Pertukaran data dan/ atau informasi Konsumen di sektor keuangan dapat dilakukan langsung oleh PUSK dan/ atau melalui infrastruktur pengelolaan data secara terintegrasi yang difasilitasi oleh otoritas sektor keuangan. (3) Pertukaran data dan/ atau …"}, {"l": "UU 4/2023", "p": "241", "b": "Bagian Ketujuh", "t": "(1) PUSK dapat melakukan transfer data dan/atau informasi Konsumen kepada pihak lain di luar wilayah hukum Negara Kesatuan Republik Indonesia dengan memenuhi ketentuan peraturan perundang-undangan mengenai pelindungan data pribadi dan peraturan perundang­ undangan lain yang ditetapkan oleh otoritas sektor keuangan. (2) Penyelenggaraan transfer data dan/atau informasi Konsumen sebagaimana dimaksud pada ayat (1) dilaksanakan sesuai dengan ketentuan peraturan perundang-undangan mengenai pelindungan data pribadi."}, {"l": "UU 4/2023", "p": "242", "b": "Bagian Ketujuh", "t": "Dalam pelaksanaan kegiatan usahanya, PUSK wajib memastikan keamanan sistem informasi dan ketahanan siber sesuai dengan ketentuan peraturan perundang-undangan mengenai keamanan sistem informasi dan ketahanan siber, dan ketentuan peraturan perundang-undangan lain yang ditetapkan oleh otoritas sektor keuangan."}, {"l": "UU 4/2023", "p": "243", "b": "Bagian Ketujuh", "t": "Pemerintah, Bank Indonesia, dan Otoritas Jasa Keuangan melakukan koordinasi dalam rangka Pelindungan Konsumen di sektor keuangan. Pasal 244 ... jdih.kemenkeu.go.id REPUBUK INDONESIA Pasal244 (1) Dalam rangka Pelindungan Konsumen, otoritas sektor keuangan berwenang memberikan perintah atau melakukan tindakan tertentu kepada PUSK. (2) Ketentuan mengenai pelaksanaan kewenangan sebagaimana dimaksud pada ayat (1) diatur dengan peraturan otoritas sektor keuangan. Pasal245 (1) PUSK wajib memiliki dan melaksanakan mekanisme penanganan pengaduan yang disampaikan oleh Konsumen. (2) Dalam hal tidak terdapat kesepakatan terhadap hasil penanganan pengaduan yang dilakukan oleh PUSK sebagaimana dimaksud pada ayat (1), Konsumen dapat: a. menyampaikan pengaduan kepada otoritas sektor keuangan untuk penanganan pengaduan sesuai dengan kewenangan masing-masing; atau b. mengajukan sengketa kepada lembaga atau badan penyelesaian sengketa yang mendapat persetujuan dari otoritas sektor keuangan atau kepada pengadilan. (3) Dalam melakukan kegiatan Pelindungan Konsumen, otoritas sektor keuangan melakukan penanganan pengaduan sesuai dengan kewenangan masing-masing. (4) Dalam hal terdapat gugatan ganti rugi …"}, {"l": "UU 4/2023", "p": "246", "b": "Bagian Ketujuh", "t": "(1) LAPS-SK wajib mendapat persetujuan dari otoritas sektor keuangan sesuai dengan kewenangan masing-masing. (2) Ketentuan lebih lanjut mengenai pembentukan dan syarat-syarat LAPS-SK sebagaimana dimaksud pada ayat (1) diatur dalam peraturan otoritas sektor keuangan sesuai dengan kewenangan masing-masing."}, {"l": "UU 4/2023", "p": "247", "b": "Bagian Ketujuh", "t": "(1) Untuk melindungi kepentingan masyarakat, Otoritas Jasa Keuangan bersama otoritas/kementerian/lembaga terkait membentuk satuan tugas untuk penanganan kegiatan usaha tanpa izin di sektor keuangan. (2) Satuan tugas sebagaimana dimaksud pada ayat (1) bertugas mencegah dan menangani kegiatan usaha tanpa izin di sektor keuangan. (3) Pembentukan satuan tugas serta kelembagaan dan tata kelola satuan tugas sebagaimana dimaksud pada ayat (1) diatur oleh Otoritas Jasa Keuangan bersama dengan otoritas/kementerian/lembaga anggota satuan tugas. (4) Tindak lanjut pelaksanaan tugas sebagaimana dimaksud pada ayat (2), dilakukan oleh otoritas/kementerian/lembaga terkait sesuai dengan kewenangan masing-masing."}, {"l": "UU 4/2023", "p": "248", "b": "Bagian Ketujuh", "t": "Peraturan perundang-undangan mengenai Pelindungan Konsumen di sektor keuangan bersifat khusus terhadap ketentuan peraturan perundang-undangan mengenai Pelindungan Konsumen di luar sektor keuangan."}, {"l": "UU 4/2023", "p": "250", "b": "BAB XIX AKSES PEMBIAYAAN USAHA MIKRO, KECIL, DAN MENENGAH", "t": "(1) Dalam hal terjadi piutang macet, perlu adanya kepastian hukum dalam rangka penanganan piutang macet pada Bank dan/ atau lembaga keuangan non-Bank badan usaha milik negara kepada Usaha Mikro, Kecil, dan Menengah. (2) Piutang macet pada Bank dan/atau lembaga keuangan non-Bank badan usaha milik negara kepada Usaha Mikro, Kecil, dan Menengah sebagaimana dimaksud pada ayat (1), dapat dilakukan penghapusbukuan dan penghapustagihan untuk mendukung kelancaran pemberian akses pembiayaan kepada Usaha Mikro, Kecil, dan Menengah. (3) Penghapusbukuan piutang macet sebagaimana dimaksud pada ayat (2) dilakukan oleh Bank dan/ atau lembaga keuangan non-Bank badan usaha milik negara dengan ketentuan sebagai berikut: a. terhadap piutang macet telah dilakukan upaya restrukturisasi; dan b. Bank dan/atau lembaga keuangan non-Bank badan usaha milik negara telah melakukan upaya penagihan secara optimal, termasuk upaya restrukturisasi sebagaimana dimaksud dalam huruf a, tetapi tetap tidak tertagih. Pasal 251 ... jdih.kemenkeu.go.id REPUBUK INDONESIA"}, {"l": "UU 4/2023", "p": "251", "b": "BAB XIX AKSES PEMBIAYAAN USAHA MIKRO, KECIL, DAN MENENGAH", "t": "(1) Kerugian yang dialami oleh Bank dan/atau lembaga keuangan non-Bank badan usaha milik negara dalam melaksanakan penghapusbukuan dan/ atau penghapustagihan piutang merupakan kerugian Bank dan/ atau lembaga keuangan non-Bank badan usaha milik negara yang bersangkutan. (2) Kerugian sebagaimana dimaksud pada ayat (1) bukan merupakan kerugian keuangan negara sepanjang dapat dibuktikan tindakan dilakukan berdasarkan iktikad baik, ketentuan peraturan perundang-undangan, anggaran dasar, dan prinsip tata kelola perusahaan yang baik. (3) Direksi dalam melakukan penghapusbukuan dan/atau penghapustagihan piutang tidak dapat dipertanggungjawabkan atas kerugian yang terjadi sebagaimana dimaksud pada ayat (1)."}, {"l": "UU 4/2023", "p": "252", "b": "Bagian Kesatu", "t": "(1) PUSK bertanggung jawab melakukan pengembangan kualitas sumber daya manusia melalui peningkatan kompetensi dan keahlian sumber daya manusia. (2) Peningkatan kompetensi dan keahlian sumber daya manusia sebagaimana dimaksud pada ayat (1) dilakukan melalui pendidikan dan pelatihan sumber daya manusia secara berkesinambungan. (3) Untuk mendukung penyelenggaraan pendidikan dan pelatihan sumber daya manusia, PUSK wajib menyediakan dana pendidikan dan pelatihan dari anggaran tahun berjalan. (4) Ketentuan lebih lanjut mengenai kewajiban penyediaan dana pendidikan dan pelatihan sebagaimana dimaksud pada ayat (3) diatur oleh otoritas sektor keuangan sesuai dengan tugas dan kewenangan masing-masing. Pasal 253 ... jdih.kemenkeu.go.id REPUBUK INDONESIA"}, {"l": "UU 4/2023", "p": "253", "b": "Bagian Kesatu", "t": "(1) PUSK harus menerapkan standar kompetensi. (2) Standar kompetensi sebagaimana dimaksud pada ayat (1) mengacu pada standar kompetensi yang ditetapkan oleh lembaga yang berwenang yang telah mendapatkan persetujuan atau pengakuan dari otoritas sektor keuangan terkait. (3) Ketentuan lebih lanjut mengenai standar kompetensi sebagaimana dimaksud pada ayat (1) dan ayat (2) diatur oleh otoritas sektor keuangan."}, {"l": "UU 4/2023", "p": "254", "b": "Bagian Kedua", "t": "Profesi Sektor Keuangan terdiri atas: a. Profesi Penunjang Sektor Keuangan; dan b. Profesi Pelaku Usaha Sektor Keuangan."}, {"l": "UU 4/2023", "p": "255", "b": "Bagian Kedua", "t": "Dalam melakukan kegiatan usaha di industri sektor keuangan, Pelaku Profesi Sektor Keuangan wajib memberikan jasa yang profesional. Pasal256 (1) Setiap Profesi Sektor Keuangan harus memiliki Asosiasi Profesi. (2) Setiap Pelaku Profesi Sektor Keuangan harus menjadi anggota Asosiasi Profesi. Pasal 257 ... jdih.kemenkeu.go.id"}, {"l": "UU 4/2023", "p": "257", "b": "Bagian Kedua", "t": "(1) Asosiasi Profesi sebagaimana dimaksud dalam Pasal 256 harus mendapat pengakuan dari kementerian atau otoritas terkait sesuai dengan ketentuan peraturan perundang-undangan. (2) Asosiasi Profesi sebagaimana dimaksud pada ayat (1) bertugas: a. mengoordinasikan dan menetapkan penyusunan standar profesi dan kode etik; b. membentuk komite penegakan etika profesi; c. menerapkan penegakan disiplin anggota terhadap etika profesi; d. mengadakan pendidikan dan pelatihan yang berkelanjutan; e. melakukan reviu mutu bagi anggotanya sesuai dengan ketentuan peraturan perundang-undangan; dan f. melaksanakan tugas lainnya, yang dilaporkan kepada kementerian dan/ atau otoritas terkait."}, {"l": "UU 4/2023", "p": "258", "b": "Bagian Kedua", "t": "Setiap Pelaku Profesi Sektor Keuangan wajib menaati kode etik yang ditetapkan oleh Asosiasi Profesi masing-masing sepanjang tidak bertentangan dengan Undang-Undang ini dan/ a tau peraturan pelaksanaannya. Paragraf 2 Profesi Penunjang Sektor Keuangan"}, {"l": "UU 4/2023", "p": "259", "b": "Bagian Kedua", "t": "(1) Profesi Penunjang Sektor Keuangan terdiri atas: a. akuntan publik; b. akuntan berpraktik; c. aktuaris; d. penilai ... jdih.kemenkeu.go.id d. penilai publik; e. konsultan pajak; f. notaris; g. konsultan hukum; h. ahli syariah jasa keuangan; dan i. profesi lain yang ditetapkan oleh kementerian, lembaga, atau otoritas pembina dan pengawas profesi terkait. (2) Dalam melakukan kegiatan usaha di industri sektor keuangan, Profesi Penunjang Sektor Keuangan wajib memberikan jasa yang independen. (3) Pembinaan dan pengawasan Profesi Penunjang Sektor Keuangan sebagaimana dimaksud pada ayat (1), dilakukan oleh: a. kementerian yang menyelenggarakan urusan pemerintahan di bidang keuangan untuk huruf a sampai dengan huruf e; b. kementerian yang menyelenggarakan urusan pemerintahan di bidang hukum untuk huruf f dan huruf g; c. Otoritas Jasa Keuangan untuk huruf h; atau d. kementerian, lembaga, atau otoritas yang sesuai dengan ketentuan peraturan perundang-undangan ditetapkan sebagai pembina dan pengawas Profesi Penunjang Sektor Keuangan sebagaimana dimaksud dalam huruf i. (4) Kementerian, lembaga, atau otoritas lain dapat melakukan pembinaan dan pengawasan terhadap Profesi Penunjang Sektor …"}, {"l": "UU 4/2023", "p": "261", "b": "Bagian Kedua", "t": "(1) Pelaku Profesi Sektor Keuangan wajib memiliki sertifikat profesi sesuai bidang pekerjaan masing-masing. (2) Sertifikat profesi sebagaimana dimaksud pada ayat (1) diterbitkan oleh: a. Lembaga Sertifikasi Profesi; dan/ atau b. Asosiasi Profesi sesuai dengan ketentuan peraturan perundang-undangan. (3) Untuk dapat menerbitkan sertifikat profesi sebagaimana dimaksud pada ayat (2), Lembaga Sertifikasi Profesi wajib mendapatkan lisensi terlebih dahulu dari badan atau lembaga yang diberikan kewenangan untuk melaksanakan sertifikasi kompetensi kerja sesuai dengan ketentuan peraturan perundang-undangan. (4) Untuk ... jdih.kemenkeu.go.id REPUBUK INDONESIA (4) Untuk mendapatkan lisensi sebagaimana dimaksud pada ayat (3), Lembaga Sertifikasi Profesi minimal harus mendapatkan rekomendasi terlebih dahulu dari kementerian, lembaga, atau otoritas pada sektor keuangan terkait bidang pekerjaan masing-masing sesuai dengan ketentuan peraturan perundang-undangan. (5) Kementerian, lembaga, atau otoritas sektor keuangan sebagaimana dimaksud pada ayat (4) dapat mengadministrasikan Lembaga Sertifikasi Profesi dan/ a tau Asosiasi Profesi yang menerbitkan sertifikat profesi sebagaimana dimaksud pada ayat …"}, {"l": "UU 4/2023", "p": "262", "b": "Bagian Kedua", "t": "Dalam hal PUSK menggunakan jasa Pelaku Profesi Sektor Keuangan, PUSK wajib menggunakan jasa Pelaku Profesi Sektor Keuangan yang telah memperoleh izin dan/ a tau persetujuan pendaftaran dari kementerian atau otoritas yang berwenang. Paragraf 5 Peningkatan Kualitas dan Kuantitas Profesi Sektor Keuangan Dalam Negeri Pasal263 Pemerintah dan/ atau otoritas sektor keuangan mendorong peningkatan kualitas dan kuantitas Profesi Sektor Keuangan dalam negeri guna menciptakan industri sektor keuangan yang kredibel."}, {"l": "UU 4/2023", "p": "264", "b": "Bagian Kedua", "t": "Pemerintah dan/atau otoritas sektor keuangan dapat bekerja sama dengan Asosiasi Profesi, Lembaga Sertifikasi Profesi, lembaga pendidikan tinggi, dan/ atau lembaga pendidikan lainnya yang setara untuk mendorong pendidikan dan pelatihan Profesi Sektor Keuangan. Paragraf 6 ... jdih.kemenkeu.go.id REPUBUK INDONESIA . Paragraf 6 Pemantauan dan Evaluasi Penguatan dan Pengembangan Sumber Daya Manusia Sektor Keuangan"}, {"l": "UU 4/2023", "p": "265", "b": "Bagian Kedua", "t": "(1) Dalam rangka pengembangan dan penguatan sumber daya manusia sektor keuangan, disusun peta jalan. (2) Petajalan sebagaimana dimaksud pada ayat (1) digunakan sebagai bahan pemantauan dan evaluasi kebijakan sumber daya manusia sektor keuangan. (3) Ketentuan mengenai penetapan peta jalan dan tata cara pemantauan dan evaluasi sebagaimana dimaksud pada ayat (1) dan ayat (2) diatur dalam Peraturan Pemerintah."}, {"l": "UU 4/2023", "p": "266", "b": "Bagian Ketiga", "t": "(1) PUSK wajib menerapkan prinsip tata kelola yang baik yang minimal mencakup: a. keterbukaan; b. akuntabilitas; c. tanggung jawab; d. independensi; dan e. kewajaran. (2) Selain penerapan prinsip sebagaimana dimaksud pada ayat (1), PUSK harus mengikuti perkembangan dinamika industri dalam rangka penerapan tata kelola yang baik."}, {"l": "UU 4/2023", "p": "267", "b": "Bagian Ketiga", "t": "PUSK wajib menerapkan manajemen risiko yang efektif. Pasal 268 ... jdih.kemenkeu.go.id REPUBUK INDONESIA"}, {"l": "UU 4/2023", "p": "268", "b": "Bagian Ketiga", "t": "PUSK wajib menyampaikan laporan pelaksanaan tata kelola yang baik dan penerapan manajemen risiko secara berkala kepada otoritas sektor keuangan sesuai dengan tugas dan kewenangan masing-masing."}, {"l": "UU 4/2023", "p": "269", "b": "Bagian Ketiga", "t": "Ketentuan lebih lanjut mengenai tata kelola yang baik sebagaimana dimaksud dalam Pasal 266, penerapan manajemen risiko sebagaimana dimaksud dalam Pasal 267, dan pelaporan sebagaimana dimaksud dalam Pasal 268 diatur dalam peraturan otoritas sektor keuangan sesuai dengan tugas dan kewenangan masing-masing. Pasal270 (1) Dalam rangka memastikan agar industri sektor keuangan dijalankan secara profesional, efektif, efisien, dan berkinerja optimal, otoritas sektor keuangan melakukan pemantauan dan evaluasi atas penerapan tata kelola yang baik. (2) Pemantauan dan evaluasi sebagaimana dimaksud pada ayat (1) dilakukan secara berkala. (3) Ketentuan lebih lanjut mengenai pemantauan dan evaluasi sebagaimana dimaksud pada ayat (1) dan ayat (2) diatur dalam peraturan otoritas sektor keuangan sesuai dengan tugas dan kewenangan masing-masing."}, {"l": "UU 4/2023", "p": "271", "b": "Bagian Keempat", "t": "(1) PUSK dan pihak yang melakukan interaksi bisnis dengan sektor keuangan harus menyampaikan laporan keuangan sesuai dengan ketentuan peraturan perundang- undangan. (2) Laporan keuangan sebagaimana dimaksud pada ayat (1) wajib disusun berdasarkan standar laporan keuangan. (3) Standar ... jdih.kemenkeu.go.id REPUBUK INDONESIA (3) Standar laporan keuangan sebagaimana dimaksud pada ayat (2) ditetapkan oleh komite standar laporan keuangan yang independen dengan tata kelola yang baik. (4) Dengan tetap memperhatikan ketentuan sebagaimana dimaksud pada ayat (3), Otoritas Jasa Keuangan dapat melengkapi pengaturan ketentuan akuntansi dalam rangka keterbukaan dan pelindungan investor publik. (5) Komite standar laporan keuangan sebagaimana dimaksud pada ayat (3) berwenang menyusun dan menetapkan standar laporan keuangan. (6) Komite standar laporan keuangan sebagaimana dimaksud pada ayat (3) ditetapkan dengan Keputusan Presiden. (7) Laporan keuangan sebagaimana dimaksud pada ayat (1) wajib diaudit oleh akuntan publik sesuai dengan ketentuan peraturan perundang-undangan."}, {"l": "UU 4/2023", "p": "272", "b": "Bagian Keempat", "t": "(1) Dalam rangka penyampaian laporan keuangan sebagaimana dimaksud dalam Pasal 271 ayat (1), Pemerintah dapat membentuk atau menunjuk platform bersama pelaporan keuangan (financial reporting single window). (2) Penyampaian laporan keuangan melalui platform bersama pelaporan keuangan (financial reporting single window) sebagaimana dimaksud pada ayat (1) tidak menghilangkan kewenangan kementerian, lembaga, atau otoritas terkait untuk meminta laporan keuangan secara langsung kepada entitas pelapor sehubungan dengan pelaksanaan tugasnya sesuai dengan ketentuan peraturan perundang­ undangan. (3) PUSK dan pihak yang melakukan interaksi bisnis dengan sektor keuangan bertanggung jawab atas laporan keuangan yang disampaikan, termasuk yang disampaikan melalui platform bersama pelaporan keuangan (financial reporting single window). Pasal 273 ... jdih.kemenkeu.go.id REPUBUK INDONESIA ."}, {"l": "UU 4/2023", "p": "273", "b": "Bagian Keempat", "t": "Ketentuan lebih lanjut mengenai kewajiban penyusunan dan penyampaian laporan keuangan, standar laporan keuangan, dan komite standar sebagaimana dimaksud dalam Pasal 271 dan platform bersama pelaporan keuangan (financial reporting single window) sebagaimana dimaksud dalam Pasal 272 diatur dalam Peraturan Pemerintah."}, {"l": "UU 4/2023", "p": "275", "b": "BAB XXI STABILITAS SISTEM KEUANGAN", "t": "Dalam rangka pengembangan dan penguatan sektor keuangan melalui penataan Stabilitas Sistem Keuangan, Undang-Undang ini mengubah, menghapus, dan/ atau menetapkan pengaturan baru beberapa ketentuan yang diatur dalam Undang-Undang Nomor 9 Tahun 2016 tentang Pencegahan dan Penanganan Krisis Sistem Keuangan (Lembaran Negara Republik Indonesia Tahun 2016 Nomor 70, Tambahan Lembaran Negara Republik Indonesia Nomor 5872). Pasal276 Beberapa ketentuan dalam Undang-Undang Nomor 9 Tahun 2016 tentang Pencegahan dan Penanganan Krisis Sistem Keuangan (Lembaran Negara Republik Indonesia Tahun 2016 Nomor 70, Tambahan Lembaran Negara Republik Indonesia Nomor 5872) diubah sebagai berikut: 1. Di antara Pasal 15 dan Pasal 16 dalam Bagian Kesatu Bab III disisipkan 2 (dua) pasal, yakni Pasal 15A dan Pasal 158 sehingga berbunyi sebagai berikut: Pasal 15A ... jdih.kemenkeu.go.id REPUBUK INDONESIA"}, {"l": "UU 4/2023", "p": "15B", "b": "BAB XXI STABILITAS SISTEM KEUANGAN", "t": "(1) Dalam hal berdasarkan: a. pengawasan dan pemeriksaan sesuai dengan kewenangan yang dimiliki setiap l embaga; dan/atau b. hasil penilaian kondisi Bank dari forum koordinasi sebagaimana dimaksud dalam Pasal 15A ayat (1), ditemukan potensi permasalahan Bank, Otoritas Jasa Keuangan dengan Bank Indonesia dan/ a tau Lembaga Penjamin Simpanan dapat melakukan pemeriksaan bersama. (2) Pemeriksaan ... jdih.kemenkeu.go.id REPUBUK INDONESIA (2) Pemeriksaan bersama sebagaimana dimaksud pada ayat (1) dapat dilakukan sebagai langkah antisipatif dan/atau penanganan permasalahan Bank. 2. Di antara Bagian Kesatu dan Bagian Kedua Bab III disisipkan 1 (satu) bagian, yakni Bagian Kedua sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "16A", "b": "Bagian Kedua", "t": "(1) Otoritas Jasa Keuangan mengatur dan menetapkan status pengawasan Bank. (2) Status pengawasan Bank sebagaimana dimaksud pada ayat (1) terdiri atas: a. Bank dalam pengawasan normal; b. Bank dalam penyehatan; dan c. Bank dalam resolusi. (3) Bank dalam resolusi sebagaimana dimaksud pada ayat (2) huruf c merupakan Bank yang dinyatakan oleh Otoritas Jasa Keuangan sebagai Bank yang mengalami kesulitan keuangan dan membahayakan kelangsungan usahanya serta tidak dapat disehatkan sesuai dengan kewenangan yang dimiliki Otoritas Jasa Keuangan. (4) Status pengawasan Bank sebagaimana dimaksud pada ayat (2) ditetapkan oleh Otoritas Jasa Keuangan. (5) Otoritas Jasa Keuangan memberitahukan perubahan status pengawasan Bank secara tertulis kepada Bank, Lembaga Penjamin Simpanan, dan Bank Indonesia. (6) Untuk ... jdih.kemenkeu.go.id . REPUBUK INDONESIA (6) Untuk melaksanakan tugas pengawasan Bank, Otoritas Jasa Keuangan berwenang memberikan perintah kepada Bank untuk melakukan tindakan tertentu. (7) Bank wajib melaksanakan perintah Otoritas Jasa Keuangan sebagaimana dimaksud pada ayat (6). (8) Ketentuan lebih lanjut mengenai kriteria penetapan status pengawasan Bank dan tindakan dalam rangka …"}, {"l": "UU 4/2023", "p": "16B", "b": "Bagian Kedua", "t": "Dalam hal Bank dalam pengawasan normal mengalami kesulitan yang membahayakan kelangsungan usahanya atau Bank ditetapkan sebagai Bank dalam penyehatan, Otoritas Jasa Keuangan berwenang melakukan tindakan pengawasan sebagaimana dimaksud dalam undang­ undang mengenai perbankan dan undang-undang mengenai perbankan syariah."}, {"l": "UU 4/2023", "p": "16C", "b": "Bagian Kedua", "t": "(1) Otoritas Jasa Keuangan menetapkan Bank sebagai Bank dalam penyehatan sebagaimana dimaksud dalam Pasal 16A ayat (2) huruf b dalam hal Bank tidak memenuhi ketentuan yang ditetapkan oleh Otoritas Jasa Keuangan mengenai: a. tingkat kesehatan; b. tingkat likuiditas; dan/ atau c. tingkat permodalan dengan memperhitungkan risiko. (2) Penetapan Bank dalam penyehatan sebagaimana dimaksud pada ayat (1) dilakukan oleh Otoritas Jasa Keuangan. (3) Dalam ... jdih.kemenkeu.go.id (3) Dalam hal Bank ditetapkan sebagai Bank dalam penyehatan dan Bank mengajukan permintaan kepada Otoritas Jasa Keuangan, Otoritas Jasa Keuangan dapat meminta kepada Lembaga Penjamin Simpanan untuk melakukan penempatan dana kepada Bank setelah Otoritas Jasa Keuangan melakukan analisis kelayakan permohonan Bank. (4) Otoritas Jasa Keuangan menetapkan Bank dalam penyehatan untuk jangka waktu paling lama 1 (satu) tahun terhitung sejak tanggal pemberitahuan tertulis Otoritas Jasa Keuangan kepada Bank, Lembaga Penjamin Simpanan, dan Bank Indonesia sebagaimana dimaksud dalam Pasal 16A ayat (5). (5) Dalam hal Bank menerima penempatan dana dari Lembaga Penjamin Simpanan sebagaimana dimaksud pada ayat (3), jangka waktu Bank …"}, {"l": "UU 4/2023", "p": "16D", "b": "Bagian Kedua", "t": "Pengelola statuter yang ditunjuk oleh Otoritas Jasa Keuangan, dalam hal Bank mengalami kesulitan yang membahayakan kelangsungan usahanya atau Bank dalam penyehatan sebagaimana dimaksud dalam Pasal 16B, berwenang untuk: a. mengambil alih seluruh wewenang dan fungsi direksi dan dewan komisaris pada Bank; b. mengendalikan dan mengelola kegiatan usaha Bank sesuai dengan ketentuan peraturan perundang­ undangan; c. membatalkan atau mengakhiri perjanjian yang dibuat oleh Bank dengan pihak ketiga yang merugikan dan/ atau menurut pengelola statuter dapat merugikan kepentingan Bank dan/atau nasabah; dan/atau d. melakukan pengalihan sebagian atau seluruh portofolio kekayaan atau usaha dan/ atau kumpulan dana dari Bank yang menurut pengelola statuter dapat mencegah kerugian yang lebih besar bagi Bank dan/ atau nasabah."}, {"l": "UU 4/2023", "p": "16E", "b": "Bagian Kedua", "t": "(1) Otoritas Jasa Keuangan menetapkan Bank sebagai Bank dalam resolusi sebagaimana dimaksud dalam Pasal 16A ayat (2) huruf c apabila: a. sebelum jangka waktu Bank dalam penyehatan sebagaimana dimaksud dalam Pasal 16C ayat (4) atau ayat (5) berakhir, Bank mengalami pemburukan dan tidak memenuhi ketentuan permodalan minimum dan/atau giro wajib minimum; b. sampai dengan jangka waktu Bank dalam penyehatan sebagaimana dimaksud dalam Pasal 16C ayat (4) atau ayat (5) berakhir, Bank belum dapat memenuhi ketentuan tingkat permodalan dengan memperhitungkan risiko dan/ atau belum dapat menyelesaikan permasalahan likuiditas mendasar; atau c. Bank ... jdih.kemenkeu.go.id REPUBUK INDONESIA c. Bank tidak dapat mengembalikan penempatan dana Lembaga Penjamin Simpanan. (2) Penetapan Bank dalam resolusi sebagaimana dimaksud pada ayat (1) dilakukan oleh Otoritas Jasa Keuangan. (3) Dalam hal Bank dalam resolusi merupakan Bank Sistemik, Otoritas Jasa Keuangan meminta penyelenggaraan rapat Komite Stabilitas Sistem Keuangan untuk melaporkan penetapan Bank Sistemik sebagai Bank dalam resolusi. (4) Dalam rapat Komite Stabilitas Sistem Keuangan sebagaimana dimaksud pada ayat (3), Komite Stabilitas Sistem …"}, {"l": "UU 4/2023", "p": "18A", "b": "Bagian Ketiga", "t": "(1) Bank Sistemik wajib menyusun rencana aksi pemulihan untuk disetujui oleh Otoritas Jasa Keuangan. (2) Rencana aksi pemulihan sebagaimana dimaksud pada ayat (1) paling sedikit memuat kewajiban PSP dan/atau pihak lain untuk menambah modal Bank dan mengubah jenis kewajiban tertentu menjadi modal Bank. (3) Otoritas Jasa Keuangan berwenang menetapkan tambahan kapasitas permodalan bagi Bank Sistemik yang digunakan untuk menyerap kerugian pada saat mengalami permasalahan keuangan. (4) Ketentuan . . . jdih.kemenkeu.go.id REPUBUK INDONESIA (4) Ketentuan mengenai rencana aksi pemulihan sebagaimana dimaksud pada ayat (1) dan ayat (2) serta tambahan kapasitas permodalan Bank Sistemik sebagaimana dimaksud pada ayat (3) diatur dalam Peraturan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "18B", "b": "Bagian Ketiga", "t": "(1) Bank Sistemik wajib menyusun dan menyampaikan rencana resolusi kepada Lembaga Penjamin Simpanan untuk mendapat persetujuan. (2) Rencana resolusi sebagaimana dimaksud pada ayat (1) paling sedikit memuat: a. struktur Bank, kondisi keuangan, lini bisnis utama, fungsi ekonomi penting, dan pihak terafiliasi; dan b. keterkaitan dengan Sistem Keuangan. (3) Ketentuan lebih lanjut mengenai rencana resolusi sebagaimana dimaksud pada ayat (1) dan ayat (2) diatur dalam Peraturan Lembaga Penjamin Simpanan."}, {"l": "UU 4/2023", "p": "18C", "b": "Bagian Ketiga", "t": "(1) Lembaga Penjamin Simpanan melakukan penilaian terhadap rencana resolusi yang disampaikan Bank Sistemik sebagaimana dimaksud dalam Pasal 18B ayat (1). (2) Penilaian rencana resolusi sebagaimana dimaksud pada ayat (1) dilakukan Lembaga Penjamin Simpanan baik secara langsung maupun secara tidak langsung. (3) Untuk kepentingan Lembaga Penjamin Simpanan dalam menilai rencana resolusi Bank Sistemik sebagaimana dimaksud pada ayat (1), Bank Sistemik wajib menyampaikan kepada Lembaga Penjamin Simpanan: a. rencana aksi pemulihan Bank Sistemik sebagaimana dimaksud dalam Pasal 18A yang telah disetujui oleh Otoritas Jasa Keuangan; dan b. data dan informasi serta dokumen lainnya yang diperlukan Lembaga Penjamin Simpanan. (4) Berdasarkan ... jdih.kemenkeu.go.id REPUBUK INDONESIA (4) Berdasarkan hasil penilaian terhadap rencana resolusi yang disampaikan Bank Sistemik, Lembaga Penjamin Simpanan memberikan persetujuan atau meminta perbaikan rencana resolusi Bank Sistemik. (5) Terhadap rencana resolusi Bank Sistemik yang telah disetujui sebagaimana dimaksud pada ayat (4), Lembaga Penjamin Simpanan dapat melakukan uji resolvabilitas untuk mengidentifikasi hambatan yang mungkin ada pada saat …"}, {"l": "UU 4/2023", "p": "20C", "b": "Bagian Keempat", "t": "(1) Terhadap Bank Sistemik yang menerima penempatan dana sebagaimana dimaksud dalam Pasal 20B, Lembaga Penjamin Simpanan beiwenang untuk: a. melakukan pemeriksaan penggunaan dana; b. melarang Bank Sistemik untuk melakukan tindakan tertentu; c. menunjuk pihak lain untuk memberikan bantuan teknis; d. memerintahkan pemegang saham untuk melakukan penggantian anggota direksi dan/ atau anggota dewan komisaris; dan e. menunjuk pihak lain sebagai pengelola statuter dengan kewenangan sebagaimana diatur dalam"}, {"l": "UU 4/2023", "p": "20D", "b": "Bagian Keempat", "t": "(1) Selama jangka waktu penempatan dana Lembaga Penjamin Simpanan pada Bank Sistemik atau selama Bank Sistemik belum mengembalikan penempatan dana, Bank Sistemik dilarang: a. menyalurkan kredit dan/ atau pembiayaan baru kepada pihak terkait Bank Sistemik, kecuali untuk pemenuhan komitmen yang telah diperjanjikan sebelumnya; b. merealisasikan penarikan dana oleh pihak terkait Bank Sistemik; dan c. melakukan pembagian dividen. (2) Larangan sebagaimana dimaksud pada ayat (1) tidak meniadakan larangan lain yang dikeluarkan oleh Otoritas Jasa Keuangan. (3) Anggota direksi, anggota dewan komisaris, PSP, pegawai, dan/ a tau pihak terafiliasi dilarang menggunakan penempatan dana Lembaga Penjamin Simpanan untuk pencairan dana dan mendapatkan manfaat keuangan untuk diri sendiri. (4) Larangan pencairan dana sebagaimana dimaksud pada ayat (3) tidak berlaku untuk pembayaran gaji pegawai Bank Sistemik. 14. Ketentuan . . . jdih.kemenkeu.go.id REPUBUK INDONESIA 14. Ketentuan Bagian Keempat Bab III diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "36C", "b": "Bagian Keenam", "t": "(1) Dalam hal terjadi ancaman krisis yang berpotensi mengakibatkan merosotnya kepercayaan masyarakat terhadap perbankan dan membahayakan Stabilitas Sistem Keuangan, Lembaga Penjamin Simpanan dapat memberikan penjaminan terhadap seluruh simpanan milik Pemerintah pada Bank dalam rangka pelaksanaan kebijakan penanganan permasalahan perekonomian nasional. (2) Besaran nilai simpanan milik Pemerintah yang dijamin oleh Lembaga Penjamin Simpanan sebagaimana dimaksud pada ayat (1) ditetapkan dengan Peraturan Pemerintah. 29. Ketentuan Pasal 41 diubah sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "46A", "b": "BAB IVA SANKS! ADMINISTRATIF", "t": "(1) Bank umum yang melanggar ketentuan kewajiban: a. penyusunan rencana aksi pemulihan untuk disetujui Otoritas Jasa Keuangan sebagaimana dimaksud dalam Pasal 18A ayat (1); dan b. melaksanakan perintah Otoritas Jasa Keuangan sebagaimana dimaksud dalam Pasal 16C ayat (7), dikenai sanksi administratif oleh Otoritas Jasa Keuangan berupa teguran tertulis, denda administratif, dan/ atau bunga. (2) Sanksi administratif sebagaimana dimaksud pada ayat (1) dikenai sesuai dengan tingkat pelanggaran yang dilakukan. (3) Ketentuan lebih lanjut mengenai sanksi administratif sebagaimana dimaksud pada ayat (1) dan ayat (2) diatur dalam Peraturan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "468", "b": "BAB IVA SANKS! ADMINISTRATIF", "t": "(1) Bank umum yang melanggar ketentuan kewajiban: a. penyampaian ... jdih.kemenkeu.go.id REPUBUK INDONESIA a. penyampaian rencana resolusi sebagaimana dimaksud dalam Pasal 18B ayat (1); dan/atau b. penyampaian rencana aksi pemulihan, data dan informasi serta dokumen lainnya yang dibutuhkan dalam rangka penyusunan rencana resolusi sebagaimana dimaksud dalam Pasal 18C ayat (3), dikenai sanksi administratif oleh Lembaga Penjamin Simpanan berupa denda. (2) Ketentuan lebih lanjut mengenai besaran dan jangka waktu pengenaan serta tata cara pengenaan sanksi administratif untuk pelanggaran kewajiban sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Lembaga Penjamin Simpanan. 33. Di antara Pasal 4 7 dan Pasal 48 disisipkan 1 (satu) pasal, yakni Pasal 4 7 A sehingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "277", "b": "BAB XXII LEMBAGA PEMBIAYMN EKSPOR INDONESIA", "t": "Dalam rangka menunjang kebijakan Pemerintah untuk mendorong program ekspor nasional, Undang-Undang ini mengubah dan/atau menetapkan pengaturan baru beberapa ketentuan yang diatur dalam Undang-Undang Nomor 2 Tahun 2009 tentang Lembaga Pembiayaan Ekspor Indonesia (Lembaran Negara Republik Indonesia Tahun 2009 Nomor 2, Pasal 278 ... jdih.kemenkeu.go.id REPUBUK INDONESIA"}, {"l": "UU 4/2023", "p": "278", "b": "BAB XXII LEMBAGA PEMBIAYMN EKSPOR INDONESIA", "t": "Ketentuan Pasal 16 dalam Undang-Undang Nomor 2 Tabun 2009 tentang Lembaga Pembiayaan Ekspor Indonesia (Lembaran Negara Republik Indonesia Tabun 2009 Nomor 2, diubab sebingga berbunyi sebagai berikut:"}, {"l": "UU 4/2023", "p": "279", "b": "Bagian Kesatu", "t": "(1) Otoritas Jasa Keuangan berwenang mengenakan sanksi administratif kepada Setiap Orang yang melakukan pelanggaran terbadap Undang-Undang ini dan peraturan pelaksanaannya. (2) Setiap Orang yang melanggar ketentuan sebagaimana dimaksud dalam Pasal 54 ayat (1), ayat (2), dan ayat (3), Pasal 55 ayat (6), ayat (8), dan ayat (9), Pasal 56 ayat (5) dan ayat (6), Pasal 58 ayat (3), Pasal 60 ayat (9), Pasal 61 ayat (2), Pasal 64 ayat (2) dan ayat (3), Pasal 65 ayat (5), Pasal 67 ayat (2), Pasal 70 ayat (4), Pasal 71 ayat (1), Pasal 75 ayat (2), Pasal 76 ayat (1), Pasal 77 ayat (4) dan ayat (10), Pasal 78 ayat (3), dan Pasal 317 ayat (9) dan ayat (11) dikenai sanksi administratif. (3) Sanksi ... jdih.kemenkeu.go.id REPUBUK INDONESIA (3) Sanksi administratif sebagaimana dimaksud pada ayat {2) berupa: a. peringatan tertulis; b. penurunan tingkat kesehatan perusahaan; c. pembatasan kegiatan usaha, untuk sebagian atau seluruh kegiatan usaha; d. larangan untuk memasarkan produk asuransi untuk lini usaha tertentu; e. larangan menjadi: 1. pemegang saham, Pengendali, direksi, dewan komisaris, atau yang setara dengan pemegang saham, Pengendali, direksi, dan dewan komisaris pada badan hukum …"}, {"l": "UU 4/2023", "p": "280", "b": "Bagian Kedua", "t": "(1) Lembaga Penjamin Simpanan berwenang mengenakan sanksi administratif berupa denda administratif kepada Perusahaan Asuransi dan Perusahaan Asuransi Syariah yang melanggar ketentuan sebagaimana dimaksud dalam Pasal 81 ayat (1) huruf c dan huruf d. (2) Perusahaan ... jdih.kemenkeu.go.id (2) Perusahaan Asuransi dan Perusahaan Asuransi Syariah wajib memenuhi denda administratif sebagaimana dimaksud pada ayat (1) untuk jangka waktu paling lama 12 (dua belas bulan). (3) Ketentuan lebih lanjut mengenai besaran denda administratif sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Pemerintah. (4) Ketentuan lebih lanjut mengenai tata cara pengenaan sanksi administratif sebagaimana dimaksud pada ayat (1) diatur dalam Peraturan Lembaga Penjamin Simpanan."}, {"l": "UU 4/2023", "p": "281", "b": "Bagian Kedua", "t": "Lembaga Penjamin Simpanan menyampaikan informasi kepada Otoritas Jasa Keuangan mengenai Perusahaan Asuransi dan Perusahaan Asuransi Syariah yang tidak memenuhi ketentuan sebagaimana dimaksud dalam Pasal 81 dan Pasal 280."}, {"l": "UU 4/2023", "p": "282", "b": "Bagian Ketiga", "t": "(1) Setiap Orang yang melanggar ketentuan sebagaimana dimaksud dalam Pasal 110, Pasal 111 ayat (1), Pasal 112 ayat (2) huruf a, Pasal 116 ayat (1) dan ayat (2), Pasal 117, Pasal 121 ayat (1), Pasal 122 ayat (1) dan ayat (2), Pasal 123 ayat (1), Pasal 126 ayat (1), Pasal 127 ayat (2) dan ayat (3), dan Pasal 128 ayat (2) dikenai sanksi administratif berupa: a. peringatan tertulis; b. pembekuan sebagian atau seluruh kegiatan usaha; c. pembatasan kegiatan usaha tertentu; d. penurunan basil penilaian tingkat risiko; e. pembatalan persetujuan; f. larangan menjadi PSP, direksi, Dewan Pengawas Syariah, dewan komisaris, pengawas, dan/ atau pengurus Usaha Jasa Pembiayaan; g. denda administratif; h. pencabutan ... jdih.kemenkeu.go.id REPUBUK INDONESIA h. pencabutan izin unit usaha syariah; dan/ atau i. pencabutan izin usaha. (2) Pengenaan sanksi administratif sebagaimana dimaksud pada ayat (1) diberlakukan sesuai dengan tingkat pelanggaran yang dilakukan. (3) Ketentuan lebih lanjut mengenai tata cara pengenaan sanksi administratif sebagaimana dimaksud pada ayat (1) dan ayat (2) diatur dalam Peraturan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "283", "b": "Bagian Keempat", "t": "(1) Setiap Orang yang melanggar ketentuan sebagaimana dimaksud dalam Pasal 206 ayat (1), Pasal 208 ayat (1), Pasal 209 ayat (1), dan Pasal 210 ayat (2) dikenai sanksi administratif berupa: a. peringatan tertulis; b. perintah penggantian manajemen; c. penilaian kembali kemampuan dan kepatutan; d. pembatasan kegiatan usaha Konglomerasi Keuangan; e. pengurangan kepemilikan saham pada WK yang dikendalikan; f. denda administratif; dan/ a tau g. pembatalan persetujuan, pendaftaran, dan pengesahan. (2) Pengenaan sanksi administratif sebagaimana dimaksud pada ayat (1) diberlakukan sesuai dengan tingkat pelanggaran yang dilakukan. (3) Ketentuan lebih lanjut mengenai tata cara pengenaan sanksi administratif sebagaimana dimaksud pada ayat (1) dan ayat (2) diatur dalam Peraturan Otoritas Jasa Keuangan."}, {"l": "UU 4/2023", "p": "284", "b": "Bagian Kelima", "t": "(1) Penyelenggara ITSK yang: a. telah memperoleh perizinan dari otoritas sektor keuangan terkait yang melakukan kegiatan tidak sesuai dengan perizinannya; dan/ atau b. melanggar ketentuan sebagaimana dimaksud dalam Pasal 220 ayat (1) dan Pasal 221 ayat ( 1), dikenai sanksi administratif oleh otoritas sektor keuangan sesuai dengan kewenangan masing-masing. (2) Sanksi sebagaimana dimaksud pada ayat (1) berupa: a. peringatan tertulis; b. penurunan tingkat kesehatan; c. penghentian sementara, sebagian, atau seluruh kegiatan termasuk pelaksanaan kerja sama; d. denda administratif; e. pembatalan persetujuan; f. pembatalan pendaftaran; g. pemberhentian dan/atau penggantian pengurus; h. pencantuman anggota pengurus, pegawai, pemegang saham dalam daftar orang tercela di sektor keuangan; dan/atau 1. pencabutan izin. (3) Pengenaan sanksi sebagaimana dimaksud pada ayat (2) diberlakukan sesuai dengan tingkat pelanggaran yang dilakukan. (4) Ketentuan lebih lanjut mengenai jenis, kriteria, dan tata cara pengenaan sanksi sebagaimana dimaksud pada ayat (1) sampai dengan ayat (3) diatur dalam peraturan otoritas sektor keuangan sesuai dengan kewenangan masing-masing."}, {"l": "UU 4/2023", "p": "286", "b": "Bagian Ketujuh", "t": "PUSK, Pelaku Profesi Sektor Keuangan, Asosiasi Profesi, dan/ atau Lembaga Sertifikasi Profesi yang melanggar ketentuan sebagaimana dimaksud dalam Pasal 252 ayat (3), Pasal 255, Pasal 258, Pasal 259 ayat (2) dan ayat (5), Pasal 260 ayat (3), Pasal 261 ayat (1) dan ayat (3), Pasal 262, Pasal 266, Pasal 267, Pasal 268, serta Pasal 271 ayat (2) dan ayat (7) dikenai sanksi administratif oleh menteri, lembaga, atau otoritas terkait sesuai dengan kewenangan masing-masing."}, {"l": "UU 4/2023", "p": "288", "b": "Bagian Kesatu", "t": "(1) Setiap Orang yang melakukan kegiatan usaha penukaran valuta asing tanpa izin dari Bank Indonesia sebagaimana dimaksud dalam Pasal 50 ayat (2) dipidana dengan pidana penjara paling singkat 1 (satu) tahun dan paling lama 5 (lima) tahun dan pidana denda paling sedikit Rp50.000.000,00 (lima puluh juta rupiah) dan paling banyak Rp2.000.000.000,00 (dua miliar rupiah). (2) Dalam hal kegiatan sebagaimana dimaksud pada ayat (1) dilakukan oleh korporasi atau badan usaha baik yang berbentuk badan hukum maupun yang tidak berbentuk badan hukum, atau badan lainnya, penjatuhan pidana terhadap badan dilakukan baik kepada yang memberi perintah melakukan perbuatan itu maupun kepada yang bertindak sebagai pimpinan dalam perbuatan itu atau terhadap keduanya."}, {"l": "UU 4/2023", "p": "290", "b": "Bagian Kedua", "t": "Badan pengelola instrumen keuangan (special purpose vehicle) dan/atau pengelola dana perwalian (trustee) yang dengan sengaja: a. melanggar ketentuan sebagaimana dimaksud dalam Pasal 35 ayat (3); dan/atau b. tidak ... jdih.kemenkeu.go.id . REPUBUK INDONESIA b. tidak melaksanakan langkah yang diperlukan untuk memastikan ketaatan sebaga imana dimaksud dalam Pasal 35 ayat (4), dipidana dengan pidana penjara paling singkat 3 (tiga) tahun dan paling lama 5 (lima) tahun dan pidana denda paling sedikit Rp500.000.000,00 (lima ratus juta rupiah) dan paling banyak Rp2.000.000.000,00 (dua miliar rupiah)."}, {"l": "UU 4/2023", "p": "291", "b": "Bagian Kedua", "t": "Pemegang saham badan pengelola instrumen keuangan (special purpose vehicle) dan/ atau pengelola dana perwalian (trustee) yang dengan sengaja melanggar ketentuan sebagaimana dimaksud dalam Pasal 35 ayat (5) dipidana dengan pidana penjara paling singkat 1 (satu) tahun dan paling lama 3 (tiga) tahun dan pidana denda paling sedikit Rpl00.000.000,00 (seratus juta rupiah) dan paling banyak Rpl .500.000.000,00 (satu miliar lima ratus juta rupiah)."}, {"l": "UU 4/2023", "p": "292", "b": "Bagian Kedua", "t": "Badan pengelola instrumen keuangan (special purpose vehicle) dan/ atau pengelola dana perwalian (trustee) yang dengan sengaja melanggar ketentuan sebagaimana dimaksud dalam Pasal 35 ayat (6) dipidana dengan pidana penjara paling singkat 1 (satu) tahun dan paling lama 5 (lima) tahun dan pidana denda paling sedikit Rp200.000.000,00 (dua ratus juta rupiah) dan paling banyak Rpl.000.000.000,00 (satu miliar rupiah)."}, {"l": "UU 4/2023", "p": "293", "b": "Bagian Kedua", "t": "(1) Tindak pidana yang dilakukan oleh badan pengelola instrumen keuangan (special purpose vehicle) dan/ atau pengelola dana perwalian (trustee) sebagai korporasi atau badan usaha baik yang berbentuk badan hukum maupun tidak berbentuk badan hukum, atau badan lainnya, tuntutan dan sanksi pidana dijatuhkan terhadap: a. badan pengelola instrumen keuangan (special purpose vehicle) dan/ a tau pengelola dana perwalian (trustee) sebagai badan usaha baik yang berbentuk badan hukum maupun tidak berbentuk badan hukum, a tau badan lainnya; dan/ a tau b. orang ... jdih.kemenkeu.go.id REPUBUK INDONESIA b. orang perseorangan yang memberi perintah untuk melakukan dan/ a tau yang bertindak sebagai pemimpin dalam tindak pidana dimaksud. (2) Terhadap badan pengelola instrumen keuangan (special purpose vehicle) dan/ atau pengelola dana perwalian (trustee) sebagai badan usaha baik yang berbentuk badan hukum maupun tidak berbentuk badan hukum, atau badan lainnya sebagaimana dimaksud pada ayat (1) huruf a dipidana dengan pidana denda paling sedikit RpS00.000.000,00 (lima ratus juta rupiah) dan paling banyak Rpl0.000.000.000.000,00 (sepuluh triliun rupiah)."}, {"l": "UU 4/2023", "p": "294", "b": "Bagian Ketiga", "t": "(1) Anggota direksi, anggota dewan komisaris, dan/atau pemegang saham, atau yang setara dengan anggota direksi, anggota dewan komisaris, dan/ a tau pemegang saham pada badan hukum berbentuk koperasi atau Usaha Bersama, serta Pengendali a tau pegawai Perusahaan Asuransi atau Perusahaan Asuransi Syariah yang tidak memenuhi ketentuan sebagaimana dimaksud dalam Pasal 81 ayat (1) huruf a, huruf b, huruf e, atau huruf f, a tau Pasal 280 ayat (2) dan/ atau menyebabkan Perusahaan Asuransi atau Perusahaan Asuransi Syariah yang melanggar ketentuan sebagaimana dimaksud dalam Pasal 81 ayat (1) huruf a, huruf b, huruf e, atau huruf f, atau Pasal 280 ayat (2) dipidana dengan pidana penjara paling singkat 2 (dua) tahun dan paling lama 10 (sepuluh) tahun dan pidana denda paling sedikit Rp2.000.000.000,00 (dua miliar rupiah) dan paling banyak Rp3.000.000.000,00 (tiga miliar rupiah). (2) Anggota ... jdih.kemenkeu.go.id REPUBUK INDONESIA (2) Anggota direksi, anggota dewan komisaris, dan/ atau pemegang saham atau yang setara dengan anggota direksi, anggota dewan komisaris, dan/ atau pemegang saham pada badan hukum berbentuk koperasi atau Usaha Bersama, serta Pengendali atau pegawai Perusahaan …"}, {"l": "UU 4/2023", "p": "295", "b": "Bagian Ketiga", "t": "Anggota direksi, anggota dewan komisaris, dan/ a tau pemegang saham, atau yang setara dengan anggota direksi, anggota dewan komisaris, dan/ atau pemegang saham pada badan hukum berbentuk koperasi a tau Usaha Bersama, serta Pengendali, pegawai, atau mantan pegawai Perusahaan Asuransi atau Perusahaan Asuransi Syariah dalam likuidasi yang melanggar ketentuan sebagaimana dimaksud dalam Pasal 97 ayat (1) atau ayat (2) dipidana dengan pidana penjara paling singkat 1 (satu) tahun dan paling lama 3 (tiga) tahun dan pidana denda paling sedikit Rp2.000.000.000,00 (dua miliar rupiah) dan paling banyak Rp3.000.000.000,00 (tiga miliar rupiah)."}, {"l": "UU 4/2023", "p": "296", "b": "Bagian Ketiga", "t": "Setiap Orang yang memberikan dokumen, data, informasi, dan/ a tau laporan yang berkaitan dengan penjaminan polis sebagaimana dimaksud dalam Pasal 81 ayat (1) huruf a, huruf d, atau huruf e, atau Pasal 89 ayat (2) yang tidak benar, palsu, dan/atau menyesatkan dipidana dengan pidana penjara paling singkat 1 (satu) tahun dan paling lama 3 (tiga) tahun dan pidana denda paling sedikit Rp2.000.000.000,00 (dua miliar rupiah) dan paling banyak Rp3.000.000.000,00 (tiga miliar rupiah). Pasal 297 ... jdih.kemenkeu.go.id REPUBUK INOONESIA"}, {"l": "UU 4/2023", "p": "297", "b": "Bagian Ketiga", "t": "Setiap Orang yang menolak memberikan data, informasi, dan/atau dokumen kepada Lembaga Penjamin Simpanan sebagaimana dimaksud dalam Pasal 89 ayat (2) dipidana dengan pidana penjara paling singkat 1 (satu) tahun dan paling lama 3 (tiga) tahun, dan pidana denda paling sedikit Rp2.000.000.000,00 (dua miliar rupiah) dan paling banyak Rp3.000.000.000,00 (tiga miliar rupiah)."}, {"l": "UU 4/2023", "p": "299", "b": "Bagian Keempat", "t": "(1) Anggota dewan komisaris, anggota pengawas, anggota direksi, anggota pengurus, pengelola, pegawai, dan/ atau pihak terafiliasi penyelenggara Usaha Jasa Pembiayaan yang: a. membuat pencatatan palsu dalam pembukuan atau laporan keuangan dan/ a tau tanpa didukung dengan dokumen yang sah; b. menghilangkan atau tidak memasukkan informasi yang benar dalam laporan kegiatan usaha dan laporan keuangan; dan/ a tau c. mengubah, mengaburkan, menyembunyikan, menghapus, dan/atau menghilangkan suatu pencatatan dalam pembukuan atau dalam laporan keuangan, dan dalam dokumen atau laporan kegiatan usaha, sebagaimana ... jdih.kemenkeu.go.id . REPUBUK INDONESIA sebagaimana dimaksud dalam Pasal 118 ayat (1) dipidana dengan pidana penjara paling singkat 1 (satu) tahun dan paling lama 3 (tiga) tahun dan pidana denda paling sedikit Rpl.000.000.000,00 (satu miliar rupiah) dan paling banyak Rp5.000.000.000,00 (lima miliar rupiah). (2) Dalam hal tindakan sebagaimana dimaksud pada ayat (1) mengakibatkan kerugian terhadap harta benda atau kerusakan barang, selain dipidana dengan pidana penjara dan pidana denda sebagaimana dimaksud pada ayat (1), pelaku juga dipidana dengan pidana tambahan berupa penggantian …"}, {"l": "UU 4/2023", "p": "300", "b": "Bagian Keempat", "t": "(1) Anggota dewan komisaris, anggota pengawas, anggota direksi, anggota pengurus, pengelola, pegawai, dan/atau pihak terafiliasi penyelenggara Usaha Jasa Pembiayaan yang: a. meminta atau menerima suatu imbalan di luar biaya resmi, berupa uang atau barang untuk keuntungan pribadi atau keluarganya; b. menjadikan orang lain mendapatkan uang muka atau fasilitas pembiayaan dari Usaha Jasa Pembiayaan; c. memberikan atau menyebabkan persetujuan bagi orang lain untuk melaksanakan penarikan dana yang melebihi batas pembiayaan pada Usaha Jasa Pembiayaan; dan/atau d. tidak melaksanakan langkah yang diperlukan untuk memastikan ketaatan Usaha Jasa Pembiayaan terhadap ketentuan dalam Undang-Undang ini dan ketentuan peraturan perundang-undangan lainnya yang berlaku bagi Usaha Jasa Pembiayaan, sebagaimana dimaksud dalam Pasal 118 ayat (2) huruf a sampai dengan huruf d dipidana dengan pidana penjara paling singkat 1 (satu) tahun dan paling lama 3 (tiga) tahun dan pidana denda paling sedikit Rpl.000.000.000,00 (satu miliar rupiah) dan paling banyak Rp5.000.000.000,00 (lima miliar rupiah). (2) Dalam hal tindakan sebagaimana dimaksud pada ayat (1) mengakibatkan kerugian terhadap harta benda atau …"}, {"l": "UU 4/2023", "p": "301", "b": "Bagian Keempat", "t": "(1) Pemegang saham dan/atau pihak terafiliasi Usaha Jasa Pembiayaan yang menyuruh anggota dewan komisaris, anggota pengawas, anggota direksi, anggota pengurus, pengelola, pegawai penyelenggara Usaha Jasa Pembiayaan, dan/atau pihak terafiliasi lainnya untuk melakukan atau tidak melakukan tindakan yang mengakibatkan Usaha Jasa Pembiayaan tidak melaksanakan langkah yang diperlukan untuk memastikan ketaatan Usaha Jasa Pembiayaan terhadap ketentuan dalam Undang-Undang ini dan ketentuan peraturan perundang-undangan lainnya bagi Usaha Jasa Pembiayaan sebagaimana dimaksud dalam Pasal 118 ayat (3) dipidana dengan pidana penjara paling singkat 1 (satu) tahun dan paling lama 3 (tiga) tahun dan pidana denda paling sedikit Rpl.000.000.000,00 (satu miliar rupiah) dan paling banyak Rp5.000.000.000,00 (lima miliar rupiah). (2) Dalam ... jdih.kemenkeu.go.id R£PUBUK INDONESIA (2) Dalam hal tindakan sebagaimana dimaksud pada ayat (1) mengakibatkan kerugian terhadap harta benda atau kerusakan barang, selain dipidana dengan pidana penjara dan pidana denda sebagaimana dimaksud pada ayat (1), pelaku juga dipidana dengan pidana tambahan berupa penggantian kerugian atas harta benda atau kerusakan barang. …"}, {"l": "UU 4/2023", "p": "302", "b": "Bagian Keempat", "t": "(1) Anggota dewan komisaris, anggota pengawas, anggota direksi, anggota pengurus, pengelola, pegawai, dan / a tau pihak terafiliasi penyelenggara Usaha Jasa Pembiayaan yang memberikan laporan, informasi, data, dan/atau dokumen kepada Otoritas Jasa Keuangan secara tidak benar, palsu, dan/ atau menyesatkan sebagaimana dimaksud dalam Pasal 118 ayat (2) huruf e dipidana dengan pidana penjara paling singkat 1 (satu) tahun dan paling lama 3 (tiga) tahun dan pidana denda paling sedikit Rpl.000.000.000,00 (satu miliar rupiah) dan paling banyak RpS.000.000.000,00 (lima miliar rupiah). (2) Dalam hal tindakan sebagaimana dimaksud pada ayat (1) mengakibatkan kerugian terhadap harta benda atau kerusakan barang, selain dipidana dengan pidana penjara dan pidana denda sebagaimana dimaksud pada ayat (1), pelaku juga dipidana dengan pidana tambahan berupa penggantian kerugian atas harta benda atau kerusakan barang. (3) Pidana tambahan berupa penggantian kerugian atas harta benda atau kerusakan barang sebagaimana dimaksud pada ayat (2) dikembalikan kepada pihak yang dirugikan. (4) Penggantian kerugian sebagaimana dimaksud pada ayat (3) dapat berupa: a. sejumlah kerugian yang diderita; atau b. secara …"}, {"l": "UU 4/2023", "p": "303", "b": "Bagian Kelima", "t": "WK yang menjalankan kegiatan usaha bulion (bullion) tanpa izin usaha dari Otoritas Jasa Keuangan sebagaimana dimaksud dalam Pasal 131 dipidana dengan pidana penjara paling singkat 5 (lima) tahun dan paling lama 15 (lima belas) tahun dan pidana denda paling sedikit RpS0.000.000.000,00 (lima puluh miliar rupiah) dan paling banyak Rp600.000.000.000,00 (enam ratus miliar rupiah)."}, {"l": "UU 4/2023", "p": "304", "b": "Bagian Keenam", "t": "Setiap Orang yang melanggar ketentuan perizinan sebagaimana dimaksud dalam Pasal 218 dipidana dengan pidana penjara paling singkat 5 (lima) tahun dan paling lama 10 (sepuluh) tahun dan pidana denda paling sedikit Rpl.000.000.000,00 (satu miliar rupiah) dan paling banyak Rpl.000.000.000.000,00 (satu triliun rupiah)."}, {"l": "UU 4/2023", "p": "305", "b": "Bagian Ketujuh", "t": "(1} Setiap Orang yang dengan sengaja melanggar ketentuan sebagaimana dimaksud dalam Pasal 237 diancam dengan pidana penjara paling singkat 5 (lima} tahun dan paling lama 10 (sepuluh} tahun dan pidana denda paling sedikit Rpl.000.000.000,00 (satu miliar rupiah} dan paling banyak Rpl.000.000.000.000,00 (satu triliun rupiah}. (2} Dalam hal kegiatan sebagaimana dimaksud pada ayat (1} dilakukan oleh badan hukum yang berbentuk perseroan terbatas, penjatuhan pidana dilakukan terhadap badan hukum, pihak yang memberi perintah melakukan perbuatan itu, dan/ a tau yang memimpin perbuatan itu."}, {"l": "UU 4/2023", "p": "306", "b": "Bagian Ketujuh", "t": "(1) PUSK yang melanggar ketentuan sebagaimana dimaksud dalam Pasal 236 ayat (3) huruf c, huruf f, huruf g, huruf h, huruf i, huruf 1, atau huruf m, atau ayat (4) huruf a, huruf b, huruf d, huruf e, atau huruf f, atau Pasal 238 ayat (4) dipidana dengan pidana penjara paling singkat 2 (dua) tahun dan paling lama 10 (sepuluh) tahun dan pidana denda paling sedikit Rp25.000.000.000,00 (dua puluh lima miliar rupiah) dan paling banyak Rp250.000.000.000,00 (dua ratus lima puluh miliar rupiah). (2) Dalam hal sanksi administratif sebagaimana dimaksud dalam Pasal 285 ayat (4) tidak dilaksanakan pada batas pemenuhan jangka waktu tertentu sebagaimana dimaksud dalam Pasal 285 ayat (5), PUSK dipidana dengan pidana penjara paling singkat 2 (dua) tahun dan paling lama 10 (sepuluh) tahun dan pidana denda paling sedikit Rp25.000.000.000,00 (dua puluh lima miliar rupiah) dan paling banyak Rp250.000.000.000,00 (dua ratus lima puluh miliar rupiah). BABXXV ... jdih.kemenkeu.go.id REPUBUK INDONESIA BABXXV KETENTUAN LAIN-LAIN Pasal307 Dalam rangka pengembangan dan penguatan sektor keuangan, Pemerintah dapat memberikan perlakuan dan/atau insentif perpajakan atas penyelenggaraan jasa keuangan tertentu dan/ …"}, {"l": "UU 4/2023", "p": "308", "b": "Bagian Kesatu", "t": "(1) Pada saat Undang-Undang ini mulai berlaku, berdasarkan Undang-Undang ini: a. Kepala Eksekutif Lembaga Penjamin Simpanan ditetapkan menjadi Wakil Ketua Dewan Komisioner Lembaga Penjamin Simpanan; dan b. anggota Dewan Komisioner Lembaga Penjamin Simpanan selain Ketua Dewan Komisioner dan Kepala Eksekutif Lembaga Penjamin Simpanan ditetapkan menjadi anggota Dewan Komisioner yang membidangi Penjaminan dan resolusi Bank. (2) Masa jabatan: a. Wakil Ketua Dewan Komisioner Lembaga Penjamin Simpanan sebagaimana dimaksud pada ayat (1) huruf a melanjutkan sisa masa jabatan sebagai Kepala Eksekutif Lembaga Penjamin Simpanan; dan b. anggota Dewan Komisioner yang membidangi Penjaminan dan resolusi Bank sebagaimana dimaksud pada ayat (1) huruf b melanjutkan sisa masa jabatan sebagai anggota Dewan Komisioner Lembaga Penjamin Simpanan. Pasal 309 ... jdih.kemenkeu.go.id REPUBUK INDONESIA ."}, {"l": "UU 4/2023", "p": "309", "b": "Bagian Kesatu", "t": "Waldl Ketua Dewan Komisioner Lembaga Penjamin Simpanan menjalankan tugas dan wewenang sebagai Kepala Eksekutif sampai dengan ditetapkannya Peraturan Dewan Komisioner sebagaimana dimaksud dalam Pasal 63 ayat (5) dalam Pasal 7 angka 37 Undang-Undang ini."}, {"l": "UU 4/2023", "p": "310", "b": "Bagian Kesatu", "t": "Pada saat Undang-Undang ini mulai berlaku: a. Kepala Eksekutif Pengawas Perasuransian, Dana Pensiun, Lembaga Pembiayaan, dan Lembaga Jasa Keuangan Lainnya berdasarkan Undang-Undang ini ditetapkan menjadi Kepala Eksekutif Pengawas Perasuransian, Penjaminan, dan Dana Pensiun. b. Masa jabatan Kepala Eksekutif Pengawas Perasuransian, Penjaminan, dan Dana Pensiun sebagaimana dimaksud dalam huruf a melanjutkan sisa masa jabatan sebagai Kepala Eksekutif Pengawas Perasuransian, Dana Pensiun, Lembaga Pembiayaan, dan Lembaga Jasa Keuangan Lainnya."}, {"l": "UU 4/2023", "p": "311", "b": "Bagian Kesatu", "t": "Sampai dengan diangkat dan ditetapkannya pejabat definitif: a. Kepala Eksekutif Pengawas Lembaga Pembiayaan, Perusahaan Modal Ventura, Lembaga Keuangan Mikro, dan Lembaga Jasa Keuangan Lainnya; dan b. Kepala Eksekutif Pengawas Inovasi Teknologi Sektor Keuangan, Aset Keuangan Digital dan Aset Kripto, tugas dan wewenangnya dilaksanakan oleh Kepala Eksekutif Pengawas Perasuransian, Penjaminan, dan Dana Pensiun."}, {"l": "UU 4/2023", "p": "312", "b": "Bagian Kesatu", "t": "(1) Pada saat Undang-Undang ini mulai berlaku, peralihan tugas pengaturan dan pengawasan terhadap kegiatan: a. aset keuangan digital sebagaimana dimaksud dalam Pasal 6 ayat (1) huruf b dan huruf e dalam Pasal 8 Angka 4 Undang-Undang ini; dan b. komoditi ... jdih.kemenkeu.go.id REPUBUK INDONESIA . b. komoditi yang termasuk instrumen keuangan yang dijadikan subjek kontrak berjangka, kontrak derivatif syariah, dan/ atau kontrak derivatif lainnya sebagaimana dimaksud dalam Pasal 3A dalam Pasal 20 Undang-Undang ini, dari badan pengawas perdagangan berjangka komoditi kepada otoritas sektor keuangan harus diselesaikan secara penuh paling lambat 24 (dua puluh empat) bulan. (2) Ketentuan lebih lanjut mengenai peralihan tugas pengaturan dan pengawasan sebagaimana dimaksud pada ayat (1), diatur dalam Peraturan Pemerintah yang harus ditetapkan paling lambat 6 (enam) bulan terhitung sejak Undang-Undang ini diundangkan."}, {"l": "UU 4/2023", "p": "313", "b": "Bagian Kesatu", "t": "Anggota Badan Supervisi Bank Indonesia yang telah diangkat dan ditetapkan sebelum Undang-Undang ini diundangkan, tetap menjalankan tugas dan wewenangnya sampai dengan masa jabatannya berakhir."}, {"l": "UU 4/2023", "p": "314", "b": "Bagian Kedua", "t": "Pada saat Undang-Undang ini mulai berlaku: a. Nomenklatur \"Bank Perkreditan Rakyat\" yang telah ada sebelum Undang-Undang ini berlaku dimaknai sama dengan \"Bank Perekonomian Rakyat\" sebagaimana dimaksud dalam Undang-Undang ini. b. Nomenklatur \"Bank Pembiayaan Rakyat Syariah\" yang telah ada sebelum Undang-Undang ini berlaku dimaknai sama dengan \"Bank Perekonomian Rakyat Syariah\" sebagaimana dimaksud dalam Undang-Undang ini. c. Perubahan nomenklatur \"Bank Perkreditan Rakyat\" menjadi \"Bank Perekonomian Rakyat\" dan \"Bank Pembiayaan Rakyat Syariah\" menjadi \"Bank Perekonomian Rakyat Syariah\" dilakukan paling lama 2 (dua) tahun terhitung sejak Undang-Undang ini diundangkan. d. Bank ... jdih.kemenkeu.go.id REPUBUK INDONESIA d. Bank Perkreditan Rakyat yang berbentuk badan hukum selain perseroan terbatas atau koperasi yang telah ada berdasarkan peraturan perundang-undangan sebelum berlakunya Undang-Undang ini masih tetap dapat melakukan kegiatan usaha sebagai Bank Perkreditan Rakyat dan diberikan kesempatan paling lama 3 (tiga) tahun untuk melakukan perubahan bentuk badan hukum sesuai dengan Undang-Undang ini."}, {"l": "UU 4/2023", "p": "315", "b": "Bagian Ketiga", "t": "( 1) Setiap Pihak yang telah memiliki saham dan / a tau melakukan tindakan pengendalian pada lebih dari 1 (satu) perusahaan efek berdasarkan undang-undang mengenai pasar modal wajib menyesuaikan dengan Undang-Undang ini paling lama 3 (tiga) tahun terhitung sejak Undang- Undang ini diundangkan. (2) Perusahaan efek yang telah memperoleh izin usaha untuk melakukan kegiatan sebagai penjamin em1s1 efek dan/ atau perantara pedagang efek, atau manajer investasi sebelum berlakunya Undang-Undang m1 wajib menyesuaikan dengan Undang-Undang 1m dengan memisahkan kegiatan usahanya sebagai manajer investasi paling lama 1 (satu) tahun terhitung sejak Undang- Undang ini diundangkan."}, {"l": "UU 4/2023", "p": "316", "b": "Bagian Ketiga", "t": "Perusahaan efek yang sebelum berlakunya Undang~Undang ini dalam proses pencabutan izm usaha bukan karena pelanggaran ketentuan peraturan perundang-undangan tidak wajib melakukan pembubaran perseroan sepanjang dalam jangka waktu 6 (enam) bulan terhitung sejak berlakunya Undang-Undang ini perusahaan efek mengubah anggaran dasar yang berkaitan dengan nama dan kegiatan usaha perusahaan efek."}, {"l": "UU 4/2023", "p": "317", "b": "Bagian Keempat", "t": "(1) Polis asuransi yang dimiliki oleh pemegang polis sebelum berlakunya Undang-Undang ini dinyatakan tetap berlaku sesuai dengan ketentuan yang tercantum dalam polis asuransi. (2) Perpanjangan atas polis asuransi sebagaimana dimaksud pada ayat (1) yang dilakukan setelah berlakunya Undang­ Undang ini harus mengikuti ketentuan Undang-Undang ini dan peraturan pelaksanaannya. (3) Anggaran dasar Usaha Bersama yang telah ada sebelum diundangkannya Undang-Undang ini dinyatakan tetap berlaku sepanjang tidak bertentangan dengan ketentuan dalam Undang-Undang ini dan peraturan pelaksanaannya. (4) lzin usaha dari Usaha Bersama yang telah ada sebelum diundangkannya Undang-Undang ini dinyatakan tetap berlaku. (5) Badan Perwakilan Anggota Usaha Bersama yang telah ada pada saat Undang-Undang ini diundangkan, dinyatakan sebagai RUA dan memiliki tugas serta kewenangan sesuai dengan ketentuan dalam Undang-Undang ini dan peraturan pelaksanaannya. (6) Anggota Badan Perwakilan Anggota Usaha Bersama yang telah ada pada saat Undang-Undang ini diundangkan, dinyatakan sebagai peserta RUA. (7) Peserta RUA sebagaimana dimaksud pada ayat (6) memiliki masa tugas paling lama sampai dengan berakhimya periode …"}, {"l": "UU 4/2023", "p": "318", "b": "Bagian Kelima", "t": "Pada saat Undang-Undang ini mulai berlaku: a. Penyelenggara Usaha Jasa Pembiayaan yang telah mendapatkan izin usaha sebelum berlakunya Undang­ Undang ini, dinyatakan telah memperoleh izin usaha berdasarkan Undang-Undang ini; dan b. Penyelenggara Usaha Jasa Pembiayaan sebagaimana dimaksud dalam huruf a wajib menyesuaikan dengan ketentuan Undang-Undang ini paling lama 3 (tiga) tahun terhitung sejak Undang-Undang ini diundangkan."}, {"l": "UU 4/2023", "p": "319", "b": "Bagian Kelima", "t": "Setiap Orang di luar penyelenggara Usaha Jasa Pembiayaan yang telah melakukan kegiatan Usaha Jasa Pembiayaan sebelum berlakunya Undang-Undang ini wajib memenuhi ketentuan dalam Undang-Undang ini dalam jangka waktu paling lama 3 (tiga) tahun terhitung sejak Undang-Undang ini diundangkan."}, {"l": "UU 4/2023", "p": "320", "b": "Bagian Keenam", "t": "(1) Pada saat Undang-Undang ini mulai berlaku, bagi semua Dana Pensiun yang telah mendapatkan pengesahan dari Otoritas Jasa Keuangan, pengesahan dari Otoritas Jasa Keuangan tersebut dinyatakan tetap berlaku. (2) Dana Pensiun sebagaimana dimaksud pada ayat (1) yang menyelenggarakan Program Pensiun yang menjanjikan pembayaran uang secara sekaligus bagi peserta Program Pensiun sebelum 20 April 1992, tetap dapat melanjutkan program tersebut sampai selesainya seluruh kewajiban kepada karyawan yang telah menjadi peserta Program Pensiun pada tanggal 20 April 1992. (3) Pelaksana tugas Pengurus pada Dana Pensiun Lembaga Keuangan menjadi Pengurus Dana Pensiun Lembaga Keuangan dan dewan komisaris dari Pendiri Dana Pensiun Lembaga Keuangan bertindak sebagai Dewan Pengawas Dana Pensiun Lembaga Keuangan sampai dengan jangka waktu paling lama 2 (dua) tahun terhitung sejak Undang- Undang ini diundangkan. (4) Ketentuan sebagaimana dimaksud dalam Pasal 146, berlaku untuk Setiap Orang yang mulai menjadi Peserta Dana Pensiun terhitung sejak Undang-Undang ini diundangkan. (5) Ketentuan sebagaimana dimaksud dalam Pasal 169 ayat (3) diterapkan oleh Dana Pensiun Lembaga Keuangan paling lambat 5 (lima) …"}, {"l": "UU 4/2023", "p": "321", "b": "Bagian Ketujuh", "t": "Pada saat Undang-Undang ini mulai berlaku: a. menteri yang menyelenggarakan urusan pemerintahan di bidang koperasi harus melakukan penilaian sesuai kriteria sebagaimana dimaksud dalam Pasal 44B ayat (2) dalam Pasal 202 Undang-Undang ini; b. penilaian sebagaimana dimaksud dalam huruf a harus diselesaikan paling lambat 2 (dua) tahun terhitung sejak Undang-Undang ini diundangkan; c. koperasi sebagaimana dimaksud dalam Pasal 44B ayat (2) dalam Pasal 202 Undang-Undang ini wajib melaporkan kegiatan usahanya kepada menteri yang menyelenggarakan urusan pemerintahan di bidang koperasi; d. penyelenggaraan penilaian sebagaimana dimaksud dalam huruf a yang dilakukan oleh kementerian yang menyelenggarakan urusan pemerintahan di bidang koperasi dapat dibantu oleh Pemerintah Daerah provinsi atau Pemerintah Daerah kabupaten/kota; e. menteri yang menyelenggarakan urusan pemerintahan di bidang koperasi menyerahkan daftar koperasi sebagaimana dimaksud dalam Pasal 44B ayat (2) dalam Pasal 202 Undang-Undang ini kepada Otoritas Jasa Keuangan untuk dapat ditindaklanjuti sesuai dengan ketentuan undang-undang mengenai sektor jasa keuangan; f. Otoritas Jasa Keuangan memproses perizinan usaha yang diajukan …"}, {"l": "UU 4/2023", "p": "322", "b": "Bagian Kedelapan", "t": "Pada saat Undang-Undang ini mulai berlaku: a. LKM yang telah mendapatkan izin usaha sebelum berlakunya Undang-Undang m1, dinyatakan telah memperoleh izin usaha berdasarkan Undang-Undang ini; b. LKM sebagaimana dimaksud dalam huruf a wajib menyesuaikan dengan ketentuan Undang-Undang ini paling lama 3 (tiga) tahun terhitung sejak Undang-Undang ini diundangkan; c. LKM yang menghimpun dana masyarakat dan belum memiliki izin usaha harus mengajukan izin usaha kepada Otoritas Jasa Keuangan sebagai LKM skala usaha kecil, menengah atau besar paling lama 3 (tiga) tahun terhitung sejak Undang-Undang ini diundangkan; dan d. LKM yang tidak menghimpun dana masyarakat dan belum memiliki izin usaha harus melakukan pendaftaran kepada Pemerintah Daerah kabupaten/kota sebagai LKM inkubasi paling lama 3 (tiga) tahun terhitung sejak Undang-Undang ini diundangkan."}, {"l": "UU 4/2023", "p": "324", "b": "Bagian Kesepuluh", "t": "Ketentuan mengenai pelaporan keuangan sebagaimana dimaksud dalam Pasal 271 ayat (1) dilakukan oleh PUSK dan pihak yang melakukan interaksi bisnis dengan sektor keuangan dilaksanakan paling lambat 3 (tiga) tahun terhitung sejak Undang-Undang ini diundangkan."}, {"l": "UU 4/2023", "p": "326", "b": "BAB XXVII KETENTUAN PENUTUP", "t": "Pada saat Undang-Undang ini mulai berlaku, semua peraturan perundang-undangan yang merupakan peraturan pelaksanaan dari: a. Undang-Undang Nomor 7 Tahun 1992 tentang Perbankan (Lembaran Negara Republik Indonesia Tahun 1992 Nomor 31, Tambahan Lembaran Negara Republik Indonesia Nomor 3472) sebagaimana telah beberapa kali diubah terakhir dengan Peraturan Pemerintah Pengganti Undang-Undang Nomor 2 Tahun 2022 tentang Cipta Kerja (Lembaran Negara Republik Indonesia Tahun 2022 Nomor 238, Tambahan Lembaran Negara Republik Indonesia Nomor 6841); b. Undang-Undang ... jdih.kemenkeu.go.id REPUBUK INDONESIA b. Undang-Undang Nomor 11 Tahun 1992 tentang Dana Pensiun (Lembaran Negara Republik Indonesia Tahun 1992 Nomor 37, Tambahan Lembaran Negara c. Undang-Undang Nomor 25 Tahun 1992 tentang Perkoperasian (Lembaran Negara Republik Indonesia Tahun 1992 Nomor 116, Tambahan Lembaran Negara diubah dengan Peraturan Pemerintah Pengganti Undang- Undang Nomor 2 Tahun 2022 tentang Cipta Kerja (Lembaran Negara Republik Indonesia Tahun 2022 Nomor 238, Tambahan Lembaran Negara Republik Indonesia Nomor 6841); d. Undang-Undang Nomor 8 Tahun 1995 tentang Pasar Modal (Lembaran Negara Republik Indonesia Tahun 1995 …"}, {"l": "UU 4/2023", "p": "327", "b": "BAB XXVII KETENTUAN PENUTUP", "t": "Pada saat Undang-Undang ini mulai berlaku, ketentuan mengenai: a. permohonan kepailitan bagi Bank, Perusahaan Efek, Bursa Efek, Lembaga Kliring dan Penjaminan, Lembaga Penyimpanan dan Penyelesaian, dan Dana Pensiun sebagaimana diatur dalam Pasal 2; dan b. penundaan kewajiban pembayaran utang bagi Bank, Perusahaan Efek, Bursa Efek, Lembaga Kliring dan Penjaminan, Lembaga Penyimpanan dan Penyelesaian, Perusahaan Asuransi, Perusahaan Reasuransi, dan Dana Pensiun sebagaimana diatur dalam Pasal 223, Undang-Undang Nomor 37 Tahun 2004 tentang Kepailitan dan Penundaan Kewajiban Pembayaran Utang (Lembaran Negara dinyatakan tidak berlaku. Pasal 328 ... jdih.kemenkeu.go.id"}, {"l": "UU 4/2023", "p": "328", "b": "BAB XXVII KETENTUAN PENUTUP", "t": "Pada saat program penjaminan polis mulai dilaksanakan berdasarkan Undang-Undang 1m, ketentuan mengenai likuidasi dalam Pasal 44, Pasal 45, Pasal 46, Pasal 4 7, Pasal 48, Pasal 49, dan Pasal 52 Undang-Undang Nomor 40 Tahun 2014 tentang Perasuransian (Lembaran Negara Republik Indonesia Tahun 2014 Nomor 337, Tambahan Lembaran Negara Republik Indonesia Nomor 5618) tidak berlaku bagi Perusahaan Asuransi dan Perusahaan Asuransi Syariah yang menjadi peserta program penjaminan polis. Pasal329 Penyelenggaraan program penjaminan polis mulai berlaku 5 (lima) tahun terhitung sejak Undan g-Undang m1 diundangkan."}, {"l": "UU 4/2023", "p": "330", "b": "BAB XXVII KETENTUAN PENUTUP", "t": "Pada saat Undang-Undang ini mulai berlaku, Undang-Undang Nomor 11 Tahun 1992 tentang Dana Pensiun (Lembaran Negara Republik Indonesia Tahun 1992 Nomor 37, Tambahan dinyatakan tidak berlaku."}, {"l": "UU 4/2023", "p": "331", "b": "BAB XXVII KETENTUAN PENUTUP", "t": "Pada saat Undang-Undang ini mulai berlaku, semua peraturan perundang-undangan yang berkaitan dengan: a. Usaha Jasa Pembiayaan; b. Pelindungan Konsumen di sektor keuangan; c. ITSK; d. sumber daya manusia, profesi, tata kelola yang baik dan pelaporan keuangan di sektor keuangan; dan e. asuransi Usaha Bersama, dinyatakan masih tetap berlaku sepanjang tidak bertentangan dengan Undang-Undang ini. Pasal 332 ... jdih.kemenkeu.go.id"}, {"l": "UU 4/2023", "p": "332", "b": "BAB XXVII KETENTUAN PENUTUP", "t": "Pada saat Undang-Undang ini mulai berlaku, rencana resolusi bank umum yang telah disampaikan kepada Lembaga Penjamin Simpanan sebelum Undang-Undang ini berlaku dinyatakan telah memenuhi ketentuan Undang-Undang ini dan selanjutnya penyampaian rencana resolusi mengikuti ketentuan yang diatur dalam Undang-Undang ini dan peraturan pelaksanaan Undang-Undang ini. Pasal333 (1) Untuk pertama kali, salah satu anggota Dewan Komisioner Lembaga Penjamin Simpanan sebagaimana dimaksud dalam Pasal 65 ayat (2) huruf d dalam Pasal 7 angka 39 Undang-Undang ini diangkat dan ditetapkan paling lambat 1 (satu) tahun sebelum program penjaminan polis dimulai sebagaimana dimaksud dalam Pasal 329. (2) Pengangkatan dan penetapan anggota Dewan Komisioner Lembaga Penjamin Simpanan sebagaimana dimaksud pada ayat (1) dilakukan dengan mengikuti ketentuan mengenai pengangkatan dan penetapan anggota Dewan Komisioner Lembaga Penjamin Simpanan yang berakhir masa jabatannya sebagaimana dimaksud dalam Pasal 65 dalam Pasal 7 angka 39 Undang-Undang ini. Pasal334 Pada saat Undang-Undang ini mulai berlaku, dalam undang­ undang mengenai Otoritas Jasa Keuangan dan peraturan pelaksanaannya, pelaksanaan tugas dan wewenang …"}, {"l": "UU 4/2023", "p": "335", "b": "BAB XXVII KETENTUAN PENUTUP", "t": "(1) Pada saat Undang-Undang ini mulai berlaku, berdasarkan Undang-Undang m1, masa jabatan Ketua Dewan Komisioner Otoritas Jasa Keuangan dan anggota Dewan Komisioner Otoritas Jasa Keuangan yang membidangi edukasi dan Pelindungan Konsumen periode tahun 2022- 2027 ditetapkan masa jabatannya menjadi 6 (enam) tahun terhitung sejak diangkat dan ditetapkan. (2) Pada saat Undang-Undang ini mulai berlaku, untuk pertama kali, pengangkatan dan penetapan: a. Kepala Eksekutif Pengawas Lembaga Pembiayaan, Perusahaan Modal Ventura, Lembaga Keuangan Mikro, dan Lembaga Jasa Keuangan Lainnya merangkap anggota; dan b. Kepala Eksekutif Pengawas lnovasi Teknologi Sektor Keuangan, Aset Keuangan Digital dan Aset Kripto merangkap anggota, dilakukan paling lambat 7 (tujuh) bulan terhitung sejak Undang-Undang ini diundangkan."}, {"l": "UU 4/2023", "p": "336", "b": "BAB XXVII KETENTUAN PENUTUP", "t": "Anggota Badan Supervisi Lembaga Penjamin Simpanan sebagaimana dimaksud dalam Pasal 89B dalam Pasal 7 angka 61 Undang-Undang ini dan Badan Supervisi Otoritas Jasa Keuangan sebagaimana dimaksud dalam Pasal 38B dalam Pasal 8 angka 19 Undang-Undang ini ditetapkan paling lambat 1 (satu) tahun terhitung sejak Undang-Undang ini diundangkan. Pasal 337 ... jdih.kemenkeu.go.id REPUBUK INDONESIA"}, {"l": "UU 4/2023", "p": "337", "b": "BAB XXVII KETENTUAN PENUTUP", "t": "Pada saat Undang-Undang ini mulai berlaku: a. semua istilah \"LPS\" yang sudah ada sebelum Undang­ Undang ini berlaku harus dimaknai sebagai istilah \"Lembaga Penjamin Simpanan\" sebagaimana dimaksud dalam Undang-Undang ini; b. semua istilah \"Lembaga Pengawas Perbankan\" dan \"OJK\" yang sudah ada sebelum Undang-Undang ini berlaku harus dimaknai sebagai istilah \"Otoritas Jasa Keuangan\" sebagaimana dimaksud dalam Undang-Undang ini; c. semua istilah \"Bank Gagal\" dan \"Bank yang mengalami kesulitan keuangan dan membahayakan kelangsungan usahanya serta dinyatakan tidak dapat lagi disehatkan oleh Otoritas Jasa Keuangan sesuai dengan wewenang yang dimilikinya\" yang sudah ada sebelum Undang­ Undang ini berlaku diganti menjadi \"Bank dalam resolusi\"; d. semua istilah \"Bank Gagal yang Berdampak Sistemik\" yang sudah ada sebelum Undang-Undang ini berlaku diganti menjadi \"Bank Sistemik yang ditetapkan sebagai Bank dalam resolusi\"; e. semua istilah \"Bank Gagal yang tidak berdampak sistemik\" yang sudah ada sebelum Undang-Undang ini berlaku diganti menjadi \"Bank selain Bank Sistemik yang ditetapkan sebagai Bank dalam resolusi\"; f. semua istilah \"Lembaga Jasa Keuangan\" yang sudah ada sebelum Undang-Undang …"}, {"l": "UU 4/2023", "p": "338", "b": "BAB XXVII KETENTUAN PENUTUP", "t": "Pada saat Undang-Undang ini mulai berlaku, semua peraturan perundang-undangan yang berkaitan dengan \"Bank Perkreditan Rakyat\" dan \"Bank Pembiayaan Rakyat Syariah\" dinyatakan tetap berlaku sepanjang tidak bertentangan dan belum diganti berdasarkan Undang-Undang ini."}, {"l": "UU 4/2023", "p": "339", "b": "BAB XXVII KETENTUAN PENUTUP", "t": "(1) Peraturan pelaksanaan dari Undang-Undang m1 ditetapkan paling lama 2 (dua) tahun terhitung sejak Undang-Undang ini diundangkan. (2) Peraturan Dewan Komisioner Lembaga Penjamin Simpanan sebagaimana dimaksud dalam Pasal 63 ayat (5) dalam Pasal 7 angka 37 Undang-Undang ini ditetapkan paling lama 6 (enam) bulan terhitung sejak Undang­ Undang ini diundangkan."}, {"l": "UU 4/2023", "p": "340", "b": "BAB XXVII KETENTUAN PENUTUP", "t": "(1) Pemantauan dan peninjauan terhadap Undang-Undang ini dilakukan setelah Undang-Undang ini diundangkan. (2) Pemantauan dan peninjauan terhadap Undang-Undang sebagaimana dimaksud pada ayat (1) dilaksanakan oleh DPR dan Pemerintah. (3) Pemantauan dan peninjauan terhadap Undang-Undang sebagaimana dimaksud pada ayat (1) dikoordinasikan oleh DPR melalui alat kelengkapan yang khusus menangani bidang legislasi."}, {"l": "UU 4/2023", "p": "341", "b": "BAB XXVII KETENTUAN PENUTUP", "t": "Undang-Undang ini mulai berlaku pada tanggal diundangkan. Agar ... jdih.kemenkeu.go.id REPUBUK INDONESIA pengundangan Undang-Undang ini dengan penempatannya dalam Lembaran Negara Republik Indonesia. pada tanggal 12 Januari 2023 JOKOWIDODO pada tanggal 12 Januari 2023 MENTER! SEKRETARIS NEGARA PRATIKNO KEMENTERIAN SEKRETARIAT NEGARA -·~EPUBLIK --, INDONESIA · ~~~~~ erundang-undangan dan ~. ~~ ~:~=:.~q~l.iL · ~.J\"- strasi Huk , lvanna Djaman ,,_,..· REPUBUK INDONESIA"}, {"l": "RV", "p": "2", "b": "Bagian 1. Penyampaian Surat Pernyataan Gugatan, Pemberitahuan Kepada", "t": "Kecuali yang secara khusus ditentukan dalam peraturan ini mengenai penyampaian pemberitahuan kepada para pihak, bersamaan dengan pemberitahuan gugatannya atau selama perkara berjalan dan tentang pelaksanaan tempat tinggal pilihan, maka pernberitahuan gugatan dan pemberitahuan-pemberitahuan lain, sesual dengan pasal 24 Kitab Undang-undang Hukum Perdata (KUHPerd.) dengan mengingat pembedaan- pembedaan yang diadakan di dalamnya, dapat dilakukan juga di tempat tinggal pilihan yang dimaksudkan dalam pasal itu. (Rv. 106 dst., 443.) Dg. S. 1908-522 jo. 1909-115, ditambah alinea 2-6. (s.d.u. dg. S. 1925-497.) Panitera raad vanjustitie (R.v.J.), dan di tempat yang tidak ada raad van jusititie, kepala daerah (Gubernur, Residen dan Asisten-Residen) yang kantomya dipilih sebagai tempat tinggal pilihan, wajib menerima pemberitahuan- pemberitahuan yang disampaikan di kantornya, dan secepatnya memberitahukannya kepada yang berkepentingan atau kuasanya, sepanjang mereka bertempat tinggal di Indonesia atau berada di situ dan tempat tinggal atau di mana ia berada diketahui oleh Panitera, kepala daerah atau kepala pemerintahan setempat (Gubemur, Residen atau Asisten-Residen), tanpa perlu terbukti …"}, {"l": "RV", "p": "3", "b": "Bagian 1. Penyampaian Surat Pernyataan Gugatan, Pemberitahuan Kepada", "t": "(s.d.u. dg. S. 1908-522.) Dalam hal juru sita tidak dapat bertemu dengan tergugat atau anggota keluarganya di tempat tinggalnya itu, g maka ia segera menyampaikan turunan surat yang bersangkutan kepada r kepala pemerintahan setempat (asisten residen) yang s . o kemudian membubuhkan tanda tangan dengan menyebutkan tanggal pada surat yang l i a asli serta turunannya tanpa biaya dan sedapat-dapatnya menyampaikan t turunan surat itu kepada tergugat, tanpa perlu bukti keabsahan penyampaian itu. (RBg. 321, 322-30.) a l. eg Juru sita memberi catatan tentang penyampaian itu pada surat gugatan asli dan turunannya. w w Jika kepala pemerintahan setempat (asisten residen) berhalangan, tidalk ada kepala pemerintahan setempat atau tidak ada di tempat, w maka surat disampaikan kepada pejabat orang Eropa dengaii pangkat tertinggi atau kepada pegawai kantor asisten residen, yang kemudian bertindak seperti yang diperintahkan kepada asisten residen dalam alinea pertama pasal ini. (Rv. 1, 20, 82, 94, 339, 457, 809.)"}, {"l": "RV", "p": "4", "b": "Bagian 1. Penyampaian Surat Pernyataan Gugatan, Pemberitahuan Kepada", "t": "Kepada tiap-tiap tergugat diberikan turunan surat pemberitahuan gugatan. Kepada suami/isteri yang tidak pisah meja dan ranjang atau kawin dengan perpisahan harta kekayaan hanya diberikan satu turunan saja. (Rv. 1, 7, 94 dst., 339; KUHPerd. 110, 186 dst., 233 dst.; Sv. 89.)"}, {"l": "RV", "p": "5", "b": "Bagian 1. Penyampaian Surat Pernyataan Gugatan, Pemberitahuan Kepada", "t": "(s.d.u. dg. S. 1908-522; S. 1925-497.) Pemberitahuan gugatan diberikan: - langsung olehjuru sita yang ditunjuk oleh yang berkepentingan,jika tergugat bertempat tinggal di ibukota tempat majelis bersidang untuk mengadili gugatan itu; - jika tergugat bertempat tinggal di luar ibukota, tetapi masih di dalam wilayah hukum hakim yang bersangkutan kepada siapa diajukan gugatan itu, atau langsung oleh seorang juru sita yang ditugaskan oleh penggugat atau atas pilihan penggugat dengan surat permohonan pengacaranya dengan perantaraan hakim tersebut yang akan mengirimkan akte gugatannya kepada asisten-residen yang wilayahnya meliputi tempat tinggal tergugat agar atas perintahnya oleh orang yang berkewajiban diberitahukan kepada tergugat. - jika tergugat bertempat tingkal di luar wilayah kekuasaan hakim yang menerima gugatan atau segera dalam hal seperti diuraikan di atas atau atas pilihan penggugat dan atas permohonan pengacaranya dengan surat kepada hakim di tempat tinggal tergugat yang kemudian akan memberitahukannya dengan perantaraan juru sita yang ditunjuknya, jika tergugat bertempat tinggal di dalam karesidenan tempat akan diadakan sidang majelis, dan jika tidak tinggal di situ ia …"}, {"l": "RV", "p": "6", "b": "Bagian 1. Penyampaian Surat Pernyataan Gugatan, Pemberitahuan Kepada", "t": "s . o Pemberitahuan gugatan dan semua pemberitahuan lainnya dilakukan sebagai berikut: l i t a 1 . (s.d. u. dg. S. 1925-497io. S. 1926-229.) terhadap Gubemur a Jenderal, dalam perkara yang menyangkut pribadinya, disampaikan l. eg kepadanya sendiri atau dengan perantaraan kantor Gubemur Jawa Barat; w 2 . terhadap pemerintah Indonesia disampaikan kepada Menteri yang (Rv. 99'8.) w w bersangkutan sebagai wakil Negara atau di tempat tinggalnya; 30. (s.d.u. dg. S. 1925-497jo. S. 1938-276.) terhadap badan-badan hukum umum disampaikan kepada pipinan pengurus sendiri atau di tempat tinggalnya atau di tempat pengurus biasa bersidang atau mempunyai kantomya; 3 bis. (s.d.t. dg. S. 1925-497; s.d.u. dg. S. 1931-168jo. 423; S. 1938-276.) terhadap Badan Hukum, kepada pengurus Badan Hukum atau salah satu anggota pengurus di tempat tinggalnya, dan apabila pengurus telah dinonaktifkan, kepada salah satu pemberes (utang-piutang) atau ke tempat, kedudukan kantomya; (KUHPerd. 1653 dst.; KUHD 36 dst., 39, 44, 56.) 40. (s.d.u. dg. S. 1908-522; S. 1925-497.) terhadap orang-orang seperti tersebut pasal 9, kepada asisten residen. Jika asisten residen itu berhalangan, tidak ada asisten residen atau sedang …"}, {"l": "RV", "p": "7", "b": "Bagian 1. Penyampaian Surat Pernyataan Gugatan, Pemberitahuan Kepada", "t": "w w w (s.d.u. dg. S. 1908-522.) Terhadap orang-orang yang telah meninggal dunia, pemberitahuan gugatan dan pemberitahuan-pemberitahuan lainnya dilakukan terhadap semua ahli waris dan sekaligus, tanpa menyebut nama dan tempat tinggalnya, di tempat tinggal terakhir almarhum dan tidak boleh melebihi waktu enam bulan setelah meninggalnya. (KUHPerd. 23, 833, F. 198, 200; Rv. 4, 9912, 337.)"}, {"l": "RV", "p": "8", "b": "Bagian 1. Penyampaian Surat Pernyataan Gugatan, Pemberitahuan Kepada", "t": "Pemberitahuan gugatan harus memuat: (Rv. 2 , 21, 74.) 1 . hari, bulan dan tahun; nama kecil, nama dan tempat tinggal penggugat dengan menyebut tempat tinggal pilihan dalam jarak palingjauh sepuluh pal (lima belas kilometer) dari gedung tempat bersidang hakim yang akan mengadili perkara yang bersangkutan; (KUHPerd. 17 dst., 24 dst., 1405-6'; Rv. 17 dst., 106, 443, 477, 504, 533, 655-2-, 662, 666-11; S. 1853-64.) 2 . nama kecil, nama dan tempat tinggat juru sita, nama dan tempat tinggal tergugat serta menyebut pula nama orang yang menerima turunan pemberitahuan gugatan. (Rv. 4, 204.) (s.d.u. dg. S. 1938-276.) Jika pihak penggugat atau tergugat merupakan badan hukum atau badan usaha dagang, maka namanya dicantumkan sebagai pengganti nama dan nama kecil; (KUHPerd. 1618 dst., 1653 dst., KUHD 16 dst., 36 dst., Chin. 3; Rv. 8-11.) 30. upaya-upaya dan pokok gugatan disertai kesimpulan yang jelas dan tertentu; (Rv. 50, 112, 339, 394, 411-11, 444.). 4 . penundjukan hakim yang akan mengadili; (KUHPerd. 99.) 50. hari dan jam tergugat menghadap di sidang pengadilan. (Rv. 16.) surat pernyataan gugatan dan tembusannya harus ditandatangani oleh juru sita. (RO. 200; Rv. 106.)"}, {"l": "RV", "p": "9", "b": "Bagian 1. Penyampaian Surat Pernyataan Gugatan, Pemberitahuan Kepada", "t": "Jika gugatan ditujukan kepada seorang raja atau seorang Indonesia yang mempunyai kedudukan atau kelahiran golongan tinggi yang tanpa izin sebelumnya menurut undang-undang tidak boleh digugat, maka di dalam surat pemberitahuan gugatan itu harus dicantumkan izin yang membolehkan orang itu dilibatkan dalam acara peradilan. (ISR 140; Rv. 6-40, 94; RO. 4.)"}, {"l": "RV", "p": "10", "b": "Bagian 1. Penyampaian Surat Pernyataan Gugatan, Pemberitahuan Kepada", "t": "(s.d.u. dg. S. 1908-522.) Jangka waktu biasa memberitahukan gugatan ke hadapan raad van justitie dan H.G.H. adalah sebagai berikut: 10. sedikitnya delapan hari bagi tergugat yang bertempat tinggal atau jika tidak diketahui tempat tinggalnya di Indonesia, bertempat kediaman nyata di karesidenan tempat persidangan raad van justitie yang akan mengadili perkara itu; 2 . sedikitnya empat belas hari bagi tergugat yang bertempat tinggal r g atau seperti ditentukan di atas, berdiam secara nyata di sebuah karesidenan di Jawa dan Madura lain daripada yang disebut dalam . o no. 10 yang lalu, tetapi masih di dalam wilayah hukum raad van s justitie yang sama; l i t a 3 . dan sedikitnya dua puluh hari bagi tergugat yang bertempat a tinggal atau seperti ditentukan di atas, berdiam secara nyata di l. eg suatu karesidenan lain di Jawa, lain dari apa yang disebut dalam no. 20 dan juga tidak di dalam wilayah hukum raad van justitie yang sama. w w Dalam perkara yang sangat mendesak ketua raad van justitie, atas permohonan lisan w atau tertulis dari penggugat, dapat mempersingkat tenggang waktu tersebut; dalam hal pertama maka izin itu dicantumkan di kepala surat pemberitahuan gugatan, sedangkan dalam …"}, {"l": "RV", "p": "11", "b": "Bagian 1. Penyampaian Surat Pernyataan Gugatan, Pemberitahuan Kepada", "t": "(s.d.u. dg. S. 1908-522.) Dalam hal-hal seperti tersebut dalam pasal 6 no. 7 alinea kedua dan keempat, maka jangka waktu itu sedikitnya empat bulan. (Rv. 15, 94.) (s.d.t. dg. S. 1938-276.) Jangka waktu itu atas permohonan penggugat dapat dipersingkat, bila perlu dengan syarat-syarat. Dalam hal ini diberlakukan pasal 10 alinea kedua dengan ketentuan bahwa syarat-syarat yang menjadi alasan dipersingkatnya jangka waktu itu juga dicantumkan pada kepala surat pemberitahuan gugatan itu."}, {"l": "RV", "p": "12", "b": "Bagian 1. Penyampaian Surat Pernyataan Gugatan, Pemberitahuan Kepada", "t": "(s.d.u. dg. S. 1938-276.) Jika tergugat di Indonesia tidak mempunyai tempat tinggal atau tempat kediaman yang nyata tetapi mempunyai tempat tinggal di luar Indonesia, makajangka waktu penyampaian surat pemberitahuan gugatan ditetapkan dengan Peraturan Pemerintah. (Rv. 68, 13, 15, 94, 308; KUHPerd. 17, 24.) Pasal 11 alinea kedua berlaku dalam hal ini."}, {"l": "RV", "p": "13", "b": "Bagian 1. Penyampaian Surat Pernyataan Gugatan, Pemberitahuan Kepada", "t": "Jika surat pemberitahuan gugatan disampaikan kepada seorang tergugat di Indonesia, sedangkan sebenamya ia bertempat tinggal di luar Indonesia atau jika ia dalam urusan tertentu telah menetapkan tempat tinggal pilihan di Indonesia, maka berlakulah jangka waktu yang ditentukan untuk penduduk dengan memperhatikan jarak tempat dilakukannya pemberitahuan gugatan itu. (KUHPerd. 24, Rv. 6-7 ; 10, 94, 443.)"}, {"l": "RV", "p": "14", "b": "Bagian 1. Penyampaian Surat Pernyataan Gugatan, Pemberitahuan Kepada", "t": "Jika beberapa orang karena gugatan yang sama ditetapkan untuk jangka waktu yang berlainan, maka semua akan ditetapkan untuk datang r menghadap pada waktu yang ditentukan untuk yang bertempat tinggalg terjauh. (Rv. 10 dst., 94.) s . o"}, {"l": "RV", "p": "15", "b": "Bagian 1. Penyampaian Surat Pernyataan Gugatan, Pemberitahuan Kepada", "t": "l i t a Hari untuk menyampaikan surat panggilan dan hari untuk menghadap di a pengadilan, tidak diperhitungkan dalam tenggang waktu umum, yang l. eg ditentukan untuk mengurus gugatan, peringatan, dan untuk memberikan tanda tangan terhadap surat resmi dari pengadilan yang disampaikan Sv. 424; IR. 391; RBg. 719.) w w oleh juru sita. (KUHD 135 dst., 172, Rv. 82, 94, 297, 479, 550, 731; w (S.d.u. dg. S. 1908-522.) Dalam hal yang ditentukan dalam pasal 3 maka hari yang dicantumkan pejabat yang menerima surat itu dianggap sebagai hari disampaikannya surat panggilan gugatan. (Rv. 94.)"}, {"l": "RV", "p": "16", "b": "Bagian 1. Penyampaian Surat Pernyataan Gugatan, Pemberitahuan Kepada", "t": "surat pemberitahuan gugatan, pemberitahuan-pemberitahuan atau panggilan-panggilan untuk hadir di suatu acara pengadilan atau perintah hanya akan menyebut tempat, hari dan jam sidang pertama; hal itu tidak perlu diulangi meskipun sidang digeser atau 0 0 dilanjutkan pada hari lain. (Rv. 6-7 , 8-5 , 25, 99, 182, 239.)"}, {"l": "RV", "p": "17", "b": "Bagian 1. Penyampaian Surat Pernyataan Gugatan, Pemberitahuan Kepada", "t": "surat panggilan tidak disampaikan pada hari Minggu, kecuali atas izin ketua raad van justitie. Jika hari terakhir jangka waktu panggilan jatuh pada hari Minggu, maka hal itu dilakukan pada hari berikutnya. (Rv. 94, 283, 596, 716; KUHD 1433, 171, 171a, 354; Sv. 424.) (s.d.u. dg. S. 1908-522.) Bila dalam peraturan ini disebut jangka waktu satu bulan, maka yang dimaksud adalah 30 hari. (KUHD 135.)"}, {"l": "RV", "p": "18", "b": "Bagian 1. Penyampaian Surat Pernyataan Gugatan, Pemberitahuan Kepada", "t": "Pemberitahuan surat gugatan atau pelaksanaan suatu putusan pengadilan tidak boleh dilakukan sebelum jaim enam pagi dan sesudah jam enam sore, kecuali diizinkan oleh ketua dalam hal-hal yang sangat mendesak. (Rv. 8-10, 16, 94, 339, 596.) (s. d. t. dg. S. 1908-522.) Izin tersebut dalam pasal ini dan p asal yang lalu dapat diberikan atas permohonan lisan atau tertulis dari pihak yang berkepentingan; dalam hal yang pertama izin dicantumkan pada kepala surat pemberitahuan gugatan atau pada kepala berita acara pelaksanaan, sedangkan dalam hal kedua ketetapan ketua dicantumkan di surat permohonannya. Penetapan ini dapat dilaksanakan berdasarkan surat aslinya. Hal itu tidak diberitahukan kepada pihak lawan melainkan dicatat pada kepala surat pemberitahuan gugatan atau berita acara."}, {"l": "RV", "p": "19", "b": "Bagian 1. Penyampaian Surat Pernyataan Gugatan, Pemberitahuan Kepada", "t": "(s. d. u. dg. S. 1932-42.) Saksi-saksi yang diperlukan kehadirannya dalam beberapa macam panggilan harus penduduk Indonesia, cukup umur untuk memberikan kesaksian yang sah dan oleh jurusita yang melakukan panggilan dikenal sebagai orang yang dapat dipercaya atau oleh kepala pemerintahan setempat dinyatakan sebagai orang yang demikian. (KUHPerd. 1405-70, 1912; RBg. 444, 560, 567, 723, 758, 761.)"}, {"l": "RV", "p": "20", "b": "Bagian 1. Penyampaian Surat Pernyataan Gugatan, Pemberitahuan Kepada", "t": "Juru sita tidak boleh melakukan panggilan untuk keluarganya sedarah atau karena perkawinan dalam garis lurus sampai tidak terbatas dan dalam garis samping, sampai anak-anak saudara laki-laki maupun r g perempuannya. (KUHPerd. 290.) s . o Dalam hal ada halangan, karena keadaan di atas atau karena sebab l i t a lain, maka ketua, jika berkenaan dengan jurusita biasa atau residen dalam hal jurusita luar biasa, akan menunjuk orang yang dipandangnya a tepat untuk melakukan panggilan-panggilan yang diperlukan. (RBg. l. eg 322-21.) Orang itu disumpah terlebih dahulu, kecuali ia adalah seorang w w pejabat yang sudah melakukan sumpah jabatan. (RO. 193 dst.) Penunjukan itu akan disebutkan dalam surat-surat panggilan yang w bersangkutan. (Rv. 8, 21, 94, 97.)"}, {"l": "RV", "p": "21", "b": "Bagian 1. Penyampaian Surat Pernyataan Gugatan, Pemberitahuan Kepada", "t": "Jika suatu surat panggilan dinyatakan batal karena juru sita telah melakukan sesuatu yang menyebabkan batalnya surat panggilan itu, maka iadapat dihukum untuk mengganti biaya panggilan itu dan biaya acara yang batal, demikian pula untuk mengganti segala kerugian dan bunga pihak yang dirugikan, dengan memperhatikan keadaan; semua itu tidak mengurangi apa yang ditentukan dalam pasal 60. (KUHPerd. 1243 dst., 1365 dst.; Rv. 8, 20, 93, 98.)"}, {"l": "RV", "p": "22", "b": "Bagian 2. Sidang-sidang Pengadilan.", "t": "Sidang-sidang pengadilan diadakan secara terbuka menurut ketentuanketentuan dalam pasal 29 RO (Susunan Kehakiman dan Kebijaksanaan Mengadili). Ketentuan-ketentuan dalam Bab XII Peraturan Hukum Acara Pidana untuk R.v.J. di Jawa dan sebagainya berlaku dalam hal ini. (Rv. 283, 837, 841; Sv. 254 dst.; IR. 373; RB9. 701.)"}, {"l": "RV", "p": "23", "b": "Bagian 2. Sidang-sidang Pengadilan.", "t": "(s.d.u. dg. S. 1908-522.) Pengacara penggugat mencatatkan dalam daftar sidang giliran (rol) paling lambat satu hari sebelum hari sidang yang ditentukan dalam gugatan atau yang diajukan menurut pasal 107. Jika dalam perkara-perkara yang pemberitahuan gugatannya dilakukan dalam waktu pendek sehingga ia tidak akan dapat memenuhi ketentuan ini, maka ia secepat mungkin mendaftarkan perkara tersebut. Semua perkara, termasuk perkara-perkara mengenai perniagaan, dicatat dalam rol (daftar giliran sidang) menurut waktu mencatatnya dengan menyebut nama pihak-pihak serta pengacara-pengacaranya. (Rv. 111, 943.)"}, {"l": "RV", "p": "24", "b": "Bagian 2. Sidang-sidang Pengadilan.", "t": "Pada hari yang telah ditentukan jurusita memanggil para pihak yang berperkara menurut urutan yang tercantum dalam daftar giliran sidang. panitera untuk tiap-tiap persidangan menyerahkan suatu kutipan daftar sidang giliran yang berisi perkara-perkara yang akan diperiksa kepada juru sita. Kutipan-kutipan semacam itu juga diserahkan kepada ketua raad van justitie sehari sebelum hari sidang; kutipan-kutipan semacam itu dalam jumlah yang mencukupi disediakan juga di dalam ruang sidang, sebelum sidang dimulai, untuk para anggota raad van justitie dan penuntut umum. (Rv. 111, 113, 118.)"}, {"l": "RV", "p": "25", "b": "Bagian 2. Sidang-sidang Pengadilan.", "t": "Jika suatu perkara tidak dapat segera diselesaikan pada hari r g pertama, s . o maka pemeriksaan lanjutan serta penyelesaiannya ditunda sampai hari lain. Panitera berkewajiban membuat catatan tentang hal l i a itu dan perkara-perkara yang ditunda pada hari yang telah ditentukan t dipanggil dalam urutan seperti semula. (Rv. 16, 111, 114, 119 dst., IR. 159.) a"}, {"l": "RV", "p": "26", "b": "Bagian 2. Sidang-sidang Pengadilan.", "t": "l. eg w Jika mengenai perkara yang diputus tanpa kehadiran tergugat (verstek) ada perlawanan, maka perkara itu menempati urutan kembali w dalam daftar sidang giliran, kecuali bila ketua menentukan hari w tertentu untuk mengadili perlawanan itu. (Rv. 83.)"}, {"l": "RV", "p": "27", "b": "Bagian 2. Sidang-sidang Pengadilan.", "t": "(s.d.u. dg. S. 1908-522.) Jika pada hari persidangan pertama atau pada hari lain yang ditentukan untuk sidang lanjutan tidak ada pihak yang datang menghadiri, maka perkara dicoret dari daftar. Tetapi perkara harus diajukan dan dilanjutkan atas permohonan dengan suara bulat dari para pihak, tanpa gugatan baru sebelumnya berdasarkan daftar giliran sidang seolah-olah pencoretan tidak terjadi. Hal yang sama terjadi, bila atas permohonan para pihak pencoretan perkara diperintahkan oleh hakim. (Rv. 77.)"}, {"l": "RV", "p": "28", "b": "Bagian 2. Sidang-sidang Pengadilan.", "t": "(s.d.u. dg. S. 1908-522.) Para pengacara pihak-pihak (kecuali dalam kasasi) diwajibkan untuk menyampaikan kepada Panitera kesimpulan yang mereka ambil dan mereka tandatangani. Panitera wajib secara cermat mencatat semua kesimpulan yang disampaikan oleh para pihak secara lisan jika tidak diharuskan membuat kesimpulan tertulis. (Rv. 106, 139; IR. 186.)"}, {"l": "RV", "p": "29", "b": "Bagian 2. Sidang-sidang Pengadilan.", "t": "(s.d.u. dg. S. 1917-497.) Para pembela wajib membela perkara di hadapan hakim dengan kedewasaan dan dalam segala hal memperhatikan dan mempertahankan kehormatan yang diwajibkan terhadap peradilan. Jika mereka melupakan hal ini maka hakim akan memperingatkannya, dengan tidak mengurangi penggunaan pasal 192 RO., jika untuk itu dianggap perlu. (RO. 46, 185 dst.; Sv. 126, 254; IR. 372; RB9. 700.)"}, {"l": "RV", "p": "30", "b": "Bagian 2. Sidang-sidang Pengadilan.", "t": "Jika para hakim sama-sama berpendapat bahwa suatu perkara sudah menjadi jelas, maka ketua raad van justitie menghentikan pembelaan- pembelaan."}, {"l": "RV", "p": "31", "b": "Bagian 2. Sidang-sidang Pengadilan.", "t": "Hakim di dalam segala hal dan dalam setiap tahap pemeriksaan, jika dianggapnya ada kemungkinan untuk mencapai perdamaian, baik atas permohonan para pihak atau salah satu dari mereka, maupun karena jabatannya, dapat merintahkan mereka untuk menghadap dia dengan datang sendiri atau dengan diwakili pengacaranya ataupun bersama- sama dengan pengacaranya agar dapat diusahakan perdamaian. Jika tercapai perdamaian dan para pihak menghendakinya, maka dibuatlah berita acara yang ditandatangani oleh para pihak atau oleh para kuasanya yang secara khusus ditunjuk untuk itu, dalam berita acara mana disebutkan perjanjian-perjanjian yang telah disepakati para pihak. Berita acara dibuat dalam bentuk yang sudah siap untuk dilaksanakan. (KUHPerd. 1851, 1868; Rv, 49, 51, 160-20; 435; IR. 130.) r g (s.d.t. dg. hakim menentukan hari perkara akan disidangkan kembali. s . o S. 1908-522.) Jika tidak tercapai perdamaian, maka"}, {"l": "RV", "p": "32", "b": "Bagian 2. Sidang-sidang Pengadilan.", "t": "l i t a a Para penasihat yang dalam hal-hal tersebut dalam pasal 7 RO. harus l. eg ditanya pendapatnya setelah pemeriksaan di sidang dianggap selesai dan setelah memberikan pendapatnya dalam rapat Majelis, kemudian w w dapat meninggalkan rapat itu, kecuali jika ketua meminta mereka tetap hadir untuk mengikuti permusyawaratan selanjutnya; mereka bagaimanapun diundang, 0 w jika mau, untuk menghadiri putusan. (RO. 41; Rv. 61-3 ; IR. 184, 186, 319-3 , 322.) pengucapan"}, {"l": "RV", "p": "33", "b": "Bagian 2. Sidang-sidang Pengadilan.", "t": "Jika sepanjang jalannya pemeriksaan diperlukan bantuan seorang juru bahasa, maka oleh para pihak atau jika ada persesuaian pilihan, oleh ketua dipilih seorangjuru bahasa. Jika yang dipilih bukan orang yang oleh pemerintah telah diangkat sebagai juru bahasa yang telah disumpah, maka ia sebelum melakukan tugasnya di muka sidang harus bersumpah di hadapan ketua, bahwa ia seorang juru bahasa akan melakukan tugas yang diwajibkan kepadanya dengan cermat dan menurut hati nuraninya. (Rv. 59, Sv. 156 dst.; IR. 130 dst., 284 dst.; RBg. 154 dst., 586 dst.) Jika diperlukan juru bahasa dalam tindakan yang harus dilakukan oleh hakim, komisaris atau oleh seorang pejabat yang dikuasakan, maka wewenang ketua beralih kepada hakim-komisaris atau pejabat itu."}, {"l": "RV", "p": "34", "b": "Bagian 3. Hakim-hakim Dan Penolakan Terhadap Mereka.", "t": "Hakim, penuntut umum, panitera serta panitera pengganti, dilarang untuk menjadi pembela para pihak, baik secara lisan maupun tertulis, meskipun dengan nama pemberian nasihat, bahkan tidak untuk perkara- perkara di muka pengadilan lain daripada di mana dia menjalankan tugasnya. Namun mereka diperbolehkan di muka semua Pengadilan membela perkaranya sendiri dan isterinya, keluarga sedarah atau keluarga karena perkawinan dalam garis lurus serta anak-anak asuhannya. Mereka juga dilarang menjadi juru pemisah. (RO. 9, 35, 37; KUHPerd. 290, Rv. 266, 617, 621.)"}, {"l": "RV", "p": "35", "b": "Bagian 3. Hakim-hakim Dan Penolakan Terhadap Mereka.", "t": "Hakim tidak dapat ditolak kecuali dalam hal -hal sebagai berikut: (Rv. 36, 266 dst., 621; Sv. 268 dst., IR. 374, RBg. 702.) 1 . jika ia secara pribadi mempunyai kepentingan dalam perkara yang bersangkutan; (IR. 374.) 2 . jika ia dengan salah satu pihak mempunyai hubungan keluarga sedarah atau periparan sampai derajat keempat; (KUHPerd. 290, 297; Sv. 10, IR. 374.) 3 . jika dalam waktu satu tahun sebelum penolakan terhadap salah satu pihak atau isterinya ataupun terhadap keluarga sedarah atau keluarga karena perkawinan dalam gaiis lurus, telah dilakukan proses pidana atas tuntutannya atau karena tindakannya; (KUHPerd. 290, 297; Sv. 10.) (Rv. 34.) r g 4 . jika ia telah memberikan nasihat tertulis di dalam perkara itu; 50. jika ia selama berjalannya perkara telah . o menerima suatu s l i a pemberian dari orang yang berkepentingan, atau telah dijadikan t suatu pemberian kepadanya yang disetujuinya; (IR. 374; KUHP 418 dst.) a l. eg 6 . jika ia, isterinya, keluarga sedarah serta keluarga karena perkawinan mereka dalam garis lurus mempunyai persengketaan w w tentang pokok perkara serupa dengan yang sedang dialami oleh para pihak; (KUHPerd. 290, 297; IR. 374.) 70. jika antara hakim, …"}, {"l": "RV", "p": "36", "b": "Bagian 3. Hakim-hakim Dan Penolakan Terhadap Mereka.", "t": "Setiap hakim yang mengetahui bahwa ada suatu alasan untuk penolakan terhadap dirinya, berkewajiban memberitahukannya kepada majelis yang ia menjadi salah satu anggotanya, yang kemudian akan memutuskan apakah ia harus mengundurkan diri dari perkara tersebut. (Rv. 35, 42; Sv. 276; IR. 374; RBg. 702.)"}, {"l": "RV", "p": "37", "b": "Bagian 3. Hakim-hakim Dan Penolakan Terhadap Mereka.", "t": "Alasan-alasan penolakan terhadap seorang hakim berlaku juga terhadap penuntut umum, panitera dan panitera pengganti, akan tetapi dengan pengertian bahwa seorang penuntut umum tidak dapat ditolak, jika ia karena jabatannya terlibat sebagai pihak dalam perkara yang bersangkutan; seperti juga penolakan yang demikian itu tidak dapat terjadi dalam perkara pidana yang dilancarkan oleh pam penuntut umum karena jabatan terhadap orang-orang tersebut dalam pasal 35 No. 30. Penolakan dengan cara yang sama seperti terhadap para hakim. (Sv. 275.)"}, {"l": "RV", "p": "38", "b": "Bagian 3. Hakim-hakim Dan Penolakan Terhadap Mereka.", "t": "Pihak yang mau menolak hakim harus mengajukan penolakan itu dengan disertai alasan, jika ia tidak ingin haknya hilang, selambat- lambatnya sebelum dilakukan pleidoi (pembelaan) atau, jika proses pemeriksaan perkara dijalankan secara tertulis, sebelum tenggang waktu tanya-jawab habis, kecuali jika alasan penolakan atau sebab yang menimbulkan penolakan baru timbul kemudian. Sebagai kekecualian terhadap hal terakhir, maka penolakan terhadap seorang hakim-komisaris harus dilakukan sebelum ia memulai tugasnya. Akta penolakan harus ditandatangani oleh pihak yang bersangkutan r g sendiri atau oleh orang yang khusus dikuasakan untuk itu dengan akta tanda terima memberitahukan kepada hakim yang s . o otentik dan disainpaikan kepada panitera yang sesudah memberikan bersangkutan. t a (KUHPerd. 1868; Rv. 41, 111 dst., 118, 180 dst.; Sv. 270 dst., 275.) l i"}, {"l": "RV", "p": "39", "b": "Bagian 3. Hakim-hakim Dan Penolakan Terhadap Mereka.", "t": "a l. eg Hakim dalam waktu dua hari harus membuat tanggapan tertulis tentang penolakan itu dan menyampaikannya dalam sampul tertutup kepada ketua. (Rv. 40.) Jika penolakan ditujukan w w kepada ketua, maka tanggapan itu w disampaikan kepada wakil ketua dan jika wakil ketua tidak ada, kepada hakim yang pangkatnya langsung di bawah ketua."}, {"l": "RV", "p": "40", "b": "Bagian 3. Hakim-hakim Dan Penolakan Terhadap Mereka.", "t": "Majelis hakim akan menyelidiki alasan-alasan penolakan, dan jika alasan itu dianggap terbukti dan benar, maka penolakan diterima. (Rv. 38 dst.; SV. 273, IR. 374.)"}, {"l": "RV", "p": "41", "b": "Bagian 3. Hakim-hakim Dan Penolakan Terhadap Mereka.", "t": "Jika pihak yang menolak berpendapat ada beberapa alasan penolakan terhadap hakim yang sama, maka semua alasan itu harus dikemukakan sekaligus. (Rv. 35, 38; Sv. 271.)"}, {"l": "RV", "p": "42", "b": "Bagian 3. Hakim-hakim Dan Penolakan Terhadap Mereka.", "t": "Jika satu pihak akan menolak lebih dari satu anggota majelis yang sama, maka penolakan kedua dan berikutnya tidak dapat dikemukakan sebelum ada putusan mengenai penolakan terdahulu. (Rv. 36 dst., 266 dst.; Sv. 272.)"}, {"l": "RV", "p": "43", "b": "Bagian 3. Hakim-hakim Dan Penolakan Terhadap Mereka.", "t": "Tak seorang anggota Majelis pun boleh mengundurkan diri dari pembicaraan mengenai penolakan serta pengambilan putusannya. (AB. 22; Rv. 36; Sv. 273.)"}, {"l": "RV", "p": "44", "b": "Bagian 3. Hakim-hakim Dan Penolakan Terhadap Mereka.", "t": "Putusan mengenai penolakan tidak dapat dimintakan banding, peninjauan kembali atau kasasi. (Rv. 218, 327 dst., 362 dst., 402 dst., Sv. 281., IR. 374; RBg. 702.)"}, {"l": "RV", "p": "45", "b": "Bagian 3. Hakim-hakim Dan Penolakan Terhadap Mereka.", "t": "Dicabut dg. S. 1872-13."}, {"l": "RV", "p": "46", "b": "Bagian 4. Keputusan Pengadilan Pada Umumnya.", "t": "Jika penggugat atau tergugat tidak datang menghadap pada hari yang telah ditentukan, maka diambil tindakan-tindakan seperti diatur dalam bagian keenam bab ini. (Rv. 77 dst., 107 dst.)"}, {"l": "RV", "p": "47", "b": "Bagian 4. Keputusan Pengadilan Pada Umumnya.", "t": "Jika para pihak datang hadir, maka mereka saling didengar tentang kepentingannya dengan mengingat ketentuan-ketentuan dalam reglemen ini. (s.d. u. dg. S. 1908-522.) Setelah selesai pembelaan masing-masing r g atau jika tidak diajukan pembelaan-pembelaan dalam perkara itu s . dengan permohonan keputusan berdasarkan surat-surat yang ada, makao hakim setelah mempelajari surat-surat itu segera l i t amemberikan keputusan atau menentukan hari lain untuk mengucapkan keputusannya. (s.d. t. dg. a S. 1908-522.) Hakim dapat memberikan keputusan lebih l. eg awal dari hari yang ditentukan, tetapi dalam hal itu sedikitnya dua hari sebelum keputusan diucapkan ia memerintahkan panitera untuk memberitahukan kepada para pengucapan keputusan tersebut. w w pengacara tentang pengajuan hari (s.d.t. dg. S. 1908-522.) Jika surat keputusan belum selesai untuk w diucapkan pada hari yang telah ditentukan, maka hakim menentukan pada sidang hari itu hari lain untuk mengueapkan keputusannya. (ISR. 146; Rv. 49, 79, 180, 321 dst.; IR. 131, 135.)"}, {"l": "RV", "p": "48", "b": "Bagian 4. Keputusan Pengadilan Pada Umumnya.", "t": "Hakim sebelum mengambil putusan akhir dapat mengambil putusan persiapan atau putusan sela. Putusan persiapan mencakup putusan-putusan dan surat-surat perintah yang dikeluarkan untuk memberi petunjuk-petunjuk mengenai perkara dan yang bermaksud mempersiapkan keputusan akhir tanpa mempengaruhi pokok perkaranya. Putusan sela mencakup putusan-putusan dan surat-surat perintah yang memberi jalan kepada hakim sebelum memutus perkara yang bersangkutan memperoleh bukti, memerintahkan suatu penyelidikan ataupun pengarahan yang dapat menentukan dalam pengambilan keputusan. (KUHPerd. 1929 dst., 1940 dst.; Rv. 58, 99, 138, 171, 211 dst., 215 dst., 230 dst., 262 dst., 331 dst., 351, 425, 783; IR. 185.)"}, {"l": "RV", "p": "49", "b": "Bagian 4. Keputusan Pengadilan Pada Umumnya.", "t": "Jika hakim telah menentukan hari untuk mengueapkan putusan dan para pihak sedang mengadakan pembicaraan untuk mencapai suatu penyelesaian damai, maka mereka dapat memohon kepada hakim agar pengucapan putusan untuk sementara ditangguhkan. (KUHPerd. 1851, Rv. 31.)"}, {"l": "RV", "p": "50", "b": "Bagian 4. Keputusan Pengadilan Pada Umumnya.", "t": "Para hakim dalam musyawarahnya karenajabatan wajib menambah dasar hukum yang mungkin tidak dikemukakan oleh para pihak. Mereka wajib memberi putusan tentang semua hal yang dituntut. Mereka dilarang memberikan putusan tentang hal-hal yang tidak dituntut atau memberikan lebih daripada yang dituntut. (RO. 30 dst., 39 dst.; KUHPerd. 1940, 1950; Rv. 47, 128, 132 dst., 138, 171, 173, 211, 215, 385-20, 31 dan 41, 643-40; IR. 178.)"}, {"l": "RV", "p": "51", "b": "Bagian 4. Keputusan Pengadilan Pada Umumnya.", "t": "Jika hakim memerintahkan agar para pihak datang menghadap, maka ia menentukan hari dan jam untuk itu di dalam putusan. (Rv. 31, 68, 230 dst.) 52. Setiap putusan sela yang memerintahkan sumpah harus memuat perbuatan-perbuatan apa yang harus dinyatakan dalam lafal sumpah dan pengambilan sumpah dilakukan dengan dihadiri oleh pihak lawan atau setelah lawan dipanggil dengan patut. Jika suatu pihak yang diminta mengucapkan sumpah oleh pihak lawan pada hari yang ditentukan tidak datang, maka ia dianggap menolak melakukan sumpah itu, kecuali ia mengajukan bantahan (perlawanan) dengan alasan ia tidak datang karena ada halangan yang sah. (KUHPerd. 1929 dst., 1932, 1940 dst., 1944 dst.; Rv. 46, 48, 68, 77 dst., 106, 236; IR. 156 dst.) r g"}, {"l": "RV", "p": "53", "b": "Bagian 4. Keputusan Pengadilan Pada Umumnya.", "t": "s . o l i t a Jika ada tuntutan sebagian (provisionil) dan perkara tersebut siap diputus dalam tuntutan pokoknya serta sebagiannya, maka terhadap itu a hakim menjatuhkan satu keputusan. (KUHPerd. 190, 212 dst., 246, 457, l. eg 0 0 0 561, 1738; Rv. 55-8 , 68, 115-2 , 241 dst., 286, 332, 344-3 , 785.)"}, {"l": "RV", "p": "54", "b": "Bagian 4. Keputusan Pengadilan Pada Umumnya.", "t": "(s.d.u. dg. w w S. 1908-522.) Pelaksanaan sementara putusan-putusan w hakim meskipun ada banding atau perlawanan dapat diperintakan bila: 10. putusan didasarkan atas suatu alas hak otentik; 2 . putusan didasarkan atas surat di bawah tangan yang diakui oleh pihak terhadap siapa dapat dipakai sebagai dasar, atau yang dianggap diakui menurut hukum, juga dianggap diakui jika perkara diputus tanpa kehadiran tergugat (verstek); 30. dalam hal telah ada penghukuman dengan keputusan hakim yang mendahuluinya yang terhadapnya tidak dapat diajukan perlawanan atau tidak dapat dimintakan banding. (IR. 180.) Apakah perintah ini diberikan dengan atau tanpa jaminan perseorangan diserahkan kepada pertimbangan hakim. (KUHPerd. 1820 dst., 1830, 1868, 1870 dst., 1875, 1917 dst.; Rv. 55 dst., 82, 84, 148 dst., 155 287, 338, 346 dst., 403, 437, 585, 855.)"}, {"l": "RV", "p": "55", "b": "Bagian 4. Keputusan Pengadilan Pada Umumnya.", "t": "Pelaksanaan sementara keputusan-keputusan hakim meskipun ada banding atau perlawanan dapat diperintahkan dengan atau tanpa jaminan perseorangan, dalam hal-hal yang bersangkutan dengan: 10. penyegelan dan pembukaan segel atau pendaftaran kekayaan; (Rv. 652 dst., 663 dst., 672 dst.; Ov. 100 dst.) 20. perbaikan-perbaikan yang mendesak; (KUHPerd. 1551, 1555.) 3 . pengosongan barang yang disewakan, jika tidak ada bukti tertulis tentang sewa-menyewa yang masih berlaku, diperbaharui atau diperpanjang atau jika waktu sewanya sudah habis; (KUHPerd. 1570 dst., 1581, 1587, 1597.) 4 . pengangkatan orang-orang yang mengelola barang-barang sengketa, komisaris-komisaris dan penyimpan-penyimpan; (KUHPerd. 1736, 1738; Rv. 454, 508, 561, 580-4 .) 50. penerimaan jaminan-jaminan dan jaminan lanjutan; (KUHPerd. 1820, 1823; Rv. 614.) 6 . pengangkatan wali, pengampu serta pengurus-pengurus lain serta pemberian pertanggungjawabannya; (KUHPerd. 348, 359 dst., 369 dst., 409 dst., 441, 449 dst., 463 dst., 979, 1127; F. 13; Rv. 764 dst.) 7 . (s. d. u. dg. S. 1908-552.) uang tahunan, atau pemberian nafkah dan pada umumnya pelunasan sejumlah uang tertentu; (KUHPerd. 0 0 213, 225 dst., 321 dst., 960-2 , 1429-3 …"}, {"l": "RV", "p": "56", "b": "Bagian 4. Keputusan Pengadilan Pada Umumnya.", "t": "Jika hakim tidak memerintahkan pelaksanaan sementara, maka ia tidak r dapat memutuskan hal itu kemudian, tanpa mengurangi hak para pihakg untuk menuntut hal ini dalam banding. (Rv. 347 dst.) s . o"}, {"l": "RV", "p": "57", "b": "Bagian 4. Keputusan Pengadilan Pada Umumnya.", "t": "l i t a Pelaksanaan sementara tidak dapat diperintahkan terhadap biaya, a meskipun hal itu dikabulkan sebagai pengganti kerugian dan bunga. l. eg (KUHPerd. 1243 dst., 1366 dst.; Rv. 58, 460, 540, 605, 725, 732, 741, 743.)"}, {"l": "RV", "p": "58", "b": "Bagian 4. Keputusan Pengadilan Pada Umumnya.", "t": "w w (s.d.u. dg. putusan, untuk membayar w S. 1908-522.) Barangsiapa dinyatakan kalah dalam biaya perkara. Namun biaya itu diperhitungkan seluruh atau sebagian antara suami dan isteri, keluarga sedarah dalam garis lurus, saudara laki-laki atau perempuan atau keluarga karena perkawinan dalam derajat yang sama, juga jika para pihak dalam beberapa hal saling dikalahkan. Demikian pula hakim akan membebankan kepada pihak yang telah mengeluarkan atau menyebabkan keluarnya biaya yang tidak perlu, biaya yang dikeluarkan itu. Dalam hal putusan sebagian (provisionil), putusan persiapan serta putusan sela, maka putusan mengenai biaya dapat ditangguhkan sampai pada keputusan akhir. (s.d.t. dg. S. 1908-522.) Jumlah biaya yang harus dipikul oleh pihak yang kalah, ditetapkan dalam putusan hakim untuk hal-hal sebelum dijatuhkan putusan dan tidak mengenai hal-hal yang dikeluarkan oleh pihak sendiri. (s.d.t. dg. S. 1908-522.) Dalam perkara-perkara yang oleh peraturan perundang-undangan diwajibkan atau diperbolehkan tindakan-tindakan atau pembelaan-pembelaan oleh para pengacara, maka segera setelah pembelaan itu dilakukan, oleh pengacara tersebut disampaikan perhitungan-perhitungan biaya. Bila hal …"}, {"l": "RV", "p": "59", "b": "Bagian 4. Keputusan Pengadilan Pada Umumnya.", "t": "(s.d.t. dg. S. 1908-522.) Dalam perkara-perkara tersebut dalam pasal 58 bagian terakhir, di dalam putusan sudah termasuk upah serta uang muka para pengacara menurut tarip-tarip yang ada atau yang akan ditentukan kem udian. (RO. 191; Rv. 106, 610.) Hal yang sama berlaku juga terhadap biaya yang berhubungan dengan penggunaan juru bahasa serta pembuatan terjemahan-terjemahan. Uang muka dibayar oleh pihak yang memohon digunakannya juru bahasa atau dibuatnya terjemahan atau juga karena jabatannya diperintahkan oleh hakim agar dibayar oleh penggugat. (Rv. 33; IR. 130 dst., 182; RBg. 154 dst., 193.)"}, {"l": "RV", "p": "60", "b": "Bagian 4. Keputusan Pengadilan Pada Umumnya.", "t": "Dengan tidak mengurangi apa yang ditentukan dalam pasal 192 dan 203 RO., maka pengacara danjuru sita yang menyimpang dari tugas yang ada padanya dan siapa pun yang mengabaikan kepentingan-kepentingan yang penigurusannya diserahkan kepadanya dapat dihukum untuk menanggung dari saku sendiri seluruh atau sebagian biaya, bahkan untuk mengganti kerugian dan bunga, jika ada alasan-alasan untuk itu tanpa dapat menuntutnya dari mereka yang memberi kuasa kepadanya. (KUHPerd. 331 dst., 449 dst., 979, 1243 dst.; Rv. 21, 58, 93, 98, 256, 264, 607.) r g"}, {"l": "RV", "p": "61", "b": "Bagian 4. Keputusan Pengadilan Pada Umumnya.", "t": "s . o l i a (s. d. u. dg. S. 1908-522.) Keputusan wajib diucapkan sendiri oleh t hakim dan berisi: (RO. 29; Rv. 47, 64 dst., 632; IR. 184; RBg. 195.) a 10. nama-nama serta tempat tinggal para pihak serta nama-nama para l. eg 0 0 pengacara, jika digunakan pengacara; (Rv. 8-1 dan 2 ; 106 dst.; S. 1853-64.) didengar; (Rv. 322.) w w 20. pendapat akhir dari kesimpulan penuntut umum dalam hal ia w 3 . pertimbangan para penasihat menurut pasal 7 RO. dalam perkara- perkara yang memerlukan nasihat mereka; 40. dasar pertimbangan-pertimbangan putusan, tentang kejadian- kejadian serta tentang hukumya, masing-masing sendiri dan keputusannya. (RO. 30 dst., 173; Rv. 50, 414; IR. 184.) Pada akhimya disebut juga nama-nama hakim yang mengadili perkara serta penuntut umum yang mengikuti persidangan-persidangan. (RO. 121, 154; Sv. 174.)"}, {"l": "RV", "p": "62", "b": "Bagian 4. Keputusan Pengadilan Pada Umumnya.", "t": "Keputusan hakim oleh panitera dimasukkan dalam surat putusan (audientieblad) dan selambat-lambatnya dalam waktu dua kali dua puluh empat jam ditandatangani oleh ketua dan panitera. (Rv. 65; IR. 186.)"}, {"l": "RV", "p": "63", "b": "Bagian 4. Keputusan Pengadilan Pada Umumnya.", "t": "Jika ketua berhalangan untuk menandatangani surat putusan, maka hal itu dilakukan oleh hakim anggota yang tertua yang duduk dalam majelis. Jika panitera berhalangan, maka hal itu dinyatakan dengan tegas dalam surat putusan. (RO, 53; Rv. 62; IR. 187; RBg. 198.)"}, {"l": "RV", "p": "64", "b": "Bagian 4. Keputusan Pengadilan Pada Umumnya.", "t": "(s.d.u. dg. S. 1908-522.) Penjaminan surat keputusan dilakukan tanpa kerja sama dengan para pihak dan memuat, di samping apa yang dimuat dalam pasal 61, juga: (Rv. 66, 435, 853, 858.) 10. pendapat terakhir dari kesimpulan para pihak atau jika itu tidak tertulis, apa yang dicatat oleh panitera; (Rv. 111, 113 dst., 119 dst.) 2 . pernyataan bahwa putusan telah diucapkan di muka umum; (ISR. 146; RO. 29.) 3 . hari/tanggal putusan diucapkan. (Rv. 61, 142 dst.) 65. Dicabut dg. Inv. Sw."}, {"l": "RV", "p": "66", "b": "Bagian 4. Keputusan Pengadilan Pada Umumnya.", "t": "Panitera wajib atas permintaan para pihak memberikan salinan surat keputusan kepada mereka segera bila sudah dimungkinkan dengan ancaman mengganti biaya, kerugian dan bungajika ada alasan untuk itu. (KUHPerd. 1243; Rv. 64, 607, 853.)"}, {"l": "RV", "p": "67", "b": "Bagian 4. Keputusan Pengadilan Pada Umumnya.", "t": "Semua putusan yang membebani kewajiban timbal-balik kepada kedua pihak, atau yang menimbulkan hak dan kewajiban untuk kedua pihak dapat dilaksanakan oleh masing-masing untuk kepentingan mereka sendiri. (Rv. 435 dst., 764 dst., 831 dst.)"}, {"l": "RV", "p": "68", "b": "Bagian 4. Keputusan Pengadilan Pada Umumnya.", "t": "r g (s.d.u. dg. . o S. 1908-522.) surat-surat keputusan dan surat-surat s perintah tersebut dalam pasal 48 tidak perlu diperingatkan, kecuali jika karena ketentuan-ketentuan buku kedua l i t a undang-undang diperlukan untuk tuntutan kewajiban keuangan yang harus dipenuhi ini a l. eg pihak lain. (Rv. 58, 70, 82, 88, 106 dst., 139,, 435, 443, 594.)"}, {"l": "RV", "p": "69", "b": "Bagian 4. Keputusan Pengadilan Pada Umumnya.", "t": "Dicabut dg. S. 1908-522. w w w"}, {"l": "RV", "p": "70", "b": "Bagian 5. Penanggungan.", "t": "(s.d.u. dg. S. 1908-522.) Jika seorang tergugat berpendapat ada alasan untuk memanggil seseorang untuk menanggungnya dan pemanggilan tidak dilakukan sebelum hari sidang pemeriksaan perkaranya, maka ia pada hari yang ditentukan untuk mengadakan bantahan harus mengajukan kesimpulan disertai alasan-alasan untuk itu sebelum bantahan dilakukan. Di dalam kesimpulan itu boleh dimasukkan tangkisan tentang ketidakwewenangan hakim, menyimpang dari apa yang ditentukan dalam pasal 114 dan bila ini tidak terjadi dianggap tidak diajukan, kecuali bila hakim tidak berwenang berdasarkan pokok perselisihan. Bila penggugat berpendapat ada alasan-alasan untuk memanggil seseorang untuk menanggungnya, maka ia harus mengajukan permohonan untuk itu dengan kesimpulan yang disertai alasan-alasan pada hari ia harus mengajukan jawaban balik (replik). Jika permohonan dikabulkan, maka hakim akan memberikan waktu yang cukup berdasarkan jarak ke tempat tinggal si penanggung dan menentukan hari untuk memeriksa perkara pokoknya maupun perkara penanggungan. (Rv. 99.) Putusan yang mengabulkan permohonan penanggungan tidak perlu diberitahukan kepada penanggung. Hal itu dimasukkan dalam gugatan dan diserahkan …"}, {"l": "RV", "p": "71", "b": "Bagian 5. Penanggungan.", "t": "Jika permohonan penanggungan tidak diajukan pada hari yang sudah ditentukan atau jika tuntutan penanggungan tidak dilakukan dalam waktu yang telah ditentukan, maka tanpa penundaan dilanjutkan pemeriksaan perkara yang mula-mula. (KUHPerd. 1503; Rv. 70.)"}, {"l": "RV", "p": "72", "b": "Bagian 5. Penanggungan.", "t": "(s.d.u. dg. S. 1908-522.) Dalam hal penanggungan terhadap hipotek atau hak-hak kebendaan lain, maka penanggung selalu dapat mengambil alih perkara tertanggung, yang dibiarkan di luar acara, jika ia menghendakinya, sebelum ada suatu keputusan dijatuhkan antara dia dan pihak lawan semula. Namun si tertanggung, jika menghendakinya, dapat tetap ikut berperkara untuk mempertahankan haknya; juga pihak lawan si tertanggung untuk mempertahankan haknya dapat menuntut r g si 528, 1208, 1492; Rv. 74, 117, 279 dst.) s . o tertanggung untuk tetap ikut dalam perkara itu. (RO. 127; KUHPerd."}, {"l": "RV", "p": "73", "b": "Bagian 5. Penanggungan.", "t": "l i t a a Putusan-putusan yang dijatuhkan terhadap si penanggung seperti l. eg tersebut dalam pasal yang lalu dilaksanakan terhadap si tertanggung. Putusan cukup diberitahukan kepada para tertanggung, kecuali jika w mereka berada di luar proses perkara, atau jika mereka tetap ikut dalam perkara tanpa diperlukan tuntutan atau gugatan lain. w Mengenai biaya, kerugian dan bunga, maka penyelesaiannya dan w pelaksanaannya hanya dapat dilakukan terhadap si penanggung. Namun jika si penanggung ternyata tidak mampu, maka si tertanggung, jika dikeluarkan dari perkara, harus menanggung biaya-biayanya, begitu pula mengenai ganti-rugi dan bunga bila oleh hakim dianggap beralasan untuk itu. (KUHPerd. 1104, 1199, 1293, 1496-30; Rv. 58, 67, 72, 74, 435 dst., 607 dst.)"}, {"l": "RV", "p": "74", "b": "Bagian 5. Penanggungan.", "t": "Dalam hal penanggungan yang sederhana, maka si penanggung hanya dapat masuk dalam perkara tanpa mengambil alih perkaranya dari si tertanggung. (KURPerd. 1084, 1843; Rv. 72, 117, 279.)"}, {"l": "RV", "p": "75", "b": "Bagian 5. Penanggungan.", "t": "(s.d.u. dg. S. 1908-522.) Dalam hal perkara aslinya dan perkara penanggung siap untuk diputus, maka diputus bersama-sama, dalam hal ini jika penggugat atau tergugat tidak memohonnya, perkara pokok diputus terpisah. (Rv. 249.)"}, {"l": "RV", "p": "76", "b": "Bagian 5. Penanggungan.", "t": "Barangsiapa digugat karena penanggungan wajib berperkara di hadapan hakim yang berwenang menangani perkara yang mula-mula, meskipun ia menyangkal menjadi seorang penanggung, tetapi jika jelas ternyata gugatan yang asli hanya bermaksud untuk menariknya dari hakimnya yang berwenang, maka ia akan diajukan ke muka hakim itu. (ISR. 136; KUHPerd. 1493 dst., 1674; Rv. 9914, 130.)"}, {"l": "RV", "p": "77", "b": "Bagian 6. Putusan Tanpa Kehadiran Tergugat Dan Perlawanan.", "t": "Jika penggugat pada hari yang telah ditentukan tidak datang menghadap, maka perkara diputus tanpa kehadirannya (verstek), dan pihak lawan dibebaskan dari perkara tersebut dengan menghukum penggugat membayar biaya perkara. Dalam hal ini tidak boleh diajukan perlawanan, tetapi penggugat dapat mengajukan gugatan baru sesudah membayar biaya verstek. (Rv. 46 dst., 91, 94, 121, 330, 405 dst., 780; IR. 124 dst.)"}, {"l": "RV", "p": "78", "b": "Bagian 6. Putusan Tanpa Kehadiran Tergugat Dan Perlawanan.", "t": "Jika tergugat tidak datang menghadap setelah tenggang waktu serta tata tertib acara dipenuhi, maka putusan dbatuhkan tanpa kehadiran tergugat dan penggugat dikabulkan, kecuali jika hakim menganggap gugatan itu tanpa hak atau tanpa dasar hukum. (Rv. I dst., 46, 80, 83, 89, 91, 9 la, 94, 107, 121, 254, 405; Sv. 217; IR. 125, 345; RBg. 149, 634.)"}, {"l": "RV", "p": "79", "b": "Bagian 6. Putusan Tanpa Kehadiran Tergugat Dan Perlawanan.", "t": "Setiap putusan tanpa kehadiran salah satu pihak (verstek) selalu r g s . o diticapkan dalam sidang pengadilan; tetapi hakim dapat memerintahkan agar surat-surat yang bersangkutan diletakkan di meja dahulu dan 47, 77 dst., 94.) l i a mumutuskan kesimpulankesimpulan pihak penggugat pada hari lain. (Rv. t a l. eg"}, {"l": "RV", "p": "80", "b": "Bagian 6. Putusan Tanpa Kehadiran Tergugat Dan Perlawanan.", "t": "Semua pihak yang telah dipanggil dan tidak datang menghadap dimuat Pasal 81. w w dalam suatu putusan. (Rv. 77 dst.) (s.d. u. dg. w S. 1889-31.) Jika ada beberapa tergugat dan di antaranya ada satu atau lebih yang tidak datang menghadap, maka terhadap yang tidak datang diputus tanpa kehadirannya, sedangkan untuk yang menghadap dilakukan pemeriksaan biasa. Tiap-tiap pihak yang datang menghadap berhak untuk memberitahukan lewat jurusita pihak-pihak yang tidak datang dengan panggilan semua pihak untuk menghadap pada hari yang telah ditentukan untuk memeriksa perkara yang bersangkutan. Untuk panggilan-panggilan ini harus diperhatikan ketentuan-ketentuan mengenai tenggang waktu. Terhadap semua pihak dijatuhkan satu putusan yang dipandang sebagai suatu putusan atas bantahan dan terhadapnya tidak dimungkinkan perlawanan. (Rv. I dst., 14, 83, 91, 121 dst., 330, 782, 949.)"}, {"l": "RV", "p": "82", "b": "Bagian 6. Putusan Tanpa Kehadiran Tergugat Dan Perlawanan.", "t": "(s.d.u. dg. S. 1938-276.) Putusan-putusan dengan kehadiran tergugat tidak boleh dilaksanakan sebelum lewat empat belas hari setelah diberitahukan dengan perantaraan juru sita kepada orangnya sendiri di tempat tinggatnya atau dengan cars seperti ditentukan dalam pasal 3 dan 6 mengenai gugatan, kecuali jika pelaksanaan sementara diperintahkan hakim. (Rv. 54, 88; Sv. 218; IR. 345; RBg. 634.)"}, {"l": "RV", "p": "83", "b": "Bagian 6. Putusan Tanpa Kehadiran Tergugat Dan Perlawanan.", "t": "(s.d. u. dg. S. 1889-31.) Tergugat yang perkaranya diputus tanpa kehadirannya (verstek) dapat mengajukan perlawanan (verzet). (s.d.u. dg. S. 1908-522.) Perlawanan harus dilakukan dalam waktu tiga puluh hari setelah putusan atau suatu akta yang dibuat berdasarkan keputusan itu atau akta untuk pelaksanaan keputusan itu diberitahukan kepadanya pribadi, atau juga sesudah ia melakukan sesuatu yang menyatakan bahwa ia mengetahui tentang putusan atau dimulainya pelaksanaan putusan itu. Di luar keadaan tersebut dalam ayat yang lain, maka perlawanan dapat diterima sampai putusan dilaksanakan. Terhukum yang menyatakan menerima putusan tidak dapat mengajukan perlawanan. (Rv. 52, 77 dst., 81, 84, 89, 91, 330, 389, 405, 408 dst., 428, 636, 763, 786, 949; Sv. 219 dst., 223.)"}, {"l": "RV", "p": "84", "b": "Bagian 6. Putusan Tanpa Kehadiran Tergugat Dan Perlawanan.", "t": "(s. d. u. dg. S. 1889-31; S. 1908-522; S. 1916-530.) Keputusan dianggap sudah selesai dilaksanakan: - dalam hal pelaksanaan putusan tentang benda bergerak, setelah diadakan penjualan; - dalam hal putusan pembayaran sejumlah uang kepada pihak-ketiga, setelah pembayaran kepada pihak ketiga; - dalam hal pelaksanaan putusan (uitwinning) benda tetap, pada hari ketiga puluh setelah pemberitahuan pertama seperti ditentukan dalam pasal 517; - dalam hal perceraian atau pisah meja dan ranjang, setelah r g s . o diberitahukan kepada tergugat dan diumumkan dengan cara seperti ditentukan dalam pasal 843 dan juga sesudah lewat sembilan puluh sesudah diumumkan. l i a hari setelah diberitahukan maupun setelah lewat tiga puluh hari t a Perlawanan yang dilakukan dalam jangka waktu tersebut di atas dan l. eg dengan cara seperti ditentukan di bawah ini, mencegah pelaksanaan putusan hakim, bila hal itu tidak diperintahkan oleh hakim meskipun w ada perlawanan. (Rv. 54 dst., 82 dst., 86, 91 dst., 385, 389, 408 dst., 442, 466 dst., 587 dst., 590, 603.) w"}, {"l": "RV", "p": "85", "b": "Bagian 6. Putusan Tanpa Kehadiran Tergugat Dan Perlawanan.", "t": "(s. d. u. dg. w S. 1908-522.) Pemberitahuan perlawanan menyebutkan secara singkat alasan-alasan pihak itu serta gugatan terhadap diri penggugat asli atau pemberitahuan tentang tempat tinggal pilihannya. Penggugat asli berhak, sesuai dengan pasal 107, untuk memanggil lebih awal dari hari yang telah disebutkan dalam pemberitahuan perlawanan. (KUHPerd. 24; Rv. 1 dst., 6 dst., 10, 14, 84, 288.)"}, {"l": "RV", "p": "86", "b": "Bagian 6. Putusan Tanpa Kehadiran Tergugat Dan Perlawanan.", "t": "Perlawanan dapat dilakukan baik dengan akta otentik di luar pengadilan maupun pada waktu diberitahukan keputusan hakim, atau pada waktu disampaikan akta lain yang bermaksud melaksanakan putusan tersebut, dengan kewajiban pada pelawan untuk mengulangi perlawanannya menurut pasal yang lalu dalam waktu yang sama dengan waktu ia digugat atau yang semestinya digugat menurut ketentuan- ketentuan bagian pertama bab ini. Juru sita yang bertugas memberitahukan atau melaksanakan putusan harus mencantumkan hal perlawanan itu di dalam surat laporannya atau berita acara dengan ancaman, bila tidak mencantumkannya, ia akan menanggung biaya, kerugian dan bunganya. (Rv. 60, 82, 85.)"}, {"l": "RV", "p": "87", "b": "Bagian 6. Putusan Tanpa Kehadiran Tergugat Dan Perlawanan.", "t": "Pihak pelawan berhak untuk meminta ke bagian kepaniteraan agar hal itu dicatat dalam daftar (register) yang disediakan untuk itu dengan menyebut para pihak, hari tanggal keputusan tanpa kehadiran tergugat (verstek) dan adanya perlawanan yang dilakukan. (Rv. 88, 413, 438.)"}, {"l": "RV", "p": "88", "b": "Bagian 6. Putusan Tanpa Kehadiran Tergugat Dan Perlawanan.", "t": "(s.d.u. dg. S. 1938-276.)Pada putusan verstek, yang pelaksanaannya sementara tidak diperintahkan, dapat dilaksanakan terhadap pihak ketiga sebelum lewat empat belas hari sesudah diberitahukan kepada yang bersangkutan menurut pasal 82 dan dengan menunjukkan pernyataan panitera, bahwa dalam daftar-daftar (register) yang bersangkutan tidak tercatat adanya perlawanan. (Rv. 82, 437 dst.)"}, {"l": "RV", "p": "89", "b": "Bagian 6. Putusan Tanpa Kehadiran Tergugat Dan Perlawanan.", "t": "Seorang pelawan yang untuk kedua kalinya membiarkan ia diputus verstek tidak dapat diterima untuk mengadakan perlawanan baru. (Rv. 57 dst., 77 dst., 405.)"}, {"l": "RV", "p": "90", "b": "Bagian 6. Putusan Tanpa Kehadiran Tergugat Dan Perlawanan.", "t": "Dicabut dg. S. 1889-31."}, {"l": "RV", "p": "91", "b": "Bagian 6. Putusan Tanpa Kehadiran Tergugat Dan Perlawanan.", "t": "Biaya verstek, termasuk biaya putusan dan biaya yang dipandang timbul sebagai akibat tidak hadimya pihak yang melakukan perlawanan, menjadi beban pihak Pelawan, kecuali jika verstek dijatuhkan r g berdasarkan gugatan yang dinyatakan batal. (Rv. 57 dst., 77 dst., 94, 98.) s . o"}, {"l": "RV", "p": "91A", "b": "Bagian 6. Putusan Tanpa Kehadiran Tergugat Dan Perlawanan.", "t": "l i t a (s.d.t. dg. a S. 1908-522.) Tergugat yang perkaranya menghadapi l. eg putusan verstek, selama putusan itu belum dijatuhkan, berhak untuk menghadap pada hari yang ditentukan yang menyebabkan tidak berlakunya w akibat-akibat verstek, kecuali mengenai biaya yang disebabkan karena keterlambatannya dan untuk itu berlaku pasal 91. (Rv. 78 dst., 108 dst.) w w"}, {"l": "RV", "p": "92", "b": "Bagian 7. Keadaan Batal.", "t": "Tidak ada surat pemberitahuan atau akta tata cara Peradilan (rechspleging) yang dapat dinyatakan batal, jika peraturan-peraturan perundang-undangan tidak memerintahkan secara tegas tentang kebatalannya. (Rv. 94, 106, 339, 443, 478, 533, 729.) 93. Dihapus dg. Inv. Sw. 3."}, {"l": "RV", "p": "94", "b": "Bagian 7. Keadaan Batal.", "t": "Apa yang ditentukan dalam pasal-pasal 1, 3, 4, 6, 8, 9, 10, 11, 12, 13, 14, 15, 17, 18 dan 20 harus diperhatikan dengan ancaman batal. (Rv, 106.) Hal tergugat tidak datang menghadap, maka terhadapnya tidak dapat dijatuhkan putusan verstek dan hakim dalam menyatakan keadaan batal, menghukum penggugat membayar biaya perkara. (Rv. 78, 91, 96 dst., 339.)"}, {"l": "RV", "p": "95", "b": "Bagian 7. Keadaan Batal.", "t": "Dicabut dg. S. 1908-522."}, {"l": "RV", "p": "96", "b": "Bagian 7. Keadaan Batal.", "t": "(s.d.u. dg. S. 1908-522.) Bila tergugat datang menghadap memenuhi panggilan gugatan dan mengajukan tuntutan pernyataan batalnya panggilan gugatannya, maka hakim dapat menolak tangkisan itu bila kealpaan atau pelanggaran yang dilakukan sedemikian rupa sehingga tergugat dianggap tidak dirugikan dalam pembelaannya dan juga tidak ada kepentingan dalam menggunakan keadaan batal itu. (Rv. 24, 188, 339.)"}, {"l": "RV", "p": "97", "b": "Bagian 7. Keadaan Batal.", "t": "Jika panggilan gugatan telah dilakukan oleh orang yang tidak berwenang untuk itu, maka hakim berkewajiban untuk menyatakan panggilan gugatan itu batal. (AB. 23; Rv. 1, 20, 94, 96, 339.)"}, {"l": "RV", "p": "98", "b": "Bagian 7. Keadaan Batal.", "t": "Biaya akta-akta dalam tata cars peradilan yang batal atau yang tidak diperlukan, dibebankan kepada pengacara atau juru sita yang telah menyebabkan dibuatnya atau dikeluarkannya akta-akta itu. Di samping itu kepada mereka, menurut keadaan, dapat dipertanggungjawabkan atas timbulnya kerugian dan bunga dan bahkan, menurut keadaan, dapat dijatuhi hukuman seperti tersebut dealam pasal 192 RO. (KUHPerd. 1243, 1365; Rv. 21, 60, 264, 339, 53 1; Sv. 305.) r g s . o"}, {"l": "RV", "p": "100", "b": "Bagian 1. Gugatan.", "t": "(s.d.u. dg. S. 1915-299, 642.) Seorang asing bukan penduduk, bahkan tidak berdiam di Indonesia, dapat digugat di hadapan hakim Indonesia untuk Perikatan-perikatan yang dilakukan di Indonesia atau di mana saja dengan warga negara Indonesia. (ISR. 136; AB. 3; Rv. 99, 761.)"}, {"l": "RV", "p": "101", "b": "Bagian 1. Gugatan.", "t": "Didalam tuntutan-tuntutan kebendaan atau dalam tuntutan-tuntutan yang bersifat campuran, maka dalam gugatan harus dijelaskan di mana letak benda-benda tetap itu, begitu pula nama serta sifatnya. (Rv. 0 0 92, 99, 102, 506-3 , 517-2 .)"}, {"l": "RV", "p": "102", "b": "Bagian 1. Gugatan.", "t": "Tuntutan perorangan adalah suatu tuntutan yang obyeknya adalah mengenai pelaksanaan suatu perikatan perorangan yang timbul karena suatu persetujuan atau karena undang-undang. (KUHPerd. 1233 dst.) Tuntutan kebendaan adalah suatu tuntutan mengenai hak milik suatu benda tertentu atau suatu hak kebendaan lain. (KUHPerd. 528, 574, 711, 720, 737, 740, 756, 818, 1725, 1977; KUHD 230 dst.) r g mengenai kebendaan, yaitu: s . o Tuntutan campuran adalah tuntutan mengenai perorangan dan sekaligus - - l i t tuntutan untuk mendapatkan warisan; (KUHPerd. 834.) a tuntutan untuk pembagian harta benda; (KUHPerd. 1066 dst.) - a tuntutan pemisahan harta bersama; (KUHPerd. 128, 573, 1652.) l. eg - tuntutan untuk memberi batas antara dua bidang tanah yang berdampingan. (RO. 124 dst., 159; KUHPerd. 624, 630a dst., 643.)"}, {"l": "RV", "p": "103", "b": "Bagian 1. Gugatan.", "t": "w w w Tuntutan mengenai hak menguasai (bezit) dan mengenai hak milik (petitoir) tidak dapat dilakukan bersama. (KUHPerd. 550, 557, 562 dst., 565, 574; Rv. 55-90, 104 dst., 244-30.)"}, {"l": "RV", "p": "104", "b": "Bagian 1. Gugatan.", "t": "Barangsiapa telah mengajukan tuntutan mengenai hak milik atas suatu benda tidak dapat diterima dalam tuntutan mengenai hak menguasai (bezit). (KUHPerd. 565; Rv. 103, 105.)"}, {"l": "RV", "p": "105", "b": "Bagian 1. Gugatan.", "t": "Seorang tergugat dalam perkara mengenai hak menguasai (bezit) tidak boleh mengadakan tuntutan mengenai hak milik atas benda yang bersangkutan sewm gugatan mengenai hak menguasai (bezit) belum selesai. Jika ia dalam hal terakhir diputus kalah, maka ia tidak dapat diterima dalam gugatannya tentang hak milik sebelum memenuhi seluruhnya isi keputusan terhadapnya, kecuali bila pelaksanaannya tidak ia jalankan atau terhambat oleh utang pihak yang menang; dalam hal itu maka hakim yang memeriksa gugatan mengenai hak milik atas benda yang bersangkutan dapat menentukan jangka waktu yang harus dilampaui sebelum gugatan itu dapat dilakukan. (KUHPerd. 561, 1738- 20; Rv. 53, 103 dst., 244-30.)"}, {"l": "RV", "p": "106", "b": "Bagian 1. Gugatan.", "t": "(s.d. u. dg. S. 1908-522.) Penggugat diwajibkan pada waktu menalankan panggilan gugatan menunjuk seorang pengacara, dengan ancaman gugatannya akan batal. (Rv. 8, 92, 94, 319, 339, 349, 411- 41.) Tempat tinggal tersebut dalam pasal 8 No. 1 , dianggap dipilih di tempat tinggal pengacara tersebut, kecuali jika penggugat telah menyatakan memilih tempat tinggal pilihan lain. (KUHPerd. 24; Rv. 107, 280, 800.) Semua akta dalam acara perkara itu sampai dengan putusan akmr diberitahukan kepada alamat itu dan pengacara itu wajib menandatangani naskah-naskah serta surat-surat yang disebut dalam bab ini dan berikutnya. (KUHPerd. 24; Rv. 68, 160, 199 dst., 206, 211, 217, 221, 230, 250, 256, 267, 272, 280 dst.) Pada surat panggilan gugatan dilampirkan turunan surat-surat yang menjadi dasar gugatan yang bersangkutan. Bila turunan itu, yang mana harus diberikan oleh penggugat selama perkara masih berjalan, tidak ada, maka untuk hal itu tidak boleh dipungut biaya, kecuali untuk surat-surat yang diperlukan selama pembelaan si tergugat atau untuk yang ditimbulkannya, atau untuk perkaraperkara yang harus diselidiki secara tertulis sebagaimana diperintahkan oleh hakim. (KUHPerd. 1886, 1888, 1934, …"}, {"l": "RV", "p": "108", "b": "Bagian 2. Jawaban Dan Penjelasan Perkara.", "t": "Kecuali dalam hal seperti disebut dalam pasal yang lain, maka oleh pengacara yang bertindak atas nama tergugat hal ini dinyatakan di dalam sidang. Pernyataan itu disebut dalam berita acara sidang. Tergugat dianggap memilih tempat tinggal di tempat kedudukan pengacara. Pasal 106 alinea ketiga berlaku dalam hal ini. (KUHPerd. 24; Rv. 106, 349, 413; F 118.)"}, {"l": "RV", "p": "109", "b": "Bagian 2. Jawaban Dan Penjelasan Perkara.", "t": "Tergugat yang tidak menunjuk pengacara diputus verstek dan selanjutnya diselesaikan menurut ketentuan-ketentuan dalam Bagian 6 Bab I. (Rv. 78, 248.)"}, {"l": "RV", "p": "110", "b": "Bagian 2. Jawaban Dan Penjelasan Perkara.", "t": "Kepada orang-orang Indonesia yang datang menghadap sendiri dan tidak segera dapat menunjuk pengacara untuk mewakilinya diberikan kesempatan untuk dalam waktu singkat menunjuk seorang pengacara, kecuali dalam hal gugatan yang batal atau dalam hal berlaku pasal 94 alinea kedua. Bila waktu yang diberikan lampau tanpa ada seorang pengacara yang ditunjuk, maka perkara tanpa diberikan penundaan lagi diputus verstek. (Rv. 46, 77 dst.)"}, {"l": "RV", "p": "111", "b": "Bagian 2. Jawaban Dan Penjelasan Perkara.", "t": "Jika pendaftaran gugatan tidak terjadi seperti dimaksud dalam pasal 23, maka pengacara tergugat berhak untuk meminta agar perkara itu dimasukkan di dalam daftar dengan menyampaikan panggilan gugatan dan surat panggilan pengajuan hari sidang, jika memang itu terjadi. Terhadap penggugat yang tidak datang menghadap, maka perkaranya diputus verstek dan selanjutnya perkara berjalan seperti diatur dalam Bagian 6 Bab 1, kecuali jika dalam hal permohonan pengajuan hari sidang tidak diperhatikan ketentuan-ketentuan dalam pasal 107. (Rv. 77.)"}, {"l": "RV", "p": "112", "b": "Bagian 2. Jawaban Dan Penjelasan Perkara.", "t": "Pada hari sidang atau pada hari lain yang telah ditentukan, r g s . o pengacara penggugat mengemukakan gugatannya yang disertai alasan- alasannya dan pada waktu itu juga di sidang ia menyerahkan turunan 120.) l i a surat gugatnya kepada pengacara tergugat. (Rv. 8, 106, 113, 117, t a l. eg"}, {"l": "RV", "p": "113", "b": "Bagian 2. Jawaban Dan Penjelasan Perkara.", "t": "Setelah itu pada hari itu juga atau pada hari lain yang telah ditentukan, pengacara alasan-alasannya dan w tergugat turunannya w penggugat. (Rv. 107 dst., 120.) mengajukan disampaikan jawabannya kepada disertai pengacara"}, {"l": "RV", "p": "114", "b": "Bagian 2. Jawaban Dan Penjelasan Perkara.", "t": "w Pengacara tergugat berkewajiban mengajukan semua tangkisan dan jawaban mengenai pokok perkaranya bersama-sama dengan ancaman tangkisan yang tidak diajukan gugur dan jika tidak dijawab pokok persoalannya ia akan kehilangan hak untuk mengajukannya. Namun para waris, janda dan wanita-wanita, baik yang bercerai maupun pisah meja dan ranjang atau pisah harta kekayaan yang mendapat waktu untuk mempertimbangkan menerima atau menolak warisan, cukup dengan menunjuk kepada keadaan itu dalam pembelaannya. (KUHPerd. 133 dst., 138, 232, 243, 1023 dst.; Rv. 128, 130, 241.)"}, {"l": "RV", "p": "115", "b": "Bagian 2. Jawaban Dan Penjelasan Perkara.", "t": "Setelah jawaban diberikan dalam persidangan, maka pengacara penggugat diberi kesempatan untuk mengajukan jawabannya kembali (replik) yang dapat dijawab lagi oleh pengacara tergugat (duplik). (Rv. 343.)"}, {"l": "RV", "p": "116", "b": "Bagian 2. Jawaban Dan Penjelasan Perkara.", "t": "Hakim atas permintaan bersama para pihak dapat memberi kesempatan untuk saling menjawab."}, {"l": "RV", "p": "117", "b": "Bagian 2. Jawaban Dan Penjelasan Perkara.", "t": "(s.d.u. dg. S. 1925-198jo. 273.) Hakim menentukan waktu-waktu pengajuan jawaban, bila perlu setelah mempelajari surat-surat. Dalam hal kedua pihak mempunyai pendapat yang sama, maka hakim mengabulkan permohonan mereka, kecuali jika hal itu akan menimbulkan hambatan yang tidak patut dalam pelaksanaan pemeriksaan. Terhadap ketetapan-ketetapan hakim semacam itu tidak ada upaya hukum lain. (Rv. 112 dst., 120, 241, 343.)"}, {"l": "RV", "p": "118", "b": "Bagian 2. Jawaban Dan Penjelasan Perkara.", "t": "Setelah diadakan pertukaran surat jawab-menjawab, maka para pihak diberi kesempatan mengajukan pembelaan atau ditentukan hari lain untuk keperluan itu, kecuali jika para pihak menghendaki putusan hakim berdasarkan surat-surat. (Rv. 249.)"}, {"l": "RV", "p": "119", "b": "Bagian 2. Jawaban Dan Penjelasan Perkara.", "t": "Hakim dalam tahap pembelaan berhak untuk minta penjelasan kepada para pengacara tentang apa yang dimaksud dalam jawaban-jawaban tertulis maupun lisan yang telah mereka sampaikan. (Rv. 112 dst., 120, 241, 249, 343.)"}, {"l": "RV", "p": "120", "b": "Bagian 2. Jawaban Dan Penjelasan Perkara.", "t": "Bila gugatan ditetapkan untuk diperiksa dalam waktu singkat menurut pasal 10 sebelum, alinea terakhir reglemen ini (dalam keadaan yang mendesak), maka pada hari yang telah ditentukan oleh pengacara r g s . o penggugat diajukan tuntutannya yang disertai alasan-alasannya dan sekaligus dalam sidang itu disampaikan turunannya kepada pengacara tergugat. l i t a Pengacara tergugat segera mengajukan jawabannya yang disertai alasan-alasannya dan menyerahkan a turunannya kepada pengacara l. eg penggugat. Hakim atas permintaan para pihak atau karena jabatannya untuk kepentingan jawaban-jawaban watau pembelaan penundaan. (Rv. 47, 107 dst., 117, 249, 285, 605.) w dapat memberikan Pasal 121. w Jika pengacara yang mewakili orang yang semula datang menghadap tetapi kemudian pada sidang lanjutan tidak hadir, maka hal itu tidak dapat menjadi alasan untuk dijatuhkan putusan verstek, tetapi putusan itu dianggap sebagai putusan itu yang dijatuhkan atas bantahan."}, {"l": "RV", "p": "122", "b": "Bagian 2. Jawaban Dan Penjelasan Perkara.", "t": "Para pihak tidak dapat menarik kembali penunjukkan seorang pengacara tanpa menunjuk seorang pengacara lain sebagai penggantinya; selama belum ditunjuk pengacara baru, maka acara berjalan atas nama pengacara yang ditunjuk pertama kali. (KUHPerd. 1813 dst., 1974; Rv. 106, 108, 248 dst., 256, 343.)"}, {"l": "RV", "p": "123", "b": "Bagian 2. Jawaban Dan Penjelasan Perkara.", "t": "Pihak yang jawabannya mendasarkan atas suatu surat, wajib menyebutkan dalam jawaban itu bahwa surat itu diajukan di dalam sidang. Seorang pengacara, bila dipandangnya perlu, dapat meminta turunan semua surat-surat yang diajukan dalam perkara oleh pihak lawan dan turunan-turunannya harus disampaikan dalam waktu delapan hari sesudah permintaan itu. Kecuali itu maka pihak yang bersangkutan wajib, jika lawannya menyatakannya dengan perantaraan pengacara kepada pengacara lawannya, meminta untuk melihat surat-surat aslinya yang diajukan dalam sidang dengan meletakkan suratsurat itu di kepaniteraan ataupun menyerahkannya kepada pengacara pihak lawan, dengan memberi tanda terima. Jika suatu pihak setelah ditentukan hari untuk mengajukan pembelaan masih mengajukan suatu surat, maka ini dilakukannya dengan memberikan turunan kepada pengacara pihak lawan di samping menyampaikan satu turunan kepada panitera dengan tanda terima. Jika mengenai suatu surat tidak dipenuhi ketentuan-ketentuan dalam pasal ini, atau dibiarkan begitu adanya sehingga lawan tidak sempat memberikan jawaban terhadapnya, maka ia hanya dapat menyinggung keadaan itu pada waktu pembelaan. Hakim dapat mengesampingkan surat …"}, {"l": "RV", "p": "124", "b": "Bagian 2. Jawaban Dan Penjelasan Perkara.", "t": "surat-surat dapat disampaikan kepada panitera tanpa meterai."}, {"l": "RV", "p": "125", "b": "Bagian 2. Jawaban Dan Penjelasan Perkara.", "t": "surat-surat harus dikembalikan dalam waktu delapan hari sesudah tanggal tanda terima atau sejak pemberitahuan kepada pihak lawan bahwa surat-surat sudah disampaikan kepada panitera, (Rv. 241.) r g"}, {"l": "RV", "p": "126", "b": "Bagian 2. Jawaban Dan Penjelasan Perkara.", "t": "s . o Jika surat-surat itu tidak dikembalikan dalam tenggang waktu itu, l i a maka pihak yang lalai dapat dipaksa oleh ketua dengan suatu surat t perintah, bahkan dengan paksaan badan (lijfsdwang) dengan tidak a mengurangi tanggung jawab atas penggantian biaya, kerugian dan l. eg bunga, di mana perlu. (KUHPerd. 1243 dst., 1365 dst.; Rv. 241, 580 dst., 607 dst.)"}, {"l": "RV", "p": "127", "b": "Bagian 2. Jawaban Dan Penjelasan Perkara.", "t": "w w Penggugat berhak untuk mengubah atau mengurangi tuntutannya sampai w saat perkara diputus, tanpa boleh mengubah atau menambah pokok gugatannya. (Rv. 8, 344, 503; KUHPerd. 1900.)"}, {"l": "RV", "p": "128", "b": "Bagian 3. Permohonan Sementara Dan Tangkisan Tentang Ketidakwenangan.", "t": "(s.d.u. dg. S. 1915-299, 642.) Orang-orang asing bukan penduduk sebagai penggugat, atau menggabungkan diri atau masuk dalam suatu perkara atas permintaan pihak lawan sebelum melakukan pembelaan atau bantahan diminta jaminan mengenai pembayaran biaya, kerugian dan bunga yang mungkin dapat dibebankan kepadanya. Pihak yang minta jaminan tidak dianggap sebagai telah mengakui wewenang hakim. (ISR. 163, AB. 3-5; KUHPerd. 1827; Rv. 114, 117, 130, 134, 241, 279, 349, 580-90, 611, 614, 872.)"}, {"l": "RV", "p": "129", "b": "Bagian 3. Permohonan Sementara Dan Tangkisan Tentang Ketidakwenangan.", "t": "Putusan hakim yang memerintahkan pemberian jaminan menyebut jumlah uang yang menjadi tanggungan serta Cara pemberiannya. (KUHPerd. 1830; Rv. 349, 611 dst.)"}, {"l": "RV", "p": "130", "b": "Bagian 3. Permohonan Sementara Dan Tangkisan Tentang Ketidakwenangan.", "t": "Barangsiapa yang dihadapkan kepada hakim yang tidak berwenang untuk mengadili sengketa yang bersangkutan dapat menuntut agar hakim itu menyatakan dirinya tidak berwenang. (ISR. 136; RO. 175; Rv. 76, 99, 328, 349.) 131. Dicabut dg. S. 1908-522."}, {"l": "RV", "p": "132", "b": "Bagian 3. Permohonan Sementara Dan Tangkisan Tentang Ketidakwenangan.", "t": "(s.d.u. dg. S. 1908-522.) Dalam hal hakim tidak berwenang karena jenis pokok perkaranya, maka ia meskipun tidak diajukan tangkisan tentang ketidakwenangannya, karena jabatan wajib menyatakan dirinya tidak berwenang. (Rv.130, 328, 349, 951; IR. 134; RBg. 160.)"}, {"l": "RV", "p": "133", "b": "Bagian 3. Permohonan Sementara Dan Tangkisan Tentang Ketidakwenangan.", "t": "(s.d.u. dg. S. 1908-522.) Bila suatu perkara yang menjadi wewenang Residentierechter (hakim Karesidenan), diajukan ke raad van justitie dan tergugat yang hadir tidak mengajukan tangkisan tentang ketidakwewenangannya, maka raad van justitie akan menangani perkara itu dan mengadilinya pada tingkat tertinggi. (Rv. 130, 132, 972.)"}, {"l": "RV", "p": "134", "b": "Bagian 3. Permohonan Sementara Dan Tangkisan Tentang Ketidakwenangan.", "t": "(s.d. u. dg. S. 1901-15; S. 1908-522.) Perkara-perkara yang sebelumnya telah digugat di hadapan hakim lain antara pihak-pihak yang sama mengenai pokok perselisihan yang sama pula atau yang oleh pihak-pihak yang sama mengenai pokok perselisihan yang sama pula telah diserahkan penyelesaiannya kepada para wasit dan masih r g berjalan, atau dalam hal suatu perselisihan yang erat hubungannya s . o dengan suatu perkara yang sudah ada di tangan hakim lain atau ada di tangan para wasit, maka dapat dimintakan agar l i t a perkara dilimpahkan kepada hakim lain itu atau pada para wasit yang telah itu diangkat. a Hal ini harus dilakukan dengan suatu permintaan yang l. eg beralasan sebelum dilakukan pembelaan pada hari yang telah ditentukan untuk pembelaan itu. (s.d. t. dg. w S. 1908-522.) Pelimpahan itu dapat juga diminta oleh penggugat, tetapi hanya dalam tahap dilakukan kesimpulan gugatnya. w (KUHPerd. 1197; Rv. 95, 99, 128, 270, 279, 349, 436, 615.)"}, {"l": "RV", "p": "135", "b": "Bagian 3. Permohonan Sementara Dan Tangkisan Tentang Ketidakwenangan.", "t": "w (s.d.t. dg. S. 1908-522.) Jika ada perkara antara orang-orang yang sama mengenai pokok-pokok sengketa yang sama pada waktu yang bersamaan, atau pada hakim yang saina ada perkara-perkara yang sangat erat hubungannya maka dapat dimintakan penggabungan. Jika penggabungan itu dimintakan oleh tergugat, maka berlakulah kalimat terakhir alinea pertama pada pasal yang lain. Penggabungan dapat juga dimintakan oleh penggugat, tetapi hanya dalam tahap dilakukan kesimpulan gugatnya. (Rv. 112, 114, 120, 134, 244, 279.) Pasal 136 dan 137. Dicabut dg. S. 1908-522."}, {"l": "RV", "p": "138", "b": "Bagian 4. Pemeriksaan Perkara Atas Dasar Jawab-Menjawab Tertulis.", "t": "(s.d.u, dg. S. 1908-522.) Jika setelah dilakukan jawab-menjawab di dalam sidang pengadilan perkara ternyata tidak dapat diselesaikan dengan cara lisan, maka hakim atas permohonan para pihak atau karena jabatan dapat memerintahkan bahwa perkara diperiksa berdasarkan jawab-menjawab tertulis. (Rv. 48, 106, 255, 349.)"}, {"l": "RV", "p": "139", "b": "Bagian 4. Pemeriksaan Perkara Atas Dasar Jawab-Menjawab Tertulis.", "t": "(s.d.u. dg. S. 1908-522.) Perintah pemeriksaan perkara berdasarkan jawab-menjawab tertulis tidak dapat dimohonkan banding, dan tidak ada upaya hukum lain yang tersedia. (Rv. 66, 68.)"}, {"l": "RV", "p": "140", "b": "Bagian 4. Pemeriksaan Perkara Atas Dasar Jawab-Menjawab Tertulis.", "t": "Dalam waktu empat belas hari setelah putusan hakim dijatuhkan untuk pemeriksaan perkara berdasarkan jawab-menjawab tertulis, maka penggugat dikabulkan dengan perantaraan jurusita kepada tergugat surat-surat yang menyebutkan upaya-upaya hukumnya serta menyerahkan turunan-turunannya; berkas itu diakhiri dengan daftar surat-surat untuk menguatkan gugatannya. Berkas surat-surat ini dalam waktu dua puiuh empat jam sesudah diberitahukan disampaikan di kepaniteraan. Akta bukti penyampaian berkas itu diberitahukan kepada tergugat. (Rv. 68, 139, 143.)"}, {"l": "RV", "p": "141", "b": "Bagian 4. Pemeriksaan Perkara Atas Dasar Jawab-Menjawab Tertulis.", "t": "Dalam waktu empat belas hari sesudah pemberitahuan dengan perantaraan juru sita tersebut, tergugat dapat melihat berkas itu serta minta turunan surat-surat yang telah diserahkan kepada panitera dan ia memberitahukan jawabannya dengan upaya-upaya hukum r g kepada penggugat; mendukung jawaban itu. juga disampaikan daftar o surat-surat s . untuk l i a Jawaban serta surat-surat juga diserahkan kepada panitera beserta t turunan-turunannya itu dalam waktu dua puluh empat jam sesudah a pemberitahuan dan akta penyerahan itu juga diberitahukan kepada l. eg pihak lawan. (Rv. 68, 113 dst., 143 dst., 145,,349.)"}, {"l": "RV", "p": "142", "b": "Bagian 4. Pemeriksaan Perkara Atas Dasar Jawab-Menjawab Tertulis.", "t": "w w Dalam tenggang waktu yang sama para pihak dapat saling menyampaikan surat-surat jawaban (replik) dan jawaban balik (duplik) yang dengan w cara yang sama bersama-sama dengan surat-surat yang bersangkutan diserahkan kepada panitera. (Rv. 68, 120, 143 dst., 145, 249, 349.)"}, {"l": "RV", "p": "143", "b": "Bagian 4. Pemeriksaan Perkara Atas Dasar Jawab-Menjawab Tertulis.", "t": "Dalam hal-hal yang diatur dalam tiga pasal terdahulu, maka para pihak dapat saling memberitahukan surat-surat secara sukarela dengan surat tanda terima; pasal 126 berlaku dalam hal ini. (Rv. 126, 145, 349.)"}, {"l": "RV", "p": "144", "b": "Bagian 4. Pemeriksaan Perkara Atas Dasar Jawab-Menjawab Tertulis.", "t": "surat-surat atau alat-alat lain yang oleh para pihak kemudian saling diperlihatkan atau saling diberitahukan tidak dapat dimasukkan dalam perhitungan biaya. (Rv. 98, 10,6, 349.)"}, {"l": "RV", "p": "145", "b": "Bagian 4. Pemeriksaan Perkara Atas Dasar Jawab-Menjawab Tertulis.", "t": "Bila dalam waktu yang telah ditentukan di atas, salah satu pihak tidak menunjukkan atau memberitahukan surat-surat ataupun tidak memberitahuan daftar surat-surat, maka perkaranya akan dipertimbangkan berdasarkan surat-surat dari pihak lawan. (Rv. 126, 140 dst., 143, 349.) Dalam hal itu, seperti juga setelah ditunjukkan atau diberitahukan surat-surat dan pemberitahuan oleh juru sita dalam waktu yang telah ditentukan, maka panitera atas keinginan pihak yang lebih dulu siap, menyerahkan surat-surat itu kepada ketua yang akan membicarakan hal itu pada rapat yang pertama berikutnya. (Rv. 140 dst., 249, 349.)"}, {"l": "RV", "p": "146", "b": "Bagian 4. Pemeriksaan Perkara Atas Dasar Jawab-Menjawab Tertulis.", "t": "Jika sifat perkara adalah sedemikian rupa sehingga perlu mendengar penuntut umum, maka oleh hakim diperintahkan kepada panitera untuk memberitahukan kepadanya perkara itu. (Rv. 349.) Penuntut umum mengambil kesimpulan pada sidang pemeriksaannya, yang diumumkan pada hari sidang sebelumnya. (Rv. 322 dst.)"}, {"l": "RV", "p": "147", "b": "Bagian 4. Pemeriksaan Perkara Atas Dasar Jawab-Menjawab Tertulis.", "t": "Hakim memberikan putusannya pada hari sidang yang ditentukan olehnya. (Rv. 22, 47, 349.)"}, {"l": "RV", "p": "148", "b": "Bagian 5. Perselisihan Mengenai Asli Tidaknya surat-surat Dan Tentang", "t": "Pemeriksaan di sidang pengadilan mengenai asli tidaknya surat-surat yang hendak dipergunakan para pihak diadakan: (Sv. 231 dst.; IR. 138; RBg. 164.) 10. jika pihak yang dikatakan telah membuat surat di bawah tangan r g atau menandatanganinya, menyangkal telah membuatnya menandatanganinya; (KUHPerd. 1875 dst.; Rv. 149.) s . oatau t a 2 . jika pihak yang dilawan dengan menggunakan suatu surat di bawah l i tangan yang ditulis oleh pihak ketiga atau ditandatangani oleh a pihak ketiga itu dan menyatakan tidak mengakui surat atau tanda l. eg tangan orang yang dikatakan telah menulis atau menandatangani surat itu; (KUHPerd. 1875 dst.; Rv. 149.) w w 30. jika salah satu pihak mengatakan bahwa surat itu palsu atau dipalsukan. (KUHPerd. 1872; BS. 25, 28; Rv. 349, 628.) Pasal 149. w Dalam kejadian-kejadian seperti tersebut dalam No. 10 dan 20 pasal yang lalu, maka pihak yang ingin mempertahankan serta menggunakan surat yang oleh pihak lawan disangkal keasliannya dapat menuntut agar ia diberi kesempatan untuk membuktikannya baik dengan surat- surat, dengan ahli-ahli, maupun dengan saksi-saksi. (KUHPerd. 1867 dst., 1895; Rv. 151, 154, 215 dst., 349.)"}, {"l": "RV", "p": "150", "b": "Bagian 5. Perselisihan Mengenai Asli Tidaknya surat-surat Dan Tentang", "t": "Dalam kejadian seperti tersebut dalam no. 31 pasal 148, maka pihak yang mengatakan bahwa surat yang dikemukakan adalah palsu atau dipalsukan dapat menuntut agar ia diberi kesempatan untuk membuktikannya baik dengan surat-surat, dengan ahli-ahli, maupun dengan saksi-saksi. (s.d.u. dg. S. 1872-13.) Tetapi ia tidak akan diperbolehkan untuk itu sebelum menyampaikan di kepaniteraan suatu akta yang ditandatangani olehnya sendiri atau oleh orang yang khusus dikuasakan untuk itu dengan suatu akta otentik, dan memuat pernyataan yang tegas bahwa surat-surat yang bersangkutan dianggap palsu atau dipalsukan dan juga menyebutkan tindakan-tindakan, keadaan serta alat-alat bukti yang dipandangnya perlu untuk membuktikan kepalsuan atau dipalsukannya surat-surat itu. (KUHPerd. 1867 dst., 1872, 1895; Rv. 151, 154, 215 dst., 349.; Sv. 231 dst.)"}, {"l": "RV", "p": "151", "b": "Bagian 5. Perselisihan Mengenai Asli Tidaknya surat-surat Dan Tentang", "t": "(s. d. u. dg. S. 1908-522.) Perintah untuk pemeriksaan di sidang pengadilan mengenai asli atau tidaknya suatu surat, tidak diberikan sebelum diberikut suatu pernyataan seperti diatur dalam dua pasal berikut, satu dan yang lain mengingat apa yang menjadi tuntutan dalam gugatan. Pernyataan-pernyataan itu diucapkan secara lisan dalam sidang pengadilan. Tentang hal itu dicatat dalam berita acara."}, {"l": "RV", "p": "152", "b": "Bagian 5. Perselisihan Mengenai Asli Tidaknya surat-surat Dan Tentang", "t": "(s. d. u. dg. S. 1908-522.) Jika tuntutan dilakukan sesuai dengan pasal 149, maka pihak yang menyangkal keaslian surat harus menyatakan tetap menyangkal keaslian surat dengan tidak mengakui surat atau tanda tangan atau menyatakan tidak mengenalnya. Dalam hal ia tidak datang menghadap pada hari yang telah ditentukan atau menolak untuk menjawab atau tidak tetap pada sangkalannya atau bantahannya, maka atas permintaan pihak yang berkepentingan hal itu dicatat dalam berita acara, dan hakim menyatakan bahwa surat yang bersangkutan dapat diterima dalam pemeriksaan perkara yang bersangkutan. Semua itu dicatat dalam berita acara. (Rv. 148, 154, 349.) r g"}, {"l": "RV", "p": "153", "b": "Bagian 5. Perselisihan Mengenai Asli Tidaknya surat-surat Dan Tentang", "t": "s . o (s.d.u. dg. l i t a S. 1908-522.) Jika suatu gugatan dilakukan menurut pasal 150, maka pihak yang mengemukakan surat harus menyatakan a apakah ia ingin menggunakan surat itu dalam perkaranya. l. eg Jika ia tidak datang menghadap pada hari yang telah ditentukan atau menolak untuk menjawab atau menyatakan tidak akan menggunakan surat w itu, maka atas permintaan pihak lawan hal itu dicatat dalam, berita acara dan oleh hakim dinyatakan surat itu di luar pemeriksaan perkara. w w Semua itu dicatat dalam berita acara. (Rv. 154, 349.)"}, {"l": "RV", "p": "154", "b": "Bagian 5. Perselisihan Mengenai Asli Tidaknya surat-surat Dan Tentang", "t": "(s.d.u. S. 1908-522.) Jika suatu pernyataan diberikan men urut dua pasal terdahulu, dan terdapat cukup alasan-alasan, maka hakim memerintahkan untuk mengadakan pemeriksaan hari sidang yang ditentukan olehnya, paling cepat setelah empat belas hari tentang asli tidaknya surat-surat yang bersangkutan, dan jika ia tidak dapat melakukannya sendiri, ia mengangkat seorang hakim komisaris dan tiga orang ahli. Dalam hal para pihak bersepakat untuk memilih ahli-ahlinya, maka hakim akan menerimanya. Perintah ini sekaligus memuat perintah agar surat yang disengketakan diberikan keterangan yang cukup mengenai cirinya serta diberi tanda oleh ketua dan paniteran untuk kemudian diserahkan ke kepaniteraan untuk disimpan di sana, dengan tidak mengurangi hak para pihak untuk dapat melihat atau mendapatkan (KUHPerd. 1877; Rv. 148 dst., 215 dst., 349; Sv. 231 dst., 241.)"}, {"l": "RV", "p": "155", "b": "Bagian 5. Perselisihan Mengenai Asli Tidaknya surat-surat Dan Tentang", "t": "Pada hari yang ditentukan para pihak datang menghadap ketua atau hakim komisaris untuk menyetujui mengenai pencocokan surat-surat yang bersangkutan. Jika salah satu pihak tidak datang, maka diperintahkan pemanggilan untuk hari lain. Jika pada hari itu pihak yang ingin menggunakan surat itu tidak datang, maka surat itu tidak akan digunakan dalam pemeriksaan perkara yang bersangkutan. Jika pihak lawan yang tidak datang, maka hakim menyatakan surat itu sebagai diakui oleh pihak lawan itu. Jika kedua pihak tidak datang pada hari pemeriksaan yang pertama, maka hakim dapat menyatakan gugur tuntutan bahwa surat yang bersangkutan adalah palsu atau yang dipalsukan ataupun dapat juga memanggil para pihak untuk kedua kalinya. (RV. 152 dst., 156 dst. , 349.)"}, {"l": "RV", "p": "156", "b": "Bagian 5. Perselisihan Mengenai Asli Tidaknya surat-surat Dan Tentang", "t": "Sementara para pihak tidak sependapat mengenai surat-surat yang dicocokkan, hakim tidak boleh menerima surat-surat lain semacam itu, kecuali: 10. akta-akta otentik; (KUHPerd. 1868 dst., IR. 165.) 20. surat-surat di bawah tangan yang diakui kedua pihak; (KUHPerd. 1874 dst., lsm; Sv., 238.) 3 . bagian selebilmya dari surat-surat yang dikemukakan, sementara pemeriksaan mengenai asli atau tidaknya hanya mengenai bagian itu; hakim komisaris dengan mengikuti . apa yang diucapkannya; r g 4 . hal-hal yang harus ditulis oleh para pihak di hadapan hakim atau . o 50. (s.d.t. dg. S. 1919-603.) Sidik jari yang harus dibubuhkan s l i a dihadapan atau atas petunjuk hakim atau hakim komisaris. t Penolakan untuk menulis dapat diartikan sebagai pengakuan atas a surat-surat yang bersangkutan. (KUHPerd. 1922; Sv. 237 dst.)"}, {"l": "RV", "p": "157", "b": "Bagian 5. Perselisihan Mengenai Asli Tidaknya surat-surat Dan Tentang", "t": "l. eg Dalam hal surat-surat yang akan dicocokkan ada di tangan pejabat w w penyimpan umum atau Penyimpan lain, maka hakim atau hakim komisaris dapat memerintahkan agar Penyimpan itu membawa surat-surat itu w kepadanya pada hari dan jam yang ditentukan oleh hakim atau hakim komisaris di tempat pemeriksaan akan dilakukan dengan ancaman paksaan badan terhadap penyimpan umum dan terhadap penyimpan yang lainnya dengan dipaksa sesuai ketentuan hukum, dengan tidak mengurangi paksaan badan juga penyanderaan bila dipandang perlu. (KUHPerd. 1239; Rv. 160, 349, 580-5', 584, 952; Sv. 234.)"}, {"l": "RV", "p": "158", "b": "Bagian 5. Perselisihan Mengenai Asli Tidaknya surat-surat Dan Tentang", "t": "Jika surat-surat yang untuk dicocokkan tidak dapat ditunjukkan, atau tempat tinggal para penyimpannya amat jauh, maka terserah pada hakim, berdmrkan laporan hakim komisaris, bila diangkat, dalam segala hal sesudah didengar penuntut umum, apakah akan diperintahkan agar pemeriksaan dilakukan oleh hakim atau oleh Kepala Daerah di tempat tinggal penyimpan itu, atau agar dalam waktu yang ditetapkan surat-surat itu dikirimkan kepada kepaniteraan dengan cara-yang ditentukan oleh hakim. (RO. 33; BS. 9 dst.; Rv. 159, 349, 952; Rbg. 322-30.)"}, {"l": "RV", "p": "169", "b": "Bagian 5. Perselisihan Mengenai Asli Tidaknya surat-surat Dan Tentang", "t": "(s.du. dg. S. 1,908-522.) Jika dalam hal terakhir ini penyimpan adalah seorang pejabat umum, maka ia sebelumnya membuat turunan surat-surat, yang akan dicocokkan dengan aslinya dan ditandatangani oieh ketua R.v.J. atau Residentierechter di wilyah tempat tinggal pejabat tersebut, dan oleh mereka dibuat berita acara tentang hal itu. Turunan itu oleh pejabat tersebut digabungkan dengan surat- surat yang asli atau niinutnya sebagai ganti surat-surat yang asli sampai yang asti dikembalikan kepadanya dan ia dapat mengeluarkan grossen dan turunan yang sah dengan menyebutkan berita acara tersebut di atas. Biaya dibayar oleh pihak yang meminta pemeriksaan di sidang mengenai asli tidaknya surat-surat kepada penyimpan, menurut perhitungan pejabat yang membuat berita acara dan untuk itu diberikan perintah pelaksanaannya kepada pejabat penyimpan. (Rv. 148, 158, 161, 349, 952; Sv. 237.)"}, {"l": "RV", "p": "160", "b": "Bagian 5. Perselisihan Mengenai Asli Tidaknya surat-surat Dan Tentang", "t": "Pihak yang telah siap lebih dulu memanggil dengan perantaraan juru sita para ahli, jika ada yang diangkat, dan para pejabat penyimpan yang diperintahkan menghadap secara pribadi untuk siap pada hari dan jam yang telah ditentukan dengan surat perintah oleh hakim atau hakim komisaris; para ahli harus mengangkat sumpah sebelum mulai dengan pemeriksaan serta membuat laporannya; kemudian para penyimpan menyampaikan surat-surat untuk dicocokkan. Tentang semuanya itu dibuat berita acara. Pihak ini dipanggil dengan akta juru sita di tempat tinggal yang dipilih untuk hadir pada waktu pemeriksaan. (Rv. 8, 16, 106 dst., 157 dst., 215 dst., 349.) r g"}, {"l": "RV", "p": "161", "b": "Bagian 5. Perselisihan Mengenai Asli Tidaknya surat-surat Dan Tentang", "t": "s . o maka terserah kepada hakim atau l i a Jika surat-surat telah diperlihatkan oleh para pejabat penyimpan, t hakim-komisaris untuk memerintahkannya, sementara menyimpan asurat-surat itu, tetap l. eg menghadiri pemeriksaan dan pada tiap-tiap sidang yang memerlukan memperlihatkan dan mengambil kembali surat, surat simpanannya, diserahkan kepada panitera. w w ataupun dapat memerintahkan agar surat-surat yang bersangkutan Dalam hal terakhir jika pejabat penyimpan adalah seorang pejabat w umum, ia dapat membuat turunan seperti diatur dalam pasal 159, dan meskipun tempat diadakannya pemeriksaan berada di luar wilayahnya, penyimpan itu menurut peraturan dapat membuat akta. Dalam hal itu pencocokan dilakukan oleh ketua raad van justitie di dalam wilayah hukum dimana surat-surat yang bersangkutan berada. (KUHPerd. 1868; Rv. 349.)"}, {"l": "RV", "p": "162", "b": "Bagian 5. Perselisihan Mengenai Asli Tidaknya surat-surat Dan Tentang", "t": "Para ahli harus mengangkat sumpah. Surat-surat disampaikan kepadanya yang kemudian dibuatkan laporan disertai alasan-alasan pertimbangannya. (s.d.u. dg. S. 1908-522, S. 1925-525.) Dalam hal ini berlaku ketentuan-ketentuan dalam pasal: 222, 225, 228 dan 229. (Rv. 160, 204, 223 dst., 349; Sv. 239.)"}, {"l": "RV", "p": "163", "b": "Bagian 5. Perselisihan Mengenai Asli Tidaknya surat-surat Dan Tentang", "t": "Sebagai saksi-saksi dapat didengar mereka yang melihat pembuatan akta atau penandatanganannya atau mereka yang mengetahui seluk-beluk kejadiannya, untuk dapat ditemukan kebenarannya. surat-surat yang tidak diakui atau disangka palsu diperlihatkan kepada mereka, serta mereka memberi tanda mengetahui dan selanjutnya diikuti ketentuan-ketentuan mengenai pemeriksaan saksi-saksi. (KUHPerd. 1895 dst.; Rv. 149 dst., 171 dst., 349; Sv. 239.)"}, {"l": "RV", "p": "164", "b": "Bagian 5. Perselisihan Mengenai Asli Tidaknya surat-surat Dan Tentang", "t": "(s. d. u. dg. S. 1908-522.) Jika pemeriksaan telah selesai, maka pihak yang sudah siap lebih dulu memanggil pihak yang lain dengan perantaraan pengacara untuk melanjutkan pemeriksaan perkaranya, kecuali jika perkara masih menunggu giliran. (Rv. 154, 158, 160, 208, 349.)"}, {"l": "RV", "p": "165", "b": "Bagian 5. Perselisihan Mengenai Asli Tidaknya surat-surat Dan Tentang", "t": "Bila di dalam pemeriksaan di sidang timbul dugaan telah dilakukan pemalsuan oleh orang yang masih hidup, maka oleh hakim karena jabatan atau atas permintaan penuntut umum diperintahkan agar surat- surat diserahkan kepada penuntut umum untuk dilakukan pemeriksaan oleh hakim pidana yang bersangkutan. Sengketa perdatanya ditunda sampai ada putusan hakim pidana. (AB. 29; KUHPerd. 1872, 1918; Rv. 321, 349, 952; KUHP 263 dst., 266; Sv. 9 dst., 231 dst., 390; IR. 138; RBg. 164.)"}, {"l": "RV", "p": "166", "b": "Bagian 5. Perselisihan Mengenai Asli Tidaknya surat-surat Dan Tentang", "t": "Jika hakim perdata dalam putusannya mengenai tuduhan pemalsuan memerintahkan agar surat-surat yang dinyatakan palsu atau dipalsukan dikesampingkan, disobek atau dicoret seluruhnya atau sebagian, ataupun agar diperbaiki dan dirapikan, maka bagian putusan ini r g s . o ditunda pelaksanaannya selama bagi terhukum belum lewat tenggang waktu untuk banding, peninjauan kembali atau kasasi atau bila ia 388, 402 dst.; Sv. 243.) l i a tidak menerima putusan. (AB. 29; KUHPerd. 16; Rv. 329, 334, 349, t a l. eg"}, {"l": "RV", "p": "167", "b": "Bagian 5. Perselisihan Mengenai Asli Tidaknya surat-surat Dan Tentang", "t": "Dalam putusan hakim disebutkan kecuali mengenai palsu tidaknya surat para pihak, saksi-saksi w yang bersangkutan juga tentang tenggang waktu dan cara bagaimana dan w pejabat-pejabat penyimpan harus mengembalikan surat-surat yang ditunjukkan. (Rv. 155 dst., 349; Sv. 244.) w Pasal 168, 169 dan 170. Dicabut dg. S. 1872-13."}, {"l": "RV", "p": "171", "b": "Bagian 6. Pemeriksaan Saksi-saksi.", "t": "Jika para pihak tidak mendapat kesepakatan tentang kejadian- kejadiannya, dan oleh undang-undang diperbolehkan dibuktikan dengan saksi-saksi, dan kejadian-kejadian itu akan dapat membawa ke arah penyelesaian perkaranya, maka atas permintaan pihak-pihak yang bersangkutan hakim dapat memerintahkan dilakukannya pemeriksaan saksi. (IR. 121, 139; RBg. 145, 165.) Dalam keadaan seperti di atas, maka ia karena jabatan dapat memerintahkannya bila dianggapnya berguna atau perlu untuk memutuskan perkara itu. (Rv. 953.) Pemeriksaan saksi, jika menuju ke arah penyelesaian perkara, selalu diperbolehkan tanpa kecuali bila dikehendaki oleh orang Indonesia atau yang diperan dengan mereka, yang mengingat perkara dalam sengketa tidak sesuai dengan ketentuan hukum, atau yang tidak menyatakan tunduk kepada hukum yang berlaku untuk golongan Eropa. (IR. 168; AB. 1 1 dst.; Rv. 953 .) Bukti lawan menurut hukum selalu diperbolehkan. (KUHPerd. 1866, 1895 dst.; Rv. 48, 173, 241 dst., 332, 349, 393.)"}, {"l": "RV", "p": "172", "b": "Bagian 6. Pemeriksaan Saksi-saksi.", "t": "(s.d.u. dg. S. 1908-522.) surat keputusan yang di dalamnya termuat perintah pemeriksaan saksi harus menyebutkan perbuatan-perbuatan yang harus dibuktikan. Dalam perkara-perkara mengenai hak menguasai (bezit) yang tidak mengakui hak itu atau terhadapnya, tidak boleh menyebutkan perbuatan-perbuatan yang mengenai hak milik atas benda yang bersangkutan (petitoir) itm, Dalam putusan itu hakim memerintahkan, bahwa pemeriksaan saksi akan dilakukan di dalam persidangan, atau atas permintaan para pihak atau karena alasanalasan yang penting yang disebut dalam putusan itu, di hadapan seorang hakim komisaris yang diangkat olehnya sepanjang ia tidak menggunakan hak yang diberikan kepadanya dalam pasal 173 (Rv. 293a.) Begitu pula bila telah terjadi putusan, seperti yang dimaksudkan dalam dua alinea terdahulu, hakim dapat menggunakan wewenangnya seperti yang disebutkan dalam pasal berikutnya, yaitu untuk mengubah putusan itu, baik karena jabatan, maupun atas permohonan kedua belah pihak atau salah satu pihak."}, {"l": "RV", "p": "173", "b": "Bagian 6. Pemeriksaan Saksi-saksi.", "t": "g (s.d. u. dg, S. 1908-522.) Jika para saksi bertempat tinggal dalam r tempat kedudukan raad van justitie, maka s pemeriksaano wilayah hukum raad van justitie tetapi di luar karesidenan/afdeling . dapat (Rv. 896.) l i a diserahkan kepada hakim karesidenan di tempat tinggal para saksi. t a Jika para saksi bertempat tinggal di luar wilayah hukum raad van l. eg justitie maka pemeriksa dapat diserahkan kepada raad van justitie atau Residentierechter di tempat tinggal para saksi. Raad van w justitie yang diminta bantuannya dapat melakukannya sendiri atau menyerahkannya kepada hakim komisaris atau dalam keadaan seperti w tersebut dalam alinea yang lalu kepada Residentierechter. (Rv. 896.) w Jika para saksi bertempat tinggal di luar Indonesia, maka hakim dapat meminta kepada seorang pejabat di negara tempat tinggal saksi itu untuk memeriksanya atau menyerahkan pemeriksaan itu kepada seorang pejabat konsuler di tempat tinggal para saksi. Berita acara itu mempunyai kekuatan yang sama dengan berita acara yang dibuat oleh hakim Indonesia. (Rv. 896.) . Jika saksi karena sakit atau karena halangan yang sah tidak datang menghadap, maka hakim dapat memerintahkan kepada seorang hakim komisaris, …"}, {"l": "RV", "p": "174", "b": "Bagian 6. Pemeriksaan Saksi-saksi.", "t": "(s.d. u. dg. S. 1908-522.) Jika pemeriksaan saksi dilakukan di dalam sidang pengadilan, maka dalam putusan disebutkan hari dan jam saksi-saksi tersebut didengar. Pemeriksaan mengenai bukti lawan dilakukan pada hari dan jam yang juga ditentukan dalam putusan atau segera ditentukan setelah mendengar keterangan saksi sebagai pembuktian. Jika salah satu pihak mohon perpanjangan tenggang waktu seperti dalam alinea pertama dan kedua, maka hal ini segera ditentukan tanpa ada kemungkinan upaya hukum lain. Selanjutnya untuk mendengar keterangan saksi di sidang, harus diperhatikan aturan-aturan seperti yang dimaksudkan dalam pasal- pasal yang berikut ini."}, {"l": "RV", "p": "175", "b": "Bagian 6. Pemeriksaan Saksi-saksi.", "t": "(s.d.u. dg. S. 1908-522.) Saksi-saksi dipanggil dengan bertemu dengan mereka sendiri atau di tempat tinggalnya sedikitnya tiga hari sebelum hari pemeriksaan. Tenggang waktu ini ditambah dengan satu hari untuk tiap-tiap jarak lima belas pal. (Rv. 953 .) surat panggilan memuat putusan, tempat, hari dan jam diadakan pemeiiksaan serta mengenai hal-hal yang harus dibuktikan. (Rv. 8, 15, 96, 176, 188, 204, 896.)"}, {"l": "RV", "p": "176", "b": "Bagian 6. Pemeriksaan Saksi-saksi.", "t": "Nama-nama serta tempat tinggal saksi-saksi selambat-lambatnya delapan hari sebelum hari pemeriksaan oleh Para pihak diberitahukan kepada pengacara pihak lawan. (Rv. 96, 106 188, 200,)"}, {"l": "RV", "p": "177", "b": "Bagian 6. Pemeriksaan Saksi-saksi.", "t": "Hakim menanyakan kepada saksi tentang naina nama depan, pekerjaan umur serta tempat tinggalnya, juga mengenai apakah ia mempunyai r g hubungan keluarga dengan para pihak karena keturunan atau karena s . perkawinan dan bila ada dalam derajat ke berapa dan juga apakah o l i t a iamerupakan buruh atau pembantu rumah tangga salah satu pihak. Setelah itu mereka masing-masing akan bersumpah atau berjanji a menurut agama masing-masing, bahwa mereka akan memberikan keterangan l. eg yang sebenar-benamya dan tidak lain dari yang sebenamya. (ISR. 173; KUHPerd. 290 dst., 1909 dst.; Rv. 179, 188 dst. 204, 896,; Sv. 48, w 139; IR. 144, 147 dst., 265; S. 1920-69.) w 178. Dicabut dg."}, {"l": "RV", "p": "179", "b": "Bagian 6. Pemeriksaan Saksi-saksi.", "t": "S. 1925-525. w Kemudian masing-masing saksi secara sendiri-sendiri didengar keterangannya di dalam sidang pengadilan dengan atau tanpa hadimya para pihak lawan. Mereka tidak diperbolehkan membaca jawaban tertulis. Para pihak tidak diperbolehkan memutus pembicaraan saksi, permohonan Para pihak, dan juga karena jabatannya dapat pertanyaan-pertanyaan yang dipandangnya perlu kepada saksi. (Rv. 204, 896)."}, {"l": "RV", "p": "180", "b": "Bagian 6. Pemeriksaan Saksi-saksi.", "t": "(s.d.u. dg. S. 1908-522, S. 1925-525.) Jika seorang dipanggil dengan patut tidak datang menghadap atau jika memberi jawaban, maka pihak yang berkepentingan dapat memohon ke memberi kesempatan di lain waktu."}, {"l": "RV", "p": "181", "b": "Bagian 6. Pemeriksaan Saksi-saksi.", "t": "Jika saksi menuntut ganti rugi, maka besar ganti rugi itu akan direncanakan pada turunan surat panggilan yang bersangkutan dan tentang hal itu akan dicatat dalam berita acara. (Rv. 204, 896; S. 1851-27 pasal 53.)"}, {"l": "RV", "p": "182", "b": "Bagian 6. Pemeriksaan Saksi-saksi.", "t": "Dalam hal Para saksi tidak dapat didengar dalam satu hari, maka hakim menundanya sampai hari dan jam lain dan baik terhadap para pihak ataupun saksi tidak diadakan panggilan baru. (Rv. 16, 204, 896.)"}, {"l": "RV", "p": "183", "b": "Bagian 6. Pemeriksaan Saksi-saksi.", "t": "Pihak yang mengajukan lebih dari lima saksi mengenai satu perkara tidak dapat membebankan biaya selebihnya dari lima saksi.itu kepada pihak lawan. (Rv. 204, 958.)"}, {"l": "RV", "p": "184", "b": "Bagian 6. Pemeriksaan Saksi-saksi.", "t": "(s.d.u. dg. S. 1917-497.) Saksi yang tidak datang menghadap walaupun sudah dipanggil dengan patut dihukum untuk mengganti biaya panggilan yang telah dilakukan dengan sia-sia, juga membayar kerugian dan bunga kepada Para pihak. Ia dipanggil lagi atas biaya sendiri. (KUHPerd. 1909; Rv. 204, 896, 954; Sv. 51 dst.; 133 dst.; IR. 140, 260 dst., 263; RBg. 166.)"}, {"l": "RV", "p": "185", "b": "Bagian 6. Pemeriksaan Saksi-saksi.", "t": "(s.d.u. dg. S. 1917-497.)Jika saksi-saksi yang telah dipanggil lagi untuk kedua kalinya belum juga datang menghadap, maka mereka dihukum kedua haknya untuk membayar biaya panggilan yang telah dikeluarkan dengan sia-sia dan juga membayar ganti rugi serta bunga kepada para pihak. r g oleh pejabat yang berkuasa ke hadapannya s untuk o Hakim dapat memerintahkan agar saksi-saksi yang tidak datang dibawa . memenuhi dst.; IR. 141; RBg. 167.) l i a kewajibannya. (Rv. 204, 580-10-, 896, 956, 959; Sv. 51 dst., 133 t a l. eg"}, {"l": "RV", "p": "186", "b": "Bagian 6. Pemeriksaan Saksi-saksi.", "t": "Jika saksi, yang datang berdasarkan panggilan pertama atau kedua w atau setelah dihadapkan kepada hakim, tanpa alasan yang sah menolak untuk bersumpah atau berjanji atau memberikan kesaksiannya, maka w hakim atas permohonan pihak yang berkepentingan dapat memerintahkan w agar terhadap saksi tersebut atas biaya pihak yang mengajukannya dilakukan penyanderaan dan tetap disandera sampai ia bersedia memenuhi kewajibannya. (Rv. 204, 580- 1 O-, 896; Sv. 53, 136; IR. 148; RBg. 176.)"}, {"l": "RV", "p": "187", "b": "Bagian 6. Pemeriksaan Saksi-saksi.", "t": "Jika saksi yang tidak datang menghadap dapat membuktikan bahwa ketidakdatangannya disebabkan karena alasan-alasan yang sah, maka hakim setelah mendengar keterangannya dapat membebaskannya dari segala kewajiban membayar uang telah dibebankan kepadanya. (Rv. 204, 896, 959; Sv. 52; IR. 142; RBg. 168.)"}, {"l": "RV", "p": "188", "b": "Bagian 6. Pemeriksaan Saksi-saksi.", "t": "Di luar apa yang diatur dalam pasal 171 tentang pengucapan sumpah, kealpaan dalam melakukan formalitas seperti tersebut dalam pasal 172 dan berikutnya, hanya dapat membatalkan kesaksian itu, jika hal itu menimbulkan kerugian bagi pembelaan pihak lawan dan kealpaan itu tidak dapat diperbaiki atau tidak diperbaiki meskipun hal itu dapat dilakukan. Perbaikan, bila ada alasan untuk itu, diperintahkan oleh hakim atas permohonan dan biaya pihak yang berkepentingan. (Rv. 92, 96, 204.)"}, {"l": "RV", "p": "189", "b": "Bagian 6. Pemeriksaan Saksi-saksi.", "t": "(s.d. u. dg, S. 1908-522.) Tanpa pemberitahuan atau panggilan terlebih dahulu, hakim dapat menerima keterangan-keterangan para saksi yang diajukan oleh kedua pihak dan datang kepadanya atas kemauan sendiri. (Rv. 176, 179 dst.; IR. 122; RBg. 145.) 190 - 196. Ditarik kembali dg. s. 1908-522."}, {"l": "RV", "p": "197", "b": "Bagian 6. Pemeriksaan Saksi-saksi.", "t": "Bila Pemeriksaan dilakukan di hadapan hakim komisaris, maka harus diikuti ketentuan berikut. (Rv. 38, 349.)"}, {"l": "RV", "p": "198", "b": "Bagian 6. Pemeriksaan Saksi-saksi.", "t": "(s.d.u. dg. S. 1908-522.) Putusan, selain memuat mengenai kejadian- kejadian yang diperbolebkan atau diperintahkan pembuktiannyajuga memuat: 1 . pengangicatan hakim komisaris, 20. jangka waldu untuk mengajukan permohonan kepada hakim komisaris tentang Perintah pemanggilan para saksi. 30 Jangka waktu dihitung mulai pada hari putusan diucapkan. (Rv. 15, 68.)"}, {"l": "RV", "p": "199", "b": "Bagian 6. Pemeriksaan Saksi-saksi.", "t": "Dalam jangka waktu itu pihak yang diwajibkan mengajukan saksi harus mengajukan permohonan tertulis kepada hakim komisaris agar mendapat r g . o perintah pemanggilan untuk menghadap saksi-saksi pada hari, jam dan tempat yang ditentukan. s i t a Bila hal itu tidak dilakukan, maka tidak diperbolehkan membuktikan l perkaranya dengan saksi-saksi. (Rv. 201, 206, 349.) a"}, {"l": "RV", "p": "200", "b": "Bagian 6. Pemeriksaan Saksi-saksi.", "t": "l. eg Pihak itu selanjutnya diwajibkan dengan ancaman batal sedikitnya delapan hari sebelum hari w w pemeriksaan saksi-saksi untuk memberitahukan perintah itu dengan perantaraan pengacaranya kepada w pengacara pihak lawan dengan menyebutkan tentang nama dan tempat tinggal saksi-saksi yang akan mereka ajukan (Rv. 349.)"}, {"l": "RV", "p": "201", "b": "Bagian 6. Pemeriksaan Saksi-saksi.", "t": "Jika Pihak lawan untuk kepentingan pembelaannya yang diperbolehkan menurut hukum juga ingin mengajukan saksi-saksi, maka ia dapat meminta untuk memanggil saksi-saksi itu untuk menghadap pada hari itu juga. Tetapi mereka boleh didengar bila nama dan tempat tinggal mereka tidak diberitahukan kepada pengacara pihak lain sedikitnya dua puluh empat jam sebelum diperiksa. (Rv. 171, 200, 206, 349.) 202 dan 203. Dicabut kembali dg. S. 1925-525."}, {"l": "RV", "p": "204", "b": "Bagian 6. Pemeriksaan Saksi-saksi.", "t": "(s.d.u. dg. S. 1908-522.) Ketentuan-ketenttian dalam pasal 175, 177, 179, 181 s/d. 188 dan 209 berlaku juga terhadap pemeriksaan saksi di hadapan hakim komisaris. (Rv. 349.) 205. Ditarik kembali dg. S. 1908-522."}, {"l": "RV", "p": "206", "b": "Bagian 6. Pemeriksaan Saksi-saksi.", "t": "Bila pihak lawan karena keterangan saksi, menganggap perlu untuk pembuktian lawan mengajukan saksi-saksi lain, maka ia untuk itu dalam berita acara pemeriksaan saksi tersebut mengajukan permohonan dan hakim komisaris memberikan kepadanya jangka waktu disertai ketentuan hari dan jam saksi-saksi akan didengar. Ia berkewajiban, dengan ancaman batal, selambat-lambatnya empat hari sebelum hari pemeriksaan saksi yang sudah ditentukan, untuk memberitahukan nama dan tempat tinggal saksi-saksi yang iaingin ajukan kepada pihak lainnya; tetapi kepada pihak itu tidak akan diadakan panggilan lagi. (Rv. 171, 188, 199 dst., 204, 207, 349.)"}, {"l": "RV", "p": "207", "b": "Bagian 6. Pemeriksaan Saksi-saksi.", "t": "(s..d. u. dg. S. 1925-525.) Jika seorang saksi yang sudah dipanggil dengan patut tidak datang atau menolak untuk memberikan jawaban, maka pihak yang berkepentingan dapat memohon dalam berita acara pemeriksaan saksi itu agar diberi kesempatan lain. (KUHPerd. 1910, 1913; Rv. 174, 184 dst., 204, 206, 349.)"}, {"l": "RV", "p": "208", "b": "Bagian 6. Pemeriksaan Saksi-saksi.", "t": "(s.d. a. dg. S. 1908-522.) Setelah selesai pendengaran saksi atau jika hal itu tidak terjadi maka hakim atau hakim komisaris menentukan hari perkara itu mendapat giliran untuk diperiksa lagi."}, {"l": "RV", "p": "208A", "b": "Bagian 6. Pemeriksaan Saksi-saksi.", "t": "(s.d.t. dg. S. 1908-,1522.; s.d.u. dg. S. 1925-525.) Jika pemeriksaan dilakukan di hadapan hakim yang diperintahkan menurut r g sebagai berikut: s . o pasal 173 alinea pertama dan kedua, maka diikuti ketentuan-ketentuan l i a Nama serta tempat tinggal saksi-saksi diberitahukan kepada pihak t lawan bersama-sama dengan pemberitahuan tentang hari, jam dan tempat pemeriksaan dilakukan. a l. eg Dalam hal-hal yang berhubungan dengan tindakan-tindakan terhadap saksi-saksi yang tidak datang atau enggan menjadi saksi, pendengaran w saksi yang sakit atau karena alasan yang sah yang tidak dapat datang, pertanyaan-pertanyaan sementara yang diajukan kepada saksi- w saksi yang menghadap, wewenang mereka untuk mengundurkan diri w sebagai saksi, kecakapan mereka untuk menjadi saksi, sumpah mereka dan cara bagaimana pemeriksaan dilakukan, maka oleh hakim yang berwenang digunakan ketentuan-ketentuan yang berlaku baginya, semuanya dengan memperhatikan pasal 209 dan apa yang ditentukan di bawah ini. Pengacara para pihak dalam pemeriksaan dapat mewakilkannya kepada teman sejawatnya yang diangkat pada pengaditan di tempat pemeriksaan dilakukan. Bila para pihak dalam pemeriksaan saksi tidak diwakili …"}, {"l": "RV", "p": "209", "b": "Bagian 6. Pemeriksaan Saksi-saksi.", "t": "(s.d. u. dg. S. 1908-522.) Kecuali dalam hal pemeriksaan dilakukan oleh hakim komisaris atau dilakukan di tempat tinggal saksi, maka pemeriksaan saksi dilakukan secara terbuka, kecuali jika dalam ketentuan undang-undang diatur lain, atau oleh hakim karena alasan yang penting yang disebut dalam berita acara diperintahkan agar pemeriksaan seluruhnya atau sebagian dilakukan dengan pintu tertutup. (RO. 29.) Para pihak boleh hadir secara pribadi pada waktu pemeriksaan saksi. (s.d. u. dg. S. 1925-525.) Berita acara dibuat pada tiap-tiap pemeriksaan saksi harus memuat berita apa yang diminta oleh pasal 177 dan selaroutnya memuat berita tentang pengambilan sumpah beserta isi keterangan-keterangan saksi selengkapnya. Berita acara dibuat oleh panitera dan dibacakan di hadapan para saksi bagianbagian yang menyangkut saksi itu. Saksi boleh mengadakan perubahan-perubahan dan tambahan-tambahan, yang dicatat di bagian bawah atau di bagian tepi keterangannya dan dibacakan kepadanya. Saksi harus menandatangani keterangan-keterangan yang diberikan dan disebutkan pula alasan tentang tidak dapatnya ia menandatanganinya atau menolak untuk menandatanganinya. (ISR. 146; RO. 29; Rv. 22, 177, 189, 204, …"}, {"l": "RV", "p": "210", "b": "Bagian 6. Pemeriksaan Saksi-saksi.", "t": "Ketentuan-ketentuan pasal 413, 414 dan 415 Peraturan Hukum Acara Pidana juga berlaku dalam perkara-perkara perdata. (IR. 380 dst.; RBg. 708 dst.)"}, {"l": "RV", "p": "211", "b": "Bagian 7. Pemeriksaan Di Tempat Dan Penyaksiannya.", "t": "s . o l i a Jika hakim atas permintaan para pihak atau karena jabatan memandang t perlu, maka dengan surat putusan dapat diperintahkan agar seorang a atau lebih para anggota yang duduk dalam majelis, disertai oleh l. eg panitera, datang di tempat yang harus diperiksa untuk menilai keadaan setempat dan membuat akta pendapatnya, baik dilakukan w sendiri maupun dengan dibantu oleh ahli-ahli. (s.d.u. dgS. 1908-522.) Dengan cara dan maksud yang sama dapat w diperintahkan dengan suatu putusan, penyaksian benda-benda bergerak w yang tidak dapat atau sukar untuk diajukan ke depan sidang pengadilan. (s.d.u. dg S. 1908-522.) Putusan itu menentukan waktu pemeriksaan di tempat atau waktu dan tempat peninauan, tenggang waktu, bilamana berita acara seperti tersebut dalam pasal 212 harus disediakan di kepaniteraan, dan menentukan waktu dilakukannya persidangan bagi para pihak untuk melanjutkan perkumya. (Rv. 48, 499; JR. 153; Rbg. 180.)"}, {"l": "RV", "p": "212", "b": "Bagian 7. Pemeriksaan Di Tempat Dan Penyaksiannya.", "t": "(s.d.u. dgS. 1908-522.) Panitera membuat berita acara tentang semua hal yang terjadi di tempat dilakukan pemeriksaan. (Rv. 21 1; JR. 153; RBg. 180.)"}, {"l": "RV", "p": "213", "b": "Bagian 7. Pemeriksaan Di Tempat Dan Penyaksiannya.", "t": "(sd.u. dg S. 1908-522.) Jika pemeriksaan setempat atau penyaksian harus dilakukan dalam wilayah hukum suatu pengadilan, tetapi di luar tempat kedudukannya, maka hal itu dapat diserahkan kepada Residentierechter. Dengan suatu keputusan ditetapkan hari perkara itu mendapat giliran pemeriksaan lagi."}, {"l": "RV", "p": "214", "b": "Bagian 7. Pemeriksaan Di Tempat Dan Penyaksiannya.", "t": "(s.d.u. dgS. 1908-522.) Ongkos jalan ditanggung oleh pihak yang menghendaki diadakannya Pengamatan atau penyaksian setempat, dibayar lebih dan diserahkan kepada panitera. Jika hakim yang memerintahkan pengamatan dan penyaksian setempat, maka ia menentukan pula siapa yang harus membayar lebih dulu biayanya. (Rv, 58, 349.)"}, {"l": "RV", "p": "215", "b": "Bagian 8. Keterangan Para Ahli.", "t": "Jika hakim atas permohonan para pihak atau karena jabatan memandang perlu, maka dengan putusan dapat diperintahkan agar diadakan pemeriksan atau pengamatan oleh ahli-ahli. putusan itu dengan jelas menyebut obyek yang harus diperiksa atau diamati, berisi pengangkatan tiga ahli. Akantetapi jika kedua Pihak memohon agar pemeriksaan hanya dilakukan oleh satu orang ahli saja, maka tidak diangkat lebih dari satu orang ahli. (Rv. 48. 150, 154, 162, 216 dst., 241 dst., 349, 963; KUHPerd. 389 dst., 396, 480, 1077 dOL. 1220., 150; IR. 154; RB9. 181; S. 1851-27 pasal 49; S. 1858-15; S. 1866108; S. 1934-683.)"}, {"l": "RV", "p": "216", "b": "Bagian 8. Keterangan Para Ahli.", "t": "Jika Para pihak dalam persidangan bersepakat tentang orangnya atau ketiga orangnya yang dikehendaki sebagai ahli, maka mereka diangkat dalam putusan itu. r g s . o (sdu. dg. S. 1908-522.) Jika para pihak tidak memperoleh kesepakatan tentang orangnya, maka dalam putusan diperintahkan agar Para pihak l i a dalam waktu delapan hari menyampaikan nama-nama ahli itu dan jika t tidak dapat dipenuhi dikeluarkan Perintah Pengangkatan ahli karena jabatannya dalam putusan yang sama. a l. eg Dalam jangka waktu tersebut maka para pihak, jika sudah menyepakati pengangkatan ahli-ahli, menyerahkan Pernyataan kepada kepaniteraan. (Rv. 15, 82, 215, 519.) Pasal 217. w w w Dalam putusan yang dimaksud dalam pasal 216 ditetapkan hari dan jam pengambilan sumpah dilakukan. (sdu- dg. S. 1908-522.) Pihak yang paling siap memanggil para ahli dengan Pemntaraan juru sita untuk mengangkat sumpah dengan surat perintah hakim, tetapi dalam hal para pihak di sidang tidak mencapai kesepakatan mengenai siapa diangkat sebagai ahli, tidak sebelum lewat tenggang waktu seperti tersebut kedua pasal 216 atau tidak sebelum memberikan Pernyataan seperti tersebut daiam alinea ketiga pasal itu. panggilan ini dilakukan …"}, {"l": "RV", "p": "221", "b": "Bagian 8. Keterangan Para Ahli.", "t": "(s. d.u. dg. S. 1,908-522.) Hakim menetapkan dalam berita acara sumpah, tempat, hari dan jam, di mana dan kapan para ahli mulai dengan pemeriksaan dan juga kapan mereka harus menyerahkan keterangan tertulis mereka kepada panitera, dan kapan sidang akan dilanjutkan untuk memeriksa perkara, kesemuanya setelah didengar para ahli dan para pihak yang datang menghadap. (Rv. 966.) Jika ahli yang telah diangkat dan telah disumpah tidak melaksanakan pekerjaan, maka atas permohonan para pihak atau salah satu dari mereka, hakim menentukan hari lain untuk pemeriksaan lanjutan. Tempat, hari dan jam, di mana dan kapan para ahli mengadakan pemeriksaan serta tenggang waktu yang harus dipenuhi untuk menyampaikan laporan tertulisnya kepada panitera dengan begitu ditentukan oleh Kepala Daerah (Asisten Residen) pada waktu pengambilan sumpah setelah mendengar Para ahli dan pihak-pihak yang hadir, dan dimuat dalam berita acara sumpah. (Rv. 211, 217, 225; IR. 17.)"}, {"l": "RV", "p": "222", "b": "Bagian 8. Keterangan Para Ahli.", "t": "Jika seorang ahli yang telah diangkat menolak pengangkatannya, atau tidak datang menghadap pada hari yang ditentukan, baik untuk melakukan sumpah atau untuk melaksanakan suatu perintah lain, maka para pihak segera mengusahakan kesepakatan untuk mengangkat ahli lain; jika tidak ada, inaka hakim karena jabatan akan mengangkat seorang ahli. r g s . o Jika ahli yang telah diangkat dan telah bersumpah tidak melaksanakan pekedaan-pekerjaan yang telah diterimanya, ia dapat dihukum oleh l i a hakim untuk membayar semua biaya yang disebabkan kelalaiannya itu, t bahkan sampai membayar kerugian dan bunga, bila ada cukup alasan. a (KUHPerd. 1239, 1366, 1817; Rv. 162, 215 dst., 226, 607, 964.)"}, {"l": "RV", "p": "223", "b": "Bagian 8. Keterangan Para Ahli.", "t": "l. eg kepada para ahli. w w Turunan putusan hakim dan surat-surat yang diperlukan diserahkan Dalam penyelidikan oleh Para ahli, para pihak dapat mengajukan w dasar-dasr serta permintaan yang diperlukan dan tentang hal itu dicantumkan dalam surat laporan. (Rv. 217, 228, 966 dst.)"}, {"l": "RV", "p": "224", "b": "Bagian 8. Keterangan Para Ahli.", "t": "Para ahli setelah bermusyawarah membuat laporan tertulis dengan suara terbanyak. Dalam hal ada perbedaan pendapat, maka pendapat yang berbeda itu dapat dimasukkan dalam laporan tanpa menyebut siapa-siapa ahli yang mempunyai pendapat tertentu itu. Laporan diberi tanggal dan ditandatangani semua ahli. Jika tidak ada di antara Para ahli yang dapat menyusun laporan itu, maka dibuat laporan oleh notaris yang ikut menandatanganiriya. (Rv. 223, 316, 966.)"}, {"l": "RV", "p": "225", "b": "Bagian 8. Keterangan Para Ahli.", "t": "(s.d.u. dg. S. 1908-522.) Para ahli wajib menyerahkan laporannya kepada panitera R.V.J. yang telah memerintahkan pemeriksaan dalam waktu yang telah ditentukan dalam pasal 221 dengan ancaman membayar ganti rugi dan bunga; panitera wajib memberikan tanda penyerahan itu. Upah mereka dianggarkan oleh ketua di bagian bawah turunan asli laporan itu dengan dikeluarkan perintah pelaksanaan atas beban pihak yang memohon pemeriksaan oleh ahli, atau dalam hal perintah diberikan karena jabatan pihak yang menuntutnya. (KUHPerd. 1239; Rv. 188, 316; IR. 154; RBg. 181; S. 1851-27 pasal 49 dst.; S. 1856-15; S. 1866-108; S. 1934-683.)"}, {"l": "RV", "p": "226", "b": "Bagian 8. Keterangan Para Ahli.", "t": "Jika ada penolakan atau hambatan mengenai pelaksanaan apa yang dintentukan dalam alinea pertama pasal yang lalu, maka ahli tersebut oleh pihak yang telah siap lebih dulu dapat dituntut di hadapan hakim yang mengangkatnya, pada akhimya bahkan dapat dihukum dengan paksaan badan (lijfsdwang) agar menyerahkan laporan yang bersangkutan kepada panitera. (Rv. 968.) (s.d.u.dg.S. 1908-522,)Hakim memutus tanpa didahului adanya surat gugatan setelah mendengar ahli-ahli yang datang menghadap. (Rv. 222, 580-101.) 227. Ditarik kembali dg. S. 1908-522."}, {"l": "RV", "p": "228", "b": "Bagian 8. Keterangan Para Ahli.", "t": "Jika hakim dalam laporan yang bersangkutan tidak menjumpai keterangan-keterangan yang diperlukan, maka ia dapat mengangkat ahli-ahli baru yang dapat meminta penjelman kepada ahli-ahli yang lama sepanjang dipandang perlu. (Rv. 162, 215, 223 dst.)"}, {"l": "RV", "p": "229", "b": "Bagian 8. Keterangan Para Ahli.", "t": "r g Hakim sama sekali tidak terikat untuk mengikuti pendapat dikemukakan para ahli jika keyakinannya bertentangan dengan s . o yang itu. (KUHPerd. 1908; Rv. 162, 224; IR. 154; RBg. 181.) l i t a a"}, {"l": "RV", "p": "230", "b": "Bagian 9. Pendengaran Para Pihak.", "t": "l. eg w Para pihak diperbolehkan dalam semua perkara da, dalam segala tahap pemeriksaan memohon agar masing-masing didengar tentang hal-hal w mengenai pokok persoalannya dan tidak ditanyakan hal-hal yang tidak ada hubungannya dengan itu. w Pihak yang ingin lawannya didengar dapat mengajukan permohonan tertulis yang memuat kejadian-keiadian dan pertanyaan-pertanyaannya. (KUHPerd, 1923 dst.; Rv. 48, 113 dst., 118 dst., 138 dst., 173, 241 dst., 323, 349.) (s.d.t.dg. S. 1908-522.) Jika permohonan diajukan setelah ditentukan hakim untuk mengajukan pembelaan atau pada hari itu juga, pembelaan dilakukan juga dan jika permohonan ditolak, bersama-sama atau sesudah dilakukan pendengaran diputus mengenai pokok perkaranya tanpa proses lain."}, {"l": "RV", "p": "231", "b": "Bagian 9. Pendengaran Para Pihak.", "t": "Hakim harus memeriksa dengan cermat apakah pertanyaan-pertanyaan itu ada hubungaruiya dengan perkaranya; ia harus mengesampingkan pertanyaan yang bersifat menjebak atau jika ada cukup alasan menolak mendengar para pihak. (Rv. 230, 241, 267, 281; Sv. 84; IR. 269; RBg. 572.)"}, {"l": "RV", "p": "232", "b": "Bagian 9. Pendengaran Para Pihak.", "t": "Jika hakim mengabulkan permohonan untuk mendengar para pihak, maka iamemerintahkan mereka untuk menghadap di hadapan sidang atau di hadapan hakim komisaris yang iatentukan pada hari dan jam untuk didengar tentang Pertanyaan-pertanyaan yang diajukan oleh lawan masing-masing. (s.d.t. dg. S. 1908-522.) Dalam putusan itu ditentukan juga hari perkara itu mendapat giliran pemeriksaan lanjutan. (Rv. 16, 48, 68, 230, 234.)"}, {"l": "RV", "p": "233", "b": "Bagian 9. Pendengaran Para Pihak.", "t": "(s.d.u. dg. S. 1908-522; S. 1939-715.) Dalam hal tempat tinggal yang jauh letaknya atau ada halangan yang sah setelah diizinkan untuk mendengar Pihak yang bersangkutan, maka pendengaran dapat diserahkan kepada hakim karesidenan di tempat pihak yang bersangkutan. (s.d.t. dg. S. 1908-522.) Pasal yang lalu alinea kedua berlaku dalam hal ini. (RO. 33; Rv. 239.)"}, {"l": "RV", "p": "234", "b": "Bagian 9. Pendengaran Para Pihak.", "t": "Pihak yang bersangkutan harus secara pribadi, tanpa dibantu oleh pengacara, dan di luar hadimya pemohon atau pengacaranya, tanpa membaca karangan tertulis, menjawab pertanyaan-pertanyaan kepadanya yang diajukan oleh atau oleh pejabat yang menggantikannya dan hal- ikhwal yang dimuat dalam surat Permohonan dan pertanyaan-pertanyaan yang diajukan karena jabatan yang berhubungan dengan itu. (Rv. 231, 833.)"}, {"l": "RV", "p": "235", "b": "Bagian 9. Pendengaran Para Pihak.", "t": "r g s . o Jika pihak yang didengar tentang sesuatu dari pertanyaan-pertanyaan yang diajukan kepadanya, menyatakan tidak mampu menjawab segera l i a dengan memwkan dengan memberikan alasan-alasannya, maka hakim atau t pejabat yang menggantikannya dapat memberikarl Penundaan jika alasan-alasannya itu dapat diterima. a"}, {"l": "RV", "p": "236", "b": "Bagian 9. Pendengaran Para Pihak.", "t": "l. eg w Pengurus lembaga-lembaga umum, yayasan-yayasan dan badan-badan bukum mengangkat salah seorang anggotanya untuk menjawab pertanyaan- w pertanyaan mengenai keiadian-kejadian dan Pokok-pokok persoalannya. Pengurus lembaga umum, w Para pihak tetap mempunyai hak untuk mengajukan pertanyaan kepada yayasan-yayasan dan badan-badan hukum mengenai hal-hal yang bersangkutan dengan dirinya piibadi, agar mendapat perhatian yang semestinya dari hakim. (KUHPerd. 1655, 1795; Rv. 230, 234.)"}, {"l": "RV", "p": "237", "b": "Bagian 9. Pendengaran Para Pihak.", "t": "(s.d.u. dg. S. 1908-522.) Berita acara pemeriksaan dibuat oleh panitera dan di hadapan yang didengar, yang kemudian dapat mengadakan perubahan-perubahan serta tambahan-tambahan yang dipandangnya perlu dan yang ditulis di akhir atau di sebelah kiri berita acara. Tentang hal itu dibacakan juga di hadapan yang didengar dan berita acara ditandatangani oleh pihak yang didengar ketua, hakim komisaris atau Residentierechter dan panitera. (Rv. 232.)"}, {"l": "RV", "p": "238", "b": "Bagian 9. Pendengaran Para Pihak.", "t": "Jika pihak yang bersangkutan tidak datang tanpa alasail yang sah, atau jika ia menolak memberi jawaban, maka hal itu dicantumkan dalam berita acara dan hal-hal yang ditanyakan dapat dianggap telah diakui. Akan tetapi bila pihak yang tidak datang kemudian, sebelum dibuat putusan mengenai pokok perkaranya, datang melapor, maka ia dapat didengar dengan kewajiban membayar biaya yang timbul karena tidak hadimya dan juga membayar kerugian serta bunga jika ada alasan- alasan untuk itu. (KUHPerd. 1875; Rv. 239.)"}, {"l": "RV", "p": "239", "b": "Bagian 9. Pendengaran Para Pihak.", "t": "(s.d.u. dg. S. 1908-522.)Dalam hal pihak yang tidak datang dapat membuktikan adanya halangan yang sah tentang tidak hadimya maka hakim menentukan hari lain untuk mendengamya. (Rv. 16, 233.) Pasal 240. Dicabut kembali dg. S. 1908-522."}, {"l": "RV", "p": "241", "b": "Bagian 10. Gugatan Antara (insidentil).", "t": "(s.d.u. dg. S. 1908-522.) Gugatan-gugatan antara diajukan ke hadapan sidang pada hari-hari yang telah ditentukan disertai kesimpulan- kesimpulannya. Terhadap sengketa antara berlaku ketentuan-ketentuan tersebut dalam pasal: 113, 114, 117, 118, 119 dan 123 s/d. 126. Hakim atas permohonan para pihak secara bersama mengizinkan dilakukannya replik dan duplik. (KUHPerd. 213 dst., 246; Rv. 23, 70, 148, 171, 211, 215, 230, 256, 266, 279, 349, 839, 841.) r g"}, {"l": "RV", "p": "242", "b": "Bagian 10. Gugatan Antara (insidentil).", "t": "s . o Semua gugatan antara diajukan bersama sekaligus. biaya yang mungkin l i a dibayar kemudian dan yang sebab-sebabnya sudah ada bersama-sama yang t dahulu tidak dapat dituntut kembali. (Rv. 58, 98, 106, 117, 135.) a l. eg"}, {"l": "RV", "p": "243", "b": "Bagian 10. Gugatan Antara (insidentil).", "t": "(s.d.u. dg. S. 1908-522.) Gugatan-gugatan antara diputus pertama dan w lebih dahulu jika perkaranya menghendakinya. Sepanjang perkara itu memungkinkan, maka hakim dalam memutus gugatan antara juga w menentukan hari perkara yang bersangkutan diperiksa kembali. w Dalam hal perkara yang diperintahkan untuk diperiksa berdasarkan surat-surat, maka sengketa antara diajukan ke hadapan sidang pengadilan dan diputus sebagaimana mestinya. (Rv. 53, 138 dst., 281.)"}, {"l": "RV", "p": "244", "b": "Bagian 11. Gugatan Balik (Rekonpensi).", "t": "Tergugat berhak untuk mengajukan gugatan balik (rekonpensi) dalam semua perkara, kecuali : 1 . bila penggugat asli (konpensi) bertindak dalam suatu kedudukan tugas, sedangkan gugatan balik itu mengenai pribadi penggugat atau sebaliknya; (KUHPerd. 383, 452, 1655 dst.) 2 . bila hakim yang memeriksa perkara gugatan asal tiddk berwenang untuk mengadili gugatan balik dalam hubungan dengan pokok perkaranya; (ISR. 136; Rv. 99, 130, 132 dst., 310.) 3 . dalam perkara-perkara tentang hak menguasai (bezit), jika gugatan balik mengenai hak milik atas benda yang bersangkutan sendiri (petitoir); (Rv. 103 dst.) 4 . dalam perkara perselisihan mengenai pelaksanaan suatu putusan (Rv. 183,442.) Jikalau dalam tingkat pertama tidak diajukan gugatan balik, maka hal itu tidak dapat diajukan dalam tingkat banding. (KUHPerd. 1425 dst.; WV. 134, 344, 349.)"}, {"l": "RV", "p": "245", "b": "Bagian 11. Gugatan Balik (Rekonpensi).", "t": "Gugatan balik harus segera diajukan bersama dengan jawaban terhadap penggugat. (Rv. 243.)"}, {"l": "RV", "p": "246", "b": "Bagian 11. Gugatan Balik (Rekonpensi).", "t": "Perkara-perkara gugatan asal dan gugatan baliknya diselesaikan dan diputus bersama-sama dalam satu surat keputusan kecuali jika hakim berpendapat bahwa yang satu dapat diselesaikan lebih dulu dari yang lain tetapi dengan ketentuan, bahwa gugatan asal atau gugatan balik yang belum diselesaikan tetap ditangani oleh hakim yang sama sampai diputusnya. (Rv. 53, 247.)"}, {"l": "RV", "p": "247", "b": "Bagian 11. Gugatan Balik (Rekonpensi).", "t": "Banding dimungkinkan bila jumlah gugatan asal ditambah dengan gugatan balik melampaui wewenang hakim untuk memutus dalam tingkat tertinggi. Jika kedua perkara dipisah dan diputus sendiri-sendiri, maka diikuti aturan-aturan yang biasa mengenai wewenang pemeriksaan banding.(Rv. 246.)"}, {"l": "RV", "p": "249", "b": "Bagian 12. Penundaan Dan Lanjutan Pemeriksaan Perkara.", "t": "Dalam hal-hal tersebut di atas tidak diadakan penundaan pemeriksaan atau penghentian perkara jika keadaan sudah sebegitu jauh sehingga perkara sudah pada tahap untuk diputus. (Rv. 112-120.) Dalam tiga hal pertama tersebut dalam pasal yang lalu mengenai soal penundaan, maka yang diartikan perkara sudah ada pada tahap untuk diputus bila kesimpulan-kesimpulan akhir sudah diambil dalam sidang majelis. Dalam hal terakhir, sesudah selesai pembelaan masing-masing atau bila pemeriksaan dengan surat-surat diperintahkan setelah masing- masing jawaban itu diberitahukan kepada para pihak atau jangka waktu yang ditentukan telah lewat. (Rv. 145.)"}, {"l": "RV", "p": "250", "b": "Bagian 12. Penundaan Dan Lanjutan Pemeriksaan Perkara.", "t": "Sebab penundaan pemeriksaan hakim, jika perkara belum sampai pada tahap untuk diputus, diberitahukan atas nama pihak yang berkepentingan kepada pihak lain dan tanpa pemberitahuan semacam itu, walaupun ada sebab-sebab demikian, pemeriksaan perkara dapat dilanjutkan. Hanya dalam kejadian nomor 41 pasal 248 tidak diharuskan adanya pemberitahuan itu dan penundaan terjadi dengan sendirinya. (KUHPerd. 1819; Rv. 252, 337.) Semua acara setelah pemberitahuan itu adalah batal dan tidak mempunyai akibat apa pun, kecuali bila di samping pengangkatan pengacara baru ada pernyataan bahwa pemeriksaan perkara dilanjutkan berdasarkan berkas perkara terakhir, dalam hal itu pemeriksaan dapat segera dilanjutkan. (Rv. 106, 349; Sv. 393.)"}, {"l": "RV", "p": "251", "b": "Bagian 12. Penundaan Dan Lanjutan Pemeriksaan Perkara.", "t": "Jika surat pemberitahuan tidak tnemuat hal itu semua, maka pihak lawan berhak untuk memanggil pihak lain dengan cara yang biasa untuk melanjutkan pemeriksaan perkara berdasarkan berkas perkara terakhir. Hal yang sama terjadi bila pengacara yang meninggal dunia atau kehilangan jabatannya tidak diganti. (Rv. 1, 250, 273.)"}, {"l": "RV", "p": "252", "b": "Bagian 12. Penundaan Dan Lanjutan Pemeriksaan Perkara.", "t": "Pemeriksaan perkara dilanjutkan dan pengacara yang demikian itu diganti dengan akta pemberitahuan yang sederhana. (Rv. 106, 250 dst.) 263. Ditarik kembali dg. S. 1908-522."}, {"l": "RV", "p": "254", "b": "Bagian 12. Penundaan Dan Lanjutan Pemeriksaan Perkara.", "t": "r g s . o Jika terhadap pemanggilan pemeriksaan kembali dijatuhkan putusan, maka sepanjang ada manfaatnya, pemeriksaan dinyatakan dilanjutkan berdasarkan berkas perkara terakhir. l i t a Dalam hal tidak ada penggantian pengacara, maka pokok perkaranya a segera diputus dengan verstek. (Rv. 77 dst., 82 dst., 251.)"}, {"l": "RV", "p": "255", "b": "Bagian 12. Penundaan Dan Lanjutan Pemeriksaan Perkara.", "t": "l. eg w Perlawanan terhadap putusan verstek yang disebut dalam pasal yang lain, juga dalam hal pemeriksaan perkara dilakukan dengan surat- w surat, dapat diselesaikan dalam sidang pengadilan. (Rv. 83, 138 dst.) w"}, {"l": "RV", "p": "256", "b": "Bagian 13. Penyangkalan Dalam Pemeriksaan Hakim.", "t": "Jika selama berjalannya perkara, atas nama salah satu pihak dilakukan suatu tawaran dan diterima, terjadi pengakuan-pengakuan, diberikan izin dan diterima, tanpa oleh pihak itu diberikan kuasa khusus dan tertentu secara tertulis, maka pihak itu di liadapan sidang dapat menyangkal perbuatan-perbuatan demikian itu dengan suatu akta biasa yang diberitahukan baik kepada pengacara pihak lawan maupun kepada pengacara yang perbuatan-perbuatarlnya disangkal, dan pihak itu dapat memohon hakim untuk menganggap perbuatan-perbuatan itu seperti tidak pemah terjadi dan untuk menyatakan tidak berharga semua akta yang timbul karenanya dan putusan-putusan yang diberikan untuk membawa perkara ini, dalam keadaan siap diputus. (KUHPerd. 1405, 1795 dst., 1797, 1807, 1925, 1934; Rv. 38, 372, 809, 860.) Pemberitahuan kepada pengacara berlaku sebagai panggilan di sidang untuk membuat bantahan terhadap penyangkalan. Di dalamnya disebut hari untuk menghadap di sidang. (RV. 8-50 117, 241, 349.)"}, {"l": "RV", "p": "257", "b": "Bagian 13. Penyangkalan Dalam Pemeriksaan Hakim.", "t": "Jika pengacara telah mengundurkan diri, maka penyangkalan diberitahukan di tempat tinggalnya oleh seorang juru sita dan jika pengacara telah meninggal dunia, hal itu diberitahukan kepada ahli warisnya dengan pemanggilan pada hari yang ditentukan menghadap pada hakim yang menangarti perkaranya, dan kepada pihak-pihak dalam perkara diberitahukan dengan surat melalui pengacara masing-masing. (RV. 1, 7, 248-40, 200.)"}, {"l": "RV", "p": "258", "b": "Bagian 13. Penyangkalan Dalam Pemeriksaan Hakim.", "t": "Penyangkalan selalu disampaikan kepada hakim yang menerima perbuatan-perbuatan yang disangkal meskipun perkaranya ditangani oleh seorang hakim lain. Hal itu diberitahukan kepada para pihak dalam pokok perkara dan mereka harus dipanggil dalam pemeriksaan mengenai penyangkalan itu. (RV. 257, 260, 262.)"}, {"l": "RV", "p": "259", "b": "Bagian 13. Penyangkalan Dalam Pemeriksaan Hakim.", "t": "Pemeriksaan mengenai pokok perkaranya ditunda sampai dijatuhkan putusan mengenai penyangkalan dengan ancaman batal. Akan tetapi hakim dapat memerintahkan pihak yang mengajukan r sangkalan untuk melanjutkan pemeriksaan mengenai penyangkalannya g 248, 263.) s . o dalam waktu tertentu atau bila tidak akan dijatuhkan putusan. (RV."}, {"l": "RV", "p": "260", "b": "Bagian 13. Penyangkalan Dalam Pemeriksaan Hakim.", "t": "l i t a a Jika penyangkalan mengenai suatu hal yang tidak sedang menjadi l. eg perkara, maka gugatan diajukan di hadapan hakim yang berwenang bagi pihak tergugat. (RV. 99, 257 dst.)"}, {"l": "RV", "p": "261", "b": "Bagian 13. Penyangkalan Dalam Pemeriksaan Hakim.", "t": "w w w Jika penyangkalan dinyatakan benar, maka perbuatan yang disangkal dan putusan yang dijatuhkan terhadapnya, atau hal-hal yang dinyatakan dalam putusan yang berhubungan dengan penyangkalan itu, menjadi batal dan tidak berharga. (RV. 48, 256, 264.)"}, {"l": "RV", "p": "262", "b": "Bagian 13. Penyangkalan Dalam Pemeriksaan Hakim.", "t": "Akan tetapi dalam hal telah dijatuhkan putusan akhir, dan tenggang waktu untuk mengajukan banding belum habis, pihak yang bersangkutan dapat memohon pembatalan akta-akta dan putusan-putusan yang dimaksud pasal 256 dalam tingkat banding dan diputus pokok perkaranya. (RV. 48, 261, 334 dst.)"}, {"l": "RV", "p": "263", "b": "Bagian 13. Penyangkalan Dalam Pemeriksaan Hakim.", "t": "Dalam hal putusan akhir duatuhkan dalam tingkat tertinggi atau sudah mendapat kekuatan hukum yang pasti, tnaka pihak yang dirugikan sampai saat pelaksanaan putusan dapat memohon kepada hakim yang memutus, agar hal itu ditarik kembali. Selama pemeriksaan tentang hal itu berjalan, maka pelaksanaan putusan ditunda. (RV. 259, 329.)"}, {"l": "RV", "p": "264", "b": "Bagian 13. Penyangkalan Dalam Pemeriksaan Hakim.", "t": "Pengacara yang tuntutan penyangkalan terhadapnya diterima, dihukum membayar kerugian dan bunga kepada penggugat dan pihak lainnya jika ada aiasan-alasan untuk itu. Hakim dapat juga berdasarkan sifat perkaranya, sesuai dengan pasal 192, RO., memberhentikannya untuk sementara atau mengusulkan agar diberbentikan. Jika penggugat yang dinyatakan tidak benar, maka ia dihukum membayar kerugian dan bunga, jika ada alasan-alasan untuk itu. (KUHPerd. 1243 dst.; Rv. 60, 98.)"}, {"l": "RV", "p": "265", "b": "Bagian 13. Penyangkalan Dalam Pemeriksaan Hakim.", "t": "(s.d. u. dg. S. 1908-522.) Jika salah satu pihak menyangkal bahwa pengacara yang mewakilinya telah diberi perintah untuk melakukan perbuatan itu, maka berlaku ketentuan dalam bagian ini. (RV. 106 dst., 260.)"}, {"l": "RV", "p": "266", "b": "Bagian 14. Penunjukan Kepada Pengadilan Lain Dan Soal-soal Kekuasaan", "t": "Bila penolakan terhadap seorang hakim atau permintaan untuk membebaskan diri seorang hakim disetujui, jumlah anggota suatu raad van justitie, termasuk panitera seperti ditentukan dalam pasal 122 RO., tidak lagi mencukupi untuk mengadili perkara yang bersangkutan, maka dapat diajukan tuntutan kepada H.G.H. agar perkara itu diajukan kepada suatu raad van justitie lain. (Ro. 121, 127, 154, 162; Rv. 34 dst., 269, 349; Sv. 277.) r g"}, {"l": "RV", "p": "267", "b": "Bagian 14. Penunjukan Kepada Pengadilan Lain Dan Soal-soal Kekuasaan", "t": "s . o Tuntutan disjukan sebelum diadakan pembelaan dan dalam hal l i t a pemeriksaan dilakukan atas surat-surat sebelum jawaban-jawaban a persiapan selesai seluruhnya, dengan suatu surat permohonan yang l. eg menyebutkan alasan-alasannya. Hal itu diberitahukan kepada pihak lawan dengan peringatan memberikan jawaban serta alasan-alasannya w dalam waktu empat belas hari dan menyampaikannya di kepaniteraan. Jawaban Pihak lawan dalam tenggang waktu itu juga harus sudah w disampaikan di kepaniteraan raad van justitie. w Jalannya Persidangan ditunda seiak hazi pemberitahuan tersebut alinea pertama pasal lni. (Rv. 38, 135 dst., 145, 248, 270.)"}, {"l": "RV", "p": "268", "b": "Bagian 14. Penunjukan Kepada Pengadilan Lain Dan Soal-soal Kekuasaan", "t": "Setelah lewat waktu seperti tersebut dalam pasal yang lalu, maka panitera raad van justitie mengirimkan surat permohonan pengugat untuk penunjukan pengadilan lain dan jawaban pihak lawan segera ke H.G.H. H.G.H. memberi putusan tentang permohonan itu dan jika ada alasan- alasan untuk itu menunjuk hakim yang akan mengadili perkara tersebut. (Ov. 84; Rv. 270, 354.) Dalam hal ini, maka perkara dengan satu akta oleh pihak yang sudah sipil lebih dulu diberitahukan kepada pihak lawan pribadi atau di tempat tinggalnya dengan mengingat jangka waktu yang telah ditentukan untuk pemanggilan menghadap di sidang guna dilanjutkan persidangan berdasarkan segala surat-surat yang disampaikan kepada hakim. (Rv. 10.)"}, {"l": "RV", "p": "269", "b": "Bagian 14. Penunjukan Kepada Pengadilan Lain Dan Soal-soal Kekuasaan", "t": "Dalam hal terjadi yang disebutkan dalam pasal 266, yakni mengenai H- G-H.; maka Gubernur Jenderal, atas permintaan pihak yang paling siap, setelah meminta pendapat H.G.H, untuk sementara dan hanya untuk menyelesaikan perkara dimana penolakan telah terjadi, dapat menambah jumlah anggota majelis itu secukupnya. Dalam pengangkatan sementara yang tidak mengakibatkan penggajian sedapat diperhatikan ketentuan-ketentuan pasal 153 RO. dan kebijaksanaan justitie. (Sv. 279.)"}, {"l": "RV", "p": "270", "b": "Bagian 14. Penunjukan Kepada Pengadilan Lain Dan Soal-soal Kekuasaan", "t": "(s.d.u. dg. S. 1908-522.) Jika timbul perselisihan tentang kekuasaan untuk mengadili, maka diajukan tuntutan untuk pengaturan kekuasaan itu dengan surat Pemohonan yang menyebutkan alasan- alasannya. Surat Permohonan ini diberitahukan kepada pihak lawan disertai peringatan untuk menjwabnya datam waktu satu bulan dan selanutnya sekaligus surat-surat relas pemanggilan dan Peringatan serta surat- surat lainnya disampaikan kepada badan Peradilan yang menurut RO. harus mengadili soal perselisihan tersebut kepada badan mana Pihak lawan juga mengajukan jawabannya. Setelah jawaban masuk atau jangka waktu yang ditentukan untuk itu telah lampau, maka perkaranya diperiksa berdasarkan surat-surat dan diputuskan tentang kekuasaan mengadili (kompetensi). (RO. 127, 162; Rv. 267; RBg. 322-50; S 1926-356jo. S. 1927-246.)"}, {"l": "RV", "p": "271", "b": "Bagian 15. Pencabutan instansi (Tingkatan Kewajiban Dalam Pemeriksaan", "t": "s . o Penggugat dapat melepaskan instansi (mencabut perkaranya) asal hal itu dilakukan sebelum diberikan jawaban. l i t a Setelah ada jawaban, maka pencabutan instansi hanya dapat terjadi a dengan Persetujuan pihak lawan. (RV. 58, 113 dst., 120, 349.)"}, {"l": "RV", "p": "272", "b": "Bagian 15. Pencabutan instansi (Tingkatan Kewajiban Dalam Pemeriksaan", "t": "l. eg w w Pencabutan tnstansi dapat dilakukan di dalam sidang pengadilan jika semua pihak-hadir secara pribadi atau pengacara-pengacara mereka w yang mendapat surat kuasa untuk itu, atau dengan kuasa yang sama diberitahukan dengan akta sederhana oleh pengacara pihak satu kepada pengacara pihak lawan. (Rv.335, 349.) Pencabutan instansi dapat diterima dengan cara yang sama. (Rv. 256.) Pencabutan instansi membawa akibat demi hukum bahwa: 1 . semua pada kedua belah pihak dikembalikan kepada keadaan yang sama seperti sebelum diajukan gugatan; (KUHPerd. 1979, 1981,) 2 . pihak yang mencabut gugatannya berkewajiban membayar biaya perkara yang harus dilakukan berdasarkan surat perintah Ketua yang ditulis menurut penaksiran besamya biaya. (Rv. 58 dst., 607 dst.) surat perintah ini dapat dilaksanakan segera. (Rv. 54. dst., 246, 334,)"}, {"l": "RV", "p": "273", "b": "Bagian 16. Gugumya Instansi.", "t": "Instansi gugur jika dalam tiga tahun tidak dilanjutkan. Jangka waktu ditambah dengan enam bulan dalam hal permohonan untuk melanjutkan perkara masih dapat terjadi. (KUHPerd. 271; Rv. 90, 248 dst., 275, 349.)"}, {"l": "RV", "p": "274", "b": "Bagian 16. Gugumya Instansi.", "t": "Jangka waktu yang dipersyaratkan untuk gugumya suatu instansi berlaku terhadap negara, lembaga-lembaga umum, anak-anak di bawah umur dan pada umumnya terhadap semua orang, tanpa kecuali, dengan tidak mengurangi hak semua pihak tersebut untuk minta pertanggungjawaban dari pengurus-pengurusnya dan wali-walinya. (KUHPerd. 385, 404, 452, 1365, 1987.)"}, {"l": "RV", "p": "275", "b": "Bagian 16. Gugumya Instansi.", "t": "Instansi tidak gugur demi hukum. Pernyataan gugur dapat dicegah dengan tindakan hukum yang dilakukan oleh salah satu pihak, sebelum permohonan untuk dinyatakan gugur diajukan. (KUHPerd. 1950, 1979,)"}, {"l": "RV", "p": "276", "b": "Bagian 16. Gugumya Instansi.", "t": "Pernyataan gugur diucapkan dalam sidang secara sederhana dan diberitahukan kepada pihak yang bersangkutan atau di tempat tinggalnya. Pernyataan gugur tidak membatalkan tuntutannya melainkan hanya acara perkara yang telah dimulai; biaya perkara karena pernyataan gugur itu dianggap sudah dibayar. (Rv. 58, 106, 272, 278.)"}, {"l": "RV", "p": "277", "b": "Bagian 16. Gugumya Instansi.", "t": "Dalam pengajuan gugatan yang baru, maka pihak-pihak satu sama lain berhak untuk menggunakan lagi sumpab-sumpah, pengakuan-pengakuan, dan keterangan-keterangan yang telah diberikan olehnya dalam perkara r g yang terdahulu, begitu juga keterangan-keterangan yang telah s . o diberikan oleh saksi-saksi yang sudah meninggal dunia, jika hal itu l i a telah dicantumkan dalam berita acara yang dibuat dengan baik. t (KUHPerd. 1925, 1929 dst.; Rv. 209, 230 dst., 293 dst,, 894 dst.) a l. eg"}, {"l": "RV", "p": "278", "b": "Bagian 16. Gugumya Instansi.", "t": "Dengan gugumya instansi dalam tingkat banding, maka putusan yang"}, {"l": "RV", "p": "279", "b": "Bagian Ke 17. w w", "t": "w (s.d.u. dg. S. 1908-522.) Barangsiapa mempunyai kepentingan dalam suatu perkara perdata yang sedang berjalan antara pihak-pihak lain dapat menuntut untuk menggabungkan diri atau campur tangan. (KUHPerd. 188, 1558; F. 118; Rv. 72, 74, 128, 282, 349, 378, 535 dst.)"}, {"l": "RV", "p": "280", "b": "Bagian Ke 17. w w", "t": "(s.d.u. dg. S. 1908-522.) Tindakan-tindakan ini dilakukan dengan surat permohonan pada hari sidang yang telah ditetapkan sebelum atau pada waktu kesimpulan terakhir diambil dalam perkara yang sedang berjalan. Dalam perkara yang diperiksa t)erdasarkan surat-surat, tindakan itu dilakukan dengan pemberitahuan kepada para pihak disertai pemanggilan mereka untuk menghadap di sidang pengaditan. (Rv. 112- 117; 120, 138 dst., 249, 281.)"}, {"l": "RV", "p": "281", "b": "Bagian Ke 17. w w", "t": "(s.d.u. dg. S. 1908-522.) surat permohonan, yang sekaligus berisi pengangkatan seorang pengacara, memuat nama kecil, nama dan tempat tinggal yang mengajukan permohonan serta dasar alasan permohonan iiu diajukan, semua dengan ancaman batal. Ia dianggap telah memilih tempat tinggal pada pengacaranya, kecuali jika dalam surat permohonannya ia menyatakan memilih tempat tinggal lain. (Rv. 8, 94, 106.)"}, {"l": "RV", "p": "282", "b": "Bagian Ke 17. w w", "t": "(s.d.u. dg. S. 1908-522.) Jika hakim yang memutus permohonan itu memerintahkan para pihak untuk melanjutkan perkaranya, maka dalam putuan yang sama itu ditentukan pula haii mereka harus menghadap di muka persidangan untuk melanjutkan perkaranya itu. (Rv. 241, 243.)"}, {"l": "RV", "p": "283", "b": "Bagian 18. Pemeriksaan Singkat Di Hadapan Ketua R.v.J.", "t": "Dalam perkara-perkara yang menghendaki segera diberikan putusan, tuntutan dapat diajukan kepada sidang secara singkat yang diadakan oleh ketua R.v.J. pada hari-hari yang sudah ditentukan untuk itu tentang pelaksanaan putusan pengadilan atau suatu alas hak pelaksanaan (executoriale titel), tentang perselisihan penyegelan atau pengangkatan segel, maupun tentang kewajiban seorang Notaris untuk membuat suatu akta notaris yang tidak dapat ditunda dan selanjutnya dalam segala hal untuk kepentingan pihak-pihak yang memerlukan pelaksanaan segera. Dalam hal-hal yang benar-benar sangat mendesak, maka pemanggilan r g s . o dapat diperintahkan pada hari dan jam, termasuk hari Minggu, yang ditentukan oleh ketua bagi setiap perkara atas permohonan secara lisan oleh pihak yang berkepentingan. l i t a Dalam hal ini ketua dapat memerintahkan agar persidangan diadakan di a rumah yang berkepentingan. (RO. 29; Rv. 17, 22, 285, 293, 348, 442, l. eg 599, 659, 668, 669-80, 676, 682, 688, 720 dst., 884.)"}, {"l": "RV", "p": "284", "b": "Bagian 18. Pemeriksaan Singkat Di Hadapan Ketua R.v.J.", "t": "w w Dalam hal yang terakhir ini ketua memerintahkan secara lisan w kepada seorang juru sita untuk melakukan pemanggilan dan di kepata surat panggilan dicantumkan bahwa perkara itu sangat mendesak. Para pihak dalam hal seperti tersebut dalam pasal yang lain juga secara sukarela dapat datang menghadap kepada ketua raad van justitie (Rv. 283.)"}, {"l": "RV", "p": "285", "b": "Bagian 18. Pemeriksaan Singkat Di Hadapan Ketua R.v.J.", "t": "Jika dalam persidangan kepada ketua ternyata bahwa perkara dapat ditunda tanpa menimbulkan kerugian yang besar atau kerugian yang tidak dapat diperbaiki untuk diperiksa secara biasa atau secara singkat oleh raad van justitie sendiri atau jika perkara tidak mempunyai alasan untuk diperiksa secara singkat, maka ia menunjuk para pihak ke acara biasa, atau memberi izin kepada pihak yang mengajukan untuk menggugat dengan acara singkat di pengadilan yang berwenang mengadili perkara itu. (Rv. 10, 120, 284.)"}, {"l": "RV", "p": "286", "b": "Bagian 18. Pemeriksaan Singkat Di Hadapan Ketua R.v.J.", "t": "Putusan-putusan yang segera harus dilaksanakan tidak membawa kerugian kepada perkara pokoknya. (Rv. 53, 58, 68, 283, 332, 682, 688.)"}, {"l": "RV", "p": "287", "b": "Bagian 18. Pemeriksaan Singkat Di Hadapan Ketua R.v.J.", "t": "Ketua berwenang memerintahkan pelaksanaan putusan-putusannya dengan segem atau tanpa jaminan, meskipun ada perlawanan atau banding dalam perkara-perkara yang dapat dimintakan banding. (RO. 124 dst.; Rv. 54 dst., 291, 311.)"}, {"l": "RV", "p": "288", "b": "Bagian 18. Pemeriksaan Singkat Di Hadapan Ketua R.v.J.", "t": "(s.d.u. dg. S. 1908-522.) Perlawanan diajukan kepada raad van justitie. (Rv. 83 dst.)"}, {"l": "RV", "p": "289", "b": "Bagian 18. Pemeriksaan Singkat Di Hadapan Ketua R.v.J.", "t": "(s.d.u. dg. S. 1908-522.) Banding dapat segera dilakukan setelah dijatuhkan putusan yang dapat dilaksanakan dengan segera ataupun tidak. Banding diajukan kepada H.G.H. Setelah lewat tiga minggu dihitung dari hari keputusan, maka permohonan banding tidak dapat diterima lagi. (RO. 124 dst., 190; Rv. 68, 287, 330, 334, 338 dst., 435.)"}, {"l": "RV", "p": "290", "b": "Bagian 18. Pemeriksaan Singkat Di Hadapan Ketua R.v.J.", "t": "surat-surat asli (minut) keputusan ketua dimasukkan dalam daftar khusus di kepaniteraan dan ditandatangani oleh ketua dan panitera. (Rv 62.)"}, {"l": "RV", "p": "291", "b": "Bagian 18. Pemeriksaan Singkat Di Hadapan Ketua R.v.J.", "t": "Jika diperlukan sekali untuk kepentingan perkara, maka ketua dapat memerintahkan pelaksanaan atas dasar keputusan asli. (Rv. 287, 435.) r g 292. Dicabut dg. s . o S. 1901-168. (Lihat RB9. pasal 321-2 dan 322- 70) l i t a Pasal 293. a l. eg Di setiap raad van justitie diadakan daftar giliran sidang tersendiri, untuk perkara-perkara yang diperiksa secara singkat oleh w Ketua menurut pasal 65 RO. (Rv. 283 dst., 290.) w w ATURAN PENUTUP BAB II"}, {"l": "RV", "p": "293A", "b": "Bagian 18. Pemeriksaan Singkat Di Hadapan Ketua R.v.J.", "t": "(s.d.t. dg. S. 1908-522.) Jika suatu gugatan yang dalam pemeriksaan terdahulu tidak dapat diselesaikan, bukan karena pencabutan atau gugur, diajukan kembali, maka masing-masing pihak terhadap satu sama lain, berhak untuk menggunakan lagi sumpah, pengakuan serta keterangan-keterangan dalam sidang yang telah diajukan dalam pemeriksaan perkara yang dahulu. Hal yang sama berlaku terhadap keterangan para saksi-saksi, keterangan ahli, dalam perkara terdahulu atau pendapatnya tentang pemeriksaan atau pengamatan setempat asal satu dan lain tercantum dalam berita acara atau laporan tertulis yang dibuat dalam bentuk baik. Jika hakim memandang perlu untuk mendengar lagi beberapa atau semua saksi yang dalam perkara yang terdahulu pemah didengar, maka pemeriksaan yang baru itu dilakukan di hadapan hakim itu sendiri. (Rv. 172 dst., 277.)"}, {"l": "RV", "p": "299", "b": "BAB III BERACARA DI MUKA SIDANG DALAM PERKARA-PERKARA WESEL DAN KELAUTAN", "t": "(s.d.u. dg. S. 1938-276) Ketua R.v.J. dapat memberi izin kepada scorang pemegang surat Wesel atau surat tanda utang, yang terhadapnya dinyatakan tidak akan dibayar, untuk meletakkan sita jaminan atau, benda-henda bergerak milik orang yang mengeluarkan Wesel, yang membuat akseptasi dan Para endosan (orang-orang yang memindahkan Wesel). (KUHD 142 dst.; 176; Rv. 720 dst., 763a dst., 763h dst.; Cpt. 65 dst.; S. 1926-28 pasal 9.) (s.d.t. dg. S. 1935-77jo. 562.) Izin yang sama dapat diberikan kepada pemegang cek yang terhadapnya dinyatakan tidak akan dibayar atau pernyataan lain semacam itu atas benda-benda bergerak milik orang yang mengeluarkan cek atau yang memindahkan cek itu. (KUHD 217r g dst.; RBg. 321, 322-20'.) s . o 300-307. Dicabut dg. S. 1938-276. l i t a a l. eg"}, {"l": "RV", "p": "308", "b": "BAB III BERACARA DI MUKA SIDANG DALAM PERKARA-PERKARA WESEL DAN KELAUTAN", "t": "Dalam perkara-perkara mengenai kelautan atau yang disamakan dengan itu jika ada pihak-pihak yang tidak mempunyai tempat tinggal yang w w tetap dan juga dalam perkara mengenai alat-alat perlengkapan kapal, persediaan makan di kapal, anak buah kapal, bagian-bagian dari kayu w pada perahu-perahu yang siap berlayar dan hal-hal lain yang perlu segera disediakan, maka pemanggilan di sidang dapat dilakukan tiap- tiap hari, tiap-tiap jam tanpa surat perintah dan perkara itu segera, bahkan dapat diputus verstek. (KUHD 309 dst.; Rv. 79, 316a dst., 577.)"}, {"l": "RV", "p": "309", "b": "BAB III BERACARA DI MUKA SIDANG DALAM PERKARA-PERKARA WESEL DAN KELAUTAN", "t": "Semua pemanggilan yang dilakukan di kapal bagi nakhoda, opsir atau anak buah kapal, atau seorang penumpang adalah sah dan berlaku. (Rv. 1, 3 dst.) 310, 311, 312. Dicabut dg. S. 1938-276."}, {"l": "RV", "p": "313", "b": "BAB III BERACARA DI MUKA SIDANG DALAM PERKARA-PERKARA WESEL DAN KELAUTAN", "t": "(s.d.u. dg. S. 1908-522) Jika diperlukan pembagian dalam semua biaya, luar biasa kapal yang dikeluarkan, maka atas permohonan salah satu pihak oleh raad van justitie akan diangkat ahli-ahli, kecuali jika para pihak telah menyetujui pengangkatan ahli-ahli yang lain. (KUHD 698 dst., 724, 726; Rv. 215 dst.)"}, {"l": "RV", "p": "314", "b": "BAB III BERACARA DI MUKA SIDANG DALAM PERKARA-PERKARA WESEL DAN KELAUTAN", "t": "Nakhoda atau, jika ini tidak ada, pengusaha angkutan laut diwajibkan dalam waktu delapan hari setelah ahli-ahli diangkat oleh para pihak atau oleh raad van justitie, menyampaikan kepada panitera: (KUHD 724.) 10. daftar barang-barang yang dimuat dalam kapal yang menyebutkan jumlah, merek dan nomor-nomor barang-barang pemiagaan, nama para penyewa ruangan kapal dan yang memasukkan barang itu dalam kapal dan nama mereka yang barang-barangnya ditahan. (KUHD 347, 454 dst, 505 dst.) 20. keadaan serta besamya kapal serta besamya biaya angkutan. (KUHD 347.) Sementara itu Para pemilik barang-barang yang diangkut wajib menyampaikan kepada panitera suatu daftar harga barang-barang itu sewaktu dimuat dalam kapal dan diturunkan dari kapal. Para pihak jika diminta, harus menguatkan kebenaran isi surat-surat yang disampaikan dengan sumpah."}, {"l": "RV", "p": "315", "b": "BAB III BERACARA DI MUKA SIDANG DALAM PERKARA-PERKARA WESEL DAN KELAUTAN", "t": "Setelah para ahli disumpah, maka panitera menyerahkan kepada Para ahli itu surat-surat yang telah disampaikan oleh Para pihak kepada panitera, dengan menerima tanda terima. Para ahli kemudian mengadakan pembagian sesuai ketentuan Kitab Undang-undang Hukum Dagang (KUHD), juga meskipun salah satu pihak tidak menyerahkan surat-suratnya kepada panitera. (KUHD 724, 727 dst.; Rv. 32 1.)"}, {"l": "RV", "p": "316", "b": "BAB III BERACARA DI MUKA SIDANG DALAM PERKARA-PERKARA WESEL DAN KELAUTAN", "t": "r g . o Laporan para ahli beserta surat-surat yang diterima dari panitera s diserahkan kepada panitera. Pihak yang sudah siap lebih dulu l i t a meminta pengesahan raad van justitie, dan setelah Para pihak didengar atau dipanggil dengan patut, doatuhkan putusan. (RO. 124; KUHD 214; Rv. 225.) a Dg. l. eg S. 1933-47jo. 1938-2 ditambahkan pasal-pasal 316a-316r."}, {"l": "RV", "p": "316A", "b": "BAB III BERACARA DI MUKA SIDANG DALAM PERKARA-PERKARA WESEL DAN KELAUTAN", "t": "w w w Untuk dapat mendasarkan pada pembatasan tanggungjawabnya yang ditentukan dalam pasal 474, 525 dan 541 KUHD, maka pemilik perusahaan angkutan laut wajib menyetorkan kepada panitera raad van justitie tempat kapal tersebut telah didaftar, sejumlah uang yang tersebut dalam pasal itu untuk kepentingan mereka yang mempunyai tagihan seperti tersebut dalam pasal itu, disertai permohonan kepada raad van justitie untuk pengangkatan hakim komisans. Dalam menerapkan pasal 316a-316o pengusaha angkutan laut diwakili oleh pengacara; pengusaha angkutan laut tersebut dianggap memilih tempat tinggal di tempat tinggal pengacara tersebut. (KUHPerd. 24, 1916; KUHD 314, 320; Rv. 106, 108j, 3161, p, r, 483, 512, 547.) Dalam hal kapal tidak terdaftar, maka penyerahan uang tersebut dalam alinea pertama dilakukan kepada panitera raad van justitie yang wilayah hukumnya meliputi tempat tinggal pemilik kapal yang bersangkutan. (Tbs. 3, 8 , 19 dst.) Jika tempat tinggal itu tidak termasuk wilayah salah satu raad van justitie, penyerahan uang itu dilakukan di kepaniteraan raad van justitie di Jakarta. (RO. 117 dst; RBg. 73 dst.)"}, {"l": "RV", "p": "316B", "b": "BAB III BERACARA DI MUKA SIDANG DALAM PERKARA-PERKARA WESEL DAN KELAUTAN", "t": "Tentang penyetoran uang serta pengangkatan hakim komisaris oleh panitera segera diumumkan dalam majalah resmi (Berita Negara) dan dalam satu atau beberapa surat kabar lain yang ditunjuk oleh hakim komisaris. Pengumuman itu memuat nama, alamat serta kantor pengusaha angkutan laut yang bersangkutan, nama kapal, nama hakim komisaiis, dan jumlah uang yang telah disetorkan kepada panitera. (KUHPerd. 17; Rv. 316a, d, p, q, r.)"}, {"l": "RV", "p": "316C", "b": "BAB III BERACARA DI MUKA SIDANG DALAM PERKARA-PERKARA WESEL DAN KELAUTAN", "t": "Dalam waktu delapan hari setelah mengajukan permohonan, maka pemohon menyampaikan daftar orang-orang yang ia kenal terhadap siapa ia menurut pasal 474, 525 dan 541 KUHD dapat mendasarkan pembatasan akan tanggung jawabnya. (Rv. 316a, p, q, r.)"}, {"l": "RV", "p": "316D", "b": "BAB III BERACARA DI MUKA SIDANG DALAM PERKARA-PERKARA WESEL DAN KELAUTAN", "t": "Selanjutnya hakim komisaris menentukan sebelum habis jangka waktu, untuk mengajukan tagihan-tagihan disertai dengan surat-surat yang bersangkutan kepada panitera, demikian pula hari, jam dan tempat untuk mencocokkan tuntutan-tuntutan, termasuk di dalamnya hak-hak yang harus didahulukan. (KURD 316, 318.) panitera segera memberitahukan penetapan-penetapan ini dengan surat kepada semua penagih tersebut dalam daftar dimaksud dalam pasal yang lain dan juga kepada pemohon; di samping itu maka hal itu diumumkannya dalam majalah resmi (Berita Negara) dan dalam satu atau beberapa surat kabar yang ditunjuk oleh hakim komisaris. (Rv. 316a-c, g, p, q, r.) r g"}, {"l": "RV", "p": "316E", "b": "BAB III BERACARA DI MUKA SIDANG DALAM PERKARA-PERKARA WESEL DAN KELAUTAN", "t": "s . o l i a Setelah lewat jangka waktu tersebut dalam pasal 316d, maka oleh t panitera dibuat daftar tagihan-tagihan yang telah diterimanya dengan a nenyebut tiap-tiap surat yang bersangkutan dengan tiap-tiap tagihan l. eg itu. Daftar ini diletakkan di kepaniteraan dalam waktu paling sedikit w delapan hari sebelum hari diadakan pencocokan tagihan-tagihan untuk dapat dilihat oleh siapa ptin tanpa membayar. (Rv. 316a, h, p, q, r.) w"}, {"l": "RV", "p": "316F", "b": "BAB III BERACARA DI MUKA SIDANG DALAM PERKARA-PERKARA WESEL DAN KELAUTAN", "t": "w Pada hari yang telah ditetapkan, maka hakim komisaris dengan dibantu panitera mengadakan sidang terbuka untuk pencocokan tagihan-tagihan. Untuk itu iamenyurith membacakan daftar tagihan yang masuk. Pengusaha angkutan laut dan tiap-tiap penagih dapat mengajukan keberatan terhadap pengakuan tagihan atau tentang hak untuk didahulukan. (Rv. 316a, l, p q, r.)"}, {"l": "RV", "p": "316G", "b": "BAB III BERACARA DI MUKA SIDANG DALAM PERKARA-PERKARA WESEL DAN KELAUTAN", "t": "Tagihan-tagihan yang dimasukkan setelah lewat jangka waktu seperti tersebut dalam pasal 316d atas permohonan penagih dapat diterima oleh hakim untuk dicocokkan. Permohonan harus diterima jika penagih bertempat tinggal di luar Indonesia dan karena itu terhalang untuk datang lebih awal. (Rv. 316p, q, r.) Pasal 316h. Tagihan-tagihan dan hak untuk didahulukan yang tidak dibantah dianggap sebagai diakui. Tentang pengakuan itu dicatat dalam berita acara persidangan dan dalam daftar tersebut dalam pasal 316e. (Rv. 316f, p, q, r.) Pasal 316i. Dalam hal ada bantahan, maka hakim komisaris memerintahkan para pihak apabila tidak dapat mencapai kesepakatan, untuk menghadap ke sidang raad van justitie yang ia tentukan harinya tanpa perlu diadakan panggilan. Para pengacara yang mewakili masing-masing pihak menyatakan hal itu pada waktu dipanggil dalam persidangan Jika orang yang berpiutang yang mohon pengesahan tidak datang di hadapan persidangan, maka ia dianggap tnenarik kembali permohonannya yang dibantah; jika ia datang menghadap sedangkan yang membantah tidak datang, maka ia dianggap tidak mempertahankan bantahannya dan hakim mengakui tagihan itu atau hak untuk didahulukan. (Rv. 1, 106, …"}, {"l": "RV", "p": "3161", "b": "BAB III BERACARA DI MUKA SIDANG DALAM PERKARA-PERKARA WESEL DAN KELAUTAN", "t": "w w Dalam sidang pencccokan tagihan-tagihan maka tiap-tiap penagih dapat w memohon pembenaran jumlah uang yang disetorkan oleh pengusaha angkutan taut dan membantah kebenaran jumlah itu. Hakim komisaris dalam hal ada bantahan, menentukan hari persidangan dimana raad van justitie menyelesaikan perkara itu. (Rv. 316a, f, i, p, q, r.) Pasal 316m. Pada hari yang ditentukan maka para pihak atau wakil-wakilnya didengar dalam sidang terbuka yang kemudian diputus oleh raad van justitie. Ketentuan dalam pasal 316k berlaku dalam hal ini. (Rv. 316a, p, q, r.) Pasal 316n. Sesudah rapat, atau jika hal ini menimbulkan perselisihan, sesudah tentang hal itu diadakan keputusan yang tetap, maka oleh panitera dibuat daftar pembagian dan kemudian dimintakan persetujuan hakim komisaris. Hakim komisaris dapat mengangkat seorang ahli untuk membantu panitera dalam menyusun daftar. Iajuga yang menentukan upahnya. (Rv. 316f, k, o, q, t.)"}, {"l": "RV", "p": "3160", "b": "BAB III BERACARA DI MUKA SIDANG DALAM PERKARA-PERKARA WESEL DAN KELAUTAN", "t": "Daftar pembagian yang sudah disetwui oleh hakim komisaris selama, enam minggu diletakkan di kepaniteraan raad van justitie untuk dapat dilihat dengan cuma-cuma oleh para penagih yang telah diakui tagihannya. Tentang peletakan daftar tersebut oleh panitera diberitahukan kepada pihak-pihak kreditur dengan surat tercatat; masing-masing dari mereka selama waktu dimaksud dapat mengajukan perlawanan terhadap daftar pembagian tersebut dengan mengajukan surat keberatan disertai alasan-alasannya ke kepaniteraan. Setelah lewat tenggang waktu yang ditentukan, raad van justitie memberikan keputusannya sesudah mendengar para kreditur atau setelah mereka dipanggil dengan patut. Panggilan dilakukan oleh panitera dengan surat tercatat. Terhadap banding terhadap putusan ini berlaku pasal 316k. Setelah daftar pembagian oleh hakim komisaxis atau, bila ada perlawanan, oleh hakim dinyatakan dapat dilaksanakan, maka panitera raad van justitie memanggil dengan surat tercatat para kreditur untuk menerima bagian masing-masing. Daftar tersebut setelah dinyatakan dapat dilaksanakan diletakkan di kepaniteraan untuk dapat dilihat dengan cuma-cuma oleh yang berkepentingan. (Rv. 316e, n, p, q, r.) Pasal 316p. …"}, {"l": "RV", "p": "318", "b": "BAB IV PENUNTUT UMUM", "t": "S. 186.4-522 jo. 1908-522 pasal 105c dengan ditariknya kembali pasal 318 dan 320 dan RO. pasal 55 ayat terakhir, dan semua peraturan yang bertentangan dengan itu, telah ditentukan: Dalam suatu perkara perdata penuntut umum di Indonesia tidak memberikan suatu pendapat, dan hanya hadir di persidangan bila ditentukan oleh undang-undang atau demi kepentingan peradilan. (RO. 54 dst., 61 dst.; Rv. 806.)"}, {"l": "RV", "p": "319", "b": "BAB IV PENUNTUT UMUM", "t": "(s.d.u. dg. S. 1872-13; lW8-522.) Jika penuntut umum karena jabatannya bertindak sebagai satu Pihak, maka ia harus mengikuti ketentuan-ketentuan umum dalam hukum acara Perdata, kecuali dalam hal penunjukan pengacara. (RO. 55, 170-10, 171; KUHPerd. 65, 86, 88 dst., 92, 381, 435, 463, 465, 1127; RV4 106, 867) Hukuman-hukuman yang mungkin dijatuhkan terhadapnya mengenai penggantianbiaya, kerugian ke bunga serta biaya perkara selalu dipikul oleh Negara. (Rv. 58.) 320. Ditarik kembali: lihat pasal 318."}, {"l": "RV", "p": "321", "b": "BAB IV PENUNTUT UMUM", "t": "Penuntut umum dapat menuntut agar kepadanya diberitahukan semua perkara yang dipandang perlu berhubung dengan pekerjaannya itu. Hakim, karena jabatan, dapat juga memerintahkan agar hal-hal semacam itu diberitahukan kepada penuntut umum. (RO. 55.)"}, {"l": "RV", "p": "322", "b": "BAB IV PENUNTUT UMUM", "t": "Penuntut umum segera setelah selesai pertukaran pendapat para pihak (pleidoi) atau pada hari sidang lain yang ditentukan menyarnpaikan pendapatnya. (Rv. 61-20.)"}, {"l": "RV", "p": "323", "b": "BAB IV PENUNTUT UMUM", "t": "Para pihak atau pembela-pembela mereka, tanpa alasan apa pun mendapat kesempatan untuk mengajukan pembelaannya setelah penuntut umum mengajukan pendapatnya. r g Hanya catatan-catatan kecil untuk menjelaskan hal-ikhwal yang s . o menurut pendapatnya merupakan kekhilafan penuntut urnum dapat segera disampaikan kepada ketua. (Rv. 146.) l i t a a"}, {"l": "RV", "p": "324", "b": "BAB V", "t": "Dalam hal perkara yang mungkin banding kepada raad van justitie atau H.G.H., maka para pihak bebas untuk bersepakat dengan suatu akta untuk memohon agar perkara mereka sejak semula langsung diperiksa oleh badan peradilan yang scharusnya akan mengadili perkara itu dalam tingkat banding. (ISR. 136; RO. 127, 163 dst.; KUHPerd. 1851 dst.; Rv. 133, 351, 354, 615, 638.)"}, {"l": "RV", "p": "325", "b": "BAB V", "t": "Para wali pengampu dan mereka yang menurut ketentuan-ketentuan undang-undang tanpa izin atau kuasa, tidak boleh rnengadakan perdamaian atau menyerahkan perkara kepadanya wasit, dalam membuat kesepakatan yang tersebut dalarn pasal 324 harus mendapat izin atau kuasa pula dari yang berkepentingan. (KUHPerd. 307, 352, 361, 393 dst., 407, 452, 789, 983, 1019, 1797, 1852; F. 100; Rv. 615.)"}, {"l": "RV", "p": "326", "b": "BAB V", "t": "Bagi raad vanjustitie dan H.G.H. dalam proses perkara-perkara ini berlaku aturan-aturan tentang pemeriksaan perkara dalam tingkat pertarna. Badan peradilan yang memeriksa karena prorogasi memutus perkara yang bersangkutan dalam tingkat pertama dan terakhir dengan tidak mengurangi peninjauan kembali, dan bagi raad van justitie juga dengan tidak mengurangi kasasi bila untuk satu dan lain ada dasar hukumnya. (Rv. 385 dst., 402 dst.)"}, {"l": "RV", "p": "327", "b": "Bagian 1. Perkara-perkara yang Dapat Dimohonkan Banding.", "t": "Para pihak dapat mengajukan pemeriksaan dalam tingkat banding kepada H.G. H. dalam perkara yang dipiitus dalam tingkat pertama oleh R.v.J. (RO. 124 dst.; F. 8 dst., 82, 150, 210, 217; Rv. 44, 247, 289, 330, 438, 641, 847, 892.)"}, {"l": "RV", "p": "328", "b": "Bagian 1. Perkara-perkara yang Dapat Dimohonkan Banding.", "t": "Dalam persengketaan tentang wewenang mengadili, maka banding dapat diterima, meskipun hakim yang wewenangnya untuk mengadili ditangkis, sebenamya berhak mengadili pokok perkaranya dalam tingkat tertinggi. (Rv. 130; Sv. 313.) r g"}, {"l": "RV", "p": "329", "b": "Bagian 1. Perkara-perkara yang Dapat Dimohonkan Banding.", "t": "s . o l i a tiap-tiap pihak yang menyatakan menerima putusan tidak dapat t diterima untuk mengajukan pemeriksaan dalam tingkat banding. (Rv. 84, 278, 385, 404.) a"}, {"l": "RV", "p": "330", "b": "Bagian 1. Perkara-perkara yang Dapat Dimohonkan Banding.", "t": "l. eg Putusan-putusan verstek tidak dapat dimintakan banding, tetapi jika w w penggugat aslinya menyatakan banding, maka tergugat dapat juga menyampaikan semua pembelaannya dalam tingkat banding, bahkan w sebagai banding insidentil tanpa dapat menggunakan lagi upaya perlawanan dalam tingkat pertama. Akan tetapi dalam hal terjadi seperti diatur dalam pasal 81 bagian akhir, maka pihak yang ketinggalan dapat minta banding, asal sebelumnya memenuhi putusan terlebih dahulu dengan memberikan jaminan dan bahkan bila dalam putusan itu tidak diperintahkan pelaksanaan lebih dahulu. (Rv. 89, 324 dst., 611.)"}, {"l": "RV", "p": "331", "b": "Bagian 1. Perkara-perkara yang Dapat Dimohonkan Banding.", "t": "(s. d. u. dg. S. 1908-522.) Banding terhadap putusan persiapan, putusan sela, dan putusan insidentil, tidak dapat diajukan kecuali dalam waktu yang sudab ditentukan dan bersama-sama dengan banding terhadap putusan akhir. Banding ini dapat diterima meskipun putusan persiapan, putusan sela dan putusan insidentil tanpa kecuali terhadap mereka yang berkeberatan telah dilaksanakan. (Rv. 48, 332, 334, 363, 404; IR. 190; RBg. 201.) Putusan pengadilan yang mengandung ketetapan sedemikian rupa sehingga menyebabkan penyelesaian pokok perkara tidak ada, dianggap sebagai putusan akhir. Putusan pengadilan yang berisi penolakan penggabungan atau campur tangan berlaku terhadap mereka yang mengajukannya juga sebagai putusan akhir. (Rv. 48, 53.)"}, {"l": "RV", "p": "332", "b": "Bagian 1. Perkara-perkara yang Dapat Dimohonkan Banding.", "t": "(s.d.u. ag. S. 1908-522.) Permohonan banding terhadap suatu putusan pengadilan yang mengabulkan atau menolak tuntutan provisi dapat dilakukan sebelum putusan akhir dijatuhkan. Hal yang sama berlaku terhadap putusan yang dijatuhkan atas permohonan-permohonan sementara, begitu pula terhadap putusan yang dtatuhkan atas permohonan untuk memanggil seseorang untuk menanggungnya terhadap tuntutan atau terhadap pembelaan yang dimaksud dalam pasal 114, jika kesemuanya itu diajukan secara terpisah. Akan tetapi jika dalam hal pasal 70 tangkisan terhadap wewenang mengadili berkaitan dengan permohonan pemanggilan untuk penanggungan dan dalam hal ini hakim menyatakan diri berwenang, maka permohonan banding tidak dapat diajukan tersendiri sebelum dijatuhkan putusan akhir terhadap pokok perkaranya. (Rv. 48, 53, 171, 211, 215, 230, 286, 331, 334, 336, 404; IR. 190; RBg. 201.)"}, {"l": "RV", "p": "333", "b": "Bagian 1. Perkara-perkara yang Dapat Dimohonkan Banding.", "t": "Ditarik kembali dg. S. 1908-522."}, {"l": "RV", "p": "334", "b": "Bagian 2. Jangka Waktu Untuk Permohonan Banding.", "t": "s . (s.d.u. dg. S. 1908-522) Jangka waktu untuk permohonan banding o l i a adalah tiga bulan terhitung hari dijatuhkan putusan, kecuali yang t ditentukan dalam pasal 339 alinea kedua dan ketiga. (Rv. 15, 289, a 331, 336, 341, 489, 515, 530, 539, 554, 818; F. 8, 11, 150, 217; IR. l. eg 188.)"}, {"l": "RV", "p": "335", "b": "Bagian 2. Jangka Waktu Untuk Permohonan Banding.", "t": "w w (s.d.u. dg. S. 1908-522) Pihak terbanding sebaliknya dapat mengajukan banding insidentil, bahkan sesudah lampau jangka waktu w tersebut dalam pasal yang lain dan sesudah menyatakan menerima putusan. Permohonan banding insidentil dalam kesempatan ini diajukan dalam kesimpulan jawabannya, dengan ancaman gugur. (Rv. 329 dst., 342 dst., 420.) Pencabutan banding pokok tidak membatalkan banding insidentil yang diajukan. (Rv. 272, 278.)"}, {"l": "RV", "p": "336", "b": "Bagian 2. Jangka Waktu Untuk Permohonan Banding.", "t": "Setelah lampaujangka waktu tersebut dalam pasal 334, maka banding tidak dapat diajukan lagi. Jangka waktu itu berlaku terhadap semua pihak dengan tidak mengurangi ganti rugi menurut hak masing-masing. (KUHPerd. 1239.) Alinea ketiga dan keempat dicabut dg. S. 1908-522."}, {"l": "RV", "p": "337", "b": "Bagian 2. Jangka Waktu Untuk Permohonan Banding.", "t": "(s. d. u. dg. S. 1908-522) Jika pihak yang kalah meninggal dunia dalam tenggang waktu untuk mengajukan banding, maka permohonan banding masih dapat diajukan oleh ahli warisnya atau mereka yang mendapat hak daripadanya dalam waktu enam bulan setelah.kematiannya, atau jika mereka menggunakan hak untuk berpikir dalam dua bulan setelah tenggang waktu untuk itu lewat. (Rv. 248, 250, 390, 404; KUHPerd. 1023 dst., 1992.)"}, {"l": "RV", "p": "338", "b": "Bagian 2. Jangka Waktu Untuk Permohonan Banding.", "t": "Banding terhadap suatu putusan yang tidak dapat dilaksanakan lebih dahulu, tidak dapat dilaksanakan dalam waktu delapan hari setelah putusan diucapkan; jika permohonan banding diajukan dalam tenggang waktu itu, maka perinohonan itu tidak dapat diterima dengan tidak mengurangi wewenangnya mengulangi permohonan bandingnya, asal jangka waktunya belum habis. Putusan yang tidak dapat dilaksanakan lebih dahulu, ditunda dalam waktu delapan hari itu. (Rv. 54 dst., 289, 334, 346, 515, 530.)"}, {"l": "RV", "p": "339", "b": "Bagian 3. Pemeriksaan Dalam Tingkat Banding Dan Akibat-akibatnya.", "t": "Pemeriksaan dalam tingkat banding dimulai dengan suatu pemanggilan untuk menghadap di sidang yang bentuk dan caranya sama dengan pemeiiksaan dalam tingkat pertama tanpa harus menyebutkan alasan- alasan yang menjadi dasar permohonan banding maupun tanpa harus melampirkan turunan-turunan surat-surat yang bersangkutan, kecuali dalam hal pemanggilan itu mengandung tuntutan baru yang diperbolehkan oleh pasal 344. Semua itu diberitahukan dengan cara yang sama. Pasal 10 alinea terakhir berlaku juga bagi penggugat pembanding. Surat permohonan yang bersangkutan harus disampaikan ke kepaniteraan r g H.G. H. Sebelum jangka waktu yang ditentukan habis. s . (s.du. dg. . 1908-522.) Hari pengajuan surat permohonan berlaku o l i a sebagai hari permulaan pemeriksaan tingkat banding dan dicatat oleh t panitera H. G. H. dalam; surat permohonan tersebut dan kemudian a segera dengan surat tercatat diberitahukan kepada pihak terbanding. l. eg H.G.H. tidak akan memperhatikan permohonan banding tersebut jika tidak diajukan dalam jangka waktu seperti tersebut dalam alinea kedua kepada panitera; w Ketentuan-ketentuan dalam bagian 7 Bab I buku ini berlaku juga dalam w tingkat banding. (Rv. 1 dst., 6 dst., …"}, {"l": "RV", "p": "341", "b": "Bagian 3. Pemeriksaan Dalam Tingkat Banding Dan Akibat-akibatnya.", "t": "Banding terhadap ketetapan-ketetapan mengenai permohonan-permohonan diajukan juga kepada hakim yang lebih tinggi dengan surat permohonan. Hal yang sama harus dilakukan oleh mereka yang menerima penetapan- penetapan semacam itu dalam waktu tiga bulan setelah tanggal penandatanganan surat penetapan ftu dan orang-orang lain yang berkepentingan dalam tiga bulan setelah surat itu diberitahukan kepada mereka. Jangka waktu itu menjadi enam bulan jika yang diberitahukan itu bertempat tinggal di suatu pulau di Indonesia seperti dimaksud dalam pasal 334 lama alinea terakhir. 342. Ditarik kembaii dg. S. 1908-522."}, {"l": "RV", "p": "343", "b": "Bagian 3. Pemeriksaan Dalam Tingkat Banding Dan Akibat-akibatnya.", "t": "(s.d.u. dg. S. 1908-522.) Dalam tingkat banding digunakan acara seperti diatur untuk tingkat pertama dengan perbedaan, bahwa hanya kesimpulan gugatan dan kesimpulan jawaban yang dapat diajukan. Tetapi jika diajukan banding insidentil ataujika oleh terbanding diajukan tangkisan terhadap banding pokok, maka atas pennohonan pembanding diberi waktu untuk dapat memberi jawaban terhadap banding insidentil atau terhadap tangkisan itu. (Rv. 107 dst., 118 dst., 335.)"}, {"l": "RV", "p": "344", "b": "Bagian 3. Pemeriksaan Dalam Tingkat Banding Dan Akibat-akibatnya.", "t": "Dalam tingkat banding tidak dapat diajukan tuntutan-tuntutan baru kecuali jika mengenai: 10. uang bunga, sewa dan lain-lain akibat kebendaan yang sudah ada atau timbul sejak putusan dalam tingkat pertama; (KUHPerd. 500 dst., 502, 588, 1250, 1560-50, 1765.) 20. biaya, kerugian dan bunga karena kerugian yang diderita, sejak putusan itu; (KUHPerd. 1243.) 3 . tuntutan untuk dapat dijalankan lebih dahulu. (Rv. 53.) (s.d. u. dg. S. 1908-522) Tergugat asli dapat mengajukan pembelaan baru tentang hak-hak yang mengenai persoalan pokoknya, kecuali hal itu ditutupnya dalam tingkat pertama, tidak termasuk kejadian yang menyebabkan gugumya jawaban menurut pasal 114; tetapi seandainya ia dibenarkan dalam persoalan pokoknya, ia dapat dihukum juga membayar biaya acara sampai pada pengajuan pembelaan yang ia sebenamya dapat lakukan dalam tingkat pertama. (KUHPerd. 443, 1426, 1951; Rv, 71, 132, 244-2 , 339, 345, 349, 989.) r g"}, {"l": "RV", "p": "345", "b": "Bagian 3. Pemeriksaan Dalam Tingkat Banding Dan Akibat-akibatnya.", "t": "s . o l i a (s.d. u. dg. S. 1908-522.) Baik dalam banding pokoknya maupun dalam t banding insidentil dapat diajukan tuntutan baru dan pembelaan baru a yang telah diatur dalam pasal yang lain dengan disertai kesimpulan l. eg yang berdasarkan alasanalasan yang jelas. (Rv. 241, 399.)"}, {"l": "RV", "p": "346", "b": "Bagian 3. Pemeriksaan Dalam Tingkat Banding Dan Akibat-akibatnya.", "t": "w w Gugatan tersebut dalam pasal 339 menangguhkan pelaksanaan putusan pengadilan, jika tidak ditentukan bahwa putusan tersebut dapat w dilaksanakan lebih dahulu dalam hal-hal yang diperbolehkan. (Rv. 54 dst., 381, 403, 437 dst., 442, 585.)"}, {"l": "RV", "p": "347", "b": "Bagian 3. Pemeriksaan Dalam Tingkat Banding Dan Akibat-akibatnya.", "t": "(s.d.u. dg. S. 1908-522.) Jika pelaksanaan tidak diperintahkan lebih dahulu dalam hal-hal yang diperintahkan oleh undang-undang atau diperbolehkannya, maka terbanding dalam kesimpulan masih dapat menuntut agar pelaksanaan dilakukan dengan lebih dahulu pada hari yang ditentukan sebagai hari persidangan pertama. (Rv. 54 dst., 82, 403.)"}, {"l": "RV", "p": "348", "b": "Bagian 3. Pemeriksaan Dalam Tingkat Banding Dan Akibat-akibatnya.", "t": "Jika di luar yang ditentukan menurut undang-undang diperintahkan agar putusan provisional dilaksanakan, maka pembanding dalam persidangan dapat mohon agar pelaksanaan dihentikan; ia setelah mendapat izin, juga dapat memanggil lawannya dalam persidangan singkat. (Rv. 10, 54 dst., 82, 381.)"}, {"l": "RV", "p": "349", "b": "Bagian 3. Pemeriksaan Dalam Tingkat Banding Dan Akibat-akibatnya.", "t": "(s.d.u. dg. S. 1908-522.) Pasal 23 tentang pendaftaran di dalam daftar giliran sidang dan ketentuan dalam Bab II buku ini dan juga ketentuan-ketentuan penutup dalam bab itu berlaku juga dalam tingkat banding dalam hal: - pengangkatan pengacara (Rv. 106.) - pengajuan hari sidang (Rv. 107.) - permohonan-permohonan sementara dan tangkisan-tangkisan (Rv. 128 dst.) - pemeriksaan berdasarkan surat-surat (Rv. 138 dst.) - sengketa mengenai asli atau tidaknya surat-surat (Rv. 148 dst.) - pemeriksaan saksi-saksi (Rv. 171.) - pemeriksaan dan pengamatan setempat (Rv. 211 dst.) - laporan para ahli (Rv. 215 dst.) - pemeriksaan para pihak (Rv. 230.) - tuntutan-tuntutan insidentit (Rv. 241 dst.) - penundaan dan lanjutan pemeriksaan (Rv. 248 dst.) - penyangkalan perbuatan-perbuatan dalam sidang (Rv. 256 dst.) - melepaskan kesempatan pemeriksaan tingkat pertama (Rv. 271 dst.) - gugumya pelepasan tingkat itu (Rv. 273.) - penggabungan dan campur tangan (Rv. 279.) dalam banding berlaku pula seperti yang disebutkan dalam pasal penutup dari Bab itu. (Rv. 244, 343 dst.) Dalam pada itu pasal 128 dan 129 hanya berlaku dengan tidak mengurangi ketentuan-ketentuan sebagai berikut: Tergugat asli, penggugat …"}, {"l": "RV", "p": "350", "b": "Bagian 3. Pemeriksaan Dalam Tingkat Banding Dan Akibat-akibatnya.", "t": "l i t a a Dalam hal keputusan dikuatkan, maka pelaksanaannya dilakukan oleh l. eg hakim yang mengadilinya dalam tingkat pertama. Dalam hal putusan dibatalkan untuk seluruhnya atau untuk sebagian, w maka pelaksanaannya dilakukan oleh hakim yang memutus dalam tingkat banding atau oleh yang ditunjuk dalam putusan, kecuali dalam w tuntutan untuk membatalkan penyanderaan dan pencabutan dengan paksa w dan lain-lain yang diperintahkan oleh undang-undang kepada pengadilan. (Rv. 61, 360, 429, 460, 497 dst., 605, 734, 766; IR. 195; RBg. 206,)"}, {"l": "RV", "p": "351", "b": "Bagian 3. Pemeriksaan Dalam Tingkat Banding Dan Akibat-akibatnya.", "t": "(s.d.u. dg. S. 1908-522.) Dalam hal banding putusan-putusan yang dimaksud dalam pasal 332 diajukan sebelum dijatuhkan putusan akhir, maka hakim banding dalam Putusannya menyampaikan perkara tersebut kepada hakim pertama untuk memutus pokok gugatannya, kecuali jika tangkisan tentang wewenang mengadili yang bersangkutan dengan permohonan pemanggilan untuk penanggungan ataupun jika pembelaan dimaksud dalam pasal 114 dinyatakan beralasan atau jika terjadi penunjukan perkara kepada hakim lain atau kepada para wasit. Pengembalian perkara kepada hakim pertama untuk diputuskan tentang pokok perkaranya, dilakukan juga dalam hal hakim banding memberikan keputusan atau putusan termaksud dalam pasal 331 alinea keempat. (Rv. 48, 241, 324 dst., 357.) 352, 353. Ditarik kembaii dg. s. 1908-522."}, {"l": "RV", "p": "354", "b": "Bagian 3. Pemeriksaan Dalam Tingkat Banding Dan Akibat-akibatnya.", "t": "Jika hakim pertama telah menyatakan diri tidak berwenang dan putusan itu dibatalkan, maka hakim banding akan menyampaikan perkara itu kembali kepada hakim pertama untuk diputus pokok persoalannya, kecuali: 10. jika kedua pihak menuntut agar hakim banding itulah yang mengadili perkara itu; (Rv. 324 dst., 351, 357.) 20. jika hakim banding itu memandang ada alasan-alasan yang berhubungan dengan sifat perkaranya untuk menarik perkara itu kepadanya. (Rv. 991.)"}, {"l": "RV", "p": "355", "b": "BAB VII PEMERIKSAAN DALAM TINGKAT BANDING TENTANG", "t": "(s.d.u. dg. s. 1908-522.) Pernyataan permohonan banding terhadap perkara yang diputus oleh badan pengadilan untuk orang-orang Indonesia dianggap oleh R.v.J. mengandung pernyataan bahwa dimohonkan banding juga terhadap putusan-putusan yang mendahului putusan pengadilan itu serta penetapan-penetapan, kecuali jika dalam 96, 109; IR. 188, 192; RBg. 199, 204.) r g catatan permohonan banding dinyatakan secara tegas sebaliknya. (RO."}, {"l": "RV", "p": "356", "b": "BAB VII PEMERIKSAAN DALAM TINGKAT BANDING TENTANG", "t": "s . o i t a (s.d.u. dg. S. 1908-522.) Para pihak berhak untuk menyerahkan l penjelasan-penjelasan dan surat-surat di kepaniteraan pengadilan a l. eg yang lebih tinggi yang mereka anggap perlu asal surat-surat sebelumnya telah diberitahukan kepada pihak lawan dengan perantaraan pengacaranya atau orang lain yang herwenang untuk menyampaikan w w pemberitahuan, menurut ketentuan dalam H. I. R. atau aturan-aturan yang sama yang mengatur pengadilan untuk daerah luar Jawa dan w Madura. Penyerahan surat-surat itu sekali-kati tidak boleh menghambat penyelesaian perkaranya. Hakim yang lebih tinggi tidak akan memperhatikan surat-surat demikian itu atau yang dahulu sudah disampaikan di kepaniteraan hakim pertama, yang sebelumnya sesuai ketentuan tidak ternyata telah diberitahukan kepada pihak lawan (RQ.. 432; IR. 192 dst., 388 dst.; RBg. 202 dst., 716 dst.) (s.d.t dg. S. 1908-522.) Dalam tingkat banding tidak boleh diajukan tuntutan baru kecuali yang berhubungan dengan pasal 344 alinea pertama. (s.d.t. dg. S. 1908-522.) Sebaliknya tergugat boleh mengajukan pembelaan yang baru asal mengenai pokok persoalannya dan belum dikemukakan dalam tingkat pertama; ia dapat dihukum untuk membayar biaya …"}, {"l": "RV", "p": "357", "b": "BAB VII PEMERIKSAAN DALAM TINGKAT BANDING TENTANG", "t": "(s.d.u. dg. S. 1908-522.) Perkara kemudian oleh hakim banding yang bersangkutan tanpa hanyak proses diputus berdasarkan surat-surat saja tetapi ia berwenang sebelum menjatuhkan putusan akhir untuk memberi putusan persiapan atau putusan sela. Pasal 354 berlaku dalam hal ini. (s.d.t. dg. S. 1914-414.) R.v.J. berhak mengadakan catatan-catatan tentang cara penyelesaian perkara tersebut."}, {"l": "RV", "p": "358", "b": "BAB VII PEMERIKSAAN DALAM TINGKAT BANDING TENTANG", "t": "Putusan pengadilan banding dibuat dan diucapkan dengan cara biasa. (Rv. 61, 64; IR. 184; RBg. 195.) (s.d.u. dg. S. 1901 -124.) Panitera raad vanjustitie segera mengirimkan turunan otentik putusan dalam bentuk yang dapat ditaksanakan dengan berkas yang bersangkutan kepada hakim pertama serta memberitahukannya kepada penuntut umum tentang putusan asli yang ada di kepaniteraan. Penuntut umum dapat melihatnya dan bila perlu dapat meminta turunannya yang otentik. (Rv. 360, 435, 992; IR. 194; RBg. 205.)"}, {"l": "RV", "p": "359", "b": "BAB VII PEMERIKSAAN DALAM TINGKAT BANDING TENTANG", "t": "(s.d.u. dg. S. 1,937-631.) Semua putusan raad vanjustitie dalam tingkat banding dianggap dijatuhkan atas bantahan. (Rv. 81, 385, 993.)"}, {"l": "RV", "p": "360", "b": "BAB VII PEMERIKSAAN DALAM TINGKAT BANDING TENTANG", "t": "Pelaksanaannya selalu dilakukan oleh hakim yang memutus dalam tingkat pertama. (Rv. 350, 358, 429, 432, 994; IR. 195; RBg. 206.)"}, {"l": "RV", "p": "361", "b": "BAB VII PEMERIKSAAN DALAM TINGKAT BANDING TENTANG", "t": "(s.d.u. dg. S. 1901-24, S. 1937-631.) Panitera raad van justitie r g s . o mencatat dengan seksama semua perkara yang ada dalam tingkat banding dalam sebuah register yang diperuntukkan untuk itu. Pencatatan itu l i a menyebut nama para pihak dan tanggal putusan yang dimohonkan t banding, tentang pernyataan banding, tentang penerimaan berkas a perkaranya, tentang putusan yang doatuhkan dalam tingkat banding, l. eg dan tentang pengiriman putusan itu kepada hakim pertama. (Rv. 358, 438, 994; IR. 191; RB9. 202.) w"}, {"l": "RV", "p": "378", "b": "BAB X PERLAWANAN PIHAK KETIGA", "t": "Pihak-pibak ketiga berhak melakukan perlawanan terhadap suatu putusan yang merugikan hak-hak mereka, jika mereka secara pribadi atau wakil mereka yang sah menurut hukum, atau pun pihak yang mereka wakili tidak dipanggil di sidang pengadilan, atau karena penggabungan perkara atau campur tangan dalam perkara pemah menjadi pihak. (KUHPerd. 383, 452, 833, 955, 1917; F. lo, 24; Rv. 279, 349, 382, 384.)"}, {"l": "RV", "p": "379", "b": "BAB X PERLAWANAN PIHAK KETIGA", "t": "Perlawanan ini diperiksa hakim yang menjatuhkan putusan itu. Perlawanan diajukan dengan suatu pemanggilan untuk menghadap sidang terhadap semua pihak yang telah mendapat keputusan dan peraturan umum mengenai cara berperkara berlaku dalam perlawanan ini. (KUHPerd. 1967; Rv. 1, 99 dst., 384.)"}, {"l": "RV", "p": "380", "b": "BAB X PERLAWANAN PIHAK KETIGA", "t": "Jika putusan yang demikian dijatuhkan terhadap pihak ketiga dalam suatu persidangan dan perlawanan terhadapnya dilakukan sesuai pasal yang lain, maka hakim yang memeriksa perkara berwenang jika untuk itu ada alasan-alasan mengizinkan penundaan perkara itu sampai perkara perlawanan diputus. (Rv. 248 dst., 384, 393)"}, {"l": "RV", "p": "381", "b": "BAB X PERLAWANAN PIHAK KETIGA", "t": "Hakim yang memeriksa perkara perlawanan, jika ada alasan-alasannya, dapat menunda pelaksanaan putusan yang dilawan sampai soal perlawanan itu diputus. (Rv. 346, 384, 396, 437.)"}, {"l": "RV", "p": "382", "b": "BAB X PERLAWANAN PIHAK KETIGA", "t": "Bila perlawanan disahkan, maka putusan yang dilawan itu diperbaiki hanya sejauh hal merugikan hak-hak pihak ketiga itu, kecuali jika putusan yang dijatuhkan mengenai hal-hal yang tidak dapat dipecah, menghendaki pembatalan seluruh putusan. (Rv. 378.) 383. Ditarik kembali dg. S. 1872-13."}, {"l": "RV", "p": "384", "b": "BAB X PERLAWANAN PIHAK KETIGA", "t": "Ketentuan-ketentuan dalam bab ini berlaku juga bagi keputusan yang dijatuhkan oleh H.G.H. r g"}, {"l": "RV", "p": "386", "b": "BAB XI", "t": "Anak-anak yang di bawah umur masih dapat mengajukan peninjauan kembali, jika mereka tidak pemah dibela. (KUHPerd 229, 330, 383, 403, 452, 1446 dst., 1450; Rv. 401.)"}, {"l": "RV", "p": "387", "b": "BAB XI", "t": "Jika hanya ada alasan untuk menarik kembali sebagian putusan, maka hanya bagian itu yang ditarik kembali, kecuali jika bagian-bagian lain tergantung dari bagian itu. (Rv. 398, 401.)"}, {"l": "RV", "p": "388", "b": "BAB XI", "t": "(s.d. u. dg. S. 1908-522.) Peninjauan kembali dilakukan dengan pemanggilan untuk menghadap sidang dan dilakukan dalam waktu tiga bulan terhitung hari keputusan yang tidak disetujui diucapkan dengan tidak mengurangi apa yang ditentukan dalam pasal 339 alinea kedua dan ketiga yang juga berlaku dalam hal ini. Jangka waktu menjadi enam bulan bagi mereka yang bertempat tinggal di sebuah pulau di Indonesia, di luar Jawa dan Madura. (Rv. 10, 15, 402; RBg. 322-90.) Terhadap anak-anak, dalam hal apa yang diatur dalam pasal 386, jangka waktu tidak berlaku sebelum anak itu menjadi dewasa, dan r g s . o pemberitahuan dilakukan kepadanya sendiri atau dilakukan di tempat tinggalnya. (KUHPerd. 330, 420; Rv. 68, 336, 389 dst., 391 dst., 394, 401, 435.) l i t a"}, {"l": "RV", "p": "389", "b": "BAB XI", "t": "a l. eg Terhadap perkara-perkara yang diputus verstek, tenggang waktu mulai berjalan sejak hari tidak dapat lagi dilakukan perlawanan. (Rv. 84 dst., 385, 401.) w w"}, {"l": "RV", "p": "390", "b": "BAB XI", "t": "w Jika pihak yang kalah meninggal dunia dalam jangka waktu seperti tersebut di atas, maka berlaku pasal 337. (Rv. 284-40, 250, 388, 401.)"}, {"l": "RV", "p": "391", "b": "BAB XI", "t": "Jika peninjauan kembali diajukan berdasarkan pemalsuan penipuan, tipu-muslihat atau karena ditemukan surat-surat baru, maka tenggang waktu mulai berlaku baru sejak diketahui kepalsuan, penipuan atau tipu-muslihat atau ditemukannya surat-surat yang disembunyikan asal dalam hal-hal terakhir itu dengan surat-surat dibuktikan tentang hari diketahui atau ditemukannya kenyataan-kenyataan tersebut. (KUHPerd. 1861, 1866; Rv. 385-10, 70 dan 80, 388, 401.)"}, {"l": "RV", "p": "392", "b": "BAB XI", "t": "(s.d. u. dg. S. 1908-522.) Jika terjadi pertentangan antara putusan- putusan maka tenggang waktunya dihitung mulai hari dijatuhkan putusan terakhir allujika itu diputus verstek dihitung sejak hari terhadap verstek itu tidak dapat lagi diadakan perlawanan. (Rv. 385- 61, 388, 398, 401, 430.)"}, {"l": "RV", "p": "393", "b": "BAB XI", "t": "Peninjauan kembali diajukan kepada hakim yang sama yang telah menjatuhkan putusan yang tidak disetujui. (Rv. 399.) Jika putusan yang tidak disetujui diajukan dalam suatu perkara yang sedang diperiksa oleh hakiin lain, maka hakim ini dengan melihat keadaan dapat melanjutkan pemeriksaan perkara itu atau menundanya. (Rv. 134, 250, 380, 399.)"}, {"l": "RV", "p": "394", "b": "BAB XI", "t": "Peninjauan kembali diajukan dengan pemanggilan untuk menghadap sidang dalam bentuk biasa, diberitahukan kepada pihak yang bersangkutan atau di tempat tinggalnya. Di dalamnya disebutkan upaya-upaya yang menjadi dasar permohonan itu; upaya lain tidak dapat diajukan, baik di dalam sidang maupun dengan surat. (Rv. I dst., 8-31, 118 dst., 230, 267, 280, 388, 393, 401, 411.) 395. Ditarik kembali dg. S. 1872-13."}, {"l": "RV", "p": "396", "b": "BAB XI", "t": "Peninjauan kembali tidak menghambat pelaksanaan putusan yang tidak disetujui dan ini tidak dapat dicegah dengan perintah hakim. (Rv. 346, 348, 381, 393, 398, 401.)"}, {"l": "RV", "p": "397", "b": "BAB XI", "t": "Ditarik kembali dg. S. 1872-13. r g"}, {"l": "RV", "p": "398", "b": "BAB XI", "t": "s . o l i putusan yang bersangkutan ditarik kembali dan para pihak a (s. d. u. dg. S. 1872-13.) Jika peninjauan kembali dikabulkan, maka t a dikembalikan dalam keadaan seperti sebelum putusan itu dijatuhkan, l. eg segala apa yang sebagai akibat penghukuman yang dijatuhkan dalam putusan telah dinikmati atau diterima harus dikembalikan. (Rv. 385- 50, 387, 392.) w w Jika peninjauan kembali dikabulkan karena ada pertentangan antara w putusan-putusan, maka dengan putusan diperintahkan, bahwa putusan yang pertamalah yang mempunyai kekuatan. (Rv. 385-50, 392, 401, 430.)"}, {"l": "RV", "p": "399", "b": "BAB XI", "t": "Sengketa pokok, terhadap mana putusan yang ditiwau kembali dijatuhkan, diperiksa oleh hakim yang sama, yang memutus peninjauan kembali. (Rv. 393, 401.)"}, {"l": "RV", "p": "400", "b": "BAB XI", "t": "Setelah mengajukan peninjauan kembali, entah itu diterima atau tidak, maka tidak dapat diajukan peninjauan kembali yang kedua, baik terhadap putusan yang diberikan dalam peninjauan kembah maupun terhadap putusan, sesudah peninjauan kembali itu diterima, dalam pokok perkaranya. (Rv. 89, 330, 385, 401; Sv. 324.)"}, {"l": "RV", "p": "401", "b": "BAB XI", "t": "Ketentuan-ketentuan bagian ini berlaku juga bagi putusan-putusan H.G.H."}, {"l": "RV", "p": "477", "b": "Bagian 2. Sita Eksekutorial Pada Pihak Ketiga. (S.1853-70, 71.)", "t": "(s. d. u. dg. S. 1925-497.) Sita atas piutang-piutang yang mungkin dapat dituntut pihak yang dieksekusi dari pihak ketiga, at4u atas barang-barang miliknya yang mungkin ada pada pihak ketiga, memuat kecuali persyaratan-persyaratan yang biasa tentang eksplot, juga r pemilihan tempat tinggal pada ibu kota dari afdeling tempat tinggalg . pihak ketiga itu, dengan perintah untuk menahan apa yang disita s o dalam kekuasaannya, dengan ancaman pembayaran atau penyerahan yang telah dilakukan, tidak berharga. l i t a a dengan salinan keputusan hakim atau alas hak eksekutorial lainnya, l. eg berdasarkan surat-surat mana pelaksanannya dilakukan. (KUHPerd. 24, 511-31; Rv. 2 dst., 8, 433, 450, 474 dst., 481a, 481b, 491, 542, 593, 728 dst., 812.) w w"}, {"l": "RV", "p": "478", "b": "Bagian 2. Sita Eksekutorial Pada Pihak Ketiga. (S.1853-70, 71.)", "t": "w Dalam delapan hari setelah melakukan sita ini, hal itu harus disampaikan kepada pihak yang dieksekusi dengan ancaman batal, tanpa diharuskan untuk memberikan suatu keterangan yang cukup tentang hal itu. (Rv. 475, 481, 731.) (s.d.u. dg. S. 1908-522.) Bila yang dieksekusi bertempat tinggal dalam karesidenan lain dari tempat dilakukannya sita pada pihak ketiga, jangka waktu pemberitahuan diperpanjang menurut ukuran yang ditetapkan pada pasal 10 dengan pengertian, bahwa bila timbul hal yang dimaksud dalam alinea terakhir pasal itu, pemberitahuan dilakukan dalam empat puluh hari. (Rv. 479, 481g3; RBg. 322-100.)"}, {"l": "RV", "p": "479", "b": "Bagian 2. Sita Eksekutorial Pada Pihak Ketiga. (S.1853-70, 71.)", "t": "Dalam delapan hari setelah pemberitahuan tersebut dalam pasal yang lalu, pihak yang terkena eksekusi, bila dia beranggapan mempunyai dasar-dasar untuk itu, dapat melakukan perlawanan terhadap sita ini, dan dalam hak itu menyampaikan perlawanannya dalam delapan hari kemudian kepada pihak ketiga yang terkena sita. (s.d.u. dg. S. 1908-522.) Jangka-jangka waktu itu diperpanjang menurut ukuran yang ditetapkan dalam pasal 10, bila tentang hal yang pertama pihak yang melakukan sita bertempat tinggal dalam karesidenan lain daripada tempat tinggal pihak yang terkena eksekusi, dan mengenai hal yang kedua, pihak ketiga yang terkena sita tidak bertempat tinggal di karesidenan yang sama dengan tempat pemanggilan perlawanan dikeluarkan. (s.d.t. dg. S. 1908-522.) Bila terhadap eksekutan terjadi hal seperti yang dimaksud dalam alinea terakhir pasal 10, maka surat permohonan dimaksud di situ, yang dilampiri dengan salinan eksplot pemberitahuan yang diterima oleh pihak yang dieksekusi, dimasukkan dalam waktu delapan hari sesudah pemberitahuan pada kepaniteraan hakim yang memeriksa perlawanan itu. Hari pemasukan oleh panitera dicatat pada surat permohonan. Hakim tidak akan mengindahkan perlawanan, …"}, {"l": "RV", "p": "480", "b": "Bagian 2. Sita Eksekutorial Pada Pihak Ketiga. (S.1853-70, 71.)", "t": "s . o Bila perlawanan pihak yang dieksekusi dianggap mempunyai dasar, dan l i t a karena itu,dia mendapat hak untuk diangkat sitanya, bila ada dasar untuk itu, eksekutan diputuskan untuk dihukum atas penggantian a biaya-biaya, kerugiankerugian dan bunga-bunga, untuk kepentingan l. eg pihak yang dieksekusi. (KUHPerd. 1365 dst.; Rv. 479, 481d, 607, 723.)"}, {"l": "RV", "p": "481", "b": "Bagian 2. Sita Eksekutorial Pada Pihak Ketiga. (S.1853-70, 71.)", "t": "w w w Bila yang dieksekusi tidak melakukan perlawanan tersebut dalam pasal 479, atau bila hal itu dilakukan, tetapi ditolak, pihak ketiga yang terkena sita (dalam hal terakhir dengan pemberitahuan keputusan penolakannya) dipanggil ke sidang pengadilan untuk memberi keterangan dengan cara sama dan dengan akibat-akibat yang sama seperti yang ditentukan pada pasal 733 dan berikutnya. (Rv. 476, 48le, 734 dst.)"}, {"l": "RV", "p": "481A", "b": "Bagian 2. Sita Eksekutorial Pada Pihak Ketiga. (S.1853-70, 71.)", "t": "(s.d.t. dg, S. 1938-680.) Penyitaan pada pihak ketiga untuk negara, umum atau dana pensiun Indonesia, dengan tidak mengurangi ditentukan dalam pasal 65 dan 66 Undang-undang Perbendaharaan Indonesia (ICW), pasal 23 Keputusan Desentralisasi dan pasal 9 Keputusan Raja 3 desember 1925 No. 51 (I.S. 1926 No. 28) diperkenankan, namun hanya atas piutang-piutang atau barang-barang tertentu yang diuraikan dalam surat juru sita atau dalam hal sita yang disederhanakan, yang diuraikan dalam pemberitahuan atau dalam tuntutan. Pembayaran atau penyerahan setelah penyitaan membebaskan Negara, badan-badan umum atau dana pensiun Indonesia, bila suatu perintah yang diberikan sebelum sita untuk membayar atau menyerahkan tidak dapat lagi ditarik kembali tepat pada waktunya. Dengan alasan kepentingan umum, Negara, badan-badan umum atau dana pensiun Indonesia, dalam proses singkat di hadapan ketua dapat meminta pengangkatan sita pada pihak ketiga. (Rv. 283 dst., 481b dst., 730.) Dengan S. 1933-622, mb. 22 Desember 1938, ditambahkan bagian berikut:"}, {"l": "RV", "p": "481B", "b": "Bagian 2A. Sita Eksekutorial Terhadap Pihak Ketiga Mengenai", "t": "Pengenaan sita atas tagihan sejumlah uang yang digunakan untuk pengurusan sesuatu menurut Buku Kesatu Kitab Undang-undang Hukum Perdata, termasuk di dalamnya biaya pengurusan dan pendidikan seorang anak di bawah umur, upah atau pemberian tunjangan secara berkala, yang dapat ditagih kepada pihak ketiga oleh orang yang terhadapnya dikenakan sita, dilaksanakan dengan tuntutan dan cara yang mendatangkan akibat seperti yang ditentukan dalam bagian yang lalu, sejauh mengenai hal itu dalam bagian ini tidak diadakan penyimpangan. (KUHPerd. 329a.)"}, {"l": "RV", "p": "481C", "b": "Bagian 2A. Sita Eksekutorial Terhadap Pihak Ketiga Mengenai", "t": "Ketentuan-ketentuan dalam peraturan-peraturan umum yang menjadi dasar wewenang para kreditur, begitu pula tentang upah dan tunjangan-tunjangan berkala lainnya, tidak diberlakukan untuk bagian itu. (KUHPerd. 1602g; Rv. 451 dst.) r g s . o Akan tetapi dalam hal ini ketentuan dalam pasal 750 hanya dinyatakan tidak berlaku bila eksekutannya adalah Dewan Perlindungan Anak-anak."}, {"l": "RV", "p": "481D", "b": "Bagian 2A. Sita Eksekutorial Terhadap Pihak Ketiga Mengenai", "t": "l i t a a orang yang dikenakan sita, setiap waktu dapat mengadakan perlawanan l. eg dengan cara dan akibat-akibat termaksud dalam pasal 479 dan 480, atas dasar bahwa ketentuan tnengenai pemberian tunjangan itu pada w waktu itu telah diubah atau telah dicabut, atau bahwa kewajiban untuk membelikan tunjangan itu telah tidak ada. (KUHPerd. 329b.) w Pasal 481e. w Semenjak hari dikenakan sita terhadap pihak ketiga, pihak ini wajib melakukan pembayaran, seperti yang telah dikenakan sita kepadanya, kepada eksekutan bila eksekutan ini menghendaki, dan bila hal itu mengenai upah dan tunjangan-tunjangan berkala lainnya, ia wajib melakukan pembayaran sejumlah uang yang pembayarannya ditunggak, kecuali bila ada tagihan yang dikenakan sita terhadap utang-utang yang derajatnya lebih tinggi atau sama. (Rv. 477 dst. 728 dst.) Dalam hal termaksud pada akhir alinea yang lalu, pihak ketiga yang dikenakan sita ini dapat digugat untuk mengadakan pernyataan tersebut dalam pasal 734. (Rv. 481; RO. 116g .) Perlawanan yang diajukan oleh orang yang dikenakan sita, menunda kewajiban untuk melakukan pembayaran, kecuali bila ketua raad van justitie memerintahkan melaksanakan kelanjutan pembayaran yang …"}, {"l": "RV", "p": "481F", "b": "Bagian 2A. Sita Eksekutorial Terhadap Pihak Ketiga Mengenai", "t": "Tagihan yang ditujukan kepada pihak ketiga, yang telah dikenakan sita tetapi lalai dalam melakukan kewajibannya, dicatat oleh residentierechter (kini: kepaniteraan Pengadilan Negeri). (RO. 116g; Rv. 924 dst.)"}, {"l": "RV", "p": "481G", "b": "Bagian 2A. Sita Eksekutorial Terhadap Pihak Ketiga Mengenai", "t": "Bila Dewan Perlindungan Anak-anak menjadi eksekutan sendiri, maka ia dapat melakukan sita itu dengan cara yang biasa, dapat juga dengan memberitahukan salinan putusan atau penetapan dari pengadilan kepada pihak ketiga. Dalam hal yang terakhir ini, pihak ketiga yang dikenakan sita ini harus mengirimkan kembali salinan pemberitahuan itu kepada Dewan Perlindungan Anak-anak, setelah menandatanganinya dan menyatakan \"telah saya ketahui\" di atasnya. Dengan pengiriman kembali ini, pelaksanaan sita telah selesai dikerjakan. Dewan Perlindungan Anak-anak dapat melakukan sita satu hari sebelumnya untuk melakukan pembayaran tagihan oleh pihak ketiga ini tanpa terlebih dahulu harus menandatangani surat perintah dari panitera atau memberikan keterangan, seperti yang dimaksud dalam pasal 88 dan 437( ). Diterimanya kembali salinan pemberitahuan, yang dikirimkan oleh eksekutan secara tercatat dalam tujuh hari setelah pengiriman pemberitahuan itu kepada pihak ketiga yang dikenakan sita untuk dinyatakan \"diketahui\" secara tertulis, berlaku sebagai penandatangan tersebut dalam pasal 471(2). (1) Bunyi pasal yang dimaksud adalah sebagai berikut ; r g . o 437. Putusan pengadilan, yang tidak berisikan …"}, {"l": "RV", "p": "482", "b": "Bagian 3. Pembagian Hasil Eksekusi.", "t": "(s.d.u. dg. S. 1908-522.) Bila tidak ada kreditur yang mengajukan perlawanan, maka kantor lelang sesuai dengan peraturan perundang- undangan yang ada atau yang akan diadakan membayarkan jumlah uang kepada yang memohon sita sebesar yang menjadi haknya menurut keputusan pengadilan dari hasil pelelangan itu, dikurangi dengan jumlah biaya eksekusi. Jikalau ada sisa, maka sisa itu dipertanggungiawabkan kepada orang 0 0 yang barangnya dilelang. (KUHPerd. 1139-l , 1149-1 ; Rv. 449, 455, 473, 481, 558, 576, 702, 744 dst., 747.)"}, {"l": "RV", "p": "483", "b": "Bagian 3. Pembagian Hasil Eksekusi.", "t": "Jika dalam waktu delapan hari terhitung dari hari penjualan pihak yang memohon sita, pihak yang barang-barangnya disita dan pihak- pihak lawan tidak dapat bersepakat tentang pembagian hasil penualannya, maka pihak yang barang-barangnya disita, pihak yang memohon sita atau pihak lawan yang paling siap, dapat memohon kepada ketua raad van justitie di wilayah penjualan, agar diangkat seorang hakim-komisaris yang akan menyaksikan pembagian hasil penjualan tersebut. Permohonan ini dicatat dalam daftar/register yang ada di kepaniteraan. (Rv. 461 dst., 481, 484, 547 dst., 576, 746 dst.)"}, {"l": "RV", "p": "484", "b": "Bagian 3. Pembagian Hasil Eksekusi.", "t": "Dalam tiga puluh hari terhitung dari hari pengangkatan hakim- komisaris, oleh orang yang memohon eksekusi, orang yang barang- barangnya dieksekusi atau lawan yang paling siap, diberitahukan kepada orang-orang yang disebut dalam pasal yang lalu, maka para kreditur wajib menyerahkan kepada hakim komisaris alas hak mereka, dengan ancaman jika tidak melakukannya, mereka tidak akan diikutkan dalam pembagian hasil lelangnya. Mereka wajib mengganti tempat tinggalnya yang dahulu dengan tempat tinggal pengacara yang dipilihnya dan menyuruhnya mengajukan gugatan tertulis yang ditandatanganinya agar diberikan urutan sebagai kreditur yang didahulukan atau yang sejajar. (KUHPerd. 1139, 1149; Rv. 106, 461 dst., 485, 549 dst., 556, 576.) Tentang pengajuan permohonan itu, jika ada, dicatat dalam berita acara hakim - komisaris."}, {"l": "RV", "p": "485", "b": "Bagian 3. Pembagian Hasil Eksekusi.", "t": "Setelah lewat tiga puluh hari seperti ditentukan dalam pasal yang lalu, maka hakim-komisaris berdasarkan surat yang disampaikan r g 480, 551, 576.) s . o kepadanya membuat daftar pembagian. (KUHPerd. 1139-l', 1140-11; Rv."}, {"l": "RV", "p": "486", "b": "Bagian 3. Pembagian Hasil Eksekusi.", "t": "l i t a a (s.d.u. dg. S. 1908-522.) Daftar pembagian diletakkan di l. eg kepaniteraan oleh hakim-komisaris dan tentang peletakan itu dalam delapan hari oleh yang membuat urutan diberitahukan kepada pihak w seperti tersebut dalam pasal 483 dengan perantaraan juru sita, dengan disebutkan mengenai hari dan jam semua pihak dapat w menghubungi hakim-komisaris untuk mengajukan keberatan-keberatan. (Rv. 483, 487, 551 dst., 576.)w"}, {"l": "RV", "p": "487", "b": "Bagian 3. Pembagian Hasil Eksekusi.", "t": "(s.d. u. dg. S. 1908-522.) Jika dalam waktu empat belas hari setelah pemberitahuan seperti tersebut dalam pasal yang lalu tidak ada yang mengajukan keberatan, maka hakim-komisaris akan menutup berita acaranya dan dengan satu surat perintah memerintahkan kantor lelang untuk membayarkan kepada mereka yang berhak menurut peraturan perundang-undangan yang ada atau yang akan diadakan, jumlah yang telah ditentukan dalam daftar tersebut. Surat-surat perintah itu dikeluarkan dalam bentuk seperti ditentukan dalam pasal 435(1) Keberatan dicatat dalam berita acara hakim komisaris. (RV.482, 484, 0 0 486, 488, 491, 553, 576, 580 – 3 dan 4 ) ( )Bunyi dalam pasal dimaksud adalah sebagai berikut : Grosse putusan pengadilan di Indonesia, dapat dilaksanakan dimana saja (ISR. 1, 159, RV 6 –7, 291, 491, 614; RBg. 321 – 2, 7; Ov. 89) Pada kepala surat putusan itu harus dimuat perkataan : “Demi keadilan berdasarkan Ketuhanan Yang Maha Esa” (ISR 130; R. 27; Rv 440) Putusan pengadilan harus ditandatangani oleh orang yang berkepentingan itu sendiri, atau hal itu dilakukan di tempat kediamannya dengan cara seperti yang disebutkan dalam pasal 3 dan 6 (Rv. 6 – 7 dan 8, 66 dst., 106, 440, 487, 553, 639, 853, …"}, {"l": "RV", "p": "488", "b": "Bagian 3. Pembagian Hasil Eksekusi.", "t": "(s. d. u. dg. S. 1908-522.) Dalam hal ada keberatan, maka hakim- komisaris akan meminta mereka yang berkeberatan untuk datang ke hadapan sidang pengadilan yang ia tentukan tanpa dilakukan pemanggilan. (Rv. 442, 489, 554, 576.)"}, {"l": "RV", "p": "489", "b": "Bagian 3. Pembagian Hasil Eksekusi.", "t": "(s.d.u. dg. S. 1908-522.) Banding dapat diajukan seketika dan harus disampaikari dalam empat belas hari sesudah diucapkan putusan. (RBg. 322-13 .) Permohonan banding harus diberitahukan kepada pengacara pihak lawan dan harus memuat tuntutan, disertai penjelasan mengenai alasan keberatan pihak pembanding. Dalam banding ini hanya diadakan tuntutan terhadap mereka yang ada pada waktu pengajuan keberatan. Pemberitahuan keberatan juga dilakukan kepada panitera pengadilan yang menjatuhkan putusan. (Rv. 106, 334, 338 dst., 402, 487 dst., 554, 576.)"}, {"l": "RV", "p": "490", "b": "Bagian 3. Pembagian Hasil Eksekusi.", "t": "(s. d. u. dg. S. 1908-522.) Putusan banding atas perrnohonan pihak r yang paling siap diberitahukan kepada panitera yang selanjutnya akang 554, 576.) s . o inemberikan putusan itu kepada hakim-komisaris. (Rv. 342, 488 dst.,"}, {"l": "RV", "p": "491", "b": "Bagian 3. Pembagian Hasil Eksekusi.", "t": "l i t a a Setelah pemberitahuan itu, hakim-komisaris, jika tidak ada l. eg permohonan kasasi, akan menutup berita acaranya dan akan mengeluarkan surat perintah pembayaran sesuai dengan pasal 487. (Rv. w 402 dst., 413, 437, 489, 555, 576.) w"}, {"l": "RV", "p": "492", "b": "Bagian 3. Pembagian Hasil Eksekusi.", "t": "w Setelah penutupan berita acara pembagian, maka masing-masing pihak yang berkepentingan tidak berhak lagi atas bungajumlah yang telah mereka terima. (KUHPerd. 1515; Rv. 555, 576.)"}, {"l": "RV", "p": "493", "b": "Bagian 1. Ketentuan-ketentuan Umum.", "t": "Kreditur karena suatu putusan pengadilan atau karena alas hak eksekutorial lin dapat menuntut penjlan paksa (onteigening) dengan suatu eksekusi. (KUHPerd. 1210; Rv. 435, 440 dst.; Cpt. 65 dst.; S. 1905-137 pas. 23; S. 1926-28 jo. 1929 pas. 9.) 10 arang-barang tetap yang dalam perdagangan, dengan segala kelengkapannya, sepanjg yang tersebut terakhir itu dianggap 0 0 sebigai barang tetap; (KUHPerd. 506 dst., 1164-l Rv. 451-l 509.) 2 hak pakai hasil barang-barang serta kelengkapannya; (KUHPerd. 0 0 508-1 ; 756 dst., 1164-2 .) 30. hak numpang karang (opstal) dan erfpacht; (KUHPerd. 508-31, 41, 711dst., 720 dst., 1164-3 .) 40. hak atas tanah, baik dalam bentuk uang maupun dalam bentuk hasil bumi yang harus dibayar. (KUHPerd. 508-50, 737 dst.; Rv. 541 dst.) 50. hak atas sepersepuluh hasil; (KUHPerd. 508-60, 740 dst., 1164- 50.) 6 . bazar-bazar atau pasar-pasar yang diakui pemerintah serta kemudahan-kemudahan yang terkait dengannya. (KUHPerd. 508-70. 1164-60; Rv. 494.)"}, {"l": "RV", "p": "494", "b": "Bagian 1. Ketentuan-ketentuan Umum.", "t": "Karena utang pribadi, bagian sesama ahli wares dari warisan yang berupa barang-barang tetap, tidak boleh dbual sebelum harta warisan itu dibagi yang, jika dipandang perlu, dapat dituntut pembagiannya. (KUHPerd. 128, 1066 dst., 1083, 1111, 1131, 1166; Rv. 578.)"}, {"l": "RV", "p": "495", "b": "Bagian 1. Ketentuan-ketentuan Umum.", "t": "Jika suatu barang yang dibebani hipotek pindah ke tangan pihak ketiga, maka pernegang hipotek dapat mengeksekusi barang tersebut terhadap pihak ketiga itu dengan kewajiban memberikan perintah kepada debitur menurut ketentuan pasal 1198 dan 1199 KUHPerd. (Rv. 504.) r g"}, {"l": "RV", "p": "496", "b": "Bagian 1. Ketentuan-ketentuan Umum.", "t": "s . o Kreditur tidak dapat melanjutkan penjualan barang-barang tetap yang l i a tidak dibebani hipotek, kecuali jika barang-barang yang dihipotekkan t kepadanya tidak mencukupi dan kecuali apa yang ditentukan dalam pasal 499. (KUHPerd. 1220; Rv. 499.) - a"}, {"l": "RV", "p": "497", "b": "Bagian 1. Ketentuan-ketentuan Umum.", "t": "l. eg w w Penjualan dilakukan dengan perantaraan kantor lelang yang wilayahnya meliputi letak barang tersebut. (Rv. 350, 505, 521.) Pasal 498. w Penjualan barang-barang yang terletak dalam wilayah beberapa kantor lelang, tidak dapat dilakukan selain dengan cara dari barang satu pindah ke barang yang lain, kecuali yang ditentukan dalam pasal berikut. (Rv. 99, 497.)"}, {"l": "RV", "p": "499", "b": "Bagian 1. Ketentuan-ketentuan Umum.", "t": "Jika barang-barang yang dihipotekkan kepada kreditur, dan barang- barang yang tidak dihipotekkan atau barang-barang yang terletak di dalam wilayah wewenang beberapa kantor lelang merupakan bagian- bagian dari penggarapan yang sama, maka penjualan dilakukan bersama- sama jika debitur tidak menentangnya. Penjualan dilakukan dengan perantaraan kantor telang yang lingkungannya meliputi ibu kota tempat penggarapan utama, atau jika tidak ada, di bagian-bagian penggarapan, di mana dipungut pajak yang tertinggi dan diperhitungkan harga barang-barang yang dihipotekkan menurut ketentuan pasal 1220 KUHPerd. (Rv. 496 dst., 525.)"}, {"l": "RV", "p": "500", "b": "Bagian 1. Ketentuan-ketentuan Umum.", "t": "Jika debitur dengan surat-surat bukti otentik atau dengan bukti- bukti yang sah lain menunjukkan bahwa hasil bersih dan murni barang- barang tetap selama satu tahun cukup untuk membayar utang pokoknya beserta biaya dan bunganya dan ia menawarkan penyerahan hal itu kepada kreditur dengan mernberi kuasa, maka penuntutan di hadapan raad van justitie dapat ditunda, dengan dimungkinkan melanjutkannya jika terjadi keterlambatan atau halangan dalam pembayarannya. Raad van Justitie tidak akan memberikan penundaan jika karenanya akan timbul kerugian besar bagi kreditur. (KUHPerd. 502, 613, 1471 0 0 dst., 1548 dst.; Rv. 751 dst.; RBg. 321-1 , 322-20 .)"}, {"l": "RV", "p": "501", "b": "Bagian 1. Ketentuan-ketentuan Umum.", "t": "Penjualan paksa barang-barang tetap hanya dapat dilakukan untuk utang atau tagihan tertentu yang telah diperiksa oleh instansi yang berwajib. Jika utang atau tagihan mengenai jumlah yang belurn ditentukan besarnya, maka tuntutan pengadilannya sah adanya, tetapi penualan baru dapat dilakukan setelah diadakan perhitungan. (KUHPerd. 1176, 1263, 1265; Rv. 443, 445, 503.)"}, {"l": "RV", "p": "502", "b": "Bagian 1. Ketentuan-ketentuan Umum.", "t": "Barangsiapa menadi pemilik suatu alas hak atau bukti utang yang sudah mempunyai kekuatan eksekusi, tidak dapat melakukan jual paksa barang-barang sebelum memberitahukan hal itu kepada debitur. (KUHPerd. 613; Rv. 504, 579.)"}, {"l": "RV", "p": "503", "b": "Bagian 1. Ketentuan-ketentuan Umum.", "t": "r Penuntutan di pengadilan tidak dapat dibatalkan atas dasar kreditur g atasnya ia berhak. (Rv. 106, 501, 579.) s . o memulai dengan tuntutan jumlah yang lebih besar daripada jumlah yang l i t"}, {"l": "RV", "p": "504", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "(s. d. u. dg. S. 1908-522.) Penyitaan barang-barang tetap harus perantaraan juru sita. w w didahului dengan perintah membayar yang disampaikan dengan w Harus disebutkan alas hak yang menjadi dasar tuntutannya dan juga memuat pilihan tempat tinggal di salah satu pengaeara pada raad van justitie yang mempunyai wilayah hukum tempat penjualan akan dilakukan; juga disebutkan bahwa jika pembayaran tidak dilakukan akan dilakukan penyitaan atas barang-barang tetap milik debitur. (KUHPerd. 24; Rv. 6, 92, 435, 443 dst., 497, 530, 559, 593.) (s.d.t. dg. S. 1908-522.) Jika pemberitahuan putusan atau alas hak sudah memuat perintah yang diperlukan, maka tidak dikeluarkan perintah tersendiri."}, {"l": "RV", "p": "505", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "(s.d. u. dg, S. 1908-522.) Tidak boleh dilakukan penyitaan barang- barang tetap sebelum lewat dua hari setelah disampaikan surat perintah; jika kreditur membiarkan surat perintah itu lewat selama satu tahun, maka ia harus mengulangi perintah itu. (Rv. 15, 92, 273, 530.)"}, {"l": "RV", "p": "506", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "Setelah tenggang waktu yang ditentukan lewat, maka penyitaan akan dilakukan dengan berita acara juru sita yang memuat: 1 . pernyataan, bahwa juru sita telah datang di tempat adanya barang, menyebutkan nama depan, nama serta tempat tinggal orang yang memohon sita dan orang yang barangnya disita; (Rv. 560; KUHP 429.) 2 . penyebutan alas hak yang menjadi dasar tuntutan; (Rv. 443.) 30. sifat barang-barang tetap yang disita, letaknya menurut pembagian pendaftaran tanah, jika itu ada dan jika mengenai tanah negara, luasnya, semuanya dengan sejelas mungkin; (Rv. 517-2 .) 40. penunjukan kantor lelang yang akan melakukari pelelangan dan penyebutan tempat tinggal menurut pasal 504. (Rv. 6, 92, 497 dst., 521, 530, 561.)"}, {"l": "RV", "p": "507", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "Turunan berita acara penyitaan diberikan kepada orang yang barangnya disita. (Rv. 3, 457.) Hal itu diumumkan di kantor penyimpanan hipotek yang wilayahnya meliputi letak barang-barang yang disita, dengan menyebut jam, hari, bulan dan tahun pengumuman itu dimintakan. (Ov. 50; Rv. 515.) Pejabat yang diserahi tugas penyimpanan hipotek harus mencatat semenjak menerimanya: jam, hari, bulan, dan tahun pada hipotek aslinya. (Ov. 50.) (s.d. u. dg. S. 1908-522.) Terhitung dari sejak hari pengumuman, maka orang yang barangnya disita tidak boleh memindahtangankan, membebani dengan hipotek atau menyewakan barang-barang yang disita; perjanjian-perjanjian yang dilakukan bertentangan dengan larangan r g itu tidak dapat digunakan untuk menentang pihak yang memohon sita. . o Perjanjian-perjanjian sewa yang dilakukan sebelum hari itu akan s tetap berlaku asal tidak dibuat untuk mengurangi hak kreditur. (KUHPerd. 1185, 1341, 1880; Oogstv. 19.) l i t a (s.d.u. dg. S. 1906-348.) Pendaftaran barang tetap yang hak a l. eg miliknya telah diserahkan lebih dulu, atau pendaftaran hipotek yang telah dilakukan lebih dulu dari pengumuman berita acara penyitaan tidak dapat mengurangi hak pihak yang memohon …"}, {"l": "RV", "p": "508", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "w Selama dalam penyitaan, maka pihak yang barang-barangnya disita menjadi penyimpan barang-barang itu menurut hukum, menguasai barang- barang yang disita yang tidak merupakan barang-barang yang disewakan atau dipah, Hal itu tidak boleh menimbulkan turunnya harga barang-barang itu, dengan ancaman membayar ganti rugi dan bunga, bahkan denganjalan paksaan badan, jika sampai terjadi hal itu. Raad van justitie atas permohonan seorang atau beberapa kreditur dapat mengangkat penyimpan lain yang tugasnya akan berakhiir pada hari akta penjualan dan penunjukan diumumkan. (Ov. 52; KUHPerd. 1239 dst., 1243, 1739; Rv. 0 0 0 454 dst., 580-10 ; RBg. 321-1 , 322-20 .)"}, {"l": "RV", "p": "509", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "(S. d. u. dg. S. 1908-522.) Hasil tanah yang dikumpulkan setelah diumumkan penyitaan atau siap untuk dikumpulkan, dianggap sebagai barang tetap dan para kreditur dapat memerintahkan agar buah yang masih ada di pohon atau umbi-umbian serta tumbuh-tumbuhan dikumpulkan atau dijual; uang sewa atau uang pah (sewa tahunan) dengan sendirinya termasuk barang-barang yang disita dan setelah diberitahukan dengan perantaraan juru sita kepada penyewa atau pemegang pah dibayarkan kepada kreditur agar bersama-sama dengan hasil penjualan barang tetapnya dibagi menurut urutan tagihannya. (KUHPerd. 500, 502, 506-3 , 588 dst., 753; Rv. 477 dst., 507.)"}, {"l": "RV", "p": "510", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "(s.d.u. dg. S. 1908-522.) Jika ada perjanjian seperti tersebut dalam pasal 1178 KUHPerd., maka pemohon eksekusi dalam waktu sepuluh hari setelah pengumuman seperti tersebut dalam pasal 507 memberitahukan tentang penyitaan itu kepada kreditur yang mengadakan perjanjian itu dan kepada pemegang register hipotek di tempat tinggal pilihan. (Ov. 50, 53; KUHPerd. 1186-10; Rv. 15, 506-40, 511, 513 dst.)"}, {"l": "RV", "p": "511", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "Jika berdasarkan apa yang diatur dalam pasal 1178 karena debitur tidak melaksanakan kewajiban yang dijanjikan, ia berhak untuk menjual tanah yang merdadi obyek perjanjian, dan bila ia hendak menggunakan haknya itu, maka penualan dilakukan dengan cara seperti ditentukan dalam pasal KUHPerd. diatas Namun ia berkewajiban untuk, di samping mengikuti formalitas- formalitas tersebut dalam pasal ini, memberitahukan hari penjualan sedikitnya tiga puluh hari sebelumnya lewat juru sita kepada pemohon eksekusi, kecuali jika sudah dimulai dengan penjualan sebelum dilakukan penyitaan. (KUH Perd. 24, 1211; Rv. 506 - 40 , 513 dst, 530) r g"}, {"l": "RV", "p": "512", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "s . o Ia selanjutnya berkewajiban untuk menyerahkan hasil penjualannya l i t a kepada kepaniteraan pengadilan yang menangani penyitaan setelah dikurangi dengan jumlah yang menjadi haknya menurut tuntutannya a beserta biaya dan bunganya dan memberitahukan hal itu kepada pemohon l. eg eksekusi di tempat tinggal pilihannya. (KUHPerd. 1149-l0, 1209; Rv. 506-40, 514, 547.) w w (s.d.t. dg. S. 1924-329jo. 391.) Pengurangan tidak dilakukan jika kreditur, yang mempunyai hak didahulukan atas tanah tersebut dari w hipotek, sebelum penjualan dengan perantaraan juru sita memberitahukan lebih dulu kepada pemegang register di tempat tinggal pilihan, agar seluruh hasil penjualan disampaikan ke kepaniteraan pengadilan yang bersangkutan. (F. 58.)"}, {"l": "RV", "p": "513", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "Bila kreditur berwenang dan berhasrat untuk rnenggunakan hak yang ada padanya itu, maka ia berkewajiban dalam waktu tiga puluh hari sesudah pemberitahuan penyitaan untuk memberitahukan hal itu kepada pengacara pemohon eksekusi, disertai keterangan jangka waktu ia akan pengadakan penjualan; tanpa pemberitahuan itu eksekusi dapat dilanjutkan. (KUHPerd. 1198, 1211; Rv. 510 dst., 515 dst.)"}, {"l": "RV", "p": "514", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "Jika tenggang waktu yang ditentukan dianggap terlalu lama atau jika kreditur lalai untuk mengadakan penjualan dalam waktu yang telah ditentukan, maka pemohon eksekusi dapat menuntutnya di hadapan hakim agar ditentukan waktu yang diwajibkannya untuk mengadakan penjualan, dan jika lalai dalam tenggang waktu itu, ia akan kehilangan haknya dan pemohon eksekusi dapat melaksanakan eksekusinya. (Rv. 283, 508 dst., 513.)"}, {"l": "RV", "p": "515", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "Jika ada beberapa kreditur yang meminta penjualan barang-barang yang sama, maka izin untuk itu atas tuntutan kreditur yang pertarna-tanta mengurnumkan berita acara penyitaan menurut pasal 507 dan pemohon- pemohon sita yang lainnya wajib nienghentikan tuntutannya. (Ov. 50.) Raad van justitie dengan jalan subrogasi dapat mendahulukan kreditur yang melakukan penyitaan belakangan: (KUHPerd. 1400 dst.) 10. jika telah terjadi tipu-muslihat yang dilakukan oleh kreditur yang telah melakukan penyitaan pertarna-- tama atau ada persekongkolan dengan pihak yang barangnya disita; dalam hal itu maka kreditur karena tipu-muslihat atau persekongkolan itu dihukum untuk membayar ganti rugi. (KUHPerd. 1328.) 20. jika pemohon sita pertama mengabaikan formalitas atau membiarkan tenggang waktu lewat tanpa melakukan penuntutan. (KUHPerd. 1365; Rv. 530 dst.) (s. d. u. dg. S. 1908-522.) Perselisihan yang timbul harus diajukan dengan akta dari pengacara terhadap pengacara. Banding terhadap putusan mengenai hal itu tidak akan diterima setelah lewat detapan hari terhitung sejak putusan diucapkan. (Rv. 334, 402; RBg. 322-130.) Barangsiapa yang tempatnya digantikan dalam putusan, wajib menyerahkan surat-surat …"}, {"l": "RV", "p": "516", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "s . o (s.d.u. dg. S. 1908-522.) Dalam waktu sedikitnya dua puluh hari dan i t a selambat-lambatnya enam puluh hari setelah pengumuman berita l penyitaan, akan dimulai pemberitahuan bahwa penjualan akan dilakukan a l. eg dengan cara yang lazim dilakukan mengenai barang-barang sitaan. (AB. 15.) Pemberitahuan dilakukan dengan memuatnya di dalam suatu surat kabar w w berbahasa Belanda dan berbahasa Melayu (Indonesia), keduanya di tempat penjualan akan dilakukan dan jika satu atau kedua surat kabar w semacam itu tidak ada di situ, di satu tempat terdekat, begitu pula dengan penempelan surat-surat, kesemuanya dengan cara seperti tersebut dalam dua pasal berikut. (Ov. 50; Rv. 84, 507 dst., 521, 527, 530, 533, 564, ;IR. 2007 8 9 , 206; RBg. 217, 2244)"}, {"l": "RV", "p": "517", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "(s. d. u. dg. S. 1908-522.) Pemberitahuan dalam surat kabar berbahasa Belanda dilakukan empat kali. Antara pemberitahuan pertama dan kedua harus lewat sedikitnya tiga puluh hari. Pemberitahuan ketiga dan keempat dalam surat kabar berbahasa Belanda, begitu pula pemuatan dalam surat kabar berbahasa Melayu (Indonesia) dilakukan dalam lima belas hari sebelum dilakukan penjualan. Pemberitahuan berisi: 1 . tempat, hari dan jam penualan akan dilakukan; 20. sifat barang-barang yang akan dijual, letaknya menurut surat pendaftaran tanah, kalau ada, nomor verponding, jika ada, mengenai tanah negara; (Rv. 506-3 .) 30. penyebutan nama depan, nama dan tempat tinggal pemohon eksekusi dan pengacaranya dan orang yang barang-barangnya disita. (KUHPerd. i7, 24; Rv. 504, 523, 536.)"}, {"l": "RV", "p": "518", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "(s. d. u. dg. S. 1908-522.) Penempelan surat-surat pengumuman dilakukan dalam waktu delapan hari setelah dimuat dalam surat kabar yang berbahasa Belanda dan di tempat yang biasa digunakan dalam kantor lelang dan pada bangunan atau dekat bangunan yang disita dan bila mungkin di tempat yang mudah dilihat dari jalan umum. (Rv. 84, 86, 497, 564.) Tentang penempelan surat-surat itu dibuatkan berita acara olehjuru sita dan dilampiri surat penetapan pajak atau turunannya. Dalam berita acara tersebut diterangkan olehjuru sita bahwa penempelan telah dilakukan dengan cara seperti toirsebut di atas. (Rv. 530.) Surat penetapan pajak kecuali memuat apa yang ditentukan dalam pasal yang lalu, juga memuat: 1 . anggaran mengenai pendapatan menurut pajak bumi; jumlah sewa, sewa tahunan atau penghasilan-penghasilan lain, jika dapat diketahui; 20. beban yang mungkin ada atas barang tersebut pada waktu dilakukan penyitaan; 3 . batas tawaran terendah yang diberikan oleh pemohon eksekusi dan apa yang menjadi ganti tawaran pertama itu. (Rv. 523.)"}, {"l": "RV", "p": "519", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "r g . o Pemohon eksekusi meminta dari pejabat penyimpan surat-surat hipotek s turunan semua surat-surat pendaftaran barang-barang yang disita pada i t a waktu pengumuman penyitaan dan ia meletakkannya di kantor lelang agar dapat dilihat umum. (Ov. 50.) l a l. eg (s.d.u. dg. S. 1908-522) Sehelai surat pajak atau turunannya akan diberitahukan/diserahkan kepada orang yang barang-barangnya disita dan kepada semua kreditur yang didaftar di tempat tinggal 566; S. 1932-112.) w w pilihannya. (KUHPerd. 1186-10, 1224; Rv. 507, 516 dst., 530, 540, w Jika dipandang perlu untuk menentukan syarat-syarat khusus yang tidak termuat dalam instruksi kantor-kantor lelang, maka syarat- syarat itu ditetapkan oleh pemohon eksekusi dan pada hari surat- surat pengumuman ditempelkan, diletakkan di kantor lelang untuk dapat dibaca. Syarat-syarat lelang setidak-tidaknya tidak boleh bertentangan dengan instruksi-instruksi tersebut di atas. (Rv. 467, 521; S. 1908- 190.)"}, {"l": "RV", "p": "520", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "Segala perselisihan mengenai syarat-syarat pelelangan harus diajukan kepada ketua raad van justitie dalam waktu empat belas hari setelah peletakan di kantor lelang, agar diputus dalam sidang singkat. (Rv. 283 dst., 442; RBg. 321-10, 322-120, dan 200.)"}, {"l": "RV", "p": "521", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "(s.d.u. dg. S. 1908-522.) Sedikitnya tiga puluh hari sesudah pemberitahuan kedua dalam surat kabar berbahasa Belanda oleh kantor lelang, dilakukan pelelangan barang-barang sitaan itu. (Rv. 516, 526, 530.) Sedikitnya tiga hari sebelum pelelangan, maka oleh ketua raad van justitie dirancang biaya seperti tersebut dalam pasal 524 dan rancangan itu diletakkan di kantor lelang untuk dapat dibaca. (RBg. 321-11, 322-201.) Sebelum diadakan pelelangan dibacakan syarat-syarat lelang. (Rv. 519.)"}, {"l": "RV", "p": "522", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "Pemilik barang-barang yang dilelang tidak boleh ikut membeli, kenaikan penawaran atau penurunan yang dilakukan olehnya tidak berlaku. Barangsiapa menjadi pembeli karena menawar secara pribadi dan langsung, bertanggung jawab atas kerugian dan bunga yang harus dibayamya dan dapat dipaksakan kepadanya, bahkan dengan jalan paksaan badan. Barangsiapa menjadi pembeli sesuatu atas beban rekening dari orang- orang yang nyata-nyata berada dalam keadaan tidak mampu membayar, bertanggung jawab dan menanggung kerugian - bahkan dapat dikenakan paksaan badan untuk diri sendiri dan untuk mereka tentang pembayaran uangnya, walaupun terdapat keterangan bahwa perbuatan itu dilakukan karena pengajuan atau penawaran dari mereka. (KUHPerd. 396, 399, 1199, 1204, 1293, 1460, 1799; Rv.496, 527, 580-10 .)"}, {"l": "RV", "p": "523", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "Pemohon eksekusi menjadi pembeli bila dengan batas harga terendah tidak ada penawaran yang lebih tinggi. (Rv. 517-60.)"}, {"l": "RV", "p": "524", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "r g . Biaya eksekusi dan lelang didahulukan pembayarannya dari hasil s pelelangan. (KUHPerd. 1139-10; Rv. 482, 521, 525 dst., 553.) o Pasal 525. l i t a a l. eg (s.d.u. dg. S. 1908-522.) Jika urutan penjualan dan penunjukan barang-barang tetap dalam satu penyitaan sudah mencukupi untuk membayar pemohon eksekusi dan kreditur-kreditur lainnya beserta w w biayanya, maka penjualan barang-barang selebihnya dihentikan, kecuali jika debitur menghendaki agar penjualan dilanjutkan. (Rv. 411, 473, 521, 524.) w"}, {"l": "RV", "p": "526", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "Hak milik barang yang dilelang berpindah ke tangan pembeli berdasarkan pengumuman kutipan daftar pelelangan yang tidak dapat dibuktikan selain dengan menunjukkan dengan bukti tertulis yang dikeluarkan oleh kantor lelang, yang menyatakan bahwa telah dipenuhi semua syarat-syarat pelelangan. (Ov. 52.) (s.d.u. dg. S. 1908-522.) Orang yang barang-barangnya dieksekusi dapat dipaksa untuk mengosongkan bangunan dengan cara seperti disebut dalam pasal 1033(1). (KUHPerd. 616, 1459, 1514; Rv. 507, 10 11 527, 532, 579; IR. 200 , ; RB9. 218.) (1) Bunyi pasal yang dimaksud adalah sbb:"}, {"l": "RV", "p": "1033", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "(s.d.u. dg. S. 1901-168.) Bila putusan untuk pengosongan barang tidak bergerak harus dan debitur, setelah diberi peringatan seperti yang dimaksud dalam pasal 999, tidak memenuhi putusan tersebut dalam jangka waktu yang telah ditetapkan itu, maka residentierechter mengeluarkan perintah tertulis kepada pegawai yang berwenang untuk menjalankan eksplot, dibantu dengan cara seperti yang disebutkan dalam pasal 1000, jika perlu dengan menggunakan tangan besi dari yang berwenang untuk itu, untuk memindahkan debitur tempat itu dan mengosongkan rumah atau barang tidak bergerak lainnya."}, {"l": "RV", "p": "999", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "Pelaksanaan putusan dimulai dengan perintah dari residentierechter kepada si terhukum untuk diperingati sekali lagi agar memenuhi putusan pengadilan dalam waktu dua hari. Pihak yang dimenangkan, segera setelah jangka waktu tersebut habis, wajib memberitahukan atau menyuruh memberitahukan kepada residentierechter tentang sudah- atau belum- dipenuhinya putusan tersebut. (Rv. 936; IR. 196.)"}, {"l": "RV", "p": "1000", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "Bila dalam jangka waktu yang telah ditetapkan putusan pengadilan tidak dipenuhi dan hal itu berkaitan dengan barang-barang bergerak dari debitur, residentierechter mengeluarkan perintah tertulis untuk melakukan penyitaan atas barang-barang itu sampai seharga sejumlah uang yang dapat diperkirakan akan cukup untuk membayar utang debitur menurut putusan pengadilan dan biaya perkara. Pelaksanaan penyitaan ini dilakukan oleh pejabat yang berwenang menjalankan perintah (eksplot) dengan dibantu oleh panitera pengadilan atau oleh pejabat atau pegawai yang atas permintaan residentierechter ditunjuk oleh Kepala Pemerintahan Daerah setempat. Pada setiap pelaksanaan penyitaan dibuat berita acara yang ditandatangani oleh penyita (juru sita), pejabat atau pegawai dan oleh seseorang yang berdasarkan pasal 1002 ditugaskan untuk mengurus penyimpanan barang-barang sita tersebut. Dalam berita acara itu dinyatakan alasan-alasan penyitaan yang disebutkan dalam surat perintah yang bersangkutan dan pula rincian secara teliti tentang barang-barang yang disita. Isi berita acara ini r g diberitahukan kepada orang yang kena sita, bila ia hadir pada waktu itu. Bila ia menurut pasal 1002 juga ditugaskan untuk …"}, {"l": "RV", "p": "1002", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "w w Seseorang yang ditugaskan untuk melaksanakan penyitaan, setelah w memperhatikan pertimbangan-pertimbangan yang diajukan oleh pejabat atau pegawai yang mendampingi dan memberikan bantuannya dalam penyitaan ini, dapat menyerahkan seluruhnya atau sebagian dari barang barang yang disita itu kepada suami (istri) orang yang kena sita itu, keluarga sedarah atau semenda atau orang seisi rumah, bila mereka menghendakinya dan mendapatkan persetujuan untuk mengurus penyimpanan barang-barang tersebut, ataupan untuk memindahkan barang-barang itu ke tempat penyimpanan lain yang dianggap lebih baik, sesuai dengan kepentingannya. Penyimpanan uang kontan dan surat-surat berharga dipindahkan ke kantor Kepata Pemerintahan Daerah Setempat, kecuali bila telah tercapai persetujuan dengan pihak yang kena sita untuk disimpan di tempat lain. Dalam berita acara penyitaan harus dicantumkan pula hal-hal seperti yang disebutkan dalam alinea pertama dan kedua dari pasal ini. (s.d.u. dg. S. 1901-168.) Bila di antara surat-surat berharga tersebut terdapat bukti mengenai utang kepada pihak ketiga, yang tidak dapat dibayarkan alas tunjuk (aan toonder), residentierechter, bila dianggap perlu, membebaskan utang …"}, {"l": "RV", "p": "1007", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "Kreditur dari seorang debitur yang terhadap barang-barangnya telah diadakan penyitaan, sama sekali tidak diperbolehkan untuk mengajukan bantahan (oposisi) bahkan terhadap uang sewa sekalipun, kecuali hanya terhadap pemberian hasil penjualan dalam bentuk mata uang. Bantahan ini diajukan sehari sebelum diadakan penjualan, baik secara tertulis maupun secara lisan, kepada residentierechter yang wilayah kekuasaannya meliputi tempat penyitaan itu dilakukan, Residentierechter akan membuat bantahan lisan ini dalam bentuk tertulis. Bantahan ini, selain harus memuat tempat kediaman yang dipilih dan yang berada dalam wilayah kekuasaan residentierechter, juga memuat alasan-alasan yang digunakan, perkembangan jumlah uang yang dipersoalkan atau bila jumlah uang itu tidak dapat dipastikan atau diselesaikan secara baik, diajukan menurut jumlah taksiran dari pihak pembantah. Bantahan tertulis dapat dilakukan dengan akta khusus di bawah tangan atau dibuat di hadapan panitera pengadilan (residentiegerecht) atau orang yang diberikan kuasa dengan akta notaris yang hersifat umum ataupun khusus. (Rv. 461, 944, 1037.) Bantahan-bantahan tertulis yang tidak memenuhi persyaratan seperti tersebut dalam …"}, {"l": "RV", "p": "527", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "w Jika pembeli lalai memenuhi syarat-syarat pembelian, maka ketua raad van justitie atas permohonan mereka yang berkepentingan, dapat memerintahkan atas beban pembeli pelelangan ulang serta pembagian, dan dalam hal ini berlaku ketentuan-ketentuan dalam pasal 516 dan berikutnya. (Rv. 526, 528 dst.; 569; RBg. 321-10; 322-200.)"}, {"l": "RV", "p": "528", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "Dalam hal seseorang telah memenangkan penawaran, kemudian membuktikan telah memenuhi syarat-syarat dan menyerahkan jumlah uang untuk disimpan di pengadilan yang direncanakan hakim untuk membayar biaya pelelangan ulang, maka pelelangan ulang dan penunjukan tidak akan dilanjutkan. (Rv. 526.)"}, {"l": "RV", "p": "529", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "Pembeli yang lalai, dalam hal dilakukan paksaan badan bertanggung jawab atas perbedaan harga antara penawaran yang ia menangkan dahulu dengan hasil peletangan ulang barang yang bersangkutan, dan tidak dapat menuntut perbedaan lebih, yang mungkin ada karena hasil lelang ulang; kelebihan itu akan dibayarkan kepada kreditur-kreditur dan bila mereka sudh dibayar penuh, yang lebihnya lagi diberikan kepada pihak yang barangnya disita. (Rv. 527, 558, 580-11 .)"}, {"l": "RV", "p": "530", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "(s.d.u. dg. S. 1908-522.) Bila formalitas-forrnalitas untuk mengadakan penjualan seperti tersebut dalam pasal terdahulu tidak diperhatikan, maka orang yang barangnya disita atau para kreditur yang didaftar dapat menuntut agar syarat-syarat itu dipenuhi, tetapi tuntutan itu tidak akan diterima, jika tidak diajukan kepada raad van justitie dalam waktu dua puluh hari sebelum hari/tanggal yang telah ditentukan untuk mengadakan penjualan. (RBg. 321-10, 322-2010.) Banding terhadap putusan itu harus diajukan dalam waktu delapan hari setelah putusan diucapkan, terhadap sidang beiikutnya sesudah disarnpaikan pemanggilan, dengan mengindahkan tenggang waktu menurut undang-undang. (Rv. 92, 94, 96, 334, 402, 504 dst., 515, 531; RBg. 322-130.)"}, {"l": "RV", "p": "531", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "Jika dalam kejadian yang disebut dalam pasal yang lalu raad van justitie memerintahkan agar formalitas diperbaiki, maka semua formalitas berikutnya harus dipenuhi lagi dan biayanya dibebankan kepada orang yang menyebabkan kejadian itu. (Rv. 21, 96, 98; RBg. 0 0 321-1 , 322-20 .)"}, {"l": "RV", "p": "532", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "Pengumuman kutipan daftar lelang memberikan hak milik kepada pembeli tidak melebihi hak yang pernah dirniliki orang yang barangnya r g disita. (Ov. 52; KUHPerd. 1519, 1523; Rv. 526; IR. 2000.) s . o"}, {"l": "RV", "p": "533", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "l i t a a Para kreditur dari orang yang barangnya disita dapat mengajukan l. eg perlawanan terhadap pembayaran hasil pelelangan sampai pada saat penunjukan. (s.d.u. dg. S. 1925-497.) Perlawanan selain memuat syarat-syarat w w eksploit biasa juga memuat dasar hukumnya dan juga tempat tinggal pilihan di ibu kota afdeling, di mana terletak barangnya, bila lawan w tidak bertempat tinggal di situ juga. Hal itu diberitahukan kepada pihak lawan dan pengacaranya dan juga kepada kantor lelang. Semuanya dengan ancaman batal jika tidak dipenuhi. (Rv. 8, 92, 461, 506-40, 525, 547, 549, 558, 571, 573.)"}, {"l": "RV", "p": "534", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "Ketentuan-ketentuan dalam pasal 462(a) berlaku juga dalam hal ini. (a) Bunyi pasal yang dimaksud adalah sbb:"}, {"l": "RV", "p": "462", "b": "Bagian 2. Penyitaan Barang-barang Tetap. a", "t": "Pihak pembantah (oposan) tidak dapat memulai gugatannya selain kepada pihak yang barang-barangnya telah disita; kepada pihak penibantah tidak akan dilakukan prosedur perkara dalam sidang, selain untuk diadakan pemeriksaan tentang kedudukannya menurut hukum sebagai pembantah untuk mendapatkan bagiannya dari uang yang akan dibagikan. (Rv. 443, 484, 493, 534, 550 dst.)"}, {"l": "RV", "p": "535", "b": "Bagian 3. Penuntutan Hak Milik.", "t": "Sebelum dilakukan penjualan seluruh atau sebagian barang yang disita, mereka yang mau menuntutnya sebagai miliknya harus mengajukan perlawanan terhadap penjualan itu. (KUHPerd. 547, 1471; KUHD 230; Rv. 279 dst., 378, 460, 532, 571; IR. 208; RBg. 228.)"}, {"l": "RV", "p": "536", "b": "Bagian 3. Penuntutan Hak Milik.", "t": "Perlawanan dilakukan dengan surat pemberitahuan gugatan dengan perantaraan juru sita dan berisi: 1 . suatu penjelasan yang rinci tentang barang yang diminta kembali; (Rv. 101.) 20. upaya hukum dan kesimpulan; (Rv. 8-30.) 0 0 3 . hari dan jam para pihak harus menghadap hakim ; (Rv. 8-5 .) Surat panggilan ditujukan kepada pemohon eksekusi ditempat tinggal pilihannya menurut pasal 504 dan kepada orang yang barangnya disita atau ditempat tinggalnya; turunan surat tersebut disampaikan kepada kantor lelang (Rv.506-40, 517.) Alas hak dan bukti-bukti hak milik pelawan sebelumnya harus disarnpaikan di kepaniteraan yang dapat dilihat dan diambil turunannya oleh para pihak dan Hal itu disebut dalam surat panggilan. (Rv. 280.)"}, {"l": "RV", "p": "537", "b": "Bagian 3. Penuntutan Hak Milik.", "t": "Setiap kali terjadi penuntutan hak milik, maka penjualan barang yang dituntut ditangguhkan. (Rv. 540.)"}, {"l": "RV", "p": "538", "b": "Bagian 3. Penuntutan Hak Milik.", "t": "r g Jika penuntutan kembali itu hanya mengenai sebagian saja barang yang . o disita, raad van justitie dapat memerintahkan penjualan barang- s barang selebihnya atau seluruh penjualan ditangguhkan. (Rv. 540; 0 0 RBg. 321-1 , 322-20 ) l i t a a l. eg"}, {"l": "RV", "p": "539", "b": "Bagian 3. Penuntutan Hak Milik.", "t": "(s.d.u. dg. S. 1908-522.) Pada hari yang telah ditentukan raad van justitie menjatuhkan putusan tentang tuntutan hak milik itu dan w w terhadap putusan itu tidak dapat diajukan banding setelah lewat empat belas hari setelah putusan diucapkan. (Rv. 47, 334, 402, 435; RBg. 322-131.) w"}, {"l": "RV", "p": "540", "b": "Bagian 3. Penuntutan Hak Milik.", "t": "(s.d.u. dg. S. 1908-522.). Jika penjualan terhambat oleh adanya tuntutan kembali hak milik, maka penjualan tidak dapat dilanjutkan sebelum diperbaharui pemberitahuan dan penempelan bilyet-bilyet (bukti pajak) menurut pasal 516 dan berikutnya. Biaya harus ditanggung oleh pihak yang tuntutan kembali haknya ditolak. Di samping itu, jika ada dasar hukumnya, pemohon sita dapat dihukum untuk membayar ganti rugi, biaya serta bunga. (Ov. 105; KUHPerd. 1365 dst.; Rv. 58, 346, 460, 538 dst., 607.)"}, {"l": "RV", "p": "541", "b": "Bagian 4. Sita Eksekutorial Atas Bunga Tanah (Grondrente).", "t": "Kecuali dengan perubahan-perubahan sebagai berikut, maka pada eksekusi bunga tanah seperti tersebut dalam pasal 737 KUHPerd. harus diikuti formalitas seperti pada penyitaan dan penjualan barang tetap lain. (KUHPerd. 508-51; Rv. 463-41.)"}, {"l": "RV", "p": "542", "b": "Bagian 4. Sita Eksekutorial Atas Bunga Tanah (Grondrente).", "t": "Penyitaan atas bunga tanah dilakukan dengan pemberitahuan juru sita kepada debitur dan juga kepada si wajib bayar bunga. (Rv. 477 dst., 504, 507, 544.)"}, {"l": "RV", "p": "543", "b": "Bagian 4. Sita Eksekutorial Atas Bunga Tanah (Grondrente).", "t": "Si wajib bayar bunga dapat dipanggil oleh pemohon eksekusi untuk memberitahukan tentang sifat dan besamya bunga yang harus dibayar. Pemberitahuan keterangan itu akan dilakukan menurut ketentuan- ketentuan dan dengan akibat seperti tersebut dalam bagian 3 Bab IV Buku Ketiga. (Rv. 478, 734 dst.)"}, {"l": "RV", "p": "544", "b": "Bagian 4. Sita Eksekutorial Atas Bunga Tanah (Grondrente).", "t": "Dengan pemberitahuan tersebut di atas, maka bunga yang sudah diterbitkan dan yang akan diterbitkan ikut disita. (Rv. 542.)"}, {"l": "RV", "p": "545", "b": "Bagian 4. Sita Eksekutorial Atas Bunga Tanah (Grondrente).", "t": "Penjualan harus didahului dengan penempelan surat-surat pajak seperti tersebut dalam pasal 518 yang harus memuat: 10. nama depan dan nama mereka yang mengadakan penyitaan, orang yang barangnya disita dan si wajib bayar bunga; 20. penyebutan barang yang dikenakan bunga; 3 . jumlah bunganya; 40. pendaftaran hipotek, jika ada; 50. tawaran terendah yang ditentukan oleh pemohon eksekusi; g 60. tempat, hari dan jam penjualan akan dilakukan. (Rv. 497, 517.) r"}, {"l": "RV", "p": "546", "b": "Bagian 4. Sita Eksekutorial Atas Bunga Tanah (Grondrente).", "t": "s . o l i a (s. d. u. dg. S. 1908-522.) Jika bunga yang disita berjumlah lebih t dari seratus gulden per tahun, maka harus dilakukan pengumuman dalam a waktu delapan hari setelah dilakukan penempelen di salah satu surat l. eg kabar di tempat akan diadakan penjualan, dan jika tidak ada surat kabar di tempat itu, di surat kabar tempat yang terdekat. w w"}, {"l": "RV", "p": "547", "b": "Bagian 5. Pengaturan Hak Didahulukan Dan Pembagian Uang Hasil", "t": "w (s.d.u. dg. S. 1908--522.) Bila para kreditur dan pihak yang barangnya disita tidak dapat menyetujui pembagian uang hasil penjualan dan sisanya seperti dimaksud dalam pasal 512, maka oleh kreditur, pembeli dan pihak yang barangnya disita yang paling siap, mohon kepada raad van justitie agar diangkat seorang hakim-komisaris yang di hadapannya akan dilakukan pengaturan tentang hak untuk didahulukan. (KUHPerd. 1196, 1209-30, 1210, 1212; F. 175; Rv. 402, 482 dst., 521, 533, 549, 552, 558, 576.)"}, {"l": "RV", "p": "548", "b": "Bagian 5. Pengaturan Hak Didahulukan Dan Pembagian Uang Hasil", "t": "Raad van justitie mengangkat seorang hakim-komisaris dan iamemberikan perintah berdasarkan penetapan majelis. (Rv. 483, 549 dst., 576.)"}, {"l": "RV", "p": "549", "b": "Bagian 5. Pengaturan Hak Didahulukan Dan Pembagian Uang Hasil", "t": "(s.d.u. dg. S. 1906-348, S. 1908-522.) Barangsiapa menuntut pengaturan hak untuk didahulukan harus mengajukan ketetapan raad van justitie dengan surat perintah hakim-komisaris yang pada hari yang ditentukan akan membuka berita acara pengaturan itu dan melampirkan padanya kutipan semua pendaftaran yang dikeluarkan oleh pegawai penyimpan hipotek, begitu juga petikan dan daftar para kreditur yang mengajukan perlawanan. (Rv. 484, 507, 519, 533, 558, 576.)"}, {"l": "RV", "p": "550", "b": "Bagian 5. Pengaturan Hak Didahulukan Dan Pembagian Uang Hasil", "t": "(s.d. u. dg. S. 1908-522.) Berdasarkan surat perintah yang dibeiitahukan kepada kantor lelang, maka pemohon akan menyuruh memanggil para kreditur di tempat tinggal pilihannya agar dalam waktu satu bulan setelah pemanggilan itu menyerahkan surat-suratnya kepada hakim-komisaris dengan tuntutan agar dimasukkan dalam penentuan urutan. Sekaligus ia memilih tempat tinggal pada salah seorang pengacara; para kreditur yang dipanggil juga wajib melakukannya, jika dulu belum dilakukannya pada waktu melakukan tuntutan. Hakim-komisaris akan mencatat semua surat-surat itu dalam berita acaranya. (Ov. 53; KUHPerd. 1186-10; Rv. 15, 106, 484, 533 dst., 551, 576; S. 1932-112.)"}, {"l": "RV", "p": "551", "b": "Bagian 5. Pengaturan Hak Didahulukan Dan Pembagian Uang Hasil", "t": "Setelah pemohon menyatakan bahwa tenggang waktu seperti ditentukan dalam pasal yang lalu telah lampau, maka hakim-komisaris berdasarkan surat-surat yang telah ada padanya membuat daftar urutan dan dalam satu berita acara menentukan tempat, hari dan jam di mana para pihak harus datang menghadap. (KUHPerd. 1187; Rv. 485, 549, 556.)"}, {"l": "RV", "p": "552", "b": "Bagian 5. Pengaturan Hak Didahulukan Dan Pembagian Uang Hasil", "t": "r g s . o Pemohon akan memberitahukan kepada pihak yang barangnya dieksekusi dan para kreditur di tempat tinggal pilihan mereka, bahwa pengaturan l i t a unitannya telah tersusun dan mereka masing-masing dapat melihatnya di kepaniteraan, dengan peringatan, bahwa mereka harus menghadap a hakim-komisaris pada tempat, hari dan jam yang telah ditentukan l. eg agar, jika ada alasan, dapat menyatakan keberatan atas penempatan mereka dalam urutan yang ditempatkan oleh hakiiin-ko a dalam berita w acara yang dibuatnya. (Rv. 486, 550, 576.) w"}, {"l": "RV", "p": "553", "b": "Bagian 5. Pengaturan Hak Didahulukan Dan Pembagian Uang Hasil", "t": "w (s.d.u. dg. S. 1908-522.) Jika tidak ada keberatan yang diajukan, maka hakim-komisaris akan menutup pengaturan urutannya dan menentukan biaya yang harus dibayar lebih dahulu. Ia akan memerintahkan penyerahan perincian tentang penempatan mereka yang mempunyai tagihan lebih (sisa lebih) dan pencoretan-pencoretan dati daftar dan pemindahan penyitaan yang tidak mempunyai sisa lebih. Surat rincian-rincian itu beserta apa yang tersebut dalam pasal berikut dikeluarkan sesuai dengan ketentuan-ketentuan dalam pasal 435( ). (KUHPerd. 1213 dst.; Rv. 487, 524, 576.) (s.d.t. dg. S. 1908-522.) Biaya-biaya yang didahulukan adalah gaji dan uang muka pengacara yang telah melakukan kewajibannya pada waktu dilakukan penyitaan dan pada waktu pengaturan urutan untuk para pihak. Mengenai bunyi pasal 435, lihat catatan kaki pasal 487."}, {"l": "RV", "p": "554", "b": "Bagian 5. Pengaturan Hak Didahulukan Dan Pembagian Uang Hasil", "t": "Dalam hal ada keberatan-keberatan yang diajukan, maka hakim komisaris memerintahkan para yang mengajukan keberatan untuk tanpa dipanggil lagi menghadap pada sidang pengadilan yang ditetapkannya. Namun ia akan menentukan urutan tagihan-tagihan yang harus didahulukan di atas yang dibantah dan memerintahkan menyerahkan daftar rincian penempatan para kreditur. Perkara kemudian diputus berdasarkan laporan hakim-komisaris dan sesudah ada kesimpulan-kesimpulan, bila perlu sesudah diadakan pertukaran pembelaan-pembelaan. Keputusan tidak dapat dibanding jika hal itu tidak diajukan dalam waktu empat belas hari setelah putusan diucapkan. (F. 180, Rv. 334, 338, 342, 402, 576; RBg. 322-13 .) Alinea keempat dicabut dg. S. 1908-522."}, {"l": "RV", "p": "555", "b": "Bagian 5. Pengaturan Hak Didahulukan Dan Pembagian Uang Hasil", "t": "(s.d.u. dg. S. 1908-522.) Empat belas hari sesudah diputuskan mengenai keberatan-keberatan dan dalam hal ada banding atau kasasi, empat belas hari setelah putusan diberitahukan kepada panitera, maka hakim-komisaris akan menetapkan utang-utang yang dibantah dan yang mendapat giliran kemudian dan begitu selanjutnya seperti yang diatur dalam pasal 553. Keuntungan-keuntungan dan bunga para kreditur yang mendapat tempat dalam urutan yang mempunyai sisa lebih berhenti dalam perhitungan satu sama lain, kecuali tetap adanya hak mereka terhadap debitur. (Rv. 402, 438, 489 dst., 491 dst., 558, 576.)"}, {"l": "RV", "p": "556", "b": "Bagian 5. Pengaturan Hak Didahulukan Dan Pembagian Uang Hasil", "t": "Kreditur yang lewat tenggang waktu di atas, tetapi sebelum pengaturan urutan ditutup, masih menyampaikan surat-surat dan keberatan, masih dapat diterima dalam penyampaian surat-surat dan r g keberatan itu dengan membayar kerugian dan bunga yang timbul karena keterlambatan itu. (KUHPerd. 1243 dst.; Rv. 484, 576, 607.) s . o"}, {"l": "RV", "p": "557", "b": "Bagian 5. Pengaturan Hak Didahulukan Dan Pembagian Uang Hasil", "t": "l i t a Pegawai penyimpan hipotek berkewajiban tnelakukan pencoretan atas a penunjukan perintah hakim atau akta otentik yang berisi persetujuan l. eg kreditur. (KUHPerd. 1196, 1213; F. 183; Rv. 576.)"}, {"l": "RV", "p": "558", "b": "Bagian 5. Pengaturan Hak Didahulukan Dan Pembagian Uang Hasil", "t": "w w Setelah dibayar utang-utang hipotek dan biayanya, maka sisa uang w penjualan dibagi antara para kreditur yang telah mengadakan bantahan dan jika tidak ada kreditur semacam itu, diserahkan kepada debitur; semuanya sesuai dengan ketentuan-ketentuan dalam bagian 3 bab yang lain. (Rv. 482 dst., 533, 549 dst., 576, 702.)"}, {"l": "RV", "p": "559", "b": "BAB IV SITA EKSEKUTORIAL ATAS KAPAL DAN PENJUALAN KAPAL", "t": "(s.d.u. dg. S. 1933-48 jo. S. 1938-2.) Sita eksekutorial atas kapal, termasuk kapal yang sedang dibangun, tidak dapat dilakukan, kecuali atas dasar suatu keputusan hakim atau alas hak eksekutorial lainnya. (Rv. 435, 440, 443, 502, 579, 720 dst.) Hal itu harus didahului oleh suatu perintah, yang dua puluh empat jam sebelumnya diberitahukan kepada pemilik atau tempat tinggal pemilik atau agennya, atau pemegang bukunya, atau dengan cara yang diatur pada pasal 3 dan pasal 6. (KUHD 320 dst., 327, 329; Rv. 504, 563.) Namun bila ada kekhawatiran bahwa kapal itu akan segera berangkat ke tempat lain, maka kreditur setelah mendapat izin dari ketua raad van justitie yang di dalam daerah hukumnya kapal itu berlabuh, juga tanpa perintah lebih dahulu, dapat melakukan penyitaan. (KUHPerd. 510; KUHD 309; Rv. 560, 576 dst., 579, 593; RBg. 321-10, 322-200.)"}, {"l": "RV", "p": "560", "b": "BAB IV SITA EKSEKUTORIAL ATAS KAPAL DAN PENJUALAN KAPAL", "t": "Sita atas kapal harus dilakukan di atas kapal itu sendiii. (Rv. 456, 506-10.) Juru sita dalam pada itu didampingi dua saksi, yang nama-nama mereka, pekerjaan dan tempat tinggal dia sebutkan dalam berita acara. Mereka semua menandatangani surat yang asli dan salinan- (s.d.u. dg. S. 1908-522.) Hal itu diberitahukan kepada pemilik atau tempat tinggal pemilik atau agennya atau pemegang bukunya ataupun dengan cars yang diatur pada pasal 3, dengan menyerahkan suatu 563, 578; KUHD 320 dst., 327, 329.) Bila sita dilakukan untuk utang dengan hak didahulukan atas kapal, ataupun untuk utang, yang atasnya menurut peraturan-peraturan Buku Kedua Kitab Undang-undang Hukum Dagang, kapal itu bertanggungjawab, maka berita acara penyitaan di atas kapal dapat disampaikan kepada juragan kapal. (KUHD 314, 315d, 316, 318, 341d; Tbs. 24; Rv. 504.)"}, {"l": "RV", "p": "561", "b": "BAB IV SITA EKSEKUTORIAL ATAS KAPAL DAN PENJUALAN KAPAL", "t": "(s.d.u. dg. S. 1925-497.) Dalam berita acara penyitaan, jurusita menyatakan: - r g nama depan, nama, pekerjaan dan tempat tinggal kreditur (Rv. 8, - 506.) alas hak sebagai dasar dia mengeksekusi; (Rv. 559.) s . o - - l i t a jumlah-jumlah yang dia tuntut pembayarannya; (Rv. 503, 579.) pemilihan tempat tinggal oleh kreditur di ibu kota afdeling a tempat kapal itu berlabuh, dan pada seorang pengacara pada raad l. eg van justitie yang di dalam daerah hukumnya dituntut penjualannya; - w nama dari pemilik, dari agennya atau pemegang bukunya, bila w mereka diketahui, dan dari juragan kapal; (KUHD 320 dst., 327, - 329, 341.) w nama, macam dan sedapat mungkin ruang kapal; (KUHD 347, 506, 592-10.) - uraian secara umum tentang sekoci-sekoci, perahu-perahu, tali- temali, alat-alat perlengkapan, senjata-senjata, alat-alat perang dan kebutuhan hidup. Dia selanjutnya harus mengangkat seorang penyimpan di atas kapal, setelah mengambil langkah-langkah untuk menghalangi keberangkatan kapal itu. (KUHPerd. 1739; Rv. 454 dst., 508, 560, 563.) Perwira-perwira dan pegawai-pegawai yang dibebani tugas kepofisian pelabuhan-pelabuhan dan tempat-tempat berlabuh, bila diminta, memberikan bantuan untuk …"}, {"l": "RV", "p": "562", "b": "BAB IV SITA EKSEKUTORIAL ATAS KAPAL DAN PENJUALAN KAPAL", "t": "(s.d.u. dg. S. 1906-348; S. 1933-48jo. S. 1938-2.) Berita acara tentang penyitaan kapal atau saham-saham dalam kapal, yang ukurannya paling sedikit dua puluh meter kubik kotor, dibuat di muka umum dalam register yang diselenggarakan khusus untuk itu pada kepaniteraan raad van justitie dalam resort penyitaan itu dilakukan. (KUHPerd. 309, 310 dst., 314, 315b.) Bila kapal itu dibukukan dalam register yang ditentukan untuk itu, pencatatan sita itu dilakukan dalam register pokok, tempat kapal itu dibukukan, baik atas penunjukan dan penyerahan salinan otentik belita acara sita oleh yang berkepentingan, maupun berdasarkan permohonan dan atas beban yang berkepentingan yang oleh panitera yang dalam kepaniteraannya sita diumumkan, diberitahukan secara telegrafis, kepada penyimpan register pokok. (Tbs. 7 dst., 28.) Penyerahan atau pembebanan kapal atau saham kapal setelah pencatatan dalam register pokok tidak boleh mendatangkan kerugian kepada hak- hak pihak yang meletakkan sita. (Tbs. 21 dst., 24; Rv. 507.)"}, {"l": "RV", "p": "563", "b": "BAB IV SITA EKSEKUTORIAL ATAS KAPAL DAN PENJUALAN KAPAL", "t": "(s.d.u. dg. S. 1908-522.) Bila pemilik kapal, agennya atau pemegang bukunya bertempat tinggal dalam karesidenan yang di dalamnya dilakukan sita, maka arrestan (si penahan) dalam waktu delapan hari harus memberitahukan salinan berita acara penyitaan kepadanya. (KUHD 320 dst., 327, 329.) Alinea kedua hapus dg. S. 1908-522. (s.d.u. dg. S. 1908-522.) Bila dia tidak bertempat tinggal dalam karesidenan itu, jangka waktu pemberitahuan diperpanjang menurut ukuran yang ditetapkan pada pasal 10, dengan pengertian, bahwa bila terjadi hal termaksud dalam alinea terakhir pasal itu, pemberitahuan dilakukan dalam empat puluh hari. (RBg. 322-14-.) Bila dia bertempat tinggal di luar Indonesia, atau tidak dikenal, pemberitabuan dilakukan kepada juragan kapal atau wakilnya. (KUHD 341, 341d.) r g kapal. (Rv. 10 dst., 560.) s . o Dalam hal satu dan lain tidak ada, pemberitahuan ditempelkan pada"}, {"l": "RV", "p": "564", "b": "BAB IV SITA EKSEKUTORIAL ATAS KAPAL DAN PENJUALAN KAPAL", "t": "l i t a a (s.d.u. dg. S. 1908-522.) Dua pengumuman diadakan dari delapan l. eg sampai delapan hari dalam suatu surat kabar di tempat penjualan akan dilakukan, dan bila surat kabar demikian tidak ada, dalam surat kabar di tempat sekitamya. w Dalam waktu sepuluh hari setelah pengumuman-pengumuman yang pertama, w ditempelkan bilyet-bilyet pada tempat-tempat yang ditunjukkan pada w pasal 518, serta pada tiang kapal yang disita. (Rv. 468 dst., 516, 518, 565, 568; RBg. 322-150.)"}, {"l": "RV", "p": "565", "b": "BAB IV SITA EKSEKUTORIAL ATAS KAPAL DAN PENJUALAN KAPAL", "t": "Pengumuman-pengumuman dan bilyet-bilyet itu berisi: nama depan, nama, pekerjaan dan tempat tinggal orang yang mengeksekusi; alas hak yang menjadi dasar dia melakukan penuntutan; keseluruhan jumlah terutang kepadanya; pemilihan tempat tinggal yang dilakukan di tempat sidang raad van justitie, dan dalam residentie afdeling tempat kapal itu berlabuh; nama dan tempat tinggal pemilik kapal atau agennya, atau dari pemegang buku kapal yang disita, bila ada salah satu yang diketahui; nama kapal itu, dan bila kapal itu berawak, nama dari juragan kapal; ruang kapal, sedapat mungkin ditentukan dengan jelas; tempat kapal itu berlabuh; jumlah pertama dari tuntutan eksekutan; tempat, hari dan jam, di mana dan bilamana penjualan dilakukan. (Rv. 517, 523, 545, 561, 564, 567 dst.)"}, {"l": "RV", "p": "566", "b": "BAB IV SITA EKSEKUTORIAL ATAS KAPAL DAN PENJUALAN KAPAL", "t": "(s. d. u. dg. S. 1908-,522; S. 1933-48jo. S. 1938-2.) Dalam waktu empat belas hari setelah pengumuman pertama, orang yang menuntut penyitaan, memberitahukan salinan bilyet-bilyet kepada para kreditur, yang dibukukan pada register pokok tersebut dalam pasal 7 Peraturan Pendaftaran Kapal, yaitu pada tempat tinggal yang dipilih mereka pada waktu pembukuan. (Ov. 53; KUHD 314, 315b, 316, 316e, 318 dst.; Tbs. 11, 21, 24; Rv. 562, 564.)"}, {"l": "RV", "p": "567", "b": "BAB IV SITA EKSEKUTORIAL ATAS KAPAL DAN PENJUALAN KAPAL", "t": "Tiga puluh hari setelah pengumuman kedua, penjualan dilakuan dengan cara yang diatur untuk penjualan barang-barang tetap yang disita. (Rv. 521 dst., 579.)"}, {"l": "RV", "p": "568", "b": "BAB IV SITA EKSEKUTORIAL ATAS KAPAL DAN PENJUALAN KAPAL", "t": "(s.d.u. dg. S. 1933-48jo. S.1938-2.) Penyitaan dan penjualan perahu-perahu, sekoci-sekoci atau lain-lain alat berlayar yang besamya kurang dari dua puluh meter kubik isi-kotor, dilakukan dengan cara yang sama seperti untuk barang-barang bergerak lainnya. (Rv. 466 dst.)"}, {"l": "RV", "p": "569", "b": "BAB IV SITA EKSEKUTORIAL ATAS KAPAL DAN PENJUALAN KAPAL", "t": "Siapa saja yang kepadanya dijual kapal yang berapa saja besamya, berkewajiban untuk membayarkan uang-uang pembeliannya dalam empat belas ban pada kantor lelang, dengan ancaman paksaan badan, bila tidak dilakukan. Bila tidak dibayar, kapal itu dikenakan penetapan lagi untuk dijual, dengan mengindahkan formalitas-formalitas yang sama seperti yang tersebut pada pasal-alpasal yang lampau, dan dijual untuk beban pembeli yang pertama, yang juga terikat pada paksaan badan untuk r g (Rv. 472, 512, 527, 529 dst., 566, 573, 580-100.) s . o kekurangannya, serta untuk kerugian dan bunga-bunga dan biaya-biaya."}, {"l": "RV", "p": "570", "b": "BAB IV SITA EKSEKUTORIAL ATAS KAPAL DAN PENJUALAN KAPAL", "t": "l i t a a Karena penjualan melalui pengadilan, kapal itu terbebas dari segala l. eg utang-utang dengan hak untuk didahulukan yang mengikat kapal itu. (KUHD 314 dst., 315e, 316, 318b; Tbs. 26, 28; Rv. 526, 560, 573, 579.) w w"}, {"l": "RV", "p": "571", "b": "BAB IV SITA EKSEKUTORIAL ATAS KAPAL DAN PENJUALAN KAPAL", "t": "w Tuntutan-tuntutan untuk reklame dikemukakan di hadapan raad van justitie dan diberitahukan sebelum hari penjualan, sesuai dengan yang diatur pada pasal 536. Bila hal itu baru dikemukakan setelah penjualan, inaka hal itu menurut hukum dianggap diadakan untuk melawan terhadap pembayaran harga pembelian. (Rv. 460 dst., 535 dst., 572 dst.)"}, {"l": "RV", "p": "572", "b": "BAB IV SITA EKSEKUTORIAL ATAS KAPAL DAN PENJUALAN KAPAL", "t": "(s.d. u. dg. S. 1908-522.) Orang yang mengemukakan reklame, atau opposan, menuntut haknya di hadapan raad van justitie, bila dia menghendaki yang demikian itu dalam jangka waktu singkat. (KUHPerd. 24, 1365; Rv. 8, 106, 111, 460, 536, 540.)"}, {"l": "RV", "p": "573", "b": "BAB IV SITA EKSEKUTORIAL ATAS KAPAL DAN PENJUALAN KAPAL", "t": "Perlawanan dari para kreditur terhadap pembayaran uang-uang pembelian tidak diperbolehkan setelah penjualan dilakukan. (Rv. 461, 533, 571, 574.)"}, {"l": "RV", "p": "574", "b": "BAB IV SITA EKSEKUTORIAL ATAS KAPAL DAN PENJUALAN KAPAL", "t": "para kreditur yang melakukan perlawanan, berkewajiban untuk menyerahkan alas hak piutang mereka pada kepaniteraan dalam waktu delapan hari pertama yang berikut, setelah mereka melakukan perlawanan, dan tanpa peringatan; bila hal itu tidak ada, maka dimulai dengan pembayaran uang-uang pembelian, tanpa memasukkan mereka di dalamnya. (Rv. 573.)"}, {"l": "RV", "p": "575", "b": "BAB IV SITA EKSEKUTORIAL ATAS KAPAL DAN PENJUALAN KAPAL", "t": "Urutan para kreditur dan pembagian uang pembelian dilakukan di antara para kreditur yang mempunyai hak untuk didahulukan dalam urutan yang diatur dalam Bab I Buku Kedua Kitab Undang-undang Hukum Dagang, dan di antara para kreditur lainnya, dalam perbandingan piutang-piutang mereka. tiap-tiap pihak kreditur ditempatkan menurut jumlah pokok, bunga- bunga dan biaya-biaya. (KUHD 314 dst., 316 dst., 318 dst., 750.)"}, {"l": "RV", "p": "576", "b": "BAB IV SITA EKSEKUTORIAL ATAS KAPAL DAN PENJUALAN KAPAL", "t": "Ketentuan-ketentuan termuat dalam Bagian 5 Bab III Buku Kedua, juga berlaku pada pembayaran hasil penjualan kapal dengan eksekusi yang di atas kesepuluh syaratnya telah dipenuhi (schepen boven de tien lasten). (Rv. 547 dst.) Mengenai pembagian hasil dari kapal-kapal kecil, berlaku ketentuan- ketentuan Bagian 3 Bab 11 Buku Kedua. (Rv. 535 dst.)"}, {"l": "RV", "p": "577", "b": "BAB IV SITA EKSEKUTORIAL ATAS KAPAL DAN PENJUALAN KAPAL", "t": "Sebuah kapal laut yang siap untuk berlayar, tidak dapat disita, kecuali untuk utang-utang yang dibuat untuk perjalanan yang akan g dilakukan kapal itu; dan bahkan penyitaan demikian dapat dihalangi r dengan penjaminan untuk utang-utang itu. (KUHPerd. 1820 dst.) Kapal itu dianggap siap bertayar, begitu pemimpin kapal s . o l i berangkat. (KUHD 347 dst., 748, 754; Rv. 559, 728.) a diperlengkapi dengan surat-surat.yang diperlukan untuk dapat t a l. eg"}, {"l": "RV", "p": "578", "b": "BAB IV SITA EKSEKUTORIAL ATAS KAPAL DAN PENJUALAN KAPAL", "t": "Pihak kreditur dari peserta pengusaha kapal atau alat berlayar apa w pun, tidak dapat menyita atau menjualnya, tetapi mereka dapat menyita atau menjual porsi kapal dari debitur mereka. w Penyitaan porsi kapat dilakukan dengan suratjuru sita, yang w disampaikan kepada orang yang berutang dan kepada pemegang buku perusahaan kapal. Penjualan porsi kapal dilakukan sesuai dengan peraturan-peraturan yang diatur dalam bab ini, dengan mengindahkan pembedaan antara beban-beban kapal; kecuali jika bilyet-bilyet tidak akan ditempel pada kapal. (KUHPerd. 1641; KUHD 320 dst., 323, 326, 329, 331 dst., 751; Rv. 494, 559, 576, 579.)"}, {"l": "RV", "p": "579", "b": "BAB IV SITA EKSEKUTORIAL ATAS KAPAL DAN PENJUALAN KAPAL", "t": "Ketentuan-ketentuan pasal 502, 503 dan 526 berlaku juga terhadap sita dan penjualan kapal. (Ov. 52.)"}, {"l": "RV", "p": "580", "b": "Bagian 1. Paksaan Badan", "t": "(s.d.u. dg. S. 1938-360jis. 361, 276.) Paksaan badan dapat dilakukan: (Ov. 92; Rv. 581, 583 dst., 586, 593 dst., 596, 605 dst., 900-l , 1019.) 1 . karena penggelapan tanah; (KUHP 385.) 20. karena penitipan berdasarkan keadaan yang memaksa; (KUHPerd. 1703, 1709.) 3 . untuk pengembalian uang yang diberikan guna disimpan oleh orang yang khusus diangkat oleh pemerintah; (KUHPerd. 1406-20; Rv. 449.) 4 . untuk pengembalian barang-barang yang dititipkan pada sequester, komisaris dan penyimpan-penyimpan lain; (KUHPerd. 1739; Rv. 55- 40, 458, 508, 754, 759.) 50. terhadap semua pejabat-pejabat umum, untuk memperlihatkan surat asli yang disimpannya, bila hal itu diperintahkan berdasarkan hukum; (Rv. 175, 851.) 6 . terhadap para pengacara, notaris, juru sita dan pejabat-pejabat lain, untuk pengembalian alas-alas hak yang dipercayakan padanya berdasarkan tugasnya dan uang yang mereka terima dalam kedudukannya atas nama atasannya; (KUHPerd. 1224, 1974; Rv. 126, 487, 848 dst.) 70. (s.d.u. dg. S. 1917-497, S. 1938-360jis. 361, 276.) untuk penggantian biaya-biaya, kerugian-kerugian dan bunga-bunga, sejumlah lebih dari seratus lima puluh gulden, yang harus dibayar oleh seseorang yang dipidana dalam …"}, {"l": "RV", "p": "581", "b": "Bagian 1. Paksaan Badan", "t": "(s.d.u. dg. S. 1926-381; 1934-562jo. 1935-531; 1935-77, 562; S. 1938,-276.) Paksaan badan dapat dilakukan juga: (F. 32, 84; Rv. 586, 1019.) 10. terhadap semua orang yang telah menandatangani surat wesel atau cek sebagai penarik, akseptasi atau endosan atau telah menjaminkannya dengan borgtogt yang disebut aval; (KUHD 100, 106 dst., 110 dst., 125, 127, 131, 169, 178, 181, 187 dst., 191 dst., 195, 204, 228a, 229.) 20. terhadap semua orang yang karena usahanya menandatangani surat- surat order atau surat-surat niaga lainnya. (KUHD 174, 177, 229f-k.) Barangsiapa menjalankan suatu usaha, dianggap mengikatkan diri untuk kepentingan usahanya bila yang sebaliknya tidak dinyatakan dalam surat yang ia tandatangani, kecuali jika ia dapat membuktikan sebaliknya. (KUHPerd. 1916.)"}, {"l": "RV", "p": "582", "b": "Bagian 1. Paksaan Badan", "t": "(s.d. u. dg. S. 1938-360jis. 361, 276.) Dengan tidak mengurangi apa yang ditentukan dalam pasal 580, hakim dapat menyatakan suatu keputusan dapat dengan paksaan badan bila dan sepanjang keputusan itu mengandung suatu hukuman untuk: (Rv. 583.) 1 . atau menyerahkan suatu benda tertentu; (KUHPerd. 574, 582, 612, 959,1235 dst.) 20. atau me suatu perbuatan yang semata-mata tergantung dari kehendak terhukum dan hanya dapat dilakukan olehnya; (KUHPerd. 959, 1239, 1241.) 3 . atau tidak melakukan suatu perbuatan. (KUHPerd. 625 dst., 6922 , 778, 1242, 1366.)"}, {"l": "RV", "p": "583", "b": "Bagian 1. Paksaan Badan", "t": "(s.d.u. dg. S. 1938-360jis, 361, 276.) Paksaan badan sekali-kali tidak dapat diizinkan kepada anak-anaknya dan keturunan selanjutnya menurut keturuan sedarah dan semenda dalam garis lurus ke atas. (KUHPerd. 290 dst.) Paksaan badan tidak dapat dilakukan terhadap orang-orang yang telah berusia genap enam puluh lima tahun. (KUHPerd. 591-50.)"}, {"l": "RV", "p": "584", "b": "Bagian 1. Paksaan Badan", "t": "Paksaan badan sekali-kali tidak dapat dijalankan selain atas r kekuatan keputusan hakim, (Rv. 439, 443, 493, 559, 582, 585, 594,g 647, 761, 1019; IR. 209, 224; RBg. 242, 258.) s . o"}, {"l": "RV", "p": "585", "b": "Bagian 1. Paksaan Badan", "t": "l i t a a Perlawanan, banding atau kasasi sekali-kali tidak menghalang-halangi l. eg pelaksanaan paksaan badan yang dinyatakan dengan keputusan hakim dapat dualankan lebih dahulu walaupun ada perlawanan, banding atau kasasi, asalkan dalam hal ini diberi jaminan sebagai ganti rugi atas w w biaya-biaya, kerugian-kerugian dan bunga-bunga yang dapat dibebankan pada pihak yang meminta pelaksanaan paksaan badan. (KUHPerd. 1162 w dst., 1820 dst., 1830; F. 32, 228; Rv. 54 dst., 346, 402, 605 dst., 606a, 761, 905 dst., 1019.)"}, {"l": "RV", "p": "586", "b": "Bagian 1. Paksaan Badan", "t": "(s.d.u. dg. S. 1938-360jis 361, 276.) Seseorang tidak dapat disandera karena utang yang sama lebih lama dari satu tahun. (Rv. 604, 1019; IR. 210; RBg. 243.)"}, {"l": "RV", "p": "587", "b": "Bagian 1. Paksaan Badan", "t": "Pada pelaksanaan paksaan badan kreditur diwajibkan membayar terlebih dahulu sejumlah uang menurut tarip yang ditetapkan oleh Gubemur Jenderal atau yang kemudian akan ditetapkan sebagai perawatan debitur untuk setiap tiga puluh hari. (Rv. 1020.) (s.d.u. dg. S. 1889-89; S. 1925-497.) Bila kreditur lalai memenuhi kewajibannya sebelum hari ketiga puluh satu, maka atas permintaan debitur, asalkan surat permohonannya disertai surat kesaksian dari kepala lembaga pemasyarakatan yang menerangkan uang persekot tidak dibayar, atau atas permintaan kepala lembaga pemasyarakatan, tanpa suatu formalitas segera dikeluarkan surat perintah pembebasan dari penyanderaan oleh ketua raad van justitie bila di wilayah itu ada raad van justitie dan selainnya oleh residentierechter, atau jika tidak ada di tempat atau berhalangan, oleh kepala daerah setempat. (s.d.u. dg. S. 1889-89.) Perintah pembebasan, yang tidak dapat dimintakan banding, dilaksanakan berdasarkan asli surat perintah pembebasan tersebut dan jika pertu dengan kekuatan polisi, (Rv. 590 dst., 601-50, 604 dst., 1020; IR. 216; RBg. 250.)"}, {"l": "RV", "p": "588", "b": "Bagian 1. Paksaan Badan", "t": "Terhadap debitur dapat dimohonkan penyanderaan oleh orang lain yang juga berhak untuk melakukan paksaan badan terhadapnya. (s.d, u. dg. S. 1917-497.) Terhadap seseorang yang sedang menjalani hukuman atau kurungan atau sedang ditahan karena suatu perbuatan pidana, dapat juga dimohonkan paksaan badan dan berdasarkan permohonan itu, iatetap ditahan sekalipun terhadapnya telah diperintahkan pembebasan dalam perkara pidana atau waktu hukumannya telah lampau. (Rv. 439, 584, 589, 591, 603, 1021.)"}, {"l": "RV", "p": "589", "b": "Bagian 1. Paksaan Badan", "t": "Batalnya suatu penyanderaan, atas dasar apa pun keputusan yang bersangkutan dijatuhkan, sekali-kali tidak mengakibatkan batalnya permohonan. (Rv. 465, 588, 592, 605, 1021.)"}, {"l": "RV", "p": "590", "b": "Bagian 1. Paksaan Badan", "t": "Pihak yang mengajukan permohonan diwajibkan, atas permintaan, m emikul untuk bagian yang sama sebagai biaya perawatan yang ditahan dan dalam hal ini pihak yang meminta pelaksanaan penyanderaan tidak r g dapat mengambil kembali uang itu tanpa izin dari pihak yang ditahan. s . o Permintaan itu dapat diajukan pada raad van justitie dalam wilayah mana si sandera ditahan. (Rv. 587, 592, 599, 601-31, 603, 605.)"}, {"l": "RV", "p": "591", "b": "Bagian 1. Paksaan Badan", "t": "l i t a a Debitur yang disandera secara sah mendapatkan kembali kebebasannya l. eg secara mutlak: (Rv. 599, 605; IR. 217; RBg. 251.) 10. karena izin dari kreditur yang menyuruh Penyanderaan dan dari w w mereka yang mengajukan permohonan bila ada. Izin untuk membebaskan debitur itu dapat diberikan di hadapan (Rv. 584, 588, 6 02,) w notaris, atau dalam daftar yang memuat pendaftaran para sandera; 2 . karena pembayaran atau penitipan uang di pengadilan sebesar jumlah yang terutang, baik kepada kreditur yang melakukan paksaan badan maupun kepada mereka yang mengajukan permohonan, demikian pula segala bunga-bunga yang ada, biaya-biaya pemberesan, biaya penyanderaan dan uang persekot untuk perawatannya; (KUHPerd. 1382 dst., 1404 dst.; Rv. 809 dst.) (s.d.t. dg. S. 1938-360jis. 361, 276.) Dengan pembayaran, sepanjang tidak mengenai pembayaran dengan uang disamakan kesediaan si sandera untuk memenuhi keputusan hakim dengan jaminan cukup; 3 . (s.d.u. dg. S. 1906-348.) karena pelepasan hak alas harta peninggalan; (F. 32; Rv. 586 dst., 699 dst.) 40. (s.d.t, dg. S. 1938-360jis. 361, 276.) bila penyanderaan itu mempunyai danipak yang sedemikian merugikan kesehatan yang disandera sehingga …"}, {"l": "RV", "p": "592", "b": "Bagian 1. Paksaan Badan", "t": "Debitur yang penyanderaannya dinyatakan batal atau dibebaskan karena tidak dibayamya persekot biaya perawatan untuk utang yang sama tidak dapat dilakukan penyanderaan lagi kecuali sedikit-dikitnya satu hari sesudah pembebasan itu. (Rv. 587, 590, 604 dst., 1023; IR. 219; RBg. 253.)"}, {"l": "RV", "p": "593", "b": "Bagian 1. Paksaan Badan", "t": "Pelaksanaan paksaan badan sekali-kali tidak menghalang-halangi atau menghentikan kelanjutan dan pelaksanaan penyitaan atas barang- barang. Demikian pula pelaksanaan penyitaan atas barang-barang tidak menghalang-halangi atau menghentikan pelaksanaan paksaan badan. (Rv. 441, 443 dst., 477 dst, 504 dst., 541 dst., 559 dst., 1023; IR. 221; RBg. 255.)"}, {"l": "RV", "p": "594", "b": "Bagian 2. Pelaksanaan Paksaan Badan", "t": "Suatu paksaan badan hanya dapat dilaksanakan satu hari setelah diberi tahukan keputusan hakim yang memerintahkan penyanderaan. (Rv. 68; IR. 209; . 242.) r g s . o Akan.tetapi ketua raad vanjustitie dapat memerintahkan untuk segera melaksanakannya bila terdapat alasan untuk itu. (Rv. 559, 585, 597, 599, 751, 761; RBg. 321-l0, 322-200.) l i t a Pemberitahuan itu mengandung suatu perintah untuk membayar dan a pemilihan suatu tempat tinggal dalam jarak sepuluh pal dari gedung l. eg raad van justitie yang menjatuhkan keputusan. (KUHPerd. 24; Rv. 443, 504, 605, 1024.)"}, {"l": "RV", "p": "595", "b": "Bagian 2. Pelaksanaan Paksaan Badan", "t": "w w w Debitur tidak dapat disandera: (IR. 212; RBg. 246.) 10. dalam gedung yang digunakan untuk keperluan agama selama diadakan kegiatan agama; 20. di tempat dan selama dilangsungkan sidang oleh penguasa; 3 . di tempat bursa selama waktu bursa; (KUHD 59.) 40. di rumah kediamannya, atau di rumah khusus yang tidak terbuka untuk setiap orang, kecuali bila juru sita disertai oleh kepala daerah setempat atau oleh pejabat yang ditunjuk olehnya; 5 . selama iabebas dalam waktu yang ditetapkan oleh hakim agar debitur dapat menghadap padanya."}, {"l": "RV", "p": "596", "b": "Bagian 2. Pelaksanaan Paksaan Badan", "t": "Penyanderaan dapat dilaksanakan juga pada hari Minggu dan pada jam- jam yang menurut pasal 18 tidak diperbolehkan untuk pemberitahuan oleh juru sita. (Rv. 17, 716. 1024.)"}, {"l": "RV", "p": "597", "b": "Bagian 2. Pelaksanaan Paksaan Badan", "t": "Berita acara penyanderaan, selain harus memenuhi persyaratan biasa, harus diberitahukan olehjuru sita dan berisikan suatu pemberitahuan yang berisikan: 1 . pengulangan dari perintah untuk membayar; 2 . pilihan suatu tempat tinggal dalam jarak sepuluh pal dari tempat dilakukan penyanderaan debitur. (KUHPerd. 24.) Juru sita harus disertai oleh dua orang saksi. (Rv. 8, 19, 439, 594, 599 dst.; 605.)"}, {"l": "RV", "p": "598", "b": "Bagian 2. Pelaksanaan Paksaan Badan", "t": "Bila ada perlawanan, maka juru sita dapat mengadakan penjagaan di depan pintu agar debitur tidak melarikan diri dan minta bantuan polisi setempat, dengan tidak mengurangi tuntutan pidanajika terdapat cukup alasan. (Rv.446, 1024.)"}, {"l": "RV", "p": "599", "b": "Bagian 2. Pelaksanaan Paksaan Badan", "t": "Bila debitur mengajukan perlawanan terhadap sahnya penyanderaan dan menuntut agar segera diadakan keputusan, maka hal itu harus segera diajukan kepada ketua raad van justitie, dalam daerah hukum dimana penyanderaan itu dilakukan, dan ia harus segera menjatuhkan keputusannya. surat perintah ketua itu harus dinyatakan dalam berita acara juru sita dan harus segera dilaksanakan. (Rv. 287, 289, 291, 597, 605.) (s.d. u. dg. S. 1908-522.) Jika penahanan terjadi di luar daerah hukum raad van justitie, maka debitur yang mengajukan perlawanan dapat minta agar ia segera diajukan ke hadapan residentierechter atau, bila tugasnya dijalankan oleh seorang ahli hukum dalam kedudukan ketua pengadilan negeri yang terletak di dekatnya, ke hadapan ketua pengadilan negeri di tempat iaditahan, dan ketua r g tersebut dapat menghentikan penahanan, bila debitur dapat s . o membuktikan ketidakabsahan penahanannya dengan keharusan untuk l i a segera mengirim turunan otentik dari berita acara yang dibuat t olehnya kepada ketua raad van justitie dengan disertai surat-surat a yang bersangkutan untuk mendapatkan pengukuhan atau penetapan lebih l. eg lanjut. (Rv. 1025.) (s..d. t. dg. S. 1908-522.) Bila …"}, {"l": "RV", "p": "600", "b": "Bagian 2. Pelaksanaan Paksaan Badan", "t": "Debitur yang disandera, yang tidak mengajukan perlawanan atau perlawanannya ditolak, dimasukkan dalam lembaga pemasyarakatan di tempat ia ditangkap dan bila di situ tidak ada lembaga pemasyarakatan, dalam lembaga pemasyarakatan di tempat terdekat; juru sita diwajibkan untuk segera membuat dan menandatangani berita acara mengenai penahanan itu. (IR. 214; RBg. 248.) Juru sita dan siapa saja yang membawa, menerima atau menahan debitur di tempat yang menurut undang-undang tidak termasuk tempat untuk menahan sandera, atau, jika tempat sedemikian tidak ada, di tempat yang menurut undang-undang tidak digunakan untuk menyekap para terhukum, dapat dituntut karena penahanan semena-mena. (Rv. 1025; Sv. 361; KUHP 333; S. 1851-27 pasal 44.) Tidak termasuk hal itu, penahanan sementara atau pewagaan terhadap debitur di luar tempat sedemikian dalam menunggu kesempatan dibawanya ke lembaga pemasyarakatan."}, {"l": "RV", "p": "601", "b": "Bagian 2. Pelaksanaan Paksaan Badan", "t": "Akta penahanan si sandera memuat: 10. keputusan hakim yang memerintahkan dilakukannya paksaan badan; (Rv. 584, 602.) 20. nama, nama kecil dan tempat tinggal kreditur; 3 . pilihan tempat tinggal dalam jarak sepuluh pal dari tempat debitur disandera; (KUHPerd. 24; Rv. 597, 605.) 4 . nama dan tempat tinggal si sandera; 5 . persekot dari uang perawatan untuk sekurang-kurangnya tiga puluh hari; (Rv. 587, 603; S. 1935-305.) 6 . akhimya, penyebutan bahwa oleh juru sita sendiri telah diserahkan akta dan berita acara penyanderaan pada si sandera, yang dilakukan dengan segera. (Rv. 600.)"}, {"l": "RV", "p": "602", "b": "Bagian 2. Pelaksanaan Paksaan Badan", "t": "Kepala lembaga pemasyarakatan menyalin akta penahanan itu dalam daftamya, demikian pula kutipan keputusan hakim yang memerintahkan penyanderaan dan menyimpan perintah secara keseluruhan. (Rv. 61-4', 584.) Bila juru sita tidak memperlihatkan keputusan hakim yang bersangkutan, kepala lembaga pemasyarakatan harus menolak untuk r g . o menerima debitur. (Rv. 601-1 , 605; IR. 215, 222; RBg. 249, 256; KUHP 333 dst., 555; S. 1851-27 pasal 44.) s"}, {"l": "RV", "p": "603", "b": "Bagian 2. Pelaksanaan Paksaan Badan", "t": "l i t a a Syarat-syarat yang ditentukan untuk suatu penyanderaan harus l. eg diperhatikan dalam permohonan-permohonan; dalam pada itu juni sita tidak perlu disertai oleh dua orang saksi dan orang yang mengajukan w w permohonan tidak perlu membayar uang perawatan bila untuk itu sudah dibayar uang persekot. (Rv. 439, 584, 587 dst., 590, 594, 597, 599, 601 dst.)"}, {"l": "RV", "p": "604", "b": "Bagian 2. Pelaksanaan Paksaan Badan", "t": "w (s.d.u. dg. S. 1938-360jis, 361, 276.) Bila diperintahkan pembebasan karena tidak dipenuhinya pembayaran persekot untuk perawatan, kreditur tidak dapat minta untuk menyandera debitur lagi sebelum mengganti biaya mengenai pembebasan tersebut atau jika ia menolak, disimpan di bawah pengawasan kepala lembaga pemasyarakatan dan juga membayar persekot untuk perawatan selama enam bulan atau, jika berdasarkan pasal 586 debitur tidak dapat disandera sampai enam bulan, untuk waktu kurang dari enam bulan. Dalam hal ini tidak pertu lagi dipenuhi syarat-syarat yang niendahului penyanderaan. (Rv. 587, 592, 1029; IR. 219; RBg. 253.)"}, {"l": "RV", "p": "605", "b": "Bagian 2. Pelaksanaan Paksaan Badan", "t": "(s.d.u.dg.S. 1938-360jis. 361, 276.) Debitur dapat menuntut pembatalan penyanderaannya, bila formalitas-formalitas seperti diuraikan di alas tidak dipenuhi dan tuntutan itu seperti halnya dengan tuntutan pembebasan dengan alasan lain sebagaimana ditentukan dalam pasal 591 , diajukan kepada raad van justitie yang daerah hukumnya meliputi tempat di mana ia disandera. Tuntutan pembatalan yang didasarkan atas alasan-alasan yang menyangkut gugatan pokok, diajukan kepada majelis hakim yang ditugaskan untuk pelaksanaan keputusan itu. (s.d.u. dg. S. 1908-522.) Gugatan dapat diajukan dalam waktu singkat dan di tempat yang dipilih seperti tersebut dalam daftar kepala lembaga pemasyarakatan; kreditur dapat dihukum untuk membayar biaya, kerugian dan bunga, bila terdapat cukup alasan. (KUHPerd. 1243 dst., 1365 dst.; Rv. 10, 350, 586 dst., 589, 591 dst., 594, 597, 601 dst., 1027; IR. 218; RB9. 252.)"}, {"l": "RV", "p": "606", "b": "Bagian 2. Pelaksanaan Paksaan Badan", "t": "(s.d. t. dg. S. 1938-360jis, 361, 276.) Debitur yang tidak mampu untuk memenuhi keputusan hakim yang menghukumnya, dapat menuntut alas dasar itu dengan acara singkat, agar penyanderaan tidak dilaksanakan atau tidak dilanjutkan pelaksanaannya. (Rv. 283 dst.) setelah tuntutan itu dikabulkan, maka penyanderaan tidak dapat dilakukan untuk utang yang sama, kecuali bila kreditur dalam pemeriksaan secara singkat dapat membuktikan, bahwa debitur mampu untuk memenuhi keputusan hakim yang menghukumnya. Debitur yang membuat dirinya sengaja tidak mampu untuk memenuhi kewajibannya sehubungan dengan akan dilaksanakannya keputusan hakim atau sebelum dijatuhkan keputusan hakim yang akan menghukumnya, tidak dapat menggunakan ketentuan dalam alinea pertama pasal ini. Dg. S. 1938-360jis. 361, 276 ditambahkan Bagian Ketiga ini."}, {"l": "RV", "p": "606A", "b": "Bagian 3. Uang Paksa.", "t": "s . o l i a (s. d. t. dg. S. 1938-360jis. 361, 276.) Sepanjang suatu keputusan t hakim mengandung hukuman untuk sesuatu yang lain daripada membayar a sejumlah uang, maka dapat ditentukan, bahwa sepanjang atau setiap l. eg kali terhukum tidak memenuhi hukuman tersebut, olehnya harus diserahkan sejumlah uang yang besamya ditetapkan dalam keputusan Pasal 606b. w w hakim, dan uang tersebut dinamakan uang paksa. w (s.d,t. dg. S. 1938-360jis. 361, 276.) Bila keputusan tersebut tidak dipenuhi, maka pihak lawan dari terhukum berwenang untuk metaksanakan keputusan terhadap sejumlah uang paksa yang telah ditentukan tanpa terlebih dahulu memperoleh alas hak baru menurut hukum. Pasal 606 berlaku juga dalam hal ini. Bila pihak lawan mengajukan gugatan untuk memperoleh alas hak baru seperti dimaksud pada alinea pertama, maka tergugat dapat mengajukan bantahan seperli diatur dalam alinea pertama di muka terhadap pelaksanaannya tanpa alas hak dasar baru."}, {"l": "RV", "p": "607", "b": "BAB VI PENYELESAIAN BIAYA, KERUGIAN DAN BUNGA, SERTA BIAYA ACARA", "t": "Hakim yang menghukum suatu pihak untuk mengganti biaya-biaya, kerugian-kerugian dan bunga-bunga harus menetapkan jumlahnya dalam keputusannya; bila ia tidak dapat menetapkan jumlah itu, maka suatu daftar te,tang hal itu harus dibuat oleh pihak lawan dan diberitahukan di tempat yang telah dipilffi oleh pihak lain; surat- surat yang dimaksudkan sebagai bukti harus dibeii. tahukaii pada pihak lain atau diserahkan di kepaniteraan. (KUHPerd. 24, 403, 606, 608, 1243 dst., 1246; Rv. 8-l , 60, 99, 106 dst., 222, 264, 460 dst., 466, 540, 610; IR. 183 2 ; RBg. 1942.)"}, {"l": "RV", "p": "608", "b": "BAB VI PENYELESAIAN BIAYA, KERUGIAN DAN BUNGA, SERTA BIAYA ACARA", "t": "Dalam waktu empat belas haii setelah pemberitahuan terhukum diwajibkan untuk menyerahkan rancangan tentang jumlah biaya-biaya, kerugian-kerugian dan bunga-bunga menurut pendapatnya. Bila tidak, ia dianggap menerima gugatan. (KUHPerd. 1405; Rv. 607, 610, 809.)"}, {"l": "RV", "p": "609", "b": "BAB VI PENYELESAIAN BIAYA, KERUGIAN DAN BUNGA, SERTA BIAYA ACARA", "t": "(s. d. u. dg. S. 1908-522.) Bila antara para pihak tidak terdapat kesepakatan, maka perkara itu akan diajukan pada sidang dengan suatu akta yang sederhana dari pengacara ke pengacara. (Rv. 57, 84, 346, 350, 402, 429, 610.)"}, {"l": "RV", "p": "610", "b": "BAB VI PENYELESAIAN BIAYA, KERUGIAN DAN BUNGA, SERTA BIAYA ACARA", "t": "(s. d. u.. dg. S. 1908-522.) Ketentuan-ketentuan di atas berlaku juga untuk penaksiran biaya-biaya perkara yang dibebankan pada salah satu pihak yang menurut ketentuan itu diselesaikan, dengan pengecualian seperti tersebut pada alinea ketiga dari pasal 58. (Rv. 58 dst., 607 dst., 975; IR. 1832; RBg. 194-20; S. 1851-27.)"}, {"l": "RV", "p": "611", "b": "BAB VII", "t": "l i t a Keputusan hakim yang mengandung perintah untuk membelikan jaminan, a harus menetapkan jangka waktu, yang di dalamnya jaminan itu harus l. eg diberikan dan jangka waktu, yang di dalamnya jaminan itu harus diterima atau ditolak. (KUHPerd. 335, 452, 472, 483, 784, 786, 789, w w 819, 982, 1035, 1150, 1162, 1171, 1827 dst., 1830; KUHD 167a, 167b, 176, 227a, 227b; Rv. 54 dst., 128 dst., 283, 330, 613, 696, 722.) Pasal 612. w Jaminan itu harus diajukan dengan suatu akta yang diberitahukan pengacara ke pengacara. Cara yang sama digunakan juga dalam hal menerima jaminan. (KUHPerd. 24; Rv. 106.)"}, {"l": "RV", "p": "613", "b": "BAB VII", "t": "(s.d.u. dg. S. 1908-522.) Bila tidak terdapat kesepakatan tentang cukup tidaknya jaminan itu, maka pihak yang membantah diwajibkan untuk mengajukan perkara itu ke pengadilan dalam jangka waktu yang telah ditetapkan dalam keputusan hakim dalam bentuk seperti ditentukan dalam pasal di muka. (Rv. 112 dst., 611.)"}, {"l": "RV", "p": "614", "b": "BAB VII", "t": "Bila jaminan itu berupa suatu borg, dan borg itu diterima atau disetujui, maka ia harus mengikatkan diri dengan suatu akta di kepaniteraan, akta mana dapat dilaksanakan dengan surat perintah dari ketua raad van justitie yang dibuat dalam bentuk seperti diuraikan dalam pasal 435 (1). (KUHPerd. 117111827 dst., 1832-51; Rv. 55-5 .) (1) Mengenai bunyi pasal 435, lihat catatan kaki pasal 487."}, {"l": "RV", "p": "615", "b": "Bagian 1. Kompromi Dan Pengangkatan Wasit.", "t": "Setiap orang dapat menyerahkan perselisihan mengenai hak-hak yang ia kuasai secara bebas kepada keputusan wasit. (KUHPerd. 108, 194, 330 dst., 433 dst., 1852; F. 22, 226, 246; IR. 377; RBg. 705.) Semua orang yang diangkat dengan suatu keputusan hakim, atau yang menurut ketentuan-ketentuan dalam KUHPerd. atau KUHD memerlukan kuasa dengan suatu keputusan hakim untuk melakukan perdamaian atau untuk menjual barang-barang, tanpa kuasa tersebut dalam menjalankan pekerjaannya tidak boleh menyerahkan penyelesaian perkara pada keputusan wasit. (KUHPerd. 407, 425, 452, 463, 481, 979, 1020, 1035, 1127, 1331, 1446, 1796 dst., 1852; F. 132, l00; 226; Rv. 697.) r g s . o Seorang bahkan sebelumnya dapat mengikatkan diri, bila di kemudian dst.; KUHPerd. 1318; Rv. 324, 619, 648.) l i a hari terjadi sengketa, untuk tunduk pada keputusan wasit. (ISR. 135 t a l. eg"}, {"l": "RV", "p": "616", "b": "Bagian 1. Kompromi Dan Pengangkatan Wasit.", "t": "Seseorang, dengan ancaman kebatalan, tidak dapat mengadakan kompromi w tentang pemberian dan hibah-wasiat untuk keperluan hidup, perumahan atau pakaian; tentang pemisahan antara suami dan istri, baik karena w perceraian, maupun pisah meja dan ranjang, dan pemisahan harta w benda; tentang perselisihan mengenai status seseorang, demikian juga tentang sengketa-sengketa lain yang tidak diizinkan dilakukannya perdamajan menurut ketentuan-ketentuan undang-undang. (AB. 23, KUHPerd, 85 dst., 186 dst,, 207 dst., 233 dst., 250 dst., 261; Rv. 451-20, 643-20, 749.)"}, {"l": "RV", "p": "617", "b": "Bagian 1. Kompromi Dan Pengangkatan Wasit.", "t": "Kecuali apa yang disebut dalam ketentuan-ketentuan pasal 34, maka setiap orang yang dapat menerima suatu kuasa, dapat juga diangkat sebagai wasit. Dari ketentuan itu dikecualikan para wanita dan mereka yang belum cukup umur. (KUHPerd. 330, 424, 1798; Rv. 643-21.)"}, {"l": "RV", "p": "618", "b": "Bagian 1. Kompromi Dan Pengangkatan Wasit.", "t": "Akta kompromi dibuat secara tertulis dan ditandatangani oleh para pihak; bila para pihak tidak dapat menandatangani, maka kompromi itu dibuat di depan notaris dan saksi-saksi. Akta kompromi itu harus memuat pokok-pokok sengketa dan nama kecil, nama dan tempat tinggal para pihak, demikian pula nama dan tempat tinggal dari wasit atau wasit-wasit, yang jumlahnya harus ganjil. Semua itu atas ancaman kebatalan, (KUHPerd. 1851; Rv. 31, 616, 620, 0 0 624, 631, 635, 641, 643-2 dan 6 , 651; IR. 130.)"}, {"l": "RV", "p": "619", "b": "Bagian 1. Kompromi Dan Pengangkatan Wasit.", "t": "Dalam hal seperti tereantum dalam alinea ketiga dari pasal 615, para pihak pada saat terjadinya sengketa tidak memperoleh kata sepakat mengenai penunjukan wasit-wasit, maka wasit-wasit itu, atas permohonan pihak yang paling siap, diangkat oleh hakim yang berwenang untuk mengadili sengketa itu, sekiranya tidak terjadi kompromi - (KUHPerd. 99 dst., 313, 621, 650-30, 651 .)"}, {"l": "RV", "p": "620", "b": "Bagian 1. Kompromi Dan Pengangkatan Wasit.", "t": "Kompronii menentukan jangka waktu, dalam waktu mana sengketa yang diajukan pada wasit harus diputus; dan jika hal itu tidak ditentukan, maka tugas yang dibebankan pada wasit berlaku selama enam bulan, terhitung mulai diterimanya pengangkatan. Selama jangka waktu itu, para wasit tidak dapat ditarik kembali kecuali dengan kesepakatan para pihak. (KUHPerd. 1338; Rv. 623, 628 dst., 643, 650.)"}, {"l": "RV", "p": "621", "b": "Bagian 1. Kompromi Dan Pengangkatan Wasit.", "t": "Terhadap wasit-wasit yang tidak diangkat oleh hakim, tidak dapat diajukan keberatan, kecuali karena alasan-alasan yang timbul setelah pengangkatanitu. (Rv. 218.) Terhadap wasit-wasit yang diangkat oleh hakim, jika para pihak r g s . o secara tegas atau secara diam-diam menerima pengangkatan itu, tidak dapat diajukan kebemtan, kecuali karena alasan-alasan yang timbul kemudian. l i t a Alasan-alasan keberatan adalah sama seperti hainya terhadap hakim; a keberatan itu akan diadili secara singkat oleh hakim seperti diatur l. eg dalam pasal 619. (Rv.34 dst., 38.)"}, {"l": "RV", "p": "622", "b": "Bagian 1. Kompromi Dan Pengangkatan Wasit.", "t": "w w Penerimaan tugas sebagai wasit dilakuk- secara tertulis. w Hal itu dapat dilakukan di atas akta pengangkatannya. (KUHPerd. 1793; Rv. 618 dst., 650.)"}, {"l": "RV", "p": "623", "b": "Bagian 1. Kompromi Dan Pengangkatan Wasit.", "t": "para wasit yang telah menerima tugasnya tidak dapat lagi menarik diri, kecuali berdasarkan alasan-alasan yang disetujui oleh hakim seperti ditunjuk oleh pasal 619. mereka dapat dihukum untuk membayar ganti rugi mengenai kerugian-kerugian dan bunga-bunga kepada para pihak, bila mereka tanpa alasan yang sah tidak mengambil keputusan dalam jangka waktu yang telah ditentukan. (KUHPerd. 1800: Rv. 620, 622.)"}, {"l": "RV", "p": "624", "b": "Bagian 2. Pemeriksaan Perkara oleh para Wasit.", "t": "Pemeriksaan perkara dilakukan dengan cara dan dalam waktu seperti ditentukan dalam kompromi, dan jika hal itu tidak ada, ditentukan oleh para wasit. (Rv. 618, 620, 626 dst., 643-70.)"}, {"l": "RV", "p": "625", "b": "Bagian 2. Pemeriksaan Perkara oleh para Wasit.", "t": "Setelah jangka waktu itu lewat, maka para wasit hanya mengambil keputusan hanya berdasarkan memori-memori dan surat-surat yang diajukan. (RV. 145, 626, 636.)"}, {"l": "RV", "p": "626", "b": "Bagian 2. Pemeriksaan Perkara oleh para Wasit.", "t": "Bila para pihak tidak mengajukan suatu suratpun, maka para wasit atas permintaan mereka dapat menetapkan jangka waktu baru, atau menyatakan bahwa tugasnya telah berakhir. (Rv. 623, 625.)"}, {"l": "RV", "p": "627", "b": "Bagian 2. Pemeriksaan Perkara oleh para Wasit.", "t": "Semua perintah yang dapat dilaksanakan lebih dahulu yang dikeluarkan oleh para wasit dan semua penetapan tentang tingkatan pemeriksaan, dapat dilaksanakan, tanpa formalitas-formalitas apa pun, terhitung mulai hari para wasit memberitahukan hal itu kepada para pihak. (KUHPerd. 1736; Rv. 48, 53, 624 dst.)"}, {"l": "RV", "p": "628", "b": "Bagian 2. Pemeriksaan Perkara oleh para Wasit.", "t": "Bila harus dilakukan pemeriksaan oleh pengadilan mengenai asli atau tidaknya suatu surat, atau bila terdapat perselisihan tentang sifat kepidanaan dalam perkara itu, maka para wasit mempersilahkan para pihak untuk mengajukannya kepada hakim biasa. Dalam hal itu jangka-jangka waktu berlaku kembali sejak hari keputusan hakim terhadap perkara itu mempunyai kekuatan tetap. (RO. 55; AB. 29; KUHPerd. 1853; Rv. 148 dst., 165, 620, 629, 643-80.)"}, {"l": "RV", "p": "629", "b": "Bagian 2. Pemeriksaan Perkara oleh para Wasit.", "t": "r g s . o Ketentuan dalam alinea kedua dari pasal di muka berlaku juga, bila para wasit menjatuhkan keputusan terhadap suatu insiden, atau oleh l i t a mereka dijatuhkan keputusan sela. Dalam hal tersebut terakhir, mereka dapat memperpanjang jangka waktu untuk keputusan akhir. (Rv. 48, 241, 620, 624 dst.) a Pasal 630. l. eg w w Bila oleh para wasit diperintahkan pemeriksaan saksi-saksi dan saksi-saksi itu tidak datang menghadap secara sukarela, atau menolak w memberikan keterangan di bawah sumpah atau janji, maka pihak yang paling berkepentingan dapat mengajukan permohonan kepada raad van justitie yang daerah hukumnya meliputi tempat, di mana pemeriksaan saksi-saksi itu diperintahkan, untuk mengangkat seorang hakim- komisaris yang akan melakukan pemeriksaan saksi-saksi dengan cara seperti dalam perkara biasa. Dalam hal itu, maka jalannya jangka-jangka waktu ditunda sampai pemeriksaan saksi-saksi selesai. (KUHPerd. 1932; Rv. 184 dst., 194 dst., 204, 207, 238, 628 dst.)"}, {"l": "RV", "p": "631", "b": "Bagian 3. Keputusan para Wasit.", "t": "para wasit menjatuhkan keputusan menurut aturan-aturan hukum, kecuali jika menurut kompromi, mereka diberi wewenang untuk memutus sebagai manusia-manusia baik berdasarkan keadilan. (Rv. 618, 624 dst.)"}, {"l": "RV", "p": "632", "b": "Bagian 3. Keputusan para Wasit.", "t": "Keputusan itu memuat: nama kecil, nama dan tempat tinggal para pihak; kesimpulan akhir tentang keterangan-keterangan masing-masing pihak; dasar pertimbangan dan keputusan. (Rv. 61, 631.) Dalam keputusan itu dicantumkan hari dan tempat, di mana keputusan itu dijatuhkan dan ditandatangani oleh setiap wasit. (Rv. 58 dst., 61, 620, 633, 643-60, 649.)"}, {"l": "RV", "p": "633", "b": "Bagian 3. Keputusan para Wasit.", "t": "Bila bagian minoritas menolak untuk menandatangani, maka para wasit yang lain menyebutkan hal itu dan keputusan itu mempunyai kekuatan yang sama seperti ditandatangani oleh semua wasit. (Rv. 623, 632.)"}, {"l": "RV", "p": "634", "b": "Bagian 3. Keputusan para Wasit.", "t": "Dalam waktu empat belas hari untuk Jawa dan Madura, dan sedapat mungkin dalam waktu tiga bulan untuk tempat-tempat lain yang termasuk dalam daerah hukum raad van justitie di Jawa, terhitung sejak hari keputusan, surat keputusan aslinya oleh salah satu dari para wasit, atau oleh seorang pengacara yang dikuasakan oleh mereka dengan akta otentik, diserahkan di kepaniteraan raad van justitie yang daerah hukumnya meliputi tempat di mana keputusan itu diambil. (Rv. 619, 621, 635, 637; RBg. 322-16.) Akta penyerahan ditulis pada bagian bawah atau pinggir dari surat keputusan asli yang diserahkan dan ditandatangani oleh panitera dan juga oleh pihak yang menyerahkan. Panitera membuat akta itu; dari para wasit tidak boleh ditarik biaya akta itu, demikian juga uang persekot, tetapi biaya itu harus r dibayar oleh para pihak sendiri, atau ditagih dari mereka. (KUHPerd.g 1794, 1811; Rv. 58 dst., 618.) s . o"}, {"l": "RV", "p": "635", "b": "Bagian 3. Keputusan para Wasit.", "t": "l i t para wasit diwajibkan untuk menyerahkan, bersama dengan a a keputusannya, akta asli pengangkatannya atau turunan otentiknya di l. eg kepaniteraan. (Rv.618.)"}, {"l": "RV", "p": "686", "b": "Bagian 3. Keputusan para Wasit.", "t": "w w Terhadap keputusan para wasit, bagaimanapun sifatnya, tidak dapat w dilakukan perlawanan. (Rv. 618, 624 dst., 627, 641 dst.)"}, {"l": "RV", "p": "637", "b": "Bagian 3. Keputusan para Wasit.", "t": "Keputusan para wasit dilaksanakan atas kekuatan surat perintah dari ketua raad van justitie seperti tersebut dalam pasal 634, surat perintah mana dikeluarkan dalam bentuk seperti diuraikan dalam pasal 435 (yang sudah tidak sesuai 14 dengan keadaan sekarang). Hal itu dicantumkan di atas surat keputusan asli dan dan disalin pada turunan yang dikeluarkan. (Rv. 638 dst., 644, 646.)"}, {"l": "RV", "p": "638", "b": "Bagian 3. Keputusan para Wasit.", "t": "Bila suatu perkara, yang diputus oleh hakim biasa pada tingkat pertama, pada tingkat banding diserahkan pada para wasit, maka keputusannya diserahkan di kepaniteraan majelis hakim yang seharusnya memeriksa perkara itu pada tingkat banding, dan surat perintah diberikan oleh ketua majelis itu. (Rv. 324, 327 dst., 618, 624, 634 dst., 637.)"}, {"l": "RV", "p": "639", "b": "Bagian 3. Keputusan para Wasit.", "t": "Keputusan wasit, yang dilengkapi dengan surat perintah dari ketua raad van justitie yang berwenang, dilaksanakan menurut cara pelaksanaan biasa. (Rv435.dst., 644.)"}, {"l": "RV", "p": "640", "b": "Bagian 3. Keputusan para Wasit.", "t": "Majelis hakim, yang ketuanya mengeluarkan surat perintah , memeriksa sengketa mengenai pelaksanan keputusan wasit. (Rv. 442, 637 dst.)"}, {"l": "RV", "p": "641", "b": "Bagian 4. Ketentuan Terhadap Keputusan Wasit.", "t": "Terhadap keputusan wasit yang dijatuhkan pada tingkat pertama, sesuai dengan ketentuan dalam pasal 163 Ro., dapat diajukan permohonan banding pada hooggerechtshof, bila pokok sengketa bemilai lebih dari f 500,-, kecuali jika dalam kompromi dengan tegas dinyatakan, bahwa para pihak melepaskan haknya untuk naik banding. (Rv. 618, 642 dst.) Ketentuan-ketentuan tm,at dalam Bab VI Buku Pertama dari reglemen yang sekarang, berlaku terhadap permohonan banding tersebut. (Rv. 327 dst.)"}, {"l": "RV", "p": "642", "b": "Bagian 4. Ketentuan Terhadap Keputusan Wasit.", "t": "Terhadap keputusan wasit tidak. dapat diajukan permohonan kasasi, juga upaya hukum peninjauan kembali, sekalipun hal itu diperjanjikan oleh para pihak. (ISR. 157; RO. 171; Rv. 385 dst., 402 dst., 643, 649.)"}, {"l": "RV", "p": "643", "b": "Bagian 4. Ketentuan Terhadap Keputusan Wasit.", "t": "g Terhadap keputusan wasit yang tidak dapat dimintakan banding, dapat r dst.) s . o dimintakan kebatalannya dalam hal-hal seperti berikut: (Rv. 641, 644 618.) l i a 10. bila keputusan itu diambil di luar batas-batas kompromi; (Rv. t a 2 . bila keputusan itu didasarkan atas kompromi yang tidak berharga l. eg atau telah gugur; (Rv. 616 dst., 618, 620, 650.) 30. bila keputusan itu dijatuhkan oleh beberapa wasit yang tidak (Rv. 618, 651.) w w berwenang menjatuhkan keputusan di luar kehadiran yang lain; w 4 . bila diputuskan tentang sesuatu yang tidak dituntut, atau dengan itu diberikan lebih dari yang dituntut; (Rv. 385-20 dan 30.) 5 . bila keputusan itu mengandung ketentuan-ketentuan yang bertentangan satu dengan yang lain; (Rv. 385-60.) 60. bila para wasit lalai memutus satu atau beberapa hal yang seharusnya diputuskan, sesuai dengan ketentuan dalam kompromi; (Rv. 384-40, 615, 618.) 7 . bila melanggar bentuk acara yang telah ditetapkan dengan ancaman kebatalan; tapi ini hanya bila dalam kompromi diperjanjikan dengan tegas, bahwa para wasit wajib memenuhi aturan acara biasa; (Rv. 177, 206, 624.) 8 . bila diputus atas dalam surat-surat yang setelah keputusan para wasit, diakui sebagai …"}, {"l": "RV", "p": "644", "b": "Bagian 4. Ketentuan Terhadap Keputusan Wasit.", "t": "Tuntutan akan kebatalan tidak dapat diterima, kecuali jika diajukan dalam waktu enam bulan, terhitung dari hari pemberitahuan para wasit kepada orang yang bersangkutan atau di tempat tinggalnya. 0 0 0 Akan tetapi dalam hal-hal seperti disebut dalam nomor 8 , 9 dan 10 pasal di muka, jangka waktu enam bulan mulai berjalan sejak hari diketahuinya kepalsuan, peniuan atau tipu-muslihat, atau ditemukannya surat-surat; dengan ketentuan, bahwa dalam hal-hal ini hanya bukti tertulis yang dapat digunakan untuk membuktikan hari itu. (Rv. 645 dst.)"}, {"l": "RV", "p": "645", "b": "Bagian 4. Ketentuan Terhadap Keputusan Wasit.", "t": "Tuntutan kebatalan diajukan dengan surat panggilan untuk menghadap di sidang yang berisikan perlawanan terhadap perintah pelaksanaan, (Rv. I dst., 646 dst.)"}, {"l": "RV", "p": "646", "b": "Bagian 4. Ketentuan Terhadap Keputusan Wasit.", "t": "Tuntutan itu diajukan pada raad van justitie yang ketuanya memerintahkan pelaksanaan itu. Raad van justitie memutus tuntutan itu, dan para pihak dapat mengajukan banding, jika terdapat cukup alasan, terhadap keputusan itu, seperti dalam perkara-perkara pengadilan biasa. (Rv. 327 dst., 385 dst., 402 dst., 637, 645.)"}, {"l": "RV", "p": "647", "b": "Bagian 4. Ketentuan Terhadap Keputusan Wasit.", "t": "r g Bila para wasit memutuskan paksaan badan terhadap terhukum pada s . o tingkat akhir, dan ia menganggap bahwa ketentuan-ketentuan undang- l i t a undang tidak membolehkan upaya paksaan dalam hal yang bersangkutan, maka iadapat mengajukan permohonan pembatalan dari bagian keputusan a itu, kepada hakim seperti disebut dalam pasal di muka, dalam jangka l. eg waktu dan dengan cara seperti ditentukan dalam pasal 644 dan 645, dan sekalipun bertentangan dengan ketentuan-ketentuan yang dibuat w dalam akta kompromi. (AB. 23; Rv. 508 dst., 583.) w"}, {"l": "RV", "p": "648", "b": "Bagian 4. Ketentuan Terhadap Keputusan Wasit.", "t": "w"}, {"l": "RV", "p": "649", "b": "Bagian 5. Berakhimya Perkara Di Muka Para Wasit.", "t": "Tugas para wasit berakhir dengan dijatuhkannya keputusan. (KUHPerd. 631 dst.)"}, {"l": "RV", "p": "650", "b": "Bagian 5. Berakhimya Perkara Di Muka Para Wasit.", "t": "Tugas tersebut berakhir juga: (Rv. 623.) 1 . dengan lewatnya jangka waktu yang ditetapkan dalam kompromi, atau yang diperpanjang oleh para pihak selama perkara masih bergantung; (Rv. 620.) 2 . setelah lewat enam bulan, terhitung sejak hari ditandatangani akta penerimaan, bila tidak ditentukan jangka waktu lain; (Rv. 620, 622.) 30. dengan ditariknya kembali para wasit atas kesepakatan para pihak. (KUHPerd. 1813 dst.; Rv. 620.)"}, {"l": "RV", "p": "651", "b": "Bagian 5. Berakhimya Perkara Di Muka Para Wasit.", "t": "Tugas dari para wasit berakhir pula karena kematian, keberatan terhadapnya yang diterima atau pemecatan seorang atau lebih dari mereka. (Rv. 621, 623,) Bila tidak diperjanjikan sebaliknya, maka dalam hal-hal tersebut, atau oleh para pihak, atau jika di antara mereka tidak terdapat kata sepakat, atas tuntutan salah satu atau kedua pihak, oleh hakim seperti ditunjuk dalam pasal 619, diangkat wasit-wasit baru dengan tugas untuk melanjutkan pemeriksaan berdasarkan akta-akta terakhir."}, {"l": "RV", "p": "652", "b": "Bagian 1. Penyegelan.", "t": "Dalam hal-hal, di mana setelah seseorang meninggal dunia, harus dilakukan penyegelan, maka hal itu dijalankan di tempat di mana pekerjaan itu harus dilakukan, oleh pejabat yang bertugas melakukan penyegelan. r g . o Pejabat itu menggunakan segel yang diperuntukkan bagi keperluan itu. s Ia mengangkat seorang penyimpan barang yang disegel dan sedapat l i t mungkin seseorang yang diajukan oleh orang-orang yanga berkepentingan, jika orang itu dianggapnya memenuhi syarat untuk a itu. (KUHPerd. 190, 215, 246, 461, 833, 1128, 1330, 1701; F. 7, 90; l. eg Rv. 653 dst., 660, 823, 840; S. 1851-27 pasal 5 dst.)"}, {"l": "RV", "p": "653", "b": "Bagian 1. Penyegelan.", "t": "w w Penyegelan dapat dituntut: (Rv. 659, 665, 671, 673, 823, 840.) w 10. oleh suami atau istri yang ditinggalkan dan oleh mereka yang mengaku mempunyai suatu hak atas warisan atau harta bersama; (KUHPerd 126-10, 127, 190, 383, 40i dst., 452, 832 dst., 955, 957 dst.,1652.) 20. oleh para kreditur yang memiliki alas hak pelaksanaan terhadap harta warisan atau setelah diadakan penyelidikan secara singkat tentang kebenaran tuntutan mereka dan tentang kepentingannya pada penyegelan, berdasarkan suatu izin dari ketua raad van justitie; (KUHPerd. 1107; Rv. 435 dst., 440, 655-30; RBg. 321-10, 322-200.) 0 0 3 . bila orang-orang seperti tersebut pada nomor 1 tidak hadir, oleh mereka yang bekerja pada orang yang telah meninggal dunia atau bertempat tinggal bersama dengan orang yang telah meninggal dunia; (Rv. 655, 673.) 4 . oleh para pelaksana surat wasiat; (KUHPerd. 1005 dst., 1009, 1017.) 5 . oleh para sanak saudara terdekat dari anak-anak yang belum cukup umur atau orang yang berada di bawah pengampuan yang berkepentingan, bila mereka, di luar apa yang ditentukan dalam pasal 360 KUHPerd., tidak mempunyai wali atau pengampu, demikian pula jika wali atau pengampu mereka tidak hadir. …"}, {"l": "RV", "p": "654", "b": "Bagian 1. Penyegelan.", "t": "Penyegelan dilakukan demi hukum dalam hal anak yang belum cukup umur, atau orang yang di bawah pengampuan yang berkepentingan atau turut berkepentingan dalam suatu warisan, tidak mempunyai wali atau pengampu, atau tidak diwakili berdasarkan alinea kedua pasal 360 KUHPerd., atau bila si wali atau pengampu , atau suami/istri dari orang yang meninggal dunia, atau salah satu dari para ahli waris tidak hadir, atau bila orang yang meninggal dunia adalah penyimpan umum dari beberapa barang. (KUHPerd. 424, 429, 1009; Rv. 635-50, 664.) Dalam hal tersebut terakhir, penyegelan tidak dilakukan selain terhadap barang-barang yang termasuk dalam penyimpanannya. Penyegelan berdasarkan ketidakhadiran tidak dilakukan bila orang yang tidak hadir telah menujuk seorang kuasa dengan suatu kuasa otentik, untuk mewakili dalam warisan atau warisan-warisan yangjatuh padanya, dan kuasa ini mengajukan perlawanan terhadap penyegelan itu. (KUHPerd. 1793, 1796.)"}, {"l": "RV", "p": "655", "b": "Bagian 1. Penyegelan.", "t": "Tentang penyegelan harus ternyata dari berita acara yang memuat: 10. penyebutan hari dan jam, demikian juga alasan penyegelan; (Rv. 653 dst ) r g . o 2 . (s.d.u.dg.S.1925 -427.) namakecil ,nama dan tempat tinggal dari s orang yang dilakukan penyegelan dan tempat tinggal yang dipilih i t a di ibu kota dari daerah di mana penyegelan itu dilakukan, jika l ia tidak bertempat tinggal di daerah itu; (KUHPerd. 24, 666-30.) a l. eg 30. kuasa dari ketua raad van justitie, bila hal itu diberikan, ataupun penyebutan dari bukti eksekutorial, atas dasar nama 0 0 0 w tuntutan dilakukan; (Rv. 653-2 ; RBg. 321-1 , 322-20 .) 40. kehadiran dan titntutan-tuntutan dari para pihak; (Rv. 653.) w w 5 . uraian tentang tempat-tempat dan barang-barang yang disegel dan uraian singkat tentang barang-barang yang tidak turut disegel; (Rv. 654, 656 dst., 660.) 6 . nama, tempat tinggal dan pekerjaan si penyimpan; (Rv. 652.) 70. sumpah pada penutupan segel yang diucapkan oleh orang-orang yang menempati rumah di mana penyegelan dilakukan, di hadapan pejabat yang ditugaskan tersebut, bahwa mereka tidak menggelapkan, juga tidak melihat dan tidak mengetahui, bahwa ada sesuatu yang digelapkan, baik langsung maupun …"}, {"l": "RV", "p": "656", "b": "Bagian 1. Penyegelan.", "t": "Bila pada penyegelan ditemukan suatu wasiat yang tidak disegel, maka hal itu harus disebut dalam berita acara dan bila ditemukan suatu penetapan dibawah tangan seperti tersebut dalam pasal 935 KUHPerd., maka hal itu diperlakukan juga sesuai dengan pasal 936 KUHPerd. itu 0 0 (ov. 75; KUHPerd. 932, 938, 943; Rv. 655-5 ; 657 dst., 675-8 .)"}, {"l": "RV", "p": "657", "b": "Bagian 1. Penyegelan.", "t": "Bila pada penyegelan terdapat surat-surat yang bersegel, maka pejabat tersebut harus menerangkan keadaan luar surat-surat itu, demikian pula mengenai segel dan judul surat, sekiranya ada; selanjutnya ia akan menandatangani sampulnya bersama dengan pihak- pihak yang hadir, jika mereka dapat menulis, dan menyebutkan hari dan jam, pada saat mana surat-surat itu dibuka olehnya. Ia menyebutkan segala sesuatu dalam berita acara yang ditandatangani oleh para pihak; bila para pihak menolak atau tidak mampu, maka hal itu harus diterangkan dalam berita acara tersebut. Bila dari judul surat atau hal lain ternyata, bahwa surat-surat itu tidak termasuk dalam warisan, maka surat-surat itu dilarang dibuka, atau bila orang yang meninggal dunia menunjuk pada suatu tuiuari tertentu, maka setelah memanggil Pihak-pihak yang berkepentingan, pejabat tersebut menyerahkan surat-surat itu dalam keadaan tertutup kepada mereka, jika tidak ada seorang pun mengajukan perlawanan terhadap hal itu; atau ia dapat juga memerintahkan agar surat-surat itu dalam keadaan tertutup diserahkan pada kantor karesidenan untuk kemudian diserahkan pada orang yang ternyata berhak. (Rv. 655-5 , 656, 675-8 .)"}, {"l": "RV", "p": "658", "b": "Bagian 1. Penyegelan.", "t": "Pada hari yang telah ditentukan dan tanpa suatu pemberitahuan, pejabat yang bertugas melakukan penyegelan membuka surat-surat yang tidak- dittajukan kepada orang-orang seperti termaksud dalam alinea terakhir pasal di muka; ia menerangkan keadaan surat-surat itu dan memerintahkan untuk sementara disimpan di kantor karesidenan dan kemudian diserahkan kepada pihak-pihak yang berkepentingan. Semuanya tidak mengurangi formalitas-formalitas seperti tersebut r dalam Bab XIII Buku Kedua KUHPerd. mengenai pembukaan surat-suratg . o wasiat yang bersifat rahasia. (KUHPerd. 940, 942; Rv. 657, 675-80.) s"}, {"l": "RV", "p": "659", "b": "Bagian 1. Penyegelan.", "t": "l i t a (s. d. u. dg. S. 1925-497.) Bila seseorang mengajukan perlawanan a l. eg terhadap penyegelan, atau bila ditemukan halangan-halangan, atau baik sebelum maupun pada saat penyegelan diajukan keberatan- keberatan, maka ketua raad van justitie dalam acara singkat w w memutuskan hal-hal tersebut, jika penyegelan dilakukan di daerah, di mana terdapat raad van justitie. w Bila penyegelan dilakukan di daerah lain, maka pejabat yang ditugaskan untuk itu segera mengirimkan turunan otentik dari berita acaranya kepada ketua raad van justitie untuk dimohonkan keputusannya. Dalam segala hal, penyegelan dihentikan dan oleh pejabat yang ditugaskan dengan penyegelan, diangkat penyiinpan-penyimpan di luar atau menurut keadaan juga di dalam rumah. Akan tetapi, pejabat tersebit dengan tidak mengurangi kewajibannya dapat menetapkan sebelumnya suatu penundaan, tidak mungkin untuk segera menyerahkan hal itu kepada keputusan ketua raad van justitie. (Rv. 55-10, 283 dst., 652, 655, 668, 669-80; RBg. 321-10; 322-200.)"}, {"l": "RV", "p": "660", "b": "Bagian 1. Penyegelan.", "t": "Bila dalam harta peninggalan tidak ditemukan barang-barang bergerak apa pun, pejabat yang ditugaskan melakukan penyegelan menyatakan hal itu dengan akta yang dibuatnya. Jika dalam harta peninggalan itu terdapat barang-barang bergerak, yang pemakaiannya diperlukan oleh penghuni-penghuni rumah, atau yang tidak dapat bersama-sama disegel, maka pejabat itu membuat berita acara yang memuat suatu uraian singkat mengenai barang-barang yang tidak disegel. Bila dalam harta peninggalan terdapat surat dagang yang mendatangkan kerugian jika dilakukan penyegelan, maka pejabat termaksud yang lalu membuat suatu uraian singkat tentang hal itu dalam berita acara dan menyerahkan surat tersebut kepada pihak yang berkepentingan. (F. 99; Rv. 655-50.)"}, {"l": "RV", "p": "661", "b": "Bagian 2. Perlawanan Terhadap Pengangkatan Segel.", "t": "Mereka yang berhak untuk hadir pada waktu dibuat daftar barang- barang, dapat mengajukan perlawanan terhadap pengangkatan segel- segel di luar kehadiran mereka. (Rv. 662, 666-30, 667, 673 dst.)"}, {"l": "RV", "p": "662", "b": "Bagian 2. Perlawanan Terhadap Pengangkatan Segel.", "t": "(s. d. u. dg. S. 1925-497.) Perlawanan terhadap pengangkatan segel- segel diajukan dengan pernyataan tertulis atau lisan oleh pelawan yang kemudian dimasukkan dalam berita acara penyegelan, pernyataan mana berisikan alasan-alasan dari perlawanan dan pilihan tempat tinggal di ibu kota dari daerah, dalam daerah mana penyegelan dilakukan, jika ia tidak bertempat tinggal di daerah itu. (KUHperd. 24 dst.; Rv. 55-10, 92, 655, 666.)"}, {"l": "RV", "p": "663", "b": "Bagian 3. Pengangkatan Segel.", "t": "r g Suatu segel hanya boleh diangkat setelah lewat tiga hari penuh sejak . o penyegelan dilakukan, kecuali dalam hal ada keharusan yang mendesak, s hal mana diputuskan oleh pejabat yang ditugaskan melakukan t penyegelan. (KUHPerd 1365; Rv. 55-10, 655-l0, 669.) l i a a l. eg"}, {"l": "RV", "p": "664", "b": "Bagian 3. Pengangkatan Segel.", "t": "Bila para ahli waris atau beberapa di antaranya belum cukup umur, dan tidak diwakili seperti tersebut dalam alinea kedua dari pasal w w 360 KUHPerd., maka pengangkatan segel tidak boleh dilakukan sebelum diadakan perwalian. (KUH-Perd. 386, 419, 429; Rv. 653-50; 654, 671.)"}, {"l": "RV", "p": "665", "b": "Bagian 3. Pengangkatan Segel.", "t": "w Semua orang, yang berdasarkan pasal 653 berhak untuk menyuruh melakukan penyegelan, dapat pula menuntut pengangkatan segel; kecuali mereka yang minta dilakukan penyegelan berdasarkan nomor 31 dari pasal tersebut. (KUHPerd. 386, 1008; Rv. 653-40 dan 50, 659, 661, 664, 666, 673.)"}, {"l": "RV", "p": "666", "b": "Bagian 3. Pengangkatan Segel.", "t": "(s.d.u. dg. S. 1925-497.) Formalitas-formalitas untuk dapat melakukan pengangkatan segel adalah: 10. tuntutan untuk itu yang dicatat dalam pemlintaan penyegelan dengan pilihan tempat tinggal di ibu kota dari daerah, dalam daerah mana penyegelan dilakukan, jika pemohon tidak bertempat tinggal di daerah itu danjika hal itu belum dilakukan; (KUHPerd. 24; Rv. 655-20, 662.) 2 . perintah dari pejabat yang ditugask- melakukan penyegelan dengan 0 0 penetapan hari dan jam pengangkatan segel; (Rv. 655- 1 , 669-3 .) 3 . suatu pemberitahuan untuk hadir pada pengangkatan segel yang harus disampaikan paling lambat dua puluh empat jam sebelum pengangkatan segel dilakukan, kepada suami atau istri yang masih hidup, kepada para ahli waris yang diperkirakan sepanjang dapat diketahui, kepada para pelaksana suatu wasiat, kepada kreditur yang minta atas dasar tuntutannya penyegelan dilakukan, dan kepada mereka yang mengajukan keberatan terhadap suatu pengangkatan segel di luar kehadirannya. (KUHPerd. 383, 452; Rv. 653, 662.) Pemberitahuan untuk para kreditur dan pelawan tersebut terakhir disampaikan di tempat yang mereka pilih dan selanjutnya pemberitahuan itu tidak perlu disampaikan kepada orang-orang …"}, {"l": "RV", "p": "667", "b": "Bagian 3. Pengangkatan Segel.", "t": "Suami atau istri yang masih hidup, para ahli waris yang diperkirakan, atau orang-orang yang mewakili mereka, dan para pelaksana wasiat, dapat hadir pada semua sidang tentang pengangkatan segel dan pendaftaran harta peninggalan. (KUHPerd. 1005.) Pejabat yang ditugaskan melakukan penyegelan bebas untuk menentukan, bahwa sesudah sidang pertama, orang-orang lain yang telah dipanggil menurut pasal terdahulu, pada sidang-sidang selanjutnya tidak r g . diizinkan kecuali secara bersama-sama dan atas biaya mereka, s o diwakili oleh seorang kuasa yang mereka sepakati tanpa penundaan, 1811.) l i t a atau jika tidak, akan diangkat oleh pejabat tersebut. (KUHPerd. a Bila salah satu dari mereka yang berkepentingan mengajukan l. eg kepentingan-kepentingan khusus atau yang bertentangan, maka ia , atas izin dari pejabat tersebut, dapat tetap hadir secara pribadi, ditunjuknya. (Rv. 666.) w w atau atas biaya sendiri diwakili oleh seorang kuasa khusus yang Pasal 668. w Bila pejabat yang ditugaskan melakukan penyegelan, setelah diaiukan tuntutan, menolak mengangkat segel-segel, maka sengketa itu diputus oleh ketua raad van justitie menurut cara seperti diuraikan dalam alinea kesatu dari pasal 659. …"}, {"l": "RV", "p": "669", "b": "Bagian 3. Pengangkatan Segel.", "t": "Berita acara pengangkatan segel berisikan: 10. penyebutan tentang hari dan jam dilakukannya pengangkatan segel; (Rv. 655-1 .) 20. nama dan tempat tinggal atau tempat tinggal yang dipilih dari orang yang menuntut pengangkatan segel; (Rv. 66, 666-l .) 0 0 3 . penyebutan perintah untuk mengangkat segel; (Rv. 666-2 .) 0 0 4 . penyebutan pemberitahuan seperti dimaksud oleh nomor 3 dari pasal 666; 5 . kehadiran dan semua tuntutan atau keterangan-keterangan dari para pihak; 6 . pengenalan segel-segel dan pendapat tentang segel-segel itu dalam keadaan utuh dan tidak rusak. Bila tidak demikian halnya, maka harus disebutkan keadaan yang ditemui dan tindakan-tindakan yang menurut pejabat yang bertugas melakukan penyegelan dianggap perlu dan telah diambilnya; (Sv. 6; KUHP 232.) 70. pengangkatan seorang notaris dan penaksir-penaksir, bila ada alasan-alasan untuk itu, yang dipilih oleh orang-orang yang berkepentingan, atau bila ada perselisihan, yang diangkat oleh pejabat tersebut, demikian pula pengambilan sumpah para penaksir oleh pejabat itu; (Rv. 283, 670, 675-10, 676.) 8 . pengajuan keberatan-keberatan dan perselisihan-perselisihan yang timbul di antara para pihak yang berkepentingan pada …"}, {"l": "RV", "p": "670", "b": "Bagian 3. Pengangkatan Segel.", "t": "Bila pada pengangkatan segel-segel, alasan untuk melakukan penyegelan tidak gugur, dan pada pengangkatan itu harus dilakukan pendaftaran harta peninggalan, maka segel-segel itu diangkat, tergantung dari pendaftaran yang dilakukan; pada akhir tiap sidang dilakukan penyegelan lagi atas barang yang belum didaftar, tetapi telah diangkat segelnya. (Rv. 655-10; 664, 671, 673, 675.) Pasal 671. r g . o Dalam hal alasan untuk penyegelan gugur sebelum pengangkatan segel s dilakukan atau pada saat sedang dilakukan, maka segel-segel itu i t a sekaligus diangkat dan berakhirlah kehadiran selanjutnya dari l a pejabat yang ditugaskan melakukan penyegelan pada pendaftaran harta l. eg peninggalan jika hal ini dilakukan. (KUHPerd. 386, 1008 dst., 1024, 1128; Rv. 655-10, 673.) w"}, {"l": "RV", "p": "673", "b": "Bagian 4. Inventarisasi Atau Pendaftaran Harta Peninggalan.", "t": "Semua orang yang menur-ut pasal 653 mempunyai hak untuk minta dilakukan penyegelan, dalam pengangkatan segel-segel berhak untuk minta inventarisasi atau pendaftaran harta peninggalan, kecuali mereka yang minta dilakukan penyegelan berdasarkan nomor 31 pasal tersebut. (KUHPerd. 1041, 1149-10; Rv. 665, 670, 674.)"}, {"l": "RV", "p": "674", "b": "Bagian 4. Inventarisasi Atau Pendaftaran Harta Peninggalan.", "t": "Bila pada pengangkatan segel-segel sampai dilakukan pendaftaran harta peninggalan, maka hal ini dilakukan dengan kehadiran orang- orang tersebut pada nomor 31 pasal 666, dan berdasarkan ketentuan- ketentuan itu segel-segel diangkat. (Rv. 667.)"}, {"l": "RV", "p": "675", "b": "Bagian 4. Inventarisasi Atau Pendaftaran Harta Peninggalan.", "t": "Dalam hal-hal di luar penyegelan, di mana oleh undang-undangjuga ditentukan suatu pendaftaran harta peninggalan, atau pendaftaran harta peninggalan setelah penyegelan diangkat, maka pendaftaran harta peninggalan itu, kecuali formalitas-formalitas dari semua akta umum atau di bawah tangan, memuat: (KUHPerd. 127, 386, 464, 783, 819, 1023, 1073, 1874, 1880; KUHD 346; F.91.) 10. nama kecil, nama dan tempat tinggal dari orang-orang yang hadir atau yang diwakili dan wakil-wakil mereka; dari orang-orang yang tidak hadir, bila mereka diketahui dan telah dipanggil, dan dari para penaksir; (KUHPerd. 390, 981, 990, 1078; Rv. 669-70, 674.) 2 . penyebutan tentang tempat, di mana pendaftaran itu dilakukan, dan barang-barang ditemukan; (Rv. 652.) 3 . uraian singkat tentang barang-barang dengan penyebutan penilaian dari barang-barang bergerak; 40. penyebutan tentang mata uang, demikian pula tentang keadaan dan bobot dari barang-barang emas dan perak; 5 . penyebutan tentang buku-buku catatan atau daftar-daftar, jika barang-barang itu ada. Bila pendaftaran dilakukan di hadapan r g seorang notaris, maka buku-buku atau daftar-daftar tersebut oleh notaris pada halaman pertama dan terakhir diberi tanda …"}, {"l": "RV", "p": "676", "b": "Bagian 4. Inventarisasi Atau Pendaftaran Harta Peninggalan.", "t": "Bila pada pendaftaran harta peninggalan terdapat keberatan-keberatan atau perselisihan-perselisihan, maka para pihak, juga notaris yang melakukannya, mengajukan permohonan kepada ketua raad van justitie, dalam daerah hukum mana pendaftaran harta peninggalan dilakukan, untuk memutuskan lebih dahulu dengan acara singkat. (RBg. 321-1 , 322-20 .) (s.d.u. dg. S. 1925-497.) Jika pendaftaran harta peninggalan dilakukan di luar daerah, di mana raad vaniustitie bersidang, maka notaris menguraikan dengan jelas keberatan-keberatan dan perselisihan-perselisihan dalam berita acara yang dibuat olehnya, yang setelah dibacakan, turut ditandatangani oleh para pihak, kecuali jika mereka tidak dapat menulis atau tidak mau menandatangani, hal harus disebutkan. Berita acara ini segera diajukan dengan suatu surat perkepada ketua tersebut yang segera tanpa suatu formahtas menjatuhkan keputusan yang dapat dilaksanakan lebih dahulu. (Rv. 283 dst., 290, 599, 668, 669-80.)"}, {"l": "RV", "p": "677", "b": "Bagian 5. Penjualan Barang-barang Bergerak.", "t": "Bila semua ahli waris sudah dewasa, dan bebas menguasai barang- barang mereka, maka penjualan barang-barang bergerak yang termasuk warisan dapat dilakukan di tempat dan dengan cara seperti disepakali oleh para pihak, asalkan kesepakan itu tidak bertentangan dengan peraturan-peraturan perundangundangan yang ada tentang lembaga pelelangan. (KUHPerd. 108, 330, 424 dst., 433 dst., 1012, 1034, 1070; Rv. 678, 680, 683, 695; S. 1908-189.)"}, {"l": "RV", "p": "678", "b": "Bagian 5. Penjualan Barang-barang Bergerak.", "t": "Jika harus dilakukan penjualan barang-barang bergerak, di mana diantara mereka yang berkepentingan terdapat anak-anak yang belum r g s . o dewasa, orangorang yang berada di bawah pengampuan atau orang-orang yang tak hadir, atau jika tidak terdapat kesepakatan di antara para l i t ahli waris, maka penjualan dilakukan di depan umum dengan a perantaraan kantor lelang menurut kebiasaan setempat. (AB. 15; KUHPerd. 389; Rv. 680, 684, 698.) a"}, {"l": "RV", "p": "679", "b": "Bagian 5. Penjualan Barang-barang Bergerak.", "t": "l. eg w w Akan tetapi bila semua orang yang berkepentingan sepakat, juga bila di antara mereka yang berkepentingan terdapat orang-orang yang belum w cukup umur atau yang berada di bawah pengampuan, maka raad van justitie, tergantung dari keadaan, dapat mengizinkan bahwa penjualan itu dilakukan dengan cara yang lain daripada yang diharuskan dalam pasal 389 dari KUHPerd. (Rv. 467 dst., 678, 685, 698.)"}, {"l": "RV", "p": "680", "b": "Bagian 5. Penjualan Barang-barang Bergerak.", "t": "Jika penjualan itu harus dilakukan di depan umum, maka ketua raad van justitie, atas permohonan salah satu pihak, dapat memerintahkan agar penjualan itu segera dilaksanakan. Ia menentukan jangka waktu, dalam mana penjualan itu harus dilakukan, jika para pihak tidak mencapai kesepakatan tentang hal itu. Ia juga memerintahkan bahwa tentang satu dan lain hal itu diberitahukan pada pihak -pihak yang berkepentingann lainnya dengan cara dalam waktu sedemikian rupa yang dipandang pantas sesuai dengan keadaan. (KUHPerd. 389; Rv. 677 dst., 681, 686.)"}, {"l": "RV", "p": "681", "b": "Bagian 5. Penjualan Barang-barang Bergerak.", "t": "Penjualan dilakukan, baik di luar hadimya maupun dengan dihadiii oleh pihak-pihak yang berkepentingan. (Rv. 680, 687.)"}, {"l": "RV", "p": "682", "b": "Bagian 5. Penjualan Barang-barang Bergerak.", "t": "Dalam hal timbul keberatan-keberatan, maka hal itu diputus oleh ketua raad van justitie lebih dahulu dengan acara singkat. (Rv. 283 0 0 dst., 688; RBg. 321-l , 322-20 .)"}, {"l": "RV", "p": "683", "b": "Bagian 6. Penjualan Barang-barang Tetap.", "t": "Bila barang-barang tetap merupakan kepunyaan orang-orang dewasa saja, yang menguasai dengan bebas barang-barang itu, maka barang- barang itu dapat dijual dengan cara sedemikian seperti mereka sepakati, asalkan kesepakatan itu tidak bertentangan dengan peraturan-peraturan perundang-undangan yang ada mengenai lembaga lelang. (KUHPerd. 108, 330, 424 dst., 430, 433 dst., 1012, 1034, 1070; Rv. 677, 684, 695; S. 1908-189.)"}, {"l": "RV", "p": "684", "b": "Bagian 6. Penjualan Barang-barang Tetap.", "t": "Bila harus dilakukan penjualan barang-barang tetap yang seluruhnya atau sebagian merupakan kepunyaan orang-orang yang belum cukup umur, orang yang berada di bawah pengampuan atau yang tak hadir, atau juga jika para ahli waris tidak mencapai kata sepakat, maka penjualan itu harus dilakukan dengan cara seperti diatur dalam pasal 395 KUHPerd.; akan tetapi dengan ketentuan, bahwa dalam hal tersebut terakhir campur tangan dari Balai Harta Peninggalan tidak diharuskan. (KUHPerd. 393 dst., 396 dst., 1076; Rv. 678, 686, 698.) r g"}, {"l": "RV", "p": "685", "b": "Bagian 6. Penjualan Barang-barang Tetap.", "t": "s . Jika semua orang yang berkepentingan mencapai kata sepakat, makao l i a bila di antara orang-orang yang berkepentingan itu terdapat juga t orang-orang yang belum cukup umur atau orang yang berada di bawah a pengampuan, raad van jusititie, tergantung dari keadaan, dapat l. eg mengizinkan bahwa penjualan barang-barang tetap itu dilakukan dengan cara sedemikian seperti ditentukan dalam pasal 396 KUHPerd. (KUHPerd. 506, 1076; Rv. 679.) Pasal 686. w w w Bila penjualan itu harus dilakukan di depan umum, maka atas permohonan salah satu pihak raad van justitie dapat memerintahkan, agar penjualan itu segera dilaksanakan. Bila para pihak tidak bersepakat tentang itu, raad van justitie menetapkan jangka waktu, dalam waktu mana penjualan harus dilaksanakan. Raad van justitie memerintahkan juga agar semuanya itu diberitahukan kepada orang-orang yang berkepentingan lainnya, dengan cara dan dalam waktu sedemikian sebagaimana dipandang pantas menurut keadaan. (KUHPerd. 395, 1076; Rv. 680.)"}, {"l": "RV", "p": "687", "b": "Bagian 6. Penjualan Barang-barang Tetap.", "t": "Penjualan dilakukan, baik di luar kehadiran maupun dengan kehadiran para pihak. (Rv. 681, 686.)"}, {"l": "RV", "p": "688", "b": "Bagian 6. Penjualan Barang-barang Tetap.", "t": "Dalam hal terjadi keberatan-keberatan, maka hal itu diputus oleh ketua raad van justitie lebih dahulu dengan acara singkat. (Rv. 283 dst., 682; RBg. 321-l0, 322-200.)"}, {"l": "RV", "p": "689", "b": "Bagian 7. Pembagian.", "t": "Tuntutan hukum terhadap pemisahan harta peninggalan diajukan pada raad van justitie dengan pemanggilan dalam bentuk biasa. (KUHPerd. 128, 405, 573, 1066 dst., 1072, 1652; Rv. 99, 102.)"}, {"l": "RV", "p": "690", "b": "Bagian 7. Pembagian.", "t": "Keputusan yang memerintahkan sua.u pemisahan harta peninggalan, memuat pengangkatan seorang notaris, di hadapan notaris mana pemisahan itu dilakukan, jika para yang berkepentingan tidak mencapai kata sepakat mengenai pilihan seorang notaris. Dalam keputusan itu dapat ditentukan hari, bilamana para pihak diharuskan hadir tanpa diperlukan suatu panggilan lagi. (KUHPerd. 1069, 1071 dst., 1074.)"}, {"l": "RV", "p": "691", "b": "Bagian 7. Pembagian.", "t": "Jika selama dilakukan pekerjaan pemisahan timbul keberatan- keberatan, maka notaris membuat berita acara tersendiri tentang hal itu yang memuat keterangan-keterangan dari para pihak. Suatu turunan dari berita acara itu harus dikirim olehnya kepada kepaniteraan, dan pihak yang paling siap menyuruh memanggil pihak lawannya di depan raad van justitie. (KUHPerd. 1075.)"}, {"l": "RV", "p": "692", "b": "Bagian 7. Pembagian.", "t": "Bila pada saat dilakukan pekerjaan pemisahan dipandang perlu untuk menjual barang-barang bergerak, maka hal itu dilaksanakan sesuai dengan ketentuan-ketentuan KUHPerd. dan bagian kelima bab ini. r g (KUHPerd. 389, 1076; Rv. 678 dst.) s . o"}, {"l": "RV", "p": "693", "b": "Bagian 7. Pembagian.", "t": "l i t a para notaris berkewajiban untuk memberikan turunan atau petikan dari a akta pemisahan pada tiap pihak, jika yang berkepentingan memintanya. l. eg (KUHPerd. 1885; Rv. 854 dst.)"}, {"l": "RV", "p": "695", "b": "Bagian 8. Hak Istimewa Untuk Pendaftaran Harta Peninggalan.", "t": "Jika harus ditaksanakan penjualan barang-barang bergerak atau barangbarang tetap dari warisan itu, maka si ahli waris yang menerima warisan dengan hak istimewa untuk pendaftaran harta peninggalan diwajibkan bersikap menurut aturan-aturan seperti dimuat dalam pasal 1034 KUHPerd. (KUHPerd. 393, 1029.)"}, {"l": "RV", "p": "696", "b": "Bagian 8. Hak Istimewa Untuk Pendaftaran Harta Peninggalan.", "t": "Bila seorang ahli waris yang menerima warisan dengan hak istimewa untuk pendaftaran harta peninggalan menolak atau lalal memberijaminan seperti diuraikan dalam pasal 1035 KUHPerd., maka setelah lewat delapan hari, untuk itu ia dapat dipanggil di depan pengadilan, dan jika ia tetap menolak atau tidak hadir, oleh raad van justitie diperintahkan pada Balai Harta Peninggalan untuk bertindak seperti diatur dalam alinea kedua dari pasal tersebut. (Rv. 99, 611 dst., 694, 697.)"}, {"l": "RV", "p": "697", "b": "Bagian 8. Hak Istimewa Untuk Pendaftaran Harta Peninggalan.", "t": "Gugatan-gugatan oleh ahli waris yang menerima warisan dengan hak istimewa untuk pendaftaran harta peninggalan, atas beban dari harta warisan, harus diajukan terhadap para ahli waris yang lain, dan jika ada ahli waris yang lain, atau bila gugatan itu diajukan oleh semua ahli waris, hal itu harus diajukan terhadap Balai Harta Peninggalan, sesudah balai tersebut, atas permohonan mereka yang berkepentingan, atau atas usul dari kejaksaan, diperintahkan oleh raad van justitie untuk menjadi kurator terhadap harta warisan yang telah diterima dengan hak istimewa untuk pendaftaran harta peninggalan. (KUHPerd. 1032-2 , 1127 dst.; Rv. 777.)"}, {"l": "RV", "p": "698", "b": "Bagian 9. Penjualan Barang-barang Bergerak Dan Barang Tetap yang", "t": "Tentang penjualan barang bergerak dan barang tetap yang termasuk dalam barang-barang tak terurus, balai harta peninggalan berkewajiban untuk memenuhi formalitas-formalitas seperti diatur dalam pasal 678, 679 dan 684. (KUHPerd. 1126 dst.; Rv. 777; Weesk 66.) r g"}, {"l": "RV", "p": "699", "b": "BAB III s . o PELEPASAN HARTA KEKAYAAN", "t": "(s.d.u. dg. S. 1906-348.) Pelepasan harta kekayaan terjadi jika debitur yang tidak mampu untuk membayar utang-utangnya, menyerahkan 451-20, 452, 749-10.) w w semua barang miliknya kepada para kreditur. (KUHPerd. 1131 dst.; Rv."}, {"l": "RV", "p": "700", "b": "BAB III s . o PELEPASAN HARTA KEKAYAAN", "t": "w (s.d.u. dg. S. 1906-348; S. 1908-522.) Pelepasan harta kekayaan memerlukan penerimaan secara sukarela oleh para kreditur. Pelepasan itu tidak mempunyai akibat lain daripada apa yang bersumber pada ketentuan-ketentuan dalam perjanjian yang dibuat antara mereka dan debitur. (KUH 591-3 .) 701. Ditailk kembali dg. S. 1906-348."}, {"l": "RV", "p": "702", "b": "BAB III s . o PELEPASAN HARTA KEKAYAAN", "t": "(s. d. u. dg. S. 1.906-348; S. 1908-522,) Pelepasan harta kekayaan tidak memindahkan hak milik pada para kreditur; pelepasan itu hanya memberi hak untuk menjual barang-barang itu untuk keuntungan mereka, dan untuk menarik hasil-hasil sampai terjadinya penjualan. Apa yang menjadi sisa dari hasil penjualan sesudah pemenuhan dari semua para kreditur, dibayarkan pada debitur. (Rv. 482, 558, 700.) 703-713. Ditarik kembali dg. S. 1906-348."}, {"l": "RV", "p": "714", "b": "Bagian 1. Sita Revindikasi Barang Bergerak.", "t": "(s.d.u. dg. S. 1908-522.) Barangsiapa mempunyai hak menuntut kembali atau hak reklame atas barang bergerak dapat menyitanya. (KUHPerd. 509 dst., 574, 582 dst., 1145, 1702, 1741, 1977; KUHD 230 dst., 240, 555; Rv. 763h dst., 924, 971; IR. 226; RBg. 260.)"}, {"l": "RV", "p": "715", "b": "Bagian 1. Sita Revindikasi Barang Bergerak.", "t": "Tidak dapat dilakukan penyitaan kecuali dengan surat perintah raad van justitie berdasarkan surat permohonan yang menyebutkan dengan singkat barang-barang yang dimohon untuk disita, dengan ancaman membayar biaya, kerugian dan bunga, baik terhadap pihak maupun terhadap juru sita yang telah melakukan penyitaan tanpa surat perintah semacam itu. (KUHPerd. 1365; Rv. 21, 60, 98, 460, 971.) r g"}, {"l": "RV", "p": "716", "b": "Bagian 1. Sita Revindikasi Barang Bergerak.", "t": "s . o hari Minggu. (Rv. 17, 283, 596.) l i a Ketua raad van justitie dapat mengizinkan melakukan penyitaan pada t a l. eg 717. Dihapus dg. s. 1938-360jis. 361, 276."}, {"l": "RV", "p": "718", "b": "Bagian 1. Sita Revindikasi Barang Bergerak.", "t": "w w Penyitaan akan dilakukan dengan cara seperti dalam penyitaan eksekusi barang-barang bergerak. (Rv. 443 dst.; 447, 453 dst.) w (s.d.t. dg. S. 1938-360jis. 361, 276.) Ketentuan dalam pasal 448b alinea pertama (1) berlaku juga dalam hal ini, bahwa nilai barang yang disita menjadi pengganti nilai tuntutan yang memerlukan penyitaan. Mengenai bunyi pasal 448b, lihat catatan kaki pasal 823b."}, {"l": "RV", "p": "719", "b": "Bagian 1. Sita Revindikasi Barang Bergerak.", "t": "Dalam waktu delapan hari maka penyitaan itu harus disusul dengan tuntutan pernyataan sah dan berharga atas sitaan itu. Tuntutan itu, begitu pula tuntutan pengangkatan sita, diajukan kepada hakim yang menetapkan sitaan yang bersangkutan. (Dg. S. 1908-522 alinea kedua diganti dengan tiga alinea berikut.) Gugatan yang mengandung tuntutan kepada orang yang tidak memegang/ menguasai barang yang akan disita diberitahukan kepada orang tersebut dalam waktu delapan hari setelah penyitaan dilakukan. (RBg. 322-160). Jika orang yang memegang/menguasai barang yang akan disita bertempat tinggal di luar tempat tinggal tergugat, maka tenggang waktu tersebut dalam alinea kedua diperpanjang menurut ukuran yang ditetapkan dalam pasal 1 , dengan pengertian bahwa jika keadaannya adalah seperti yang tersebut dalam alinea terakhir pemberitahuan dilakukan dalam waktu empat puluh hari. Jika tidak diajukan tuntutan sah dan berharga dan gugatan seperti tersebut dalam dua alinea terakhir tidak diberitahukan dalam waktu yang telah ditentukan, maka gugatan gugur demi hukum. (Rv. 10, 15, 17, 72, 99, 117, 241, 926, 972.) 0 0"}, {"l": "RV", "p": "720", "b": "Bagian 2. (RBg. 321-1 , 322-20 ) Penyitaan Atau Putusan yang Ada Di", "t": "(s.d.u. dg. S. 1908-522.) Ketua raad van justitie dapat memberikan kepada kreditur, yang secara singkat dapat menunjukkan isi gugatannya serta menunjukkan adanya kekhawatiran yang nyata bahwa debitur akan menggelapkan barang-barang bergeraknya dan barang- barang tetapnya, izin untuk menyita barang-barang bergerak debitur itu; ia juga dapat mendengamya lebih dahulu jika ada alasan- alasannya. (KUHPerd. 1131 dst.; Rv. 283, 299, 726, 761, 763h, 926, 971 dst., 1001; IR. 227; RBg. 261.)"}, {"l": "RV", "p": "721", "b": "Bagian 2. (RBg. 321-1 , 322-20 ) Penyitaan Atau Putusan yang Ada Di", "t": "Jika penyitaan diizinkan, maka besamya tagihan yang dijamin oleh sitaan itu disebutkan. (Rv. 302, 445, 729.)"}, {"l": "RV", "p": "722", "b": "Bagian 2. (RBg. 321-1 , 322-20 ) Penyitaan Atau Putusan yang Ada Di", "t": "r g Ketua dalam memberikan izin penyitaan sekaligus dapat memerintahkan s . o atas penyitaan tidak akan dijalankan jika tidak dijamin biaya, kerugian dan bunga, yang mungkin timbul karena penyitaan tersebut. l i t a Dalam hal itu, maka jaminan harus diberikan bersama-sama dengan perintah penyitaan dan orang yang barangnya disita, jika dianggap a bahwa uang jaminannya tidak mencukupi, dapat meminta agar ketua l. eg dalam sidang singkat menentukannya. Namun sementara itu penyitaan dapat dijalankan. (Rv. 283 dst., 611 dst., 725, 728.)"}, {"l": "RV", "p": "723", "b": "Bagian 2. (RBg. 321-1 , 322-20 ) Penyitaan Atau Putusan yang Ada Di", "t": "w w w Tata cara yang ditentukan pada penyitaan eksekusi barang bergerak berlaku juga dalam hal ini. (Rv. 435 dst., 443 dst., 454 dst., 971.)"}, {"l": "RV", "p": "724", "b": "Bagian 2. (RBg. 321-1 , 322-20 ) Penyitaan Atau Putusan yang Ada Di", "t": "Orang yang barang-barang bergeraknya diizinkan disita dapat segera mengajukan bantahan baik dengan sidang singkat di hadapan ketua maupun di hadapan sidang raad van justitie. (Rv. 283 dst., 725 dst.)"}, {"l": "RV", "p": "725", "b": "Bagian 2. (RBg. 321-1 , 322-20 ) Penyitaan Atau Putusan yang Ada Di", "t": "Pengangkatan sita diperintahkan bila oleh debitur diberikan jaminan yang cukup untuk tagihan yang menyebabkan diletakkannya sita, begitu pula, bila para pihak telah didengar secara singkat dan terbukti bahwa tuntutan tidak dan penyitaan dipandang tidak perlu. (Rv. 611 dst., 720 dst., 726, 763j.) Penyitaan batal demi hukum jika permohonan pernyataan sah dan berharga tidak diajukan dalam waktu delapan hari setelah dilakukan penyitaan itu. (Rv. 15, 17, 727, 926, 972; IR. 227; RBg. 261, 322- 160.) Dalam semua hal itu pemohon sita dihukum membayar biaya, kerugian dan bunga, apabila ada alasan untuk itu. (KUHPerd. 1246, 1365; Rv. 607 dst.)"}, {"l": "RV", "p": "726", "b": "Bagian 2. (RBg. 321-1 , 322-20 ) Penyitaan Atau Putusan yang Ada Di", "t": "Pelaksanaan surat-surat perintah dan penetapan-penetapan ketua dalam pasal-pasal terdahulu dapat diperintahkan dengan atau tanpa penjamin meskipun ada perlawanan, banding atau kasasi. (KUHPerd. 1828, 1830; Rv. 55, 287, 291, 402, 611.dst.)"}, {"l": "RV", "p": "727", "b": "Bagian 2. (RBg. 321-1 , 322-20 ) Penyitaan Atau Putusan yang Ada Di", "t": "Permohonan pernyataan sah dan berharga atas penyitaan diajukan kepada raad van justitie yang berwenang untuk menangani gugatan pembayaran utang yang dimohonkan sita. (Rv. 99, 926, 971 dst.; IR. 227; RBg. 261.)"}, {"l": "RV", "p": "728", "b": "Bagian 3. Penyitaan Di Tangan Pihak Ketiga.", "t": "Kecuali apa yang disebut dalam Bagian 2 Bab 11 Buku Kedua, maka setiap kreditur, atas kekuatan surat-surat otentik atau di bawah tangan, dapat meletakkan sita atas uang dan barang-barang yang dikuasai pihak ketiga dan yang merupakan utang kepada debitur atau yang merupakan kepunyaannya atau debitur dapat mengadakan perlawanan terhadap penyerahan barang-barang itu kepada kreditur. (KUHPerd. 1868, 1874; Rv. 477, 763h, 9715, 1001.) Bila tidak ada surat-surat, maka ketua raad van justitie, dalam r g . o daerah mana debitur bertempat tinggal, dan juga raad vanjustitie, s dalam daerah pihak-pihak ketiga bertempat tinggal, di mana uang dan izin untuk suatu penyitaan. (KUHPerd. 1571.) l i t a barang-barang berada, atas suatu surat permohonan, dapat memberi a Ketentuan-ketentuan dari pasal 722 berlaku juga dalam hal ini. l. eg Tetapi penyitaan itu dapat diangkat dengan pemberian jaminan sejumlah uang, untuk mana penyitaan dilakukan. (KUHPerd. 1388, 1434, w 1820; F. 229; Rv. 61 lv, 725, 7,03j, 812.) w"}, {"l": "RV", "p": "729", "b": "Bagian 3. Penyitaan Di Tangan Pihak Ketiga.", "t": "w Setiap pemberitahuan dari juru sita tentang penyitaan memuat uraian mengenai surat-surat atau penyebutan izin dari hakim, demikian juga mengenai jitmlah uang untuk mana penyitaan dilakukan. (Rv. 728 .) (S.d.u. dg. S. 1908-522.) Tuntutan-tuntutan yang tidak dipenuhi dan biaya-biaya yang dapat dibebankan pada debitur dirancang untuk sementara oleh hakim (Rv. 721.) (s.d.u. dg. S. 1925-497.) Pemberitahuan dari juru sita memuat juga pemilihan suatu tempat tinggal di ibu kota dari daerah, di mana pihak ketiga yang di bawah tangannya dilakukan penyitaan bertempat tinggal, jika orang yang meletakkan sita tidak bertempat tinggal di daerah itu. (KUHPerd. 24.) Semuanya diancam dengan kebatalan dari penyitaan yang telah dilakukan. (Rv. 8, 92, 444.)"}, {"l": "RV", "p": "730", "b": "Bagian 3. Penyitaan Di Tangan Pihak Ketiga.", "t": "Pemberitahuan mengenai penyitaan oleh para penerima atau para penyimpan kas-kas atau uang-uang umum, dilakukan kepada para pejabat atau mereka yang merupakan kepala kantor tersebut, dan oleh mereka pada aslinya ditandatangani sebagai mengetahui. Dalam hal ada penolakan, maka juru sita menyebutkan hal itu. (Rv. 750; S. 1853-70, 71.)"}, {"l": "RV", "p": "731", "b": "Bagian 3. Penyitaan Di Tangan Pihak Ketiga.", "t": "Dalam waktu delapan hari sesudah dilakukan penyitaan, maka pihak yang meletakkan sita, dengan ancaman kebatalan dari penyitaan itu, berkewajiban untuk memberitahukan penyitaan itu kepada debitur, dan melakukan pemanggilan terhadapnya untuk pernyataan-sah di depan raad van justitie, dalam daerah hukum mana ia bertempat tinggal, yang juga akan memeriksa tuntutan untuk mengangkat sita. (Rv. 17, 1001.) Dg. S. 1908-522 alinea kedua diganti dengan empat alinea berikut: Pihak yang meletakkan sita selanjutnya berkewajiban, juga dengan ancaman kebatalan dari penyitaan, untuk menyainpaikan turunan dari pemanggilan untuk pernyataan sah itu, kepada pihak-pihak ketiga yang terkena sita, dalam waktu delapan hari setelah pemanggilan itu diajukan. (Rv. 17.) Jangka waktu delapan hari seperti tersebut dalam alinea kesatu maupun alinea kedua tersebut, diperpanjang, sesuai dengan ukuran yang ditetapkan oleh pasal 10 jika debitur tidak bertempat tinggal dalam karesidenan yang sama, di mana sita dilakukan atau pihak ketiga yang terkena sita tidak bertempat tinggal dalam karesidenan yang sama, di mana pemanggilan untuk pernyataan sah diajukan. Bila debitur berada dalam keadaan seperti tersebut pada …"}, {"l": "RV", "p": "732", "b": "Bagian 3. Penyitaan Di Tangan Pihak Ketiga.", "t": "Jika tuntutan debitur akan pengangkatan sita dikabulkan, maka kreditur yang meletakkan sita dihukum untuk membayar biaya-biaya, kerugian-kerugian dan bunga-bunga, jika terdapat alasan untuk itu. (KUHPerd. 1365; Rv. 480, 763k.)"}, {"l": "RV", "p": "733", "b": "Bagian 3. Penyitaan Di Tangan Pihak Ketiga.", "t": "Bila penyitaan dinyatakan sah, maka keputusan itu diberitahukan kepada pihak ketiga, di bawah siapa sita diletakkan, dalam waktu satu bulan setelah keputusan diucapkan; bila pihak yang meletakkan sita membiarkanjangka waktu itu lewat, maka pembayaran-pembayaran yang dilakukan oleh pihak ketiga menjadi sah. (KUHPerd. 1388; Rv. 68, 437, 481.)"}, {"l": "RV", "p": "734", "b": "Bagian 3. Penyitaan Di Tangan Pihak Ketiga.", "t": "Bersamaan dengan pemberitahuan keputusan yang menyatakan sahnya penyitaan itu, pihak ketiga yang terkena sita dipanggil di depan hakim yang sama, untuk memberi keterangan tentang barang-barang dari si terhukum yang ia kuasai, atau yang merupakan utang padanya; selanjutnya untuk dibukum mengembahkan barang-barang yang ternyata kepunyaan si terhukum, atau menyerahkan untuk keperluan pelaksanaan keputusan hakim demi kepentingan pihak yang meletakkan sita, agar daripadanya dapat dipenuhi tuntutannya, dan untuk, bila tidak memberi keterangan seperti dimaksud di muka, dihukum untuk membayar sejumlah uang yang dituntut, untuk mana penyitaan telah dinyatakan benar, dengan bunga-bunga dan biaya-biaya, seakan-akan ia adalah benar-benar debitur. Dalam pemanggilan-pemanggilan ini berlaku jangka-jangka waktu biasa. (Rv. 10 dst., 99, 437, 481, 543, 739, 742, 744 dst., 747 dst.)"}, {"l": "RV", "p": "735", "b": "Bagian 3. Penyitaan Di Tangan Pihak Ketiga.", "t": "Keterangan-keterangan itu harus berdasarkan alasan-alasan dan berisikan suatu daftar dari uang-uang atau barang-barang bergerak yang dikuasai pihak ketiga yang terkena sita; penyebutan dari sebab dan jumlah utangnya; tentang pembayaran-pembayaran melalui rekening, jika pemah teijadi dan cara pelunesan utang, jika pihak ketiga yang terkena sita mengaku tidak mempunyai utang lagi, dan dalam semua penyitaan-penyitaan lain yang mungkin dilakukan di bawahnya. (KUHPerd. 1335, 1381; Rv. 543; 578.)"}, {"l": "RV", "p": "736", "b": "Bagian 3. Penyitaan Di Tangan Pihak Ketiga.", "t": "Keterangan itu diberikan pada hari yang telah ditentukan untuk menghadap dan dibuat secara tertulis, yang ditandatangani oleh pihak ketiga yang terkena sita atau oleh orang lain atas namanya. (KUHPerd. 1924; Rv. 106 dst.) r g"}, {"l": "RV", "p": "737", "b": "Bagian 3. Penyitaan Di Tangan Pihak Ketiga.", "t": "s . o l i a Bila pihak ketiga yang terkena sita memberi keterangan yang dianggap t benar, dan jika ia tidak menyangkal hukuman untuk menyerahkan, maka a semua biaya yang dikeluarkan olehnya harus diganti, dan ia tidak l. eg dapat diwajibkan untuk suatu penyerahan tanpa penggantian atau pengurangan daripadanya. (Rv. 738, 748.)"}, {"l": "RV", "p": "738", "b": "Bagian 3. Penyitaan Di Tangan Pihak Ketiga.", "t": "w w (s.d. u. dg. S. 1908-522.) Bila pihak ketiga yang terkena sita w menganggap mempunyai -alasan sah untuk membantah kewajiban pemberian keterangan itu, maka ia, jika alasan-alasannya ditolak, diperintahkan untuk sekali lagi memberikan keterangan pada hari yang ditentukan, dengan juga menghukum untuk membayar biaya-biaya. (Rv. 58 dst., 117, 737, 743.)"}, {"l": "RV", "p": "739", "b": "Bagian 3. Penyitaan Di Tangan Pihak Ketiga.", "t": "Bila ia pada hari pemangolan untuk memberi keterangan, atau pada hari seperti tersebut dalam pasal di muka, tidak memenuhi kewajibannya untuk memberi keterangan, maka terhadapnya dijatuhkan keputusan tanpa kehadirannya, dan iaatas kekuatan itu dihukum untuk membayar sejumlah uang yang dituntut, untuk mana diletakkan sita, ditambah dengan bunga-bunga dan biaya-biaya, seakan-akan ia adalah benar-benar debitur. (Rv. 78 dst., 107, 734, 737 dst., 740.)"}, {"l": "RV", "p": "740", "b": "Bagian 3. Penyitaan Di Tangan Pihak Ketiga.", "t": "Akan tetapi terhadap keputusan ini iadiperkenankan mengajukan perlawanan, asalkan menawarkan kesediaan untuk membayar biaya- biayanya; dan jika sudah diberikannya keterangan ternyata bahwa ia tidak berutang sesuatu apa pun pada omng, terhadap siapa sita itu dilakukan, atau ia tidak menguasai suatu apa pun kepunyaan debitur, maka ia dengan perlawanannya dibebaskan dari,hukuman untuk membayar sejumlah uang yang dituntut, untuk mana sita diletakkan. (Rv. 83 dst, 91, 741.)"}, {"l": "RV", "p": "741", "b": "Bagian 3. Penyitaan Di Tangan Pihak Ketiga.", "t": "Bila stas perlawanan ini ternyata bahwa yang ia kuasai atau utangnya kurang dari jumlah yang dituntut oleh pihak yang meletakkan sita, ia cukup membayar atau menyerahkan barang itu saja, ditambah dengan penggantian biaya-biaya, kerugian-kerugian dan bunga-bunga yang disebabkan oleh kelalaiannya"}, {"l": "RV", "p": "742", "b": "Bagian 3. Penyitaan Di Tangan Pihak Ketiga.", "t": "Pihak yang meletakkan sita dapat mengharuskan pihak ketiga, di bawah saja sita diletakkan, untuk memperkuat kebenaran dari keterangannya dengan sumpah. (KLTHPerd. 1929 dst., 1932.)"}, {"l": "RV", "p": "743", "b": "Bagian 3. Penyitaan Di Tangan Pihak Ketiga.", "t": "(s.d.u. dg. S. 1908-522.) Bila dalam sangkalan terhadap keterangan itu pihak ketiga yang terkena sita tidak dibenarkan, maka keterangan itu diperbaiki oleh hakim, dan pihak ketiga yang terkena sita dihukum untuk memenuhi atau menyerahkan apa yang telah ternyata menjadi utangnya atau yang ia kuasai. Ia dalam hal itu dapat juga dihukum untuk membayar biaya-biaya, kerugian-kerugian dan bunga-bunga. (KUHPerd. 1365; Rv. 735, 738 dst.) r g"}, {"l": "RV", "p": "744", "b": "Bagian 3. Penyitaan Di Tangan Pihak Ketiga.", "t": "s . o Uang yang ternyata kepunyaan pihak yang terkena sita yang ada pada l i a ketiga atau yang terutang oleh pihak ketiga pada pihak yang terkena t sita pada pihak yang meletakkan sita sampai jumlah tuntutan yang a dikabulkan dengan keputusan hakim tentang “pernyataan-benar” dan l. eg jika perlu, berdasarkan kekuatan keputusan hakim terhadap pihak ketiga yang terkena sita, ditagih dengan pelaksanaan keputusan. (Rv. 84, 474, 750c.) Pasal 745. w w w Dengan cara yang sama pihak ketiga yang terkena sita dapat dipaksa untuk menyerahkan barang-barang yang terkena sita kepunyaan pihak yang terkena sita yang ternyata ada pada pihak ketiga; barang-barang itu dijual dengan pelaksanaan keputusan hakim dan uangnya dibayarkan pada pihak yang meletakkan sita sampai suatu jumlah yang terutang padanya. (Rv. 443 dst., 446 dst., 473, 482 dst., 734.)"}, {"l": "RV", "p": "746", "b": "Bagian 3. Penyitaan Di Tangan Pihak Ketiga.", "t": "Perlawanan terhadap penyerahan hasil penjualan dari barang-barang yang telah disita, tidak diperkenankan. (Rv. 461 dst.)"}, {"l": "RV", "p": "747", "b": "Bagian 3. Penyitaan Di Tangan Pihak Ketiga.", "t": "Akan tetapi bila, sebelum dijatuhkan keputusan terhadap pihak ketiga yang terkena sita mengenai penyerahan, sesuai dengan tuntutan seperti tersebut dalam pasal 734, dilakukan beberapa penyitaan oleh para kreditur lain terhadap pihak ketiga yang terkena sita, maka keputusan hakim mengenai penyerahan itu dianggap untuk kepentingan semuanya, dan penyitaan atau hasil penjualan barang-barang itu dibagi di antara mereka, menurut jumlah dari tiap tuntutan yang dinyatakan benar, dengan cara seperti ditentukan dalam Bagian 3 Bab II Buku Kedua. Pihak ketiga yang terkena sita tidak diwajibkan untuk suatu penyerahan sebelum semua penyitaan yang dilakukan terhadapnya dinyatakan sah atau diangkat. (Rv. 482 dst.) Setiap orang yang meletakkan sita yang telah dinyatakan sah, jika orang-orang lain yang meletakkan sita tidak mengajukan tuntutan untuk pernyataan-sah menurut jangka-jangka waktu dalam hukum acara seperti diatur oleh reglemen ini, dapat campur dalam perkara yang sedang berjalan dan dapat menuntut secara khusus agar ditentukan suatu jangka waktu untuk penyelesaian, dan sesudah waktu itu lewat, penyitaan itu, sejauh tidak juga dinyatakan benar, dianggap sebagai telah diangkat. (Rv. 279, …"}, {"l": "RV", "p": "748", "b": "Bagian 3. Penyitaan Di Tangan Pihak Ketiga.", "t": "Jika para kreditur itu menganggap tidak dapat menerima keterangan yang diberikan oleh pihak ketiga yang terkena sita, atau yang diperbaiki oleh hakim, maka mereka, selain hak untuk campur dalam perkara yang sedang bergantung mengenai keterangan, dapat memanggil lagi pihak ketiga yang terkena sita untuk memberi keterangan dan tuntutan lebih lanut sesuai dengan pasal 734, asal untuk itu diajukan alasan-alasan dan alat-alat bukti lain daripada yang digunakan pada perkara yang telah selesai dengan para kreditur lain. (Rv. 279.)"}, {"l": "RV", "p": "749", "b": "Bagian 3. Penyitaan Di Tangan Pihak Ketiga.", "t": "(s.d.u. dg. S. 1938-622.) Sita ini tidak boleh diletakkan: 1 . atas barang-barang yang oleh undang-undang ditetapkan tidak r g boleh dilakukan penyitaan; (Rv. 451 dst., 763i; Aut. 2.) s . 2 . atas uang-uang yang diputus oleh hakim untuk keperluan o l i t perawatan; (KUHPerd. 225, 246, 321 dst., 329a.) a 30. atas uang-uang dan tunjangan-tunangan tahunan untuk perawatan, a l. eg yang oleh orang yang meninggalkan warisan atau oleh si pemberi, dinyatakan tidak boleh dilakukan penyitaan. Ketentuan sedemikian dapat dibuat oleh satu orang untuk kepentingan satu w w orang yang sama yang mendapat keuntungan mengenai uang-uang dan tunjangan-tunjangan tahunan sampai jumlah f 1000, - terhitung w 0 0 untuk satu tahun. (KUHPerd. 1429-3 ; F. 20-l .) Akan tetapi barang-barang, yang termasuk dalam nomor 20 dan 30, dapat disita untuk menagih utang yang harus dibayar atas penyerahan kebutuhan-kebutuhan hidup untuk keperluan orang, terhadap siapa dilakukan penyitaan. (KUHPer4. 1131 dst.; Rv. 452, 750a dst.)"}, {"l": "RV", "p": "750", "b": "Bagian 3. Penyitaan Di Tangan Pihak Ketiga.", "t": "Gaji-gaji dan pensiun-pensiun para pegawai dan para pemberi jasa tidak dapat disita, selain untuk bagian dan dengan cara seperti ditetapkan oleh peraturan-peratuan khusus untuk itu. (Rv. 481c, 730; F. 21; S. 1938-680.) Dengan S. 1908-522 ditambahkan pasal 750a-d."}, {"l": "RV", "p": "750A", "b": "Bagian 3. Penyitaan Di Tangan Pihak Ketiga.", "t": "Penyitaan seperti tersebut dalam bagian ini dapat diletakkan oleh kreditur terhadap barang-barang di bawah kekuasaan dirinya, atas kekuatan surat-surat otentik atau di bawah tangan. Akan tetapi penyitaan atas kekuatan surat-surat di bawah tangan tidak dapat dilakukan, kecuali sesudah dengan surat permohonan untuk itu mendapat izin dari ketua raad van justitie, dalam daerah hukum mana orang yang meletakkan sita bertempat tinggal. Sita dapat diangkat dengan pemberian jaminan yang cukup atau pembayaran sejumlah uang, untuk mana penyitaan dilakukan. (Rv. 728, 759, 763h, j; Cpt. 65 dst., S. 1926-28 pasal 9.)"}, {"l": "RV", "p": "750B", "b": "Bagian 3. Penyitaan Di Tangan Pihak Ketiga.", "t": "Sita diletakkan dengan pemberitahuan oleh juru sita pada pihak, terhadap siapa sitaan diletakkan. Pemberitahuan ini memuat uraian tentang surat-surat dan jika itu merupakan surat-surat di bawah tangan, juga penyebutan tentang izin dari hakim, selardutnya penyebutan secara cermat mengenai barang- barang atau tuntutan-tuntutan utang, dan mengenai jumlah uang, untuk mana penyitaan dilakukan. Tuntutan yang tidak dibayar dan biaya-biaya, yang dapat dijatuhkan terhadap orang yang terkena sita, dirancang untuk sementara oleh hakim. Pemberitahuan itu juga memuat panggilan untuk menghadap di depan raad vaniustitie, dalam daerah hukum mana pihak yang terkena sita bertempat tinggal atau, dalam hal termaksud dalam alinea ketiga (baca: kedua) pasal di muka, di mana pihak yang meletakkan sita bertempat tinggal, dalam hal ini untuk pernyataan-sah penyitaan itu dan penunjukan apa yang termaksud di dalamnya. Semuanya diancam dengan ancaman kebatalan penyitaan yang telah dilakukan. Raad van justitie yang ditunjuk oleh alinea keempat pasal ini memeriksa juga tuntutan untuk pengangkatan sita itu. Pasal 732, 749 dan 750 berlaku juga terhadap penyitaan ini. (Rv. 729, 731, 734 dst.) r g"}, {"l": "RV", "p": "750C", "b": "Bagian 3. Penyitaan Di Tangan Pihak Ketiga.", "t": "s . o l i a Hakim menjatuhkan satu keputusan terhadap seluruh tuntutan yang t diajukan dalam pemanggilan, kecuali ia berpendapat bahwa sebagian a daripadanya diputus lebih dahulu daripada yang lain, dalam hal mana l. eg hal itu dapat dilakukan. Bila tuntutan dikabulkan untuk seluruhnya atau sebagian, maka pihak w yang meletakkan sita berwenang untuk menagih apa yang harus dibayar padanya, yang menurut keputusan hakim termasuk dalam penyitaan w sesuai dengan ketentuan-ketentuan pasal-pasal 744, 745 dan 746. (Rv. 750b.) w"}, {"l": "RV", "p": "750D", "b": "Bagian 3. Penyitaan Di Tangan Pihak Ketiga.", "t": "Akan tetapi jika sebelum dijatuhkan suatu keputusan, atas kekuatan mana dapat dilakukan penagihan, dilakukan beberapa penyitaan oleh para kreditur lain terhadap pihak yang meletakkan sita, maka keputusan itu berlaku terhadap semuanya, dan selanjutnya berlaku pasal 747 dan 748, dengan ketentuan bahwa para kreditur akan memperoleh hak seperti dimaksud dalam pasal 748, bila mereka menyatakan bahwa lebih dari apa yang diletakkan sita oleh pihak yang meletakkan sita berada di bawah kekuasaannya atau harus dibayar olehnya. Demikian juga, bila sebelum sita dari pasal 750a diletakkan, terhadap kreditur yang dimaksud dalam pasal tersebut, sita diletakkan oieh para kreditur lain, maka apa yang ditentukan dalam pasal 747 dan 748 juga akan menguntungkan kreditur pertama. (Rv. 735.)"}, {"l": "RV", "p": "751", "b": "Bagian 4. Sita Gadai Untuk Sewa Dan Gann Rugi Usaha (Pacht).", "t": "(s.d.u., dg. S. 1908-522.) Pihak-pihak yang menyewakan gedung-gedung dan tanah-tanah milik, entah untuk itu dibuat perjanjian sewa- menyewa maupun tidak, dapat seger - tanpa perintah sebelumnya, dengan izin dari ketua raad van Justitie dan bahkan dari residentierechter, jika penyitaan harus dilakukan diluar daerah, di mana raad van justitie berada, atau juga tanpa izin sedemikian itu .satu hari sesudah perintah diberikan - menyuruh menyita, untuk sewa-sewa yam telah lewat dan tidak dibayar, barang-barang yang menurut pasal 1140 dan 1142 dari KUHPerd. dinyatakan terikat untuk uang-uang sewa. (KUHPerd. 1139-20, 1143, 1581, 1589; Rv. 15, 443, 451 dst., 461, 504, 559, 756, 926, 971 dst.; Cpt. 65 dst.; S. 1926- 28 jo. 29 pasal 9; S. 1905-137 pasal 23.)"}, {"l": "RV", "p": "752", "b": "Bagian 4. Sita Gadai Untuk Sewa Dan Gann Rugi Usaha (Pacht).", "t": "Barang-barang sejenis, sepanjang barang-barang itu kepunyaan penyewa-penyewa yang menyewa dari penyewa pertama, dapat disita untuk sewa-sewa yang terutang oleh penyewa pertama, akan tetapi mereka akan memperoleh pengangkatan sita, bila mereka dapat membuktikan bahwa mereka telah membayar tanpa tipu-muslihat. Mereka tidak dapat melakukan pembayaran-pembayaran lebih dahulu, kecuali sepanjang hal itu dilakukan sesuai dengan pasal 1582 dari Kitab Undang-undang Hukum Perdata. (KUHPerd. 1140, 1559.)"}, {"l": "RV", "p": "753", "b": "Bagian 4. Sita Gadai Untuk Sewa Dan Gann Rugi Usaha (Pacht).", "t": "Penyitaan dilakukan dengan cara yang sama dengan penyitaan atas r g barang-barang bergerak; orang, terhadap siapa penyitaan dilakukan, s . o dapat diangkat sebagai penyimpan, kecuali mengenai buah yang masih terikat keras pada tangkai dan akar; dalam hal ini harus diangkat 466.) l i t a seorang penyimpan yang cocok untuk itu. (Rv. 443 dst., 453 dst., a l. eg"}, {"l": "RV", "p": "754", "b": "Bagian 4. Sita Gadai Untuk Sewa Dan Gann Rugi Usaha (Pacht).", "t": "(s.d.u. dg. S. 1008-522.) Bila binatang-binatang, alat-alat kerja w w untuk , atau buah di ladang atau hasil-hasil lain dari pertanian yang sudah dipisahkan dari tanah atau barang-barang sedemikian yang w masih terikat keras pada tangkai dan akar, disita, maka residentierechter dalam daerah, di mana penyitaan dilakukan, atas permohonan dari pelaksana, dan sesudah mendengar atau memanggil secara cukup pihak yang terkena eksekusi, dapat mengangkat seorang atau lebih untuk mengusahakan penanaman dan pengumpulan buah. (Rv. 455.)"}, {"l": "RV", "p": "755", "b": "Bagian 4. Sita Gadai Untuk Sewa Dan Gann Rugi Usaha (Pacht).", "t": "Bila buah di ladang atau hasil-hasil pertanian lain, baik itu sudah dipisahkan dari tanah maupun masih terlekat keras pada tangkai dan akar, disita, maka berita acara penyitaan itu harus berisikan uraian mengenai tiap tanah, di atas mana barang-barang itu berada, jika mungkin isinya, letaknya dan sedikitnya dua batasan, demikian juga jenis dari buah atau hasil pertanian. (KUHPerd. 1140; Rv. 101, 456.)"}, {"l": "RV", "p": "756", "b": "Bagian 4. Sita Gadai Untuk Sewa Dan Gann Rugi Usaha (Pacht).", "t": "Barang-barang yang disita gadai tidak dapat dijual, kecuali sesudah penyitaan itu dengan keputusan raad van justitie, dinyatakan sah sesudah pemanggilan pihak, terhadap siapa sita diletakkan. Bila penyitaan, sesuai dengan pasal 1142 KUHPerd., dilakukan oleh pihak ketiga, maka ia juga akan dipanggil untuk mendengarkan pernyataan sah penyitaan itu. (Rv. 719, 725, 731, 760, 763, 971 dst., 1001.) (s.d.t. dg. S. 1908-522.) Penyitaan gugur demi hukum, jika tuntutan untuk pernyataan-sah tidak diajukan dalam waktu delapan hari sesudah sita itu diletakkan. (Rv. 17, 750b, 763c, 972.) (s.d.t. dg. S. 1908-522.) Bila seseorang, terhadap siapa sita diletakkan, bertempat tinggal di lain karesidenan daripada karesidenan di mana sita diletakkan, maka jangka waktu seperti tersebut dalam alinea di muka diperpanjang menurut ukuran yang ditetapkan dalam pasal 10 dengan ketentuan bahwa, jika terdapat keadaan seperti dimaksud dalam alinea terakhir dari pasal itu, pemberitahuan harus dilakukan dalam waktu empat puluh hari. (Rv. 17.)"}, {"l": "RV", "p": "757", "b": "Bagian 5. Penyitaan Terhadap para Debitur yang Tidak Mempunyai Tempat", "t": "(s.d.u. dg. S. 1908-522.) Setiap kreditur, sekalipun tidak mempunyai bukti tertulis, tanpa suatu perintah sebelumnya, tapi dengan izin dari ketua raad van justitie, dalam daerah hukum mana barang- barangnya berada, bahkan juga dari residentierechter di tempat- tempat yang terletak di luar daerah, dimana raad van justitie bersidang, dapat menyuruh melakukan sita atas barang-barang dari debitumya, jika ia tidak mempunyai tempat tinggal yang diketahui di g wilayah Indonesia. (AB. 3; Nedsch. 12; KUHPerd. 17, 1867; Rv. 443, r 504, 559, 751, 762, 763h dst., 926, 971 dst., 1001.) s . o"}, {"l": "RV", "p": "758", "b": "Bagian 5. Penyitaan Terhadap para Debitur yang Tidak Mempunyai Tempat", "t": "l i t a Formalitas-formalitas dalam reglemen ini yang ditentukan untuk sita a eksekutorial atas barang-barang bergerak, berlaku terhadap sita ini. l. eg (Rv. 443 dst.)"}, {"l": "RV", "p": "759", "b": "Bagian 5. Penyitaan Terhadap para Debitur yang Tidak Mempunyai Tempat", "t": "w w Pihak yang meletakkan sita adalah penyimpan demi hukum dari barang- barang yang disita, jika barang-barang itu berada di dalam w kekuasaannya; jika tidak, maka diangkat seorang penyimpan atas barang-barang itu. (KUHPerd. 1139-60 dan 70, 1147; Rv. 454.)"}, {"l": "RV", "p": "760", "b": "Bagian 5. Penyitaan Terhadap para Debitur yang Tidak Mempunyai Tempat", "t": "Ketentuan-ketentuan dari alinea kesatu pasal 756 berlaku juga untuk sita ini, dan tuntutan untuk pernyataan sah diajukan di depan raad van justitie, dalam daerah mana sita itu diletakkan. (Rv. 926, 972.)"}, {"l": "RV", "p": "761", "b": "Bagian 5. Penyitaan Terhadap para Debitur yang Tidak Mempunyai Tempat", "t": "(s.d.u. dg. S. 1915-299, 642.) Orang-orang tersebut dalam pasal 580 nomor 100 (baca: 90), jika perkaranya tidak mungkin ditunda, tanpa keputusan hakim terhadap mereka, atas perintah dari ketua raad van justitie, dapat disandera lebih dahulu karena suatu utang yang telah jatuh waktu dan dapat ditagitr, yang dibuatnya terhadap seorang warga negara Indonesia. (RBg. 321-10, 322-200) Formalitas-formalitas yang ditentukan dalam Bagian 2 Bab V Buku Kedua berlaku juga terhadap penyanderaan ini. (AB. 3; Rv. 584, 595 dst., 762, 971 dst.)"}, {"l": "RV", "p": "762", "b": "Bagian 5. Penyitaan Terhadap para Debitur yang Tidak Mempunyai Tempat", "t": "Pengangkatan sita dan penyanderaan tersebut dalam pasal 757 dan 761 dapat diminta dengan memberikan borg atau jaminan lain yang cukup untuk utangnya dengan bunga-bunga dan biaya. (Rv. 611 dst., 725, 763, 763j.)"}, {"l": "RV", "p": "763", "b": "Bagian 5. Penyitaan Terhadap para Debitur yang Tidak Mempunyai Tempat", "t": "Penyitaan dan penyanderaan berhenti demi hukum atau jaminan yang diberikan gugur, jika tuntutan untuk pernyataan-sah tidak diajukan dalam waktu delapan hari sesudah barang-barang disita, atau debitur disandera. (Rv. 15, 17, 757, 761 dst., 972.) (s.d.t. dg. S. 1908-522.) Hal yang sama berlakujuga terhadap penyitaan, jika itu dilakukan terhadap pihak ketiga, bila tuntutan untuk pernyataan-sah tidak diberikan kepada pihak yang menguasai barang-barang yang disita, dalam waktu delapan hari setelah tuntutan itu diajukan. (Rv. 750b, 756 dst., 763c, 971, 1001; RBg. 322-16 .) Dg. S. 1908-522 telah ditambahkan bagian sbb.:"}, {"l": "RV", "p": "763A", "b": "Bagian 6. Penyitaan Atas Barang Tetap.", "t": "(s.d.u. dg. S. 1938-276.) Dalam hal-hal seperti diatur dalam pasal 299, 720 dan 757 dapat juga diberi izin untuk meletakkan sita atas satu atau lebih barang-barang tetap yang ditunjuk kepunyaan debitur. Atas penyitaan ini bertaku ketentuan-ketentuan dari kalimat terakhir pasal 720 dan pasal 721, 722, 724, 725, 726 dan 727. r g s . o Ketua raad van justitie yang memberi izin untuk melakukan penyitaan dapat sekaligus memperpanjang jangka waktu delapan hari termaksud l i t a dalam pasal 725, atas permohonan dari pihak yang berkepentingan, sepanjang hal itu dipandang perlu, jika tidak mungkin dalam jangka a waktu itu diajukan tuntutan untuk pernyataan-sah sehubungan dengan l. eg jarak. (KUH Perd. 506 dst.; Rv. 17, 504, 54 1; IR. 227; RBg. 261; Cpt. 65 dst.; S. 1926-28jo. 29, pasal 9; S. 1905-137 pasal 23.)"}, {"l": "RV", "p": "763B", "b": "Bagian 6. Penyitaan Atas Barang Tetap.", "t": "w w w Penyitaan dilakukan dalam bentuk dan dengan akibat-akibat tersebut dalam pasal 506, 507 dan 508 dengan pengecualian, bahwa juru sita tidak perlu pergi ke tempat barang tetap yang disita berada, bahwa sebagai ganti dari bukti tersebut dalam pasal 506-20 harus disebut izin, atas kekuatan mana penyitaan dilakukan dan sebagai ganti penyebutan tempat tinggal yang dipilih seperti diharuskan dalam pasal 506-40, berita acara penyitaan harus memuat pilihan dari tempat tinggal pengacara pada raad van justitie, dalam daerah mana barang itu berada. Selanjutnya dalam berita acara penyitaan itu, dengan ancaman kebatalan, ditunjuk hakim, kepada siapa tuntutan untuk pernyataan- sah diajukan. (Rv. 723, 763c, 763f.)"}, {"l": "RV", "p": "463C", "b": "Bagian 6. Penyitaan Atas Barang Tetap.", "t": "Pihak yang meletakkan sita berkewajiban untuk, dalam waktu empat belas hari sesudah sita diletakkan, mendaftarkan tuntutan untuk pernyataan sah dengan memperlihatkan pemanggilan untuk menghadap di sidang di kepaniteraan dari majelis hakim seperti tersebut dalam berita acara, guna dimasukkan dalam daftar yang diadakan untuk itu. Bila pendaftaran yang diharuskan tidak mungkin dilakukan dalam waktu empat belas hari sehubungan dengan jarak, maka jangka waktu itu dapat diperpanjang dengan cara seperti ditentukan dalam alinea ketiga pasal 763a. Dalam hal itu, perpangan jangka waktu itu dicatat pada pengumuman penyitaan di daftar-daftar umum menurut pasal 507. (Rv. 719, 727, 731, 750b, 756, 763, 763b, 763f.)"}, {"l": "RV", "p": "763D", "b": "Bagian 6. Penyitaan Atas Barang Tetap.", "t": "Bila setelah penyitaan itu dinyatakan sah, dilanjutkan dengan pelaksanaan keputusan, maka penyitaan itu dinyatakan sebagai sita eksekusi dan penjualan dilakukan sesuai dengan ketentuan-ketentuan dari Bagian 2 Bab III Buku Kedua reglemen ini. (Rv. 997.) Jangka waktu dari pasal 510 dihitung mulai hari diberitahukannya keputusan hakim mengenai pernyataan sah. (Rv. 15, 504, 521, 763c.)"}, {"l": "RV", "p": "763E", "b": "Bagian 6. Penyitaan Atas Barang Tetap.", "t": "Dengan tidak mengurangi apa yang ditentukan dalam pasal 725, pihak yang meletakkan sita, yang tidak menyertai sita yang diletakkan dengan tuntutan untuk pernyataan sah dalam jangka waktu yang telah ditetapkan, berkewajiban, atas ancaman membayar biaya-biaya, kerugian-kerugian dan bunga-bunga, jika terdapat alasan untuk itu, untuk menyuruh mencoret pendaftaran dalam daftardaftar umum dalam waktu enam hari setelah jangka waktu untuk mengajukan tuntutan untuk pernyataan-sah lampau. (Rv. 732, 763b dst., 763f.)"}, {"l": "RV", "p": "763F", "b": "Bagian 6. Penyitaan Atas Barang Tetap.", "t": "Bila pihak yang meletakkan sita tidak memenuhi ketentuan dari pasal r g di muka, maka pendaftaran berita acara mengenai penyitaan dalam s . daftar-daftar umum dicoret atas kekuatan suatu keterangan daii o l i a panitera majelis hakim yang ditunjuk dalam berita acara penyitaan t sesuai dengan alinea kedua pasal 763b, yang berisikan, bahwa dalam a jangka waktu tersebut dalam pasal 763c atau dalam jangka waktu yang l. eg diperpanjang menurut alinea kedua pasal itu, padanya tidak terjadi pencatatan tentang diajukannya tuntutan untuk pernyataan-sah. juga: w w Pencoretan dari pendaftaran dalam daftar-daftar umum dapat terjadi w 1 . atas kekuatan dari izin untuk mencoret pendaftaran berdasarkan suatu permohonan untuk itu seperti ditentukan dalam pasal 1196 KUHPerd; (Rv. 763a.) 2 . atas kekuatan keputusan hakim yang inemuat perintah untuk mengangkat sita. (Rv. 763a jo. 725.) Di luar izin dari yang berkepentingan, pendaftaran tidak dicoret, kecuali dengan memperhatikan ketentuan dari pasal 437 (1) dengan perubahannya, bahwa tenggang waktu empat puluh hari sesudah pemberitahuan keputusan hakim diganti dengan tenggang waktu empat puluh hari sesudah keputusan hakim; (RBg. 322-181.) 3 . atas …"}, {"l": "RV", "p": "763G", "b": "Bagian 6. Penyitaan Atas Barang Tetap.", "t": "Akta kuasa untuk mencoret atau turunan otentik akta demikian, demikian pula keterangari-keterangan seperti tersebut dalam pasal di muka, tetap berada pada pegawai tersebut dalam alinea ketiga pasal 507 yang mendaftar berita acara penyitaan. Suatu kutipan dari keputusan hakim yang mengandung perintah untuk mengangkat sita atau keputusan hakim yang sudah mempunyai kekuatan hukum pasti yang memutuskan, bahwa pihak yang terkena sita dinyatakan dalam keadaan pailit atau tidak mampu untuk membayar utang-utangnya diserahkan kepada panitera atau kepada pegawai yang mewakilinya. (Rv. 763a jo. 725, 763f, 823.) Dg. S. 1939-547 telah ditambahkan bagan berikut:"}, {"l": "RV", "p": "764", "b": "BAB V PERHITUNGAN DAN PERTANGGUNGJAWABAN", "t": "l i t a Orang yang berkewajiban mengadakan perhitungan, akan tetapi lalai a mengadakan perhitungan, dipanggil oleh yang berkepentingan menurut l. eg jalan biasa dan perkaranya diperiksa menurut acara biasa. (KUHPerd. 105, 124, 307 dst., 332, 409i 449, 452, 465, 472, 476, 482, 485, 790, 1014, 1036, 1130, 1354, 1002; Rv. 1 dst., 99, 118, 775.) Pasal 765. w w w Dalam keputusan hakim yang memerintahkan untuk mengadakan perhitungan, ditetapkan waktunya, dalam waktu mana diangkat seorang hakim komisaris dan di hadapannya dilakukan perhitungan. (Rv. 55-60; 776.) Hakim-komisaris menetapkan hati diadakannya perhitungan. Bila pihak yang berkewajiban mengadakan perhitungan tidak datang menghadap pada hari yang telah ditetapkan, atau tidak mengadakan perhitungan, maka ia, bila hal ini dituntut, dipaksa dengan diadakan penyitaan dan penjualan barang-barangnya sampai sejumlah yang ditetapkan dalam keputusan hakim. Paksaan badan terhadapnya dapat juga diputtiskan oleh hakim, bila hakim memandang hal itu perlu. (Rv. 58, 445, 501, 580-30, 8 dan 100, 593.)"}, {"l": "RV", "p": "766", "b": "BAB V PERHITUNGAN DAN PERTANGGUNGJAWABAN", "t": "Jika suatu keputusan hakim dibatalkan pada tingkat banding yang semula menolak tuntutan untuk mengadakan perhitungan dan pertanggungjawaban, maka perhitungan diadakan dan dinilai di hadapan hakim yang telah memeriksa tuntutan itu, atau di hadapan hakim lain seperti ditunjuk oleh keputusan hakim tingkat banding. (Rv. 350 dst., 765.)"}, {"l": "RV", "p": "767", "b": "BAB V PERHITUNGAN DAN PERTANGGUNGJAWABAN", "t": "Perhitungan memuat penerimaan dan pengeluaran yang sebenamya.Dalam hal penerimaan melebihi pengeluaran, maka pihak, terhadap siapa perhitungan diadakan, dapat menuntut pada hakim-komisaris untuk mengeluarkan surat perintah agar membayar kelebihannya itu, tanpa adanya anggapan bahwa dengiln demikian ia telah membenarkan perhitungan. surat perintah ini dikeluarkan dalam bentuk seperti tersebut dalam pasal 435 (1). (Rv. 771.) (1) Mengenai bunyi pasal 435, lihat catatan kaki pasal 487."}, {"l": "RV", "p": "768", "b": "BAB V PERHITUNGAN DAN PERTANGGUNGJAWABAN", "t": "Perhitungan itu diberitahukan kepada pihak lawan, dan surat-surat yang digunakan sebagai bukti disampaikan dengan tanda texima atau dengan perantaraan kepaniteraan. (Rv. 765, 769 dst.) (s.d.t. dg. S. 1908-522.) Pemberitahuan ini dilakukan dalam suatu tenggang waktu yang ditetapkan oleh hakim-komisaris pada waktu diadakan perhitungan. (s.d.t. dg. S. 1908-522.) Dalam hal pemberitahuan tidak dilakukan dalam waktu tersebut, maka terhadap pihak yang berkewajiban mengadakan perhitungan berlaku alinea ketiga dan alinea keempat pasal 765. (Rv. 766, 770, 780.) r g"}, {"l": "RV", "p": "769", "b": "BAB V PERHITUNGAN DAN PERTANGGUNGJAWABAN", "t": "s Bila pihak, kepada siapa harus diadakan perhitungan, memilih. o l i a beberapa pengacara, namun mempunyai kepentingan saina, maka t pemberitahuan dan penyampaian tersebut di atas dilakukan hanya kepada pengacara yang tertua. a l. eg Akan tetapi jika mereka mempunyai kepentingan berbeda, maka pemberitahuan itu dilakukan tersendiri kepada masing-masing pengacara. (Rv. 768.) Pasal 770. w w w Dalam waktu satu bulan sesudah pemberitahuan, maka pihak, kepada siapa diadakan perhitungan, harus membenarkan perhitungan itu atau jika tidak, menyuruh memberitahukan kepada pihak lawan suatu surat bantahan, kecuab jika hakim-komisaris memberi waktu perpanangan lebih lama karena alasan-alasan keadilan. (Rv. 768.) Dalam tenggang waktu yang sama sesudah pemberitahuan dari surat bantahan, pihak yang mengadakan perhitungan bebas untuk menyuruh memberitahukan kepada pihak lawannya suatu risalah dari bantahan- balasan untuk membenarkan perhitungannya dan penyelesaian dari alasan-alasan yang diajukan terhadap itu. surat-surat kedua belah pihak disebut pada akhir risalah, dan diberitahukan dengan tanda terima atau dengan perantaraan kepaniteraan. (Rv. 768, 774.)"}, {"l": "RV", "p": "771", "b": "BAB V PERHITUNGAN DAN PERTANGGUNGJAWABAN", "t": "Paling lama empat belas hari setelah pemberitahuan bantahan-balasan atau segera setelah tenggang waktu yang diberikan untuk itu lampau, hakimkomisaris, atas permohonan dari pihak yang pahng siap, memerintahkan agar para pihak datang menghadap padanya pada hari dan jam yang ditetapkan dalam surat perintah, untuk menelaskan tentang soal-soal yang disengketakan, dan, jika mungkin, untuk mencapai kesepakatan tentang hal itu. Bila para pihak tidak dapat memperoleh kata sepakat, hakim-komisaris membuat berita acara mengenai semuanya itu; ia menyampaikan laporannya kepada sidang pengadilan pada hari yang ia tetapkan, dan para pihak diharuskan hadir di situ tanpa pemleritahuan lebih lanjut, agar dapat menyampaikan kepentingan mereka secara lisan. (Rv. 774.)"}, {"l": "RV", "p": "772", "b": "BAB V PERHITUNGAN DAN PERTANGGUNGJAWABAN", "t": "Dalam keputusan yang dijatuhkan bantahan tentang perhitungan dibuat seluruh jumlah penerimaan dan pengeluaran serta ditetapkan saldonya. (Rv. 350, 580-8-, 766, 774.)"}, {"l": "RV", "p": "773", "b": "BAB V PERHITUNGAN DAN PERTANGGUNGJAWABAN", "t": "Tidak diperkenankan perhitungan ulangan atas dasar kekeliruan perhitungan, penghapusan, pos-pos paisu atau rangkap, akan tetapi para pihak hanya bebas untuk menuntut pada hakim yang sama suatu perbaikan tentang itu. (Rv. 772.)"}, {"l": "RV", "p": "774", "b": "BAB V PERHITUNGAN DAN PERTANGGUNGJAWABAN", "t": "Bila orang, kepada siapa perhitungan harus diadakan, tidak memberitahukan surat bantahannya, atau kemudian, tidak mengajukan kepentingannya dengan cara seperti tersebut dalam pasal 771, maka keputusan dijatuhkan atas surat-surat yang diserahkan, tanpa diperkenankan perlawanan terhadap keputusan ini. (Rv. 83, 770 dst.) Bila, berdasarkan keputusan ini, pihak yang berkewajiban mengadakan g perhitungan mempunyai utang sejumlah uang, maka iadapat menahan uang r 1805.) s . o itu sampai dituntut, tanpa untuk itu terhutang bunga. (KUHPerd. 413,"}, {"l": "RV", "p": "775", "b": "BAB V PERHITUNGAN DAN PERTANGGUNGJAWABAN", "t": "l i t a a Semua orang yang berkewajiban mengadakan perhitungan dan ingin l. eg mengadakan perhitungan, karena penolakan atau kelalaian orang-orang yang berkepentingan untuk memeriksa dan menutup perhitungan itu, w dapat menyuruh memanggil mereka menurut cara yang biasa ke hadapan hakim yang dapat memanggil pihak yang berkewajiban mengadakan w perhitungan untuk mengadakan perhitungan. (Rv. 99, 764.)"}, {"l": "RV", "p": "776", "b": "BAB V PERHITUNGAN DAN PERTANGGUNGJAWABAN", "t": "w Pengangkatan hakim-komisaris, di hadapan siapa perhitungan dapat diadakan, dan pemeriksaan, pembantahan serta penutupan tersebut harus diproses dengan cara biasa, dan dengan memperhatikan peraturan-peraturan khusus dari bab ini. (Rv. 764 dst., 781.)"}, {"l": "RV", "p": "777", "b": "BAB V PERHITUNGAN DAN PERTANGGUNGJAWABAN", "t": "Akan tetapi jika para ahli waris yang menerima warisan dengan hak istimewa untuk pendaftaran harta peninggalan (beneficiaire erfgenamen) atau orang-orang lain yang berkewajiban mengadakan perhitungan ingin mengadakan perhitungan, dan bila hal itu harus diadakan, baik pada sejumlah besar orang yang berkepentingan, pada orang-orang yang berkepentingan yang hanya sebagian diketahui, maupun akhimya di antara mereka terdapat orang-orang yang tak hadir, maka orang-orang yang berkewajiban mengadakan perhitungan itu dapat mengajukan permohonan kepada hakim tersebut dalam pasal 775, agar menetapkan suatu tenggang waktu yang pantas untuk memanggil di hadapannya secara umum orang-orang yang berkepentingan yang diketahui dan yang tidak diketahui. (KUHPerd. 467, 1035 dst., 1130; Rv. 6-70, 779, 786.)"}, {"l": "RV", "p": "778", "b": "BAB V PERHITUNGAN DAN PERTANGGUNGJAWABAN", "t": "(s.d.u. dg. S. 1908-522.) Tenggang waktu itu, setelah mendengar pihak kejaksaan, ditetapkan menurut jarak yang diperkirakan dari tempat tinggal atau kediaman dari orang-orang yang berkepentingan, dan juga diperintahkan agar panggilan itu, menurut lebib atau kurang pentingnya perkara, baik sekaligus maupun berkali-kali dimuat dalam satu surat kabar atau lebih yang ditunjuk dalam perintah itu, dan juga agar turunannya ditempelkan pada tempat sidang majelis hakim. (KUHPerd. 467, 1036; Rv. 6-70, 777, 780 dst.)"}, {"l": "RV", "p": "779", "b": "BAB V PERHITUNGAN DAN PERTANGGUNGJAWABAN", "t": "Perintah itu juga, jika hakim memandang perlu dan dapat dilaksanakan, memuat keharusan untuk memanggil pihak-pihak yang berkepentingan yang diketahui dengan surat-surat edaran dengan perantaraan kepaniteraan; pemohon harus menunjuk untuk keperluan itu nama-nama dan tempat-tempat tinggal mereka dalam surat permohonannya. (F. 105; Rv. 777 dst., 782.)"}, {"l": "RV", "p": "780", "b": "BAB V PERHITUNGAN DAN PERTANGGUNGJAWABAN", "t": "Orang yang berkewajiban mengadakan perhitungan menyerahkan pehitungan dengan surat-suratnya di kepaniteraan dengan tanda terima selama tenggang waktunya untuk dilihat orang-orang yang berkepentingan, dan memberitahukan hal itu dalam surat panggilan, juga dalam surat-surat edaran, bila cara pangggilan ini juga diperintahkan oleh hakim. (Rv. 768, 770, 778 dst.) r g"}, {"l": "RV", "p": "781", "b": "BAB V PERHITUNGAN DAN PERTANGGUNGJAWABAN", "t": "s . o l i t a Pada hari yang ditetapkan, untuk memenuhi ketentuan dalam pasal 776, antara pihak-pihak yang datang menghadap ditempuh acara biasa dan a dengan memperhatikan ketentuan-ketentuan khusus dari bab ini. (Rv. l. eg 777 dst., 782 dst.)"}, {"l": "RV", "p": "782", "b": "BAB V PERHITUNGAN DAN PERTANGGUNGJAWABAN", "t": "w w Terhadap para yang berkepentingan lainnya, baik yang diketahui w maupun yang tidak diketahui, diputus verstek dan, untuk keuntungan mereka, diperintahkan panggilan kedua dengan cara seperti diatur dalam pasal 778 dan 779, dan terhadap tergugat-tergugat yang hadir, perkaranya ditahan sampai hari mengajukan lagi, untuk kemudian pemeriksaan dilanjutkan, dan terhadap lainnya dimohonkan putusan verstek untuk kedua kalinya. (Rv. 81, 107, 117, dst., 781, 783.)"}, {"l": "RV", "p": "783", "b": "BAB V PERHITUNGAN DAN PERTANGGUNGJAWABAN", "t": "Keputusan hakim yang dijatuhkan kemudian mengikat semua pihak, dan tidak diperkenankan mengajukan perlawanan. (Rv. 81 dst., 330, 771 dst., 774, 781 dst., 786.)"}, {"l": "RV", "p": "784", "b": "BAB V PERHITUNGAN DAN PERTANGGUNGJAWABAN", "t": "Bila harus diadakan ketentuan tentang tingkatan, maka hal itu dilakukan sesuai dengan peraturan-peraturan tentang hal itu yang terdapat dalam reglemen ini. (KUHPerd. 1037 dst.; Rv. 482 dst, 547 dst.)"}, {"l": "RV", "p": "785", "b": "BAB V PERHITUNGAN DAN PERTANGGUNGJAWABAN", "t": "Pihak-pihak yang berkewajiban mengadakan perhitungan, selama sengketa tentang ketentuan mengenai tingkatan itu bergantung, dapat membebaskan diri dari saldo yang ada padanya, dengan menyetor ke kas-penitipan (consignatiekas), dan penyetoran itu dapat juga diperintahkan atas tuntutan dari pihak-pihak yang berkepentingan. (KUHPerd. 1406-2 .)"}, {"l": "RV", "p": "786", "b": "BAB V PERHITUNGAN DAN PERTANGGUNGJAWABAN", "t": "Jika dalam hal-hal seperti dalam pasal 777, atas panggilan seperti diatur di situ, tidak seorang pun datang menghadap, maka diputus verstek, dan, untuk keuntungan mereka, diperintahkan panggilan guna menghadap di depan hakim untuk kedua kalinya dan bila atas panggilan itu tidak seorang pun datang menghadap, perhitungan ditutup, dan saldonya ditetapkan sedemikian yang menurut pandangan hakim adalah sah berdasarkan surat-surat. Terhadap keputusan hakim ini tidak diperkenankan mengajukan perlawanan. (Rv. 81, 783.)"}, {"l": "RV", "p": "787", "b": "BAB V PERHITUNGAN DAN PERTANGGUNGJAWABAN", "t": "Pada instruksi untuk balai-balai harta peninggalan ditentukan, apakah dan sampai di manakah peraturan-peraturan dalam bab ini berlaku terhadap balai-balai itu. (KUHPerd. 416, Weesk 78a, 80.)"}, {"l": "RV", "p": "800", "b": "Bagian 2. Penetapan Hak Milik (Eigendomsrecht) Atas Barang -barang", "t": "w w (s.d.u. dg. S. 1894 -262.) Seseorang yang menurut ketentuan dalam w pasal 621 dari KUHPerd. mohon untuk ditetapkan hak miliknya (eigendomsrecht) atas barang barang tetap yang ia kuasai (bezitten), mengajukan surat permohonan disertai alasan-alasan dengan melampirkan surat-surat yang bersangkutan pada raad van justitie, dalam daerah man, terletak barang-barang itu yang memuat sifat dari barang-barang itu, letaknya, berdasarkan pembagian kadaster, atau jika hal itu tidak pemah terjadi, menurut pengukuran oleh pengukur tanah pemerintah, nomor pendaftaran verponding, nama yang dikenal untuk barang itu, dan jika mengenai milik-milik tanah, disebutkan luasnya. Bersama itu ditentukan pengacaranya dan dipilih tempat tinggal dalam jarak sepuluh pal dari gedung tempat raad van justitie bersidang. Ketentuan dalam alinea kedua pasal 106 berlaku di sini."}, {"l": "RV", "p": "801", "b": "Bagian 2. Penetapan Hak Milik (Eigendomsrecht) Atas Barang -barang", "t": "(s.d,u. dg. S. 1894-262.) Raad van justitie memerintahkan agar permohonan itu diumumkan tiga kali berturut-turut dengan waktu antara paling sedikit satu bulan dalam surat kabar resmi, juga dalam surat kabar lain yang ditunjuk oleh raad vaniustitie, dan juga agar surat permohonan dengan surat-surat yang diajukan ditempatkan di kepaniteraan untuk dilihat oleh mereka yang berkepentingan. (Ov. 105; RBg. 322-210.) Pengumuman-pengumuman di kedua surat kabar harus memuat: 1 . nama kecil, nama, juga tempat tinggal yang sebenamya dan yang dipilih dari pemohon; (KUHPerd. 17, 24 dst.; Rv. 800.) 2 . isi pokok dari permohonan, dengan Penyebutan raad van justitie, yang kepadanya diajukan permohonan itu; 3 . penyebutan dari sifat barang-barang, tentang batas-batasnya, tentang nama yang sekiranya dikenal, tentang nomor pendaftaran verponding, tentang daerah, afdeeling, distrik, kota, lingkungan atau kampung, desa atau desa-desa, di mana barang-barang itu terletak, tentang letaknya menurut pembagian kadaster, atau sepanjang hal itu tidak pemah terjadi, menurut pengukuran oleh pengukur tanah pemerintah, tentang nama pengukur tanah Pemerintah, oleh siapa pengukuran dilakukan, dan tentang …"}, {"l": "RV", "p": "802", "b": "Bagian 2. Penetapan Hak Milik (Eigendomsrecht) Atas Barang -barang", "t": "Terhadap permohonan itu tidak dapat diambil keputusan sebelum lewat tiga bulan setelah terjadi pengumuman terakhir dalam surat kabar resmi. (Rv, 800, 807,) r g . o Sampai akhir tenggang waktu itu setiap orang yang berkepentidgan s berwenang untuk mengajukan perlawanan untuk dikabulkannya permohonan itu. (Rv. 803, 806 dst.) l i t a a l. eg"}, {"l": "RV", "p": "803", "b": "Bagian 2. Penetapan Hak Milik (Eigendomsrecht) Atas Barang -barang", "t": "Perlawanan itu dilakukan dengan suatu keterangan yang diberikan atas nama pelawan oleh seorang pengacara di kepaniteraan raad van w w justitie, dan dicatat dalam daftar untuk keperluan itu. (Rv. 802.) Perlawanan itu, dengan ancaman gugur, dalam waktu satu bulan diikuti w dengan pemanggilan dalam bentuk biasa yang diberitahukan kepada Pemohon secara pribadi atau di tempat kediaman yang sebenamya atau yang dipilih. (KUHPerd. 17, 24 dst.)"}, {"l": "RV", "p": "804", "b": "Bagian 2. Penetapan Hak Milik (Eigendomsrecht) Atas Barang -barang", "t": "Bila penguasa (bezit) dari pemohon dibantah oleh pelawan, perkaranya akan diperiksa Seperti terhadap tuntutan-tuntutan dalam perkara hak menguasai, dan permohonan untuk Pernyataan-hak milik ditolak jika pemohon ternyata tidak menguasai barang-barang yang disengketakan, dengan tidak mengurangi hak dari yang tersebut terakhir untuk mengajukan gugatan mengenai barang-barang itu dengan cara biasa. (KUHPerd. 529 dst., 548 dst., 550 dst.; Rv. 103 dst., 191 .)"}, {"l": "RV", "p": "805", "b": "Bagian 2. Penetapan Hak Milik (Eigendomsrecht) Atas Barang -barang", "t": "(s.d. u. dg. S. 1908-522.) Bila pelawan mengaku pemilik barang- barang yang disengketakan, perlawanannya dianggap tidak beralasan, jika ia tidak dapat membuktikan hak miliknya. (Rv. 118 dst.)"}, {"l": "RV", "p": "806", "b": "Bagian 2. Penetapan Hak Milik (Eigendomsrecht) Atas Barang -barang", "t": "Jika dalam tenggang waktu yang ditetapkan dalam pasal 802 tidak ada perlawanan yang tercatat di kepaniteraan, atau juga jika perlawanan yang diajukan dinyatakan gugur karena keterangan itu tidak diikuti oleh pemanggilan dalam tenggang waktu yang ditetapkan, demikian pula jika para pelawan dinyatakan tidak beralasan dalam perlawanan yang diajukan, maka raad van justitie mengambil keputusan tentang pernyataan-hak milik setelah mendengar pihak kejaksaan. (Rv. 803, 805.)"}, {"l": "RV", "p": "807", "b": "Bagian 2. Penetapan Hak Milik (Eigendomsrecht) Atas Barang -barang", "t": "(s.d.u. dg. S. 1894-262,) Dalam bal permohonan dikabulkan, keputusan hakim itu diumumkan dalam surat kabar resmi dan surat kabar yang ditunjuk oleh raad van justitie berdasarkan pasal 801 alinea kesatu. (RBg. 322-210.) Pengumuman-pengumuman itu memuat, selain yang diatur dalam ayat kedua pasal 801 tentang pengumuman-pengumuman permohonan, penyebutan bahwa permohonan itu dikabulkan, demikian pula hari ditandatanganinya keputusan hakim. Pengumuman-pengumuman itu diulang sesudah lewat tiga bulan. Panitera raad van justitie menglnm segera suatu turunan dari keputusan hakim kepada kepala daerah, di mana barang-barang itu berada, untuk diumumkan setempat."}, {"l": "RV", "p": "808", "b": "Bagian 2. Penetapan Hak Milik (Eigendomsrecht) Atas Barang -barang", "t": "(s.d. u. dg. S. 1894-262.) Selama waktu satu tahun sesudah terjadi pengumuman terakhir dalam surat kabar resmi, setiap orang yang berkepentingan yang perlawanannya didasarkan atas sarana-sarana seperti diajukan pada perlawanan menurut alinea kedua pasal 802, r g yang belum diputus dengan kekuatan bukum yang tetap, dapat s . o mengajukan perlawanan dengan cara seperti diatur terhadap keputusan- keputusan hakim dengan verstek. l i t a Bila sebelum tenggang waktu tersebut lampau tidak terjadi a perlawanan, juga bila perlawanan yang diajukan dalam tenggang waktu l. eg itu dinyatakan tidak beralasan, maka panitera raad van justitie, sesudah tenggang waktu untuk naik banding atau untuk mengajukan w w kasasi lampau, jika raad telah mengadakan keputusan dalam tingkat terakhir, memberi surat keterangan sebagai bukti bahwa terhadap w keputusan hakim mengenai pernyataan hak milik tidak dapat diajukan perlawanan lagi, dan keputusan hakim ini diumumkan oleh atau atas nama yang berkepentingan di kantor penyimpanan hipotek-hipotek, dalam daerah mana barang-barang itu berada, dengan menyerahkan keterangan tersebut di atas seperti diatur oleh KUHPerd. (KUHPerd. 622; Rv. 83 dst., 334, 402.)"}, {"l": "RV", "p": "809", "b": "Bagian 3. Penawaran Pembayaran, Dan Penitipan Di Pengadilan Atau", "t": "Berita acara tentang penawaran pembayaran harus memuat barangbamng atau jenis uang-uang yang ditawarkan. (KUHPerd. 1405-70, 1406-30; Rv. 675-40.) Berita acara itu dilakukan pada kreditur sendiri atau di tempat tinggalnya dan di dalamnya disebutkan jawaban dari kreditur atau, jika ia tidak ada, dari orang, kepada siapa tawaran itu dilakukan. (KUHPerd. 1405-6 ; Rv. 3.) Jawaban ini ditandatangani oleh kreditur, atau jika ia tidak ada, oleh orang yang memberi jawaban. Jika kreditur atau orang yang memberi jawaban menolak untuk menandatangani, atau menerangkan tidak dapat menandatangani, maka hal itu harus disebut dalam berita acara yang diberi tanggal dan ditandatangani oleh notaris atau juru sita, dan daripadanya harus dibuat turunan yang diserahkan kepada kreditur sendiri atau tempat tinggalnya semuanya atas ancaman kebatalan. (Rv. 8, 92.) Dalam hal notaris atau juru sita tidak menemukan baik kreditur maupun seseorang dari sesama penghuni di tempat tinggalnya, maka ia berbuat seperti ditentukan dalam pasal 3. (KUHPerd. 1395, 1470.)"}, {"l": "RV", "p": "810", "b": "Bagian 3. Penawaran Pembayaran, Dan Penitipan Di Pengadilan Atau", "t": "Bila barang atau uang yang ditawarkan tidak diterima, maka debitur boleh menitipkannya di pengadilan, asal memperhatikan apa yang diatur diBagian 2 Bab IV Buku Ketiga KUHPerd. (KUHPerd. 1404 dst., 1406, 1412; Rv, 591-2 , 812.)"}, {"l": "RV", "p": "811", "b": "Bagian 3. Penawaran Pembayaran, Dan Penitipan Di Pengadilan Atau", "t": "(s.d.u. dg. S. 1908-522.) Gugatan untuk pernyataan-sah atau pernyataan-batal dari penawaran-penawaran yang diajukan atau dari penitipan diperiksa seperti gugatan biasa. Jika penawaran atau penitipan demikian itu terjadi dalam perkara yang bergantung, maka hal itu diperiksa sebagai suatu insiden. (KUHPerd. 1405-60, 1406; Rv. 99, 106, 241, 926 jo. RO. 116f huruf f.)"}, {"l": "RV", "p": "812", "b": "Bagian 3. Penawaran Pembayaran, Dan Penitipan Di Pengadilan Atau", "t": "Penitipan sukarela atau penitipan di pengadilan tidak mengurangi r hak-hak yang timbul dari penyitaan yang telah dilakukan jika hal itu g . o telah terjadi, dan diberitahukan oleh juru sita kepada orang-orang s yang meletakkan sita dan pelawan-pelawan. (KUHPerd. 1406, 1409, 1412; Rv. 68, 435, 477 dst., 728 dst., 811.) l i t a a"}, {"l": "RV", "p": "814", "b": "Bagian 4. Kuasa Dari Perempuan yang Kawin.", "t": "Bila si isteri menerangkan bahwa suaminya yang sebenamya dapat memberi kuasa, tetapi menolaknya, maka raad vanjustitie tidak dapat memutuskan atas permohonan itu, kecuali si suami telah didengar atau telah dipanggil dengan cukup. (KUHPerd. 21, 112; Rv. 821.) (s.d. u. dg. S. 1908-522.) Dalam hal tempat tinggalnya jauh, maka pendengaran si suami dapat diperintahkan pada residentierechter."}, {"l": "RV", "p": "815", "b": "Bagian 4. Kuasa Dari Perempuan yang Kawin.", "t": "Bila dalam suatu perkara terhadap seorang perempuan yang kawin, suami dipanggil untuk mewakili isterinya, dan ia tidak datang menghadap, maka hakim memberikan kuasa itu. (KUHPerd. 105, 110 dst.)"}, {"l": "RV", "p": "816", "b": "Bagian 5. Pencegahan Perkawinan.", "t": "Pada pencegahan perkawinan, perlawanan dilakukan dengan suatu akta yang diberitahukan oleh juru sita baik kepada pegawai catatan sipil maupun kepada pihak, terhadap siapa perlawanan itu ditujukan. (KUHPerd. 52, 70, 71-60; BS. 59; Rv. 1 dst., 8.) Akta ini memuat alasan-alasan dari perlawanan itu, dan kedudukan yang memberi hak kepada pelawan untuk menentang perkawinan itu. (KUHPerd. 60 dst., 67 dst.) Akta itu juga memuat tempat tinggal yang dipilih di tempat atau tempat-tempat, di mana perkawinan seharusnya dilangsungkan; semuanya diancam dengan kebatalan. (KUHPerd. 24, 53, 59 dst., 76.)"}, {"l": "RV", "p": "817", "b": "Bagian 5. Pencegahan Perkawinan.", "t": "Tuntutan untuk pengangkatan perlawanan itu diajukan dengan cara biasa dan diperiksa oleh raad van justitie, dalam daerah mana telah dipilih tempat tinggal dan atas tuntutan itu harus secepatnya diambil keputusan. (KUHPerd. 66, Rv. I dst., 816.) Bila dipilih tempat tinggal dalam daerah lebih dari satu raad van justitie, maka gugatan diajukan pada salah satu, tergantung pada pilihan penggugat. (KUHPerd. 24, 53, 66, 70, 76.)"}, {"l": "RV", "p": "818", "b": "Bagian 5. Pencegahan Perkawinan.", "t": "(s.d.u dg S. 1908-522.) Terhadap keputusan hakim yang memutus tuntutan untuk pengangkatan perlawanan terhadap perkawinan, dapat segera diajukan permohonan banding dan diajukan dalam waktu tiga puluh hari sesudah keputusan. (Rv. 15, 68, 83 dst., 334, 338, 385 dst., 402 dst., 435.) r g"}, {"l": "RV", "p": "819", "b": "Bagian 6. Pemisahan Barang-barang.", "t": "l i t a a Tuntutan untuk pemisahan barang-barang tidak dapat diajukan oleh si l. eg isteri taripa kuasa dail ketua raad van justitie, dalam daerah hukum mana suaminya bertempat tinggal. (Rv. 824; KUHPerd. 110, 111-20, 186 dst., 243.) w w"}, {"l": "RV", "p": "820", "b": "Bagian 6. Pemisahan Barang-barang.", "t": "w Untuk tujuan itu, isteri yang meminta pemisahan barang-barang harus mengajukan surat permohonan yang memuat alasan-alasan kepada raad van justitie, dan R.v.J. dengan surat perintah yang ditempatkan di atas surat permohonan tersebut memerintahkan agar para pihak datang menghadap padanya pada hari dan jam tertentu secara pribadi agar jika mungkin, mereka dengan perantaraannya dapat mengusahakan suatu permufakatan. Turunan dari surat perintah ini dan surat permohonan diberitahukan kepada si suami paling lambat tiga hari sebelum hari yang ditetapkan untuk datang menghadap. (Rv. 15, 234, 821, 833.) (s.d.u. dg. S. 1923-287, 441.) Jika terdapat alasan yang sah tentang halangan untuk datang menghadap, maka ketua raad van justitie pergi ke rumah suami-isteri itu. (s.d,t, dg. S. 1923-247, 441; s.d.u. dg. S. 1925-497.) Jika suami- isteri bertempat tinggal di luar daerah di mana raad vanjustitie berada, maka ketua raad van justitie dapat menunjuk residentierechter atau, jika ia tidak ada, berhalangan atau tidak di tempat, kepada kepala pemerintahan setempat untuk melakukan perbuatan-perbuatan seperti tersebut dalam alinea kesatu dan ketiga. Pejabat yang ditunjuk harus membuat berita acara …"}, {"l": "RV", "p": "821", "b": "Bagian 6. Pemisahan Barang-barang.", "t": "Bila si isteri pada hari yang ditetapkan tidak datang menghadap tanpa suatu alasan yang sah, permohonannya dianggap gugur. Bila kedua pihak datang menghadap dan tidak dapat dipertemukan, atau jika si suami, setelah dipanggil dengan cukup, tidak datang menghadap, maka ketua raad van justitie memberi kuasa yang diminta kepada si isteri untuk menggugat ke hadapan raad van justitie. (KUHPerd. 112; Rv. 813 dst., 834.) (s.d.t. dg. S. 1908-522.) Tentang hasil dari kehadiran itu dibuat berita acara. alinea keempat dan kelima diubah dg. S. 1923-281, 441, dan ditarik kembali dg. S.192,5-678io. S. 1926-63.)"}, {"l": "RV", "p": "822", "b": "Bagian 6. Pemisahan Barang-barang.", "t": "r g s . o (s.d.u. dg. S. 1908-522.) Tuntutan untuk pemisahan diberitahukan dengan jalan pengumuman-pengumuman yang ditempelkan di ruang sidang l i a dan pada gedung, di mana raad van justitie bersidang, dan dimuat di t salah satu surat kabar di karesidenan, atau jika tidak ada, di karesidenan terdekat. a l. eg Pengumuman-pengumuman itu harus memuat: 10. penyebutan dari tuntutan akan pemisahan barang-barang dan hari ditandatanganinya; w w 2 . nama-nama, nama-nama kecil, pekerjaan dan tempat tinggal suami- w isteri. Penempelan dilakukan oleh juru sita, dan ia membuat berita acara tentang hal itu. (KUHPerd. 187 dst.; Rv. 1 dst., 8 dst., 10 dst., 282, 824, 826.)"}, {"l": "RV", "p": "823", "b": "Bagian 6. Pemisahan Barang-barang.", "t": "(s.d.u. dg. S. 1908-522.)Dndakan-tindakan yang boleh dilakukan sehubungan dengan pasal 190 KUHPerd. adalah penyegelan, pencatatan harta kekayaan dan penilaian barang-barang, penyitaan jaminan atas barang-barang bergemk bersama atau kepunyaan isteri, dan penyitaan jaminan atas barang-barang tetap bersama, sesuai ketentuan-ketentuan dari sepuluh pasal berikut. (KUHPerd, 215; Rv. 241, 652 dst., 672 dst., 675-30, 720 dst., 763a dst., 763h dst., 824, 840.) Dg. S. 1908-522 ditambahkan pas. 823a-j."}, {"l": "RV", "p": "823A", "b": "Bagian 6. Pemisahan Barang-barang.", "t": "Izin untuk mengambil satu atau lebih tindakan ini dapat diminta kepada ketua raad van justitie pada saat atau sesudah mengajukan surat permohonan seperti dimaksud dalam pasal 820. Ketua raad van justitie memberi izin itu, jika ia menganggap perlu, dapat memanggil si suami. (Rv. 283, 720, 763a, 840; KUHPerd. 190.)"}, {"l": "RV", "p": "823B", "b": "Bagian 6. Pemisahan Barang-barang.", "t": "(s.d.u. dg. S. 1938 – 360 jis. 361, 276) Terhadap penyitaan atas barang-barang bergerak bersama atau atas barang-barang bergerak dari isteri berlaku kalimat kedua alinea kesatu dan ketiga pasal 444, pasal 447, 448, 448a, 448b, 451, 452, ahnea kesatu pasal 454, 456, 457, 458 dan 726 (1) (s.d.t. dg. S. 1938-360jis. 361, 276.) Ketentuan dalam alinea kesatu pasal 448b berlaku dalam pengertian bahwa nilai barang yang disita menggantikan jumlah dari tuntutan, untuk mana sita diletakkan. Sebagai penyimpan-penyimpan dari barang itu tidak boleh diangkat pihak yang meletakkan sita, juga anak-anak atau cucu-cucu dari suami-isteri kecuali dengan persetujuan tegas dari pihak yang terkena sita. (RV. 454, 823, 840.) (1) Bunyi pasal-pasal yang dimaksud adalah sbb:"}, {"l": "RV", "p": "444", "b": "Bagian 6. Pemisahan Barang-barang.", "t": "(s.d.u. dg. S. 1,908-522.) Segera pada hari berikutnya dapat dilakukan penyitaan. Demikian pula bila penyitaan itu dilakukan dengan eksplot (surat perintah) juru sita, maka yang ada pada pemegangnya merupakan surat perintah untuk melaksanakan penyitaan itu. (Rv. 439, 443, 463.) Hal yang sama akan dilakukan selain daripada tindakan seperlunya yang harus dilakukan pada eksplot-eksplot biasa, juga tambahan perintah yang harus dipenuhi untuk kepentingan apa penyitaan itu dilakukan, (Rv. 8, 443.) (s.d.u. dg. S. 1925-280, 497; S. 1939-288; S. 1940-3.) Juru sita akan dibantu oleh panitera- panitera dari raad van justitie, bila penyitaan itu r g dilakukan di salah satu tempat yang letaknya tidak lebih dari sepuluh pal dari tempat kedudukan pengadilan yang bersangkutan, dan bila letak tempat . o penyitaan lebih dari sepuluh pal, dibantu oteh pejabat yang ditunjuk oleh s asisten residen. Juru sita yang bersangkutan dalam berita acaranya akan l i t a menyebutkan jabatan dan tempat kediaman pejabat yang telah memberikan bantuannya; juru sita dan pejabat yang hersangkutan akan menandatangani a berita acara yang asli dan salinannya. (RO. 64, 119; KUHPerd. 994; BS. 13; l. eg Rv. 19, 446 dst., …"}, {"l": "RV", "p": "447", "b": "Bagian 6. Pemisahan Barang-barang.", "t": "w w (s.d.u. dg. S. 1908-522.) Segera atau paling lambat pada hari berikutnya, w juru sita dengan dihadiri oleh pejabat seperti yang disebutkan pada alinea terakhir pasal 444, melakukan penunjukan lebih lanjut dan secara khusus tentang barang-barang yang akan disita dan dalam beiita acara yang akan dibuatnya secara rinci menguraikan barang-barang yang disita dengan menyebutkan jumlah, berat dan ukuran menurut jenisnya masing-masing; pihak yang mohon penyitaan tidak dibolehkan hadir pada waktu penyitaan itu sedang dilakukan. (Rv. 446, 449 dst., 454, 463, 469, 471, 561, 660.)"}, {"l": "RV", "p": "448", "b": "Bagian 6. Pemisahan Barang-barang.", "t": "Bila semua pintu dalam keadaan tertutup, atau pembukaan pintu ditolak, begitu pula pada penolakan pembukaan kamar atau salah satu perkakas rumah tangga dan demikian pula pada ketidakhadiran orang yang dikenakan sita atau tidak terdapat seseorang yang mewakilinya, maka pejabat yang mendampingi juru sita dalam melakukan pekerjaannya, berwenang untuk membuka pintu-pintu rumah dan perkakas-perkakas nimah tangga. (KUHP 429.) (s.d.u. dg. S. 1938-360jis. 361, 276.) Juru sita yang bersangkutan dalam berita acara pelaksanaan sita itu, akan menyebutkan (melaporkan) semua hal yang telah terjadi dengan dihadiri oleh pejabat berdasarkan empat pasal berikut di bawah ini. (Rv. 446, 469, 1000.)"}, {"l": "RV", "p": "448A", "b": "Bagian 6. Pemisahan Barang-barang.", "t": "(s.d.t. dg. S. 1938-360jis. 361, 276.) Bila terdapat dugaan yang beralasan, bahwa barang-barang yang harus disita berada di suatu tempat, yang disewa dari pihak ketiga atau secara lain sehingga tempat itu dapat digunakan, dan dalam keadaan sedemikian rupa sehingga untuk memasuki tempat yang bersangkutan dibutuhkan bantuan pihak ketiga, maka pejabat yang bertugas memberikan hantuan kepada juru sita yang bersangkutan, jika terjadi penolakm untuk membuka pintu-masuk demi kepentingan orang yang kena sita, berwenang menyuruh pihak ketiga itu membuka pintu yang diperlukan untuk menjalankan penyitaan itu. Penolakan pembukaan pintu tersebut sama artinya dengan ketidakhadirannya atau orang yang diberinya kuasa setelah diberikan peringatan secara tertulis untuk membuka pintu untuk keperluan penyitaan. Pihak ketiga ini wajib memberi keterangan tentang tempat yang disewa atau tempat yang dengan cara lain dapat digunakan untuk kepentingan itu kepada juru sita, bila diperlihatkan bukti sebagai alasan dari pengenaan sita yang bersangkutan. Barangsiapa menyewakan atau dengan cara lain memberikan sesuatu untuk dipakai, seperti yang disebutkan dalam alinea-alinea sebelumnya, dan dalam hal itu …"}, {"l": "RV", "p": "448B", "b": "Bagian 6. Pemisahan Barang-barang.", "t": "r g . o (s. d. u. dg. S. 1938 360 jis. 361, 276.) Bila pihak ketiga berkewajiban s seperti ymg disebutkan dalam alinea kedua, ketiga dan keempat dari pasal l i t a sebelum ini, ia dapat dihukum untuk membayar bunga dan biaya yang telah dikeluarkan untuk itu dari sitaan yang telah dikenakan padanya. (Rv. 7181, 823b.) a l. eg Kerusakan yang menimbulkan kerugian, yang diderita oleh pihak ketiga akibat pembukaan pintu dengan Cara yang tidak semestinya, diberi pembayaran ganti rugi oleh orang yang kena sita, bila hal ini dilakukan bukan atas kesalahan w w pihak ketiga ini, kecuali bila orang yang kena sita ini dapat mempertanggungiawabkannya kepada seseorang yang melakukan hal itu dengan w cara yang bertentangan dengan penyitaan itu bila terdapat alasan-alasan yang menguatkan hal itu. (KUHPerd. 1367; Rv. 611, 614.) Juru sita dan pejabat seperti yang disebutkan dalam pasal 448, wajib merahasiakan isi daftar dan surat-surat seperti yang disebutkan dalam alinea ketiga pasal sebelumnya; akan tetapi, asalkan terhadap orang yang kena sita itu tidak diadakan permintaan permintaan lainnya kecuali hanya untuk memenuhi kewajiban dalam melakukan tugas penyitaan. (KUHP 322.)"}, {"l": "RV", "p": "451", "b": "Bagian 6. Pemisahan Barang-barang.", "t": "Dengan tidak mengurangi larangan dan pembatasan dalam ketentuan-ketentuan terhadap penyitaan barang-barang dengan ketentuan-ketentuan khusus berdasarkan peraturan perundang-undangan yang telah ada atau yang akan diadakan, penyitaan barang-barang bergerak sama sekali tidak dapat dilaksanakan terhadap: (KUHPerd. 1786; Cpt. 65 dst.; S. 1926-28 jo. 29 pasal 9; Aut. 21.) 1 . barang-barang yang menurut ketentuan dalam perundang-undangan dinyatakan sebagai barang-barang tidak bergerak karena tujuan pemakaiannya; (KUHPerd. 507 dst.; Rv. 493.) 2 tempat tidur dan kain alasnya yang digunakan oleh orang yang kena sita dan oleh anak anaknya yang bersama-sama berkediaman dalam satu rumah, begitu pula tidak dilakukan sita terhadap pakaian yang digunakan oleh orang yang kena sita beserta anak-anaknya; 30. pakaian seragam yang digunakan dalam dinas ketentaraan menurut dinas dan pangkatnya; 4 . Alat/perkakas kerja tukang dan pekerja/ buruh yang merupakan kepunyaan pribadi dalam perusahaannya; (Rv. 452-21; IR. 97, 113, 1971; RBg. 138, 211.) 5 . persediaan bahan makanan dan minuman untuk memenuhi kebutuhan keluarga selama sebulan. (KUHPerd. 1131; Rv. 452, 749-11, 1000.)"}, {"l": "RV", "p": "452", "b": "Bagian 6. Pemisahan Barang-barang.", "t": "Begitu juga tidak dapat dilakukan penyitaan terhadap: 10. buku-buku yang berkaitan dengan pekerjaan (profesi) orang yang kena sita yang bernilai sejumlah dua ratus gulden; 2 . peralatan dan perkakas kerja, yang digunakan untuk mengajarkan suatu ilmu atau mem pelajari suatu kesenian dan ilmu, yang nilainya sejumlah uang yang sama seperti di atas, menurut pilihannya sendiri; (Rv. 451- 40.) 30. dan akhirnya dua ekor sapi atau hewan ternak atau seekor kuda atau dua ekor babi atau dua ekor domba atau empat ekor kambing, semua itu atas pilihan orang yang kena sita, disertakan jerami dan makanan hewan-hewan itu yang cukup untuk persediaan satu bulan. (Rv. 454; IR. 97, 113, 1970; RBg. 138, 211.) Akan tetapi dapat pula dilakukan sita terhadap barang-barang yang disebutkan dalam pasal ini, bila: 10. barang-barang untuk kebutuhan hidup sehari-hari, yang diberikan oleh orang lain kepada orang yang kena sita itu; (KUHPerd. 1149-51.) 20. uang yang seharusnya menjadi hak orang yang membuat barang-barang, yang mengadakan perbaikan terhadap barang-barang atau yang telah dijual kepada orang lain; (KUHPerd. 1139-30 dan 50.) 30. barang-barang tidak bergerak itu disewakan dan dipahkan atau telah 751, …"}, {"l": "RV", "p": "454", "b": "Bagian 6. Pemisahan Barang-barang.", "t": "s . Juru sita mengangkat seorang yang diberi tugas penyimpanan yang o berkemampuan baik. l i t a Sebagai penyimpan tidak akan diangkat orang yang kena sita atau istrinya, a keluarga sedarah atau semenda sampai pada derajat keenam dalam keluarga, l. eg begitu juga tidak akan diangkat seorang pembantu rumah tangganya; akan tetapi sebaliknya dapat diangkat suami (istri)nya, keluarga sedarah atau semenda dari orang-orang seisi rumah dengan persetujuan orang yang kena w w sita itu dan kesukarelaan dan kesanggupan orang-orang yang bersangkutan seperti tersebut di atas. (KUHPerd. 1330 dst., 1739; Rv. 456, 458 dst., 753; IR. 197; RBg. 212.) Pasal 456. w Berita acara dapat dibuat dengan segel di tempat kejadian itu; aslinya dan tembusannya harus ditandatangani oleh penyimpan (orang yang diserahi tugas penyirnpanan). Bila penyimpan tidak dapat memberikan tanda-tangan, hal itu harus dicatat dalam asli dan tembusannya. Tembusan dari berita acara ini ditinggalkan pada penyimpan. (Rv. 444, 453 dst., 755.)"}, {"l": "RV", "p": "457", "b": "Bagian 6. Pemisahan Barang-barang.", "t": "Tembusan dari berita acara penyitaan harus ditandatangani oleh orang yang kena sita di tempat atau di ruahnya; bila ia tidak hadir di tempat atau di rumahnya, penandatanganan ini dilakukan oleh penyimpan yang diangkat itu, yang selanjutnya dengan segera akan mengusahakan tanda-tangan dari yang berkepentingan dalam hal ini. (Rv. 3, 453 dst.)"}, {"l": "RV", "p": "458", "b": "Bagian 6. Pemisahan Barang-barang.", "t": "Seorang yang diserahi tugas penyimpan tidak diperbolehkan memakai barang- barang yang disita itu, begitu pula menyewakan atau meminamkannya, dengan sanksi tidak akan dibayarkan upah simpan dan pembayaran ganti rugi dan bunga dan kalau memang dianggap perlu dengan menjalani paksaan badan. (KUHPerd. 535, 556, 1239 dst., 1365, 1712, 1739; Rv. 454 dst., 459, 580-40 dan 101.)"}, {"l": "RV", "p": "823C", "b": "Bagian 6. Pemisahan Barang-barang.", "t": "Dalam sita tidak termasuk barang-barang bergerak yang oleh pihak yang terkena sita ditunjuk sebagai tidak termasuk dalam barang- barang bersama atau bukan kepunyaan si isteri, semuanya, kecuali yang menjadi hak masing-asing, dapat diserahkan pada keputusan dari hakim baik berdasarkan pasal 823d maupun berdasarkan penerapan alinea terakhir dari pasal 823e. (RV. 284, 452 dst., 840.)"}, {"l": "RV", "p": "823D", "b": "Bagian 6. Pemisahan Barang-barang.", "t": "Seseorang yang menerangkan pemilik dari barang-barang yang disita atau sebagian daripadanya, dapat mengajukan keberatan terhadap penyitaan itu dengan cara seperti dimaksud dalam pasal 460 (l). (RV. 823, 823e, 840.) (1)Bunyi pasal yang dimaksud adalah sbb:"}, {"l": "RV", "p": "460", "b": "Bagian 6. Pemisahan Barang-barang.", "t": "Barangsiapa mengaku dirinya sebagai pemilik barang-barang yang disita, atau sebagian barang-barang itu, dapat mengadakan perlawanan dengan suatu gugatan kepada orang yang kena hukuman atau orang yang barang-barangnya dikenakan sita, dan gugatan itu harus ditandatangani oleh Petugas yang diserahi tugas penyimpanan barang-barang itu; hal itu semua dengan sanksi batal demi hukum. (s.d. u. dg. S. 1908-522.) Raad van justitie, yang mempunyai wilayah kekuasaan di tempat penyitaan itu dilakukan, akan memberikan putusannya mengenai hal tersebut diatas. Penggugat yang dinyatakan kalah dalaml perkara, akan dijatuhi hukuman berdasarkan alasan-alasannya, untuk membayar ganti rugi terhadap semua kerugian dan bunganya kepada pelaksana penyitaan yang bersangkutan (KUHPerd. 150, 155, 164, 1140,1143, 114r, &t., 1341,1365; KUHD 230, 244; RV. 442, 454, 435 dst., 607.) r g"}, {"l": "RV", "p": "823E", "b": "Bagian 6. Pemisahan Barang-barang.", "t": "s Keputusan hakim yang memuat penolakan terhadap tuntutan akan. o i pemisahan memerintahkan juga pengangkatan penyitaan. l t a Pada pengabulan terhadap pemisahan, sita berakhir dengan pembagian a l. eg sungguh-sungguh dari barang-barang bersama atau dengan pemberian pada isteri barang-barangnya. (RV. 823b, 827, 840; KUHPerd. 191, 194.)"}, {"l": "RV", "p": "823F", "b": "Bagian 6. Pemisahan Barang-barang.", "t": "w w w Terhadap sita atas barang -barang tetap bersama berlaku ketentuan dalam alinea kesatu pasal 763b. Pasal 726 berlaku juga pada sita ini. (RV. 506 dst., 823g, 840.)"}, {"l": "RV", "p": "823G", "b": "Bagian 6. Pemisahan Barang-barang.", "t": "Pencatatan sita atas barang-barang tetap dicoret di daftar-daftar umum: 1 . berdasarkan persetujuan dari si isteri untuk mencoret pencatatan seperti dimaksud dalam pasal 1196 KUHPerd; 20. berdasarkan keputusan hakim yang memuat penolakan terhadap tuntutan akan pemisahan atau perintah pengangkatan sita. Di luar persetujuan dari pihak-pihak yang berkepentingan tidak dilakukan pencoretan, kecuali dengan memperhatikan ketentuan pasal 437 ( ) dengan perubahan, bahwa tenggang waktu empat belas hari sesudah pemberitahuan keputusan hakim diganti dengan tenggang waktu empat puluh lima hari sesudah keputusan hakim; (RB9. 322-180.) 3 . berdasarkan keterangan dari panitera pada majelis hakim, di mana tuntutan akan pemisahan terakhir masih bergantung, bahwa telah terjadi pelepasan instansi atau bahwa hal itu telah gugur; 4 . berdasarkan keputusan yang menyatakan si suami berada dalam keadaan pailit atau ternyata tidak mampu niembayar utang- utangnya dan atas permohonan dari Balai Harta Peninggalan; 5 . berdasarkan jabatannya oleh pegawai yang dimaksud dalam alinea ketiga pasal 507 dan dengan cara dimaksud pada pencatatan dari akta pemisahan harta perkawinan bersama atau kutipan daripadanya. …"}, {"l": "RV", "p": "824", "b": "Bagian 6. Pemisahan Barang-barang.", "t": "(s.d.u. dg. S. 1908-522.) Selain ketentuan-ketentuan yang bermaksud untuk mengamankan hak, maka atas permohonan akan pemisahan tidak boleh diambil keputusan oleh hakim, kecuali dalam waktu tiga bulan sesudah memperhatikan formalitas-formalitas tersebut dalam pasal 822. (KUHPerd. 188.)"}, {"l": "RV", "p": "825", "b": "Bagian 6. Pemisahan Barang-barang.", "t": "Pengakuan dari suami saja tidak berlaku sebagai bukti, sekalipun seandainya tidak ada para kreditur. (KUHPerd. 186, 188, 1925; Rv. 230.)"}, {"l": "RV", "p": "826", "b": "Bagian 6. Pemisahan Barang-barang.", "t": "(s.d.u. dg. S. 1916-530.) Pemisahan barang-barang harus diumumkan dengan menempatkan kutipan dari keputusan hakim dalam surat kabar resmi. Kutipan itu memuat hari penandatanganan keputusan hakim dan penunjukan oleh raad van justitie bahwa permohonan telah dikabulkan, nama-nama, nama-nama kecil, pekerjaan dan tempat tinggal dari suami- isteri. Alasan-alasan yang merupakan dasar keputusan hakim tidak boleh dimuat dalam kutipan itu. (KUH Perd. 189, 191, 245; RV. 819, 822, 830; RBg. 322-21 .)"}, {"l": "RV", "p": "827", "b": "Bagian 6. Pemisahan Barang-barang.", "t": "(s.d.u. dg. S. 1916-530.) Si istri tidak dapat melaksanakan keputusan hakim selain sesudah formalitas seperti diatur dalam pasal di muka dipenuhi. (KUHPerd. 189, 191; RV. 90.)"}, {"l": "RV", "p": "828", "b": "Bagian 6. Pemisahan Barang-barang.", "t": "iika syarat-syarat seperti diharuskan dalam bagian ini dipenuhi, maka setelah lampau tenggang waktu seperti disebut dalam pasal di muka, keputusan hakim tentang pemisahan berlaku juga terhadap para kreditur si suami. (KUH-Perd. 188 dst., 192, 1341; RV. 578.)"}, {"l": "RV", "p": "829", "b": "Bagian 6. Pemisahan Barang-barang.", "t": "isteri yang akan melepaskan barang-barang yang berasal dari harta bersama harus memberi keterangan di kepaniteraan dari raad van justitie yang memutuskan tuntutan atas pemisahan harta bersama itu. (KUHPerd. 21, 126-50, 128 132; RV. 819.) r g"}, {"l": "RV", "p": "830", "b": "Bagian 6. Pemisahan Barang-barang.", "t": "s . o (S.d.u. dg. S. 1916-530.) Akta, di mana kebersamaan barang-barang l i t terhadap pemisahan barang-barang. (KUHPerd. 196 dst.) a dikembalikan, harus diumumkan seperti diatur dalam pasal 826 a l. eg"}, {"l": "RV", "p": "831", "b": "Bagian 7. Perceraian.", "t": "w w Seorang suami atau isteri yang ingin mengajukan tuntutan perceraian, w memuat kejadian-kejadian dan kesimpulan-kesimpulannya dengan disertai surat berkewajiban untuk mengajukan surat permohonan kepada raad van justitie yang surat bukti. Surat permohonan itu disampaikan kepada ketua raad van justitie oleh suami atau isteri yang menuntut secara pribadi, kepada siapa diberi nasihat-nasihat seperlunya menurut pandangannya. (s.d.u. dg. S. 1923-287, 441.) Jika ternyata ada alasan yang sah atas ketidakhadirannya, maka ketua raad van justitie pergi ke rumah kediaman penggugat. (s.d.u. dg. S. 1908-522; S. 1923-287,441; S. 1925-497; S. 1926- 235jo. 284.) Bila penggugat bertempat tinggal atau berdiam di luar daerah, di mana raad van justitie berada, maka ketua raad vanjustitie dapat menunuk residentierechter atau, jika tidak ada, berhalangan atau tidak di tempat, dapat menunjuk kepala daerah setempat untuk melakukan perbuatan-perbuatan tersebut dalam alinea kedua dan alinea ketiga. Pejabat-pejabat yang ditunjuk itu harus membuat berita acara mengenai perbuatan yang ia lakukan dati rriengirimnya segera ke raad van justitie. (RBg. 322-19 .) (s.d.u. dg. S. 1923 -287, 441.) Bila penggugat …"}, {"l": "RV", "p": "832", "b": "Bagian 7. Perceraian.", "t": "Bila penggugat tetap pada gugatannya, ketua raad van justitie memerintahkan pada bagian bawah atau pinggir surat permohonan, agar suami dan isteri menghadap kepadanya pada hari dan jam yang ditentukan. (Rv. 831.) Turunan dari perintah itu harus dikirim oleh panitera kepada pihak tergugat. (KUHPerd. 239; F. 105; Rv. 6-70, 834,)"}, {"l": "RV", "p": "832A", "b": "Bagian 7. Perceraian.", "t": "(s.d. t. dg. S. 1926-235jo. 284.) Bila tergugat tidak mempunyai tempat tinggal yang diketahui dan juga tidak mempunyai tempat tinggal yang diketahui dalam wilayah Indonesia, maka waktu untuk menghadap ditetapkan paling sedikit enam bulan sesudah pengajuan surat permohonan, dan tergugat dipanggil pada hari itu dengan dua kali panggilan berturut-turut dengan waktu antara sedikitnya tiga puluh hari yang dimuat dalam satu atau lebih surat kabar di r g Indonesia dan di Belanda atau tempat lain yang ditunjuk oleh ketua . o raad van justitie, dan ditempatkan pada bagian yang mencolok menurut pandangan ketua tersebut. s waktu sedikitnya tiga bulan. l i t a Antara hari untuk menghadap dan panggilan terakhir harus ada jangka a Dalam waktu empat belas hari sesudah panggilan pertama, turunan l. eg panggilan itu harus ditempelkan pada pintu utama ruang sidang hakim yang akan memeriksa perkara itu, dan turunan kedua diserahkan kepada w w pejabat penuntut umum pada hakim itu, yang akan menandatangani surat aslinya sebagai mengetahui dengan menyebut tanggalnya. w Penempelan dan pemberitahuan dilakukan oleh seorang juru sita, yang membuat berita acara mengenai satu dan lain hal. …"}, {"l": "RV", "p": "833", "b": "Bagian 7. Perceraian.", "t": "Suami dan isteri diharuskan menghadap secara pribadi tanpa didampingi oleh keluarga terdekat atau penasihat. (Rv. 234.)"}, {"l": "RV", "p": "834", "b": "Bagian 7. Perceraian.", "t": "Pada hari yang ditentukan ketua raad van justitie memberikan nasihat-nasihat yang ia pandang perlu kepada suami dan isteri atau kepada penggugat, jika hanya dia yang datang menghadap, agar tercapai suatu perdamaian. Jika penggugat tidak datang menghadap tanpa alasan yang sah, permohonan untuk perceraian menjadi gugur. Dari hasil kehadiran itu dibuat suatu berita acara. (Rv. 821, 836.) (s.d.u. dg. S. 1925-678jo. S. 1926-63; S. 1926-235jo. 284 S. 1928- 424) Ketentuan-ketentuan yang termuat dalam alinea kempat dan kelima pasal 820 berlaku juga terhadap perbuataii-perbuatan yang dilakukan oleh ketua raad van justitie seperti tersebut dalam pasal ini dan tiga pasal di muka yang menyangkut perceraian."}, {"l": "RV", "p": "835", "b": "Bagian 7. Perceraian.", "t": "(s.d.u. dg. S. 1927-31jis. 390, 421.) Ketua raad vanjustitie (R.v.J,) dapat memberikan kuasa kepada isteri yang bersangkutan dalam berita acara yang sama itu juga, dalam hal tidak tercapainya kesatuan pendapat untuk perdamaian, untuk memasuki rumah yang telah disetujui oleh kedua belah pihak atau ketua itu dalam hal ini karena jabatannya menunjuk rumah tersebut untuk dimasuki dan sekaligus memberikan perintah agar barang-barang guna kepentingan kehidupan sehari-haanya menjadi haknya untuk dipakai. Oleh ketua itu sekaligus dapat diberikan ketetapan yang dapat dijalankan terlebih dahulu untuk menyertakan anak-anaknya bertempat tinggal di rumah tersebut; bila dalam hal ini belum ada ketentuan di bawah penguasaan siapa di antara suami isteri anak-anak itu berada, maka ketua dalam ketetapannya memerintahkan kepada siapa (suami atau isteri) diikutsertakan untuk diurus. Untuk kepentingan ini berlaku ketentuan dalam alinea kedua, ketiga, keempat, dan kelima, dari pasal 319h KUHPerd. r g s . o Ketua raad van justitie juga harus mendapatkan dasar/alasan yang kuat untuk menentukan sejumlah uang yang sesuai dengan martabat dan l i a kekayaan si suami, yang akan diberikan kepada si isteri …"}, {"l": "RV", "p": "836", "b": "Bagian 7. Perceraian.", "t": "(s.d.u. dg. S. 1923-287, 441; S. 1926-235jo. 284.) Bila antara para pihak tidak dicapai penyelesaian secara damai, maka ketua memberikan izin kepada pemohon (penggugat) untuk mengajukan persoalannya secara gugatan perdata biasa dan menetapkan jangka waktu untuk mengajukan gugatan itu. Bila penggugat (pemohon) tidak mengetahui alamat rumah/tempat tinggal pihak lawannya (tergugat) dan tergugat ini tidak hadir dalam sidang, maka pemberian izin seperti tersebut di atas oleh ketua raad van justitie dilakukan bila kepada ketua telah diberitahukan dengan jelas -- hal ini sangat tergantung dari pendapat ketua itu sendiri - - bahwa pemohon telah berusaha sungguh-sungguh untuk mencari alamat rumah/tempat tinggal pihak lawannya akan tetapi tidak berhasil dalam usahanya. Bila jangka waktu seperti yang dimaksudkan dalam alinea kesatu tidak dipenuhi oleh pemohon, maka gugurlah izin yang telah diberikan oleh ketua. (Rv.1 dst., 8, 15.)"}, {"l": "RV", "p": "837", "b": "Bagian 7. Perceraian.", "t": "Gugatan selanjutnya dilakukan dengan cara dan ketentuan-ketentuan seperti pada gugatan perkara perdata biasa lainnya, akan tetapi sidang perkara dilakukan secara tertutup untuk umum, sedangkan keputusannya diucapkan secara terbuka di muka umum. (RO. 29; KUHPerd. 207 dst-, 221; Rv. 22, 78, 118 dot., 843.)"}, {"l": "RV", "p": "838", "b": "Bagian 7. Perceraian.", "t": "Bila memang beralasan untuk memberikan izin mengadakan pembuktian dengan saksi-saksi, pemeriksaan saksi-saksi ini dilakukan dalam sidang tertutup untuk umum. (KUHPerd. 1895; Rv. 171 dst., 842.)"}, {"l": "RV", "p": "839", "b": "Bagian 7. Perceraian.", "t": "(,q.d.u. dg, S. 1908-522.) Gugatan insidental yang dilakukan berdasarkan pasal 213 dan 214 KUHPerd. dan yang dimaksudkan untuk mengubah atau mencabut penetapan-penetapan ketua raad van justitie menurut pasal 835 dilakukan dengan memberi kesimpulan yang disertai alasan-alasannya. (KUHPerd. 212; Rv.241 dst.)"}, {"l": "RV", "p": "840", "b": "Bagian 7. Perceraian.", "t": "(s.d.u. dg. S. 1908-522.) Tindakan-tindakan yang boleh dilakukan oleh si isteri berdasarkan pasal 215 KUHPerd. untuk membela haknya r g adalah sama dengan haknya dalam hal permohonan pemisahan harta s . o benda yang diatur dalam pasal 823. Tetapi ia hanya dapat memperoleh l i terjadinya penggelapan. (Rv. 720, 823a, 823j, 841.) a izin untuk sita jaminan jika ada kekhawatiran yang beralasan tentang t a l. eg"}, {"l": "RV", "p": "841", "b": "Bagian 7. Perceraian.", "t": "Syarat-syarat untuk perceraian berlaku pula untuk gugatan pisah meja dst., 233 dst., 236 dst., 246.) w w dan ranjang, karena alasan-alasan tertentu. (KUHPerd. 209 dst., 212 Pasal 842. w (s.d.u. dg. S. 1925 -525.) Peraturan pasal 1910 no. 10 dan no. 20 KUH.Perd - berlaku juga baik dalam gugatan pisah meja dan ranjang karena alasan-alasan tertentu dan dalam gugatan perceraian; tetapi dengan ketentuan-ketentuan untuk kedua perkara, bahwa orang tua dan anak-anak suami-isteri dapat membebaskan diri untuk memberi kesaksian. (KUHPerd. 207dst, 233 dst.; Rv. 831 dst.; Sv. 145 dst.; IR 145, 274.)"}, {"l": "RV", "p": "843", "b": "Bagian 7. Perceraian.", "t": "Putusan-putusan hakim mengenai perceraian dan pisah meja dan ranjang diumumkan dengan cara yang ditentukan dalam Pasal 826. (KUHPerd. 221, 245, 248 dst.; BS. 64; R,. 329, 334; RBg. 322-210.) Dg. S. 1938-622 ditambahkn Bagian Ketujuh A (mb. 22 Des 1938)."}, {"l": "RV", "p": "843A", "b": "Bagian 7A. Cara Berperkara Mengenai Nafkah Biaya Hidup.", "t": "Gugatan-gugatan yang semata-mata untuk: 10. penentuan mengenai pembayaran untuk pemeliharaan yang terutang berdasarkan buku pertama KUHPerd. (KUHPed. 206a, 225, 230b, 240 , 2460, 301, 3063, 321 dst., 329a.) 20. perubahan atau penarikan kembali suatu keputusan hakim atau penetapan tentang pembayaran-pembayaran semacam itu; 30. perubahan atau Penarikan kembali suatu Pengaturan tentang pemeliharaan yang dibuat oleh para pihak; dilakukan dengan surat Permohonan, kecuali: tentang tuntutan mengenai Pemberian biaya Pemeliharaan sementara oleh suami selama berlangsung perkara tentang perceraian atau pisah meja dan ranjang Pemeliharaan mencakup Pemeliharaan dan pendidik. anak yang belum cukup umur. Surat Permohonan memuat kenyataan-kenyataan dan keadaan-keadaan yang menjadi dasar tuntutan dan disampaikan bersama dengan surat-surat untuk menguatkannya kepada raad van justitie dengan disertai turunan-turunan sebanyak jumlah pihak-pihak yang digugat. Raad van justitie di tempat tinggal pemohon, termohon atau para termohon, atas Pilihan pemohon berhak untuk memeriksa tuntutan- tuntutan tersebut di bawah No. 10 dan 30. Tuntutan-tuntutan tersebut di bawah 20 diajukan kepada raad van justitie …"}, {"l": "RV", "p": "843B", "b": "Bagian 7A. Cara Berperkara Mengenai Nafkah Biaya Hidup.", "t": "Panitera mencatat di atas surat permohonan hari diterimanya r surat permohonan dan turunan surat-surat lampirannya kepada tiap-g permohonan dan segera mengirimkan dengan surat tercatat satu turunan . tiap termohon. Ditambahkan padanya suatu pemberitahuan yang s o menyebutkanjangka waktu yang tidak boleh dilampaui untuk mengajukan i t a surat jawaban seperti tersebut dalam alinea terakhir pasal ini, dan l juga tentang akibat yang disebut dalam alinea kesatu pasal berikut, a l. eg jika tidak dimasukkan surat jawaban, dengan memberitahukan juga, kecuali jika tergugat adalah dewan wali, bahwa pengajuan jawaban hanya dibolehkan dengan perantaraan seorang pengacara, dan dengan w w penjelasan tentang cara yang harus ditempuh untuk mendapat bantuan secara cuma-cuma dalam hal tergugat adalah orang yang miskin. Jika w baik tempat tinggal maupun tempat kediaman di mana tergugat tidak dikenal, maka panitera memuat segera suatu panggilan dalam satu atau beberapa surat kabar yang ditunjuk oleh raad van justitie agar yang bersangkutan mengambil surat-surat tersebut di kepaniteraan raad van justitie. Tergugat dalam waktu yang ditentukan oleh ketua, dengan memperhatikan keadaan, sedikitnya tiga …"}, {"l": "RV", "p": "843C", "b": "Bagian 7A. Cara Berperkara Mengenai Nafkah Biaya Hidup.", "t": "Raad van justitie tanpa mendengar para pihak lebih lanjut, rnengabulkan gugatan, jika dalam jangka waktu yang ditentukan tidak ada surat pembelaan yang masuk dari pihak tergugat, kecuali jika gugatan dianggap melawan hukum atau tidak mempunyai dasar. (Rv. 843h.) Tiap tergugat yang tidak dapat menerima penetapan itu dapat mengajukan perlawanan dalam waktu tiga puluh hari sesudah penetapan atau suatu akta yang dibuat berdasarkan gugatan itu atau untuk pelaksanaannya telah diberitahukan kepadanya pribadi dengan perantaraan juru sita atau setelah ia melakukan suatu perbuatan yang menimbulkan kesimpulan bahwa penetapan atau pelaksanaan yang dimulai telah ia ketahui. (Rv. 77 dst., 83 dst.) Surat permohonan disertai turunan yang oteh panitera disampaikan kepada pemohon asli."}, {"l": "RV", "p": "843D", "b": "Bagian 7A. Cara Berperkara Mengenai Nafkah Biaya Hidup.", "t": "Jika dalam jangka waktu yang sah telahdisampaikan surat jawaban atau surat permohonan perlawanan, maka raad van justitie menentukan hari untuk mendengar para pihak dan dalam hal dewan para wali merupakan pihak, untuk mendengar salah seorang yang menjalankan kekuasaan orang tua atau perwalian terhadap anaknya yang belum dewasa. Jika ada beberapa tergugat, selama belum semua mengajukan surat jawaban, maka penentuan harinya ditunggu sampai habis jangka waktu yang, ditentukan untuk mengajukan surat jawaban. Terhadap pemeriksaan seperti tersebut dalam alinea yang lalu, maka berlakulah pasal 173 alinea kesatu, kedua, ketiga, dan kelima. Raad van justitie, jika gugatan mengenai pemeliharaan seorang anak di bawah umur, dapat meminta pertimbangan tertuus dewan para wali, sepanjang dewan ini tidak merupakan pihak. (KUHPerd. 329b; Rv. 832i.) Pertimbangan diberikan dalam waktu yang ditetapkan oleh raad van justitie dan dapat dilihat di kepaniteraan oleh orang tua dan para wali. Surat panggilan tersebut dalam pasal berikut memberikan pula penjelasan-penjelasan bagi yang berkepentingan. g Raad van justitie dalam segala tingkat pemeriksaan kepada para pihak r s . o dapat memerintahkan agar …"}, {"l": "RV", "p": "843E", "b": "Bagian 7A. Cara Berperkara Mengenai Nafkah Biaya Hidup.", "t": "a l. eg Pemanggilan pihak-pihak orang tua dan wali dilakukan dengan surat panitera yang dikirimkan selambat-lambatnya pada hari kedua sesudah w diterima pertimbangan atau sesudah lampau jangka waktu yang ditentukan dan jika raad van justitie tidak meminta pertimbangan w seperti itu, sesudah pendengaran terhadap para pihak ditentukan. w Jika salah satu di antara mereka tidak diketahui tempat tinggal atau tempat kediamannya, maka panitera memuat panggilan itu dalam satu atau beberapa surat kabar yang ditentukan oleh raad van justitie."}, {"l": "RV", "p": "843F", "b": "Bagian 7A. Cara Berperkara Mengenai Nafkah Biaya Hidup.", "t": "Raad van justitic dapat memerintahkan pemeriksaan saksi mengenai fakta-fakta tertentu pada hari pemeriksaan atau menentukan hari lain untuk itu. Saksi-saksi sedapat mungkin ditunuk dalam surat penetapan itu dan dipanggil atau dibawa oleh pihak yang sudah siap lebih dulu. Para pihak di dalam surat permohonan atau surat jawaban dapat mengajukan keinginannya agar orang-orang yang disebut nama dan tempat tinggalnya didengar sebagai saksi. Ketentuan-ketentuan dalam pasal-pasal 173 alinea kesatu, kedua, ketiga, dan kelima, 175, 177, 179, 181, 182, 183, 185 alinea kedua dan 186 berlaku pula dalam mendengar para saksi. Setelah selesai pemeriksaan atau pemeriksaan lawutan, maka ketua raad van justitie memberitahukan kapan keputusan akan dijatuhkan. Raad van justitie segera memberikan ketetapan. (Rv. 843h.)"}, {"l": "RV", "p": "843G", "b": "Bagian 7A. Cara Berperkara Mengenai Nafkah Biaya Hidup.", "t": "Panitera membuat berita acara tentang apa yang telah terjadi pada pemeriksaan dengan menyebut isi pokok apa yang telah diterangkan oleh para pihak, orang tua, para wali dan para saksi. Ketua raad van justitie dapat memerintahkan pencabutan keterangan- keterangan tertentu. Berita acara ditentukan oleh ketua atau oleh salah satu hakim yang menghadiri pemeriksaan dan panitera, dan sesegera mungkin setelah pemeriksaan selesai ditandatangani. Pasal 843h. Ketetapan termaksud dalam pasal 843c alinea kesatu dan pasal 843f alinea terakhir, dengan ancaman kebatalan jika tidak dipenuhi, disertai alasanalasannya, diumumkan. Ketetapan-ketetapan itu dapat dinyatakan boleh dilaksanakan sebelumnya (RV. 54 dst) Tentang biaya Perkara berlaku ketentuan-ketentuan dalam pasal 58, 59 dan 60. Pasal 843i. Penggugat yang gugatannya ditolak seluruhnya atau sebagian dan tergugat yang setelah para pihak diperiksa seperti dimaksud dalam pasal 843d, tuntutannya dikabulkan seluruhnya atau sebagian, tanpa melihat apakah ia mengajukan jawaban atau tidak atau apakah ia hadir atau tidak sewaktu diadakan Pemeriksaan, dapat mengajukan banding atas penetapan raad van justitie kepada H-G.H. dalam waktu tiga puluh hari …"}, {"l": "RV", "p": "844", "b": "Bagian 8. Penambahan Atau Perbaikan Akta-akta Catatan Sipil.", "t": "Barangsiapa yang berdasarkan pasal 13 KUHPerd. memohon agar w diperintahkan diadakan tambahan atau perbaikan akta catatan sipil, harus mengajukan surat permohonan kepada raad van justitie yang w disebut dalam pasal 14 KUHPerd. dengan disertai alasan-alasannya. w (KUHPerd. 1914; BS. 27; S. 1854- 40.)"}, {"l": "RV", "p": "845", "b": "Bagian 8. Penambahan Atau Perbaikan Akta-akta Catatan Sipil.", "t": "Jika raad van justitie memerintahkan agar pihak-pihak yang berkepentingan dipanggil menghadap, maka hal itu dilakukan dengan suatu surat panggilan untuk menghadap atau, jika hal itu dimohonkan dalam suatu perkara yang sedang diperiksa, dilakukan dengan suatu akta pengacara kepada pengacara pi. hak yang lain. (Rv. 1 dst., 8 d,t.)"}, {"l": "RV", "p": "846", "b": "Bagian 8. Penambahan Atau Perbaikan Akta-akta Catatan Sipil.", "t": "(s.d.u. dg. s. 1908-522.) Perkara diajukan menurut daftar urutan pada hari yang ditentukan dan diperiksa seperti perkara gugatan biasa. (KUHPerd, 14 dst.)"}, {"l": "RV", "p": "847", "b": "Bagian 8. Penambahan Atau Perbaikan Akta-akta Catatan Sipil.", "t": "Keputusan dapat dimintakan banding, oleh Pemohon semata-mata untuk penambahan atau perubahan dalam perkara. Dalam hal terakhir maka banding dilakukan dengan suatu permohonan sederhana. (KUHPerd. 14, 16; Rv. 341.)"}, {"l": "RV", "p": "848", "b": "Bagian 9. Pembuatan Akta Dengan Paksa. (S. 1854-18 pasal 7.)", "t": "Barangsiapa selama dalam suatu proses hendak memperoleh turunan atau kutipan sesuatu akta, di mana ia tidak pemah merupakan pihak, harus mengajukan tuntutannya agar diberikan dengan paksa dengan suatu akta pengacara kepada pengacara. (KUHPerd. 1886; Rv. 8, 849, 851, 853 dst.)"}, {"l": "RV", "p": "849", "b": "Bagian 9. Pembuatan Akta Dengan Paksa. (S. 1854-18 pasal 7.)", "t": "(s. d. u. dg. S. 1908-522.) Tuntutan itu pada hari yang ditentukan dengan akta diajukan pada hari sidang."}, {"l": "RV", "p": "850", "b": "Bagian 9. Pembuatan Akta Dengan Paksa. (S. 1854-18 pasal 7.)", "t": "Pelaksanaan putusan, meskipun ada perlawanan atau banding, dapat diperintahkan oleh hakim jika ada alasan-alasan untuk itu. (Rv. 54 dst.)"}, {"l": "RV", "p": "851", "b": "Bagian 9. Pembuatan Akta Dengan Paksa. (S. 1854-18 pasal 7.)", "t": "Atas penunjukan putusan hakim itu maka turunan atau kutipan akta diberikan oleh notaris atau pejabat penyimpanan dan dibuat berita r g acara tentang itu olehnya. s . o para pihak boleh hadir pada waktu berita acara dibuat dan meminta 580-6 , 852.) l i a catatan. catatan mereka untuk ditambahkan di dalamnya. (Rv. 68, 437, t a l. eg"}, {"l": "RV", "p": "852", "b": "Bagian 9. Pembuatan Akta Dengan Paksa. (S. 1854-18 pasal 7.)", "t": "Bila timbul sengketa tentang hal itu, maka pada hari yang ditentukan w w dalam berita acara tanpa panggilan lebih lanjut hal itu diajukan di hadapan sidang; pejabat penyimpan akta membawa akta yang w bersangkutan ke sidang, bila ada alasan-alasan. Raad van justitie, setelah membandingkan akta yang asli dengan turunan atau kutipannya, memberi keputusan. Biaya pembuatan berita acara dan biaya perjalanan atau pemindahan pejabat penyimpan dan juga biaya pembuatan turunan atau kutipan dibayarkan uang muka lebih dahulu oleh Pemohon. (Rv. 106, 283, 580- 50, 851.)"}, {"l": "RV", "p": "853", "b": "Bagian 9. Pembuatan Akta Dengan Paksa. (S. 1854-18 pasal 7.)", "t": "Para panitera dan para penyimpan register-register umum, tanpa perintah hakim atas pembayaran biaya yang menjadi hak mereka, wajib memberikan turunan atau kutipan kepada mereka yang memintanya, dengan ancaman penggantian biaya, kerugian-kerugian dan bunga. Tetapi kepada mereka yang tidak pemah menjadi pihak dalam perkara tidak diberikan turunan atau kutipan penetapan atau putusan-putusan hakim dalam perkara pidana, juga dalam hal yang tidak secara tegas diatur dalam undang-undang, tidak diberikan turunan atau kutipan suatu perkara yang bersangkutan yang disimpan di kepaniteraan, tanpa kuasa ketua majelis, dan permohonan-permohonan untuk itu hanya dikabulkan, jika diberikan bukti-bukti bahwa ia mempunyai kepentingan dalam perkara itu. (KUHPerd. 210, 1224, 1227, 1238, 1405; BS. 25; Rv. 438.)"}, {"l": "RV", "p": "854", "b": "Bagian 9. Pembuatan Akta Dengan Paksa. (S. 1854-18 pasal 7.)", "t": "para notaris dan juga penyimpan surat-surat asli atau akta wajib memberikan turunan dengan pembayaran biayanya, kepada orang-orang yang baik secara langsung berkepentingan ataupun kepada para ahli warisnya ataupun orang-orang yang mendapat hak dari mereka. Dalam hal permintaan itu ditolak, maka mereka dapat dihukum untuk mengganti biaya, kerugian dan bunga, jika ada alasan-alasan untuk itu, bahkan jika perlu dengan paksaaan badan. (KUHPerd. 832 dst., 955, 957, 1243 dst., 1318, 1889; Rv. 58, 580-100, 856.)"}, {"l": "RV", "p": "855", "b": "Bagian 9. Pembuatan Akta Dengan Paksa. (S. 1854-18 pasal 7.)", "t": "(s.d.u. dg. S. 1908-522.) Perselisihan diselesaikan sebagai suatu gugatan biasa dan hakim, bila ia menemukan alasan untuk itu, dapat memerintahkan pelaksanaan lebih dahulu, meskipun ada perlawanan atau banding. (Rv. 54 dst.,861 dst.) Penggantian kerugian diberikan hanya jika ada kepastian tentang hal itu. (Rv.57.)"}, {"l": "RV", "p": "856", "b": "Bagian 9. Pembuatan Akta Dengan Paksa. (S. 1854-18 pasal 7.)", "t": "Pihak yang menghendaki dikeluarkannya grosse kedua atau selanutnya mengajukan surat permohonan kepada raad van justitie, yang wilayahnya meliputi tempat tinggal pejabat penyimpan; raad van justitie memerintahkan dengan siati surat perintah kepada pejabat penyimpan untuk melaksanakan pemberiannya pada hari dan jam yang r telah ditentukan dan kepada pihak-pihak yang berkepentingan untuk g hadir pada waktu penyerahannya. Di kaki grosse kedua atau ya s . o disebut adanya surat perintah itu, begitu pula mengenai jumlah uang l i t a yang dapat dilaksanakan terhadap grosse tersebut, jika tuntutan utang telah dilunasi atau dibayar sebagian. (KUHPerd. 1889; Rv. 12, 15, 68, 435, 851, 858.) a"}, {"l": "RV", "p": "857", "b": "Bagian 9. Pembuatan Akta Dengan Paksa. (S. 1854-18 pasal 7.)", "t": "l. eg w w (s.d.u. dg. S. 1908-522.) Jika ada bantahan, maka hal itu diajukan kepada raad van justitie. (Rv. 437, 852.) Pasal 858. w Kepada pihak yang sama tidak boleh diberikan grosse kedua atau selebihnya dengan kekuatan eksekutorial dari suatu putusan, kecuali atas perintah ketua majelis yang memutusnya; dan untuk itu diperhatikan juga syarat-syarat yang ditentukan untuk memperoleh grosse kedua atau grosse-grosse selebihnya dari akta-akta. (Rv. 435, 856 dst.)"}, {"l": "RV", "p": "859", "b": "Bagian 10. Penolakan Mengadili Dan Penyerahan Kepada Hakim Lain.", "t": "Jika oleh seorang pegawai Eropa, hakim tunggal, atau raad van justitie atau salah seorang anggotanya, ditolak untuk memberikan penetapan atas suatu surat permohonan, atau memberikan putusan mengenai suatu perkara yang sedang berjalan, begitu pula penyelesaian suatu perkara dengan cara yang tidak patut diperlambat, maka pihak yang berkepentingan dapat mengajukan aduan kepada H.G.H. (ISR. 157; Rv. 623; AB. 22.)"}, {"l": "RV", "p": "860", "b": "Bagian 10. Penolakan Mengadili Dan Penyerahan Kepada Hakim Lain.", "t": "Aduan diajukan dengan suatu surat permohonan, yang kecuali ditandatangani oleh pengacara juga oleh pemohon atau oleh orang yang dikuasakan secara khusus untuk itu dan surat kuasa itu harus disertakan pada surat permohonan itu, dengan ancaman kebatalan jika tidak disertakan. Alat-alat bukti yang ada harus disertakan dan pemohon harus memilih tempat tinggal di tempat H.G.H. bersidang. (KUHPerd. 24, 1934; Rv. 106, 272, 736.)"}, {"l": "RV", "p": "861", "b": "Bagian 10. Penolakan Mengadili Dan Penyerahan Kepada Hakim Lain.", "t": "H.G.H. memerintahkan agar surat permohonan diberitahukan kepada hakim yang ditentang; untuk itu suatu turunan perintah itu beserta turunan surat permohonan dengan bukti-bukti yang bersangkutan oleh panitera H.G. H. disampaikan kepada kepaniteraan hakim itu."}, {"l": "RV", "p": "862", "b": "Bagian 10. Penolakan Mengadili Dan Penyerahan Kepada Hakim Lain.", "t": "Dalam jangka waktu yang cbtetapkan oleh H.G.H., hakim yang diadukan itu harus menyampaikan jawaban pembelaannya secara tertulis kepada kepaniteraan H.G.H. Pengadu dan pengacara dapat melihat jawaban itu di kepaniteraan. (Rv. 15, 864.)"}, {"l": "RV", "p": "863", "b": "Bagian 10. Penolakan Mengadili Dan Penyerahan Kepada Hakim Lain.", "t": "Hakim-hakim yang diadukan selama pemeriksaan dilarang menangani perkara yang diadukan sebagai perkara yang olehnya ditolak pemeriksaannya, begitu pula semua perkara yang mengenai pengadu yang mungkin ada pada hakim itu, dengan ancaman kebatalan putusannya. Mereka dengan cara yang sama harus menolak menangani perkara-perkara r g s dari pengadu dan suami atau isterinya, dan juga dengan ancaman. o yang ada di majelisnya yang ada hubungan keluarga dalam garis lurus kebatalan. (Rv. 35-70, 36 dst.) l i t a"}, {"l": "RV", "p": "864", "b": "Bagian 10. Penolakan Mengadili Dan Penyerahan Kepada Hakim Lain.", "t": "a l. eg H.G.H. memberikan putusan atas permohonan-permohonan dan surat-surat yang diajukan kepadanya kecuali jika diperbolehkan pengajuan w w risalah-risalah tambahan atau diperintahkan untuk memasukkan risalah-risalah tambahan itu. (Rv.145,:329-40, 859, 862.) Pasal 865. w Jika pengaduan beralasan, maka hakim yang bersangkutan dihukum untuk membayar biaya, ganti rugi dan bunga kepada pengadu. (KUHPerd. 1246; Rv. 607.) Perkara dalam hal itu atas perintah H. G. H. diserahkan kepada majelis dan diputus dalam tingkat tertinggi. (Rv. 266 dst.) 866. Ditarik kembali dg. S. 1872-13."}, {"l": "RV", "p": "867", "b": "Bagian 11. Pelanggaran yang Dilakukan Oleh Pegawai Catalan Sipil,", "t": "(s. d. u. dg. S. 1918-30.) Pelanggaran-pelanggaran yang dilakukan oleh pegawai atau perantara pada catatan sipil, panitera, notaris dan pegawai-pegawai lain, dalam menjalankan tugasnya yang hanya diancam dengan pidana denda, menjadi wewenang hakim perdata, dan dituntut di hadapan raad van justitie yang berwenang serta diadili berdasarkan tuntutan hukum tertulis dari officer van justitie yang diajukan kepada raad van justitie. (Ov. 59; KUHPerd. 82; BS. 28; Rv. 870; Sv. 177 dst., 370 dst., 391 dst.; S. 1851-27 pasal 17, 19; Not. 57, 60.)"}, {"l": "RV", "p": "868", "b": "Bagian 11. Pelanggaran yang Dilakukan Oleh Pegawai Catalan Sipil,", "t": "Raad van justitie memerintahkan agar tuntutan hukum itu diberitahukan kepada pegawai yang bersangkutan dengan perantaraan juru sita dan ditentukan pula jangka waktu yang bersangkutan dapat mengajukan risalah pembelaannya kepada raad van justitie. Pada waktu pemberitahuan tuntutan hukum itu disampaikan turunan perintah itu kepada pegawai tersebut. (Rv. 15, 870.) Setelah lampau jangka waktu tersebut, maka raad van justitie mengambil keputusan."}, {"l": "RV", "p": "869", "b": "Bagian 11. Pelanggaran yang Dilakukan Oleh Pegawai Catalan Sipil,", "t": "(s.d. u. dg. S. 1908-522.) Putusan-putusan perkara tersebut, tergantung pada apakah diberikan dalam tingkat pertama atau banding, dapat dimohonkan banding atau kasasi dalam jangka waktu seperti tersebut dalam peraturan ini. (RO. 126, 171; Rv. 327 dst., 402 dst.) Baik upaya hukum pertama maupun kedua diputus secara singkat berdasarkan surat-surat dan risalah-risalah yang untuk keperluan itu sebelum tiba hari sidang dikirimkan ke kepaniteraan H.G.H."}, {"l": "RV", "p": "870", "b": "Bagian 11. Pelanggaran yang Dilakukan Oleh Pegawai Catalan Sipil,", "t": "Meskipun ada pemindahan seorang pegawai menurut pasal 867 ke luar g wilayah raad van justitie, di dalam wilayah hukum mana pegawai itu r s . o melakukan pelanggaran dalam jabatannya, hanya penuntut umum di tempat raad van justitie itulah yang tetap berwenang melakukan tuntutan hukum. (KUHPerd. 18; Sv. 12.) l i t a Dalam hal itu raad van justitie menyampaikan surat tuntutan hukum a itu kepada majelis yang wilayah hukumnya meliputi tempat tinggal l. eg baru pegawai yang bersangkutan untuk diselesaikan menurut pasal 868 alinea kesatu. w Setelah lampau jangka waktu yang ditetapkan oleh majelis tersebut terakhir, maka dikirimkan risalah pembelaan yang masuk atau berita w dalam hal tidak dimasukkan risalah pembelaan dengan menyampaikan w turunan surat perintah dan surat pemberitahuan yang asli kepada raad van justitie tempat terjadinya pelanggaran yang kemudian mengambil keputusan tentang pokok perkaranya. Dalam hal dijatuhkan pidana, maka pelaksanaannya dilakukan atas tuntutan penuntut umum pada raad van justitie yang menjatuhkan putusan, tetapi perselisihan-perselisihan yang mungkin timbul pada waktu pelaksanaan diselesaikan oleh majelis di tempat tinggal terhukum."}, {"l": "RV", "p": "871", "b": "Bagian 11. Pelanggaran yang Dilakukan Oleh Pegawai Catalan Sipil,", "t": "(s.d.u. dg. S. 1908-522.) Pelanggaran-pelanggaran termaksud dalam bagian ini tetap mempunyai sifat pelanggaran pidana, meskipun perintah penyelesaiannya ditujukan kepada hakim perdata. Peraturan Hukum Acara Pidana tetap berlaku sepanjang tidak ada penyimpangan- penyimpangan menurut pasal-pasal yang lalu."}, {"l": "RV", "p": "872", "b": "Bagian 12. Berperkara Secara Cuma-cuma (Prodeo) Alau Dengan Biaya", "t": "Barangsiapa menjadi penggugat atau tergugat dapat menunjukkan, bahwa ia adalah miskin atau tidak mampu untuk membayar biaya perkaranya, oleh hakim yang akan mulai memeriksa perkaranya atau sedang memeriksa perkaranya, dapat diizinkan untuk berperkara secara cuma- cuma atau dengan biaya dengan tarip yang dikurangi. (Ro. 72; Rv. 873 dst., 879, 887; IR. 237 dst.; RBg. 273 dst.) orang-orang asing tidak dimungkinkan untuk diizinkan berperkara dengan cuma-cuma kecuali dengan suatu perjanjian yang tegas-tegas mengenai hal itu (AB. 3; Nedsch 12; Rv. 128, 580-9 .)"}, {"l": "RV", "p": "873", "b": "Bagian 12. Berperkara Secara Cuma-cuma (Prodeo) Alau Dengan Biaya", "t": "Izin dimohon dengan suatu surat permohonan yang ditandatangani oleh seorang pengacara. (Rv. 106 dst., 889.) surat permohonan disertai satu turunan dan mengemukakan dasar permohonan itu atau pembelaan pemohon. Di dalamnya disebutkan juga nama pihak lawan, begitu juga tempat tinggalnya di Indonesia atau - jika itu tidak ada - tempat kediamannya yang nyata dan - jika itu pun tidak ada - tempat tinggalnya di luar Indonesia; jika tidak ada tempat tinggal atau tempat kediaman yang diketahui, maka hal itu disebutkan dalam surat permohonan. (KUHPerd. 17 dst., 24; Rv. 8781, 884-887.)"}, {"l": "RV", "p": "874", "b": "Bagian 12. Berperkara Secara Cuma-cuma (Prodeo) Alau Dengan Biaya", "t": "Pada surat permohonan dilampirkan suatu pernyataan - di dalam daerah gubernemen di Jawa dan Madura dibuat oleh asisten residen dan di daerah lain oleh kepala pemerintah daerah - yang berisi selengkap mungkin mengenai jabatan, pekerjaan atau perusahaan dan keluarga r g pemohon serta mengenai penghasilan dan kekayaannya sendiri dan s . o keluarganya. (Rv. 876, 885 dst., 890; Zeg. 31, al. II-33; S. 1851- 27 pasal 21.) l i t a Sepanjang tidak ada tempat tinggal di Indonesia dan tidak mungkin a ditunjukkan keterangan mengenai hal itu, maka diusahakan sedapat l. eg mungkin surat keterangan semacam itu. Badan hukurn menunjukkan surat-surat yang diperlukan untuk w w menguatkan keadaan miskin atau kurang mampunya. Balai harta peninggalan dan balai budel yang bertindak untuk budel w yang diurusnya atau harta orang lain yang diwakilinya yang pada waktu beracara sama sekali atau untuk sebagian tidak cukup untuk membiayai perkaranya, harus menyertakan satu daftar singkat mengenai budel itu. Dengan peraturan pemerintah dapat diadakan aturan-aturan lebih lanjut tentang pemberian surat keterangan seperti tersebut dalam alinea kesatu. Dengan S. 1941-511 jo. 513 ditetapkan sebagai berikut: Pasal …"}, {"l": "RV", "p": "875", "b": "Bagian 12. Berperkara Secara Cuma-cuma (Prodeo) Alau Dengan Biaya", "t": "Hakim memberikan ketetapan tentang permohonan tersebut setelah mendengar para pihak, setidak-tidaknya setelah mereka dipanggil untuk menghadap pada hari yang telah ditentukan. Pemanggilan dilakukan oleh panitera dengan cara yang ditentukan dalam peraturan pemerintah dengan mengingat tenggang waktu sedikitnya lima hari. Pemanggilan lawan pemohon disertai dengan turunan surat permohonannya. (S. 1941-512.) Tidak perlu dilakukan pemanggilan, jika pihak lawan secara tertulis menngatakan tidak keberatan tentang permohonan itu, begitu pula jika tidak diketahui tempat tinggainya atau tempat kediamannya. Pemeriksaan para pihak dilakukan oleh seorang komisaris yang ditunjuk oleh majelis dari para anggotanya. Komisaris memberikan laporan kepada majelis. (Rv. 8763 , 887.)"}, {"l": "RV", "p": "876", "b": "Bagian 12. Berperkara Secara Cuma-cuma (Prodeo) Alau Dengan Biaya", "t": "Jika benar tentang miskin atau tidak mampunya peniohon, maka hakim mengabulkan permohonan itu, kecuali jika ia sudah dapat menganggap bahwa gugatan atau pembelaannya nampaknya tidak mempunyai dasar hukum, atau pemohon sendiri tidak dibenarkan untuk berperkara secara prodeo. (Rv. 887, 889 .) Hakim dalam memutuskan perkara mengindahkan besar kecilnya biaya perkara berhubungan dengan penghasilan dan kekayaan yang bersangkutan. Sebelum menentukan keadaan miskin atau tidak mampu maka hakim dalam tiap-tiap hal yang ditentukan dalam peraturan pemerintah dan dalam keadaankeadaan lainnya dengan mengindahkan aturan-aturan yang telah ditentukan, dapat meminta keterangan dari tata usaha kantor pajak. Hal ini berlaku juga bagi Komisaris yang bersangkutan, sebelum r g mengajukan laporan kepada Majelis. (S. 1941-512.) s . o Hakim dengan menolak perrnohonan untuk berperkara dengan prodeo l i jika ada alasan-alasan untuk itu. (Rv. 879, 888.)t a dapat mernberi izin untuk berperkara dengan tarip yang dikurangi a l. eg"}, {"l": "RV", "p": "877", "b": "Bagian 12. Berperkara Secara Cuma-cuma (Prodeo) Alau Dengan Biaya", "t": "Untuk memperoleh ketetapan izin berperkara secara prodeo atau dengan w w tarip yang dikurangi tidak dipungut biaya. Dalam biaya pada pasal ini termasuk gaji penasihat hukum dan juru sita. (Rv. 880.)"}, {"l": "RV", "p": "878", "b": "Bagian 12. Berperkara Secara Cuma-cuma (Prodeo) Alau Dengan Biaya", "t": "w Pemohon banding atau kasasi yang dalam tingkat yang lalu telah berperkara secara prodeo atau dengan tarip yang dikurangi, tidak dapat dalam tingkat banding atau kasasi berperkara lagi secara prodeo atau dengan tarip yang dikurangi sebelurn diizinkan lagi oleh hakim yang lebih tinggi itu dengan cara seperti yang dilakukan dalam tingkat pertama. Tergugat dalam tingkat banding atau kasasi yang dalam tingkat pertama telah berperkara secara prodeo atau dengan tarip yang dikurangi tidak perlu memohon lagi izin untuk berperkara secara prodeo atau dengan tarip yang dikurangi. (Rv. 881.)"}, {"l": "RV", "p": "879", "b": "Bagian 12. Berperkara Secara Cuma-cuma (Prodeo) Alau Dengan Biaya", "t": "Akibat diizinkannya berperkara secara prodeo atau dengan tarip yang dikurangi adalah, bahwa biaya kepaniteraan dalam hal pertama seluruhnya, sedangkan dalam hal kedua untuk separuhnya, dibebaskan kepadanya, bahwa masing-masing untuk hal yang pertama tidak dipungut dan unink hal kedua dipungut separuh gaji pengacara dan juru sita, juga masingmasing untuk hal yang pertama secara cuma-cuma dan dalam hal kedua dipungut separuh biaya pelaksanaan keputusan hakim. (RO. 72, 190, 201; Rv. 877, 881 dst.) Perjanjian yang bertentangan dengan apa yang ditentukan dalam alinea kesatu adalah batal."}, {"l": "RV", "p": "880", "b": "Bagian 12. Berperkara Secara Cuma-cuma (Prodeo) Alau Dengan Biaya", "t": "Semua exploit (peniberitahuan juru sita) dilakukan sebagai berikut: pemberitahuan yang dilakukan dalam daerah tempat kedudukali pengadilan dilakukan oleh juru sita yang ditunjuk pada waktu permohonan izin dikabulkan. yang lainnya dilakukan oleh juru sita luar biasa yang berwenang menyampaikan pemberitahuan dan yang tempat tinggalnya dekat dengan tempat pemberitahuan harus dilakukan. Untuk menyampaikan surat pemberitahuan dapat juga diminta bantuan hakim seperti tersebut dalam pasal 5. Jikalau surat pemberitahuan itu barns disampaikan kepada pemohon yang diizinkan berperkara secara prodeo dan akan dilakukan di tempat yang jauhnya 1 1/2 km atau lebih dari tempat tinggal juru sita, maka uang jalannya akan dibayar oleh pemerintah menurut tarip yang ditetapkan untuk itu. (RO. 193 dst., 201; Rv. 1, 20, 877, 879, 8812 , 8221, 883; S. 1851-27 pas. 422.) Pasal 88 1 Izin berperkara secara prodeo atau dengan tarip yang dikurangi untuk suatu tingkat peradilan yang belum selesai dan dalam penerapan pasal 878 ahnea kedua selama tingkat berikutnya atas permohonan orang yang mendapat izin atau pihak lawan ataupun karena jabatannya, dapat ditarik kembali oleh hakim yang memberikan izin: r g s . o …"}, {"l": "RV", "p": "882", "b": "Bagian 12. Berperkara Secara Cuma-cuma (Prodeo) Alau Dengan Biaya", "t": "Bila ada alasan-alasan untuk pihak lawan dari orang yang diizinkan untuk berperkara secara prodeo, atau dengan tarip yang dikurangi, untuk menanggung biayanya, maka hakim karena jabatannya akan menghukumnya untuk membayar kepada panitera biaya kepaniteraan menurut ketentuan pasal 879, begitu pula mengganti biaya yang telah dikeluarkan pemerintah untuk uang jalan juru sita juga gaji pengacara dan para juru sita yang termasuk dalam pengertian biaya sepanjang pemohon yang diizinkan itu dibebaskan menurut pasal yang bersangkutan, juga dari uang yang telah dibayarkan lebih dulu. Putusannya menyebutkan masing-masing yang harus dibayarkan. Pihak lawan dipaksa untuk melakukannya dengan suatu surat perintah pelaksanaan yang dikeluarkan oleh ketua raad van justitie yang menjatuhkan putusan. Penyerahan tidak adak dilaksanakan sebelum keputusan mempunyai kekuatan hukum yang pasti. Terhadap surat perintah itu tidak ada upaya hukum yang lebih tinggi."}, {"l": "RV", "p": "883", "b": "Bagian 12. Berperkara Secara Cuma-cuma (Prodeo) Alau Dengan Biaya", "t": "Bila pernohon izin untuk berperkara secara prodeo atau dengan tarip yang dikurangi dihukum untuk membayar biaya, maka pihak lawannya bebas untuk sedapat rnungkin membebankan biaya yang telah dikeluarkan olehnya kepadanya. Dalam hat pihak lawan juga diizinkan secara prodeo atau dengan tarip yang dikurangi, maka ia pun mempunyai hak yang sama seperti tersebut dalam pasal yang lalu. (RO. 72; Rv. 58, 879 dst.)"}, {"l": "RV", "p": "884", "b": "Bagian 12. Berperkara Secara Cuma-cuma (Prodeo) Alau Dengan Biaya", "t": "Dalam hal penyelesaian yang sangat buru-buru sambil menunggu putusan mengenai permohonannya, ketua majelis, seperti dimaksud dalam pasal 873, dapat mengizinkan pernohon untuk berperkara secara prodeo atau dengan tarip yang dikurangi. Izin itu dimohon dengan surat permohonan yang ditandatangani oleh r g pengacara. Tentang keharusan menyampaikan surat-surat untuk s . o menguatkan keadaan miskin atau kurang mampu ditetapkan oleh ketua. l i a Untuk memperoleh ketetapan mengenai perrnohonan tidak boleh dipungut t biaya. Pasal 876 alinea terakhir juga berlaku dalam hal ini. a Ketetapan yang memberi izin untuk sementara sekaligus menentukan l. eg waktu kapan perrnohonan menurut pasal 873 harus diajukan. Bila permohonan tidak diajukan, maka dianggap bahwa izin sementara itu tidak diberikan. w Penetapan seperti tersebut dalam pasal 873 berlaku surut untuk menggantikan izin sementara. w w Jika izin sementara dimohonkan dalam sidang singkat, maka ketua dalam memberikan izin sekaligus menentukan bahwa permohonan termaksud dalam pasal 873 tidak akan diajukan tetapi bahwa dalam kesempatan pemberian keputusan dalam sidang secara singkat akan diberikan izin yang tetap. Hakim menentukan …"}, {"l": "RV", "p": "885", "b": "Bagian 12. Berperkara Secara Cuma-cuma (Prodeo) Alau Dengan Biaya", "t": "Bila seorang yang miskin atau tidak mampu di luar suatu acara hukum memerlukan suatu surat kuasa yang harus dibuat Oleh hakim, suatu persetujuan hakim atau suatu ketetapan hakim dengan suatu permohonan sederhana atau suatu permohonan lain, maka ia harus menyertakan dalam permohonannya surat-surat seperti tersebut dalam pasal 874, (KUHPerd. 13 dst,, 374, 393 dst., 400, 421; Rv. 813, 843a, 844, 886 dst.) Kemudian hakim menentukan bahwa untuk mendapat penetapan dan pelaksanaannya tidak perlu dibayarkan biaya atau dipungut hanya separuh biaya itu, bila cukup ternyata tentang miskinnya atau kurang mampunya untuk membayar biaya tersebut. Pasal 876 alinea ketiga dan keempat berlaku dalam hal ini. (R,. 874, 879.) Dalam memberi izin kepada orang yang miskin atau kurang mampu untuk mengadakan penyitaan, ketua dapat memberikan izin untuk bebas atau membayar separuh biaya pengajuan tuntutan pernyataan sah dan berharga atas penyitaaan itu dan penyampaian turunan tuntutan pernyataan sah dan berharga atas penyitaan itu kepada pihak ketiga yang mengalami penyitaan. Pasal 884 alinea ketiga dan keempat berlaku juga dalam hal ini. (Rv. 714 dst., 720 dst., 728 dst., 751 dst., 757 dst., 763a dst., …"}, {"l": "RV", "p": "886", "b": "Bagian 12. Berperkara Secara Cuma-cuma (Prodeo) Alau Dengan Biaya", "t": "Barangsiapa yang miskin atau kurang mampu menginginkan suatu ketetapan hakim atau suatu grosse tanpa mengeluarkan biaya atau suatu pelaksanan dengan separuh biaya, mengajukan permohonan kepada ketua raad vanjustitie di tempat tinggalnya atau jika ia tidak mempunyai tempat tinggal di Indonesia, mengajukannya ke raad van justitie di tempat di mana pelaksanaan akan dilakukan, dengan penyertaan surat-surat termaksud dalam pasal 874. Izin diberikan bila ternyata ia benar miskin atau kurang mampu untuk membayar biaya perkara. Pasal 876 alinea ketiga dan keempat berlaku pula dalam hal ini. Untuk mendapatkan penetapan atas permohonan itu tidak dipungut biaya. (Rv. 879, 885, 888.)"}, {"l": "RV", "p": "887", "b": "Bagian 12. Berperkara Secara Cuma-cuma (Prodeo) Alau Dengan Biaya", "t": "Jika ada permohonan untuk berperkara secara prodeo atau dengan tarip yang dikurangi: r g 10. dalam suatu sengketa melulu untuk mendapatkan penetapan s . o pemberian nafkah yang wajib menurut KUHPerd. Buku 1, termasuk l i t a biaya hidup dan pendidikan anak di bawah umur, ataupun untuk pelaksanaan perubahan atau suatu penarikan kembali suatu a putusan, suatu penetapan atau pengaturan antara para pihak l. eg mengenai pembayaran semacam itu; 2 . dalam suatu sengketa mengenai periawian kerja, maka pasal 873 w w alinea kedua, 875 dan 876 alinea pertama tidak berlaku dan hakim membatasi diri dalam pemeriksanya yaitu apakah cukup terbukti w tentang miskin atau kurang mampunya pemohon. Ketentuan-ketentuan itu tidak berlaku terhadap mereka yang mengajukan permohonan lagi sedangkan ia pemah mengajukan permohonan semacam itu yang ditolak. (KUHPerd. 319f.)"}, {"l": "RV", "p": "888", "b": "Bagian 12. Berperkara Secara Cuma-cuma (Prodeo) Alau Dengan Biaya", "t": "Terhadap putusan hakim mengenai izin untuk berperkara dengan prodeo atau dengan tarip yang dikurangi, untuk pelaksanaan dan untuk penarikan kembali penetapan semacam itu tidak dapat dimohonkan banding atau upaya hukum lain."}, {"l": "RV", "p": "889", "b": "Bagian 12. Berperkara Secara Cuma-cuma (Prodeo) Alau Dengan Biaya", "t": "Dalam perkara yang memerlukan bantuan hukiim dalam permohonan izin untuk berperkara secara prodeo atau dengan tarip yang dikurangi dan pemohon tidak mempunyai pengacara, maka ketua dapat memperbantukan seorang pengacara kepadanya, kecuali bila ia beranggapan bahwa permohonannya tidak mempunyai dasar hukum atau berpendapat bahwa kepentingan pemohon sendiri mengenai pekerjaan yang harus dilakukan tidak membenarkannya. Pemberian bantuan semacam itu dapatjuga dilakukan atas permohonan tergugat dalam tingkat banding atau dalam kasasi dan dalam tingkat sebelumnya ia telah berperkara secara prodeo atau dengan tarip yang dikurangi tanpa diperbantukan seorang pengacara kepadanya. (Rv. 8730, 8760, 891 dst.) Permohonan seperti tersebut dalam alinea kesatu dapat diajukan secara tertulis atau dengan lisan. Jika pemohon bertempat tinggal di luar wilayah hukum asisten residen yang ada majelisnya, maka ia dapat mengajukan permohonan lisannya kepada hakim karesidenan di tempat tinggal atau tempat kediamannya, yang kemudian membuat atau menyuruh membuat catatan tentang permohonan itu.Catatan itu disertai surat-surat yang diserahkan kepada asisten residen dan segera dikirimkan kepada ketua majelis. …"}, {"l": "RV", "p": "890", "b": "Bagian 12. Berperkara Secara Cuma-cuma (Prodeo) Alau Dengan Biaya", "t": "Ketua sebelum mengambil ketetapan dapat minta disampaikan kepadanya surat-surat seperti terrnaksud dalam pasal 874. Ia juga dengan mengindahkan aturan-aturan yang ada dalam peraturan pemerintah meminta keterangan-keterangan dari tata usaha kantor pajak. (S. 1941-512.)"}, {"l": "RV", "p": "891", "b": "Bagian 12. Berperkara Secara Cuma-cuma (Prodeo) Alau Dengan Biaya", "t": "Ketua berwenang membebaskan pengacara dari tugasnya atas permohonannya bila ia berpendapat bahwa tuntutan tidak berdasar ataupun berpendapat bahwa kepentingan pemohon tidak dapat r g membenarkan tugas yang akan dijalankannya, dan selanjutnya bahwa kepentingan pengacara membenarkan pembebasan itu. s . o l i a Jika pembebasan diberikan dengan alasan yang terakhir, rnaka ketua t dalam penetapannya dapat memperhantukan seorang pengacara lain kepada pemohon. (Rv. 892.) a"}, {"l": "RV", "p": "892", "b": "Bagian 12. Berperkara Secara Cuma-cuma (Prodeo) Alau Dengan Biaya", "t": "l. eg w Terhadap ketetapan ketua yang diambil berdasarkan pasal 889 dan 891 tidak ada upaya hukum untuk melawannya. w"}, {"l": "RV", "p": "916", "b": "BAB VIII PEMBERIAN RELIEF (PERBAIKAN KESALAHAN ATAU PENYIMPANGAN TERHADAP TENGGANG WAKTU Y", "t": "Para hakim dilarang sama sekali untuk memberi relief dari kesalahankesalahan yuridis, kelalaian-kelalaian dan kekurangan- kekurangan di luar hal yang diperkenankan oleh ketentuan-ketentuan undang-undang untuk memperbaikinya. Demikian pula mereka dilarang memberi relief dari jalannya tenggang- tenggang waktu dari perlawanan, banding dan kasasi, atau dari tenggang-tenggang waktu yang mutlak, dari jenis apa pun, di luar satu-satunya hal bahwa seseorang yang minta relief telah mernbuktikan dengan pasti bahwa ia, atau karena jauhnya jarak, atau karena tidak adanya sarana perhubungan, atau karena tidak adanya orang-orang yang berwenang menyampaikan pemberitahuan, tidak mungkin untuk memperhatikan tenggang-tenggang waktu atau waktu-waktu tersebut. (Rv. 83 dst., 127, 334, 402, 415, 418, 770.)"}, {"l": "RV", "p": "917", "b": "BAB VIII PEMBERIAN RELIEF (PERBAIKAN KESALAHAN ATAU PENYIMPANGAN TERHADAP TENGGANG WAKTU Y", "t": "Permohonan relief, atas ancaman tidak dapat diterima, harus diajukan dalam waktu enam bulan sesudah tenggang waktu atau waktu yang tidak diperhatikan, kepada hakim yang berwenang dengan surat permohonan disertai alasan-alasan yang berisi penunjukan pengacara dan pilihan tempat kediaman sesuai dengan ketentuan dalam pasal 106. Pengajuannya harus disertai bukti-bukti yang perlu."}, {"l": "RV", "p": "918", "b": "BAB VIII PEMBERIAN RELIEF (PERBAIKAN KESALAHAN ATAU PENYIMPANGAN TERHADAP TENGGANG WAKTU Y", "t": "Bila permohonan, yang sebelumnya harus diberitahukan kepada pihak penuntut umum untuk terhadapnya diberikan kesirnpulan tertulis segera ternyata bagi hakim bahwa permohonan itu tidak beralasan, maka ia menolaknya tanpa mengadakan penyelidikan lebih lanjut. r g"}, {"l": "RV", "p": "919", "b": "BAB VIII PEMBERIAN RELIEF (PERBAIKAN KESALAHAN ATAU PENYIMPANGAN TERHADAP TENGGANG WAKTU Y", "t": "s . o Bila permohonan itu tidak segera ternyata tidak beralasan, hakim beserta l i a rnemerintahkan dengan suatu surat perintah agar surat permohonan itu t a surat-surat yang bersangkutan dengarlnya dan surat perintah itu l. eg sendiri diberitahukan kepada pihak-pihak yang berkepentingan dengan panggilan untuk datang di sidang pengadilan pada haii yang w ditetapkan dalarn surat perintah, baik secara pribadi maupun diwakili oleh pengacaranya, untuk, bila dikehendaki, membantah permohonan. (Rv. 92 1.) w"}, {"l": "RV", "p": "920", "b": "BAB VIII PEMBERIAN RELIEF (PERBAIKAN KESALAHAN ATAU PENYIMPANGAN TERHADAP TENGGANG WAKTU Y", "t": "w Pada hari yang ditentukan, pemohon dan pihak-pihak yang berkepentingan dapat saiing mernberikan alasan-alasannya. Bila pada hakim ternyata bahwa orang-orang yang berkepentingan yang tidak hadir tidak dipanggil dengan sempurna, ia memerintahkan untuk memanggil lagi pada hari sidang yang ditetapkan; dan pemeriksaan perkara itu ditunda sarnpai hari sidang tersebut. Sesudah mendengar atau memanggil dengan cukup orang-orang yang berkepentingan, hakirn rnengambil keputusan setelah mendengar pihak penuntut umurn. Alinea keempat ditarik kembali dengan S. 1872-13."}, {"l": "RV", "p": "921", "b": "BAB VIII PEMBERIAN RELIEF (PERBAIKAN KESALAHAN ATAU PENYIMPANGAN TERHADAP TENGGANG WAKTU Y", "t": "Pelaksanaan dari keputusan-keputusan yang dapat dilaksanakan, tidak tertunda oleh permohonan relief, dengan tidak mengurangi kewenangan hakim untuk memerintahkan dengan surat perintah tersebut dalam pasal 919, agar pelaksanaan sementara tidak dilanjutkan."}, {"l": "RV", "p": "922", "b": "BAB VIII PEMBERIAN RELIEF (PERBAIKAN KESALAHAN ATAU PENYIMPANGAN TERHADAP TENGGANG WAKTU Y", "t": "Jika dalam hal relief dikabulkan, perkaranya tidak dapat lagi diajukan dalam keseluruhan, maka kerugian yang timbul karenanya selalu dibebankan pada pihak, kepada siapa relief diberikan."}, {"l": "RV", "p": "923", "b": "BAB VIII PEMBERIAN RELIEF (PERBAIKAN KESALAHAN ATAU PENYIMPANGAN TERHADAP TENGGANG WAKTU Y", "t": "Terhadap keputusan-keputusan hakim menurut ketentuan-ketentuan dalam bab ini, tidak diperkenankan mengajukan keberatan. (Rv. 82, 327 dst., 362 dst., 385 dst., 402 dst.)"}];
